DROP TABLE IF EXISTS figure_series;
CREATE TABLE figure_series (
    id TEXT PRIMARY KEY,
    line TEXT NOT NULL,
    name TEXT NOT NULL,
    sort_index INTEGER,
    UNIQUE(line, name)
);

DROP TABLE IF EXISTS figures;
CREATE TABLE figures (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    line TEXT,
    series_id TEXT,
    release_date DATE,
    sort_index INTEGER,
    owned BOOLEAN,
    image_url TEXT, type TEXT, region TEXT, platform_id INTEGER,
    FOREIGN KEY(series_id) REFERENCES figure_series(id)
);

DROP TABLE IF EXISTS ignored_items;
CREATE TABLE ignored_items (id TEXT PRIMARY KEY, type TEXT, reason TEXT);

DROP TABLE IF EXISTS platforms;
CREATE TABLE "platforms" (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                name TEXT NOT NULL,
                igdb_id INTEGER UNIQUE,
                display_name TEXT,
                parent_platform_id INTEGER,
                brand TEXT,
                launch_date DATE,
                image_url TEXT,
                description TEXT
            );

PRAGMA foreign_keys = ON;
