INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3do-interactive-multiplayer', 'Doom', 'Doom', '1996-04-26', '3DO Interactive Multiplayer', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-3do-interactive-multiplayer', 'Lemmings', 'Lemmings', '1994-01-01', '3DO Interactive Multiplayer', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 1);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-3d-3do-interactive-multiplayer', 'Wolfenstein 3D', 'Wolfenstein', '1995-10-19', '3DO Interactive Multiplayer', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9rdz.jpg', 'The SNES version of Wolfenstein 3D has modified episodes and storyline, along with heavy censorship. The changes make this version a different game from the original DOS game, and was used as the basis for the Atari Jaguar, Macintosh, 3DO and Apple IIgs ports.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('asteroids-atari-video-computer-system', 'Asteroids', NULL, '1981-08-01', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wvq.jpg', 'Asteroids for the Atari 2600 is a port of the arcade space shooter released in November 1979. The player controls a spaceship in an asteroid field which is periodically traversed by flying saucers. The objective of the game is to destroy both, asteroids and saucers. The triangular ship can rotate left and right, fire shots straight forward, and thrust forward. Once the ship begins moving in a direction, it will continue in that direction for a time without player intervention unless the player applies thrust in a different direction. The ship eventually comes to a stop when not thrusting. The player can also send the ship into hyperspace, causing it to disappear and reappear in a random location on the screen, at the risk of self-destructing or appearing on top of an asteroid.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('breakout-atari-video-computer-system', 'Breakout', NULL, '1978-11-09', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94iu.jpg', 'The objective of the game is to destroy a multilayered wall of bricks at the top the screen. Upon hitting the bricks with a ball which bounces off of a paddle at the bottom of the screen the bricks are destroyed. If the player misses the ball with his horizontally moveable paddle the ball is lost. After loosing five balls the game is over.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('combat-atari-video-computer-system', 'Combat', NULL, '1977-01-01', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v43.jpg', 'Combat 2 is video game for the Atari 2600. Originally announced in 1982, it was subsequently cancelled. Developed by Atari, the game was supposed to be the sequel to the classic Atari VCS game Combat, which was bundled with the system. In 2005 it finally saw release on the Atari Flashback 2 dedicated console, and has seen two subsequent releases, the first in the 2011 Nintendo DS compilation Atari''s Greatest Hits Volume II and the second in the iPhone and Android app Atari Greatest Hits, initially released in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-atari-video-computer-system', 'Superman', 'DC', '1979-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co987r.jpg', 'Superman is an action adventure game for the Atari 2600. It was one of the first single-player games for the system and one of the earliest licensed video games. Superman is one of the first to utilize multiple screens as playing areas.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-atari-video-computer-system', 'Donkey Kong', 'Donkey Kong', '1982-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hs3.jpg', 'The Atari 2600 port of the hit arcade Donkey Kong differs from the original version in gameplay and has two stages instead of the original four.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-atari-video-computer-system', 'Donkey Kong Jr.', 'Donkey Kong', '1983-09-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2182.jpg', 'Donkey Kong Jr. + Jr. Sansuu Lesson is a game released for the Family Computer in Japan. It is a compilation of the games Donkey Kong Jr. and Donkey Kong Jr. Math. Despite being a compilation of two games, only parts of both are included. Combining half of the 1- and 2-Player game modes from Donkey Kong Jr. and the +-×÷ Exercise mode from Donkey Kong Jr. Math, the game can cater to classic arcade excitement and arithmetic lessons directed towards the younger set. No other gameplay mechanics or details seem to have changed.', NULL, 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-bros-atari-video-computer-system', 'Mario Bros.', 'Mario', '1983-07-26', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jlf.jpg', 'Mario Bros. is the Atari 2600 port of the homonymous arcade game.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-atari-video-computer-system', 'Spider-Man', 'Marvel', '1982-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co791o.jpg', 'Spider-Man released in 1982 by Parker Brothers was the first video game to feature SpiderMan and also the first video game based on a Marvel Comics character.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-atari-video-computer-system', 'Pac-Man', 'Pac-Man', '1982-03-01', 'Atari 2600', 0, 0, NULL, NULL, 'This is a "new" version of Pac-Man for Atari 2600 I''ve been programming since about 2007, but had left in 2008, then in 2013 I resume again to try to finish.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-atari-video-computer-system', 'Ms. Pac-Man', 'Pac-Man', '1983-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9dsj.jpg', 'Like in the original Pac-Man, the goal of the game is to eat all of the dots in a maze while avoiding the four ghosts; if one of the ghosts catches Ms. Pac-Man, a life is lost and the game ends when the player has no more remaining lives. In each corner of the maze are power pellets; when Ms. Pac-Man eats one of these, the ghosts temporarily turn blue and are no longer a threat (the player can earn bonus points for eating ghosts while blue). On some sides of the screen are warp tunnels which transport the player to the opposite side of the screen; if a ghost follows through the tunnel they are unable to move as fast allowing the player to use them to escape. Once all of the dots in the maze have been eaten, the player continues to the next level. As the levels progress, the difficulty is increased by increasing the overall game speed and the duration the ghosts remain blue after eating a power pellet is shortened (eventually disappearing altogether).', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-atari-video-computer-system', 'Space Invaders', 'Space Invaders', '1980-01-01', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtjz.jpg', 'A new port of Space Invaders released in Atari Flashback consoles. It is based on the Atari 2600 architecture.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-empire-strikes-back-atari-video-computer-system', 'Star Wars: The Empire Strikes Back', 'Star Wars', '1982-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pix.jpg', 'In Star Wars: The Empire Strikes Back the player takes on the role of a Rebel pilot attempting to destroy AT-ATs on Hoth.', 'NA', 52);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-of-the-jedi-death-star-battle-atari-video-computer-system', 'Return of the Jedi: Death Star Battle', 'Star Wars', '1983-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co74k7.jpg', 'Return of the Jedi: Death Star Battle is a Shoot ''em up video game published by Parker Brothers in 1983 for various Atari platforms and in 1984 for the Sinclair ZX Spectrum. It was the first released video game to be based on the movie Return of the Jedi.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-arena-atari-video-computer-system', 'Star Wars: Jedi Arena', 'Star Wars', '1983-01-01', 'Atari 2600', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co74j8.jpg', 'In Jedi Arena, you have to face an opponent in the arena to see who is the true Jedi master. Wandering throughout the arena is a seeker which is capable of firing laser bolts. To be victorious you need to destroy your opponents shield by having the seeker fire laser bolts at it. You are armed only with a light saber which is used to control the direction of the laser bolts you fire, as well as block incoming fire from your opponent.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-breakout-atari-video-computer-system', 'Super Breakout', NULL, '1981-10-01', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co671m.jpg', 'Atari 2600 port of Super Breakout.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('video-olympics-atari-video-computer-system', 'Video Olympics', NULL, '1977-09-01', 'Atari 2600', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9id7.jpg', 'Video Olympics a collection of games from Atari''s popular arcade Pong series is one of the nine 2600 launch titles. The games are a collection of "bat and ball" style games, including several previously released by Atari as coin-ops in the early 1970s. The games are played using the 2600s paddle controllers and are for one to four players (three or four players requires a second set of paddle controllers).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('centipede-atari-5200-supersystem', 'Centipede', NULL, '1983-02-01', 'Atari 5200', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8d2j.jpg', 'Atari 5200 port of Centipede.', 'NA', 54);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-bros-atari-5200-supersystem', 'Mario Bros.', 'Mario', '1983-12-31', 'Atari 5200', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jld.jpg', 'Mario Bros. is the Atari 5200 port of the homonymous arcade game.', 'NA', 54);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-atari-5200-supersystem', 'Pac-Man', 'Pac-Man', '1982-11-01', 'Atari 5200', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9dsf.jpg', 'The Atari 5200 port of Pac-Man, which is a port of the Atari 8-bit version.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-atari-5200-supersystem', 'Ms. Pac-Man', 'Pac-Man', '1983-01-01', 'Atari 5200', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ds6.jpg', NULL, 'NA', 54);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-atari-5200-supersystem', 'Space Invaders', 'Space Invaders', '1982-01-01', 'Atari 5200', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9s.jpg', 'Space Invaders for the Atari 5200 is an enhanced port of the Atari 8-bit port.', 'NA', 54);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-of-the-jedi-death-star-battle-atari-5200-supersystem', 'Return of the Jedi: Death Star Battle', 'Star Wars', '1983-01-01', 'Atari 5200', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co74k7.jpg', 'Return of the Jedi: Death Star Battle is a Shoot ''em up video game published by Parker Brothers in 1983 for various Atari platforms and in 1984 for the Sinclair ZX Spectrum. It was the first released video game to be based on the movie Return of the Jedi.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-breakout-atari-5200-supersystem', 'Super Breakout', NULL, '1982-10-01', 'Atari 5200', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6as9.jpg', 'Atari 5200 port of Super Breakout.', 'NA', 54);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('centipede-atari-7800-prosystem', 'Centipede', NULL, '1986-05-15', 'Atari 7800', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8d30.jpg', 'The Atari 7800 port of Centipede.', 'NA', 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-atari-7800-prosystem', 'Donkey Kong', 'Donkey Kong', '1988-11-01', 'Atari 7800', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hs5.jpg', 'The Donkey Kong port for Atari 7800 was developed by Atari Corporation.', 'NA', 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-atari-7800-prosystem', 'Donkey Kong Jr.', 'Donkey Kong', '1988-11-01', 'Atari 7800', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2182.jpg', 'Donkey Kong Jr. + Jr. Sansuu Lesson is a game released for the Family Computer in Japan. It is a compilation of the games Donkey Kong Jr. and Donkey Kong Jr. Math. Despite being a compilation of two games, only parts of both are included. Combining half of the 1- and 2-Player game modes from Donkey Kong Jr. and the +-×÷ Exercise mode from Donkey Kong Jr. Math, the game can cater to classic arcade excitement and arithmetic lessons directed towards the younger set. No other gameplay mechanics or details seem to have changed.', NULL, 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-bros-atari-7800-prosystem', 'Mario Bros.', 'Mario', '1987-07-10', 'Atari 7800', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jlb.jpg', 'Mario Bros. is the Atari 7800 port of the homonymous arcade game.', 'NA', 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-atari-7800-prosystem', 'Ms. Pac-Man', 'Pac-Man', '1986-01-01', 'Atari 7800', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ds7.jpg', 'Pac-Man is in love! And what a star his sweetheart is, with her red ribbon and long eyelashes. Just like her leading man, Ms. Pac-Man chomps her way through mazes as she battles four ghosts. Round and round, back and forth, across the stage she races as she gobbles up dots, energy pills, teddy bears, fruit, and pretzels. Can she escape the marauding ghosts? Or will this be her final curtain? Will Pac-Man ever see his lady love again?', 'NA', 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pole-position-ii-atari-7800-prosystem', 'Pole Position II', 'Pole Position', '1986-05-15', 'Atari 7800', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xey.jpg', 'Just like the first game, but with improved graphics and 4 different tracks to choose.', 'NA', 56);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battlezone-2000-atari-lynx', 'Battlezone 2000', 'Battlezone', '1995-01-01', 'Atari Lynx', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z3q.jpg', '2005 A.D. A deadly virus has infected the Supertank''s ultrasophisticated computer systems, turning these mighty weapons of destruction against their creators. Humankind is on the brink of extinction. Free the battle zones from this robotic plague!', 'NA', 5);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-atari-lynx', 'Lemmings', 'Lemmings', '1993-01-01', 'Atari Lynx', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 5);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-atari-lynx', 'Ninja Gaiden', 'Ninja Gaiden', '1991-01-01', 'Atari Lynx', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ip6.jpg', 'A handheld electronic port of Ninja Gaiden, released in 1989.', 'NA', 5);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-iii-the-ancient-ship-of-doom-atari-lynx', 'Ninja Gaiden III: The Ancient Ship of Doom', 'Ninja Gaiden', '1993-01-01', 'Atari Lynx', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ips.jpg', 'Thrilling new cinema screen! Follow the story of Ryu''s epic adventure through Tecmo''s movie-like Cinema Screen Animation. As you complete each level, a new part of the story unfolds. Exciting new powers and weapons! Over the years Ninja Ryu''s fighting skills have improved to include fantastic new powers and weapons. Action-packed Ninja adventure! Can you get Ryu through his most challenging adventure as he battles the hideous ancient forces of darkness to save mankind? The Ultimate Ninja Challenge!', 'NA', 5);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-atari-lynx', 'Ms. Pac-Man', 'Pac-Man', '1990-01-01', 'Atari Lynx', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sq9.jpg', NULL, 'NA', 5);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-in-fractured-furry-tales-atari-jaguar', 'Bubsy in Fractured Furry Tales', 'Bubsy', '1994-12-09', 'Atari Jaguar', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co985k.jpg', 'Bubsy in: Fractured Furry Tales was released December 15, 1994 for the Atari Jaguar. This title sets Bubsy traversing across various fairy tales. The game sees Bubsy taking on the Mad Hatter in Alice in Wonderland, the Giant in Jack and the Beanstalk, the Djinni in Ali Baba and the 40 Thieves, a sea monster in Twenty Thousand Leagues Under the Sea and Hansel and Gretel in Candyland. The game plays similarly to the prior two games in the series, but without any of the gadgets or band-aids of Bubsy 2.', 'NA', 6);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-atari-jaguar', 'Doom', 'Doom', '1994-11-28', 'Atari Jaguar', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-atari-jaguar', 'Dragon''s Lair', 'Dragon''s Lair', '1995-01-01', 'Atari Jaguar', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-atari-jaguar', 'Rayman', 'Rayman', '1995-09-19', 'Atari Jaguar', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jo7.jpg', 'English with Rayman is an educational 2D platform game, based on the original Rayman. It was designed to teach young children the basics of the English language. It is not to be confused with Rayman Junior, which is an entirely different game. English with Rayman blends the Glade of Dreams with the real world in a way which makes little sense in the context of the series, making numerous references to real-world locations such as Ireland and Scotland. English with Rayman was adapted to teach various other languages under such names as French with Rayman.', 'NA', 6);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-3d-atari-jaguar', 'Wolfenstein 3D', 'Wolfenstein', '1994-05-01', 'Atari Jaguar', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9rdz.jpg', 'The SNES version of Wolfenstein 3D has modified episodes and storyline, along with heavy censorship. The changes make this version a different game from the original DOS game, and was used as the basis for the Atari Jaguar, Macintosh, 3DO and Apple IIgs ports.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-colecovision', 'Donkey Kong', 'Donkey Kong', '1982-07-01', 'ColecoVision', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-colecovision', 'Donkey Kong Jr.', 'Donkey Kong', '1983-02-01', 'ColecoVision', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2182.jpg', 'Donkey Kong Jr. + Jr. Sansuu Lesson is a game released for the Family Computer in Japan. It is a compilation of the games Donkey Kong Jr. and Donkey Kong Jr. Math. Despite being a compilation of two games, only parts of both are included. Combining half of the 1- and 2-Player game modes from Donkey Kong Jr. and the +-×÷ Exercise mode from Donkey Kong Jr. Math, the game can cater to classic arcade excitement and arithmetic lessons directed towards the younger set. No other gameplay mechanics or details seem to have changed.', 'NA', 7);
