INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-intellivision', 'Donkey Kong', 'Donkey Kong', '1982-10-01', 'Intellivision', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-intellivision', 'Donkey Kong Jr.', 'Donkey Kong', '1983-10-01', 'Intellivision', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2182.jpg', 'Donkey Kong Jr. + Jr. Sansuu Lesson is a game released for the Family Computer in Japan. It is a compilation of the games Donkey Kong Jr. and Donkey Kong Jr. Math. Despite being a compilation of two games, only parts of both are included. Combining half of the 1- and 2-Player game modes from Donkey Kong Jr. and the +-×÷ Exercise mode from Donkey Kong Jr. Math, the game can cater to classic arcade excitement and arithmetic lessons directed towards the younger set. No other gameplay mechanics or details seem to have changed.', 'NA', 7);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-intellivision', 'Pac-Man', 'Pac-Man', '1983-10-01', 'Intellivision', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 7);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-empire-strikes-back-intellivision', 'Star Wars: The Empire Strikes Back', 'Star Wars', '1983-01-01', 'Intellivision', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v53.jpg', 'Now transform your Star Wars games into a new adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-neo-geo-pocket-color', 'Pac-Man', 'Pac-Man', '1999-01-01', 'Neo Geo Pocket Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 11);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-pocket-adventure-neo-geo-pocket-color', 'Sonic the Hedgehog Pocket Adventure', 'Sonic the Hedgehog', '1999-12-04', 'Neo Geo Pocket Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4se0.jpg', 'Help Sonic rescue his forest friends from the evil Dr. Robotnik. Grab those golden rings and collect all the chaos emeralds for special bonuses. Rush through multiple bonus levels and challenge the high score record. Collect puzzle pieces and complete the mystery photo. Play against a friend in a 2-player Vs. battle. The action is gonna be super SONIC!', 'NA', 11);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baseball-nintendo-entertainment-system', 'Baseball', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co857x.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-nintendo-entertainment-system', 'Blaster Master', 'Blaster Master', '1988-11-30', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('robowarrior-nintendo-entertainment-system', 'Robowarrior', 'Blaster Master', '1988-12-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3026.jpg', 'Robowarrior takes place on an alien planet called Altile. The player operates a cyborg named ZED (Z-type Earth Defence). In the game, ZED raids Altile to fight the Xantho empire and destroy its leader, Xur. ZED deploys bombs to clear a path through rocks, walls, and forests, while killing enemies and collecting items.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-nintendo-entertainment-system', 'Bomberman', 'Bomberman', '1987-01-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q1m.jpg', 'Bomberman Jetters is an action RPG that could be considered the spiritual successor to Bomberman Tournament.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-ii-nintendo-entertainment-system', 'Bomberman II', 'Bomberman', '1993-02-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4o46.jpg', 'Bomberman II follows the popular Famicom/NES game Bomberman, incorporating a number of new features to the series. The game maintained the classic Bomberman game-type, requiring the player to navigate a maze of blocks using bombs to make a path. It added a two-player and three-player mode, and had a more developed storyline. The game was developed by Hudson Soft and released on the Family Computer and the NES. It was marketed as Dynablaster in Europe.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-nintendo-entertainment-system', 'Castlevania', 'Castlevania', '1987-05-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sn4.jpg', 'Castlevania was a cakewalk compared to this bloody curse. You thought you had the Prince of Darkness defanged - eh, Simon Belmont? Well think again, ''cause according to a damsel in distress, evil Count Dracula has left a horrifying curse in his wake. And the only hope you have of ending the terror is to destroy his missing body parts! Talk about your frightening quest, searching a maze of mansions, graveyards and dark, eerie forests - each guarded by man-eating werewolves, fire-throwing zombies and other devilish demons. Your grim chances are kept alive in Transylvania, where cowardly villagers offer clues to the whereabouts of Dracula''s remains. And where you''ll purchase magic weapons, including silver knives and flame whips. But beware the night. For when the sun disappears, Dracula''s curse grows deadlier. And your chances grow dimmer and dimmer.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-ii-simon-s-quest-nintendo-entertainment-system', 'Castlevania II: Simon''s Quest', 'Castlevania', '1988-12-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sn4.jpg', 'Castlevania was a cakewalk compared to this bloody curse. You thought you had the Prince of Darkness defanged - eh, Simon Belmont? Well think again, ''cause according to a damsel in distress, evil Count Dracula has left a horrifying curse in his wake. And the only hope you have of ending the terror is to destroy his missing body parts! Talk about your frightening quest, searching a maze of mansions, graveyards and dark, eerie forests - each guarded by man-eating werewolves, fire-throwing zombies and other devilish demons. Your grim chances are kept alive in Transylvania, where cowardly villagers offer clues to the whereabouts of Dracula''s remains. And where you''ll purchase magic weapons, including silver knives and flame whips. But beware the night. For when the sun disappears, Dracula''s curse grows deadlier. And your chances grow dimmer and dimmer.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-iii-dracula-s-curse-nintendo-entertainment-system', 'Castlevania III: Dracula''s Curse', 'Castlevania', '1990-09-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86uq.jpg', 'A fanmade remake of Castlevania III: Dracula''s Curse by studio WarMachine.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-nintendo-entertainment-system', 'Contra', 'Contra', '1988-02-02', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co64pi.jpg', 'This game is action from beginning to end, do not think that you will have a moment of peace, even because Aliens are at war with planet earth, and resting will be your least concern.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-contra-nintendo-entertainment-system', 'Super Contra', 'Contra', '1990-04-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co59su.jpg', 'A port of the Arcade version of Super Contra for the Xbox Live Arcade. Celebrating the 20th anniversary of Contra, this newly updated version of Super Contra features enhanced graphics, HD support, and Co-op multiplayer over Xbox LIVE. Help Lance and Bill stop Red Falcon before they take over the world. The Alien Wars are coming... do you have what it takes to defend earth?', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-force-nintendo-entertainment-system', 'Contra Force', 'Contra', '1992-09-30', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7xbj.jpg', 'Contra Force is an action shooting game released by Konami for the Nintendo Entertainment System in 1992 in North America. It is a spinoff of the Contra series, being the third game in the series released for the NES following the original Contra and Super Contra, although the game''s plot and setting are unrelated to previous entries, as the villains in the game are human terrorists instead of an alien menace', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-nintendo-entertainment-system', 'Superman', 'DC', '1988-12-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b3i.jpg', 'Superman: The New Adventures, often referred to as Superman 64, is a 1999 adventure video game developed and published by Titus Software for the Nintendo 64 video game console. The game is based on the television series Superman: The Animated Series. Superman was first released in North America on May 31, 1999 and in Europe on July 23, 1999.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-nintendo-entertainment-system', 'Batman', 'DC', '1990-02-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fx3.jpg', 'This addon inlcudes a Batman costume inspired by the 2008 movie ‘The Dark Knight’.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-return-of-the-joker-nintendo-entertainment-system', 'Batman: Return of the Joker', 'DC', '1991-12-20', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pij.jpg', 'Batman: Return of the Joker was developed and published by Sunsoft as the second in their Batman series on the Nintendo Entertainment System. It departed from the original game by focusing on the comic-book version of Batman instead of the movie-inspired conception. The story itself was self-contained, and did not depict a pre-existing storyline. The game is a side-scrolling platformer with beat ''em up features.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-returns-nintendo-entertainment-system', 'Batman Returns', 'DC', '1992-12-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zck.jpg', 'Batman Returns is a beat-em-up side-scrolling game designed for the Sega consoles. It was published by Sega.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('swamp-thing-nintendo-entertainment-system', 'Swamp Thing', 'DC', '1992-12-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w0k.jpg', 'A Handheld Electronic LCD device based on the DC Comics superhero Swamp Thing.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-math-nintendo-entertainment-system', 'Donkey Kong Jr. Math', 'Donkey Kong', '1985-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co23ir.jpg', 'The game features one and two player modes, both of which are single screen. In the first mode, the objective is to enter math answers in order to receive points. These questions include addition, subtraction, multiplication, and division.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-nintendo-entertainment-system', 'Donkey Kong', 'Donkey Kong', '1986-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jr-nintendo-entertainment-system', 'Donkey Kong Jr.', 'Donkey Kong', '1986-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2182.jpg', 'Donkey Kong Jr. + Jr. Sansuu Lesson is a game released for the Family Computer in Japan. It is a compilation of the games Donkey Kong Jr. and Donkey Kong Jr. Math. Despite being a compilation of two games, only parts of both are included. Combining half of the 1- and 2-Player game modes from Donkey Kong Jr. and the +-×÷ Exercise mode from Donkey Kong Jr. Math, the game can cater to classic arcade excitement and arithmetic lessons directed towards the younger set. No other gameplay mechanics or details seem to have changed.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-3-nintendo-entertainment-system', 'Donkey Kong 3', 'Donkey Kong', '1986-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-classics-nintendo-entertainment-system', 'Donkey Kong Classics', 'Donkey Kong', '1988-10-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wk6.jpg', 'What''s more fun than a barrel of monkeys? A Donkey Kong double feature! In DONKEY KONG you''ll duck barrel bombs and flaming fireballs as you help Mario save his girlfriend Pauline from the clutches of Donkey Kong. In DONKEY KONG JR., you''ll join forces with these madcap monkeys to help Donkey Kong Jr. rescue his father from Mario''s prison. Are you ready for laughter? You''d better be. Because this double dose of monkey business will have you rolling in the aisles!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dr-mario-nintendo-entertainment-system', 'Dr. Mario', 'Dr. Mario', '1990-10-14', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4lat.jpg', 'Dr. Mario Express, known in Japan and PAL regions as A Little Bit of... Dr. Mario (ちょっとDr. MARIO Chotto Dr. Mario?),[5] is a Mario action puzzle video game published by Nintendo. The game was released exclusively as a DSiWare title for the Nintendo DSi platform. Dr. Mario Express was first released as a launch title for the DSiWare service in Japan on December 24, 2008, and was released in both North America and PAL regions in 2009. The game was developed by Arika, which had also created Dr. Mario Online Rx for WiiWare.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-nintendo-entertainment-system', 'Dragon Warrior', 'Dragon Quest', '1989-08-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s7a.jpg', 'Dragon Warrior III is a top-down role-playing game where you travel around the overworld, caves, castles, cities and other locations while battling random encounters, buying equipment, and talking to people.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-ii-nintendo-entertainment-system', 'Dragon Warrior II', 'Dragon Quest', '1990-10-30', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8003.jpg', 'Dragon Warrior II is an early top-down RPG that expands and improves on its predecessor. Unlike the first game, Dragon Warrior II allows the player to join forces with two other characters, a magic-using princess and a wizard-warrior prince.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-iii-nintendo-entertainment-system', 'Dragon Warrior III', 'Dragon Quest', '1992-03-12', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s7a.jpg', 'Dragon Warrior III is a top-down role-playing game where you travel around the overworld, caves, castles, cities and other locations while battling random encounters, buying equipment, and talking to people.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-iv-nintendo-entertainment-system', 'Dragon Warrior IV', 'Dragon Quest', '1992-10-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7trb.jpg', 'Dragon Warrior IV differs from the rest of the series by breaking up the game into five distinct chapters, each of which focuses on a different protagonist or protagonists. The first four are told from the perspective of the Hero''s future companions and the fifth one, from the hero''s perspective, brings all the characters together as they begin their journey to save the world.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('legacy-of-the-wizard-nintendo-entertainment-system', 'Legacy of the Wizard', 'Dragon Slayer', '1989-04-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zd6.jpg', 'The NES/Famicom port of Legacy of the Wizard. Play as five members of a family that set out to kill a dragon hidden within a giant maze.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-nintendo-entertainment-system', 'Dragon''s Lair', 'Dragon''s Lair', '1990-12-29', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('duck-hunt-nintendo-entertainment-system', 'Duck Hunt', 'Duck Hunt', '1985-10-18', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co42pf.jpg', 'It’s duck season, and your trusty hunting dog is ready to scour the open fields. Test your sharpshooting skills as your targets take flight. Be quick to knock them out of the skies, or your canine companion won’t hesitate to make you the laughingstock of hunters! Need a change in scenery? Best your score against clay-pigeon targets instead!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-nintendo-entertainment-system', 'DuckTales', 'DuckTales', '1989-09-14', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4wth.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-2-nintendo-entertainment-system', 'DuckTales 2', 'DuckTales', '1993-06-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wrf.jpg', 'DuckTales 2 is a platform video game developed by Make Software and published by Capcom. It is a sequel to the original DuckTales based on the Disney animated series of the same name. It was released on the Nintendo Entertainment System in early 1993. The title was ported to the Game Boy handheld system in Japan and North America at the end of the year.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('excitebike-nintendo-entertainment-system', 'Excitebike', 'Excite', '1985-10-18', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co549b.jpg', 'The PC-8801 and Sharp X1 port of Excitebike.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f1-race-nintendo-entertainment-system', 'F1 Race', NULL, '1984-11-02', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zi6.jpg', 'Get ready to experience Formula One cars, teams and circuits like never before with F1 Race Stars from Codemasters Racing, the home of the series of HD official Formula One games. F1 Race Stars is a fast-to-the-fun arcade racing game featuring the official cars, teams and circuits as they''ve never been seen before. Drivers including Lewis Hamilton, Fernando Alonso and Sebastian Vettel have been transformed into personality-packed heroes bursting with charm and character and stunning Formula One locations have become exhilarating racing theme parks designed for speed and wheel-to-wheel competition.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-nintendo-entertainment-system', 'Final Fantasy', 'Final Fantasy', '1990-07-12', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vn2.jpg', 'The Twin Pack includes Final Fantasy VII and the remastered version of Final Fantasy VIII.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gargoyle-s-quest-ii-nintendo-entertainment-system', 'Gargoyle''s Quest II', 'Gargoyle''s Quest', '1992-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ro.jpg', 'The Law of the Claw!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghosts-n-goblins-nintendo-entertainment-system', 'Ghosts ''n Goblins', 'Ghosts ''n Goblins', '1986-11-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ghb.jpg', 'A heavily stripped down version of the 1985 arcade platformer, with only two levels and no music.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golf-nintendo-entertainment-system', 'Golf', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ek7.jpg', 'Experience iconic golf courses like Pebble Beach, St Andrews and Wolf Creek in the most realistic free golf game, now available on PC, Mac and Steam. Connect with millions of players all over the world!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gumshoe-nintendo-entertainment-system', 'Gumshoe', NULL, '1986-06-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wxq.jpg', 'You are a private detective and you have been asked to rescue the daughter of a millionaire and your investigation has brought you to a complex of ten tower blocks. Gumshoe is a platform game where a small part of the block is shown and the screen scrolls when you move in all directions. You have to navigate the various floors of the block to find the girl using ladders, escalators which change direction every few seconds and elevators that move up and down various levels but can''t be shot from. There are also rubbish chutes and when entered they transport you to another part of the block.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gyromite-nintendo-entertainment-system', 'Gyromite', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co42tm.jpg', 'Gyromite is a video game released in 1985 for the Nintendo Entertainment System, designed for use with the Robotic Operating Buddy (R.O.B.). Gyromite is one of two games in Nintendo''s Robot Series, the other being Stack-Up', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hogan-s-alley-nintendo-entertainment-system', 'Hogan''s Alley', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co83w0.jpg', 'Hogan''s Alley is a 1984 video game by Nintendo. It was one of the first games to use a light gun as an input device. The game presents players with "cardboard cut-outs" of villains and innocent civilians. The player must shoot the villains and spare the innocent people.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ice-climber-nintendo-entertainment-system', 'Ice Climber', 'Ice Climber', '1985-10-18', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8m2.jpg', 'A version of Ice Climber with a special letter from Takashi Tezuka and a Famicom Disk System item distributed on a Controller Pak, via magazine giveaways. It is a very rare item, only two giveaways are documented to have happened, distributing 30 Controller Pak each. It could only be played in Doubutsu no Mori, on its built-in NES emulator.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('solar-jetman-hunt-for-the-golden-warpship-nintendo-entertainment-system', 'Solar Jetman: Hunt for the Golden Warpship', 'Jetman', '1990-10-14', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa2kt.jpg', 'Blasting off through the cosmos and into hostile alien terrain, Jetman has returned in his most ambitious adventure yet! After the most powerful spacecraft in the known Universe, the Golden Warpship, is disassembled by a band of ruthless Space Pirates and scattered throughout the galaxy, Solar Jetman is tasked with rebuilding the ship to its former glory. Aided only by the gargantuan Federation Mothership for refuelling, Jetman will have to explore twelve labyrinthine planets solo in his Jetpod, where opposition is hidden inside every cavern and beyond every crater. With survival running as thin as his fuel, Solar Jetman will need to ward off every potential invasion and escape with the Golden Warpship intact – only then can he face off against his largest interstellar foe yet!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kid-icarus-nintendo-entertainment-system', 'Kid Icarus', 'Kid Icarus', '1987-07-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7hjx.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-adventure-nintendo-entertainment-system', 'Kirby''s Adventure', 'Kirby', '1993-05-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3x.jpg', 'Not everything is well in Dream Land. For some mysterious reason, the Dream Spring, a magical well that is the reservoir for all the dreams of the citizens of Dream Land, is no longer working. Everyone is being subjected to their worst nightmares every time they go to sleep. Upon reaching the Dream Spring, Kirby finds out that evil King Dedede has stolen the Star Rod, thus depriving Dream Land of the magical energy that feeds its spring. Using 20 unique tricks and your ability to steal your enemies'' powers by swallowing them, you''ll have to make your way through a horrific land filled with all kinds of nightmares. Recover the broken pieces of the Star Rod, and everyone in Dream Land will sleep peacefully once again. If you fail, the citizens of Dream Land will be subjected to a lifetime of terrible nightmares.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-nintendo-entertainment-system', 'The Legend of Zelda', 'The Legend of Zelda', '1987-07-14', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ip4.jpg', 'BS Legend of Zelda "MottZilla Patch" is a ROM hack/mod for BS Zelda no Densetsu Map 2. It makes the game able to be played on a real SNES, making it a single game with both BS Zelda games (Maps 1 and 2), with a time limit of 50 minutes per week (weeks on the Satellaview worked like time-limited episodes).', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zelda-ii-the-adventure-of-link-nintendo-entertainment-system', 'Zelda II: The Adventure of Link', 'The Legend of Zelda', '1988-12-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uje.jpg', 'Zelda II: The Adventure of Link is the second major installment in The Legend of Zelda series and the direct sequel to the first game. Like its predecessor, it features dungeons that must be located in the overworld and searched for an item that will prove useful. However, the game presents many very important gameplay changes compared to the previous one, affecting especially the movements and the combat. Moving around the world map involves encounters with enemies that take place on a side-scrolling playfield rather than the top-down perspective for which the series became known.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-nintendo-entertainment-system', 'Lemmings', 'Lemmings', '1992-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-nintendo-entertainment-system', 'Marble Madness', NULL, '1989-04-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-nintendo-entertainment-system', 'Super Mario Bros.', 'Mario', '1985-09-13', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5k7b.jpg', 'A remaster of the original Super Mario Bros., released exclusively as part of the Super Mario All-Stars bundle.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-bros-nintendo-entertainment-system', 'Mario Bros.', 'Mario', '1986-06-23', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9mlw.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-2-nintendo-entertainment-system', 'Super Mario Bros. 2', 'Mario', '1988-10-09', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yq8.jpg', 'A remaster of the original Super Mario Bros. 2 (the American port of Yume Koujou: Doki-doki Panic), released exclusively as part of the Super Mario All-Stars bundle.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-3-nintendo-entertainment-system', 'Super Mario Bros. 3', 'Mario', '1990-02-12', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tpt.jpg', 'Super Mario Advance 4: Super Mario Bros. 3 was originally released for the Game Boy Advance and had physical expansion in the form of a collection of e-Reader cards. When the game was re-released on the Wii U Virtual Console, it included the full game with all of the level expansions found in the World-e. All levels were included in this version, even the ones only released in Japan and the promotional exclusives (not included in any card pack).', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-is-missing-nintendo-entertainment-system', 'Mario Is Missing!', 'Mario', '1992-04-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21l6.jpg', 'Mario Is Missing! is an educational game and the first game where Luigi is the main protagonist with Mario in a supporting role. The main gameplay consists of moving around a city in side-scrolling manner while jumping on Koopas to collect stolen artifacts. Luigi then must secure the city by taking these artifacts to their respective locations and correctly answering two questions about the landmark.The computer version is a point-and-click adventure game, while the NES and SNES versions have more of an emphasis on platforming.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-time-machine-nintendo-entertainment-system', 'Mario''s Time Machine', 'Mario', '1994-06-23', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wwm.jpg', 'Mario''s Time Machine is an edutainment title and the successor of Mario is Missing! The game is meant to teach younger players basic world history and is the last Mario Discovery Series game before discontinuation. This game and Hotel Mario are the only games in the Mario franchise in which Mario as a protagonist has full lines of dialogue. The objective of the game is to return the historical artifacts to their proper time periods thanks to the central hub. As soon as you enter a certain time period you need to explore and interact with various residents of the area in order to get more information about the artifact, the period itself and the person connected to it.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nes-open-tournament-golf-nintendo-entertainment-system', 'NES Open Tournament Golf', 'Mario Golf', '1987-06-14', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21kv.jpg', 'NES Open Tournament Golf is an NES game featuring Mario characters. As the name of the game implies, it is a golf game and was one of the first golfing games in the Mario series. You can play a round of golf on one of three different courses. One or two players can play in the U.S., Japan, or the U.K. and choose a stroke or match play game. Gameplay is from two point of views, starting with an overhead view allowing you to set up the shot and choose a club, then switching to a 3-D point of view. Hitting the ball uses the common power meter where tapping the button starts the meter, tap the button a second time to select the amount of power in the shot, then tap the button a third time to select the amount of slice or hook.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-uncanny-x-men-nintendo-entertainment-system', 'The Uncanny X-Men', 'Marvel', '1989-12-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6oy8.jpg', 'The Uncanny X-Men is an overhead-view action game. Players commence by selecting two X-Men from the roster, with the second controlled by another player or the computer. They then choose one of five levels, including a practice level. The objective in each level is to reach the concealed ''command centre'' and demolish it. All X-Men share similar abilities, allowing movement in any direction, jumping, and attacking. Half of the characters (Storm, Iceman, Cyclops) possess long-range attacks, while the other half (Wolverine, Nightcrawler, Colossus) need to engage enemies in close combat. Each X-Man can endure a specific number of hits before being defeated. If both X-Men fall in battle, players can select two more to attempt the level again until all X-Men are used.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silver-surfer-nintendo-entertainment-system', 'Silver Surfer', 'Marvel', '1990-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ov1.jpg', 'Silver Surfer is a shooter game, with some levels taking place vertically and some horizontally. The Surfer''s only ability is to move around on the screen and to shoot directly in front of him. Power-ups that can be picked up include: the letter "F" (Firepower) which will increase the number and power of his projectiles, Smart bombs which destroy everything on the screen, the letter "S" (Speedup) which increases the surfer''s movement and Orbs which will also fire the Surfer''s weapon. Orbs are special in that two can be obtained (only 1 is shown on horizontal scrolling levels) and they can be positioned to fire forwards, backwards or sideways.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-punisher-nintendo-entertainment-system', 'The Punisher', 'Marvel', '1990-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p2u.jpg', 'Crime is everywhere on the streets of New York City. As Frank "the Punisher" Castle, it is your job to clean them up. However, there seem to be bigger things at hand...', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolverine-nintendo-entertainment-system', 'Wolverine', 'Marvel', '1991-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coae2u.jpg', 'Wolverine was a game in development for the NES by Zippo Games in 1989 and set to be published by Rare. The game had you play as a tank with an extendable body roaming around a massive Glider-rider style 3D isometric island. The game was cancelled after half way through development.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-and-the-avengers-nintendo-entertainment-system', 'Captain America and The Avengers', 'Marvel', '1991-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h0d.jpg', 'The Captain America and the Avengers for Game Boy.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-return-of-the-sinister-six-nintendo-entertainment-system', 'Spider-Man: Return of the Sinister Six', 'Marvel', '1992-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co987q.jpg', 'Spider-Man: Return of the Sinister Six is a side-scrolling game which puts you in the role of Spidey throughout six levels against Electro, Sandman, Mysterio, Vulture, Hobgoblin and Doctor Octopus respectively. Some puzzle solving (like finding a key) is necessary to beat some levels. Spidey can duck jump, climb walls, punch, shoot webs to swing (by pressing punch and jump together) and perform a jump kick (by pressing the punch button twice). Collecting web cartridges allows Spidey to shoot limited web projectiles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-nintendo-entertainment-system', 'Mega Man', 'Mega Man', '1988-03-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z14.jpg', 'A box set decorated with Mega Man 30th Anniversary art containing 19 Mega Man games and the voice acting script used for Mega Man 11.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-2-nintendo-entertainment-system', 'Mega Man 2', 'Mega Man', '1989-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5572.jpg', 'The second handheld installment of the Mega Man series has him (along with his dog, Rush) defeating eight more revived Robot Masters (from Mega Man 2 and Mega Man 3), while finding the whereabouts of Dr. Wily (who has traveled into the future to steal a weapon to counter Mega Man).', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-3-nintendo-entertainment-system', 'Mega Man 3', 'Mega Man', '1990-11-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0j.jpg', 'Mega Man 3 Mobile is the mobile port of Mega Man 3 (NES). It was released for mobile phones and had adjustments to make the game playable on numeric keypads.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-4-nintendo-entertainment-system', 'Mega Man 4', 'Mega Man', '1992-01-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62v1.jpg', 'A huge celebration at the World Robot Expo is shattered by the sight of a flying saucer streaking across the sky. But instead of holding little green men, this saucer holds one very mad scientist! Armed with a mind control machine that transmits a sinister signal. Dr. Wily is ready to mesmerize all the robots of the city into an army of mindless metallic mercenaries!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-5-nintendo-entertainment-system', 'Mega Man 5', 'Mega Man', '1992-12-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5hwy.jpg', 'Mega Man V, known as Rockman World 5, is a video game developed and published by Capcom for the Game Boy handheld game console. It is the fifth and final game in the Game Boy version of the original Mega Man series. The game follows the adventures of the protagonist Mega Man as he must defend the Earth from a group of powerful robots from outer space called the "Stardroids". Mega Man V was also unique from the previous Game Boy Mega Man games as it features original and unique bosses rather than recycling those from the original Nintendo Entertainment System (NES) Mega Man games.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-6-nintendo-entertainment-system', 'Mega Man 6', 'Mega Man', '1994-03-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0m.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-nintendo-entertainment-system', 'Metal Gear', 'Metal Gear', '1988-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p0n.jpg', 'The NES version of Metal Gear. It differs from the original MSX2 release in level layout and enemy differences, including an alternative final boss.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('snake-s-revenge-nintendo-entertainment-system', 'Snake''s Revenge', 'Metal Gear', '1990-04-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6saq.jpg', 'Handheld LCD port of the game Snake''s Revenge.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-nintendo-entertainment-system', 'Metroid', 'Metroid', '1987-08-15', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6m4o.jpg', 'Wii de Asobu: Metroid Prime 2 (also known as New Play Control! Metroid Prime 2) is a port of Metroid Prime 2: Echoes for the Wii, with motion controls compatibility. This port later released as a part of Metroid Prime: Trilogy in the West.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-nintendo-entertainment-system', 'Ninja Gaiden', 'Ninja Gaiden', '1989-03-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ip6.jpg', 'A handheld electronic port of Ninja Gaiden, released in 1989.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-ii-the-dark-sword-of-chaos-nintendo-entertainment-system', 'Ninja Gaiden II: The Dark Sword of Chaos', 'Ninja Gaiden', '1990-05-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ubo.jpg', 'The Ninja Ryu is back to avenge the death of his father, and stop the Evil Ashtar.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-iii-the-ancient-ship-of-doom-nintendo-entertainment-system', 'Ninja Gaiden III: The Ancient Ship of Doom', 'Ninja Gaiden', '1991-08-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ips.jpg', 'Thrilling new cinema screen! Follow the story of Ryu''s epic adventure through Tecmo''s movie-like Cinema Screen Animation. As you complete each level, a new part of the story unfolds. Exciting new powers and weapons! Over the years Ninja Ryu''s fighting skills have improved to include fantastic new powers and weapons. Action-packed Ninja adventure! Can you get Ryu through his most challenging adventure as he battles the hideous ancient forces of darkness to save mankind? The Ultimate Ninja Challenge!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-nintendo-entertainment-system', 'Pac-Man', 'Pac-Man', '1984-01-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-nintendo-entertainment-system', 'Ms. Pac-Man', 'Pac-Man', '1990-01-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sq9.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pinball-nintendo-entertainment-system', 'Pinball', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, NULL, 'Pinball Champ Deluxe table is the original Pinball Champ ''82 table reimagination with such modern pinball features like LCD display, prism lamps, game and multiball modes, and the secondary playfield.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-nintendo-entertainment-system', 'Prince of Persia', 'Prince of Persia', '1992-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mike-tyson-s-punch-out-nintendo-entertainment-system', 'Mike Tyson''s Punch-Out!!', 'Punch-Out!!', '1987-10-18', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6386.jpg', 'Punch-Out!!, originally released in North America as Mike Tyson''s Punch-Out!!, is a boxing sports fighting video game for the Nintendo Entertainment System (NES) developed and published by Nintendo in 1987. Part of the Punch-Out!! series, it is a port of both the Punch-Out!! and Super Punch-Out!! arcade games (particularly the latter) with some variations.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('punch-out-nintendo-entertainment-system', 'Punch-Out!!', 'Punch-Out!!', '1990-08-02', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bsq.jpg', 'Also known by the unofficial titles of Punch-Out!! Gold and Punch-Out!! Special, with the in-game title of simply Punch-Out!!, recently released on the Japanese Nintendo Switch Online as Punch-Out!!: Shouhin-ban (Prize Version), this was the first released version of Punch-Out!! for the NES/Famicom, which was released in Japan, as a prize for the participants of the official NES Open Tournament Golf (Golf Tournament US Course) competition.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-nintendo-entertainment-system', 'Space Invaders', 'Space Invaders', '1985-01-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stack-up-nintendo-entertainment-system', 'Stack-Up', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co42u8.jpg', 'Stack-Up is a video game released in 1985 for the Nintendo Entertainment System, designed for use with the Robotic Operating Buddy (R.O.B.) Stack-Up is one of two games in Nintendo''s Robot Series, the other being Gyromite (Robot Gyro in Japan). While Gyromite is a pack-in game with the R.O.B. itself and therefore comes with all the parts needed to play the game, Stack-Up comes in a large box containing additional bases and colored discs. The game''s retail box comes with many small, plastic parts, which may contribute to difficulty in maintaining a complete set. Stack-Up is considered by collectors to be one of the rarest first-party games for the NES.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-nintendo-entertainment-system', 'Star Wars', 'Star Wars', '1991-11-01', 'Nintendo Entertainment System', 0, 0, NULL, NULL, NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-empire-strikes-back-nintendo-entertainment-system', 'Star Wars: The Empire Strikes Back', 'Star Wars', '1992-03-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v53.jpg', 'Now transform your Star Wars games into a new adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('startropics-nintendo-entertainment-system', 'StarTropics', 'StarTropics', '1990-12-01', 'Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sur.jpg', 'Find out just how resourceful you can be in this classic game, with its mixture of adventure and RPG elements. Step into the shoes of Mike Jones, a teenage star pitcher from Seattle who has come to the tropics to visit his famous archeologist uncle, Dr. Jones. After being told that his uncle has been abducted, Mike begins a perilous quest in order to rescue him and figure out the mysterious plot behind his disappearance.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoda-s-revenge-startropics-ii-nintendo-entertainment-system', 'Zoda''s Revenge: StarTropics II', 'StarTropics', '1994-03-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kch.jpg', 'Stop Zoda''s revenge and break the code!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-duck-hunt-nintendo-entertainment-system', 'Super Mario Bros. / Duck Hunt', NULL, '1988-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22q8.jpg', 'A compilation of Duck Hunt and Super Mario Bros. Duck Hunt featured a lightgun shooting game while Super Mario Bros. is a well-known platformer.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tennis-nintendo-entertainment-system', 'Tennis', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zpn.jpg', 'First Person Tennis is the first tennis simulator developed for HTC Vive and Oculus Rift.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-nintendo-entertainment-system', 'Tetris', 'Tetris', '1989-11-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69ff.jpg', 'Tetris is now available for the first time on the PSP! See why hundreds of millions of players worldwide have made Tetris one of the most popular games ever! It features the famous Marathon Mode along with 12 new mini-versions based on the Tetris gameplay you know & love. Offering 15 levels of difficulty, it records your ''best times'' and ‘best scores’ for each variation. Use the Replay Viewer to look up cool moves in the in-game glossary and check out sweet replays of some of the best Tetris players in the world. TETRIS has changed with the times, but after 25 years some things remain the same... it’s captivating, fun, and addictive! Let the Tetris revolution begin!', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hatris-nintendo-entertainment-system', 'Hatris', 'Tetris', '1992-01-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7198.jpg', NULL, 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-2-nintendo-entertainment-system', 'Tetris 2', 'Tetris', '1993-10-01', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobgsb.jpg', 'Tetris 2 is a 1990 video game by František Fuka (Fuxoft). It is inspired by a Soviet game Tetris. It is considered to be the most successful game developed by Fuka.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-s-woods-nintendo-entertainment-system', 'Wario''s Woods', 'Wario', '1994-12-10', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4fn4.jpg', 'Wario''s Woods is a puzzle game similar to Tetris or Columns, but with a twist. Instead of directly controlling the monsters and bombs that are falling down, the player controls Toad who has to carry around stacks of monsters and bombs and to combine them in the right way. One bomb plus at least two monsters of the same color have to be combined to make them disappear. If five or more objects are cleared at the same time, a diamond will appear. Destroying the diamond will clear all monsters of the diamond''s color.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wild-gunman-nintendo-entertainment-system', 'Wild Gunman', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co42pd.jpg', 'Wild Gunman is a light gun shooter game created by Nintendo.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wrecking-crew-nintendo-entertainment-system', 'Wrecking Crew', NULL, '1985-10-18', 'Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21it.jpg', 'Wrecking Crew is a platform action game for one or two players. The player controls Mario (Player 2 as Luigi) working on a demolition site. The goal is to break down all of the stone walls on each stage. The game features a custom level maker, where players can make their own Wrecking Crew levels. The game had the ability to save those custom levels. However, the required peripherals (the keyboard and Data Recorder accessories) were released only in Japan.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-nintendo-entertainment-system', 'Yoshi', 'Yoshi', '1992-06-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5z4t.jpg', 'Yoshi is a puzzle game featuring the titular character. In this game, the player must stack two of the same Mario enemy on top of one another to clear them. The concept of the game was inspired by Tetris.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-cookie-nintendo-entertainment-system', 'Yoshi''s Cookie', 'Yoshi', '1993-04-01', 'Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yby.jpg', 'The Game Boy version of Yoshi''s Cookie was released as part of a dual launch with the NES version of the game. While they both featured the original three forms of game play, individuals on Gameboy were at an advantage in the form of the amount of players that could compete against one another in the VS mode.', 'NA', 13);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alleyway-game-boy', 'Alleyway', NULL, '1989-07-31', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21lj.jpg', 'Interstellar ping-pong with a deadly energy ball! Your spaceship is at the gate of the Alleyway. Use your vessel to repel the energy ball. Atomize space grids with your return shots. Destroy the entire field and move on to even more challenging targets. You''re in command in the Alleyway!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baseball-game-boy', 'Baseball', NULL, '1989-07-31', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co857x.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-boy-game-boy', 'Blaster Master Boy', 'Blaster Master', '1992-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5fuf.jpg', 'Blaster Master Jr., known as Blaster Master Boy in North America and Bomber King: Scenario 2 (ボンバーキング シナリオ2?) in Japan, is an action video game developed by Aicom and published by Sunsoft. The game was released in 1991 for Game Boy. The game is a sequel to Robowarrior, a spin-off title in the Bomberman series by Hudson Soft. However, the game was marketed in western territories as a game in the Blaster Master series by Sunsoft.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atomic-punk-game-boy', 'Atomic Punk', 'Bomberman', '1991-05-05', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6l2d.jpg', 'There are four modes of gameplay in Atomic Punk, including two single player modes and two multiplayer game modes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-gb-game-boy', 'Bomberman GB', 'Bomberman', '1998-04-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5u5u.jpg', 'A Bomberman named Indy Bomber sets out on a long journey to uncover a legendary treasure called the Ring of Wishes. He discovers a scripture and begins reading it, but soon falls into a trap in the floor and ends up in a cave. Now he must find hs way out of the cave and find the Ring of Wishes!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-2-game-boy', 'Bubsy 2', 'Bubsy', '1995-08-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h04.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-the-adventure-game-boy', 'Castlevania: The Adventure', 'Castlevania', '1989-12-15', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7j1d.jpg', 'A remaster of Castlevania: The Adventure released as part of Konami GB Collection.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-ii-belmont-s-revenge-game-boy', 'Castlevania II: Belmont''s Revenge', 'Castlevania', '1991-08-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9a8.jpg', 'Fifteen years after vanquishing the emperor of evil, Count Dracula, Christopher Belmont now faces a vampire swearing vengeance. Drac''s back. And he''s turned your son, Soleiyu Belmont, into a deadly demon to do his dirty deeds. Now not only do you have to rescue your kid from the Count''s clutches, you have to first track him down in four creep packed Castles. Fortunately, you posses weapons like armor piercing Battle Axes, beast burning Holy Water, and the Legendary Mystic Whip. And you can increase your arsenal with power up items like Crystal Balls, Hearts, and Candles. Strap on your shield and step into the shadows. That is, if you''re prepared for the dwellers of darkness.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kid-dracula-game-boy', 'Kid Dracula', 'Castlevania', '1993-03-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vv9.jpg', 'His pearly fangs drive the girls wild, while his dead-of-the-party sense of humor makes them scream. He''s Kid Dracula, star of the mythical Transylvania 92010, and the coolest living corpse ever to stake his claim on the Game Boy. If you thought Mario had a way with magic, you should see junior jugular''s spellbinding powers, including the mesmerizing bat transformation. Poof! Nobody wings it better than Kid Drac.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-legends-game-boy', 'Castlevania Legends', 'Castlevania', '1998-03-11', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20d8.jpg', 'Every legend has a beginning. Now discover the beginning of the Castlevania Legend in Castlevania Legends for Game Boy. In this single-player adventure, you play as Sonia Belmont, the very first in the line of vampire hunting Belmonts. Use your whip to fend off the forces of darkness, as you work your way through six stages of non-linear gameplay. Explore the legendary areas of Castlevania, including the surrounding forest and the infamous clock tower. Don''t forget to collect hearts from the torches that litter the stages to gain extra lives. Adjustable difficulty settings allow you to choose the skill level at which you want to play. At the end of it all, Count Dracula himself awaits. Can you defeat him and put the evil to rest for another 100 years?', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('operation-c-game-boy', 'Operation C', 'Contra', '1991-02-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6fy1.jpg', 'Operation C is an Action game, developed and published by Konami, which was released in 1991.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-the-alien-wars-game-boy', 'Contra: The Alien Wars', 'Contra', '1994-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co64pk.jpg', 'Welcome to 2636 the year the notorious Red Falcon gets even-with an unprecedented alien onslaught orchestrated to push the Contra forces to their ultimate reaches. Plunge through a molten massacre on a high speed voyage to the guts of the archenemy alien. Check out the side and top perspectives that engulf you in a 3-D sensation. Pick off solar slimedogs while you scale over walls swing from girders and ropes whatever it takes to defeat Red Falcon''s allies. Sweat through five gut-splitting stages including the Streets of the Neo City and the Mucho Grande Badlands.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-game-boy', 'Batman', 'DC', '1990-06-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fx3.jpg', 'This addon inlcudes a Batman costume inspired by the 2008 movie ‘The Dark Knight’.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-flash-game-boy', 'The Flash', 'DC', '1991-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coauc0.jpg', 'Need an Action Fix? Get Sky High!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-return-of-the-joker-game-boy', 'Batman: Return of the Joker', 'DC', '1992-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pij.jpg', 'Batman: Return of the Joker was developed and published by Sunsoft as the second in their Batman series on the Nintendo Entertainment System. It departed from the original game by focusing on the comic-book version of Batman instead of the movie-inspired conception. The story itself was self-contained, and did not depict a pre-existing storyline. The game is a side-scrolling platformer with beat ''em up features.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('swamp-thing-game-boy', 'Swamp Thing', 'DC', '1992-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w0k.jpg', 'A Handheld Electronic LCD device based on the DC Comics superhero Swamp Thing.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-animated-series-game-boy', 'Batman: The Animated Series', 'DC', '1993-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7xj1.jpg', 'An LCD game based on the animation Batman: The Animated Series.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-game-boy', 'Batman Forever', 'DC', '1995-08-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gyn.jpg', 'The Game Boy version of Batman Forever', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-game-boy', 'Donkey Kong', 'Donkey Kong', '1994-07-22', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-land-game-boy', 'Donkey Kong Land', 'Donkey Kong', '1995-06-26', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wvc.jpg', 'Donkey Kong Land III is the last part in the Donkey Kong Land series and was released for the Game Boy by Nintendo in 1997.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-land-2-game-boy', 'Donkey Kong Land 2', 'Donkey Kong', '1996-09-23', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ww1.jpg', 'Donkey Kong Land 2 is the first sequel to Donkey Kong Land for the Nintendo Game Boy and was released in 1996.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-land-iii-game-boy', 'Donkey Kong Land III', 'Donkey Kong', '1997-10-27', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wvc.jpg', 'Donkey Kong Land III is the last part in the Donkey Kong Land series and was released for the Game Boy by Nintendo in 1997.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dr-mario-game-boy', 'Dr. Mario', 'Dr. Mario', '1990-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4lat.jpg', 'Dr. Mario Express, known in Japan and PAL regions as A Little Bit of... Dr. Mario (ちょっとDr. MARIO Chotto Dr. Mario?),[5] is a Mario action puzzle video game published by Nintendo. The game was released exclusively as a DSiWare title for the Nintendo DSi platform. Dr. Mario Express was first released as a launch title for the DSiWare service in Japan on December 24, 2008, and was released in both North America and PAL regions in 2009. The game was developed by Arika, which had also created Dr. Mario Online Rx for WiiWare.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-the-legend-game-boy', 'Dragon''s Lair: The Legend', 'Dragon''s Lair', '1991-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sj1.jpg', 'The Game Boy version for Dragon''s Lair is actually a port of Roller Coaster, with its protagonist replaced by Dirk the Daring. Dirk must collect all "lifestones" scattered all around the game world (by walking or jumping) to finally save Princess Daphne. The game world is divided in several screens which can be freely navigated and are a little wider than Game Boy''s screen. As Dirk moves the screen will scroll and when its limit is reached, it will flick to a new one. To help him move around, Dirk can jump over bumper cars, flying magic hats and other kinds of moving platforms.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-game-boy', 'DuckTales', 'DuckTales', '1990-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4wth.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-2-game-boy', 'DuckTales 2', 'DuckTales', '1993-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wrf.jpg', 'DuckTales 2 is a platform video game developed by Make Software and published by Capcom. It is a sequel to the original DuckTales based on the Disney animated series of the same name. It was released on the Nintendo Entertainment System in early 1993. The title was ported to the Game Boy handheld system in Japan and North America at the end of the year.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-gallery-game-boy', 'Game & Watch Gallery', 'Game & Watch Gallery', '1997-05-05', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60wm.jpg', 'Enjoy four different games from the classic Game & Watch Gallery series: Manhole, Fire, Octopus and Oil Panic. Original and revised versions of each game are included.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gargoyle-s-quest-game-boy', 'Gargoyle''s Quest', 'Gargoyle''s Quest', '1990-07-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27rm.jpg', 'Gargoyle''s Quest Brings Big-Screen Action to Game Boy!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golf-game-boy', 'Golf', NULL, '1990-02-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ek7.jpg', 'Experience iconic golf courses like Pebble Beach, St Andrews and Wolf Creek in the most realistic free golf game, now available on PC, Mac and Steam. Connect with millions of players all over the world!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kid-icarus-of-myths-and-monsters-game-boy', 'Kid Icarus: Of Myths and Monsters', 'Kid Icarus', '1991-11-05', 'Game Boy', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5v48.jpg', 'A lighthearted adventure with mythical challenges. The "8-bit Summer" series continues with this classic action game from 1991. Angel Land is up to its halos in woes as mythical monsters are running rampant. Pit, the original Kid Icarus, must save the realm again. Armed with his trusty bow, he''ll zap the bad guys and find the Three Sacred Treasures hidden by Palutena. Only after this grueling training will he be strong enough to take on the dark forces behind Angel Land''s troubles. Pit will encounter old friends and new enemies - from helpful Centurions to the dreaded Eggplant Wizard - as he journeys from the depths of the underworld to the towers of the sky palace. Find hammers to shatter special walls and reveal helpful items. Collect hearts by fighting off Pit''s foes. Train hard and battle harder. Pit''s challenges make the labors of Hercules look like a walk in the park.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-dream-land-game-boy', 'Kirby''s Dream Land', 'Kirby', '1992-08-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ffy.jpg', 'The gluttonous King Dedede has stolen all of the food from the inhabitants of Dream Land for a midnight feast, so Kirby, a resident of Dream Land, goes to retrieve the food and stop Dedede. Kirby''s Dream Land plays like other platformers of the 8-bit and 16-bit era of video games: Kirby must use various natural abilities and occasionally external abilities or items while heading toward the goal at the end of each level. Like many 1980s-era platformers, the player can accumulate points, with an extra life granted when the player has enough points. However, because Kirby lacks a save function, scores are not recorded. Also, there are no save files, so the player has to start over again when the Game Boy is turned off, if the player chooses to return to the title screen after a Game Over, or if the player resets the game. All levels are played on a two-dimensional plane, letting Kirby move only left, right, up, and down. Kirby can walk, jump, and fly. Kirby can also inhale objects and enemies, swallowing them or spitting them out as projectiles.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-pinball-land-game-boy', 'Kirby''s Pinball Land', 'Kirby', '1993-11-30', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qv2.jpg', 'Choose your world and take aim! Kirby will be launched into the fast-paced danger of uncharted worlds, but you can help him face his foes head on. It''s a pinball race to check out each new world''s surprise enemies and pitfalls. Flip Kirby in battles against lethal eyeballs, a shooting tree and mace-swinging maniacs. Take aim and leap to new worlds!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-dream-land-2-game-boy', 'Kirby''s Dream Land 2', 'Kirby', '1995-05-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7crs.jpg', 'Kirby returns and has joined forces with new friends in this thrilling sequel!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-block-ball-game-boy', 'Kirby''s Block Ball', 'Kirby', '1996-05-04', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pmh.jpg', 'Kirby''s back with fast-paced, four-way action!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-star-stacker-game-boy', 'Kirby''s Star Stacker', 'Kirby', '1997-07-14', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53e2.jpg', 'Kirby''s Star Stacker is the official English title given to a puzzle Kirby game that was originally released on Japan''s Super Famicom system on February 1, 1998. It is a remake of Kirby''s Star Stacker, which is known in Japan under exactly the same name as the remake. The game was originally released as a new title for the Nintendo Power flash RAM service, but was released in standard cartridge form a year later. It was intended for international release, but the SNES''s lifespan ended in North America and Europe before the game could be localized in either region. The standard cartridge release of the game also came out in the exact year of the SNES''s discontinuation in North America, further compounding its isolation. The game was the final title in the Kirby series officially published for Super Famicom. A North American and European release would eventually be seen through the Nintendo Switch Online service in September 2023.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-link-s-awakening-game-boy', 'The Legend of Zelda: Link''s Awakening', 'The Legend of Zelda', '1993-08-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4o47.jpg', 'The Legend of Zelda: Link''s Awakening DX is an updated re-release of Link''s Awakening with several new additions, the most notable of which being the entire game is now in color.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-2-the-tribes-game-boy', 'Lemmings 2: The Tribes', 'Lemmings', '1994-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6dnq.jpg', 'This port is almost completely identical to the main release. However, the lack of game intro and the greatly reduced quality of sounds with a chiptune soundtrack due to the sound card makes this an overall inferior port.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-game-boy', 'Lemmings', 'Lemmings', '1994-08-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-adventure-game-boy', 'Final Fantasy Adventure', 'Mana', '1991-11-01', 'Game Boy', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpk.jpg', 'In the Empire of Glaive, a gladiator-slave is forced to fight evil monsters controlled by the Dark Lord. But when his best friend is mortally wounded, he learns of a secret pendant which will give him great power. As the hero, you must battle your way out of the Dark Knight''s castle and search through a dangerous world for the girl who has the pendant. But you discover she has been captured by the Dark Knight''s men. To free her, you must find the legendary sword and fight off the Dark Knight''s beasts and overlords through deserts, snowfields, lakes, forests, and caves. Are you ready for the adventure of your life?', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-game-boy', 'Marble Madness', NULL, '1991-05-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-land-game-boy', 'Super Mario Land', 'Mario', '1989-07-31', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co216h.jpg', 'Hey! Things are really cookin'' on Kitchen Island! Wario''s got a scheme to steal the pirates'' treasure so he can have his very own castle! You help Wario get the treasure by smashing into the the magic pots! Each pot changes him into Dragon Wario, Bull Wario, or Jet Wario! With each change comes new powers!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-land-2-6-golden-coins-game-boy', 'Super Mario Land 2: 6 Golden Coins', 'Mario', '1992-11-02', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7gxg.jpg', 'Super Mario Land 2: 6 Golden Coins is a platforming game for the Game Boy and the sequel to Super Mario Land. It also marks the debut of Mario''s self-proclaimed arch rival Wario, who would later become a recurring character in the Mario series as well as a protagonist in his own series. The game features new graphics, power-ups, challenges, and a completely original storyline.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-picross-game-boy', 'Mario''s Picross', 'Mario', '1995-03-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qxw.jpg', 'Mario''s Super Picross is the first sequel to the Game Boy game, Mario''s Picross, and can be played on the Super Famicom. After the commercial failure of Mario''s Picross in the West, this sequel was released only in Japan. The game plays much the same way as the first, except Wario appears in it and presents his own set of special rules, which also return in the sequel. Other features includes game-saves, hints and tutorials.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-game-boy', 'The Amazing Spider-Man', 'Marvel', '1990-07-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-punisher-the-ultimate-payback-game-boy', 'The Punisher: The Ultimate Payback!', 'Marvel', '1991-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dsx.jpg', 'The Punisher: The Ultimate Payback is an Action game, developed by Beam Software and published by Acclaim, which was released in 1991.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-game-boy', 'The Amazing Spider-Man 2', 'Marvel', '1992-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-3-invasion-of-the-spider-slayers-game-boy', 'The Amazing Spider-Man 3: Invasion of the Spider-Slayers', 'Marvel', '1993-01-01', 'Game Boy', 0, 0, NULL, NULL, NULL, NULL, 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-and-the-avengers-game-boy', 'Captain America and The Avengers', 'Marvel', '1994-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h0d.jpg', 'The Captain America and the Avengers for Game Boy.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-the-x-men-in-arcade-s-revenge-game-boy', 'Spider-Man and the X-Men in Arcade''s Revenge', 'Marvel', '1994-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal21.jpg', 'Spider-Man and members of the X-Men have teamed up in this side-scrolling action game to fight against Arcade, who has built a giant amusement park for the sole purpose of trapping and destroying the super-heroes. You first play as Spider-Man, who sees the X-Men get kidnapped by Arcade and follows them. Once you make it inside Arcade''s park you can choose to play as Spider-Man, Cyclops, Storm, Gambit, or Wolverine, each of whom are trapped in a different part of Arcade''s maze of deadly traps. You must navigate all five of them safely out, using their different skills and abilities while defeating baddies and bosses along the way.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-and-x-o-manowar-in-heavy-metal-game-boy', 'Iron Man and X-O Manowar in Heavy Metal', 'Marvel', '1996-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co80mh.jpg', 'The Game Boy port of Iron Man and X-O Manowar in Heavy Metal.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-dr-wily-s-revenge-game-boy', 'Mega Man: Dr. Wily''s Revenge', 'Mega Man', '1991-12-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55bv.jpg', 'Dr. Wily''s most challenging robot masters will be there when you pump up the GameBoy. And knowing the maniac he is, he''s probably concocted a new one or two. Can you survive the eight empires before you break into Dr. Wily''s lab? Well, if you experienced MegaMan before, you know it''s no day at the beach. But good reason to get going on MegaMan in Dr. Wily''s Revenge. Now.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-ii-game-boy', 'Mega Man II', 'Mega Man', '1992-02-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5572.jpg', 'The second handheld installment of the Mega Man series has him (along with his dog, Rush) defeating eight more revived Robot Masters (from Mega Man 2 and Mega Man 3), while finding the whereabouts of Dr. Wily (who has traveled into the future to steal a weapon to counter Mega Man).', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-iii-game-boy', 'Mega Man III', 'Mega Man', '1992-12-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0j.jpg', 'Mega Man 3 Mobile is the mobile port of Mega Man 3 (NES). It was released for mobile phones and had adjustments to make the game playable on numeric keypads.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-iv-game-boy', 'Mega Man IV', 'Mega Man', '1993-12-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62v1.jpg', 'A huge celebration at the World Robot Expo is shattered by the sight of a flying saucer streaking across the sky. But instead of holding little green men, this saucer holds one very mad scientist! Armed with a mind control machine that transmits a sinister signal. Dr. Wily is ready to mesmerize all the robots of the city into an army of mindless metallic mercenaries!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-v-game-boy', 'Mega Man V', 'Mega Man', '1994-09-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5hwy.jpg', 'Mega Man V, known as Rockman World 5, is a video game developed and published by Capcom for the Game Boy handheld game console. It is the fifth and final game in the Game Boy version of the original Mega Man series. The game follows the adventures of the protagonist Mega Man as he must defend the Earth from a group of powerful robots from outer space called the "Stardroids". Mega Man V was also unique from the previous Game Boy Mega Man games as it features original and unique bosses rather than recycling those from the original Nintendo Entertainment System (NES) Mega Man games.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-ii-return-of-samus-game-boy', 'Metroid II: Return of Samus', 'Metroid', '1991-11-01', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wwx.jpg', 'A Sinister Planet Threatens the Galaxy!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-shadow-game-boy', 'Ninja Gaiden Shadow', 'Ninja Gaiden', '1991-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co404u.jpg', 'When a madman threatens to take over the entire world, our beloved hero Ryu must travel the globe to get to New York. Once he gets there, there are hazards and enemies hiding in each and every nook and cranny. If you think the "Big Apple" is dangerous in real life, you''ll be amazed at the depths of evil employed by the big-city villains in this escapade. You''ll have to hack, slash, and kick your way through the streets and all the way to one of the most dangerous bosses in videogame history. Another installment in the ongoing Ninja Gaiden series, Ninja Gaiden Shadow boasts intense graphics, a great storyline, and smooth gameplay. The world could really use a hero, and if you''ve got the skills and know-how, you could be it.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-adventures-game-boy', 'Oddworld Adventures', 'Oddworld', '1998-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gtu.jpg', 'Oddworld Adventures is a demake of Abe''s Oddysee due to the Game Boy''s limitations, and the game is massively shortened to just one area, the Paramonian Temple. A sequel was later released, known as Oddworld Adventures II, mostly based off Abe''s Exoddus, and with many improved elements over the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-game-boy', 'Pac-Man', 'Pac-Man', '1990-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-attack-game-boy', 'Pac-Attack', 'Pac-Man', '1994-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kty.jpg', 'Pac-Man makes a rare appearance outside of a maze environment in Pac-Attack, a fun and quirky puzzle game. This unique entry in the genre puts its own twist on established conventions and adds one of gaming''s most iconic characters to the mix. The goal is simple: Keep your screen clear of falling blocks and ghosts by lining up blocks horizontally, causing them to disappear.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-in-time-game-boy', 'Pac-In-Time', 'Pac-Man', '1995-01-03', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbsa.jpg', 'The evil Ghost Witch has cast a vicious spell on Pac-Man and thrown him back in time to when he was a Pac-Boy. Only you can save him now. Down some Pac-Pellets and get ready to battle your way through a totally supersonic side-scrolling adventure. Journey through snowy mountains and forests, collect fireballs and bubbles, crunch Pac-Bats and ghosts, swim like a fish and swing like a monkey... and ultimately get Pac-Man back to the real world! Sega Mega Drive and Sega Game Gear versions were announced at CES 1995, but were ultimately cancelled for unknown reasons. A prototype of the Game Gear version has since been found and released online.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-game-boy', 'Pac-Man World', 'Pac-Man', '1999-10-15', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oy.jpg', 'Twenty years after Pac-Man''s first adventure in Pac-Land, Pac-Man returns one day to his house only to find it deserted. Toc-Man and his ghosts have kidnapped Pac-Man''s friends, Ms. Pac-Man, Pac Jr., Baby Pac, Professor Pac, Pooka, and Chomp-Chomp the dog! Pac-Man must venture to Toc-Man''s lair on Ghost Island to rescue his friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-red-version-game-boy', 'Pokémon Red Version', 'Pokémon', '1998-09-28', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k6q.jpg', 'Started in 2018 by a secret cabal of ancient Pokemon nerds, Shin Pokemon is an enhancement ROM hack of Pokemon Red & Blue that aims to be the ultimate remaster fans never got. It is a mostly-vanilla hack that focuses on fixing game engine bugs and oversights from the original game. Additionally, trainer AI routines are improved and multiple quality-of-life enhancements have been added. It also acts as a kind of research-informed speculative work that interprets what the 2016 Nintendo Virtual Console re-release of Gen-1 Pokemon could have been. It is the image of a glitch-free experience with player-friendly goodies and enhancements common to other modern remasterings.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-blue-version-game-boy', 'Pokémon Blue Version', 'Pokémon', '1998-09-28', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k6p.jpg', 'Started in 2018 by a secret cabal of ancient Pokemon nerds, Shin Pokemon is an enhancement ROM hack of Pokemon Red & Blue that aims to be the ultimate remaster fans never got. It is a mostly-vanilla hack that focuses on fixing game engine bugs and oversights from the original game. Additionally, trainer AI routines are improved and multiple quality-of-life enhancements have been added. It also acts as a kind of research-informed speculative work that interprets what the 2016 Nintendo Virtual Console re-release of Gen-1 Pokemon could have been. It is the image of a glitch-free experience with player-friendly goodies and enhancements common to other modern remasterings.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-yellow-special-pikachu-edition-game-boy', 'Pokémon Yellow: Special Pikachu Edition', 'Pokémon', '1999-10-18', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pih.jpg', 'Pokémon Yellow is an enhanced version of Pokémon Red and Blue that allows you to start the game with your very own Pikachu following you around on-foot and collect the 3 other starters from strangers you meet around the region. However, your goal remains the same: catch them all and become the ultimate Pokémon Master.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-game-boy', 'Prince of Persia', 'Prince of Persia', '1992-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-final-fantasy-legend-game-boy', 'The Final Fantasy Legend', 'SaGa', '1990-09-30', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rle.jpg', 'The long-running FINAL FANTASY series hits the Game Boy with FINAL FANTASY LEGEND. Create your party by choosing four warriors from eight different character classes including humans, mutants, and monsters. Humans specialize in hand-to-hand combat and have access to most weapons, mutants wield magic like no other, and monsters can evolve themselves by feasting on the meat of fallen opponents to become new monsters! Venture your way through four different lands each with a unique fantasy theme to stop the wicked Ashura Devils from destroying the world. A beautiful fantasy soundtrack adds atmosphere to the experience and puts you in the right mood. This single-player RPG features battery backup to save your progress, and is compatible with both Game Boy and Game Boy Color. RPG fans on the go should check out FINAL FANTASY LEGEND.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-legend-ii-game-boy', 'Final Fantasy Legend II', 'SaGa', '1991-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7v7x.jpg', 'The Final Fantasy Legend series continues! In this classic RPG adventure, you are on a quest to reunite with your father. In order to find your father, you must travel far and wide to find the scattered fragments of a mystical force, known as Magi. Your quest takes you to several mysterious lands filled with caves, temples, enemy bases, ancient Japanese castles, and much more. Many of the worlds are filled with quirky inhabitants, such as the world of giants. Another world praises beauty but banishes ugliness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-legend-iii-game-boy', 'Final Fantasy Legend III', 'SaGa', '1993-08-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpm.jpg', 'Millennia ago, a fierce battle was waged for control of an idyllic world known as Pureland. After much fighting, the brave warriors of Pureland were protectively sealed in their own dimension, away from the rest of the universe. This was done by means of Talon, a powerful space craft capable of traveling through both time and space. Centuries have passed and the would-be master of Pureland have managed to create a rift in the galaxy, sending the Pureland Water Entity to devour all that stands in its path. You must journey through past, present, and future to find the 13 pieces of the now-divided Talon. Only then can you save the universe from total destruction.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-game-boy', 'Space Invaders', 'Space Invaders', '1990-03-30', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-game-boy', 'Star Wars', 'Star Wars', '1992-11-01', 'Game Boy', 0, 0, NULL, NULL, NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-empire-strikes-back-game-boy', 'Star Wars: The Empire Strikes Back', 'Star Wars', '1993-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v53.jpg', 'Now transform your Star Wars games into a new adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-star-wars-return-of-the-jedi-game-boy', 'Super Star Wars: Return of the Jedi', 'Star Wars', '1995-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xp.jpg', 'All the Adventure and Excitement of the 16-bit Game -- are you ready to challenge the dark side?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-gb-game-boy', 'Harvest Moon GB', 'Story of Seasons', '1998-08-12', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6o.jpg', 'Harvest Moon GB is the second game in the Harvest Moon series of video games, and was developed by Victor Interactive Software. Harvest Moon GB is the first portable Harvest Moon game, developed for the Game Boy. A Game Boy Color version was released later under the name Harvest Moon GBC.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tennis-game-boy', 'Tennis', NULL, '1984-03-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zpn.jpg', 'First Person Tennis is the first tennis simulator developed for HTC Vive and Oculus Rift.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-game-boy', 'Tetris', 'Tetris', '1989-07-31', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69ff.jpg', 'Tetris is now available for the first time on the PSP! See why hundreds of millions of players worldwide have made Tetris one of the most popular games ever! It features the famous Marathon Mode along with 12 new mini-versions based on the Tetris gameplay you know & love. Offering 15 levels of difficulty, it records your ''best times'' and ‘best scores’ for each variation. Use the Replay Viewer to look up cool moves in the in-game glossary and check out sweet replays of some of the best Tetris players in the world. TETRIS has changed with the times, but after 25 years some things remain the same... it’s captivating, fun, and addictive! Let the Tetris revolution begin!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hatris-game-boy', 'Hatris', 'Tetris', '1991-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7198.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-2-game-boy', 'Tetris 2', 'Tetris', '1993-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobgsb.jpg', 'Tetris 2 is a 1990 video game by František Fuka (Fuxoft). It is inspired by a Soviet game Tetris. It is considered to be the most successful game developed by Fuka.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-blast-game-boy', 'Tetris Blast', 'Tetris', '1996-01-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dp1.jpg', 'Have a BLAST! The favorite puzzle sensation EXPLODES back on the Game Boy scene! Test your dexterity at the highest level yet! With rapid moves align blocks containing explosive bombs and clear away the screen. KA-BLAAM!! In FIGHT MODE build a mega bomb and take out menacing enemies that threaten your progress, BOOM! You''ve never experienced Tetris like this before! It''s DYNAM', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-attack-game-boy', 'Tetris Attack', 'Tetris', '1996-08-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dp0.jpg', 'The Game Boy version of the Super Nintendo game with the same name, which in turn is a version of the exclusive japanese game Panel de Pon.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-plus-game-boy', 'Tetris Plus', 'Tetris', '1997-08-25', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9idl.jpg', NULL, 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-battle-of-the-bionosaurs-game-boy', 'Turok: Battle of the Bionosaurs', 'Turok', '1997-12-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dpm.jpg', 'Turok: Battle of the Bionosaurs is an action platformer Game Boy adaptation of Turok: Dinosaur Hunter, developed by Bit Managers and published by Acclaim.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-super-mario-land-3-game-boy', 'Wario Land: Super Mario Land 3', 'Wario', '1994-03-14', 'Game Boy', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co216h.jpg', 'Hey! Things are really cookin'' on Kitchen Island! Wario''s got a scheme to steal the pirates'' treasure so he can have his very own castle! You help Wario get the treasure by smashing into the the magic pots! Each pot changes him into Dragon Wario, Bull Wario, or Jet Wario! With each change comes new powers!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-blast-featuring-bomberman-game-boy', 'Wario Blast: Featuring Bomberman!', 'Wario', '1994-11-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b96.jpg', 'OH, NO! Wario has stumbled upon the secret gateway into Bomberland! Now the greedy warmonger wants to claim the land, its inhabitants, and treasures as his own. Entering the underground labyrinth, he meets the resistance of the Madbombers - explosives experts who have some TNT tricks and surprises to toss at Wario. The battle heats up as Wario and Bomberman each try to outwit the other, level by level in a dynamite duel!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-ii-game-boy', 'Wario Land II', 'Wario', '1998-03-09', 'Game Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qfz.jpg', 'What kind of no-good ruffians would break into my castle and steal my treasures?! It''s that rotten Captain Syrup and that Black Sugar Gang! I''m looking out for bad guys and scavenging for coins as I track down my treasures. If I don''t get them all the first time, that''s OK. I can go back again and again until I find them all. Captain Syrup doesn''t stand a chance against me!', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wave-race-game-boy', 'Wave Race', 'Wave Race', '1992-07-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ksa.jpg', 'This version of Wave Race 64 was released only in Japan and has Rumble Pak compatibilty.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-game-boy', 'Yoshi', 'Yoshi', '1992-07-10', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5z4t.jpg', 'Yoshi is a puzzle game featuring the titular character. In this game, the player must stack two of the same Mario enemy on top of one another to clear them. The concept of the game was inspired by Tetris.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-cookie-game-boy', 'Yoshi''s Cookie', 'Yoshi', '1993-04-01', 'Game Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yby.jpg', 'The Game Boy version of Yoshi''s Cookie was released as part of a dual launch with the NES version of the game. While they both featured the original three forms of game play, individuals on Gameboy were at an advantage in the form of the amount of players that could compete against one another in the VS mode.', 'NA', 14);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-bomberman-super-nintendo-entertainment-system', 'Super Bomberman', 'Bomberman', '1993-09-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x7j.jpg', 'A sequel to Super Bomberman R, featuring an expanded story mode, and a new "Castle" battle mode which has one group teaming up to build castle defenses while the other attempts to breach the castle and take the treasure.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-bomberman-2-super-nintendo-entertainment-system', 'Super Bomberman 2', 'Bomberman', '1994-09-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x7j.jpg', 'A sequel to Super Bomberman R, featuring an expanded story mode, and a new "Castle" battle mode which has one group teaming up to build castle defenses while the other attempts to breach the castle and take the treasure.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-in-claws-encounters-of-the-furred-kind-super-nintendo-entertainment-system', 'Bubsy in Claws Encounters of the Furred Kind', 'Bubsy', '1993-05-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sls.jpg', 'Bubsy in Claws Encounters of the Furred Kind, known as Bubsy for short, is a platform video game released by Accolade in the early 1990s. It is the first game in the Bubsy series of video games. The game''s name is a play on words in reference to Close Encounters of the Third Kind, with the game revolving around Bubsy defending the planet''s supply of yarnballs from alien invaders. The game received a sequel, Bubsy 2, in 1994.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-2-super-nintendo-entertainment-system', 'Bubsy 2', 'Bubsy', '1994-10-15', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h04.jpg', NULL, 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-castlevania-iv-super-nintendo-entertainment-system', 'Super Castlevania IV', 'Castlevania', '1991-12-04', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20dc.jpg', 'A century of Transylvanian tranquility is about to come to a shocking end. Once again the mortifying screams of helpless villagers shake the ground as they huddle against new nightmarish horrors unleashed by the Duke of Darkness, Count Dracula. And this time he has a tombstone with your name on it, Simon Belmont.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-dracula-x-super-nintendo-entertainment-system', 'Castlevania: Dracula X', 'Castlevania', '1995-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9a9.jpg', 'The Legend Returns... Rising up from his eternal sleep, Count Dracula is back again to battle the descendants of the great vampire-stalking Belmont family of the Castlevania series. He has summoned his dark minions-Cerberus, Minaurus, and the Salamander-to bring a reign of terror on the land. Grab your whip and try to defeat these dark forces in this new conversion of the hit Japanese game: DRACULA X. The 7+ stages unfold with myriad possibilities depending on the choices you make during the game. This multi-ending, multi-story feature takes you through many levels of adventure. You must strategically use magical tomes, mystical power-ups and titanic weapons to defeat the horrifying bosses and discover secret bonus levels.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chrono-trigger-super-nintendo-entertainment-system', 'Chrono Trigger', 'Chrono', '1995-08-11', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87df.jpg', 'As the definitive version of Chrono Trigger, not only have the controls been updated, the graphics and sound have also been revamped to make your adventure even more fun and enjoyable to play. To complete your journey, also included is the mysterious ‘Dimensional Vortex’ dungeon and the forgotten ‘Lost Sanctum’ dungeon. Meet the challenges presented to you and long-lost secrets may be revealed...', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-super-nintendo-entertainment-system', 'Sid Meier''s Civilization', 'Civilization', '1995-10-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hgf.jpg', 'An expansion pack to Sid Meier''s compelling strategy game Civilization II, the rare Scenario Disk Conflicts in Civilization includes 20 bonus scenarios, including eight "Best of the Net" scenarios created by fans of the series.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-iii-the-alien-wars-super-nintendo-entertainment-system', 'Contra III: The Alien Wars', 'Contra', '1992-03-26', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co64pi.jpg', 'This game is action from beginning to end, do not think that you will have a moment of peace, even because Aliens are at war with planet earth, and resting will be your least concern.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-returns-super-nintendo-entertainment-system', 'Batman Returns', 'DC', '1993-04-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zck.jpg', 'Batman Returns is a beat-em-up side-scrolling game designed for the Sega consoles. It was published by Sega.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-adventures-of-batman-robin-super-nintendo-entertainment-system', 'The Adventures of Batman & Robin', 'DC', '1994-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6379.jpg', 'Robin & Commissioner Gordon have mysteriously disappeared, and Batman suspects kidnapping. Have our two comrades succumb to the deadly beauty of Poison Ivy? Does the Riddler know the answer? Or will The Joker have the last laugh?', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-death-and-return-of-superman-super-nintendo-entertainment-system', 'The Death and Return of Superman', 'DC', '1994-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25nt.jpg', 'Brace yourself for a hard-hitting fight to the finish that lets you relive the classic DC comic book series! As Superman, fight for your life against mighty Doomsday, the vile distributor of death and destruction! Then, control the destiny of the four Supermen - each claiming to be the one, true Superman! Explode through 10 levels of super-powered battles and fly at furious speeds - until only the real Superman is left standing!', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-task-force-super-nintendo-entertainment-system', 'Justice League Task Force', 'DC', '1995-06-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wc7.jpg', 'Justice League Task Force is a fighting game produced by Sunsoft and distributed by Acclaim for the Super Nintendo Entertainment System and Genesis in 1995. The Super NES version was co-developed by Blizzard Entertainment and the Genesis version by Condor, Inc. (later known as Blizzard North).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-super-nintendo-entertainment-system', 'Batman Forever', 'DC', '1995-08-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gyn.jpg', 'The Game Boy version of Batman Forever', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-super-nintendo-entertainment-system', 'Donkey Kong Country', 'Donkey Kong', '1994-11-21', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jhu.jpg', 'Game Boy Color port of Donkey Kong Country.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-2-diddy-s-kong-quest-super-nintendo-entertainment-system', 'Donkey Kong Country 2: Diddy''s Kong Quest', 'Donkey Kong', '1995-12-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217m.jpg', 'Donkey Kong Country 2: Diddy''s Kong Quest is the sequel to Donkey Kong Country. It was developed by Rare and is one of the best selling Super Nintendo games.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-3-dixie-kong-s-double-trouble-super-nintendo-entertainment-system', 'Donkey Kong Country 3: Dixie Kong''s Double Trouble!', 'Donkey Kong', '1996-11-18', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co217n.jpg', 'Monkey Mayhem Lives On!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-super-nintendo-entertainment-system', 'Doom', 'Doom', '1995-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-super-nintendo-entertainment-system', 'Dragon''s Lair', 'Dragon''s Lair', '1993-02-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('earthbound-super-nintendo-entertainment-system', 'EarthBound', 'EarthBound', '1995-06-05', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/udoqdu91vczupvadieku.jpg', 'Unrelated to the popular SNES RPG, Earthbound is an adventure game developed by Xtalsoft in 1983.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f-zero-super-nintendo-entertainment-system', 'F-Zero', 'F-Zero', '1991-08-23', 'Super Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ufz.jpg', 'F-Zero is set in the year 2560, when humanity''s multiple encounters with alien life forms had resulted in the expansion of Earth''s social framework. This led to commercial, technological and cultural interchanges between planets. The multi-billionaires who earned their wealth through intergalactic trade were mainly satisfied with their lifestyles, although most coveted more entertainment in their lives. This resulted in a new entertainment based on the Formula One races to be founded with vehicles that could hover one foot above the track. These Grand Prix races were soon named "F-Zero" after a rise in popularity of the races. The game introduced the first set of F-Zero racers: Captain Falcon, Dr. Stewart, Pico, and Samurai Goroh.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-ii-super-nintendo-entertainment-system', 'Final Fantasy II', 'Final Fantasy', '1991-11-23', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob25b.jpg', 'The WonderSwan Color version of Final Fantasy II included completely redone graphics in the manner of the 16-bit generation Final Fantasy games and includes larger character sprites, remixed music by Tsuyoshi Sekito, and full graphical backgrounds in battle mode. It is from this base that the international version of Final Fantasy II began to take shape.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-mystic-quest-super-nintendo-entertainment-system', 'Final Fantasy Mystic Quest', 'Final Fantasy', '1992-10-05', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y0b.jpg', 'Focus Tower is the center of the world and balances the forces of the world. However 4 monsters have taken the 4 elemental crystals (Earth, Water, Fire, Wind) for their own use, and also taken the 4 keys that for doors inside of Focus Tower. With the balance disrupted, disasters befall the world. A young boy by the name of Benjamin finds his home village destroyed. Meeting a mysterious old man while trying to escape from earthquakes, he soon learns that he is the prophesized hero and the only one who can save the world. Benjamin must recover the 4 crystals, unlock Focus Tower and defeat the ultimate monster before the 5th crystal, the Crystal of Life is corrupted.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-iii-super-nintendo-entertainment-system', 'Final Fantasy III', 'Final Fantasy', '1994-10-11', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ojk.jpg', 'Two of the most representative titles of the classic role-playing game series, brought together to get lost in their timeless stories of heroes, betrayal, love and redemption... now on PC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('demon-s-crest-super-nintendo-entertainment-system', 'Demon''s Crest', 'Gargoyle''s Quest', '1994-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69t5.jpg', 'This is the third game featuring Firebrand from the Gargoyle''s Quest series. It is side a scrolling platformer.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-ghouls-n-ghosts-super-nintendo-entertainment-system', 'Super Ghouls ''n Ghosts', 'Ghosts ''n Goblins', '1991-11-28', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7run.jpg', 'As dauntless knight Arthur you are caught up in the most dangerous of quests! A spell has been cast upon the kingdom. Your fair maiden, Princess Prin Prin has been snatched up by the evil emperor. Only as Arthur can you get her back from the creatures of the undead that haunt the land. Test your courage and skill to the limit. You must keep up the quest. On your journey, your mightiest weapon of all awaits you... MAGIC!', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-dream-course-super-nintendo-entertainment-system', 'Kirby''s Dream Course', 'Kirby', '1995-02-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob67a.jpg', 'Kirby''s Dream Course is a 1994 miniature golf video game developed by HAL Laboratory and Nintendo EAD and published by Nintendo for the Super Nintendo Entertainment System (SNES).', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-avalanche-super-nintendo-entertainment-system', 'Kirby''s Avalanche', 'Kirby', '1995-04-25', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pmf.jpg', 'King Dedede has challenged Kirby and other members of Dream Land to an Avalanche Competition in the Dream Fountain. Kirby, taking on the challenge, has decided to battle his way through the forest and into the Dream Fountain to win the Avalanche Cup from King Dedede.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-super-star-super-nintendo-entertainment-system', 'Kirby Super Star', 'Kirby', '1996-09-20', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qyi.jpg', 'Kirby Super Star, released as Kirby''s Fun Pak in PAL regions, is a platforming video game developed by HAL Laboratory and published by Nintendo. The game was advertised as featuring eight games: seven short subsections with the same basic gameplay, and two minigames. Kirby Super Star sees players take on the role of Kirby, who can float around the screen, inhale blocks and enemies and spit them out. By swallowing certain enemies after inhaling them, Kirby can copy their abilities and use them as his own, becoming able to perform a wide range of attacks. A unique feature of the game is the addition of helpers. When Kirby is in possession of an ability, he can choose to transform it into a helper character which can be controlled by a second player or the computer AI.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-dream-land-3-super-nintendo-entertainment-system', 'Kirby''s Dream Land 3', 'Kirby', '1997-11-27', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xr.jpg', 'That mean old King Dedede is at it again! He''s causing his mischief and Dreamland''s in trouble! Kirby, the resident hero of Dreamland, sets out to teach Dedede a lesson, this time with the help of many of his good friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-a-link-to-the-past-super-nintendo-entertainment-system', 'The Legend of Zelda: A Link to the Past', 'The Legend of Zelda', '1992-04-13', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3nsh.jpg', 'The Legend of Zelda: A Link to the Past & Four Swords features two games, a port of the SNES game The Legend of Zelda: A Link to the Past and a new multiplayer adventure called Four Swords.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-super-nintendo-entertainment-system', 'Lemmings', 'Lemmings', '1992-03-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-2-the-tribes-super-nintendo-entertainment-system', 'Lemmings 2: The Tribes', 'Lemmings', '1995-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6dnq.jpg', 'This port is almost completely identical to the main release. However, the lack of game intro and the greatly reduced quality of sounds with a chiptune soundtrack due to the sound card makes this an overall inferior port.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('secret-of-mana-super-nintendo-entertainment-system', 'Secret of Mana', 'Mana', '1993-10-03', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9a7h.jpg', '"The memorable adventure of Randi, Primm and Popoi is reborn as "Secret of Mana"!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-world-super-nintendo-entertainment-system', 'Super Mario World', 'Mario', '1991-08-23', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co779k.jpg', 'The remake of Super Mario World included in Super Mario Advance 2 for the Game Boy Advance. In this refreshed version for the portable system, you can choose to play as either Mario or Luigi in single player.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-is-missing-super-nintendo-entertainment-system', 'Mario Is Missing!', 'Mario', '1992-04-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21l6.jpg', 'Mario Is Missing! is an educational game and the first game where Luigi is the main protagonist with Mario in a supporting role. The main gameplay consists of moving around a city in side-scrolling manner while jumping on Koopas to collect stolen artifacts. Luigi then must secure the city by taking these artifacts to their respective locations and correctly answering two questions about the landmark.The computer version is a point-and-click adventure game, while the NES and SNES versions have more of an emphasis on platforming.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-paint-super-nintendo-entertainment-system', 'Mario Paint', 'Mario', '1992-08-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2er1.jpg', 'Mario Paint is an educational game that allows anyone to create simple pictures, paint over black and white pictures, or free draw their own using the specially developed SNES Mouse. The player can also create their own piece of music using a selection of notes and themes, create greeting cards and animations, or play a game of "Gnat Attack", where they use the mouse to control a swatter to swat flies.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-all-stars-super-nintendo-entertainment-system', 'Super Mario All-Stars', 'Mario', '1993-08-11', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co98uf.jpg', 'Put quite simply, this is the amalgamation of the previously released Super Mario All-Stars compilation with Super Mario World added. While games already in the All-Stars bundle have major graphical and audio improvements, the only change made to Super Mario World is a slight tweak of Luigi''s graphic sprites, making him slightly thinner and taller (rather than being the same height and stature of Mario) which does not affect gameplay.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-time-machine-super-nintendo-entertainment-system', 'Mario''s Time Machine', 'Mario', '1993-12-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wwm.jpg', 'Mario''s Time Machine is an edutainment title and the successor of Mario is Missing! The game is meant to teach younger players basic world history and is the last Mario Discovery Series game before discontinuation. This game and Hotel Mario are the only games in the Mario franchise in which Mario as a protagonist has full lines of dialogue. The objective of the game is to return the historical artifacts to their proper time periods thanks to the central hub. As soon as you enter a certain time period you need to explore and interact with various residents of the area in order to get more information about the artifact, the period itself and the person connected to it.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-early-years-fun-with-numbers-super-nintendo-entertainment-system', 'Mario''s Early Years: Fun with Numbers', 'Mario', '1994-09-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21mb.jpg', 'Mario''s Early Years! Fun with Numbers is an educational Mario game that taught numbers and basic geometry to children. The game takes place on a set of islands to which Mario and Princess Peach sail. The player can click one of the islands to enter, after which the player sees Luigi asleep. Once the player clicks him, various activities must be performed to learn. Activities include counting objects, identifying shapes, comparing sizes, and sorting.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-early-years-fun-with-letters-super-nintendo-entertainment-system', 'Mario''s Early Years! Fun with Letters', 'Mario', '1994-10-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21m9.jpg', 'Mario''s Early Years: Fun With Letters is a collection of letter-related activities for kids ages 3 to 6. Playing with either Mario or Princess Toadstool, you select from 10 different activity worlds each filled with different activities that range from letter recognition to sentence fill-in, letter-sound recognition, vowel recognition, etc. Each activity can be played in either Discovery mode, where you are free to do what you wish, or in Learning mode, where Luigi guides you through the activities.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-early-years-preschool-fun-super-nintendo-entertainment-system', 'Mario''s Early Years! Preschool Fun', 'Mario', '1994-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21m5.jpg', 'Mario''s Early Years! Preschool Fun is an educational developed for children under six years of age. The game is set around a group of islands, where each island teaches a different subject to the players. Part of the Mario''s Early Years educational series, Preschool Fun is different from the others because it doesn''t specialize in a specific subject. Instead, it teaches about the body, shapes, animal noises, counting, opposites, and colors. However, several of the activities share the common theme of following instructions. This was the last of three educational games to be released.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-all-stars-super-mario-world-super-nintendo-entertainment-system', 'Super Mario All-Stars + Super Mario World', 'Mario', '1994-12-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co98uf.jpg', 'Put quite simply, this is the amalgamation of the previously released Super Mario All-Stars compilation with Super Mario World added. While games already in the All-Stars bundle have major graphical and audio improvements, the only change made to Super Mario World is a slight tweak of Luigi''s graphic sprites, making him slightly thinner and taller (rather than being the same height and stature of Mario) which does not affect gameplay.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-rpg-legend-of-the-seven-stars-super-nintendo-entertainment-system', 'Super Mario RPG: Legend of the Seven Stars', 'Mario', '1996-05-13', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5r6p.jpg', 'A JRPG entry in the Super Mario franchise in which Mario meets many unlikely allies in order to jump and fight his way through the Mushroom Kingdom and collect stars to repair the Star Road, the pathway that grants people''s wishes, which was destroyed by Smithy, the otherworldly entity that hijacked Bowser''s castle and threw the Kingdom into disarray.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-kart-super-nintendo-entertainment-system', 'Super Mario Kart', 'Mario Kart', '1992-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coabiz.jpg', NULL, 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-the-x-men-in-arcade-s-revenge-super-nintendo-entertainment-system', 'Spider-Man and the X-Men in Arcade''s Revenge', 'Marvel', '1992-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal21.jpg', 'Spider-Man and members of the X-Men have teamed up in this side-scrolling action game to fight against Arcade, who has built a giant amusement park for the sole purpose of trapping and destroying the super-heroes. You first play as Spider-Man, who sees the X-Men get kidnapped by Arcade and follows them. Once you make it inside Arcade''s park you can choose to play as Spider-Man, Cyclops, Storm, Gambit, or Wolverine, each of whom are trapped in a different part of Arcade''s maze of deadly traps. You must navigate all five of them safely out, using their different skills and abilities while defeating baddies and bosses along the way.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-and-the-avengers-super-nintendo-entertainment-system', 'Captain America and The Avengers', 'Marvel', '1993-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h0d.jpg', 'The Captain America and the Avengers for Game Boy.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolverine-adamantium-rage-super-nintendo-entertainment-system', 'Wolverine: Adamantium Rage', 'Marvel', '1994-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xqh.jpg', 'Released in 1994 for both the Super NES and the Sega Genesis, Wolverine: Adamantium Rage is a platform-action video game. Teeny Weeny Games developed the Genesis version, while the Super NES version was created by Bits Studios. Despite being developed independently, the two versions share a common opening storyline and gameplay, though they differ in certain key aspects. Notably, it is one of the pioneering video games to incorporate a recharging health system.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-venom-maximum-carnage-super-nintendo-entertainment-system', 'Spider-Man and Venom: Maximum Carnage', 'Marvel', '1994-09-16', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal24.jpg', 'Spider-Man and Venom: Maximum Carnage is a side-scrolling beat ''em up game for the Super NES and Sega Genesis/Mega Drive, developed by Software Creations and published by Acclaim Entertainment and it''s subsidiary LJN in 1994. The game, based on a sprawling comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-super-nintendo-entertainment-system', 'The Incredible Hulk', 'Marvel', '1994-10-01', 'Super Nintendo Entertainment System', 0, 0, NULL, NULL, NULL, 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mutant-apocalypse-super-nintendo-entertainment-system', 'X-Men: Mutant Apocalypse', 'Marvel', '1994-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dgk.jpg', 'Because of a rise of anti-mutant activity in Genosha, Professor Xavier uses Cerebro to scan the island nation and discovers Apocalypse''s presence there. Genosha''s government is apparently using Apocalypse to bring their mutant population under control. However, Xavier suspects Apocalypse to follow his own plans and sends five X-Men, Cyclops, Wolverine, Psylocke, Beast and Gambit, to investigate.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-super-nintendo-entertainment-system', 'Spider-Man', 'Marvel', '1995-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('venom-spider-man-separation-anxiety-super-nintendo-entertainment-system', 'Venom/Spider-Man: Separation Anxiety', 'Marvel', '1995-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal37.jpg', 'Separation Anxiety is a side scrolling beat''em up game, featuring characters and stories taken from the Spiderman comics. The story is loosely based on a mini series of comics about Venom. In this game, the player(s) gets to choose between controlling Spider-Man, or his on and off again foe Venom. As Spiderman you must stop the life foundation who have removed five symbiotes from Venom. They plan to bond them with their soldiers, creating a dangerous army. Venom recovering from his wounds also realises he must destroy them.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-heroes-in-war-of-the-gems-super-nintendo-entertainment-system', 'Marvel Super Heroes In War of the Gems', 'Marvel', '1996-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b7l.jpg', 'The most powerful collection of Marvel Super Heroes now unite to battle treacherous mobs of Super-Villians! A mysterious foe has kicked off his plan to rule the world by collecting the Infinity Gems. While each gem controls one force of nature, combined they command limitless power.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-soccer-super-nintendo-entertainment-system', 'Mega Man Soccer', 'Mega Man', '1994-03-25', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pic.jpg', 'Mega Man Soccer, known in Japan as Rockman''s Soccer, is a soccer video game for the Super Nintendo Entertainment System/Famicom. The game is based on the original Mega Man series of action-platform games. Mega Man Soccer was first released in Japan on February 17, 1994 and in North America in April of that same year.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-7-super-nintendo-entertainment-system', 'Mega Man 7', 'Mega Man', '1995-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6o8y.jpg', 'Mega Man 7 is an action platform video game developed and published by Capcom for the Super Nintendo Entertainment System. It is the seventh game in the original Mega Man series. The game was released in Japan on March 24, 1995 and was localized later in the year in North America and Europe.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-super-nintendo-entertainment-system', 'Mega Man X', 'Mega Man X', '1994-01-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0b.jpg', 'This is the iOS-port of the original game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x2-super-nintendo-entertainment-system', 'Mega Man X2', 'Mega Man X', '1995-01-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co80st.jpg', NULL, 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x3-super-nintendo-entertainment-system', 'Mega Man X3', 'Mega Man X', '1996-01-31', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55pa.jpg', 'Mega Man X and his trusty partner Zero have a new force to reckon with. Who or what has caused a riot of Mavericks to break out in the experimental utopia known as Doppler Town?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-metroid-super-nintendo-entertainment-system', 'Super Metroid', 'Metroid', '1994-04-18', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4obe.jpg', 'Super Metroid Phazon is a full hack of Super Metroid.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('j-r-r-tolkien-s-the-lord-of-the-rings-vol-i-super-nintendo-entertainment-system', 'J.R.R. Tolkien''s The Lord of the Rings, Vol. I', 'Middle-earth', '1994-10-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cwz.jpg', 'J.R.R. Tolkien''s The Lord of the Rings, Vol. I is a fantasy role-playing game based on The Fellowship of the Ring, the first volume of the Lord of the Rings book trilogy by J.R.R. Tolkien. The events of the game follow those depicted in the book rather closely, though a few characters and occurrences are not present, and many quests have been added. Characters belonging to various races and nations join Frodo on his quest; these include key figures from the book as well as several characters unique to the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-trilogy-super-nintendo-entertainment-system', 'Ninja Gaiden Trilogy', 'Ninja Gaiden', '1995-01-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50ip.jpg', 'Here it is! The complete NINJA GAIDEN TRILOGY you asked for. Enjoy the 3 classic Nintendo Ninja Gaiden games on one Super NES Game Pak.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-attack-super-nintendo-entertainment-system', 'Pac-Attack', 'Pac-Man', '1993-10-10', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kty.jpg', 'Pac-Man makes a rare appearance outside of a maze environment in Pac-Attack, a fun and quirky puzzle game. This unique entry in the genre puts its own twist on established conventions and adds one of gaming''s most iconic characters to the mix. The goal is simple: Keep your screen clear of falling blocks and ghosts by lining up blocks horizontally, causing them to disappear.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-2-the-new-adventures-super-nintendo-entertainment-system', 'Pac-Man 2: The New Adventures', 'Pac-Man', '1994-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sss.jpg', 'Pac-Man 2: The New Adventures, known in Japan as Hello! Pac-Man, is a side-scrolling adventure game "sequel" to Pac-Man. Instead of being a maze game like the majority of its predecessors, Pac-Man 2 incorporates light point-and-click adventure game elements. It was produced and published by Namco for the Super Nintendo Entertainment System (SNES) and Sega Mega Drive/Genesis systems, and was released on April 6, 1994 by Namco. The game borrows its structure and certain elements from Pac-Land, and also appears to contain certain elements from the animated series, such as Pac-Man''s family and a main villain commanding the ghosts. The Genesis version was not released in Japan or Europe.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-in-time-super-nintendo-entertainment-system', 'Pac-In-Time', 'Pac-Man', '1995-01-03', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbsa.jpg', 'The evil Ghost Witch has cast a vicious spell on Pac-Man and thrown him back in time to when he was a Pac-Boy. Only you can save him now. Down some Pac-Pellets and get ready to battle your way through a totally supersonic side-scrolling adventure. Journey through snowy mountains and forests, collect fireballs and bubbles, crunch Pac-Bats and ghosts, swim like a fish and swing like a monkey... and ultimately get Pac-Man back to the real world! Sega Mega Drive and Sega Game Gear versions were announced at CES 1995, but were ultimately cancelled for unknown reasons. A prototype of the Game Gear version has since been found and released online.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pilotwings-super-nintendo-entertainment-system', 'Pilotwings', 'Pilotwings', '1991-08-13', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5iq5.jpg', 'Are you ready to earn your wings at the most exclusive flight school in the world? Then report immediately to the secret Pilotwings Flight Club, where your training begins! You''ll see the ground twist beneath you as you jump from your plane and attempt a precision skydive (don''t forget to pull your rip cord!). You''ll relive the early days of flying as you bring your biplane in for a pin-point landing. After you master the basics, you''ll be called on to test an experimental rocket pack, soar in a hang glider, and pilot an advanced attack helicopter in a hazardous rescure mission.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-super-nintendo-entertainment-system', 'Prince of Persia', 'Prince of Persia', '1992-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-2-the-shadow-the-flame-super-nintendo-entertainment-system', 'Prince of Persia 2: The Shadow & The Flame', 'Prince of Persia', '1996-10-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ek1.jpg', 'Prince of Persia 2: The Shadow and the Flame is a platform game released as the sequel to 1989''s Prince of Persia. Prince of Persia 2 was published for MS-DOS and ported to Macintosh, Super NES, and FM Towns – a much shorter list of platforms than the first game. It was also available as a bonus that unlocks in the Xbox NTSC version of Prince of Persia: The Sands of Time.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-punch-out-super-nintendo-entertainment-system', 'Super Punch-Out!!', 'Punch-Out!!', '1994-09-14', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kmg.jpg', 'The original Arcade release of "Super Punch-Out!!".
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('simcity-super-nintendo-entertainment-system', 'SimCity', 'SimCity', '1991-08-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ov0.jpg', 'The NES port of SimCity is an unreleased game based on Nintendo''s SNES version of SimCity. The game was lost until it was found and dumped onto the internet.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-super-nintendo-entertainment-system', 'Star Fox', 'Star Fox', '1993-03-26', 'Super Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ap2.jpg', 'A promotional cartridge, Super Star Fox Weekend (Official Competition) (titled Star Wing: Official Competition in Europe), was released as part of the game''s marketing campaign in Europe and the U.S. It featured time-limited single-player mode on modified stages, as well as an exclusive bonus level. The altered start-up screen displays ''Official Competition Cartridge''. Depending on the points scored, players could win a t-shirt, a jacket, or trips to international destinations. An estimated 2000 cartridges were made.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-star-wars-super-nintendo-entertainment-system', 'Super Star Wars', 'Star Wars', '1992-11-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xr.jpg', 'Join Luke, Han and Chewbacca in their fierce war against the evil Empire. Battle treacherous aliens. Pilot two vehicles in high-speed, first-person, 3-D sequences. Fight your way through the wastelands of Tatooine to the hostile streets of Mos Eisley and beyond. So grab your blaster, strap on your lightsaber, and take on the fight for galactic freedom.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-star-wars-the-empire-strikes-back-super-nintendo-entertainment-system', 'Super Star Wars: The Empire Strikes Back', 'Star Wars', '1993-06-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xq.jpg', 'Pursued across the galaxy, you and your Rebel Forces now marshall new strength on the remote ice world of Hoth. Although tracked by probe droids, attacked by ice monsters, and confronted by an army of gigantic Imperial Walkers, you must not give in. You are the Alliance''s only hope. Learn the ways of the Force, then test your skills in this fast-paced, action-packed sequel to the hit game Super Star Wars.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-star-wars-return-of-the-jedi-super-nintendo-entertainment-system', 'Super Star Wars: Return of the Jedi', 'Star Wars', '1994-06-22', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xp.jpg', 'All the Adventure and Excitement of the 16-bit Game -- are you ready to challenge the dark side?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-super-nintendo-entertainment-system', 'Harvest Moon', 'Story of Seasons', '1997-06-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl3.jpg', 'Explore a world of new and familiar faces, unique villages and adventurous challenges, while managing your growing farm.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-scope-6-super-nintendo-entertainment-system', 'Super Scope 6', NULL, '1992-02-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47ne.jpg', 'Super Scope 6, known as Nintendo Scope 6 in Europe and Australia, was the title Nintendo bundled with the Super Scope for the Super NES. As the name suggests, the cartridge contains six games that require the Super Scope to play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-2-super-nintendo-entertainment-system', 'Tetris 2', 'Tetris', '1994-08-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobgsb.jpg', 'Tetris 2 is a 1990 video game by František Fuka (Fuxoft). It is inspired by a Soviet game Tetris. It is considered to be the most successful game developed by Fuka.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-attack-super-nintendo-entertainment-system', 'Tetris Attack', 'Tetris', '1996-08-01', 'Super Nintendo Entertainment System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dp0.jpg', 'The Game Boy version of the Super Nintendo game with the same name, which in turn is a version of the exclusive japanese game Panel de Pon.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-dr-mario-super-nintendo-entertainment-system', 'Tetris & Dr. Mario', NULL, '1994-12-30', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47ff.jpg', 'Compliation game released for the Super Nintendo featuring both Tetris and Dr Mario.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-s-woods-super-nintendo-entertainment-system', 'Wario''s Woods', 'Wario', '1994-12-10', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4fn4.jpg', 'Wario''s Woods is a puzzle game similar to Tetris or Columns, but with a twist. Instead of directly controlling the monsters and bombs that are falling down, the player controls Toad who has to carry around stacks of monsters and bombs and to combine them in the right way. One bomb plus at least two monsters of the same color have to be combined to make them disappear. If five or more objects are cleared at the same time, a diamond will appear. Destroying the diamond will clear all monsters of the diamond''s color.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-3d-super-nintendo-entertainment-system', 'Wolfenstein 3D', 'Wolfenstein', '1994-02-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9rdz.jpg', 'The SNES version of Wolfenstein 3D has modified episodes and storyline, along with heavy censorship. The changes make this version a different game from the original DOS game, and was used as the basis for the Atari Jaguar, Macintosh, 3DO and Apple IIgs ports.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-cookie-super-nintendo-entertainment-system', 'Yoshi''s Cookie', 'Yoshi', '1993-06-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yby.jpg', 'The Game Boy version of Yoshi''s Cookie was released as part of a dual launch with the NES version of the game. While they both featured the original three forms of game play, individuals on Gameboy were at an advantage in the form of the amount of players that could compete against one another in the VS mode.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-safari-super-nintendo-entertainment-system', 'Yoshi''s Safari', 'Yoshi', '1993-09-01', 'Super Nintendo Entertainment System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pz6.jpg', 'Yoshi''s Safari is the first and so far the only dedicated rail shooting game in the Mario franchise, and one of the few games to use the SNES''s Super Scope light gun peripheral. Gameplay consists of shooting enemies before they attack. There are bosses along the way that must be destroyed before players can move on to the next area.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-world-2-yoshi-s-island-super-nintendo-entertainment-system', 'Super Mario World 2: Yoshi''s Island', 'Yoshi', '1995-10-04', 'Super Nintendo Entertainment System', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kn9.jpg', 'Super Mario World 2: Yoshi''s Island is a platform video game acting as a prequel to 1990''s Super Mario World. The game casts players as Yoshi as he escorts Baby Mario through 48 levels in order to reunite him with his brother Luigi, who had been kidnapped by Baby Bowser''s minions. As a Super Mario series platformer, Yoshi runs and jumps to reach the end of the level while solving puzzles and collecting items. In a style new to the series, the game has a hand-drawn aesthetic and is the first to have Yoshi as its main character. The game introduces his signature abilities to flutter jump, produce eggs from swallowed enemies, and transform into vehicles.', 'NA', 15);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-clash-virtual-boy', 'Mario Clash', 'Mario', '1995-10-01', 'Virtual Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co258m.jpg', 'Mario Clash is the first 3D stereoscopic Mario game released for the Virtual Boy. The game is a return to the style of the original Mario Bros. To progress through the game, Mario must knock enemies off platforms using Turtle Shells. There are always two Koopas; if one gets knocked off, another one takes its place. Many enemies need to be hit from the side, thus Mario must throw shells from the background to the foreground and vice-versa in order to knock them off.', 'NA', 16);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-s-tennis-virtual-boy', 'Mario''s Tennis', 'Mario Tennis', '1995-08-14', 'Virtual Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yr.jpg', 'Spin, Lob, Drop, Smash -- It''s time for some Mario Tennis! Take your game to the next level in Mario Tennis with 3 fun-packed modes! Practice control on your swings and shots in Exhibition Mode. In Mario Tour, create your own tennis player on three different save slots. Begin your tennis career as a rookie at the Royal Tennis Academy, where coaches share their sage advice and the students are all about winning. Gain experience by training and playing matches, then divide those points across stats for spin, power, control and speed. As your performance improves, you will be able to face tougher adversaries—and maybe even get to encounter some familiar faces! Need a break? Then try your luck on some Mario Mini-games. It’s time to pick up your racquet, and start playing!', 'NA', 16);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('3d-tetris-virtual-boy', '3D Tetris', 'Tetris', '1996-03-22', 'Virtual Boy', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co84ay.jpg', '3-D Tetris is a video game released for the Virtual Boy in 1996. A Japanese version was planned, to be called Polygo Block, but production of games was ceased due to lack of interest in the Virtual Boy system. This was the last game released on the Virtual Boy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('virtual-boy-wario-land-virtual-boy', 'Virtual Boy Wario Land', 'Wario', '1995-11-27', 'Virtual Boy', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wol.jpg', 'Yikes!!! Get ready for a devious treasure hunt with the infamous scheming Wario. Capture the shining gold and vast treasures locked deep inside a hidden cave. But, beware of poison ponds, perilous prisons, endless walls and creepy woods! Make a quick change into Sea Dragon Wario, Eagle Wario or Bull Wario and utilize their mighty strengths. Blow away enemy cave defenders with body attacks and power actions. Succeed in this greedy plot to seize the riches of this underground world and find this key to freedom!', 'NA', 16);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('banjo-kazooie-nintendo-64', 'Banjo-Kazooie', 'Banjo-Kazooie', '1998-06-29', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bha.jpg', 'The Xbox 360 remaster of Banjo-Kazooie has visual and performance improvements over the Nintendo 64 version. In this version, the player doesn''t lose the notes after getting out of a stage, which is a major difference over the original, since it doesn''t require the player to get everything again after leaving or dying.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('banjo-tooie-nintendo-64', 'Banjo-Tooie', 'Banjo-Kazooie', '2000-11-20', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bhb.jpg', 'The Xbox 360 remaster of Banjo-Tooie has visual and performance improvements over the Nintendo 64 version. In this version, the player doesn''t loose the notes after getting out of a stage, which is a major difference over the original, since it doesn''t require the player to get everything again after leaving or dying. It also has a reimplementation of the Stop ''n'' Swop feature, using the save data from the Banjo-Kazooie remaster to unlock new content.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battlezone-rise-of-the-black-dogs-nintendo-64', 'Battlezone: Rise of the Black Dogs', 'Battlezone', '2000-03-30', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wh6.jpg', 'Battlezone: Rise of the Black Dogs is a port of the PC game Battlezone with extra missions.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-64-nintendo-64', 'Bomberman 64', 'Bomberman', '1997-11-30', 'Nintendo 64', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25y5.jpg', 'Not to be confused with the 1997 game known in North America and Europe as "Bomberman 64," this 2D Bomberman title was the last N64 game to be released in Japan.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-hero-nintendo-64', 'Bomberman Hero', 'Bomberman', '1998-09-01', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nww.jpg', 'Bomberman''s latest adventure takes him across the galaxy! Princess Millian has been kidnapped by the evil Garaden Empire and it''s up to Bomberman to save the day. Travel through worlds of ice, fire and water. Use new abilities and get help from friends like Louie the rabbit and Pibol the robot. New vehicles like the Bomber Copter and Bomber Marine will come in handy in your quest to save the Princess and free the universe once again!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-64-the-second-attack-nintendo-64', 'Bomberman 64: The Second Attack', 'Bomberman', '2000-05-28', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ygs.jpg', 'Of the great discoveries in the universe, few are more important than the legendary 8 elements. When the evil Rukifellth found one of these elements - the powerful Celestial Stone - he used his influence to assemble the dreaded BHB Army. Armed with his new army and a giant space warship, the power-crazed Rukifellth began scouring the galaxy for the other 7 elements, invading planets and enslaving innocent races throughout the galaxy. Rukifellth controls these enslaved planets with special Gravity Generators - the same devices the BHB Army used to create a Black Hole. Rukifellth uses his Black Hole to capture new planets... But he should have thought twice before he tried to capture Bomber Planet!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-nintendo-64', 'Castlevania', 'Castlevania', '1999-01-26', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sn4.jpg', 'Castlevania was a cakewalk compared to this bloody curse. You thought you had the Prince of Darkness defanged - eh, Simon Belmont? Well think again, ''cause according to a damsel in distress, evil Count Dracula has left a horrifying curse in his wake. And the only hope you have of ending the terror is to destroy his missing body parts! Talk about your frightening quest, searching a maze of mansions, graveyards and dark, eerie forests - each guarded by man-eating werewolves, fire-throwing zombies and other devilish demons. Your grim chances are kept alive in Transylvania, where cowardly villagers offer clues to the whereabouts of Dracula''s remains. And where you''ll purchase magic weapons, including silver knives and flame whips. But beware the night. For when the sun disappears, Dracula''s curse grows deadlier. And your chances grow dimmer and dimmer.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-legacy-of-darkness-nintendo-64', 'Castlevania: Legacy of Darkness', 'Castlevania', '1999-11-30', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54ti.jpg', 'Castlevania: Legacy of Darkness is a video game that was developed and published by Konami for the Nintendo 64. It was first released in North America on November 30, 1999 and is a prequel and expanded version to the first Castlevania game on the Nintendo 64, but also contains a remake of the original game with improved graphics, added villains (Spider Queen, Medusa), and alternate versions of some levels (Forest of Silence, Tower of Science, Tower of Execution, Clock Tower).', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chameleon-twist-nintendo-64', 'Chameleon Twist', 'Chameleon Twist', '1997-12-09', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coafzh.jpg', NULL, 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chameleon-twist-2-nintendo-64', 'Chameleon Twist 2', 'Chameleon Twist', '1999-04-14', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b3d.jpg', 'Chameleon Twist 2 is the direct sequel to Chameleon Twist. The original Japanese version kept the original design for the main characters, whereas the international release changed them to more realistic-looking chameleons.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('conker-s-bad-fur-day-nintendo-64', 'Conker''s Bad Fur Day', 'Conker', '2001-03-05', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uq6.jpg', 'Humorous action-platformer that does away with the tedious item collection found in most games in the genre. Instead, BFD employs a combination of standard jump, run and explore mechanics and context-sensitive gags and actions. For instance, in the beginning of the game, by pressing the B button on the first pad he encounters, Conker drinks some Alka-Seltzer to wipe out his hangover, at which point players can proceed forward. Later on these pads are used to activate a slingshot and throwing knives; to turn Conker into an anvil and drop downward; to shoot automatic, double-handed guns; to activate a The Matrix-inspired slow-motion effect and flip through the air shooting enemies; and much, much more.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-64-nintendo-64', 'Superman 64', 'DC', '1999-05-31', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b3i.jpg', 'Superman: The New Adventures, often referred to as Superman 64, is a 1999 adventure video game developed and published by Titus Software for the Nintendo 64 video game console. The game is based on the television series Superman: The Animated Series. Superman was first released in North America on May 31, 1999 and in Europe on July 23, 1999.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-beyond-return-of-the-joker-nintendo-64', 'Batman Beyond: Return of the Joker', 'DC', '2000-12-13', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ap0.jpg', 'Batman Beyond: Return of the Joker (also known as Batman of the Future: Return of the Joker in Europe and Australia) is a 2000 American direct-to-video animated film featuring the comic book superhero Batman and his archenemy, the Joker. It is set in the continuity of the animated series Batman Beyond, in which Bruce Wayne has retired from crime fighting, giving the mantle of Batman to high school student Terry McGinnis, and serves as a sequel to both Batman: The Animated Series and The New Batman Adventures. As in the TV series, Will Friedle and Kevin Conroy star as Terry McGinnis and Bruce Wayne, respectively. Mark Hamill, who played the Joker opposite Conroy in Batman: The Animated Series and The New Batman Adventures, reprises his role.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diddy-kong-racing-nintendo-64', 'Diddy Kong Racing', 'Donkey Kong', '1997-11-24', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wgj.jpg', 'Diddy Kong Racing is set on Timber''s Island and revolves around Diddy Kong and his friends'' attempt to defeat the intergalactic antagonist, a wizarding pig named Wizpig, through winning a series of races. The player can take control of any of the featured characters throughout the game. Diddy Kong Racing features five worlds with four racetracks each, and the ability to drive a car, hovercraft, or pilot an aeroplane.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-64-nintendo-64', 'Donkey Kong 64', 'Donkey Kong', '1999-11-22', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co289i.jpg', 'K. Rool has kidnapped the Kongs! Can Donkey Kong rescue his friends, reclaim the Golden Bananas and save his homeland from certain doom? Take out some Kremlings with Chunky''s Pineapple Launcher or Lanky''s Trombone. Float through the air using Tiny''s Ponytail Twirl. Even rocket to the sky with Diddy''s Jetbarrel!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-64-nintendo-64', 'Doom 64', 'Doom', '1997-04-04', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qmz.jpg', 'Fight against demons in your crusade to hunt down the Mother of Demons and stop Hell''s invasion. As the player battle through more than 30 action-packed levels, they have to be on the lookout for enhanced weapons and secrets to help them put an end to the demonic threat.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dr-mario-64-nintendo-64', 'Dr. Mario 64', 'Dr. Mario', '2001-04-08', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21r4.jpg', 'The flu season has come about, and it''s Dr. Mario''s duty to use his Megavitamins to heal the people of the land. However, Wario, wanting to have the fame that Dr. Mario has, attempts to steal the Megavitamins, but to no avail. Afterwards, Mad Scienstein and Rudy the Clown (from Wario Land 3) steal the Megavitamins, and both Dr. Mario and Wario give chase.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('excitebike-64-nintendo-64', 'Excitebike 64', 'Excite', '2000-04-30', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4an4.jpg', 'Experience extreme MX! You grind your way through the hairpin turn, a wall of mud exploding in your wake. Your next jump launches you into the air - you pull off a spectacular double no-footed can-can and become an instant legend! In Excitebike 64, you''ll find all the high-flying action, heart-stopping stunts and bone-jarring crashes of the extreme sport of motocross. It''ll set the daredevil inside you free. 20 stadium tracks and awesome outdoor courses - plus six different riders with six unique styles!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f-zero-x-nintendo-64', 'F-Zero X', 'F-Zero', '1998-10-26', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53i2.jpg', 'It''s you against 29 other machines competing for the title of F-Zero X Champion. You''re racing at speeds of over 1,000 km/h high above the atmosphere. Your competition comes from every corner of the galaxy and won''t shed a tear at the thought of smashing you off the track. With four-player simultaneous gameplay and the Rumble Pak accessory, you have the fastest racing game on the N64 system!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('glover-nintendo-64', 'Glover', NULL, '1998-11-16', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar3y.jpg', 'The cult classic from the ''90s returns! Glover is a charming 3D platformer where you control a magical glove on a quest to restore balance to the kingdom. Roll, jump, and manipulate your magic ball to solve puzzles, overcome challenges, and defeat the evil glove threatening the world!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jet-force-gemini-nintendo-64', 'Jet Force Gemini', NULL, '1999-10-11', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tav.jpg', 'An unreleased Game Boy Color version of the Nintendo 64 game Jet Force Gemini.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-64-the-crystal-shards-nintendo-64', 'Kirby 64: The Crystal Shards', 'Kirby', '2000-06-26', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wcz.jpg', 'Kirby''s first 3-D adventure is also his Nintendo 64 debut, and it finds the always-versatile hero battling a new enemy called Dark Matter. Dark Matter is after a distant land''s powerful crystal, but a young fairy named Ribbon attempts to save it by escaping with the gem to Dream Land. Now the crystal has been broken, and it''s scattered around the world. Take control of Kirby and help him journey across six worlds, battling a wide variety of enemies and challenging bosses, as he tries to collect all 100 pieces of the shattered crystal.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-ocarina-of-time-nintendo-64', 'The Legend of Zelda: Ocarina of Time', 'The Legend of Zelda', '1998-11-23', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6fxc.jpg', 'A fan recreation of The Legend of Zelda: Ocarina of Time with updated graphics, made using the Unreal Engine.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-majora-s-mask-nintendo-64', 'The Legend of Zelda: Majora''s Mask', 'The Legend of Zelda', '2000-10-26', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pah.jpg', 'The Legend of Zelda: Majora''s Mask is a direct sequel to Ocarina of Time, it utilizes the same engine and visual style as its predecessor. The game retains the traditional elements of Zelda games as well as those introduced in Ocarina of Time, such as active blocking with a shield, various throwing items, and the usage of melodies played on the ocarina to solve puzzles. Compared to the previous Zelda games, this installment is more oriented towards interaction with NPCs and has a larger variety of items, optional quests, and mini-games. It also includes a time system that spans three days, and this cycle must be reset periodically to progress through the game.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-racers-nintendo-64', 'Lego Racers', 'Lego', '1999-10-12', 'Nintendo 64', 0, 0, NULL, NULL, NULL, 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-64-nintendo-64', 'Super Mario 64', 'Mario', '1996-09-29', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wv6.jpg', 'A port of Super Mario 64 included in Super Mario 3D All-Stars, built upon the Shindou Pak Taiou Version and its enhancements, also featuring updated textures and a higher output resolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-nintendo-64', 'Mario Golf', 'Mario Golf', '1999-07-26', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uk4.jpg', 'The Game Boy Color version of Mario Golf, differing from the Nintendo 64 counterpart, includes RPG elements and has an isometric view with sprite-based graphics.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-64-nintendo-64', 'Mario Kart 64', 'Mario Kart', '1997-02-10', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67hm.jpg', 'Mario Kart 64 is the second main installment of the Mario Kart series. It is the first game in the series to use three-dimensional graphics, however, the characters and items in this game are still two-dimensional, pre-rendered sprites. The game offers two camera angles and three engine sizes: 50cc, 100cc and 150cc. Each kart has distinctive handling, acceleration and top speed capabilities. Shells that you fire at rival racers, Bananas that make them skid out and Lightning Bolts that make them small and very slow are just a few of the game''s unique power-ups.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-nintendo-64', 'Mario Party', 'Mario Party', '1999-02-08', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba2w.jpg', 'Mario Party 8 is the eighth installment of the Mario Party series on a home console and the first Mario Party game for the Wii. Mario Party 8 is notable for its strong use of the Wii Remote and its motion control capabilities in minigames. Players are required to perform various gestures instead of traditional button/joystick controls. Common motions include pointing-and-shooting, shaking, waving, turning, and twisting the Wii Remote. Player-created Miis are featured in this game, wherein they often show up within crowds. Miis can appear in certain minigames and may also serve as the player''s character in Extra Mode. By playing regular party games, minigames, and completing the Star Battle Arena mode, players will earn Carnival Cards, which may be spent to unlock figures and game features.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-2-nintendo-64', 'Mario Party 2', 'Mario Party', '2000-01-24', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yt.jpg', 'Mario and the gang are back for another round of Bowser-bashin'' party action! Watch as your favorite Nintendo characters don different duds for each of the five all-new Adventure Boards! A slew of new tricks and devices bring new levels of challenge and excitement to board game play. New board maps, new Mini-Games, new action and new surprises means a whole new batch of fun! Get ready to unleash your best Hip Drops, hammer swings and high-flying high junks for another round of frenzied multi-player action!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-3-nintendo-64', 'Mario Party 3', 'Mario Party', '2001-05-07', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yu.jpg', 'Mario Party 3 is the third and final Mario Party title for the Nintendo 64. A total of eight characters are available to choose from: Mario, Luigi, Princess Peach, Yoshi, Wario, Donkey Kong, and newcomers Waluigi and Princess Daisy. Mario Party 3 features duel maps, in which two players try to lower each other''s stamina to zero using non-playable characters such as Chain Chomps. It is the first Mario Party game to feature Luigi''s main voice and also it is last Mario game where Princess Daisy appears in a yellow and white dress, and with long hair, as well as the last Mario game (until New Super Mario Bros. Wii) in which Yoshi''s "record-scratching" voice is used. It is also the first Mario Party game to have multiple save slots.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-nintendo-64', 'Mario Tennis', 'Mario Tennis', '2000-08-28', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yr.jpg', 'Spin, Lob, Drop, Smash -- It''s time for some Mario Tennis! Take your game to the next level in Mario Tennis with 3 fun-packed modes! Practice control on your swings and shots in Exhibition Mode. In Mario Tour, create your own tennis player on three different save slots. Begin your tennis career as a rookie at the Royal Tennis Academy, where coaches share their sage advice and the students are all about winning. Gain experience by training and playing matches, then divide those points across stats for spin, power, control and speed. As your performance improves, you will be able to face tougher adversaries—and maybe even get to encounter some familiar faces! Need a break? Then try your luck on some Mario Mini-games. It’s time to pick up your racquet, and start playing!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-nintendo-64', 'Spider-Man', 'Marvel', '2000-11-21', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-64-nintendo-64', 'Mega Man 64', 'Mega Man Legends', '2001-01-10', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qb3.jpg', 'Mega Man Volnutt is the game''s playable character. Mega Man Volnutt is a "Digger", a person in charge of investigating ruins from a flooded Earth. During his journey with his friends, their ship crashes in Kattelox Island, where Mega Man decides to confront pirates who are attacking it to obtain the its hidden treasure. As an action roleplaying game, Mega Man Legends''s gameplay is very different from the ones of the original series despite sharing a few elements.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-64-nintendo-64', 'Namco Museum 64', 'Namco Museum', '1999-10-31', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jct.jpg', 'Namco Museum 64 is a compilation of several classic arcade games released by Namco, including Pac-Man, Ms. Pac-Man, Pole Position, Galaga, Galaxian and Dig-Dug. The game also features the ability to save high scores with the use of a Nintendo 64 Controller Pak. The N64 Rumble pack can also be used in with this game.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-maze-madness-nintendo-64', 'Ms. Pac-Man Maze Madness', 'Pac-Man', '2000-11-12', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66r6.jpg', 'Game Boy Advance port of Ms. Pac-Man: Maze Madness.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-nintendo-64', 'Paper Mario', 'Paper Mario', '2001-02-05', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25us.jpg', 'What sleeps behind the door?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('perfect-dark-nintendo-64', 'Perfect Dark', 'Perfect Dark', '2000-05-22', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co77xv.jpg', 'Perfect Dark is a first-person shooter video game developed by Rare and published by Nintendo for the Nintendo 64 video game console. It is considered the spiritual successor to Rare''s earlier first-person shooter GoldenEye 007, with which it shares many gameplay features. Perfect Dark was first released in North America on 22 May 2000; PAL and NTSC-J releases followed soon afterwards. A separate Game Boy Color game, also titled Perfect Dark, was released in August 2000 as a supplement to the game and allows certain features within the Nintendo 64 game to alternatively be unlocked via a Transfer Pak.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pilotwings-64-nintendo-64', 'Pilotwings 64', 'Pilotwings', '1996-09-29', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5iq6.jpg', 'Forget about those other flying games. This is the ultimate flight experience! Pilotwings 64 carries you off into a vast three-dimensional environment. Pilot several different vehicles and take in breathtaking sights. Successfully complete flight tests to earn your flight badge. Get a high enough score, and you’ll get a chance at bonus games such as Cannonball and Sky Diving! Soar into a wild blue yonder with Pilotwings 64!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-snap-nintendo-64', 'Pokémon Snap', 'Pokémon', '1999-06-30', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qiz.jpg', 'Traverse various areas and take photographs of different types of Pokémon by discovering their secrets. Capture the perfect frame to gain bonus points from Professor Oak in order to unlock helpful items and locate and photograph the elusive Mew, a legendary Pokémon whose existence has never been recorded.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-stadium-nintendo-64', 'Pokémon Stadium', 'Pokémon', '2000-02-29', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w07.jpg', 'While Pokémon Stadium 2 does have a storyline, progress in the game can be made by winning Cups in the Stadium and completing the Gym Leader Castle. When all Cups have been won and the Gym Leader Castle completed, the player''s Rival will appear. Defeating the Rival will unlock Round 2, in which the player must re-challenge the Stadium, Gym Leader Castle, and the Rival in order to complete the game. But, they have different Pokémon and the difficulty is much higher.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-puzzle-league-nintendo-64', 'Pokémon Puzzle League', 'Pokémon', '2000-09-25', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ywa.jpg', 'Discover the most frantic, frenzied, fun-filled Pokémon challenge ever--Pokémon Puzzle League! Line up three or more blocks of the same type to clear them off the screen. Create chains and combos to send garbage to your opponent. Collect badges from other Pokémon trainers to earn the right to enter the ultimate competition... a battle against the mysterious Puzzle Master!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hey-you-pikachu-nintendo-64', 'Hey You, Pikachu!', 'Pokémon', '2000-11-06', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co407c.jpg', 'Hey you, Pokémon fanatic! Have you ever wanted to control your very own Pokémon? Now you can with HEY YOU, PIKACHU! for the Nintendo 64. It''s as simple as speaking into the microphone that connects to your controller. If Pikachu understands you, he''ll respond. The little yellow pocket monster has a vocabulary of approximately 200 words, and Professor Oak is even on hand to train you in the ways of creature communication. Wake up Pikachu each day by shouting "Good Morning!" and decide what games to play and activities to engage in. You can play Pokémon trivia on the in-game TV, gather food, hunt for treasure, collect seemingly endless goodies, go fishing, baby-sit Caterpie, and much more. You''ll also play a variety of mini-games while guiding Pikachu along with friendly commands. As you bond and converse with your cartoon pal you''ll investigate the Ochre Woods, head for the campground, check out Bulbasaur''s picnic, and even solve clever puzzles. HEY YOU, PIKACHU! is an interactive romp that gives the younger set a chance to get up close and personal with their favorite Pokémon character.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-stadium-2-nintendo-64', 'Pokémon Stadium 2', 'Pokémon', '2001-03-28', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w07.jpg', 'While Pokémon Stadium 2 does have a storyline, progress in the game can be made by winning Cups in the Stadium and completing the Gym Leader Castle. When all Cups have been won and the Gym Leader Castle completed, the player''s Rival will appear. Defeating the Rival will unlock Round 2, in which the player must re-challenge the Stadium, Gym Leader Castle, and the Rival in order to complete the game. But, they have different Pokémon and the difficulty is much higher.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-nintendo-64', 'Quake', 'Quake', '1998-03-24', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-nintendo-64', 'Quake II', 'Quake', '1999-06-30', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-2-the-great-escape-nintendo-64', 'Rayman 2: The Great Escape', 'Rayman', '1999-11-06', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54kj.jpg', 'The PC version of Rayman 2: The Great Escape retains the same level structure from the Nintendo 64 version with higher resolution graphics and a higher frame rate.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-nintendo-64', 'Resident Evil 2', 'Resident Evil', '1999-10-31', 'Nintendo 64', 0, 0, NULL, NULL, NULL, 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rocket-robot-on-wheels-nintendo-64', 'Rocket: Robot on Wheels', NULL, '1999-10-31', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa5ns.jpg', 'First-time Nintendo 64 developer Sucker Punch Studios jumped onto the scene with a highly original 3D platformer. The design philosophy behind the title is simple -- rather than build the platformer around the main character, the software house opted instead to focus on the interactivity of the 3D environments he travels. To that end, Rocket employs an advanced physics engine which allows the main character, a lovable unicycle-based robot named Rocket, to travel and experiment with colorful, platform-esque worlds with realistic gravity and inertia. Every object has its own set of lifelike attributes that must be "weighed" into consideration when solving puzzles.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-nintendo-64', 'Space Invaders', 'Space Invaders', '1999-01-01', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-64-nintendo-64', 'Star Fox 64', 'Star Fox', '1997-06-30', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3e.jpg', 'The Star Fox team triumphantly returns to one of its greatest missions with this remake of Star Fox 64 in full 3D, featuring a complete graphical update.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-shadows-of-the-empire-nintendo-64', 'Star Wars: Shadows of the Empire', 'Star Wars', '1996-12-03', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xv.jpg', 'As Luke Skywalker and the Rebel Alliance struggle to defeat Darth Vader and the Empire, a new threat arises. Dark Prince Xizor aspires to take Darth Vader''s place at the Emperor''s side. As Dash Rendar, it''s up to you to protect Luke and help the Alliance. May the Force be with you!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-rogue-squadron-nintendo-64', 'Star Wars: Rogue Squadron', 'Star Wars', '1998-12-07', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k18.jpg', 'It is a time of great rejoicing in the galaxy. Luke Skywalker, with the help of Wedge Antilles, has blown up the Death Star. But there is little time to celebrate. The mighty Empire is gathering strength for a determined, all-out assault on the Rebel forces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-racer-nintendo-64', 'Star Wars Episode I: Racer', 'Star Wars', '1999-05-18', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wj7.jpg', 'Star Wars: Episode 1 - Racer lets you participate in the famous pod race sequence that was the critical highlight of the film Star Wars: Episode I, The Phantom Menace back in 1999.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-battle-for-naboo-nintendo-64', 'Star Wars Episode I: Battle for Naboo', 'Star Wars', '2000-12-18', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dy9.jpg', 'Attention defenders of Naboo! The Trade Federation must be stopped! Storm through more than 15 missions over land, sea and space as your freedom fighters rally against the droid armies. Take control of 7 vehicles: the Naboo starfighter, Gian speeder, and new craft like the heavy STAP, Trade Federation gunboat and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-64-nintendo-64', 'Harvest Moon 64', 'Story of Seasons', '1999-12-22', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ae7.jpg', 'Retire to the country for a new challenge in Harvest Moon 64. Hard work is rewarded as you struggle to bring prosperity back to a neglected farm. Work the land, pick up odd-jobs, and get to know the neighbors. Harvest Moon 64 has all the charm of the original Super Nintendo classic, plus many new surprises.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-nintendo-64', 'Super Smash Bros.', 'Super Smash Bros.', '1999-04-26', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ysr.jpg', 'This Smash Wii U modpack has a real and authentic look, all the extra skins make sense as alts of the character they go on, fighters from one series are on fighters from the same series. In addition to a bunch of extra alternate costumes/characters, almost all of the Omega stages have been replaced with brand new stages or safe versions of the original stages. Beyond that, aesthetics have been changed, well over 100 new music tracks have been added, the camera is unrestricted whenever possible, and various other improvements have been added within the mod.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetrisphere-nintendo-64', 'Tetrisphere', 'Tetris', '1997-08-11', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bag.jpg', 'Tetrisphere is a variant on Tetris in which various shapes are shifted across a wrapped three-dimensional grid resembling a sphere, and then destroyed. The objective of the game changes depending on the mode, but generally consists of removing layers of shapes to reach the playing field''s core. Despite very little domestic advertising, Tetrisphere enjoyed moderately good sales and a mostly favorable critical reception. Reviewers praised the game''s originality and the musical score composed by Neil D. Voss.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('magical-tetris-challenge-nintendo-64', 'Magical Tetris Challenge', 'Tetris', '1999-01-14', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4vrz.jpg', 'The Game Boy Color port of Magical Tetris Challenge.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-new-tetris-nintendo-64', 'The New Tetris', 'Tetris', '1999-07-31', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3a6w.jpg', 'There are several key differences in gameplay from the original Tetris. First, in addition to clearing lines, one can also form 4x4 large squares of four pieces to form blocks. When a block is created, it turns solid gold or silver, depending on the makeup of the block. Blocks can only be constructed from whole pieces: if any part of a piece has been cleared, then it cannot be used to form a block. When a line that has pieces from a block is cleared, it earns more points.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-dinosaur-hunter-nintendo-64', 'Turok: Dinosaur Hunter', 'Turok', '1997-03-04', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yzh.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-2-seeds-of-evil-nintendo-64', 'Turok 2: Seeds of Evil', 'Turok', '1998-12-10', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zcg.jpg', 'The Amaranthine Accordance is trying to bring a massive Dinosoid army to Earth from the Lost Land in an effort to restore dinosaurs to their rightful home.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-rage-wars-nintendo-64', 'Turok: Rage Wars', 'Turok', '1999-11-23', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zqu.jpg', 'Turok: Rage Wars is a first-person shooter video game released for the Nintendo 64. The game supports up to four players or bots with a single player mission-based mode also available. The game allows use of the RAM Expansion Pak for enhanced play sessions.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-3-shadow-of-oblivion-nintendo-64', 'Turok 3: Shadow of Oblivion', 'Turok', '2000-09-06', 'Nintendo 64', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7fpt.jpg', 'Turok 3: Shadow of Oblivion is a faithful restoration of the classic first-person shooter originally released in 2000 for the Nintendo 64, upgraded through Nightdive Studios’ proprietary KEX Engine for play on modern gaming devices with up to a 4K resolution at 120FPS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wave-race-64-nintendo-64', 'Wave Race 64', 'Wave Race', '1996-11-01', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ksa.jpg', 'This version of Wave Race 64 was released only in Japan and has Rumble Pak compatibilty.', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-story-nintendo-64', 'Yoshi''s Story', 'Yoshi', '1998-03-10', 'Nintendo 64', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co260t.jpg', 'Baby Bowser has taken the Super Happy Tree and cast a spell on Yoshi''s world, turning it into the pages of a picture book. The only Yoshis not affected by the spell were six hatchlings that were still protected by their shells. It''s up to them to reclaim the Super Happy Tree and restore happiness to the world. That is the only thing that can break Baby Bowser''s Spell!', 'NA', 17);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-enemy-below-game-boy-color', 'Blaster Master: Enemy Below', 'Blaster Master', '2000-09-24', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ndw.jpg', 'Jason, brave hero of yesteryear, is roused from retirement by the news that mutant lifeeorms, thought to have been long since destroyed, are once again on the move, hollowing out subterranean niches in the image of their old haunts. The decision to reactivate Sophia seems to Jason nothing more than an inevitability. Back into the cold once more...
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pocket-bomberman-game-boy-color', 'Pocket Bomberman', 'Bomberman', '1998-11-18', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52x7.jpg', 'Everyone is familiar with explosive hurling hero ''Bomberman'' but this time he''s back in a side-view platforming adventure on the Game Boy and Game Boy Color. Use your bombs to blast your way through each stage and overcome the boss battles at the end of each zone to reach your ultimate goal.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-quest-game-boy-color', 'Bomberman Quest', 'Bomberman', '1999-11-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co44e1.jpg', 'Bomberman is on his way home when the engines on his ship are stolen. As a result, he must make an emergency landing on a strange planet. However, Bomberman is not traveling alone he''s got all of the monsters he has captured on his adventures with him. After a rough crash landing, the monsters escaped. You must help Bomberman recapture the monsters and find his engines in order to return home. You''ll travel to four different regions of the planet collecting bombs, finding items, and getting hints for how to proceed on your adventure. Along with the main quest a Two-Player mode is also included, in which you try to trap your opponent by setting bombs; the first person to be victimized by a bomb loses.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-max-blue-champion-game-boy-color', 'Bomberman Max: Blue Champion', 'Bomberman', '2000-05-14', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ovi.jpg', 'In Bomberman Max, your task is to jump through five zones with a dozen levels each. At the beginning of the round, you''re given your quota to meet -- in some levels, you''ll have to destroy all the enemies. In another, wipe out all the blocks in the land. In another, rescue the level''s Charabomb. And in others, simply make your way to the target square in the set amount of time. But it won''t be easy, since many enemies just don''t stay still for you to walk up and plant a bomb next to them. It''s all in the strategy of bomb-placement. Plus, once a level''s complete, you''ll have to pick the proper exit that appears. Released in two versions, Blue and Red.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-max-red-challenger-game-boy-color', 'Bomberman Max: Red Challenger', 'Bomberman', '2000-05-14', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7m7m.jpg', 'In Bomberman Max, your task is to jump through five zones with a dozen levels each. At the beginning of the round, you''re given your quota to meet -- in some levels, you''ll have to destroy all the enemies. In another, wipe out all the blocks in the land. In another, rescue the level''s Charabomb. And in others, simply make your way to the target square in the set amount of time. But it won''t be easy, since many enemies just don''t stay still for you to walk up and plant a bomb next to them. It''s all in the strategy of bomb-placement. Plus, once a level''s complete, you''ll have to pick the proper exit that appears. Released in two versions, Blue and Red.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('conker-s-pocket-tales-game-boy-color', 'Conker''s Pocket Tales', 'Conker', '1999-06-08', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4smz.jpg', 'It''s Conker''s birthday and someone crashed his party! The Evil Acorn has stolen all of Conker''s presents and kidnapped his best chipmunk friend, Berri. Now you must take on the role of the bushy-tailed hero, pursuing your nemesis throughout 6 visually-stunning worlds to rescue Berri and save your birthday from complete disaster. Strain your brain to solve challenging puzzles, battle the Evil Acorn''s horde of minions with your trusty slingshot, and even flex your muscles in sporting events as you track your foe to the final showdown!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('croc-game-boy-color', 'Croc', 'Croc', '2000-06-06', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pps.jpg', 'Croc 2 is a platformer that follows the cute crocodile protagonist, Croc, in his adventure to free his furry friends the gobbos from the forces of evil. On his way Croc collects gems in order to buy items that will assist his quest.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('croc-2-game-boy-color', 'Croc 2', 'Croc', '2001-01-25', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pps.jpg', 'Croc 2 is a platformer that follows the cute crocodile protagonist, Croc, in his adventure to free his furry friends the gobbos from the forces of evil. On his way Croc collects gems in order to buy items that will assist his quest.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-beyond-return-of-the-joker-game-boy-color', 'Batman Beyond: Return of the Joker', 'DC', '2000-11-20', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ap0.jpg', 'Batman Beyond: Return of the Joker (also known as Batman of the Future: Return of the Joker in Europe and Australia) is a 2000 American direct-to-video animated film featuring the comic book superhero Batman and his archenemy, the Joker. It is set in the continuity of the animated series Batman Beyond, in which Bruce Wayne has retired from crime fighting, giving the mantle of Batman to high school student Terry McGinnis, and serves as a sequel to both Batman: The Animated Series and The New Batman Adventures. As in the TV series, Will Friedle and Kevin Conroy star as Terry McGinnis and Bruce Wayne, respectively. Mark Hamill, who played the Joker opposite Conroy in Batman: The Animated Series and The New Batman Adventures, reprises his role.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sgt-rock-on-the-frontline-game-boy-color', 'Sgt. Rock On The Frontline', 'DC', '2000-12-17', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yd4.jpg', 'Sgt. Rock: On the Frontline is based on the popular DC Comics war hero. The game is a loose adaptation of the game Front Line, and was made into an actual Front Line sequel in Japan.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-chaos-in-gotham-game-boy-color', 'Batman: Chaos in Gotham', 'DC', '2001-02-16', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ipw.jpg', 'The Batman returns on Game Boy Color with BATMAN: Total Chaos in Gotham City. Based on the popular animated BATMAN series, this single-player action game allows you to don the cowl of one of two Bat-heroes: Batman or Batgirl. Some of the Dark Knight''s famous arch-villains have escaped and are causing serious trouble in Gotham, and it''s up to you to put them back where they belong. Everyone from Poison Ivy to the Clown Prince of Crime the Joker himself is here to wreak havoc and keep the caped crusader busy. Grab your utility belt and assault 18 stages of varied action that take you on a tour of Gotham City. Much of the action is played from a side-scrolling perspective, but some levels have you taking out the Batmobile or the Batcycle in overhead high-speed excitement. Naturally, Batman and Batgirl are both packing their usual assortment of weapons and tools including the Batarang, the grappling hook, smoke bombs, and more.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-game-boy-color', 'Donkey Kong Country', 'Donkey Kong', '2000-11-20', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jhu.jpg', 'Game Boy Color port of Donkey Kong Country.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-monsters-game-boy-color', 'Dragon Warrior Monsters', 'Dragon Quest', '2000-01-25', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ghx.jpg', 'Dragon Quest Monsters is a turn-based RPG that involves recruiting monsters to fight for you in random encounters. Two recruited monsters can be fused together for a better one and extra monsters can be stored on a farm while not in your party.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-iii-game-boy-color', 'Dragon Warrior III', 'Dragon Quest', '2001-07-07', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s7a.jpg', 'Dragon Warrior III is a top-down role-playing game where you travel around the overworld, caves, castles, cities and other locations while battling random encounters, buying equipment, and talking to people.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-monsters-2-game-boy-color', 'Dragon Warrior Monsters 2', 'Dragon Quest', '2001-09-15', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y6k.jpg', 'Dragon Quest Monsters 2 followed Pokemon''s strategy of releasing 2 games with exclusive monsters that would need to be traded between versions to collect them all.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-gallery-2-game-boy-color', 'Game & Watch Gallery 2', 'Game & Watch Gallery', '1998-11-20', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a83.jpg', 'Game & Watch Gallery 2 is the sequel to Game & Watch Gallery released in 1997 for the Game Boy, only in Japan. This version is a colorized version released for the Game Boy Color in 1998. The game included six revisions of classic Game & Watch games, one of which is not playable from the beginning and must be unlocked.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-gallery-3-game-boy-color', 'Game & Watch Gallery 3', 'Game & Watch Gallery', '1999-12-06', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5v47.jpg', 'Flash back to the ''80s with Game & Watch Gallery 3, featuring original and updated versions of five handheld classics.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-game-boy-color', 'Grand Theft Auto', 'Grand Theft Auto', '1999-11-22', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-2-game-boy-color', 'Grand Theft Auto 2', 'Grand Theft Auto', '2000-12-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4s1j.jpg', 'The PSX port of Grand Theft Auto 2 is an open world action-adventure video game. It is the sequel to Grand Theft Auto, part of the Grand Theft Auto series. The open world design lets players freely roam Anywhere City, the setting of the game.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-tilt-n-tumble-game-boy-color', 'Kirby Tilt ''n'' Tumble', 'Kirby', '2001-04-11', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wbo.jpg', 'Peacefully sleeping in his Dream Land, Kirby drifts lazily amongst the beauty of the sky. A beauty that King Dedede cannot abide with. Jealous of the sky''s wondrous splendor, King Dedede has acquired a tool that will let him steal the night''s stars, plunging the world into eternal drab daylight. When Kirby awoke, he found that it was still daytime. And evermore, it would be daytime, unless Kirby made the journey to find King Dedede and recover the stars to restore the night''s sky. So begins the latest Kirby adventure, another action adventure with the morphing marshmallow in a starnge fantasy world. However, the one thing separating this latest adventure is the control scheme. Here, you don''t control Kirby directly. Instead, you guide Kirby by tipping your system to roll the little round pink puff through a series of mazes. If you get in a jam you can make Kirby jump by a controller press, and Kirby can still acquire weapons from other enemies, but the real skill is using the tilting to your advantage.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-link-s-awakening-dx-game-boy-color', 'The Legend of Zelda: Link''s Awakening DX', 'The Legend of Zelda', '1998-12-15', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4o47.jpg', 'The Legend of Zelda: Link''s Awakening DX is an updated re-release of Link''s Awakening with several new additions, the most notable of which being the entire game is now in color.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-oracle-of-seasons-game-boy-color', 'The Legend of Zelda: Oracle of Seasons', 'The Legend of Zelda', '2001-05-14', 'Game Boy Color', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tw0.jpg', 'The Legend of Zelda: Oracle of Seasons is one of two Zelda titles released for the Game Boy Color, the other being Oracle of Ages. The game retain many gameplay elements from Link''s Awakening such as the graphics, audio and top-view perspective. It also features eight dungeons and a large overworld to explore like in the previous games. Oracle of Seasons is said to be more action-oriented than its counterpart being more puzzle-oriented. After completing one of the two games, both can be linked to form a single linear plot with an alternate ending. Oracle of Seasons and Oracle of Ages were often credited as being two of the top games for the Game Boy Color.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-oracle-of-ages-game-boy-color', 'The Legend of Zelda: Oracle of Ages', 'The Legend of Zelda', '2001-05-14', 'Game Boy Color', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tw1.jpg', 'The Legend of Zelda: Oracle of Ages is one of two Zelda titles released for the Game Boy Color, the other being Oracle of Seasons. The game retain many gameplay elements from Link''s Awakening such as the graphics, audio and top-view perspective. It also features eight dungeons and a large overworld to explore like in the previous games. Oracle of Ages is said to be more puzzle-oriented than its counterpart being more action-oriented. After completing one of the two games, both can be linked to form a single linear plot with an alternate ending. Oracle of Ages and Oracle of Seasons were often credited as being two of the top games for the Game Boy Color.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-alpha-team-game-boy-color', 'Lego Alpha Team', 'Lego', '2000-11-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8ji.jpg', NULL, 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-stunt-rally-game-boy-color', 'Lego Stunt Rally', 'Lego', '2000-12-29', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co76ju.jpg', NULL, 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-racers-game-boy-color', 'Lego Racers', 'Lego', '2001-01-18', 'Game Boy Color', 0, 0, NULL, NULL, NULL, 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-island-2-the-brickster-s-revenge-game-boy-color', 'Lego Island 2: The Brickster''s Revenge', 'Lego', '2001-03-30', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94mf.jpg', 'The Brickster is back and out to cause more mischief in this wild, racing, chasing, island-hopping sequel. In your quest to piece together The Informaniac''s Constructopedia, you''ll drive, scuba-dive, fly a place and even ride a dinosaur as you chase the Brickster down through these amazing new LEGO worlds. Meet all kinds of fun characters along the way as you journey through the game. You''ll need all your skills to solve the puzzles and achieve your ultimate goal, to prevent LEGO Island being ruined.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-oh-no-more-lemmings-game-boy-color', 'Lemmings & Oh No! More Lemmings', 'Lemmings', '2000-12-20', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6aus.jpg', 'This Windows port contains two complete games from DMA Design''s classic ''Lemmings'' puzzle series, which are all mind-boggling games of multiple skill levels, featuring fantastically animated graphics and simple yet addictive gameplay.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-game-boy-color', 'Marble Madness', NULL, '1999-12-01', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-deluxe-game-boy-color', 'Super Mario Bros. Deluxe', 'Mario', '1999-05-10', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2299.jpg', 'Bowser has once again taken over the Mushroom Kingdom, and it''s up to Mario to put an end to his sinister reign. Battle Bowser''s vile henchmen through 32 different levels - all taken directly from the 1985 classic! Then move on to collect special Red Coins and Yoshi Eggs in the Challenge Mode. Or face off against a friend and race through 8 competition courses in the all-new VS Mode! This time there''s a lot more to do than just save a Princess, so get ready for a brick-smashin'', pipe-warpin'', turtle-stompin'' good time!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-game-boy-color', 'Mario Golf', 'Mario Golf', '1999-10-05', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uk4.jpg', 'The Game Boy Color version of Mario Golf, differing from the Nintendo 64 counterpart, includes RPG elements and has an isometric view with sprite-based graphics.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-game-boy-color', 'Mario Tennis', 'Mario Tennis', '2001-01-16', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21yr.jpg', 'Spin, Lob, Drop, Smash -- It''s time for some Mario Tennis! Take your game to the next level in Mario Tennis with 3 fun-packed modes! Practice control on your swings and shots in Exhibition Mode. In Mario Tour, create your own tennis player on three different save slots. Begin your tennis career as a rookie at the Royal Tennis Academy, where coaches share their sage advice and the students are all about winning. Gain experience by training and playing matches, then divide those points across stats for spin, power, control and speed. As your performance improves, you will be able to face tougher adversaries—and maybe even get to encounter some familiar faces! Need a break? Then try your luck on some Mario Mini-games. It’s time to pick up your racquet, and start playing!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mutant-academy-game-boy-color', 'X-Men: Mutant Academy', 'Marvel', '2000-07-14', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y74.jpg', 'X-Men: Mutant Academy is a 3-D/2D fighting game developed by Paradox, the company behind Activision''s Wu-Tang: Shaolin Style and the never-published Thrill Kill, and based on the X-Men characters from Marvel Comics. The game was released for the Game Boy Color and PlayStation as a tie-in to X-Men.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-game-boy-color', 'Spider-Man', 'Marvel', '2000-09-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mutant-wars-game-boy-color', 'X-Men: Mutant Wars', 'Marvel', '2000-11-07', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9810.jpg', 'Released in 2000 for the Game Boy Color, X-Men: Mutant Wars is a side-scrolling beat ''em-up game and the second X-Men title for the system. Its launch was synchronized with the release of the X-Men film on DVD.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blade-game-boy-color', 'Blade', 'Marvel', '2000-11-20', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25bz.jpg', 'In an open sand box world you choose your allies, your enemies, what provinces to conquer, what castles to siege and what quests to embark on. With Fire and Sword builds and expands upon the highly regarded combat system from Mount & Blade: Warband. Firearms have been introduced to the battlefield. Additionally, muskets and pistols can now be used as sidearms in hand-to-hand combat to quickly drop your foes. In addition to the enhanced singleplayer mode, With Fire & Sword also provides a host of original multiplayer content including the new game mode: Captain.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-wolverine-s-rage-game-boy-color', 'X-Men: Wolverine''s Rage', 'Marvel', '2001-05-15', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co980z.jpg', 'X-Men: Wolverine''s Rage is a side-scrolling video game designed for the Game Boy Color. The game''s plot centres around Wolverine as he pursues Lady Deathstrike, Sabretooth, and Cyber.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-the-sinister-six-game-boy-color', 'Spider-Man 2: The Sinister Six', 'Marvel', '2001-05-30', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qh7.jpg', 'Spider-Man 2: The Sinister Six (or Spider-Man 2: Enter the Sinister Six in Europe) is a 2001 platform video game based on the Marvel Comics character Spider-Man. It was developed by Torus Games and published by Activision for the Game Boy Color. It is an alternative sequel to Spider-Man (2000) and mostly follows the events of the Game Boy Color version of that game. Though it has a similar format, it is not related to Spider-Man: Return of the Sinister Six (1992).', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-xtreme-game-boy-color', 'Mega Man Xtreme', 'Mega Man X', '2001-01-10', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co202i.jpg', 'The future world is in turmoil. The peace keeping mother computer has been hacked and a virus runs rampant throughout the world. Only Mega Man X has the ability to traverse eight dangerous levels in cyberspace, battle huge bosses along the way and restore the mother computer to its normal state. When the going gets too intence, Mega Man X''s pal, Zero can be summoned to help him out of the most dangerous situations. It''s an X-treme situation that only Mega Man X can resolve!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-xtreme-2-game-boy-color', 'Mega Man Xtreme 2', 'Mega Man X', '2001-11-01', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co202k.jpg', 'Something mysterious is going on at the reploid research island. The reploids have ceased functionality... their data strangely erased. Now the investigation team encounters "irregular" reploids infected with a strange new DNA chip. This strange DNA chip, known as "DNA Soul", replaces useful data with a devastating Sigma virus and places all reploids in imminent danger. Now, it''s up to Mega Man X and his comrade, Zero, to get to the damaged island and find out who is behind the DNA Soul virus.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-ghost-babel-game-boy-color', 'Metal Gear: Ghost Babel', 'Metal Gear', '2000-05-05', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobiso.jpg', 'Metal Gear: Ghost Babel is a Game Boy Color spinoff of the popular stealth action game Metal Gear Solid. This is not a port of said game but an original game made specifically for the Game Boy Color. Metal Gear: Ghost Babel is a non-canon game that serves as an alternate sequel to the events of the original Metal Gear.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-adventures-2-game-boy-color', 'Oddworld Adventures 2', 'Oddworld', '2000-01-19', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gu6.jpg', 'Abe thought he had saved the Mudokons from the evil Glukkons with the destruction of Rupture Farms. However, a new threat has arisen: the Glukkons who run Soul Storm Brewery have created an addictive drink made from Mudokon bones. To get all of the bones they need, Soul Storm has an army of Mudokon slaves excavating the Mudokon City of Death; when one of the slaves is worked to death, he becomes part of the product. The only person who can put a stop to this is Abe. You will guide Abe as he travels through the brewery and tries to destroy the boilers. Along the way, he must also try to save his people. Luckily, Abe can talk to his people and get them to help defeat the enemies and solve puzzles he faces along the way. Help Abe save the Mudokons in Oddworld Adventures 2.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-game-boy-color', 'Pac-Man', 'Pac-Man', '1999-01-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('perfect-dark-game-boy-color', 'Perfect Dark', 'Perfect Dark', '2000-08-28', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co77xv.jpg', 'Perfect Dark is a first-person shooter video game developed by Rare and published by Nintendo for the Nintendo 64 video game console. It is considered the spiritual successor to Rare''s earlier first-person shooter GoldenEye 007, with which it shares many gameplay features. Perfect Dark was first released in North America on 22 May 2000; PAL and NTSC-J releases followed soon afterwards. A separate Game Boy Color game, also titled Perfect Dark, was released in August 2000 as a supplement to the game and allows certain features within the Nintendo 64 game to alternatively be unlocked via a Transfer Pak.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-pinball-game-boy-color', 'Pokémon Pinball', 'Pokémon', '1999-06-28', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4y.jpg', 'There are two tables in the game, red and blue. Each table has its own details and gameplay elements.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-trading-card-game-game-boy-color', 'Pokémon Trading Card Game', 'Pokémon', '2000-04-10', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coadk4.jpg', 'Unofficial Extension for collecting and trading Pokemon cards. Users collect digital currency to open digital packs with. Complete missions, earn rare cards, level up and share your collection with each other on Twitch! This is a community focused and built game, this is not officially licensed or endorsed by the official Pokemon Company.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-gold-version-game-boy-color', 'Pokémon Gold Version', 'Pokémon', '2000-10-15', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pia.jpg', 'Pokémon Gold, along with Pokémon Silver, are the sequels to Pokémon Red and Blue. They offer 100 new Pokémon to capture and train, 8 more Gyms to take on and a new Pokémon League challenge. Featuring an expanded post-game, Pokémon Gold and Silver additionally offer extra content from the previous entries in the series.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-silver-version-game-boy-color', 'Pokémon Silver Version', 'Pokémon', '2000-10-15', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pid.jpg', 'Pokémon Silver, along with Pokémon Gold, are the sequels to Pokémon Red and Blue. They offer 100 new Pokémon to capture and train, 8 more Gyms to take on and a new Pokémon League challenge. Featuring an expanded post-game, Pokémon Gold and Silver additionally offer extra content from the previous entries in the series.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-puzzle-challenge-game-boy-color', 'Pokémon Puzzle Challenge', 'Pokémon', '2000-12-04', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ywc.jpg', 'In a rising pit of colored blocks, it''s your task to continuously eliminate these tiles by switching two tiles'' positions on the horizontal row. When three or more tiles link up in a up/down or left/right fashion, they disappear. Gravity kicks in and settles the rest of the tiles into the bin ? this can cause a chain reaction to occur since other blocks of the same color can fall into place next to each other. It''s up to you to continuously work the bin to wipe out tiles by making combination connections and chain reactions. That''s the game in a nutshell, but there are several modes of play that''ll keep your fingers busy. In the game''s Challenge mode, for example, you''re up against a computer opponent and you''ll have to make combos and chain reactions to send garbage blocks to his unseen screen -- but keep in mind your opponent''s doing the same to you.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-crystal-game-boy-color', 'Pokémon Crystal', 'Pokémon', '2001-07-29', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6it0.jpg', 'Pokémon: Liquid Crystal is a complete remake of the original Pokémon Crystal game for the GameBoy Color. The story is the same as the original Crystal with a load of extra events and even a brand new region to explore; the Orange Islands.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-game-boy-color', 'Prince of Persia', 'Prince of Persia', '1992-01-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-game-boy-color', 'Rayman', 'Rayman', '2000-03-29', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jo7.jpg', 'English with Rayman is an educational 2D platform game, based on the original Rayman. It was designed to teach young children the basics of the English language. It is not to be confused with Rayman Junior, which is an entirely different game. English with Rayman blends the Glade of Dreams with the real world in a way which makes little sense in the context of the series, making numerous references to real-world locations such as Ireland and Scotland. English with Rayman was adapted to teach various other languages under such names as French with Rayman.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-2-game-boy-color', 'Rayman 2', 'Rayman', '2001-06-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qwk.jpg', 'Rayman 2 is the Game Boy Color port of Rayman 2: The Great Escape. Instead of being a 3D platformer, the game was adapted to be in 2D.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-gaiden-game-boy-color', 'Resident Evil Gaiden', 'Resident Evil', '2002-06-03', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xix.jpg', 'Resident Evil Gaiden is a Resident Evil game for the Game Boy Color. It is non-canon, as its plot is contradicted by the main series in key parts and its events are ignored. The game features three playable characters and consists of exploring areas, collecting items and combating enemies in the process. Unlike previous entries in the series, Resident Evil Gaiden assumes a top-down perspective for the environment portions that, upon approaching an enemy, changes to a first-person combat mode with a reticle constantly moving to the left and right. To attack, the player has to press the action button while the reticle is in range of the enemy.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-game-boy-color', 'Shantae', 'Shantae', '2002-06-02', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27l6.jpg', 'Genie-girl Shantae is the self-appointed guardian of a small fishing village, Scuttle Town. Living life in a lighthouse rather than a bottle, she''s constantly on the lookout for danger. When the nefarious lady-pirate, Risky Boots catches wind of the treasure that was recently unearthed in the village, she launches an attack. To get Scuttle out of trouble, it''s up to Shantae to prove that she''s the rightful ''Guardian Genie'' to the best of her dancing, buying and hair-whipping abilities. Now crack that whip!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-game-boy-color', 'Space Invaders', 'Space Invaders', '1999-01-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-racer-game-boy-color', 'Star Wars Episode I: Racer', 'Star Wars', '1999-12-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wj7.jpg', 'Star Wars: Episode 1 - Racer lets you participate in the famous pod race sequence that was the critical highlight of the film Star Wars: Episode I, The Phantom Menace back in 1999.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-yoda-stories-game-boy-color', 'Star Wars: Yoda Stories', 'Star Wars', '1999-12-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co74jd.jpg', 'Grab your lightsaber and get ready for terrific Star Wars adventuring in Yoda Stories, the newest in a series of easy-to-play Desktop Adventures from LucasArts. Join Luke Skywalker as he trains to become a Jedi with Yoda, then harness the Force and cross the galaxy to meet exotic aliens, collect stange devices and weapons and deal the Galactic Empire one crippling blow after another - all within an hour!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-obi-wan-s-adventures-game-boy-color', 'Star Wars Episode I: Obi-Wan''s Adventures', 'Star Wars', '2000-11-27', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobhay.jpg', 'The Republic is in grave peril: the evil Trade Federation has Naboo in its clutches and all appears to be lost. The only hope is a lone Jedi Knight. In OBI WAN''S ADVENTURES, you take control of Obi Wan Kenobi and lead him through his treacherous battle to free the planet Naboo.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-gbc-game-boy-color', 'Harvest Moon GBC', 'Story of Seasons', '1998-12-31', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6cd2.jpg', 'Harvest Moon GBC is a remaster of the Game Boy game Harvest Moon GB. It was released for the Game Boy Color by Natsume in North America and Nintendo in Europe. In the game, you''ll take care of your farm within the in-game year. The game has Game Boy link support where you can trade items with other owners of the game. The game is viewed from a bird''s eye perspective.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-2-gbc-game-boy-color', 'Harvest Moon 2 GBC', 'Story of Seasons', '2000-11-18', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl6.jpg', 'The second Harvest Moon game released on the Game Boy Color, Harvest Moon 2 GBC is a farming simulation in which the player assumes the role of either a boy or a girl who is left a farm and given three years to turn its fortunes around.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-3-gbc-game-boy-color', 'Harvest Moon 3 GBC', 'Story of Seasons', '2001-11-14', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xm1.jpg', 'The third Harvest Moon release on Game Boy. A direct sequel to Harvest Moon 2, it is set on an island off the mainland, the player is tasked with reviving the farm and turning around it''s fortunes using two unique playable characters, a first for the series.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-dx-game-boy-color', 'Tetris DX', 'Tetris', '1998-11-18', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3a6u.jpg', 'Tetris DX has everything you need to satisfy your puzzle appetite. Play marathon, the classic Tetris game. Try your hand at ultra or 40 lines, two Tetris games with a twist. The vs. game will have you playing for hours!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('magical-tetris-challenge-game-boy-color', 'Magical Tetris Challenge', 'Tetris', '2000-02-17', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4vrz.jpg', 'The Game Boy Color port of Magical Tetris Challenge.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toki-tori-game-boy-color', 'Toki Tori', 'Toki Tori', '2001-09-12', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1of8.jpg', 'Toki Tori 2 is a puzzle adventure game in which you explore a lush forest island inhabited by strange creatures. Whistle and stomp to influence their behavior, and solve the puzzles. But what''s up with that black goo? It''s threatening your home world!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-game-boy-color', 'Tomb Raider', 'Tomb Raider', '2000-06-08', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-curse-of-the-sword-game-boy-color', 'Tomb Raider: Curse of the Sword', 'Tomb Raider', '2001-06-25', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21sp.jpg', 'Tomb Raider: Curse of the Sword is a video game based on the Tomb Raider series. It is a sequel to the first Tomb Raider for the same system. You''ll experience the usual amounts of ledge jumping and rope climbing that one expects from a game in the Tomb Raider series, as well as a number of activities unique to this particular release, such as boss battles, demolitions, and submarine piloting.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-2-seeds-of-evil-game-boy-color', 'Turok 2: Seeds of Evil', 'Turok', '1998-12-03', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zcg.jpg', 'The Amaranthine Accordance is trying to bring a massive Dinosoid army to Earth from the Lost Land in an effort to restore dinosaurs to their rightful home.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-rage-wars-game-boy-color', 'Turok: Rage Wars', 'Turok', '1999-11-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zqu.jpg', 'Turok: Rage Wars is a first-person shooter video game released for the Nintendo 64. The game supports up to four players or bots with a single player mission-based mode also available. The game allows use of the RAM Expansion Pak for enhanced play sessions.', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-3-shadow-of-oblivion-game-boy-color', 'Turok 3: Shadow of Oblivion', 'Turok', '2000-07-27', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7fpt.jpg', 'Turok 3: Shadow of Oblivion is a faithful restoration of the classic first-person shooter originally released in 2000 for the Nintendo 64, upgraded through Nightdive Studios’ proprietary KEX Engine for play on modern gaming devices with up to a 4K resolution at 120FPS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-ii-game-boy-color', 'Wario Land II', 'Wario', '1999-02-10', 'Game Boy Color', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qfz.jpg', 'What kind of no-good ruffians would break into my castle and steal my treasures?! It''s that rotten Captain Syrup and that Black Sugar Gang! I''m looking out for bad guys and scavenging for coins as I track down my treasures. If I don''t get them all the first time, that''s OK. I can go back again and again until I find them all. Captain Syrup doesn''t stand a chance against me!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-3-game-boy-color', 'Wario Land 3', 'Wario', '2000-06-01', 'Game Boy Color', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qgc.jpg', 'Trapped inside a magical music box, the invincible Wario is on a dangerous quest to help a mysterious figure recover its lost powers! Smash, bash and crash your way through more than two dozen gigantic levels in search of hidden keys, valuable treasures and mystical music boxes. Test your wits on puzzle after intricate puzzle and flex your muscles in action-packed boss fights! Be wary of Wanderin'' Gooms, Hammer-bots, Mad Scienstein and more as you plunge into one of the largest, most dazzling adventures ever to hit Game Boy Color!', 'NA', 18);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('advance-wars-game-boy-advance', 'Advance Wars', 'Advance Wars', '2001-09-10', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobavc.jpg', 'Lead a cast of colorful characters in fun, turn-based battles with two classic campaigns.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('advance-wars-2-black-hole-rising-game-boy-advance', 'Advance Wars 2: Black Hole Rising', 'Advance Wars', '2003-06-24', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9o1.jpg', 'Ten-hut! It’s time for basic training on the Advance Wars 1+2: Re-Boot Camp game! Guide your units in tactical, turn-based battles, find the CO Power that best fits your playstyle, and defend your HQ from opposing nations.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('altered-beast-guardian-of-the-realms-game-boy-advance', 'Altered Beast: Guardian of the Realms', 'Altered Beast', '2002-11-26', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5v1i.jpg', 'Zeus, creator and ruler of the Guardians of the Gates, raises you from your grave! You must go fourth and defeat a new, unknown evil that has destroyed the Guardians and ravaged the universe. To do so, you must collect the keys and Essence of each land, transforming you into beasts with unnatural powers and special abilities. Conquer this evil and you will become the sole Guardian, the protector of the universe.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('banjo-kazooie-grunty-s-revenge-game-boy-advance', 'Banjo-Kazooie: Grunty''s Revenge', 'Banjo-Kazooie', '2003-09-12', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ffk.jpg', 'Gruntilda is back, and only Banjo and Kazooie can stop her master plan! Travel through time encountering puzzles, battles, and meeting friends old and new in this all-new Banjo-Kazooie adventure!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('banjo-pilot-game-boy-advance', 'Banjo-Pilot', 'Banjo-Kazooie', '2005-01-12', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fed.jpg', 'Banjo Pilot is a kart-style racing game which was originally slated to become "Diddy Kong Pilot." It features at least eight characters from the Banjo-Kazooie series, each with its own aircraft and storyline, including Banjo, Mumbo Jumbo, Humba Wumba, Guntilda, Klungo, Jolly Roger and Kazooie. The game includes link cable support for up to four players.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-tournament-game-boy-advance', 'Bomberman Tournament', 'Bomberman', '2001-06-29', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2plm.jpg', 'An S.O.S. from the cosmos signals that planet Phantarion is in trouble! Grab your arsenal and get ready for non-stop action as you blast your way through interactive battlefields and take on up to 4 real-time players. Battle opponents through 8 interactive battlefield mazes! Take on up to 4 players in multi-player blastfests! Fast, furious, explosive bombing adventure!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-max-2-blue-advance-game-boy-advance', 'Bomberman Max 2: Blue Advance', 'Bomberman', '2002-05-30', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49km.jpg', 'Bomberman and Max have been shrunk to the size of an ant by the evil Mujie''s secret weapon. Work together with max to find and destroy the device before Mujoe can take control of the universe. And so the newest adventures of Bomberman begins!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-max-2-red-advance-game-boy-advance', 'Bomberman Max 2: Red Advance', 'Bomberman', '2002-05-30', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5u5x.jpg', 'Bomberman again teams up with Max to take on the evil Mujoe. But before they get the chance, Mujoe turns the tables, shrinking the heroes into tiny critters. Now the two must use their bombing powers and traverse the levels, blowing up obstacles and enemies to get to the exit, to eventually destroy the device and return themselves to normal size.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-bomberman-game-boy-advance', 'Classic NES Series - Bomberman', 'Bomberman', '2004-06-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wyp.jpg', 'The game that spawned more than 15 others, Bomberman, returns to the Game Boy Advance with its unique combination of action and puzzle-solving. As the title character, you must blow up bricks and enemies on the battlefield in an effort to find the door to the next level. In each stage, you''ll find power-ups that extend your blast radius. However, if you''re caught in your own bomb blast, you must start the level over.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-circle-of-the-moon-game-boy-advance', 'Castlevania: Circle of the Moon', 'Castlevania', '2001-06-11', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9yx.jpg', 'A port of Castlevania: Circle of the Moon included in "Castlevania Advance Collection."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-harmony-of-dissonance-game-boy-advance', 'Castlevania: Harmony of Dissonance', 'Castlevania', '2002-09-16', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9a6.jpg', 'Nearly fifty years has past since Simon Belmont rescued the land from the curse of Dracula. Now, Simon''s descendant Juste Belmont, must acquire the relics of Dracula to unravel the disappearance of his childhood friend Lydie. The castle''s enchanting mysteries and danger await all those who dare enter.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-aria-of-sorrow-game-boy-advance', 'Castlevania: Aria of Sorrow', 'Castlevania', '2003-05-06', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co687k.jpg', 'This is a hack of Aria of Sorrow that changes most part of the map, and the aim is to give completely new experience to players.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-castlevania-game-boy-advance', 'Classic NES Series - Castlevania', 'Castlevania', '2004-10-25', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dbs.jpg', 'Take a stroll down memory lane with the classic side-scrolling game Castlevania. The game, which is part of the Classic NES Series on the Game Boy Advance, sets you off on a mission to undo the curse of the evil Count. Before you challenge the Count, you must first battle his army of ghosts, mummies, bats, and zombies. Use your magic whip and other weapons if you want to make it out of the castle alive.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-double-pack-game-boy-advance', 'Castlevania: Double Pack', 'Castlevania', '2006-01-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z47.jpg', 'Compiles both Harmony of Dissonance and Aria of Sorrow on one Game Boy Advance cartridge.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-advance-the-alien-wars-ex-game-boy-advance', 'Contra Advance: The Alien Wars EX', 'Contra', '2002-11-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3fdh.jpg', 'In Contra Advance The Alien Wars EX, take down massive hordes of aliens, robots, and monsters to stop the evil Red Falcon from taking over the world! Featuring all new levels and graphics from the original Super Nintendo hit, Contra''s fast paced shooting action will keep you on the edge of your seat!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-the-huge-adventure-game-boy-advance', 'Crash Bandicoot: The Huge Adventure', 'Crash Bandicoot', '2002-02-25', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3py8.jpg', 'Tired of endlessly doing battle with meddling bandicoots, the nefarious Dr. Neo Cortex shrinks the entire Earth, and Crash and Coco along with it, to the size of a wumpa fruit. Luckily, Coco invents a machine to reverse the effects, but she needs crystals from around the world to power it. Crash must retrieve the crystals to help return the entire planet to its natural state. Experience Crash''s biggest adventure yet, with gameplay modes ranging from side-scrolling to 3D chase levels to aerial dogfight combat sequences. Battle your way through over 20 huge levels and six unique locations to defeat Cortex and save the world.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-2-n-tranced-game-boy-advance', 'Crash Bandicoot 2: N-Tranced', 'Crash Bandicoot', '2003-01-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7zdr.jpg', 'Crash is back and ready to take on an all-new nefarious villain. After the events of Crash Bandicoot: The Huge Adventure, Tropy, with the help of N. Trance, kidnaps Coco and Crunch, planning to brainwash them to the evil side. Now, Crash must travel to N. Trance''s twisted realm, battle and rescue Coco and Crunch, and ultimately defeat N. Trance and N. Tropy. To achieve these goals, you must use all of Crash''s spin, slide, and jumping abilities across 24 different levels. As you progress through the game, you''ll find yourself flying a helicopter, water-skiing, and piloting a spaceship--all for the sake of saving your friends.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-nitro-kart-game-boy-advance', 'Crash Nitro Kart', 'Crash Bandicoot', '2003-11-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pya.jpg', 'Crash Bandicoot returns to the karting scene with a host of other characters from the adventure series, and this time they have both Neo Cortex and Emperor Velo to worry about. Velo has taken the crew to a remote planet, forced to race for their lives against Neo Cortex and his many evil doers.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-purple-ripto-s-rampage-game-boy-advance', 'Crash Bandicoot Purple: Ripto''s Rampage', 'Crash Bandicoot', '2004-06-03', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7zk5.jpg', 'Crash Bandicoot Purple: Ripto''s Rampage is a handheld game featuring Crash Bandicoot in a crossover in the world of Spyro the Dragon. In these side-scrolling adventures, you can link up with three friends for a variety of multiplayer modes, including Party Games, Wager Games, and Card Trading. Connecting both Crash Bandicoot Purple and Spyro Orange gives you the option of unlocking special content and allows you to trade and wager the cards with friends.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-game-boy-advance', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-04', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-vengeance-game-boy-advance', 'Batman: Vengeance', 'DC', '2001-10-30', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h0x.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-injustice-for-all-game-boy-advance', 'Justice League: Injustice for All', 'DC', '2002-11-17', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d1w.jpg', 'Justice League: Injustice for All is a 2002 video game developed by Saffire and published by Midway Games for the Game Boy Advance. The game is based on the Justice League animated television series and showcases the League''s seven members within the context of a side-scrolling beat ''em up with platforming elements. The plot centres on the League''s efforts to avert global catastrophe carried out by Lex Luthor''s Injustice Gang.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-countdown-to-apokolips-game-boy-advance', 'Superman: Countdown to Apokolips', 'DC', '2003-03-26', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d2g.jpg', 'Lois Lane has been kidnapped, and only the Man of Steel can save her! Agents from the lava-scarred planet Apokolips have come to Metropolis to humiliate Superman before the entire world, right in his own hometown. Enlisting the aid of local mob kingpin Bruno Mannheim, leader of the notorious Intergang, wicked emissary Kanto supplies the gang with out-of-this-world weaponry possessing the power to bring down Superman. While Superman is busy bringing the thugs of Intergang to justice, the beastlike Kalibak seizes the opportunity to abduct Lois and spirit her away to a remote, clandestine location. In the meantime, bad bundle of energy Livewire has busted out of Strykers Island Prison, and she is out for vengeance against the man who put her there--Superman. There is no rest for the Last Son of Krypton as the Countdown to Apokolips begins!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-rise-of-sin-tzu-game-boy-advance', 'Batman: Rise of Sin Tzu', 'DC', '2003-10-27', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc6.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-chronicles-game-boy-advance', 'Justice League: Chronicles', 'DC', '2003-11-12', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ycu.jpg', 'Justice League: Chronicles is a video game based on Justice League. It was released on November 12, 2003. This game has three levels; each level has two characters. In the first stage, they are Green Lantern and Flash; in the second, Batman and Hawkgirl; and in the last, Superman and Wonder Woman.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('catwoman-game-boy-advance', 'Catwoman', 'DC', '2004-07-20', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3t.jpg', 'Catwoman is an action-adventure video game based on the 2004 film of the same name based on the fictional character. It features the likeness of the film''s lead actress Halle Berry, while the character''s voice is provided by actress Jennifer Hale.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-begins-game-boy-advance', 'Batman Begins', 'DC', '2005-06-14', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xux.jpg', 'Game Boy Advance port of Batman Begins.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teen-titans-game-boy-advance', 'Teen Titans', 'DC', '2005-10-16', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ubh.jpg', 'A game based on the "Teen Titans Go!" animated series. It follows the main character, Robin, as he seeks to be the best figure fighter in Jump City, a fictional city in the DC Universe.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-heroes-the-flash-game-boy-advance', 'Justice League Heroes: The Flash', 'DC', '2006-10-17', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5zpf.jpg', 'Justice League Heroes: The Flash is the Game Boy Advance version of Justice League Heroes released from Xbox and PlayStation 2. This version focuses primarily on The Flash and features 2D sidescrolling action gameplay and a sidestory to the console game''s plot.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teen-titans-2-game-boy-advance', 'Teen Titans 2', 'DC', '2006-10-23', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6iv6.jpg', 'Teen Titans 2 (alternatively known as Teen Titans 2: The Brotherhood''s Revenge on the title screen) is a Game Boy Advance game released in 2006, one year after the previous Teen Titans Game Boy Advance game and the same year as the Teen Titans video game for the PlayStation 2, Xbox, and Nintendo GameCube.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-returns-fortress-of-solitude-game-boy-advance', 'Superman Returns: Fortress of Solitude', 'DC', '2006-11-20', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yd3.jpg', 'Inspired by the Warner Bros. Pictures feature film and more than 60 years of DC Comics'' lore. As the Man of Steel, you’ll hone your unworldly super powers such as Flight, X-Ray Vision, Heat Vision, Super Hearing, Super Strength, Super Speed, and Super Breath to fight villains that only Superman can defeat.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-game-boy-advance', 'Donkey Kong Country', 'Donkey Kong', '2003-06-09', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jhu.jpg', 'Game Boy Color port of Donkey Kong Country.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-donkey-kong-game-boy-advance', 'Classic NES Series - Donkey Kong', 'Donkey Kong', '2004-06-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wt1.jpg', 'Classic NES Series: Donkey Kong is a port of the NES version of the famous arcade game. In Donkey Kong, Jumpman must rescue a damsel in distress, Lady, from a giant ape named Donkey Kong. The hero and ape later became two of Nintendo''s most popular characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-2-game-boy-advance', 'Donkey Kong Country 2', 'Donkey Kong', '2004-11-15', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7n25.jpg', 'Donkey Kong Country 2 is a remake of the SNES game Donkey Kong Country 2: Diddy''s Kong Quest. It is the second game in the series of remakes of the original Country trilogy for the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dk-king-of-swing-game-boy-advance', 'DK: King of Swing', 'Donkey Kong', '2005-09-19', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wfx.jpg', 'The normally quiet jungle is abuzz with excitement, because it''s time for the ceremony to choose the king of the jungle! Or at least it would be if King K. Rool hadn''t stolen the special medallion meant for the winner. Donkey Kong and his friends must swing their way through the jungle to get the medallion back and, along the way, rescue Diddy, Dixie, and Funky Kong from King K. Rool''s minions. A unique control system lets you swing through the trees and spin to build up momentum for a mighty leap. Innovative level design combines elements of platform and puzzle games: Grab gears and spin to crank doors open. Watch out for bolts that loosen as you spin, or you might find yourself falling flat. You''ll need steady hands to make the leap-of-faith that takes you to the treetops.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-3-game-boy-advance', 'Donkey Kong Country 3', 'Donkey Kong', '2005-11-07', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ven.jpg', 'Donkey Kong Country 3 is the Game Boy Advance version of the SNES game "Donkey Kong Country 3: Dixie Kong''s Double Trouble!". Although being developed as a port, the game has a different soundtrack composed by the veteran of the series David Wise, new minigames, worlds and overworld map layout.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-game-boy-advance', 'Doom', 'Doom', '2001-10-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-ii-game-boy-advance', 'Doom II', 'Doom', '2002-10-28', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6w0l.jpg', 'Doom II was included in Doom 3 Collector''s Edition for the Xbox, which was released in 2005. This port includes an exclusive level, "Betray". It featured multiplayer like the PC version, however not through Xbox Live. This port was programmed by Vicarious Visions. The Xbox version of Doom 3: Resurrection of Evil also contains this same port, as well as Master Levels for Doom II.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-dr-mario-game-boy-advance', 'Classic NES Series - Dr. Mario', 'Dr. Mario', '2004-10-25', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3u9v.jpg', 'The objective of Dr. Mario is to destroy the viruses populating the playing field by aligning them with vitamins of matching color, which are manipulated by the player after being dropped into the playing field.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mother-3-game-boy-advance', 'Mother 3', 'EarthBound', '2006-04-20', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v39.jpg', 'The Nintendo 64 version, cancelled in 2000, of the Game Boy Advance game MOTHER 3, released in 2006.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-excitebike-game-boy-advance', 'Classic NES Series - Excitebike', 'Excite', '2004-06-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wyv.jpg', 'Nintendo rereleases Excitebike on the Game Boy Advance, complete with all the high-flying action from the original NES game. As in the original, your biker must keep his balance while flying through the air, avoid getting clipped by other racers, and prevent his bike from overheating. In Design mode, you can make your own course--with all the ramps, mounds, bridges, and other obstacles in the game--and then save the design for your friends to race on.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f-zero-maximum-velocity-game-boy-advance', 'F-Zero: Maximum Velocity', 'F-Zero', '2001-06-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjw.jpg', 'All galactic speed limits are about to be broken! F-Zero Maximum Velocity has arrived, and the future of racing has never looked so sweet. Brand-new vehicles and Game Boy Advance original tracks await, so whether you''re a Super NES veteran or a race rookies, you''ll need some practice laps. And even if you do master the Grand Prix circuit, you''ll still have to beat your friends to the finish line. That''s right, race fans--with the Game Boy Advance Game Link cable you can take on up to three rival racers, so put the pedal to the metal and get busy boosting, bumping and jumping your way to intergalactic glory!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f-zero-gp-legend-game-boy-advance', 'F-Zero: GP Legend', 'F-Zero', '2004-09-20', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjx.jpg', 'The F-Zero series grows with new racing circuits, an intense storyline, and multiplayer modes. F-Zero GP Legend lets you take control of one of eight characters, including Captain Falcon, racing star Rick Wheeler, the evil lord Black Shadow, and more. Guide your character through various Grand Prix cups, time trials, and challenges that span multiple planets. In addition to conquering single-player challenges, you can challenge up to three of your friends in multiplayer competitions.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-tactics-advance-game-boy-advance', 'Final Fantasy Tactics Advance', 'Final Fantasy', '2003-09-08', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8fn.jpg', 'Squaresoft brings its popular Final Fantasy franchise to the Game Boy Advance in the form of strategic warfare. Final Fantasy Tactics Advance trails the story of a young boy named Marche who is magically transported from his sleepy modern-time home to a strange kingdom where magic and adventure reign supreme.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-i-ii-dawn-of-souls-game-boy-advance', 'Final Fantasy I & II: Dawn of Souls', 'Final Fantasy', '2004-11-29', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xzm.jpg', 'Final Fantasy I & II: Dawn of Souls is a compilation of the first two games in the Final Fantasy series. Graphically, it is similar to the previously released enhanced remakes of both games for the WonderSwan Color.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-iv-advance-game-boy-advance', 'Final Fantasy IV Advance', 'Final Fantasy', '2005-12-12', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yc0.jpg', 'Final Fantasy IV Advance is largely based on the WonderSwan Color version. Some changes include the addition of character portraits in text boxes, the ability to switch party members, increased difficulty, and new dungeons with new items and weapons along with new bosses. The script received a re-translation more faithful to the original material. The Quicksave, which allows the player to save the current position (regardless of where) in a file that is deleted upon loading, is featured.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-v-advance-game-boy-advance', 'Final Fantasy V Advance', 'Final Fantasy', '2006-11-06', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yc1.jpg', 'The winds fail. Ships stand still, unable to fill their sails. The world races to its end. Unless a handful of heroes can protect the remaining crystals, the world will fall into ruin. Set off on a grand adventure in the finest version of FINAL FANTASY V ever released!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-vi-advance-game-boy-advance', 'Final Fantasy VI Advance', 'Final Fantasy', '2007-02-05', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yh2.jpg', 'Final Fantasy VI Advance is more than a simple port of the SNES classic: every aspect of the games has been reviewed and enhanced. Additionally, a host of brand-new elements has been seamlessly merged with the original game, providing unexpected surprises for longtime fans. With new dungeons, new job classes, and other exciting features, both old-school players and newcomers can enjoy this genre-defining FINAL FANTASY title in a portable format.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-game-boy-advance', 'Fire Emblem', 'Fire Emblem', '2003-11-03', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6i98.jpg', 'Fire Emblem Fates - Special Edition was a limited time bundle containing both base stories, Birthright and Conquest, and gave access to DLC for the 3rd story, Revelation, when it became available. The games were otherwise sold separately though you could get the second story path digitally at a discount. You need to be have completed chapter 6 in the either game to access the other stories, and the DLCs, path.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-the-sacred-stones-game-boy-advance', 'Fire Emblem: The Sacred Stones', 'Fire Emblem', '2005-05-23', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25q4.jpg', 'In Fire Emblem: The Sacred Stones, you must help protect the nation of Renais from the invading Grado Empire. Plan your strategy, choose your units, and then lead your soldiers in to battle. The more experience your soldiers gain, the more you can upgrade their abilities. This time, your soldiers can gain experience by fighting new monsters in the Tower of Valni.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-gallery-4-game-boy-advance', 'Game & Watch Gallery 4', 'Game & Watch Gallery', '2002-10-28', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6au9.jpg', 'Relive the birth of handheld gaming with over a dozen classic Game & Watch games. Picture-perfect versions reproduce all the fast-paced action of the original games, and new modern versions bring these games into the 21st century with improved graphics, sound, and game play!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-ghouls-n-ghosts-game-boy-advance', 'Super Ghouls ''n Ghosts', 'Ghosts ''n Goblins', '2002-09-23', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7run.jpg', 'As dauntless knight Arthur you are caught up in the most dangerous of quests! A spell has been cast upon the kingdom. Your fair maiden, Princess Prin Prin has been snatched up by the evil emperor. Only as Arthur can you get her back from the creatures of the undead that haunt the land. Test your courage and skill to the limit. You must keep up the quest. On your journey, your mightiest weapon of all awaits you... MAGIC!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-sun-game-boy-advance', 'Golden Sun', 'Golden Sun', '2001-11-12', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25rt.jpg', 'The story of Golden Sun: The Lost Age picks up right near the end of the first game. Golden Sun veterans will be surprised to learn that The Lost Age is played from the point of view of the party being chased as they try to light the remaining two lighthouses, which will unlock the power of alchemy for the world--or will it instead unlock the world''s destruction?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-sun-the-lost-age-game-boy-advance', 'Golden Sun: The Lost Age', 'Golden Sun', '2003-04-14', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25rt.jpg', 'The story of Golden Sun: The Lost Age picks up right near the end of the first game. Golden Sun veterans will be surprised to learn that The Lost Age is played from the point of view of the party being chased as they try to light the remaining two lighthouses, which will unlock the power of alchemy for the world--or will it instead unlock the world''s destruction?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-advance-game-boy-advance', 'Grand Theft Auto Advance', 'Grand Theft Auto', '2004-10-26', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbf.jpg', 'Grand Theft Auto Advance is a handheld console game developed by Digital Eclipse, published by Rockstar Games, and released on October 26, 2004 for the Game Boy Advance. It is the only Grand Theft Auto game to not be developed by a Rockstar studio (formerly DMA Design).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-ice-climber-game-boy-advance', 'Classic NES Series - Ice Climber', 'Ice Climber', '2004-06-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kye.jpg', 'Twenty years after their debut on the NES, mountain climbers Popo and Nana return to scale the heights as part of the NES Classic Series for the Game Boy Advance. As Popo (player two plays as Nana), you must use your trusty mallet to work your way up the mountain by chipping away at the blocks overhead and then jumping through the resulting hole. Your mallet is also useful for eliminating pesky enemies, including polar bears, seals, and mountain men.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jet-grind-radio-game-boy-advance', 'Jet Grind Radio', 'Jet Set Radio', '2003-06-01', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rje.jpg', 'Jet Grind Radio (released as Jet Set Radio in Europe) is a video game for the Game Boy Advance system, which is based on the Dreamcast title of the same name. The game was developed by Vicarious Visions and published by THQ.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-chain-of-memories-game-boy-advance', 'Kingdom Hearts: Chain of Memories', 'Kingdom Hearts', '2004-12-07', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wrx.jpg', 'Kingdom Hearts: Chain of Memories is the second game in the Kingdom Hearts series. It is a direct sequel to Kingdom Hearts and exclusive to the Game Boy Advance. It was published by Square Enix and developed by Jupiter, and was released in 2004. Chronologically, it is the third game in the timeline after Kingdom Hearts Birth by Sleep and Kingdom Hearts, and takes place during Kingdom Hearts 358/2 Days.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-nightmare-in-dream-land-game-boy-advance', 'Kirby: Nightmare in Dream Land', 'Kirby', '2002-12-02', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wcd.jpg', 'A remake of the original Kirby''s Adventure for the NES.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-the-amazing-mirror-game-boy-advance', 'Kirby & the Amazing Mirror', 'Kirby', '2004-10-18', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w9u.jpg', 'Once again, Kirby must save the kingdom from evil. But this time he''ll need some backup. As Kirby, you can call up one of four alter egos for help during your quest. Each character features new copy abilities that range from arrow-shooting to melee moves. Practice your skills in new side games, such as Crackity Hack and Speed Eaters. In addition to new abilities and subgames, Kirby & the Amazing Mirror also introduces new multiplayer modes.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-a-link-to-the-past-and-four-swords-game-boy-advance', 'The Legend of Zelda: A Link to the Past and Four Swords', 'The Legend of Zelda', '2002-12-02', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3nsh.jpg', 'The Legend of Zelda: A Link to the Past & Four Swords features two games, a port of the SNES game The Legend of Zelda: A Link to the Past and a new multiplayer adventure called Four Swords.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-the-legend-of-zelda-game-boy-advance', 'Classic NES Series - The Legend of Zelda', 'The Legend of Zelda', '2004-06-02', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wst.jpg', 'The Legend of Zelda invented a genre and captivated a gaming generation. Now you can play the timeless NES adventure on your Game Boy Advance! The evil warlock Ganon has imprisoned Princess Zelda and plunged the peaceful land of Hyrule into darkness and despair. Only a young boy named Link has the courage to answer the call for a hero. Will he find the lost Triforce fragments, slay Ganon, and save Princess Zelda? Only you can decide the fate of Hyrule!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-zelda-ii-the-adventure-of-link-game-boy-advance', 'Classic NES Series - Zelda II: The Adventure of Link', 'The Legend of Zelda', '2004-10-25', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kyc.jpg', 'Zelda II: The Adventure of Link is an action role-playing game, and a sequel to The Legend Of Zelda. The gameplay alternates between a top-down view (when traveling the land) and side-scrolling perspectives (when fighting, in a temple, or town). In the top-down view, Link cannot do much except for walking: in the side-scrolling action view, however, he can fight, cast spells, collect items and talk to people.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-the-minish-cap-game-boy-advance', 'The Legend of Zelda: The Minish Cap', 'The Legend of Zelda', '2005-01-10', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3nsk.jpg', 'The Legend of Zelda: The Minish Cap is a top-down action adventure game that tells the origins of the evil Vaati from Four Swords. Like most other titles in the series, The Minish Cap features the fully explorable land of Hyrule, although it can be viewed from the eyes of a human or the eyes of a Minish, a race of tiny people and an alternate form that Link can transform into. Unlike the multiplayer focus of the other games in the series, The Minish Cap retains the original form of exploration and dungeons as seen in A Link to the Past, Oracle of Seasons, and Oracle of Ages, as well as returning characters and game mechanics such as Malon and the Spin Attack. New features include fusing Kinstones and shrinking to the size of a Minish.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-island-2-the-brickster-s-revenge-game-boy-advance', 'Lego Island 2: The Brickster''s Revenge', 'Lego', '2001-10-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94mf.jpg', 'The Brickster is back and out to cause more mischief in this wild, racing, chasing, island-hopping sequel. In your quest to piece together The Informaniac''s Constructopedia, you''ll drive, scuba-dive, fly a place and even ride a dinosaur as you chase the Brickster down through these amazing new LEGO worlds. Meet all kinds of fun characters along the way as you journey through the game. You''ll need all your skills to solve the puzzles and achieve your ultimate goal, to prevent LEGO Island being ruined.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-bionicle-quest-for-the-toa-game-boy-advance', 'Lego Bionicle: Quest for the Toa', 'Lego', '2001-10-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3den.jpg', 'LEGO Bionicle is an action-adventure platformer in an isometric perspective. The player controls Takua, a villager on the island of Mata Nui through a series of linear levels that take place in the 6 different biomes across the island. This is the only canon handheld Bionicle game, and seems to serve as a prelude to the Mata Nui Online Game and Mata Nui Online Game II.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-racers-2-game-boy-advance', 'Lego Racers 2', 'Lego', '2001-11-27', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xvv.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('soccer-mania-game-boy-advance', 'Soccer Mania', 'Lego', '2002-06-18', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i98.jpg', 'Soccer Mania is a Sports game, developed by Kitty Group and published by Epic Sony Record, which was released in 1992.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('galidor-defenders-of-the-outer-dimension-game-boy-advance', 'Galidor: Defenders of the Outer Dimension', 'Lego', '2002-10-15', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tg5.jpg', 'A 3D Action platformer video game tie-in to the TV Show/LEGO Toyline of the same name. It was originally being developer for PS2 and Gamecube consoles in 2002 but never released, leaving only the GBA game in it''s stead. It would eventually release for Windows PC in 2005 as a bargain title in the UK, usually bundled with other LEGO games at the time. It was later included in the 2007 "10 LEGO PC Games Collector''s Box".', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-matoran-adventures-game-boy-advance', 'Bionicle: Matoran Adventures', 'Lego', '2002-10-16', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xeb.jpg', 'BIONICLE: Matoran Adventures offers a fun character-switching feature to help players advance through each of the six levels found in the game. Players start as a Matoran and unlock more Matoran characters as they progress. Turaga, with their unique powers, can be "picked up" throughout the game to help the player through an elemental hazard like a lava pool or to activate a switch to a secret door. Once found, that "picked-up" Turaga follows you onwards in your adventure.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('island-xtreme-stunts-game-boy-advance', 'Island Xtreme Stunts', 'Lego', '2002-11-15', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4fgf.jpg', 'Island Xtreme Stunts is a mixture of different genres in a single game. The player explores a LEGO-based environment in an open world format: ride a skateboard, drive, fly and pilot a range of vehicles all whilst performing stunts and tricks while taking on the bad guy, Brickster. The player is cast as Pepper Roni, a lead stuntman in a big movie production set on LEGO Island.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drome-racers-game-boy-advance', 'Drome Racers', 'Lego', '2003-06-19', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yv6.jpg', 'Tensions are high as you await the first stage of the Drome Championship.You''ve trained for the intensity of Multi-Challenge Racing; each race a seamless set of stages, mixing tracks from realistically stunning City, Mountain, and Canyon environments.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-game-boy-advance', 'Bionicle', 'Lego', '2003-09-10', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3den.jpg', 'LEGO Bionicle is an action-adventure platformer in an isometric perspective. The player controls Takua, a villager on the island of Mata Nui through a series of linear levels that take place in the 6 different biomes across the island. This is the only canon handheld Bionicle game, and seems to serve as a prelude to the Mata Nui Online Game and Mata Nui Online Game II.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-knights-kingdom-game-boy-advance', 'Lego Knights'' Kingdom', 'Lego', '2004-10-04', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coahi2.jpg', 'A compilation of two LEGO games on the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-video-game-game-boy-advance', 'Lego Star Wars: The Video Game', 'Lego', '2005-03-29', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xvm.jpg', 'Take LEGO Star Wars mobile with the official port for the Game Boy Advance. Experience Star Wars in LEGO form while platforming through The Phantom Menace, Attack of the Clones and Revenge of the Sith.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-maze-of-shadows-game-boy-advance', 'Bionicle: Maze of Shadows', 'Lego', '2005-09-13', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3d3i.jpg', 'A top down action-adventure, set in the LEGO Bionicle universe and based on the book of the same name. Features six playable characters, six stages of adventure, and special multiplayer features.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-game-boy-advance', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-heroes-game-boy-advance', 'Bionicle Heroes', 'Lego', '2006-11-14', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525j.jpg', 'Bionicle Heroes DS is a classic first-person shooter. As a nameless Matoran, you''ll travel across 25 themed levels (including jungles, lava-worlds, ancient underground temples) discovering new weapons and new robotic foes to blast apart. Along the way, you''ll use the masks'' powers to survive the hostile environments as well as collect gears and robot parts to solve simple puzzles by assembling LEGO-style ramps, bridges, and doorways.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sword-of-mana-game-boy-advance', 'Sword of Mana', 'Mana', '2003-12-01', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9hkc.jpg', 'Legend of the Mana Sword focuses on making the first game of the Mana series both a better experience for first time players, and more fun for returning players.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-klax-game-boy-advance', 'Marble Madness / Klax', NULL, '2005-08-23', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7qfh.jpg', 'A compilation of the classic arcade games Klax and Marble Madness brought to the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-advance-game-boy-advance', 'Super Mario Advance', 'Mario', '2001-06-11', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21r7.jpg', 'An updated re-release of Super Mario Bros. 2 (the American reskin of "Yume Kōjō: Doki Doki Panic," later re-released in Japan as "Super Mario USA") as a Game Boy Advance launch title. Based heavily on the Super Mario All-Stars version of the game, it also features an updated version of the original Mario Bros. arcade game, which can be played with up to three other players via link cable.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-world-super-mario-advance-2-game-boy-advance', 'Super Mario World: Super Mario Advance 2', 'Mario', '2002-02-11', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nhk.jpg', 'Super Mario Advance 2: Super Mario World is a remake of Super Mario World for the Game Boy Advance starring Mario''s dinosaur friend Yoshi for the first time.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-advance-4-super-mario-bros-3-game-boy-advance', 'Super Mario Advance 4: Super Mario Bros. 3', 'Mario', '2003-10-21', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9xs8.jpg', 'The Wal-Mart set for Super Mario Advance 4 includes 5 more cards than the version from other retailers, with 7 cards in total. 5 of them are Power-Up Cards, 1 Level Card and 1 Demo Card.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-super-mario-bros-game-boy-advance', 'Classic NES Series - Super Mario Bros.', 'Mario', '2004-06-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3axg.jpg', 'Classic NES Series: Super Mario Bros. takes you back to the very first battle between Mario and Bowser. Now on the Game Boy Advance, you can relive all the mushroom-eating, Koopa-stomping action from the original game. Always strive for the high score while jumping on top of flag poles, pipes, and bricks. This time, two players can alternate play with a single Game Pak or with GBAs linked by a Game Boy Advance Game Link Cable.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-pinball-land-game-boy-advance', 'Mario Pinball Land', 'Mario', '2004-10-04', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wsi.jpg', 'Jumping has always helped Mario perform heroic feats, but in Mario Pinball Land, the plumber must learn how to roll to rescue the princess. When Bowser kidnaps Peach and escapes to another dimension, a scientist transforms Mario into a ball to chase after the fiend. Now you must use your flippers to shoot a much rounder Mario into doors that lead to new areas. In his new form, Mario is also useful for knocking down enemies, picking up special bonuses, and finding power-ups.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-superstar-saga-game-boy-advance', 'Mario & Luigi: Superstar Saga', 'Mario & Luigi', '2003-11-17', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22a7.jpg', '"The game that launched the Mario & Luigi series returns looking better than ever before.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-advance-tour-game-boy-advance', 'Mario Golf: Advance Tour', 'Mario Golf', '2004-06-22', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2204.jpg', 'Grab your clubs and start down the road to golfing perfection in this role-playing golf adventure! Chat up the locals at golf clinics, hone your skills in challenges like Club Slots and Go-Go Gates, and try to become the champ of all the country clubs! The Mushroom Kingdom residents take on only the very best.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-super-circuit-game-boy-advance', 'Mario Kart: Super Circuit', 'Mario Kart', '2001-08-27', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7o0u.jpg', 'Classic Mario Kart action is back once again, this time in a colorful, lightning-fast game that you can take anywhere. Mario, Luigi, Peach, Toad, Wario, Yoshi and Bowser are all tearing up the track, tossing Koopa Shells and laying banana peels along the way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-advance-game-boy-advance', 'Mario Party Advance', 'Mario Party', '2005-03-28', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v3t.jpg', 'It''s a portable party on your Game Boy Advance! Mario Party Advance takes all the fun of the home console game and puts it in your hands. All-new mini-games and a host of Professor E. Gadd''s incredible Gaddgets -- unique trinkets, toys, detectors and tricks like the Lip Disguise-o-matic that let you play tricks on your friends, test your compatibility and much more. Discover the 60 mini-games as you play through the single-player game boards. Earn coins as you play the mini-games, and use those coins to unlock Gaddgets you can use with your friends. Use your Gaddgets to take the game into the real world. Place your finger on the Finger X-Ray to see what''s hidden inside, or use the Compatibility Meter to see how well you and your friends match up.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-power-tour-game-boy-advance', 'Mario Tennis: Power Tour', 'Mario Tennis', '2005-12-05', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gme.jpg', 'Players can test their backhand in this unique role-playing tennis adventure. Train hard at the Royal Tennis Academy to be a champion. Gain experience and improve your skills through lessons and tournaments, and rise to the top of the ranks. Play as Mario, Peach, Waluigi, or Donkey Kong in a slew of wild modes. Advance through the story and unlock even more characters, all with their own power moves. Beat Mario at his own game, then link up with a friend or three for even more frantic fun.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-vs-donkey-kong-game-boy-advance', 'Mario vs. Donkey Kong', 'Mario vs. Donkey Kong', '2004-05-24', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6omn.jpg', 'Mario vs. Donkey Kong: Minis March Again! (マリオVSドンキーコング ミニミニ再行進!? Mario tai Donkī Kongu Mini Mini sai Kōshin!) is a puzzle video game for the Nintendo DSi. Announced at the Electronic Entertainment Expo 2009, it is the third game in the Mario vs. Donkey Kong series. It was released via the Nintendo DSiWare download service in North America on June 8, 2009, in Europe and Australia on August 21, 2009 and in Japan on October 7, 2009. It is the first DSiWare game to feature a level editor in which players can create custom-made levels and send them to players on other devices via a wireless Internet connection.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-mysterio-s-menace-game-boy-advance', 'Spider-Man: Mysterio''s Menace', 'Marvel', '2001-09-19', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qh9.jpg', 'Set in New York, Spider-Man: Mysterio''s Menace enables players to assume the role of Spider-Man as they take on super-villain Mysterio and his illusory tricks for control of Manhattan. Spider-Man must fight a slew of Mysterio''s sinister conspirators and gadgetry to get to the bottom of their plot and free New York from Mysterio''s mind-warping grip.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-reign-of-apocalypse-game-boy-advance', 'X-Men: Reign of Apocalypse', 'Marvel', '2001-09-25', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zgg.jpg', 'You and your fellow X-Men are lost in an alternate reality, only to discover that supervillain Apocalypse reigns supreme. Not only do you find yourself at the mercy of his minions, but also the line between foe and friend is dangerously blurred in this mirror universe. Your only hope is to fight your way through numerous enemies and threats until you reach the Warp Gate and return home. Will you survive long enough to make it there?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-game-boy-advance', 'Spider-Man', 'Marvel', '2002-04-16', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-invincible-iron-man-game-boy-advance', 'The Invincible Iron Man', 'Marvel', '2002-12-15', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co485u.jpg', 'The Invincible Iron Man allows you to experience the powers of Iron Man as he fights hordes of enemies while tracking down the super-villains who have stolen his battle suit technology. Using a variety of battle suit weaponry he navigates diverse levels that are filled with environmental obstacles and imminent danger. Multiple power-ups, unlockable bonus items and special pick-ups provide fans with the ultimate Iron Man experience.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('daredevil-game-boy-advance', 'Daredevil', 'Marvel', '2003-02-14', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3z.jpg', 'Daredevil for the Game Boy Advance is your basic punch-kick-jump action platformer featuring Marvel''s more unlikely superhero, a blind lawyer with enhanced abilities and senses. Though the game was marketed as a tie-in with the February 14th release of the Daredevil film, the GBA title is more based upon a less realistic, comic book design with bright and vibrant colors and the occasional "Pow!" and "Bif!" when knocking out opponents. Some levels cut across rooftops, others over vehicles in traffic; some go in buildings and underground. As players get through the 23 different levels, they''ll uncover the game''s original plot through comic book-style cutscenes.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x2-wolverine-s-revenge-game-boy-advance', 'X2: Wolverine''s Revenge', 'Marvel', '2003-04-15', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gx1.jpg', 'Logan was surgically implanted with the virtually unbreakable adamantium skeleton that made him into Wolverine, one of the world''s most famous X-Men. Now, more than 30 years later, Wolverine has discovered that he was also implanted with something else: a viral time-bomb that will render him lifeless in 48 hours. The clock is ticking. The antidote needs to be found quickly.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-game-boy-advance', 'The Incredible Hulk', 'Marvel', '2003-05-28', 'Game Boy Advance', 0, 0, NULL, NULL, NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-game-boy-advance', 'Spider-Man 2', 'Marvel', '2004-06-28', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-game-boy-advance', 'Fantastic Four', 'Marvel', '2005-06-27', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nah.jpg', 'The Fantastic Four video game, released in 1997 for the PlayStation, is a beat ''em-up action game based on the Marvel Comics superhero team. Developed by Probe Entertainment and published by Acclaim Entertainment, the game features playable characters Mr. Fantastic, The Invisible Woman, The Human Torch, The Thing, and She-Hulk, each with unique abilities. A version for the Sega Saturn was planned but ultimately cancelled. Players engage in combat, solve puzzles, and navigate obstacles across various levels, drawing from the rich lore of the Fantastic Four comics.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-spider-man-game-boy-advance', 'Ultimate Spider-Man', 'Marvel', '2005-09-22', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/lsjknidfrlnz2cintrkr.jpg', 'Help Spider-Man save Harry Osborn from the Venom symbiote.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-4-flame-on-game-boy-advance', 'Fantastic 4: Flame On', 'Marvel', '2005-11-08', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d6g.jpg', 'You are the Human Torch! Unleash your powers as you take on enemies around the globe in this all-new Fantastic 4 adventure.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-game-boy-advance', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-game-boy-advance', 'Marvel: Ultimate Alliance', 'Marvel', '2006-10-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-battle-for-new-york-game-boy-advance', 'Spider-Man: Battle for New York', 'Marvel', '2006-11-14', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dep.jpg', 'Spider-Man: Battle for New York allows players to take on the role of Spider-Man and one of his famed nemeses, Green Goblin. For the first time in a handheld Spider-Man game, players can personalize their experiences by choosing what abilities and powers to upgrade and when, such as Spider-Man’s web manoeuvres or Green Goblin’s fire attacks.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-rider-game-boy-advance', 'Ghost Rider', 'Marvel', '2007-02-13', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7sv8.jpg', 'The Ghost Rider feature film follows superstar motorcycle stunt rider Johnny Blaze as he strikes a deal with the vile Mephistopheles for the most precious of commodities - his immortal soul. Now Johnny Blaze is forever destined to ride night after night as the host to the powerful supernatural entity known as the Ghost Rider. The video game continues the storyline, dropping players into the role of Blaze as he is transformed into a super hero with powers to avenge any evil he encounters. Featuring many of the characters and motorcycles from the comic book and movie, Ghost Rider engages gamers in an immersive, supernatural third person world with a seamless blend of hand-to-hand combat and high-speed motorcycle action.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-game-boy-advance', 'Spider-Man 3', 'Marvel', '2007-05-04', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-bass-game-boy-advance', 'Mega Man & Bass', 'Mega Man', '2003-03-11', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55c4.jpg', 'Mega Man & Bass is an entry in the classic Mega Man series, with option for controlling either Mega Man or Bass, due to Dr. Wily and Dr. Light making a truce to fight against King. The game was originally released only in Japan, but a later Game Boy Advance port had an international release.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-game-boy-advance', 'Mega Man Battle Network', 'Mega Man Battle Network', '2001-10-31', 'Game Boy Advance', 1, 0, NULL, NULL, NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-2-game-boy-advance', 'Mega Man Battle Network 2', 'Mega Man Battle Network', '2002-06-12', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobog3.jpg', 'The second entry, which introduced the Style Change system. Your battle style will impact MegaMan''s abilities, adding another layer of strategy to battles!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-3-blue-version-game-boy-advance', 'Mega Man Battle Network 3 Blue Version', 'Mega Man Battle Network', '2003-06-24', 'Game Boy Advance', 1, 0, NULL, NULL, NULL, NULL, 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-3-white-version-game-boy-advance', 'Mega Man Battle Network 3 White Version', 'Mega Man Battle Network', '2003-06-24', 'Game Boy Advance', 1, 0, NULL, NULL, NULL, NULL, 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-chip-challenge-game-boy-advance', 'Mega Man Battle Chip Challenge', 'Mega Man Battle Network', '2004-03-02', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bhg.jpg', 'Bring it On... Rise to the Challenge! Face off against your opponents. Earn new battle chips and power ''em up! Test your skills in cool new battle scenes and prepare for the ultimate battle for "Net Domination" in the Battle Chip Grand Prix. Choose familiar characters from the Battle Network universe—including Mega Man and Guts Man, meet an all new Net-Navi character, and render shots, sword maneuvers and specialized moves with your Battle Chips. Released in Japan as Rockman EXE Battle Chip GP, Mega Man Battle Chip Challenge supports combat for two players via link-up.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-4-red-sun-game-boy-advance', 'Mega Man Battle Network 4 Red Sun', 'Mega Man Battle Network', '2004-06-29', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coant3.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips except for GunSolEX. GrandPrixPower and Duo event chips are nowhere to be seen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-4-blue-moon-game-boy-advance', 'Mega Man Battle Network 4 Blue Moon', 'Mega Man Battle Network', '2004-06-29', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coant1.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips except for GunSolEX. GrandPrixPower and Duo event chips are nowhere to be seen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-5-team-protoman-game-boy-advance', 'Mega Man Battle Network 5 Team Protoman', 'Mega Man Battle Network', '2005-06-21', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coant2.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips including Otenko and GunDelEX. LeadersRaid and ChaosLord event chips are nowhere to be seen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-5-team-colonel-game-boy-advance', 'Mega Man Battle Network 5 Team Colonel', 'Mega Man Battle Network', '2005-06-21', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coant0.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips including Otenko and GunDelEX. LeadersRaid and ChaosLord event chips are nowhere to be seen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-6-cybeast-gregar-game-boy-advance', 'Mega Man Battle Network 6 Cybeast Gregar', 'Mega Man Battle Network', '2006-06-13', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3hl.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips (opposite version Navi chips). Furthermore, since the Event BBS cards, which are implemented by default in the international GBA version, were added to the Japanese version via the Network Menu.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-6-cybeast-falzar-game-boy-advance', 'Mega Man Battle Network 6 Cybeast Falzar', 'Mega Man Battle Network', '2006-06-13', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3hm.jpg', 'In the Virtual Console version, the Network Menu now lets you obtain one copy each of all secret chips (opposite version Navi chips). Furthermore, since the Event BBS cards, which are implemented by default in the international GBA version, were added to the Japanese version via the Network Menu.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-game-boy-advance', 'Mega Man Zero', 'Mega Man Zero', '2002-09-10', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobkv1.jpg', 'It''s your mission to help the exiled scientist Ciel discover the source of a new reploid energy! Play as Mega Man''s pal Zero, the reploid from the Mega Man X series turned good by the infectious Sigma Virus and 100 years of sleep. Conquer your adversaries and find the energy source... or risk ultimate defeat. It''s up to you to defend good from the destructive powers in the universe.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-2-game-boy-advance', 'Mega Man Zero 2', 'Mega Man Zero', '2003-10-14', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co203j.jpg', 'In Zero''s next mission, he falls prey to a trap set by Neo Arcadia''s ruthless commander. Planning to trick Zero, he tries to use him to wreak chaos between reploids and humans once again. But, can he succeed?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-3-game-boy-advance', 'Mega Man Zero 3', 'Mega Man Zero', '2004-10-05', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakol.jpg', 'The version of Mega Man Zero released in Mega Man Zero Collection added support for all of the e-Reader content without using the peripheral.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-4-game-boy-advance', 'Mega Man Zero 4', 'Mega Man Zero', '2005-10-04', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204g.jpg', 'Mega Man Zero 4 is a video game created by Capcom and Inti Creates for the Game Boy Advance in 2005. It''s the fourth and final installment in the Mega Man Zero series, making Zero the first Mega Man subseries to see a proper conclusion.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-fusion-game-boy-advance', 'Metroid Fusion', 'Metroid', '2002-11-18', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w49.jpg', 'Metroid Fusion is a side-scrolling action-adventure game that combines exploration, combat, and progression within a structured environment. Players navigate distinct sectors, acquire new abilities, and unlock access to previously restricted areas as they advance.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-zero-mission-game-boy-advance', 'Metroid: Zero Mission', 'Metroid', '2004-02-09', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vci.jpg', 'The full story of Samus Aran''s first mission finally unfolds...
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-metroid-game-boy-advance', 'Classic NES Series - Metroid', 'Metroid', '2004-10-25', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kzc.jpg', 'Classic NES Series: Metroid is a port of Metroid for the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-fellowship-of-the-ring-game-boy-advance', 'The Lord of the Rings: The Fellowship of the Ring', 'Middle-earth', '2002-09-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lum.jpg', 'J.R.R. Tolkien''s Middle-earth is a land of beauty, magic, and darkness. In The Lord of the Rings: The Fellowship of the Ring, you follow Tolkien''s narrative from the Shire to the halls of Moria, and finally to the banks of the River Anduin. Gameplay alternates between melee, archery, sorcery, and stealth as you control Frodo, Gandalf, and Aragorn. Join this band of heroes in their quest to destroy the One Ring, which contains all the power of the dark lord Sauron.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-two-towers-game-boy-advance', 'The Lord of the Rings: The Two Towers', 'Middle-earth', '2002-11-12', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxb.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-return-of-the-king-game-boy-advance', 'The Lord of the Rings: The Return of the King', 'Middle-earth', '2003-11-05', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hd8.jpg', 'An unlicensed Lord of the Rings Game using the engine from Pocky and Rocky with Becky. Despite the name, the game is vaguely based on the first Lord of the Rings movie, The Fellowship of the Ring. Each level starts off with a screenshot from the movie, though the actual levels and bosses have little resemblance', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-hobbit-game-boy-advance', 'The Hobbit', 'Middle-earth', '2003-11-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3li.jpg', 'Step into the hairy hobbits'' feet of Bilbo Baggins in Vivendi Universal Games'' take on Tolkien''s prequel to the massive Lord of the Rings trilogy.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-third-age-game-boy-advance', 'The Lord of the Rings: The Third Age', 'Middle-earth', '2004-11-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20oi.jpg', 'The Lord of the Rings: The Third Age for Game Boy Advance is a turn-based tactics game released in 2004. The game consists of 2 campaigns (Good and Evil). In each campaign the player chooses a commander. As the player completes missions and progresses through the campaign, they are able to use experience points to purchase skills and equipment upgrades in order to enhance the performance of their primary and secondary heroes.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-game-boy-advance', 'Namco Museum', 'Namco Museum', '2001-06-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhd.jpg', 'Popular Namco games collected on Nintendo Switch.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-munch-s-oddysee-game-boy-advance', 'Oddworld: Munch''s Oddysee', 'Oddworld', '2003-09-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yni.jpg', 'Oddworld: Munch''s Oddysee is set in the fictional Oddworld universe and take place after those of Abe''s Exoddus. The player controls Munch as well as Abe, the hero of the previous Oddworld games. Abe''s abilities haven''t changed much since the last installment: as before, GameSpeak must be used to communicate with other creatures, leading them to safety. His fellow Mudokons can now be ordered to attack enemies. Abe can also grab and toss Mudokons or Munch to lead them to area they cannot access otherwise. Possessing enemies also comes into play, and is needed to solve many of the puzzles. Possession abilities can now be used to ignite quarrels between enemies and make them fight each other.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-collection-game-boy-advance', 'Pac-Man Collection', 'Pac-Man', '2001-07-13', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/xuyjsipxplncg6xlaffn.jpg', 'Pac-Man Collection (Atari 7800) is a 2006 homebrew compilation by Bob “PacManPlus” DeCrescenzo, published through AtariAge. It includes multiple Pac-Man and Ms. Pac-Man arcade variants—such as Puck Man, Hangly Man, Ultra Pac-Man, and Random Mazes—each can also be played in Plus mode, with selectable Fast, Slow, or Button-activated speed settings.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('classic-nes-series-pac-man-game-boy-advance', 'Classic NES Series - Pac-Man', 'Pac-Man', '2004-06-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wsz.jpg', 'Classic NES Series: Pac-Man is a Game Boy Advance port of the NES version of Pac-Man.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-maze-madness-game-boy-advance', 'Ms. Pac-Man Maze Madness', 'Pac-Man', '2004-11-03', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66r6.jpg', 'Game Boy Advance port of Ms. Pac-Man: Maze Madness.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-pinball-advance-game-boy-advance', 'Pac-Man Pinball Advance', 'Pac-Man', '2005-05-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dns.jpg', 'Pac-Man takes on the role of the pinball, and his foes Blinky, Inky, Pinky and Clyde are going to do their best to stop him from rescuing the kidnapped residents of Pac-World. Pac-Man Pinball offers multi-ball play with the aid of Ms. Pac-Man, and challenges players to mini-games to keep the action fresh. True to Pac-Man tradition, players can also collect dots and power pellets for points and upgrades.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-2-game-boy-advance', 'Pac-Man World 2', 'Pac-Man', '2005-10-09', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8l2.jpg', 'PAC-MAN WORLD 2 Re-PAC modernizes, updates, and enhances the fan favorite 3D Platforming adventure in nearly every way! Venture across PAC-LAND to reclaim the golden fruit and put a stop to the ghosts and their dastardly boss, Spooky!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ruby-version-game-boy-advance', 'Pokémon Ruby Version', 'Pokémon', '2003-03-19', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zhq.jpg', 'Sequel to Pokémon Gold and Silver Versions (1999), Pokémon Ruby and Sapphire Versions offer 135 new Pokémon, more complex battling and training systems, new crime organizations, a longer and more story-focused campaign and upgraded graphics to create a new and technically improved Pokémon experience.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-sapphire-version-game-boy-advance', 'Pokémon Sapphire Version', 'Pokémon', '2003-03-19', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zhp.jpg', 'Sequel to Pokémon Gold and Silver Versions (1999), Pokémon Ruby and Sapphire Versions offer 135 new Pokémon, more complex battling and training systems, new crime organizations, a longer and more story-focused campaign and upgraded graphics to create a new and technically improved Pokémon experience.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-pinball-ruby-sapphire-game-boy-advance', 'Pokémon Pinball: Ruby & Sapphire', 'Pokémon', '2003-08-25', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s2w.jpg', 'Pokemon Pinball has all the features you''d demand of a pinball game, including bonus tables, lots of bumpers and ways to score massive points. As with your standard videogame pinball game, the left button on the D-pad and the A-button control the flippers with the R/L triggers used to shake the table. The catch here is that everything is themed in Pokemon. Instead of a ball, you make use of a Pokeball. Instead of standard bumpers, you''re hitting the Pokeball against other Pokemon, and the ultimate goal is of course to "catch ''em all". The game features 200 Pokemon, two main tables, and link cable support.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-firered-version-game-boy-advance', 'Pokémon FireRed Version', 'Pokémon', '2004-09-09', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ziq.jpg', 'Pokémon FireRed Version and Pokémon LeafGreen Version are a pair of core series Generation III games that are set in the Kanto region. They were released in Japan on January 29, 2004, in North America on September 9, 2004, in Australia on September 23, 2004 and in Europe on October 1, 2004.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-leafgreen-version-game-boy-advance', 'Pokémon LeafGreen Version', 'Pokémon', '2004-09-09', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zip.jpg', 'Pokémon LeafGreen Version and Pokémon FireRed Version are a pair of core series Generation III games that are set in the Kanto region. They were released in Japan on January 29, 2004, in North America on September 9, 2004, in Australia on September 23, 2004 and in Europe on October 1, 2004.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-emerald-game-boy-advance', 'Pokémon Emerald', 'Pokémon', '2005-05-01', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fje.jpg', 'In this hack, the entire overworld has been turned into an ice puzzle. The game is able to be beaten (a lot of overworld changes were required to make this happen, carpets and flowers are safe spots), but the path to the end is very different than a normal playthrough.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-red-rescue-team-game-boy-advance', 'Pokémon Mystery Dungeon: Red Rescue Team', 'Pokémon', '2006-09-18', 'Game Boy Advance', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21em.jpg', 'You, a regular human, find yourself trapped in the body of a Pokémon in a world inhabited by Pokémon. Without any other choice, you go on rescue missions through randomly generated dungeons with your newly-acquired partner and friend to save the world and get back to your human life.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-sands-of-time-game-boy-advance', 'Prince of Persia: The Sands of Time', 'Prince of Persia', '2003-10-28', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4t8l.jpg', 'Deceived by the treacherous Vizier, I was led to unleash the Sands of Time curse upon the Sultan''s kingdom. With little but an ancient dagger and a devious princess to aid me, I must undo my fatal mistake. Mine is a fight for survival… not glory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-game-boy-advance', 'Rayman', 'Rayman', '2001-06-11', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jo7.jpg', 'English with Rayman is an educational 2D platform game, based on the original Rayman. It was designed to teach young children the basics of the English language. It is not to be confused with Rayman Junior, which is an entirely different game. English with Rayman blends the Glade of Dreams with the real world in a way which makes little sense in the context of the series, making numerous references to real-world locations such as Ireland and Scotland. English with Rayman was adapted to teach various other languages under such names as French with Rayman.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-3-hoodlum-havoc-game-boy-advance', 'Rayman 3: Hoodlum Havoc', 'Rayman', '2003-03-04', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jnb.jpg', 'This port of Rayman 3 released for the DigiBlast handheld console is based on the Game Boy Advance port of the game, but has less stages and no multiplayer. Every pseudo-3D stage were removed.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-hoodlums-revenge-game-boy-advance', 'Rayman: Hoodlums'' Revenge', 'Rayman', '2005-03-15', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3k9a.jpg', 'Rayman: Hoodlums'' Revenge is an isometric platformer game based on Rayman 3: Hoodlum Havoc.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-advance-risky-revolution-game-boy-advance', 'Shantae Advance: Risky Revolution', 'Shantae', '2025-04-21', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaboc.jpg', 'Shantae is back in an adventure 20 years in the making! The nefarious pirate Risky Boots has a “groundbreaking” new plan that will leave Sequin Land spinning — by rotating the continent, she can move any town right to the coast for easy plundering! As Shantae, turn the tectonic tables on Risky by taking control of the land itself: shift, twist, navigate, and explore by swapping between mix-and-match multilayered levels! Hair-whip and belly-dance your way through scrambled lands, misplaced towns, monster-filled crypts, and daunting labyrinths. Six creature transformations, fierce boss battles, and a 4-player versus mode await!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-bustin-out-game-boy-advance', 'The Sims Bustin'' Out', 'The Sims', '2003-12-16', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5w.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-urbz-sims-in-the-city-game-boy-advance', 'The Urbz: Sims in the City', 'The Sims', '2004-11-09', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5s.jpg', 'Starting out as a humble window washer in the city of Miniopolis, the player is quickly embroiled in a devious plot by the greedy tycoon Daddy Bigbucks to take over the city.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-game-boy-advance', 'The Sims 2', 'The Sims', '2005-10-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja7.jpg', 'The Sims 2 for Nintendo DS is the first DS game of The Sims 2. Like the many of the console games it takes place in Strangetown with some of the same faces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-game-boy-advance', 'The Sims 2: Pets', 'The Sims', '2006-11-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-advance-game-boy-advance', 'Sonic Advance', 'Sonic the Hedgehog', '2002-02-03', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coahgv.jpg', 'A compilation of two Sonic the Hedgehog games on a single cartridge.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-advance-2-game-boy-advance', 'Sonic Advance 2', 'Sonic the Hedgehog', '2003-03-09', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zv8.jpg', 'Sonic returns for a second outing on the Game Boy Advance.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-pinball-party-game-boy-advance', 'Sonic Pinball Party', 'Sonic the Hedgehog', '2003-06-01', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coahib.jpg', 'Bundle containing Sonic Pinball Party and Sonic Battle for the Game Boy Advance.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-battle-game-boy-advance', 'Sonic Battle', 'Sonic the Hedgehog', '2004-01-05', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvd.jpg', 'Sonic and pals are gearing up for some brawling action!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-advance-3-game-boy-advance', 'Sonic Advance 3', 'Sonic the Hedgehog', '2004-06-07', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvg.jpg', 'Sonic is back, and this time, he needs the help of all of his friends to defeat the evil Dr. Eggman. In Sonic Advance 3, Sonic and Tails must reunite with their friends Cream, Knuckles, and Amy. Team up with any of the five characters to gain special attack moves: Sonic increases your speed, Tails increases your jump power, Knuckles increases your attack power, Amy offers the Piko Piko hammer attack, and Cream lets you perform a homing attack. With a Game Boy Advance link, you and three of your friends can battle it out in multiplayer modes.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-genesis-game-boy-advance', 'Sonic the Hedgehog Genesis', 'Sonic the Hedgehog', '2006-11-14', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9gy1.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-channel-5-special-edition-game-boy-advance', 'Space Channel 5: Special Edition', 'Space Channel 5', '2003-06-17', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co44xs.jpg', '"Space Channel 5 Special Edition" actually contains two games. The first is "Space Channel 5", and the second is "Space Channel 5 Part 2". This is the first NA release of the latter game.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-game-boy-advance', 'Space Invaders', 'Space Invaders', '2002-03-19', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-season-of-ice-game-boy-advance', 'Spyro: Season of Ice', 'Spyro', '2001-11-07', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yqk.jpg', 'Spyro: Season of Ice is the first Spyro game not developed by Insomniac Games and to appear on the Game Boy Advance. Unlike the Playstation series, Seasons of Ice has the player controlling Spyro through an isometric overhead camera. However, all of Spyro''s skills are still available to use, including his flame breath and glide. And the flying bonus levels make use of the Mode 7 technology in order to create the 3D like perspective.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-2-season-of-flame-game-boy-advance', 'Spyro 2: Season of Flame', 'Spyro', '2002-09-25', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8omq.jpg', 'Spyro 2: Season of Flame is the sequel to Spyro: Season of Ice. All the old characters from previous games are there, with Hunter and Bianca, and the player can also control Sheila the Kangaroo and Agent 9. Spyro has a few unusual abilities in this GBA game, including a fire/ice breath toggle. Some items can only be affected by one or the other. Unlike the PSX games, Spyro is presented primarily in an isometric view.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-attack-of-the-rhynocs-game-boy-advance', 'Spyro: Attack of the Rhynocs', 'Spyro', '2003-10-27', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48fc.jpg', 'Spyro: Attack of the Rhynocs is the third isometric platform game developed for the Game Boy Advance. It was the last Spyro game to release under the Universal Interactive label, as the label would be phased out shortly after the game''s release. In this game, RPG elements offer more depth than previous Spyro titles, including quests, mini-quests, and a new inventory system, creating more ways to enjoy the Dragon Realms and making this a completely new Spyro experience.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-orange-the-cortex-conspiracy-game-boy-advance', 'Spyro Orange: The Cortex Conspiracy', 'Spyro', '2004-06-03', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7zkr.jpg', 'Spyro Orange: The Cortex Conspiracy is a handheld crossover title with the Crash Bandicoot franchise. It is the first Spyro game developed by Vicarious Visions. The development team has given the dragon a more traditional side-scrolling environment for his overworld instead of taking him back to his isometric exploits. But the scrolling platformer is only part of the experience. Spyro Orange focuses on dozens of mini-challenges for its gameplay, like a vertical shooter where Spyro floats around blasting sheep or collecting gems, a rapid-button-tapping challenge involving tug-o-war and ice cube creation, or driving around in a tank, or knocking out a series of bad guys in a Breakout-style challenge. The game supports link cable play for multiplayer challenges.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-a-new-beginning-game-boy-advance', 'The Legend of Spyro: A New Beginning', 'Spyro', '2006-10-10', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86aa.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-the-eternal-night-game-boy-advance', 'The Legend of Spyro: The Eternal Night', 'Spyro', '2007-10-02', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a9.jpg', NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-jedi-power-battles-game-boy-advance', 'Star Wars Episode I: Jedi Power Battles', 'Star Wars', '2001-11-21', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav0d.jpg', 'The game follows the plot of Star Wars Episode I: The Phantom Menace. Players can choose from one of five prequel-era Jedi and run, jump, slash, and use the Force through the game''s ten levels, starting on the Trade Federation Battleship and ending with the battle against Darth Maul on Naboo.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-ii-attack-of-the-clones-game-boy-advance', 'Star Wars: Episode II – Attack of the Clones', 'Star Wars', '2002-05-30', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ekh.jpg', 'Star Wars: Episode II - Attack of the Clones is a side-scrolling action game based on the second movie in the Star Wars prequel trilogy. Players fight through the story of the movie as Obi-Wan Kenobi, Anakin Skywalker, and Mace Windu.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-new-droid-army-game-boy-advance', 'Star Wars: The New Droid Army', 'Star Wars', '2002-11-14', 'Game Boy Advance', 0, 0, NULL, NULL, NULL, 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-flight-of-the-falcon-game-boy-advance', 'Star Wars: Flight of the Falcon', 'Star Wars', '2003-11-18', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d2m.jpg', 'Can you outrun the Empire?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-trilogy-apprentice-of-the-force-game-boy-advance', 'Star Wars Trilogy: Apprentice of the Force', 'Star Wars', '2004-09-21', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3b.jpg', 'For the first time, the legendary Star Wars movie trilogy arrives on Game Boy Advance. Players will experience the most exciting and memorable scenes from Star Wars: A New Hope, The Empire Strikes Back, and Return of the Jedi.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-iii-revenge-of-the-sith-game-boy-advance', 'Star Wars: Episode III – Revenge of the Sith', 'Star Wars', '2005-05-04', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3sjo.jpg', 'The Clone Wars continue to rage between the Republic and the Separatists. Supreme Chancellor Palpatine has been taken hostage, and Obi-Wan, together with Anakin, must rescue him! The Star Wars Episode III: Revenge of the Sith games for the Game Boy Advance and Nintendo DS systems allow players to experience the stunning Jedi action of the movie. Developed by Ubisoft''s Montreal studio, each version leverages the strengths of its handheld platform to produce the ultimate Jedi action experience. The control of multiple heroes, devastating Force powers, and never-before-seen locations are just a few of the elements in store!', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-friends-of-mineral-town-game-boy-advance', 'Harvest Moon: Friends of Mineral Town', 'Story of Seasons', '2003-11-17', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25u5.jpg', 'Turn a long-neglected field of rocks and weeds into a successful farm in this rustic role-playing game.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-more-friends-of-mineral-town-game-boy-advance', 'Harvest Moon: More Friends of Mineral Town', 'Story of Seasons', '2005-07-26', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25u5.jpg', 'Turn a long-neglected field of rocks and weeds into a successful farm in this rustic role-playing game.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-jr-game-boy-advance', 'Super Monkey Ball Jr.', 'Super Monkey Ball', '2002-11-19', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3s81.jpg', 'The goal of the game is to maneuver a monkey trapped in a ball by tilting the labyrinth and reaching the goal at the end of the maze.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-phantasia-game-boy-advance', 'Tales of Phantasia', 'Tales', '2006-03-06', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25yi.jpg', 'Tales of Phantasia is the first installment of the Tales series, and was released by Namco in 1995 for the Super Famicom. Released at the end of 1995, Tales of Phantasia is considered one of the crowning achievements for its time. It has graphics that push the console to its limits, an original never-before-seen battle system, and the addition of actual voices and voice actors. It is also the first and only Super Famicom game to feature an entirely original, vocalized theme song featured directly in the game.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-game-boy-advance', 'Tom Clancy''s Splinter Cell', 'Tom Clancy''s Splinter Cell', '2003-04-27', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r1.jpg', '2D versions of the game were released for the Game Boy Advance and N-Gage (the latter as Tom Clancy''s Splinter Cell: Team Stealth Action), as well as the mobile phones version developed by Gameloft. A remastered high definition version of Tom Clancy''s Splinter Cell was released on the PlayStation 3 in September 2011. The success of the game series spawned a series of novels written under the pseudonym David Michaels.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-pandora-tomorrow-game-boy-advance', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow', 'Tom Clancy''s Splinter Cell', '2004-03-24', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tce.jpg', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow is a stealth video game developed and published by Ubisoft Shanghai and Ubisoft Milan, while Ubisoft Montreal, developer of the original Splinter Cell, was working on Chaos Theory. Pandora Tomorrow is the second game in the Splinter Cell series endorsed by writer Tom Clancy. The game follows the covert activities of Sam Fisher, an agent working for a black-ops branch of the National Security Agency (NSA) called "Third Echelon". Sam Fisher is voiced by Michael Ironside. Dennis Haysbert voices the character Irving Lambert, Fisher''s boss, making this the only time he is not voiced by Don Jordan. Lalo Schifrin provides the theme music for the game. A remastered high-definition version of Tom Clancy''s Splinter Cell: Pandora Tomorrow was announced for the PlayStation Network for the PlayStation 3 on December 20, 2010.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-the-prophecy-game-boy-advance', 'Tomb Raider: The Prophecy', 'Tomb Raider', '2002-11-12', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3iad.jpg', 'Tomb Raider: The Prophecy is the first game for the Gameboy Advance. Lara is now in a quasi-3D overhead environment, as opposed to the 2D-platformer view of the previous handheld versions. This view proves helpful while Lara runs, jumps, shimmys, and shoots around. Although there is lack of a save feature, there is a password system which lets you restore back to ''almost'' where you left.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-game-boy-advance', 'Tomb Raider: Legend', 'Tomb Raider', '2006-11-14', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-evolution-game-boy-advance', 'Turok: Evolution', 'Turok', '2002-09-01', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p3p.jpg', 'Get locked and loaded in an exciting prequel to the Turok series. Turok: Evolution is an epic adventure set against the backdrop of living jungles, mysterious temples, and deadly dinosaurs. Battle over 32 types of dinosaurs as Tal''Set, a warrior caught in the midst of a brutal war in the Lost Land. Use your arsenal of all-new weapons including Variable Payload Cruise Missiles, Gravity Disruptor beams, and the Swarm Bore. Soar through the skies on a winged Quetzalcoatlus, or set out on foot on of the lush interactive environments. Experience an adventure before time.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-4-game-boy-advance', 'Wario Land 4', 'Wario', '2001-11-18', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wpx.jpg', 'Wario''s back for more...and more...and MORE!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-inc-mega-microgames-game-boy-advance', 'WarioWare, Inc.: Mega Microgames!', 'WarioWare', '2003-05-26', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9paw.jpg', 'WarioWare, Inc.: Mega Microgame$! is a series of promotional Adobe Flash games created to promote the homonymous game for the Game Boy Advance. They are interactive banner advertisements that were playable on websites. Each version contained three ports of microgames present on the GBA, and three variants are known to exist.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-twisted-game-boy-advance', 'WarioWare: Twisted!', 'WarioWare', '2005-05-23', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wqe.jpg', 'After accidentally discovering spin technology, Wario reassembles the developers at WarioWare, Inc. to make a new set of wild minigames. WarioWare: Twisted! maintains the fast-paced style of gameplay from the original WarioWare and introduces a new gyro sensor that lets you control the gameplay by rotating the Game Boy Advance SP left and right. The new controls play into more than 200 minigames. Play through them all to unlock souvenirs, such as bonus games, figurines, and instruments.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-3d-game-boy-advance', 'Wolfenstein 3D', 'Wolfenstein', '2002-04-01', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9rdz.jpg', 'The SNES version of Wolfenstein 3D has modified episodes and storyline, along with heavy censorship. The changes make this version a different game from the original DOS game, and was used as the basis for the Atari Jaguar, Macintosh, 3DO and Apple IIgs ports.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-island-super-mario-advance-3-game-boy-advance', 'Yoshi''s Island: Super Mario Advance 3', 'Yoshi', '2002-09-24', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ac4.jpg', 'Super Mario Advance 3 is a GBA remake for the SNES with the dinosaur Yoshi and his friends as main characters carrying Baby Mario and Luigi on their back.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-topsy-turvy-game-boy-advance', 'Yoshi Topsy-Turvy', 'Yoshi', '2005-06-13', 'Game Boy Advance', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47kd.jpg', 'In Yoshi Topsy-Turvy, Yoshi Island has been turned into a picture book. Yoshi will not stand for this outlandish attempt at flattening his world, and he heads off on an adventure to return things back to their original state. To help in on his quest, a group of spirits who like to surprise people give Yoshi the ability to rotate the world to his liking. The big catch with Yoshi Topsy-Turvy is its use of a motion sensor, similar to the one set to be featured in the second Wario Ware GBA game. The game cartridge includes a built in motion sensor which detects how you move the GBA system. By turning the system, you make the world rotate. A meter on the upper right corner of the screen shows which way the system is being held at any time. Rotate the system to help Yoshi stay on the path and make it past perils and through the varied stages.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-the-fist-of-mars-game-boy-advance', 'Zone of the Enders: The Fist of Mars', 'Zone of the Enders', '2002-02-12', 'Game Boy Advance', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ry2.jpg', 'Based on the popular PlayStation2 title, Zone of the Enders: The Fist of Mars is a 2-D, turn-based strategy game in which players take control of an army of trucks, tanks, fighters, and giant anime-styled robots, called LEVs, to fight for liberation as part of the Mars underground resistance. Players must carefully select their actions, move around large battlefields, and think tactically when engaging enemy units. Battle experience will make you more powerful, and you will be able to optimize and upgrade your units.', 'NA', 19);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battalion-wars-gamecube', 'Battalion Wars', 'Advance Wars', '2005-09-19', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p3y.jpg', 'A global conflict has reached a stalemate in the console version of the Game Boy Advance series Advance Wars. The evil Kaiser Vlad, seeking to take advantage of the standoff, has assembled an army of shock troops, forcing The Western Frontier and the Tundran Territories to ally and fight back. Battalion Wars is a real-time strategy game that lets you control teams of soldiers and vehicles and lead them through more than 20 missions, using a variety of weapons and tactics.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-gamecube', 'Animal Crossing', 'Animal Crossing', '2002-09-16', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wmn.jpg', 'Occasionally strange but completely addictive, Nintendo''s Animal Crossing for the GameCube is not so much a game as a simulation of life on a small town. Players begin the game by setting out to live life on their own in a colorful town, where they are greeted by a seemingly endless supply of things to do and characters to meet.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-gamecube', 'Beyond Good & Evil', 'Beyond Good & Evil', '2003-12-11', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n6b.jpg', 'Beyond Good & Evil is an action-adventure game with elements of puzzle-solving and stealth-based games. The player controls the protagonist, Jade, from a third-person perspective. Jade can run, move stealthily, jump over obstacles and pits, climb ladders, push or bash doors and objects, and flatten herself against walls. As Jade, the player investigates a number of installations in search of the truth about a war with an alien threat.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('billy-hatcher-and-the-giant-egg-gamecube', 'Billy Hatcher and the Giant Egg', NULL, '2003-09-23', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26dv.jpg', 'Darkness has fallen upon a once-magical land. An evil King who seeks to rule with an everlasting night has captured the creatures that inhabit this realm. Now, a young boy must use the powers of a legendary suit to control special eggs in order to restore light to the land.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-generation-gamecube', 'Bomberman Generation', 'Bomberman', '2002-06-03', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w96.jpg', 'Bomberman returns with a new cel-shaded 3D look. The same storyline applies, however. Bomberman has been given the task of taking back a powerful element of magic, and protecting it from the hands of evil. To do so, he must use his bombing abilites to blast his way through mazes filled with crazy enemies and hidden secrets. There are 5 worlds in all, each with 16 levels to complete. And after completing cetain objectives and picking up items, Bomberman will learn new techniques and abilities to improve his range with his bombs or use new weapons.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-jetters-gamecube', 'Bomberman Jetters', 'Bomberman', '2004-03-10', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gh1.jpg', 'Bomberman Jetters is a 2002 Japanese anime television series created by Studio Deen and NAS. It has also spawned two manga series and three video games, one of which was localized and given an English dub. It is based on the popular Bomberman video game series created by Hudson Soft.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chibi-robo-gamecube', 'Chibi-Robo!', 'Chibi-Robo!', '2006-02-08', 'Nintendo GameCube', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2iu2.jpg', 'Like most families, the Sandersons bicker about money and cleaning. Unlike most families, though, they also have robotic spiders, aliens, and talking toys to worry about. Enter Chibi-Robo, a tiny robot programmed to spread happiness. Join him on his quest to restore order to the Sanderson house and SAVE THE WORLD!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-the-wrath-of-cortex-gamecube', 'Crash Bandicoot: The Wrath of Cortex', 'Crash Bandicoot', '2002-09-17', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55ex.jpg', 'Crash Bandicoot: The Wrath of Cortex is the fourth mainline series game and the first to feature Crash Bandicoot on the PlayStation 2. It was later ported to the GameCube and Xbox, making it his first multiplatform appearance. The player controls Crash and his younger sister Coco who must gather 25 crystals and defeat the main antagonists of the story, Doctor Neo Cortex and his new super weapon Crunch Bandicoot. Much of the game takes place in a Virtual Reality Hub System created by Coco to help Crash gather the crystals. The gameplay is similar to the older games of the series.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-nitro-kart-gamecube', 'Crash Nitro Kart', 'Crash Bandicoot', '2003-11-11', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pya.jpg', 'Crash Bandicoot returns to the karting scene with a host of other characters from the adventure series, and this time they have both Neo Cortex and Emperor Velo to worry about. Velo has taken the crew to a remote planet, forced to race for their lives against Neo Cortex and his many evil doers.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-tag-team-racing-gamecube', 'Crash Tag Team Racing', 'Crash Bandicoot', '2005-10-19', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ocb.jpg', 'After being humiliated yet again by Crash Bandicoot at the end of Crash Twinsanity, Cortex returns to his evil scheming in his dilapidated Iceberg Lair. He stumbles across a newspaper article regarding the closure of Ebeneezer Von Clutch''s condemned racing arena. He hatches a sinister plan to challenge Crash to a seemingly friendly race competition... with plans of crushing the hapless bandicoot under the ruins of the hazardous racetrack! Will the evil doctor''s plans be the end of our furry hero?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dance-dance-revolution-mario-mix-gamecube', 'Dance Dance Revolution Mario Mix', NULL, '2005-10-24', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co214p.jpg', 'Boogie down with Mario in his own dance party. Players shake their things to more than 25 dance-flavored songs, from classic Nintendo themes to familiar favorites. With five difficulty levels, dancers of all abilities will be able to get into the groove. The special "Workout" feature tracks the calories burned while playing. Someone has stolen the Music Keys and released the music they held. Without the Music Keys, the unstable power of the music is wreaking havoc on the land. Mario must recover them before the chaos destroys the entire Mushroom Kingdom! The path to the keys is simple: Left, Right, Up, Down, Right, Down ...Characters include Mario, Luigi, Toad, Waluigi, Wario, Bowser. Players clear levels by performing the correct steps. Once they clear all the levels in a particular world, they''ll collect a Music Key. Collect all the Music Keys to win. Players control Dance Dance Revolution: Mario Mix by stepping on different arrows on the Action Pad (included with game). Players can finally experience the thrill of stomping Goombas and other enemies firsthand. As players clear songs, they will unlock more songs, minigames and difficulty levels.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-vengeance-gamecube', 'Batman: Vengeance', 'DC', '2001-11-18', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ot2.jpg', 'Batman: Vengeance is a 2001 video game that was released on all major platforms of the sixth generation of console games. It was developed and published by Ubisoft in conjunction with Warner Bros. Interactive Entertainment and DC Comics. It is based on the television series The New Batman Adventures (the successor to Batman: The Animated Series).', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-dark-tomorrow-gamecube', 'Batman: Dark Tomorrow', 'DC', '2003-03-25', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dys.jpg', 'Batman: Dark Tomorrow is an action-adventure video game developed by HotGen and published by Kemco for the Nintendo GameCube and Microsoft Xbox consoles. The Xbox version is not compatible with the Xbox 360. It is based on the DC Comics'' character Batman and his iteration from the DC Universe source material, unlike most other Batman games which are adaptations of the character in film or television appearances.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-shadow-of-apokolips-gamecube', 'Superman: Shadow of Apokolips', 'DC', '2003-03-25', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dze.jpg', 'Based on the Superman Animated Series, you play as Superman saving citizens in Metropolis and battling villains like Lex Luthor, Metallo, Livewire, Parasite and Darseid. It uses cel-shaded graphics and voice-actors from the tv series.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('aquaman-battle-for-atlantis-gamecube', 'Aquaman: Battle for Atlantis', 'DC', '2003-07-23', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sn0.jpg', 'Aquaman: Battle for Atlantis is an action-adventure video game for the Xbox and GameCube systems. Developed by Lucky Chicken Games and published by TDK, it is based on Peter David''s interpretation of the DC Comics character Aquaman.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-rise-of-sin-tzu-gamecube', 'Batman: Rise of Sin Tzu', 'DC', '2003-11-11', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dyt.jpg', 'Batman: Rise of Sin Tzu is a 2003 beat ''em up video game released for the Xbox, PlayStation 2, Game Boy Advance and GameCube consoles. It was developed and published by Ubisoft in conjunction with Warner Bros. Interactive Entertainment and DC Comics. It is based on the television series The New Batman Adventures and is a sequel to the game Batman: Vengeance', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('catwoman-gamecube', 'Catwoman', 'DC', '2004-07-20', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3t.jpg', 'Catwoman is an action-adventure video game based on the 2004 film of the same name based on the fictional character. It features the likeness of the film''s lead actress Halle Berry, while the character''s voice is provided by actress Jennifer Hale.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-begins-gamecube', 'Batman Begins', 'DC', '2005-06-14', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n98.jpg', 'Step into the shadows of Gotham City’s perilous criminal underworld as DC Comics’ legendary Dark Knight in the Batman BeginsTM video game. Slated for release day and date with the Warner Bros. Pictures film, Batman Begins challenges players to use fear as their ultimate weapon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teen-titans-gamecube', 'Teen Titans', 'DC', '2006-05-24', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzg.jpg', 'Teen Titans is an action beat ''em up video game released for the GameCube, PlayStation 2, and Xbox. A game under the same name was released for the Game Boy Advance in 2005. The game is themed after the 2003 Cartoon Network TV series Teen Titans, and most of the original voice actors reprise their respective roles.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-konga-gamecube', 'Donkey Konga', 'Donkey Kong', '2004-09-27', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2f7u.jpg', 'Donkey Konga 3: Tabe-houdai! Haru Mogitate 50 Kyoku is a music video game in the Donkey Kong series developed by Namco and published by Nintendo. Before the second installment was released in North America, Nintendo and Namco had already started plans for the third game in the series, which, unlike the first two Donkey Konga games, was eventually released only in Japan in early 2005.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jungle-beat-gamecube', 'Donkey Kong Jungle Beat', 'Donkey Kong', '2005-03-14', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co289j.jpg', 'Donkey Kong Jungle Beat is a Nintendo GameCube video game featuring the ape Donkey Kong and played with the DK Bongos. It was released in Japan on December 16, 2004, in Europe on February 4, 2005, in North America on March 14, 2005, and in Australia on March 17, 2005. In 2008 and 2009, the game was re-released in the New Play Control! series of revamped Nintendo GameCube titles. This is the first game to be rated E10 by the ESRB.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-konga-2-gamecube', 'Donkey Konga 2', 'Donkey Kong', '2005-05-09', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6rha.jpg', 'A rhythm and beat game like the popular Dance Dance Revolution game series, but instead of matching the beats with your feet you use your hands to play the bongos. Starring the characters from the Donkey Kong series of games. There are more than 30 tunes to drum beats to, from every genre of music - pop favorites to classical remixes. The more on-time your beats are with the music the higher score you get to earn more coins to unlock different beat sounds.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-3d-return-to-the-lair-gamecube', 'Dragon''s Lair 3D: Return to the Lair', 'Dragon''s Lair', '2002-12-22', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22p7.jpg', 'Dragon''s Lair 3D: Return to the Lair is an action-adventure video game released in 2002 by Dragonstone Software. The game is based on Cinematronics'' 1983 laserdisc arcade game Dragon''s Lair, and follows a similar story; the hero, Dirk the Daring, must enter the evil wizard Mordroc''s castle to rescue Princess Daphne from Singe the dragon. Many of the characters and locations from the 1983 original make appearances in the game, along with new puzzles, rooms and enemies. Animator and director Don Bluth, who produced the cartoon animation for the arcade original, also produced two new animated sequences for the opening and ending of the game. The game uses cel shading to mimic the distinctive style of the original.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eternal-darkness-sanity-s-requiem-gamecube', 'Eternal Darkness: Sanity''s Requiem', NULL, '2002-06-24', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1sa8.jpg', 'Eternal Darkness: Sanity''s Requiem is a psychological horror action adventure, released in 2002 by Nintendo for the Gamecube. It tells the stories of twelve characters that span across the world and two millennia who have to deal with ancient forces of evil which have been trying to manifest themselves in our world. Chapters take place in Ancient Rome, Persia, the Middle East, and modern-day Rhode Island. Throughout the game, the protagonists will have access to several weapons appropriate for their era, from bastard sword & gladius to flintlock pistol and shotgun.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('f-zero-gx-gamecube', 'F-Zero GX', 'F-Zero', '2003-08-25', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525x.jpg', 'F-Zero GX is the fourth installment in the F-Zero series and the successor to F-Zero X. The game continues the series'' difficult, high-speed racing style, retaining the basic gameplay and control system from the Nintendo 64 title. A heavy emphasis is placed on track memorization and reflexes, which aids in completing the title. GX introduces a "Story Mode" element, where the player walks in the footsteps of Captain Falcon through nine chapters, completing various missions.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-crystal-chronicles-gamecube', 'Final Fantasy Crystal Chronicles', 'Final Fantasy', '2004-02-09', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vjk.jpg', 'Join a crystal caravan! A deadly miasma has swallowed the land, and it''s up to you to hold it at bay! Many dangers lie along your journey, but you need not face them alone. Enlist your friends in a crystal caravan and make your mark together in the Crystal Chronicles!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-path-of-radiance-gamecube', 'Fire Emblem: Path of Radiance', 'Fire Emblem', '2005-10-17', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ofh.jpg', 'Fire Emblem: Path of Radiance is a tactical role-playing video game developed by Intelligent Systems and Nintendo SPD, and published by Nintendo for the GameCube home console in 2005. It is the ninth main installment in the Fire Emblem series,[c] and the third to be released in the west. As with previous installments, gameplay revolves around positioning characters on a battlefield to defeat an opposing force. If characters are defeated in battle, they are removed from the rest of the game.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-air-ride-gamecube', 'Kirby Air Ride', 'Kirby', '2003-10-13', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nwh.jpg', 'Kirby Air Ride is a 2003 racing game video game developed by HAL Laboratory and published by Nintendo for the Nintendo GameCube video game console. The game has the players and computer-controlled racers ride on Air Ride Machines. The game supports up to four players, and was the first GameCube title to support LAN play using broadband adapters and up to four GameCube systems. Players take control of Kirby or any of his multicolored counterparts to compete in races or other minigames. The game consists of three different game modes: Air Ride, Top Ride, and City Trial.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-ocarina-of-time-gamecube', 'The Legend of Zelda: Ocarina of Time', 'The Legend of Zelda', '2003-02-16', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vvd.jpg', 'A special bonus disc that contained the both the original Ocarina of Time and the previously unreleased Master Quest. This disc was given out in limited quantities with preorders of The Wind Waker. Additionally, it was sold packaged with The Wind Waker in some regions.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-the-wind-waker-gamecube', 'The Legend of Zelda: The Wind Waker', 'The Legend of Zelda', '2003-03-24', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6txb.jpg', 'A mod which adds the ability to play in multiplayer (up to 4 players) in The Wind Waker.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-collector-s-edition-gamecube', 'The Legend of Zelda Collector''s Edition', 'The Legend of Zelda', '2003-11-17', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n26.jpg', 'Receive Four Complete Classic Zelda games all on one disc when you buy the Zelda GameCube Bundle: The Legend of Zelda, Zelda II - The adventure of Link, The Legend of Zelda: Ocarina of Time, The Legend of Zelda: Majora''s Mask. The disc also includes: Playable Demo of the Legend of Zelda: The Wind Waker, Zelda Retrospective Movie, The Legend of Zelda: The Wind Waker Movie Preview.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-four-swords-adventures-gamecube', 'The Legend of Zelda: Four Swords Adventures', 'The Legend of Zelda', '2004-06-07', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xf.jpg', 'The Legend of Zelda: Four Swords Adventures is the only console Zelda title to date to incorporate multiplayer elements into its main campaign. Because of its single-player elements, Four Swords Adventures is also the first game in the series to allow a single player to control more than one Link at once, and it utilizes various methods to allow the player to make use of the four Links, such as formations. Also it is the only title to break locations and temples up into succinct, separate stages and levels which can be replayed even after beating them once. The game itself, though an innovation in Zelda gameplay, is heavily inspired by the music, graphics, and locations of A Link to the Past.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-twilight-princess-gamecube', 'The Legend of Zelda: Twilight Princess', 'The Legend of Zelda', '2006-12-11', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mtv.jpg', 'The Legend of Zelda: Twilight Princess is the last Zelda game for GameCube, it was highly anticipated by many members of the gaming community and was regarded as finally fulfilling the dreams of those who wanted a much more realistic and mature game than the ones before. The art is similar to the naturalistic style of Ocarina of Time, rather than the cel-shaded look of The Wind Waker. The main adventure takes place in several provinces with dungeons and temples. New to this game is the ability for Link to transform into a Wolf when entering the Twilight. As a wolf, Link can use his senses to solve puzzles and get past obstacles, he can also dig holes to find hearts and rupees. Twilight Princess has received universal acclaim from reviewers and journalists, who cited it as the greatest Zelda game of all time.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drome-racers-gamecube', 'Drome Racers', 'Lego', '2003-09-16', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yv6.jpg', 'Tensions are high as you await the first stage of the Drome Championship.You''ve trained for the intensity of Multi-Challenge Racing; each race a seamless set of stages, mixing tracks from realistically stunning City, Mountain, and Canyon environments.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-gamecube', 'Bionicle', 'Lego', '2003-10-20', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gaw.jpg', 'The PS2/Gamecube Port of "Bionicle Heroes".
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-video-game-gamecube', 'Lego Star Wars: The Video Game', 'Lego', '2005-10-25', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4930.jpg', 'LEGO Star Wars blends the unique world of LEGO with the adventure of Star Wars, for unforgettable action and fun. Live the most popular moments from The Phantom Menace, Attack of the Clones and Revenge of the Sith. Episodes I to III come to life -- and you can become a part of the story! Will you succumb to the dark side of the force or will you become a strong Jedi knight? Find your destiny.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-gamecube', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzo.jpg', 'LEGO Star Wars II: The Original Trilogy takes the fun and endless customization of LEGO and combines it with the epic story, characters and action from the original Star Wars movies that revolutionized pop culture forever (Episode IV A New Hope, Episode V The Empire Strikes Back and Episode VI Return of the Jedi). With a unique tongue-in-cheek take on the Original Trilogy, LEGO Star Wars II follows the Rebel Alliances crusade to dismantle the Galactic Empire and rebuild a galaxy in pieces', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('luigi-s-mansion-gamecube', 'Luigi''s Mansion', 'Luigi''s Mansion', '2001-11-18', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wr1.jpg', 'Luigi steps out from the shadow of his brother Mario and into the gloomy shadows of a very haunted house in this, his first-ever starring role. When Luigi learns that he''s the proud new owner of a creepy old mansion, he''s thrilled. Of course, his feelings immediately shift when his brother, the storied Mario, disappears from the house. Now, you''ll have to help Luigi track his brother down, making your way through expansive 3D levels. Each stage is packed with ghosts and ghouls to put you on edge; and you''ll be armed with a flashlight and a vacuum cleaner to help you capture your foes. Armed with a flashlight and a customized vacuum cleaner, Luigi must rid the mansion of Boos and ghouls -- and find his missing brother to boot!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-sunshine-gamecube', 'Super Mario Sunshine', 'Mario', '2002-08-26', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8q1.jpg', 'Super Mario Sunshine is a Mario action-adventure 3D platformer. It follows Super Mario 64, and is the second 3D Mario platformer. Gameplay features a combination of action and puzzle solving, with numerous stages and multiple episodes to each stage, and plenty of hidden secrets and surprises. This game introduced many recurring characters and bosses in the Mario series, including Toadsworth, Bowser Jr., Petey Piranha, Gooper Blooper, Piantas, Nokis, Shadow Mario, and F.L.U.D.D. Super Mario Sunshine pays homage to Mario''s Italian heritage and upbringing, with many of the locations in the game having Italian names and sometimes referencing Italian culture.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-superstar-baseball-gamecube', 'Mario Superstar Baseball', 'Mario Baseball', '2005-08-29', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tml.jpg', 'The superstars of the Mushroom Kingdom have gathered on the diamond to power up America''s game! Pick a captain, fill your team with your favorite characters from the Mario universe, then hit the field. Each captain has a special Star Skill for pitching and batting, so whether you''re hurling fireballs as Mario or blasting curving banana-ball dingers as DK, you''ve never played ball like this!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-toadstool-tour-gamecube', 'Mario Golf: Toadstool Tour', 'Mario Golf', '2003-07-29', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ec2.jpg', 'Hit the links in the Mushroom Kingdom!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-double-dash-gamecube', 'Mario Kart: Double Dash', 'Mario Kart', '2003-11-17', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ndu.jpg', 'The Mushroom Kingdom just got a whole lot more hectic as Mario and friends double up for furious kart racing. This time around, each kart holds two racers that can switch places at any time, so choose from a huge cast of favorites and pair them up any way you see fit. The character in front handles the driving duties, while the character in the rear doles out damage with six normal items and eight special items that only specific characters can use. Get ready for some intense multiplayer mayhem with your favorite characters, including Mario, Luigi, Donkey Kong, Peach, Bowser, and Koopa.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-4-gamecube', 'Mario Party 4', 'Mario Party', '2002-10-21', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2jxh.jpg', 'Toad, Koopa, and other party-planning pranksters have hidden birthday presents for their closest friends inside the Party Cube. To win the presents, Mario, Yoshi, Peach, and other Mushroom Kingdom favorites will have to plunge into a circus of minigame trickery. As always, keep an eye out for Bowser and his trouble-making goons. Even Whomp and Thwomp have rockin'' surprises for you in their Extra Room. Packed with surprises, wild multiplayer action, and zany challenges, Mario Party 4 is your ticket to a good time.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-5-gamecube', 'Mario Party 5', 'Mario Party', '2003-11-10', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2jxf.jpg', 'Help Mario and his friends restore peace to Dream World while racing around all-new game boards and finding new surprises.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-6-gamecube', 'Mario Party 6', 'Mario Party', '2004-12-06', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co214o.jpg', 'Mario Party 6 offers a new batch of games that require both your fingers and your voice. In this installment in the Mario Party series, you can use the included microphone controller to talk your way to victory. More than 80 minigames are included. You can play as Mario, Bowser, or other characters from the Mushroom Kingdom. New characters appear on the board depending on what time of day it is. The game supports up to four players.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-7-gamecube', 'Mario Party 7', 'Mario Party', '2005-11-07', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21z3.jpg', 'You can play more than 80 new minigames in the most recent Mario-themed party game, Mario Party 7. Mario and pals needed some time off, but they forgot to invite Bowser on their cruise. You can battle against an angry Bowser or up to seven of your friends on a single GameCube system. Mario Party 7 includes a few new characters and brings back microphone support from Mario Party 6.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-strikers-gamecube', 'Super Mario Strikers', 'Mario Strikers', '2005-12-05', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xd3.jpg', 'Super Mario Strikers is the first game in the Mario Strikers series, it features a version of soccer without referees and rules and has power-ups and special strikes which count as two goals. In comparison to actual soccer, the game features a smaller version of the soccer field and each team has only five members instead of the usual eleven-a-side rule. The match time can be manually set from 2 to 15 minutes but is defined as 5 minutes by default. If time runs out when scores are level, a Sudden Death follows the regular game time where next goal wins.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-power-tennis-gamecube', 'Mario Power Tennis', 'Mario Tennis', '2004-11-08', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21z0.jpg', 'Mario Power Tennis features variations of tennis matches consisting of characters, courts, and scenarios based on the Mario series. The range of courts includes the standard three types of tennis court, but consists predominantly of those themed upon games in the Mario series, known as "Gimmick" courts. As well as adopting the style aesthetically, these feature thematic elements that influence how the match will be played on that surface, such as the ghosts in the Luigi''s Mansion court, which hinder movement when the character comes into physical contact with them.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-gamecube', 'Spider-Man', 'Marvel', '2002-04-16', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p17.jpg', 'Developed by Treyarch and published by Activision, the game has you playing as Spider-Man in the events of the movie while also adding new enemies like the Shocker and Vulture. The gameplay consists of successive levels where you need to defeat thugs with your fists and web and save someone/something from multiple sources of danger until you reach the boss of the section. You either fight in enclosed environments or swing around New-York City in "aerial" sequences.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-next-dimension-gamecube', 'X-Men: Next Dimension', 'Marvel', '2002-10-15', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzm.jpg', 'X-Men: Next Dimension is a fighting game and the third game in the X-Men: Mutant Academy game series. Next Dimension expands upon the concept of the first two games by adding several new characters, 3-D maps, and a story mode, which allows the player to fight a series of battles in between short movies that move the plot along. The plot of the story mode is loosely based on the comic story "Operation: Zero Tolerance".', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('men-in-black-ii-alien-escape-gamecube', 'Men in Black II: Alien Escape', 'Marvel', '2003-04-08', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ox0.jpg', 'Men in Black 2: Alien Escape is a fast-paced third-person perspective action game liberally infused with the trademark humor of the smash 1997 movie and the upcoming sequel. The game is divided into five distinct episodes, including a Nuclear Station, the Docks and the streets of Manhattan. All episodes include numerous levels and challenges to complete prior to progressing through the game.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x2-wolverine-s-revenge-gamecube', 'X2: Wolverine''s Revenge', 'Marvel', '2003-04-14', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n0v.jpg', 'The action is played from a third-person perspective as players fight a number of armored soldiers, mutant creatures, and archenemies such as Sabretooth, Magneto, Wendigo, Lady Deathstrike, and Juggernaut. While Professor X is able to assist Wolverine with powers of telepathy, the surly comic book hero must ultimately carry out his adventure alone. To that end, players must tap into Wolverine''s unique talents to overcome all manner of obstacles. Wolverine will be able to hunt and track his prey using his heightened sense of smell and ability to detect body heat. As Wolverine makes his way through the military compounds, he will need to avoid defense systems and guards, and find ways into locked rooms to discover the information he needs to survive.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hulk-gamecube', 'Hulk', 'Marvel', '2003-05-28', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ovx.jpg', 'Based after the events of the blockbuster movie (starring Eric Bana), you play Dr. Bruce Banner and his alter ego, green giant The Hulk. After fighting his way through the first year of his new identity, Bruce and The Hulk must now face a new enemy, The Leader, who wants to use the same gamma technology that created The Hulk in Bruce to develop an army of giants.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-gamecube', 'Spider-Man 2', 'Marvel', '2004-06-28', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-gamecube', 'X-Men Legends', 'Marvel', '2004-09-21', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pez.jpg', 'X-Men enter the realm of role-playing games with an intense story, superhero action, and multiplayer modes. The story in X-Men Legends begins when the X-Men learn that Magneto has devised a plan to give mutants the power to reign supreme over humans. To save the human race from imprisonment, you compose a four-person team from a roster of X-Men characters, including Storm, Gambit, and Wolverine.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-gamecube', 'Fantastic Four', 'Marvel', '2005-06-27', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ouw.jpg', 'Fantastic Four (2005 video game) is an action-adventure game developed by 7 Studios and published by Activision. It is based on the 2005 film of the same name and features characters and storylines from the movie. Players control the four main characters—Mr. Fantastic, The Invisible Woman, The Human Torch, and The Thing—each possessing unique abilities that correspond to their superhero powers. The game includes single-player and cooperative modes, allowing players to switch between characters to utilise their specific powers to solve puzzles, battle enemies, and navigate through various levels. The gameplay primarily focuses on combat and character-specific abilities to progress through the story-driven missions.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-ultimate-destruction-gamecube', 'The Incredible Hulk: Ultimate Destruction', 'Marvel', '2005-08-23', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzh.jpg', 'The Incredible Hulk: Ultimate Destruction, released in 2005, is an action-adventure video game developed by Radical Entertainment and published by Vivendi Universal Games (VU Games). The game centres around the Marvel Comics superhero, the Hulk, and features an open world with destructible environments. The storyline depicts the Hulk being unconsciously guided by his human alter-ego, Bruce Banner, and his psychotherapist, Leonard Samson. They influence him to construct a device aimed at healing Banner''s psyche and preventing the emergence of a darker personality. In addition to progressing through the main narrative, players can undertake side missions and acquire new abilities for the Hulk.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-nemesis-rise-of-the-imperfects-gamecube', 'Marvel Nemesis: Rise of the Imperfects', 'Marvel', '2005-09-20', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1jr.jpg', 'Marvel Nemesis: Rise of the Imperfects pits fierce Marvel superheroes against each other in a 3D fighting game. You can assume control of heroes such as the Punisher, Spider-Man, and Captain America, and duel with them in interactive and destructible environments. A new team of superheroes called the Imperfects joins the mayhem. You can play in single-player story mode to unlock collectible awards, or you can play against other gamers in multiplayer modes.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-ii-rise-of-apocalypse-gamecube', 'X-Men Legends II: Rise of Apocalypse', 'Marvel', '2005-09-20', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pf0.jpg', 'X-Men Legends II: Rise of Apocalypse is an action role-playing game and a sequel to X-Men Legends. The player controls a party of four characters, though only one at a time can be controlled directly. Besides switching the characters for combat purposes, the player is often obliged to do so, because some of the tasks in the game require the specific abilities of a certain mutant. For example, Iceman can put out the fire, Magneto can generate a metal bridge across a gap, etc. Most of the time, however, is spent in combat, collecting loot and acquiring experience points. Unlike the first game, items dropped by enemies are random. The character will level up, become stronger, and learn new skills. The player can opt to allocate all the experience and skill points manually.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-spider-man-gamecube', 'Ultimate Spider-Man', 'Marvel', '2005-09-22', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rry.jpg', 'Based on the comic book of the same name, Ultimate Spider-Man lets you play as either the hero Spider-Man or his arch-nemesis, Venom. Use the unique combat techniques of either Spider-Man or Venom to battle a host of Spider-Man characters. Artistic contributions by the creators of the series make for an authentic Spider-Man experience.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-gamecube', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-anniversary-collection-gamecube', 'Mega Man Anniversary Collection', 'Mega Man', '2004-06-23', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2050.jpg', 'For 15 years, Mega Man games have appeared on consoles, and now you can play ten of them on one disc. Mega Man Anniversary Collection includes the first eight Mega Man games plus two that were never-before-released in the U.S. See how Mega Man has crossed into other media by watching unlockable bonus features, including footage from the original Mega Man TV Series, over 30 original artwork selections, and remixed music tracks inspired by the series.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-network-transmission-gamecube', 'Mega Man Network Transmission', 'Mega Man Battle Network', '2003-06-17', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co203m.jpg', 'Mega Man Network Transmission, known in Japan as Rockman EXE Transmission (ロックマン エグゼ トランスミッション), is a video game developed by Arika and published by Capcom and ShoPro Entertainment for the Nintendo GameCube console. The game was first released in Japan on 6 March 2003, and in North America and PAL regions the following June. Network Transmission is part of the Mega Man Battle Network series, which originated on the Game Boy Advance (GBA) handheld.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-command-mission-gamecube', 'Mega Man X: Command Mission', 'Mega Man X', '2004-09-21', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coblt2.jpg', 'Mega Man X: Command Mission, known as Rockman X Command Mission in Japan, is a spin-off game in the Mega Man X series. It was released in 2004 on both the PlayStation 2 and the Nintendo GameCube, making it the second-to-last game in the Mega Man X series to be released. Unique to the series, it is an RPG featuring turn-based combat and an extensive story. It plays quite similarly to Capcom''s signature Breath of Fire series in a number of ways, due to the shared development team. Chronologically, it is currently the Mega Man X game set furthest in the future, taking place sometime in the twenty-third century (22XX time period); however, it is also set in an alternate timeline outside of the main storyline of the Mega Man series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-collection-gamecube', 'Mega Man X Collection', 'Mega Man X', '2006-01-10', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2030.jpg', 'Mega Man X Collection contains the first six games in the Mega Man X series. Mega Man X and Mega Man X2 are based on their appearances on the SNES. Mega Man X3, also originally on the SNES, is based on its 32-bit update for the PlayStation, Sega Saturn, and PC. The remaining three games are based on their PlayStation renditions. All the games now use save files, including the first few titles that originally necessitated a password for continuation, though upon loading save data, the player is still greeted with the old, fully-functional password entry screen, complete with the correct password to access the saved game. Mega Man Battle & Chase is a game that is unlocked after completing the first three games. It is a classic series kart-racing game previously unreleased in North America. Mega Man X Collection also contains unlockable artwork and music.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-the-twin-snakes-gamecube', 'Metal Gear Solid: The Twin Snakes', 'Metal Gear', '2004-03-09', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v8c.jpg', 'The Twin Snakes features graphical improvements over the original, new cutscenes written and directed by Ryuhei Kitamura, and gameplay functions originally introduced in Metal Gear Solid 2: Sons of Liberty. The game also includes a revised translation with re-recorded voice acting using all of the original English voice cast. Hideo Kojima and Shigeru Miyamoto oversaw development of the game. It was also intended to allow the player to play Metal Gear Solid as it was meant to be played', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-gamecube', 'Metroid Prime', 'Metroid', '2002-11-17', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbn6.jpg', 'An exploration-driven 3D metroidvania/first-person shooter hybrid and sequel to Metroid Prime (2002) in which Samus lands on Aether, an intricate planet torn into light and dark versions of itself, to help its remaining inhabitants defend against the invaders from its dark incarnation by traversing both the light and dark worlds, acquiring new power-ups and braving oppressive environments.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-2-echoes-gamecube', 'Metroid Prime 2: Echoes', 'Metroid', '2004-11-15', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbn6.jpg', 'An exploration-driven 3D metroidvania/first-person shooter hybrid and sequel to Metroid Prime (2002) in which Samus lands on Aether, an intricate planet torn into light and dark versions of itself, to help its remaining inhabitants defend against the invaders from its dark incarnation by traversing both the light and dark worlds, acquiring new power-ups and braving oppressive environments.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-two-towers-gamecube', 'The Lord of the Rings: The Two Towers', 'Middle-earth', '2002-12-31', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20od.jpg', 'The Lord of the Rings: The Two Towers is an action and adventure game based off of the first two movies of the popular Lord of the Rings series, The Fellowship of the Ring and The Two Towers. Players battle their way through some of the key events of these films as Aragorn, Legolas, and Gimli.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-return-of-the-king-gamecube', 'The Lord of the Rings: The Return of the King', 'Middle-earth', '2003-11-05', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20of.jpg', 'The video game adaption of the acclaimed film of the same name. The Lord of the Rings: The Return of the King is a follow up the well received adaption of the first two films in the trilogy. The game expands on what The Two Towers accomplished, with the action and adventure sequel introducing three separate story lines from the movie: one following Aragorn, Legolas, and Gimli, as The Two Towers did, another following Gandalf, and a third following Frodo and Sam, with Merry, Pippin, and Faramir serving as unlockable characters. Gameplay features were also expanded upon, including multiplayer.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-hobbit-gamecube', 'The Hobbit', 'Middle-earth', '2003-11-11', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3li.jpg', 'Step into the hairy hobbits'' feet of Bilbo Baggins in Vivendi Universal Games'' take on Tolkien''s prequel to the massive Lord of the Rings trilogy.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-third-age-gamecube', 'The Lord of the Rings: The Third Age', 'Middle-earth', '2004-11-02', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20oe.jpg', 'The Lord of the Rings:The Third Age introduces entirely new characters which aren''t mentioned in the books or movies. The game does relate to the movies by including scenes from all three movies, with new background speech by Ian McKellen (Gandalf).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-gamecube', 'Namco Museum', 'Namco Museum', '2002-10-08', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz6.jpg', 'Includes 14 Classic Arcade Hits
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-50th-anniversary-gamecube', 'Namco Museum 50th Anniversary', 'Namco Museum', '2005-08-30', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz6.jpg', 'Includes 14 Classic Arcade Hits
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-2-gamecube', 'Pac-Man World 2', 'Pac-Man', '2002-03-19', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1oy7.jpg', 'Long ago, back in medieval times, an evil spirit known as Spooky had terrorized all of Pac-Land. In response to this, the great Wizard Pac created a potion that turned 5 ordinary fruit into the "Golden Fruit." A young knight called Sir Pac-alot fought and sealed Spooky underneath a large tree using the Golden Fruit, which were attached to the branches of the tree. In the present time late at night, Inky, Pinky, Blinky and Clyde sneak into the village and, in their mischief, pick the Golden Fruit off the tree in the center of town. Unfortunately, this has released Spooky from his prison. Spooky tells the ghosts to take the Golden Fruit and follow him if they wish to rid the land of the Pac-people forever. When Pac-Man awakes, he hears the news from Professor Pac about the Golden Fruit and Spooky, and sets off to defeat the ghosts and Spooky.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-fever-gamecube', 'Pac-Man Fever', 'Pac-Man', '2002-09-03', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz7.jpg', NULL, 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-vs-gamecube', 'Pac-Man Vs.', 'Pac-Man', '2003-12-02', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9z8o.jpg', 'Pac-Man vs & Pac-Man World 2 is a bundle release containing both the video games Pac-Man vs and Pac-Man World 2.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-3-gamecube', 'Pac-Man World 3', 'Pac-Man', '2005-11-15', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2de8.jpg', 'The classic gaming character Pac-Man is back for the third iteration of the Pac-Man World series. The game features the classic Pac-Man powers and adds a few new abilities--such as superstomp and electric shock--to assist the yellow-ball-like hero against his ghost foes.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-rally-gamecube', 'Pac-Man World Rally', 'Pac-Man', '2006-08-22', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz9.jpg', 'Pac-Man World Rally is a kart racing game that features a lineup of characters and courses from Namco''s various games.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-the-thousand-year-door-gamecube', 'Paper Mario: The Thousand-Year Door', 'Paper Mario', '2004-10-11', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25us.jpg', 'What sleeps behind the door?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-gamecube', 'Pikmin', 'Pikmin', '2001-12-03', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co98j3.jpg', 'Play through a full recreation of the original Pikmin game in the engine of it''s sequel, along with a whole randomizer, a whole second story featuring Louie, and much more! Fully playable alone or with a friend!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-2-gamecube', 'Pikmin 2', 'Pikmin', '2004-08-30', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8qg6.jpg', NULL, 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-channel-gamecube', 'Pokémon Channel', 'Pokémon', '2003-12-01', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pok.jpg', 'Pokémon Channel is a 2003 video game in the Pokémon series for the GameCube, developed by Ambrella and published by Nintendo and The Pokémon Company. The player''s goal is to help Professor Oak refine and promote his TV network through watching broadcasts with a Pikachu. The game contains elements of the adventure, digital pet, and simulation genres. The player can explore full 3D environments, have Pikachu converse with other Pokémon, and collect various items.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-colosseum-gamecube', 'Pokémon Colosseum', 'Pokémon', '2004-03-22', 'Nintendo GameCube', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tpe.jpg', 'Pokemon fans can now battle their favorite Pokemon on the grand stage. Starring a brand new leading character, Pokemon, Colosseum offers a story mode that pits you against tough trainers who routinely catch damaged Pokemon. In Battle mode, you can use the Game Boy Advance cable to send your team from your Pokemon Ruby or Pokemon Sapphire Game Pak to your Gamecube, then witness the true potential of your team. Rescue Pokemon and watch them come to life in spectacular Colosseum battles.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-colosseum-bonus-disc-gamecube', 'Pokémon Colosseum Bonus Disc', 'Pokémon', '2004-03-22', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaw8k.jpg', 'This disc contains a preview of Pokémon Colosseum, a sneak peek for movie Jirachi: Wish Maker, as well as a Jirachi Special Gift.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-box-ruby-and-sapphire-gamecube', 'Pokémon Box: Ruby and Sapphire', 'Pokémon', '2004-07-12', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sh1.jpg', 'Pokémon Box: Ruby & Sapphire (Japanese: ポケモンボックス ルビー＆サファイア Pokémon Box Ruby & Sapphire) is a Nintendo GameCube Pokémon utility. Pokémon Box itself is not so much a game as it is a storage system for Trainers'' Pokémon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-xd-gale-of-darkness-gamecube', 'Pokémon XD: Gale of Darkness', 'Pokémon', '2005-10-03', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zk4.jpg', 'Pokemon XD is a sequel to the role-playing game Pokémon Colosseum. You''ll play as Michael, a Pokémon trainer who is trying to thwart the evil Cipher. Cipher plans to control the world by using the powerful, but unpredictable, shadow Pokémon. Now you must fight back by collecting your own shadow Pokémon and beating Cipher''s goons in battle. Pokémon XD also lets you import Pokémon from Game Boy Advance Pokémon games and participate in head-to-head battles with other players.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-sands-of-time-gamecube', 'Prince of Persia: The Sands of Time', 'Prince of Persia', '2003-11-18', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4t8l.jpg', 'Deceived by the treacherous Vizier, I was led to unleash the Sands of Time curse upon the Sultan''s kingdom. With little but an ancient dagger and a devious princess to aid me, I must undo my fatal mistake. Mine is a fight for survival… not glory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-warrior-within-gamecube', 'Prince of Persia: Warrior Within', 'Prince of Persia', '2004-12-02', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9x1a.jpg', 'Prince of Persia: Warrior Within is a video game and sequel to Prince of Persia: The Sands of Time. It picks up where The Sands of Time left off, adding new features, specifically, options in combat. The Prince now has the ability to wield two weapons at a time as well as the ability to steal his enemies'' weapons and throw them. The Prince''s repertoire of combat moves has been expanded into varying strings that allow players to attack enemies with more complexity than was possible in the previous game. Warrior Within has a darker tone than its predecessor adding in the ability for the Prince to dispatch his enemies with various finishing moves. In addition to the rewind, slow-down, and speed-up powers from The Sands of Time, the Prince also has a new sand power: a circular "wave" of sand that knocks down all surrounding enemies as well as damaging them.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-two-thrones-gamecube', 'Prince of Persia: The Two Thrones', 'Prince of Persia', '2005-12-01', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ta0.jpg', 'I returned home expecting peace. Instead, I found my kingdom ravaged by war and my people enslaved. Now I am a fugitive, hunted by hostile armies and plagued by a curse that is gradually possessing my soul. A darker Prince resides in me now. And I must embrace his powers and skill if I want to restore peace to my land, my people, and my soul.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-m-gamecube', 'Rayman M', 'Rayman', '2002-09-24', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctf.jpg', 'Developed by Ubisoft Montpellier and Pastagames, Rayman Mini follows Rayman on a legendary journey as he has been reduced to the size of ant! To undo this spell, Rayman will travel through a macro-photographic world, encountering friendly allies and defeating epic bosses along the way.', NULL, 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-3-hoodlum-havoc-gamecube', 'Rayman 3: Hoodlum Havoc', 'Rayman', '2003-03-04', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jky.jpg', 'Hoodlum Havoc is a 3-D platformer from Ubisoft starring limbless hero Rayman. A hilarious story takes a few twists as Rayman sets out to stop the evil black lum Andre and his army of hoodlums.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-gamecube', 'Resident Evil', 'Resident Evil', '2002-04-30', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vz8.jpg', 'Resident Evil is the 2002 remake of the original 1996 video game of the same name featuring various improvements and gameplay overhaul. The game features all-new graphics and sound, and also incorporates gameplay elements from the earlier installments. While the overall plot remained mostly unchanged, several new areas and rooms were added to the game. This remake also features many additional modes, secrets and various endings over the original.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-zero-gamecube', 'Resident Evil Zero', 'Resident Evil', '2002-11-12', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w3w.jpg', 'Resident Evil Zero is a third-person survival horror video game and a prequel to the first Resident Evil. The gameplay remains largely the same as previous entries in the series but also introduces what it calls a partner zapping system, which allows you to switch between the two characters Rebecca and Billy at any time. This feature must be used at times, as the game requires both characters to work together to solve some puzzles. New to the game are a bunch of terrifying enemies, like the mutant centipede, new areas to explore, and the ability to drop items on the ground instead of having to find an item box.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-gamecube', 'Resident Evil 2', 'Resident Evil', '2003-01-14', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vz0.jpg', 'Resident Evil 2 is a sequel to the first Resident Evil title. Like the previous game in the series, Resident Evil 2 is a 3D action-adventure using three-dimensional polygon characters over two-dimensional pre-rendered backgrounds, with the action viewed through a variety of cinematic fixed camera angles in each room. Players can choose to play as one of two possible characters; each goes through the same initial scenario but with differences in the type of weaponry they find and the people they meet along the way.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-3-nemesis-gamecube', 'Resident Evil 3: Nemesis', 'Resident Evil', '2003-01-15', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vvb.jpg', 'Resident Evil 3: Nemesis is a survival horror video game and the third instalment in the Resident Evil series. Like its two predecessors, it is a third-person action-adventure game with polygonal characters on pre-rendered backgrounds with cinematic camera angles. Although the game uses the same basic engine and gameplay as the previous games, the gameplay is improved by features such as auto-targeting, a 180-degree spin, and a new dodge move that allows Jill to avoid enemy attacks. The PC and Dreamcast versions include all eight of Jill''s possible costumes, as well as the mercenary mini-game Operation Mad Jackal, which allows players to play as one of the three Umbrella soldiers. On the PlayStation version, these special features must be unlocked by beating the game with a high score.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-code-veronica-x-gamecube', 'Resident Evil – Code: Veronica X', 'Resident Evil', '2003-12-03', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vzv.jpg', 'Resident Evil Code: Veronica X is a port of the original game with additional content comprised of improved graphics along with an extra nine minutes of cutscenes. The character Steve had his hairstyle changed to have a noticeable fringe, and no longer proudly shows his forehead. This change was made to all cutscenes that feature him, as well as to the family photograph he carries with him. Apart from these changes, the game is almost the same as the original one.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-gamecube', 'Resident Evil 4', 'Resident Evil', '2005-01-11', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wk8.jpg', 'Resident Evil 4 is the sixth installment in the Resident Evil series and is often noted for its departure from the fixed camera angles of earlier titles. It introduced an over-the-shoulder third-person perspective, faster-paced gunplay, and more dynamic controls. The game features larger, more open environments and a new AI system that enables enemies to coordinate attacks and attempt to corner the player. Enemies exhibit more human-like behavior, such as climbing ladders, opening doors, and using weapons.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-gamecube', 'The Sims', 'The Sims', '2003-03-25', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gpk.jpg', 'Home consoles version of The Sims.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-bustin-out-gamecube', 'The Sims Bustin'' Out', 'The Sims', '2003-12-16', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20ag.jpg', 'The Sims Bustin'' Out is the second title in The Sims console series and the first The Sims title to not be released on PC. It featured the same 3D environment and engine the past game did, however adds several features from The Sims expansion packs: The Sims: Hot Date, The Sims: Superstar, and The Sims: Livin'' Large. Bustin'' Out was released for the Game Boy Advance, GameCube, PlayStation 2, Xbox and N-Gage in the fourth quarter of 2003. As the title suggests, the Sims can get out of the house to visit other locations such as Shiny Things Lab or Casa Caliente. There are two modes. Bust Out Mode which has mission based gameplay and Freeplay Mode which is open-ended gameplay very much like the original The Sims PC game.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-urbz-sims-in-the-city-gamecube', 'The Urbz: Sims in the City', 'The Sims', '2004-11-09', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zo9.jpg', 'The Sims have moved to the City where there''s always action and where reputation means everything. In the Urbz: Sims in the City, you can go to work at such locations as the Sushi Bar, Chop Shop, or Bootleg Fireworks, Inc. Success at work brings promotions, access to new power socials, and gear to influence your new lifestyle. Flaunt your attitude by styling your Urbz, and then cross the velvet ropes of an uptown night club, or explore the subway to earn new skills and items.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-gamecube', 'The Sims 2', 'The Sims', '2005-10-24', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j4e.jpg', 'The console versions of The Sims 2 featured local splitscreen multiplayer, a story mode and an option to control game characters directly, as opposed to queuing options as is traditional Sims gameplay. In this videogame, you cannot have children nor age, but you are only adults (excluding elders), even though you can get married. You must earn aspiration points to unlock rewards by filling up your "goals" which will also be needed to complete story mode. Story mode is a sequence of multiple levels along with developed storylines which each character asks you to fulfill wants that pertain to their story. There is also a sandbox mode where you can live in a preset family or build your own.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-gamecube', 'The Sims 2: Pets', 'The Sims', '2006-10-17', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-adventure-2-battle-gamecube', 'Sonic Adventure 2: Battle', 'Sonic the Hedgehog', '2002-02-11', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p3m.jpg', 'Sonic Adventure 2: Battle is a complete conversion of Sonic Adventure 2 from the Dreamcast with additional features. Exclusive to the Gamecube are improved visuals, new 2 player battle games (including Kart Racing, Hunting and Chao Karate) and the ability to grow your Chao and exchange them to the Game Boy Advance game Sonic Advance for portable training.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mega-collection-gamecube', 'Sonic Mega Collection', 'Sonic the Hedgehog', '2002-11-10', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6h.jpg', 'Sonic Mega Collection is a video game compilation developed by Sonic Team and published by Sega in 2002 for the GameCube. The compilation contains twelve to fourteen games (depending on region) originally released on the Sega Genesis. Ten of the included games are installments of the Sonic the Hedgehog series, while the remaining two to four games are only related to the series through its publisher, Sega.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-adventure-dx-director-s-cut-gamecube', 'Sonic Adventure DX: Director''s Cut', 'Sonic the Hedgehog', '2003-06-17', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te5.jpg', 'An ancient evil lurking within the Master Emerald has been unleashed from its slumber by the devious Dr. Eggman and is on the verge of becoming the ultimate monster using the 7 Chaos Emeralds. Only Sonic and his friends are heroic enough to put a stop to Dr. Eggman and his evil minions.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-heroes-gamecube', 'Sonic Heroes', 'Sonic the Hedgehog', '2004-01-06', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9olx.jpg', 'Sonic Heroes is an adventure and multiplatform video game in the Sonic The Hedgehog series, developed by Sonic Team and published by SEGA for the Nintendo GameCube, Sony PlayStation 2, Microsoft Xbox and Microsoft Windows PCs.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-gems-collection-gamecube', 'Sonic Gems Collection', 'Sonic the Hedgehog', '2005-08-16', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co29p3.jpg', 'Sonic Gems Collection is a 2005 compilation of Sega video games, primarily those in the Sonic the Hedgehog series. The emulated games span multiple genres and consoles—from the Sega Genesis to the Sega Saturn—and retain the features and errors of their initial releases with minimal edits.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-the-hedgehog-gamecube', 'Shadow the Hedgehog', 'Sonic the Hedgehog', '2005-11-15', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1up3.jpg', 'The world is in peril as forces, both good and evil, make a play for the powerful Chaos Emeralds. In Shadow the Hedgehog, you can control Shadow and choose which side to fight for. This 3D platformer lets you use weapons, vehicles, environmental objects, and time and space manipulation to combat your foes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-riders-gamecube', 'Sonic Riders', 'Sonic the Hedgehog', '2006-02-21', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3vnv.jpg', 'Sonic Riders is the fourth racing game in the Sonic the Hedgehog series, preceded by Sonic Drift, Sonic Drift 2 and Sonic R.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-raiders-gamecube', 'Space Raiders', 'Space Invaders', '2004-04-19', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pei.jpg', 'Space Raiders is a third-person shooter taking place after an alien invasion of Earth. The game is a spin-off of Taito''s Space Invaders with similar gameplay but in a 3D destroyed city setting.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-enter-the-dragonfly-gamecube', 'Spyro: Enter the Dragonfly', 'Spyro', '2002-11-19', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3qjh.jpg', 'Spyro: Enter the Dragonfly is the fourth game in the Spyro the Dragon series and the first Spyro game to be on the PlayStation 2 and Nintendo Gamecube. Gameplay is similar to the previous three console games. The only playable character is Spyro, however he can man several vehicles: Hunter''s Manta Ray and the UFO''s make a return appearance from Year of the Dragon, alongside two new vehicles, the tank and the Spitfire attack plane.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-a-hero-s-tail-gamecube', 'Spyro: A Hero''s Tail', 'Spyro', '2004-11-09', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48ew.jpg', 'Spyro: A Hero''s Tail is the fifth console game in the original Spyro series and the ninth game in the series in all. Developed by Eurocom, it was the first game in the series for the Xbox, as well as the second game in the series for the PlayStation 2 and GameCube (with the former console release being the only one of the three to support widescreen). It is also the final installment in the original Spyro continuity for home consoles. This is also the first and only Spyro game to be completely produced in Europe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-a-new-beginning-gamecube', 'The Legend of Spyro: A New Beginning', 'Spyro', '2006-10-10', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yqu.jpg', 'The Legend of Spyro: A New Beginning explores the true origins of Spyro as you embark on a dangerous, combat-driven quest that will bring you face to face with the Dark Master''s ultimate creation, Cynder. Experience the true power of the purple dragon as you unleash devastating fury attacks, upgradeable breaths and ground to aerial melee combos in a frenzied battle with hordes of menacing enemies and bone-chilling bosses. It''s an epic and cinematic gameplay experience.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-adventures-gamecube', 'Star Fox Adventures', 'Star Fox', '2002-09-23', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pek.jpg', 'Star Fox Adventures takes place in a vast 3-D world full of strange scenery, brain-teasing puzzles and intense action. Learn the secrets of a mystical staff to fend off enemies and cast a variety of spells. Plus the intuitive, enemy-locking target system allows you to battle foes without skipping a beat. And you''ll need to build clever strategies to defeat the huge boss enemies.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-assault-gamecube', 'Star Fox: Assault', 'Star Fox', '2005-02-14', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pem.jpg', 'Step into the guise of furry flyboy Fox McCloud as he returns to take on his deadliest enemy; wingmen Slippy Toad, Peppy Hare and Falco Lombardi are covering your back, as you take on hordes of intergalactic hostiles on land and in air.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-rogue-squadron-ii-rogue-leader-gamecube', 'Star Wars Rogue Squadron II: Rogue Leader', 'Star Wars', '2001-11-18', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v76.jpg', 'In Star Wars Rogue Squadron II: Rogue Leader you get the chance to jump into the cockpit of an X-wing and join Luke Skywalker and the Star Wars galaxy''s most daring pilots as they return to face off against the Empire.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-gamecube', 'Star Wars: The Clone Wars', 'Star Wars', '2002-10-28', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1l.jpg', 'The Clone Wars has you deep inside the battles of the Old Republic through 16 missions, piloting a range of vehicles including speeder bikes, Republic Gunships and fighter tanks as well as the weapon of the Jedi, your lightsabre, for close combat. Whereas the Rogue Squadron series concentrated on aerial battles, The Clone Wars contains almost all ground battles. You must fight as Anakin Skywalker, Obi Wan Kenobi, Mace Windu, and others throughout the game to prevent the Confederacy from gaining a deadly weapon. Multiplayer options are also included for up to four players with game types including deathmatch, conquest, and a co-op ground and vehicle survival mode.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-ii-jedi-outcast-gamecube', 'Star Wars Jedi Knight II: Jedi Outcast', 'Star Wars', '2002-11-19', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y67.jpg', 'In the tradition of the highly acclaimed Star Wars: Jedi Knight series, Star Wars: Jedi Knight 2, Jedi Outcast features rebel agent Kyle Katarn in exhilarating first-person action. Several years have passed since Kyle avenged his father''s death and saved the Valley of the Jedi from Jerec and his band of Dark Jedi. Allowing his Force powers to languish for fear of falling to the dark side, Kyle entrusted his lightsaber to Luke Skywalker, vowing never to use it again. But when a new and menacing threat to the galaxy emerges, Kyle knows he must reclaim his past in order to save his future.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-bounty-hunter-gamecube', 'Star Wars: Bounty Hunter', 'Star Wars', '2002-12-07', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56lf.jpg', 'Star Wars: Bounty Hunter (released in Japan as Star Wars: Jango Fett) is a Star Wars video game developed and published by LucasArts for the GameCube and Sony PlayStation 2, released in 2002. In the game, players play as the bounty hunter Jango Fett, featured in the 2002 film Star Wars Episode II: Attack of the Clones, to which this game serves as a prequel. Both Temuera Morrison and Leeanna Walsman reprise their roles from the film as Jango Fett and Zam Wesell, respectively.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-rogue-squadron-iii-rebel-strike-gamecube', 'Star Wars Rogue Squadron III: Rebel Strike', 'Star Wars', '2003-10-15', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w3t.jpg', 'X-wings, B-wings, speeder bikes, AT-STs, tauntauns--you''ll have to master them all to save Luke, Wedge, Han, Chewie, and Leia from Darth Vader and his Imperial forces. All new multiplayer modes include the entire Rogue Leader game in co-op, plus endurance, capture-the-base, and dogfight modes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-a-wonderful-life-gamecube', 'Harvest Moon: A Wonderful Life', 'Story of Seasons', '2004-03-16', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ae6.jpg', 'Harvest Moon: A Wonderful Life will span a lifetime on the farm and follow the drama that goes with it. Not only must you build and successfully run a farm, but you must also build a successful life with family and friends! This new Harvest Moon experience will take the best qualities of the series and add more...more animals, more vegetables and more drama! What sort of life will you live?', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-another-wonderful-life-gamecube', 'Harvest Moon: Another Wonderful Life', 'Story of Seasons', '2005-07-26', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xk8.jpg', 'Another Wonderful Life''s gameplay is very similar to its predecessors, involving growing crops while taking care of the variety of animals inhabiting the farm.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-magical-melody-gamecube', 'Harvest Moon: Magical Melody', 'Story of Seasons', '2006-03-28', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xk5.jpg', 'Flower Bud Village wasn''t a blossom of a burg when you bought a plot of land. Now newcomers depend on the bounty from your land for their livelihoods. It''s up to you to create a farm, raise a family and build a village in the most challenging Harvest ever!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-gamecube', 'Super Monkey Ball', 'Super Monkey Ball', '2001-11-18', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5tes.jpg', 'Super Monkey Ball is a 2001 platform party video game developed by Amusement Vision and published by Sega. The game debuted in Japan at the 2001 Amusement Operators Union trade show as Monkey Ball, an arcade cabinet running on Sega''s NAOMI hardware and controlled with a distinctive banana-shaped analog stick. Due to the failure of Sega''s Dreamcast home console and the company''s subsequent restructuring, an enhanced port dubbed Super Monkey Ball was released as a launch title for the GameCube in late 2001, garnering interest as Sega''s first game published for a Nintendo home console.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-2-gamecube', 'Super Monkey Ball 2', 'Super Monkey Ball', '2002-08-25', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwer.jpg', 'The objective of Super Monkey Ball 2 is to guide a monkey trapped inside a plastic ball through a maze to the goal. There are three variations, story mode, challenge mode, and practice mode. In story mode you have an unlimited number of tries to complete a stage, and after clearing 10 stages a movie clip is shown followed by a new world of 10 stages. In challenge mode, you have a limited number of monkeys and a time limit to complete numerous levels of increasing difficulty. In practice mode, you can play any stage already completed in the other two modes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-adventure-gamecube', 'Super Monkey Ball Adventure', 'Super Monkey Ball', '2006-08-01', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5tgc.jpg', 'Our four heroes from Super Monkey Ball - Aiai, Meemee, Baby and Gongon - were enjoying a typical day, when they saw a flying machine crash down on a nearby island. Soon, they discovered that the mysterious Naysayers have appeared, spreading discord and unhappiness all over the island. And to top it all off, the prince and princess of the neighboring islands have gone missing on Jungle Island - if they aren''t found and returned, there''s sure to be trouble! Can our heroes restore order to Monearth?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-melee-gamecube', 'Super Smash Bros. Melee', 'Super Smash Bros.', '2001-12-03', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kpq.jpg', '"The year is 20XX. Everyone plays Fox at TAS levels of perfection. Because of this, the winner of a match depends solely on port priority. The RPS metagame has evolved to ridiculous levels due to it being the only remaining factor to decide matches."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-symphonia-gamecube', 'Tales of Symphonia', 'Tales', '2004-07-13', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1peo.jpg', 'In a dying world, legend has it that a Chosen One will one day rise from amongst the people and the land will be reborn. The line between good and evil blurs in this epic adventure where the fate of two interlocked worlds hangs in the balance.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-gamecube', 'Tom Clancy''s Splinter Cell', 'Tom Clancy''s Splinter Cell', '2003-04-10', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rj.jpg', 'The GameCube version has an exclusive feature where you can link up to the Game Boy Advance, which allows you display a real-time overhead map on your handheld whilst playing the game on your console', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-pandora-tomorrow-gamecube', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow', 'Tom Clancy''s Splinter Cell', '2004-07-20', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9eos.jpg', 'Pandora Tomorrow takes place in Indonesia during the spring of 2006, in which the United States has established a military presence in the newly independent country of East Timor to train that country''s military forces in their fight against anti-separatist Indonesian guerrilla militias. Foremost among these Indonesian militias is the Darah Dan Doa (Blood and Prayer), led by Suhadi Sadono.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-chaos-theory-gamecube', 'Tom Clancy''s Splinter Cell: Chaos Theory', 'Tom Clancy''s Splinter Cell', '2005-03-31', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coamhg.jpg', 'You are Sam Fisher, the NSA''s most elite black-ops agent. To achieve your mission you will kill from close range, attack with your combat knife, shoot with the prototype Land Warrior rifle, and use radical suppression techniques such as the inverted neck break. Also take on cooperative multiplayer infiltration missions, where teamwork is the ultimate weapon.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-gamecube', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2006-10-26', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-gamecube', 'Tomb Raider: Legend', 'Tomb Raider', '2006-11-14', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gze.jpg', 'This version of Tomb Raider: Legend includes a few omissions, likely due to disc space limitations. The rolling demos that typically play when the game is left idle on the title screen have been removed, and the "Unfortunate Mishaps" video is also absent. Additionally, several visual filters used for explosions and motion blur have been removed, resulting in sharper textures but less visually striking explosions.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-evolution-gamecube', 'Turok: Evolution', 'Turok', '2002-09-01', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p3p.jpg', 'Get locked and loaded in an exciting prequel to the Turok series. Turok: Evolution is an epic adventure set against the backdrop of living jungles, mysterious temples, and deadly dinosaurs. Battle over 32 types of dinosaurs as Tal''Set, a warrior caught in the midst of a brutal war in the Lost Land. Use your arsenal of all-new weapons including Variable Payload Cruise Missiles, Gravity Disruptor beams, and the Swarm Bore. Soar through the skies on a winged Quetzalcoatlus, or set out on foot on of the lush interactive environments. Experience an adventure before time.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viewtiful-joe-gamecube', 'Viewtiful Joe', 'Viewtiful Joe', '2003-10-07', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nqo.jpg', 'Joe is no ordinary man and Viewtiful Joe is no ordinary game. Capcom''s new superhero action game mixes funky cartoon-style visuals with classic side-scrolling gameplay and introduces the world''s quirkiest million dollar action hero. More than just any ordinary dude, Joe must transform into the ultimate superhero. It''s up to you to activate the correct view mode like "slow" or "zoom in" in order to clobber your enemies with beautiful style. You can also speed up or slow down your visual effects for even more "viewtiful" moves. Viewtiful Joe mixes an innovative viewpoint with an amazing stunt-filled action movie universe.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viewtiful-joe-2-gamecube', 'Viewtiful Joe 2', 'Viewtiful Joe', '2004-11-18', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2162.jpg', 'Joe and Silvia are back in this sequel to Viewtiful Joe. This time you have more style, new special moves, and more than 40 new enemies to defeat. Now Joe''s trusty aircraft transforms into various shapes to support his activities throughout the game''s many stages. In addition to Joe, you can play as Silva, Joe''s girlfriend. Call upon the powers of Joe and Silvia, and get ready to both solve new puzzles and save the day.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viewtiful-joe-red-hot-rumble-gamecube', 'Viewtiful Joe: Red Hot Rumble', 'Viewtiful Joe', '2005-11-08', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nyo.jpg', 'Captain Blue is casting for the lead in his new action movie and the competition is RED HOT! Fight head-to-head against your friends - whoever is the most kick-butt lands the starring role!', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-world-gamecube', 'Wario World', 'Wario', '2003-06-23', 'Nintendo GameCube', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c4.jpg', 'While Wario enjoys the riches from his many adventures, a mysterious black jewel in his trove transforms gems into monsters. Now, Wario must scramble to recover his riches in an alternate world filled with quirky puzzles, swarming enemies, and lots of loot. As Wario, you''ll punch, kick, jump, grab monsters and objects, and inhale surrounding coins like a vacuum cleaner. You must cling to 3D balls to fight bosses, find hidden areas through trap doors, and bash your surroundings to uncover secrets.', 'NA', 70);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-inc-mega-party-games-gamecube', 'WarioWare, Inc.: Mega Party Games!', 'WarioWare', '2004-04-05', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b10.jpg', 'Following the almost universally acclaimed short-attention-span action of the Game Boy Advance''s WarioWare, Inc.: Mega Microgame$! comes this party-game adaptation for GameCube. Many of the mini-games featured in the handheld original have been converted for four-player competition on the console. Gamers strive to be the quickest teeth-brushers, the most precise nose pickers, the best free-throwers, the most accurate apple shooters, the most skillful paper-airplane pilots, and the victors in countless other quick contests that take no more than a few seconds to complete.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wave-race-blue-storm-gamecube', 'Wave Race: Blue Storm', 'Wave Race', '2001-11-18', 'Nintendo GameCube', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pet.jpg', 'Racing atop a bed of dynamically changing waves, gamers must navigate their way through eight different environments under random weather conditions, including the powerful and visually impressive Storm setting.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('advance-wars-dual-strike-nintendo-ds', 'Advance Wars: Dual Strike', 'Advance Wars', '2005-08-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9nk.jpg', 'Advance Wars: Dual Strike is the third installment in the Advance Wars series (first on DS media). Advance Wars is the international title of the Wars video game series, which dates back to the Family Computer game Famicom Wars in 1988.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('advance-wars-days-of-ruin-nintendo-ds', 'Advance Wars: Days of Ruin', 'Advance Wars', '2008-01-21', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobblv.jpg', 'Days of Ruin takes place in an entirely new world where a large-scale meteor shower triggered massive global destruction that eradicated 90 percent of the population. After the catastrophe, the survivors have formed together into militaristic bands that are warring over the last remaining scraps of civilization. You''ll take control of Will, a young military cadet (whose hair is admittedly just a little spiky) who quickly becomes embroiled in the conflict at the outset of the game.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-wild-world-nintendo-ds', 'Animal Crossing: Wild World', 'Animal Crossing', '2005-12-05', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wms.jpg', 'Players move into a living, breathing world inside the Nintendo DS...and then invite their friends to visit from anywhere on earth. In Animal Crossing: Wild World, the sequel to the popular Nintendo GameCube game, players and up to three friends can hang out in the same village and interact in real time -- either through wireless LAN or over Nintendo Wi-Fi Connection. Players can visit a friend''s village from thousands of miles away. The touch screen makes item management and world navigation a breeze. Typing letters and designing patterns are now just stylus strokes away. Days and seasons pass in real time, so whether players want to decorate their homes, catch bugs or fish, collect brand-new items like hats and sunglasses or just chat with the wild and wacky characters in their villages, there''s always something to do.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('art-academy-nintendo-ds', 'Art Academy', 'Art Academy', '2010-10-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ac9.jpg', 'Art Academy offers simple, easy to understand art lessons that you can take at your own pace. You even have the ability to fast forward or rewind a step if you would like to view it again. Vince is your in-game art tutor and he will guide you through each new lesson, gradually introducing new concepts to you. Each new lesson builds upon concepts that you learned in previous lessons, complete with step by step examples.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-alta-r-s-chronicles-nintendo-ds', 'Assassin''s Creed: Altaïr''s Chronicles', 'Assassin''s Creed', '2008-02-05', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yvv.jpg', 'As the direct prequel of the critically acclaimed console title Assassin’s Creed, discover more of the story of Altaïr as he must find “the chalice,” an object of such power that whoever is in possession of it can end the Crusades.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-ii-discovery-nintendo-ds', 'Assassin''s Creed II: Discovery', 'Assassin''s Creed', '2009-11-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xic.jpg', 'Discover an untold chapter from the Assassin’s Creed II storyline
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bejeweled-twist-nintendo-ds', 'Bejeweled Twist', 'Bejeweled', '2010-01-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coajv9.jpg', 'Spin, match, explode... WOW! It''s a brilliant new way to play Bejeweled! Get set for a vivid sensory rush as you spin and match explosive gems for shockwaves of fun. Rotate jewels freely to set up electrifying combos, outwit surprising obstacles like Locks and Bombs, and create high-voltage Flame and Lightning gems. When you need to dial up the intensity or fine-tune your skills, turn to Challenge mode or five-minute Blitz. And if relaxing is more your style, kick up your feet with stress-free Zen. No matter the mode, you''ll discover new strategies, improve your moves, and find endless ways to win!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bejeweled-3-nintendo-ds', 'Bejeweled 3', 'Bejeweled', '2011-11-15', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zso.jpg', 'The biggest, brightest Bejeweled ever! Discover all-new ways to play the world''s #1 puzzle game. Find your perfect match with 8 breathtaking game modes that meet all your moods ease into Classic Bejeweled for cascades of fun, journey through 40 challenging Quest puzzles, charge into the electrifying Lightning for non-stop action, and tailor your experience in Zen for a revolutionary new way to relax.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-nintendo-ds', 'Bomberman', 'Bomberman', '2005-06-21', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q1m.jpg', 'Bomberman Jetters is an action RPG that could be considered the spiritual successor to Bomberman Tournament.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-land-touch-nintendo-ds', 'Bomberman Land Touch!', 'Bomberman', '2006-11-08', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ki9.jpg', 'The fun of the Bomberman series returns to the Nintendo DS, this time with not only classic Bomberman gameplay, but a whole new selection of addictive mini games to play alone, or over Nintendo''s Wi-Fi connection! Navigate your way through an amusement park filled with addictive mini games with intuitive stylus control, while working to unlock all the games.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-land-touch-2-nintendo-ds', 'Bomberman Land Touch! 2', 'Bomberman', '2008-01-29', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69oc.jpg', 'BOMBERMAN LAND Touch! 2 is the follow up sequel to IGN''s Best Online Multiplayer 2006 Game of the Year on the Nintendo DS. Embark on a fun-filled, theme park adventure as you discover a huge land to explore, a gigantic multiplayer pack, and a host of addicting mini-games that can be played by yourself or with up to 4 people.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-dawn-of-sorrow-nintendo-ds', 'Castlevania: Dawn of Sorrow', 'Castlevania', '2005-10-04', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9z0.jpg', 'Draw the correct magic seal quickly, or your enemies will never die! Fight and explore through one of the largest castles ever seen in the series! Race another player through custom-made castle rooms in versus mode!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-portrait-of-ruin-nintendo-ds', 'Castlevania: Portrait of Ruin', 'Castlevania', '2006-12-05', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9kf.jpg', 'A port of Castlevania: Portrait of Ruin included in "Castlevania Dominus Collection."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-order-of-ecclesia-nintendo-ds', 'Castlevania: Order of Ecclesia', 'Castlevania', '2008-10-21', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9ko.jpg', 'A port of Castlevania: Order of Ecclesia included in "Castlevania Dominus Collection."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chibi-robo-park-patrol-nintendo-ds', 'Chibi-Robo!: Park Patrol', 'Chibi-Robo!', '2007-10-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yp0.jpg', 'A pollution epidemic is killing off flowers and ravaging parks worldwide. To combat this threat, Citrusoft Robotics has developed an eco-friendly model of Chibi-Robo and sent it to parks everywhere. As Chibi-Robo, players restore their local park to its former glory by raising flowers and plants, building park equipment and defeating toxic enemies called Smoglings.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chrono-trigger-nintendo-ds', 'Chrono Trigger', 'Chrono', '2008-11-25', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87df.jpg', 'As the definitive version of Chrono Trigger, not only have the controls been updated, the graphics and sound have also been revamped to make your adventure even more fun and enjoyable to play. To complete your journey, also included is the mysterious ‘Dimensional Vortex’ dungeon and the forgotten ‘Lost Sanctum’ dungeon. Meet the challenges presented to you and long-lost secrets may be revealed...', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('civilization-revolution-nintendo-ds', 'Civilization Revolution', 'Civilization', '2008-07-08', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95wx.jpg', 'Build. Discover. Conquer. Rule the World!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('clubhouse-games-nintendo-ds', 'Clubhouse Games', 'Clubhouse Games', '2006-10-09', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ac8.jpg', 'It''s game night and everyone''s invited. Play more than 20 classic board, card and party games alone, with friends or via Nintendo Wi-Fi Connection. With familiar favorites like checkers, darts and poker, Clubhouse Games is for everyone and part of the Touch Generations library. Video game newcomers will appreciate the easy-to-use interface. Players can challenge up to seven friends with one game card via Multi-Card Play or DS Download Play. Can''t play checkers without shouting "KING ME!" across the table? The in-game (PictoChat-like) feature takes table talk to a new level. There''s no need to lug around cards or boards when you want to play a quick game. Clubhouse Games is one-stop gaming that will appeal to everyone''s tastes, whether they''re in the mood for bowling, backgammon, bridge or billiards.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-4-nintendo-ds', 'Contra 4', 'Contra', '2007-11-13', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2guv.jpg', 'The action franchise that started it all is celebrating its 20th anniversary with an all-new adventure on Nintendo DS! Set after the events of Contra III: Alien Wars, the game follows mercenaries Bill Rizer and Lance Bean as they battle to save the world from a new extraterrestrial threat. Contra 4 takes advantage of the dual screens of the Nintendo DS to deliver larger than life action, with massive enemies, detailed platforming and mind-blowing set pieces.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-boom-bang-nintendo-ds', 'Crash Boom Bang!', 'Crash Bandicoot', '2006-10-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55s8.jpg', 'Crash Boom Bang! is a party game developed by Dimps and published by Vivendi Universal Games in Japan and by Sierra Entertainment internationally for the Nintendo DS. It was released in Japan on July 20, 2006, in North America on October 10, 2006,[1] in Europe on October 27, 2006, and in Australia on November 2, 2006.[3] It is the only game in the Crash Bandicoot series to be developed by a Japanese company and the first to be released in Japan before North America. It was also the final game in the series to be released in Japan.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-nintendo-ds', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-mind-over-mutant-nintendo-ds', 'Crash: Mind over Mutant', 'Crash Bandicoot', '2008-10-29', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3n2m.jpg', 'Crash: Mind Over Mutant is the sequel to Crash of the Titans and the seventh Crash Bandicoot series game. The game uses many of the same mechanics as its predecessor with a few changes. Rather than having twenty linear platforming levels to complete in sequence, Mind Over Mutant features eight distinct locations for Crash to explore and travel between as the story progresses. The player can complete missions given by non-playable characters and discover collectibles through the levels.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-heroes-nintendo-ds', 'Justice League Heroes', 'DC', '2006-10-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxy.jpg', 'The PlayStation Portable version of Justice League Heroes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-returns-nintendo-ds', 'Superman Returns', 'DC', '2006-11-22', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2des.jpg', 'Inspired by the Warner Bros. Pictures feature film and more than 60 years of DC Comics'' lore. As the Man of Steel, you’ll hone your unworldly super powers such as Flight, X-Ray Vision, Heat Vision, Super Hearing, Super Strength, Super Speed, and Super Breath to fight villains that only Superman can defeat.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-brave-and-the-bold-the-videogame-nintendo-ds', 'Batman: The Brave and the Bold – The Videogame', 'DC', '2010-09-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hfo.jpg', 'The Brave and the Bold the Videogame fully immerses fans into the vivid animated world of the successful TV series where kids can play as Batman or together with family and friends in two-player co-op mode. Players can choose from iconic characters Robin, Green Lantern, Blue Beetle, along with drop-in heroes such as Aquaman to help solve puzzles and fight foes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('green-lantern-rise-of-the-manhunters-nintendo-ds', 'Green Lantern: Rise of the Manhunters', 'DC', '2011-06-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ky.jpg', 'Green Lantern: Rise of the Manhunters is an action video game, the first based on DC Comics'' Green Lantern (Hal Jordan). The game is a tie-in/sequel to the film Green Lantern, which opened in theatres on June 17, 2011. The game features 3D visuals on the PlayStation 3 and Xbox 360, providing TriOviz Inficolor 3D for standard televisions and stereoscopic 3D for dedicated 3DTVs.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diddy-kong-racing-ds-nintendo-ds', 'Diddy Kong Racing DS', 'Donkey Kong', '2007-02-05', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wk1.jpg', 'A bloated space pig has taken control of Diddy Kong''s Island paradise and only you can stop his nefarious plot! Take on the racing challenge of a lifetime as you drive, hover and fly your way across the massive island. This remastered take on a Nintendo 64 classic is sure to rev the engines of adventure racing fans everywhere!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dk-jungle-climber-nintendo-ds', 'DK: Jungle Climber', 'Donkey Kong', '2007-09-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba0o.jpg', 'DK: Jungle Climber is the sequel to DK: King of Swing (2005) for the Game Boy Advance, featuring similar gameplay. However, the visuals have been designed to more closely resemble Donkey Kong Country and add dual screen support.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-heroes-rocket-slime-nintendo-ds', 'Dragon Quest Heroes: Rocket Slime', 'Dragon Quest', '2006-09-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j66.jpg', 'Dragon Quest Heroes: Rocket Slime is based in the fictional world of Slimenia, specifically in the capital city of Boingburg. It begins with four Slimes, Rocket, Hooly, Bo, and Swotsy, who are playing in front of the castle. Hooly has gotten his hands on a valuable flute, and in response to the flute being blown by Rocket, his father comes running over, forcing Hooly to stick the flute in Rocket''s mouth. Afterward, an organization known as the Plob invades Boingburg, capturing 100 of its 101 inhabitants. Because he was distorted and long, the Plob mistakenly believed Rocket was not a Slime but a worm, and discarded him into Forewood Forest. There, Rocket begins his journey to rescue his fellow slimes, who have been locked up in large treasure chests.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-monsters-joker-nintendo-ds', 'Dragon Quest Monsters: Joker', 'Dragon Quest', '2007-11-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gg2.jpg', 'As Monster Scouts, players can recruit wild monsters to build a team and battle against other players in this turn-based role-playing game. Each year, monster scouts from around the world gather to compete for the title of world''s greatest scout. Players crash-land on a mysterious island after their airship is struck by lightning. They must rescue their missing passengers and crew members by fighting various enemies using their own monster parties. The only way off the island is to solve its many mysteries.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-iv-chapters-of-the-chosen-nintendo-ds', 'Dragon Quest IV: Chapters of the Chosen', 'Dragon Quest', '2008-09-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mw7.jpg', 'Embark on a journey to explore the land, seas and skies of the Dragon Quest universe in this grand entry from the Zenithia Trilogy. Soon to follow are Dragon Quest V: Hand of the Heavenly Bride and Dragon Quest VI: Realms of Reverie.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-v-nintendo-ds', 'Dragon Quest V', 'Dragon Quest', '2009-02-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tre.jpg', 'Dragon Quest V uses basic role-playing video game mechanics seen in the rest of the series, which includes leveling up by gaining experience points through battle, first person turn-based battles, and equipping weapons and armor. Something new to the Dragon Quest series is the ability to tame monsters into the player''s party. The monsters can be used in battle and level-up like the human characters. Monsters sometimes request to join the Hero after battles if the party is strong enough. There are a total of 71 monsters that are capable of joining the Hero''s party', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-ix-nintendo-ds', 'Dragon Quest IX', 'Dragon Quest', '2010-07-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7wt9.jpg', 'In Dragon Quest IX: Sentinels of the Starry Skies, players begin their adventure as a city guardian who is sent to retrieve a sacred trees fruits, which have the power to grant wishes. Players travel the world, conquer fearsome monsters and unravel an epic storyline. During their journey, players will encounter mighty opponents in fast-paced battles, and also interact with a colorful cast of characters.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-vi-realms-of-revelation-nintendo-ds', 'Dragon Quest VI: Realms of Revelation', 'Dragon Quest', '2011-02-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakcl.jpg', 'Dragon Quest VI did not receive an enhanced remake on a console until the Nintendo DS. The Dragon Quest VI enhanced remake for the Nintendo DS was announced in late 2007 by Square Enix and was developed by ArtePiazza. A handful of changes were made to the game, some remaining controversial among fans.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-monsters-joker-2-nintendo-ds', 'Dragon Quest Monsters: Joker 2', 'Dragon Quest', '2011-09-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gg2.jpg', 'As Monster Scouts, players can recruit wild monsters to build a team and battle against other players in this turn-based role-playing game. Each year, monster scouts from around the world gather to compete for the title of world''s greatest scout. Players crash-land on a mysterious island after their airship is struck by lightning. They must rescue their missing passengers and crew members by fighting various enemies using their own monster parties. The only way off the island is to solve its many mysteries.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-nintendo-ds', 'Dragon''s Lair', 'Dragon''s Lair', '2010-11-15', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-iii-nintendo-ds', 'Final Fantasy III', 'Final Fantasy', '2006-11-14', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ojk.jpg', 'Two of the most representative titles of the classic role-playing game series, brought together to get lost in their timeless stories of heroes, betrayal, love and redemption... now on PC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-fables-chocobo-tales-nintendo-ds', 'Final Fantasy Fables: Chocobo Tales', 'Final Fantasy', '2007-04-03', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vm2.jpg', 'Final Fantasy Fables: Chocobo Tales starts when the Final Fantasy black magician brings a picture book onto the Chocobo farm. This book is actually home to the great devil Bebuzu, and it sucks the entire farm into its pages! Chocobo heads on an adventure with the white and black magicians in order to stop Bebezu from reviving himself to full form.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xii-revenant-wings-nintendo-ds', 'Final Fantasy XII: Revenant Wings', 'Final Fantasy', '2007-11-20', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49tj.jpg', 'One year after the events of FINAL FANTASY XII, the young protagonist Vaan travels the skies of Ivalice with his trusted navigator Penelo at his side. Their treasure hunting adventures take them to the sky continent of LemurÃs where they meet Llyud, a member of the aegyl race. These mysterious winged people have been living on the floating continent for centuries, but a disturbance has allowed treasure-seeking sky pirates to breach their once-hidden territory. It falls to Vaan and his band of young sky pirates to stand up against the trespassers, and defend this extraordinary world and its people.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-crystal-chronicles-ring-of-fates-nintendo-ds', 'Final Fantasy Crystal Chronicles: Ring of Fates', 'Final Fantasy', '2008-03-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8jn.jpg', 'Final Fantasy: Crystal Chronicles - Ring of Fates is a prequel to Final Fantasy Crystal Chronicles for the Nintendo DS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-tactics-a2-grimoire-of-the-rift-nintendo-ds', 'Final Fantasy Tactics A2: Grimoire of the Rift', 'Final Fantasy', '2008-06-24', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobsxb.jpg', 'School is out for the summer, but mischievous Luso Clemens must first face detention to make up for his misbehavior. Alone in the library, he stumbles upon an ancient book with magical powers that summons him to the mystical land of Ivalice. Warped into the middle of a battlefield, Luso joins Cid and his clan to set off on an adventurous journey looking for a way home.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-iv-nintendo-ds', 'Final Fantasy IV', 'Final Fantasy', '2008-07-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nd8.jpg', 'A port of Final Fantasy IV for WonderSwan Color released only in Japan. It is largely based on the PlayStation port while lacking its FMVs and having a decreased screen resolution, and down-sampled music and sound effects to meet the specifications of the device.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-crystal-chronicles-echoes-of-time-nintendo-ds', 'Final Fantasy Crystal Chronicles: Echoes of Time', 'Final Fantasy', '2009-03-24', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26f0.jpg', 'Final Fantasy Crystal Chronicles: Echoes of Time is an installment in the Final Fantasy Crystal Chronicles series. It is the first Final Fantasy Crystal Chronicles game that allows players to play together online and it allows players who own a Nintendo Wii or Nintendo DS to play together at the same time using the Pollux Engine, an Engine created by Square Enix.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-the-4-heroes-of-light-nintendo-ds', 'Final Fantasy: The 4 Heroes of Light', 'Final Fantasy', '2010-10-05', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vjn.jpg', 'With FINAL FANTASY: The 4 Heroes of Light, the FINAL FANTASY series is rendered anew as an epic storybook adventure by the creators of the FINAL FANTASY III and FINAL FANTASY IV Nintendo DS remakes. Players will enter a beautiful fairy-tale world featuring illustrations and character designs by acclaimed character designer Akihiko Yoshida (FINAL FANTASY III for DS, FINAL FANTASY XII).', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-shadow-dragon-nintendo-ds', 'Fire Emblem: Shadow Dragon', 'Fire Emblem', '2009-02-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z4p.jpg', 'This collector’s edition of the game will include a nostalgic, stylized physical NES box and a replica NES Game Pak art piece with a protective sleeve that transports owners to the era of the original game’s release. The collector’s edition also includes a colorful, 222-page Legacy of Archanea deluxe hardbound art book and a game download code. It will be accompanied by an NES instruction manual, newly localized from the original Famicom release, along with a fold-out world map and a Mini Nintendo Power retro collectible.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-collection-nintendo-ds', 'Game & Watch Collection', 'Game & Watch Collection', '2008-12-15', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25i3.jpg', 'Game & Watch Collection is a compilation cartridge featuring three of Nintendo''s Multi-Screen Game & Watch games. Not available for purchase, this game could only be obtained in Japan, North America and Australia, by buying it with points included with Nintendo games and systems. The included games are: Oil Panic, Donkey Kong and Green House.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-watch-collection-2-nintendo-ds', 'Game & Watch Collection 2', 'Game & Watch Collection', '2010-03-31', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b2g.jpg', 'The Game & Watch Collection returns in this exclusive Club Nintendo game for the Nintendo DS. It includes Parachute and Octopus.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-trick-phantom-detective-nintendo-ds', 'Ghost Trick: Phantom Detective', NULL, '2011-01-11', 'Nintendo DS', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9sm.jpg', '"Ghost Trick: Phantom Detective" was created by Shu Takumi, the creator of the Ace Attorney series, and is now back in a long-requested HD remaster of the original 2010 release!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('giana-sisters-ds-nintendo-ds', 'Giana Sisters DS', 'Giana Sisters', '2011-02-22', 'Nintendo DS', 0, 0, NULL, NULL, 'Giana Sisters DS is a 2007 port of a Commodore 64 classic The Great Giana Sisters to the Nintendo DS. Not to be confused with the officially released 2009 remake of the same name.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-sun-dark-dawn-nintendo-ds', 'Golden Sun: Dark Dawn', 'Golden Sun', '2010-11-29', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25qp.jpg', 'After going dark six years ago, 2010 will see a new dawn. Golden Sun DS updates the popular portable Golden Sun role-playing series with an impressive graphical style. This installment follows the story of the previous heroes'' descendants and immerses players into the magic of its adventure by pushing the boundaries of intuitive touch-screen controls.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-chinatown-wars-nintendo-ds', 'Grand Theft Auto: Chinatown Wars', 'Grand Theft Auto', '2009-03-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lba.jpg', 'Grand Theft Auto: Chinatown Wars is an entirely original entry into the critically acclaimed Grand Theft Auto series, and brings a new level of interactivity to its sprawling open environments. With the use of the DS touch screen, players navigate their way through the streets as they uncover the truth behind an epic tale of crime and corruption within the Triad crime syndicate, delivering the unprecedented amount of depth that has become a true trademark of the franchise.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puzzle-de-harvest-moon-nintendo-ds', 'Puzzle de Harvest Moon', 'Harvest Moon', '2007-11-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkz.jpg', 'A puzzle game based on the Harvest Moon series.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-frantic-farming-nintendo-ds', 'Harvest Moon: Frantic Farming', 'Harvest Moon', '2009-08-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl5.jpg', 'Harvest Moon: Frantic Farming is an all-new action-puzzle game set in the world of Harvest Moon.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-358-2-days-nintendo-ds', 'Kingdom Hearts 358/2 Days', 'Kingdom Hearts', '2009-09-29', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31qj.jpg', 'Kingdom Hearts 358/2 Days revolves around Roxas, the "other" hero from
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-re-coded-nintendo-ds', 'Kingdom Hearts Re:coded', 'Kingdom Hearts', '2011-01-11', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tq6.jpg', 'Kingdom Hearts Re: Coded is a remake of Kingdom Hearts Coded that was released for Mobile, only in Japan. The game takes place after the events of Kingdom Hearts II, when Jiminy''s Journal (where the events of Kingdom Hearts I & II are recorded) gets infested with bugs. In order to decode the information in the journal and debug it, King Mickey, Donald, Goofy and Jiminy Cricket digitalize it. With the help of a digital Sora, recreated from the Journal''s code, they start exploring the Worlds in the journal to reveal what is missing.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-canvas-curse-nintendo-ds', 'Kirby: Canvas Curse', 'Kirby', '2005-06-13', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qov.jpg', 'Your DS stylus has been infused with the power to paint! When Kirby gets turned into a ball by an evil witch, your hand-drawn rainbow paths become the only way he can find power-ups and reach the gates of each world. Draw loops to make him speed up, make ramps to jump danger, and draw walls to block laser beams and cannon blasts as you explore seven worlds packed with adventure! Get in touch: Stun enemies, break blocks, and much more - all with a touch of the stylus! Be a copycat: Tap Kirby to dash into enemies and copy their abilities. Eleven abilities in all! So many modes: Try timed challenges, take on bosses, or play simple but fun mini-games!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-squeak-squad-nintendo-ds', 'Kirby: Squeak Squad', 'Kirby', '2006-12-04', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4385.jpg', '"Kirby: Squeak Squad", known in Europe as "Kirby: Mouse Attack" and in Japan as "Kirby of the Stars: Calling on the Dorotche Gang", is a 2006-07 platforming video game developed by HAL Laboratory, Flagship and Natsume, and published by Nintendo for the Nintendo DS handheld video game console. Unlike the previous Nintendo DS title, Kirby: Canvas Curse, Squeak Squad is a traditional platformer which uses the face buttons instead of the touch screen to control Kirby.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-super-star-ultra-nintendo-ds', 'Kirby Super Star Ultra', 'Kirby', '2008-09-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3g9j.jpg', 'Kirby Super Star Ultra for the Nintendo DS re-imagines one of the most beloved Kirby games of all time. The game features new graphics and fully rendered animated cut scenes. With so many adventures waiting to be unlocked, there will never be a dull moment as Kirby runs, floats, copies enemies and uses Helpers to fight King Dedede and Meta Knight. New modes like Revenge of the King and Meta Knight Ultra await, along with classics like The Great Cave Offensive and Milky Way Wishes. On top of the main modes, there are also three new touch-screen-controlled mini-games that can be played with up to three friends via DS Download Play. Not only that, but players can go on Kirby adventures with a friend via local wireless as well.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-mass-attack-nintendo-ds', 'Kirby Mass Attack', 'Kirby', '2011-09-19', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pm7.jpg', 'One day, an evildoer with a magic cane appears and splits Kirby into 10 pieces. Kirby sets off on a journey to return to his original form. Players use the touch screen to control a mass of Kirby characters in a new and novel way. Swipe the touch screen to launch them in a mass attack against enemies, then tap the enemies into submission.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-phantom-hourglass-nintendo-ds', 'The Legend of Zelda: Phantom Hourglass', 'The Legend of Zelda', '2007-10-01', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ocu.jpg', 'The Legend of Zelda: Phantom Hourglass is the first Zelda game for the Nintendo DS and a direct sequel to The Wind Waker. The art direction is the same cel-shaded style as the Wind Waker but is displayed from a classic top-down perspective. The gameplay is structured similarly to other games in the series and is divided into two major gameplay sections: sailing between islands and exploring the islands and their dungeons on foot. The touch screen is used to make Link move and attack instead of buttons, you can also make notes of secret treasures and items on the map simply by writing them down. The game received critical acclaim from reviewers, who agreed that the game was a worthy sequel to The Wind Waker.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-spirit-tracks-nintendo-ds', 'The Legend of Zelda: Spirit Tracks', 'The Legend of Zelda', '2009-12-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3oj6.jpg', 'The Legend of Zelda: Spirit Tracks is the second Zelda game for the Nintendo DS. The art direction is still cel-shading, but the game have notable changes from Phantom Hourglass with more puzzles and a new mode of transportation by train. You have to draw your route to the next area on the map and then let the train run its course. While the train is moving, caution will be needed to avoid obstacles, animals and enemies on the tracks. In certain dungeons, both Link and Zelda will be playable as they will need to work together to solve puzzles.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-nintendo-ds', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-heroes-nintendo-ds', 'Bionicle Heroes', 'Lego', '2006-11-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525j.jpg', 'Bionicle Heroes DS is a classic first-person shooter. As a nameless Matoran, you''ll travel across 25 themed levels (including jungles, lava-worlds, ancient underground temples) discovering new weapons and new robotic foes to blast apart. Along the way, you''ll use the masks'' powers to survive the hostile environments as well as collect gears and robot parts to solve simple puzzles by assembling LEGO-style ramps, bridges, and doorways.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-complete-saga-nintendo-ds', 'Lego Star Wars: The Complete Saga', 'Lego', '2007-11-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrr.jpg', 'Play through a fun Star Wars galaxy that combines the endless customization of LEGO with the epic story from all six episodes of Star Wars. This is the definitive LEGO Star Wars comprising the first two games and expanding them with new characters, enhanced visuals, and more bonus levels than you can shake a lightsaber at.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-nintendo-ds', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-nintendo-ds', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-battles-nintendo-ds', 'Lego Battles', 'Lego', '2009-06-09', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3c2u.jpg', 'Play through six distinct storylines in the game to create your base, buildings and team and deploy your troops for battle! Test your strategies in single-player campaign or Free Play mode to unlock hidden treasures, or play against two of your friends to put your soldiers on the road to victory!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-rock-band-nintendo-ds', 'Lego Rock Band', 'Lego', '2009-11-03', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wpb.jpg', 'LEGO Rock Band is a blending of Rock Band and LEGO series. Players get to start a band and hire band members who will play with them. Just like with real Lego, players can mix and match bodies, torsos, legs and heads to create a character any way they want. The main game has players touring around the world at various locations, like the original Rock Band games. Unlike Rock Band however, LEGO Rock Band also has special levels where you must perform outrageous tasks such as fighting an octopus or demolishing a building using your rock concert. As players make their way through the song lists, they earn "Studs", the game''s currency. Studs can be used to purchase Lego items to decorate your Rock Den, hire new staff, buy new clothes or instruments.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-2-the-adventure-continues-nintendo-ds', 'Lego Indiana Jones 2: The Adventure Continues', 'Lego', '2009-11-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6up6.jpg', 'LEGO Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO fashion, get creative and build your own levels to play with friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-1-4-nintendo-ds', 'Lego Harry Potter: Years 1–4', 'Lego', '2010-06-29', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65lz.jpg', 'LEGO Harry Potter: Years 1-4 will give gamers the chance to experience the magic and adventure of Harry Potter in a uniquely LEGO way. Playing as Harry Potter, Ron Weasley and Hermione Granger, as well as more than 100 other favorite characters, gamers will have the opportunity to attend lessons, cast spells, mix potions, fly on broomsticks and complete tasks to earn rewards. Throughout the game, players will also have the freedom to explore iconic settings from the wizarding world including Hogwarts castle, Diagon Alley, the Forbidden Forest and the village of Hogsmeade.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-nintendo-ds', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-battles-ninjago-nintendo-ds', 'Lego Battles: Ninjago', 'Lego', '2011-04-12', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4o8h.jpg', 'Build your army, battle your enemies and become a master of Spinjitzu as you recover powerful ninja weapons and restore the world''s harmony in LEGO Battles: Ninjago! Deploy Hero troops through exciting missions and adventures to defeat the sinister Skulkin forces, play as the bad guys and face-off against ninjas of Spinjitzu, or challenge a friend in thrilling multiplayer battles to see whose army ranks supreme.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-nintendo-ds', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-nintendo-ds', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-nintendo-ds', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-nintendo-ds', 'Lego The Lord of the Rings', 'Lego', '2012-10-30', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-legends-of-chima-laval-s-journey-nintendo-ds', 'Lego Legends of Chima: Laval''s Journey', 'Lego', '2013-08-31', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co615v.jpg', 'Get ready for an epic adventure as Laval races to unlock the secret of the legendary triple-Chi armour before Cragger can manipulate its awesome power to threaten the balance of Chima itself! Laval and his allies will explore Lion Temple, Eagle Spire, Gorilla Forrest, Rhino Quary, Croc Swamp and more as they harness the power of Chi to leap, swing, fly and fight through 15 levels of intense action! Can Laval discover the truth behind the legend of the triple-Chi before it’s too late?', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-universe-in-peril-nintendo-ds', 'Lego Marvel Super Heroes: Universe in Peril', 'Lego', '2014-02-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co484t.jpg', 'A port of Lego Marvel Super Heroes, a 2013 Lego-themed action-adventure video based on Marvel comic book character.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-friends-nintendo-ds', 'Lego Friends', 'Lego', '2014-04-08', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gy3.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('children-of-mana-nintendo-ds', 'Children of Mana', 'Mana', '2006-10-30', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7hkx.jpg', 'This installment of the series takes place in the world of Fa''diel on the island of Illusia where, at the center of the island, stands the famous Tree of Mana. Several years ago, on the island of Illusia, an event known the "great disaster" took place at the base of the Mana Tree and many lives were lost. During this event, a brave young boy and girl used the Sword of Mana to save the world from disaster. Now, years later, a group of orphans sets out to investigate the details of the event that took so many loved ones away from them. The player must journey through the rest of Fa''diel''s five continents of Jadd, Topple, Wendell, Ishe, and Lorimar to complete the game, traveling to the other continents by riding Flammie from place to place using the "Flammie Drum."', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('heroes-of-mana-nintendo-ds', 'Heroes of Mana', 'Mana', '2007-08-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co40ad.jpg', 'Breathing new life into the vaunted Mana franchise, Heroes of Mana takes the beloved series into an entirely new dimension. In the first real-time strategy title for the series, generals will plan, plot and strategize their way to victory on the battlefield. Command an army of heroes, creatures and beloved rabites with the use of the Nintendo DS Touch Screen, and experience an all-new perspective on the ever-evolving Mana saga. Players can see how they rank among others in the country by accessing the Heroes of Mana servers via the Nintendo Wi-Fi Connection.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-64-ds-nintendo-ds', 'Super Mario 64 DS', 'Mario', '2004-11-21', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2u80.jpg', 'Super Mario 64, the classic 3D platformer for the Nintendo 64, arrives on the Nintendo DS with all-new features that take advantage of the portable system''s dual screens, touch screen, and wireless multiplayer capability. Like the original game, Super Mario 64 DS challenges you to find all the power stars hidden throughout the royal castle in the effort to free Peach imprisoned inside the castle. This time, you can play as Mario, Luigi, Wario, and Yoshi, each of whom has unique abilities. Overcome the challenges on your own or battle up to three of your friends in the multiplayer modes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-mario-bros-nintendo-ds', 'New Super Mario Bros.', 'Mario', '2006-05-15', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21ts.jpg', 'New Super Mario Bros. U is a side-scrolling 2.5D platform game, and the fourth and latest installment in the New Super Mario Bros. series. As the sequel to New Super Mario Bros. Wii, the game is a follow-up game of New Super Mario Bros. 2. It uses new, more detailed background styles and models and introduces the Flying Squirrel power-up, acquired by Mario and his friends from an item called the Super Acorn, as well as utilizing the Wii U GamePad in Boost Mode. In addition to the core campaign, there are also challenge modes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-partners-in-time-nintendo-ds', 'Mario & Luigi: Partners in Time', 'Mario & Luigi', '2005-11-28', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba41.jpg', 'The famous Mario Brothers return in this sequel to the humorous Superstar Saga. In this adventure, Princess Peach takes a trip in a time machine, but when it returns, there''s only a monster inside! The heroic brothers travel back in time only to discover that evil alien life forms known as the Shroobs have taken over the Mushroom Kingdom, and no-one is safe! They soon meet up with their younger selves, and set out to stop the alien menace, not to mention rescue the Princess!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-bowser-s-inside-story-nintendo-ds', 'Mario & Luigi: Bowser''s Inside Story', 'Mario & Luigi', '2009-09-15', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21vr.jpg', 'Mario & Luigi: Bowser''s Inside Story is the third game in the Mario & Luigi series of games. Players control Mario and Luigi simultaneously in the side-scrolling platform environment of Bowser''s body, while also controlling the Koopa King himself in the top-down world of the Mushroom Kingdom. Similar to games like Earthbound, enemy encounters are seen as actual enemies that players can avoid or attempt to strike early. The actual battles are a combination of turn-based menu attacks, and timed reactions to enemies during battle. By watching the way an enemy reacts, you can anticipate their attack and avoid it or counterattack.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-olympic-games-nintendo-ds', 'Mario & Sonic at the Olympic Games', 'Mario & Sonic at the Olympic Games', '2008-01-22', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wvp.jpg', 'Mario & Sonic on the Wii is a collection of twenty-four events based on the Olympic Games. Players can assume the role of a Nintendo or Sega character while competing against the others in these events. Players use the Wii Remote to mimic actions performed in real life sports, such as swinging a paddle.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-olympic-winter-games-nintendo-ds', 'Mario & Sonic at the Olympic Winter Games', 'Mario & Sonic at the Olympic Games', '2009-10-13', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wvr.jpg', 'Mario & Sonic at the Olympic Winter Games is a sports game with the official license of the 2010 Winter Olympic Games and a crossover franchise from the Mario and the Sonic universe similar to Mario & Sonic at the Olympic Games. It takes place at the Vancouver Winter Olympics of 2010. Like the previous game, the 27 events are presented as motion-based mini-games. Aside from the main events there are a series of Dream Events that have enhanced features and visuals. Some of the events can optionally be played using the balance board peripheral. Events include for instance skiing, snowboarding, bobsleigh, ice hockey, figure skating and more. The games can be played individually or in a festival mode that spans 17 days.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-hoops-3-on-3-nintendo-ds', 'Mario Hoops 3-on-3', NULL, '2006-09-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2206.jpg', 'Get that magic touch. There are plenty of basketball games out there, but none with the hands-on control of Mario Hoops 3-on-3. Players use the touch screen to get their game on as they execute tricky dribbles, special passes and sweet shots - all with strokes and taps of the stylus. Players choose their teams of three characters from the Mario universe and hit the parquet. Power-ups like Red Shells and Bob-ombs can turn the tide as they chase down coins - they will affect the score, so players collect as many as they can as they drive to the hoop. Whether playing against friends on a local wireless connection, jamming through a tournament or just playing mini-games, there''s a mode for everyone.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-ds-nintendo-ds', 'Mario Kart DS', 'Mario Kart', '2005-11-14', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9rx.jpg', 'Mario Kart DS is the continuation of the long running racing game series that began on the Super Nintendo. It features 16 new tracks as well as 16 tracks from the previous 4 games, with each set split up into the Nitro and Retro Grand Prix respectively. Eight racers are initially available, each with two go-karts to choose from. A number of characters and additional karts are also available to unlock. New items have been added to the arsenal, including a Blooper squid that squirts ink onto the screens of other players and a Bullet Bill power up that transforms the player into a giant, fast-travelling bullet on autopilot.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-ds-nintendo-ds', 'Mario Party DS', 'Mario Party', '2007-11-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba90.jpg', 'He''s captured Mario and his friends in his pursuit of a crystal that the group collected when it fell from the sky, and he doesn''t hesitate to shrink them to miniature size to get rid of them and get his hands on the other four crystals. The mini-heroes have to find the crystals before he does, making their way through giant environments filled with enormous creatures. The single-player campaign takes place in five different settings, each of them ending with a boss. As usual, players have to collect coins and stars, at the same time escaping dangers such as Piranha Plants and other classic creatures from the Mario universe.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-vs-donkey-kong-2-march-of-the-minis-nintendo-ds', 'Mario vs. Donkey Kong 2: March of the Minis', 'Mario vs. Donkey Kong', '2006-09-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21ti.jpg', 'It seems folks love those Mini Mario toys. So much so that the Mario Toy Company has expanded the line to include Mini Donkey Kong, Mini Toad and Mini Peach figures to the series. With all these toys bringing him more money than he knows what to do with, Mario decides to fulfill his lifelong dream and open a theme park called Super Mini Mario World. The opening-day crowd includes Pauline and Donkey Kong, who immediately falls head over heels for the lovely lass. The proud ape tries to show off his Mini DK toy to Pauline, but she picks the Mini Mario toy over his and the jealous Donkey Kong becomes enraged. He smashes the displays, destroys the toys and takes Pauline to the top floor of the amusement park. Players must find Pauline and save the day. Mario vs. Donkey Kong 2 allows players to create their own maps with a new level editor. Once a map is created, players can send it across the world via Nintendo Wi-Fi Connection. Players also can use Nintendo Wi-Fi Connection to download maps created by others, check out a player-ranking system and access special bonuses. These unique features are sure to be a smash hit with puzzle fans everywhere.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-vs-donkey-kong-mini-land-mayhem-nintendo-ds', 'Mario vs. Donkey Kong: Mini-Land Mayhem!', 'Mario vs. Donkey Kong', '2010-11-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21to.jpg', 'At the grand opening of Mario''s third theme park, the first 100 guests receive a new Mini Pauline toy. Donkey Kong arrives as the 101st guest and finds himself out of luck. He grabs Pauline and heads into the park with Mario and his Mini Marios in hot pursuit. The fourth game in the series adds new challenges and new opportunities for users to share what they have created.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-nintendo-ds', 'Spider-Man 2', 'Marvel', '2004-11-21', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-spider-man-nintendo-ds', 'Ultimate Spider-Man', 'Marvel', '2005-09-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/lsjknidfrlnz2cintrkr.jpg', 'Help Spider-Man save Harry Osborn from the Venom symbiote.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-nemesis-rise-of-the-imperfects-nintendo-ds', 'Marvel Nemesis: Rise of the Imperfects', 'Marvel', '2005-10-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1jr.jpg', 'Marvel Nemesis: Rise of the Imperfects pits fierce Marvel superheroes against each other in a 3D fighting game. You can assume control of heroes such as the Punisher, Spider-Man, and Captain America, and duel with them in interactive and destructible environments. A new team of superheroes called the Imperfects joins the mayhem. You can play in single-player story mode to unlock collectible awards, or you can play against other gamers in multiplayer modes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-nintendo-ds', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-battle-for-new-york-nintendo-ds', 'Spider-Man: Battle for New York', 'Marvel', '2006-11-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dep.jpg', 'Spider-Man: Battle for New York allows players to take on the role of Spider-Man and one of his famed nemeses, Green Goblin. For the first time in a handheld Spider-Man game, players can personalize their experiences by choosing what abilities and powers to upgrade and when, such as Spider-Man’s web manoeuvres or Green Goblin’s fire attacks.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-nintendo-ds', 'Spider-Man 3', 'Marvel', '2007-05-04', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-rise-of-the-silver-surfer-nintendo-ds', 'Fantastic Four: Rise of the Silver Surfer', 'Marvel', '2007-06-15', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x77.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-friend-or-foe-nintendo-ds', 'Spider-Man: Friend or Foe', 'Marvel', '2007-10-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h33.jpg', 'Defeat Spider-Man’s most famous enemies, like Venom, Green Goblin, and Doc Ock to add them to your epic array of playable sidekicks in this movie trilogy inspired adventure. Experience ground-breaking Co-operative Multiplayer, as Spider-Man or a sidekick, in exotic spots around the globe, including Tokyo, Egypt and Nepal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-nintendo-ds', 'Iron Man', 'Marvel', '2008-05-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-nintendo-ds', 'The Incredible Hulk', 'Marvel', '2008-06-05', 'Nintendo DS', 0, 0, NULL, NULL, NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-nintendo-ds', 'Spider-Man: Web of Shadows', 'Marvel', '2008-10-21', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ujz.jpg', 'Spider-Man: Web of Shadows is a video game title encompassing three versions: a full-3D action game for Microsoft Windows, PlayStation 3, Wii, and Xbox 360; a 2.5D sidescrolling beat em up action game for the PlayStation Portable and PlayStation 2 (called Amazing Allies Edition), and a 2.5D side-scrolling brawler/platformer for the Nintendo DS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-nintendo-ds', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-nintendo-ds', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-15', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-nintendo-ds', 'Marvel Super Hero Squad', 'Marvel', '2009-10-20', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e7b.jpg', 'Marvel Super Hero Squad is an action beat-em-up game for one to four players that is based on the animated Marvel TV series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-2-nintendo-ds', 'Iron Man 2', 'Marvel', '2010-05-04', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sxm.jpg', 'This is the Wii version of Iron Man 2, an action-adventure video game loosely based on the 2010 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-shattered-dimensions-nintendo-ds', 'Spider-Man: Shattered Dimensions', 'Marvel', '2010-09-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zpp.jpg', 'Spider-Man: Shattered Dimensions is a thrilling action-packed adventure set in four dramatically different universes from legendary Spider-Man lore, each with a distinct Spider-Man armed with unique skills and strengths, in one original storyline. Players will be transported to new locations never before seen in a Spider-Man game, from lush jungles and dusty deserts to various urban terrains. Acclaimed comic book writer Dan Slott takes players on a mission to contain the magical energy of the Tablet of Order and Chaos, which has been shattered and sent hurtling across parallel universes, and battle fan-favorite villains in a quest to restore the fabric of reality.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-the-infinity-gauntlet-nintendo-ds', 'Marvel Super Hero Squad: The Infinity Gauntlet', 'Marvel', '2010-11-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2di9.jpg', 'Marvel Super Hero Squad: The Infinity Gauntlet is a continuation of the video game Marvel Super Hero Squad and it was released on November 16, 2010. Similar to the first game, it features cartoonish Super-deformed versions of the Marvel Comics characters, as seen in the Marvel Super Hero Squad toy line, as well as the television show.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thor-god-of-thunder-nintendo-ds', 'Thor: God of Thunder', 'Marvel', '2011-05-03', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co531w.jpg', 'Thor: God of Thunder is an action-adventure game developed by Liquid Entertainment and published by Sega in 2011. It serves as a tie-in to the Thor film from the Marvel Cinematic Universe. Players control Thor as he wields Mjolnir to battle enemies across the Nine Realms, facing iconic foes such as Surtur and Ulik while protecting Asgard from destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-super-soldier-nintendo-ds', 'Captain America: Super Soldier', 'Marvel', '2011-07-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ovp.jpg', 'The Nintendo 3DS port of Captain America: Super Soldier.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-destiny-nintendo-ds', 'X-Men: Destiny', 'Marvel', '2011-09-27', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnk.jpg', 'X-Men: Destiny is an action role-playing video game based on the X-Men comic book series. It was developed by Silicon Knights. Written by Mike Carey, the writer of the X-Men: Legacy comic book series, it was first published and released by Activision for the Nintendo DS, PlayStation 3, Xbox 360 and Wii consoles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-edge-of-time-nintendo-ds', 'Spider-Man: Edge of Time', 'Marvel', '2011-10-04', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h30.jpg', 'The fate of one Webslinger hangs on the webs of another in this game where two Spider-Man worlds collide with the death - yes, the death - of Peter Parker. Play as the Amazing Spider-Man and Spider-Man 2099 in a storyline that weaves together two timelines. The two heroes battle in separate worlds with a shared destiny, working to prevent an event that has dire consequences for Parker and the fate of the worlds he protects. Your actions in one timeline could cause ripple effects in the other. Picture-in-picture visuals let you watch your actions change the future - or rewrite the past - for better or for worse.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-nintendo-ds', 'The Amazing Spider-Man', 'Marvel', '2012-06-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-battle-network-5-double-team-ds-nintendo-ds', 'Mega Man Battle Network 5: Double Team DS', 'Mega Man Battle Network', '2005-11-01', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0c.jpg', 'Mega Man Battle Network 5: Double Team is a dual screen version of the Game Boy Advance title. The DS will combine both Team Protoman and Team Colonel in one game, but add specific content unique to the Nintendo DS version. The second screen comes into play by giving players direct access to their Cyber Map and PET. The microphone can be "yelled" into to power up Mega Man during battle. And using the Nintendo DS''s GBA slot, players can carry over battle chips earned in past Mega Man Battle Network games for use in the Nintendo DS edition.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-pegasus-nintendo-ds', 'Mega Man Star Force Pegasus', 'Mega Man Star Force', '2007-08-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2048.jpg', 'Pegasus Magic is one of three Satellite Admins from the MegaMan Star Force series. He is an AM-ian and one of the three wise sages of Planet AM.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-leo-nintendo-ds', 'Mega Man Star Force Leo', 'Mega Man Star Force', '2007-08-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2049.jpg', 'Mega Man Star Force introduces a new lead character, a boy named Subaru Hoshikawa, who puts on special "visualizer" goggles left to him by his father, triggering a specific wave and summoning the presence of a mysterious alien life form named Warlock. Dangerous creatures from Warlock''s planet have come to attack Earth, so they must join together to transform into Mega Man in order to defeat these menacing forces. Specific to the Leo version - turning up the heat, Fire Leo uses a special Flame Burner attack that can incinerate enemies in its path.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-dragon-nintendo-ds', 'Mega Man Star Force Dragon', 'Mega Man Star Force', '2007-08-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204a.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-2-zerker-ninja-nintendo-ds', 'Mega Man Star Force 2 Zerker × Ninja', 'Mega Man Star Force', '2008-06-24', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bhm.jpg', 'Mega Man Star Force 2 blends a unique formula of RPG exploration elements with fast-paced action, as players travel and battle between coexisting worlds, the physical world and the virtual Wave World, to unravel the mystery around this new troublemaker.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-2-zerker-saurian-nintendo-ds', 'Mega Man Star Force 2 Zerker × Saurian', 'Mega Man Star Force', '2008-06-24', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bhn.jpg', 'Mega Man Star Force 2 blends a unique formula of RPG exploration elements with fast-paced action, as players travel and battle between coexisting worlds, the physical world and the virtual Wave World, to unravel the mystery around this new troublemaker.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-3-black-ace-nintendo-ds', 'Mega Man Star Force 3 Black Ace', 'Mega Man Star Force', '2009-06-30', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ilk.jpg', 'Mega Man Star Force returns in the most thrilling series adventure yet, delivering totally upgraded and cutting-edge online communication and device customization technologies through a portable RPG adventure that is brought to life in the iconic, action-driven Mega Man way! New to the series are "Noise Changes," random enhancements that change Mega Man''s form and unlock new abilities. There are more than 100 transformations possible. Mega Man Star Force 3 will be available in two versions, Red Joker and Black Ace, each with their own unique Noise Types. Mega Man Star Force 3 blends a unique formula of RPG exploration elements with fast-paced action, as players travel and battle between coexisting worlds, the physical world and the virtual Wave World. Players will encounter enemies in the virtual Wave World and battle them on three-by-five battle grids with their Battle Card deck. Mega Man Star Force 3 also adds a new feature called "Rezon," which allow players to fill in profiles about battles and their team name/symbol.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-star-force-3-red-joker-nintendo-ds', 'Mega Man Star Force 3 Red Joker', 'Mega Man Star Force', '2009-06-30', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z0a.jpg', 'The world is in peril from a mysterious "noise" that is affecting the EM digital world. Through his bond with the alien Omega, Geo must transform into the legendary Mega Man to uncover the mystery behind the noise and protect the Earth. Can he master the new Mega Man transformations of Black Ace and Red Joker before it''s too late?', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-collection-nintendo-ds', 'Mega Man Zero Collection', 'Mega Man Zero', '2010-06-08', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204x.jpg', 'The first Mega Man ZERO game was released in 2002. It featured Zero, a popular Capcom character that was introduced in the Mega Man X series. The Mega Man ZERO series follows Zero through a dark and thrilling 2D action-adventure with high-quality visuals and action. Users can expect to make use of Zero''s trademarks weapons like the Z-sabor and Buster Shot. There will also be interesting devices like the Chain Rod and Zero Knuckle. For the first time, the Mega Man ZERO series will be available for Nintendo DS, complete with all-new modes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zx-nintendo-ds', 'Mega Man ZX', 'Mega Man ZX', '2006-09-12', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ji9.jpg', 'This game contains elements from the Mega Man X series and the Mega Man Zero series. The game introduces a new open-ended gameplay environment and the ability to select the protagonist''s gender, a first in the series. The player''s character, Vent or Aile, is on a 2-dimensional overlay map with sprites where he or she engages enemies to finish the mission. When Vent and Aile receive a Biometal, they are able to change form, gaining various abilities, such as the charge moves, or charging their weapon with an element of that Biometal; for example, Biometal H will charge the weapon with electricity. While in a special form, using the form-specific abilities use up weapon energy. When Vent and Aile receive the other half of the Biometal, they are able to perform a different special ability.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zx-advent-nintendo-ds', 'Mega Man ZX Advent', 'Mega Man ZX', '2007-10-23', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2047.jpg', 'In Mega Man ZX Advent, the main characters discover the power of the mysterious "Biometal model A," which on its own has several attacks, but also has a special Megamerge ability which allows the character to transform into one of eight "Pseudoroid" bosses that each have a unique set of abilities. Once a boss is defeated, players can emulate their powers to find hidden routes, discover rare items and aid their battles against more powerful enemies. The title takes full advantage of the Nintendo DS features to enhance the action-packed gameplay and story line of the popular series.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-pinball-nintendo-ds', 'Metroid Prime Pinball', 'Metroid', '2005-10-24', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wwq.jpg', 'Samus Aran''s entry into the bumper-and-flipper world is a sleek, sci-fi classic gaming adventure that has her careening into gigantic boss monsters and bouncing through a variety of exciting pinball tables. Play tables across two screens at the same time using the touch screen to nudge the pinball table. Battle deadly enemies and experience a number of special modes such as Clone Machine Multiball and the Wall-Jump Challenge while you blast and bomb your high score into a state of pure pinball pandemonium.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-hunters-nintendo-ds', 'Metroid Prime Hunters', 'Metroid', '2006-03-20', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7j9t.jpg', 'Metroid Prime Hunters is a first-person action-adventure game that combines exploration, shooting, and competitive multiplayer gameplay. Set across interconnected locations, it features objective-based progression alongside encounters with rival bounty hunters, each with distinct abilities and weapons.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-conquest-nintendo-ds', 'The Lord of the Rings: Conquest', 'Middle-earth', '2009-01-13', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lup.jpg', 'Play as Evil characters in a brand new, ''Evil'' campaign. Battle through scenarios after Frodo failed to destroy the One Ring; it''s good to be bad! Battle online, in a co-op campaign or offline in split-screen.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-aragorn-s-quest-nintendo-ds', 'The Lord of the Rings: Aragorn''s Quest', 'Middle-earth', '2010-09-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9nie.jpg', 'The NDS/PSP ports features slightly different HUD, and the NDS version uses the second screen as a map.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-ds-nintendo-ds', 'Namco Museum DS', 'Namco Museum', '2007-09-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hxq.jpg', 'A collection of Namco classics for the Nintendo DS.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-dragon-sword-nintendo-ds', 'Ninja Gaiden: Dragon Sword', 'Ninja Gaiden', '2008-03-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co404s.jpg', 'This action-adventure title is presented in a third person, pseudo-3D manner, meaning all the game-models are rendered in full 3D, but the world the player travels around in is pre-rendered. When played, the Nintendo DS is held sideways, as in Hotel Dusk: Room 215 and Brain Age: Train Your Brain in Minutes a Day!. The left screen shows the area map, while the right displays the main gameplay, when set for right-handed play, and reverse when set for left-handed play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kamiden-nintendo-ds', 'Ōkamiden', 'Ōkami', '2011-03-15', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8mj.jpg', 'Ōkamiden is the DS-sequel to Ōkami on PS2 and Wii. The story takes place a few months after the story of Okami. It revolves around the adventures of Chibiterasu, the young sun god and Amaterasu''s son, who is called to save the land!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-pix-nintendo-ds', 'Pac-Pix', 'Pac-Man', '2005-04-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bh4.jpg', 'A mischievous magician, known for playing pranks on poor unsuspecting folks, created something known as "Ghost Ink," a fluid that pretty much turns any drawing into evil and vicious ghost monsters. Any ghost created with the ink ends up just as mischievous as the magician. Ink ghosts have invaded books and paintings, causing trouble within those realms, and now it''s up to Pac-Man to wipe out the ghost problem by using the "Ghost Pen," a device that allows him to enter the infested books and paintings to clear out the bad guys. Pac-Pix is a game tailored specifically for the Nintendo DS'' system capabilities. By drawing Pac-Man characters in a specific fashion (the mouth first, then the circle, all in one swoop), the drawing will come to life and munch anything in his path. Players can maneuver Pac-Man drawings in different directions by plotting pathways on the screen for the scribble to follow.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-n-roll-nintendo-ds', 'Pac ''n Roll', 'Pac-Man', '2005-08-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85i2.jpg', 'In Pac''N Roll, the inhabitants of Pac-World have been turned into spheres by the evil monster Golvis'' Ghost Light. Pac-Man must roll his way through Ghost-Land, collecting pellets and confronting Ghosts to save his family and restore peace to Pac-Land. Introducing an innovative new control scheme, Pac''N Roll lets players control Pac-Man with the Nintendo DS stylus. Players can roll and dash around the environment as well as execute maneuvers such as hairpin turns, immediate stops and precision rolling with effortless strokes of the stylus. In his quest to save Pac-Land, Pac-Man will venture through stages such as Castle Pac, Gyro-Jungle and the Ghost House, while facing perilous hazards like moving floors, dash panels, jump zones and wind zones. Along the way, Pac-Man will find power-ups like the Winged Chocolate, allowing him to fly through the worlds and jump over Ghosts, or the "Knight Chocolate," providing him with armor which grants him the power to crash through walls and withstand more damage. Pac''N Roll also includes the original Pac-Man arcade game, allowing up to two players to munch on pellets and claim the highest score.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-3-nintendo-ds', 'Pac-Man World 3', 'Pac-Man', '2005-12-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc8.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('picross-3d-nintendo-ds', 'Picross 3D', 'Picross', '2010-05-03', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzy.jpg', 'Picross 3D is the sequel to the popular Picross DS puzzle game. The original game was a number-based grid puzzle that challenged players to reveal a hidden picture. Picross 3D moves the action into three dimensions. Picross 3D blends the logical challenge of a sudoku puzzle with the excitement of discovering the hidden images within.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-nintendo-ds', 'Plants vs. Zombies', 'Plants vs. Zombies', '2011-01-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69id.jpg', 'Zombies are invading your home, and the only defense is your arsenal of plants! Plants vs. Zombies is a tower defense video game developed and published by PopCap Games. As a horde of zombies approaches along several parallel lanes, players must defend their homes by placing plants, which fire projectiles at the zombies or otherwise detrimentally affect them.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-dash-nintendo-ds', 'Pokémon Dash', 'Pokémon', '2005-03-13', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4wo1.jpg', 'In Pokémon Dash, you''ll control Pikachu and race against other Pokémon. Use the DS''s touch screen to adjust Pikachu''s direction and speed. Off the course, Pikachu can cross water terrain by riding on Lapras'' back and fly using a hot-air balloon.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-trozei-nintendo-ds', 'Pokémon Trozei!', 'Pokémon', '2006-03-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3uqa.jpg', 'A crazy departure from your normal Pokémon game, Pokémon Trozei is a speedy puzzle game that will send your stylus flying! Your goal is to match the faces of four Pokémon in the game board to remove them, then string together more Pokémon faces to perform big combos. The Pokémon keep coming faster and faster, increasing the challenge the more you play. When you clear a set of Pokémon, that Pokémon will be added to your Pokédex, so look out for rare and special Pokémon to clear from the board! All of the 386 Pokémon available through Pokémon FireRed Version and Pokémon LeafGreen Version are in Pokémon Trozei, but it''ll take a great many games to catch them all!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-blue-rescue-team-nintendo-ds', 'Pokémon Mystery Dungeon: Blue Rescue Team', 'Pokémon', '2006-09-18', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yyk.jpg', 'You, a regular human, find yourself trapped in the body of a Pokémon in a world inhabited by Pokémon. Without any other choice, you go on rescue missions through randomly generated dungeons with your newly-acquired partner and friend to save the world and get back to your human life.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ranger-nintendo-ds', 'Pokémon Ranger', 'Pokémon', '2006-10-30', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z5b.jpg', 'Pokémon Ranger is an action role-playing video game developed by HAL Laboratory and Creatures Inc. and published by Nintendo for the Nintendo DS video game console. The game was released at various dates, varying between continents. The game was first released in Japan on March 22, 2006 and was later released in North America and Australia during the remainder of 2006. The game''s final release date was in Europe in April 2007.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-diamond-version-nintendo-ds', 'Pokémon Diamond Version', 'Pokémon', '2007-04-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zht.jpg', 'Pokémon Diamond Version and Pearl Version are role-playing games (RPGs) developed by Game Freak and published by Nintendo for the Nintendo DS. With the enhanced remake Pokémon Platinum, the games comprise the fifth installment and fourth generation of the Pokémon series of RPGs. First released in Japan on September 28, 2006, the games were later released to North America, Australia, and Europe over the course of 2007.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-pearl-version-nintendo-ds', 'Pokémon Pearl Version', 'Pokémon', '2007-04-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zio.jpg', 'Pokémon Pearl Version and Diamond Version are role-playing games (RPGs) developed by Game Freak and published by Nintendo for the Nintendo DS. With the enhanced remake Pokémon Platinum, the games comprise the fifth installment and fourth generation of the Pokémon series of RPGs. First released in Japan on September 28, 2006, the games were later released to North America, Australia, and Europe over the course of 2007.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-explorers-of-time-nintendo-ds', 'Pokémon Mystery Dungeon: Explorers of Time', 'Pokémon', '2008-04-20', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yzu.jpg', 'Embark on a journey after you get turned into a Pokémon as a result of a freak accident, causing you to lose your memory as well as contact with and knowledge of your previous adventuring partner, with whom you were on a secret mission to save the world. Watch your story unfold in a dungeon crawling rogue-lite experience as you form your very own rescue team with a new partner of your choosing.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-explorers-of-darkness-nintendo-ds', 'Pokémon Mystery Dungeon: Explorers of Darkness', 'Pokémon', '2008-04-20', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yzs.jpg', 'Embark on a journey after you get turned into a Pokémon as a result of a freak accident, causing you to lose your memory as well as contact with and knowledge of your previous adventuring partner, with whom you were on a secret mission to save the world. Watch your story unfold in a dungeon crawling rogue-lite experience as you form your very own rescue team with a new partner of your choosing.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ranger-shadows-of-almia-nintendo-ds', 'Pokémon Ranger: Shadows of Almia', 'Pokémon', '2008-11-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yzl.jpg', 'In the second in the Pokemon Ranger series, you once again play as a Pokemon Ranger, working to help people, Pokemon and nature in a new area called the Almia Region. Starting out as a Student Ranger, you quickly earn the title of a full-fledged Pokemon Ranger. As you succeed in more and more missions, you will aspire to become the highest Ranger rank: Top Ranger. Along the way you meet and capture all kinds of different Pokemon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-platinum-nintendo-ds', 'Pokémon Platinum', 'Pokémon', '2009-03-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaaom.jpg', 'This game makes you rediscover the Sinnoh Region while incorporating elements of the anime series and by making the game harder to give a bigger challenge to the player.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-explorers-of-sky-nintendo-ds', 'Pokémon Mystery Dungeon: Explorers of Sky', 'Pokémon', '2009-10-12', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ovf.jpg', 'Embark on a journey after you get turned into a Pokémon as a result of a freak accident, causing you to lose your memory as well as contact with and knowledge of your previous adventuring partner, with whom you were on a secret mission to save the world. Watch your story unfold in a dungeon crawling rogue-lite experience as you form your very own rescue team with a new partner of your choosing.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-heartgold-version-nintendo-ds', 'Pokémon HeartGold Version', 'Pokémon', '2010-03-14', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z57.jpg', 'Pokémon HeartGold Version and Pokémon SoulSilver Version are paired Generation IV remakes of the Generation II games Pokémon Gold and Silver.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-soulsilver-version-nintendo-ds', 'Pokémon SoulSilver Version', 'Pokémon', '2010-03-14', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z59.jpg', 'Pokemon HeartGold Version and Pokemon SoulSilver Version return players to the scenic Johto region first introduced in the beloved original Pokemon Gold and Pokemon Silver games nearly a decade ago. The richly detailed adventure of Pokemon Gold and Pokemon Silver is now enhanced for the Nintendo DS and Nintendo DSi systems with updated graphics and sound, as well as new touch-screen features and a host of surprises. Pokemon HeartGold Version and Pokemon SoulSilver Version bring dozens of Pokemon characters back into the limelight for a new Pokemon generation - and longtime fans - to catch, train and battle.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ranger-guardian-signs-nintendo-ds', 'Pokémon Ranger: Guardian Signs', 'Pokémon', '2010-10-04', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z1q.jpg', 'The third installment in the action-packed Pokemon Ranger series lets players take on the role of a Pokemon Ranger tasked with protecting Pokemon, people and nature.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-black-version-nintendo-ds', 'Pokémon Black Version', 'Pokémon', '2011-03-06', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z8d.jpg', 'Pokémon Black Version 2 and Pokémon White Version 2 are the second and final paired versions of Generation V and are the sequels of Pokémon Black and White, respectively.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-white-version-nintendo-ds', 'Pokémon White Version', 'Pokémon', '2011-03-06', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z8e.jpg', 'Pokémon White Version 2 and Pokémon Black Version 2 are the second and final paired versions of Generation V and are the sequels of Pokémon Black and White, respectively.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-conquest-nintendo-ds', 'Pokémon Conquest', 'Pokémon', '2012-06-18', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2jxm.jpg', 'Pokémon Conquest is a strategy game set in the Ransei region. You play as a Warlord of the Primus Kingdom, one of the 17 Kingdoms in the Ransei region. You are charged with the task of battling against a wide variety of powerful opponents, including the mighty Nobunaga, whose goal is to destroy the Ransei region!The 17 Kingdoms of the Ransei region possess a variety of Armies competing for control. The 17 Kingdoms are also deeply linked to a specific Pokémon type. Primus Kingdom, for example, has a strong connection with Normal-type Pokémon!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-black-version-2-nintendo-ds', 'Pokémon Black Version 2', 'Pokémon', '2012-10-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z8d.jpg', 'Pokémon Black Version 2 and Pokémon White Version 2 are the second and final paired versions of Generation V and are the sequels of Pokémon Black and White, respectively.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-white-version-2-nintendo-ds', 'Pokémon White Version 2', 'Pokémon', '2012-10-07', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z8e.jpg', 'Pokémon White Version 2 and Pokémon Black Version 2 are the second and final paired versions of Generation V and are the sequels of Pokémon Black and White, respectively.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battles-of-prince-of-persia-nintendo-ds', 'Battles of Prince of Persia', 'Prince of Persia', '2005-12-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav9u.jpg', 'Battles of Prince of Persia is the first game in the Prince of Persia franchise to make its way onto the Nintendo DS. The storyline takes place in the time between the Prince of Persia: The Sands of Time and Prince of Persia: The Two Thrones. Unlike other entries, this game is about tactical combat, as you must control armies using the Prince, and a number of generals, via playable trading cards. There are nine different playable characters, 27 different units to control, and three different factions. Multiplayer is available for competition, with one copy of the cartridge capable of being shared among multiple players.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-fallen-king-nintendo-ds', 'Prince of Persia: The Fallen King', 'Prince of Persia', '2008-12-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ouc.jpg', 'Prince of Persia: The Fallen King is a third-person action-adventure video game developed by Ubisoft Casablanca. The game was released for the Nintendo DS in December 2008, as a spin-off sequel to the Prince of Persia reboot.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-forgotten-sands-nintendo-ds', 'Prince of Persia: The Forgotten Sands', 'Prince of Persia', '2010-05-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8z2j.jpg', 'Prince of Persia: The Forgotten Sands is a promotional browser flash game created to promote the Prince of Persia: The Forgotten Sands. Playing the game unlocked a costume in the main game, though that feature no longer works. The game is still playable on explosivebarrel.net
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-princess-peach-nintendo-ds', 'Super Princess Peach', 'Princess Peach', '2006-02-27', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wsg.jpg', 'Princess Power!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-2-nintendo-ds', 'Rayman Raving Rabbids 2', 'Rabbids', '2007-11-13', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gt4.jpg', 'They''ve invaded the world of Rayman, and now the insane Rabbids have a new objective: invade planet Earth! They have established their base at a shopping mall and begun training for their nastiest scheme yet. As part of this training, the Rabbids must carry out several missions around the globe to help them in an attempt to dominate the world. The Rabbids will also try to study human behavior by mimicking everything we do... but in the Rabbid sort of way, with no logic... of course.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-tv-party-nintendo-ds', 'Rayman Raving Rabbids: TV Party', 'Rabbids', '2008-11-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8544.jpg', 'Rayman Raving Rabbids TV Party (DS) is the Nintendo DS version of Rayman Raving Rabbids TV Party, the third instalment of the Rayman Raving Rabbids series. In the same vein as Rayman Raving Rabbids 2 for the handheld, the game centres around minigames almost entirely.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-go-home-nintendo-ds', 'Rabbids Go Home', 'Rabbids', '2009-11-01', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jq9.jpg', 'Rabbids Go Home was released on PC in select countries in Europe, notable France (in which it was published by Mindscape), Russia (Бука), Czech Republic (Playman), Germany (Computer Bild Spiele). It was developed by Ubisoft Sofia. Much of the content from the original Wii version is absent from this version, such as the In Ze Remote features and the Centre City. Only 16 levels are present in the game. Polish port was split into 4 parts (one contains 4 levels, totally 16). It was sold with the magazine (which truly was only a front cover) issued every two months with disc and Rabbid figure. The publisher was Egmont Polska.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-ds-nintendo-ds', 'Rayman DS', 'Rayman', '2005-03-28', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48ul.jpg', 'The character with no arms and no legs makes his debut on the Nintendo DS. Rayman must defeat the pirates who have enslaved his world. As Rayman, you''ll travel through magical worlds where you can explore waterfalls, sea caves, and pirate hideouts. Master Rayman''s special moves to progress through each challenging level. The DS''s bottom screen let you monitor your progress, track your lums, and keep an eye on Rayman''s health.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-deadly-silence-nintendo-ds', 'Resident Evil: Deadly Silence', 'Resident Evil', '2006-02-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20cb.jpg', 'Resident Evil: Deadly Silence is an enhanced version of the original Resident Evil for the Nintendo DS. It was made to commemorate the tenth anniversary of the series. The key difference with the original game is the use of the dual screen and touch sensitive formats, among many gameplay additions. A primary map is displayed on the second screen, providing extra help in finding the important areas of the mansion. The lower touch screen can be used to open locks or, in a special 1st person perspective addition, fight off various versions of the evil dead. The game also includes wireless LAN support for up to four players with two different multiplayer game modes.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rhythm-heaven-nintendo-ds', 'Rhythm Heaven', 'Rhythm Heaven', '2009-04-05', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobvt4.jpg', 'Rhythm Heaven puts the music in your hands and some rhythm in your life. Let the music move you as you tap and slide your stylus on the touch screen to the beat of more than 50 musical rhythm games. The controls are as natural as tapping your finger to music.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-a-fantasy-harvest-moon-nintendo-ds', 'Rune Factory: A Fantasy Harvest Moon', 'Rune Factory', '2007-08-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkp.jpg', 'You awaken to find yourself in an unfamiliar village with no memory of who you are or how you arrived. Mist, a beautiful young woman comes to your aid and helps you start to build a life for yourself on a farm. Till the land, grow crops, raise animals, catch fish and battle monsters!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-2-nintendo-ds', 'Rune Factory 2', 'Rune Factory', '2008-11-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkk.jpg', 'Rune Factory 2 is set several years after the first game. The evil Sechs Empire has been defeated, and the Kingdom of Norad is once again at peace. Things may not stay that way for long, however, as dark premonitions foretell of dangers to come. It''s up to player to uncover the source of these premonitions and bring peace to the kingdom once more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-3-nintendo-ds', 'Rune Factory 3', 'Rune Factory', '2010-11-09', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co692u.jpg', 'Settle down in an idyllic fantasy town as a young adventurer with a monstrous secret in Rune Factory 3, remade for a new generation on Nintendo Switch and PC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-nintendo-ds', 'Scribblenauts', 'Scribblenauts', '0200-09-15', 'Nintendo DS', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d5u.jpg', 'What Will You Write?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-scribblenauts-nintendo-ds', 'Super Scribblenauts', 'Scribblenauts', '2010-10-12', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co543g.jpg', 'In this new game created and developed by 5TH Cell, players use the stylus and touch screen to help Maxwell, the game''s hero, acquire the "Starite," the prize earned from solving the puzzle in even more robust challenges and redesigned levels. Players now have the ability to write any object that comes to mind and modify it in any way they desire using adjectives to reach the goal in each level. Adjectives can change the color, size, elements, behaviors and many other aspects of the object they are describing. Multiple adjectives can be combined together to produce incredibly creative objects, allowing the player''s imagination to run wild for a truly unique and individualistic experience.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-tennis-nintendo-ds', 'Sega Superstars Tennis', 'Sega All-Stars', '2008-03-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6p9b.jpg', 'Developed by Sumo Digital, this is the handheld port of Sega Superstars Tennis. While the core mechanics remain very similar, the game differs from the home console version in its presentation, depth, and certain elements of functionality.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-sega-all-stars-racing-nintendo-ds', 'Sonic & Sega All-Stars Racing', 'Sega All-Stars', '2010-02-23', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te6.jpg', 'Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('simcity-ds-nintendo-ds', 'SimCity DS', 'SimCity', '2007-06-19', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2den.jpg', 'SimCity DS (SCDS) is a city building and management computer game and the first Nintendo DS installment in the SimCity series. It was published by Electronic Arts (EA) and developed by the AKI Corporation and EA Japan.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('simcity-creator-nintendo-ds', 'SimCity Creator', 'SimCity', '2008-09-22', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobdj8.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-urbz-sims-in-the-city-nintendo-ds', 'The Urbz: Sims in the City', 'The Sims', '2004-11-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5s.jpg', 'Starting out as a humble window washer in the city of Miniopolis, the player is quickly embroiled in a devious plot by the greedy tycoon Daddy Bigbucks to take over the city.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-nintendo-ds', 'The Sims 2', 'The Sims', '2005-10-24', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja7.jpg', 'The Sims 2 for Nintendo DS is the first DS game of The Sims 2. Like the many of the console games it takes place in Strangetown with some of the same faces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-nintendo-ds', 'The Sims 2: Pets', 'The Sims', '2006-10-31', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-nintendo-ds', 'MySims', 'The Sims', '2007-09-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6e0k.jpg', 'The Nintendo DS version of MySims takes place in a vacation resort with the player tasked with the job of luring tourists. This is accomplished by doing tasks for the locals who live in your town and after you''re done with a certain task you earn stars. Players collect stars to unlock other parts of the city as well as new minigames and new items in stores. As more stars are collected, the town grows and mini games are unlocked.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-castaway-nintendo-ds', 'The Sims 2: Castaway', 'The Sims', '2007-10-22', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja9.jpg', 'Castaway is the third console spin-off of the video game The Sims 2. The Sims Castaway Stories is a similar game created for personal computers. It is the final game in the series released for the PlayStation 2 and the final game in the Sims 2 series for console.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-apartment-pets-nintendo-ds', 'The Sims 2: Apartment Pets', 'The Sims', '2008-08-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zob.jpg', 'Your Sims are leaving the suburbs for the hustle and bustle of apartment life! They''re moving into a apartment building full of interesting neighbors and a wide variety of pets. Your Sim can adopt pets of their own to play with and care for. As the manager of the on-site pet spa, your Sim can earn Simoleons by making sure that the local pets get the right treatments to keep them-and their owners-happy. From loveable cats and dogs to all-new exotic animals including slithery snakes, colorful birds, and cuddly rabbits, your Sim will experience all the hilarious unpredictability of owning pets while enjoying their exciting new apartment lifestyle!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-kingdom-nintendo-ds', 'MySims Kingdom', 'The Sims', '2008-10-28', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9jux.jpg', 'MySims Kingdom sets you on an adventure to help King Roland and his subjects revitalize the Kingdom. Throughout the quest, you will join up with friends, discover fascinating lands, take on challenges, and build amazing contraptions. Almost everything is customizable, allowing every creation within your world to have a signature look.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-party-nintendo-ds', 'MySims Party', 'The Sims', '2009-03-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa0ls.jpg', 'Up to 4 players can test their wits, quickness and skill in 40 mini-games, each hosted by a different MySim. Each of your friends and you can select a custom team of 4 characters to play the huge variety MySims Party has to offer. Outwit friends by selecting the right team who will carry the day in contests based on strength, endurance, speed and luck. Pick carefully though, the wrong team will give your friends the edge over you. Bragging rights only belong to those who choose wisely and play flawlessly. Real People. Real fun. With the MySims.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-racing-nintendo-ds', 'MySims Racing', 'The Sims', '2009-06-12', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaqzg.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-agents-nintendo-ds', 'MySims Agents', 'The Sims', '2009-09-29', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87qm.jpg', 'In MySims Agents on the Nintendo DS, players are agents assigned by their agency to help the mayor stop a notorious thief from stealing an ancient treasure. By searching for clues, solving intricate puzzles, and matching wits with the thief, gamers can protect the treasure and the town! Along the way, they can talk to their favorite MySims, sharpen their agent skills with 10 different mini-games, and search through underground caverns for clues to the thief’s undoing!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-skyheroes-nintendo-ds', 'MySims SkyHeroes', 'The Sims', '2010-09-28', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uk1.jpg', 'The DS port of the final game in the MySims series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-nintendo-ds', 'The Sims 3', 'The Sims', '2010-10-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nas.jpg', 'The Sims 3 is a console game developed by Electronic Arts for the Nintendo Wii.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-rush-nintendo-ds', 'Sonic Rush', 'Sonic the Hedgehog', '2005-11-15', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coahh6.jpg', 'Sonic Rush Rerun is a full fan reimagining of the Nintendo DS game “SONIC RUSH”. The idea behind this remake is to take the greatest strengths of the Sonic Rush trilogy (Rush, Rush Adventure, and Colors DS), crank them up to 11, and combine those strengths into the ultimate remake of Sonic Rush!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-rush-adventure-nintendo-ds', 'Sonic Rush Adventure', 'Sonic the Hedgehog', '2007-09-18', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvk.jpg', 'Sonic returns to the DS with all the classic 2D dual screen action of "Sonic Rush," as well as a new high-seas adventure where he clashes with ruthless pirates. As Sonic, set off from Windmill Village to explore seven islands for action-packed adventures spread across a large map. As you venture, you''ll uncover valuable items and materials that will help Tails build new ships so that Sonic can track down the villainous pirates in a variety of ways.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-chronicles-the-dark-brotherhood-nintendo-ds', 'Sonic Chronicles: The Dark Brotherhood', 'Sonic the Hedgehog', '2008-09-30', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85o7.jpg', 'Is an online Flash game released in 2008 to promote Sonic Chronicles: The Dark Brotherhood. The game was featured on the Sonic Chronicles: The Dark Brotherhood''s official websites before they were shut down.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-classic-collection-nintendo-ds', 'Sonic Classic Collection', 'Sonic the Hedgehog', '2010-03-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v8f.jpg', 'Sonic Classic Collection is a video game compilation for the Nintendo DS developed by The Creative Assembly Australia, under supervision by Sega Australia and Sega of Europe. It is a collection of:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-colors-nintendo-ds', 'Sonic Colors', 'Sonic the Hedgehog', '2010-11-16', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6yuq.jpg', 'An extraordinary amusement park has been seen orbiting around the home planet of Sonic the Hedgehog, and rumors are spreading that an alien race of Wisps, who have a unique colorful energy, are being held captive there by the evil Dr. Eggman. Soon after arriving at the amusement park, Sonic discovers he is able to use these mysterious alien forces to help the Wisps escape!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-revolution-nintendo-ds', 'Space Invaders Revolution', 'Space Invaders', '2005-09-20', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9h.jpg', 'Space Invaders Revolution is a new take on the series, which marks a true progression over any version before it: New types of invaders, new rules and new ways to destroy them. Contains a faithful reproduction of the original arcade machine in Classic Mode. New Era mode: the simple rules of Space Invaders are expanded and twisted into a revolutionary step for the classic franchise. New Era mode takes the form of a world tour, with the player confronting the Space Invaders at 20 recognisable geographical locations. In total there are 60 levels to defend and 13 different types of invader to battle. Power-ups include protective shields, additional support craft, rapid-fire shots and column-clearing laser beams - essential aides as the action becomes progressively more intense. Power-ups can be used in combination: using support craft with laser results in three laser beams, decimating multiple waves of invaders with every press of the fire button.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-extreme-nintendo-ds', 'Space Invaders Extreme', 'Space Invaders', '2008-06-17', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65kk.jpg', 'Space Invaders Extreme combines the captivating essence of the original game with a stunning alliance of futuristic graphic design and cutting-edge audio. The gameplay experience has been developed to maximise on the consoles'' abilities, offering players a whole new range of amazing features including a vast array of new power-ups.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-extreme-2-nintendo-ds', 'Space Invaders Extreme 2', 'Space Invaders', '2009-10-20', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48t6.jpg', 'High-speed action-packed game play returns with the addition of exciting head-to-head battle modes, a challenging new time attack mode, and expanded game play progression that goes beyond Fever Time to SUPER FEVER TIME! Space Invaders Extreme 2 - faster and more exhilarating than ever before!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spore-creatures-nintendo-ds', 'Spore Creatures', 'Spore', '2008-09-07', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v61.jpg', 'Spore Creatures is the sequel to Spore Origins, featuring gameplay similar to the creature stage from the original PC game Spore!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spore-hero-arena-nintendo-ds', 'Spore Hero Arena', 'Spore', '2009-10-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coalt4.jpg', 'An evil force is wreaking havoc across the galaxy, and only you can stop it! For the first time ever, build fully 3D Spore creatures on your Nintendo DS and take them into battle. Explore planets all over the galaxy, fight creatures, and gather parts to customize and enhance your mighty hero. Compete in a variety of arena battles against dangerous enemies in your quest to become the Galactic Champion and save the galaxy!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-shadow-legacy-nintendo-ds', 'Spyro: Shadow Legacy', 'Spyro', '2005-10-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ys7.jpg', 'Spyro Shadow Legacy introduces role playing elements to the Dragon Realms, offering Spyro fans an "RPG light" experience with all new gameplay features. By fighting and defeating creatures in the game, players earn experience points that improve Spyro''s strength and abilities. This RPG element allows players to use their experience to build Spyro’s new magical powers and martial arts combat abilities as the game progresses.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-a-new-beginning-nintendo-ds', 'The Legend of Spyro: A New Beginning', 'Spyro', '2006-10-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86aa.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-the-eternal-night-nintendo-ds', 'The Legend of Spyro: The Eternal Night', 'Spyro', '2007-10-02', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a9.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-dawn-of-the-dragon-nintendo-ds', 'The Legend of Spyro: Dawn of the Dragon', 'Spyro', '2008-10-21', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a8.jpg', NULL, 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-command-nintendo-ds', 'Star Fox Command', 'Star Fox', '2006-08-28', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8iyy.jpg', 'Star Fox Command lets you hop into your fight through a unique branching storyline of missions, all rendered in gorgeous 3-D. This game brings a whole new strategic element to the series, with a commander''s view of the mission. Using the touch screen, players can draw the routes they and their teammates will take. Battle the enemies they encounter as they take over bases and strategically advance across the map. Players can also blow their friends out of the sky, as they dogfight 8 players over a local wireless connection -- or take on 4 players from around the world on Nintendo Wi-Fi Connection.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-iii-revenge-of-the-sith-nintendo-ds', 'Star Wars: Episode III – Revenge of the Sith', 'Star Wars', '2005-05-04', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3sjo.jpg', 'The Clone Wars continue to rage between the Republic and the Separatists. Supreme Chancellor Palpatine has been taken hostage, and Obi-Wan, together with Anakin, must rescue him! The Star Wars Episode III: Revenge of the Sith games for the Game Boy Advance and Nintendo DS systems allow players to experience the stunning Jedi action of the movie. Developed by Ubisoft''s Montreal studio, each version leverages the strengths of its handheld platform to produce the ultimate Jedi action experience. The control of multiple heroes, devastating Force powers, and never-before-seen locations are just a few of the elements in store!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-lethal-alliance-nintendo-ds', 'Star Wars: Lethal Alliance', 'Star Wars', '2006-12-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qmf.jpg', 'To capture the plans for the Death Star and make it back home safely, players must guide Rianna Saren and her trusty droid Zeeo through a variety of Star Wars environments while avoiding or attacking Imperial soldiers and their allies. Rianna is gifted in combat and Zeeo comes in handy for unlocking security doors, reaching high places, and bypassing dangerous areas. The story of Star Wars: Lethal Alliance unfolds between Episode III and Episode IV, when Princess Leia recruits the duo to steal the plans so the Rebels may learn any weaknesses in the massive weapon. Players will explore such areas as Tatooine, Despayre, Alderaan, and Danuta while interacting with characters including Boba Fett, Darth Vader, and Kyle Katarn. The PSP features various mini-games and multiplayer Twil''lek vs. Twi''lek combat over a wireless network.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-nintendo-ds', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-jedi-alliance-nintendo-ds', 'Star Wars: The Clone Wars – Jedi Alliance', 'Star Wars', '2008-11-11', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2der.jpg', 'Star Wars: The Clone Wars - Jedi Alliance is an action/adventure game developed and published by LucasArts.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-nintendo-ds', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-elite-squadron-nintendo-ds', 'Star Wars Battlefront: Elite Squadron', 'Star Wars', '2009-11-03', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal7m.jpg', 'Star Wars Battlefront: Elite Squadron is the fourth installment in the Star Wars: Battlefront series, and the second handheld exclusive, after Star Wars Battlefront: Renegade Squadron. Nintendo DS version of Elite Squadron uses an isometric view, similar to a modern dungeon crawler. Unlike classic Battlefront games, Instant Action is played with only four players, usually one from each faction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-ii-nintendo-ds', 'Star Wars: The Force Unleashed II', 'Star Wars', '2010-10-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xw.jpg', 'The Star Wars Saga continues with Star Wars: The Force Unleashed II, the highly anticipated sequel to the fastest-selling Star Wars game ever created, which has sold more than seven million copies worldwide.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-nintendo-ds', 'Harvest Moon DS', 'Story of Seasons', '2006-09-12', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xm4.jpg', 'Help to save the Harvest Goddess, who has become trapped in another world, in the first game of the farm-simulation franchise to appear on the Nintendo DS.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-cute-nintendo-ds', 'Harvest Moon DS Cute', 'Story of Seasons', '2008-03-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl9.jpg', 'Harvest Moon DS Cute is the female version of Harvest Moon DS for the Nintendo DS. It was published and developed by Marvelous Interactive Inc., and first released in Japan on December 8, 2005. Harvest Moon DS Cute replaces the male protagonist from Harvest Moon DS with a female character; players may choose either Pony from Harvest Moon: Another Wonderful Life or Claire from Harvest Moon: More Friends of Mineral Town. The Japanese version introduced a system not present in the North American version known as the "Best Friend" system. This allowed the player to essentially marry any of the bachelorettes from Harvest Moon DS, as well as the bachelors.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-island-of-happiness-nintendo-ds', 'Harvest Moon DS: Island of Happiness', 'Story of Seasons', '2008-08-26', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkt.jpg', 'In Harvest Moon: Island of Happiness you develop the island by growing crops and taking care of animals and expanding your farm. The better you do, the more the island will grow, and the more others will start to move onto the island. Though it was not your original dream, now is you chance to create your very own paradise!', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-sunshine-islands-nintendo-ds', 'Harvest Moon DS: Sunshine Islands', 'Story of Seasons', '2009-11-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xjw.jpg', 'Gameplay is split into four 30-day seasons to make up a year. Each day takes place over approximately fifteen minutes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-grand-bazaar-nintendo-ds', 'Harvest Moon DS: Grand Bazaar', 'Story of Seasons', '2010-08-24', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xky.jpg', 'Harvest Moon DS: Grand Bazaar is a video game released on December 18, 2008 by Marvelous Interactive in Japan, and released on August 24, 2010 by Natsume in North America. It was also released in Europe on September 30, 2011 by Rising Star Games.[2] The game is the nineteenth game in the Story of Seasons series and the fifth game in the series for the Nintendo DS.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-ds-the-tale-of-two-towns-nintendo-ds', 'Harvest Moon DS: The Tale of Two Towns', 'Story of Seasons', '2011-09-20', 'Nintendo DS', 0, 0, NULL, NULL, NULL, NULL, 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-touch-roll-nintendo-ds', 'Super Monkey Ball Touch & Roll', 'Super Monkey Ball', '2006-02-21', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3s7y.jpg', 'Super Monkey Ball Touch & Roll brings the Super Monkey Ball series to the DS. Featuring a similar selection of party games and 50 different characters, this newest entry builds on the previous versions of the game. Ten different worlds will challenge your monkey-controlling skills. Also, touch-screen controls and wireless play have been implemented to take advantage of the DS platform.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metcha-taiko-no-tatsujin-ds-7-tsu-no-shima-no-daibouken-nintendo-ds', 'Metcha! Taiko no Tatsujin DS - 7-tsu no Shima no Daibouken', 'Taiko no Tatsujin', '2008-04-24', 'Nintendo DS', 1, 0, NULL, NULL, NULL, NULL, 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-ds-nintendo-ds', 'Tetris DS', 'Tetris', '2006-03-20', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65xn.jpg', 'THQ''s Tetris DS was under development for months and appeared to be nearing completion, but legal issues between THQ and The Tetris Company arose, leading to this version being cancelled.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-party-deluxe-nintendo-ds', 'Tetris Party Deluxe', 'Tetris', '2010-05-25', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cyk.jpg', 'Tetris Party makes its way to the Nintendo DS and Wii. Deluxe features six new game modes and four new enhanced modes of play.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-chaos-theory-nintendo-ds', 'Tom Clancy''s Splinter Cell: Chaos Theory', 'Tom Clancy''s Splinter Cell', '2005-06-28', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rb.jpg', 'Tom Clancy''s Splinter Cell: Chaos Theory is the mobile version of the console game of the same name and the fourth mobile game in the series. Like the previous games in the series it is a stealth based platform game played from a side view perspective and has similar gameplay. The player once again controls Sam Fisher who has to prevent terrorists from crashing the global stock markets and overthrow the world''s governments.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-nintendo-ds', 'Tomb Raider: Legend', 'Tomb Raider', '2006-11-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-underworld-nintendo-ds', 'Tomb Raider: Underworld', 'Tomb Raider', '2008-11-18', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voc.jpg', 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of challenge and choice.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viva-pi-ata-pocket-paradise-nintendo-ds', 'Viva Piñata: Pocket Paradise', 'Viva Piñata', '2008-09-08', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mv6.jpg', 'In Viva Pinata: Pocket Paradise, players will inherit a neglected garden on Pinata Island and turn it into a pinata paradise by tending to all aspects of cleaning the garden, growing and maintaining vegetation, caring for and breeding pinatas, as well as attracting new pinata species. The game features seven all-new pinata species, each with new requirements, houses and unique cut scenes. Viva Pinata: Pocket Paradise also includes twelve full motion video clips that serve as tutorial levels within the game. The videos feature the stars of the Fox 4Kids Viva Pinata TV series, including Hudson Horstashio, Fergy Fudgehog and Paulie Pretztail. The brand-new Playground mode allows players to create a lush garden full of exciting and exotic pinatas in a very short amount of time. In addition, certain rare pinatas can only be acquired by using the Nintendo DS local wireless connection, where players can transfer items from their garden to a friend''s garden.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-master-of-disguise-nintendo-ds', 'Wario: Master of Disguise', 'Wario', '2007-03-05', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5435.jpg', 'The world''s most low-down and ornery garlic-lover never lets a get-rich quick scheme pass him by. Wario: Master of Disguise opens with our money-mad hero taking a break from being a shady software impresario to watch a TV show about a master thief. Working himself up into a lather of jealousy, Wario leaps through the screen and embarks on his own glamorous globe-trotting career as a thief.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-touched-nintendo-ds', 'WarioWare: Touched!', 'WarioWare', '2005-02-14', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b7s.jpg', 'Wario makes his debut on the Nintendo DS with hundreds of all-new minigames. Now you must complete your goals by using the touch screen and a stylus. Tap, scratch, and rub your stylus on the touch screen to play minigames that have you do everything from milking a cow and drawing a mustache to hurling stars at evil ninjas. You can even play some minigames by blowing into the DS''s built-in microphone. The more minigames you clear, the more characters and items you unlock.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-d-i-y-nintendo-ds', 'WarioWare D.I.Y.', 'WarioWare', '2010-03-28', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8huz.jpg', 'This game, which puts the concept of user-generated content on center stage, allows players to design their own micro-games from scratch. Every element, such as the characters, the environment, the actions and even the purpose of the micro-game itself, is controlled entirely by the player. Players will then be able to share their completed micro-games with other WarioWare D.I.Y. owners.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-world-ends-with-you-nintendo-ds', 'The World Ends with You', 'The World Ends with You', '2008-04-22', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n67.jpg', 'In the game, Neku Sakuraba and his allies are forced to participate in a game that will determine their fate. The battle system uses many of the unique features of the Nintendo DS, including combat that takes place on both screens, and attacks performed by certain motions on the touchscreen or by shouting into the microphone. Elements of Japanese youth culture, such as fashion, food, and cell phones, are key aspects of the missions.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-touch-go-nintendo-ds', 'Yoshi Touch & Go', 'Yoshi', '2005-03-14', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hg9.jpg', 'Yoshi and Baby Mario are back together at long last, and it''ll take a steady hand to guide them through their latest adventure. As Yoshi charges across the island, you use the stylus to throw eggs at enemies, lead him to egg-replenishing fruit, and make him jump over danger. On vertical-scrolling levels, you use the stylus to draw clouds to encircle enemies, throw coins, and guide Baby Mario through the dangerous skies. Take on the single-player challenges or compete against a friend using the wireless link of the Nintendo DS.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-island-ds-nintendo-ds', 'Yoshi''s Island DS', 'Yoshi', '2006-11-13', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4wgl.jpg', 'Yoshi''s Island DS is a 2D platformer for the Nintendo DS in the Yoshi''s Island series. It is the sequel to Super Mario World 2: Yoshi''s Island, where Kamek and the Toadies have kidnapped all the babies in the world in search for the star children, a group of seven babies who possess powerful stars in their hearts. While the game is heavily derivative from Super Mario World 2: Yoshi''s Island, including general gameplay, themes, and graphics, the game primarily differentiates itself from its predecessor by taking advantage of the Nintendo DS''s dual screen to display levels while introducing multiple babies to carry on Yoshi''s back, who all have special abilities that are required to complete levels.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('999-nine-hours-nine-persons-nine-doors-nintendo-ds', '999: Nine Hours, Nine Persons, Nine Doors', 'Zero Escape', '2010-11-16', 'Nintendo DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hsz.jpg', 'The game is a murder mystery visual novel with a heavy story focus that requires multiple playthroughs to figure out and involves puzzle rooms used to progress through the story with dialogue choices to be made inbetween them.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoo-tycoon-ds-nintendo-ds', 'Zoo Tycoon DS', 'Zoo Tycoon', '2005-10-10', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22u7.jpg', 'Zoo Tycoon is a business simulation developed by Blue Fang Games and released by Microsoft Game Studios. It is a tycoon game in which the player must run a zoo and try to make a profit. Although first released for Microsoft Windows and Macintosh in 2001, it was ported to the Nintendo DS in 2005. It was followed by two expansion packs, Zoo Tycoon: Dinosaur Digs and Zoo Tycoon: Marine Mania, which were released in 2002, as well as a sequel, Zoo Tycoon 2, released in 2004.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoo-tycoon-2-ds-nintendo-ds', 'Zoo Tycoon 2 DS', 'Zoo Tycoon', '2008-02-05', 'Nintendo DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7g2l.jpg', 'In Zoo Tycoon 2 DS, the player edits and builds the zoo in a main mode resembling the original Zoo Tycoon. Zookeeper mode is more like Zoo Tycoon 2 graphics-wise and has five mini-games: petting, cleaning animal waste, feeding, washing, and healing animals.', 'NA', 21);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battalion-wars-2-wii', 'Battalion Wars 2', 'Advance Wars', '2007-10-29', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sat.jpg', 'This sequel to Battalion Wars plays much like its predecessor, blending real-time strategy with third-person shooting. The game''s plot traces decades of war among six factions (Solar Empire, Western Frontier, Anglo Isles, Iron Legion, Tundran Territories, Xylvania), and unfolds through contemporary missions that advance the conflict and flashback missions that reveal its history.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-city-folk-wii', 'Animal Crossing: City Folk', 'Animal Crossing', '2008-11-16', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaaw.jpg', 'Step into a living, breathing world where days and seasons pass in real time and your destiny is yours to create.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bit-trip-complete-wii', 'Bit.Trip Complete', 'Bit.Trip', '2011-09-13', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86bm.jpg', 'BIT.TRIP COMPLETE is a compilation of all 6 award-winning BIT.TRIPgames: BEAT, CORE, VOID, RUNNER, FATE, and FLUX! This COMPLETE version includes a video gallery with more than 25 clips telling the story of CommanderVideo, an image gallery with concept art, and an audio gallery featuring fan remixes, original songs, and demos of BIT.TRIP songs.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-land-wii', 'Bomberman Land', 'Bomberman', '2008-01-29', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87mg.jpg', 'Bomberman Land is a theme park filled with people and different attractions. As in top-down RPG games, the player controls a character who can interact with the NPCs and objects on the map. Various spots give access to the attractions, in the form of mini-games. In some games, the player must pick-up sheep and lock them out of the field, complete jigsaw puzzles, look at equations and answer if they are true or false, etc. Completing various tasks will reward the player with numbered coupons that give access to new areas of the theme park.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-judgment-wii', 'Castlevania Judgment', 'Castlevania', '2008-11-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z4e.jpg', 'Castlevania Judgement is a first in many: it''s the first Castlevania beat''em up. It''s also the first time old friends of the Belmont clan meet together in a full 3D environment.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-wii', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-04', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-mind-over-mutant-wii', 'Crash: Mind over Mutant', 'Crash Bandicoot', '2008-10-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3n2m.jpg', 'Crash: Mind Over Mutant is the sequel to Crash of the Titans and the seventh Crash Bandicoot series game. The game uses many of the same mechanics as its predecessor with a few changes. Rather than having twenty linear platforming levels to complete in sequence, Mind Over Mutant features eight distinct locations for Crash to explore and travel between as the story progresses. The player can complete missions given by non-playable characters and discover collectibles through the levels.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-brave-and-the-bold-the-videogame-wii', 'Batman: The Brave and the Bold – The Videogame', 'DC', '2010-09-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hfo.jpg', 'The Brave and the Bold the Videogame fully immerses fans into the vivid animated world of the successful TV series where kids can play as Batman or together with family and friends in two-player co-op mode. Players can choose from iconic characters Robin, Green Lantern, Blue Beetle, along with drop-in heroes such as Aquaman to help solve puzzles and fight foes.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('green-lantern-rise-of-the-manhunters-wii', 'Green Lantern: Rise of the Manhunters', 'DC', '2011-06-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ky.jpg', 'Green Lantern: Rise of the Manhunters is an action video game, the first based on DC Comics'' Green Lantern (Hal Jordan). The game is a tie-in/sequel to the film Green Lantern, which opened in theatres on June 17, 2011. The game features 3D visuals on the PlayStation 3 and Xbox 360, providing TriOviz Inficolor 3D for standard televisions and stereoscopic 3D for dedicated 3DTVs.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-chop-till-you-drop-wii', 'Dead Rising: Chop Till You Drop', 'Dead Rising', '2009-02-24', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4a2a.jpg', 'Dead Rising: Chop Till you Drop is an adaptation of Dead Rising, for the Wii. The freelance photojournalist Frank West investigates a zombie outbreak in Willamette, Colorado. He has three days at the mall to rescue survivors and solve the case before the helicopter that dropped him off returns.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-extraction-wii', 'Dead Space: Extraction', 'Dead Space', '2009-09-29', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w51.jpg', 'Dead Space Extraction tells the untold story of the Aegis VII Colony through a handful of survivors battling to reach the orbiting USG Ishimura amidst a horrific infection and the initial invasion by a violent alien race known as Necromorphs. As these survivors'' allies mysteriously fall victim to dementia, it becomes clear that protecting a young girl granting them a bizarre immunity may be their only hope for survival in a struggle that could have implications for all of humanity.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-wii', 'Disney Infinity', 'Disney Infinity', '2013-08-18', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-barrel-blast-wii', 'Donkey Kong Barrel Blast', 'Donkey Kong', '2007-10-08', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wfc.jpg', 'Donkey Kong Barrel Blast is a racing game where the player can handle the selected character using the Wii Remote and Nunchuk, replacing the DK Bongos that initially were to be used. To speed the player must shake the Wii Remote and Nunchuk simultaneously, lift them to jump and use the motion sensor to beat rivals and obstacles and using items, while the character will be guided by the route of the tracks, including curves of automatic. Players can learn to race at Cranky''s flight school where Cranky gives 8 lessons on how to play the game, acceleration, use of elements and Wild Move.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-jungle-beat-wii', 'Donkey Kong Jungle Beat', 'Donkey Kong', '2009-05-04', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5y6u.jpg', 'The highly rated Nintendo GameCube game, created by the same team that developed Super Mario Galaxy, returns with enhanced motion controls and new surprises.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-returns-wii', 'Donkey Kong Country Returns', 'Donkey Kong', '2010-11-21', 'Wii', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wf4.jpg', 'Under the influence of a group of evil Tikis, the animals of Donkey Kong Island have raided Donkey Kong''s banana hoard and stolen his stash of bananas - and being an ape of large appetites he understandably wants them back. Good thing that you are along for the ride. With Donkey Kong Country Returns, Retro Studios brings Donkey Kong back to a banana and platforming hungry public in a new side-scrolling adventure with familiar characters and new levels that reignite the passion players had for the Super NES original and all things Donkey Kong.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-swords-wii', 'Dragon Quest Swords', 'Dragon Quest', '2008-02-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7zey.jpg', 'Developed from the ground up to take advantage of the Wii and its motion-sensing technology, Dragon Quest Swords: The Masked Queen and the Tower of Mirrors is set to slice its way onto Nintendo''s next-generation platform. This exclusive title utilizes the Wii''s motion-sensing controls as players use the Wii Remote to slash, parry and blast their way through a land filled with trademark Dragon Quest foes. Developed with both longtime fans and casual players in mind, Dragon Quest Swords: The Masked Queen and the Tower of Mirrors is poised to take video gaming to an entirely new level of fun and interaction.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-trilogy-wii', 'Dragon''s Lair Trilogy', 'Dragon''s Lair', '2010-10-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co249y.jpg', 'Dragon''s Lair Trilogy (includes Dragon''s Lair, Dragon''s Lair II: Time Warp, and Space Ace.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-wii', 'Epic Mickey', 'Epic Mickey', '2010-11-30', 'Wii', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6omo.jpg', 'Disney Epic Mickey is an action-adventure platforming game for Wii console that sends Mickey Mouse on an epic journey of creativity and discovery. As Mickey, the player is propelled into Wasteland, an alternate world made up of Disney''s forgotten creative efforts, and is given the power to wield paint and paint thinner to dynamically change the world while determining Mickey''s path to becoming an epic hero.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-2-the-power-of-two-wii', 'Epic Mickey 2: The Power of Two', 'Epic Mickey', '2012-11-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nhy.jpg', 'Unleash the power of the brush in an all new co-op adventure. Join Mickey and Oswald in an epic battle to save the magical world of Wasteland and change it forever. Interact with your favorite characters like never before in the most heroic adventure yet.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('excite-truck-wii', 'Excite Truck', 'Excite', '2006-11-19', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2auh.jpg', 'In the grand and classic racing tradition of Excitebike, get ready for a big-air experience like no other! Players rocket their trucks across dynamically changing terrain in this nitrous-injected, high-flying racer for speed junkies. Showing the Wii Remote controller''s versatility, players tilt the controller on its side to turn it into a wireless steering wheel!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('excitebots-trick-racing-wii', 'Excitebots: Trick Racing', 'Excite', '2009-04-20', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ggz.jpg', 'Excitebots is controlled with the Wii remote horizontally or optionally with the Wii Wheel. Most of the games are played on courses large in size with many opportunities to take meandering paths. The 25 different courses offered are modeled after real locations on Earth. Because of the size of each course, most races are two laps long and offer opportunities to gain massive altitude, perform various maneuvers, and obtain various items.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-vengeance-wii', 'Far Cry Vengeance', 'Far Cry', '2006-12-12', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xei.jpg', 'The game takes full advantage of the Wii Remote and its Nunchuk attachment. For example, the player can make the character jump by lifting the nunchuk. Weapons are aimed by pointing the Wii Remote at the screen, and melee attacks are carried out by making a slashing motion with it. The zoom on sniper rifles will similarly be controlled by moving the Wii Remote towards the television. Split screen Chaos mode (standard deathmatch) is included.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-fables-chocobo-s-dungeon-wii', 'Final Fantasy Fables: Chocobo''s Dungeon', 'Final Fantasy', '2008-07-08', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6r9w.jpg', 'Randomly generated dungeons and turn-based battles are highlighted in the second Wii title set in the Final Fantasy universe. A yellow, bird-like Chocobo migrates from a successful stint on the DS handheld to console in this exclusive release, featuring the distinctive artwork of Toshiyuki Itahana (Final Fantasy: Crystal Chronicles, Final Fantasy Fables: Chocobo Tales). You must retrieve, of all things, lost "memories" by delving into dungeons created by a mysterious lad named Raffaello. Succeed and the town''s populace just might remember who and where they are.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-crystal-chronicles-echoes-of-time-wii', 'Final Fantasy Crystal Chronicles: Echoes of Time', 'Final Fantasy', '2009-03-24', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26f0.jpg', 'Final Fantasy Crystal Chronicles: Echoes of Time is an installment in the Final Fantasy Crystal Chronicles series. It is the first Final Fantasy Crystal Chronicles game that allows players to play together online and it allows players who own a Nintendo Wii or Nintendo DS to play together at the same time using the Pollux Engine, an Engine created by Square Enix.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-crystal-chronicles-the-crystal-bearers-wii', 'Final Fantasy Crystal Chronicles: The Crystal Bearers', 'Final Fantasy', '2009-12-26', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vjl.jpg', 'A thousand years have passed since the events of the original Final Fantasy: Crystal Chronicles. The destruction of the Yuke Crystal during the Great War, with the Yuke Tribe suffering apparent annihilation, had at last brought the victorious Lilties dominion over the world as they bring it into a new age of science and reason through machines called "crystal reactors," with the use of magic outlawed and rule over the Clavats and few Selkies who comply to the new order. In this new era of imbalance exists a rare breed of powerful beings called "crystal bearers", whose seemingly magical abilities have led them to be feared and scorned by the public.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-radiant-dawn-wii', 'Fire Emblem: Radiant Dawn', 'Fire Emblem', '2007-11-05', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb09.jpg', 'Radiant Dawn is a turn-based tactics RPG and a direct sequel, 3 years have passed, to the game "Fire Emblem: Path of Radiance" for the Nintendo GameCube. It features new magic, class upgrades, weapons, and a reworked forging system.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fortune-street-wii', 'Fortune Street', NULL, '2011-12-05', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dvu.jpg', 'Get on board, corner the market & make a fortune! Players become familiar characters from the Nintendo and Dragon Quest universes in a board game that challenges them to play the real estate and stock markets wisely to win. Players race around the board trying to accumulate wealth and hit a target value while buying, selling and trading property with friends and family to see who can be the first to cash out. What appears at first to be a simple property-buying board game offers multiple levels of money-maximizing opportunity.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-epic-yarn-wii', 'Kirby''s Epic Yarn', 'Kirby', '2010-10-17', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w9w.jpg', 'While walking through Dream Land, Kirby discovers a tomato and decides to eat it. Yin-Yarn, the evil sorceror who possessed the tomato (revealed to be a Metamato), appears and magically banishes Kirby into Patch Land, a world completely made of fabric, via the sock carried around his neck. In Patch Land, Kirby''s body transforms into yarn, rendering his power to inhale useless. Instead, Kirby is granted the ability to transform by the magic of the Metamato, which he uses to rescue a boy being attacked by a monster. The boy, named Prince Fluff, explains that Yin-Yarn has separated Patch Land into pieces, which was tied together by magic yarn. Kirby decides to help Prince Fluff collect all seven pieces of the yarn and restore Patch Land.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-return-to-dream-land-wii', 'Kirby''s Return to Dream Land', 'Kirby', '2011-10-24', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba1d.jpg', 'Kirby and his friends are back in an adventure designed to satisfy longtime Kirby fans and beginners alike. When an alien spaceship crashes in the otherwise peaceful realm of Pop Star, its pieces are scattered throughout the land. Players must guide Kirby as he retrieves the ship’s parts and helps the aliens return to their home planet. This time, however, he’s not alone. At any time, up to three more players can join in the fun and play as Meta Knight, King Dedede and Waddle Dee to help Kirby in his quest.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-dream-collection-wii', 'Kirby''s Dream Collection', 'Kirby', '2012-09-16', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yep.jpg', 'Kirby''s Dream Collection Special Edition is an anthology disc celebrating the 20th anniversary of the Kirby series, which took place on April 27, 2012. The game was released in Japan and in North America, but not in Europe. Kirby''s Dream Collection includes six playable Kirby titles originally released on the Game Boy, NES, SNES and Nintendo 64. In addition to the GameCube Controller and Classic Controller, all six games have been calibrated for use with the Wii Remote turned horizontally.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-twilight-princess-wii', 'The Legend of Zelda: Twilight Princess', 'The Legend of Zelda', '2006-11-19', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w1h.jpg', 'The Legend of Zelda: Twilight Princess was initially developed with the Nintendo GameCube in mind, but ended up receiving a Wii port when it was released to promote the new console. This version has motion control compatibility for the sword and pointer controls for the menus, the bow and the boomerang. This version of the game has a completely inverted map and locations when comparing with the GameCube release. The change in layout was meant to adapt Link''s usually left-handed design to right-handed people, given the motion controls.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('link-s-crossbow-training-wii', 'Link''s Crossbow Training', 'The Legend of Zelda', '2007-11-19', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ocw.jpg', 'Link returns from The Legend of Zelda: Twilight Princess to pick up the Wii Zapper and take aim at a host of targets in this shooting-gallery-style game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-skyward-sword-wii', 'The Legend of Zelda: Skyward Sword', 'The Legend of Zelda', '2011-11-20', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wrj.jpg', 'The Legend of Zelda: Skyward Sword is the first Zelda game created specifically with the Wii in mind. The game makes use of the Wii MotionPlus peripheral for sword fighting, with a revised Wii Remote pointing system used for targeting. Skyward Sword is structured very similar to previous Zelda games, as you travel through an overworld in search of temples to visit and once in you solve a series of puzzles before fighting a boss at the end and receive the next bit of plot. The biggest change is that the overworld is more focused on puzzles with only a handful of action.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-heroes-wii', 'Bionicle Heroes', 'Lego', '2007-04-24', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525j.jpg', 'Bionicle Heroes DS is a classic first-person shooter. As a nameless Matoran, you''ll travel across 25 themed levels (including jungles, lava-worlds, ancient underground temples) discovering new weapons and new robotic foes to blast apart. Along the way, you''ll use the masks'' powers to survive the hostile environments as well as collect gears and robot parts to solve simple puzzles by assembling LEGO-style ramps, bridges, and doorways.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-complete-saga-wii', 'Lego Star Wars: The Complete Saga', 'Lego', '2007-11-06', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrr.jpg', 'Play through a fun Star Wars galaxy that combines the endless customization of LEGO with the epic story from all six episodes of Star Wars. This is the definitive LEGO Star Wars comprising the first two games and expanding them with new characters, enhanced visuals, and more bonus levels than you can shake a lightsaber at.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-wii', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-wii', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-rock-band-wii', 'Lego Rock Band', 'Lego', '2009-11-03', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wpb.jpg', 'LEGO Rock Band is a blending of Rock Band and LEGO series. Players get to start a band and hire band members who will play with them. Just like with real Lego, players can mix and match bodies, torsos, legs and heads to create a character any way they want. The main game has players touring around the world at various locations, like the original Rock Band games. Unlike Rock Band however, LEGO Rock Band also has special levels where you must perform outrageous tasks such as fighting an octopus or demolishing a building using your rock concert. As players make their way through the song lists, they earn "Studs", the game''s currency. Studs can be used to purchase Lego items to decorate your Rock Den, hire new staff, buy new clothes or instruments.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-2-the-adventure-continues-wii', 'Lego Indiana Jones 2: The Adventure Continues', 'Lego', '2009-11-17', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6up6.jpg', 'LEGO Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO fashion, get creative and build your own levels to play with friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-1-4-wii', 'Lego Harry Potter: Years 1–4', 'Lego', '2010-06-29', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65lz.jpg', 'LEGO Harry Potter: Years 1-4 will give gamers the chance to experience the magic and adventure of Harry Potter in a uniquely LEGO way. Playing as Harry Potter, Ron Weasley and Hermione Granger, as well as more than 100 other favorite characters, gamers will have the opportunity to attend lessons, cast spells, mix potions, fly on broomsticks and complete tasks to earn rewards. Throughout the game, players will also have the freedom to explore iconic settings from the wizarding world including Hogwarts castle, Diagon Alley, the Forbidden Forest and the village of Hogsmeade.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-wii', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-wii', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-wii', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-wii', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-wii', 'Lego The Lord of the Rings', 'Lego', '2012-11-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-galaxy-wii', 'Super Mario Galaxy', 'Mario', '2007-11-12', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavv6.jpg', 'Travel the stars with Mario in enhanced versions of these beloved adventures.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-mario-bros-wii-wii', 'New Super Mario Bros. Wii', 'Mario', '2009-11-15', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobrmo.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-galaxy-2-wii', 'Super Mario Galaxy 2', 'Mario', '2010-05-23', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakzq.jpg', 'A short troll hack for Mario 64 based on the Bart Simpson concussion meme', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-all-stars-25th-anniversary-edition-wii', 'Super Mario All-Stars 25th Anniversary Edition', 'Mario', '2010-12-12', 'Wii', 1, 0, NULL, NULL, NULL, NULL, 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-olympic-games-wii', 'Mario & Sonic at the Olympic Games', 'Mario & Sonic at the Olympic Games', '2007-11-06', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wvp.jpg', 'Mario & Sonic on the Wii is a collection of twenty-four events based on the Olympic Games. Players can assume the role of a Nintendo or Sega character while competing against the others in these events. Players use the Wii Remote to mimic actions performed in real life sports, such as swinging a paddle.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-olympic-winter-games-wii', 'Mario & Sonic at the Olympic Winter Games', 'Mario & Sonic at the Olympic Games', '2009-10-13', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wvr.jpg', 'Mario & Sonic at the Olympic Winter Games is a sports game with the official license of the 2010 Winter Olympic Games and a crossover franchise from the Mario and the Sonic universe similar to Mario & Sonic at the Olympic Games. It takes place at the Vancouver Winter Olympics of 2010. Like the previous game, the 27 events are presented as motion-based mini-games. Aside from the main events there are a series of Dream Events that have enhanced features and visuals. Some of the events can optionally be played using the balance board peripheral. Events include for instance skiing, snowboarding, bobsleigh, ice hockey, figure skating and more. The games can be played individually or in a festival mode that spans 17 days.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-london-2012-olympic-games-wii', 'Mario & Sonic at the London 2012 Olympic Games', 'Mario & Sonic at the Olympic Games', '2011-11-15', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22wi.jpg', 'The 3DS version of Mario & Sonic at the London 2012 Olympic Games has some key differences from the Wii version. While it shares many events, it has more. It also features an exclusive Story Mode. The protagonists from the Mario and Sonic series team up to defeat Bowser and Dr. Eggman, who, along with their underlings, have taken over London. There are different parts to the story, depending on the character played. The player must win events against the antagonists. Playable characters consist of all 20 playable characters from the previous installment''s Nintendo DS version, and are split into five groups of four.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-super-sluggers-wii', 'Mario Super Sluggers', 'Mario Baseball', '2008-08-25', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2235.jpg', 'Mario Super Sluggers, the sequel to Mario Superstar Baseball, continues the arcade-style gameplay of Mario sports games. Mario and friends are invited to the Baseball Kingdom to play games against each other. When Bowser hears this, he immediately interrupts the party.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-wii-wii', 'Mario Kart Wii', 'Mario Kart', '2008-04-27', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ycm.jpg', 'CTGP Revolution is a mod for Mario Kart Wii which adds many new custom tracks and cups to the game.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-8-wii', 'Mario Party 8', 'Mario Party', '2007-05-29', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p83.jpg', 'The Mario Party 8 dice game is an Adobe Flash game published by extra toxic as part of its Nintendo advent calendar microsite. The game was made to promote Mario Party 8.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-9-wii', 'Mario Party 9', 'Mario Party', '2012-03-11', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2241.jpg', 'Grab your friends and family and captain the crew to victory!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sports-mix-wii', 'Mario Sports Mix', NULL, '2011-02-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co223k.jpg', 'The games include volleyball, hockey (both field and ice), dodgeball, and basketball in the vein of the two companies'' earlier collaboration, Mario Hoops 3 on 3. There are power-up items which give advantages to the team that attains them. Each game has an Exhibition mode, in which up to four human players compete in individual matches, and Tournament mode, where up to three players play matches in a tournament structure, with modes of difficulty named Mushroom, Flower and Star.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-strikers-charged-wii', 'Mario Strikers Charged', 'Mario Strikers', '2007-07-30', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co220c.jpg', 'Mario Strikers Charged is a Mario soccer Wii game and the sequel to the Nintendo GameCube game Super Mario Strikers. Up to four players can participate in this game as play soccer, attempting to kick the ball into another opponent''s goal. The soccer in this game, however, has several differences than the real soccer, such as the ability to tackle other players with a minimal penalty, using Mario-themed items to give players an advantage over their opponents, and playing with stage hazards effectively. This game places a higher emphasis on individual character attributes compared to its precedent, by not only assigning stats, but by also giving team captains a unique Super Ability and the Mega Strike, an opportunity to score up to six goals. Another introduced mechanic is the power level of the ball: indicated by the color of the glow, the shots of the ball become more quick and powerful the more active it is, thus making it easier to score goals with.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-power-tennis-wii', 'Mario Power Tennis', 'Mario Tennis', '2009-03-09', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21z0.jpg', 'Mario Power Tennis features variations of tennis matches consisting of characters, courts, and scenarios based on the Mario series. The range of courts includes the standard three types of tennis court, but consists predominantly of those themed upon games in the Mario series, known as "Gimmick" courts. As well as adopting the style aesthetically, these feature thematic elements that influence how the match will be played on that surface, such as the ghosts in the Luigi''s Mansion court, which hinder movement when the character comes into physical contact with them.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-wii', 'Marvel: Ultimate Alliance', 'Marvel', '2006-11-14', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-wii', 'Spider-Man 3', 'Marvel', '2007-05-04', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-rise-of-the-silver-surfer-wii', 'Fantastic Four: Rise of the Silver Surfer', 'Marvel', '2007-06-15', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x77.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-friend-or-foe-wii', 'Spider-Man: Friend or Foe', 'Marvel', '2007-10-02', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h33.jpg', 'Defeat Spider-Man’s most famous enemies, like Venom, Green Goblin, and Doc Ock to add them to your epic array of playable sidekicks in this movie trilogy inspired adventure. Experience ground-breaking Co-operative Multiplayer, as Spider-Man or a sidekick, in exotic spots around the globe, including Tokyo, Egypt and Nepal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-wii', 'Iron Man', 'Marvel', '2008-05-02', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-wii', 'The Incredible Hulk', 'Marvel', '2008-06-05', 'Wii', 0, 0, NULL, NULL, NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-wii', 'Spider-Man: Web of Shadows', 'Marvel', '2008-10-21', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ujz.jpg', 'Spider-Man: Web of Shadows is a video game title encompassing three versions: a full-3D action game for Microsoft Windows, PlayStation 3, Wii, and Xbox 360; a 2.5D sidescrolling beat em up action game for the PlayStation Portable and PlayStation 2 (called Amazing Allies Edition), and a 2.5D side-scrolling brawler/platformer for the Nintendo DS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-wii', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-wii', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-15', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-wii', 'Marvel Super Hero Squad', 'Marvel', '2009-10-20', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e7b.jpg', 'Marvel Super Hero Squad is an action beat-em-up game for one to four players that is based on the animated Marvel TV series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-2-wii', 'Iron Man 2', 'Marvel', '2010-05-04', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sxm.jpg', 'This is the Wii version of Iron Man 2, an action-adventure video game loosely based on the 2010 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-shattered-dimensions-wii', 'Spider-Man: Shattered Dimensions', 'Marvel', '2010-09-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zpp.jpg', 'Spider-Man: Shattered Dimensions is a thrilling action-packed adventure set in four dramatically different universes from legendary Spider-Man lore, each with a distinct Spider-Man armed with unique skills and strengths, in one original storyline. Players will be transported to new locations never before seen in a Spider-Man game, from lush jungles and dusty deserts to various urban terrains. Acclaimed comic book writer Dan Slott takes players on a mission to contain the magical energy of the Tablet of Order and Chaos, which has been shattered and sent hurtling across parallel universes, and battle fan-favorite villains in a quest to restore the fabric of reality.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-heroes-3d-grandmaster-s-challenge-wii', 'Marvel Super Heroes 3D: Grandmaster’s Challenge', 'Marvel', '2010-11-12', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4863.jpg', 'The supervillain Grandmaster has imprisoned a quintuple of Marvel heroes â" Spider-Man, Captain America, Thor, Iron Man and Wolverine â" in a deadly game purely for his own amusement. The heroes are forced to play along and complete a variety of challenges designed to test their abilities to their limits as the Grandmaster manipulates them like pawns on his own private board game. Up to four players can participate to compete against the Grandmaster and his band of villain henchmen, all the while joining forces to break the dome and win their freedom.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-the-infinity-gauntlet-wii', 'Marvel Super Hero Squad: The Infinity Gauntlet', 'Marvel', '2010-11-16', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2di9.jpg', 'Marvel Super Hero Squad: The Infinity Gauntlet is a continuation of the video game Marvel Super Hero Squad and it was released on November 16, 2010. Similar to the first game, it features cartoonish Super-deformed versions of the Marvel Comics characters, as seen in the Marvel Super Hero Squad toy line, as well as the television show.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thor-god-of-thunder-wii', 'Thor: God of Thunder', 'Marvel', '2011-05-03', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co531w.jpg', 'Thor: God of Thunder is an action-adventure game developed by Liquid Entertainment and published by Sega in 2011. It serves as a tie-in to the Thor film from the Marvel Cinematic Universe. Players control Thor as he wields Mjolnir to battle enemies across the Nine Realms, facing iconic foes such as Surtur and Ulik while protecting Asgard from destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-super-soldier-wii', 'Captain America: Super Soldier', 'Marvel', '2011-07-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ovp.jpg', 'The Nintendo 3DS port of Captain America: Super Soldier.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-destiny-wii', 'X-Men: Destiny', 'Marvel', '2011-09-27', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnk.jpg', 'X-Men: Destiny is an action role-playing video game based on the X-Men comic book series. It was developed by Silicon Knights. Written by Mike Carey, the writer of the X-Men: Legacy comic book series, it was first published and released by Activision for the Nintendo DS, PlayStation 3, Xbox 360 and Wii consoles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-edge-of-time-wii', 'Spider-Man: Edge of Time', 'Marvel', '2011-10-04', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h30.jpg', 'The fate of one Webslinger hangs on the webs of another in this game where two Spider-Man worlds collide with the death - yes, the death - of Peter Parker. Play as the Amazing Spider-Man and Spider-Man 2099 in a storyline that weaves together two timelines. The two heroes battle in separate worlds with a shared destiny, working to prevent an event that has dire consequences for Parker and the fate of the worlds he protects. Your actions in one timeline could cause ripple effects in the other. Picture-in-picture visuals let you watch your actions change the future - or rewrite the past - for better or for worse.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-comic-combat-wii', 'Marvel Super Hero Squad: Comic Combat', 'Marvel', '2011-11-15', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co485l.jpg', 'Marvel Super Hero Squad: Comic Combat is a video game that uses the uDraw GameTablet, developed by Griptonite Games, and published by THQ and Vivendi Games. The game is the third in the Marvel Super Hero Squad franchise, acting as the sequel to two video games Marvel Super Hero Squad and Marvel Super Hero Squad: The Infinity Gauntlet. It was released on November 15, 2011 for the uDraw GameTablet, PlayStation 3, Xbox 360, and Nintendo Wii game systems.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mib-alien-crisis-wii', 'MIB: Alien Crisis', 'Marvel', '2012-05-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9cbu.jpg', 'Become the next top agent of the Men In Black. Arm yourself with a full arsenal of iconic MIB weapons to investigate and stop an evil alien plot to snatch up an ancient artifact that is the key to seizing control of the universe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-wii', 'The Amazing Spider-Man', 'Marvel', '2012-06-26', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-3-corruption-wii', 'Metroid Prime 3: Corruption', 'Metroid', '2007-08-27', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaun.jpg', 'The trilogy closes as corruption creeps over the universe… and into Samus Aran. Using the Wii Remote and Nunchuk, players control Samus as she partners with other bounty hunters, shoots down enemies, and explores alien worlds in a harrowing mission to stop the mutagenic Phazon from spreading across the galaxy.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-trilogy-wii', 'Metroid Prime: Trilogy', 'Metroid', '2009-08-24', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co404a.jpg', 'In this compilation that bundles all three landmark Metroid Prime games, experience the danger and high-intense action of facing space alone as you play skilled bounty hunter, Samus Aran.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-other-m-wii', 'Metroid: Other M', 'Metroid', '2010-08-31', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc4u.jpg', 'A part of the Metroid series, it features gameplay in both first- and third-person perspectives, and is the first installment of the franchise to feature melee attacks which could only be executed when an enemy''s health was reduced to a certain degree.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-aragorn-s-quest-wii', 'The Lord of the Rings: Aragorn''s Quest', 'Middle-earth', '2010-09-14', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9nie.jpg', 'The NDS/PSP ports features slightly different HUD, and the NDS version uses the second screen as a map.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-tri-wii', 'Monster Hunter Tri', 'Monster Hunter', '2010-04-20', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ssf.jpg', 'Monster Hunter Tri depicts an ecosystem where man co-exists with fantastic beasts that roam both the land and the sea. Featuring both online and offline cooperative modes, players can join online hunting parties with up to four players or play with two players on a single TV for select quests. Players also have the option to face Monster Hunter Tri''s quests as a single player experience accompanied by Cha-Cha, an AI hunting partner whose tracking and trapping skills will prove invaluable in the hunt.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-remix-wii', 'Namco Museum Remix', 'Namco Museum', '2007-10-23', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jcu.jpg', 'Namco Museum Remix is a video game compilation for the Wii, featuring a wide array of classic and updated Namco arcade games. Featured in the compilation are the original versions of nine arcade games from the 1970s and 1980s.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-megamix-wii', 'Namco Museum Megamix', 'Namco Museum', '2010-11-26', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kee.jpg', 'Includes Cutie Q, Galaxian, Pac-Man, Rally-X, King & Balloon, New Rally-X, Bosconian, Galaga, Dig Dug, Super Pac-Man, Xevious, Mappy, Pac & Pal, Gaplus, Grobda, Motos, Dig Dug II and Pac-Mania, as well as five remade "remix" versions of Rally-X, Galaga, Grobda, Motos, Gator Panic and Pac ''n Roll.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nights-journey-of-dreams-wii', 'Nights: Journey of Dreams', 'Nights', '2007-12-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25aw.jpg', 'This time around, however, Nights takes a bit of a different turn. Keeping in line with the "world of dreams" theme – it wouldn''t be Nights without it – players will take control of Will and Helen, two young children each entering into Nightopia (the world of dreams) with their own back-story, emotional baggage, and inner demons that come to life though the forming of nightmares. It''s a pretty simple concept overall, and with each child''s five main levels you''ll get a different piece of the story leading up to the same grand finale. Once they arrive in the land of dreams, each character meets up with a Nights almost instantaneously, and from there learns to meld with the mysterious creature and fly through the world of Nightopia. Along the way you''ll learn of the quest to find the hidden Ideya (basically essences of the human spirit), and eventually attempt to defeat a powerful god-like creature named Wizeman and his right-hand man Reala.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-wii', 'No More Heroes', 'No More Heroes', '2008-01-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95vk.jpg', 'The Memory of the Hero campaign follows the story of helicopter pilot Sergey Pavlovich Borisov. Being an honored sniper and research helicopter pilot and a hero of the Soviet Union and Russia, this campaign explores his experiences in the Mi-8MTV2 and the Ka-50 Black Shark. The campaign is full of danger and exciting moments as you relive some of his more harrowing experiences!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-2-desperate-struggle-wii', 'No More Heroes 2: Desperate Struggle', 'No More Heroes', '2010-01-26', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobp4c.jpg', 'No More Heroes 2: Desperate Struggle continues the tale of punk anti-hero Travis Touchdown, the Japanese anime Otaku, and pro wrestling-obsessed assassin. Travis finds himself at the bottom of the UAA (United Assassins Association) rankings and must wage war to become the No. 1 assassin once again. The follow-up to the popular No More Heroes will offer fans infectious, fun gameplay that allows you to wield not just one, but two swords and face multiple bosses simultaneously in bigger-than-ever boss battles.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-wii', 'Ōkami', 'Ōkami', '2008-04-15', 'Wii', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53vn.jpg', 'This edition includes the following PS4:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-party-wii', 'Pac-Man Party', 'Pac-Man', '2010-11-16', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22kz.jpg', 'A brand-new arcade experience featuring a four-player Battle Mode where the last PAC-MAN standing wins.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-paper-mario-wii', 'Super Paper Mario', 'Paper Mario', '2007-04-09', 'Wii', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba44.jpg', 'The newest chapter of the Paper Mario story isn''t just out of this world... it''s out of this dimension. What at first glance appears to be a 2D side-scroller ripped straight from the stylized pages of the Paper Mario universe soon turns into a hilarious dimension-shifting platformer possible only on Wii.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-wii', 'Pikmin', 'Pikmin', '2009-03-09', 'Wii', 1, 0, NULL, NULL, NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-2-wii', 'Pikmin 2', 'Pikmin', '2012-06-10', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5y6r.jpg', 'Captain Olimar has returned to marshall new colors of Pikmin in a wild, open-ended adventure—and this time, he''s brought an assistant. The company he works for is going bankrupt and, to save it, Olimar has come to salvage the treasure buried below the surface of the planet. His company''s debt is a whopping 10,000 Pokos.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-battle-revolution-wii', 'Pokémon Battle Revolution', 'Pokémon', '2007-06-25', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z85.jpg', 'Pokémon Battle Revolution features three main modes of play: Colosseum Battle Mode, DS Battle Mode, and Wi-Fi Battle Mode. In Colosseum Battle Mode, your goal is to battle your way through a series of Colosseums, each with its own set of rules and challenges.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-park-wii-pikachu-s-adventure-wii', 'PokéPark Wii: Pikachu''s Adventure', 'Pokémon', '2010-11-01', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4m.jpg', 'Take control of Pikachu in Poképark, a Pokémon amusement park. Make friends with other Pokémon and enjoy the rides with them.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-park-2-wonders-beyond-wii', 'PokéPark 2: Wonders Beyond', 'Pokémon', '2012-02-27', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3d1o.jpg', 'Sequel to PokéPark Wii: Pikachu''s Adventure. As in the previous game you play as Pikachu, traveling around and encountering other Pokémon.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-two-thrones-wii', 'Prince of Persia: The Two Thrones', 'Prince of Persia', '2007-04-03', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav9r.jpg', 'In the mobile version of the last game in the trilogy, the Prince returns to Babylon after the events of the previous game, only to find out that a vizier has taken his throne. This new ruler has captured the Babylonian women. You need to set them free and defeat the vizier at the same time. Exposure to the sands of time, however, has awakened an evil presence inside the Prince, which manifests itself as the Dark Prince. During the game, you will often morph into the other presence, whose only goal it to reclaim the throne, the populace be damned.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-forgotten-sands-wii', 'Prince of Persia: The Forgotten Sands', 'Prince of Persia', '2010-05-18', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8z2j.jpg', 'Prince of Persia: The Forgotten Sands is a promotional browser flash game created to promote the Prince of Persia: The Forgotten Sands. Playing the game unlocked a costume in the main game, though that feature no longer works. The game is still playable on explosivebarrel.net
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('punch-out-wii', 'Punch-Out!!', 'Punch-Out!!', '2009-05-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bsq.jpg', 'Also known by the unofficial titles of Punch-Out!! Gold and Punch-Out!! Special, with the in-game title of simply Punch-Out!!, recently released on the Japanese Nintendo Switch Online as Punch-Out!!: Shouhin-ban (Prize Version), this was the first released version of Punch-Out!! for the NES/Famicom, which was released in Japan, as a prize for the participants of the official NES Open Tournament Golf (Golf Tournament US Course) competition.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-wii', 'Rayman Raving Rabbids', 'Rabbids', '2006-11-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pj8.jpg', 'Rayman Raving Rabbids was originally developed as a 3D platform game, under the working title Rayman 4. It was announced by Ubisoft on the 11th of April, 2006, shortly after the cancellation of Phoenix Studio''s unrelated Rayman 4 project. Under development by Ubisoft Montpellier, the game was to be a free-roaming action platforming game, in which the player would control Rayman as he battled against an invading army of Rabbids. The game was announced for the PlayStation 3, Xbox 360, Windows, and the Nintendo Wii, which was then codenamed the ''Revolution''.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-2-wii', 'Rayman Raving Rabbids 2', 'Rabbids', '2007-11-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gt4.jpg', 'They''ve invaded the world of Rayman, and now the insane Rabbids have a new objective: invade planet Earth! They have established their base at a shopping mall and begun training for their nastiest scheme yet. As part of this training, the Rabbids must carry out several missions around the globe to help them in an attempt to dominate the world. The Rabbids will also try to study human behavior by mimicking everything we do... but in the Rabbid sort of way, with no logic... of course.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-tv-party-wii', 'Rayman Raving Rabbids: TV Party', 'Rabbids', '2008-11-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8544.jpg', 'Rayman Raving Rabbids TV Party (DS) is the Nintendo DS version of Rayman Raving Rabbids TV Party, the third instalment of the Rayman Raving Rabbids series. In the same vein as Rayman Raving Rabbids 2 for the handheld, the game centres around minigames almost entirely.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-go-home-wii', 'Rabbids Go Home', 'Rabbids', '2009-11-01', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jq9.jpg', 'Rabbids Go Home was released on PC in select countries in Europe, notable France (in which it was published by Mindscape), Russia (Бука), Czech Republic (Playman), Germany (Computer Bild Spiele). It was developed by Ubisoft Sofia. Much of the content from the original Wii version is absent from this version, such as the In Ze Remote features and the Centre City. Only 16 levels are present in the game. Polish port was split into 4 parts (one contains 4 levels, totally 16). It was sold with the magazine (which truly was only a front cover) issued every two months with disc and Rabbid figure. The publisher was Egmont Polska.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('raving-rabbids-travel-in-time-wii', 'Raving Rabbids: Travel in Time', 'Rabbids', '2010-11-21', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jqi.jpg', 'Raving Rabbids: Travel in Time is a party game for the Wii in which the titular Rabbids travel back in time using a washing machine. Its various co-operative and competitive mini-games can be played alone or with 2-4 players both online and offline.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('raving-rabbids-party-collection-wii', 'Raving Rabbids: Party Collection', 'Rabbids', '2011-03-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/xd6h03h3wyzdc0fg4fuy.jpg', 'The Raving Rabbids Party Collection combines three hit Raving Rabbids party games for a total of over 175 crazy minigames! Included in this pack are Rayman: Raving Rabbids, Raving Rabbids 2, and Raving Rabbids TV Party.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-origins-wii', 'Rayman Origins', 'Rayman', '2011-11-15', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v7k.jpg', 'Bubble Dreamer, Rayman, his best friend Globox, and some Teensy friends are chilling out at the Bubble Dreamer''s resting grounds, the Snoring Tree. However, their snoring disturbs an old granny from the Land of the Livid Dead, who retaliates by sending an evil army of horrendous creatures and the Darktoons across the world, capturing the Electoons that inhabit the world, imprisoning Betilla the Nymph and her sisters, and plunging the Glade into chaos. As a result, the ensuing disaster causes the Bubble Dreamer to go crazy and have nightmares. Although they are captured, Rayman and his friends are able to escape the Darktoons. They are then tasked by the Magician to gather enough Electoons to cure the Bubble Dreamer and restore the Glade of Dreams. Their efforts to locate the Electoons allow them to gain access to the various lands of the Glade, rescuing the Nymphs along the way.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-wii', 'Resident Evil 4', 'Resident Evil', '2007-06-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wn5.jpg', 'This pack includes Resident Evil 4 and Resident Evil CODE: Veronica X.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-the-umbrella-chronicles-wii', 'Resident Evil: The Umbrella Chronicles', 'Resident Evil', '2007-11-13', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w7o.jpg', 'Resident Evil: The Umbrella Chronicles is an on-rails light gun shooter video game developed by Capcom and Cavia as part of the Resident Evil series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-archives-resident-evil-wii', 'Resident Evil Archives: Resident Evil', 'Resident Evil', '2009-06-23', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20cp.jpg', 'Resident Evil Archives: Resident Evil is the port of the remake Resident Evil for the Wii console system.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-the-darkside-chronicles-wii', 'Resident Evil: The Darkside Chronicles', 'Resident Evil', '2009-11-17', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wmx.jpg', 'Resident Evil: The Darkside Chronicles is an on-rails shooting game and the second title exclusive to the Wii platform in the Resident Evil series. The player do not control the character''s movement but only the shooting aspect, shown from a first-person perspective. The player''s partner is also shown on the screen and there is an cooperative option for two players.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-archives-resident-evil-zero-wii', 'Resident Evil Archives: Resident Evil Zero', 'Resident Evil', '2009-12-01', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20cq.jpg', 'Resident Evil Archives: Resident Evil Zero is the port of the game Resident Evil Zero for the Wii console system.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rhythm-heaven-fever-wii', 'Rhythm Heaven Fever', 'Rhythm Heaven', '2012-02-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2klu.jpg', 'Summary: Known as "Beat the Beat: Rhythm Paradise" in the UK/EU. Feel the Beat and Get into the Rhythm Rhythm Heaven Fever promise to be the quirkiest, most charming rhythm game you and your friends will ever play.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-frontier-wii', 'Rune Factory Frontier', 'Rune Factory', '2009-03-17', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2stq.jpg', 'The player can own a farm. There are 4 distinct seasons, 3 of which you can grow different types of crops. Examples include: Strawberries and turnips in the spring, tomatoes and pineapples in the summer, and yams in the fall. There are many other crops, and you can grow flowers, which can all be sold for gold (the game''s currency.) Farming is only half of the game. The other half is dungeon crawling. There are four very different dungeons, three of which represent the four different seasons (the third dungeon represents both autumn and winter). In these dungeons, crops of that dungeon''s seasonal affiliation can be grown. The fourth dungeon, Whale Island, is omni-seasonal, and all crops can be grown there at any time.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-tides-of-destiny-wii', 'Rune Factory: Tides of Destiny', 'Rune Factory', '2011-10-07', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h4x.jpg', 'Aden and Sonja, two lifelong friends, live a tranquil life on Fenith Island until they''re struck by a mysterious curse: they awaken to find both of their souls are now trapped in the same body! On top of this unusual calamity, the Fenith they knew is gone, replaced by a strange island populated with unfamiliar faces. Only by exploring this new world will they be able to solve the mystery of this curse and save their beloved Island. During the course of their journey, Aden and Sonja will be aided by a colorful cast of characters, as well as take command of the towering golem Ymir. Using their newfound giant friend, they''ll cross vast seas, discover hidden islands and dungeons packed with riches, and battle fearsome monsters of the deep!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-tennis-wii', 'Sega Superstars Tennis', 'Sega All-Stars', '2008-03-18', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6p9b.jpg', 'Developed by Sumo Digital, this is the handheld port of Sega Superstars Tennis. While the core mechanics remain very similar, the game differs from the home console version in its presentation, depth, and certain elements of functionality.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-sega-all-stars-racing-wii', 'Sonic & Sega All-Stars Racing', 'Sega All-Stars', '2010-02-23', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te6.jpg', 'Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('simcity-creator-wii', 'SimCity Creator', 'SimCity', '2008-09-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobdj8.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-wii', 'The Sims 2: Pets', 'The Sims', '2007-06-12', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-wii', 'MySims', 'The Sims', '2007-09-18', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6e0k.jpg', 'The Nintendo DS version of MySims takes place in a vacation resort with the player tasked with the job of luring tourists. This is accomplished by doing tasks for the locals who live in your town and after you''re done with a certain task you earn stars. Players collect stars to unlock other parts of the city as well as new minigames and new items in stores. As more stars are collected, the town grows and mini games are unlocked.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-castaway-wii', 'The Sims 2: Castaway', 'The Sims', '2007-10-22', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja9.jpg', 'Castaway is the third console spin-off of the video game The Sims 2. The Sims Castaway Stories is a similar game created for personal computers. It is the final game in the series released for the PlayStation 2 and the final game in the Sims 2 series for console.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-kingdom-wii', 'MySims Kingdom', 'The Sims', '2008-10-28', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9jux.jpg', 'MySims Kingdom sets you on an adventure to help King Roland and his subjects revitalize the Kingdom. Throughout the quest, you will join up with friends, discover fascinating lands, take on challenges, and build amazing contraptions. Almost everything is customizable, allowing every creation within your world to have a signature look.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-party-wii', 'MySims Party', 'The Sims', '2009-03-10', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa0ls.jpg', 'Up to 4 players can test their wits, quickness and skill in 40 mini-games, each hosted by a different MySim. Each of your friends and you can select a custom team of 4 characters to play the huge variety MySims Party has to offer. Outwit friends by selecting the right team who will carry the day in contests based on strength, endurance, speed and luck. Pick carefully though, the wrong team will give your friends the edge over you. Bragging rights only belong to those who choose wisely and play flawlessly. Real People. Real fun. With the MySims.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-racing-wii', 'MySims Racing', 'The Sims', '2009-06-12', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaqzg.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-agents-wii', 'MySims Agents', 'The Sims', '2009-09-29', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87qm.jpg', 'In MySims Agents on the Nintendo DS, players are agents assigned by their agency to help the mayor stop a notorious thief from stealing an ancient treasure. By searching for clues, solving intricate puzzles, and matching wits with the thief, gamers can protect the treasure and the town! Along the way, they can talk to their favorite MySims, sharpen their agent skills with 10 different mini-games, and search through underground caverns for clues to the thief’s undoing!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-skyheroes-wii', 'MySims SkyHeroes', 'The Sims', '2010-09-28', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uk1.jpg', 'The DS port of the final game in the MySims series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-wii', 'The Sims 3', 'The Sims', '2010-11-15', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nas.jpg', 'The Sims 3 is a console game developed by Electronic Arts for the Nintendo Wii.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-spyro-s-adventure-wii', 'Skylanders: Spyro''s Adventure', 'Skylanders', '2011-10-16', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsc.jpg', 'Skylanders: Spyro''s Adventure is the first video game in the Skylanders series. It is a video game that is played along with toy figures that interact with it through a "Portal of Power", that reads their tag through NFC and features the voices of Josh Keaton, Dave Wittenberg, Darin De Paul, Joey Camen, Audrey Wasilewski, Keythe Farley and Kevin Michael Richardson.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-giants-wii', 'Skylanders: Giants', 'Skylanders', '2012-10-21', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vlm.jpg', 'Skylanders: Giants is a 2012 video game in the Skylanders series, a direct sequel to the 2011 game Skylanders: Spyro''s Adventure and features the voices of Kevin Michael Richardson, Greg Ellis, Peter Lurie, Steve Blum, Dave Wittenberg, Carlos Alazraqui, Kevin Sorbo, Bobcat Goldthwait, Patrick Seitz and Julie Nathanson. It is the game before Skylanders: Swap Force. As the title suggests, it features larger Skylanders known as "Giants", along with other new gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-wii', 'Skylanders: Swap Force', 'Skylanders', '2013-10-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-wii', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-racing-wii', 'Skylanders: SuperChargers Racing', 'Skylanders', '2015-09-20', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ysr.jpg', 'Fans can augment their SuperCharger experience with a complementary, dedicated racing combat game -- Skylanders SuperChargers Racing -- for the Wii system and Nintendo 3DS hand-held system. All-new tracks, augmented with power-ups, boosts, hazards and more, offer up to 50 different and exciting gameplay experiences.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-and-the-secret-rings-wii', 'Sonic and the Secret Rings', 'Sonic the Hedgehog', '2007-02-20', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rl4.jpg', 'Sonic and the Secret Rings is a three-dimensional platform and action game featuring an on-rails style of movement. Sonic the Hedgehog, the series'' main character, is the game''s only player character. He is controlled exclusively with the Wii Remote, which is held horizontally like a traditional gamepad.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-riders-zero-gravity-wii', 'Sonic Riders: Zero Gravity', 'Sonic the Hedgehog', '2008-01-08', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvm.jpg', 'Sonic Riders: Zero Gravity is a hoverboard racing video game developed by Sonic Team and published by Sega for the PlayStation 2 and Wii. It is the fifth racing game in the Sonic the Hedgehog series, and the second entry the Sonic Riders trilogy. A port for the Xbox 360 was cancelled during development, while a sequel, Sonic Free Riders, was released exclusively for that system in 2010.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-unleashed-wii', 'Sonic Unleashed', 'Sonic the Hedgehog', '2008-11-18', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6p.jpg', 'Gameplay in Sonic Unleashed focuses on two modes of platforming play: fast-paced levels that take place during daytime, showcasing Sonic''s trademark speed as seen in previous games in the series, and slower, night-time levels, during which Sonic''s Werehog form emerges, and gameplay switches to an action-based, brawler style of play, in which Sonic battles Gaia enemies', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-and-the-black-knight-wii', 'Sonic and the Black Knight', 'Sonic the Hedgehog', '2009-03-03', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4at1.jpg', 'A wizard named Merlina, granddaughter of the original Merlin, summons Sonic to help free the mystical realm of King Arthur, who has been possessed by an unknown evil that comes from Excalibur''s scabbard, and is now ruling the realm as the tyrannical Black Knight.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-colors-wii', 'Sonic Colors', 'Sonic the Hedgehog', '2010-11-16', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6yuq.jpg', 'An extraordinary amusement park has been seen orbiting around the home planet of Sonic the Hedgehog, and rumors are spreading that an alien race of Wisps, who have a unique colorful energy, are being held captive there by the evil Dr. Eggman. Soon after arriving at the amusement park, Sonic discovers he is able to use these mysterious alien forces to help the Wisps escape!', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spore-hero-wii', 'Spore Hero', 'Spore', '2009-10-06', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3deg.jpg', 'Enjoy maximum replay value as you evolve your Spore Hero, then return to explore early areas of the game with new powerful items and abilities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-the-eternal-night-wii', 'The Legend of Spyro: The Eternal Night', 'Spyro', '2007-10-02', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a9.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-dawn-of-the-dragon-wii', 'The Legend of Spyro: Dawn of the Dragon', 'Spyro', '2008-10-21', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a8.jpg', NULL, 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-wii', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-lightsaber-duels-wii', 'Star Wars: The Clone Wars – Lightsaber Duels', 'Star Wars', '2008-11-11', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cyj.jpg', 'Star Wars: The Clone Wars - Lightsaber Duels allows players on the Wii to step right into the world of the all-new Star Wars: Clone Wars animated feature film and television series, ready for action with a lightsaber at their side.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-wii', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-ii-wii', 'Star Wars: The Force Unleashed II', 'Star Wars', '2010-10-26', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xw.jpg', 'The Star Wars Saga continues with Star Wars: The Force Unleashed II, the highly anticipated sequel to the fastest-selling Star Wars game ever created, which has sold more than seven million copies worldwide.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-tree-of-tranquility-wii', 'Harvest Moon: Tree of Tranquility', 'Story of Seasons', '2008-09-30', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26jz.jpg', 'You have moved to an island town that was once enchanted ... however it has been years since the mystical Mother Tree has shown any signs of life and the Harvest Goddess has vanished. The island has lost its connection with nature and the inhabitants don''t know what to do. It is up to you to save the island!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-magical-melody-wii', 'Harvest Moon: Magical Melody', 'Story of Seasons', '2009-08-25', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakko.jpg', 'The Wii version does not include the female playable character like the GameCube version does, and as such she was removed from the boxart.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-animal-parade-wii', 'Harvest Moon: Animal Parade', 'Story of Seasons', '2009-11-10', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xk1.jpg', 'Harvest Moon: Animal Parade offers more traditional Harvest Moon gameplay for the Nintendo Wii, and features a range of exotic animals for you to interact with.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-blitz-wii', 'Super Monkey Ball: Banana Blitz', 'Super Monkey Ball', '2006-11-19', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uh1.jpg', 'Hold onto your bananas, because Super Monkey Ball: Banana Blitz HD is rolling your way! Experience the magic of one of the most beloved titles in the series, now remastered in HD!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-step-roll-wii', 'Super Monkey Ball: Step & Roll', 'Super Monkey Ball', '2010-02-09', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8pnn.jpg', 'Super Monkey Ball: Step & Roll, like the previous Super Monkey Ball: Banana Blitz, is a fun ball-rolling design with a nice stack of challenges and a hit-or-miss pile of mini-games. There are some neat inclusions like the Super Mario Galaxy-like co-op mode where other players can shoot obstacles out of the players’ way. The added balance board support wasn’t that much of a selling point for me – on paper it sounds like a match made in heaven but in practice it’s just a great big load of frustration. Skip the balance board support and you’ll have a good time.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-brawl-wii', 'Super Smash Bros. Brawl', 'Super Smash Bros.', '2008-03-09', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co221w.jpg', 'Super Smash Bros. Brawl is the third installment in the Super Smash Bros. series and the follow-up to Super Smash Bros. Melee. This edition introduces super attacks referred to as final smashes, as well as a brand-new adventure mode in The Subspace Emissary which is a side-scrolling adventure in the style of a platformer. It retains all basic mechanics of the Super Smash Bros. series, such as a damage meter, stocks, and Smash-style attacks.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-party-deluxe-wii', 'Tetris Party Deluxe', 'Tetris', '2010-05-25', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cyk.jpg', 'Tetris Party makes its way to the Nintendo DS and Wii. Deluxe features six new game modes and four new enhanced modes of play.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-wii', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2006-11-28', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-anniversary-wii', 'Tomb Raider: Anniversary', 'Tomb Raider', '2007-11-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mz7.jpg', 'The Wii port of Tomb Raider: Anniversary carries over the levels and general gameplay of the other versions while incorporating motion controls. Wii-exclusive first-person puzzles include breaking through walls with a pickaxe, using a flashlight in dark areas, assembling mechanisms from pieces found around the environment, manipulating symbol-based locks and using paper and charcoal to take rubbings of puzzle-related symbols, all utilizing the Wii Remote.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-underworld-wii', 'Tomb Raider: Underworld', 'Tomb Raider', '2008-11-18', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voc.jpg', 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of challenge and choice.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wario-land-shake-it-wii', 'Wario Land: Shake It!', 'Wario', '2008-09-22', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnw.jpg', 'Wario, Nintendo''s greedy, uncouth and rude anti-hero, returns to his roots. The Wario Land series is where Wario first appeared, and it''s back in all its side-scrolling, platform-jumping glory.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-smooth-moves-wii', 'WarioWare: Smooth Moves', 'WarioWare', '2007-01-15', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b0v.jpg', 'Wario and his pals learn fun, wacky moves after discovering a strange book and a mystical device called the Form Baton. Familiar characters from the WarioWare universe will return to this installment and some new ones will appear. Players must clear fast-paced sets of microgames, changing the way they hold the Wii Remote each time.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-sports-wii', 'Wii Sports', 'Wii', '2006-11-19', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2maz.jpg', 'A bundle containing Wii Sports and Wii Sports Resort for the Wii.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-play-wii', 'Wii Play', 'Wii', '2007-02-12', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnl.jpg', 'Wii Play: Motion is a minigame collection that features Miis as playable characters. All the minigames require use of the Wii MotionPlus accessory, which allows Wii Remote movement to be detected with greater accuracy. Twelve minigames are available to play with both single-player and multiplayer modes.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-fit-wii', 'Wii Fit', 'Wii', '2008-05-21', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86ml.jpg', 'Wii Fit is an exercise game consisting of activities using the Wii Balance Board peripheral.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-music-wii', 'Wii Music', 'Wii', '2008-10-20', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3vl3.jpg', 'Create a musical masterpiece with up to four players. Anyone can play the huge selection of instruments in Wii Music with simple motions. Play faster. Play slower. Skip a beat, or throw in 10 more. No matter what you do, Wii Music automatically transforms your improv stylings into great music. There are no mistakes - just playing for the pure joy of playing.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-sports-resort-wii', 'Wii Sports Resort', 'Wii', '2009-07-26', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2may.jpg', 'Set off on a journey to a tropical island where an array of fun activities await. In Wii Sports Resort, the sequel to the engaging Wii Sports, you''ll discover a wide range of new sports and activities you can play anytime. Go head-to-head with your friends and family in the ultimate sports showdown set in a tropical paradise.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-fit-plus-wii', 'Wii Fit Plus', 'Wii', '2009-10-04', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86mm.jpg', 'Wii Fit Plus provides all of the original activities in Wii Fit in addition to fifteen Balance/Aerobics games (in a separate category called "Training Plus") and six Yoga and Strength-Training exercises unique to the game.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-party-wii', 'Wii Party', 'Wii', '2010-10-03', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnj.jpg', 'Wii Party features 13 different game modes divided amongst three categories: Party Games, House Party Games, and Pair Games. Most of the game modes integrate use of Wii Party''s 80 mini-games. The game also offers additional modes that make exclusive use of the mini-games.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-play-motion-wii', 'Wii Play: Motion', 'Wii', '2011-06-13', 'Wii', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnl.jpg', 'Wii Play: Motion is a minigame collection that features Miis as playable characters. All the minigames require use of the Wii MotionPlus accessory, which allows Wii Remote movement to be detected with greater accuracy. Twelve minigames are available to play with both single-player and multiplayer modes.', 'NA', 22);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-wii', 'Xenoblade Chronicles', 'Xenoblade Chronicles', '2012-04-06', 'Wii', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8jeg.jpg', 'This convenient bundle includes the Xenoblade Chronicles 3 game for the Nintendo Switch system, along with the Xenoblade Chronicles 3 Expansion Pass that offers four waves of downloadable content.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-new-leaf-nintendo-3ds', 'Animal Crossing: New Leaf', 'Animal Crossing', '2013-06-09', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8m6.jpg', 'The charming community-building franchise returns for with Animal Crossing: New Leaf. The Nintendo 3DS entry into this popular franchise introduces a number of options new to Animal Crossing, including the ability to become the head of the village and boost its development, a way to install certain items in the village to make its characteristics more personalized for each player, and the ability to view homes of other players who are tagged through StreetPass connections.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-happy-home-designer-nintendo-3ds', 'Animal Crossing: Happy Home Designer', 'Animal Crossing', '2015-09-25', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wic.jpg', 'Show off your style by designing homes for all of your favorite Animal Crossing villagers! Use your creativity to design the perfect houses—inside and out—for both old and new friends. With the new amiibo cards, you can call your favorite villagers into the game.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-new-leaf-welcome-amiibo-nintendo-3ds', 'Animal Crossing: New Leaf - Welcome Amiibo', 'Animal Crossing', '2016-12-08', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob92t.jpg', 'Animal Crossing: New Leaf - Welcome amiibo! is an update available to New Leaf that was released worldwide on November 2, 2016. It introduces amiibo compatibility, Animal Crossing Puzzle League and various other features.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('art-academy-lessons-for-everyone-nintendo-3ds', 'Art Academy: Lessons for Everyone!', 'Art Academy', '2012-10-01', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6c6d.jpg', 'Art Academy: Lessons for Everyone! is an interactive application that teaches real world art techniques anyone can enjoy-from beginners to experts of all ages. Discover more than 30 lessons, all using realistic stylus and touch screen-based tools for drawing and painting. Enjoy a robust Free Paint mode that lets you create to your heart''s content using included subjects, or your own images taken with the Nintendo 3DS Camera—whenever and wherever the inspiration strikes.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-art-academy-nintendo-3ds', 'Pokémon Art Academy', 'Art Academy', '2014-10-24', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zis.jpg', 'This Pokémon-themed installment of the Art Academy series offers Pokémon fans and budding illustrators alike 40 unique lessons to learn how to paint, sketch and draw beloved Pokémon characters in 2D. Along the way, students of Pokémon Art Academy can pick up actual illustration skills that they can transfer onto real canvas, or share their digital masterpieces with the world. Pokémon Art Academy boasts 40 lessons in which players can encounter favorite Pokémon from throughout the series, such as Pikachu, Oshawott, Charizard, Torchic, Fletchling and Fennekin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-art-academy-nintendo-3ds', 'Disney Art Academy', 'Art Academy', '2016-05-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1psk.jpg', 'Master the art of drawing beloved Disney and Pixar characters! Step-by-step lessons can teach anyone how to draw. Add some magic to your art! The Magic Brush makes it easy to add patterns, such as sparkles or stars, to any work of art. Go from amateur to expert with over 80 characters to draw!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bit-trip-saga-nintendo-3ds', 'Bit.Trip Saga', 'Bit.Trip', '2011-09-13', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86bj.jpg', 'All six BIT.TRIP games are transformed into 3D, morphing into a single entity called /BIT.TRIP SAGA/. Experience the crushing difficulty of the rhythmic galaxies and ride along the long journey with CommanderVideo as he completes his mission and returns...home.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bravely-default-nintendo-3ds', 'Bravely Default', 'Bravely Default', '2014-02-07', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25nj.jpg', 'Bravely Default follows the story of main character Tiz, a humble shepherd and the lone survivor of a cataclysmic event, as he joins a group of loyal companions on a journey to restore balance to the world. The battle system is what differentiates Bravely Default from other RPGs. Here players can strategically choose when to initiate two complementary commands: Brave and Default. This innovative system encourages players to think carefully about strategy during every enemy encounter. Selecting "Brave" lets players increase the number of actions a character can take in a turn, while "Default" allows players to store actions for later use.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-toad-treasure-tracker-nintendo-3ds', 'Captain Toad: Treasure Tracker', NULL, '2018-07-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v2d.jpg', 'Captain Toad Treasure Tracker is a ROM hack/mod of Super Mario World which adapts the mechanics of the homonymous official game for the Wii U to a 2D platformer.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lords-of-shadow-mirror-of-fate-nintendo-3ds', 'Castlevania: Lords of Shadow – Mirror of Fate', 'Castlevania', '2013-03-05', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pat.jpg', 'Initially set 25 years after the events of Castlevania: Lords of Shadow, Mirror of Fate will reveal the story of Gabriel''s descendants, as they battle their own destiny in each era only to discover their true, shocking fate.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cave-story-3d-nintendo-3ds', 'Cave Story 3D', 'Cave Story', '2011-11-08', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dhp.jpg', 'Having received tremendous acclaim in its previous releases on PC and WiiWare, Cave Story, an indie side scrolling 2D action game, now makes its way into an all new dimension with Cave Story 3D for Nintendo 3DS. At once both a throwback to classic 2D action platformers and also the potential future of the genre, Cave Story 3D blends tight controls, superb level design, and excellent story and presentation to deliver a memorable, addicting retro experience!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chibi-robo-zip-lash-nintendo-3ds', 'Chibi-Robo! Zip Lash', 'Chibi-Robo!', '2015-10-09', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h9y.jpg', 'Chibi-Robo! Zip Lash comes to the Nintendo 3DS system with a fresh, new take on the franchise. In this side-scrolling game, Chibi-Robo uses his plug and cord to whip enemies, grapple onto ledges, and swing across chasms. Power-up the plug and cord to search for collectables and explore previously out of reach areas.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('code-name-s-t-e-a-m-nintendo-3ds', 'Code Name: S.T.E.A.M.', NULL, '2015-03-13', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21q1.jpg', 'Launch S.T.E.A.M., an elite team of steam-powered special-forces soldiers, to save the world from an alien menace. In this new blend of action and strategy, your commandos use steam power stored in special backpacks to move into position and fire an arsenal of distinct weapons. Pick your team members and load out, then use strategy to decide the best way to approach this steampunk-inspired battlefield.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('green-lantern-rise-of-the-manhunters-nintendo-3ds', 'Green Lantern: Rise of the Manhunters', 'DC', '2011-06-07', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ky.jpg', 'Green Lantern: Rise of the Manhunters is an action video game, the first based on DC Comics'' Green Lantern (Hal Jordan). The game is a tie-in/sequel to the film Green Lantern, which opened in theatres on June 17, 2011. The game features 3D visuals on the PlayStation 3 and Xbox 360, providing TriOviz Inficolor 3D for standard televisions and stereoscopic 3D for dedicated 3DTVs.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-origins-blackgate-nintendo-3ds', 'Batman: Arkham Origins Blackgate', 'DC', '2013-10-25', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4oie.jpg', 'Batman: Arkham Origins Blackgate - Deluxe Edition amplifies the 2.5-D game developed by Armature Studio with new maps, enemy encounters, difficulty levels, and batsuits, all with enhanced visuals.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('young-justice-legacy-nintendo-3ds', 'Young Justice: Legacy', 'DC', '2013-11-19', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7mda.jpg', 'Young Justice: Legacy is a multiplayer action RPG based on the Young Justice TV series.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-nintendo-3ds', 'Disney Infinity', 'Disney Infinity', '2013-08-18', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-returns-3d-nintendo-3ds', 'Donkey Kong Country Returns 3D', 'Donkey Kong', '2013-05-24', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wf5.jpg', 'Donkey Kong Country Returns 3D offers over 70 levels of banana‑hoarding platform action starring Donkey Kong and Diddy Kong. Run, jump, climb, and defeat enemies across diverse environments to reclaim the stolen banana hoard, rebuilt and optimized for portable play on Nintendo 3DS with stereoscopic 3D.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-vii-fragments-of-the-forgotten-past-nintendo-3ds', 'Dragon Quest VII: Fragments of the Forgotten Past', 'Dragon Quest', '2016-09-16', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x9h.jpg', 'Travel to the past to save the present in this classic Dragon Quest adventure that has been completely remade from the ground up for Nintendo 3DS. The world has been rebuilt, the characters have new 3D models and the story has been completely re-localized. Even customize your party with over 30 classes and rank up in turn-based battles to learn new spells and abilities.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-viii-journey-of-the-cursed-king-nintendo-3ds', 'Dragon Quest VIII: Journey of the Cursed King', 'Dragon Quest', '2017-01-20', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xc0.jpg', 'This is a portable version of the classic RPG, with added content and other 3DS enhancements.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-power-of-illusion-nintendo-3ds', 'Epic Mickey: Power of Illusion', 'Epic Mickey', '2012-11-18', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w31.jpg', 'In "Disney Epic Mickey: Power Of Illusion," gamers will play as Mickey Mouse as he infiltrates the Castle of Illusion on a quest to put an end to the evil witch Mizrabel''s diabolical intentions. Players will be taken on an all-new adventure made specifically for the Nintendo 3DS where, "Reality Is What You Paint Of It." Created by critically acclaimed video game developer DreamRift, "Disney Epic Mickey: Power Of Illusion" furthers the Wasteland saga by taking players on a completely new story and adventure.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('theatrhythm-final-fantasy-nintendo-3ds', 'Theatrhythm Final Fantasy', 'Final Fantasy', '2012-07-03', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x5n.jpg', 'Theatrhythm Final Fantasy features a hybrid of music rhythm gameplay with RPG elements. Adorably re-designed heroes from the catalogue of FINAL FANTASY titles will set out on an adventure to combat memorable villains with the rhythmic taps of the player''s stylus.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('theatrhythm-final-fantasy-curtain-call-nintendo-3ds', 'Theatrhythm Final Fantasy: Curtain Call', 'Final Fantasy', '2014-09-16', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2roh.jpg', 'A sequel to the first FINAL FANTASY rhythm action game released in 2012, THEATRHYTHM FINAL FANTASY CURTAIN CALL expands on the original in every way with new gameplay modes, over 200 songs, and 60 playable characters. Featuring music that spans the full breadth of the storied FINAL FANTASY franchise, players tap along to the memorable beats and harmonies as the adorable, stylized characters battle and quest through their worlds. The music of over 20 titles is brought together in one package, fusing together the moving scores, cinematic visuals, and role-playing elements the series is known for.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-explorers-nintendo-3ds', 'Final Fantasy Explorers', 'Final Fantasy', '2016-01-26', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vjp.jpg', 'Final Fantasy Explorers features both cooperative play with friends and solo play, utilizing a refined party system which allows Explorers to master over 20 new and familiar jobs—including series classics like Dragoon, Dark Knight, Black Mage and White Mage—to defeat the realm’s mightiest monsters and even recruit them for battle.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-awakening-nintendo-3ds', 'Fire Emblem Awakening', 'Fire Emblem', '2013-02-04', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcko.jpg', 'Armies clash as the world burns. As an inevitable war draws ever closer, you must stand with Chrom and his forces--knights, mages, archers, and more--commanding them against the armies of kingdoms, empires, and the dead themselves.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-fates-birthright-nintendo-3ds', 'Fire Emblem Fates: Birthright', 'Fire Emblem', '2016-02-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobab2.jpg', 'Fire Emblem Fates is split into three story paths. Birthright is one of the two base stories, the other being Conquest. The other story path can be bought digitally at a discount through the in-game store. The third story path is Revelation, a DLC that was released later. You need to be have completed Chapter 6 in either game to access the other stories and DLC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-fates-conquest-nintendo-3ds', 'Fire Emblem Fates: Conquest', 'Fire Emblem', '2016-02-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaaj.jpg', 'Fire Emblem Fates is split into three story paths. Conquest is one of the two base stories, the other being Birthright. The other story path can be bought digitally at a discount through the in-game store. The third story path is Revelation, a DLC that was released later. You need to be have completed Chapter 6 in either game to access the other stories and DLC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-fates-special-edition-nintendo-3ds', 'Fire Emblem Fates Special Edition', 'Fire Emblem', '2016-02-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6i98.jpg', 'Fire Emblem Fates - Special Edition was a limited time bundle containing both base stories, Birthright and Conquest, and gave access to DLC for the 3rd story, Revelation, when it became available. The games were otherwise sold separately though you could get the second story path digitally at a discount. You need to be have completed chapter 6 in the either game to access the other stories, and the DLCs, path.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-echoes-shadows-of-valentia-nintendo-3ds', 'Fire Emblem Echoes: Shadows of Valentia', 'Fire Emblem', '2017-05-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3w.jpg', 'In 1992, the second game in the Fire Emblem series, Fire Emblem Gaiden, launched exclusively in Japan. Now, for the first time, fans outside of Japan will get a taste of this classic game on the Nintendo 3DS family of systems. Fire Emblem Echoes: Shadows of Valentia is inspired by the 1992 original, reimagined on a grander scale. Every aspect of the Fire Emblem Gaiden game''s presentation has been updated, along with the game being fully voiced. Fire Emblem Echoes: Shadows of Valentia recreates classic Fire Emblem gameplay with a modern twist, mixing in exploration of dungeons crawling with enemies."', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fragrant-story-nintendo-3ds', 'Fragrant Story', NULL, '2022-04-21', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qib.jpg', 'Build a team of Fierce Fleuristas, and lend your skills to the Ancient Aroma. You''ll be guided by Colonel Rhubarb as you defend the region from invaders.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-the-lost-valley-nintendo-3ds', 'Harvest Moon: The Lost Valley', 'Harvest Moon', '2014-11-04', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkv.jpg', 'In Harvest Moon 3D: The Lost Valley, players will experience the role-playing farm simulation in a three-dimensional setting for the first time. The game has a fully customizable world, and players can customize their field in any way they see fit: from a field full of tulips to a valley filled with water, the choice is up to you. You''ve never played a Harvest Moon game quite like this!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-skytree-village-nintendo-3ds', 'Harvest Moon: Skytree Village', 'Harvest Moon', '2016-11-08', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xlh.jpg', '"Times have changed in the land known as the Oasis of the Harvest Goddess. Many people used to live in Skytree Village, and the land was lush and green. However, the power of the Harvest Goddess gradually began to wane, and the land became parched and dry.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kid-icarus-uprising-nintendo-3ds', 'Kid Icarus: Uprising', 'Kid Icarus', '2012-03-23', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9me.jpg', 'One of the most beloved franchises in Nintendos long history makes its glorious return in spectacular 3D! Pit of Kid Icarus fame is back in a new game designed specifically for the Nintendo 3DS system, by Masahiro Sakurai, creator of the Kirby and Super Smash Bros. franchises, and his development team at Project Sora.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-3d-dream-drop-distance-nintendo-3ds', 'Kingdom Hearts 3D: Dream Drop Distance', 'Kingdom Hearts', '2012-07-31', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co318g.jpg', 'Kingdom Hearts 3D: Dream Drop Distance is the seventh game in the Kingdom Hearts series. It was originally developed for the Nintendo 3DS hand-held system. It is a direct sequel to Kingdom Hearts II, Kingdom Hearts coded, and the epilogue of Kingdom Hearts Birth by Sleep.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-triple-deluxe-nintendo-3ds', 'Kirby: Triple Deluxe', 'Kirby', '2014-05-02', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1q9m.jpg', 'A side-scrolling installment in the beloved Kirby series, Kirby: Triple Deluxe uses the 3D features of the Nintendo 3DS to allow Kirby to move not only from left to right, but also from the foreground to the background. Kirby also gets an “inhale everything” ability that can be used in specific parts of each stage to help him clear anything blocking his path. As always, Kirby has the power to inhale his enemies and take on their abilities. Each copy ability can let him do a variety of actions and moves, depending on which buttons are pressed.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-planet-robobot-nintendo-3ds', 'Kirby: Planet Robobot', 'Kirby', '2016-06-10', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcm6.jpg', '"Harness the power of a mysterious mech to stop ruthless invaders from mechanizing Kirby''s home world. Smash through tough obstacles, lift heavy objects with ease, and scan enemies to shape-shift into new Modes with powerful abilities in this supercharged action-platformer!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-battle-royale-nintendo-3ds', 'Kirby Battle Royale', 'Kirby', '2018-01-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobab3.jpg', 'Kirby is entering a tournament against his toughest rival yet... himself! 1-4 players can fight in local or online battles. Pick from 10+ abilities and 10 battle types to compete in countless matchups. Hoard treasure in Ore Express, knock out opponents in Slam Hockey, shoot missiles at Robo Bonkers, and more! There''s a single-player story mode too!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-extra-epic-yarn-nintendo-3ds', 'Kirby''s Extra Epic Yarn', 'Kirby', '2019-03-08', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69p5.jpg', 'The hit Wii game Kirby’s Epic Yarn is warping to Nintendo 3DS. Every stage in the original Wii version is stitched in, but this Nintendo 3DS version has some new features, like the ability to craft bigger yarn balls, summon bead-collecting wind and play two new modes featuring familiar faces King Dedede and Meta Knight.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-ocarina-of-time-3d-nintendo-3ds', 'The Legend of Zelda: Ocarina of Time 3D', 'The Legend of Zelda', '2011-06-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co600u.jpg', 'The Legend of Zelda: Ocarina of Time 3D is a remake of Ocarina of Time with more up-to-date graphics, streamlined UI and different additional game modes. Most textures are significantly more detailed, and many models are more faithful to the game''s concept and promotional art. In addition, the frame rate has been increased to 30 FPS compared to the original''s 20 FPS.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-a-link-between-worlds-nintendo-3ds', 'The Legend of Zelda: A Link Between Worlds', 'The Legend of Zelda', '2013-11-22', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p0j.jpg', 'The Legend of Zelda: A Link Between Worlds is the first Zelda game made exclusively for the Nintendo 3DS. It is an indirect sequel to A Link to the Past with the same version of Hyrule but with new characters and gameplay elements. Unlike the series'' tradition, many areas of the world are accessible from the beginning of the game and the dungeons can be visited in any order. Puzzles are encountered not only in dungeons but also in the open world, a part of them revolves around the game''s 3D visual effect. The 3DS touch-screen display shows the world, dungeon or map depending on where you are.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-majora-s-mask-3d-nintendo-3ds', 'The Legend of Zelda: Majora''s Mask 3D', 'The Legend of Zelda', '2015-02-13', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9x9.jpg', 'The Legend of Zelda: Majora''s Mask 3D is a remake of the original Nintendo 64 game with more up-to-date graphics, streamlined UI and different additional game modes. Most textures are significantly more detailed, and many models are more faithful to the game''s concept and promotional art. In addition, the frame rate has been increased to 30 FPS compared to the original''s 20 FPS.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-tri-force-heroes-nintendo-3ds', 'The Legend of Zelda: Tri Force Heroes', 'The Legend of Zelda', '2015-10-23', 'Nintendo 3DS', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p1a.jpg', 'The Legend of Zelda: Tri Force Heroes is the direct sequel to The Legend of Zelda: A Link Between Worlds. The game is similar to the Four Swords games in which Link is accompanied by two other Links in the game''s multiplayer mode, but it also allows for a single-player mode in which the other Links are replaced by animated dolls that can be swapped out during the game. The three Link can cooperate in a variety of ways to solve puzzles and coordinate their attacks with the help of on-screen notifications that give clues on what to do.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyrule-warriors-legends-nintendo-3ds', 'Hyrule Warriors Legends', 'The Legend of Zelda', '2016-03-25', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4mxs.jpg', 'This pack includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-nintendo-3ds', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-nintendo-3ds', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-nintendo-3ds', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-nintendo-3ds', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-nintendo-3ds', 'Lego The Lord of the Rings', 'Lego', '2012-10-30', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-city-undercover-the-chase-begins-nintendo-3ds', 'Lego City Undercover: The Chase Begins', 'Lego', '2013-04-21', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fua.jpg', 'LEGO City Undercover: The Chase Begins. A prequel to the Wii U game, follow the exploits of Chase McCain as a rookie cop. Find out how the story of Chase McCain begins. Chase McCain is on his first assignment as a police offer-and it''s up to you to help him clean up LEGO City! By changing into different disguises, Chase has access to unique abilities, such as putting out fires as a Fireman and breaking open doors as a Robber. After using his skills to infiltrate criminal organizations, help Chase finish the job by slapping cuffs on the bad guys. With multiple areas of LEGO City to explore and a boatload of LEGO Bricks and Studs to collect, the chase has most certainly begun.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-legends-of-chima-laval-s-journey-nintendo-3ds', 'Lego Legends of Chima: Laval''s Journey', 'Lego', '2013-06-25', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co615v.jpg', 'Get ready for an epic adventure as Laval races to unlock the secret of the legendary triple-Chi armour before Cragger can manipulate its awesome power to threaten the balance of Chima itself! Laval and his allies will explore Lion Temple, Eagle Spire, Gorilla Forrest, Rhino Quary, Croc Swamp and more as they harness the power of Chi to leap, swing, fly and fight through 15 levels of intense action! Can Laval discover the truth behind the legend of the triple-Chi before it’s too late?', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-friends-nintendo-3ds', 'Lego Friends', 'Lego', '2013-11-12', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gy3.jpg', NULL, 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-nintendo-3ds', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-universe-in-peril-nintendo-3ds', 'Lego Marvel Super Heroes: Universe in Peril', 'Lego', '2014-02-18', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co484t.jpg', 'A port of Lego Marvel Super Heroes, a 2013 Lego-themed action-adventure video based on Marvel comic book character.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-nintendo-3ds', 'Lego The Hobbit', 'Lego', '2014-04-08', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-ninjago-nindroids-nintendo-3ds', 'Lego Ninjago: Nindroids', 'Lego', '2014-07-29', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co615t.jpg', 'The highly popular LEGO Ninjago videogame franchise is back with high-kicking action and adventure! LEGO Ninjago: Nindroids comes to the Nintendo 3DS and PlayStation Vita this summer. Based on the first five new episodes of the animated TV series, "LEGO Ninjago Rebooted,” players will battle and defend the New Ninjago City where the Ninjas face a technological threat by the evil Overlord and his robotic army of Nindroids. Using swift combo attacks, unique fighting moves, special weapons and new vehicles, the Ninjas must fight with all their might to save Ninjago.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-nintendo-3ds', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-ninjago-shadow-of-ronin-nintendo-3ds', 'Lego Ninjago: Shadow of Ronin', 'Lego', '2015-03-24', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3c83.jpg', 'There is a new threat in Ninjago, and he goes by the name of Ronin. With help from his army of dark samurai, Ronin steals the Ninjas'' memories using an ancient weapon called the Obsidian Glaive. In LEGO Ninjago: Shadow of Ronin, it is up to players to help the Ninjas regain their memories and reclaim their powers before Ronin completes his plan and releases an even greater evil on Ninjago.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-nintendo-3ds', 'Lego Jurassic World', 'Lego', '2015-06-12', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-nintendo-3ds', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-nintendo-3ds', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('luigi-s-mansion-dark-moon-nintendo-3ds', 'Luigi''s Mansion: Dark Moon', 'Luigi''s Mansion', '2013-03-24', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3vjj.jpg', 'Luigi is back on a mission to remove a bunch of stubborn ghosts from some spooky mansions. Armed with his trusty Poltergust ghost-sucking vacuum cleaner, Mario''s brother takes center stage to capture these pesky phantoms. Luigi''s Mansion 2: Dark Moon gives players multiple mansions to explore, a variety of puzzles to solve and new ghosts to capture. Armed with the Poltergust 5000, a ghost-sucking, vacuum-like invention, Luigi must complete a number of missions assigned to him by Professor E. Gadd.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('luigi-s-mansion-nintendo-3ds', 'Luigi''s Mansion', 'Luigi''s Mansion', '2018-10-12', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8pr.jpg', 'G-g-ghosts!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-3d-land-nintendo-3ds', 'Super Mario 3D Land', 'Mario', '2011-11-13', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobab1.jpg', 'Super Mario 3D Land is the second 3D Super Mario platformer for a handheld device, and the successor to Super Mario Galaxy 2. The game is closely based on side-scrolling Mario games, as it combine elements from both traditional 2D Mario games and modern free-roaming 3D Mario games. It also introduces elements into the series, including power-ups and gameplay mechanics.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-mario-bros-2-nintendo-3ds', 'New Super Mario Bros. 2', 'Mario', '2012-08-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaah.jpg', 'New Super Mario Bros. 2 is a side-scrolling 2.5D action-adventure platform game for the Nintendo 3DS. As the direct sequel to New Super Mario Bros., it is an indirect follow-up to New Super Mario Bros. Wii. The game''s main focus is on coins, with the primary goal being to collect one million. To reach the goal, the game includes many new items to aid the player, such as the Gold Flower, which turns Mario into Gold Mario.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-maker-for-nintendo-3ds-nintendo-3ds', 'Super Mario Maker for Nintendo 3DS', 'Mario', '2016-12-02', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ngw.jpg', NULL, 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-dream-team-nintendo-3ds', 'Mario & Luigi: Dream Team', 'Mario & Luigi', '2013-08-11', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ahq.jpg', 'Mario and Luigi embark on the adventure of their dreams in a hilarious action RPG that combines the resort world of Pi’illo Island with the wild landscapes of Luigi’s imagination, where anything can happen. Meet a host of hilarious characters as you strive to rescue Princess Peach and help Prince Dreambert free his petrified Pi’illo people from the bat-king Antasma’s curse.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-paper-jam-nintendo-3ds', 'Mario & Luigi: Paper Jam', 'Mario & Luigi', '2016-01-22', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ahr.jpg', 'Paper Mario jumps out of a book and into the bizarre adventures of Mario & Luigi, resulting in hilarious, and dangerous, hijinks! Become the superstar team of Mario, Luigi and Paper Mario to take on quests, take down enemies, and untangle these two unique universes in this playful new entry in the Mario & Luigi series.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-superstar-saga-bowser-s-minions-nintendo-3ds', 'Mario & Luigi: Superstar Saga + Bowser''s Minions', 'Mario & Luigi', '2017-10-06', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22a7.jpg', '"The game that launched the Mario & Luigi series returns looking better than ever before.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-bowser-s-inside-story-bowser-jr-s-journey-nintendo-3ds', 'Mario & Luigi: Bowser''s Inside Story + Bowser Jr.''s Journey', 'Mario & Luigi', '2019-01-11', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3z.jpg', 'In addition to the game’s revamped graphics and refined gameplay, a new side story follows Bowser Jr. as he gathers an army, creates formations, supports his allies with an arsenal of moves and generally causes chaos (in the best way possible).', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-london-2012-olympic-games-nintendo-3ds', 'Mario & Sonic at the London 2012 Olympic Games', 'Mario & Sonic at the Olympic Games', '2012-02-14', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22wi.jpg', 'The 3DS version of Mario & Sonic at the London 2012 Olympic Games has some key differences from the Wii version. While it shares many events, it has more. It also features an exclusive Story Mode. The protagonists from the Mario and Sonic series team up to defeat Bowser and Dr. Eggman, who, along with their underlings, have taken over London. There are different parts to the story, depending on the character played. The player must win events against the antagonists. Playable characters consist of all 20 playable characters from the previous installment''s Nintendo DS version, and are split into five groups of four.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-rio-2016-olympic-games-nintendo-3ds', 'Mario & Sonic at the Rio 2016 Olympic Games', 'Mario & Sonic at the Olympic Games', '2016-03-18', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22wj.jpg', 'A new 3DS game sees Mario and Sonic team up to compete in a whole range of different Olympic games. You can download to three other 3DS’s and play four players in each of the different events. There’s also a Pocket Marathon mode than uses the motion sensor in the 3DS to act like a pedometer and challenge people to get outside and get active.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-world-tour-nintendo-3ds', 'Mario Golf: World Tour', 'Mario Golf', '2014-05-02', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co224o.jpg', 'Luigi and his Mushroom Kingdom neighbors are teeing up once again in Mario Golf: World Tour. The Nintendo 3DS game includes both simple controls and a deeper experience for golf fans, plus courses that range from traditional to those inspired by the Mushroom Kingdom', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-7-nintendo-3ds', 'Mario Kart 7', 'Mario Kart', '2011-12-04', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2146.jpg', 'The seventh installment of the fan-favorite Mario Kart franchise brings Mushroom Kingdom racing fun into glorious 3D. For the first time, drivers explore new competitive kart possibilities, such as soaring through the skies or plunging to the depths of the sea. New courses, strategic new abilities and customizable karts bring the racing excitement to new heights.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-island-tour-nintendo-3ds', 'Mario Party: Island Tour', 'Mario Party', '2013-11-22', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co224q.jpg', 'Mario Party: Island Tour lets you take the fun on the road with your Nintendo 3DS system!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-star-rush-nintendo-3ds', 'Mario Party: Star Rush', 'Mario Party', '2016-11-04', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba35.jpg', 'A new Mario Party game for Nintendo 3DS that includes additions and changes to make it much more fast-paced and portable-friendly', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-the-top-100-nintendo-3ds', 'Mario Party: The Top 100', 'Mario Party', '2017-11-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2254.jpg', 'Mario Party: The Top 100 is a party compilation that brings together 100 of the series’ most memorable mini‑games from classic entries, optimized for quick competitive or casual sessions. Players compete in bite‑sized challenges that capture the series’ variety (timing tests, reflex puzzles, skill contests), either locally or in short online matches, preserving the pick‑up‑and‑play chaos and charm of Mario Party across multiple eras.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sports-superstars-nintendo-3ds', 'Mario Sports Superstars', NULL, '2017-03-24', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2251.jpg', 'Mario Sports Superstars is a multi‑sport compilation featuring five arcade‑style sports (soccer, baseball, tennis, golf, and horse racing), each with accessible controls and quick matches. Players pick from familiar Mario characters, compete in tournaments or single events, and enjoy local or online multiplayer alongside single‑player challenge modes.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-open-nintendo-3ds', 'Mario Tennis Open', 'Mario Tennis', '2012-05-20', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2242.jpg', 'Instantly jump into the multiplayer fun, locally or online, as your Mii or your favorite Mushroom Kingdom character. Discover simple touch screen controls as well as strategic depth with different tennis swings, both which propel the tennis experience into an ever-intensifying crescendo of fun as the volleys go on.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-super-soldier-nintendo-3ds', 'Captain America: Super Soldier', 'Marvel', '2011-07-19', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ovp.jpg', 'The Nintendo 3DS port of Captain America: Super Soldier.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thor-god-of-thunder-nintendo-3ds', 'Thor: God of Thunder', 'Marvel', '2011-09-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co531w.jpg', 'Thor: God of Thunder is an action-adventure game developed by Liquid Entertainment and published by Sega in 2011. It serves as a tie-in to the Thor film from the Marvel Cinematic Universe. Players control Thor as he wields Mjolnir to battle enemies across the Nine Realms, facing iconic foes such as Surtur and Ulik while protecting Asgard from destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-edge-of-time-nintendo-3ds', 'Spider-Man: Edge of Time', 'Marvel', '2011-10-04', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h30.jpg', 'The fate of one Webslinger hangs on the webs of another in this game where two Spider-Man worlds collide with the death - yes, the death - of Peter Parker. Play as the Amazing Spider-Man and Spider-Man 2099 in a storyline that weaves together two timelines. The two heroes battle in separate worlds with a shared destiny, working to prevent an event that has dire consequences for Parker and the fate of the worlds he protects. Your actions in one timeline could cause ripple effects in the other. Picture-in-picture visuals let you watch your actions change the future - or rewrite the past - for better or for worse.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-the-infinity-gauntlet-nintendo-3ds', 'Marvel Super Hero Squad: The Infinity Gauntlet', 'Marvel', '2011-10-11', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2di9.jpg', 'Marvel Super Hero Squad: The Infinity Gauntlet is a continuation of the video game Marvel Super Hero Squad and it was released on November 16, 2010. Similar to the first game, it features cartoonish Super-deformed versions of the Marvel Comics characters, as seen in the Marvel Super Hero Squad toy line, as well as the television show.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-nintendo-3ds', 'The Amazing Spider-Man', 'Marvel', '2012-06-26', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-nintendo-3ds', 'The Amazing Spider-Man 2', 'Marvel', '2014-04-29', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-nintendo-3ds', 'Mega Man Legacy Collection', 'Mega Man', '2016-02-23', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-snake-eater-3d-nintendo-3ds', 'Metal Gear Solid: Snake Eater 3D', 'Metal Gear', '2012-02-21', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62i0.jpg', 'Metal Gear Solid: Snake Eater 3D is a stealth action game for the Nintendo 3DS. It is a re-release of Metal Gear Solid 3: Snake Eater. The game was released on February 21, 2012 in North America and on March 8, 2012 in Japan and Europe. It is also the first Metal Gear game released on a Nintendo-developed portable system since Metal Gear: Ghost Babel back in 2000. A digital download version was released in Japan via the Nintendo eShop function on the Nintendo 3DS on December 16, 2014, exactly a decade after the initial release of the original title.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-federation-force-nintendo-3ds', 'Metroid Prime: Federation Force', 'Metroid', '2016-08-19', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaay.jpg', '"The galaxy is not at peace. The war between the Galactic Federation and the Space Pirates is far from over. Enlist with the Federation Force to join a four-player local or online squad in this co-op sci-fi shooter. Fight alongside teammates in your specialized Mech to eliminate the Space Pirate menace and any threat that stands in your way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-samus-returns-nintendo-3ds', 'Metroid: Samus Returns', 'Metroid', '2017-09-15', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wwx.jpg', 'A Sinister Planet Threatens the Galaxy!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('miitopia-nintendo-3ds', 'Miitopia', 'Miitopia', '2017-07-28', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5akw.jpg', 'Miitopia needs YOU…to cast Mii characters for the three trailers in the Casting Call demo. Fill the roles with characters you create, or choose characters made by others. Then cast them, sit back, and watch your actors play their parts!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-3-ultimate-nintendo-3ds', 'Monster Hunter 3 Ultimate', 'Monster Hunter', '2013-03-19', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lh7.jpg', 'The popular fantasy action franchise Monster Hunter is now one of the most iconic gaming series in the world selling over 21 million copies worldwide since the series began in 2004. Players take on the role of a hunter and are sent to explore a settlement within the Monster Hunter universe, completing quests on their journey to seek and slay monsters whilst improving their skills and earning equipment upgrades. With many challenging monsters and over 200 quests the latest edition to the series is set to be the most expansive offering to date. Monster Hunter 3 Ultimate utilizes the functionalities of the Nintendo 3DS system to provide players with a truly intuitive hunting experience. The touch screen feature allows players to quickly access in-game books, weapons, field maps and mini games whilst the high quality graphics 3D visuals of Nintendo 3DS powered by the latest iteration of Capcom''s MT Framework deliver a unique and stunning world for players to explore. Taking advantage of the portability of Nintendo 3DS, players can exchange their guild card that contains all their hunter''s information with other players via StreetPass. Players can experience the world of Monster Hunter alone or in four player local play using Nintendo 3DS. Finding nearby hunters to adventure on quests with is now even easier via the local Nintendo 3DS search feature. Wii U players will be able to enjoy the hunt with Nintendo 3DS players via a local wireless connection. Gamers that own both a Wii U and Nintendo 3DS can take advantage of the inter compatibility of save data between the two consoles, taking the hunt from the living room wherever they go.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-4-ultimate-nintendo-3ds', 'Monster Hunter 4 Ultimate', 'Monster Hunter', '2015-02-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gkk.jpg', 'Monster Hunter 4 Ultimate (called Monster Hunter 4G in Japan) is the newest installment in the popular Monster Hunter series, which has sold more than 28 million units worldwide to date. In Monster Hunter 4 Ultimate, players will take on the role of a hunter that joins up with a traveling caravan to explore new lands and towns along the way. This grand adventure will include hundreds of quests to take on a variety of extraordinary creatures that yield valuable resources used for weapons and equipment. Launching on Nintendo 3DS, Monster Hunter 4 Ultimate represents the biggest leap forward ever for the series with more new content and exciting features than ever before. Also, for the first time ever for the Monster Hunter series on a handheld system, players will be able to join up with friends over the internet via the Nintendo Wi-Fi Connection, as well as the previously available local wireless option.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-generations-nintendo-3ds', 'Monster Hunter Generations', 'Monster Hunter', '2016-07-15', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3xrh.jpg', 'The Monster Hunter series is just as dense as the giant hunks of meat its hunting heroes scarf down: every proverbial bite is chock full of rich combat and succulent character customization, making for a dense, thoroughly satisfying action RPG feast.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-stories-nintendo-3ds', 'Monster Hunter Stories', 'Monster Hunter', '2017-09-08', 'Nintendo 3DS', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5j9q.jpg', 'Monster Hunter Stories is a role-playing game spin-off of the popular Monster Hunter franchise, but features a drastically different gameplay focus. Unlike previous titles in the franchise, Monster Hunter Stories lets players take on the role of a Rider instead of a Hunter, and are able to take part in a traditional turn-based battle system. Major changes and additions featured in this title include hatching eggs and befriending monsters, battling alongside them, executing special kinship techniques, and customizing monsters'' abilities and appearance', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-nes-remix-nintendo-3ds', 'Ultimate NES Remix', 'NES Remix', '2014-12-05', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzu.jpg', 'Take on a rapid-fire onslaught of challenges and mash-ups from 16 of Nintendo’s finest 8-bit games! Test your skills on a gauntlet of quick, tricky challenges and remix stages that combine parts of different games. The best mix of titles from the NES Remix and NES Remix 2 games is on Nintendo 3DS. Now you’re playing with PORTABLE power!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-party-nintendo-3ds', 'Pac-Man Party', 'Pac-Man', '2010-11-16', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22kz.jpg', 'A brand-new arcade experience featuring a four-player Battle Mode where the last PAC-MAN standing wins.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-nintendo-3ds', 'Pac-Man and the Ghostly Adventures', 'Pac-Man', '2013-10-29', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-2-nintendo-3ds', 'Pac-Man and the Ghostly Adventures 2', 'Pac-Man', '2014-10-14', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-galaga-dimensions-nintendo-3ds', 'Pac-Man & Galaga Dimensions', NULL, '2011-07-27', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnv.jpg', 'Includes Pac-Man, Galaga, Pac-Man Championship Edition, Galaga Legions, Pac-Man Tilt and Galaga 3D Impact, the last two of which are exclusive to this compilation.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-sticker-star-nintendo-3ds', 'Paper Mario: Sticker Star', 'Paper Mario', '2012-11-11', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tfp.jpg', 'A sticky situation has never been so fun! There''s trouble afoot in the town of Decalburg, where the devious Bowser has disrupted the beloved Sticker Fest by causing the Sticker Comet to explode. Now Royal Stickers and pieces of the comet have been flung far and wide, and it''s up to Mario and his ally Kersti to set things right by recovering them. This captivating hand-held adventure will have new and experienced fans of the Paper Mario series captivated as they navigate colorful 3D environments, defeat enemies, collect oodles of stickers and items and use them in a variety of fun ways.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-q-shadow-of-the-labyrinth-nintendo-3ds', 'Persona Q: Shadow of the Labyrinth', 'Persona', '2014-11-25', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jpi.jpg', 'Persona Q is a crossover video game, containing characters from both Persona 3 and Persona 4 in a game based on Etrian Odyssey, with its perspective, play-style, and systems.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-q2-new-cinema-labyrinth-nintendo-3ds', 'Persona Q2: New Cinema Labyrinth', 'Persona', '2019-06-04', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8l09.jpg', 'The dream meeting of Persona 3, 4, 5! Welcome to the movie world (Labyrinth).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hey-pikmin-nintendo-3ds', 'Hey! Pikmin', 'Pikmin', '2017-07-28', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h9z.jpg', 'Captain Olimar has crashed on an unknown planet inhabited by Pikmin and his first 2D platformer will give you a new perspective on his adorably fierce partners. Touch the screen to throw Pikmin into action: swim with Blue Pikmin, fly with Winged Pikmin, and more to survive hostile wildlife, solve ecological puzzles, and escape!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pilotwings-resort-nintendo-3ds', 'Pilotwings Resort', 'Pilotwings', '2011-03-27', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uzx.jpg', 'Pilotwings Resort, an aerial adventure featuring airplanes, hang gliders and rocket belts. Players soar above tropical Wuhu Island in 3D as they complete missions or snap pictures.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-rumble-blast-nintendo-3ds', 'Pokémon Rumble Blast', 'Pokémon', '2011-10-24', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z24.jpg', 'Pokemon Rumble Blast, the first Pokemon game created exclusively for the Nintendo 3DS system, is an action-packed Pokemon adventure in 3D! Battle against waves of opponents, connect and play with friends, and collect more than 600 different Toy Pokemon!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-gates-to-infinity-nintendo-3ds', 'Pokémon Mystery Dungeon: Gates to Infinity', 'Pokémon', '2013-03-24', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4z.jpg', 'Discover the incredible 3D world of Pokemon Mystery Dungeon: Gates to Infinity, where Pokemon speak and amazing adventures are always nearby! What''s more, you will become a Pokemon yourself! You''ll meet all kinds of Pokemon throughout the game, both in the towns you''ll visit and the Mystery Dungeons you''ll explore.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-x-nintendo-3ds', 'Pokémon X', 'Pokémon', '2013-10-12', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z8y.jpg', 'An all-new 3D Pokemon adventure packed with never-before-seen Pokemon will launch worldwide in October 2013. Pokemon X and Pokemon Y will present a new generation of Pokemon, and introduce players to an exciting new adventure in a breathtaking 3D world.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-y-nintendo-3ds', 'Pokémon Y', 'Pokémon', '2013-10-12', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z9m.jpg', 'Your adventure in Pokémon X and Pokémon Y takes place in the Kalos region, home to beautiful skies and forests! The Kalos region is full of interesting places to visit and explore!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-omega-ruby-nintendo-3ds', 'Pokémon Omega Ruby', 'Pokémon', '2014-11-21', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sz3.jpg', 'During your adventure, you will battle Team Magma in Pokémon Omega Ruby and Team Aqua in Pokémon Alpha Sapphire. Team Magma seeks to increase the land, while Team Aqua wishes to increase the seas. In order to bring about these grand plans, each will turn to the power of a Legendary Pokémon: Groudon or Kyogre. Team Magma pursues Groudon, while Team Aqua goes after Kyogre. What could be driving them to such lengths?', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-alpha-sapphire-nintendo-3ds', 'Pokémon Alpha Sapphire', 'Pokémon', '2014-11-21', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56ef.jpg', 'During your adventure, you will battle Team Magma in Pokémon Omega Ruby and Team Aqua in Pokémon Alpha Sapphire. Team Magma seeks to increase the land, while Team Aqua wishes to increase the seas. In order to bring about these grand plans, each will turn to the power of a Legendary Pokémon: Groudon or Kyogre. Team Magma pursues Groudon, while Team Aqua goes after Kyogre. What could be driving them to such lengths?', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-super-mystery-dungeon-nintendo-3ds', 'Pokémon Super Mystery Dungeon', 'Pokémon', '2015-11-20', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zj4.jpg', 'Pokémon Super Mystery Dungeon is a roguelike video game in the Pokémon Mystery Dungeon series. Like its predecessors, players control a human who has awoken as a Pokémon in a world filled entirely by the series'' eponymous creatures, and must travel through random-generated dungeons completing missions and battling enemies to unravel the story.', NULL, 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-rumble-world-nintendo-3ds', 'Pokémon Rumble World', 'Pokémon', '2016-04-29', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zj0.jpg', 'Pokémon Rumble World is a freemium Nintendo 3DS game released in most regions on April 8, 2015. The game is free to download, but features in-game microtransactions. The game features all 719 species of Pokémon, as well as Mega Evolution and Primal Kyogre and Groudon. It is the fourth entry in the Pokémon Rumble series.', NULL, 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-sun-nintendo-3ds', 'Pokémon Sun', 'Pokémon', '2016-11-18', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3co7.jpg', 'Pokémon Sun and Pokémon Moon trademarks were registered thus leaking the next Pokémon game titles to the public. Pokémon.com confirmed the games would be for the Nintendo 3DS and released in holiday 2016, with a new world, new Pokémon, and new adventures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-moon-nintendo-3ds', 'Pokémon Moon', 'Pokémon', '2016-11-18', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3co8.jpg', 'Pokémon Sun and Pokémon Moon will be the first games in the Pokémon series to allow players to choose from nine languages to play in. In addition to English, French, German, Italian, Japanese, Korean, and Spanish, players will now be able to play in both Traditional and Simplified Chinese.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ultra-sun-nintendo-3ds', 'Pokémon Ultra Sun', 'Pokémon', '2017-11-17', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zjs.jpg', '"Take on the role of a Pokémon Trainer and uncover new tales, and unravel the mystery behind the two forms reminiscent of the Legendary Pokémon. With new story additions and features this earns Pokémon Ultra Sun and Pokémon Ultra Moon the name "Ultra!" Another adventure is about to begin!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-ultra-moon-nintendo-3ds', 'Pokémon Ultra Moon', 'Pokémon', '2017-11-17', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zjt.jpg', '"Take on the role of a Pokémon Trainer and uncover new tales, and unravel the mystery behind the two forms reminiscent of the Legendary Pokémon. With new story additions and features this earns Pokémon Ultra Sun and Pokémon Ultra Moon the name "Ultra!" Another adventure is about to begin!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('detective-pikachu-nintendo-3ds', 'Detective Pikachu', 'Pokémon', '2018-03-23', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zk8.jpg', 'Detective Pikachu is an adventure game developed by Creatures Inc., published by The Pokémon Company, and distributed by Nintendo for the Nintendo 3DS. The game is a spin-off of the Pokémon franchise, in which players work with a talking Pikachu to solve mysteries. A shorter, downloadable version of the game called Great Detective Pikachu: Birth of a New Duo was released in Japan in February 2016, while the full version was released worldwide in March 2018.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puzzle-dragons-z-super-mario-bros-edition-nintendo-3ds', 'Puzzle & Dragons Z + Super Mario Bros. Edition', NULL, '2015-05-22', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bvp.jpg', 'Role-playing elements and match-three puzzle fun meet in Puzzle & Dragons Z + Puzzle & Dragons: Super Mario Bros. Edition. In a single package containing both games, explore dungeons, command monsters and master all types of elemental Orbs to defeat the enemy hordes!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('raving-rabbids-travel-in-time-nintendo-3ds', 'Raving Rabbids: Travel in Time', 'Rabbids', '2011-04-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jqi.jpg', 'Raving Rabbids: Travel in Time is a party game for the Wii in which the titular Rabbids travel back in time using a washing machine. Its various co-operative and competitive mini-games can be played alone or with 2-4 players both online and offline.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-rumble-nintendo-3ds', 'Rabbids Rumble', 'Rabbids', '2012-11-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8n5n.jpg', 'Rabbids have escaped from your cartridge all over your Nintendo 3DS and found their way into the real world. You must collect them throughout 7 worlds full of mini games and bring the complete collection back, one battle at the time!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-3d-nintendo-3ds', 'Rayman 3D', 'Rayman', '2011-03-27', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3km2.jpg', 'One of the most popular franchises of all time lands on Nintendo 3DS with an outstanding platform experience that will take advantage of the Nintendo 3DS specifications with impressive graphics, stunning 3D effects and full use of the Circle Pad. An adaptation of the acclaimed Rayman 2 original game on Dreamcast, Rayman 3D will feature major updates on key game play elements such as accessibility, progression and learning curve.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-origins-nintendo-3ds', 'Rayman Origins', 'Rayman', '2012-11-06', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v7k.jpg', 'Bubble Dreamer, Rayman, his best friend Globox, and some Teensy friends are chilling out at the Bubble Dreamer''s resting grounds, the Snoring Tree. However, their snoring disturbs an old granny from the Land of the Livid Dead, who retaliates by sending an evil army of horrendous creatures and the Darktoons across the world, capturing the Electoons that inhabit the world, imprisoning Betilla the Nymph and her sisters, and plunging the Glade into chaos. As a result, the ensuing disaster causes the Bubble Dreamer to go crazy and have nightmares. Although they are captured, Rayman and his friends are able to escape the Darktoons. They are then tasked by the Magician to gather enough Electoons to cure the Bubble Dreamer and restore the Glade of Dreams. Their efforts to locate the Electoons allow them to gain access to the various lands of the Glade, rescuing the Nymphs along the way.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-the-mercenaries-3d-nintendo-3ds', 'Resident Evil: The Mercenaries 3D', 'Resident Evil', '2011-06-28', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54id.jpg', 'Resident Evil: The Mercenaries 3D is an action-oriented title where players can choose any of eight playable characters to shoot, explode and melee their way through swarms of enemies. Featuring re-mastered stages from Resident Evil 4 and Resident Evil 5, the game is a race against time as players try to defeat as many enemies as possible before the countdown reaches zero. The experience is available both as solo and multiplayer, where gamers across the world can team up and enjoy two-player co-op.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-nintendo-3ds', 'Resident Evil: Revelations', 'Resident Evil', '2012-02-07', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-nintendo-3ds', 'Shakedown: Hawaii', 'Retro City Rampage', '2023-11-06', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rodea-the-sky-soldier-nintendo-3ds', 'Rodea the Sky Soldier', NULL, '2015-11-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gfn.jpg', 'A thousand years ago, Emperor Geardo of the Naga Empire sent an army of machine soldiers to invade the sky kingdom of Garuda. Thanks to the efforts of Princess Cecilia and Rodea, a machine soldier who promised to protect Garuda, Emperor Geardo''s assault was thwarted. In present day, a spirited inventor named Ion discovers an abandoned robot that has fallen into disrepair in the heart of a scorching desert. Upon completing her repairs, the robot stirs to life and reveals itself to be none other than Rodea. Stunned to find himself in the future, Rodea learns that the Naga Empire is no more and that Garuda has known peace for a thousand years. But this peace was not meant to last, for the forces of Naga have returned to wage war against Garuda. Remembering the promise he made 1,000 years ago, Rodea takes to the skies to defend Garuda from the Naga Empire once again.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rollercoaster-tycoon-3d-nintendo-3ds', 'RollerCoaster Tycoon 3D', 'RollerCoaster Tycoon', '2012-10-16', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6iu2.jpg', 'The next installment of the hit RollerCoaster Tycoon franchise is here and this time, its in 3D!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-4-nintendo-3ds', 'Rune Factory 4', 'Rune Factory', '2013-10-01', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xko.jpg', 'Rune Factory 4 marks the return of the popular Harvest Moon spinoff that combines farming with dungeon adventuring. For the first time in the series, the player can select to play as a male or female hero, and potential suitors of either gender are also available in order to pursue love, marriage, and possibly a child. As the newly-appointed prince or princess, you can fulfill your royal duties of protecting the town from invaders, or take a more rural approach to governing by raising your own fruits and vegetables and helping townsfolk. Should some dungeon adventuring be on the days itinerary, you can select from the castles vast armament of swords, spears, and staffs along with magic for battle against dangerous foes, or even bring along a companion or friendly monster to aid you during your travels.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-unlimited-nintendo-3ds', 'Scribblenauts Unlimited', 'Scribblenauts', '2012-11-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1my3.jpg', 'Venture into a wide-open world where the most powerful tool is your imagination. Help Maxwell solve robust puzzles in seamless, free-roaming levels by summoning any object you can think of. Create your own original objects, assign unique properties, and share them with friends online using Steam Workshop – to be used in game or further modified as you like!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-unmasked-a-dc-comics-adventure-nintendo-3ds', 'Scribblenauts Unmasked: A DC Comics Adventure', 'Scribblenauts', '2013-09-24', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ns6.jpg', 'Scribblenauts Unmasked: A DC Comics Adventure is a puzzle video game developed by 5th Cell and published by Warner Bros. Interactive Entertainment. It is the fifth game in the Scribblenauts series of games and the first based on a licensed property. The game combines the series'' traditional gameplay of bringing up words and objects to solve puzzles with characters and settings from the DC Comics universe (DC Universe).', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-3d-classics-collection-nintendo-3ds', 'Sega 3D Classics Collection', NULL, '2016-04-26', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sp5.jpg', 'Sega 3D Classics Collection is a Sega Genesis compilation game developed by M2 and published by Sega for the Nintendo 3DS.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-all-stars-racing-transformed-nintendo-3ds', 'Sonic & All-Stars Racing Transformed', 'Sega All-Stars', '2013-02-12', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvw.jpg', 'Race as Sonic and a host of legendary All-Stars and prepare to transform! Speed across land, sea and air in a high velocity battle to the finish line, as your amazing transformable vehicle changes from car to boat to plane mid-race. Racing on mobile will never be the same again!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-pirate-s-curse-nintendo-3ds', 'Shantae and the Pirate''s Curse', 'Shantae', '2014-10-23', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b1u.jpg', 'Embark on a brand new adventure with Shantae, the hair-whipping belly dancing genie. When she loses her magic, Shantae must team up with her nemesis, the nefarious pirate Risky Boots in order to save Sequin Land from an evil curse. As a pirate, Shantae gains new weapons to advance her quest, slay monsters, battle epic bosses…and hopefully get her magic back in the bargain! But can she really trust her deadliest enemy?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-nintendo-3ds', 'Shovel Knight', 'Shovel Knight', '2015-11-03', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaa7.jpg', 'Shovel Knight is a sweeping classic action adventure game with awesome gameplay, memorable characters, and an 8-bit retro aesthetic. It''s a hot mashup of new and old! You play as the eponymous Shovel Knight, a small knight with a huge quest. Shovel Knight has come to this land with two goals: to defeat the evil Enchantress and quest for his lost beloved. He wields a Shovel Blade: a multipurpose weapon whose techniques have now been lost to the ages. Always honest and helpful, Shovel Knight is a shining example of the code of Shovelry: Slash Mercilessly and Dig Tirelessly!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-nintendo-3ds', 'The Sims 3', 'The Sims', '2011-03-27', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nas.jpg', 'The Sims 3 is a console game developed by Electronic Arts for the Nintendo Wii.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-pets-nintendo-3ds', 'The Sims 3: Pets', 'The Sims', '2011-10-18', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7jis.jpg', 'Bring excitement and surprise into your Sims'' lives with pets in The Sims 3: Pets, an expansion pack for The Sims 3! Create the perfect (or imperfect) pets for your Sims, from fierce guard dogs to destructive kittens to trusty horses and more as you determine not only how your Sims'' pets look but their personality traits as well. With a variety of new activities and social interactions, take direct control of your Sims'' pets and explore new ways to mess with their lives. Give your Sims a new member of their household and discover all-new ways to play with life!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-spyro-s-adventure-nintendo-3ds', 'Skylanders: Spyro''s Adventure', 'Skylanders', '2011-10-16', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsc.jpg', 'Skylanders: Spyro''s Adventure is the first video game in the Skylanders series. It is a video game that is played along with toy figures that interact with it through a "Portal of Power", that reads their tag through NFC and features the voices of Josh Keaton, Dave Wittenberg, Darin De Paul, Joey Camen, Audrey Wasilewski, Keythe Farley and Kevin Michael Richardson.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-giants-nintendo-3ds', 'Skylanders: Giants', 'Skylanders', '2012-10-21', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vlm.jpg', 'Skylanders: Giants is a 2012 video game in the Skylanders series, a direct sequel to the 2011 game Skylanders: Spyro''s Adventure and features the voices of Kevin Michael Richardson, Greg Ellis, Peter Lurie, Steve Blum, Dave Wittenberg, Carlos Alazraqui, Kevin Sorbo, Bobcat Goldthwait, Patrick Seitz and Julie Nathanson. It is the game before Skylanders: Swap Force. As the title suggests, it features larger Skylanders known as "Giants", along with other new gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-nintendo-3ds', 'Skylanders: Swap Force', 'Skylanders', '2013-10-13', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-nintendo-3ds', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-racing-nintendo-3ds', 'Skylanders: SuperChargers Racing', 'Skylanders', '2015-09-20', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ysr.jpg', 'Fans can augment their SuperCharger experience with a complementary, dedicated racing combat game -- Skylanders SuperChargers Racing -- for the Wii system and Nintendo 3DS hand-held system. All-new tracks, augmented with power-ups, boosts, hazards and more, offer up to 50 different and exciting gameplay experiences.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-generations-nintendo-3ds', 'Sonic Generations', 'Sonic the Hedgehog', '2011-11-22', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zya.jpg', 'In the 3DS version of Sonic Generations, Modern Sonic''s gameplay is similar to that of Sonic Rush and the DS version of Sonic Colors. He has the Boost, the ability to slide under obstacles, jump off walls, and the Homing Attack. After the second era, Modern Sonic learns the Stomp. Modern Sonic''s levels use the 3D effect of depth on the 3DS version more actively as well as to giving a better view for when Modern Sonic jumps into the background, although the console versions are 3D-TV compatible. In the HD version, Modern Sonic is only able to wall jump off certain panels (similar to the DS version of Sonic Colors), but in the 3DS version, he is able to wall jump on any wall (much like Sonic Unleashed and the Wii version of Sonic Colors).', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-lost-world-nintendo-3ds', 'Sonic Lost World', 'Sonic the Hedgehog', '2013-10-29', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9112.jpg', 'Dr. Eggman is at it again! The dastardly doctor has outdone himself this time, harnessing the power of menacing creatures known as the Deadly Six. But when they rise up against their master, Sonic and Dr. Eggman must put their rivalry to one side and work together in Sonic Lost World on Nintendo 3DS.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-boom-shattered-crystal-nintendo-3ds', 'Sonic Boom: Shattered Crystal', 'Sonic the Hedgehog', '2014-11-11', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7be4.jpg', 'In Sonic Boom: Shattered Crystal, Amy discovers a secret ancient language and manuscript detailing the history and whereabouts of a Lost Crystal of Power. The evil and vile villain, Lyric the Last Ancient, kidnaps Amy in his eagerness to get his claws on this long-forgotten power that has been hidden throughout the jungles and canyons of a mysterious new island. Sonic must team up with Tails, Knuckles and new friend Sticks the Badger to trace Amy’s footsteps and save her from the clutches of Lyric and his robot army. By trusting in their own abilities and working as a team, they will prove they are stronger together than they are apart.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-boom-fire-ice-nintendo-3ds', 'Sonic Boom: Fire & Ice', 'Sonic the Hedgehog', '2016-09-27', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wxi.jpg', 'Sonic Boom: Fire & Ice, known as Sonic Toon: Fire & Ice in Japan, is an upcoming 2016 action-adventure platform game developed by Sanzaru Games and published by Sega. It is part of the Sonic Boom spin-off franchise of the Sonic the Hedgehog series, along with the games Rise of Lyric and Shattered Crystal, and a TV show. Originally planned for a release in Fall 2015, Fire & Ice is now scheduled to be released on the Nintendo 3DS in 2016
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-64-3d-nintendo-3ds', 'Star Fox 64 3D', 'Star Fox', '2011-09-09', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3e.jpg', 'The Star Fox team triumphantly returns to one of its greatest missions with this remake of Star Fox 64 in full 3D, featuring a complete graphical update.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-3d-the-tale-of-two-towns-nintendo-3ds', 'Harvest Moon 3D: The Tale of Two Towns', 'Story of Seasons', '2011-11-01', 'Nintendo 3DS', 0, 0, NULL, NULL, NULL, NULL, 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-3d-a-new-beginning-nintendo-3ds', 'Harvest Moon 3D: A New Beginning', 'Story of Seasons', '2012-11-06', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xkq.jpg', 'Harvest Moon: A New Beginning is a farming simulation game for the Nintendo 3DS video game console. As the new farmer in town, it is your job to use your farm and its resources to revitalize a once-popular town. You can grow crops and raise animals, as well as interact with villagers and possibly get married.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hometown-story-nintendo-3ds', 'Hometown Story', 'Story of Seasons', '2013-10-22', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rd.jpg', 'Originally announced as Project Happiness, HomeTown Story is a simulation game from Harvest Moon creator Yasuhiro Wada about a shopkeeper taking over their grandmother''s shop.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('story-of-seasons-nintendo-3ds', 'Story of Seasons', 'Story of Seasons', '2015-03-31', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl4.jpg', 'Story of Seasons is the latest Harvest Moon title and allows players to fully create their own character from scratch. XSEED will be bringing the game to North America in 2014.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-popolocrois-a-story-of-seasons-fairytale-nintendo-3ds', 'Return to PopoloCrois: A Story of Seasons Fairytale', 'Story of Seasons', '2016-03-01', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56oz.jpg', 'The fairy tale world of PoPoLoCrois meets the farm living of Story of Seasons in this cross-over RPG. It features classically-styled turn-based combat and towns full of lively and interesting NPCs who contribute to a heartwarming narrative that veterans or newcomers to either franchise can enjoy. Ample farming and life simulation elements such as crop-raising, bug-catching, rock quarrying, item synthesis and more round out the experience.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('story-of-seasons-trio-of-towns-nintendo-3ds', 'Story of Seasons: Trio of Towns', 'Story of Seasons', '2017-02-28', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2haz.jpg', 'The series is celebrating its 20th anniversary with a new game for the Nintendo 3DS. The title of the game is Bokujō Monogatari: Mitsu no Sato no Taisetsu na Tomodachi (Harvest Moon/Story of Seasons: Precious Friends From Three Villages).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-3d-nintendo-3ds', 'Super Monkey Ball 3D', 'Super Monkey Ball', '2011-03-27', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5j9r.jpg', 'Taking advantage of the power of the Nintendo 3DS, players can let themselves loose in each new vibrant world as they twist and turn whilst aiming to collect every banana in the fastest time possible. This latest installment contains three brand-new compelling gameplay choices including single-player puzzle levels, Monkey Race and Monkey Fight. These new game modes give players the chance to compete via wireless connection with up to four players in the best 3D social experience possible in the palm of their hands. In addition, Super Monkey Ball fans will be able to choose between the Nintendo 3DS motion sensor or the Slide Pad to navigate the puzzle mazes with complete precision.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-for-nintendo-3ds-nintendo-3ds', 'Super Smash Bros. for Nintendo 3DS', 'Super Smash Bros.', '2014-10-03', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45q9.jpg', 'Super Smash Bros. Melee veteran Roy from the Fire Emblem series joins the fight once again!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-the-abyss-nintendo-3ds', 'Tales of the Abyss', 'Tales', '2012-02-14', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yw8.jpg', 'This entry in Namco''s popular Tales series takes place in a world where prophecies clue people in to future happenings. Tales of the Abyss boasts a revolutionary new free roaming battle system allowing players to move anywhere on the battlefield, a first in the Tales series which brings new depth to the intense, high-action battles that Tales games are knows for.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-nintendo-3ds', 'Terraria', NULL, '2015-12-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-axis-nintendo-3ds', 'Tetris: Axis', 'Tetris', '2011-10-02', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co772g.jpg', 'The original portable Tetris game was a smash hit on the Game Boy system. The new Tetris: Axis game lets players use the magic of the Nintendo 3DS system to jump into the action in 3D without the need for special glasses. The game includes more than 20 different modes – some familiar, some new. Up to eight players can compete in wireless multiplayer battles, even if only one player has a game card.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-ultimate-nintendo-3ds', 'Tetris Ultimate', 'Tetris', '2014-11-11', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rkf.jpg', 'Tetris Ultimate has six exciting modes, fun new features, and unique visuals, the evolution of this iconic game is the ultimate must-have on next-gen consoles.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-chaos-theory-nintendo-3ds', 'Tom Clancy''s Splinter Cell: Chaos Theory', 'Tom Clancy''s Splinter Cell', '2011-04-10', 'Nintendo 3DS', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rb.jpg', 'Tom Clancy''s Splinter Cell: Chaos Theory is the mobile version of the console game of the same name and the fourth mobile game in the series. Like the previous games in the series it is a stealth based platform game played from a side view perspective and has similar gameplay. The player once again controls Sam Fisher who has to prevent terrorists from crashing the global stock markets and overthrow the world''s governments.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomodachi-life-nintendo-3ds', 'Tomodachi Life', NULL, '2014-06-06', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobdqd.jpg', 'Create Mii characters based on family and friends, someone you admire, or something completely original—there are plenty of personality traits, little quirks, and physical traits to choose from—including some face customization options you haven’t seen before! Go deep into getting every detail just right, or create Miis quickly and easily by answering some simple questions, and then help them explore their likes and dislikes, find relationships, and get up to all sorts of fun. Your Miis are bound to surprise you as they take on a life of their own!', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-gold-nintendo-3ds', 'WarioWare Gold', 'WarioWare', '2018-08-03', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wmc.jpg', 'The infamous schemer, Wario, is back!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-new-island-nintendo-3ds', 'Yoshi''s New Island', 'Yoshi', '2014-03-14', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8pz.jpg', 'Yoshi and Baby Mario are back in Yoshi''s New Island, the third installment in the beloved franchise. The series'' fun game-play mechanics such as Yoshi''s Flutter Jump, Ground Pound and Egg Throw return, but now Yoshi knows a ton of new tricks too. Yoshi gets to bash and thrash his environment by throwing around Mega Eggdozers and Metal Eggdozers. Yoshi also can transform into a variety of objects, such as a jackhammer or a submarine, both of which can be manipulated using the Nintendo 3DS gyro controls. A certain type of star even transforms him into Super Yoshi, giving him the ability to fly through the sky or run along walls and ceilings. Players who are having trouble completing a level might see the appearance of Flutter Wings, which let Yoshi fly through the air.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('poochy-yoshi-s-woolly-world-nintendo-3ds', 'Poochy & Yoshi''s Woolly World', 'Yoshi', '2017-02-03', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wj7.jpg', 'Discover a handicraft world bursting at the seams with creativity, as you guide Yarn Yoshi or Yarn Poochy through clever side-scrolling stages. Unravel secrets, toss yarn to weave platforms, and power up with woolly transformations. All stages from the Wii U version are joined by new ones starring Poochy and more Nintendo 3DS exclusive features!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zero-escape-virtue-s-last-reward-nintendo-3ds', 'Zero Escape: Virtue''s Last Reward', 'Zero Escape', '2012-10-23', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co260l.jpg', 'The second game in the Zero Escape series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zero-escape-zero-time-dilemma-nintendo-3ds', 'Zero Escape: Zero Time Dilemma', 'Zero Escape', '2016-06-28', 'Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86n5.jpg', 'Zero Time Dilemma is the third and final entry in the Zero Escape series. It is a story focused mystery/thriller visual novel with multiple endings that involves player choices and puzzle rooms.', 'NA', 23);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-amiibo-festival-wii-u', 'Animal Crossing: Amiibo Festival', 'Animal Crossing', '2015-11-13', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sao.jpg', 'The Animal Crossing: amiibo Festival game is a brand-new way to play with your favorite Animal Crossing characters. Your amiibo figures are front-and-center in this party game, and you’ll get to use them with fun content. Bring to life an expansive and dynamic board game where the board is based on the months of the year like the core Animal Crossing series. The goal? Make your villager the happiest in town and party hard
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-wii-u', 'Assassin''s Creed III', 'Assassin''s Creed', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xii.jpg', 'The American Colonies, 1775. A brave young warrior fights to save his homeland. But what begins as a struggle over territory turns into an extraordinary journey that will transform him into a Master Assassin—and will forever change the destiny of a nation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iv-black-flag-wii-u', 'Assassin''s Creed IV: Black Flag', 'Assassin''s Creed', '2013-10-29', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tx9.jpg', NULL, 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-wii-u', 'Axiom Verge', 'Axiom Verge', '2016-09-01', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kml.jpg', 'After a lab accident, a scientist awakens in a mysterious, alien world. Is this a distant planet? The far future? Or a complex virtual-reality computer simulation?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-2-wii-u', 'Bayonetta 2', 'Bayonetta', '2014-10-24', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9e8.jpg', 'This Switch port adds amiibo support.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-toad-treasure-tracker-wii-u', 'Captain Toad: Treasure Tracker', NULL, '2014-12-05', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v2d.jpg', 'Captain Toad Treasure Tracker is a ROM hack/mod of Super Mario World which adapts the mechanics of the homonymous official game for the Wii U to a 2D platformer.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-wii-u', 'Darksiders II', 'Darksiders', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wi5.jpg', 'Become Death - The most feared of the legendary Four Horseman.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-warmastered-edition-wii-u', 'Darksiders: Warmastered Edition', 'Darksiders', '2017-05-23', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24hi.jpg', 'Deceived by the forces of evil into prematurely bringing about the end of the world, War – the first Horseman of the Apocalypse – stands accused of breaking the sacred law by inciting a war between Heaven and Hell. In the slaughter that ensued, the demonic forces defeated the heavenly hosts and laid claim to the Earth.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-city-wii-u', 'Batman: Arkham City', 'DC', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voh.jpg', 'Batman: Arkham City builds upon the intense, atmospheric foundation of Batman: Arkham Asylum, sending players soaring into Arkham City, the new maximum security "home" for all of Gotham City''s thugs, gangsters and insane criminal masterminds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-gods-among-us-wii-u', 'Injustice: Gods Among Us', 'DC', '2013-04-16', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8616.jpg', 'What if our greatest heroes became our greatest threat? Injustice: Gods Among Us introduces a bold new franchise to the fighting game genre from NetherRealm Studios, creators of the definitive fighting game Mortal Kombat. Featuring DC Comics icons such Batman, Cyborg, The Flash, Harley Quinn, Nightwing, Solomon Grundy, Superman and Wonder Woman, the latest title from the award-winning studio presents a deep original story. Heroes and villains will engage in epic battles on a massive scale in a world where the line between good and evil has been blurred.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-origins-wii-u', 'Batman: Arkham Origins', 'DC', '2013-10-25', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zg8.jpg', 'A free-to-play fighting video game for mobile that follows the same premise as the main versions of Arkham Origins.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-human-revolution-wii-u', 'Deus Ex: Human Revolution', 'Deus Ex', '2013-10-22', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rd2.jpg', 'In Deus Ex: Human Revolution you play Adam Jensen, a security specialist, handpicked to oversee the defense of one of America''s most experimental biotechnology firms. But when a black ops team breaks in and kills the scientists you were hired to protect, everything you thought you knew about your job changes. At a time when scientific advancements are routinely turning athletes, soldiers and spies into super-enhanced beings, someone is working very hard to ensure mankind''s evolution follows a particular path. You need to discover why - because the decisions you take and the choices you make will be the only things that can determine mankind''s future.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-wii-u', 'Disney Infinity', 'Disney Infinity', '2013-08-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-wii-u', 'Disney Infinity 2.0', 'Disney Infinity', '2014-09-23', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-3-0-wii-u', 'Disney Infinity 3.0', 'Disney Infinity', '2015-08-30', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-tropical-freeze-wii-u', 'Donkey Kong Country: Tropical Freeze', 'Donkey Kong', '2014-02-21', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pmi.jpg', 'Donkey Kong, Diddy Kong, Dixie Kong and Cranky Kong return for the franchise’s debut on Nintendo Switch. This title includes all the fun and challenge of the original game, plus a new beginner-friendly mode that lets players enjoy this critically acclaimed adventure as groovy surfing simian Funky Kong. Funky Kong can double jump, hover, perform infinite rolls and even perform infinite underwater corkscrews. Thanks to his sturdy surfboard, even spikes can’t slow him down.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-remastered-wii-u', 'DuckTales: Remastered', 'DuckTales', '2013-11-12', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zsa.jpg', 'DuckTales Remastered takes the classic Disney platforming adventure to a whole new level. All of the visuals from the 8-bit game have been beautifully re-created as hand-drawn and animated sprites, across a backdrop of luscious, re-envisioned level backgrounds. Furthermore, original Disney Character Voices talent, including some from the cartoon TV series, bring in-game characters to life with charm and wit, while the classic melodies of the original soundtrack are given a modern twist. The game also features an all new tutorial level where players can get familiar with the iconic pogo jump and cane swing, while Scrooge McDuck''s Museum allows players to track all their stats and compare their progress with others via global leaderboards.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-2-the-power-of-two-wii-u', 'Epic Mickey 2: The Power of Two', 'Epic Mickey', '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nhy.jpg', 'Unleash the power of the brush in an all new co-op adventure. Join Mickey and Oswald in an epic battle to save the magical world of Wasteland and change it forever. Interact with your favorite characters like never before in the most heroic adventure yet.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('giana-sisters-twisted-dreams-director-s-cut-wii-u', 'Giana Sisters: Twisted Dreams Director''s Cut', 'Giana Sisters', '2013-09-05', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rj3.jpg', 'Giana Sisters: Twisted Dreams is a platform game developed by Black Forest Games for Microsoft Windows. It is the successor to the 1987 Commodore 64 title The Great Giana Sisters and sequel to the 2009 re-imagining Giana Sisters DS. The game was funded through crowdfunding website Kickstarter, reaching its goal of $150,000.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-and-the-rainbow-curse-wii-u', 'Kirby and the Rainbow Curse', 'Kirby', '2015-02-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wcc.jpg', 'Do you have the magic touch? Then guide Kirby as he sets off on grand adventures in a hand-sculpted clay world. Draw lines on the touch screen of the Wii U GamePad controller to create rainbow-colored clay ropes to move Kirby around freely, or tap him to attack enemies or blast through obstacles. Transformations include a submarine, rocket and tank. In underwater levels, Kirby dons a swim mask. If his power level gets too low, a clay bandage appears on his head.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-the-wind-waker-hd-wii-u', 'The Legend of Zelda: The Wind Waker HD', 'The Legend of Zelda', '2013-09-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z6x.jpg', 'This Wii U bundle includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyrule-warriors-wii-u', 'Hyrule Warriors', 'The Legend of Zelda', '2014-09-26', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p0r.jpg', 'A Legendary Pairing: Cut down entire legions of enemies as Link, Zelda, Midna and other characters from The Legend of Zelda franchise using over-the-top powerful Dynasty Warriors-style moves. This tour de force through the beloved locales of Hyrule will have players battling some of the fiercest enemies in The Legend of Zelda history. Two players can play local co-op, with one player joining with the Wii U GamePad controller and another with the Wii U Pro Controller or Wii Remote and Nunchuk controllers.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-twilight-princess-hd-wii-u', 'The Legend of Zelda: Twilight Princess HD', 'The Legend of Zelda', '2016-03-04', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mqa.jpg', 'The Legend of Zelda: Twilight Princess HD is a Wii U enhanced remaster of the original game. It features graphical upgrades from the original version, higher resolution and minor gameplay changes.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-breath-of-the-wild-wii-u', 'The Legend of Zelda: Breath of the Wild', 'The Legend of Zelda', '2017-03-03', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67oa.jpg', 'The Legend of Zelda: Breath of the Wild game packs countless hours of play into a vast world of discovery. That makes it an ideal foundation for more adventures! This special bundle comes with the full game for the Nintendo Switch system and the Expansion Pass, which grants access to three new treasure chests, The Master Trials DLC Pack 1, and The Champions Ballad DLC Pack 2.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-city-undercover-wii-u', 'Lego City Undercover', 'Lego', '2013-03-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vx0.jpg', 'As Chase McCain, you''ll become an expert at hand-to-hand combat, fighting your foes and wrestling them to the ground until you can slap the cuffs on ''em. The best officers are also pros at free running, jumping, climbing, and traversing the city on special blue and white bricks. Do you have what it takes?', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-wii-u', 'Lego Batman 2: DC Super Heroes', 'Lego', '2013-05-21', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-wii-u', 'Lego Marvel Super Heroes', 'Lego', '2013-10-22', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-wii-u', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-wii-u', 'Lego The Hobbit', 'Lego', '2014-04-08', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-wii-u', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-wii-u', 'Lego Jurassic World', 'Lego', '2015-06-12', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dimensions-wii-u', 'Lego Dimensions', 'Lego', '2015-09-27', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w4t.jpg', 'Help stop crime in the Lego Dimensions multiverse with Lego City’s Chase McCain. Build and place Chase on the Lego Toy Pad to bring him to life in the game. Use his Lego City Detective Scanner to track down bad guys and change his disguise to unlock more abilities. Become a Miner to break Silver Lego bricks or a Fireman to use your Water Beam to put out fires. Unlock the Lego City Adventure World to explore new areas like Blackwell’s moonbase and the Lego City Police Department, and the Battle Arena to compete with up to 4 of your friends. Build Chase’s Police Helicopter to fire off bolts, then rebuild it into the Police Hovercraft and Police Plane for additional in-game abilities.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-wii-u', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-wii-u', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-mario-bros-u-wii-u', 'New Super Mario Bros. U', 'Mario', '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21ts.jpg', 'New Super Mario Bros. U is a side-scrolling 2.5D platform game, and the fourth and latest installment in the New Super Mario Bros. series. As the sequel to New Super Mario Bros. Wii, the game is a follow-up game of New Super Mario Bros. 2. It uses new, more detailed background styles and models and introduces the Flying Squirrel power-up, acquired by Mario and his friends from an item called the Super Acorn, as well as utilizing the Wii U GamePad in Boost Mode. In addition to the core campaign, there are also challenge modes.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-luigi-u-wii-u', 'New Super Luigi U', 'Mario', '2013-08-15', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22qv.jpg', 'This is a disc that combines the two games New Super Mario Bros. U and New Super Luigi U.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-3d-world-wii-u', 'Super Mario 3D World', 'Mario', '2013-11-22', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g5s.jpg', 'Super Mario 64 3D World is a ROM Hack made by Kaze Emanuar. This is a character hack that allows players to play as Mario, Luigi, Toad, Peach or Rosalina, each one with their signature abilities and gameplay from Super Mario 3D World. Unlike in Super Mario 64 DS, players can select a character in the file select screen and star select screen.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-maker-wii-u', 'Super Mario Maker', 'Mario', '2015-09-11', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uje.jpg', 'Super Mario 64 Maker (or Super Mario Maker 64) is a ROM Hack made by Kaze Emanuar inspired by the game Super Mario Maker for the Nintendo Wii U. Super Mario 64 Maker allows players to build and share their own custom Super Mario 64 levels in game (and transfer them using save states).', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-sochi-2014-olympic-winter-games-wii-u', 'Mario & Sonic at the Sochi 2014 Olympic Winter Games', 'Mario & Sonic at the Olympic Games', '2013-11-15', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ww7.jpg', 'Mario & Sonic at the Sochi 2014 Olympic Winter Games is a Wii U game, and is the fourth installment in the Mario & Sonic series. It includes a variety of events from the winter games such as skiing, figure skating, and curling. As the title implies, the game is centered around the 2014 Olympic Winter Games, taking place in Sochi, Russia. Different events uses the Wii Remote Plus controller, Wii U GamePad, or both. As the other games in the series, it features realistic events with ones in Mario''s and Sonic''s worlds. As the game is a Wii U exclusive, Mario & Sonic at the Sochi 2014 Olympic Winter Games is the first in the series to not have a handheld version.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-rio-2016-olympic-games-wii-u', 'Mario & Sonic at the Rio 2016 Olympic Games', 'Mario & Sonic at the Olympic Games', '2016-06-24', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22wj.jpg', 'A new 3DS game sees Mario and Sonic team up to compete in a whole range of different Olympic games. You can download to three other 3DS’s and play four players in each of the different events. There’s also a Pocket Marathon mode than uses the motion sensor in the 3DS to act like a pedometer and challenge people to get outside and get active.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-8-wii-u', 'Mario Kart 8', 'Mario Kart', '2014-05-30', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co213q.jpg', 'Turn your racing experience upside down! Nintendo’s Mario Kart franchise comes to the Wii U console in full HD, introducing new racing circuit designs and anti-gravity karts that will have players driving upside down. And for the first time, all of Bowser’s seven Koopalings are playable characters-- get a taste of being bad on the race track by playing as Iggy, Larry, Lemmy, Ludwig, Morton, Roy and Wendy. Players will also enjoy a variety of series-favorite features, including the return of 12-player online competitive play, hang-gliders, underwater racing and motorbikes.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-10-wii-u', 'Mario Party 10', 'Mario Party', '2015-03-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3h.jpg', 'Mario Party 10 has tons of fun new ways to play, challenge, and triumph over your friends, with new modes and a wealth of other exciting goodies. Strategize your way around a variety of unique boards to gather coins and stars, and best your buddies. In Bowser Party mode, you can take the role of bad guy Bowser to mess with your friends’ game. Need to let off some steam? Challenge your friends to a bunch of exciting minigames, unlock bonus content, and more.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-ultra-smash-wii-u', 'Mario Tennis: Ultra Smash', 'Mario Tennis', '2015-11-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2252.jpg', 'Grab your friends and family and dive into multiplayer mayhem with Mario Tennis: Ultra Smash on the Wii U console. Along with the fun and dynamic gameplay known to the franchise, surprise your opponents with a new move to the series, the Jumpshot, which sends the ball flying down the court.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-avengers-battle-for-earth-wii-u', 'Marvel Avengers: Battle for Earth', 'Marvel', '2012-12-04', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22so.jpg', 'The Skrulls have landed and now it is up to you to embody your favorite Marvel super heroes and defeat epic enemies during the Secret Invasion. Unleash your inner superhero in Marvel Avengers Battle For Earth!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-wii-u', 'The Amazing Spider-Man', 'Marvel', '2013-03-05', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-wii-u', 'The Amazing Spider-Man 2', 'Marvel', '2014-04-29', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-3-wii-u', 'Mass Effect 3', 'Mass Effect', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5rwt.jpg', 'The N7 Digital Deluxe Edition contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mighty-no-9-wii-u', 'Mighty No. 9', NULL, '2016-06-21', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaquo.jpg', 'Well to celebrate Cirno day and for the ⑨Jam, i made this small little game about cirno.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-wii-u-edition-wii-u', 'Minecraft: Wii U Edition', 'Minecraft', '2016-06-17', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2jxl.jpg', 'Minecraft is a game about placing blocks and going on adventures.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-wii-u', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2016-12-13', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-3-ultimate-wii-u', 'Monster Hunter 3 Ultimate', 'Monster Hunter', '2013-03-19', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lh7.jpg', 'The popular fantasy action franchise Monster Hunter is now one of the most iconic gaming series in the world selling over 21 million copies worldwide since the series began in 2004. Players take on the role of a hunter and are sent to explore a settlement within the Monster Hunter universe, completing quests on their journey to seek and slay monsters whilst improving their skills and earning equipment upgrades. With many challenging monsters and over 200 quests the latest edition to the series is set to be the most expansive offering to date. Monster Hunter 3 Ultimate utilizes the functionalities of the Nintendo 3DS system to provide players with a truly intuitive hunting experience. The touch screen feature allows players to quickly access in-game books, weapons, field maps and mini games whilst the high quality graphics 3D visuals of Nintendo 3DS powered by the latest iteration of Capcom''s MT Framework deliver a unique and stunning world for players to explore. Taking advantage of the portability of Nintendo 3DS, players can exchange their guild card that contains all their hunter''s information with other players via StreetPass. Players can experience the world of Monster Hunter alone or in four player local play using Nintendo 3DS. Finding nearby hunters to adventure on quests with is now even easier via the local Nintendo 3DS search feature. Wii U players will be able to enjoy the hunt with Nintendo 3DS players via a local wireless connection. Gamers that own both a Wii U and Nintendo 3DS can take advantage of the inter compatibility of save data between the two consoles, taking the hunt from the living room wherever they go.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nes-remix-pack-wii-u', 'NES Remix Pack', 'NES Remix', '2014-12-05', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fre.jpg', 'NES Remix Pack is a compilation of two releases of NES Remix, the game that combines all the great Nintendo games into one remixed collection of fast-paced and crazy challenges.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-3-razor-s-edge-wii-u', 'Ninja Gaiden 3: Razor''s Edge', 'Ninja Gaiden', '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1ty.jpg', 'Ninja Gaiden 3: Razor''s Edge is an enhanced port of Ninja Gaiden 3 that includes all downloadable content from the original title, as well as additional enhancements made to improve the game. The game can be considered an equivalent to the Ninja Gaiden Sigma games, as it enhances the original title.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nintendo-land-wii-u', 'Nintendo Land', NULL, '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p9c.jpg', 'Nintendo Land is a fun and lively virtual theme park filled with attractions based on popular Nintendo game worlds. Explore the Nintendo Land Plaza as your Mii character, and play in park attractions featuring unique and innovative gameplay made possible by the Wii U GamePad controller. Enjoy team, competitive, and solo gameplay experiences for up to five players!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-wii-u', 'Pac-Man and the Ghostly Adventures', 'Pac-Man', '2013-10-29', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-2-wii-u', 'Pac-Man and the Ghostly Adventures 2', 'Pac-Man', '2014-10-14', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-color-splash-wii-u', 'Paper Mario: Color Splash', 'Paper Mario', '2016-10-07', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba8x.jpg', 'A mystery is afoot on Prism Island - and only Paper Mario can solve it by restoring the island''s vanishing colors with his new Paint Hammer and the powerful Battle Cards up his sleeve. These fresh layers of strategy, along with the hilarious action adventure gameplay the series is known for, make this one of the most colorful Paper Mario action-adventure games ever.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-3-wii-u', 'Pikmin 3', 'Pikmin', '2013-08-04', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p9e.jpg', 'Explore an alien world like no other in the third edition of Nintendo''s strategic adventure series. In Pikmin 3, players take command of three explorers and a legion of adorable Pikmin in a fight for survival. By employing the unique abilities of these tiny Pikmin creatures, players will solve puzzles, battle dangerous predators, and recover food needed to save the explorers’ depleted home planet.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pokk-n-tournament-wii-u', 'Pokkén Tournament', 'Pokémon', '2016-03-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zj1.jpg', 'Pokkén Tournament was developed with BANDAI NAMCO Entertainment, Inc., the producers of one of the top achievements in fighting games, the Tekken series. True to its legacy, this game brings tight gameplay and incredible control to never-before-seen battles between Pokémon. The gameplay is designed to be enjoyed by a wide range of people—even those who have never played a fighting game or an action game before can easily pick it up and play!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-land-wii-u', 'Rabbids Land', 'Rabbids', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4tps.jpg', 'Rabbids Land is an exclusive Wii U title and the seventh installment in the Raving Rabbids franchise. The game is essentially a mini-game collection that is set around Theme Park attractions of which there are over twenty different activities including a princess castle, pirate boat, haunted house, tunnel of love, roller coaster, and many more.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-wii-u', 'Rayman Legends', 'Rayman', '2013-09-03', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-wii-u', 'Resident Evil: Revelations', 'Resident Evil', '2013-05-21', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-wii-u', 'Shakedown: Hawaii', 'Retro City Rampage', '2020-08-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rodea-the-sky-soldier-wii-u', 'Rodea the Sky Soldier', NULL, '2015-11-10', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gfn.jpg', 'A thousand years ago, Emperor Geardo of the Naga Empire sent an army of machine soldiers to invade the sky kingdom of Garuda. Thanks to the efforts of Princess Cecilia and Rodea, a machine soldier who promised to protect Garuda, Emperor Geardo''s assault was thwarted. In present day, a spirited inventor named Ion discovers an abandoned robot that has fallen into disrepair in the heart of a scorching desert. Upon completing her repairs, the robot stirs to life and reveals itself to be none other than Rodea. Stunned to find himself in the future, Rodea learns that the Naga Empire is no more and that Garuda has known peace for a thousand years. But this peace was not meant to last, for the forces of Naga have returned to wage war against Garuda. Remembering the promise he made 1,000 years ago, Rodea takes to the skies to defend Garuda from the Naga Empire once again.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-unlimited-wii-u', 'Scribblenauts Unlimited', 'Scribblenauts', '2012-11-13', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1my3.jpg', 'Venture into a wide-open world where the most powerful tool is your imagination. Help Maxwell solve robust puzzles in seamless, free-roaming levels by summoning any object you can think of. Create your own original objects, assign unique properties, and share them with friends online using Steam Workshop – to be used in game or further modified as you like!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-unmasked-a-dc-comics-adventure-wii-u', 'Scribblenauts Unmasked: A DC Comics Adventure', 'Scribblenauts', '2013-09-24', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ns6.jpg', 'Scribblenauts Unmasked: A DC Comics Adventure is a puzzle video game developed by 5th Cell and published by Warner Bros. Interactive Entertainment. It is the fifth game in the Scribblenauts series of games and the first based on a licensed property. The game combines the series'' traditional gameplay of bringing up words and objects to solve puzzles with characters and settings from the DC Comics universe (DC Universe).', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-all-stars-racing-transformed-wii-u', 'Sonic & All-Stars Racing Transformed', 'Sega All-Stars', '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvw.jpg', 'Race as Sonic and a host of legendary All-Stars and prepare to transform! Speed across land, sea and air in a high velocity battle to the finish line, as your amazing transformable vehicle changes from car to boat to plane mid-race. Racing on mobile will never be the same again!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-half-genie-hero-wii-u', 'Shantae: Half-Genie Hero', 'Shantae', '2016-12-20', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ymj.jpg', 'Shantae embarks on her first full HD adventure! After three highly successful outings with Shantae, Shantae: Risky''s Revenge, and Shantae and the Pirate''s Curse, Shantae and her friends finally get a full HD console-based sequel! Boasting vivid, detailed high-definition graphics that retain the 2D hand-drawn sprites the series is known for, this newest entry in the Shantae series almost looks like a playable TV show! Presented as a stage-based 2.5D platformer with heavy exploration elements, Shantae uses her trademark Hair-Whip Attack to dispatch enemies, then takes advantage of her Belly Dance Magic to transform into 8 different forms that each have their own unique abilities and move sets. As new forms are mastered, old stages can be re-explored to unearth new items and secrets, ensuring there''s plenty of content on offer for novices and platforming gurus alike. Topple the villainous Baron behind each criminal caper afflicting Sequin Land, and prepare for the ultimate showdown against Shantae''s arch-nemesis: that bodacious buccaneer, Risky Boots!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-wii-u', 'Shovel Knight', 'Shovel Knight', '2015-11-03', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaa7.jpg', 'Shovel Knight is a sweeping classic action adventure game with awesome gameplay, memorable characters, and an 8-bit retro aesthetic. It''s a hot mashup of new and old! You play as the eponymous Shovel Knight, a small knight with a huge quest. Shovel Knight has come to this land with two goals: to defeat the evil Enchantress and quest for his lost beloved. He wields a Shovel Blade: a multipurpose weapon whose techniques have now been lost to the ages. Always honest and helpful, Shovel Knight is a shining example of the code of Shovelry: Slash Mercilessly and Dig Tirelessly!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-giants-wii-u', 'Skylanders: Giants', 'Skylanders', '2012-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vlm.jpg', 'Skylanders: Giants is a 2012 video game in the Skylanders series, a direct sequel to the 2011 game Skylanders: Spyro''s Adventure and features the voices of Kevin Michael Richardson, Greg Ellis, Peter Lurie, Steve Blum, Dave Wittenberg, Carlos Alazraqui, Kevin Sorbo, Bobcat Goldthwait, Patrick Seitz and Julie Nathanson. It is the game before Skylanders: Swap Force. As the title suggests, it features larger Skylanders known as "Giants", along with other new gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-wii-u', 'Skylanders: Swap Force', 'Skylanders', '2013-10-13', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-wii-u', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-wii-u', 'Skylanders: SuperChargers', 'Skylanders', '2015-09-20', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsk.jpg', 'Exclusive to the Wii U version of the game is a special figure of Donkey Kong and Bowser.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-wii-u', 'Skylanders: Imaginators', 'Skylanders', '2016-10-16', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-lost-world-wii-u', 'Sonic Lost World', 'Sonic the Hedgehog', '2013-10-29', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9112.jpg', 'Dr. Eggman is at it again! The dastardly doctor has outdone himself this time, harnessing the power of menacing creatures known as the Deadly Six. But when they rise up against their master, Sonic and Dr. Eggman must put their rivalry to one side and work together in Sonic Lost World on Nintendo 3DS.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-boom-rise-of-lyric-wii-u', 'Sonic Boom: Rise of Lyric', 'Sonic the Hedgehog', '2014-11-11', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vo8.jpg', 'Sonic Boom: Rise of Lyric delivers a completely new action-adventure gameplay experience for Sonic fans. The detailed levels and emphasis on each character’s unique abilities give players more choice in exploration as they work as a team to stop the deadly snake-like ancient villain, Lyric, before he can power up his army. Players will be challenged by over-the-top speed runs, but the heart of the game is focused on intense combat and brand-new abilities including the Enerbeam. This energy-charged cord can be used by characters to navigate the world like never before. Swing or zip-line across gaps, grab and throw enemies, take away their shields in combat, and explore alternate paths filled with lush environments and landscapes.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('splatoon-wii-u', 'Splatoon', 'Splatoon', '2015-05-29', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8g6r.jpg', 'The squid kids called Inklings are back to splat more ink and claim more turf in this colorful and chaotic 4-on-4* action shooter. Take Turf War battles on-the-go with the Nintendo Switch system, and use any of the console’s portable play styles for intense local multiplayer* action. Even team up for 4-player co-op fun in Salmon Run! Purchase this bundle to own both Splatoon 2 and the large-scale Octo Expansion DLC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-zero-wii-u', 'Star Fox Zero', 'Star Fox', '2016-04-22', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vd8.jpg', NULL, 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-fox-guard-wii-u', 'Star Fox Guard', 'Star Fox', '2016-04-22', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w9c.jpg', 'Star Fox Guard is a tower defense video game co-developed by Nintendo and PlatinumGames for the Wii U. The game was bundled as a separate disc for the first print edition of Star Fox Zero during its release in April 2016, and as a digital download code on the Wii U eShop afterwards.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-for-wii-u-wii-u', 'Super Smash Bros. for Wii U', 'Super Smash Bros.', '2014-11-21', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45qp.jpg', 'Ryu joins the world of Super Smash Bros. to continue his quest to be the strongest, and he even brought his own stage! Enter his famous button combos to power up his special moves!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-wii-u', 'Terraria', NULL, '2016-06-16', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-blacklist-wii-u', 'Tom Clancy''s Splinter Cell: Blacklist', 'Tom Clancy''s Splinter Cell', '2013-08-20', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ygp.jpg', 'Splinter Cell Blacklist builds on the stealth roots of the franchise, while exploring new directions to embrace the realms of action and adventure. Players can define their personal play styles and be rewarded for those choices.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-wario-wii-u', 'Game & Wario', 'WarioWare', '2013-06-23', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2149.jpg', 'Wario has gotten into the business of designing games. With the help of his development crew at WarioWare, Inc., he has set out to make the greatest collection of games Diamond City has ever seen. Game & Wario features these fun and refreshingly unusual games that are played exclusively with the Wii U GamePad controller.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-wii-u', 'Watch Dogs', 'Watch Dogs', '2014-11-18', 'Wii U', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j2m.jpg', 'Purchase the Watch Dogs and Watch Dogs 2 bundle and gain access to these award-winning titles at a great price. In Watch Dogs, become Aiden Pearce and hack your way around Chicago to take down ctOS. In Watch Dogs 2, join Marcus Holloway and the Dedsec hacker group to expose a new digital conspiracy.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-party-u-wii-u', 'Wii Party U', 'Wii', '2013-10-25', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eul.jpg', 'It''s time to party with Wii U Enjoy board games and mini-games on the TV, play familiar tabletop games using the Wii U GamePad Controller, or transform your living room into a game show floor. No matter what kind of party you''re throwing, Wii Party U offers something for everyone.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-fit-u-wii-u', 'Wii Fit U', 'Wii', '2014-01-10', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p9r.jpg', 'Wii Fit U is a new installment in the Wii Fit series, a brand that has sold more than 40 million units worldwide. The game combines fun and fitness with new exercises and activities, and incorporates the GamePad in unique ways. It''s compatible with the existing Wii Balance Board, and Wii Fit and Wii Fit Plus owners can transfer their existing workout data. Nintendo also revealed the Fit Meter, an advanced activity monitor that will be packaged with the game and enables users to track fitness activities throughout the day and upload that data back into Wii Fit U.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wii-sports-club-wii-u', 'Wii Sports Club', 'Wii', '2014-07-25', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wrj.jpg', 'Play your favorite Wii Sports games on the Wii U console! With Wii Sports Club, you can now take the competition online with tennis, bowling and golf - baseball and boxing are coming soon. Join a club, compete against other clubs from around your region, or play online multiplayer with your friends. You can also use all-new training modes to improve your skills and support your club.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wonderful-101-wii-u', 'The Wonderful 101', 'The Wonderful 101', '2013-09-15', 'Wii U', 1, 1, NULL, NULL, 'Early plans for the game included releasing it on the Wii with existing Nintendo characters, though plans stalled and the game was put on hold. The game concepts were later revived as an original game with new characters for the Wii U and released in 2013.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-x-wii-u', 'Xenoblade Chronicles X', 'Xenoblade Chronicles', '2015-12-04', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavor.jpg', 'Xenoblade Chronicles X is an action role-playing video game and a part of the Xeno series of video games, serving as a spiritual successor to Xenoblade Chronicles on the Wii. In a similar fashion to the original, the game plays as an open world role-playing video game, with an emphasis on exploration. Traveling can take place on foot, or in large humanoid robots, approximately four times the height of the average playable character, called "Skells" ("Dolls" in the Japanese version), that the player may opt to control. The Skells have the ability to fly, traverse water, and transform into vehicles such as motorcycles or tanks. Aerial battles will also take place in the game.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-woolly-world-wii-u', 'Yoshi''s Woolly World', 'Yoshi', '2015-10-16', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob88e.jpg', 'Set off with a friend through a wild, woolly world in this grand Yoshi adventure! A treasure trove of clever handicraft stages are ready for you to explore. Unravel their secrets and color your world with a spectrum of yarn balls to knit new paths and get every last collectible.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zombiu-wii-u', 'ZombiU', 'Zombi', '2012-11-18', 'Wii U', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22ag.jpg', 'Developed by Ubisoft Montpellier, the studio behind critically acclaimed titles like From Dust, Beyond Good & Evil and, Ghost Recon Advanced Warfighter, ZombiU puts players in the middle of London circa 2012, where an outbreak has infected the population, destroying their humanity and turning them into mindless monsters preying on the flesh of the few remaining survivors. This fear-fueled first-person shooter invites takes all the horror, chaos and tension found in the best of the horror genre and adds original interactive elements, including a unique death mechanic that puts players in the body of a different survivor each time they die, allowing them to track and take down their old, infected characters, recover their equipment and see if they can stay alive just a little bit longer this time.', 'NA', 24);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-warriors-new-nintendo-3ds', 'Fire Emblem Warriors', 'Fire Emblem', '2017-10-20', 'New Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co913u.jpg', NULL, 'NA', 25);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-new-nintendo-3ds-edition-new-nintendo-3ds', 'Minecraft: New Nintendo 3DS Edition', 'Minecraft', '2017-11-10', 'New Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5j9p.jpg', 'Minecraft is a game about placing blocks and going on adventures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-3d-new-nintendo-3ds', 'Xenoblade Chronicles 3D', 'Xenoblade Chronicles', '2015-04-10', 'New Nintendo 3DS', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar97.jpg', 'Xenoblade Chronicles 3D is a port of the well-received Xenoblade Chronicles for Wii. The new version offers 3D visuals and allows players to view the maps and character stats on the bottom screen. An additional bonus mode lets players view 3D models of the characters and listen to music tracks from the game.', 'NA', 25);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('1-2-switch-nintendo-switch', '1-2-Switch', '1-2-Switch', '2017-03-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21q3.jpg', '1-2-Switch is a party game for everyone! Throw an impromptu party anywhere with anyone thanks to a new play style in which players look at each other—not the screen! Bring the action and fun into the real world as you face off in wild-west duels, cow-milking competitions, and more. While the action unfolds off-screen, the audience watches the players themselves instead of the screen.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('everybody-1-2-switch-nintendo-switch', 'Everybody 1-2-Switch!', '1-2-Switch', '2023-06-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6kpa.jpg', 'Mix up your next get-together with the Everybody 1-2-Switch, the follow-up to 1-2 Switch. Grab some Joy-Cons or smart devices for team-based games that are easy to set up and feature everything from balloons to aliens, and more! People at your next party can get moving and show off their teamwork in this multiplayer mashup.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('20xx-30xx-nintendo-switch', '20XX/30XX', NULL, '2025-11-07', 'Nintendo Switch', 1, 0, NULL, NULL, NULL, NULL, 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('advance-wars-1-2-re-boot-camp-nintendo-switch', 'Advance Wars 1+2: Re-Boot Camp', 'Advance Wars', '2023-04-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobblq.jpg', 'Command an army in strategic, turn-based combat as a tactical adviser for the Orange Star Army. Your expertise is needed as you move land, air, and naval units across the battlefield. Take down enemy squads and capture towns and bases to secure victory and keep the peace. Keep an eye on the game-changing terrain and weather as you lead a variety of units across multiple maps. This remake features two campaigns that cover the events of Advance Wars and Advance Wars 2: Black Hole Rising!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('among-us-crewmate-edition-nintendo-switch', 'Among Us: Crewmate Edition', 'Among Us', '2021-12-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wwy.jpg', 'Play online with 4-15 players as you attempt to hold your spaceship together and return back to civilization. But beware... as there may be an alien impostor aboard!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-crossing-new-horizons-nintendo-switch', 'Animal Crossing: New Horizons', 'Animal Crossing', '2020-03-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wls.jpg', 'Escape to a deserted island and create your own paradise as you explore, create, and customize in Animal Crossing: New Horizons. Your island getaway has a wealth of natural resources that can be used to craft everything from tools to creature comforts. You can hunt down insects at the crack of dawn, decorate your paradise throughout the day, or enjoy sunset on the beach while fishing in the ocean. The time of day and season match real life, so each day on your island is a chance to check in and find new surprises all year round.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-well-nintendo-switch', 'Animal Well', NULL, '2024-05-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hdh.jpg', 'What lurks beneath the surface of this deceptively minimalistic adventure? In Animal Well there is more than what you see. Explore a dense interconnected labyrinth, and unravel its many secrets. Collect items to manipulate your environment in surprising and meaningful ways. Encounter creatures both beautiful and unsettling, and try to survive what lurks in the dark.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('another-code-recollection-nintendo-switch', 'Another Code: Recollection', 'Another Code', '2024-01-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72z3.jpg', 'The Nintendo DS game Trace Memory and its Wii sequel are coming together, fully enhanced, on the Nintendo Switch system. A young girl named Ashley receives a letter from her father, who she thought had passed away. Seeking answers, she sets off for a solitary island in search of him. Once there, Ashley encounters puzzles and obstacles that threaten to hinder her investigation. Find the traces of her past and experience the full story for the first time.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('another-crab-s-treasure-nintendo-switch', 'Another Crab''s Treasure', NULL, '2024-04-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coam1a.jpg', 'Take a peek at the very first build of Another Crab''s Treasure made back in Feb of 2021!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('antonblast-nintendo-switch', 'Antonblast', NULL, '2024-12-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8txh.jpg', 'Antonblast is a fast-paced explosive action platformer that''s all about destruction. Play as the enraged Dynamite Anton (or his cranked-out coworker Annie) and use your Mighty F’n Hammer to demolish bizarre worlds, tussle with screen-filling bosses, and steal your Spirits back from Satan!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('apico-nintendo-switch', 'Apico', NULL, '2022-07-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48vu.jpg', 'Apico is a laid-back beekeeping sim game about breeding, collecting, & conserving bees! Set in a series of lush environments, Apico uniquely combines resource gathering, biology, and beekeeping minigames, taking ideas from a mix of real-life and fantasy apiculture & floriculture.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arcade-classics-anniversary-collection-nintendo-switch', 'Arcade Classics Anniversary Collection', NULL, '2019-04-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vaa.jpg', '8 Konami arcade classics of the 80s, from Nemesis to TwinBee. Including bonus eBook packed with new information never before revealed to the public.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arms-nintendo-switch', 'Arms', NULL, '2017-06-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ro8.jpg', 'ARM OF SATAN is a tough precision platformer that carries the torch from the likes of Ori and Celeste, and sets it ablaze with a passion for co-op games. Featuring kick ass visuals influenced by the Hellboy comics, arcade-inspired gameplay, and a captivating narrative.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arzette-the-jewel-of-faramore-nintendo-switch', 'Arzette: The Jewel of Faramore', NULL, '2024-02-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ryw.jpg', 'Arzette: The Jewel of Faramore is a new interactive animated adventure, where players must help Arzette save the Kingdom of Faramore from the evil demon king, Daimur. It is a spiritual successor to a pair of infamous fantasy adventure titles, being developed by Seedy Eye Software and both funded & published by Limited Run Games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-remastered-nintendo-switch', 'Assassin''s Creed III Remastered', 'Assassin''s Creed', '2019-05-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjw.jpg', 'Relive the American Revolution or experience it for the first time in Assassin''s Creed III Remastered, with enhanced graphics and improved gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-the-rebel-collection-nintendo-switch', 'Assassin''s Creed: The Rebel Collection', 'Assassin''s Creed', '2019-12-06', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r59.jpg', 'Get two action-packed games and all single-player DLC with Assassin’s Creed: The Rebel Collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('astral-chain-nintendo-switch', 'Astral Chain', NULL, '2019-08-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobd39.jpg', 'Astral Chain is a stylish action game that blends fast-paced combat with investigation elements. Players fight alongside a controllable companion called a Legion, using coordinated attacks, restraints, and abilities to overcome enemies and solve environmental challenges.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-nintendo-switch', 'Atari Flashback Classics', 'Atari Flashback Classics', '2018-12-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5byo.jpg', 'Each volume of Atari Flashback Classics packs hours of retro-gaming gaming goodness from the Atari 2600 Video Computer System (VCS) and arcade machines onto your gaming platform. Players can experience Atari’s greatest hits with the benefit of today’s technology, including full 1080p high-definition, global leaderboards, online multiplayer, and more!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-1-nintendo-switch', 'Atari Recharged Collection 1', 'Atari Recharged', '2023-11-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cnf.jpg', 'Atari Recharged Collection 1 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-2-nintendo-switch', 'Atari Recharged Collection 2', 'Atari Recharged', '2023-11-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cng.jpg', 'Atari Recharged Collection 2 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-3-nintendo-switch', 'Atari Recharged Collection 3', 'Atari Recharged', '2024-01-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaekx.jpg', 'The Atari Recharged Collection 3 includes Yars: Recharged and Caverns of Mars: Recharged.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-4-nintendo-switch', 'Atari Recharged Collection 4', 'Atari Recharged', '2024-01-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaenn.jpg', 'The Atari Recharged Collection 4 includes Missile Command: Recharged and Gravitar: Recharged.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-nintendo-switch', 'Axiom Verge', 'Axiom Verge', '2017-10-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kml.jpg', 'After a lab accident, a scientist awakens in a mysterious, alien world. Is this a distant planet? The far future? Or a complex virtual-reality computer simulation?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-2-nintendo-switch', 'Axiom Verge 2', 'Axiom Verge', '2021-08-11', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3k3x.jpg', 'You may have played Axiom Verge, or heard it referenced as a benchmark for indie “metroidvania” adventures. Axiom Verge 2 is part of the same story as Axiom Verge 1 but is a completely new game: new characters, new powers, new enemies, and a new world. You can play it before or after the original.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-1-2-double-pack-nintendo-switch', 'Axiom Verge 1 & 2 Double Pack', 'Axiom Verge', '2021-08-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wha.jpg', 'Axiom Verge 1:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baba-is-you-nintendo-switch', 'Baba Is You', NULL, '2019-03-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ic6.jpg', 'Baba Make Level adds an official level editor, the ability to share levels online with other players, a curated "Featured Levels" list, two new official levelpacks containing over 250 entirely new and unused/cut levels, new art, new music and new rules.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bakeru-nintendo-switch', 'Bakeru', NULL, '2025-02-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8txf.jpg', 'A 3D action game starring taiko drum-wielding tanuki boy Bakeru, who assumes the form of a human, going on a journey to save Japan from the clutches of a festival army led by the notorious Oracle Saitaro.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('balan-wonderworld-nintendo-switch', 'Balan Wonderworld', NULL, '2021-03-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xxs.jpg', 'Balan Wonderworld is a wondrous action-platformer game themed around a mysterious musical theatre.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('balatro-nintendo-switch', 'Balatro', NULL, '2024-02-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9f4g.jpg', 'Balatro is a deck-building roguelite in which players construct poker hands to earn chips and overcome enemy blinds. The game features mechanics for enhancing a deck of playing cards, purchasing Jokers that modify hand effects, and discovering synergies to progress through increasingly challenging encounters.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-nintendo-switch', 'Bayonetta', 'Bayonetta', '2018-02-16', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamt.jpg', 'This is a European bundle that includes Bayonetta 1 and Bayonetta 2 both in each own disc and case for the WiiU.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-2-nintendo-switch', 'Bayonetta 2', 'Bayonetta', '2018-02-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9e8.jpg', 'This Switch port adds amiibo support.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-3-nintendo-switch', 'Bayonetta 3', 'Bayonetta', '2022-10-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4z2i.jpg', 'You’ve waited long enough. The witch. Is. Back! A new-look Bayonetta returns to battle foes with her signature Witch Time! This time, she’ll wield her new Demon Masquerade ability to channel the power of demons and engage in larger-than-life action.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-origins-cereza-and-the-lost-demon-nintendo-switch', 'Bayonetta Origins: Cereza and the Lost Demon', 'Bayonetta', '2023-03-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vch.jpg', 'Long before this trainee of the dark arts would come to be called Bayonetta, she took a fateful journey into the forbidden Avalon Forest. Alongside her was Cheshire, her very first demon, possessing Cereza’s stuffed toy. Play as both Cereza and Cheshire and search through the treacherous forest to look for the power to save Cereza’s mother.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beacon-pines-nintendo-switch', 'Beacon Pines', NULL, '2022-09-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5d1x.jpg', 'Beacon Pines is a cute and creepy adventure game within a magical storybook. You play as both the reader of the book and its main character, Luka. Explore the town to find word charms. Use your charms to change the course of fate!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-20th-anniversary-edition-nintendo-switch', 'Beyond Good & Evil - 20th Anniversary Edition', 'Beyond Good & Evil', '2024-06-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8eda.jpg', 'Swoop into the marvelous world of Hillys as action-reporter Jade to investigate the mysterious DomZ alien attacks alongside colorful characters, like her adoptive uncle Pey’j or the valiant Double H. Embark on this epic adventure in up to 4K, 60 fps with improved graphics, controls, and audio, along with brand-new autosave and cross-save features. Enjoy exclusive new rewards as you explore the planet and discover more about Jade’s past in a new treasure hunt throughout Hillys. Put your skills to the test thanks to the new speedrun mode and updated achievements, and learn more about the game’s development and secrets in the anniversary gallery! Armed with her daï-jo and faithful camera, Jade’s adventure will get you to freely explore Hillys, combat creatures large and small, infiltrate dangerous areas, solve enigmatic puzzles, play addictive mini-games, race the best hovercraft pilots, and take pictures of the whole experience.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-binding-of-isaac-afterbirth-nintendo-switch', 'The Binding of Isaac: Afterbirth+', 'The Binding of Isaac', '2017-10-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8p3u.jpg', 'The Binding of Isaac: Afterbirth+ is a dungeon-crawling shoot-''em-up that''s literally a different game each and every time you play it! The randomly generated maps are built with over 11,000 unique room configurations, each populated with a nearly endless variety of enemies, items, challenges and secrets!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-binding-of-isaac-repentance-nintendo-switch', 'The Binding of Isaac: Repentance', 'The Binding of Isaac', '2021-09-30', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co949f.jpg', 'The Binding of Isaac Repentance+ is an update to The Binding of Isaac Repentance, adding in online multiplayer co-op and reworking otherwise poorly regarded items.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-the-collection-nintendo-switch', 'BioShock: The Collection', 'BioShock', '2020-05-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uv1.jpg', 'BioShock: The Collection is a game bundle consisting of remastered 1080p editions of BioShock, BioShock 2 and BioShock Infinite along with their accompanying downloadable content.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('runner3-nintendo-switch', 'Runner3', 'Bit.Trip', '2018-05-22', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86bd.jpg', 'Runner3 continues the joyous adventures of CommanderVideo from BIT.TRIP RUNNER and Runner2. Players will encounter quests, branching paths, new character moves, new Retro Challenges, and a roster of characters that somehow manages to rival the strangeness of Runner2.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-zero-nintendo-switch', 'Blaster Master Zero', 'Blaster Master', '2017-03-09', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-zero-2-nintendo-switch', 'Blaster Master Zero 2', 'Blaster Master', '2019-03-20', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-curse-of-the-moon-nintendo-switch', 'Bloodstained: Curse of the Moon', 'Bloodstained', '2018-05-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaas.jpg', '“Bloodstained: Curse of the Moon” is packed with the retro charm that made the legendary 2D action games of the 80s so enjoyable.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-ritual-of-the-night-nintendo-switch', 'Bloodstained: Ritual of the Night', 'Bloodstained', '2019-06-25', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc4a.jpg', 'Bloodstained: Ritual of the Night is a gothic horror action side-scrolling RPG set in 19th century England. A paranormal force has summoned a demon-infested castle, revealing crystal shards infused with tremendous magical power.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-curse-of-the-moon-2-nintendo-switch', 'Bloodstained: Curse of the Moon 2', 'Bloodstained', '2020-07-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobax6.jpg', 'Curse of the Moon 2 brings classic 2D action and a dark, 8-bit aesthetic together with modern playability. The multiple-scenario structure of the previous title returns with an epic new story supervised by IGA (Koji Igarashi) himself.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-bomberman-r-nintendo-switch', 'Super Bomberman R', 'Bomberman', '2017-03-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x7j.jpg', 'A sequel to Super Bomberman R, featuring an expanded story mode, and a new "Castle" battle mode which has one group teaming up to build castle defenses while the other attempts to breach the castle and take the treasure.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-the-legendary-collection-nintendo-switch', 'Borderlands: The Legendary Collection', 'Borderlands', '2020-05-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2c8q.jpg', 'The Borderlands Legendary Collection versions of Borderlands: Game of the Year Edition, Borderlands 2, and Borderlands: The Pre-Sequel come complete with loads of extra content, including the following major add-ons:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-boy-and-his-blob-retro-collection-nintendo-switch', 'A Boy and His Blob Retro Collection', 'A Boy and His Blob', '2022-05-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tlv.jpg', 'The Blob is back in an exclusive collection with Limited Run Games. The Retro Collection includes the original NES A Boy and His Blob: Trouble on Blobolonia, and The Rescue of Princess Blobette, originally on Game Boy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('brawlout-nintendo-switch', 'Brawlout', NULL, '2018-05-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7b.jpg', 'Brawlout is the competitive platform fighter, designed for couch play, online ranked matches and competitive tournaments.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('broforce-nintendo-switch', 'Broforce', NULL, '2018-09-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28vv.jpg', 'When evil threatens the world, the world calls on Broforce - an under-funded, over-powered paramilitary organization dealing exclusively in excessive force. Brace your loins with up to four players to run ‘n’ gun as dozens of different bros and eliminate the opposing terrorist forces that threaten our way of life. Unleash scores of unique weapons and set off incredible chain reactions of fire, napalm, and limbs in the name of freedom.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('broken-age-nintendo-switch', 'Broken Age', NULL, '2018-09-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vh9.jpg', 'Broken Age is a point-and-click adventure telling the stories of a young boy and girl leading parallel lives. Vella Tartine has been chosen by her village to be sacrificed to a terrible monster — but she decides to fight back. Meanwhile, Shay Volta is living a solitary life on a spaceship under the care of a motherly computer, but he wants to break free to lead adventures and do good in the world. Adventures ensue.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-paws-on-fire-nintendo-switch', 'Bubsy: Paws on Fire!', 'Bubsy', '2019-08-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mma.jpg', 'From the developers of the BIT.TRIP series comes Bubsy: Paws on Fire!, the latest and greatest in bobcat-based gaming.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bug-fables-the-everlasting-sapling-nintendo-switch', 'Bug Fables: The Everlasting Sapling', 'Bug Fables', '2020-05-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6r8x.jpg', 'Bug Fables: The Everlasting Sapling is an adventure RPG following three heroes, Vi, Kabbu, and Leif, as they embark on an epic quest in Bugaria in search of treasure and immortality. The game combines flat objects with 3D physics as the player jumps and utilizes the heroes’ unique abilities to solve puzzles and stun enemies while exploring a variety of unique, colorful areas. Battles are turn-based and with timed button inputs that can enhance your abilities.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bugsnax-nintendo-switch', 'Bugsnax', NULL, '2022-04-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qjm.jpg', 'Bugsnax is a humorous action adventure game in which we explore an island full of creatures that are hybrids of worms and food. The game was developed and released by independent Young Horses studio.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-toad-treasure-tracker-nintendo-switch', 'Captain Toad: Treasure Tracker', NULL, '2018-07-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v2d.jpg', 'Captain Toad Treasure Tracker is a ROM hack/mod of Super Mario World which adapts the mechanics of the homonymous official game for the Wii U to a 2D platformer.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('carrion-nintendo-switch', 'Carrion', NULL, '2020-07-23', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eau.jpg', 'Carrion is a reverse horror game in which you assume the role of an amorphous alien being. Use your unique otherworldly abilities to your advantage and hunt down your prey!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('carto-nintendo-switch', 'Carto', NULL, '2020-10-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kf2.jpg', 'Carto is a tile placement adventure game where you explore the lands you placed and discover the secrets while exploring. What will happen to the world and the characters when you rearrange the tiles of the map?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castle-crashers-remastered-nintendo-switch', 'Castle Crashers Remastered', NULL, '2019-09-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co527d.jpg', 'Hack, slash, and smash your way to victory in this Remastered edition of the popular 2D arcade adventure Castle Crashers! At 60FPS, Castle Crashers Remastered delivers hi-res visuals like nothing you''ve ever seen before. Up to four friends can play locally or online to save your princess, defend your kingdom, and crash some castles!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-anniversary-collection-nintendo-switch', 'Castlevania Anniversary Collection', 'Castlevania', '2019-05-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8kz.jpg', 'Konami''s Castlevania Anniversary Collection traces the origins of the historic vampire franchise. Included is a unique eBook with details provided by developers, artists and others inspired by the Castlevania legacy which sheds a fresh light into the world of Castlevania.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-advance-collection-nintendo-switch', 'Castlevania Advance Collection', 'Castlevania', '2021-09-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xj.jpg', 'Castlevania Advance Collection includes three legendary Castlevania games that were first released in the early 2000s: Circle of the Moon, Aria of Sorrow, and Harmony of Dissonance. In addition, this collection also includes Castlevania: Dracula X and some never-before-seen sketches and artwork from the games!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-dominus-collection-nintendo-switch', 'Castlevania Dominus Collection', 'Castlevania', '2024-08-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xk.jpg', 'Three incredible action adventure games from the Castlevania series have finally returned, for the first time! But wait, there''s more! Haunted Castle Revisited, a redesigned version of the very first Castlevania arcade game, makes its debut!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cave-story-nintendo-switch', 'Cave Story+', 'Cave Story', '2017-06-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9o6b.jpg', NULL, 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('celeste-nintendo-switch', 'Celeste', NULL, '2018-01-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9dh.jpg', 'Help Madeline survive her inner demons on her journey to the top of Celeste Mountain, in this super-tight platformer from the creators of TowerFall. Brave hundreds of hand-crafted challenges, uncover devious secrets, and piece together the mystery of the mountain.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chants-of-sennaar-nintendo-switch', 'Chants of Sennaar', NULL, '2023-09-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9mjo.jpg', 'In this game of adventure and enigmas where ancient languages are both the lock and the key, travel the endless steps of a prodigious labyrinth, multiply unexpected encounters and unveil the mysteries of a fantastic world inspired by the myth of Babel.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chicory-a-colorful-tale-nintendo-switch', 'Chicory: A Colorful Tale', NULL, '2021-12-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coayhk.jpg', 'Chicory: A Colorful Tale is an adventure game about a dog wielding a magic paintbrush! Use the power of art to explore, solve puzzles, help your animal friends and restore color to the world.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('child-of-light-ultimate-edition-valiant-hearts-the-great-war-nintendo-switch', 'Child of Light Ultimate Edition + Valiant Hearts: The Great War', NULL, '2019-02-26', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3v8s.jpg', 'Play the Child of Light Ultimate Edition and Valiant Hearts: The Great War bundle at home or on the go. Enjoy both games'' intricately crafted worlds that tell deep and personal stories. Enjoy two great games in one bundle, providing hours of immersive entertainment. In Child of Light, join Aurora on her journey to save her ailing father and a lost kingdom in the magical world of Lemuria. Fight alongside your allies to upgrade your stats, unlock unique abilities, and use unique gems to improve your skills. In Valiant Hearts: The Great War, the lives of all the characters are inextricably drawn together over the course of the game. Choose your favorite control mode and experience the game with either a Joy-Con or the touch screen.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chrono-cross-the-radical-dreamers-nintendo-switch', 'Chrono Cross: The Radical Dreamers', 'Chrono', '2022-04-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4mw1.jpg', 'Chrono Cross: The Radical Dreamers Edition is a remaster of Chrono Cross bundled with Radical Dreamers, which was previously only released for the Satellaview in Japan.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('citizen-sleeper-nintendo-switch', 'Citizen Sleeper', NULL, '2022-05-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zl5.jpg', 'Roleplaying in the ruins of interplanetary capitalism. Live the life of an escaped worker, washed-up on a lawless station at the edge of an interstellar society. Inspired by the flexibility and freedom of TTRPGs, explore the station, choose your friends, escape your past and change your future.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('citizens-unite-earth-x-space-nintendo-switch', 'Citizens Unite!: Earth x Space', NULL, '2021-01-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pch.jpg', 'Citizens Unite!: Earth x Space includes both the Citizens of Earth and Citizens of Space games. This time the two adventures have united with brand-new elements. Recruit 88 Citizens with unique abilities to save the Earth in both time-periods! Time travel back-and-forth between Citizens of Earth and Citizens of Space, unlocking new content and revealing the true ending!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-vi-nintendo-switch', 'Sid Meier''s Civilization VI', 'Civilization', '2018-11-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaaqr.jpg', 'Civilization is a turn-based strategy game in which you attempt to build an empire to stand the test of time. Become Ruler of the World by establishing and leading a civilization from the Stone Age to the Information Age. Wage war, conduct diplomacy, advance your culture, and go head-to-head with history’s greatest leaders as you attempt to build the greatest civilization the world has ever known.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('clubhouse-games-51-worldwide-classics-nintendo-switch', 'Clubhouse Games: 51 Worldwide Classics', 'Clubhouse Games', '2020-06-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21vp.jpg', 'Play and discover 51 board games, tabletop games, and more all in one package—Clubhouse Games: 51 Worldwide Classics. This diverse collection includes games from all over the world across multiple genres, from familiar favorites like Chess to international hits like Mancala that have been around for hundreds of years!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-anniversary-collection-nintendo-switch', 'Contra Anniversary Collection', 'Contra', '2019-06-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob230.jpg', 'The Contra Anniversary Collection brings this classic Run and Gun franchise back to modern platforms and a new generation of players. Grab power ups and blast your way through waves of menacing enemies and bosses that will put your reaction skills to the test. Also included is a digital Bonus Book with tons of concept documents and sketches, the official chronology of the franchise, an exclusive interview with the veteran producer of the series, and more! Alone or with a friend, Contra provides hours of nail biting action. In a pinch make sure you know the code!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-rogue-corps-nintendo-switch', 'Contra: Rogue Corps', 'Contra', '2019-09-24', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lzz.jpg', 'CONTRA: ROGUE CORPS is a twin stick, third-person action game drawing upon its roots in fast and focused combat developed for the Xbox One, PlayStation 4, Nintendo Switch, and PC (STEAM). From the director of CONTRA III: THE ALIEN WARS and CONTRA: HARD CORPS, Nobuya Nakazato instills more than 25 years of franchise pedigree into CONTRA: ROGUE CORPS with enormous crazed enemies, over-the-top violence, and a cast of diverse playable characters that add to the irreverent tone of the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-operation-galuga-nintendo-switch', 'Contra: Operation Galuga', 'Contra', '2024-03-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72z7.jpg', 'The legendary Contra series is back! Contra: Operation Galuga is a modern reimagining of the classic run-‘n’-gun action game from the ’80s, featuring modern graphics and sound. Encounter new stages, new play mechanics, an updated weapons system and explosive co-op combat for up to two players in Story Mode or four players in Arcade Mode.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-n-sane-trilogy-nintendo-switch', 'Crash Bandicoot N. Sane Trilogy', 'Crash Bandicoot', '2018-06-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v62.jpg', 'Crash Bandicoot N. Sane Trilogy is a remastered version, of the original 3 games (Crash Bandicoot, Crash Bandicoot 2: Cortex Strikes Back, and Crash Bandicoot 3: Warped) with enhanced features applied to each game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-racing-nitro-fueled-nintendo-switch', 'Crash Team Racing Nitro-Fueled', 'Crash Bandicoot', '2019-06-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2p89.jpg', 'This compilation contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-4-it-s-about-time-nintendo-switch', 'Crash Bandicoot 4: It''s About Time', 'Crash Bandicoot', '2021-03-12', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hp4.jpg', 'Crash Bandicoot 4: It''s About Time is the eighth Crash Bandicoot series game, though the fourth chronologically. The game retains the series'' core platforming gameplay and adds new elements through the use of the Quantum Masks, who can alter levels and provide means to traverse or overcome obstacles. It also includes additional game modes for replaying levels, and the ability to control five characters, three of whom – Cortex, Dingodile, and Tawna – have their own unique gameplay and levels.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crossing-souls-nintendo-switch', 'Crossing Souls', NULL, '2018-07-26', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45pi.jpg', 'A girl who is "one person in two bodies" challenging a mystery dungeon. Items that can be transmigrated to change their form as well as spirit weapons. The story of a soul that spans the ages. And... tasty bananas.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crow-country-nintendo-switch', 'Crow Country', NULL, '2024-10-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ab9.jpg', 'The year is 1990. Edward Crow has disappeared. The owner of ''Crow Country'', he has not been seen since he unexpectedly shut down his park two years ago. The silence is broken when a mysterious young woman named Mara Forest ventures into the heart of the abandoned theme park in order to find him.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crypt-of-the-necrodancer-nintendo-switch-edition-nintendo-switch', 'Crypt of the NecroDancer: Nintendo Switch Edition', 'Crypt of the NecroDancer', '2021-04-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9smh.jpg', 'Crypt of the NecroDancer is an award winning hardcore rhythm-based dungeon crawling game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-remastered-nintendo-switch', 'Crysis Remastered', 'Crysis', '2021-10-15', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2on5.jpg', 'With its 2007 release, Crysis set the industry standard for first person shooters with stunning visuals, highly evolved gameplay, and an enormous sandbox world. Crysis Remastered adds new graphic features, high-quality textures, and the CRYENGINE''s native hardware- and API-agnostic ray tracing solution to update the game for a new generation of hardware.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cuphead-nintendo-switch', 'Cuphead', NULL, '2019-04-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ao.jpg', 'Cuphead is a classic run and gun action game heavily focused on boss battles. Inspired by cartoons of the 1930s, the visuals and audio are painstakingly created with the same techniques of the era, i.e. traditional cel animation (hand drawn & hand inked!), watercolor backgrounds, and original jazz recordings. Play as Cuphead or Mugman (in single player or co-op) as you traverse strange worlds, acquire new weapons, learn powerful super moves, and discover hidden secrets. Cuphead is all action, all the time.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-remastered-nintendo-switch', 'Dark Souls: Remastered', 'Dark Souls', '2018-10-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobazz.jpg', 'Dark Souls Remastered is a remastered version of the original game Dark Souls. The updated version of the game features graphical enhancements, an expanded online mode, and the Artorias of the Abyss DLC.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darkest-dungeon-ancestral-edition-nintendo-switch', 'Darkest Dungeon: Ancestral Edition', 'Darkest Dungeon', '2018-04-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28qk.jpg', 'The Ancestral Edition includes the Darkest Dungeon core game plus the following content packs: The Crimson Court, The Shieldbreaker and The Color of Madness.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-warmastered-edition-nintendo-switch', 'Darksiders: Warmastered Edition', 'Darksiders', '2019-04-02', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24hi.jpg', 'Deceived by the forces of evil into prematurely bringing about the end of the world, War – the first Horseman of the Apocalypse – stands accused of breaking the sacred law by inciting a war between Heaven and Hell. In the slaughter that ensued, the demonic forces defeated the heavenly hosts and laid claim to the Earth.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-deathinitive-edition-nintendo-switch', 'Darksiders II: Deathinitive Edition', 'Darksiders', '2019-09-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qql.jpg', 'A remastered version of the 2012 release, Darksiders II.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-genesis-nintendo-switch', 'Darksiders Genesis', 'Darksiders', '2020-02-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1f.jpg', 'In this Action RPG spin-off, the fourth Horseman of the Apocalypse Strife is called upon to save humankind from certain destruction at the hands of Lucifer. True to its roots, Darksiders Genesis will feature intense combat, exploration, puzzle-solving, epic boss battles and serpent holes from heaven to hell. The game marks the first, full-scale Darksiders adventure played from the top-down perspective.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-iii-nintendo-switch', 'Darksiders III', 'Darksiders', '2021-09-30', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qqk.jpg', 'Return to an apocalyptic planet Earth in Darksiders III, a hack-n-slash action adventure where players take on the role of FURY in her quest to hunt down and dispose of the Seven Deadly Sins. The Charred Council calls upon Fury to battle from the heights of heaven down through the depths of hell in a quest to restore humanity and prove that she is the most powerful of the Horsemen. As a mage, FURY relies on her whip and magic to restore the balance between good and evil. The expansive, Darksiders III game world is presented as an open-ended, living, free-form planet Earth that is dilapidated by war and decay, and overrun by nature. FURY will move back and forth between environments to uncover secrets while advancing the Darksiders III story.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dave-the-diver-anniversary-edition-nintendo-switch', 'Dave the Diver: Anniversary Edition', NULL, '2024-06-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7u3i.jpg', 'Dave the Diver is an action-adventure and management simulation game developed by Mintrocket. In the game, players control Dave, who spends his days diving into underwater environments to catch fish and gather resources, and his nights managing a sushi restaurant. The gameplay combines real-time underwater exploration and combat with restaurant management mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-telltale-series-nintendo-switch', 'Batman: The Telltale Series', 'DC', '2017-11-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u65.jpg', 'Batman: The Telltale Series is an episodic graphic adventure game developed by Telltale Games, first released in 2016. The game offers a narrative-focused experience, where players control Bruce Wayne and his alter ego, Batman, making choices that shape the story and relationships with characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-enemy-within-nintendo-switch', 'Batman: The Enemy Within', 'DC', '2018-10-02', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co208l.jpg', 'In this latest chapter, both Bruce Wayne and Batman will be forced into precarious new roles. The Riddler has returned to terrorize Gotham City, but his gruesome puzzles merely foreshadow an even greater crisis. With the arrival of a ruthless federal agent and the return of a still nascent Joker, Batman must navigate uneasy alliances while Bruce Wayne undertakes a perilous series of deceptions. Which of Batman''s new allies will you choose to trust? And how deep into the darkness will you let Bruce descend?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dc-super-hero-girls-teen-power-nintendo-switch', 'DC Super Hero Girls: Teen Power', 'DC', '2021-06-04', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hlz.jpg', 'Suit up as the DC Super Hero Girls and save Metropolis!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-cells-nintendo-switch', 'Dead Cells', 'Dead Cells', '2019-08-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3hi.jpg', 'A port of Dead Cells exclusive to Apple Arcade, with all the game’s main DLC expansions excluding the Everyone is Here! expansion.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-cells-return-to-castlevania-edition-nintendo-switch', 'Dead Cells: Return to Castlevania Edition', 'Dead Cells', '2023-06-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob676.jpg', 'Dead Cells: Return to Castlevania Edition is a compilation. It contains: - Dead Cells (base game including the 34 free updates) - Dead Cells: The Bad Seed DLC - Dead Cells: Fatal Falls DLC - Dead Cells: The Queen and the Sea - Dead Cells: Return to Castlevania - Dead Cells: Rise of the Giant', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('death-s-door-nintendo-switch', 'Death''s Door', NULL, '2021-11-23', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45xc.jpg', 'Death''s Door is an action-adventure game developed by Acid Nerve and published by Devolver Digital. Released in 2021, it follows a crow reaper tasked with collecting souls in a mysterious, atmospheric world. The game features exploration, fast-paced combat, and puzzle-solving.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('demon-turf-nintendo-switch', 'Demon Turf', NULL, '2021-11-04', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8xp.jpg', 'Demon Turf is back and better than ever! Join Beebz in this neon lit adventure where speedy platforming reigns supreme!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-eternal-collection-nintendo-switch', 'Diablo III: Eternal Collection', 'Diablo', '2018-08-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dha.jpg', 'Generations of gamers have battled the demonic hordes of Diablo, and now it’s your turn to take part in the action-RPG legacy. This Eternal Collection features Diablo III, the Reaper of Souls expansion set and the Rise of the Necromancer pack—all together in one definitive volume. Prepare yourself, mortal hero. The hellgates are opening.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disco-elysium-the-final-cut-nintendo-switch', 'Disco Elysium: The Final Cut', 'Disco Elysium', '2022-03-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ve1.jpg', 'Disco Elysium: The Final Cut is an enhanced edition of the original role-playing game developed and published by ZA/UM. It retains the core gameplay and narrative while adding full voice acting, new quests, additional endings, and other narrative revisions.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doki-doki-literature-club-plus-nintendo-switch', 'Doki Doki Literature Club Plus!', 'Doki Doki Literature Club', '2021-06-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawpa.jpg', 'Welcome to the club! Write poems for your crush and experience the terror of school romance in this critically-acclaimed psychological horror story.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-tropical-freeze-nintendo-switch', 'Donkey Kong Country: Tropical Freeze', 'Donkey Kong', '2018-05-04', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pmi.jpg', 'Donkey Kong, Diddy Kong, Dixie Kong and Cranky Kong return for the franchise’s debut on Nintendo Switch. This title includes all the fun and challenge of the original game, plus a new beginner-friendly mode that lets players enjoy this critically acclaimed adventure as groovy surfing simian Funky Kong. Funky Kong can double jump, hover, perform infinite rolls and even perform infinite underwater corkscrews. Thanks to his sturdy surfboard, even spikes can’t slow him down.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-country-returns-hd-nintendo-switch', 'Donkey Kong Country Returns HD', 'Donkey Kong', '2025-01-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9sh.jpg', 'Donkey Kong and Diddy Kong are back for some ground-pounding action in this HD version of Donkey Kong Country Returns, originally released on the Wii system.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donut-county-nintendo-switch', 'Donut County', NULL, '2018-12-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qv8.jpg', 'Donut County is a story-based physics puzzle game where you play as an ever-growing hole in the ground. Meet cute characters, steal their trash, and throw them in a hole.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-nintendo-switch', 'Doom', 'Doom', '2017-11-10', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-the-classics-collection-nintendo-switch', 'Doom: The Classics Collection', 'Doom', '2019-07-26', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xvn.jpg', 'This includes three classic Doom games preserved on one disc - Doom, Doom II, and Doom 3! No game downloads required.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-64-nintendo-switch', 'Doom 64', 'Doom', '2020-03-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qmz.jpg', 'Fight against demons in your crusade to hunt down the Mother of Demons and stop Hell''s invasion. As the player battle through more than 30 action-packed levels, they have to be on the lookout for enhanced weapons and secrets to help them put an end to the demonic threat.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-eternal-nintendo-switch', 'Doom Eternal', 'Doom', '2020-12-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5n.jpg', 'Hell’s armies have invaded Earth. Become the Slayer in an epic single-player campaign to conquer demons across dimensions and stop the final destruction of humanity. The only thing they fear... is you.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-slayers-collection-nintendo-switch', 'Doom: Slayers Collection', 'Doom', '2021-08-19', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kdb.jpg', 'The Doom Slayers Collection takes players through more than two decades of demon slaying – from the classic games that popularized the first-person shooter to the fan favorite franchise reboot, wield an arsenal of powerful weapons as you battle demon hordes on Mars, on Earth, and across Hell in four critically acclaimed games: Doom, Doom II, Doom 3, and Doom (2016).', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-doom-ii-nintendo-switch', 'Doom + Doom II', 'Doom', '2025-05-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6w0l.jpg', 'Doom II was included in Doom 3 Collector''s Edition for the Xbox, which was released in 2005. This port includes an exclusive level, "Betray". It featured multiplayer like the PC version, however not through Xbox Live. This port was programmed by Vicarious Visions. The Xbox version of Doom 3: Resurrection of Evil also contains this same port, as well as Master Levels for Doom II.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('downwell-nintendo-switch', 'Downwell', NULL, '2019-01-31', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co284e.jpg', 'Downwell is a curious game about a young man with guns for boots venturing down a well in search of untold treasures. Make your way further and further down into a darkness filled with nasty creatures and mysterious secrets and collect the spectacular red gems scattered about the rocks. Step into an oddly placed shop to buy some helpful items or level up between caverns to battle well dwelling monsters and uncover hidden caves filled with riches and relics. No two trips down the well are ever the same!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-builders-nintendo-switch', 'Dragon Quest Builders', 'Dragon Quest', '2018-02-09', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9mq.jpg', '"Dragon Quest Builders is a sandbox action RPG where your imagination is the limit! Everything plays out in real time and the world is made entirely of blocks (although it may not look that blocky) and you can use these blocks to build pretty much whatever you want. Building is easy and can be done in three steps:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-builders-2-nintendo-switch', 'Dragon Quest Builders 2', 'Dragon Quest', '2019-07-12', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9ms.jpg', 'Dragon Quest Builders 2 is a block-building role-playing game with a charming campaign and a robust multiplayer building mode that supports up to four players online. Create your customized character, team-up with your fearless friend Malroth, gather the skills required to become a full-fledged builder, and combat the Children of Hargon, a vile cult that worships destruction! Then, take your builder online and join your friends to collaborate and create something truly magnificent. Don’t let the name fool you, despite the 2, this is a completely standalone experience featuring new characters, an expansive world, unlimited building combinations, and a storyline that’s sure to satisfy longtime fans and newcomers alike!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-xi-s-echoes-of-an-elusive-age-definitive-edition-nintendo-switch', 'Dragon Quest XI S: Echoes of an Elusive Age - Definitive Edition', 'Dragon Quest', '2019-09-27', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x9f.jpg', 'The Definitive Edition includes all the content from the original release of the acclaimed DRAGON QUEST XI, and adds extra character-specific scenarios, the choice of playing with the original soundtrack or a grand orchestral version of the music, the ability to switch between 2D and 3D graphic modes, a Japanese voice-acting option, and much more.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-trilogy-nintendo-switch', 'Dragon''s Lair Trilogy', 'Dragon''s Lair', '2019-01-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co249y.jpg', 'Dragon''s Lair Trilogy (includes Dragon''s Lair, Dragon''s Lair II: Time Warp, and Space Ace.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('duck-game-nintendo-switch', 'Duck Game', NULL, '2019-05-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9t4w.jpg', 'Join the ducks on their cute journey for world domination.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-nintendo-switch', 'The Elder Scrolls V: Skyrim', 'The Elder Scrolls', '2017-11-17', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tnw.jpg', 'Skyrim reimagines and revolutionizes the open-world fantasy epic, bringing to life a complete virtual world open for you to explore any way you choose. Play any type of character you can imagine, and do whatever you want; the legendary freedom of choice, storytelling, and adventure of The Elder Scrolls is realized like never before.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-end-is-nigh-nintendo-switch', 'The End Is Nigh', NULL, '2017-12-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n38.jpg', 'The End Is Nigh is a sprawling adventure platformer where the player takes control of Ash, one of few ''things'' that have ''survived'' the "end of the world."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ender-lilies-quietus-of-the-knights-nintendo-switch', 'Ender Lilies: Quietus of the Knights', 'Ender', '2021-06-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9s9e.jpg', 'Ender Lilies is a dark fantasy 2D Action RPG about unraveling the mysteries of a nation destroyed by a cataclysmic event. The fallen Kingdom of End is a tragic and beautiful world featuring a majestic castle, submerged forests and forbidden underground areas.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ender-magnolia-bloom-in-the-mist-nintendo-switch', 'Ender Magnolia: Bloom in the Mist', 'Ender', '2025-01-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gk1.jpg', 'Decades after the Rain of Death, a new journey begins in the Land of Fumes, where mystical powers lie beneath the earth. The kingdom’s desire for conquest led to the creation of the Homunculi, machine-like artificial life forms prepared to execute the king’s will. A recent resource-harvesting mission gone awry caused toxic vapors to emerge from underground, driving both man and machine to feral madness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enter-the-gungeon-nintendo-switch', 'Enter the Gungeon', NULL, '2017-12-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobl6c.jpg', 'Enter the Gungeon is a gunfight dungeon crawler following a band of regretful misfits seeking to shoot, loot, dodge roll and table-flip their way to personal absolution by reaching the legendary Gungeon’s ultimate treasure: the gun that can kill the past. Select a hero and battle your way to the bot¬tom of the Gungeon by surviving a challenging and evolving series of floors filled with the dangerously adorable Gundead and fearsome Gungeon bosses armed to the teeth. Gather precious loot, discover hidden secrets, and chat with opportunistic merchants and shopkeepers to purchase powerful items to gain an edge.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('etherborn-nintendo-switch', 'Etherborn', NULL, '2019-07-18', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jaf.jpg', 'Etherborn is an environmental puzzle platformer built on exploring and understanding gravity-shifting structures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-x-2-hd-remaster-nintendo-switch', 'Final Fantasy X/X-2 HD Remaster', 'Final Fantasy', '2019-04-16', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zpl.jpg', 'Based on the international versions of the games that were previously only released in Japan and Europe, FINAL FANTASY X/X-2 HD Remaster brings these timeless classics forward to the current generation of fans, old and new alike.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xii-the-zodiac-age-nintendo-switch', 'Final Fantasy XII: The Zodiac Age', 'Final Fantasy', '2019-04-30', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g6o.jpg', '"FINAL FANTASY XII THE ZODIAC AGE improves upon the 2006 classic FINAL FANTASY XII, now more beautiful and easier to play than ever. The high-definition remaster introduces several modern advancements, including reconstructed battle design and a revamped job system. With newly implemented trophies and share functions, as well as stark visual and sound improvements in true HD for the first time, players both returning and new to the game will experience a grand adventure that spans the world of Ivalice in an entirely fresh and improved way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-i-vi-collection-nintendo-switch', 'Final Fantasy I-VI Collection', 'Final Fantasy', '2024-10-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nzk.jpg', 'The Final Fantasy: Pixel Remaster series will comprise FINAL FANTASY I through FINAL FANTASY VI, with each game releasing individually. For long-term fans that will be hugely exciting news - a chance to revisit some of their most beloved RPGs of all time in a way that perfectly captures the spirit of those original game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-three-houses-nintendo-switch', 'Fire Emblem: Three Houses', 'Fire Emblem', '2019-07-26', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n8t.jpg', 'Here, order is maintained by the Church of Seiros, which hosts the prestigious Officer’s Academy within its headquarters. You are invited to teach one of its three mighty houses, each comprised of students brimming with personality and represented by a royal from one of three territories. As their professor, you must lead your students in their academic lives and in turn-based, tactical RPG battles wrought with strategic, new twists to overcome. Which house, and which path, will you choose?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fire-emblem-warriors-three-hopes-nintendo-switch', 'Fire Emblem Warriors: Three Hopes', 'Fire Emblem', '2022-06-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob84j.jpg', 'Prepare for a different story set in the same universe as Fire Emblem: Three Houses. Shez, a mercenary whose team was decimated by Byleth in battle, joins the military academy of Garreg Mach Monastery and becomes a student in one of three classes, each including students from one of the three nations of the continent of Fódlan. Like in Three Houses, the game allows players to decide which class to join, leading to different story paths and playable characters.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('five-nights-at-freddy-s-help-wanted-nintendo-switch', 'Five Nights at Freddy''s: Help Wanted', 'Five Nights at Freddy''s', '2020-05-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6975.jpg', 'This is the mobile version of Five Nights at Freddy’s: Help Wanted, a collection of classic and original mini-games set in the Five Nights universe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('five-nights-at-freddy-s-core-collection-nintendo-switch', 'Five Nights at Freddy''s: Core Collection', 'Five Nights at Freddy''s', '2021-01-12', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldz.jpg', 'Five Nights at Freddy''s: Core Collection is a physical bundle of several games in the Five Nights at Freddy''s franchise. The collection will consist of the Console Ports of Five Nights at Freddy''s 1 to 4 and Sister Location.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('freedom-planet-nintendo-switch', 'Freedom Planet', 'Freedom Planet', '2018-08-30', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qr7.jpg', 'Freedom Planet is a combat-based platform adventure that pits a spunky dragon girl and her friends against an alien attack force. There''s trouble around every turn, from insects to giant robots to sheer explosive destruction, but you''ll have a variety of special fighting abilities to blast your way through each stage.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('freedom-planet-2-nintendo-switch', 'Freedom Planet 2', 'Freedom Planet', '2024-04-04', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6dk4.jpg', 'The sequel to the 16-bit platformer by GalaxyTrail. Lilac, Carol, and Milla must stop the water dragon Merga from resurrecting the ancient super-weapon Bakunawa. It is the second entry in the Freedom Planet franchise.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('frog-detective-the-entire-mystery-nintendo-switch', 'Frog Detective: The Entire Mystery', 'Frog Detective', '2023-10-26', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p53.jpg', 'You''re a detective, and a frog, and it''s time to solve 3 thrilling mysteries!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('game-builder-garage-nintendo-switch', 'Game Builder Garage', NULL, '2021-06-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zfc.jpg', 'Turn gaming time into learning time with the Game Builder Garage software. Kids can learn how to make their own games with guided lessons created by Nintendo. From a simple game of tag to a run-and-jump obstacle course, each lesson is broken down into multiple, manageable segments that let kids go at their own pace—and have fun in the process. Learn the basics of visual game programming By playing through interactive lessons, kids will learn the basics of visual game programming. Nodon, colorful creatures with distinct personalities, keep kids engaged through lessons with tips and motivating messages. With a simple press of a button, swap between the programming screen and the game screen—watch how programming changes the game on the fly. Track progress and build confidence After completing each lesson and building a game, kids will test their knowledge by completing Checkpoints—small puzzles or tasks to solve with programming. Master these skills and head to Free Programming mode to let your imagination (and programming chops) run wild. The Nodon you meet each have distinct personalities that complement their functions. Have fun connecting them together to see how they interact and bring your game to life. The in-game Nodopedia lets you quickly check what each Nodon does as you create. There’s also a guide that recaps important skills! Easily swap between the Programming and Game screens to see the hard-working Nodon in action. Take advantage of the Nintendo Switch system’s many features. Instead of the control stick, program motion controls to control your game. Want to create…', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gex-trilogy-nintendo-switch', 'Gex Trilogy', 'Gex', '2025-06-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9d3l.jpg', 'Gex Trilogy is the definitive edition of the classic platforming series with Gexcessive attitude, complete with Gextras like rewind and save anywhere. Relive Gex''s snark-laced adventures through the warped lens of twentieth-century pop culture and use your Gexterity to survive an onslaught of television-themed challenges.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('giana-sisters-twisted-dreams-owltimate-edition-nintendo-switch', 'Giana Sisters: Twisted Dreams - Owltimate Edition', 'Giana Sisters', '2018-09-25', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co543z.jpg', 'Giana Sisters: Twisted Dreams – Owltimate Edition offers classic 2D platforming fun in meticulously detailed 3D environments. Players can turn cute Giana into a punk version of herself at the press of a button, transforming the game’s star, the soundtrack and even the world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('glover-nintendo-switch', 'Glover', NULL, '2024-08-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar3y.jpg', 'The cult classic from the ''90s returns! Glover is a charming 3D platformer where you control a magical glove on a quest to restore balance to the kingdom. Roll, jump, and manipulate your magic ball to solve puzzles, overcome challenges, and defeat the evil glove threatening the world!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-making-of-karateka-nintendo-switch', 'The Making of Karateka', 'Gold Master', '2023-08-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qdy.jpg', 'Play the history. Go behind the scenes of Jordan Mechner''s landmark game Karateka in this interactive documentary from Digital Eclipse, with archival materials, video features, and more. Experience pixel-perfect versions of this legendary game, with all-new features.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('llamasoft-the-jeff-minter-story-nintendo-switch', 'Llamasoft: The Jeff Minter Story', 'Gold Master', '2024-03-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7gxd.jpg', '42 of the weirdest, trippiest, sheepiest games ever created. Enter the mind of Jeff Minter, the legendary creator of Attack of the Mutant Camels, Gridrunner, and Tempest 2000, in this interactive documentary from Digital Eclipse.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-forever-nintendo-switch', 'Tetris Forever', 'Gold Master', '2024-11-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbof.jpg', 'Tetris Forever celebrates the original, genre-inspiring puzzle game that escaped from behind the Iron Curtain, onto the world stage, and into our cultural consciousness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golf-story-nintendo-switch', 'Golf Story', NULL, '2017-09-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2q9e.jpg', 'Play the story of a golfer, forced to give up all that he holds dear for one final shot at accomplishing his dream.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gone-home-nintendo-switch', 'Gone Home', NULL, '2018-09-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/qwhxxrcxzw7inwfrfkbq.jpg', 'A first-person exploratory game taking place in 1995 in which Katie, a university student back from Europe, arrives at her family''s newly inherited mansion only to find nobody there, with a note from her younger sister Sam suggesting that she''s left home. Katie must explore the mansion to put together the stories of where her parents have gone and why Sam has decided to leave.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gorogoa-nintendo-switch', 'Gorogoa', NULL, '2017-12-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kby.jpg', 'Gorogoa is a beautiful hand-drawn story suspended inside a completely unique puzzle. Arrange and combine lavishly illustrated panels, each one a separate interactive window into a living game world.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gradius-origins-nintendo-switch', 'Gradius Origins', 'Gradius', '2025-08-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9l0o.jpg', 'This collection features 18 versions across all 7 arcade titles in the series, including the first-ever appearance of Gradius III AM Show Version on home consoles.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grim-fandango-remastered-nintendo-switch', 'Grim Fandango Remastered', 'Grim Fandango', '2018-11-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27pj.jpg', 'Something''s rotten in the land of the dead, and you''re being played for a sucker. Meet Manny Calavera, travel agent at the Department of Death. He sells luxury packages to souls on their four-year journey to eternal rest. But there''s trouble in paradise. Help Manny untangle himself from a conspiracy that threatens his very salvation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gris-nintendo-switch', 'Gris', NULL, '2018-12-13', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qv5.jpg', 'Gris is a 2D platformer developed by Nomada Studio and published by Devolver Digital. It is a visually striking game that follows the journey of a young woman named Gris as she navigates a world of grief and loss. The game features no dialogue, relying on its hand-painted art style, evocative music, and environmental storytelling to convey its themes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grounded-fully-yoked-edition-nintendo-switch', 'Grounded Fully Yoked Edition', 'Grounded', '2024-04-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co835s.jpg', 'The free 1.4 "Fully Yoked" content update for all players introduces royal Ant Queens, a New Game+ mode, full Japanese VO, and an exciting array of new weapons, armor, and more. Additional content includes new molars, infused bugs, the ability to upgrade gear past level 9, four new achievements, one new mutation, twelve Ant Queen-related buildings, new baby ant pets, and other gameplay additions. Beginning with this update, hosts can now load a save while in the middle of a multiplayer session and all connected players will seamlessly transition into the new game world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guacamelee-one-two-punch-collection-nintendo-switch', 'Guacamelee! One-Two Punch Collection', 'Guacamelee!', '2019-02-04', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6031.jpg', 'Guacamelee! One-Two Punch Collection includes both Guacamelee! Super Turbo Championship Edition and Guacamelee! 2, an exclusive two-sided poster, a complete instruction manual, and download codes for two soundtracks.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hades-nintendo-switch', 'Hades', NULL, '2021-02-18', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4rs3.jpg', 'A South Korean-made first person shooter (potentially the first ever from that country).', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-light-of-hope-nintendo-switch', 'Harvest Moon: Light of Hope', 'Harvest Moon', '2018-05-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xlb.jpg', 'The third Harvest Moon game created by Natsume without the original developers of the series.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-mad-dash-nintendo-switch', 'Harvest Moon: Mad Dash', 'Harvest Moon', '2019-10-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gk7.jpg', 'Go solo or take a few friends along for the frenzy! Harvest, fish, milk, and more as you fullfil orders to complete each level! Things may start out easy, but you''ll hit the beach, the farm, and even the Underworld as you progress through the game! Have you ever tried to grow crops with molten lava falling on them?! That and other obstacles await you as you and your friends try to clear all the levels to restore the broken lighthouse!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-one-world-nintendo-switch', 'Harvest Moon: One World', 'Harvest Moon', '2021-03-02', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl3.jpg', 'Explore a world of new and familiar faces, unique villages and adventurous challenges, while managing your growing farm.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-hat-in-time-nintendo-switch', 'A Hat in Time', NULL, '2019-11-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1uc.jpg', 'A Hat in Time is a cute-as-heck 3D platformer featuring a little girl who stitches hats for wicked powers! Freely explore giant worlds and recover Time Pieces to travel to new heights!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('haven-nintendo-switch', 'Haven', NULL, '2021-02-04', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co542m.jpg', 'A sandbox game set in an Iron Age world loosely inspired by Slavic and Germanic myth and legend.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('heaven-s-vault-nintendo-switch', 'Heaven''s Vault', NULL, '2021-01-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2t94.jpg', 'Explore the lost ruins of the Nebula, read ancient inscriptions, and uncover a forgotten past in this narrative archaeological science-fiction adventure game from the creators of 80 Days.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hitman-blood-money-reprisal-nintendo-switch', 'Hitman: Blood Money — Reprisal', 'Hitman', '2024-01-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7etv.jpg', 'A new version of Hitman: Blood Money. Hitman: Blood Money Reprisal stars Agent 47, an assassin dispatching targets all around the world. The new version introduces some new mechanics, such as instinct mode and a minimap.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hollow-knight-nintendo-switch', 'Hollow Knight', NULL, '2018-06-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaes9.jpg', 'Unofficial port of the hit game Hollow Knight for PlayStation Vita.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hotline-miami-collection-nintendo-switch', 'Hotline Miami Collection', 'Hotline Miami', '2019-08-19', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p88.jpg', 'Hotline Miami Collection contains both legendary games in the neon-soaked, brutally-challenging Hotline Miami series from Dennaton Games.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyper-light-drifter-nintendo-switch', 'Hyper Light Drifter', 'Hyper Light', '2018-09-06', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4dwx.jpg', 'The wait is over, the worldwide acclaimed game Hyper Light Drifter is finally here with this impressive Special Edition!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iconoclasts-nintendo-switch', 'Iconoclasts', NULL, '2018-08-02', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ug9.jpg', 'Join renegade mechanic Robin and uncover the secrets of a dying planet. Explore a huge, open world filled with intricate puzzles, oddball characters and menacing bosses in a beautiful platform adventure telling a personal story about faith, purpose and whether the world is really worth saving.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ikenfell-nintendo-switch', 'Ikenfell', NULL, '2020-10-08', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fsc.jpg', 'A turn-based tactical RPG about a group of troublesome magic students. Use timing mechanics to power your spells and block attacks, explore the twisted halls of a vast magic school, fight challenging monsters and bosses, and uncover dark secrets never meant to be found.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('immortals-fenyx-rising-nintendo-switch', 'Immortals Fenyx Rising', NULL, '2020-12-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kcb.jpg', 'From the creators of Assassin’s Creed Odyssey comes a storybook adventure about a forgotten hero on a quest to save the Greek gods.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('inscryption-nintendo-switch', 'Inscryption', NULL, '2022-12-01', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co401c.jpg', 'Inscryption is an inky black card-based odyssey that blends the deckbuilding roguelike, escape-room style puzzles, and psychological horror into a blood-laced smoothie. Darker still are the secrets inscrybed upon the cards...', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('katamari-damacy-reroll-nintendo-switch', 'Katamari Damacy Reroll', 'Katamari', '2018-12-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25sm.jpg', 'When the King of All Cosmos accidentally destroys all the stars in the sky, he orders you, his pint-sized princely son, to put the twinkle back in the heavens above. Join the King and Prince of Cosmos on their wacky adventure to restore the stars at home or on the go – now in full HD!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('we-love-katamari-reroll-royal-reverie-nintendo-switch', 'We Love Katamari Reroll+ Royal Reverie', 'Katamari', '2023-06-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6589.jpg', 'We Love Katamari Reroll + Royal Reverie is a remaster of the PS2 game We Love Katamari.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kaze-and-the-wild-masks-nintendo-switch', 'Kaze and the Wild Masks', NULL, '2021-05-25', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t98.jpg', 'Go on a journey as Kaze in this 90’s classics inspired platformer. When the Crystal Islands get cursed, Kaze needs to save her friend Hogo while facing enraged living vegetables. Find the Wild Masks to unleash the powers of the legendary guardians and master land, sky and sea.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kentucky-route-zero-tv-edition-nintendo-switch', 'Kentucky Route Zero: TV Edition', 'Kentucky Route Zero', '2020-01-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xix.jpg', 'Kentucky Route Zero is a magical realist adventure game about a secret highway in the caves beneath Kentucky, and the mysterious folks who travel it. Gameplay is inspired by point-and-click adventure games (like the classic Monkey Island or King''s Quest series, or more recently Telltale''s Walking Dead series), but focused on characterization, atmosphere and storytelling rather than clever puzzles or challenges of skill.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killer-queen-black-nintendo-switch', 'Killer Queen Black', 'Killer Queen', '2019-10-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ig2.jpg', 'Killer Queen Black is an intense multiplayer action/strategy platformer for up to eight players. Fly solo, or team up with three of your friends as you race to complete one of three possible victory conditions.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-melody-of-memory-nintendo-switch', 'Kingdom Hearts: Melody of Memory', 'Kingdom Hearts', '2020-11-13', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gk9.jpg', 'Kingdom Hearts: Melody of Memory is a rhythm action game developed and published by Square Enix for the PlayStation 4, Xbox One, and Nintendo Switch. It is the fourteenth installment in the Kingdom Hearts series. The game features over 140 songs from the series and the ability to play as over 20 characters. Additionally, Kairi''s story is continued from the end of the Kingdom Hearts III Re Mind downloadable content.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-star-allies-nintendo-switch', 'Kirby Star Allies', 'Kirby', '2018-03-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ezz.jpg', 'Kirby is back in this new title coming to the Nintendo Switch console in HD. Recruit enemies as helpers, use Kirby copy abilities such as Sword, Fire and Water, and join forces with up to three friends for a different kind of team-up action.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-and-the-forgotten-land-nintendo-switch', 'Kirby and the Forgotten Land', 'Kirby', '2022-03-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yjz.jpg', 'The first level of the Switch game, now available on your Gameboy Color! Features most mechanics from the original game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-s-return-to-dream-land-deluxe-nintendo-switch', 'Kirby''s Return to Dream Land Deluxe', 'Kirby', '2023-02-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8dp2.jpg', 'The tough puff Kirby is back for a 4-player* platforming adventure. Copy enemies’ abilities and use their power to attack with a sword, wield a whip, and float with a parasol. You can also laser blast with the new Mecha Copy Ability that makes a series debut! The extra muscle will be handy in finding missing pieces for Magolor’s ship, which crash landed on Planet Popstar. Float and fight along with friends on the same system, where each player can control another Kirby or one of Kirby’s iconic friends like King Dedede, Meta Knight, and Bandana Waddle Dee.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-nintendo-switch', 'L.A. Noire', 'L.A. Noire', '2017-11-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldn.jpg', 'L.A. Noire is a neo-noir detective action-adventure video game developed by Team Bondi and published by Rockstar Games. It was initially released for the PlayStation 3 and Xbox 360 platforms on 17 May 2011; a Microsoft Windows port was later released on 8 November 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-breath-of-the-wild-nintendo-switch', 'The Legend of Zelda: Breath of the Wild', 'The Legend of Zelda', '2017-03-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67oa.jpg', 'The Legend of Zelda: Breath of the Wild game packs countless hours of play into a vast world of discovery. That makes it an ideal foundation for more adventures! This special bundle comes with the full game for the Nintendo Switch system and the Expansion Pass, which grants access to three new treasure chests, The Master Trials DLC Pack 1, and The Champions Ballad DLC Pack 2.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyrule-warriors-definitive-edition-nintendo-switch', 'Hyrule Warriors: Definitive Edition', 'The Legend of Zelda', '2018-05-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob2j6.jpg', 'A new, ultimate version of the exhilarating action game set in the Zelda universe will include every map and mission, plus all 29 playable characters from both the Wii U and Nintendo 3DS versions of the game, along with all of the previous paid downloadable content. Play as Link, Zelda, Midna, Skull Kid and dozens more in action-packed battles at home or on the go. Additionally, the game includes new outfits for Link and Zelda based on the Legend of Zelda: Breath of the Wild game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cadence-of-hyrule-crypt-of-the-necrodancer-featuring-the-legend-of-zelda-nintendo-switch', 'Cadence of Hyrule: Crypt of the NecroDancer Featuring The Legend of Zelda', 'The Legend of Zelda', '2019-06-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob88s.jpg', 'Cadence of Hyrule: Crypt of the NecroDancer Featuring The Legend of Zelda is a rhythmic action-adventure game where you can enjoy the gameplay of Crypt of the NecroDancer in the setting of The Legend of Zelda series. As Link - or even as Princess Zelda - you''ll explore the randomly generated overworld and procedurally generated dungeons on a quest to save Hyrule. Every beat of each remixed Legend of Zelda tune is a chance to move, attack, defend, and more, so stay one step ahead of each enemy and boss… or face the music.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-link-s-awakening-nintendo-switch', 'The Legend of Zelda: Link''s Awakening', 'The Legend of Zelda', '2019-09-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4o47.jpg', 'The Legend of Zelda: Link''s Awakening DX is an updated re-release of Link''s Awakening with several new additions, the most notable of which being the entire game is now in color.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyrule-warriors-age-of-calamity-nintendo-switch', 'Hyrule Warriors: Age of Calamity', 'The Legend of Zelda', '2020-11-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob22n.jpg', 'See Hyrule 100 years before the Legend of Zelda: Breath of the Wild game and experience the events of the Great Calamity.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-skyward-sword-hd-nintendo-switch', 'The Legend of Zelda: Skyward Sword HD', 'The Legend of Zelda', '2021-07-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8lb.jpg', 'The Legend of Zelda: Skyward Sword HD is a remaster of the 2011 game Skyward Sword that features enhanced graphics and frame rate. The game now has a standard resolution of 1080p, an intuitive auto-save function and a streamlined item description among other improvements.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-tears-of-the-kingdom-nintendo-switch', 'The Legend of Zelda: Tears of the Kingdom', 'The Legend of Zelda', '2023-05-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vmg.jpg', 'An epic adventure across the land and skies of Hyrule awaits in The Legend of Zelda: Tears of the Kingdom for Nintendo Switch. The adventure is yours to create in a world fueled by your imagination.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-echoes-of-wisdom-nintendo-switch', 'The Legend of Zelda: Echoes of Wisdom', 'The Legend of Zelda', '2024-09-26', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8d9b.jpg', 'The people of Hyrule are being stolen away by strange rifts that have appeared, and with a certain swordsman among those missing, it’s up to Princess Zelda to save her kingdom.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-city-undercover-nintendo-switch', 'Lego City Undercover', 'Lego', '2017-04-04', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vx0.jpg', 'As Chase McCain, you''ll become an expert at hand-to-hand combat, fighting your foes and wrestling them to the ground until you can slap the cuffs on ''em. The best officers are also pros at free running, jumping, climbing, and traversing the city on special blue and white bricks. Do you have what it takes?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-worlds-nintendo-switch', 'Lego Worlds', 'Lego', '2017-09-05', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1j95.jpg', 'LEGO Worlds is an open environment of procedurally-generated Worlds made entirely of LEGO bricks which you can freely manipulate and dynamically populate with LEGO models. Create anything you can imagine one brick at a time, or use large-scale landscaping tools to create vast mountain ranges and dot your world with tropical islands. Drop in prefabricated structures to build and customize any world to your liking. Explore using helicopters, dragons, motorbikes or even gorillas and unlock treasures that enhance your gameplay. Watch your creations come to life through characters and creatures that interact with you and each other in unexpected ways. In LEGO Worlds, anything is possible!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-ninjago-movie-video-game-nintendo-switch', 'The Lego Ninjago Movie Video Game', 'Lego', '2017-09-22', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co253j.jpg', 'Find your inner ninja with the all-new LEGO Ninjago Movie Video Game! Play as your favorite ninjas, Lloyd, Jay, Kai, Cole, Zane, Nya and Master Wu to defend Ninjago City from the evil Lord Garmadon and his Shark Army. Master the art of Ninja-gility by wall-running, high-jumping and battling the foes of Ninjago to rank up and upgrade the ninja’s combat skills. Only in the LEGO Ninjago Movie Video Game will you experience the film across 8 action packed locations each with its own unique Challenge Dojo. And with the Battle Maps, play against friends and family in competitions for up to four players!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-2-nintendo-switch', 'Lego Marvel Super Heroes 2', 'Lego', '2017-11-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27zc.jpg', 'Get the Deluxe Edition now and gain access to the main game and season pass content! Join your favorite Super Heroes and Super Villains from different eras and realities as they go head-to-head with the time-traveling Kang the Conqueror in the all-new, original adventure, LEGO Marvel Super Heroes 2! Play as the Guardians of the Galaxy, Spider-Man, Thor, Hulk, Black Panther, Captain Marvel, Doctor Strange, Green Goblin and dozens of other Marvel Super Heroes and Villains in this cosmic battle across the time-tossed city of Chronopolis! Travel across lands -- from Ancient Egypt to The Old West, Sakaar and New York City in 2099 -- and transport objects or characters through the centuries! And, with new battle modes, friends and family can play against each other in a series of themed challenges and battle arenas!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-incredibles-nintendo-switch', 'Lego The Incredibles', 'Lego', '2018-06-15', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wkq.jpg', 'LEGO The Incredibles takes players on an adventure where they’ll control their favourite Incredibles characters and team up as a family to conquer crime and family life.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dc-super-villains-nintendo-switch', 'Lego DC Super-Villains', 'Lego', '2018-10-16', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26qa.jpg', 'Lego DC Super-Villains is a Lego-themed action-adventure platform video game developed by Traveller''s Tales. The fourth installment in the Lego Batman series of games, it is a spin-off that focuses entirely on villains of the DC Universe; it is the first in the series to do so since the villain levels from Lego Batman: The Videogame.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-collection-nintendo-switch', 'Lego Harry Potter Collection', 'Lego', '2018-10-30', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8s8o.jpg', 'The LEGO Harry Potter: Collection is an action-adventure compilation that combines LEGO Harry Potter: Years 1–4 and LEGO Harry Potter: Years 5–7 into a single experience.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-2-videogame-nintendo-switch', 'The Lego Movie 2 Videogame', 'Lego', '2019-02-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dhg.jpg', 'The alien monster invaders have left Bricksburg in ruins. It is now up to Emmet and a host of heroic characters to go beyond their world and save their friends from the strange inhabitants of the Systar System. Players can journey into outer space, discover new worlds, and test their Master Building skills.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-nintendo-switch', 'Lego Jurassic World', 'Lego', '2019-09-17', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-nintendo-switch', 'Lego Marvel Super Heroes', 'Lego', '2021-10-08', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-kiwami-nintendo-switch', 'Yakuza Kiwami', 'Like a Dragon', '2024-10-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coazbq.jpg', 'A bundle including Yakuza Kiwami and Yakuza Kiwami 2.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('little-kitty-big-city-nintendo-switch', 'Little Kitty, Big City', NULL, '2024-05-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6mbt.jpg', 'You''re a curious little kitty with a big personality, on an adventure to find your way back home. Explore the city, make new friends, wear delightful hats, and leave more than a little chaos in your wake. After all, isn''t that what cats do best?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('luigi-s-mansion-3-nintendo-switch', 'Luigi''s Mansion 3', 'Luigi''s Mansion', '2019-10-31', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22a9.jpg', 'Luigi embarks on a dream vacation with Mario and friends upon receiving an invitation to a luxurious hotel. However, his dream quickly becomes a nightmare when King Boo reveals everything had been a ploy to capture Mario and friends. With the assistance of Professor E. Gadd once again, the reluctant and cowardly hero Luigi traverses up and down treacherous floors of the now-ominous hotel on a quest to save them.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('collection-of-mana-nintendo-switch', 'Collection of Mana', 'Mana', '2019-06-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w90.jpg', 'A collection of the first 3 Seiken Densetsu games, known as the Mana series internationally, with a quick save feature added and all 3 soundtracks.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('trials-of-mana-nintendo-switch', 'Trials of Mana', 'Mana', '2020-04-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lzw.jpg', 'Trials of Mana is a full high definition remake of the third entry in the Mana series, previously exclusively released in Japan in 1995 as Seiken Densetsu 3. Trials of Mana tells the story of six heroes as they battle against the monsters of destruction that threaten a world where Mana has been weakened. Players can customize their own party of three, selected from six unique characters, to experience different stories.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('manifold-garden-nintendo-switch', 'Manifold Garden', NULL, '2020-08-18', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ws9.jpg', 'Manifold Garden is a game that reimagines physics and space.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('manifold-garden-nintendo-switch-2', 'Manifold Garden', NULL, '2020-08-18', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ws9.jpg', 'Manifold Garden is a game that reimagines physics and space.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-odyssey-nintendo-switch', 'Super Mario Odyssey', 'Mario', '2017-10-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co63jd.jpg', 'A mod which adds F.L.U.D.D. from Super Mario Sunshine in Super Mario Odyssey.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-mario-bros-u-deluxe-nintendo-switch', 'New Super Mario Bros. U Deluxe', 'Mario', '2019-01-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uhl.jpg', 'New Super Mario Bros. U including New Super Luigi U. for the Nintendo Switch!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-maker-2-nintendo-switch', 'Super Mario Maker 2', 'Mario', '2019-06-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21vy.jpg', 'A side-scrolling Mario adventure that unleashes the creative potential of Super Mario Maker 2 awaits in Story Mode, which contains over 100 built-in courses. And in Course Maker, a wide range of parts, tools, and more are available so you can construct your own courses. Want coin-shooting cannons? Bowser riding on a giant Goomba? Cat Mario sliding down slopes to take out an army of baddies? Go for it! You call the shots. Pass a Joy-Con controller to a partner to build co-operatively on a single system!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-3d-all-stars-nintendo-switch', 'Super Mario 3D All-Stars', 'Mario', '2020-09-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8wk.jpg', 'Discover three of Mario’s grandest 3D adventures with Super Mario 3D All-Stars on Nintendo Switch! This special bundle includes Super Mario 64, Super Mario Sunshine and Super Mario Galaxy, all optimized for Nintendo Switch with updated HD graphics, Joy-Con controls, as well as a music player featuring the epic soundtracks from all three games!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-3d-world-bowser-s-fury-nintendo-switch', 'Super Mario 3D World + Bowser''s Fury', 'Mario', '2021-02-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb2d.jpg', 'The Super Mario 3D World + Bowser’s Fury game features the same lively co-op gameplay, creative levels and power-ups as the original game, but with added improvements. In the Super Mario 3D World part of the game, characters move faster and the dash powers up more quickly. Both adventures support the newly added Snapshot Mode, pause the action to get the perfect shot, apply filters, and decorate with stamps!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-bros-wonder-nintendo-switch', 'Super Mario Bros. Wonder', 'Mario', '2023-10-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nnl.jpg', 'The next evolution of 2D side-scrolling Super Mario Bros. games is headed to Nintendo Switch!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-rpg-nintendo-switch', 'Super Mario RPG', 'Mario', '2023-11-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kd0.jpg', 'A sequel to Super Mario RPG: Legend of the Seven Stars, otherwise known as Mario RPG 2 and Mario RPG 64 while in development. Due to complications involving Square, it was reworked into Paper Mario and was released as a standard Nintendo 64 title.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-galaxy-super-mario-galaxy-2-nintendo-switch', 'Super Mario Galaxy + Super Mario Galaxy 2', 'Mario', '2025-10-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakzq.jpg', 'A short troll hack for Mario 64 based on the Bart Simpson concussion meme', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-luigi-brothership-nintendo-switch', 'Mario & Luigi: Brothership', 'Mario & Luigi', '2024-11-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8d9a.jpg', 'The brothers return for a brand new adventure on the high seas! Set sail with Mario and Luigi on Shipshape Island (part ship, part island) and journey through the vast world of Concordia. Launch out of Shipshape’s cannon to visit, explore, and quest your way through islands that range from tropical rainforests to bustling cities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-sonic-at-the-olympic-games-tokyo-2020-nintendo-switch', 'Mario & Sonic at the Olympic Games Tokyo 2020', 'Mario & Sonic at the Olympic Games', '2019-11-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22wl.jpg', 'Mario & Sonic at the Olympic Games Tokyo 2020 is the sixth installment in the Mario & Sonic series based on the real-world 2020 Summer Olympics, which will take place in Tokyo, Japan. The game includes a number of events, including returning ones from previous Mario & Sonic titles, such as boxing, soccer, swimming, and gymnastics, and new ones, such as karate, skateboarding, sport climbing, and surfing. It will also feature a mode with 2D Events where players can compete in classic 2D versions of events from the 1964 Summer Olympics. Based off older sports games, these events are played using button controls only and will only feature eight playable characters. These 2D Events'' animations reflect the 8-bit Mario and 16-bit Sonic game art style.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-rabbids-kingdom-battle-nintendo-switch', 'Mario + Rabbids Kingdom Battle', 'Mario + Rabbids', '2017-08-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2274.jpg', 'This is the story of an unexpected encounter between Mario and the irreverent Rabbids. The Mushroom Kingdom has been torn apart by a mysterious vortex, transporting the Rabbids into the once-peaceful area, splintering this beloved land. To bring order back to the Kingdom, Mario, Luigi, Princess Peach, and Yoshi team up with Rabbids heroes in a journey through four different worlds.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-rabbids-sparks-of-hope-nintendo-switch', 'Mario + Rabbids Sparks of Hope', 'Mario + Rabbids', '2022-10-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob89b.jpg', 'Team up with Mario, Luigi, Princess Peach, Rabbid Peach, Rabbid Luigi, and their friends on a galactic journey to defeat a malevolent entity and save your Spark companions. Explore planets throughout the galaxy as you uncover mysterious secrets and compelling quests!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-golf-super-rush-nintendo-switch', 'Mario Golf: Super Rush', 'Mario Golf', '2021-06-25', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7q8.jpg', 'Tee off with family and friends in the biggest Mario Golf game yet! Hit the green with up to four players locally or online and golf with familiar Mushroom Kingdom characters. Modes range from Standard Golf to the energetic Speed Golf and an RPG-like golf adventure in story mode. Intuitive motion or button controls, a shot gauge that adapts to the curve of the course, and other new features make it easy for both new players and seasoned pros to drive and putt with power.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-8-deluxe-nintendo-switch', 'Mario Kart 8 Deluxe', 'Mario Kart', '2017-04-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ydc.jpg', 'Target Exclusive Double Pack includes both Mario Kart 8 Deluxe and Super Mario Party for Nintendo Switch.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-8-deluxe-booster-course-pass-nintendo-switch', 'Mario Kart 8 Deluxe + Booster Course Pass', 'Mario Kart', '2023-12-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67uo.jpg', 'A total of 48 more courses from throughout the Mario Kart series are racing to the Mario Kart 8 Deluxe game as paid DLC*. Take in the sights and speed through courses based on real-world locations like Tour London Loop and Tour New York Minute. This DLC also brings back half-pipes! Get some air, pull off a trick, and get a speed boost on Merry Mountain and Wii Maple Treeway.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-party-nintendo-switch', 'Super Mario Party', 'Mario Party', '2018-10-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaa9.jpg', 'Turn the tables on opponents as you race across the board to collect the most stars in the original four-player Mario Party series board game mode. Discover 80 mini-games packed with wildly different challenges, play with others online and enjoy this full-on frenzy with family and friends!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-party-superstars-nintendo-switch', 'Mario Party Superstars', 'Mario Party', '2021-10-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8q08.jpg', NULL, 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-party-jamboree-nintendo-switch', 'Super Mario Party Jamboree', 'Mario Party', '2024-10-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9yk.jpg', 'Get ready for the biggest party yet in Super Mario Party Jamboree for Nintendo Switch. From running through merry-go-rounds to motion-control minigolf, this jamboree is jam-packed with over 110 minigames – the most of any Mario Party game to date!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-tennis-aces-nintendo-switch', 'Mario Tennis Aces', 'Mario Tennis', '2018-06-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tfw.jpg', 'A new Mario Tennis game is bringing a new level of skill and competition to Nintendo Switch. Mario steps onto the court in classy tennis garb for intense rallies against a variety of characters in full-blown tennis battles. New wrinkles in tennis gameplay will challenge your ability to read an opponent''s position and stroke to determine which shot will give you the advantage. And this time the game adds the first story mode since the Mario Tennis game on Game Boy Advance, offering a new flavor of tennis gameplay, with a variety of missions, boss battles and more', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-vs-donkey-kong-nintendo-switch', 'Mario vs. Donkey Kong', 'Mario vs. Donkey Kong', '2024-02-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6omn.jpg', 'Mario vs. Donkey Kong: Minis March Again! (マリオVSドンキーコング ミニミニ再行進!? Mario tai Donkī Kongu Mini Mini sai Kōshin!) is a puzzle video game for the Nintendo DSi. Announced at the Electronic Entertainment Expo 2009, it is the third game in the Mario vs. Donkey Kong series. It was released via the Nintendo DSiWare download service in North America on June 8, 2009, in Europe and Australia on August 21, 2009 and in Japan on October 7, 2009. It is the first DSiWare game to feature a level editor in which players can create custom-made levels and send them to players on other devices via a wireless Internet connection.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-3-the-black-order-nintendo-switch', 'Marvel Ultimate Alliance 3: The Black Order', 'Marvel', '2019-07-19', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r88.jpg', 'Assemble your ultimate team of Marvel Super Heroes from a huge cast including the Avengers, the Guardians of the Galaxy, the X-Men, and more! Team up with friends to prevent galactic devastation at the hands of the mad cosmic tyrant Thanos and his ruthless warmasters, The Black Order.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-mega-man-legacy-collection-2-nintendo-switch', 'Mega Man Legacy Collection + Mega Man Legacy Collection 2', 'Mega Man', '2018-05-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-11-nintendo-switch', 'Mega Man 11', 'Mega Man', '2018-10-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qb8.jpg', 'A GameStop/EB Games exclusive edition of Mega Man 11 that was only released in North America.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-legacy-collection-1-2-nintendo-switch', 'Mega Man X Legacy Collection 1+2', 'Mega Man X', '2018-07-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2055.jpg', '"Mega Man X Legacy Collection includes the legendary 16-bit titles and the series’ exciting foray into 32-bits: Mega Man X, Mega Man X2, Mega Man X3, and Mega Man X4. The heroic robot grows stronger as he takes down Mavericks and steals their weapons, and also has the ability to dash and wall jump for thrilling, fast-paced combat. Mega Man X’s mysterious friend, Zero, also joins the fray as a playable character later in this collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-zx-legacy-collection-nintendo-switch', 'Mega Man Zero / ZX Legacy Collection', NULL, '2020-02-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204w.jpg', 'Mega Man Zero/ZX Legacy Collection brings together six classic titles in one game: Mega Man Zero 1, 2, 3 and 4, as well as Mega Man ZX and ZX Advent. The collection also features Z-Chaser, an exclusive new mode created just for this set of games.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-messenger-nintendo-switch', 'The Messenger', 'The Messenger', '2018-08-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1th.jpg', 'As a demon army besieges his village, a young ninja ventures through a cursed world, to deliver a scroll paramount to his clan''s survival.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-messenger-includes-picnic-panic-nintendo-switch', 'The Messenger [Includes Picnic Panic]', 'The Messenger', '2025-03-21', 'Nintendo Switch', 1, 0, NULL, NULL, NULL, NULL, 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-master-collection-vol-1-nintendo-switch', 'Metal Gear Solid: Master Collection Vol. 1', 'Metal Gear', '2023-10-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jaw.jpg', 'Metal Gear Solid Master Collection: Volume 1 compiles the early entries in the Metal Gear series into a single package, offering players the opportunity to experience the origins of stealth action gameplay. The collection includes the following titles: Metal Gear, Metal Gear 2: Solid Snake, Metal Gear Solid (with VR Missions/Special Missions), Metal Gear Solid 2: Sons of Liberty (HD Collection version), Metal Gear Solid 3: Snake Eater (HD Collection version), as well as the NES/Famicom version of Metal Gear and Snake’s Revenge. Regional versions of the titles are available as additional downloads.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-dread-nintendo-switch', 'Metroid Dread', 'Metroid', '2021-10-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co935n.jpg', NULL, 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-remastered-nintendo-switch', 'Metroid Prime Remastered', 'Metroid', '2023-02-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbn9.jpg', 'Get behind the visor of intergalactic bounty hunter Samus Aran in her critically-acclaimed first-person adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mighty-switch-force-collection-nintendo-switch', 'Mighty Switch Force! Collection', 'Mighty Switch Force!', '2019-07-25', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8y4.jpg', 'Switch up the fun with four games in one with Mighty Switch Force! Collection! Take control of cybernetic peacekeeper Patricia Wagon and jump, shoot, and puzzle-solve your way through four fantastic games: Mighty Switch Force!, Mighty Switch Force! 2, Mighty Switch Force! Hyper Drive Edition, and Mighty Switch Force! Academy.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('miitopia-nintendo-switch', 'Miitopia', 'Miitopia', '2021-05-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5akw.jpg', 'Miitopia needs YOU…to cast Mii characters for the three trailers in the Casting Call demo. Fill the roles with characters you create, or choose characters made by others. Then cast them, sit back, and watch your actors play their parts!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-nintendo-switch', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2017-08-22', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-nintendo-switch', 'Minecraft', 'Minecraft', '2018-06-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fu7.jpg', 'Minecraft focuses on allowing the player to explore, interact with, and modify a dynamically-generated map made of one-cubic-meter-sized blocks. In addition to blocks, the environment features plants, mobs, and items. Some activities in the game include mining for ore, fighting hostile mobs, and crafting new blocks and tools by gathering various resources found in the game. The game''s open-ended model allows players to create structures, creations, and artwork on various multiplayer servers or their single-player maps. Other features include redstone circuits for logic computations and remote actions, minecarts and tracks, and a mysterious underworld called the Nether. A designated but completely optional goal of the game is to travel to a dimension called the End, and defeat the ender dragon.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-dungeons-ultimate-edition-nintendo-switch', 'Minecraft Dungeons Ultimate Edition', 'Minecraft', '2021-10-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co82r9.jpg', 'Experience the complete story of Minecraft Dungeons from the beginning to the End! Minecraft Dungeons: Ultimate Edition includes the base game and all six DLCs.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minit-nintendo-switch', 'Minit', NULL, '2018-08-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vcj.jpg', 'Minit is a peculiar little adventure played sixty seconds at a time.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-monkey-island-nintendo-switch', 'Return to Monkey Island', 'Monkey Island', '2022-09-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56kr.jpg', 'Return to Monkey Island, the long-awaited follow-up to the legendary Secret of Monkey Island and Monkey Island 2: LeChuck''s Revenge by Ron Gilbert''s Terrible Toybox in collaboration with Devolver Digital and Lucasfilm Games, coming 2022.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-generations-ultimate-nintendo-switch', 'Monster Hunter Generations Ultimate', 'Monster Hunter', '2018-08-28', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/m0l4ma2qdh7z2m5o6m5l.jpg', 'An enhanced version of Monster Hunter Generations. It features new monsters, hunting styles, and the more challenging G-Rank quests.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-rise-nintendo-switch', 'Monster Hunter Rise', 'Monster Hunter', '2021-03-26', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7i5f.jpg', 'Experience Monster Hunter Rise and its massive expansion Monster Hunter Rise: Sunbreak in one convenient set!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-stories-2-wings-of-ruin-nintendo-switch', 'Monster Hunter Stories 2: Wings of Ruin', 'Monster Hunter', '2021-07-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobksk.jpg', 'Monster Hunter Stories 2: Wings of Ruin offers both RPG and Monster Hunter fans a unique new experience with a rich storyline featuring charming characters, challenging quests and friendly encounters with familiar monsters from the Monster Hunter series. Assuming the role of a young Monster Rider who can use a Kinship Stone to form strong bonds with monsters, players can gain experience and improve their skills to form deeper connections with these wonderful creatures. When ready, players can embark on memorable adventures filled with dramatic events and heartwarming friendships as the epic tale unfolds.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-stories-collection-nintendo-switch', 'Monster Hunter Stories Collection', 'Monster Hunter', '2024-06-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobm9s.jpg', 'A compilation of the HD port of Monster Hunter Stories and Monster Hunter Stories 2: Wings of Ruin.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monument-valley-the-trilogy-nintendo-switch', 'Monument Valley: The Trilogy', 'Monument Valley', '2025-10-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaecb.jpg', 'Monument Valley: Trilogy is a puzzle game featuring geometric landscapes and optical illusion-based levels. Players navigate through surreal architectural environments, solving spatial puzzles by manipulating the game''s architectural structures. The series follows a silent protagonist through interconnected puzzle worlds, combining minimalist design with intricate spatial challenges.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('moon-nintendo-switch', 'Moon', NULL, '2020-08-27', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co81yu.jpg', 'An interactive movie/game for the Terebikko in which the player had to help the Sailor Senshi answer the questions of the Daimon Quiz.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neon-white-nintendo-switch', 'Neon White', NULL, '2022-06-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tgh.jpg', 'Neon White is a single-player speedrunning FPS where you can sacrifice your guns for godlike parkour moves.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neva-nintendo-switch', 'Neva', NULL, '2024-10-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8x5c.jpg', 'Neva is an action-adventure game developed by Nomada Studio and published by Devolver Digital.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ni-no-kuni-wrath-of-the-white-witch-nintendo-switch', 'Ni no Kuni: Wrath of the White Witch', 'Ni no Kuni', '2019-09-20', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbw.jpg', '"Ni no Kuni: Wrath of the White Witch, a heart-warming tale of a young boy named Oliver, who embarks on a journey into a parallel world in an attempt to bring his mother back from the dead. Along the way, Oliver makes new friends and adopts many of the wonderful creatures that inhabit the world, raising them to battle other creatures on his behalf as he takes on formidable enemies. Developed by LEVEL-5 alongside Studio Ghibli, the legendary animation studio, Ni no Kuni: Wrath of the White Witch combines beautiful animated visuals, masterful storytelling and a sweeping score into an epic role-playing adventure like no other."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ni-no-kuni-ii-revenant-kingdom-prince-s-edition-nintendo-switch', 'Ni no Kuni II: Revenant Kingdom - Prince''s Edition', 'Ni no Kuni', '2021-09-17', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ahh.jpg', 'Lose yourself in the ultimate Ni no Kuni experience with this Prince''s edition including:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('night-in-the-woods-nintendo-switch', 'Night in the Woods', NULL, '2018-02-01', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fc4.jpg', 'Gather round the campfire and trace the constellations in Longest Night!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-master-collection-nintendo-switch', 'Ninja Gaiden: Master Collection', 'Ninja Gaiden', '2021-06-10', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpt5.jpg', 'The “Ninja Gaiden” series is respected and beloved across the entire gaming world, and has sold 6.8 million units in total.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nintendo-world-championships-nes-edition-nintendo-switch', 'Nintendo World Championships: NES Edition', NULL, '2024-07-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86hd.jpg', 'Test your speedrunning skills across more than 150 challenging moments from 13 classic NES games! Compete against players around the world online, challenge your friends on the couch, or try to see how far you can push your personal bests.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('travis-strikes-again-no-more-heroes-nintendo-switch', 'Travis Strikes Again: No More Heroes', 'No More Heroes', '2019-01-18', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tnf.jpg', 'Travis Strikes Again: No More Heroes is the third game in the No More Heroes series.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-nintendo-switch', 'No More Heroes', 'No More Heroes', '2020-10-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95vk.jpg', 'The Memory of the Hero campaign follows the story of helicopter pilot Sergey Pavlovich Borisov. Being an honored sniper and research helicopter pilot and a hero of the Soviet Union and Russia, this campaign explores his experiences in the Mi-8MTV2 and the Ka-50 Black Shark. The campaign is full of danger and exciting moments as you relive some of his more harrowing experiences!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-2-desperate-struggle-nintendo-switch', 'No More Heroes 2: Desperate Struggle', 'No More Heroes', '2020-10-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobp4c.jpg', 'No More Heroes 2: Desperate Struggle continues the tale of punk anti-hero Travis Touchdown, the Japanese anime Otaku, and pro wrestling-obsessed assassin. Travis finds himself at the bottom of the UAA (United Assassins Association) rankings and must wage war to become the No. 1 assassin once again. The follow-up to the popular No More Heroes will offer fans infectious, fun gameplay that allows you to wield not just one, but two swords and face multiple bosses simultaneously in bigger-than-ever boss battles.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-iii-nintendo-switch', 'No More Heroes III', 'No More Heroes', '2021-08-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co59gi.jpg', 'Witch and Hero 3 is an action game where you control the Witch, Hero and Little Hero at the same time. The two Heroes are physically strong and will keep fighting no matter how many times they''re beaten. The Witch, however, is vulnerable and even weaker in stone form; if she goes down the game is over. When the Heroes protect the Witch and fight they can collect monster''s blood from defeated enemies. When the Witch''s magic power is full she can temporarily be cured of the stone form and use magic to fight back against the dangerous enemies. Clear the stages by defeating the Boss enemies and seek revenge over the final Demon.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('octodad-dadliest-catch-nintendo-switch', 'Octodad: Dadliest Catch', NULL, '2017-11-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1szo.jpg', 'Octodad: Dadliest Catch is a game about destruction, deception, and fatherhood. The player controls Octodad, a dapper octopus masquerading as a human, as he goes about his life. Octodad''s existence is a constant struggle, as he must master mundane tasks with his unwieldy boneless tentacles while simultaneously keeping his cephalopodan nature a secret from his human family.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('octopath-traveler-nintendo-switch', 'Octopath Traveler', NULL, '2018-07-13', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa302.jpg', 'Two HD-2D RPGs from SQUARE ENIX’s Team Asano, OCTOPATH TRAVELER and OCTOPATH TRAVELER II are now available as a bundle! This series features distinctive HD-2D graphics that combine pixel art with 3D.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-stranger-s-wrath-nintendo-switch', 'Oddworld: Stranger''s Wrath', 'Oddworld', '2020-01-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gu1.jpg', 'Oddworld: Stranger''s Wrath is set in the fictional Oddworld universe, differing in many ways from the preceding installment. The game incorporates two basic genres: third-person platforming action and first-person shooter. The player can switch between the modes at any time by using a melee or a ranged weapon, respectively. The goal of the game, for the most part, is to bag the outlaws and bring them in, collecting "moolah" (the game''s currency) in the process. The Stranger can stun or knock down enemies, as well as use a stealthy approach, e.g. hiding in long grass to surprise the enemy.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-munch-s-oddysee-nintendo-switch', 'Oddworld: Munch''s Oddysee', 'Oddworld', '2020-05-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yni.jpg', 'Oddworld: Munch''s Oddysee is set in the fictional Oddworld universe and take place after those of Abe''s Exoddus. The player controls Munch as well as Abe, the hero of the previous Oddworld games. Abe''s abilities haven''t changed much since the last installment: as before, GameSpeak must be used to communicate with other creatures, leading them to safety. His fellow Mudokons can now be ordered to attack enemies. Abe can also grab and toss Mudokons or Munch to lead them to area they cannot access otherwise. Possessing enemies also comes into play, and is needed to solve many of the puzzles. Possession abilities can now be used to ignite quarrels between enemies and make them fight each other.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-new-n-tasty-nintendo-switch', 'Oddworld: New ''n'' Tasty!', 'Oddworld', '2020-10-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n69.jpg', 'Oddworld: New ''n'' Tasty is a faithful remake of Oddworld: Abe''s Oddysee where the pre-rendered sceneries are recreated in real-time 3D without changing the original gameplay. It also replaces the single screens linked together of the original version into a true 2.5D side-scrolling game. While there are various enhancements and details to the character and the scenery, the basic gameplay is still largely similar in a side by side comparison. The GameSpeak system Abe uses to command and talk to other characters start with the same commands, but can later be expanded. This version of the game supports leaderboards for the completion time of each mode and the overall game. There are three difficulty levels and the game. It includes the original cooperative function of the original game when another player can take over when the first player dies, taking turns controlling Abe.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-collection-nintendo-switch', 'Oddworld: Collection', 'Oddworld', '2021-04-05', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x6l.jpg', 'Oddworld: Collection is the oddest collection of all, and the complete Oddworld experience for Nintendo Switch!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-hd-nintendo-switch', 'Ōkami HD', 'Ōkami', '2018-08-09', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22s8.jpg', 'Experience the critically acclaimed masterpiece with its renowned Sumi-e ink art style in breathtaking high resolution. Take on the role of Amaterasu, the Japanese sun goddess who inhabits the form of a legendary white wolf, on a quest to defeat Orochi, an eight-headed demon and tyrannical monster responsible for turning the world of Nippon into a ruined wasteland.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('omori-nintendo-switch', 'Omori', NULL, '2022-06-17', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pgb.jpg', 'This is an Omori mod that was said to be AI generated to be appealing as possible to players.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ori-and-the-blind-forest-definitive-edition-nintendo-switch', 'Ori and the Blind Forest: Definitive Edition', 'Ori', '2019-09-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s0m.jpg', 'The forest of Nibel is dying. After a powerful storm sets a series of devastating events in motion, Ori must journey to find courage and confront a dark nemesis to save the forest of Nibel. “Ori and the Blind Forest” tells the tale of a young orphan destined for heroics, through a visually stunning Action-Platformer crafted by Moon Studios. Featuring hand-painted artwork, meticulously animated character performance, a fully orchestrated score and dozens of new features in the Definitive Edition, “Ori and the Blind Forest” explores a deeply emotional story about love and sacrifice, and the hope that exists in us all.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ori-and-the-will-of-the-wisps-nintendo-switch', 'Ori and the Will of the Wisps', 'Ori', '2020-09-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e1l.jpg', 'Ori and the Will of the Wisps is a platform-adventure game that combines exploration, traversal, and combat within an interconnected world. Designed in a Metroidvania style, it focuses on navigating varied environments, uncovering hidden areas, and acquiring abilities that expand movement and progression options.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ori-the-collection-nintendo-switch', 'Ori: The Collection', 'Ori', '2021-10-12', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6f0c.jpg', 'Play both award-winning games of Ori and the Blind Forest: Definitive Edition and Ori and the Will of the Wisps in this collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('outer-wilds-archaeologist-edition-nintendo-switch', 'Outer Wilds: Archaeologist Edition', 'Outer Wilds', '2023-12-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3yjh.jpg', 'Outer Wilds: Archaeologist Edition contains Outer Wilds base game and Echoes of the Eye expansion.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-outer-worlds-nintendo-switch', 'The Outer Worlds', NULL, '2020-06-05', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eew.jpg', 'The Outer Worlds is a new single-player sci-fi RPG from Obsidian Entertainment and Private Division. As you explore the furthest reaches of space and encounter a host of factions all vying for power, who you decide to become will determine the fate of everyone in Halcyon. In the corporate equation for the colony, you are the unplanned variable.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-special-edition-nintendo-switch', 'Overcooked! Special Edition', 'Overcooked!', '2018-02-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tj1.jpg', 'Get ready for the ultimate arcade-style couch cook-off in Overcooked: Special Edition for Nintendo Switch.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-2-nintendo-switch', 'Overcooked! 2', 'Overcooked!', '2018-08-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g3n.jpg', 'This bundle contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-special-edition-overcooked-2-nintendo-switch', 'Overcooked! Special Edition + Overcooked! 2', 'Overcooked!', '2019-11-19', 'Nintendo Switch', 0, 0, NULL, NULL, NULL, NULL, 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-all-you-can-eat-nintendo-switch', 'Overcooked! All You Can Eat', 'Overcooked!', '2021-03-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4969.jpg', 'Five new birthday themed levels, the new Tabby Cat chef, a recipe to make a cup of tea, and in-game Switcheroo mechanic where living playing cards stalk the levels transporting players across the kitchen, are all on the menu.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('owlboy-nintendo-switch', 'Owlboy', NULL, '2018-02-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaac.jpg', 'Owlboy is a platform/action-adventure video game created by Norwegian developer D-Pad Studio.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oxenfree-nintendo-switch', 'Oxenfree', NULL, '2017-10-06', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hlq.jpg', 'Oxenfree is a supernatural adventure game. Rites of passage and Senior year traditions set the stage for a group of friends sneaking off to Edwards Island, an old military outpost with no phone service. Players will take on the role of Alex as she brings her new stepbrother Jonas to an overnight party gone horribly wrong. Inspired by classic cult films like Stand by Me and Poltergeist, Oxenfree is an adventure that pulls from the past but looks to the present. “It’s a coming of age story where players control how their hero comes of age,” says Sean Krankel, co-founder of Night School. “We’re drawing on the fond and mortifying aspects of being in your late teens, and setting it against a dangerous and ghostly backdrop.”', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-nintendo-switch', 'Panzer Dragoon', 'Panzer Dragoon', '2020-03-26', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ixu.jpg', 'Panzer Dragoon II Zwei is an "on-rails" shoot ''em up game released exclusively for the Sega Saturn. It was the second Panzer Dragoon game released but it is a prequel of the series. It was developed by Team Andromeda, one of Sega''s internal development studios.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-the-thousand-year-door-nintendo-switch', 'Paper Mario: The Thousand-Year Door', 'Paper Mario', '2020-05-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25us.jpg', 'What sleeps behind the door?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('paper-mario-the-origami-king-nintendo-switch', 'Paper Mario: The Origami King', 'Paper Mario', '2020-07-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob89j.jpg', 'Join Mario and his new companion Olivia on a comedic adventure that will take you to the far corners of a papercraft world in Paper Mario: The Origami King on Nintendo Switch!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-pathless-nintendo-switch', 'The Pathless', NULL, '2023-02-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hm5.jpg', 'The Pathless is a mythic adventure where you play as the Hunter, a skilled archer who explores a mysterious cursed island with an eagle companion. Your goal is to lift an unnatural shroud of darkness that plagues the world. As you bound acrobatically through dense forests, you will hunt prey, discover ancient ruins, and form a deep bond with your eagle. But beware: dangerous spirits also lurk in the woods. If you aren''t careful, you may become the hunted yourself.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('penny-s-big-breakaway-nintendo-switch', 'Penny''s Big Breakaway', NULL, '2024-02-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nmg.jpg', 'Join Penny & Yo-Yo in a kinetic 3D-platformer bursting with innovative gameplay! Showcase your catalog of tricks and chain impressive combos to deliver Penny & Yo-Yo''s perfect breakout performance. Take the stage with this vibrant pair in Penny’s Big Breakaway.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pentiment-nintendo-switch', 'Pentiment', NULL, '2024-02-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v1e.jpg', 'A 16th-century narrative adventure set in Upper Bavaria, following Andreas Maler, a journeyman artist working in the bygone scriptorium of Kiersau Abbey during a time of great social unrest. While finishing his masterpiece, Andreas inadvertently becomes entangled in a series of murders that take place over 25 years. Peasants, thieves, craftsmen, monks, nuns, nobles, and even saints must be investigated and interrogated to expose the truth.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pepper-grinder-nintendo-switch', 'Pepper Grinder', NULL, '2024-03-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5rgd.jpg', 'Pepper Grinder is an action-packed pirate adventure starring the titular Pepper, a seafaring soul with a passion for prospecting, and Grinder, her super-powered drilling device.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-strikers-nintendo-switch', 'Persona 5 Strikers', 'Persona', '2021-02-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zoq.jpg', 'Persona 5 Strikers is a crossover between Koei Tecmo''s hack and slash Dynasty Warriors series and Atlus''s turn-based role-playing game Persona series. As a result, it features gameplay elements from both, such as the real-time action combat of the former with the turn-based Persona-battling aspect of the latter. The game is set six months after the events of Persona 5, and follows Joker and the rest of the Phantom Thieves of Hearts as they end up in a mysterious version of Tokyo filled with supernatural enemies.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-portable-nintendo-switch', 'Persona 3 Portable', 'Persona', '2023-01-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60ug.jpg', 'From the Midnight Channel to the Dark Hour, two iconic Persona titles return!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-golden-nintendo-switch', 'Persona 4 Golden', 'Persona', '2023-01-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1x.jpg', 'An enhanced rerelease of Shin Megami Tensei: Persona 4 (2008) featuring quality-of-life improvements, gameplay enhancements, new locations, balance tweaks, online functionality, new difficulty options, an additional side character storyline and a changed endgame.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pico-park-1-2-nintendo-switch', 'Pico Park 1 + 2', NULL, '2024-11-28', 'Nintendo Switch', 1, 0, NULL, NULL, NULL, NULL, 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-3-deluxe-nintendo-switch', 'Pikmin 3 Deluxe', 'Pikmin', '2020-10-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8grk.jpg', 'Prepare yourselves, brave explorers, and set-off for the lush planet PNF-404!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-4-nintendo-switch', 'Pikmin 4', 'Pikmin', '2023-07-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba9h.jpg', 'Meet Pikmin, small, plantlike creatures you can grow, pluck, command, and overpower your enemies with! These curious helpers come in different types—fire is no sweat for Red Pikmin and the brand-new Ice Pikmin can freeze enemies and the environment. Use your Pikmin’s miniature might (and a bit of strategy) to explore this mysterious planet.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pikmin-1-2-nintendo-switch', 'Pikmin 1+2', 'Pikmin', '2023-09-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nm6.jpg', 'Revisit the first two Pikmin games on the Nintendo Switch system!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pizza-tower-nintendo-switch', 'Pizza Tower', NULL, '2024-08-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8m9k.jpg', 'Aiming to replace every major character AND boss with beloved characters from Spindlehorse''s Helluva Boss and Hazbin Hotel (mostly Helluva). Featuring Moxxie in the place of Peppino trying to save I.M.P along with Millie and that hellhound no one cares about.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-battle-for-neighborville-complete-edition-nintendo-switch', 'Plants vs. Zombies: Battle for Neighborville Complete Edition', 'Plants vs. Zombies', '2021-03-19', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2usr.jpg', 'Tackle hilarious missions and defeat epic bosses in the Weirding Woods, Mount Steep, and Neighborville Town Center to collect medals and unlock outrageous outfits. Party with up to three friends and goof around in Giddy Park or dive into some 8v8 multiplayer in Turf Takeover, vanquishing opponents, blasting gnome bombs, bouncing on pink ooze – it’s the most fun you’ll have since sliced bread.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-plucky-squire-nintendo-switch', 'The Plucky Squire', NULL, '2024-09-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6z44.jpg', 'Storybook characters discover a three-dimensional world outside the pages of their book and must jump between 2D & 3D realms to save their friends in this charming action-adventure.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pokk-n-tournament-dx-nintendo-switch', 'Pokkén Tournament DX', 'Pokémon', '2017-09-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zji.jpg', 'Pokkén Tournament is a fighting video game and the first Pokémon title for the Nintendo Switch console. Take direct control of one of 21 prized Pokémon fighters to defeat other Pokémon in arena fights. Call upon Support Pokémon to assist in the fight, then unleash your Pokémon''s unique Burst Attack to climb atop the ranks. With all new modes and new ways to battle with friends, this is your chance to become champion of the Ferrum Region!', NULL, 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-let-s-go-pikachu-nintendo-switch', 'Pokémon: Let''s Go, Pikachu!', 'Pokémon', '2018-11-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zjy.jpg', 'Take your Pokémon journey to the Kanto region with your energetic partner, Pikachu, to become a top Pokémon Trainer as you battle other trainers. Use a throwing motion to catch Pokémon in the wild with either one Joy-Con controller or Poké Ball Plus accessory, which will light up, vibrate, and make sounds to bring your adventure to life. Share your adventure with family or friends in 2-player action on one system using a second Joy-Con or Poké Ball Plus (sold separately). You can even connect to the Pokémon GO app using a compatible smartphone to bring over Pokémon originally discovered in the Kanto region! Explore the diverse and vibrant region of Kanto! True-to-size wild Pokémon roam around in the game, so catch them like a real Pokémon Trainer by using motion, timing, and a well-placed Poké Ball. Go on a stroll with your favorite Pokémon in your Poké Ball Plus! Connect your game directly to Pokémon GO* to receive Kanto region Pokémon.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-let-s-go-eevee-nintendo-switch', 'Pokémon: Let''s Go, Eevee!', 'Pokémon', '2018-11-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ivp.jpg', 'The definitive demake, new Galar Pokémon and without the limitation of the original 150, enjoy Kanto again with this hack rom by Kevin Pokefan, capture and become the best with your faithful Eevee, now in GBA.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-sword-nintendo-switch', 'Pokémon Sword', 'Pokémon', '2019-11-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lj2.jpg', 'Become a Pokémon Trainer, embark on a new journey in the new Galar region, and unravel the mystery behind the Legendary Pokémon Zacian and Zamazenta! Explore the Wild Area, a vast expanse of land where the player can freely control the camera. And participate in Max Raid Battles in which players will face off against gigantic and super-strong Pokémon known as Dynamax Pokémon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-shield-nintendo-switch', 'Pokémon Shield', 'Pokémon', '2019-11-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zk1.jpg', 'Unsheathe your sword and take up your shield!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-mystery-dungeon-rescue-team-dx-nintendo-switch', 'Pokémon Mystery Dungeon: Rescue Team DX', 'Pokémon', '2020-03-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcnl.jpg', 'You can meet and recruit Pokémon in a dungeon-crawling adventure within their world! Build a rescue team to take on mysterious, changing dungeons and strategically plan your moves as you venture forth to make the Pokémon world a safer place…and uncover your true purpose along the way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-sword-pok-mon-sword-expansion-pass-nintendo-switch', 'Pokémon Sword + Pokémon Sword Expansion Pass', 'Pokémon', '2020-11-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wdv.jpg', 'Continue your Pokémon Sword adventure in The Isle of Armor and The Crown Tundra, two new areas to explore that will be added to the Galar region as part of the Pokémon Sword Expansion Pass! Each area offers a different adventure, where you’ll be able to visit the far reaches of the Galar region and meet the people and Pokémon that live there. You’ll also see some familiar Pokémon that didn’t appear in the Galar region before, a total of over 200 Pokémon. If you buy the Pokémon Sword Expansion Pass, you’ll be able to enjoy both The Isle of Armor and The Crown Tundra as they’re released!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-shield-pok-mon-shield-expansion-pass-nintendo-switch', 'Pokémon Shield + Pokémon Shield Expansion Pass', 'Pokémon', '2020-11-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wdx.jpg', 'Continue your Pokémon Shield adventure in The Isle of Armor and The Crown Tundra, two new areas to explore that will be added to the Galar region as part of the Pokémon Shield Expansion Pass! Each area offers a different adventure, where you’ll be able to visit the far reaches of the Galar region and meet the people and Pokémon that live there. You’ll also see some familiar Pokémon that didn’t appear in the Galar region before, a total of over 200 Pokémon. If you buy the Pokémon Shield Expansion Pass, you’ll be able to enjoy both The Isle of Armor and The Crown Tundra as they’re released!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-pok-mon-snap-nintendo-switch', 'New Pokémon Snap', 'Pokémon', '2021-04-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oil.jpg', 'New Pokémon Snap is an on-rails first-person photography game developed by Bandai Namco Studios and published by Nintendo and The Pokémon Company for the Nintendo Switch. It is a sequel to the 1999 Nintendo 64 game Pokémon Snap. Players explore an archipelago in an autopilot hovercraft and photograph Pokémon in order to conduct research about their ecology.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-brilliant-diamond-nintendo-switch', 'Pokémon Brilliant Diamond', 'Pokémon', '2021-11-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b9t.jpg', 'Revisit the Sinnoh region and the story of the Pokémon Diamond Version game
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-shining-pearl-nintendo-switch', 'Pokémon Shining Pearl', 'Pokémon', '2021-11-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b9s.jpg', 'Revisit the Sinnoh region and the story of the Pokémon Pearl Version game
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-legends-arceus-nintendo-switch', 'Pokémon Legends: Arceus', 'Pokémon', '2022-01-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3d03.jpg', 'The Pokémon Legends: Arceus game honors past Pokémon games’ core gameplay while infusing new action and RPG elements.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-scarlet-nintendo-switch', 'Pokémon Scarlet', 'Pokémon', '2022-11-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5sfi.jpg', 'The Pokémon Scarlet and Pokémon Violet games, the newest chapters in the Pokémon series, are coming to Nintendo Switch later this year. With these new titles, the Pokémon series takes a new evolutionary step, allowing you to explore freely in a richly expressed open world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-violet-nintendo-switch', 'Pokémon Violet', 'Pokémon', '2022-11-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5sfa.jpg', 'Catch, battle, and train Pokémon in the Paldea Region, a vast land filled with lakes, towering peaks, wastelands, small towns, and sprawling cities. Explore a wide-open world at your own pace and traverse land, water, and air by riding on a form-shifting Legendary Pokémon. Choose either Sprigatito, Fuecoco, or Quaxly, to be your first partner Pokémon before setting off on your journey through Paldea.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('detective-pikachu-returns-nintendo-switch', 'Detective Pikachu Returns', 'Pokémon', '2023-10-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb07.jpg', 'Solve mysteries with the personality-packed Detective Pikachu!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-scarlet-the-hidden-treasure-of-area-zero-nintendo-switch', 'Pokémon Scarlet + The Hidden Treasure of Area Zero', 'Pokémon', '2023-11-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67iv.jpg', 'A two-part story expansion for Pokémon Scarlet.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-violet-the-hidden-treasure-of-area-zero-nintendo-switch', 'Pokémon Violet + The Hidden Treasure of Area Zero', 'Pokémon', '2023-11-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67it.jpg', 'A two-part story expansion for Pokémon Violet.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-legends-z-a-nintendo-switch', 'Pokémon Legends: Z-A', 'Pokémon', '2025-10-16', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wzc.jpg', 'A new adventure awaits within Lumiose City, where an urban redevelopment plan is underway to shape the city into a place that belongs to both people and Pokémon. Please look forward to seeing it for yourself.​​', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-lost-crown-nintendo-switch', 'Prince of Persia: The Lost Crown', 'Prince of Persia', '2024-01-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coafpt.jpg', 'A Two Thrones Dark Prince–inspired skin for Sargon.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('princess-peach-showtime-nintendo-switch', 'Princess Peach: Showtime!', 'Princess Peach', '2024-03-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaup.jpg', 'The wicked Grape and the Sour Bunch have taken over the Sparkle Theater, and now it''s up to Peach and the theater''s guardian Stella to save the play––and the day!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pumpkin-jack-nintendo-switch', 'Pumpkin Jack', NULL, '2020-10-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3r4x.jpg', 'Pumpkin Jack is a Spooky Scary 3D platformer in which you embody Jack, the Mythical Pumpkin Lord! Dive into an Epic Adventure through otherworldly landscapes and help the Evil annihilate the Good!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-champions-nintendo-switch', 'Puyo Puyo Champions', 'Puyo Puyo', '2019-05-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u59.jpg', 'Easy to learn, tough to master! Jump straight into fast-paced puzzle action with features fit for both friendly rivalries and competitive tournaments in Puyo Puyo Champions. Challenge your friends and family in local multiplayer or compete against players from around the world through online matchmaking. Built for all ages, this classic puzzle game comes with a surprisingly competitive edge.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-nintendo-switch', 'Puyo Puyo Tetris', 'Puyo Puyo Tetris', '2017-04-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3vws.jpg', '"Two puzzle game juggernauts collide as Tetris, one of the largest-selling and recognized brands in gaming history, and Puyo Puyo from SEGA have combined to create a fun-to-play, fast-paced, competitive party game like no other! The game has tons of different styles of gameplay – from the single-player Adventure and Challenge modes to the ferocious competition of the up-to-four player Arcade modes. There''s plenty of Tetris/Puyo variety, even an in-game Shop where players can unlock new characters, new skins for Puyos and Tetriminos, new backgrounds and more."', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-2-nintendo-switch', 'Puyo Puyo Tetris 2', 'Puyo Puyo Tetris', '2020-12-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3246.jpg', 'Stack, chain, and combo your way to victory in the ultimate matching of two puzzle game legends! Pre-order now and get ready to traverse dimensions and experience brand new worlds in time for the holidays, with the PC release fast-dropping onto Steam in early 2021.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-nintendo-switch', 'Quake', 'Quake', '2021-08-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-nintendo-switch', 'Quake II', 'Quake', '2023-08-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rain-world-nintendo-switch', 'Rain World', NULL, '2018-12-13', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24pm.jpg', 'Rain World is a survival platformer set in an abandoned industrial environment ravaged by a shattered ecosystem. Bone-crushingly intense rains pound the surface, making life as we know it almost impossible. The creatures in this world hibernate most of the time, but in the few brief dry periods they go out in search of food.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-definitive-edition-nintendo-switch', 'Rayman Legends Definitive Edition', 'Rayman', '2017-09-12', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3m8e.jpg', 'Rayman Legends takes full advantage of the Nintendo Switch and its new controllers capabilities. Undock your Switch device and use the touch screen to take out enemies, manipulate platforms, cut ropes to clear a path and much more. With the gyroscope technology, you can move rotating platform and there are many more surprises to come!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-collection-nintendo-switch', 'Resident Evil: Revelations Collection', 'Resident Evil', '2017-11-27', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wyt.jpg', 'A bundle containing Resident Evil Revelations on a game card and download codes for the Resident Evil Revelations 2 episodes. Includes all previously released DLC for the games.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-origins-collection-nintendo-switch', 'Resident Evil Origins Collection', 'Resident Evil', '2019-05-21', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnx.jpg', 'Experience the early days of the outbreak in Resident Evil Origins Collection, a compilation package of two with two Resident Evil origin stories: Resident Evil 0 and Resident Evil HD . Both terrifying games have been brought to new new levels of horror with new HD visuals, improved sound, widescreen support, an optional modernized control system and more.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-triple-pack-nintendo-switch', 'Resident Evil Triple Pack', 'Resident Evil', '2019-10-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nbb.jpg', 'Enjoy three of the most memorable and defining survival horror titles in all of gaming with Resident Evil 4, Resident Evil 5 and Resident Evil 6, coming to the you in one amazing value pack.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('retro-city-rampage-dx-nintendo-switch', 'Retro City Rampage DX', 'Retro City Rampage', '2017-08-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h4u.jpg', 'Open-world carjacking goes back to the ''80s in this 8-BIT nostalgic throwback.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-nintendo-switch', 'Shakedown: Hawaii', 'Retro City Rampage', '2019-05-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-of-the-obra-dinn-nintendo-switch', 'Return of the Obra Dinn', NULL, '2019-10-18', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27j9.jpg', 'In this 1-bit first-person mystery game, a merchant ship called the Obra Dinn has appeared at a London harbor, years after being declared lost at sea. As an insurance adjuster, the player must examine the ship for clues.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rime-nintendo-switch', 'Rime', NULL, '2017-11-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co84t0.jpg', 'You stumble across an old book and get trapped within its world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ring-fit-adventure-nintendo-switch', 'Ring Fit Adventure', NULL, '2019-10-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcnq.jpg', 'In this fitness-focused title, you''ll be moving the ring and a leg strap -- both of which house a Switch Joy-Con -- to move your character through a fantasy world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rocket-knight-adventures-re-sparked-nintendo-switch', 'Rocket Knight Adventures: Re-Sparked', 'Rocket Knight', '2024-06-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7na9.jpg', 'The mightiest mammal to ever rocket to stardom is back in a three-game, Carbon Engine-powered collection that includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rogue-legacy-nintendo-switch', 'Rogue Legacy', NULL, '2018-11-06', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27fi.jpg', 'You control a family of characters one at a time, and when your character dies, you choose who his or her successor is, whether it is a barbarian son of yours who has OCD, your daughter who became a ninja even though she can''t see well, an assassin who is fighting for the gays, or a miner who wants to collect gold! Traits are randomized each time upon death, leading to multiple playthroughs with 35 traits, each character will be unique.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rogue-legacy-2-nintendo-switch', 'Rogue Legacy 2', 'Rogue Legacy', '2022-11-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4p51.jpg', 'Rogue Legacy is back! But now it''s got a 2 on the end of it!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rollercoaster-tycoon-adventures-nintendo-switch', 'RollerCoaster Tycoon Adventures', 'RollerCoaster Tycoon', '2018-12-13', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kaq.jpg', 'RollerCoaster Tycoon Adventures brings the RollerCoaster series into the next generation - combining classic RTC gameplay with the modernized user experience from the mobile game RollerCoaster Tycoon Touch. The game also has unique features that fits on Nintendo Switch!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rollercoaster-tycoon-3-complete-edition-nintendo-switch', 'RollerCoaster Tycoon 3: Complete Edition', 'RollerCoaster Tycoon', '2020-09-24', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g2g.jpg', 'Build the park of a lifetime and rediscover the critically acclaimed rollercoaster simulation bestseller. Feel the thrill of a genre-defining classic, complete with two huge expansion packs.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-4-special-nintendo-switch', 'Rune Factory 4 Special', 'Rune Factory', '2020-02-25', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co40eo.jpg', 'Rune Factory 4 Special is an enhanced version of the original fantasy farming RPG, combining life simulation with dungeon exploration. Players manage a farm, build relationships, battle monsters, and uncover a larger story. This edition includes improved visuals, voice acting, and a new Newlywed Mode, which features additional story content focused on married life with each character.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('salt-and-sanctuary-nintendo-switch', 'Salt and Sanctuary', 'Salt', '2018-08-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwoj.jpg', 'Salt and Sanctuary is a 2D action role-playing game developed by Ska Studios and released in 2016. It combines side-scrolling combat with mechanics inspired by action RPGs, including stamina management and character builds. Players explore a dark, interconnected world filled with hostile enemies and challenging bosses.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('salt-and-sacrifice-nintendo-switch', 'Salt and Sacrifice', 'Salt', '2023-11-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwoi.jpg', 'Salt and Sacrifice is a 2D action role-playing game developed by Ska Studios and released in 2022. It serves as a follow-up to Salt and Sanctuary, introducing a more open, hunt-focused structure. Players take on the role of a Marked Inquisitor tasked with tracking and defeating powerful mages across interconnected regions.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sayonara-wild-hearts-nintendo-switch', 'Sayonara Wild Hearts', NULL, '2019-09-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gx1.jpg', 'Sayonara Wild Hearts is a euphoric music video dream about being awesome, riding motorcycles, skateboarding, dance battling, shooting lasers, wielding swords, and breaking hearts at 200 mph.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-showdown-nintendo-switch', 'Scribblenauts Showdown', 'Scribblenauts', '2018-03-06', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co272u.jpg', 'It’s Scribblenauts, party-style! Use your imagination and go head-to-head in the ultimate multiplayer showdown! Enjoy a party-style Scribblenauts experience, conjuring from over 35,000 objects from the vast Scribblenauts dictionary to outsmart your opponent in over 25 mini-games.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-mega-pack-nintendo-switch', 'Scribblenauts Mega Pack', 'Scribblenauts', '2018-09-18', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/du7bf613i5hyjwbto3rj.jpg', 'Get the best of Scribblenauts with Scribblenauts Mega Pack! Two classic games with ALL-NEW content to explore!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sea-of-solitude-the-director-s-cut-nintendo-switch', 'Sea of Solitude: The Director''s Cut', 'Sea of Solitude', '2021-03-04', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mgi.jpg', 'Adventure through a beautiful and troubling world where nothing is as it seems, to confront and conquer your fears.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sea-of-stars-nintendo-switch', 'Sea of Stars', NULL, '2023-08-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6mru.jpg', 'A one-touch mobile game featuring underwater creatures.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-genesis-classics-nintendo-switch', 'Sega Genesis Classics', NULL, '2018-12-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sm8.jpg', 'The collection has over 50 retro classics to experience across every genre; arcade action, shooters, beat’em ups, puzzlers, old favourites and hidden gems, with a raft of modern features. These include online multiplayer, achievements, mirror modes, rewind and save states meaning players old and new should find revisiting these great games an absolute Sonic 3D Blast.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('severed-nintendo-switch', 'Severed', NULL, '2017-08-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8xkj.jpg', NULL, 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-pirate-s-curse-nintendo-switch', 'Shantae and the Pirate''s Curse', 'Shantae', '2018-03-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b1u.jpg', 'Embark on a brand new adventure with Shantae, the hair-whipping belly dancing genie. When she loses her magic, Shantae must team up with her nemesis, the nefarious pirate Risky Boots in order to save Sequin Land from an evil curse. As a pirate, Shantae gains new weapons to advance her quest, slay monsters, battle epic bosses…and hopefully get her magic back in the bargain! But can she really trust her deadliest enemy?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-half-genie-hero-ultimate-edition-nintendo-switch', 'Shantae: Half-Genie Hero Ultimate Edition', 'Shantae', '2018-04-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rka.jpg', 'The ultimate edition of Shantae: Half-Genie Hero comes with all of the previously released DLC, Modes, and Costumes in one epic collection! Includes an exclusive Blue Bathing Suit for use in Beach Mode!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-seven-sirens-nintendo-switch', 'Shantae and the Seven Sirens', 'Shantae', '2020-05-28', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7csj.jpg', 'Formerly referred to as Shantae 5, Shantae and the Seven Sirens sends the belly-dancing, hair-whipping, half-genie hero to a tropical island where Shantae and her friends encounter other Half-Genie allies, but they soon learn there’s trouble in paradise. As Shantae gets caught up in the island’s sinister secrets, she’ll use all-new dance abilities and instant-transformation Fusion Magic to explore the nonlinear, interconnected world where she’ll visit multiple towns, overcome treacherous labyrinths, and battle dastardly bosses. The game also features a new collectible card system that grants players the freedom to augment Shantae’s powers to suit their own style of play.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-risky-s-revenge-director-s-cut-nintendo-switch', 'Shantae: Risky''s Revenge - Director''s Cut', 'Shantae', '2020-10-15', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49xa.jpg', 'Shantae: Risky’s Revenge – Director’s Cut brings hair-whipping, belly-dancing to your PC! Play one of the most critically acclaimed handheld series of all time, now with brand new features!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-nintendo-switch', 'Shantae', 'Shantae', '2021-04-22', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27l6.jpg', 'Genie-girl Shantae is the self-appointed guardian of a small fishing village, Scuttle Town. Living life in a lighthouse rather than a bottle, she''s constantly on the lookout for danger. When the nefarious lady-pirate, Risky Boots catches wind of the treasure that was recently unearthed in the village, she launches an attack. To get Scuttle out of trouble, it''s up to Shantae to prove that she''s the rightful ''Guardian Genie'' to the best of her dancing, buying and hair-whipping abilities. Now crack that whip!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-advance-risky-revolution-nintendo-switch', 'Shantae Advance: Risky Revolution', 'Shantae', '2025-08-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaboc.jpg', 'Shantae is back in an adventure 20 years in the making! The nefarious pirate Risky Boots has a “groundbreaking” new plan that will leave Sequin Land spinning — by rotating the continent, she can move any town right to the coast for easy plundering! As Shantae, turn the tectonic tables on Risky by taking control of the land itself: shift, twist, navigate, and explore by swapping between mix-and-match multilayered levels! Hair-whip and belly-dance your way through scrambled lands, misplaced towns, monster-filled crypts, and daunting labyrinths. Six creature transformations, fierce boss battles, and a 4-player versus mode await!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shinobi-art-of-vengeance-nintendo-switch', 'Shinobi: Art of Vengeance', 'Shinobi', '2025-08-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9e1j.jpg', 'Slay the enemies in the silence of the moment. Run through the world of Shinobi full of monsters and ninja actions. Grab Oborozuki, the legendary sword, and slay evil once more. Your clan and the world are counting on you.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-treasure-trove-nintendo-switch', 'Shovel Knight: Treasure Trove', 'Shovel Knight', '2019-12-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gsx.jpg', 'Shovel Knight: Treasure Trove is the full and complete edition of Shovel Knight, a sweeping classic action-adventure game series with awesome gameplay, memorable characters, and an 8-bit retro aesthetic! Run, jump, and battle as Shovel Knight, wielder of the Shovel Blade, in a quest for his lost beloved. Take down the nefarious knights of the Order of No Quarter and confront their menacing leader, The Enchantress.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('signalis-nintendo-switch', 'Signalis', NULL, '2022-10-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ig.jpg', 'Signalis is a classic survival horror experience with a unique aesthetic, full of melancholic mystery. Investigate a dark secret, solve puzzles, fight off nightmarish creatures and navigate dystopian, surreal retrotech worlds as Elster, a technician Replika searching for her lost dreams.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-nintendo-switch', 'Skylanders: Imaginators', 'Skylanders', '2017-03-03', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('slime-rancher-plortable-edition-nintendo-switch', 'Slime Rancher: Plortable Edition', 'Slime Rancher', '2021-08-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yk9.jpg', 'Slime Rancher is a charming, first-person, sandbox experience. Play as Beatrix LeBeau: a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ‘Far, Far Range.’ Each day will present new challenges and risky opportunities as you attempt to amass a great fortune in the business of slime ranching. Collect colourful slimes, grow crops, harvest resources, and explore the untamed wilds through the mastery of your all-purpose vacpack.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('snipperclips-plus-cut-it-out-together-nintendo-switch', 'Snipperclips Plus: Cut It Out, Together!', NULL, '2017-11-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7por.jpg', 'Paper pals Snip and Clip must cut each other into the right shapes to overcome tricky obstacles in this updated version of the game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-forces-nintendo-switch', 'Sonic Forces', 'Sonic the Hedgehog', '2017-11-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zr8.jpg', 'Fight through a world destroyed by Dr. Eggman and a powerful new villain in Sonic Forces, the new fast-paced action platformer from the team that brought you Sonic Colors and Sonic Generations. Sonic Forces lets you speed through rolling ruined landscapes as Modern Sonic, catapult past perilous platforms as Classic Sonic, and use powerful new gadgets as your own Custom Hero Character.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-plus-nintendo-switch', 'Sonic Mania Plus', 'Sonic the Hedgehog', '2018-07-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wqj.jpg', 'Experience Classic and Modern Sonic in two great games -- speed through rolling landscapes in all-new 2D adventures in Sonic Mania Plus, and create your own character to take back the world from the evil Dr. Eggman in the 3D adventure, Sonic Forces!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('team-sonic-racing-nintendo-switch', 'Team Sonic Racing', 'Sonic the Hedgehog', '2019-05-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1upm.jpg', 'Team Sonic Racing combines the best elements of arcade and fast-paced competitive style racing as you face-off with friends in intense multiplayer racing.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-nintendo-switch', 'Sonic Mania', 'Sonic the Hedgehog', '2019-11-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8uho.jpg', 'Sonic Mania and Sonic PLUS is a complete overhaul of Sonic Mania and its DLC:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-colors-ultimate-nintendo-switch', 'Sonic Colors: Ultimate', 'Sonic the Hedgehog', '2021-09-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31a0.jpg', 'Join Sonic in the high-speed adventure of a lifetime across a colorful interstellar amusement park. Color the Universe in Sonic Colors: Ultimate!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-frontiers-nintendo-switch', 'Sonic Frontiers', 'Sonic the Hedgehog', '2022-11-08', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p52.jpg', 'Worlds will collide in Sonic the Hedgehog’s newest adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-origins-plus-nintendo-switch', 'Sonic Origins Plus', 'Sonic the Hedgehog', '2023-06-23', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6oez.jpg', 'Sonic Origins Plus is an updated version of Sonic Origins that includes the Plus Expansion Pack. Unlike Sonic Mania Plus, Sonic Origins Plus can be bought digitally on PC as a single purchase like the console versions, while the base game continues to be available on it''s own. Digital versions of Sonic Origins on all platforms can be upgraded to Plus by purchasing the Plus Expansion Pack separately.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-superstars-nintendo-switch', 'Sonic Superstars', 'Sonic the Hedgehog', '2023-10-17', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbw4.jpg', 'Adventure through the mystical Northstar Islands in this all-new take on classic 2D Sonic high-speed action platforming. Play as Sonic, Tails, Knuckles, and Amy Rose and harness all-new Emerald powers to move and attack in dynamic new ways. Navigate gorgeous, never-before-seen environments solo or with up to 3 other players and stop Dr. Eggman, Fang, and a mysterious new adversary from converting the islands'' giant animals into Badniks before it''s too late!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-space-for-the-unbound-nintendo-switch', 'A Space for the Unbound', NULL, '2023-01-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62kn.jpg', 'A coming-of-age adventure where you follow two high school sweethearts on a journey of self-discovery at the end of their high school years while facing the end of the world. Explore 90s Indonesian town, uncover its secrets, use supernatural powers to dive into people''s hearts, and pet cats.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-forever-nintendo-switch', 'Space Invaders Forever', 'Space Invaders', '2020-12-15', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kx6.jpg', 'Back again - arcade legend and icon of gaming history! Lighting the fuse for a gaming revolution. Space Invaders is surely one of the most famous video games of all time and was the launching pad for the video gaming revolution. The game mechanics and its design make it a game that encompasses all the very best.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spiritfarer-nintendo-switch', 'Spiritfarer', NULL, '2020-08-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fe7.jpg', 'Spiritfarer is a cozy management game about dying. You play Stella, ferrymaster to the deceased, a Spiritfarer. Build a boat to explore the world, then befriend and care for spirits before finally releasing them into the afterlife. Farm, mine, fish, harvest, cook, and craft your way across mystical seas. Join the adventure as Daffodil the cat, in two-player cooperative play. Spend relaxing quality time with your spirit passengers, create lasting memories, and, ultimately, learn how to say goodbye to your cherished friends. What will you leave behind?', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('splatoon-2-nintendo-switch', 'Splatoon 2', 'Splatoon', '2017-07-21', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8g6r.jpg', 'The squid kids called Inklings are back to splat more ink and claim more turf in this colorful and chaotic 4-on-4* action shooter. Take Turf War battles on-the-go with the Nintendo Switch system, and use any of the console’s portable play styles for intense local multiplayer* action. Even team up for 4-player co-op fun in Salmon Run! Purchase this bundle to own both Splatoon 2 and the large-scale Octo Expansion DLC.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('splatoon-3-nintendo-switch', 'Splatoon 3', 'Splatoon', '2022-09-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co59x3.jpg', 'Enter the Splatlands, a sun-scorched desert inhabited by battle-hardened Inklings and Octolings. Splatsville, the city of chaos, is the adrenaline-fueled heart of this dusty wasteland. Even in this desolate environment, Turf War reigns supreme and battles rage in new stages located in the surrounding wilds. Dynamic new moves help these fighters dodge attacks and cover more ground, along with a new bow-shaped weapon to sling ink.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-reignited-trilogy-nintendo-switch', 'Spyro Reignited Trilogy', 'Spyro', '2019-09-03', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaat.jpg', 'Spyro Reignited Trilogy is a collection of remasters of the first three games in the Spyro series: Spyro the Dragon (1998), Ripto''s Rage! (1999), and Year of the Dragon (2000).', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-stanley-parable-ultra-deluxe-nintendo-switch', 'The Stanley Parable: Ultra Deluxe', 'The Stanley Parable', '2022-04-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4p71.jpg', 'The Stanley Parable: Ultra Deluxe is an expanded re-imagining of 2013''s The Stanley Parable. You will play as Stanley, and you will not play as Stanley. You will make a choice, and you will become powerless. You are not here to win. The Stanley Parable is a game that plays you.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-ii-jedi-outcast-nintendo-switch', 'Star Wars Jedi Knight II: Jedi Outcast', 'Star Wars', '2019-09-24', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y67.jpg', 'In the tradition of the highly acclaimed Star Wars: Jedi Knight series, Star Wars: Jedi Knight 2, Jedi Outcast features rebel agent Kyle Katarn in exhilarating first-person action. Several years have passed since Kyle avenged his father''s death and saved the Valley of the Jedi from Jerec and his band of Dark Jedi. Allowing his Force powers to languish for fear of falling to the dark side, Kyle entrusted his lightsaber to Luke Skywalker, vowing never to use it again. But when a new and menacing threat to the galaxy emerges, Kyle knows he must reclaim his past in order to save his future.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-jedi-academy-nintendo-switch', 'Star Wars Jedi Knight: Jedi Academy', 'Star Wars', '2020-03-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5c44.jpg', 'Star Wars: Jedi Knight: Jedi Academy, of the highly acclaimed Jedi Knight series, allows players to take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker. Interact with famous Star Wars characters in many classic Star Wars locations as you face the ultimate choice: fight for good and freedom on the light side, or follow the path of power and evil to the dark side.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-racer-nintendo-switch', 'Star Wars Episode I: Racer', 'Star Wars', '2020-06-23', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wj7.jpg', 'Star Wars: Episode 1 - Racer lets you participate in the famous pod race sequence that was the critical highlight of the film Star Wars: Episode I, The Phantom Menace back in 1999.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-republic-commando-nintendo-switch', 'Star Wars: Republic Commando', 'Star Wars', '2021-04-06', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2au4.jpg', 'Chaos has erupted throughout the galaxy. As a leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihalate the enemy. Your squad will follow your orders and your lead, working together as a team-instinctively, intelligently, instantly. You are their leader. They are your weapon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-knights-of-the-old-republic-nintendo-switch', 'Star Wars: Knights of the Old Republic', 'Star Wars', '2021-11-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tmz.jpg', 'Choose Your Path! Set 4,000 years before the Galactic Empire, you are the last hope for the Jedi Order and the Republic - can you master the ways of the Force to become their savior? Or will you fall to the dark side and achieve ultimate power? Hero, villain, peacekeeper, or chaos-bringer... you and your party will determine the fate of the galaxy!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-nintendo-switch', 'Star Wars: The Force Unleashed', 'Star Wars', '2022-04-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-knights-of-the-old-republic-ii-the-sith-lords-nintendo-switch', 'Star Wars Knights of the Old Republic II: The Sith Lords', 'Star Wars', '2022-06-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrj.jpg', 'Star Wars Knights of the Old Republic II: The Sith Lords is a sequel to the blockbuster RPG Star Wars Knights of the Old Republic. Players continue to enjoy the title''s emotionally compelling and story-driven theme, additions to features such as new characters, classes, locations and force powers as well as a deeper look into the founding lore.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stardew-valley-nintendo-switch', 'Stardew Valley', NULL, '2017-10-05', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa93h.jpg', 'Stardew Valley is an open-ended country-life RPG! You’ve inherited your grandfather’s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home? It won’t be easy. Ever since Joja Corporation came to town, the old ways of life have all but disappeared. The community center, once the town’s most vibrant hub of activity, now lies in shambles. But the valley seems full of opportunity. With a little dedication, you might just be the one to restore Stardew Valley to greatness!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('starlink-battle-for-atlas-nintendo-switch', 'Starlink: Battle for Atlas', NULL, '2018-10-16', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pm8.jpg', 'Starlink: Battle for Atlas is an all-new action-adventure game developed by Ubisoft Toronto. This deep, open-world space saga features Smart Building Technology empowering players to assemble and customize real-world physical starships. Each part attached to the starship appears instantly in-game and players can experiment with different pilot abilities, weapon types, and status effects and unleash devastating combos upon their enemies.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('story-of-seasons-friends-of-mineral-town-nintendo-switch', 'Story of Seasons: Friends of Mineral Town', 'Story of Seasons', '2020-07-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mij.jpg', 'A remake combining the content of the Game Boy Advance games, Harvest Moon: Friends of Mineral Town and Harvest Moon: More Friends of Mineral Town, for the Nintendo Switch.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('story-of-seasons-pioneers-of-olive-town-nintendo-switch', 'Story of Seasons: Pioneers of Olive Town', 'Story of Seasons', '2021-03-23', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kjz.jpg', 'The long-awaited brand new entry in the original farm/life simulation franchise, known in Japan as Bokujo Monogatari, makes its debut on Nintendo Switch, bringing players more freedom than ever before to shape an untamed wilderness and customize their farm down to the very tile. A new cast of marriage candidates, a town that grows and thrives along with your farm, and a request system highlight the new features, all while retaining the core elements of the STORY OF SEASONS series. Finding Earth Sprites while exploring your farmland may lead you to mysterious, fantastical lands such as gardens where the seasons never change, an island in the sky, or even the inside of a volcano!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stray-nintendo-switch', 'Stray', NULL, '2024-11-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaa4c.jpg', 'A fantasy tactical RPG where you command over 70 characters across grid-based battles. Customize skills, unleash flashy Spell Cards, and enjoy rich animations in a strategic, story-driven adventure set in the world of Touhou.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('subnautica-subnautica-below-zero-nintendo-switch', 'Subnautica + Subnautica: Below Zero', 'Subnautica', '2021-05-14', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x8n.jpg', 'Combining the award-winning game Subnautica with its unreleased sequel Subnautica Below Zero, this Nintendo Switch exclusive allows players to fully immerse themselves in the full mystery surrounding the water world of planet 4546B. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive in both hostile water zones and frozen terrains.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-lucky-s-tale-nintendo-switch', 'New Super Lucky''s Tale', 'Super Lucky''s Tale', '2019-11-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ehd.jpg', 'Leap into a Playful Platforming Adventure for all ages!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-meat-boy-nintendo-switch', 'Super Meat Boy', 'Super Meat Boy', '2018-01-11', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5t36.jpg', 'Super Meat Boy Handheld! is Super Meat Boy for the iPhone... kinda.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-meat-boy-forever-nintendo-switch', 'Super Meat Boy Forever', 'Super Meat Boy', '2020-12-23', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qlr.jpg', 'Meat Boy and Bandage Girl have grown as a couple since 2010. It seems like only yesterday the two love birds were escaping from an exploding laboratory in the sky. Now it’s the current year, and they’ve welcomed their daughter Nugget into the world. Their peaceful days enjoying life as a family came to an abrupt end when Dr. Fetus beat the snot out of them with a rusty shovel, and kidnapped Nugget! Now it’s up to Meat Boy and Bandage Girl to rescue their daughter from a lunatic fetus in a jar that can only be described as an incel version of Tony Stark.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-blitz-hd-nintendo-switch', 'Super Monkey Ball: Banana Blitz HD ', 'Super Monkey Ball', '2019-10-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uh1.jpg', 'Hold onto your bananas, because Super Monkey Ball: Banana Blitz HD is rolling your way! Experience the magic of one of the most beloved titles in the series, now remastered in HD!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-mania-nintendo-switch', 'Super Monkey Ball Banana Mania', 'Super Monkey Ball', '2021-10-05', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaeop.jpg', 'Super Monkey Ball: Banana Mania is a "modern HD remaster" of Super Monkey Ball, Super Monkey Ball 2, and Super Monkey Ball Deluxe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-rumble-nintendo-switch', 'Super Monkey Ball Banana Rumble', NULL, '2024-06-25', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbw9.jpg', 'Join AiAi and friends in Super Monkey Ball Banana Rumble, where you and up to 16 players can compete online across multiple game modes as you aim to become Top Banana! You can also work together with your favorite bunch in 4 player cooperative mode, or slip into a wonderfully crafted story in the all-new Adventure Mode experience!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-smash-bros-ultimate-nintendo-switch', 'Super Smash Bros. Ultimate', 'Super Smash Bros.', '2018-12-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2255.jpg', 'Legendary game worlds and fighters collide in the ultimate showdown—a new entry in the Super Smash Bros. series for the Nintendo Switch system! New fighters, like Inkling from the Splatoon series and Ridley from the Metroid series, make their Super Smash Bros. series debut alongside every Super Smash Bros. fighter in the series…EVER! Faster combat, new items, new attacks, new defensive options, and more will keep the battle raging whether you’re at home or on the go.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-vesperia-definitive-edition-nintendo-switch', 'Tales of Vesperia: Definitive Edition', 'Tales', '2019-01-11', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gb5.jpg', 'Tales of Vesperia: Definitive Edition is a remaster of the expanded Playstation 3 port of the original game, which was exclusive to Japan.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-space-mutant-blobs-attack-nintendo-switch', 'Tales from Space: Mutant Blobs Attack', NULL, '2019-05-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rk0.jpg', 'Tales from Space: Mutant Blobs Attack is a sci-fi puzzle-platformer of cataclysmic proportions. You''re a Blob of alien origin with mutant powers and an insatiable appetite. To the great horror of your former captors (and all of humanity), you have escaped into the world.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-talos-principle-nintendo-switch', 'The Talos Principle', 'The Talos Principle', '2019-12-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rb5.jpg', 'The Talos Principle is a philosophical first-person puzzle game from Croteam, the creators of the legendary Serious Sam series, written by Tom Jubert (FTL, The Swapper) and Jonas Kyratzes (The Sea Will Claim Everything).', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tempest-4000-nintendo-switch', 'Tempest 4000', 'Tempest', '2022-03-22', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27a9.jpg', 'In Tempest 4000, players are once again in control of the Claw, a powerful spacecraft equipped to destroy deadly creatures and other obstructions with rapid-fire shots on vibrant geometric prisms. With three game modes to choose from and 100 levels to conquer, players must eliminate all enemies as quickly as possible to survive and achieve that coveted spot at the top of the leaderboards.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-nintendo-switch', 'Terraria', NULL, '2019-06-27', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teslagrad-nintendo-switch', 'Teslagrad', NULL, '2017-12-07', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6eo7.jpg', 'Teslagrad 2 is the sequel to the original Teslagrad, developed by Rain Games and released in 2023. This 2D puzzle platformer builds upon the magnetic and electrical mechanics of its predecessor, with players once again using these abilities to solve puzzles and traverse complex environments. Set in a new region, the game introduces new powers, enemies, and challenges, while maintaining the visual storytelling and atmospheric design characteristic of the series.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-99-nintendo-switch', 'Tetris 99', 'Tetris', '2019-09-06', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jaz.jpg', 'A blockbuster battle royale!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-effect-connected-nintendo-switch', 'Tetris Effect: Connected', 'Tetris', '2021-10-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7kus.jpg', 'Tetris Effect: Connected adds an all-new robust multiplayer expansion to the huge variety of addictive and innovative single-player modes that Tetris Effect is known for. Connect and play with or against each other in all-new modes like "Zone Battle," which shakes up traditional 1-on-1 Tetris gameplay via the time-stopping Zone mechanic, or try the innovative co-op of "Connected" mode, where up to three players can literally connect their Tetris playfields together and play as one, as they work together to take down a series of increasingly-challenging CPU-controlled bosses.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thimbleweed-park-nintendo-switch', 'Thimbleweed Park', NULL, '2017-09-21', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wq3.jpg', 'Thimbleweed Park is the curious story of two washed up detectives investigating a dead body found in the river just outside of town. It''s a game where you switch between five playable characters while uncovering the dark, satirical and bizarre world of Thimbleweed Park.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thumper-nintendo-switch', 'Thumper', NULL, '2017-05-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4e.jpg', 'Thumper is a rhythm violence game. It combines classic rhythm-action with breakneck speed and brutal physicality.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('to-the-moon-nintendo-switch', 'To the Moon', NULL, '2020-01-16', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co81yu.jpg', 'An interactive movie/game for the Terebikko in which the player had to help the Sailor Senshi answer the questions of the Daimon Quiz.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toejam-earl-back-in-the-groove-nintendo-switch', 'ToeJam & Earl: Back in the Groove', 'ToeJam & Earl', '2019-03-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1i1e.jpg', 'ToeJam and Earl have crash-landed back on Earth in ToeJam and Earl: Back in the Groove!, a funky fresh rogue-like adventure infused with old skool hip-hop and jam packed with awesome throwbacks to the 1991 classic.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lara-croft-collection-nintendo-switch', 'The Lara Croft Collection', 'Tomb Raider', '2023-06-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6rtb.jpg', 'Lara Croft makes her Nintendo Switch debut with two Tomb Raider adventures in one treasure-packed bundle, featuring non-stop arcade combat and 2-4 player co-op.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomba-special-edition-nintendo-switch', 'Tomba! Special Edition', 'Tomba!', '2024-08-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92no.jpg', 'Our favourite pink-haired, high-jumping jungle boy is back!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('towerfall-nintendo-switch', 'TowerFall', NULL, '2018-09-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/wr4oggdg58nlrvhrtkij.jpg', 'TowerFall is the ultimate version of the beloved archery combat/party game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('transistor-nintendo-switch', 'Transistor', NULL, '2018-11-01', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob23o.jpg', 'An unconventional tactical action RPG in which after a powerful group called the Camerata cause measureless destruction through the ambiguous settlement of Cloudbank, Red, a famous singer in the city, goes on a journey along with her lover who is trapped inside the Transistor, a powerful machine with mysterious properties, to get to the bottom of the situation and get her lost voice back.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('trover-saves-the-universe-nintendo-switch', 'Trover Saves the Universe', NULL, '2019-11-28', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v3y.jpg', 'Wonderful. Your dogs have been dognapped by a beaked lunatic who stuffed them into his eye holes and is using their life essence to destroy the universe. Does that make any sense? You''ve partnered with Trover, a little purple eye hole monster to save them. Find power babies and plug them into his eye holes so that he can absorb their power, track down Glorkon, and save your dogs (and the Universe).', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tunic-nintendo-switch', 'Tunic', NULL, '2022-09-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/td1t8kb33gyo8mvhl2pc.jpg', 'Tunic is an action adventure about a tiny fox in a big world. Explore the wilderness, discover spooky ruins, and fight terrible creatures from long ago.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-nintendo-switch', 'Turok', 'Turok', '2019-08-09', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2699.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-2-seeds-of-evil-nintendo-switch', 'Turok 2: Seeds of Evil', 'Turok', '2019-08-09', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zcg.jpg', 'The Amaranthine Accordance is trying to bring a massive Dinosoid army to Earth from the Lost Land in an effort to restore dinosaurs to their rightful home.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-3-shadow-of-oblivion-nintendo-switch', 'Turok 3: Shadow of Oblivion', 'Turok', '2023-11-30', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7fpt.jpg', 'Turok 3: Shadow of Oblivion is a faithful restoration of the classic first-person shooter originally released in 2000 for the Nintendo 64, upgraded through Nightdive Studios’ proprietary KEX Engine for play on modern gaming devices with up to a 4K resolution at 120FPS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('undertale-nintendo-switch', 'Undertale', NULL, '2018-09-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unpacking-nintendo-switch', 'Unpacking', NULL, '2021-11-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2879.jpg', 'Unpacking is a job-simulator game about inspecting packages, deciding if they are accepted or denied depending on the rules of that day and doing different procedures for each package.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unsighted-nintendo-switch', 'Unsighted', NULL, '2021-09-30', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bt4.jpg', 'Traverse Arcadia your way. Save your friends. Time is ticking.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('untitled-goose-game-nintendo-switch', 'Untitled Goose Game', NULL, '2019-09-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vqc.jpg', 'It''s a lovely morning in the village and you are a horrible goose.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('vampyr-nintendo-switch', 'Vampyr', NULL, '2019-10-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8lrg.jpg', 'London, 1918. You are newly-turned Vampyr Dr. Jonathan Reid. As a doctor, you must find a cure to save the city’s flu-ravaged citizens. As a Vampyr, you are cursed to feed on those you vowed to heal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-final-season-nintendo-switch', 'The Walking Dead: The Final Season', 'The Walking Dead', '2019-03-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v9y.jpg', 'After years on the road facing threats both living and dead, a secluded school might finally be Clementine and AJ''s chance for a home. But protecting it will mean sacrifice. In this gripping, emotional final season, your choices define your relationships, shape your world, and determine how Clementine''s story ends.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wandersong-nintendo-switch', 'Wandersong', NULL, '2018-09-27', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1oey.jpg', 'Wandersong takes you on a whimsical, musical journey across the globe. Eons ago, the goddess Eya put the universe into motion with her music--now, as she does every epoch or so, she''s going to sing a new song and reset existence. You play as a lowly bard tasked with finding the pieces of a mysterious melody called the Earthsong, which is said to be able to preserve the planet. Use your singing to help characters, solve puzzles, and save the world!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-get-it-together-nintendo-switch', 'WarioWare: Get It Together!', 'WarioWare', '2021-09-10', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba9o.jpg', 'Take on over 200 quick and quirky microgames - lightning-fast minigames filled with frantic fun - solo or with a friend! When his latest harebrained business scheme goes awry, Wario must use his signature style (and smell) to fix it. How? By playing a twisted collection microgames of course! From assembling a robot to pulling out a statue''s armpit hair, the WarioWare: Get It Together! game is a comedic, cooperative microgame mashup.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warioware-move-it-nintendo-switch', 'WarioWare: Move It!', 'WarioWare', '2023-11-03', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nwc.jpg', 'Strike a pose with a multitude of motion-based microgames in a brand-new entry in the WarioWare series!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-ii-the-new-colossus-nintendo-switch', 'Wolfenstein II: The New Colossus', 'Wolfenstein', '2018-06-29', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-youngblood-nintendo-switch', 'Wolfenstein: Youngblood', 'Wolfenstein', '2019-07-26', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21by.jpg', 'Wolfenstein: Youngblood is a brand-new co-op experience from MachineGames, the award-winning studio that developed the critically acclaimed Wolfenstein II: The New Colossus.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-the-dragon-s-trap-nintendo-switch', 'Wonder Boy: The Dragon''s Trap', 'Wonder Boy', '2017-04-18', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4q.jpg', 'A modern version of cult classic Wonder Boy: The Dragon''s Trap! A close collaboration between Lizardcube, DotEmu and legendary series creator Ryuichi Nishizawa, based on Westone Bit Entertainment''s original masterpiece.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-boy-and-the-cursed-kingdom-nintendo-switch', 'Monster Boy and the Cursed Kingdom', 'Wonder Boy', '2018-12-04', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27mg.jpg', 'A legendary game series returns with an all-new adventure! Monster Boy is a colourful side-scrolling action adventure created in cooperation with Ryuichi Nishizawa, the creator of the Wonder Boy Monster World series (Trademark of SEGA Corporation Japan).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wonderful-101-remastered-nintendo-switch', 'The Wonderful 101: Remastered', 'The Wonderful 101', '2020-05-19', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nnf.jpg', 'Get ready for a unique side-scrolling experience in the world of The Wonderful 101: Remastered! This free DLC lets you enjoy a brand new episode in which you experience Luka''s story!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-world-ends-with-you-final-remix-nintendo-switch', 'The World Ends with You: Final Remix', 'The World Ends with You', '2018-10-12', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n68.jpg', 'Complete the mission...or face erasure. That’s all Neku knows after regaining consciousness in the middle of a busy intersection without his memories. Now he and his partner must fight to survive a life-or-death game in this twisted tale with more turns than the urban labyrinth of Tokyo they’re trapped in.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neo-the-world-ends-with-you-nintendo-switch', 'Neo: The World Ends With You', 'The World Ends with You', '2021-07-27', 'Nintendo Switch', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kzv.jpg', 'Explore a stylized recreation of Shibuya, as you take on the role of Rindo to battle for survival and unravel the mysteries of the deadly “Reaper’s Game” in this new Action RPG and follow-up to the classic RPG hit "The World Ends with You."', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-of-goo-2-nintendo-switch', 'World of Goo 2', 'World of Goo', '2024-08-02', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8na2.jpg', 'Use living liquid creatures to build bridges, grow towers, terraform terrain, and fuel flying machines. The world is beautiful, dangerous, and evolving.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-2-nintendo-switch', 'Xenoblade Chronicles 2', 'Xenoblade Chronicles', '2017-12-01', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nb4.jpg', 'Lost in a sea of clouds, entire civilizations rest on the backs of Titans. As the giant beasts march toward death, the last hope is a scavenger named Rex—and Pyra, a living weapon known as a Blade. Can you find the fabled paradise she calls home? Command a group of Blades and lead them to countless strategic victories before the world ends. Purchase this bundle to own both Xenoblade Chronicles 2 and the Expansion Pass.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-2-torna-the-golden-country-nintendo-switch', 'Xenoblade Chronicles 2: Torna – The Golden Country', 'Xenoblade Chronicles', '2018-09-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8r1.jpg', 'Guide a group of legendary warriors on a journey through the tragic history that doomed a kingdom and drove a hero down a dark path 500 years before the events of the Xenoblade Chronicles 2 game. Defend yourself from Malos and his forces using all the fury of this refined battle system, allowing you to fight as both the artificial lifeforms known as Blades and their masters, the Drivers.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-definitive-edition-nintendo-switch', 'Xenoblade Chronicles: Definitive Edition', 'Xenoblade Chronicles', '2020-05-29', 'Nintendo Switch', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8r4.jpg', 'Discover the origins of Shulk as he and his companions clash against a seemingly-unstoppable mechanical menace. Wield a future-seeing blade, chain together attacks, and carefully position your party members in strategic, real-time combat as you journey across a massive world.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-3-nintendo-switch', 'Xenoblade Chronicles 3', 'Xenoblade Chronicles', '2022-07-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8jeg.jpg', 'This convenient bundle includes the Xenoblade Chronicles 3 game for the Nintendo Switch system, along with the Xenoblade Chronicles 3 Expansion Pass that offers four waves of downloadable content.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenoblade-chronicles-x-nintendo-switch', 'Xenoblade Chronicles X', 'Xenoblade Chronicles', '2025-03-20', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavor.jpg', 'Xenoblade Chronicles X is an action role-playing video game and a part of the Xeno series of video games, serving as a spiritual successor to Xenoblade Chronicles on the Wii. In a similar fashion to the original, the game plays as an open world role-playing video game, with an emphasis on exploration. Traveling can take place on foot, or in large humanoid robots, approximately four times the height of the average playable character, called "Skells" ("Dolls" in the Japanese version), that the player may opt to control. The Skells have the ability to fly, traverse water, and transform into vehicles such as motorcycles or tanks. Aerial battles will also take place in the game.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoku-s-island-express-nintendo-switch', 'Yoku''s Island Express', NULL, '2018-05-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob89x.jpg', 'Yoku’s Island Express is an open world/metroidvania-style pinball adventure, Seamlessly blending platform navigation with pinball mechanics across a large open world. Yoku the dung beetle sets foot on the beach of Mokumana Island, ready to take on the duties as the new postman. But the ancient island God is trapped in a restless sleep and the islanders are plagued by quakes and storms brought forth by its nightmares. Yoku''s Island Express is a unique and quirky adventure with handcrafted visuals, where you''ll soar through the air, vacuum explosive snails, fight a Screetch, feed starving lemurs, discover the mystery of the Fruit Altar, wake an old god, and hopefully help tiny Yoku rebuild the island post-office.', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-nintendo-switch', 'Yooka-Laylee', 'Yooka-Laylee', '2017-12-14', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4v.jpg', 'Explore huge, beautiful worlds, meet (and beat) an unforgettable cast of characters and horde a vault-load of shiny collectibles as buddy-duo Yooka (the green one) and Laylee (the wisecracking bat with the big nose) embark on an epic adventure to thwart corporate creep Capital B and his devious scheme to absorb all the world’s books… and convert them into pure profit!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-and-the-impossible-lair-nintendo-switch', 'Yooka-Laylee and the Impossible Lair', 'Yooka-Laylee', '2019-10-08', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2z9b.jpg', 'Yooka and Laylee are back for a brand new adventure! Get ready for the ultimate challenge - the Impossible Lair!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoshi-s-crafted-world-nintendo-switch', 'Yoshi''s Crafted World', 'Yoshi', '2019-03-29', 'Nintendo Switch', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobav7.jpg', 'Lead Yoshi on a brand new adventure that will turn everything you''ve come to expect from side-scrolling games upside down! Explore a great, big world decorated like a miniature diorama in a new art style for the franchise, where each side-scrolling stage has the traditional front side as well as a flip side with different views and surprises. Look for items throughout the stage as Yoshi makes his way to the goal. You can even join up with a friend!', 'NA', 26);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donkey-kong-bananza-nintendo-switch-2', 'Donkey Kong Bananza', 'Donkey Kong', '2025-07-17', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobd1q.jpg', 'Donkey Kong Bananza is exclusively on Nintendo Switch 2! Explore a vast underground world—by smashing your way through it! Bash, throw, and climb through just about anything in DK’s brand-new 3D platforming action-adventure game!', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-and-the-forgotten-land-nintendo-switch-2-edition-star-crossed-world-nintendo-switch-2', 'Kirby and the Forgotten Land - Nintendo Switch 2 Edition + Star-Crossed World', 'Kirby', '2025-08-28', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9m76.jpg', 'In Star-Crossed World, a new story included in the upgrade pack, Kirby must use his abilities, including the all-new Mouthful Modes, to clear a trail through uncharted territory. The upgrade pack will include this new content which can be played in single-player and local co-op, as well as improved performance for the entire game.', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kirby-air-riders-nintendo-switch-2', 'Kirby Air Riders', 'Kirby', '2025-11-20', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaauz.jpg', 'Kirby Air Riders is the long-awaited sequel to Kirby Air Ride on the Gamecube.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-breath-of-the-wild-nintendo-switch-2-edition-nintendo-switch-2', 'The Legend of Zelda: Breath of the Wild - Nintendo Switch 2 Edition', 'The Legend of Zelda', '2025-06-05', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9oy.jpg', 'Travel across vast fields, through forests, and to mountain peaks as you discover what has become of the kingdom of Hyrule-and step into a world of discovery, exploration, and adventure that''s been upgraded with performance enhancements in The Legend of Zelda: Breath of the Wild - Nintendo Switch 2 Edition! With improved framerates, faster load times, and enhanced resolution and textures, this thrilling open-air adventure has never looked better!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-zelda-tears-of-the-kingdom-nintendo-switch-2-edition-nintendo-switch-2', 'The Legend of Zelda: Tears of the Kingdom - Nintendo Switch 2 Edition', 'The Legend of Zelda', '2025-06-05', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav5n.jpg', 'In this sequel to The Legend of Zelda: Breath of the Wild, you’ll decide your own path through the sprawling landscapes of Hyrule and the mysterious islands floating in the vast skies above. Can you harness the power of Link’s new abilities to fight back against the malevolent forces that threaten the kingdom?', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyrule-warriors-age-of-imprisonment-nintendo-switch-2', 'Hyrule Warriors: Age of Imprisonment', 'The Legend of Zelda', '2025-11-06', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9n1.jpg', 'Fight the war for ancient Hyrule! Step on to the battlefield as Princess Zelda, King Rauru, and other legendary heroes as you fight to reclaim your homeland— and live the story of Demon King Ganondorf''s invasion that was only briefly alluded to in The Legend of Zelda: Tears of the Kingdom game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mario-kart-world-nintendo-switch-2', 'Mario Kart World', 'Mario Kart', '2025-06-05', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9s9.jpg', 'Put the pedal to the metal in a vast interconnected environment. Race seamlessly across connected courses like never before. Participate in the new knockout tour elimination mode, where you’ll barrel through back-to-back courses and checkpoints. And in free roam, it’s possible to go off the racetrack and drive in any direction you wish, explore areas that pique your interest and take some photos at scenic spots with a group of friends.', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-mario-party-jamboree-nintendo-switch-2-edition-jamboree-tv-nintendo-switch-2', 'Super Mario Party Jamboree – Nintendo Switch 2 Edition + Jamboree TV', 'Mario Party', '2025-07-24', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9m77.jpg', 'Super Mario Party Jamboree is getting even more minigames and an upgrade on Nintendo Switch 2! The upgrade expands on the base game and adds Nintendo Switch 2 gameplay features, such as mouse controls, enhanced rumble, sound recognition, and modes that use a camera accessory (sold separately).', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metroid-prime-4-beyond-nintendo-switch-2-edition-nintendo-switch-2', 'Metroid Prime 4: Beyond - Nintendo Switch 2 Edition', 'Metroid', '2025-12-04', 'Nintendo Switch 2', 1, 0, NULL, NULL, NULL, NULL, 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pok-mon-legends-z-a-nintendo-switch-2', 'Pokémon Legends: Z-A', 'Pokémon', '2025-10-16', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wzc.jpg', 'A new adventure awaits within Lumiose City, where an urban redevelopment plan is underway to shape the city into a place that belongs to both people and Pokémon. Please look forward to seeing it for yourself.​​', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-replaylee-nintendo-switch-2', 'Yooka-Replaylee', 'Yooka-Laylee', '2025-10-09', 'Nintendo Switch 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa05j.jpg', 'Embark on an epic open-world 3D platforming collectathon adventure with Yooka and Laylee! The search for Pagies starts anew in Yooka-Replaylee, the enhanced definitive version of the beloved indie darling with all new challenges, secrets, mechanics, and accessibility options.', 'NA', 27);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-philips-cd-i', 'Dragon''s Lair', 'Dragon''s Lair', '1994-01-01', 'Philips CD-i', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-ii-time-warp-philips-cd-i', 'Dragon''s Lair II: Time Warp', 'Dragon''s Lair', '1994-01-01', 'Philips CD-i', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y1w.jpg', 'Dragon''s Lair II: Time Warp, the followup to Don Bluth''s arcade classic Dragon''s Lair, can now be enjoyed on your PC. This fully arcade authentic version includes all of the original scenes you''ve come to enjoy, and even the unreleased Director''s Cut ending not seen in the arcades. Other bonuses include a full watch feature to sit back and enjoy Don Bluth''s stunning animation.', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('link-the-faces-of-evil-philips-cd-i', 'Link: The Faces of Evil', 'The Legend of Zelda', '1993-10-10', 'Philips CD-i', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60ta.jpg', 'Link: The Faces of Evil was the product of a compromise between Nintendo and Philips following their failure to release a CD-ROM based add-on to the Super Nintendo Entertainment System. The Faces of Evil differ from most conventional Zelda games as it is a platformer with a side-scrolling view, similar to The Adventure of Link. Stages are accessed from a world map, with more becoming available as Link clears an area or defeats a boss. The game have been subject to much criticism and Nintendo does not recognize it as part of the series.', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zelda-the-wand-of-gamelon-philips-cd-i', 'Zelda: The Wand of Gamelon', 'The Legend of Zelda', '1993-10-10', 'Philips CD-i', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60tx.jpg', 'Zelda: The Wand of Gamelon was the product of a compromise between Nintendo and Philips following their failure to release a CD-ROM based add-on to the Super Nintendo Entertainment System. It was developed in tandem with Link: The Faces of Evil and marks the first game where the eponymous princess Zelda is playable. The Wand of Gamelon differ from most conventional Zelda games as it is a platformer with a side-scrolling view, similar to The Adventure of Link. Stages are accessed from a world map, with more becoming available as Zelda clears an area or defeats a boss. The game have been subject to much criticism and Nintendo does not recognize it as part of the series.', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zelda-s-adventure-philips-cd-i', 'Zelda''s Adventure', 'The Legend of Zelda', '1994-06-05', 'Philips CD-i', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6fxj.jpg', 'In the 1990s Nintendo made a deal with Philips to develop 3 Zelda titles. The first 2 were side scrolling platformers, similar to Zelda II, and the third was a traditional top-down action adventure game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-philips-cd-i', 'Lemmings', 'Lemmings', '1993-01-01', 'Philips CD-i', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hotel-mario-philips-cd-i', 'Hotel Mario', 'Mario', '1994-06-01', 'Philips CD-i', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te1.jpg', 'Hotel Mario is a puzzle/platformer game who takes place in hotels. The general goal in each stage is to close all the doors on every floor. However, various enemies will interfere and reopen them at times. Elevators are needed to travel between floors. The first six hotels have ten stages, whilst the seventh has fifteen. The game had low sales partially due to a lack of interest in the CD-i system, and received mainly poor reviews.', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-philips-cd-i', 'Tetris', 'Tetris', '1991-01-01', 'Philips CD-i', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69ff.jpg', 'Tetris is now available for the first time on the PSP! See why hundreds of millions of players worldwide have made Tetris one of the most popular games ever! It features the famous Marathon Mode along with 12 new mini-versions based on the Tetris gameplay you know & love. Offering 15 levels of difficulty, it records your ''best times'' and ‘best scores’ for each variation. Use the Replay Viewer to look up cool moves in the in-game glossary and check out sweet replays of some of the best Tetris players in the world. TETRIS has changed with the times, but after 25 years some things remain the same... it’s captivating, fun, and addictive! Let the Tetris revolution begin!', 'NA', 28);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-playstation', 'Ape Escape', 'Ape Escape', '1999-05-31', 'PlayStation', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzc.jpg', 'Ape Escape is a single-player 3D platformer released in 1999 for the Playstation. Using the analog stick, you must capture apes that have escaped throughout time to stop them from screwing up the fabric of time and space.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-blasting-again-playstation', 'Blaster Master: Blasting Again', 'Blaster Master', '2001-05-06', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9b58.jpg', 'Years ago, the Earth was threatened by an evil being known as the Plutonium Boss. The Plutonium Boss and his minions were devouring the Earth from within, and if they had succeeded, Earth would''ve been destroyed.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-world-playstation', 'Bomberman World', 'Bomberman', '1998-09-22', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85g1.jpg', 'Bomber worlds. To complete the areas, you must control Bomberman and set bombs to destroy enemies and obstacles that will lead to the exit. To be able to complete each level, the player must locate and pick up all of the Crystals on the map. Once this is complete, the door to the exit will open, and the player is allowed to move on to the next area. In the fourth area of each world, the player will have to defeat a Dark Force Bomber, and an extra boss that is themed after the type of world the setting is in.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-fantasy-race-playstation', 'Bomberman Fantasy Race', 'Bomberman', '1999-04-16', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7k5i.jpg', 'If you''re looking for fun racing action, look no further than Bomberman Fantasy Race! Lightning fast competition, zany obstacle infested tracks and of course bombs! It''s a battle-racing game like you''ve seen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-party-edition-playstation', 'Bomberman Party Edition', 'Bomberman', '2000-09-19', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa5m3.jpg', 'Bomberman Party Edition, known in Japan and Europe as Bomberman, is a PlayStation version of the 1983 game Bomberman. In addition to vintage graphics for single player mode, an option for enhanced graphics is added.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-3d-playstation', 'Bubsy 3D', 'Bubsy', '1996-11-25', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2htw.jpg', 'A web-based 3D experience and homage to both art and Bubsy.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-symphony-of-the-night-playstation', 'Castlevania: Symphony of the Night', 'Castlevania', '1997-10-02', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53m8.jpg', 'Having been awoken from his eternal slumber by the reappearance of Castlevania, Alucard must once again face the evil minions of darkness. Use your vampiric powers, along with weapons, potions, and other magical relics to change the tide of battle.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-chronicles-playstation', 'Castlevania Chronicles', 'Castlevania', '2001-10-08', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7kax.jpg', 'The 2D whip-wielding action game Castlevania returns with a classic version never before seen in America with Castlevania Chronicles. Count Dracula has been resurrected to begin a new reign of terror across the land. As Simon Belmont, descendant of legendary vampire hunters, you enter Dracula''s estate to face the Count and his minions - alone. Be prepared for one of the first adventures in the Castlevania series ever!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chrono-cross-playstation', 'Chrono Cross', 'Chrono', '2000-08-15', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coatzy.jpg', 'CHRONO CROSS is an RPG that transcends time and space, unfolding across two interlinked parallel worlds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-playstation', 'Sid Meier''s Civilization', 'Civilization', '1996-04-26', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hgf.jpg', 'An expansion pack to Sid Meier''s compelling strategy game Civilization II, the rare Scenario Disk Conflicts in Civilization includes 20 bonus scenarios, including eight "Best of the Net" scenarios created by fans of the series.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-ii-playstation', 'Sid Meier''s Civilization II', 'Civilization', '1999-01-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6yhe.jpg', 'A turn-based strategy video game set around several different historic civilizations.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-legacy-of-war-playstation', 'Contra: Legacy of War', 'Contra', '1996-11-29', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gfb.jpg', 'Contra: Legacy of War is a 3D action game produced by Konami and developed by Appaloosa Interactive that was originally released in 1996 for the PlayStation and Sega Saturn. It was the first of two Contra games that were externally developed by Appaloosa, followed by C: The Contra Adventure in 1998. The game marks the series'' jump to three-dimensional graphics and controversial changes in gameplay. Legacy of War was released packaged with a pair of 3D anaglyph glasses, which the game supported. Legacy of War bears the distinction for being the first console game in the series to retain both the Contra title and human characters during its release in Europe and Australia (where the console series has been known as Probotector from the first NES game and up until Contra: Hard Corps). The game was scheduled to be released in Japan as well, but was canceled.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('c-the-contra-adventure-playstation', 'C The Contra Adventure', 'Contra', '1998-08-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4py0.jpg', 'Mission Critical!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-playstation', 'Crash Bandicoot', 'Crash Bandicoot', '1996-09-09', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55ex.jpg', 'Crash Bandicoot: The Wrath of Cortex is the fourth mainline series game and the first to feature Crash Bandicoot on the PlayStation 2. It was later ported to the GameCube and Xbox, making it his first multiplatform appearance. The player controls Crash and his younger sister Coco who must gather 25 crystals and defeat the main antagonists of the story, Doctor Neo Cortex and his new super weapon Crunch Bandicoot. Much of the game takes place in a Virtual Reality Hub System created by Coco to help Crash gather the crystals. The gameplay is similar to the older games of the series.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-2-cortex-strikes-back-playstation', 'Crash Bandicoot 2: Cortex Strikes Back', 'Crash Bandicoot', '1997-10-31', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co82vt.jpg', 'Crash Bandicoot 2: Cortex Strikes Back is the second game in the Crash Bandicoot series, and the sequel to the original game. The gameplay is largely similar to that of the original, as players make their way through a limited environment whilst breaking crates that contains bonuses. The goal of the game is to gather 25 crystals for Crash''s nemesis, Doctor Neo Cortex. The crystals are scattered between 25 different levels accessible via Warp Rooms, which are hub areas of the game. A level is cleared by collecting its respective crystal and reaching the end of its path, which returns Crash to the Warp Room.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-warped-playstation', 'Crash Bandicoot: Warped', 'Crash Bandicoot', '1998-10-31', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co873w.jpg', 'Crash Bandicoot: Warped is the third game in the Crash Bandicoot series and the first to feature Coco as a playable character. The player takes control of Crash and Coco Bandicoot, who must travel back and forward in time and gather 25 crystals before Uka Uka and Doctor Neo Cortex can do so. Much of the game takes place in the Time Twister which acts as the hub area of the game. The Time-Twister is split up into five chambers, each chamber has five buttons that open portals to different levels. The goal in each level is to find and obtain the crystal hidden in the level. Crash Bandicoot: Warped was lauded by critics in many areas, and the game has been considered one of the best video games of all time.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-racing-playstation', 'Crash Team Racing', 'Crash Bandicoot', '1999-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7r52.jpg', 'Crash Team Racing is a kart racing game featuring popular characters from the Crash Bandicoot series. The gameplay is very similar to other kart racing video games like Mario Kart: players have to choose a character and compete against the other racers on various racetracks. The story mode allows you to choose any one of the characters to complete all the main races and beat the ultimate boss Nitrous Oxide. Each of the main races are against 7 other AI competitors with 5 boss races. There are also a few arcade modes up to 4 players.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bash-playstation', 'Crash Bash', 'Crash Bandicoot', '2000-11-06', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobhr9.jpg', 'Crash Bash is a party game in which four people can play several mini-games as characters from the Crash Bandicoot series. The gameplay consists of 28 different mini-games and three distinct modes of play: Adventure, Battle, and Tournament. Crash Bash includes multiplayer compatibility for up to four human players with the use of the PlayStation Multitap. The games are organized from a central hub world from which spokes lead to different levels.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('croc-legend-of-the-gobbos-playstation', 'Croc: Legend of the Gobbos', 'Croc', '1997-09-29', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dmk.jpg', 'All is not well in Croc''s world. His friends, the Gobbos, have been captured by the evil Baron Dante. It is your mission in this 3D platformer to search through 42 different levels to save all of your friends before it''s too late.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('croc-2-playstation', 'Croc 2', 'Croc', '1999-06-30', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pps.jpg', 'Croc 2 is a platformer that follows the cute crocodile protagonist, Croc, in his adventure to free his furry friends the gobbos from the forces of evil. On his way Croc collects gems in order to buy items that will assist his quest.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-the-arcade-game-playstation', 'Batman Forever: The Arcade Game', 'DC', '1996-12-03', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yd0.jpg', 'A Final-Fight/Double-Dragon style game which features the Caped Crusader and his sidekick Robin in a traditional beat-em-up. Based on the Batman Forever movie, this side-scrolling beat-em-up features the plot, several memorable characters, and quotes from its movie counterpart.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-robin-playstation', 'Batman & Robin', 'DC', '1998-08-07', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ssv.jpg', 'Break out your Batarang! When the scum of Gotham City decide they want to take over, it''s no joke... Or is it? The Joker and his cohorts kidnap Robin as the perfect bait to lure Batman. You can bet that the Dark Knight is going to be up to his ears
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-beyond-return-of-the-joker-playstation', 'Batman Beyond: Return of the Joker', 'DC', '2000-11-20', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ap0.jpg', 'Batman Beyond: Return of the Joker (also known as Batman of the Future: Return of the Joker in Europe and Australia) is a 2000 American direct-to-video animated film featuring the comic book superhero Batman and his archenemy, the Joker. It is set in the continuity of the animated series Batman Beyond, in which Bruce Wayne has retired from crime fighting, giving the mantle of Batman to high school student Terry McGinnis, and serves as a sequel to both Batman: The Animated Series and The New Batman Adventures. As in the TV series, Will Friedle and Kevin Conroy star as Terry McGinnis and Bruce Wayne, respectively. Mark Hamill, who played the Joker opposite Conroy in Batman: The Animated Series and The New Batman Adventures, reprises his role.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-gotham-city-racer-playstation', 'Batman: Gotham City Racer', 'DC', '2001-04-19', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zcn.jpg', 'Cruise as Batman, Nightwing, or Batgirl - or one of 23 criminals like The Joker, Mr. Freeze, Catwoman, and Killer Croc. Master 15 supercharged vehicles loaded with signature weapons like Batarangs, Laughing Gas, Cat Claws, Sewage Slicks, and tons more. Live Batman''s world through 51 episode-based missions with real cut-scenes from the TV show.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-playstation', 'Diablo', 'Diablo', '1998-03-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coayp2.jpg', 'Azmodan arises from the burning Hells, and he’s not alone.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disruptor-playstation', 'Disruptor', NULL, '1996-11-20', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hsh.jpg', 'As a soldier in the world-renowned LightStormer Corps., your main objective is to clean up the universe...but it''s getting pretty hairy out there! Mutated humans, space marines and aliens have decimated scientific research parties on Mars, threatened Earth and infiltrated various space stations -- the LightStormer Corps. aren''t taking this situation lightly.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-playstation', 'Doom', 'Doom', '1995-11-16', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-doom-playstation', 'Final Doom', 'Doom', '1996-10-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5b12.jpg', 'The version of Final Doom found in the DLC section of the Doom Unity remasters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('torneko-the-last-hope-playstation', 'Torneko: The Last Hope', 'Dragon Quest', '2000-11-15', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wgg.jpg', 'Torneko: The Last Hope is a single player RPG title that revolves around the chubby merchant from Dragon Warrior IV as he sets out on an adventure to rid the town of all the monsters. The story unfolds in the village as you interact with the town''s inhabitants and gather information to help you in your quest.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-warrior-vii-playstation', 'Dragon Warrior VII', 'Dragon Quest', '2001-10-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7wq9.jpg', 'Dragon Quest VII is the seventh installment of the popular Dragon Quest series of role playing games and the first in the series to not be a part of a larger trilogy. It was the first main series Dragon Quest title to be released outside of Japan since the release of Dragon Quest IV: Chapters of the Chosen in North America in 1992, and the last DQ title to be released in North America with the Dragon Warrior name.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-vii-playstation', 'Final Fantasy VII', 'Final Fantasy', '1997-09-07', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vn2.jpg', 'The Twin Pack includes Final Fantasy VII and the remastered version of Final Fantasy VIII.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-tactics-playstation', 'Final Fantasy Tactics', 'Final Fantasy', '1998-01-28', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yx4.jpg', 'Lead epic battles in a new FINAL FANTASY world. Betrayal and darker dealings await in Squaresoft''s game of war. Fight hundreds of battles across dangerous 3D terrain as an ancient blood feud awakens a deadlier foe.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chocobo-racing-playstation', 'Chocobo Racing', 'Final Fantasy', '1999-08-10', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co57bi.jpg', 'The Chocobo has appeared in every Final Fantasy game since Final Fantasy IV as a large yellow bird that you can ride to other destinations or use during fights. With Chocobo Racing, you can race a Chocobo along with a range of different characters both from the Final Fantasy world including Cloud and Cid from Final Fantasy VII and created just for the game through many different fantasy worlds at high speed, using a selection of weapons to aid you. The game supports 1 and 2 player racing', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-viii-playstation', 'Final Fantasy VIII', 'Final Fantasy', '1999-09-09', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4tsp.jpg', 'The Steam version of Final Fantasy VIII comes with several in-game enhancements, including a speed-up option to fast-forward through cutscenes and FMVs and built-in cheats, such as Battle Assist, making battles almost impossible to lose. Like Final Fantasy VII, the re-release version comes with the Magic Booster feature that allows players to boost their characters'' magics to 100. Achievements and cloud save data storage are also available. Windowed mode and high-resolution displays (up to 1920x1080 @ 60 Hz) are now supported. However, the game still uses the original MIDI tracks from the 1999 version, rather than the PlayStation version music, unlike the 2012 re-released Final Fantasy VII which has received a musical update. Chocobo World is playable directly from the launcher after booting Final Fantasy VIII.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-anthology-playstation', 'Final Fantasy Anthology', 'Final Fantasy', '1999-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ygz.jpg', 'Final Fantasy Anthology offers two games in one package for PlayStation. The European Edition contains Final Fantasy IV and V, which is different from the earlier released North American version that included Final Fantasy VI instead of Final Fantasy IV.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chocobo-s-dungeon-2-playstation', 'Chocobo''s Dungeon 2', 'Final Fantasy', '1999-11-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob6ox.jpg', 'FINAL FANTASY''s Chocobo stars in an all-new adventure!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-ix-playstation', 'Final Fantasy IX', 'Final Fantasy', '2000-11-13', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob2dk.jpg', 'The PC version of Final Fantasy IX features high-resolution character models, improved FMVs and modern enhancements such as auto-save, fast-forward and battle boosters. It supports both controller and keyboard/mouse input. The Steam release also includes achievements and allows for community-created mods, including the popular Moguri Mod, which restores original-style backgrounds and audio.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-chronicles-playstation', 'Final Fantasy Chronicles', 'Final Fantasy', '2001-06-29', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co205y.jpg', 'Final Fantasy Chronicles is a compilation that includes Final Fantasy IV, and another Square production, Chrono Trigger, released for the Sony PlayStation. Both games were ports of titles originally released for the Super Nintendo Entertainment System.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-origins-playstation', 'Final Fantasy Origins', 'Final Fantasy', '2003-04-08', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54w7.jpg', 'Final Fantasy Origins is a compilation of Final Fantasy and Final Fantasy II for the PlayStation. It is the re-release of remastered versions on the PlayStation platform.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('glover-playstation', 'Glover', NULL, '1999-11-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar3y.jpg', 'The cult classic from the ''90s returns! Glover is a charming 3D platformer where you control a magical glove on a quest to restore balance to the kingdom. Roll, jump, and manipulate your magic ball to solve puzzles, overcome challenges, and defeat the evil glove threatening the world!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-playstation', 'Grand Theft Auto', 'Grand Theft Auto', '1998-06-30', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-london-1969-playstation', 'Grand Theft Auto: London 1969', 'Grand Theft Auto', '1999-04-30', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb1.jpg', 'Grand Theft Auto: London 1969 is a mission pack for Grand Theft Auto. The game uses the same game engine as Grand Theft Auto, thus having similar graphics and gameplay. Like Grand Theft Auto, the mission pack is divided into sub-sections with short cut scenes between.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-2-playstation', 'Grand Theft Auto 2', 'Grand Theft Auto', '1999-10-22', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4s1j.jpg', 'The PSX port of Grand Theft Auto 2 is an open world action-adventure video game. It is the sequel to Grand Theft Auto, part of the Grand Theft Auto series. The open world design lets players freely roam Anywhere City, the setting of the game.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('king-s-field-playstation', 'King''s Field', 'King''s Field', '1996-02-14', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p48.jpg', 'King''s Field is the first game released by FromSoftware for mobile phones. It introduces quick saving and the auto map function. Its map layout is different from its Playstation namesake, and features no discernible story nor music.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('king-s-field-ii-playstation', 'King''s Field II', 'King''s Field', '1996-11-20', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1ai.jpg', 'King''s Field II -- the hour of destiny is at hand... Your kingdom is once again under attack by the ruthless minions of evil. This time they have possessed King Alfred himself! As the King''s son, Prince Lyle, you must bring forth the tide of change that will effect the universe from now until the end of time. The fate of the world is in your hands!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-racers-playstation', 'Lego Racers', 'Lego', '1999-12-17', 'PlayStation', 0, 0, NULL, NULL, NULL, 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-rock-raiders-playstation', 'Lego Rock Raiders', 'Lego', '2000-08-17', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3shy.jpg', 'Unlike the Windows version, the PlayStation version is an action and strategy game, in which the player controls a character instead of just commanding a squad. While the former was centered on constructing a base and mining, the latter centers on exploring.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-island-2-the-brickster-s-revenge-playstation', 'Lego Island 2: The Brickster''s Revenge', 'Lego', '2001-03-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94mf.jpg', 'The Brickster is back and out to cause more mischief in this wild, racing, chasing, island-hopping sequel. In your quest to piece together The Informaniac''s Constructopedia, you''ll drive, scuba-dive, fly a place and even ride a dinosaur as you chase the Brickster down through these amazing new LEGO worlds. Meet all kinds of fun characters along the way as you journey through the game. You''ll need all your skills to solve the puzzles and achieve your ultimate goal, to prevent LEGO Island being ruined.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-3d-playstation', 'Lemmings 3D', 'Lemmings', '1997-05-26', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67te.jpg', 'Lemmings 3D is a puzzle video game released in 1995, developed by Clockwork Games and published by Psygnosis. The gameplay, like the original Lemmings game, requires the player to lead all the lemmings to their exit by giving them the appropriate "skills". It was the first Lemmings game to be rendered in 3D. It was released for DOS, PlayStation, and Sega Saturn, with all three releases being almost identical minus some performance differences.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-adventures-of-lomax-playstation', 'The Adventures of Lomax', 'Lemmings', '1997-10-10', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w1u.jpg', 'Lomax is in way over his head. Evil Ed has nabbed his pals and tricked them into doing diabolical deeds. Only Lomax has the power to break the sinister hex! Leap into action with Lomax as he battles Ed''s evildoers and travels through bizarre lands in this fast and frantic thriller!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-oh-no-more-lemmings-playstation', 'Lemmings & Oh No! More Lemmings', 'Lemmings', '1998-01-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6aus.jpg', 'This Windows port contains two complete games from DMA Design''s classic ''Lemmings'' puzzle series, which are all mind-boggling games of multiple skill levels, featuring fantastically animated graphics and simple yet addictive gameplay.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('legend-of-mana-playstation', 'Legend of Mana', 'Mana', '2000-06-06', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2us6.jpg', 'Set off on a journey to find the mystical Mana Tree seen in a dream, before discovering... the world map is empty! During your travels, you’ll acquire special artifacts; place these wherever you’d like on the map to bring towns and dungeons to life and advance the story.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-and-x-o-manowar-in-heavy-metal-playstation', 'Iron Man and X-O Manowar in Heavy Metal', 'Marvel', '1996-01-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co80mh.jpg', 'The Game Boy port of Iron Man and X-O Manowar in Heavy Metal.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-the-pantheon-saga-playstation', 'The Incredible Hulk: The Pantheon Saga', 'Marvel', '1997-04-10', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52sl.jpg', 'True to the comic books, the Hulk relies on no other weapons than his massive muscles to punch, kick and crush his enemies. When he has accumulated enough gamma energy, he may use powerful special moves like a Vortex Spin or the Floor Hammer. Rare bonus items also allow the Hulk to summon one of the four Pantheon team members Atalanta, Ulysses, Ajax and Hector to assist in the thick of battle.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-heroes-playstation', 'Marvel Super Heroes', 'Marvel', '1997-09-29', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8sbu.jpg', 'Educational arcade-style games with Spider-Man, Wolverine, Iron Man and She-Hulk. Learn addiction, subtraction, multiplication, division, fractions, geometry and more. Exciting animation, sound and interactivity. Ages 8-12.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-playstation', 'Fantastic Four', 'Marvel', '1997-10-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nah.jpg', 'The Fantastic Four video game, released in 1997 for the PlayStation, is a beat ''em-up action game based on the Marvel Comics superhero team. Developed by Probe Entertainment and published by Acclaim Entertainment, the game features playable characters Mr. Fantastic, The Invisible Woman, The Human Torch, The Thing, and She-Hulk, each with unique abilities. A version for the Sega Saturn was planned but ultimately cancelled. Players engage in combat, solve puzzles, and navigate obstacles across various levels, drawing from the rich lore of the Fantastic Four comics.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-children-of-the-atom-playstation', 'X-Men: Children of the Atom', 'Marvel', '1998-02-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wez.jpg', 'X-Men: Children of the Atom is an arcade game featuring characters licensed from Marvel Comics. Timed with the popularity of the mid-1990s X-Men animated series, the game incorporates voice actors from the show reprising their respective roles. The gameplay involves one-on-one fighting matches, where players face off against different characters in the game. The ultimate challenge comes in the form of battles against Juggernaut and Magneto.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-vs-street-fighter-playstation', 'X-Men vs. Street Fighter', 'Marvel', '1998-06-11', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8poj.jpg', 'X-Men vs. Street Fighter is a fighting game originally released as a coin-operated arcade game in 1996. It is Capcom''s third fighting game to feature Marvel Comics characters and the first game to match them against their own, with characters from Marvel''s X-Men franchise being matched against the cast from the Street Fighter series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-heroes-vs-street-fighter-playstation', 'Marvel Super Heroes vs. Street Fighter', 'Marvel', '1999-02-23', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8iho.jpg', 'Now you can choose your favorite heroes from the worlds of Street Fighter and Marvel Super Heroes to face off in a head-to-head battle for supremacy. Dive into the action to perform outrageous moves and link together amazing Chain Combos... then delight in their devastating results! Marvel Super Heroes vs. Street Fighter combines two incredible universes to create an entirely new legend of heroic proportions.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-clash-of-super-heroes-playstation', 'Marvel vs. Capcom: Clash of Super Heroes', 'Marvel', '2000-01-27', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9eql.jpg', 'This PlayStation port differs from the arcade version, in that players are unable to switch characters on-the-fly, reducing the secondary character to an assist role only.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mutant-academy-playstation', 'X-Men: Mutant Academy', 'Marvel', '2000-07-14', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y74.jpg', 'X-Men: Mutant Academy is a 3-D/2D fighting game developed by Paradox, the company behind Activision''s Wu-Tang: Shaolin Style and the never-published Thrill Kill, and based on the X-Men characters from Marvel Comics. The game was released for the Game Boy Color and PlayStation as a tie-in to X-Men.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-playstation', 'Spider-Man', 'Marvel', '2000-09-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blade-playstation', 'Blade', 'Marvel', '2000-11-23', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25bz.jpg', 'In an open sand box world you choose your allies, your enemies, what provinces to conquer, what castles to siege and what quests to embark on. With Fire and Sword builds and expands upon the highly regarded combat system from Mount & Blade: Warband. Firearms have been introduced to the battlefield. Additionally, muskets and pistols can now be used as sidearms in hand-to-hand combat to quickly drop your foes. In addition to the enhanced singleplayer mode, With Fire & Sword also provides a host of original multiplayer content including the new game mode: Captain.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-enter-electro-playstation', 'Spider-Man 2: Enter Electro', 'Marvel', '2001-08-26', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lab.jpg', 'Spider-Man 2: Enter Electro is an action-adventure video game developed by Vicarious Visions and published by Activision for the PlayStation in 2001. It is the sequel to Neversoft''s Spider-Man title, which was released the previous year. The game follows Spider-Man as he attempts to stop another old nemesis Electro from obtaining a source of power known as the Bio-Nexus Device. Game bosses include Shocker, Hammerhead, Lizard, Sandman and the exclusive charged-up Hyper-Electro.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mutant-academy-2-playstation', 'X-Men: Mutant Academy 2', 'Marvel', '2001-09-17', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kzy.jpg', 'X-Men: Mutant Academy 2 is a PlayStation video game, the sequel to X-Men: Mutant Academy. Both feature the X-Men in a 3-D fighting arena similar to Mortal Kombat 4.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('men-in-black-the-series-crashdown-playstation', 'Men in Black: The Series – Crashdown', 'Marvel', '2001-11-20', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3hbr.jpg', 'Men in Black: The Series - Crashdown is a first-person shooter video game based on the animated television series, Men in Black: The Series. The game was developed by Runecraft and published by Infogrames for the PlayStation. The game was released in November 2001, and received mixed and average reviews.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('medievil-playstation', 'MediEvil', 'MediEvil', '1998-10-21', 'PlayStation', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjk.jpg', 'MediEvil is an action-adventure game developed by SCE Cambridge Studio and published by Sony Computer Entertainment. Originally released in 1998 for the PlayStation, the game follows Sir Daniel Fortesque, a skeletal knight accidentally resurrected to battle the sorcerer Zarok and save the kingdom of Gallowmere.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('medievil-ii-playstation', 'MediEvil II', 'MediEvil', '2000-05-09', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9b90.jpg', 'A port of MediEvil 2, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-8-playstation', 'Mega Man 8', 'Mega Man', '1997-01-01', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55c7.jpg', 'A gigantic space explosion sends two strange meteors crashing to Earth. The call goes out and Mega Man speeds to the site. There he sees his arch-rival, Dr. Wiley, fleeing the scene, clutching one of the mysterious metallic meteors. Now Mega Man must uncover the secret of the second meteor in a race to stay one step ahead of Dr. Wiley and his new deadly breed of super-powered robots.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legends-playstation', 'Mega Man Legends', 'Mega Man Legends', '1998-08-31', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1ls.jpg', 'THE BLUE BOMBER BLASTS INTO A WHOLE NEW DIMENSION
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-misadventures-of-tron-bonne-playstation', 'The Misadventures of Tron Bonne', 'Mega Man Legends', '2000-04-30', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pmx.jpg', 'The other side of Mega Man Legends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legends-2-playstation', 'Mega Man Legends 2', 'Mega Man Legends', '2000-10-24', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7t7d.jpg', 'Mega Man, Roll, and all your favorites are back in this all new 3-D adventure! Far away, in an isolated wasteland, a mysterious girl and an infamous treasure have been discovered. It''s the legendary "Sealed Key," rumored to unlock an even greater mystery known as the Great Legacy. What power does the Great Legacy hold? Now, a raced unfolds as Mega Man and his friends embark on a journey which will alter their destinies forever.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x4-playstation', 'Mega Man X4', 'Mega Man X', '1997-09-25', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar91.jpg', 'Battle armies of Maverick Reploid Robots while mastering all-new strategic moves like the Air Hover and Zero''s Saber Tactic system. Discover a myriad of power-ups, secret rooms, extra weapons and invincible vehicles to take on 8 all new X-Hunter Bosses. And for the first time, play as Mega Man X or battle with his mighty partner Zero in 2 separate adventures. Mega Man X4 - now you can be a hero, or a Zero!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x5-playstation', 'Mega Man X5', 'Mega Man X', '2001-02-01', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co558j.jpg', 'Mega Man returns for more wild action in MEGA MAN X5. This time around, terrorists have attacked an asteroid colony and turned off its artificial gravity. Now, it is up to Mega Man and his friend Zero to defeat the terrorists, turn the gravity on, and keep the colony from crashing into the Earth. The gameplay is what fans of the series have come to expect: Mega Man must use his blasters and bombs to make his way through eight levels of running, jumping, and shooting action. If you decide to play as Zero, you will have to use a plasma sword and some cunning to get through the same levels. In either case, the characters will have to face tough bosses that have unique abilities. Once a boss is defeated, Mega Man and Zero can utilize the boss''s talents. Only Mega Man and Zero can save the colony and the Earth in MEGA MAN X5.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x6-playstation', 'Mega Man X6', 'Mega Man X', '2001-12-04', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co558x.jpg', 'Mission Critical... Zero is Missing... Search and Rescue!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-playstation', 'Metal Gear Solid', 'Metal Gear', '1998-10-21', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpao.jpg', 'Metal Gear Solid, original released for Windows PC''s in 2000, is based off the Japanese only release, Metal Gear Solid: Integral. While keeping some of the new additions, inducing the bonus VR Missions, Very Easy difficulty and First Person mode, other features were removed, including from the original PlayStation game, due hardware limitations of the platform.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-vr-missions-playstation', 'Metal Gear Solid: VR Missions', 'Metal Gear', '1999-09-25', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s8n.jpg', 'Metal Gear Solid: VR Missions is an add-on disk that includes 300 missions, ranging from missions that are more advanced levels of the training missions in MGS to solving mysteries.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-vol-1-playstation', 'Namco Museum Vol. 1', 'Namco Museum', '1996-07-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co726t.jpg', 'The original Japanese versions of Namco Museum Battle Collection were released in two volumes.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-vol-2-playstation', 'Namco Museum Vol. 2', 'Namco Museum', '1996-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2c4s.jpg', 'Take a trip down memory lane and relive the magical times of the 8-Bit era with a collection of Namco’s hits and long-lost treasures in Namco Museum Archives Volume 2.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-vol-3-playstation', 'Namco Museum Vol. 3', 'Namco Museum', '1997-01-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ejt.jpg', 'The third PlayStation volume contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-vol-4-playstation', 'Namco Museum Vol. 4', 'Namco Museum', '1997-06-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ejv.jpg', 'Volume 4 for the PlayStation features:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-vol-5-playstation', 'Namco Museum Vol. 5', 'Namco Museum', '1997-11-26', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ejw.jpg', 'Volume 5 for the PlayStation features:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-abe-s-oddysee-playstation', 'Oddworld: Abe''s Oddysee', 'Oddworld', '1997-09-18', 'PlayStation', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co89fk.jpg', 'Oddworld: Abe''s Oddysee is the first game set in the fictional Oddworld universe. It is a platformer with puzzle-solving elements, focusing on the portrayal of a weak, underpowered character in a grim and hostile world, who has to rely on his cunning to outwit enemies and overcome hazards. The game has pre-rendered background graphics and uses CG movies of similar style to advance the story between the levels.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-abe-s-exoddus-playstation', 'Oddworld: Abe''s Exoddus', 'Oddworld', '1998-11-17', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pvr.jpg', 'Abe’s peaceful retirement was shattered when visited by a vision from the Three Weirdos. Abe learned the Magog Cartel was mining Necrum, the sacred Mudokon city of the dead, to collect bones to make super-addictive SoulStorm Brew.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-playstation', 'Pac-Man World', 'Pac-Man', '1999-10-15', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oy.jpg', 'Twenty years after Pac-Man''s first adventure in Pac-Land, Pac-Man returns one day to his house only to find it deserted. Toc-Man and his ghosts have kidnapped Pac-Man''s friends, Ms. Pac-Man, Pac Jr., Baby Pac, Professor Pac, Pooka, and Chomp-Chomp the dog! Pac-Man must venture to Toc-Man''s lair on Ghost Island to rescue his friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-maze-madness-playstation', 'Ms. Pac-Man Maze Madness', 'Pac-Man', '2000-09-08', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66r6.jpg', 'Game Boy Advance port of Ms. Pac-Man: Maze Madness.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('revelations-persona-playstation', 'Revelations: Persona', 'Persona', '1996-12-14', 'PlayStation', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u0f.jpg', 'Revelations: Persona is a role-playing video game developed and published by Atlus. It is the first entry in the Persona series, itself a subseries of the Megami Tensei franchise, and the first role-playing entry in the series to be released in the west. The game has been ported to Playstation Portable with the title of Shin Megami Tensei: Persona and featured new cutscenes and a redone localization. The story focuses on a group of high school students as they are confronted by a series of supernatural incidents. After playing a fortune-telling game, the group each gain the ability to summon Personas, the multiple selves within them. Using this power under the guidance of Philemon, a benevolent being representing humanity''s subconscious, the group face off against multiple forces that threaten the world. Gameplay revolves around the characters navigating environments around their town and fighting enemies using their Personas. During the course of the game, the player can create new Personae for battle using spell cards gained in battle or by talking with enemies.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-2-eternal-punishment-playstation', 'Persona 2: Eternal Punishment', 'Persona', '2000-12-22', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yg6.jpg', 'Persona 2: Eternal Punishment is a 2000 role-playing video game by Atlus for the PlayStation. It is chronologically the third installment in the Persona series, a subseries of the Megami Tensei franchise. The game was later remade by Atlus for the PlayStation Portable. This version, released in Japan in 2012, did not receive an overseas release. In response to this, the PlayStation version was released on PlayStation Network in 2013.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-playstation', 'Quake II', 'Quake', '1999-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-playstation', 'Rayman', 'Rayman', '1995-09-09', 'PlayStation', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jo7.jpg', 'English with Rayman is an educational 2D platform game, based on the original Rayman. It was designed to teach young children the basics of the English language. It is not to be confused with Rayman Junior, which is an entirely different game. English with Rayman blends the Glade of Dreams with the real world in a way which makes little sense in the context of the series, making numerous references to real-world locations such as Ireland and Scotland. English with Rayman was adapted to teach various other languages under such names as French with Rayman.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-2-the-great-escape-playstation', 'Rayman 2: The Great Escape', 'Rayman', '2000-08-31', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54kj.jpg', 'The PC version of Rayman 2: The Great Escape retains the same level structure from the Nintendo 64 version with higher resolution graphics and a higher frame rate.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-brain-games-playstation', 'Rayman Brain Games', 'Rayman', '2001-08-11', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4915.jpg', 'Rayman Junior is an educational video game based on the original Rayman that was designed to teach children aged 6-8 years old the basics of mathematics and literacy.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-rush-playstation', 'Rayman Rush', 'Rayman', '2002-03-26', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ktp.jpg', 'Rayman Rush is a on-foot racing game developed and published by Ubisoft, based on the Rayman universe. In many ways, it is like half of a port of Rayman Arena, featuring conversions of the same race tracks, the same introduction movie and also character theme songs (it, however, lacks the battles from M, and the character roster is different). It is a 1-2 player game, and each race has 2 characters running (1 in certain game modes). The game was released 4 months after Rayman M/Arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-playstation', 'Resident Evil', 'Resident Evil', '1996-03-30', 'PlayStation', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20cp.jpg', 'Resident Evil Archives: Resident Evil is the port of the remake Resident Evil for the Wii console system.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-director-s-cut-playstation', 'Resident Evil: Director''s Cut', 'Resident Evil', '1997-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaej0.jpg', 'A port of Resident Evil: Director''s Cut, enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-playstation', 'Resident Evil 2', 'Resident Evil', '1998-01-21', 'PlayStation', 1, 0, NULL, NULL, NULL, 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-director-s-cut-dual-shock-ver-playstation', 'Resident Evil: Director''s Cut Dual Shock Ver.', 'Resident Evil', '1998-09-14', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob3dj.jpg', 'This game is a special re-release of Resident Evil: Director''s Cut with added Dual Shock analogue stick support. It also includes work-in-progress videos of the sequel Resident Evil 2 (also known as Resident Evil 1.5), which shows a very different version of the game than was actually released.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-dual-shock-ver-playstation', 'Resident Evil 2: Dual Shock Ver.', 'Resident Evil', '1999-02-28', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mjk.jpg', 'First re-release of Resident Evil 2, the Dual Shock Ver. incorporated support for the PlayStation''s DualShock analog controller and vibration functions. Also included is a new unlockable mini-game called "Extreme Battle" and a "Rookie" mode, which allows the player to start the main story with a powerful weapon with infinite ammo.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-3-nemesis-playstation', 'Resident Evil 3: Nemesis', 'Resident Evil', '1999-11-11', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobv12.jpg', 'Resident Evil 3: Nemesis remastered to be fully playable on modern PCs by Capcom and GOG. Join Jill Valentine, the survivor of the notorious disaster, as her nightmare continues. After resigning from S.T.A.R.S. Jill now prepares to head out of Raccoon City… but caught in a town crawling with zombies, more than ever she must rely on brute force and cunning to find a way to escape alive.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-survivor-playstation', 'Resident Evil Survivor', 'Resident Evil', '2000-08-30', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tp5.jpg', 'Resident Evil Survivor is the first Resident Evil title to be rendered in real time as opposed to making use of pre-rendered backdrops. Levels are explored in first person, and when enemies are encountered the press of a button will bring up a targeting reticle for shooting. As with most light-gun games there is infinite pistol ammunition available, but limited ammunition for more powerful weapons. At the end of each level two doors are presented which both lead to different levels, although all paths eventually lead to the same ending.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('saga-frontier-playstation', 'SaGa Frontier', 'SaGa', '1998-03-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2r88.jpg', 'Shape History or Be History
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('saga-frontier-2-playstation', 'SaGa Frontier 2', 'SaGa', '2000-01-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2r88.jpg', 'Shape History or Be History
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silent-hill-playstation', 'Silent Hill', 'Silent Hill', '1999-02-24', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vyq.jpg', 'Silent Hill: Origins is the fifth installment in the Silent Hill survival horror series, and a prequel to the original game. As in the previous entries, the player move back and forth between nightmare and real versions of the town, gathering items used to solve puzzles and open up new areas. Monsters of various types provide obstacles and, in series tradition, are mostly disturbingly twisted versions of humanity. The main character can fight with his bare fists or use melee weapons. Unlike previous games in the series, melee weapons break after a time. There are also one-shot items that can be thrown and several guns. There is no HUD, but the edge of the screen turns red when the protagonist is near death.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-playstation', 'Space Invaders', 'Space Invaders', '1999-01-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9n.jpg', 'Experience one of gaming''s iconic franchises in this perfect rendition of the arcade classic!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-the-dragon-playstation', 'Spyro the Dragon', 'Spyro', '1998-09-09', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob92j.jpg', 'The first game in the Spyro series has been completely remade from the ground up. It stars the title character, a young purple dragon named Spyro, and his dragonfly friend, Sparx, who must journey across the Dragon Kingdom to defeat Gnasty Gnorc, who has overtaken the 5 dragon Homeworlds by trapping the other dragons in crystal and turning their hoard of gems into an army of minions.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-2-ripto-s-rage-playstation', 'Spyro 2: Ripto''s Rage!', 'Spyro', '1999-11-02', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob92k.jpg', 'Spyro has been brought to the land of Avalar to defeat the evil sorcerer Ripto who has brought war to Avalar’s Homeworlds. Each Homeworld is being held captive by Ripto and his minions, and it''s up to Spyro to defeat them and bring peace to Avalar’s realms.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-year-of-the-dragon-playstation', 'Spyro: Year of the Dragon', 'Spyro', '2000-10-24', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob92l.jpg', 'The Dragon Realms are celebrating the ‘Year of the Dragon’ when a mysterious cloaked figure emerges to steal all the Dragon Eggs. Under the spell of the evil Sorceress, an army of Rhynocs is now guarding the helpless eggs in the Forgotten Realms. With new and old friends, Spyro is on a quest to recover the lost eggs, defeat the Rhynoc army and stop the evil Sorceress.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-rebel-assault-ii-the-hidden-empire-playstation', 'Star Wars: Rebel Assault II: The Hidden Empire', 'Star Wars', '1995-11-01', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zio.jpg', 'Star Wars: Rebel Assault II - The Hidden Empire is the sequel to Star Wars: Rebel Assault. This time, however, the story is not related to the original movies. The story opens in the vicinity of the Dreighton Nebula, where Rookie One is investigating disappearances of Rebel spacecraft near Dreighton, a region rich with mythology about vanishing spacecraft.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-dark-forces-playstation', 'Star Wars: Dark Forces', 'Star Wars', '1996-11-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zdy.jpg', 'The Empire stretches its evil clutches across the galaxy, consuming planets with devastating results. Through many struggles, the Rebel Alliance has learned of a new Imperial battle station, the Death Star, with enough power to destroy an entire planet.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-masters-of-ter-s-k-si-playstation', 'Star Wars: Masters of Teräs Käsi', 'Star Wars', '1997-10-31', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rey.jpg', 'Star Wars: Masters of Teräs Käsi is a fighting game released for PlayStation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-the-phantom-menace-playstation', 'Star Wars: Episode I – The Phantom Menace', 'Star Wars', '1999-09-14', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba6s.jpg', 'Star Wars Episode I: The Phantom Menace is an adventure video game released by LucasArts in 1999. It is based on the film of the same title.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-jedi-power-battles-playstation', 'Star Wars Episode I: Jedi Power Battles', 'Star Wars', '2000-04-04', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav0d.jpg', 'The game follows the plot of Star Wars Episode I: The Phantom Menace. Players can choose from one of five prequel-era Jedi and run, jump, slash, and use the Force through the game''s ten levels, starting on the Trade Federation Battleship and ending with the battle against Darth Maul on Naboo.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-demolition-playstation', 'Star Wars: Demolition', 'Star Wars', '2000-11-12', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ca.jpg', 'Experience Star Wars: Demolition originally released on the PlayStation console, enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-back-to-nature-playstation', 'Harvest Moon: Back to Nature', 'Story of Seasons', '2000-11-22', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ubz.jpg', 'Natsume''s farm simulation series makes its debut on the PlayStation with Harvest Moon: Back to Nature. It is the first Harvest Moon game for a non-Nintendo console. Starting with a few rudimentary implements and very little money, players begin the arduous task of reviving their grandfather''s farm and thereby claiming their place as its rightful heir.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-destiny-playstation', 'Tales of Destiny', 'Tales', '1998-09-30', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa12s.jpg', 'Tales of Destiny is a follow-up to Tales of Phantasia. Like its predecessor, it has the structure of traditional Japanese role-playing games, but substitutes turn-based combat for action-oriented one. Battles take place on separate side-scrolling screens and resemble those of a fighting game. The player controls the main hero, navigating him on the battle screen and performing various attacks and combos. Other party members are controlled by the game''s AI, but it is possible to pause the battle at any time and assign new combat style to any one of them.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-eternia-playstation', 'Tales of Eternia', 'Tales', '2001-09-10', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaaed.jpg', 'Tales of Eternia is an action japanese role playing game, with real time battle scenes (combos and spells can be assigned to the face buttons). It is a port of the original PS1 game, which was localized as Tales of Destiny II in the US (not to be confused with the Japanese Exclusive title Tales of Destiny 2, an actual sequel to Tales of Destiny)
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-plus-playstation', 'Tetris Plus', 'Tetris', '1996-10-18', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9idl.jpg', NULL, 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-next-tetris-playstation', 'The Next Tetris', 'Tetris', '1999-06-16', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fum.jpg', 'If you think you''ve mastered Tetris then think again! Now there''s The Next Tetris, a revolutionary twist on the classic puzzle game. More features, more challenging, and more addictive than ever. The Next Tetris - it''ll blow your mind!', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-playstation', 'Tomb Raider', 'Tomb Raider', '1996-11-14', 'PlayStation', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-ii-playstation', 'Tomb Raider II', 'Tomb Raider', '1997-11-21', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3whn.jpg', 'Tomb Raider II is the second game of the Tomb Raider games series. It is an action game with platforming and puzzle-solving elements, similar in concept and gameplay to its predecessor. Most of the gameplay consists of traversing hazardous 3D levels utilizing Lara''s athletic skills and solving environmental puzzles. The sequel puts more emphasis on fighting enemies, adding many human foes to the mix. Additional weapons include a harpoon gun, a grenade launcher, and an M16 rifle. Automatic pistols replace the magnums from the first game.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-iii-playstation', 'Tomb Raider III', 'Tomb Raider', '1998-11-20', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3h9u.jpg', 'Tomb Raider III: Adventures of Lara Croft is a platform and third-person shooter game developed by Core Design and published by Eidos Interactive. It is the third installment in the Tomb Raider series and the sequel to Tomb Raider II. The gameplay system is similar to the one implemented in the previous game. Lara''s abilities include running, jumping, climbing, swimming, rolling, crouching, crawling, sprinting, and swinging on bars and vines. A few new types of hazards have been added in this installment, including cold water in which Lara can swim for a limited amount of time, dangerous underwater creatures (such as piranhas), and the treacherous quicksand, which will swallow the heroine if the player isn''t careful and fast enough to prevent her from falling into it.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-the-last-revelation-playstation', 'Tomb Raider: The Last Revelation', 'Tomb Raider', '1999-11-22', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3hbt.jpg', 'Tomb Raider IV: The Last Revelation is the fourth game of the Tomb Raider games series, it plays very similar to the previous games in the series but some new things have been added to the game. The biggest addition is that now rather large parts of the game consist of several interconnected levels sometimes explored in any order, with puzzles in one level often requiring that some actions are done in other levels. The new additions to Lara''s arsenal are a revolver and a bow with several sets of arrows including exploding and poisonous ones.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-chronicles-playstation', 'Tomb Raider Chronicles', 'Tomb Raider', '2000-11-21', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fnm.jpg', 'A remaster of the original Tomb Raider: Chronicles and the ability to toggle between original and remastered graphics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('vagrant-story-playstation', 'Vagrant Story', NULL, '2000-05-16', 'PlayStation', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rso.jpg', 'Adventure into a world of unparalleled depth and danger with SquareSoft''s Vagrant Story. In this sweeping dungeon-crawling epic you play as Ashley Riot, a young assassin and spy for the organization known as Riskbreakers. Your goal is to unravel a deep and twisted plot and come to terms with the recent death of your wife and child. If this sounds a bit too cerebral never fear. Your path to recapturing your sense of humanity hinges on the destruction of countless vicious monsters and the exploration of dark and dangerous dungeons. Vagrant Story is awash in gorgeous scenery and features designs from Yasumi Matsuno and Akihiko Yoshida, the acclaimed artists and creators behind Final Fantasy Tactics.', 'NA', 29);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warhawk-playstation', 'Warhawk', 'Warhawk', '1995-11-10', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9j6j.jpg', 'Warhawk, released as AirAssault in Japan, is a futuristic arcade-style flight-combat game where the player flies a VTOL aircraft. The player maneuvers with 360 degrees of flight control through six levels. Weapons include fire-off lock-ons, rockets, multi-fire swarmers, and plasma cannons. The game has no multiplayer capabilities and does not feature DualShock or analog controller support.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenogears-playstation', 'Xenogears', NULL, '1998-10-20', 'PlayStation', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8ei.jpg', 'Xenogears Blends Authentic RPG Gameplay with Exquisite Hand-Drawn and Computer-Generated Animation in a Grand Science Fiction Tale. An intricate storyline involving many human and non-human characters will prove to captivate audiences of all ages.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-2-playstation-2', 'Ape Escape 2', 'Ape Escape', '2003-06-30', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhl.jpg', 'Ape Escape 2 is the sequel to Ape Escape. In this platform game it''s your goal to catch all the apes jumping, walking and flying around the diverse levels the game has to offer.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-pumped-primed-playstation-2', 'Ape Escape: Pumped & Primed', 'Ape Escape', '2004-10-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co686a.jpg', 'Ape Escape: Pumped & Primed takes you into a computer-generated world for more great Ape Escape action! Mysterious monkeys are appearing all over, while the heroes fight for their survival!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-3-playstation-2', 'Ape Escape 3', 'Ape Escape', '2006-01-17', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6b7x.jpg', 'Kei and Yumi take the lead as the new heroes. Their quest is to capture all 400 monkeys. You control either Kei or Yumi. The gameplay involves using various methods and weapons to catch them all. The game has many levels with different themes, such as a Haunted Castle, a Racing level, Jungle settings, TV studios and other settings. You can slow the animals down with various objects such as a stun club or a slingback shooter, and then you can capture them with a net.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-playstation-2', 'Beyond Good & Evil', 'Beyond Good & Evil', '2003-11-11', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n6b.jpg', 'Beyond Good & Evil is an action-adventure game with elements of puzzle-solving and stealth-based games. The player controls the protagonist, Jade, from a third-person perspective. Jade can run, move stealthily, jump over obstacles and pits, climb ladders, push or bash doors and objects, and flatten herself against walls. As Jade, the player investigates a number of installations in search of the truth about a war with an alien threat.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('capcom-classics-collection-playstation-2', 'Capcom Classics Collection', 'Capcom Classics Collection', '2005-09-27', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaskp.jpg', 'Capcom serves up a collection of classic games in Capcom Classics Collection. You can relive more than 20 classic titles including 1942, Final Fight, Ghosts ''n Goblins, and Commando. The games can be played in either one- or two-player mode. Capcom Classics Collection also includes bonus material, such as remixed soundtracks, game tips, and original artwork.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('capcom-classics-collection-vol-2-playstation-2', 'Capcom Classics Collection Vol. 2', 'Capcom Classics Collection', '2006-11-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5tsl.jpg', 'Capcom Classics Collection Vol. 2 reacquaints players with the revolutionary games of their time while providing countless rounds of quarter-free entertainment. Each treasured favourite contains bountiful bonus features including remixed soundtracks, original art and history that will leave everyone wanting for more. Homes will turn into virtual arcade halls as this 20-in-1 compilation will have players flashing back to the good old days and introduce to a new generation the titles that helped define Capcom''s legacy as a leading worldwide developer and publisher.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lament-of-innocence-playstation-2', 'Castlevania: Lament of Innocence', 'Castlevania', '2003-10-21', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1oth.jpg', 'Leon Belmont, an eleventh-century nobleman and knight of the clergy, is about to be wed when his fiancée, Sara Trantoul, suddenly disappears. Leon embarks on an epic journey to bring her back, unaware that a growing evil looms like a shadow over his quest. The majestic tale of Castlevania and the true origins of the Belmont clan of vampire-hunters is about to unfold.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-curse-of-darkness-playstation-2', 'Castlevania: Curse of Darkness', 'Castlevania', '2005-11-01', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1otg.jpg', 'Castlevania: Curse of Darkness is a direct sequel to Castlevania III: Dracula''s Curse. The game differs from its predecessor in a number of ways, including a more complex, action-adventure style of gameplay featuring character growth based on accumulated experience points. Master the unique new skills of Devil Forgery to develop and enhance Innocent Devils - allies that will help to conquer enemies, evade traps and solve challenging puzzles.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-shattered-soldier-playstation-2', 'Contra: Shattered Soldier', 'Contra', '2002-10-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1otr.jpg', 'In A.D. 2642, Earth remains scarred from previous alien conflicts as environmental problems grow beyond humanity''s control. 80% of the planet''s population was completely devastated by a malfunctioning hyper-magnetic weapons grid during development. Bill Rizer, the hero of the Alien Wars, was held responsible for the incident, as well as for murdering his partner, Lance Bean, who reportedly tried to stop him. He was given a sentence of 10,000 years in cryogenic prison.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neo-contra-playstation-2', 'Neo Contra', 'Contra', '2004-10-19', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5a67.jpg', 'Neo Contra is the sequel to Contra: Shattered Soldier. The game is a 3-D Shooter with lots of action and huge boss battles. Unlike Shattered Soldiers this game has a top-down perspective. The game is set in the future with Bill Razer''s return. He teams up with a samurai, Genbei Jaguer Yagyu. The game takes about two hours to beat but will take you several tries to make it there.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-the-wrath-of-cortex-playstation-2', 'Crash Bandicoot: The Wrath of Cortex', 'Crash Bandicoot', '2001-10-29', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55ex.jpg', 'Crash Bandicoot: The Wrath of Cortex is the fourth mainline series game and the first to feature Crash Bandicoot on the PlayStation 2. It was later ported to the GameCube and Xbox, making it his first multiplatform appearance. The player controls Crash and his younger sister Coco who must gather 25 crystals and defeat the main antagonists of the story, Doctor Neo Cortex and his new super weapon Crunch Bandicoot. Much of the game takes place in a Virtual Reality Hub System created by Coco to help Crash gather the crystals. The gameplay is similar to the older games of the series.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-nitro-kart-playstation-2', 'Crash Nitro Kart', 'Crash Bandicoot', '2003-11-11', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pya.jpg', 'Crash Bandicoot returns to the karting scene with a host of other characters from the adventure series, and this time they have both Neo Cortex and Emperor Velo to worry about. Velo has taken the crew to a remote planet, forced to race for their lives against Neo Cortex and his many evil doers.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-twinsanity-playstation-2', 'Crash Twinsanity', 'Crash Bandicoot', '2004-09-28', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55if.jpg', 'Crash Twinsanity is the fifth mainline series game of the Crash Bandicoot series where Crash and the villain Cortex are forced into partnership. Each character occupies the same screen but they run along on different planes. Crash''s gameplay is mostly the same as before, he can still do his trademark spin attack, double jump and body slam moves. The originality comes in his duo with Dr. Cortex, as he can throw him to places he can''t reach himself or use him as a hammer to slap enemies. The consistent conflict between both heroes causes many funny situations.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-tag-team-racing-playstation-2', 'Crash Tag Team Racing', 'Crash Bandicoot', '2005-10-19', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7occ.jpg', 'Crash Bandicoot returns for high adrenaline racing, bending the rules of the track in Ebeneezer Von Clutch''s condemned arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-playstation-2', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-04', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-mind-over-mutant-playstation-2', 'Crash: Mind over Mutant', 'Crash Bandicoot', '2008-10-07', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3n2m.jpg', 'Crash: Mind Over Mutant is the sequel to Crash of the Titans and the seventh Crash Bandicoot series game. The game uses many of the same mechanics as its predecessor with a few changes. Rather than having twenty linear platforming levels to complete in sequence, Mind Over Mutant features eight distinct locations for Crash to explore and travel between as the story progresses. The player can complete missions given by non-playable characters and discover collectibles through the levels.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-cloud-playstation-2', 'Dark Cloud', 'Dark Cloud', '2001-05-29', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhm.jpg', 'BUILD your world. INVENT your weapons. CREATE your adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-cloud-2-playstation-2', 'Dark Cloud 2', 'Dark Cloud', '2003-02-17', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhm.jpg', 'BUILD your world. INVENT your weapons. CREATE your adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-vengeance-playstation-2', 'Batman: Vengeance', 'DC', '2001-10-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h0x.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-shadow-of-apokolips-playstation-2', 'Superman: Shadow of Apokolips', 'DC', '2002-09-25', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dze.jpg', 'Based on the Superman Animated Series, you play as Superman saving citizens in Metropolis and battling villains like Lex Luthor, Metallo, Livewire, Parasite and Darseid. It uses cel-shaded graphics and voice-actors from the tv series.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-rise-of-sin-tzu-playstation-2', 'Batman: Rise of Sin Tzu', 'DC', '2003-10-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc6.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('catwoman-playstation-2', 'Catwoman', 'DC', '2004-07-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3t.jpg', 'Catwoman is an action-adventure video game based on the 2004 film of the same name based on the fictional character. It features the likeness of the film''s lead actress Halle Berry, while the character''s voice is provided by actress Jennifer Hale.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('constantine-playstation-2', 'Constantine', 'DC', '2005-02-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qyl.jpg', 'Indie MMORPG game, Constantine! Do Adventure And be strong! The Constantine is a world that exists inside Nathan''s tree. After spring, summer, autumn and winter, the world goes to sleep.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-begins-playstation-2', 'Batman Begins', 'DC', '2005-06-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xux.jpg', 'Game Boy Advance port of Batman Begins.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teen-titans-playstation-2', 'Teen Titans', 'DC', '2006-05-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ubh.jpg', 'A game based on the "Teen Titans Go!" animated series. It follows the main character, Robin, as he seeks to be the best figure fighter in Jump City, a fictional city in the DC Universe.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-returns-playstation-2', 'Superman Returns', 'DC', '2006-11-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2des.jpg', 'Inspired by the Warner Bros. Pictures feature film and more than 60 years of DC Comics'' lore. As the Man of Steel, you’ll hone your unworldly super powers such as Flight, X-Ray Vision, Heat Vision, Super Hearing, Super Strength, Super Speed, and Super Breath to fight villains that only Superman can defeat.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-heroes-playstation-2', 'Justice League Heroes', 'DC', '2006-11-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxy.jpg', 'The PlayStation Portable version of Justice League Heroes.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-playstation-2', 'Deus Ex', 'Deus Ex', '2002-03-26', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/hwxtk1k0z5rhfqcxxzeg.jpg', 'Deus Ex is one of the most influential games of all time. A mix of RPG and FPS elements that has often been imitated, but never bettered, no game allows the user a greater freedom to play their own way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-playstation-2', 'Devil May Cry', 'Devil May Cry', '2001-10-16', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95yo.jpg', 'A 3D version of Devil May Cry 3D, a mobile game based on Devil May Cry 3: Dante''s Awakening.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-2-playstation-2', 'Devil May Cry 2', 'Devil May Cry', '2003-01-25', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3diu.jpg', 'Devil May Cry 2 is the sequel to Devil May Cry. From the start of the game, the player controls Dante or his new partner Lucia through various levels as they battle waves of demons. This game features an Amulet system, with different parts being acquired throughout the levels that can be equipped by accessing the pause menu. The different parts of the amulet can be equipped to change aspects of the characters Devil Triggers form like elemental moves, time stop abilities, faster movement, flight abilities, etc.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-3-dante-s-awakening-playstation-2', 'Devil May Cry 3: Dante''s Awakening', 'Devil May Cry', '2005-03-01', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u6u.jpg', 'Devil May Cry 3: Dante''s Awakening is a prequel to the first Devil May Cry. The game plays very differently from its predecessors, as it puts much more emphasis on style rather than simple demon slaying. As such, combat is much more intense and faster than before. An all-new Style system that allows you to select your fighting style has also been incorporated.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-viii-journey-of-the-cursed-king-playstation-2', 'Dragon Quest VIII: Journey of the Cursed King', 'Dragon Quest', '2005-11-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xc0.jpg', 'This is a portable version of the classic RPG, with added content and other 3DS enhancements.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drakengard-playstation-2', 'Drakengard', 'Drakengard', '2004-03-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4agx.jpg', 'Drakengard follows the story of a kingdomless prince named Caim who fights for the Union against the Empire. Under the Union''s protection are the Hierarchs and the Goddess, currently Caim''s sister Furiae, who is a human manifestation of one of the four seals that protect the world from being broken. As the game begins, Cain is fatally wounded in a battle with the Empire. Encountering a captured Red Dragon who is also near death, Caim makes a fateful choice. In exchange for both their lives, the Red Dragon and Caim will enter a pact. This pact will forever chain their lives to one another and link their souls, at the cost of something irreplaceable. Recharged with the fires of a Dragon, Caim''s vengeance burns over the enemy...
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drakengard-2-playstation-2', 'Drakengard 2', 'Drakengard', '2006-02-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25ox.jpg', 'Drakengard 2 is a direct sequel to the original Drakengard: the story revolves around Nowe, a boy raised by the dragon Legna, fighting against a tyrannical faction of Knights, encountering characters from the previous game and becoming entangled in the fate of the world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-dolphin-defender-of-the-future-playstation-2', 'Ecco the Dolphin: Defender of the Future', 'Ecco the Dolphin', '2002-02-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53la.jpg', 'At the dawn of the 30th Century, dolphins and humans had been together in a cross-species society for 500 years. Together, they had set out to explore space, offering peace and friendship to all who would welcome it. But space had its dangers; a violent species known as the Foe decided to conquer Earth. However, the dolphins and humans drove them to the brink of defeat, and so the Foe sought vengeance on Earth. The few caretaker dolphins who had been left behind on Earth were not entirely defenseless; they were protected by their creation called the Guardian—a gigantic, sentient being made of a crystalline substance which projected a forcefield over the entire planet. Undeterred, the Foe made suicide attacks on the field, searching for a weak point.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-play-playstation-2', 'EyeToy: Play', 'EyeToy', '2003-11-04', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2acp.jpg', 'EyeToy: Play is a video game for the PlayStation 2, released in 2003. It was the first game to make use of the PlayStation 2''s video camera accessory, EyeToy. The game was initially packaged with the EyeToy when the accessory was first released. It features twelve mini-games to choose from. This game, and all other EyeToy titles, are played by moving one''s body. The motion is detected by the USB camera. The software recognizes pixel changes in the video image and compares the proximity of the change to other game objects to play the game. Users who get a high score get to take a photo to tease other players.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-groove-playstation-2', 'EyeToy: Groove', 'EyeToy', '2004-04-20', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/fg99lfywfcq0m7pde92a.jpg', 'In this game, you are given many popular songs to choose from and dance to. Since this is the Eye Toy we are talking about, it is much more interactive. As lights shoot at buttons around the screen, you touch the buttons. Songs include:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-antigrav-playstation-2', 'EyeToy: AntiGrav', 'EyeToy', '2004-11-09', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x6q.jpg', 'EyeToy: AntiGrav is a airboarding game made by Harmonix for the PS2 EyeToy.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-play-2-playstation-2', 'EyeToy: Play 2', 'EyeToy', '2005-08-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5y3b.jpg', 'EyeToy: Play 2 is the sequel to the first EyeToy: Play game and includes 12 new mini-games to play using the EyeToy USB camera. Games include Mr Chef (making burgers for customers), Table Tennis (playing table tennis against AI opponent), Goal Attack (being a goal keeper) and many more. There are also over 75 bonus games to try out future possibilities of EyeToy technology.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-operation-spy-playstation-2', 'EyeToy: Operation Spy', 'EyeToy', '2005-11-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sn8.jpg', 'Use the EyeToy camera to play out the role of a spy. Mission include stealthy sky diving, code breaking, face matching, and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eyetoy-kinetic-playstation-2', 'EyeToy: Kinetic', 'EyeToy', '2005-11-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ky7.jpg', 'A fitness game that utilizes the EyeToy camera (including a wide-angle lens attachment) to allow players to work out in interactive games, work on posture and balance, and tone their body with conditioning exercises. Features include Aero Motion and Combat, Mind and Body Zone, and The Toning Zone. The game features design input from Nike.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-brotherhood-of-steel-playstation-2', 'Fallout: Brotherhood of Steel', 'Fallout', '2004-01-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ybr.jpg', 'This is a Tactical Squad-Based Combat comes to the Fallout Universe. You are the wretched refuse. You may be born from dirt, but we will forge you into steel. You will learn to bend; if not you, will you break. In these dark times, the Brotherhood - your Brotherhood - is all that stands between the rekindled flame of civilization and the howling, radiated wasteland.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-playstation-2', 'Final Fantasy X', 'Final Fantasy', '2001-12-17', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tr1.jpg', 'Final Fantasy X is the tenth main installment in the FF series and the first title released on sixth-generation consoles. It was also the first game to feature fully three-dimensional areas rather than including pre-rendered backdrops, and the first to include voice acting. Final Fantasy X tells the story of a star blitzball player, Tidus, who journeys with a young and beautiful summoner named Yuna on her quest to save the world of Spira from an endless cycle of destruction wrought by the colossal menace Sin.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-2-playstation-2', 'Final Fantasy X-2', 'Final Fantasy', '2003-11-18', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x4s.jpg', 'Final Fantasy X-2 is the direct sequel to Final Fantasy X, developed and published by Square Enix. It was the first direct sequel game in the Final Fantasy series and the first to feature an all-female playable cast. It also returned to the job system not seen in the main series since Final Fantasy V.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xi-playstation-2', 'Final Fantasy XI', 'Final Fantasy', '2004-03-23', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tpl.jpg', 'Final Fantasy XI R was a remake of the 2002 MMORPG Final Fantasy XI for mobile devices.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dirge-of-cerberus-final-fantasy-vii-playstation-2', 'Dirge of Cerberus: Final Fantasy VII', 'Final Fantasy', '2006-08-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co205e.jpg', 'Dirge of Cerberus: Final Fantasy VII is an action role-playing third-person shooter. As the first shooter game in the Final Fantasy series, the action is viewed from an over-the-shoulder perspective similar to Resident Evil 4, although players can switch to a first-person perspective if they wish. Defeating enemies yields EXP, and at the end of each stage, the player can either use that EXP to level up, increasing Vincent''s stats, or convert it to Gil (the in-game currency), which can then be used to purchase items and equipment upgrades.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xii-playstation-2', 'Final Fantasy XII', 'Final Fantasy', '2006-10-31', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rhx.jpg', 'The game takes place in the fictional land of Ivalice, where the empires of Archadia and Rozarria are waging an endless war. Dalmasca, a small kingdom, is caught between the warring nations. When Dalmasca is annexed by Archadia, its princess, Ashe, creates a resistance movement. During the struggle, she meets Vaan, a young adventurer who dreams of commanding an airship. They are quickly joined by a band of allies; together, they rally against the tyranny of the Archadian Empire.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-playstation-2', 'God of War', 'God of War', '2005-03-22', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobkt6.jpg', 'God of War is the sequel to God of War III as well as a continuation of the canon God of War chronology. Unlike previous installments, this game focuses on Norse mythology and follows an older and more seasoned Kratos and his son Atreus in the years since the third game. It is in this harsh, unforgiving world that he must fight to survive… and teach his son to do the same.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-ii-playstation-2', 'God of War II', 'God of War', '2007-03-13', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dik.jpg', 'God of War II, an action-adventure hack-and-slash video game, was developed by Santa Monica Studio and published by Sony Computer Entertainment (SCE). Initially launched for the PlayStation 2, it serves as the second installment in the God of War series, the sixth in chronological order, and a sequel to 2005''s God of War. The game is rooted in Greek mythology and unfolds in ancient Greece, revolving around the theme of vengeance. The protagonist, Kratos, is the new God of War, having defeated the former, Ares. However, Kratos is betrayed by Zeus, the King of the Olympian gods, who not only strips him of his godhood but also kills him. Dragged slowly to the Underworld, Kratos is rescued by the Titan Gaia, who guides him to seek out the Sisters of Fate. These entities have the power to enable time travel, allowing Kratos to prevent his betrayal, and ultimately seek revenge on Zeus.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-iii-playstation-2', 'Grand Theft Auto III', 'Grand Theft Auto', '2001-10-22', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb8.jpg', 'Featuring a fully 3-D living city, a combination of narrative driven and non-linear gameplay and a completely open environment, Grand Theft Auto III represents a huge leap forward in interactive entertainment. For the first time, players are put at the heart of their very own gangster movie, and let loose in a fully-realised 3 dimensional city, in which anything can happen and probably will.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-vice-city-playstation-2', 'Grand Theft Auto: Vice City', 'Grand Theft Auto', '2002-10-29', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co565f.jpg', 'In the year 1986, Tommy Vercetti is heavily indebted to his mafia superiors after a drug deal gone awry, but his dreams of taking over Vice City (based on Miami) push him down a different path. Featuring a wide variety of vehicles and weapons, radio stations playing hit songs from the era and an intense atmosphere, GTA: Vice City is an open-world sandbox satire of ''80''s Miami.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-san-andreas-playstation-2', 'Grand Theft Auto: San Andreas', 'Grand Theft Auto', '2004-10-26', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb9.jpg', 'Returning after his mother''s murder to the semi-fictional city of Los Santos (based on Los Angeles), Carl Johnson, a former gang banger, must take back the streets for his family and friends by gaining respect and once again gaining control over the streets. However, a story filled with crime, lies and corruption will lead him to trudge the entire state of San Andreas (based on California and Nevada) to rebuild his life.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-liberty-city-stories-playstation-2', 'Grand Theft Auto: Liberty City Stories', 'Grand Theft Auto', '2006-06-06', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8jav.jpg', 'In this port of Grand Theft Auto: Liberty City Stories to the PS2, PS3, IOS and Android, former trusted wise guy for the Leone family, Toni Cipriani returns home to Liberty City after spending time in hiding for killing a made man. Now, the streets of Liberty City are in turmoil, as warring families vie for control and the town begins to self-destruct under waves of political corruption, organized crime, drug trafficking and union strikes. Deranged hit men, morally depraved tycoons, cynical politicians and even his own mother stand in the way as Toni tries to bring the city under Leone family control.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-vice-city-stories-playstation-2', 'Grand Theft Auto: Vice City Stories', 'Grand Theft Auto', '2007-03-05', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lc8.jpg', 'The PlayStation Portable follow-up to Rockstar''s monumental handheld entry in the series, Grand Theft Auto: Liberty City Stories. As in Liberty City Stories, this game ventures back to the location of the second PS2 game.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guitar-hero-playstation-2', 'Guitar Hero', 'Guitar Hero', '2005-11-08', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8qmr.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guitar-hero-ii-playstation-2', 'Guitar Hero II', 'Guitar Hero', '2006-11-07', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97zc.jpg', 'Unleash your inner rock star! Unlock new songs and venues to become the ultimate rock star in Career mode, jump right in and play any song you''ve unlocked in Quickplay, or play with or against friends in Multiplayer, all right from your living room!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('half-life-playstation-2', 'Half-Life', 'Half-Life', '2001-11-11', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co779u.jpg', 'This mod is to run Half-Life 2: Update (itself a mod for the original Half-Life 2) under MMod.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ico-playstation-2', 'Ico', NULL, '2001-09-24', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7221.jpg', 'Experience the wonder and magic of one of the most beloved video games of all time, now available with full HD graphics, 7.1 surround sound, and stereoscopic 3D support.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('indigo-prophecy-playstation-2', 'Indigo Prophecy', NULL, '2005-09-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rhh.jpg', 'Indigo Prophecy is an action-adventure game that involves the player in making decisions to alter the narrative. The name change in North America was made to avoid confusion with Michael Moore''s Fahrenheit 9/11 documentary film, which was released in 2004. Indigo Prophecy introduced elements like ethical ambiguity, romance, the inability to perish, and interactive storytelling that would endure in Quantic Dream later games.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-the-precursor-legacy-playstation-2', 'Jak and Daxter: The Precursor Legacy', 'Jak and Daxter', '2001-12-03', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w7q.jpg', 'Jak and Daxter: The Precursor Legacy is a 2001 platform video game developed by Naughty Dog and published by Sony Computer Entertainment for the Sony PlayStation 2 on December 4, 2001, as the first game of the Jak and Daxter series. The game follows the protagonist, a young teenager named Jak, as he tries to help his friend Daxter after he is transformed into an "ottsel", a fictional hybrid of an otter and a weasel.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-ii-playstation-2', 'Jak II', 'Jak and Daxter', '2003-10-14', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2agi.jpg', 'Jak II is an open-world platform, third-person shooter, and an action-adventure video game. It is the second game of the Jak and Daxter series and a sequel to Jak and Daxter: The Precursor Legacy.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-3-playstation-2', 'Jak 3', 'Jak and Daxter', '2004-11-09', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6kks.jpg', 'Jak 3 is a platform game developed by Naughty Dog for Sony''s PlayStation 2 console. The game is the sequel to Jak II, and third in the series. The game features new weapons and devices, new playable areas, and a storyline that picks up after the events of the previous games. As in the other games in the series, the player takes on the dual role of recurring protagonists Jak and Daxter.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-x-combat-racing-playstation-2', 'Jak X: Combat Racing', 'Jak and Daxter', '2005-10-18', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27zt.jpg', 'After saving Haven City once again, Jak and Daxter find themselves poisoned forced into competition on the international car-racing circuit by the execution of Krew''s will.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-the-lost-frontier-playstation-2', 'Jak and Daxter: The Lost Frontier', 'Jak and Daxter', '2009-11-03', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2agh.jpg', 'Jak and Daxter: The Lost Frontier is a 2009 platform game developed by High Impact Games and published by Sony Computer Entertainment. The game is the sixth and final game in the Jak and Daxter series. The player assumes the role of Jak, the angst-ridden hero enhanced by his exposure to Light and Dark Eco.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('katamari-damacy-playstation-2', 'Katamari Damacy', 'Katamari', '2004-09-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67mq.jpg', 'The King of All Cosmos accidentally destroyed the stars and—having recovered—wants the prince to rebuild them. Unfortunately the prince stands a little less than half a foot tall, so recreating the stars will require some effort. Enter the Katamari, a sphere the prince can push around our world to “roll up” items increasing the Katamari’s size until it’s suitable for the King.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('we-love-katamari-playstation-2', 'We Love Katamari', 'Katamari', '2005-09-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6589.jpg', 'We Love Katamari Reroll + Royal Reverie is a remaster of the PS2 game We Love Katamari.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-playstation-2', 'Killzone', 'Killzone', '2004-11-02', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ko7.jpg', 'Killzone is a sci-fi-themed first-person shooter. The game''s stand-out feature is the ability to control any of the four different protagonists, each with his or her own strengths and weaknesses. Up to sixteen players could compete in the online multiplayer portion, which includes eight maps and six modes: Deathmatch, Team Deathmatch, Assault, Defend and Destroy, Supply Drop, and Domination. The online servers of the game have now been closed down.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('king-s-field-the-ancient-city-playstation-2', 'King''s Field: The Ancient City', 'King''s Field', '2002-03-25', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob3up.jpg', 'King''s Field: The Ancient City, known in Japan as King''s Field IV, is a medieval-themed first-person role playing video game produced by From Software for the PlayStation 2 in 2001. It is the fourth game in the King''s Field series and the last one released for home consoles.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-playstation-2', 'Kingdom Hearts', 'Kingdom Hearts', '2002-09-17', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8dgh.jpg', 'Kingdom Hearts brings back the gameplay elements featured in the original Kingdom Hearts, though it was developed exclusively for V Cast, Verizon Wireless''s broadband services. Sora moves similar to a tank, with one button on the control pad moving him forward, another moving him backwards, and two more turning him left or right. Even with these new controls, Sora can still perform a number of moves aside from running and jumping. He can climb trees and ladders, grasp the edges of platforms and pull himself up, lift and throw objects, and use the Keyblade to slide down zip lines.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-ii-playstation-2', 'Kingdom Hearts II', 'Kingdom Hearts', '2006-03-28', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30t1.jpg', 'Kingdom Hearts II is an action role-playing game, and the primary entry to the series since the 2002 Disney Interactive and Square collaboration. The game''s setting is a collection of various levels (referred to in-game as "worlds") that the player progresses through. As in the first game, it II allows the player to travel to locales from various Disney works, along with original worlds specifically created for the series.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-re-chain-of-memories-playstation-2', 'Kingdom Hearts Re:Chain of Memories', 'Kingdom Hearts', '2008-12-02', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8m1q.jpg', 'Kingdom Hearts Re:Chain of Memories is a full remake of Kingdom Hearts: Chain of Memories, originally released on the Game Boy Advance. It was originally remade for the PS2, and eventually remastered in the collection "Kingdom Hearts HD 1.5 ReMIX". The game was also changed in that completing the "Kingdom Hearts 358/2 Days" cutscenes would unlock additional Enemy Cards that would have been unlocked in the original by having save data from "Kingdom Hearts II: Final Mix"', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-racers-2-playstation-2', 'Lego Racers 2', 'Lego', '2001-09-27', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xvv.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('soccer-mania-playstation-2', 'Soccer Mania', 'Lego', '2002-06-18', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i98.jpg', 'Soccer Mania is a Sports game, developed by Kitty Group and published by Epic Sony Record, which was released in 1992.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drome-racers-playstation-2', 'Drome Racers', 'Lego', '2002-11-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5yv6.jpg', 'Tensions are high as you await the first stage of the Drome Championship.You''ve trained for the intensity of Multi-Challenge Racing; each race a seamless set of stages, mixing tracks from realistically stunning City, Mountain, and Canyon environments.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('island-xtreme-stunts-playstation-2', 'Island Xtreme Stunts', 'Lego', '2002-11-30', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4fgf.jpg', 'Island Xtreme Stunts is a mixture of different genres in a single game. The player explores a LEGO-based environment in an open world format: ride a skateboard, drive, fly and pilot a range of vehicles all whilst performing stunts and tricks while taking on the bad guy, Brickster. The player is cast as Pepper Roni, a lead stuntman in a big movie production set on LEGO Island.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-playstation-2', 'Bionicle', 'Lego', '2003-10-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3den.jpg', 'LEGO Bionicle is an action-adventure platformer in an isometric perspective. The player controls Takua, a villager on the island of Mata Nui through a series of linear levels that take place in the 6 different biomes across the island. This is the only canon handheld Bionicle game, and seems to serve as a prelude to the Mata Nui Online Game and Mata Nui Online Game II.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-video-game-playstation-2', 'Lego Star Wars: The Video Game', 'Lego', '2005-04-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xvm.jpg', 'Take LEGO Star Wars mobile with the official port for the Game Boy Advance. Experience Star Wars in LEGO form while platforming through The Phantom Menace, Attack of the Clones and Revenge of the Sith.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-playstation-2', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-heroes-playstation-2', 'Bionicle Heroes', 'Lego', '2006-11-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525j.jpg', 'Bionicle Heroes DS is a classic first-person shooter. As a nameless Matoran, you''ll travel across 25 themed levels (including jungles, lava-worlds, ancient underground temples) discovering new weapons and new robotic foes to blast apart. Along the way, you''ll use the masks'' powers to survive the hostile environments as well as collect gears and robot parts to solve simple puzzles by assembling LEGO-style ramps, bridges, and doorways.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-playstation-2', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-playstation-2', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-playstation-2', 'Lemmings', 'Lemmings', '2006-10-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dawn-of-mana-playstation-2', 'Dawn of Mana', 'Mana', '2007-05-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bfz.jpg', 'Dawn of Mana, as the title suggests, focuses on the origins of Square''s Secret of Mana action RPG series, touching upon the genesis of both the Mana Tree and the Sword of Mana. The game takes place on the once idyllic island named Illusia, where the life-giving Mana Tree has dried up and turned to stone. In desperate need of a hero, Illusia calls upon one of its own to save the land from a dire threat. Players will guide this young warrior on an epic quest that will have them adventuring across a completely 3D world for the first time in the series. From majestic plains to towering mountains, the interactive environments in Dawn of Mana offer an assortment of places to visit, characters to meet, and creatures to battle. The combat system once again unfolds in real-time, with players able to jump, slash with a sword, fire projectiles, and even swing a whip that can attach itself to objects.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-playstation-2', 'Spider-Man', 'Marvel', '2002-04-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('men-in-black-ii-alien-escape-playstation-2', 'Men in Black II: Alien Escape', 'Marvel', '2002-06-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ox0.jpg', 'Men in Black 2: Alien Escape is a fast-paced third-person perspective action game liberally infused with the trademark humor of the smash 1997 movie and the upcoming sequel. The game is divided into five distinct episodes, including a Nuclear Station, the Docks and the streets of Manhattan. All episodes include numerous levels and challenges to complete prior to progressing through the game.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blade-ii-playstation-2', 'Blade II', 'Marvel', '2002-09-03', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ot7.jpg', 'For countless generations there was very little to stand between vampires and their human prey--until now. In Blade II, you are a vampire hunter who possesses all the strengths of a vampire, and none of its weaknesses. Skilled in martial arts, guns, and swordplay, you must protect humans from the hungering darkness. Keep the evil forces at bay with your 360-degree combat system and unstoppable rage powers. High-tech weaponry, destructive rage abilities, and over-the-top finishing moves turn every enemy encounter into an action-packed bloodbath.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-next-dimension-playstation-2', 'X-Men: Next Dimension', 'Marvel', '2002-10-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzm.jpg', 'X-Men: Next Dimension is a fighting game and the third game in the X-Men: Mutant Academy game series. Next Dimension expands upon the concept of the first two games by adding several new characters, 3-D maps, and a story mode, which allows the player to fight a series of battles in between short movies that move the plot along. The plot of the story mode is loosely based on the comic story "Operation: Zero Tolerance".', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-2-new-age-of-heroes-playstation-2', 'Marvel vs. Capcom 2: New Age of Heroes', 'Marvel', '2002-11-19', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95z7.jpg', 'The iOS port of Marvel vs. Capcom 2 introduces a new feature called Variable System that allows the player to tag in other team members at any time.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x2-wolverine-s-revenge-playstation-2', 'X2: Wolverine''s Revenge', 'Marvel', '2003-04-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gx1.jpg', 'Logan was surgically implanted with the virtually unbreakable adamantium skeleton that made him into Wolverine, one of the world''s most famous X-Men. Now, more than 30 years later, Wolverine has discovered that he was also implanted with something else: a viral time-bomb that will render him lifeless in 48 hours. The clock is ticking. The antidote needs to be found quickly.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hulk-playstation-2', 'Hulk', 'Marvel', '2003-05-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ovx.jpg', 'Based after the events of the blockbuster movie (starring Eric Bana), you play Dr. Bruce Banner and his alter ego, green giant The Hulk. After fighting his way through the first year of his new identity, Bruce and The Hulk must now face a new enemy, The Leader, who wants to use the same gamma technology that created The Hulk in Bruce to develop an army of giants.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-playstation-2', 'Spider-Man 2', 'Marvel', '2004-06-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-playstation-2', 'X-Men Legends', 'Marvel', '2004-09-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6b64.jpg', 'The N-Gage port of X-Men Legends.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-punisher-playstation-2', 'The Punisher', 'Marvel', '2005-01-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p2u.jpg', 'Crime is everywhere on the streets of New York City. As Frank "the Punisher" Castle, it is your job to clean them up. However, there seem to be bigger things at hand...', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-playstation-2', 'Fantastic Four', 'Marvel', '2005-06-27', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nah.jpg', 'The Fantastic Four video game, released in 1997 for the PlayStation, is a beat ''em-up action game based on the Marvel Comics superhero team. Developed by Probe Entertainment and published by Acclaim Entertainment, the game features playable characters Mr. Fantastic, The Invisible Woman, The Human Torch, The Thing, and She-Hulk, each with unique abilities. A version for the Sega Saturn was planned but ultimately cancelled. Players engage in combat, solve puzzles, and navigate obstacles across various levels, drawing from the rich lore of the Fantastic Four comics.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-ultimate-destruction-playstation-2', 'The Incredible Hulk: Ultimate Destruction', 'Marvel', '2005-08-23', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzh.jpg', 'The Incredible Hulk: Ultimate Destruction, released in 2005, is an action-adventure video game developed by Radical Entertainment and published by Vivendi Universal Games (VU Games). The game centres around the Marvel Comics superhero, the Hulk, and features an open world with destructible environments. The storyline depicts the Hulk being unconsciously guided by his human alter-ego, Bruce Banner, and his psychotherapist, Leonard Samson. They influence him to construct a device aimed at healing Banner''s psyche and preventing the emergence of a darker personality. In addition to progressing through the main narrative, players can undertake side missions and acquire new abilities for the Hulk.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-nemesis-rise-of-the-imperfects-playstation-2', 'Marvel Nemesis: Rise of the Imperfects', 'Marvel', '2005-09-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1jr.jpg', 'Marvel Nemesis: Rise of the Imperfects pits fierce Marvel superheroes against each other in a 3D fighting game. You can assume control of heroes such as the Punisher, Spider-Man, and Captain America, and duel with them in interactive and destructible environments. A new team of superheroes called the Imperfects joins the mayhem. You can play in single-player story mode to unlock collectible awards, or you can play against other gamers in multiplayer modes.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-ii-rise-of-apocalypse-playstation-2', 'X-Men Legends II: Rise of Apocalypse', 'Marvel', '2005-09-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pf0.jpg', 'X-Men Legends II: Rise of Apocalypse is an action role-playing game and a sequel to X-Men Legends. The player controls a party of four characters, though only one at a time can be controlled directly. Besides switching the characters for combat purposes, the player is often obliged to do so, because some of the tasks in the game require the specific abilities of a certain mutant. For example, Iceman can put out the fire, Magneto can generate a metal bridge across a gap, etc. Most of the time, however, is spent in combat, collecting loot and acquiring experience points. Unlike the first game, items dropped by enemies are random. The character will level up, become stronger, and learn new skills. The player can opt to allocate all the experience and skill points manually.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-spider-man-playstation-2', 'Ultimate Spider-Man', 'Marvel', '2005-09-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/lsjknidfrlnz2cintrkr.jpg', 'Help Spider-Man save Harry Osborn from the Venom symbiote.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-playstation-2', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-playstation-2', 'Marvel: Ultimate Alliance', 'Marvel', '2006-10-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-rider-playstation-2', 'Ghost Rider', 'Marvel', '2007-02-13', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7sv8.jpg', 'The Ghost Rider feature film follows superstar motorcycle stunt rider Johnny Blaze as he strikes a deal with the vile Mephistopheles for the most precious of commodities - his immortal soul. Now Johnny Blaze is forever destined to ride night after night as the host to the powerful supernatural entity known as the Ghost Rider. The video game continues the storyline, dropping players into the role of Blaze as he is transformed into a super hero with powers to avenge any evil he encounters. Featuring many of the characters and motorcycles from the comic book and movie, Ghost Rider engages gamers in an immersive, supernatural third person world with a seamless blend of hand-to-hand combat and high-speed motorcycle action.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-playstation-2', 'Spider-Man 3', 'Marvel', '2007-05-04', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-rise-of-the-silver-surfer-playstation-2', 'Fantastic Four: Rise of the Silver Surfer', 'Marvel', '2007-06-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x77.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-friend-or-foe-playstation-2', 'Spider-Man: Friend or Foe', 'Marvel', '2007-10-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h33.jpg', 'Defeat Spider-Man’s most famous enemies, like Venom, Green Goblin, and Doc Ock to add them to your epic array of playable sidekicks in this movie trilogy inspired adventure. Experience ground-breaking Co-operative Multiplayer, as Spider-Man or a sidekick, in exotic spots around the globe, including Tokyo, Egypt and Nepal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-playstation-2', 'Iron Man', 'Marvel', '2008-05-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-playstation-2', 'The Incredible Hulk', 'Marvel', '2008-06-05', 'PlayStation 2', 0, 0, NULL, NULL, NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-the-amazing-allies-edition-playstation-2', 'Spider-Man: Web of Shadows – The Amazing Allies Edition', 'Marvel', '2008-10-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co71as.jpg', 'Spider-Man: Web of Shadows - Amazing Allies Edition is a 2D side-scroller with 3D graphics. The story is similar to the seventh-generation console versions. A break-off piece of Venom''s symbiote begins infecting New Yorkers and it is up to Spider-Man to save the city. He can switch between the back and red suits at any time, and each has its own move set and abilities.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-playstation-2', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-playstation-2', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-playstation-2', 'Marvel Super Hero Squad', 'Marvel', '2009-10-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e7b.jpg', 'Marvel Super Hero Squad is an action beat-em-up game for one to four players that is based on the animated Marvel TV series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('max-payne-playstation-2', 'Max Payne', 'Max Payne', '2001-12-07', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lcl.jpg', 'Max Payne 2 is a third-person shooter, in which the player assumes the role of Max Payne, but also plays as Mona Sax in a few levels. Initially, the player''s weapon is a 9mm pistol. As they progress, players access other weapons including other handguns, shotguns, submachine guns, assault rifles, sniper rifles, and hand-thrown weapons. To move the game along, the player is told what the next objective is through Max''s internal monologue, in which Max iterates what his next steps should be.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('max-payne-2-the-fall-of-max-payne-playstation-2', 'Max Payne 2: The Fall of Max Payne', 'Max Payne', '2003-12-02', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lcl.jpg', 'Max Payne 2 is a third-person shooter, in which the player assumes the role of Max Payne, but also plays as Mona Sax in a few levels. Initially, the player''s weapon is a 9mm pistol. As they progress, players access other weapons including other handguns, shotguns, submachine guns, assault rifles, sniper rifles, and hand-thrown weapons. To move the game along, the player is told what the next objective is through Max''s internal monologue, in which Max iterates what his next steps should be.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('maximo-ghosts-to-glory-playstation-2', 'Maximo: Ghosts to Glory', 'Maximo', '2002-02-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4d4s.jpg', 'The game is based in the Ghosts''n Goblins universe and features original character designs by Japanese illustrator Susumu Matsushita.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('maximo-vs-army-of-zin-playstation-2', 'Maximo vs. Army of Zin', 'Maximo', '2004-01-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobk0j.jpg', 'The story of the game follows on from Maximo: Ghosts to Glory, with Maximo still searching for his lost love, Sophia. He is again accompanied by Grim (a Grim Reaper). However, their search is interrupted as a series of mechanical creatures start to attack villages and slaughter the village folk. These creatures are the Army of Zin, an ancient army powered by lost souls, who were supposedly locked in the vault of Castle Hawkmoor after the last battle with them 500 years ago. However, they are now free, due to the actions of the mysterious warlord, Lord Bane.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-anniversary-collection-playstation-2', 'Mega Man Anniversary Collection', 'Mega Man', '2004-06-23', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7154.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x7-playstation-2', 'Mega Man X7', 'Mega Man X', '2003-10-14', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7otp.jpg', 'The plot of Mega Man X7 takes place in the 22nd century, during an age when humans coexist with humanoid robots called "Reploids". As some Reploids participate in violent and destructive crime, a police organization called the "Maverick Hunters" has been established to stamp out this activity. Maverick crime is rising in newly constructed cities. As this new crime wave hits, X retires, tired from the never-ending battles. A new group of vigilantes, Red Alert, is introduced. One of their members, Axl, decides he has had enough of their "murdering" and tries to leave the group. Red, the group''s leader, is angered by Axl deserting, and goes on a rampage to get Axl back.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-command-mission-playstation-2', 'Mega Man X: Command Mission', 'Mega Man X', '2004-09-21', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coblt2.jpg', 'Mega Man X: Command Mission, known as Rockman X Command Mission in Japan, is a spin-off game in the Mega Man X series. It was released in 2004 on both the PlayStation 2 and the Nintendo GameCube, making it the second-to-last game in the Mega Man X series to be released. Unique to the series, it is an RPG featuring turn-based combat and an extensive story. It plays quite similarly to Capcom''s signature Breath of Fire series in a number of ways, due to the shared development team. Chronologically, it is currently the Mega Man X game set furthest in the future, taking place sometime in the twenty-third century (22XX time period); however, it is also set in an alternate timeline outside of the main storyline of the Mega Man series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x8-playstation-2', 'Mega Man X8', 'Mega Man X', '2004-12-07', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8sfu.jpg', 'A fan game made by AlyssonDaPaz. Bringing the original PS2 classic, MegaMan X8 back to its 16-bit roots! Play as X and blast through a familiar yet fresh experience!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-collection-playstation-2', 'Mega Man X Collection', 'Mega Man X', '2006-01-10', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2030.jpg', 'Mega Man X Collection contains the first six games in the Mega Man X series. Mega Man X and Mega Man X2 are based on their appearances on the SNES. Mega Man X3, also originally on the SNES, is based on its 32-bit update for the PlayStation, Sega Saturn, and PC. The remaining three games are based on their PlayStation renditions. All the games now use save files, including the first few titles that originally necessitated a password for continuation, though upon loading save data, the player is still greeted with the old, fully-functional password entry screen, complete with the correct password to access the saved game. Mega Man Battle & Chase is a game that is unlocked after completing the first three games. It is a classic series kart-racing game previously unreleased in North America. Mega Man X Collection also contains unlockable artwork and music.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-2-sons-of-liberty-playstation-2', 'Metal Gear Solid 2: Sons of Liberty', 'Metal Gear', '2001-11-13', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5e1c.jpg', 'Metal Gear Solid 2: Sons of Liberty is the sequel to the espionage action game Metal Gear Solid. Much of the gameplay remains the same, as the game''s protagonist has to sneak past guards, outsmart them using various gadgets and defeat the tricky boss enemies. The game expanded its predecessor''s cover mechanic, with Solid Snake or Raiden able to take cover behind walls or objects and pop out to shoot at enemies, while the improved enemy AI allowed enemies to also take cover from the player. Metal Gear Solid 2 is considered to be one of the greatest video games of all time, as well as a leading example of artistic expression in video games.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-2-substance-playstation-2', 'Metal Gear Solid 2: Substance', 'Metal Gear', '2003-03-03', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5eg1.jpg', 'Metal Gear Solid 2: Substance is a re-vamped and revised edition of the original Metal Gear Solid 2: Sons of Liberty, in which Solid Snake must recover the stolen Metal Gear Ray from a group of terrorists bent on using its power for unthinkable reasons. Along with the original espionage shooter comes a collection of 200 VR missions. Missions range from killing certain targets and using particular weapons, as well as seeing the world of Solid Snake from different perspectives and styles, with first-person target modes and a variety mode including crazy characters of different shapes and sizes. Also included are various alternative missions, ranging from the protagonist sneaking around and snapping photos of targets to bomb disposal, all out destruction, and more.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-3-snake-eater-playstation-2', 'Metal Gear Solid 3: Snake Eater', 'Metal Gear', '2004-11-17', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co99jz.jpg', 'This is the steelbook version of Metal Gear Solid 3: Snake Eater, official titled Limited Metal Edition. This version of the game is not particularly common, possibly because there is no difference between this and the original release apart for the metal case.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-3-subsistence-playstation-2', 'Metal Gear Solid 3: Subsistence', 'Metal Gear', '2006-03-14', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vd6.jpg', 'Metal Gear Solid 3: Subsistence continues the Metal Gear Solid series tradition of follow-up enhanced, international version releases.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-fellowship-of-the-ring-playstation-2', 'The Lord of the Rings: The Fellowship of the Ring', 'Middle-earth', '2002-10-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lum.jpg', 'J.R.R. Tolkien''s Middle-earth is a land of beauty, magic, and darkness. In The Lord of the Rings: The Fellowship of the Ring, you follow Tolkien''s narrative from the Shire to the halls of Moria, and finally to the banks of the River Anduin. Gameplay alternates between melee, archery, sorcery, and stealth as you control Frodo, Gandalf, and Aragorn. Join this band of heroes in their quest to destroy the One Ring, which contains all the power of the dark lord Sauron.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-two-towers-playstation-2', 'The Lord of the Rings: The Two Towers', 'Middle-earth', '2002-10-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxb.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-return-of-the-king-playstation-2', 'The Lord of the Rings: The Return of the King', 'Middle-earth', '2003-11-04', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hd8.jpg', 'An unlicensed Lord of the Rings Game using the engine from Pocky and Rocky with Becky. Despite the name, the game is vaguely based on the first Lord of the Rings movie, The Fellowship of the Ring. Each level starts off with a screenshot from the movie, though the actual levels and bosses have little resemblance', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-hobbit-playstation-2', 'The Hobbit', 'Middle-earth', '2003-11-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3li.jpg', 'Step into the hairy hobbits'' feet of Bilbo Baggins in Vivendi Universal Games'' take on Tolkien''s prequel to the massive Lord of the Rings trilogy.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-third-age-playstation-2', 'The Lord of the Rings: The Third Age', 'Middle-earth', '2004-11-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20oi.jpg', 'The Lord of the Rings: The Third Age for Game Boy Advance is a turn-based tactics game released in 2004. The game consists of 2 campaigns (Good and Evil). In each campaign the player chooses a commander. As the player completes missions and progresses through the campaign, they are able to use experience points to purchase skills and equipment upgrades in order to enhance the performance of their primary and secondary heroes.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-aragorn-s-quest-playstation-2', 'The Lord of the Rings: Aragorn''s Quest', 'Middle-earth', '2010-09-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9nie.jpg', 'The NDS/PSP ports features slightly different HUD, and the NDS version uses the second screen as a map.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-playstation-2', 'Monster Hunter', 'Monster Hunter', '2004-09-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lh7.jpg', 'The popular fantasy action franchise Monster Hunter is now one of the most iconic gaming series in the world selling over 21 million copies worldwide since the series began in 2004. Players take on the role of a hunter and are sent to explore a settlement within the Monster Hunter universe, completing quests on their journey to seek and slay monsters whilst improving their skills and earning equipment upgrades. With many challenging monsters and over 200 quests the latest edition to the series is set to be the most expansive offering to date. Monster Hunter 3 Ultimate utilizes the functionalities of the Nintendo 3DS system to provide players with a truly intuitive hunting experience. The touch screen feature allows players to quickly access in-game books, weapons, field maps and mini games whilst the high quality graphics 3D visuals of Nintendo 3DS powered by the latest iteration of Capcom''s MT Framework deliver a unique and stunning world for players to explore. Taking advantage of the portability of Nintendo 3DS, players can exchange their guild card that contains all their hunter''s information with other players via StreetPass. Players can experience the world of Monster Hunter alone or in four player local play using Nintendo 3DS. Finding nearby hunters to adventure on quests with is now even easier via the local Nintendo 3DS search feature. Wii U players will be able to enjoy the hunt with Nintendo 3DS players via a local wireless connection. Gamers that own both a Wii U and Nintendo 3DS can take advantage of the inter compatibility of save data between the two consoles, taking the hunt from the living room wherever they go.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-playstation-2', 'Namco Museum', 'Namco Museum', '2001-12-04', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhd.jpg', 'Popular Namco games collected on Nintendo Switch.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-50th-anniversary-playstation-2', 'Namco Museum 50th Anniversary', 'Namco Museum', '2005-08-30', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz6.jpg', 'Includes 14 Classic Arcade Hits
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-playstation-2', 'Ōkami', 'Ōkami', '2006-09-19', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53vn.jpg', 'This edition includes the following PS4:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('onimusha-warlords-playstation-2', 'Onimusha: Warlords', 'Onimusha', '2001-03-14', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4r13.jpg', 'This enhanced HD version of Onimusha: Warlords now supports 16:9 wide screen resolution as well as the old 4:3 ratio. Improved controls now allow players to move and fight with analog-stick precision. The Japanese voices have been re-recorded for this remaster, and the brand new soundtrack promises to be even more spectacular than the original.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-2-playstation-2', 'Pac-Man World 2', 'Pac-Man', '2002-02-24', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8l2.jpg', 'PAC-MAN WORLD 2 Re-PAC modernizes, updates, and enhances the fan favorite 3D Platforming adventure in nearly every way! Venture across PAC-LAND to reclaim the golden fruit and put a stop to the ghosts and their dastardly boss, Spooky!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-fever-playstation-2', 'Pac-Man Fever', 'Pac-Man', '2002-09-03', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz7.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-3-playstation-2', 'Pac-Man World 3', 'Pac-Man', '2005-11-15', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc8.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-rally-playstation-2', 'Pac-Man World Rally', 'Pac-Man', '2006-08-22', 'PlayStation 2', 0, 0, NULL, NULL, NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-3-playstation-2', 'Shin Megami Tensei: Persona 3', 'Persona', '2007-08-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5mo6.jpg', 'Shin Megami Tensei: Persona 3 is a role-playing video game developed by Atlus. In the game, the player takes the role of a male high-school student who joins the Specialized Extracurricular Execution Squad (SEES), a group of students investigating the Dark Hour, a time period between one day and the next that few people are aware of. During the Dark Hour, the player enters Tartarus, a large tower containing Shadows, creatures that feed on the minds of humans. To fight the Shadows, each member of SEES is able to summon a Persona, a manifestation of a person''s inner self. In addition to the standard elements of role-playing games, Persona 3 includes elements of simulation games, as the game''s protagonist progresses day by day through a school year, making friends and forming relationships that improve the strength of his Personas in battle.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-3-fes-playstation-2', 'Shin Megami Tensei: Persona 3 FES', 'Persona', '2008-04-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6j8n.jpg', 'Shin Megami Tensei: Persona 3 FES is an add-on disc for Persona 3 containing updates to the original game (referred in the game as "The Journey"), as well as a new epilogue story, The Answer, in which the player controls Aigis. The subtitle "Fes" is derived from the word "festival".', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-4-playstation-2', 'Shin Megami Tensei: Persona 4', 'Persona', '2008-12-09', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u07.jpg', 'An entry in the JRPG/visual novel hybrid Persona series in which the player has to harness the power of Personas and fight entities called Shadows by forging bonds with the locals of Inaba, a rural Japanese town thrown into unrest by inexplicable murders committed under cover of foggy weather and rumours of a television channel said to broadcast mysterious images on rainy nights.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-sands-of-time-playstation-2', 'Prince of Persia: The Sands of Time', 'Prince of Persia', '2003-11-10', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4t8l.jpg', 'Deceived by the treacherous Vizier, I was led to unleash the Sands of Time curse upon the Sultan''s kingdom. With little but an ancient dagger and a devious princess to aid me, I must undo my fatal mistake. Mine is a fight for survival… not glory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-warrior-within-playstation-2', 'Prince of Persia: Warrior Within', 'Prince of Persia', '2004-12-02', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52j9.jpg', 'Prince of Persia: Warrior Within is the mobile J2ME port of the PC/console game of the same title.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-two-thrones-playstation-2', 'Prince of Persia: The Two Thrones', 'Prince of Persia', '2005-12-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav9r.jpg', 'In the mobile version of the last game in the trilogy, the Prince returns to Babylon after the events of the previous game, only to find out that a vizier has taken his throne. This new ruler has captured the Babylonian women. You need to set them free and defeat the vizier at the same time. Exposure to the sands of time, however, has awakened an evil presence inside the Prince, which manifests itself as the Dark Prince. During the game, you will often morph into the other presence, whose only goal it to reclaim the throne, the populace be damned.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-playstation-2', 'Psychonauts', 'Psychonauts', '2005-06-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7ms.jpg', 'Psychonauts is a platform-adventure game developed by Double Fine Productions and released in 2005. It follows Razputin “Raz” Aquato, a young psychic who runs away from the circus to attend a summer camp for aspiring psychonauts. Players explore imaginative levels set inside the minds of different characters, each reflecting their mental states. Gameplay combines platforming, combat, and the use of psychic abilities such as telekinesis and levitation. The game was praised for its creativity, humor, and distinctive art style.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-iii-revolution-playstation-2', 'Quake III Revolution', 'Quake', '2001-03-26', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ra2.jpg', 'Quake III Revolution features several elements adopted from Team Arena, along with a more mission-based single-player mode. It features split-screen multiplayer for up to 4 players, but lacks online play.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-playstation-2', 'Rayman Raving Rabbids', 'Rabbids', '2006-12-05', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pj8.jpg', 'Rayman Raving Rabbids was originally developed as a 3D platform game, under the working title Rayman 4. It was announced by Ubisoft on the 11th of April, 2006, shortly after the cancellation of Phoenix Studio''s unrelated Rayman 4 project. Under development by Ubisoft Montpellier, the game was to be a free-roaming action platforming game, in which the player would control Rayman as he battled against an invading army of Rabbids. The game was announced for the PlayStation 3, Xbox 360, Windows, and the Nintendo Wii, which was then codenamed the ''Revolution''.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-playstation-2', 'Ratchet & Clank', 'Ratchet & Clank', '2002-11-04', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230q.jpg', 'This trilogy of Ratchet & Clank classics contains Ratchet & Clank, Ratchet & Clank: Going Commando, and Ratchet & Clank: Up Your Arsenal – all remastered in 1080p with additional upgrades such as Trophy and 3D support.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-going-commando-playstation-2', 'Ratchet & Clank: Going Commando', 'Ratchet & Clank', '2003-11-11', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6okp.jpg', 'A remaster of the PlayStation 2 Ratchet & Clank: Going Commando, featuring 720p HD with support for 3D graphics and PlayStation Network trophies.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-up-your-arsenal-playstation-2', 'Ratchet & Clank: Up Your Arsenal', 'Ratchet & Clank', '2004-11-02', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1oyn.jpg', 'A 3D platform video game and the third installment in the Ratchet & Clank series. The gameplay is similar to previous games in the series but introduces new features such as a new control system and more levels in the upgrade system for weapons. It follows Ratchet and Clank''s adventure through a fictional universe to defeat a robotic villain, Dr. Nefarious, who intends to destroy all organic life. Characters such as Dr. Nefarious and Sasha, a Cazar starship captain who helps Ratchet throughout the game, are introduced, and a number of characters return from the original Ratchet & Clank.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-deadlocked-playstation-2', 'Ratchet: Deadlocked', 'Ratchet & Clank', '2005-10-25', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6okr.jpg', 'A high-definition remaster version for the PlayStation 3, featuring 1080p upscaling.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-size-matters-playstation-2', 'Ratchet & Clank: Size Matters', 'Ratchet & Clank', '2008-03-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coankv.jpg', 'Ratchet & Clank: Size Matters (known as Ratchet & Clank 5 in Japan) is a 2007 platformer video game developed by High Impact Games and published by Sony Computer Entertainment for the PlayStation Portable and PlayStation 2. The game is the first Ratchet & Clank title on the PSP handheld. Development company High Impact Games was spawned from the original Ratchet & Clank developer, Insomniac Games. The story is about Ratchet and Clank as they are interrupted from their vacation to search for a kidnapped girl and encounter a forgotten race known as the Technomites.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('secret-agent-clank-playstation-2', 'Secret Agent Clank', 'Ratchet & Clank', '2009-05-26', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8uc6.jpg', 'A port of Secret Agent Clank, a platform video game developed by High Impact Games and published by Sony Computer Entertainment, released for the PlayStation Portable (PSP) in 2008.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-2-revolution-playstation-2', 'Rayman 2: Revolution', 'Rayman', '2001-01-30', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3k61.jpg', 'Ubisoft''s personable and popular cartoon hero is back and more ambitious than ever in the PlayStation 2-exclusive re-imagining, Rayman 2: Revolution. Now in full 3D and blending humor, suspense, and blinding speed, Rayman must escape an intergalactic zoo by using the powers of his still-imprisoned friends to open the door to an even greater power to free them. Unique to the PS2 version of the game are a number of brand new stages, a harder difficulty level, and a progressive upgrade system that gives Rayman a number of abilities not found in other iterations.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-m-playstation-2', 'Rayman M', 'Rayman', '2002-09-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctf.jpg', 'Developed by Ubisoft Montpellier and Pastagames, Rayman Mini follows Rayman on a legendary journey as he has been reduced to the size of ant! To undo this spell, Rayman will travel through a macro-photographic world, encountering friendly allies and defeating epic bosses along the way.', NULL, 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-3-hoodlum-havoc-playstation-2', 'Rayman 3: Hoodlum Havoc', 'Rayman', '2003-03-18', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jnb.jpg', 'This port of Rayman 3 released for the DigiBlast handheld console is based on the Game Boy Advance port of the game, but has less stages and no multiplayer. Every pseudo-3D stage were removed.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-revolver-playstation-2', 'Red Dead Revolver', 'Red Dead', '2004-05-04', 'PlayStation 2', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lcn.jpg', 'Red Dead Revolver is a 2004 action-adventure game developed by Rockstar San Diego and published by Rockstar Games. It is the first entry in the Red Dead series and was released for the PlayStation 2 and Xbox in May 2004.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-code-veronica-x-playstation-2', 'Resident Evil – Code: Veronica X', 'Resident Evil', '2001-08-21', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vzv.jpg', 'Resident Evil Code: Veronica X is a port of the original game with additional content comprised of improved graphics along with an extra nine minutes of cutscenes. The character Steve had his hairstyle changed to have a noticeable fringe, and no longer proudly shows his forehead. This change was made to all cutscenes that feature him, as well as to the family photograph he carries with him. Apart from these changes, the game is almost the same as the original one.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-dead-aim-playstation-2', 'Resident Evil: Dead Aim', 'Resident Evil', '2003-06-17', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w5n.jpg', 'Resident Evil: Dead Aim is a survival-horror game released exclusively for the PlayStation 2 under the Gun Survivor title, which was used for several games made for the Namco light gun controllers. The game is played in two camera angles: the player moves from a third-person perspective while walking, which changes to a first-person perspective while aiming the gun. You''ll pick up several guns through the course of the game, including a magnum, a shotgun, and an assault rifle. But like in other Resident Evil games, zombies are difficult to put down permanently and ammo can be very scarce.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-outbreak-playstation-2', 'Resident Evil Outbreak', 'Resident Evil', '2004-03-31', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w5p.jpg', 'Resident Evil Outbreak is a survival-horror game released exclusively for the PlayStation 2. The gameplay is similar to the previous Resident Evil games and consists mainly of exploring, solving puzzles, finding items and surviving. It was the first Resident Evil game with multiplayer capability, using the PlayStation 2''s online network. Up to four players could participate simultaneously in one scenario. Alternately, in single-player mode, the player is accompanied by two AI-controlled characters.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-outbreak-file-2-playstation-2', 'Resident Evil Outbreak: File #2', 'Resident Evil', '2005-04-26', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w5q.jpg', 'Resident Evil Outbreak File #2 is a survival-horror game released exclusively for the PlayStation 2 and a sequel to Resident Evil Outbreak, which was originally envisioned as a much larger game before being cut into multiple releases. The same eight characters from the first title return with similar abilities, and the game takes place once again in a zombie-run Raccoon City. The new game has several new scenarios and boasts new gameplay developments for the Resident Evil series. Loading times have been reduced and while the previous Outbreak was on-line enabled in the US, this game is the first on-line Resident Evil game in Europe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-playstation-2', 'Resident Evil 4', 'Resident Evil', '2005-10-25', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wn5.jpg', 'This pack includes Resident Evil 4 and Resident Evil CODE: Veronica X.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rez-playstation-2', 'Rez', 'Rez', '2002-01-08', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co720j.jpg', 'A rail shooter with a heavy emphasis on audiovisual elements in which a hacker attempts to breach an AI integral for the continuation of the human race to prevent it from shutting down due to information overload.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unlimited-saga-playstation-2', 'Unlimited Saga', 'SaGa', '2003-06-17', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uw4.jpg', '"Unlimited SaGa" is a sequel to Square''s famous series of non-linear RPGs. Like in the early Romancing Saga games, and in Saga Frontier, you assume the role of eight main characters (selectable at the beginning of the game). The story centers around Laura, a 30-year old widow and an ex-pirate, but you view the story and make it progress differently depending on which character you have chosen, and on the decisions you take throughout the game. Each character is represented by a different kind of flower.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('romancing-saga-playstation-2', 'Romancing SaGa', 'SaGa', '2005-10-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ypx.jpg', 'A grounds-up remake of Romancing SaGa that carries over the general aesthetic and style of Unlimited SaGa, featuring changes to the battle and class systems, the removal and addition of certain characters, as well as the addition of several elements that had originally been planned for the SNES Romancing SaGa 2 (the story, however, remains largely the same).', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-playstation-2', 'Sega Superstars', 'Sega All-Stars', '2004-11-03', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ozt.jpg', 'There are a total of 12 different full games to play in the main mode of Sega Superstars:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-tennis-playstation-2', 'Sega Superstars Tennis', 'Sega All-Stars', '2008-03-18', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6p9b.jpg', 'Developed by Sumo Digital, this is the handheld port of Sega Superstars Tennis. While the core mechanics remain very similar, the game differs from the home console version in its presentation, depth, and certain elements of functionality.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-of-the-colossus-playstation-2', 'Shadow of the Colossus', NULL, '2005-10-18', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ijk.jpg', 'In a desolate land where beasts as big as mountains roam free, a lone hero and his horse must ride into the unknown on a quest for ancient power. Shadow of the Colossus, an undisputed PlayStation 2 masterpiece, is about to be reborn with the power of PlayStation 3.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silent-hill-2-playstation-2', 'Silent Hill 2', 'Silent Hill', '2001-09-25', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavaf.jpg', 'Silent Hill 2 Remake is a ground-up reimagining of the 2001 psychological horror game. It follows James Sunderland as he searches for his deceased wife in the fog-shrouded town of Silent Hill. The remake features entirely rebuilt visuals in Unreal Engine 5, over-the-shoulder gameplay, reworked combat, and new voice acting.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silent-hill-3-playstation-2', 'Silent Hill 3', 'Silent Hill', '2003-08-05', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wkq.jpg', 'This version of Silent Hill 3 is a remaster included in the Silent Hill HD Collection. The graphics have been re-mastered to 720p, the in-game voice-over was updated along with a re-mastering of the soundtrack and achievements/trophies were added.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silent-hill-4-the-room-playstation-2', 'Silent Hill 4: The Room', 'Silent Hill', '2004-09-07', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vyk.jpg', 'Silent Hill 4: The Room is the fourth installment in the Silent Hill survival horror series. The game is similar to the past entries in terms of atmosphere, never letting the player know what''s behind the next corner or down the street. Aside from the traditional third-person-view, there is now a first-person mode which is used to control the main character when he is in his apartment. Objects that can be interacted with are highlighted by eyeball icons. The previous games in the series have mostly been about exploring the town and solving puzzles, but this installment has much more combat involved. There are more enemies in a given area, spread in cramped spaces. The main character mostly uses a standard Silent Hill arsenal of weapons, such as the steel pipe, pistol and a golf club.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-playstation-2', 'The Sims', 'The Sims', '2003-01-14', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5sap.jpg', 'The Everyday Sims Bundle will transform how your Sims live day to day, from teaching life lessons to child Sims to doing their laundry!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-bustin-out-playstation-2', 'The Sims Bustin'' Out', 'The Sims', '2003-12-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5w.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-urbz-sims-in-the-city-playstation-2', 'The Urbz: Sims in the City', 'The Sims', '2004-11-09', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5s.jpg', 'Starting out as a humble window washer in the city of Miniopolis, the player is quickly embroiled in a devious plot by the greedy tycoon Daddy Bigbucks to take over the city.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-playstation-2', 'The Sims 2', 'The Sims', '2005-10-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja7.jpg', 'The Sims 2 for Nintendo DS is the first DS game of The Sims 2. Like the many of the console games it takes place in Strangetown with some of the same faces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-playstation-2', 'The Sims 2: Pets', 'The Sims', '2006-10-17', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-castaway-playstation-2', 'The Sims 2: Castaway', 'The Sims', '2007-10-22', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja9.jpg', 'Castaway is the third console spin-off of the video game The Sims 2. The Sims Castaway Stories is a similar game created for personal computers. It is the final game in the series released for the PlayStation 2 and the final game in the Sims 2 series for console.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sly-cooper-and-the-thievius-raccoonus-playstation-2', 'Sly Cooper and the Thievius Raccoonus', 'Sly Cooper', '2002-09-23', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8c2u.jpg', 'A port of Sly Cooper and the Thievius Raccoonus, enhanced with up-rendering, rewind, quick save and custom video filters.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sly-2-band-of-thieves-playstation-2', 'Sly 2: Band of Thieves', 'Sly Cooper', '2004-09-14', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94yn.jpg', 'A port of Sly 2: Band of Thieves enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sly-3-honor-among-thieves-playstation-2', 'Sly 3: Honor Among Thieves', 'Sly Cooper', '2005-09-26', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95x2.jpg', 'A port of Sly 3: Honor Among Thieves, enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-heroes-playstation-2', 'Sonic Heroes', 'Sonic the Hedgehog', '2004-01-27', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9olx.jpg', 'Sonic Heroes is an adventure and multiplatform video game in the Sonic The Hedgehog series, developed by Sonic Team and published by SEGA for the Nintendo GameCube, Sony PlayStation 2, Microsoft Xbox and Microsoft Windows PCs.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mega-collection-plus-playstation-2', 'Sonic Mega Collection Plus', 'Sonic the Hedgehog', '2004-11-02', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uz8.jpg', 'Sonic Mega Collection Plus is an update of Sonic Mega Collection for the PlayStation 2 and Xbox consoles. A Microsoft Windows version was also released in Europe and North America. This edition includes all of the games in Sonic Mega Collection, including the two Genesis games that were included in the Japanese version of Sonic Mega Collection, plus the addition of six Game Gear games.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-the-hedgehog-playstation-2', 'Shadow the Hedgehog', 'Sonic the Hedgehog', '2005-11-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4s0m.jpg', 'Shadow the Hedgehog in Sonic the Hedgehog brings the Ultimate Lifeform to South Island to put a stop to Dr. Robotnik''s Evil Plans!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-riders-playstation-2', 'Sonic Riders', 'Sonic the Hedgehog', '2006-02-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coam3h.jpg', '"Sonic Riders Plus" is a mod of the original Sonic Riders for the Gamecube that focuses on enhancing the competitive potential of the game while still remaining true to the game''s nature.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-riders-zero-gravity-playstation-2', 'Sonic Riders: Zero Gravity', 'Sonic the Hedgehog', '2008-01-08', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvm.jpg', 'Sonic Riders: Zero Gravity is a hoverboard racing video game developed by Sonic Team and published by Sega for the PlayStation 2 and Wii. It is the fifth racing game in the Sonic the Hedgehog series, and the second entry the Sonic Riders trilogy. A port for the Xbox 360 was cancelled during development, while a sequel, Sonic Free Riders, was released exclusively for that system in 2010.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-unleashed-playstation-2', 'Sonic Unleashed', 'Sonic the Hedgehog', '2008-11-18', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6p.jpg', 'Gameplay in Sonic Unleashed focuses on two modes of platforming play: fast-paced levels that take place during daytime, showcasing Sonic''s trademark speed as seen in previous games in the series, and slower, night-time levels, during which Sonic''s Werehog form emerges, and gameplay switches to an action-based, brawler style of play, in which Sonic battles Gaia enemies', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-channel-5-playstation-2', 'Space Channel 5', 'Space Channel 5', '2003-11-18', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w09.jpg', 'When the Morolians invade, ace reporter Ulala scoops the story for Space Channel 5. The hip-hopping aliens zap citizens into a hypnotic dance trance, but beat girl Ulala is their ultimate match. She busts out her grooviest attacks to free the captives and make headlines. Get down with Sega''s supernova star as she struts through the space station in style.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-channel-5-part-2-playstation-2', 'Space Channel 5: Part 2', 'Space Channel 5', '2003-11-18', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw1.jpg', 'Hey there, SpaceCats – meet Ulala, the grooviest reporter in the galaxy! She’s got attitude, and she’s got moves. Help her get the scoop on an unidentified Dance Troupe that has captured thousands of people and is forcing them to dance!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-enter-the-dragonfly-playstation-2', 'Spyro: Enter the Dragonfly', 'Spyro', '2002-11-05', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3qjh.jpg', 'Spyro: Enter the Dragonfly is the fourth game in the Spyro the Dragon series and the first Spyro game to be on the PlayStation 2 and Nintendo Gamecube. Gameplay is similar to the previous three console games. The only playable character is Spyro, however he can man several vehicles: Hunter''s Manta Ray and the UFO''s make a return appearance from Year of the Dragon, alongside two new vehicles, the tank and the Spitfire attack plane.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-a-hero-s-tail-playstation-2', 'Spyro: A Hero''s Tail', 'Spyro', '2004-11-09', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48ew.jpg', 'Spyro: A Hero''s Tail is the fifth console game in the original Spyro series and the ninth game in the series in all. Developed by Eurocom, it was the first game in the series for the Xbox, as well as the second game in the series for the PlayStation 2 and GameCube (with the former console release being the only one of the three to support widescreen). It is also the final installment in the original Spyro continuity for home consoles. This is also the first and only Spyro game to be completely produced in Europe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-a-new-beginning-playstation-2', 'The Legend of Spyro: A New Beginning', 'Spyro', '2006-10-10', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86aa.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-the-eternal-night-playstation-2', 'The Legend of Spyro: The Eternal Night', 'Spyro', '2007-10-02', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a9.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-dawn-of-the-dragon-playstation-2', 'The Legend of Spyro: Dawn of the Dragon', 'Spyro', '2008-10-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a8.jpg', NULL, 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-starfighter-playstation-2', 'Star Wars: Starfighter', 'Star Wars', '2001-02-19', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coakf1.jpg', 'Space flight arcade game based on the events of Star Wars Episode 1. The game shares a title of the home release of the same name, however is a completely unique game.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-super-bombad-racing-playstation-2', 'Star Wars: Super Bombad Racing', 'Star Wars', '2001-04-23', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47v8.jpg', 'Jar Jar throws his Bongo racing ride into warp speed with his very own exciting big-headed kart racer Star Wars: Super Bombad Racing! Everybody from Star Wars Episode I: The Phantom Menace has put their intergalactic troubles aside to enter into a wild racing adventure -- Queen Amidala, Anakin, Yoda, Obi-Wan, Sebulba, Bos Nass, Sebulba, and even Darth Maul are all out for that checkered flag. Each racer gets to ride special racing vehicles (a Pod Racer, a Sith Interceptor, a Naboo Fighter), and with the different vehicles comes individually geared racing controls.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-racer-revenge-playstation-2', 'Star Wars Racer Revenge', 'Star Wars', '2002-02-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1o.jpg', 'Star Wars: Racer Revenge is a Star Wars video game that involves high speed racing. It is the sequel to Star Wars Episode I: Racer. The story takes place eight years after The Phantom Menace, Sebulba wants revenge on Anakin Skywalker. Unlike its predecessor, the player is unable to continue racing if they crash their pod.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-starfighter-playstation-2', 'Star Wars: Jedi Starfighter', 'Star Wars', '2002-03-10', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1n.jpg', 'The game features two immediately playable craft: Nym''s starfighter, "The Havoc", which features heavy armament as a bomber, and Adi''s fighter, which features force powers such as lightning and force shield.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-bounty-hunter-playstation-2', 'Star Wars: Bounty Hunter', 'Star Wars', '2002-11-19', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8f77.jpg', 'Experience the legendary Bounty Hunter fantasy set before the events of Star Wars: Episode II - Attack of the Clones. Face off against foes and maneuver through acrobatic battles in this adaption optimized for today''s consoles and hardware.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-playstation-2', 'Star Wars: The Clone Wars', 'Star Wars', '2002-12-10', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1l.jpg', 'The Clone Wars has you deep inside the battles of the Old Republic through 16 missions, piloting a range of vehicles including speeder bikes, Republic Gunships and fighter tanks as well as the weapon of the Jedi, your lightsabre, for close combat. Whereas the Rogue Squadron series concentrated on aerial battles, The Clone Wars contains almost all ground battles. You must fight as Anakin Skywalker, Obi Wan Kenobi, Mace Windu, and others throughout the game to prevent the Confederacy from gaining a deadly weapon. Multiplayer options are also included for up to four players with game types including deathmatch, conquest, and a co-op ground and vehicle survival mode.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-playstation-2', 'Star Wars: Battlefront', 'Star Wars', '2004-09-21', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2res.jpg', 'In 2004, the original Star Wars: Battlefront came onto the scene and took gamers – and Star Wars fans – by surprise. It was an ambitious action shooter that gave players the opportunity to step into the shoes of their favorite Star Wars characters, pilot quintessential Star Wars vehicles, and relive classic Star Wars battles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-iii-revenge-of-the-sith-playstation-2', 'Star Wars: Episode III – Revenge of the Sith', 'Star Wars', '2005-05-04', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3sjo.jpg', 'The Clone Wars continue to rage between the Republic and the Separatists. Supreme Chancellor Palpatine has been taken hostage, and Obi-Wan, together with Anakin, must rescue him! The Star Wars Episode III: Revenge of the Sith games for the Game Boy Advance and Nintendo DS systems allow players to experience the stunning Jedi action of the movie. Developed by Ubisoft''s Montreal studio, each version leverages the strengths of its handheld platform to produce the ultimate Jedi action experience. The control of multiple heroes, devastating Force powers, and never-before-seen locations are just a few of the elements in store!', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-ii-playstation-2', 'Star Wars: Battlefront II', 'Star Wars', '2005-11-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1g4.jpg', 'Star Wars: Battlefront II is the sequel to Star Wars: Battlefront. It is a high-selling Star Wars video game following the many adventures of several characters. The two games are very similar, as both revolve around troopers from various factions fighting in different locales. Battlefront II, however, includes elements and missions from Star Wars: Episode III Revenge of the Sith, as well as enhanced aspects of gameplay including space combat and the ability to play as Jedi characters or other heroes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-playstation-2', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-playstation-2', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-save-the-homeland-playstation-2', 'Harvest Moon: Save the Homeland', 'Story of Seasons', '2001-11-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26e3.jpg', 'The first Harvest Moon game for the PS2 takes a little deviance from all the other games in the series. The goal this time around is to save your town from being turned into a resort next year. The game focuses more on relationships than making money - which is the goal in all other Harvest Moon games to date. You still are running a farm and must succeed in the life of a farmer, but the actual gameplay rewards those who interact with the townspeople over those who just work the fields.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-a-wonderful-life-special-edition-playstation-2', 'Harvest Moon: A Wonderful Life Special Edition', 'Story of Seasons', '2005-10-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ovr.jpg', 'Harvest Moon: A Wonderful Life will span a lifetime on the farm and follow the drama that goes with it. Not only must you build and successfully run a farm, but you must also build a successful life with family and friends! This new Harvest Moon experience will take the best qualities of the series and add more...more animals, more vegetables and more drama! What sort of life will you live?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('innocent-life-a-futuristic-harvest-moon-special-edition-playstation-2', 'Innocent Life: A Futuristic Harvest Moon (Special Edition)', 'Story of Seasons', '2008-02-12', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26oy.jpg', 'Life is good for the residents of Heartflame Island, especially since new robots and automated machines do almost all of the work. But technology is a tool--not an answer to all problems. Maybe that''s why everyone is a little uneasy about the old stories of strange magic and a prediction that Flame Mountain will erupt and destroy everything. That''s why Dr. Hope, a caring and wise old scholar has sent you, his son on a journey to the ancient ruins to try and run a farm. It is your father''s dream that you will unlock the secrets of the ancient ruins and find the meaning of "life".', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-deluxe-playstation-2', 'Super Monkey Ball Deluxe', 'Super Monkey Ball', '2005-03-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rhe.jpg', 'This game is basically a fusion of Super Monkey Ball 1 and 2 for the PS2 and XBox. All of the levels from those two games are available in this collection, and all of the minigames are already unlocked and included. Formerly only available to GameCube players, the Super Monkey Ball series has made it to the PS2 and Xbox after a wait of almost 3 and a half years.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-adventure-playstation-2', 'Super Monkey Ball Adventure', 'Super Monkey Ball', '2006-08-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzl.jpg', 'Our four heroes from Super Monkey Ball - Aiai, Meemee, Baby and Gongon - were enjoying a typical day, when they saw a flying machine crash down on a nearby island. Soon, they discovered that the mysterious Naysayers have appeared, spreading discord and unhappiness all over the island. And to top it all off, the prince and princess of the neighboring islands have gone missing on Jungle Island - if they aren''t found and returned, there''s sure to be trouble! Can our heroes restore order to Monearth?', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-legendia-playstation-2', 'Tales of Legendia', 'Tales', '2006-02-07', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p28.jpg', 'Tales of Legendia is a fantasy role-playing game that continues the Tales series of games. You can play as Senel Coolidge, who encounters a giant, mysterious ship while adrift in a small boat with his sister. As you explore the history of the ship, you will encounter epic enemies and engage them using the "X-LiMBS" battle system, which lets you fight in real time like in a fighting game. The story is beset with unique characters designed by the animator featured in Kill Bill Vol. One.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-the-abyss-playstation-2', 'Tales of the Abyss', 'Tales', '2006-10-10', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yw8.jpg', 'This entry in Namco''s popular Tales series takes place in a world where prophecies clue people in to future happenings. Tales of the Abyss boasts a revolutionary new free roaming battle system allowing players to move anywhere on the battlefield, a first in the Tales series which brings new depth to the intense, high-action battles that Tales games are knows for.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-playstation-2', 'Tom Clancy''s Splinter Cell', 'Tom Clancy''s Splinter Cell', '2003-04-08', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r1.jpg', '2D versions of the game were released for the Game Boy Advance and N-Gage (the latter as Tom Clancy''s Splinter Cell: Team Stealth Action), as well as the mobile phones version developed by Gameloft. A remastered high definition version of Tom Clancy''s Splinter Cell was released on the PlayStation 3 in September 2011. The success of the game series spawned a series of novels written under the pseudonym David Michaels.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-pandora-tomorrow-playstation-2', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow', 'Tom Clancy''s Splinter Cell', '2004-06-16', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tce.jpg', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow is a stealth video game developed and published by Ubisoft Shanghai and Ubisoft Milan, while Ubisoft Montreal, developer of the original Splinter Cell, was working on Chaos Theory. Pandora Tomorrow is the second game in the Splinter Cell series endorsed by writer Tom Clancy. The game follows the covert activities of Sam Fisher, an agent working for a black-ops branch of the National Security Agency (NSA) called "Third Echelon". Sam Fisher is voiced by Michael Ironside. Dennis Haysbert voices the character Irving Lambert, Fisher''s boss, making this the only time he is not voiced by Don Jordan. Lalo Schifrin provides the theme music for the game. A remastered high-definition version of Tom Clancy''s Splinter Cell: Pandora Tomorrow was announced for the PlayStation Network for the PlayStation 3 on December 20, 2010.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-chaos-theory-playstation-2', 'Tom Clancy''s Splinter Cell: Chaos Theory', 'Tom Clancy''s Splinter Cell', '2005-03-28', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rb.jpg', 'Tom Clancy''s Splinter Cell: Chaos Theory is the mobile version of the console game of the same name and the fourth mobile game in the series. Like the previous games in the series it is a stealth based platform game played from a side view perspective and has similar gameplay. The player once again controls Sam Fisher who has to prevent terrorists from crashing the global stock markets and overthrow the world''s governments.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-playstation-2', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2006-10-24', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-the-angel-of-darkness-playstation-2', 'Tomb Raider: The Angel of Darkness', 'Tomb Raider', '2003-06-20', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-playstation-2', 'Tomb Raider: Legend', 'Tomb Raider', '2006-04-11', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-anniversary-playstation-2', 'Tomb Raider: Anniversary', 'Tomb Raider', '2007-06-05', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mz7.jpg', 'The Wii port of Tomb Raider: Anniversary carries over the levels and general gameplay of the other versions while incorporating motion controls. Wii-exclusive first-person puzzles include breaking through walls with a pickaxe, using a flashlight in dark areas, assembling mechanisms from pieces found around the environment, manipulating symbol-based locks and using paper and charcoal to take rubbings of puzzle-related symbols, all utilizing the Wii Remote.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-underworld-playstation-2', 'Tomb Raider: Underworld', 'Tomb Raider', '2009-03-03', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voc.jpg', 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of challenge and choice.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-evolution-playstation-2', 'Turok: Evolution', 'Turok', '2002-09-01', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p3p.jpg', 'Get locked and loaded in an exciting prequel to the Turok series. Turok: Evolution is an epic adventure set against the backdrop of living jungles, mysterious temples, and deadly dinosaurs. Battle over 32 types of dinosaurs as Tal''Set, a warrior caught in the midst of a brutal war in the Lost Land. Use your arsenal of all-new weapons including Variable Payload Cruise Missiles, Gravity Disruptor beams, and the Swarm Bore. Soar through the skies on a winged Quetzalcoatlus, or set out on foot on of the lush interactive environments. Experience an adventure before time.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-castle-wolfenstein-playstation-2', 'Return to Castle Wolfenstein', 'Wolfenstein', '2003-05-27', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xzr.jpg', 'Return to Castle Wolfenstein is a first-person shooter and a reboot of Wolfenstein 3D. The player''s arsenal includes among others a Luger, MP 40 submachine gun, Mauser rifle with sniper scope, flamethrower, dynamite and grenades. The game also features a multiplayer component in which players are split into Axis and Allies sides with each a set of objectives to complete.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenosaga-episode-i-playstation-2', 'Xenosaga Episode I', 'Xenosaga', '2003-02-25', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2606.jpg', 'Xenosaga: Episode I - Der Wille zur Macht, the first chapter of a trilogy, is a Japanese-style sci-fi role-playing game, sharing many common themes and gameplay elements with Xenogears.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenosaga-episode-ii-playstation-2', 'Xenosaga Episode II', 'Xenosaga', '2005-02-15', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2607.jpg', 'Xenosaga Episode II: Jenseits von Gut und Böse is a direct sequel to the first episode of the science-fiction RPG Xenosaga series.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xenosaga-episode-iii-playstation-2', 'Xenosaga Episode III', 'Xenosaga', '2006-08-29', 'PlayStation 2', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3fe3.jpg', 'The story of Xenosaga III starts a year after "Xenosaga II" ended. Shion has resigned from Vector Industries after learning that the company is deeply connected to the appearance of the Gnosis. She instead joins Scientia, an underground organization working to unveil Vector''s secrets in order to bring them down. Uncover the truth and save mankind in the finale of the Xenosaga series which boasts over 3 hours of movies, an updated battle system, and an improved customization feature with more in-depth character specialization and diversification and higher rewards for strategic party management. This RPG also includes an easily accessible database feature, the "Xeno Bible" and a mini-game with over 50 levels that challenges both you and your friends.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-playstation-2', 'Zone of the Enders', 'Zone of the Enders', '2001-03-26', 'PlayStation 2', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co260o.jpg', 'Take control of a fully armed prototype mechanized robot and fight off enemies during a space colony hijack in Hideo Kojima''s Zone of the Enders. In it, players become the character Leo Stenbuck, who sees the consequences of fighting first hand as he learns the true meaning of life and death. Combining state of the art PlayStation 2 graphics, tons of weapons, and an involving storyline, Zone of the Enders also provides a dynamically changing mission structure, a versus mode for two players, and a playable demo of Metal Gear Solid 2: Snake Eater in all first-run production copies.', 'NA', 30);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-the-2nd-runner-playstation-2', 'Zone of the Enders: The 2nd Runner', 'Zone of the Enders', '2003-03-10', 'PlayStation 2', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzx.jpg', 'The sequel to Zone of the Enders is based around mecha combat with the player once again controlling the "Orbital Frame" Jehuty. Unlike its prequel, the game is now centered on action elements with the player not needing to protect civilians in need and instead Jehuty contains more weaponry than in the previous game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-on-the-loose-playstation-portable', 'Ape Escape: On the Loose', 'Ape Escape', '2005-03-24', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6zpb.jpg', 'Experience Ape Escape: On the Loose originally released on the PSP system, enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ape-escape-academy-playstation-portable', 'Ape Escape Academy', 'Ape Escape', '2006-01-17', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5dym.jpg', 'Ape Escape Academy sees you taking on the role of one of the cheeky monkeys from the Ape Escape series. Choose your chimp, then prepare to tackle various classes in Academy Mode. Each ''class'' is actually a mini-game. Your goal is to complete as many mini-games as possible from the 9x9 grid, and score as many lines as you can (sort of like Noughts and Crosses). Mini-games range from mind-bending quizzes to wacky sports games, to the just plain silly, like protecting a roast banana from oncoming apes, or flying through the sky delivering parachutes to plummeting primates.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-bloodlines-playstation-portable', 'Assassin''s Creed: Bloodlines', 'Assassin''s Creed', '2009-11-17', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xia.jpg', 'Assassin’s Creed: Bloodlines on PSP is the first Assassin’s Creed game on the PSP system. It follows the story of Altair right after the events of Assassin’s Creed as Altair tracks down the last Templars who fled the Holy Land and retreated to the Island of Cyprus.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battlezone-playstation-portable', 'BattleZone', 'Battlezone', '2006-11-06', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mws.jpg', 'Battlezone is an arcade game from Atari released in November 1980. It displays a wireframe view (using vector graphics rather than raster graphics) on a horizontal black and white (with green and red sectioned color overlay) vector monitor. Due to its novel gameplay and look, this game was very popular for many years. Throughout the 1980s, Battlezone was ported to several home computer systems (usually on the Atarisoft label), including the Apple II, the Commodore 64, the Sinclair ZX Spectrum, and the Atari XEGS. The Atari ST port contains large parts of the original 6502 code which is emulated in real time. An Atari 2600 port was also released, but has colored raster graphics due to limitations and the view is behind the tank rather than inside it.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-playstation-portable', 'Bomberman', 'Bomberman', '2006-09-12', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q1m.jpg', 'Bomberman Jetters is an action RPG that could be considered the spiritual successor to Bomberman Tournament.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-the-dracula-x-chronicles-playstation-portable', 'Castlevania: The Dracula X Chronicles', 'Castlevania', '2007-10-23', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8t6b.jpg', 'Castlevania: The Dracula X Chronicles is an entirely new take at the best Castlevania game to never be released in the US, "Castlevania: Rondo of Blood". The Dracula X Chronicles brings this action/adventure franchise to the PSP system for the first time, complete with 3D graphics, enhanced gameplay and new music. Completing the Dracula X storyline, this game also includes an unlockable version of Symphony of the Night and players will also be able to unlock the original Rondo of Blood from the NEC PC Engine. Includes unlockable versions of the original "Rondo of Blood" and "Symphony of the Night" games, optimized for the PSP. Timeless side scrolling action through more than 10 gothic stages and additional hidden areas. Return to previously completed levels to find additional secrets.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-tag-team-racing-playstation-portable', 'Crash Tag Team Racing', 'Crash Bandicoot', '2005-11-10', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7occ.jpg', 'Crash Bandicoot returns for high adrenaline racing, bending the rules of the track in Ebeneezer Von Clutch''s condemned arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-playstation-portable', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-16', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-mind-over-mutant-playstation-portable', 'Crash: Mind over Mutant', 'Crash Bandicoot', '2008-10-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3n2m.jpg', 'Crash: Mind Over Mutant is the sequel to Crash of the Titans and the seventh Crash Bandicoot series game. The game uses many of the same mechanics as its predecessor with a few changes. Rather than having twenty linear platforming levels to complete in sequence, Mind Over Mutant features eight distinct locations for Crash to explore and travel between as the story progresses. The player can complete missions given by non-playable characters and discover collectibles through the levels.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-playstation-portable', 'Final Fantasy', 'Final Fantasy', '2007-06-26', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vn2.jpg', 'The Twin Pack includes Final Fantasy VII and the remastered version of Final Fantasy VIII.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-ii-playstation-portable', 'Final Fantasy II', 'Final Fantasy', '2007-07-24', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob25b.jpg', 'The WonderSwan Color version of Final Fantasy II included completely redone graphics in the manner of the 16-bit generation Final Fantasy games and includes larger character sprites, remixed music by Tsuyoshi Sekito, and full graphical backgrounds in battle mode. It is from this base that the international version of Final Fantasy II began to take shape.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-tactics-the-war-of-the-lions-playstation-portable', 'Final Fantasy Tactics: The War of the Lions', 'Final Fantasy', '2007-10-09', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qfx.jpg', 'Developed by passionate Final Fantasy Tactics fans, Final Fantasy Tactics: The Lion War of the Lions is a tactical role-playing game that serves as an enhanced, ''definitive'' port of the original Final Fantasy Tactics, incorporating content from its official remakes. It is an enhanced follow-up to their original hack, Final Fantasy Tactics: The Lion War.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crisis-core-final-fantasy-vii-playstation-portable', 'Crisis Core: Final Fantasy VII', 'Final Fantasy', '2008-03-25', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1trb.jpg', 'In CRISIS CORE, players can experience the D.M.W (Digital Mind Wave) system, which enhances the real-time battle system, allowing players to unleash special attacks or call upon various FINAL FANTASY summons. Players can also witness graphics and CG cutscenes coupled with voice acting in a 16:9 widescreen presentation, made possible by the PSP system hardware.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dissidia-final-fantasy-playstation-portable', 'Dissidia Final Fantasy', 'Final Fantasy', '2009-08-25', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co205i.jpg', 'Dissidia Final Fantasy is a 3D-arena fighting game with RPG elements featuring 20 characters, heroes and villains, from the first 10 final fantasy games summed by the god of discord and the goddess of harmony to fight over the fate of the world.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dissidia-012-final-fantasy-playstation-portable', 'Dissidia 012 Final Fantasy', 'Final Fantasy', '2011-03-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co205l.jpg', '"DISSIDIA 012[duodecim] FINAL FANTASY is the blockbuster follow-up to the smash hit DISSIDIA FINAL FANTASY, offering a winning mix of Beat ‘Em Up action and RPG depth, starring the most memorable heroes and villains from the worlds of the FINAL FANTASY series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-iv-the-complete-collection-playstation-portable', 'Final Fantasy IV: The Complete Collection', 'Final Fantasy', '2011-04-19', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ybu.jpg', 'After 20 years, Final Fantasy IV and its acclaimed sequel, The After Years, are now combined into one package as the ultimate role-playing game experience. A cast of unforgettable characters fight through one of the grandest stories ever told with stunning new graphics, a re-arranged, award-winning soundtrack, and bonus game features that provide the absolute Final Fantasy IV experience. Experience vibrant visuals and unforgettable melodies - includes all-new 2-D graphics designed for the PSP system''s 16:9 format. Also includes a new arrangement of one of the most acclaimed video game soundtracks of all time!', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-ghosts-n-goblins-playstation-portable', 'Ultimate Ghosts ''n Goblins', 'Ghosts ''n Goblins', '2006-08-29', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobe7y.jpg', 'Ultimate Ghosts ''n Goblins is the first game in the series to employ 3D graphics, while maintaining much of the 2D gameplay mechanics of the earlier games. It also marks the return of the series'' project head, Tokuro Fujiwara.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-chains-of-olympus-playstation-portable', 'God of War: Chains of Olympus', 'God of War', '2008-03-04', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qi2.jpg', 'An HD remaster of God of War: Chains of Olympus included in "God of War: Origins Collection." It features high-definition resolution, stereoscopic 3D, anti-aliased graphics locked in at 60 frames per second, DualShock 3 vibration function, and Trophies.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-ghost-of-sparta-playstation-portable', 'God of War: Ghost of Sparta', 'God of War', '2010-11-02', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qi1.jpg', 'An HD remaster of God of War: Ghost of Sparta included in "God of War: Origins Collection." It features high-definition resolution, stereoscopic 3D, anti-aliased graphics locked in at 60 frames per second, DualShock 3 vibration function, and Trophies.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-liberty-city-stories-playstation-portable', 'Grand Theft Auto: Liberty City Stories', 'Grand Theft Auto', '2005-10-24', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8jav.jpg', 'In this port of Grand Theft Auto: Liberty City Stories to the PS2, PS3, IOS and Android, former trusted wise guy for the Leone family, Toni Cipriani returns home to Liberty City after spending time in hiding for killing a made man. Now, the streets of Liberty City are in turmoil, as warring families vie for control and the town begins to self-destruct under waves of political corruption, organized crime, drug trafficking and union strikes. Deranged hit men, morally depraved tycoons, cynical politicians and even his own mother stand in the way as Toni tries to bring the city under Leone family control.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-vice-city-stories-playstation-portable', 'Grand Theft Auto: Vice City Stories', 'Grand Theft Auto', '2006-10-31', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lc8.jpg', 'The PlayStation Portable follow-up to Rockstar''s monumental handheld entry in the series, Grand Theft Auto: Liberty City Stories. As in Liberty City Stories, this game ventures back to the location of the second PS2 game.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-chinatown-wars-playstation-portable', 'Grand Theft Auto: Chinatown Wars', 'Grand Theft Auto', '2009-10-20', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lba.jpg', 'Grand Theft Auto: Chinatown Wars is an entirely original entry into the critically acclaimed Grand Theft Auto series, and brings a new level of interactivity to its sprawling open environments. With the use of the DS touch screen, players navigate their way through the streets as they uncover the truth behind an epic tale of crime and corruption within the Triad crime syndicate, delivering the unprecedented amount of depth that has become a true trademark of the franchise.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('daxter-playstation-portable', 'Daxter', 'Jak and Daxter', '2006-03-14', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ny0.jpg', 'The Jak and Daxter Collection is a compilation of the first three main instalments in the Jak and Daxter series (The Precursor Legacy, Jak II, and Jak 3) remastered in full 720p HD with support for 3D graphics and PlayStation Network trophies.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-the-lost-frontier-playstation-portable', 'Jak and Daxter: The Lost Frontier', 'Jak and Daxter', '2009-11-03', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2agh.jpg', 'Jak and Daxter: The Lost Frontier is a 2009 platform game developed by High Impact Games and published by Sony Computer Entertainment. The game is the sixth and final game in the Jak and Daxter series. The player assumes the role of Jak, the angst-ridden hero enhanced by his exposure to Light and Dark Eco.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jeanne-d-arc-playstation-portable', 'Jeanne d''Arc', NULL, '2007-08-21', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8h02.jpg', 'Experience Jeanne d’Arc, originally released on the PSP, enhanced with up-rendering, rewind, quick save, and custom video filters. Enter the 15th century, as France and England battle during the Hundred Years’ War. A mysterious and powerful armlet appears on the wrist of a young crusader named Jeanne. Commanded by an oracle from above, Jeanne wields the armlet to turn back the dark invading army to save her homeland once and for all.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('me-my-katamari-playstation-portable', 'Me & My Katamari', 'Katamari', '2006-03-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hix.jpg', 'The King of All Cosmos and the Royal Family decide to take some time off from their celestial construction and travel to Earth for a well-earned (for the Prince at least) tropical summer vacation on their own sunny island. Unfortunately, the King''s over-exuberance creates a tsunami that strikes and devastates nearby Paradise Commonwealth Island. One of the residents, a turtle, washes ashore next to the Royal Family and tells them his tale. The King then decides to make new islands for the animals of the Commonwealth with several katamari. Similar to the previous Katamari titles, the King sends the Prince to the Sunflower Continent, which is full of the paraphernalia used to create new landmasses.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-liberation-playstation-portable', 'Killzone: Liberation', 'Killzone', '2006-10-31', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jj3.jpg', 'Killzone Liberation is the sequel to the PS2 game Killzone. New to the franchise is the top-down/third-person perspective, instead of the PS2''s first-person pure FPS approach. During the action, you can switch to a tactical overview to plan your actions. The screen zooms out and the actions are slowed down, while icons pop up to show the different actions and objectives. The game comes with a full range of Ad Hoc settings for multiplayer, with co-op and competitive play modes included, such as Deathmatch, Assault and Capture the Flag for up to six players.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-birth-by-sleep-playstation-portable', 'Kingdom Hearts Birth by Sleep', 'Kingdom Hearts', '2010-09-07', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ych.jpg', 'Birth by Sleep is an action roleplaying game that introduces a gameplay aspect called the Command System, which allows players to customize a Command Deck with techniques and abilities that they can perform at will, called Deck Commands. Performing ordinary attacks and Commands fills a gauge displayed above the command deck that, when certain requirements are fulfilled, activates a Command Style that changes the player''s basic attack command with the "Surge" command, which racks up powerful combos depending on what Command Style is activated. Filling the gauge with certain requirements a second time causes the character to change into an even higher level Command Style, which replaces the "Surge" command with the more powerful "Storm" command.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-playstation-portable', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-playstation-portable-2', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-playstation-portable', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-playstation-portable', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-2-the-adventure-continues-playstation-portable', 'Lego Indiana Jones 2: The Adventure Continues', 'Lego', '2009-11-17', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6up6.jpg', 'LEGO Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO fashion, get creative and build your own levels to play with friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-1-4-playstation-portable', 'Lego Harry Potter: Years 1–4', 'Lego', '2010-06-29', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65lz.jpg', 'LEGO Harry Potter: Years 1-4 will give gamers the chance to experience the magic and adventure of Harry Potter in a uniquely LEGO way. Playing as Harry Potter, Ron Weasley and Hermione Granger, as well as more than 100 other favorite characters, gamers will have the opportunity to attend lessons, cast spells, mix potions, fly on broomsticks and complete tasks to earn rewards. Throughout the game, players will also have the freedom to explore iconic settings from the wizarding world including Hogwarts castle, Diagon Alley, the Forbidden Forest and the village of Hogsmeade.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-playstation-portable', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-playstation-portable', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-playstation-portable', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-playstation-portable', 'Lemmings', 'Lemmings', '2006-05-23', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-playstation-portable', 'LittleBigPlanet', 'LittleBigPlanet', '2009-11-17', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49cl.jpg', 'LittleBigPlanet is a 2009 puzzle platformer video game (with user-generated content) for the PlayStation Portable developed by SCE Cambridge Studio in conjunction with Media Molecule. It is a new entry in the LittleBigPlanet franchise made exclusively for the PSP, featuring a brand new story mode.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('locoroco-playstation-portable', 'LocoRoco', 'LocoRoco', '2006-09-05', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pnk.jpg', 'The peaceful world of the LocoRoco are under attack by the not-so-nice Moja Corps! These evil outer space creatures have come to take the LocoRoco from their land of blowing flowers, lively creatures and pastel scenery. As the planet where the LocoRoco inhabit, you must move them through more than 40 levels of slippery slopes, teetering platforms and maze-like passages. The LocoRoco have the uncanny ability to fluidly morph to their landscape, so all you need is to tilt, roll and bounce the happy blob-like creatures to safety!', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('locoroco-2-playstation-portable', 'LocoRoco 2', 'LocoRoco', '2009-02-10', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ja3.jpg', 'The LocoRoco are in danger again, the evil Moja have returned and this time they''ve brought with them a terrible song that sucks the life out of living things! The LocoRoco must once again save their planet - this time by making lots of sweet music. LocoRoco 2 is easy to play, instantly addictive and guaranteed to make you feel all warm and fuzzy while you hum along to the soundtrack! Explore 25 new stages, including hidden challenges, and meet a colourful cast of new characters. Enhance your LocoRoco through music and song, learning new actions to overcome the Moja. Perform new actions such as climbing inside shells to destroy thorns, jumping from grass blade to grass blade and swimming underwater. Expand your fun with six new mini games, including an Ad-hoc four player game.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-playstation-portable', 'Spider-Man 2', 'Marvel', '2005-03-23', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-nemesis-rise-of-the-imperfects-playstation-portable', 'Marvel Nemesis: Rise of the Imperfects', 'Marvel', '2005-10-04', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1jr.jpg', 'Marvel Nemesis: Rise of the Imperfects pits fierce Marvel superheroes against each other in a 3D fighting game. You can assume control of heroes such as the Punisher, Spider-Man, and Captain America, and duel with them in interactive and destructible environments. A new team of superheroes called the Imperfects joins the mayhem. You can play in single-player story mode to unlock collectible awards, or you can play against other gamers in multiplayer modes.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-ii-rise-of-apocalypse-playstation-portable', 'X-Men Legends II: Rise of Apocalypse', 'Marvel', '2005-10-19', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pf0.jpg', 'X-Men Legends II: Rise of Apocalypse is an action role-playing game and a sequel to X-Men Legends. The player controls a party of four characters, though only one at a time can be controlled directly. Besides switching the characters for combat purposes, the player is often obliged to do so, because some of the tasks in the game require the specific abilities of a certain mutant. For example, Iceman can put out the fire, Magneto can generate a metal bridge across a gap, etc. Most of the time, however, is spent in combat, collecting loot and acquiring experience points. Unlike the first game, items dropped by enemies are random. The character will level up, become stronger, and learn new skills. The player can opt to allocate all the experience and skill points manually.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-playstation-portable', 'Marvel: Ultimate Alliance', 'Marvel', '2006-10-24', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-rider-playstation-portable', 'Ghost Rider', 'Marvel', '2007-02-13', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7sv8.jpg', 'The Ghost Rider feature film follows superstar motorcycle stunt rider Johnny Blaze as he strikes a deal with the vile Mephistopheles for the most precious of commodities - his immortal soul. Now Johnny Blaze is forever destined to ride night after night as the host to the powerful supernatural entity known as the Ghost Rider. The video game continues the storyline, dropping players into the role of Blaze as he is transformed into a super hero with powers to avenge any evil he encounters. Featuring many of the characters and motorcycles from the comic book and movie, Ghost Rider engages gamers in an immersive, supernatural third person world with a seamless blend of hand-to-hand combat and high-speed motorcycle action.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-friend-or-foe-playstation-portable', 'Spider-Man: Friend or Foe', 'Marvel', '2007-10-02', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h33.jpg', 'Defeat Spider-Man’s most famous enemies, like Venom, Green Goblin, and Doc Ock to add them to your epic array of playable sidekicks in this movie trilogy inspired adventure. Experience ground-breaking Co-operative Multiplayer, as Spider-Man or a sidekick, in exotic spots around the globe, including Tokyo, Egypt and Nepal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-playstation-portable', 'Spider-Man 3', 'Marvel', '2007-10-16', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-playstation-portable', 'Iron Man', 'Marvel', '2008-05-02', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-the-amazing-allies-edition-playstation-portable', 'Spider-Man: Web of Shadows – The Amazing Allies Edition', 'Marvel', '2008-10-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co71as.jpg', 'Spider-Man: Web of Shadows - Amazing Allies Edition is a 2D side-scroller with 3D graphics. The story is similar to the seventh-generation console versions. A break-off piece of Venom''s symbiote begins infecting New Yorkers and it is up to Spider-Man to save the city. He can switch between the back and red suits at any time, and each has its own move set and abilities.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-playstation-portable', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-playstation-portable', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-playstation-portable', 'Marvel Super Hero Squad', 'Marvel', '2009-10-20', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e7b.jpg', 'Marvel Super Hero Squad is an action beat-em-up game for one to four players that is based on the animated Marvel TV series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-2-playstation-portable', 'Iron Man 2', 'Marvel', '2010-05-04', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sxm.jpg', 'This is the Wii version of Iron Man 2, an action-adventure video game loosely based on the 2010 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('medievil-resurrection-playstation-portable', 'MediEvil: Resurrection', 'MediEvil', '2005-09-13', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8l3.jpg', 'A port of MediEvil: Resurrection, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-powered-up-playstation-portable', 'Mega Man Powered Up', 'Mega Man', '2006-03-14', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pnq.jpg', 'Mega Man Powered Up, known as Rockman Rockman in Japan, is a remake of the first Mega Man game. It was released worldwide for the PlayStation Portable in March 2006.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-maverick-hunter-x-playstation-portable', 'Mega Man Maverick Hunter X', 'Mega Man X', '2006-01-31', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ymw.jpg', 'Mega Man Maverick Hunter X, known as Irregular Hunter X in Japan, is an enhanced remake of the original Mega Man X game released for the PlayStation Portable in 2005-2006. The game is also compatible and cross-playable with the PlayStation Vita via a PSN Download which was released at the PlayStation Vita''s launch on February 15, 2012. It has several new features and several redesigns.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-acid-playstation-portable', 'Metal Gear Acid', 'Metal Gear', '2005-03-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pnu.jpg', 'Metal Gear Acid is a turn-based collectable card game. It was the first game in the Metal Gear series for the PSP. A Java ME version for mobile phones was released by Glu Mobile in 2008 titled Metal Gear Acid Mobile.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-acid-2-playstation-portable', 'Metal Gear Acid 2', 'Metal Gear', '2006-03-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ipm.jpg', 'An All New Acid Trip!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-portable-ops-playstation-portable', 'Metal Gear Solid: Portable Ops', 'Metal Gear', '2006-12-05', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qok.jpg', 'MPO is the fourth Metal Gear title made specifically for the PSP and the first one to retain the series'' action-based play mechanics. It is the first canonical outing of the Metal Gear Solid series for a portable platform, following the storyline of Metal Gear Solid 3: Snake Eater. Set in Colombia in 1970, six years after the events of Snake Eater, the game follows the exploits of Naked Snake after his former unit, FOX, goes renegade. The game also chronicles the eventual founding of FOXHOUND and The Patriots, as well as the inspiration of the military state Outer Heaven.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-portable-ops-plus-playstation-portable', 'Metal Gear Solid: Portable Ops Plus', 'Metal Gear', '2007-11-13', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ipv.jpg', 'A standalone expansion to Metal Gear Solid: Portable Ops, mainly focused on multiplayer. A single player mode called Infinity Mission was included, but has no story. There are also new missions and tutorials for beginners. With up to 6 players via WiFi, new characters including Old Snake from Metal Gear Solid 4, Roy Campbell, and Raiden from Metal Gear Solid 2, this game continues the trend of capturing and recruiting comrades.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-peace-walker-playstation-portable', 'Metal Gear Solid: Peace Walker', 'Metal Gear', '2010-06-08', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawb5.jpg', 'Metal Gear Solid: Peace Walker is an action-adventure stealth video game and is the third action-based Metal Gear title made specifically for the PSP. The gameplay consists of two primary modes: Mission and Mother Base. Mission are the actual action sequences of the game where the player must infiltrate an enemy territory or fight a boss, whereas Mother Base is an army management. Some changes have been made to the standard Metal Gear formula: the player is now unable to move or shoot while laying down and while pinned to a wall, making Peace Walker the first game since Metal Gear to lack any crawling ability.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-tactics-playstation-portable', 'The Lord of the Rings: Tactics', 'Middle-earth', '2005-11-08', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20ok.jpg', 'Return to Middle-earth in this tactical RPG and decide the fate of The Third Age. Build a Fellowship of heroes or create a force of evil with hundreds of skill, weapon, and ability upgrades. Send your armies into battle across legendary locations from the film trilogy and J.R.R. Tolkien''s fiction. A simultaneous turn-based multiplayer system delivers a combat unrivaled by any Tactics game. The board is set, the pieces are in motion. Middle-earth awaits you.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-aragorn-s-quest-playstation-portable', 'The Lord of the Rings: Aragorn''s Quest', 'Middle-earth', '2010-09-15', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9nie.jpg', 'The NDS/PSP ports features slightly different HUD, and the NDS version uses the second screen as a map.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-freedom-playstation-portable', 'Monster Hunter Freedom', 'Monster Hunter', '2006-05-23', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hcz.jpg', 'Japan''s most successful PSP title, Monster Hunter Portable 2G, is heading to Europe and US. Renamed Monster Hunter Freedom Unite, this latest installment in the epic Monster Hunter series delivers over 500 hours of gameplay spanning some 400 missions. Added with previously unreleased monsters, weapons and missions and you have the biggest Monster Hunter game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-freedom-2-playstation-portable', 'Monster Hunter Freedom 2', 'Monster Hunter', '2007-08-28', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co406l.jpg', 'The hunt-or-be-hunted adventure continues with more content and options than ever before. In Monster Hunter Freedom 2, gamers increase their play skills as they battle through breath-taking environments while defeating bloodthirsty creatures. As mighty hunters, players can face a variety of quests alone, but the true spirit of the game comes from playing with others.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-freedom-unite-playstation-portable', 'Monster Hunter Freedom Unite', 'Monster Hunter', '2009-06-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hcz.jpg', 'Japan''s most successful PSP title, Monster Hunter Portable 2G, is heading to Europe and US. Renamed Monster Hunter Freedom Unite, this latest installment in the epic Monster Hunter series delivers over 500 hours of gameplay spanning some 400 missions. Added with previously unreleased monsters, weapons and missions and you have the biggest Monster Hunter game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-battle-collection-playstation-portable', 'Namco Museum Battle Collection', 'Namco Museum', '2005-08-23', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1po3.jpg', 'Namco Museum Battle Collection brings classic Namco arcade titles to the Sony PSP. Full wireless support lets you challenge up to four of your friends on some of the most classic multiplayer arcade titles. The collection includes more than 20 titles, such as Pac-Man, Ms. Pac-Man, Galaga, Galaxian, Rally-X, New Rally-X, Dig Dug, Rolling Thunder, and Grobda.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-battle-collection-playstation-portable-2', 'Namco Museum Battle Collection', 'Namco Museum', '2005-08-23', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1po3.jpg', 'Namco Museum Battle Collection brings classic Namco arcade titles to the Sony PSP. Full wireless support lets you challenge up to four of your friends on some of the most classic multiplayer arcade titles. The collection includes more than 20 titles, such as Pac-Man, Ms. Pac-Man, Galaga, Galaxian, Rally-X, New Rally-X, Dig Dug, Rolling Thunder, and Grobda.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-50th-anniversary-playstation-portable', 'Namco Museum 50th Anniversary', 'Namco Museum', '2005-08-30', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz6.jpg', 'Includes 14 Classic Arcade Hits
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-3-playstation-portable', 'Pac-Man World 3', 'Pac-Man', '2005-12-06', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc8.jpg', NULL, 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-rally-playstation-portable', 'Pac-Man World Rally', 'Pac-Man', '2006-08-22', 'PlayStation Portable', 0, 0, NULL, NULL, NULL, 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('patapon-playstation-portable', 'Patapon', 'Patapon', '2008-02-26', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobe8f.jpg', 'Set among a variety of colorful 2D backgrounds, Patapon unfolds through more than 30 missions with more than 20 different environments, where players are tasked with outfitting the Patapon army, collecting resources, and using strategy to grow the tribe into a devastating fighting force. Incorporating various button-timed drumbeats in real-time to control the Patapons, players will strategically traverse through each environment, battling enemies each step of the way. The game presents a variety of warrior types such as archers, infantry, cavalry, and more that players can unlock, along with a wide selection of more than 100 weapon and shield upgrades, allowing players to customize their forces throughout the funky adventure.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('patapon-2-playstation-portable', 'Patapon 2', 'Patapon', '2009-05-05', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzx.jpg', 'The story of the Patapon tribe marches forth as they hunt for the fabled Earthend. Shipwrecked in a new and strange continent the Patapon are depending on you, their god, to lead them safely through this perilous new land. As you guide the tribe through this new world with your mystical drum, they will come face to face with a new tribe, encounter a mysterious and mighty Hero Patapon and uncover the ruins of Patapolis, a mystical place long spoken of by the Patapon. All-new modes to Patapon 2 include thrilling multiplayer stages, a huge array of missions and deep tutorials that will have you drumming to the beat of the Patapon in no time. Head to patapon-game.com for the captivating mini-game, The Art Of War, where the goal is to collect as many Patapon characters as you can and then immortalise your battle with the Patapon Wallpaper creator. Lead your loyal followers through 60 rhythmic stages. Keep the beat going with tons of hidden items and mini-games to reveal. Drum along with friends and tackle multiplayer missions.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('patapon-3-playstation-portable', 'Patapon 3', 'Patapon', '2011-04-12', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9f6b.jpg', 'Patapon 3 is a rhythm game for the PlayStation Portable now back on modern consoles.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-playstation-portable', 'Shin Megami Tensei: Persona', 'Persona', '2009-09-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ejn.jpg', 'Persona is a philosophical game that takes place in a world close to our own. It is a departure from the typical swords and sorcery, and it delivers a tale of dreams, the purpose of life, and who we are as individuals. In Persona you have modern weapons like an Uzi and an AK-47. And instead of always fighting monsters, you are given the opportunity to talk your way through a confrontation. By talking things out, you can earn components of spells the more components you have, the more powerful your spells become.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-3-portable-playstation-portable', 'Shin Megami Tensei: Persona 3 Portable', 'Persona', '2010-07-06', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7r89.jpg', 'The Collector''s Edition of Persona 3 Portable contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shin-megami-tensei-persona-2-innocent-sin-playstation-portable', 'Shin Megami Tensei: Persona 2 - Innocent Sin', 'Persona', '2011-09-20', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co898j.jpg', 'Persona 2: Innocent Sin is a Japanese role-playing video game developed and released by Atlus It is the second entry in the Persona series and acts as a sequel to the original Persona. The original version was not localized for western territories, but the PSP version was released in North America and Europe under the title Shin Megami Tensei: Persona 2: Innocent Sin. Innocent Sin takes place in the fictional Sumaru City, focusing on a group of high school students from Seven Sisters High School. The main protagonist, Tatsuya Suou, and a group of friends must confront a villainous figure called the Joker, who is causing the spread of reality-warping rumors through the city. The group are aided in their quest by their Personas, personified aspects of their personalities. The gameplay features turn-based battle gameplay, where characters use their Personas in battle against demons, and a separate Rumor system, where rumors spread around the city can influence events in the characters'' favor.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-warrior-within-playstation-portable', 'Prince of Persia: Warrior Within', 'Prince of Persia', '2005-12-06', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52j9.jpg', 'Prince of Persia: Warrior Within is the mobile J2ME port of the PC/console game of the same title.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-two-thrones-playstation-portable', 'Prince of Persia: The Two Thrones', 'Prince of Persia', '2007-04-03', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav9r.jpg', 'In the mobile version of the last game in the trilogy, the Prince returns to Babylon after the events of the previous game, only to find out that a vizier has taken his throne. This new ruler has captured the Babylonian women. You need to set them free and defeat the vizier at the same time. Exposure to the sands of time, however, has awakened an evil presence inside the Prince, which manifests itself as the Dark Prince. During the game, you will often morph into the other presence, whose only goal it to reclaim the throne, the populace be damned.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-forgotten-sands-playstation-portable', 'Prince of Persia: The Forgotten Sands', 'Prince of Persia', '2010-05-18', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8z2j.jpg', 'Prince of Persia: The Forgotten Sands is a promotional browser flash game created to promote the Prince of Persia: The Forgotten Sands. Playing the game unlocked a costume in the main game, though that feature no longer works. The game is still playable on explosivebarrel.net
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-size-matters-playstation-portable', 'Ratchet & Clank: Size Matters', 'Ratchet & Clank', '2007-02-13', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coankv.jpg', 'Ratchet & Clank: Size Matters (known as Ratchet & Clank 5 in Japan) is a 2007 platformer video game developed by High Impact Games and published by Sony Computer Entertainment for the PlayStation Portable and PlayStation 2. The game is the first Ratchet & Clank title on the PSP handheld. Development company High Impact Games was spawned from the original Ratchet & Clank developer, Insomniac Games. The story is about Ratchet and Clank as they are interrupted from their vacation to search for a kidnapped girl and encounter a forgotten race known as the Technomites.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('secret-agent-clank-playstation-portable', 'Secret Agent Clank', 'Ratchet & Clank', '2008-06-17', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8uc6.jpg', 'A port of Secret Agent Clank, a platform video game developed by High Impact Games and published by Sony Computer Entertainment, released for the PlayStation Portable (PSP) in 2008.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resistance-retribution-playstation-portable', 'Resistance: Retribution', 'Resistance', '2009-03-17', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9418.jpg', 'Fueled by vengeance, former British Marine James Grayson intends to destroy the Chimeran conversion centers at any cost. Enlisted by the European resistance, The Maquis, he soon learns the Chimera have evolved a new method of converting humans. Set after events in Resistance: Fall of Man, the war for Europe continues….', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-playstation-portable', 'The Sims 2', 'The Sims', '2005-12-07', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja7.jpg', 'The Sims 2 for Nintendo DS is the first DS game of The Sims 2. Like the many of the console games it takes place in Strangetown with some of the same faces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-pets-playstation-portable', 'The Sims 2: Pets', 'The Sims', '2006-12-14', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h1q.jpg', 'A port of The Sims 2: Pets released for home consoles.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-castaway-playstation-portable', 'The Sims 2: Castaway', 'The Sims', '2007-10-22', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja9.jpg', 'Castaway is the third console spin-off of the video game The Sims 2. The Sims Castaway Stories is a similar game created for personal computers. It is the final game in the series released for the PlayStation 2 and the final game in the Sims 2 series for console.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-rivals-playstation-portable', 'Sonic Rivals', 'Sonic the Hedgehog', '2006-11-16', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvh.jpg', 'The game begins with Doctor Eggman turning Tails, Amy Rose, Rouge, and the Master Emerald into cards with his new device. Sonic and Knuckles arrive on the scene, and find out what has happened. Knuckles, bent on saving the Master Emerald, tells Sonic that teamwork is out of the question and that he needs to get to Eggman first. Sonic snickers and says that he likes a good challenge.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-rivals-2-playstation-portable', 'Sonic Rivals 2', 'Sonic the Hedgehog', '2007-11-13', 'PlayStation Portable', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvl.jpg', 'The Chao have disappeared and Sonic the Hedgehog and Miles "Tails" Prower immediately get on the case to find them. It turns out that Eggman Nega (once again masquerading as Doctor Eggman) has stolen the Chao and concealed them inside a haunted mansion. His plan is to feed them to an inter-dimensional beast called the "Ifrit" who needs to eat them to become invincible . After that, he plans to release the Ifrit into the world in order to destroy it. However, to open the portal to the Ifrit''s world, the seven Chaos Emeralds are required. Eggman Nega secretly hires Rouge the Bat to collect the Chaos Emeralds. The Master Emerald has also gone missing (again) and Knuckles the Echidna teams up with Rouge to find it.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-extreme-playstation-portable', 'Space Invaders Extreme', 'Space Invaders', '2008-06-17', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65kk.jpg', 'Space Invaders Extreme combines the captivating essence of the original game with a stunning alliance of futuristic graphic design and cutting-edge audio. The gameplay experience has been developed to maximise on the consoles'' abilities, offering players a whole new range of amazing features including a vast array of new power-ups.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-ii-playstation-portable', 'Star Wars: Battlefront II', 'Star Wars', '2005-11-01', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1g4.jpg', 'Star Wars: Battlefront II is the sequel to Star Wars: Battlefront. It is a high-selling Star Wars video game following the many adventures of several characters. The two games are very similar, as both revolve around troopers from various factions fighting in different locales. Battlefront II, however, includes elements and missions from Star Wars: Episode III Revenge of the Sith, as well as enhanced aspects of gameplay including space combat and the ability to play as Jedi characters or other heroes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-lethal-alliance-playstation-portable', 'Star Wars: Lethal Alliance', 'Star Wars', '2006-12-07', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qmf.jpg', 'To capture the plans for the Death Star and make it back home safely, players must guide Rianna Saren and her trusty droid Zeeo through a variety of Star Wars environments while avoiding or attacking Imperial soldiers and their allies. Rianna is gifted in combat and Zeeo comes in handy for unlocking security doors, reaching high places, and bypassing dangerous areas. The story of Star Wars: Lethal Alliance unfolds between Episode III and Episode IV, when Princess Leia recruits the duo to steal the plans so the Rebels may learn any weaknesses in the massive weapon. Players will explore such areas as Tatooine, Despayre, Alderaan, and Danuta while interacting with characters including Boba Fett, Darth Vader, and Kyle Katarn. The PSP features various mini-games and multiplayer Twil''lek vs. Twi''lek combat over a wireless network.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-renegade-squadron-playstation-portable', 'Star Wars Battlefront: Renegade Squadron', 'Star Wars', '2007-10-09', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pmz.jpg', 'Star Wars Battlefront: Renegade Squadron is an all-new project in the Battlefront saga exclusively for the PlayStation Portable, designed to offer an all-new storyline in the single-player mode and extremely robust PSP multiplayer options.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-playstation-portable', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-playstation-portable', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-elite-squadron-playstation-portable', 'Star Wars Battlefront: Elite Squadron', 'Star Wars', '2009-11-03', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal7m.jpg', 'Star Wars Battlefront: Elite Squadron is the fourth installment in the Star Wars: Battlefront series, and the second handheld exclusive, after Star Wars Battlefront: Renegade Squadron. Nintendo DS version of Elite Squadron uses an isometric view, similar to a modern dungeon crawler. Unlike classic Battlefront games, Instant Action is played with only four players, usually one from each faction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('innocent-life-a-futuristic-harvest-moon-playstation-portable', 'Innocent Life: A Futuristic Harvest Moon', 'Story of Seasons', '2007-05-15', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26oy.jpg', 'Life is good for the residents of Heartflame Island, especially since new robots and automated machines do almost all of the work. But technology is a tool--not an answer to all problems. Maybe that''s why everyone is a little uneasy about the old stories of strange magic and a prediction that Flame Mountain will erupt and destroy everything. That''s why Dr. Hope, a caring and wise old scholar has sent you, his son on a journey to the ancient ruins to try and run a farm. It is your father''s dream that you will unlock the secrets of the ancient ruins and find the meaning of "life".', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-boy-girl-playstation-portable', 'Harvest Moon: Boy & Girl', 'Story of Seasons', '2007-07-31', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xku.jpg', 'This first release of Harvest Moon on the Sony PSP is a port of "Harvest Moon: Back To Nature" and "Harvest Moon For Girl", play either with a 4:3 or the new PSP 16:9 resolution. You can either play as a boy (Destiny), or a girl (Fate) to bring life to Mineral Town in this comfy farming stimulator.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-hero-of-leaf-valley-playstation-portable', 'Harvest Moon: Hero of Leaf Valley', 'Story of Seasons', '2010-04-26', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xjy.jpg', 'Protect Leaf Valley from the heartless Funland corporation! Stop them from bulldozing Leaf Valley to replace it with an amusement park in this enhanced version of "Harvest Moon: Save the Homeland". With better graphics, more features, marriage system and multiple endings, the valley future is in your hand in another heroic farming stimulator.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-adventure-playstation-portable', 'Super Monkey Ball Adventure', 'Super Monkey Ball', '2006-08-29', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzl.jpg', 'Our four heroes from Super Monkey Ball - Aiai, Meemee, Baby and Gongon - were enjoying a typical day, when they saw a flying machine crash down on a nearby island. Soon, they discovered that the mysterious Naysayers have appeared, spreading discord and unhappiness all over the island. And to top it all off, the prince and princess of the neighboring islands have gone missing on Jungle Island - if they aren''t found and returned, there''s sure to be trouble! Can our heroes restore order to Monearth?', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-essentials-playstation-portable', 'Tom Clancy''s Splinter Cell: Essentials', 'Tom Clancy''s Splinter Cell', '2006-03-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co205a.jpg', 'Tom Clancy''s Splinter Cell: Essentials is an action-adventure video game with heavy emphasis on stealth. It is part of the Splinter Cell series and was released for the PlayStation Portable handheld system. It was developed by Ubisoft Montreal and published by Ubisoft on March 21, 2006 in North America. It is the fourth entry in the series and was powered by Unreal Engine 2.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-playstation-portable', 'Tomb Raider: Legend', 'Tomb Raider', '2006-06-21', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-anniversary-playstation-portable', 'Tomb Raider: Anniversary', 'Tomb Raider', '2007-08-09', 'PlayStation Portable', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mz7.jpg', 'The Wii port of Tomb Raider: Anniversary carries over the levels and general gameplay of the other versions while incorporating motion controls. Wii-exclusive first-person puzzles include breaking through walls with a pickaxe, using a flashlight in dark areas, assembling mechanisms from pieces found around the environment, manipulating symbol-based locks and using paper and charcoal to take rubbings of puzzle-related symbols, all utilizing the Wii Remote.', 'NA', 31);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('3d-dot-game-heroes-playstation-3', '3D Dot Game Heroes', NULL, '2010-05-11', 'PlayStation 3', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uui.jpg', '3D Dot Game Heroes is an action adventure title paying a strong homage to 8bit adventure games such as The Legend of Zelda and Final Fantasy Adventures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-playstation-3', 'Assassin''s Creed', 'Assassin''s Creed', '2007-11-13', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ka7.jpg', 'A bundle including three Assassin''s Creed titles: Assassin''s Creed Valhalla, Assassin''s Creed Odyssey, and Assassin''s Creed Origins.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-ii-playstation-3', 'Assassin''s Creed II', 'Assassin''s Creed', '2009-11-17', 'PlayStation 3', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rcf.jpg', 'Discover an intriguing and epic story of power, revenge and conspiracy set during a pivotal moment in history: the Italian Renaissance.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-brotherhood-playstation-3', 'Assassin''s Creed: Brotherhood', 'Assassin''s Creed', '2010-11-16', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5j8z.jpg', 'A remaster of Assassin''s Creed Brotherhood included with Assassin''s Creed: The Ezio Collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-revelations-playstation-3', 'Assassin''s Creed: Revelations', 'Assassin''s Creed', '2011-11-15', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xih.jpg', 'Assassin''s Creed Revelations presents the most immersive experience available in the series to date and the culmination of Ezio''s adventure. In Assassin''s Creed Revelations, master assassin Ezio Auditore walks in the footsteps of his legendary mentor, Altair, on a journey of discovery and revelation. It is a perilous path - one that will take Ezio to Constantinople, the heart of the Ottoman Empire, where a growing army of Templars threatens to destabilize the region.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-playstation-3', 'Assassin''s Creed III', 'Assassin''s Creed', '2012-10-30', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xii.jpg', 'The American Colonies, 1775. A brave young warrior fights to save his homeland. But what begins as a struggle over territory turns into an extraordinary journey that will transform him into a Master Assassin—and will forever change the destiny of a nation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-ezio-trilogy-playstation-3', 'Assassin''s Creed: Ezio Trilogy', 'Assassin''s Creed', '2012-11-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49hd.jpg', 'Assassin''s Creed: Ezio Trilogy is a collection of the three main series Assassin''s Creed games that feature Ezio Auditore da Firenze: Assassin''s Creed II, Assassin''s Creed: Brotherhood, and Assassin''s Creed: Revelations. The Bonfire of the Vanities, the Battle of Forlì, and the exclusive black ''Bonus Skin''. DLC for Assassin''s Creed II is only available with the PS3 version; The xbox 360 version only includes the original games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iv-black-flag-playstation-3', 'Assassin''s Creed IV: Black Flag', 'Assassin''s Creed', '2013-10-29', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tx9.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-the-americas-collection-playstation-3', 'Assassin''s Creed: The Americas Collection', 'Assassin''s Creed', '2014-10-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49pi.jpg', 'Assassin''s Creed: The Americas Collection is a compilation consisting of three games in the Assassin''s Creed series. The Americas Collection includes Assassin''s Creed III, Assassin''s Creed: Liberation HD and Assassin''s Creed IV: Black Flag.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-rogue-playstation-3', 'Assassin''s Creed Rogue', 'Assassin''s Creed', '2014-11-11', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xir.jpg', 'Assassin''s Creed Rogue is a 2014 action-adventure video game developed by Ubisoft Sofia and published by Ubisoft. It is the seventh major installment in the Assassin''s Creed series, and is set between 2012''s Assassin''s Creed III and 2013''s Assassin''s Creed IV: Black Flag. It also has ties to Assassin''s Creed Unity, which was released on the same day as Rogue. It is the last Assassin''s Creed game to be developed for the seventh generation of consoles, being released for PlayStation 3 and Xbox 360 in November 2014 and for Windows in March 2015.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-playstation-3', 'Bayonetta', 'Bayonetta', '2010-01-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamt.jpg', 'This is a European bundle that includes Bayonetta 1 and Bayonetta 2 both in each own disc and case for the WiiU.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bejeweled-3-playstation-3', 'Bejeweled 3', 'Bejeweled', '2011-10-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zso.jpg', 'The biggest, brightest Bejeweled ever! Discover all-new ways to play the world''s #1 puzzle game. Find your perfect match with 8 breathtaking game modes that meet all your moods ease into Classic Bejeweled for cascades of fun, journey through 40 challenging Quest puzzles, charge into the electrifying Lightning for non-stop action, and tailor your experience in Zen for a revolutionary new way to relax.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('best-of-playstation-network-vol-1-playstation-3', 'Best Of PlayStation Network Vol. 1', NULL, '2013-06-25', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6033.jpg', 'Best of PlayStationNetwork, Vol.1 includes four hits from the PSN library including:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-two-souls-playstation-3', 'Beyond: Two Souls', NULL, '2013-10-08', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8r4w.jpg', 'A unique psychological action thriller delivered by A-list Hollywood performances by Elliot Page and Willem Dafoe, Beyond: Two Souls takes you on a thrilling journey across the globe as you play out the remarkable life of Jodie Holmes.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-playstation-3', 'BioShock', 'BioShock', '2008-10-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3aet.jpg', 'The year is 1960 and the player character, Jack, is on board a plane crossing the Atlantic ocean. Things go wrong though and the plane crashes. Jack is lucky though and finds himself outside a lighthouse. This is no ordinary lighthouse however. It leads to Rapture, an Utopian underwater city built by the tycoon Andrew Ryan. It''s not long until Jack is contacted by a man called Atlas who offers Jack his support.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-2-playstation-3', 'BioShock 2', 'BioShock', '2010-02-09', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mlj.jpg', 'BioShock 2 is the second game of the BioShock series and the sequel to BioShock. It continues the grand storyline of the underwater metropolis Rapture. BioShock 2 capitalizes and improves upon the high-quality effects, unique gameplay elements, and immersive atmosphere that defined the first game. It explores more brutal gameplay than its predecessor, with new enemies, weapons, Plasmids, and Gene Tonics.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-ultimate-rapture-edition-playstation-3', 'BioShock: Ultimate Rapture Edition', 'BioShock', '2013-01-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54yf.jpg', 'This edition includes the original BioShock, BioShock 2 and add-on content for both games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-infinite-playstation-3', 'BioShock Infinite', 'BioShock', '2013-03-26', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n12.jpg', 'BioShock Infinite is the third game in the BioShock series. It is not a direct sequel/prequel to any of the previous BioShock games but takes place in an entirely different setting, although it shares similar features, gameplay and concepts with the previous games. BioShock Infinite features a range of environments that force the player to adapt, with different weapons and strategies for each situation. Interior spaces feature close combat with enemies, but unlike previous games set in Rapture, the setting of Infinite contains open spaces with emphasis on sniping and ranged combat against as many as fifteen enemies at once.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-infinite-the-complete-edition-playstation-3', 'BioShock Infinite: The Complete Edition', 'BioShock', '2014-11-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50k0.jpg', 'BioShock Infinite: The Complete Edition is a re-release of BioShock Infinite including all its downloadable content.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-playstation-3', 'Borderlands', 'Borderlands', '2009-10-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tx.jpg', 'With its addictive action, frantic first-person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is a breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell-bent on finding a legendary stockpile of powerful alien technology known as The Vault.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-game-of-the-year-edition-playstation-3', 'Borderlands: Game of the Year Edition', 'Borderlands', '2010-10-12', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229j.jpg', 'Lock, Load, & Face the Madness! Get ready for the mind-blowing insanity, as one of four trigger-happy mercenaries, taking out everything that stands in your way. With its addictive action, frantic first person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is the breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell bent on finding a legendary stockpile of powerful alien technology known as The Vault.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-2-playstation-3', 'Borderlands 2', 'Borderlands', '2012-09-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ba3.jpg', 'A new era of shoot and loot is about to begin. Play as one of four new vault hunters facing off against a massive new world of creatures, psychos and the evil mastermind, Handsome Jack. Make new friends, arm them with a bazillion weapons and fight alongside them in 4 player co-op on a relentless quest for revenge and redemption across the undiscovered and unpredictable living planet.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-2-game-of-the-year-edition-playstation-3', 'Borderlands 2: Game of the Year Edition', 'Borderlands', '2013-10-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k8e.jpg', 'Borderlands 2 furthers the distinct blending of First Person Shooter and Role Playing genres to create the true evolution of the Role Playing Shooter. Team up with up to three other players for four-player online goodness or go old-school with two-player split-screen couch sharing mayhem as you spend hours leveling up your character and equipping them with one of the millions of badass weapons. Borderlands 2 features a new visually stunning array of procedurally generated guns, shields, grenades, artifacts, enemies and more. Choose one of the four new character classes to be taken through a carefully crafted and connected story to all new and surprising environments across the living planet of Pandora. Make new friends, arm them to the teeth and fight alongside them on your relentless quest for revenge and redemption.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-the-pre-sequel-playstation-3', 'Borderlands: The Pre-Sequel', 'Borderlands', '2014-10-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tq.jpg', 'Shoot ''n'' loot your way through a brand new adventure that rockets you onto Pandora''s moon in Borderlands: The Pre-Sequel. Discover the story behind Borderlands 2’s villain, Handsome Jack, and his rise to power in this brand new game in the Borderlands series. Taking place between the original Borderlands and Borderlands 2, the Pre-Sequel gives you a whole lotta new gameplay featuring the genre fusion of shooter and RPG gameplay that players can’t get enough of.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-the-borderlands-playstation-3', 'Tales from the Borderlands', 'Borderlands', '2016-04-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tr.jpg', 'Tales from the Borderlands is a five part episodic game series. Set on the unforgiving world of Pandora after the events seen in Borderlands 2, this is a story full of Borderlands'' trademark humor, following two adventurers on their quest for greatness.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('br-tal-legend-playstation-3', 'Brütal Legend', NULL, '2009-10-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27c8.jpg', 'Brütal Legend is an action-adventure that marries visceral action combat with open-world freedom. Set in a universe somewhere between Lord of the Rings and Spinal Tap, it’s a fresh take on the action/driving genre, which in this case is full of imitation cover bands, demons intent on enslaving humanity and Heavy metal tunes. Featuring the talents of comedian, actor and musician, Jack Black as super roadie Eddie Riggs, as well as cameos by some of the biggest names in metal music it''s a wild ride in the belly of the beast that is not to be missed by gamers and Metalheads alike.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lords-of-shadow-playstation-3', 'Castlevania: Lords of Shadow', 'Castlevania', '2010-10-05', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pnz.jpg', 'Castlevania: Lords of Shadow 2 is an action-adventure game and a sequel to the 2010 game, Castlevania: Lords of Shadow, and the 35th installment on the Castlevania franchise. The game was developed by MercurySteam and published by Konami. This is MercurySteam''s last contribution to the franchise. The story is set in both medieval and modern worlds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lords-of-shadow-2-playstation-3', 'Castlevania: Lords of Shadow 2', 'Castlevania', '2014-02-25', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pnz.jpg', 'Castlevania: Lords of Shadow 2 is an action-adventure game and a sequel to the 2010 game, Castlevania: Lords of Shadow, and the 35th installment on the Castlevania franchise. The game was developed by MercurySteam and published by Konami. This is MercurySteam''s last contribution to the franchise. The story is set in both medieval and modern worlds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('civilization-revolution-playstation-3', 'Civilization Revolution', 'Civilization', '2008-07-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95wx.jpg', 'Build. Discover. Conquer. Rule the World!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-2-playstation-3', 'Crysis 2', 'Crysis', '2011-03-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2on2.jpg', 'Sequel to one of the greatest PC shooters ever, Crysis 2 offers console players their first taste of Crytek''s unique shooter gameplay. Featuring futuristic war, gorgeous destruction and the chance to kick alien butt on the grandest stage of all, New York City, Crysis 2 is destined at the least to equal its predecessor, if not surpass it. Additional features include: challenging AI enemies in the single player campaign, 12-player support online, new and improved upgradable Nanosuit 2 technology and more.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-3-playstation-3', 'Crysis 3', 'Crysis', '2013-02-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2on3.jpg', 'The award-winning developer Crytek is back with Crysis 3, the first blockbuster shooter of 2013! Crysis 3 is the ultimate sandbox shooter, realized in the stunning visuals only Crytek and the latest version of CryENGINE can deliver. Available now on Xbox 360, PlayStation 3, and PC.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-playstation-3', 'Dark Souls', 'Dark Souls', '2011-10-04', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x78.jpg', 'Dark Souls is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment. Released in September 2011 as a spiritual sequel to Demon''s Souls, it is set in a dark, medieval fantasy world. It is renowned for its challenging gameplay, intricate level design, and deep lore. Players control a customizable character known as the Chosen Undead, embarking on a perilous journey to uncover the secrets of the cursed land of Lordran.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-playstation-3', 'Dark Souls II', 'Dark Souls', '2014-03-11', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eoo.jpg', 'Dark Souls II is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment, released in March 2014. Set in the kingdom of Drangleic, players control the Bearer of the Curse, seeking to cure their undead curse. The game features challenging combat, deep lore, and a dark, atmospheric world. It introduces new mechanics like dual-wielding and a flexible character progression system, with improved multiplayer options for cooperative and PvP play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-scholar-of-the-first-sin-playstation-3', 'Dark Souls II: Scholar of the First Sin', 'Dark Souls', '2015-04-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb02.jpg', 'Dark Souls II: Scholar of the First Sin is an enhanced edition of Dark Souls II, released in April 2015 by FromSoftware and Bandai Namco Entertainment. This version includes updated graphics, improved performance, and all previously released DLC expansions (Crown of the Sunken King, Crown of the Old Iron King, and Crown of the Ivory King). It also features rebalanced gameplay, new enemy placements, additional NPCs, and expanded lore,', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-playstation-3', 'Darksiders', 'Darksiders', '2010-01-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pao.jpg', 'In The Darkside Detective: A Fumble in the Dark - Tales of the Darkside you''ll join the fan favorite side characters to solve the mysteries of Twin Lake! Will the Bloodwolves, the Brightside Division, and Rexa each solve their cases and save Twin Lake', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-playstation-3', 'Darksiders II', 'Darksiders', '2012-08-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wi5.jpg', 'Become Death - The most feared of the legendary Four Horseman.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mortal-kombat-vs-dc-universe-playstation-3', 'Mortal Kombat vs. DC Universe', 'DC', '2008-11-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y13.jpg', 'In this arcade-style fighting game, both DC and Mortal Kombat universes are represented by 10 champions each, and one "boss" character, for a total of 22 fighters. Play is similar to the 2D Mortal Kombat games (with some 3D elements), focusing more on the special move aspect than the complex combos found in the previous three games (Deadly Alliance, Deception, Armageddon).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watchmen-the-end-is-nigh-playstation-3', 'Watchmen: The End Is Nigh', 'DC', '2009-07-21', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fv5.jpg', 'Watchmen: The End Is Nigh is an episodic video game series that serves as a prequel to the film adaptation of the DC Comics limited series Watchmen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-asylum-playstation-3', 'Batman: Arkham Asylum', 'DC', '2009-08-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voj.jpg', 'Batman: Arkham Asylum is an action-adventure game developed by Rocksteady Studios and published by Warner Bros. Interactive Entertainment. Released in 2009, it follows Batman as he battles the Joker, who seizes control of Arkham Asylum and frees its inmates. The game features stealth, combat, and detective elements, with players using Batman''s gadgets and skills to subdue enemies and solve puzzles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dc-universe-online-playstation-3', 'DC Universe Online', 'DC', '2011-01-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u18.jpg', 'DC Universe Online is a free-to-play superhero / supervillian MMORPG that lets players create their own unique tights-wearing hero or villain and roam the streets of places like Gotham City and Metropolis fighting or creating crime. Players fight alongside such iconic DC Comics characters as Superman and Batman, Lex Luthor and The Joker, and many others. Excellent physics help bring comic book action and combat to life, all under the creative direction of noted comic book artist Jim Lee.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('green-lantern-rise-of-the-manhunters-playstation-3', 'Green Lantern: Rise of the Manhunters', 'DC', '2011-06-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ky.jpg', 'Green Lantern: Rise of the Manhunters is an action video game, the first based on DC Comics'' Green Lantern (Hal Jordan). The game is a tie-in/sequel to the film Green Lantern, which opened in theatres on June 17, 2011. The game features 3D visuals on the PlayStation 3 and Xbox 360, providing TriOviz Inficolor 3D for standard televisions and stereoscopic 3D for dedicated 3DTVs.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-city-playstation-3', 'Batman: Arkham City', 'DC', '2011-10-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voh.jpg', 'Batman: Arkham City builds upon the intense, atmospheric foundation of Batman: Arkham Asylum, sending players soaring into Arkham City, the new maximum security "home" for all of Gotham City''s thugs, gangsters and insane criminal masterminds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-gods-among-us-playstation-3', 'Injustice: Gods Among Us', 'DC', '2013-04-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8616.jpg', 'What if our greatest heroes became our greatest threat? Injustice: Gods Among Us introduces a bold new franchise to the fighting game genre from NetherRealm Studios, creators of the definitive fighting game Mortal Kombat. Featuring DC Comics icons such Batman, Cyborg, The Flash, Harley Quinn, Nightwing, Solomon Grundy, Superman and Wonder Woman, the latest title from the award-winning studio presents a deep original story. Heroes and villains will engage in epic battles on a massive scale in a world where the line between good and evil has been blurred.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-origins-playstation-3', 'Batman: Arkham Origins', 'DC', '2013-10-25', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zg8.jpg', 'A free-to-play fighting video game for mobile that follows the same premise as the main versions of Arkham Origins.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('young-justice-legacy-playstation-3', 'Young Justice: Legacy', 'DC', '2013-11-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7mda.jpg', 'Young Justice: Legacy is a multiplayer action RPG based on the Young Justice TV series.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wolf-among-us-playstation-3', 'The Wolf Among Us', 'DC', '2014-11-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vdk.jpg', 'The fifth episode of The Wolf Among Us, a five-episode series based on Fables (DC Comics/Vertigo).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-telltale-series-playstation-3', 'Batman: The Telltale Series', 'DC', '2016-09-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u65.jpg', 'Batman: The Telltale Series is an episodic graphic adventure game developed by Telltale Games, first released in 2016. The game offers a narrative-focused experience, where players control Bruce Wayne and his alter ego, Batman, making choices that shape the story and relationships with characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-playstation-3', 'Dead Rising 2', 'Dead Rising', '2010-09-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzw.jpg', 'As Chuck Greene, you have 72 hours to save your infected daughter, clear your name and survive the hordes of hungry zombies before the military comes in and nukes the city. To ensure your survival, you can combine everyday objects to create numerous deadly combo weapons and slaughter the ravenous zombies. Dead Rising 2, it’s where Creativity Kills.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-off-the-record-playstation-3', 'Dead Rising 2: Off the Record', 'Dead Rising', '2011-10-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t1w.jpg', 'The new "Off the Record" storyline means an all new Dead Rising 2 experience. Frank will face off against more twisted enemies, build more outrageous combo weapons, follow his own unique mission structure and explore brand new areas of Fortune City to get his biggest scoop yet. Join Frank as he indulges in the insanity of "Uranus Zone," Fortune City’s very own theme park. Full of deadly rides and crazy attractions, the sci-fi themed Uranus Zone is a true zombie-killing paradise.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-playstation-3', 'Dead Space', 'Dead Space', '2008-10-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5th8.jpg', 'A 2011 science-fiction survival horror mobile game developed by Australian company IronMonkey Studios and published by Electronic Arts for iOS, BlackBerry Tablet OS, Xperia Play, Android and BlackBerry 10 devices.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-2-playstation-3', 'Dead Space 2', 'Dead Space', '2011-01-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co715m.jpg', 'Cancelled Nintendo Wii port of Dead Space 2.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-3-playstation-3', 'Dead Space 3', 'Dead Space', '2013-02-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2int.jpg', 'Dead Space 3 is a 2013 survival horror action video game developed by Visceral Games and published by Electronic Arts for PlayStation 3, Windows, and Xbox 360. It is the third and final main entry in the Dead Space series. The game supports online cooperative multiplayer sessions in which a second player takes the role of new character John Carver.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('demon-s-souls-playstation-3', 'Demon''s Souls', NULL, '2009-10-06', 'PlayStation 3', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coamv6.jpg', 'Soul Demon Hunters is a 2D side-scrolling action game with pixel graphics, where you resolve supernatural phenomena across the world through combat.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-playstation-3', 'Destiny', 'Destiny', '2014-09-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-human-revolution-playstation-3', 'Deus Ex: Human Revolution', 'Deus Ex', '2011-08-23', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rd2.jpg', 'In Deus Ex: Human Revolution you play Adam Jensen, a security specialist, handpicked to oversee the defense of one of America''s most experimental biotechnology firms. But when a black ops team breaks in and kills the scientists you were hired to protect, everything you thought you knew about your job changes. At a time when scientific advancements are routinely turning athletes, soldiers and spies into super-enhanced beings, someone is working very hard to ensure mankind''s evolution follows a particular path. You need to discover why - because the decisions you take and the choices you make will be the only things that can determine mankind''s future.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-4-playstation-3', 'Devil May Cry 4', 'Devil May Cry', '2008-02-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7uh1.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-hd-collection-playstation-3', 'Devil May Cry HD Collection', 'Devil May Cry', '2012-03-29', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n18.jpg', 'Devil May Cry HD Collection is a collection of high-definition remasters of the PS2 games of the first three games in the Devil May Cry franchise. In addition to the reworked graphics, it also contains trophies/achievements.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dmc-devil-may-cry-playstation-3', 'DmC: Devil May Cry', 'Devil May Cry', '2013-01-15', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u77.jpg', 'DmC: Devil May Cry is the fifth game in the hack-and-slash third-person action series and the first not largely developed by Capcom. This title is a reimagining of the series, with the same protagonist Dante, but set in an alternate universe. The Dante in this game is very different from before, doing away with the trademark white hair and altering the main character as well as the game''s tone with a much more Western influence. The gameplay is still largely identical as Dante engages many opponents with a fast fighting style, stringing together combos and hits in quick succession.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-playstation-3', 'Diablo III', 'Diablo', '2013-09-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gfx.jpg', 'Diablo III is an action role-playing game that takes place throughout the dark fantasy world of Sanctuary.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-ultimate-evil-edition-playstation-3', 'Diablo III: Ultimate Evil Edition', 'Diablo', '2014-08-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3irp.jpg', 'Diablo III: Ultimate Evil Edition includes the expansion pack Reaper of Souls and features special four-player co-op features. With the wireless controller and a custom-designed console interface, players will be outfitted with touch pad functionality and new social features as they engage in pulse-pounding combat with hordes of monsters and acquire items of incredible power.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-playstation-3', 'Dishonored', 'Dishonored', '2012-10-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coabgu.jpg', 'Dishonored is an immersive first-person action game that casts you as a supernatural assassin driven by revenge. With Dishonored’s flexible combat system, creatively eliminate your targets as you combine the supernatural abilities, weapons and unusual gadgets at your disposal. Pursue your enemies under the cover of darkness or ruthlessly attack them head on with weapons drawn. The outcome of each mission plays out based on the choices you make.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-game-of-the-year-edition-playstation-3', 'Dishonored Game Of The Year Edition', 'Dishonored', '2013-10-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa4rb.jpg', 'While this shares the name of the Definitive Edition remaster on PS4 and Xbox One, the PC version did not receive any graphical improvements, and just saw it''s Game of the Year Edition renamed to "Definitive Edition".
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-playstation-3', 'Disney Infinity', 'Disney Infinity', '2013-08-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-playstation-3', 'Disney Infinity 2.0', 'Disney Infinity', '2014-09-23', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-3-0-playstation-3', 'Disney Infinity 3.0', 'Disney Infinity', '2015-08-30', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3-bfg-edition-playstation-3', 'Doom 3: BFG Edition', 'Doom', '2012-10-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ovt.jpg', 'The BFG Edition features enhanced graphics, better audio with more horror effects, a checkpoint save system, and support for 3D displays and HMDs. The game also includes the previous expansion Resurrection of Evil and a new single-player expansion pack called The Lost Mission. Additionally, it includes copies of the original Doom (the Ultimate Doom edition with the add-on fourth episode, "Thy Flesh Consumed"), and Doom II with the expansion No Rest for the Living, previously available for the Xbox 360. The BFG Edition also features the ability to use the flashlight while holding a weapon, in the form of the so-called armor-mounted flashlight.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-origins-playstation-3', 'Dragon Age: Origins', 'Dragon Age', '2009-11-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvs.jpg', 'Dragon Age: Origins is a third-person role-playing game described as a spiritual successor to Baldur''s Gate and Neverwinter Nights franchises. Players create their own character by customizing gender and appearance as well as choosing a race and class. Combat is in real time with the ability to pause at any moment: tactical options include an editor which allows the player to give the AI detailed instructions on how to behave in every possible situation. Although the main storyline is the same for every character created, the game features six unique prologues, two for each race. Dragon Age: Origins received critical acclaim upon release, with praise mostly directed at its story, setting, characters, music and combat system.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-origins-ultimate-edition-playstation-3', 'Dragon Age: Origins Ultimate Edition', 'Dragon Age', '2010-10-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co868g.jpg', 'Dragon Age: Origins - Ultimate Edition includes Dragon Age: Origins, Dragon Age: Origins - Awakening and all nine content packs.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-ii-playstation-3', 'Dragon Age II', 'Dragon Age', '2011-03-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mw1.jpg', 'Dragon Age II is the sequel to Dragon Age: Origins and the second major game in the series. Like its predecessor, players can explore and engage in combat from a third-person perspective and will also encounter various companions who play major roles in the plot and gameplay. Depending on players'' decisions and dialogue, a companion will either recognize the main character Hawke as a friend or a rival. The game adopts the wheel-based dialogue system, meaning short responses that reflect different tones and attitudes the player wishes to choose for Hawke. The combat system is quite similar to the one used in the previous Dragon Age game, though it has been noticeably sped up.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-inquisition-playstation-3', 'Dragon Age: Inquisition', 'Dragon Age', '2014-11-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvy.jpg', 'Dragon Age: Inquisition is a role-playing game and the third main game in the Dragon Age series. It is set in the Thedas continent, the same fantasy world as the two previous games. It consist of two large countries: Ferelden (from Dragon Age: Origins) and Orlais, as well as the land inbetween.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('drakengard-3-playstation-3', 'Drakengard 3', 'Drakengard', '2014-05-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25oy.jpg', 'Drakengard 3 transports players to a medieval world where six goddess-like sisters known as "Intoners" have brought peace to the earth with their power to manipulate magic through song. Harmony is disrupted, however, when the eldest sister, Zero, attempts to murder her younger sisters with the help of her dragon companion, Mikhail. As the story progresses, players find themselves in a battle to unravel the mystery of Zero and learn her true intentions.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('driver-san-francisco-playstation-3', 'Driver: San Francisco', 'Driver', '2011-08-30', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gdt.jpg', 'The game takes place a few months after the events of Driv3r. It is revealed that both Tanner and Jericho survived the shootout in Istanbul. In the game''s trailer, it is revealed that since then, both men have recovered and Jericho has escaped to San Francisco, while Tanner has pursued him there. Jericho is shown being transported in the back of a prison truck, but manages to escape with a vial of acid hidden within his mouth. He overpowers the guards, and hijacks the truck. Tanner and Tobias witness this from Tanner''s car, pursuing Jericho as he causes havoc on the streets of the city. Tanner ends up in front of Jericho in an alleyway, and gets pushed in front of a tractor trailer. A hard crash occurs, putting him into a coma. The game will take place in Tanner''s coma dream', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-remastered-playstation-3', 'DuckTales: Remastered', 'DuckTales', '2013-11-12', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zsa.jpg', 'DuckTales Remastered takes the classic Disney platforming adventure to a whole new level. All of the visuals from the 8-bit game have been beautifully re-created as hand-drawn and animated sprites, across a backdrop of luscious, re-envisioned level backgrounds. Furthermore, original Disney Character Voices talent, including some from the cartoon TV series, bring in-game characters to life with charm and wit, while the classic melodies of the original soundtrack are given a modern twist. The game also features an all new tutorial level where players can get familiar with the iconic pogo jump and cane swing, while Scrooge McDuck''s Museum allows players to track all their stats and compare their progress with others via global leaderboards.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-oblivion-playstation-3', 'The Elder Scrolls IV: Oblivion', 'The Elder Scrolls', '2007-03-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fpz.jpg', 'The Elder Scrolls IV: Oblivion, the fourth game in the Elder Scrolls story, is set within the province of Cyrodiil, the heartland and Imperial capital of Tamriel. Emperor Uriel Septim VII is assassinated in flight from his own palace, but just before he dies he passes on to you the mystic Amulet of Kings. The adventure proper begins with the quest to find Uriel''s lost and illegitimate son who is the only heir to the throne. In a world where the forces of darkness seek their ultimate dominion over the ranks of man and mer alike, you alone stand between the future of Tamriel and the gates of Oblivion.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-oblivion-game-of-the-year-edition-playstation-3', 'The Elder Scrolls IV: Oblivion Game of the Year Edition', 'The Elder Scrolls', '2007-10-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ycb.jpg', 'The Elder Scrolls IV: Oblivion Game of the Year Edition presents one of the best RPGs of all time like never before. Step inside the most richly detailed and vibrant game-world ever created. With a powerful combination of freeform gameplay and unprecedented graphics, you can unravel the main quest at your own pace or explore the vast world and find your own challenges. Also included in the Game of the Year edition are Knights of the Nine and the Shivering Isles expansion, adding new and unique quests and content to the already massive world of Oblivion. See why critics called Oblivion the Best Game of 2006.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-shivering-isles-playstation-3', 'The Elder Scrolls IV: Shivering Isles', 'The Elder Scrolls', '2007-12-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j90.jpg', 'In the Shivering Isles expansion, see a world created in Sheogorath''s own image, one divided between Mania and Dementia and unlike anything you''ve experienced in Oblivion.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-playstation-3', 'The Elder Scrolls V: Skyrim', 'The Elder Scrolls', '2011-11-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tnw.jpg', 'Skyrim reimagines and revolutionizes the open-world fantasy epic, bringing to life a complete virtual world open for you to explore any way you choose. Play any type of character you can imagine, and do whatever you want; the legendary freedom of choice, storytelling, and adventure of The Elder Scrolls is realized like never before.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-legendary-edition-playstation-3', 'The Elder Scrolls V: Skyrim – Legendary Edition', 'The Elder Scrolls', '2013-06-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dcm.jpg', 'Live Another Life, In Another World: Play any type of character you can imagine, and do whatever you want; the freedom of choice, storytelling, and adventure of The Elder Scrolls comes to life in one legendary experience from all three official add-ons.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enslaved-odyssey-to-the-west-playstation-3', 'Enslaved: Odyssey to the West', NULL, '2010-10-05', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gko.jpg', 'Follow a gripping, surprise-filled journey as two dissimilar characters form an uneasy partnership in order to survive through a perilous, post-apocalyptic America. 150 years in the future, war and destruction have left the world in ruins with few humans remaining and nature having reclaimed the world.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-2-the-power-of-two-playstation-3', 'Epic Mickey 2: The Power of Two', 'Epic Mickey', '2012-11-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nhy.jpg', 'Unleash the power of the brush in an all new co-op adventure. Join Mickey and Oswald in an epic battle to save the magical world of Wasteland and change it forever. Interact with your favorite characters like never before in the most heroic adventure yet.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-playstation-3', 'The Evil Within', 'The Evil Within', '2014-10-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgs.jpg', 'The Evil Within embodies the meaning of pure survival horror. Highly-crafted environments, horrifying anxiety, and an intricate story are combined to create an immersive world that will bring you to the height of tension. With limited resources at your disposal, you’ll fight for survival and experience profound fear in this perfect blend of horror and action.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-3-playstation-3', 'Fallout 3', 'Fallout', '2008-10-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yj5.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-new-vegas-playstation-3', 'Fallout: New Vegas', 'Fallout', '2010-10-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u60.jpg', 'In this first-person Western RPG, the player takes on the role of Courier 6, barely surviving after being robbed of their cargo, shot and put into a shallow grave by a New Vegas mob boss. The Courier sets out to track down their robbers and retrieve their cargo, and winds up getting tangled in the complex ideological and socioeconomic web of the many factions and settlements of post-nuclear Nevada.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-76-playstation-3', 'Fallout 76', 'Fallout', '2018-11-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yc4.jpg', 'Bethesda Game Studios welcome you to Fallout 76. Twenty-five years after the bombs fall you and your fellow Vault Dwellers, chosen from the nation’s best and brightest, emerge into post-nuclear America on Reclamation Day, 2102. Play solo or join together as you explore, quest, build, and triumph against the wasteland’s greatest threats. Explore a vast wasteland, devastated by nuclear war, in this open-world multiplayer addition to the Fallout story. Experience the largest, most dynamic world ever created in the legendary Fallout universe.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-2-playstation-3', 'Far Cry 2', 'Far Cry', '2008-10-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpo.jpg', 'A civil war has swept through the country and you''re caught in the middle of it. Track down the person at the forefront of the fighting, a ruthless arms dealer known only as "The Jackal". As you undertake deadly missions and form fragile alliances with conflicting rebel groups, one thing becomes clear - the Jackal is hunting you too.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-playstation-3', 'Far Cry 3', 'Far Cry', '2012-12-04', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpd.jpg', 'Explore an island playground as stunningly beautiful as it is diverse – from mountain ranges to swampy grasslands and white sandy beaches. Fight your way through the island’s towns, temples, river ports and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-compilation-playstation-3', 'Far Cry Compilation', 'Far Cry', '2014-01-02', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62si.jpg', 'Far Cry Compilation is a collection of Far Cry games that includes Far Cry 2, Far Cry 3 and Far Cry 3: Blood Dragon. The compilation was created to celebrate the tenth anniversary of the Far Cry series and released only in North America.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-4-playstation-3', 'Far Cry 4', 'Far Cry', '2014-11-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ke6.jpg', 'Dive into the savage universe of Far Cry with this double-pack edition featuring both Far Cry 4 and Far Cry: Primal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiii-playstation-3', 'Final Fantasy XIII', 'Final Fantasy', '2010-03-09', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coboys.jpg', 'As a deepening crisis threatens to plunge the floating world of Cocoon into chaos, a band of unsuspecting strangers find themselves branded enemies of the state. With the panicking population baying for their blood, and the military all too happy to oblige, they have no choice but to run for their lives. Join them on a desperate quest to challenge the forces controlling their fate, and prevent untold destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiii-2-playstation-3', 'Final Fantasy XIII-2', 'Final Fantasy', '2012-01-31', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tr9.jpg', 'FINAL FANTASY XIII-2 is created with the aim of surpassing the quality of its predecessor in every way, featuring new gameplay systems and cutting-edge visuals and audio. In this game the player has the freedom to choose from a range of possibilities and paths; where their choices affect not only the immediate environment, but even shape time and space!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiv-playstation-3', 'Final Fantasy XIV', 'Final Fantasy', '2013-08-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobl9m.jpg', 'Take part in an epic and ever-changing Final Fantasy as you adventure and explore with friends from around the world. Final Fantasy XIV Online is the 2013 relaunch of the massively multiplayer online role-playing game that takes the wonder of the FF legacy and expands it, allowing you to explore the realm of Eorzea like never before in a Final Fantasy game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lightning-returns-final-fantasy-xiii-playstation-3', 'Lightning Returns: Final Fantasy XIII', 'Final Fantasy', '2014-02-11', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coblfq.jpg', 'As Lightning, it is your mission to save souls so they may be brought to a new world. However, with only thirteen days remaining, not everyone can be saved. Armed with all-new weapons, player customization and battle abilities, you are in a race against time to fully understand your destiny. It all ends here.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-x-2-hd-remaster-playstation-3', 'Final Fantasy X/X-2 HD Remaster', 'Final Fantasy', '2014-03-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zpl.jpg', 'Based on the international versions of the games that were previously only released in Japan and Europe, FINAL FANTASY X/X-2 HD Remaster brings these timeless classics forward to the current generation of fans, old and new alike.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-collection-playstation-3', 'God of War Collection', 'God of War', '2009-11-17', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ene.jpg', 'God of War: Origins Collection (known as God of War Collection – Volume II in Europe and Australia) is a remastered port of the two PlayStation Portable instalments in the series—Chains of Olympus and Ghost of Sparta—for the PlayStation 3 on a single Blu-ray Disc.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-iii-playstation-3', 'God of War III', 'God of War', '2010-03-16', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3koi.jpg', 'Set in the realm of brutal Greek mythology, God of War III is a single-player game that allows players to take on the climatic role of the ex-Spartan warrior, Kratos, as he scales through the intimidating heights of Mt. Olympus and the dark depths of Hell to seek revenge on those who have betrayed him. Armed with double-chained blades, and an array of new weapons and magic for this iteration of the trilogy, Kratos must take on mythology''s darkest creatures while solving intricate puzzles throughout his merciless quest to destroy Olympus. Utilizing a new game engine built from the ground up and state-of-the-art visual technologies, the development team behind God of War III has made standard-setting strides in giving players the realistic feel of actually being on the battlegrounds. With texture resolutions quadrupling since God of War II on PlayStation 2 computer entertainment system, God of War III, in its debut on the PS3 system, will feature fluid, life-like characters, as well as dynamic lighting effects, a robust weapon system, and world-changing scenarios that will truly bring unmistakable realism to Kratos'' fateful quest. Players will have a chance to join battles on a grand scale that is four times larger than its predecessor.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-origins-collection-playstation-3', 'God of War: Origins Collection', 'God of War', '2011-09-13', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ene.jpg', 'God of War: Origins Collection (known as God of War Collection – Volume II in Europe and Australia) is a remastered port of the two PlayStation Portable instalments in the series—Chains of Olympus and Ghost of Sparta—for the PlayStation 3 on a single Blu-ray Disc.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-ascension-playstation-3', 'God of War: Ascension', 'God of War', '2013-03-12', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3die.jpg', 'God of War: Ascension, the seventh instalment in the God of War series, acts as a prequel to the preceding games. The narrative revolves around Kratos, the protagonist from earlier instalments, who was once a loyal servant of the God of War, Ares. Tricked by Ares into unknowingly murdering his own family, Kratos breaks the blood oath binding him to Ares and abandons his former master. Subsequently, Kratos finds himself imprisoned and must navigate a path to freedom, severing the bond between him and Ares.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-beast-rider-playstation-3', 'Golden Axe: Beast Rider', 'Golden Axe', '2008-10-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5x8e.jpg', 'Beast Rider is the first Golden Axe game in 3D as opposed to side scrolling hack and slash. While this is a major shift in game style from the previous games, Beast Rider maintains many of the elements from the originals such as magic and riding beasts, as well as sending the player on a quest to defeat Death Adder.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-iv-playstation-3', 'Grand Theft Auto IV', 'Grand Theft Auto', '2008-04-29', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbv.jpg', 'Grand Theft Auto IV is an action-adventure video game developed by Rockstar North and published by Rockstar Games. It is the eleventh title in the Grand Theft Auto series, and the first main entry since 2004''s Grand Theft Auto: San Andreas.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-episodes-from-liberty-city-playstation-3', 'Grand Theft Auto: Episodes from Liberty City', 'Grand Theft Auto', '2010-04-13', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbe.jpg', 'Episodes from Liberty City is a standalone compilation of the episodes: Grand Theft Auto IV: Ballad of Gay Tony and Grand Theft Auto IV: The Lost and Damned', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-playstation-3', 'Grand Theft Auto V', 'Grand Theft Auto', '2013-09-17', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('heavenly-sword-playstation-3', 'Heavenly Sword', NULL, '2007-09-12', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w52.jpg', 'Developed by Ninja Theory, Heavenly Sword is a visually stunning martial arts drama set in a mythical time and place in the Far East.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('heavy-rain-playstation-3', 'Heavy Rain', NULL, '2010-02-23', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaajv.jpg', 'Heavy Rain is a cinematic psychological thriller from game developer Quantic Dream exclusively for the PlayStation 3. Dealing with a range of adult themes, the game revolves around a sophisticated plot and strong narrative threads that explore a complex moral proposition. You assume the role of multiple characters with very different backgrounds, motivations, and skills in a world where each player decision affects what will follow.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-ico-shadow-of-the-colossus-collection-playstation-3', 'The Ico & Shadow of the Colossus Collection', NULL, '2011-09-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ako.jpg', 'The Ico & Shadow of the Colossus Collection is a video game bundle that contains high-definition remasters of two older PlayStation 2 games for the PlayStation 3, and was developed by Bluepoint Games and released alongside Ico as The Ico & Shadow of the Colossus Collection in September 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('infamous-playstation-3', 'Infamous', 'Infamous', '2009-05-26', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525t.jpg', 'Infamous is a single player open-world action/adventure game that places you in the role of Cole McGrath, a once regular guy who in the aftermath of a horrific catastrophe finds himself not only alive, but developing a fantastic array of superpowers. Going from ordinary to extraordinary overnight isn''t something to take lightly. With these powers does one exact revenge? Protect the innocent? Or perhaps, dabble in a little of both? The choice is yours in Infamous.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('infamous-2-playstation-3', 'Infamous 2', 'Infamous', '2011-06-07', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525u.jpg', 'Blamed for the destruction of Empire City and haunted by the ghosts of his past, reluctant hero Cole MacGrath makes a dramatic journey to the historic Southern city of New Marais in an effort to discover his full super-powered potential -- and face a civilization-ending confrontation with a dark and terrifying enemy from his own future. Gifted with extraordinary god-like abilities, Cole alone has the power to save humanity, but the question is-- will he choose to do so?', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-jackbox-party-pack-playstation-3', 'The Jackbox Party Pack', NULL, '2015-11-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zel.jpg', 'The team behind "You Don''t Know Jack" presents five guffaw-inducing party games in one pack! You''re gonna need more than one party for this. Your phones or tablets are your controllers! For 1-100 players! Games include:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-collection-playstation-3', 'Jak and Daxter Collection', 'Jak and Daxter', '2012-02-07', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ny0.jpg', 'The Jak and Daxter Collection is a compilation of the first three main instalments in the Jak and Daxter series (The Precursor Legacy, Jak II, and Jak 3) remastered in full 720p HD with support for 3D graphics and PlayStation Network trophies.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('journey-collector-s-edition-playstation-3', 'Journey Collector''s Edition', NULL, '2012-08-28', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xeb.jpg', 'Journey Collectors Edition is the first retail disc release for thatgamecompany. It features Journey as well as the studio''s previously released flOw and Flower and more. It was released August 28th, 2012 for the PlayStation 3.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('katamari-forever-playstation-3', 'Katamari Forever', 'Katamari', '2009-09-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hjm.jpg', 'Katamari Forever contains 34 stages, with all but three of the stages being taken from previous titles in the series. Half of the stages take place within the mind of the King of All Cosmos, who gets knocked in the head and suffers from amnesia. The levels are black-and-white in appearance, and the objective is to roll up junk to bring color back to the stages. The other half of the stages take place in the present, where RoboKing, a robotic version of the King of All Cosmos created by the cousins, goes on a rampage and destroys all the stars in the sky.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-2-playstation-3', 'Killzone 2', 'Killzone', '2009-02-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3j9z.jpg', 'Killzone 2 is the third game in the Killzone franchise and continues the story two years after the events of the first two games. The gameplay consists of what the developers describe as Hollywood Realism, focusing on scripted, cinematic gameplay. The game is played entirely from the first-person perspective, except for the portions with vehicular combat with a tank and an exoskeleton. Next to the single-player campaign, there is squad-based multiplayer called Warzone with five different kinds of missions (Assassination, Search & Retrieve, Search & Destroy, Bodycount and Capture & Hold) based on seven kinds of classes. There is support for up to 32 players, with the addition of bots to fill the remaining spots.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-3-playstation-3', 'Killzone 3', 'Killzone', '2011-02-22', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mer.jpg', 'Killzone 3 is the fourth game in the Killzone franchise. Several improvements have been made over its prequel, and it can be seen in overall smoother and more balanced gameplay. As in previous game, you will commandeer various turrets and vehicles which will add to firepower but will leave you with rails-driven gameplay. One of the new weapons is a jet-pack which lets you jump and semi-fly with unlimited ammo as a part of new exoskeleton. The environment can sometimes be destroyed or used to your advantage, shooting barrels or certain plants will take out nearby enemy soldiers. Beside single-player campaign, Killzone 3 offers an upgraded version of Killzone 2''s multiplayer. The game is also the first in the franchise to support 3D TVs.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-trilogy-playstation-3', 'Killzone Trilogy', 'Killzone', '2012-10-23', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v3z.jpg', 'Tackle the legendary might of the Helghast army in three blockbuster adventures
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-hd-1-5-remix-playstation-3', 'Kingdom Hearts HD 1.5 Remix', 'Kingdom Hearts', '2013-09-10', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co319i.jpg', 'Kingdom Hearts HD 1.5 Remix includes...
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-hd-2-5-remix-playstation-3', 'Kingdom Hearts HD 2.5 Remix', 'Kingdom Hearts', '2014-12-02', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co315m.jpg', 'Kingdom Hearts HD 2.5 Remix is an HD remastered compilation of Kingdom Hearts II Final Mix and Kingdom Hearts Birth by Sleep Final Mix. Previously exclusive to Japan, both games will be available for the first time to North America for PlayStation 3. HD remastered cinematics from Kingdom Hearts Re:coded will also be included in the compilation.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-playstation-3', 'L.A. Noire', 'L.A. Noire', '2011-05-17', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldn.jpg', 'L.A. Noire is a neo-noir detective action-adventure video game developed by Team Bondi and published by Rockstar Games. It was initially released for the PlayStation 3 and Xbox 360 platforms on 17 May 2011; a Microsoft Windows port was later released on 8 November 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-the-complete-edition-playstation-3', 'L.A. Noire: The Complete Edition', 'L.A. Noire', '2011-10-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldm.jpg', 'L.A. Noire is set in Los Angeles in 1947 and challenges the player, controlling a Los Angeles Police Department (LAPD) officer, to solve a range of cases across five divisions. Players must investigate crime scenes for clues, follow up leads, and interrogate suspects, and the player''s success at these activities will impact how much of each case''s story is revealed.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-of-us-playstation-3', 'The Last of Us', 'The Last of Us', '2013-06-14', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ziw.jpg', 'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble nature of the player character introduces platforming elements, allowing the player to jump and climb to traverse environments and gain advantages during combat.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-complete-saga-playstation-3', 'Lego Star Wars: The Complete Saga', 'Lego', '2007-11-06', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrr.jpg', 'Play through a fun Star Wars galaxy that combines the endless customization of LEGO with the epic story from all six episodes of Star Wars. This is the definitive LEGO Star Wars comprising the first two games and expanding them with new characters, enhanced visuals, and more bonus levels than you can shake a lightsaber at.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-playstation-3', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-playstation-3', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-rock-band-playstation-3', 'Lego Rock Band', 'Lego', '2009-11-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wpb.jpg', 'LEGO Rock Band is a blending of Rock Band and LEGO series. Players get to start a band and hire band members who will play with them. Just like with real Lego, players can mix and match bodies, torsos, legs and heads to create a character any way they want. The main game has players touring around the world at various locations, like the original Rock Band games. Unlike Rock Band however, LEGO Rock Band also has special levels where you must perform outrageous tasks such as fighting an octopus or demolishing a building using your rock concert. As players make their way through the song lists, they earn "Studs", the game''s currency. Studs can be used to purchase Lego items to decorate your Rock Den, hire new staff, buy new clothes or instruments.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-2-the-adventure-continues-playstation-3', 'Lego Indiana Jones 2: The Adventure Continues', 'Lego', '2009-11-17', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6up6.jpg', 'LEGO Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO fashion, get creative and build your own levels to play with friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-1-4-playstation-3', 'Lego Harry Potter: Years 1–4', 'Lego', '2010-06-29', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65lz.jpg', 'LEGO Harry Potter: Years 1-4 will give gamers the chance to experience the magic and adventure of Harry Potter in a uniquely LEGO way. Playing as Harry Potter, Ron Weasley and Hermione Granger, as well as more than 100 other favorite characters, gamers will have the opportunity to attend lessons, cast spells, mix potions, fly on broomsticks and complete tasks to earn rewards. Throughout the game, players will also have the freedom to explore iconic settings from the wizarding world including Hogwarts castle, Diagon Alley, the Forbidden Forest and the village of Hogsmeade.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-playstation-3', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-playstation-3', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-playstation-3', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-playstation-3', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-playstation-3', 'Lego The Lord of the Rings', 'Lego', '2012-11-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-playstation-3', 'Lego Marvel Super Heroes', 'Lego', '2013-10-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-playstation-3', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-playstation-3', 'Lego The Hobbit', 'Lego', '2014-04-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-playstation-3', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-playstation-3', 'Lego Jurassic World', 'Lego', '2015-06-12', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dimensions-playstation-3', 'Lego Dimensions', 'Lego', '2015-09-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w4t.jpg', 'Help stop crime in the Lego Dimensions multiverse with Lego City’s Chase McCain. Build and place Chase on the Lego Toy Pad to bring him to life in the game. Use his Lego City Detective Scanner to track down bad guys and change his disguise to unlock more abilities. Become a Miner to break Silver Lego bricks or a Fireman to use your Water Beam to put out fires. Unlock the Lego City Adventure World to explore new areas like Blackwell’s moonbase and the Lego City Police Department, and the Battle Arena to compete with up to 4 of your friends. Build Chase’s Police Helicopter to fire off bolts, then rebuild it into the Police Hovercraft and Police Plane for additional in-game abilities.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-playstation-3', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-playstation-3', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-playstation-3', 'LittleBigPlanet', 'LittleBigPlanet', '2008-10-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49cl.jpg', 'LittleBigPlanet is a 2009 puzzle platformer video game (with user-generated content) for the PlayStation Portable developed by SCE Cambridge Studio in conjunction with Media Molecule. It is a new entry in the LittleBigPlanet franchise made exclusively for the PSP, featuring a brand new story mode.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-game-of-the-year-edition-playstation-3', 'LittleBigPlanet – Game of the Year edition', 'LittleBigPlanet', '2009-09-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kps.jpg', 'If you were to stand on LittleBigPlanet and try to imagine a more astounding, fantastic, and creative place, full of enthralling adventure, uncanny characters, and brilliant things to do... you couldn’t. All imagination is here, and what you do with it all is entirely up to you.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-2-playstation-3', 'LittleBigPlanet 2', 'LittleBigPlanet', '2011-01-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ijw.jpg', 'LittleBigPlanet 2 is a puzzle platformer video game centered around user-generated content, first announced on May 8th, 2010 in the June 2010 issue of gaming magazine Game Informer. The game was developed by Media Molecule and published by Sony Computer Entertainment Europe for the PlayStation 3 console, and is the last major Little Big Planet game in the series to be produced by Media Molecule, as the sequel, Little Big Planet 3 would be produced by Sumo Digital, Tarsier Studios, and The Station.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-2-special-edition-playstation-3', 'LittleBigPlanet 2: Special Edition', 'LittleBigPlanet', '2011-11-15', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kpu.jpg', 'Exclusive for North America, a Special Edition of LittleBigPlanet 2 was released on November 15th 2011. This edition includes the standard edition of the game, PlayStation Move support, "Move Pack: Rise of the Cakeling" (5 new levels and 7 mini-levels), "Disney/Pixar Toy Story Level" and "Costume" packs, and "Pets Costumes" (the "Dogs", "Cats", and "Even More Animals Costume" packs). The Special Edition was also included as a pack-in game with the 2011 holiday 160GB PS3 system bundles in North America.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-karting-playstation-3', 'LittleBigPlanet Karting', 'LittleBigPlanet', '2012-11-06', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2f3a.jpg', 'Give full throttle to your imagination and join Sackboy and Sackgirl on the starting grid for a kart racing adventure like no other. Fire up your engines, jump behind the steering wheel and take on your friends and foes in breathtakingly unpredictable battles through an ever-changing world of content. Are you ready?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-3-playstation-3', 'LittleBigPlanet 3', 'LittleBigPlanet', '2014-11-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3t1c.jpg', 'In LittleBigPlanet 3, explore a world filled with creativity as you explore all corners of the Imagisphere, meet the inhabitants of the mysterious planet Bunkum and face the nefarious Newton. Discover endless surprises that the LittleBigPlanet Community have created and shared for you to enjoy, with new levels and games to play every day. Then if you''re feeling inspired, flex your creative muscles with the powerful and intuitive customization tools, to bring your own imagination to life in LittleBigPlanet 3.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-playstation-3', 'Marvel: Ultimate Alliance', 'Marvel', '2006-11-17', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-playstation-3', 'Spider-Man 3', 'Marvel', '2007-05-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-rise-of-the-silver-surfer-playstation-3', 'Fantastic Four: Rise of the Silver Surfer', 'Marvel', '2007-06-15', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x77.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-playstation-3', 'Iron Man', 'Marvel', '2008-05-02', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-playstation-3', 'The Incredible Hulk', 'Marvel', '2008-06-05', 'PlayStation 3', 0, 0, NULL, NULL, NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-playstation-3', 'Spider-Man: Web of Shadows', 'Marvel', '2008-10-21', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ujz.jpg', 'Spider-Man: Web of Shadows is a video game title encompassing three versions: a full-3D action game for Microsoft Windows, PlayStation 3, Wii, and Xbox 360; a 2.5D sidescrolling beat em up action game for the PlayStation Portable and PlayStation 2 (called Amazing Allies Edition), and a 2.5D side-scrolling brawler/platformer for the Nintendo DS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-playstation-3', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-playstation-3', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-15', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-2-playstation-3', 'Iron Man 2', 'Marvel', '2010-05-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sxm.jpg', 'This is the Wii version of Iron Man 2, an action-adventure video game loosely based on the 2010 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-shattered-dimensions-playstation-3', 'Spider-Man: Shattered Dimensions', 'Marvel', '2010-09-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zpp.jpg', 'Spider-Man: Shattered Dimensions is a thrilling action-packed adventure set in four dramatically different universes from legendary Spider-Man lore, each with a distinct Spider-Man armed with unique skills and strengths, in one original storyline. Players will be transported to new locations never before seen in a Spider-Man game, from lush jungles and dusty deserts to various urban terrains. Acclaimed comic book writer Dan Slott takes players on a mission to contain the magical energy of the Tablet of Order and Chaos, which has been shattered and sent hurtling across parallel universes, and battle fan-favorite villains in a quest to restore the fabric of reality.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-the-infinity-gauntlet-playstation-3', 'Marvel Super Hero Squad: The Infinity Gauntlet', 'Marvel', '2010-11-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2di9.jpg', 'Marvel Super Hero Squad: The Infinity Gauntlet is a continuation of the video game Marvel Super Hero Squad and it was released on November 16, 2010. Similar to the first game, it features cartoonish Super-deformed versions of the Marvel Comics characters, as seen in the Marvel Super Hero Squad toy line, as well as the television show.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-3-fate-of-two-worlds-playstation-3', 'Marvel vs. Capcom 3: Fate of Two Worlds', 'Marvel', '2011-02-15', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ye3.jpg', 'Marvel vs. Capcom 3: Fate of Two Worlds is a crossover fighting game developed by Capcom in collaboration with Eighting. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. It was released for the PlayStation 3 and Xbox 360 consoles in February 2011. It is the fifth installment of the Marvel vs. Capcom franchise and the first to use three-dimensional character models instead of sprites.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thor-god-of-thunder-playstation-3', 'Thor: God of Thunder', 'Marvel', '2011-05-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co531w.jpg', 'Thor: God of Thunder is an action-adventure game developed by Liquid Entertainment and published by Sega in 2011. It serves as a tie-in to the Thor film from the Marvel Cinematic Universe. Players control Thor as he wields Mjolnir to battle enemies across the Nine Realms, facing iconic foes such as Surtur and Ulik while protecting Asgard from destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-super-soldier-playstation-3', 'Captain America: Super Soldier', 'Marvel', '2011-07-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ovp.jpg', 'The Nintendo 3DS port of Captain America: Super Soldier.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-destiny-playstation-3', 'X-Men: Destiny', 'Marvel', '2011-09-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnk.jpg', 'X-Men: Destiny is an action role-playing video game based on the X-Men comic book series. It was developed by Silicon Knights. Written by Mike Carey, the writer of the X-Men: Legacy comic book series, it was first published and released by Activision for the Nintendo DS, PlayStation 3, Xbox 360 and Wii consoles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-edge-of-time-playstation-3', 'Spider-Man: Edge of Time', 'Marvel', '2011-10-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h30.jpg', 'The fate of one Webslinger hangs on the webs of another in this game where two Spider-Man worlds collide with the death - yes, the death - of Peter Parker. Play as the Amazing Spider-Man and Spider-Man 2099 in a storyline that weaves together two timelines. The two heroes battle in separate worlds with a shared destiny, working to prevent an event that has dire consequences for Parker and the fate of the worlds he protects. Your actions in one timeline could cause ripple effects in the other. Picture-in-picture visuals let you watch your actions change the future - or rewrite the past - for better or for worse.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-comic-combat-playstation-3', 'Marvel Super Hero Squad: Comic Combat', 'Marvel', '2011-11-15', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co485l.jpg', 'Marvel Super Hero Squad: Comic Combat is a video game that uses the uDraw GameTablet, developed by Griptonite Games, and published by THQ and Vivendi Games. The game is the third in the Marvel Super Hero Squad franchise, acting as the sequel to two video games Marvel Super Hero Squad and Marvel Super Hero Squad: The Infinity Gauntlet. It was released on November 15, 2011 for the uDraw GameTablet, PlayStation 3, Xbox 360, and Nintendo Wii game systems.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-marvel-vs-capcom-3-playstation-3', 'Ultimate Marvel vs. Capcom 3', 'Marvel', '2011-11-15', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yej.jpg', 'Ultimate Marvel vs. Capcom 3 is a crossover fighting game developed by Capcom in collaboration with Eighting. It is an updated version of Marvel vs. Capcom 3: Fate of Two Worlds. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. The game was released in November 2011 for the PlayStation 3 and Xbox 360, and was featured as a launch title for the PlayStation Vita in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mib-alien-crisis-playstation-3', 'MIB: Alien Crisis', 'Marvel', '2012-05-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9cbu.jpg', 'Become the next top agent of the Men In Black. Arm yourself with a full arsenal of iconic MIB weapons to investigate and stop an evil alien plot to snatch up an ancient artifact that is the key to seizing control of the universe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-playstation-3', 'The Amazing Spider-Man', 'Marvel', '2012-06-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deadpool-playstation-3', 'Deadpool', 'Marvel', '2013-06-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xsf.jpg', 'In Deadpool the player takes control of the loud-mouthed, foul-mouthed, merc-with-a-mouth Wade Wilson (a.k.a. Deadpool). While on out on a contract to kill a corrupt media mogul, Mister Sinister intervenes and kills him instead, drawing the ire of Deadpool who then vows revenge only to stumble upon a bigger plot which could spell the end of humanity.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-playstation-3', 'The Amazing Spider-Man 2', 'Marvel', '2014-04-29', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-2-playstation-3', 'Mass Effect 2', 'Mass Effect', '2011-01-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9jdu.jpg', 'Firewalker Pack is a DLC pack for Mass Effect 2.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-3-playstation-3', 'Mass Effect 3', 'Mass Effect', '2012-03-06', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5rwt.jpg', 'The N7 Digital Deluxe Edition contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-playstation-3', 'Mass Effect', 'Mass Effect', '2012-12-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7c1f.jpg', 'The heavily anticipated continuation of the Mass Effect series.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('max-payne-3-playstation-3', 'Max Payne 3', 'Max Payne', '2012-05-15', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mjo.jpg', 'Max Payne 3 is a third-person shooter in which the player assumes the role of its titular character, Max Payne. A new feature to the series, introduced in Max Payne 3, is the cover system, which allows players to gain a tactical advantage, and avoid taking damage from enemies. To progress through the linear story, players take on enemies throughout levels. The game features interactive cutscenes which transition seamlessly into continuing gameplay; there are no loading screens across gameplay and cutscenes.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-4-guns-of-the-patriots-playstation-3', 'Metal Gear Solid 4: Guns of the Patriots', 'Metal Gear', '2008-06-12', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5eju.jpg', 'Metal Gear Solid 4: Guns of the Patriots is the final canonical Metal Gear game to feature Solid Snake as the main character. The gameplay of the previous games have been kept along with some new features, such as the ability to roll on your back and also to hide in bins scattered around the environment. Most of the story and the relationship between the characters are explained through cut-scenes with a considerable length, so knowledge of the prior games is recommended to fully understand the story. The game also features a complex multiplayer mode entitled Metal Gear Online with some original missions based on the stealth aspects of the single-player games.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-hd-collection-playstation-3', 'Metal Gear Solid HD Collection', 'Metal Gear', '2011-11-08', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gkj.jpg', 'From the critically acclaimed director, Hideo Kojima, Metal Gear Solid HD Collection offers a handful of the most popular Metal Gear Solid titles from the past in true HD for the first time ever. Featuring three complete games, Metal Gear Solid 2: Sons of Liberty, Metal Gear Solid: Snake Eater and Metal Gear Solid: Peace Walker, the HD Collection offers old and new fans a chance to experience the epic game play, design and storytelling of the MGS franchise. The "Metal Gear Solid (MGS)" series is the seminal work of Hideo Kojima, Japan''s master game creator, and the progenitor of the stealth action game genre. The series has become a global phenomenon, with over 27 million copies sold worldwide. The player controls a secret agent from an elite special forces unit who is sent on solo sneaking missions through enemy installations, vast jungles, and sometimes even the thick of battle. Alone and surrounded by the enemy, even a special forces agent will find it tough to come out alive. But that is the secret behind the series'' popularity-the cerebral challenge of figuring out how to avoid combat, and the thrill of sneaking through enemy territory undetected.The MGS series is also known for its storyline, which blends seamlessly with the gameplay. The scenarios are based on extensive research and incorporate the drama of actual developments in society. These elements have made MGS what it is today: a mature work of entertainment that transcends national borders and the confines of video games, and one of the leading products of the Japanese content business.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-rising-revengeance-playstation-3', 'Metal Gear Rising: Revengeance', 'Metal Gear', '2013-02-19', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1t.jpg', 'Developed by Kojima Productions and PlatinumGames, Metal Gear Rising: Revengeance takes the renowned Metal Gear franchise into exciting new territory with an all-new action experience. The game seamlessly melds pure action and epic story-telling that surrounds Raiden – a child soldier transformed into a half-human, half-cyborg ninja who uses his High Frequency katana blade to cut through any thing that stands in his vengeful path!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-the-legacy-collection-playstation-3', 'Metal Gear Solid: The Legacy Collection', 'Metal Gear', '2013-07-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45jf.jpg', 'Metal Gear Solid: The Legacy Collection is a video game compilation released exclusively for the PlayStation 3. It includes all the mainline Metal Gear games directed and designed by Hideo Kojima (including the VR Missions standalone expansion) that were released from 1987 through 2012. Bonus content include motion comic adaptations of the Metal Gear Solid graphic novels by Kris Oprisko and Ashley Wood and a 100-page booklet that catalogs numerous promotional posters, brochures and advertisement related to the games in the compilation.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-ground-zeroes-playstation-3', 'Metal Gear Solid V: Ground Zeroes', 'Metal Gear', '2014-03-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v88.jpg', 'Metal Gear Solid V: Ground Zeroes is a prologue to Metal Gear Solid V: The Phantom Pain. It offers players new sneaking and traversal methods compared to its predecessors, as well as the choice in what order the story events take place by selecting missions by advance. The most important change for this title is the shift to an open world design with a real-time day and night cycle doing away with the linear mission approach of previous games. The game was originally developed as a mission for The Phantom Pain, but an extended development time resulted in director Hideo Kojima splitting the specific portion of the game as a stand-alone product so that players could get early access to Metal Gear Solid V.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-phantom-pain-playstation-3', 'Metal Gear Solid V: The Phantom Pain', 'Metal Gear', '2015-09-01', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v85.jpg', 'Metal Gear Solid V: The Phantom Pain is the sequel to Metal Gear Solid V: Ground Zeroes and a prequel to the original Metal Gear. The game has a complex story with long cut-scene sequences, but there are fewer and they are shorter compared to earlier Metal Gear Solid titles. Most of the gameplay mechanics introduced in Ground Zeroes are carried over: it is still an action game and stealth oriented but replaces the linear corridor design from most earlier titles with large open world environments that offer the player unrestricted freedom for the approach. The world has now a real-time day and night cycle and various weather effects that influence enemy behaviour, visibility and sound. Sabotaging or destroying certain structures can also influence other parts of the map.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-conquest-playstation-3', 'The Lord of the Rings: Conquest', 'Middle-earth', '2009-01-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lup.jpg', 'Play as Evil characters in a brand new, ''Evil'' campaign. Battle through scenarios after Frodo failed to destroy the One Ring; it''s good to be bad! Battle online, in a co-op campaign or offline in split-screen.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-aragorn-s-quest-playstation-3', 'The Lord of the Rings: Aragorn''s Quest', 'Middle-earth', '2010-09-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9nie.jpg', 'The NDS/PSP ports features slightly different HUD, and the NDS version uses the second screen as a map.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-war-in-the-north-playstation-3', 'The Lord of the Rings: War in the North', 'Middle-earth', '2011-11-01', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20p9.jpg', 'The Lord of the Rings: War in the North is a co-op Action RPG that immerses you and your friends in a brutal new chapter in the War of the Ring. Snowblind Studios is in the unique position of drawing inspiration from both the literary and film rights to world of Middle-earth, allowing players to bloody their axes on a wide range of deadly enemies and traverse both established and never-before-seen locations. The result is a journey that is both epic and intimate, familiar yet unexpected.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-mordor-playstation-3', 'Middle-earth: Shadow of Mordor', 'Middle-earth', '2014-11-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20pd.jpg', 'Middle-earth: Shadow of Mordor is a open world third-person action role-playing video game developed by Monolith Productions and published by Warner Bros. Interactive Entertainment, which takes place in the world of J.R.R. Tolkien''s Legendarium.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-playstation-3-edition-playstation-3', 'Minecraft: PlayStation 3 Edition', 'Minecraft', '2014-05-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mll.jpg', 'Minecraft focuses on allowing the player to explore, interact with, and modify a dynamically-generated map made of one-cubic-meter-sized blocks. In addition to blocks, the environment features plants, mobs, and items. Some activities in the game include mining for ore, fighting hostile mobs, and crafting new blocks and tools by gathering various resources found in the game. The game''s open-ended model allows players to create structures, creations, and artwork on various multiplayer servers or their single-player maps. Other features include redstone circuits for logic computations and remote actions, minecarts and tracks, and a mysterious underworld called the Nether. A designated but completely optional goal of the game is to travel to a dimension called the End, and defeat the ender dragon.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-playstation-3', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2016-10-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mirror-s-edge-playstation-3', 'Mirror''s Edge', 'Mirror''s Edge', '2008-11-11', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sf5.jpg', 'Mirror''s Edge is a side-scrolling platform game developed by IronMonkey Studios and published by Electronic Arts. It was released for the iPod on September 2, 2009, for iPad and iPhone on April 1, 2010, and later for Windows Phone on July 13, 2012. The game is a prequel to the original Mirror''s Edge, setting the scene about Runners and the city''s shady corporations.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('murdered-soul-suspect-playstation-3', 'Murdered: Soul Suspect', NULL, '2014-06-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7a.jpg', 'Murdered: Soul Suspect is a supernatural detective thriller which challenges players to solve possibly the hardest case of all… their own murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ni-no-kuni-wrath-of-the-white-witch-playstation-3', 'Ni no Kuni: Wrath of the White Witch', 'Ni no Kuni', '2013-01-22', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbw.jpg', '"Ni no Kuni: Wrath of the White Witch, a heart-warming tale of a young boy named Oliver, who embarks on a journey into a parallel world in an attempt to bring his mother back from the dead. Along the way, Oliver makes new friends and adopts many of the wonderful creatures that inhabit the world, raising them to battle other creatures on his behalf as he takes on formidable enemies. Developed by LEVEL-5 alongside Studio Ghibli, the legendary animation studio, Ni no Kuni: Wrath of the White Witch combines beautiful animated visuals, masterful storytelling and a sweeping score into an epic role-playing adventure like no other."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nier-playstation-3', 'Nier', 'Nier', '2010-04-27', 'PlayStation 3', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coapbf.jpg', 'Nothing is as it seems in Square Enix''s latest action adventure game, set in a crumbling world plagued by disease and dark, unrecognizable creatures. Players assume the role of the unyielding protagonist, NIER, resolute in his quest to discover a cure for his daughter, who is infected with the Black Scrawl virus. With powerful allies and a mysterious book, NIER encounters things that will confound even the mightiest of warriors. With NIER, experience seamless in-battle cinematics and explore hauntingly familiar lands, intense action-packed battles, and storytelling like only Square Enix can do', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-sigma-playstation-3', 'Ninja Gaiden Sigma', 'Ninja Gaiden', '2007-07-03', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1tx.jpg', 'Ninja Gaiden Sigma, stylized as Ninja Gaiden Σ, is an action-adventure game developed by Team Ninja for the PlayStation 3. It is an enhanced port of Ninja Gaiden, originally released on Xbox in 2004, and is the second expansion to the game after Ninja Gaiden Black. The game was released in the summer of 2007 to very positive reviews. In 2012, a port for the PlayStation Vita, titled Ninja Gaiden Sigma Plus was released on the same day the console launched in Europe and North America.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-2-playstation-3', 'Ninja Gaiden Σ2', 'Ninja Gaiden', '2009-09-29', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ymx.jpg', 'Ninja Gaiden Sigma 2 is the “ultimate” Ninja Gaiden, featuring characters from the previous installments that have defined the franchise. It radiates a striking visual appeal in high resolution display, featuring character and environmental graphics whose quality exceeds the original Ninja Gaiden Sigma. Combining both melee and long-range battles against enemies, the game requires skillful and strategic playing to successfully journey through the missions.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-3-playstation-3', 'Ninja Gaiden 3', 'Ninja Gaiden', '2012-03-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ryd.jpg', 'Ninja Gaiden 3 is the first main entry in the modern Ninja Gaiden series not to be directed by former Team Ninja head Tomonobu Itagaki. NG3 features new game mechanics, a focus on consequence and 8-player online modes.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-3-razor-s-edge-playstation-3', 'Ninja Gaiden 3: Razor''s Edge', 'Ninja Gaiden', '2013-04-02', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1ty.jpg', 'Ninja Gaiden 3: Razor''s Edge is an enhanced port of Ninja Gaiden 3 that includes all downloadable content from the original title, as well as additional enhancements made to improve the game. The game can be considered an equivalent to the Ninja Gaiden Sigma games, as it enhances the original title.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yaiba-ninja-gaiden-z-playstation-3', 'Yaiba: Ninja Gaiden Z', 'Ninja Gaiden', '2014-03-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ygu.jpg', 'Step into a living comic book in this new take on the Ninja Gaiden series. Brandishing his ninja sword and the mecha weapons in his cyber arm, Yaiba slaughters zombies with brutal, over-the-top abandon. Will you slice enemies to pieces, crush them with Yaiba''s cyborg arm or just rip off a zombie’s arms to use as nunchucks?', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-more-heroes-heroes-paradise-playstation-3', 'No More Heroes: Heroes'' Paradise', 'No More Heroes', '2011-08-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xf7.jpg', 'No More Heroes: Heroes'' Paradise is an enhanced port of No More Heroes, originally developed by Grasshopper Manufacture and directed by Goichi Suda.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-stranger-s-wrath-hd-playstation-3', 'Oddworld: Stranger''s Wrath HD', 'Oddworld', '2011-12-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yox.jpg', 'Oddworld: Stranger''s Wrath HD is a remaster of Oddworld: Stranger''s Wrath. The improvements include remastered dialogue, improved character textures and bonus material.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-new-n-tasty-playstation-3', 'Oddworld: New ''n'' Tasty!', 'Oddworld', '2015-04-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n69.jpg', 'Oddworld: New ''n'' Tasty is a faithful remake of Oddworld: Abe''s Oddysee where the pre-rendered sceneries are recreated in real-time 3D without changing the original gameplay. It also replaces the single screens linked together of the original version into a true 2.5D side-scrolling game. While there are various enhancements and details to the character and the scenery, the basic gameplay is still largely similar in a side by side comparison. The GameSpeak system Abe uses to command and talk to other characters start with the same commands, but can later be expanded. This version of the game supports leaderboards for the completion time of each mode and the overall game. There are three difficulty levels and the game. It includes the original cooperative function of the original game when another player can take over when the first player dies, taking turns controlling Abe.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-hd-playstation-3', 'Ōkami HD', 'Ōkami', '2012-10-30', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22s8.jpg', 'Experience the critically acclaimed masterpiece with its renowned Sumi-e ink art style in breathtaking high resolution. Take on the role of Amaterasu, the Japanese sun goddess who inhabits the form of a legendary white wolf, on a quest to defeat Orochi, an eight-headed demon and tyrannical monster responsible for turning the world of Nippon into a ruined wasteland.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-orange-box-playstation-3', 'The Orange Box', NULL, '2007-12-11', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yez.jpg', 'The Orange Box is a bundle that includes five titles from Valve: Half-Life 2; Half-Life 2:Episode 1; Half-Life 2: Episode Two; Team Fortress 2, the sequel to the game that put class-based, multiplayer team warfare on the map; and Portal, the game that blends puzzles, first person action, and adventure gaming to produce an experience like no other.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-playstation-3', 'Pac-Man and the Ghostly Adventures', 'Pac-Man', '2013-10-29', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-2-playstation-3', 'Pac-Man and the Ghostly Adventures 2', 'Pac-Man', '2014-10-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-arena-playstation-3', 'Persona 4 Arena', 'Persona', '2012-08-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25v5.jpg', 'Persona 4 Arena is a fighting video game developed for Japanese arcades and later ported to home consoles. Based on Atlus'' Persona role-playing game series, Arena serves as a direct sequel to Persona 4 and features characters from its predecessor, Persona 3. Atlus wrote the story to the game while Arc System Works handled the gameplay.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-arena-ultimax-playstation-3', 'Persona 4 Arena Ultimax', 'Persona', '2014-09-30', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5k1y.jpg', 'Persona 4 Arena Ultimax is a fighting video game developed by Arc System Works and Atlus. It is the direct sequel to Persona 4 Arena, which is itself a follow-up to the role-playing game Persona 4. The game was originally released in Japanese arcades on November 28, 2013, and later ported to home consoles. Unlike the previous game, it is not region locked.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-playstation-3', 'Persona 5', 'Persona', '2017-04-04', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zoq.jpg', 'Persona 5 Strikers is a crossover between Koei Tecmo''s hack and slash Dynasty Warriors series and Atlus''s turn-based role-playing game Persona series. As a result, it features gameplay elements from both, such as the real-time action combat of the former with the turn-based Persona-battling aspect of the latter. The game is set six months after the events of Persona 5, and follows Joker and the rest of the Phantom Thieves of Hearts as they end up in a mysterious version of Tokyo filled with supernatural enemies.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-playstation-3', 'Plants vs. Zombies', 'Plants vs. Zombies', '2011-02-08', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69id.jpg', 'Zombies are invading your home, and the only defense is your arsenal of plants! Plants vs. Zombies is a tower defense video game developed and published by PopCap Games. As a horde of zombies approaches along several parallel lanes, players must defend their homes by placing plants, which fire projectiles at the zombies or otherwise detrimentally affect them.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-playstation-3', 'Plants vs. Zombies: Garden Warfare', 'Plants vs. Zombies', '2014-08-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qyz.jpg', 'Plants vs. Zombies is digging into the trenches with an explosive new 3D experience. Blast zombies, plants, and new characters with inventive weapons across a mine-blowing PvZ world. Take on Co-Op and Multiplayer action with your friends and sow the seeds of victory!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-all-stars-battle-royale-playstation-3', 'PlayStation All-Stars Battle Royale', NULL, '2012-11-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ssv.jpg', 'Playstation All-Stars Battle Royal is a cross over fighting game featuring (mostly exclusive) iconic characters from various Playstation franchises. Each stage also feature prominent setting from other franchises.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-move-heroes-playstation-3', 'PlayStation Move Heroes', NULL, '2011-03-22', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wbx.jpg', 'The game offers both single-player and two-player cooperative multiplayer modes as players progress through a series of levels. Featuring six playable characters—Ratchet, Clank, Jak, Daxter, Sly Cooper, and Bentley—the game comprises a total of 50 levels categorized into five "archetypes", five weapon classes, and four environments. These environments include Paris from Sly Cooper & Bentley, Metropolis City on Kerwan from Ratchet & Clank, Haven City from Jak and Daxter, and Planet X, an original game-created environment.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('portal-2-playstation-3', 'Portal 2', 'Portal', '2011-04-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaanx.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-playstation-3', 'Prince of Persia', 'Prince of Persia', '2008-12-02', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-forgotten-sands-playstation-3', 'Prince of Persia: The Forgotten Sands', 'Prince of Persia', '2010-05-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8z2j.jpg', 'Prince of Persia: The Forgotten Sands is a promotional browser flash game created to promote the Prince of Persia: The Forgotten Sands. Playing the game unlocked a costume in the main game, though that feature no longer works. The game is still playable on explosivebarrel.net
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-prince-of-persia-trilogy-playstation-3', 'The Prince of Persia Trilogy', 'Prince of Persia', '2011-04-19', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oay.jpg', 'This is a bundle that includes the three games from the sands trilogy of the Prince of Persia franchise, namely Prince of Persia: The Sands of Time, Prince of Persia: Warrior Within and Prince of Persia: The Two Thrones.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-playstation-3', 'Prototype', 'Prototype', '2009-06-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5fpf.jpg', 'PtAP have chosen you to be the new test prototype! What does it mean, you wonder? We will force you to fight against robots and other Prototypes like you, with Power-ups and Paintballs.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-2-playstation-3', 'Prototype 2', 'Prototype', '2012-04-24', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20jt.jpg', 'Prototype 2 is an open-world action game published by Activision and developed by Radical Entertainment. It''s a direct sequel to Prototype and was announced at the 2010 Spike Video Game Awards.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puppeteer-playstation-3', 'Puppeteer', NULL, '2013-09-10', 'PlayStation 3', 1, 0, NULL, NULL, 'You''ll take part in Dr.Mcgrew''s freakish experiments when you purchase the Curse of the Puppet Master skin pack for Puppet Master: The Game!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enemy-territory-quake-wars-playstation-3', 'Enemy Territory: Quake Wars', 'Quake', '2008-05-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2o4l.jpg', 'Enemy Territory: Quake Wars is a first-person shooter video game developed by Splash Damage and published by Activision for Microsoft Windows, Linux, Mac OS X, PlayStation 3 and Xbox 360. The prequel to Quake II, Quake Wars is set in the same science fiction universe as Quake II and Quake 4, with a minimal back-story serving as a prequel to Quake II. It is the second multiplayer-focused game in the Quake series after Quake III Arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-future-tools-of-destruction-playstation-3', 'Ratchet & Clank Future: Tools of Destruction', 'Ratchet & Clank', '2007-10-23', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8542.jpg', 'Ratchet & Clank Future: Tools of Destruction (known as Ratchet & Clank: Tools of Destruction in most PAL countries) is a 2007 platformer video game developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation 3. The game was released on October 23, 2007 in North America and on November 9, 2007 in Europe. It is the first PlayStation 3 installment for the Ratchet & Clank franchise, as well as the first installment for the "Future" series. It was also one of the first PlayStation 3 games to support DualShock 3 rumble straight from the disc.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-future-a-crack-in-time-playstation-3', 'Ratchet & Clank Future: A Crack in Time', 'Ratchet & Clank', '2009-10-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6fjt.jpg', 'Ratchet & Clank Future: A Crack in Time (known as Ratchet & Clank: A Crack in Time in most PAL countries) is a platform game developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation 3 video game console. It is the sequel to Ratchet & Clank Future: Tools of Destruction and Ratchet & Clank Future: Quest for Booty. The game was released for the PlayStation 3 in North America on October 27, 2009, in Australia on November 5, 2009, and in Europe on November 6, 2009.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-all-4-one-playstation-3', 'Ratchet & Clank: All 4 One', 'Ratchet & Clank', '2011-10-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230s.jpg', 'We find our heroes in the midst of a dilemma of intergalactic proportions when Dr. Nefarious'' latest evil plan goes awry leaving Ratchet, Clank, Qwark and Nefarious himself caught in the snare of a powerful and mysterious machine. Begrudgingly, the Galaxy''s biggest do-gooders and its most sinister criminal must work together to discover a means of escape in this action-packed installment of the Ratchet & Clank series.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-collection-playstation-3', 'Ratchet & Clank Collection', 'Ratchet & Clank', '2012-08-28', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230q.jpg', 'This trilogy of Ratchet & Clank classics contains Ratchet & Clank, Ratchet & Clank: Going Commando, and Ratchet & Clank: Up Your Arsenal – all remastered in 1080p with additional upgrades such as Trophy and 3D support.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-full-frontal-assault-playstation-3', 'Ratchet & Clank: Full Frontal Assault', 'Ratchet & Clank', '2012-11-27', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230o.jpg', 'Explore action-packed battlefields and wipe out waves of enemies with outrageous weapons. Classic Ratchet & Clank gameplay returns with a base-defense twist, including competitive and co-op cross-play for the PS3 and PS Vita.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-into-the-nexus-playstation-3', 'Ratchet & Clank: Into the Nexus', 'Ratchet & Clank', '2013-11-12', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x4i.jpg', 'Ratchet & Clank: Into the Nexus (known as Ratchet & Clank: Nexus in Europe) is a 2013 platform video game developed by Insomniac Games and published by Sony Computer Entertainment for the PlayStation 3. It is the fourth and final installment in the "Future" series. The series is noted for the inclusion of exotic and unique locations and over the top gadgets, a concept of the traditional Ratchet & Clank experience, that returns in this game.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-origins-playstation-3', 'Rayman Origins', 'Rayman', '2011-11-15', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v7k.jpg', 'Bubble Dreamer, Rayman, his best friend Globox, and some Teensy friends are chilling out at the Bubble Dreamer''s resting grounds, the Snoring Tree. However, their snoring disturbs an old granny from the Land of the Livid Dead, who retaliates by sending an evil army of horrendous creatures and the Darktoons across the world, capturing the Electoons that inhabit the world, imprisoning Betilla the Nymph and her sisters, and plunging the Glade into chaos. As a result, the ensuing disaster causes the Bubble Dreamer to go crazy and have nightmares. Although they are captured, Rayman and his friends are able to escape the Darktoons. They are then tasked by the Magician to gather enough Electoons to cure the Bubble Dreamer and restore the Glade of Dreams. Their efforts to locate the Electoons allow them to gain access to the various lands of the Glade, rescuing the Nymphs along the way.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-playstation-3', 'Rayman Legends', 'Rayman', '2013-09-03', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-playstation-3', 'Red Dead Redemption', 'Red Dead', '2010-05-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6zwq.jpg', 'This bundle includes Red Dead Redemption, Red Dead Redemption: Undead Nightmare, Red Dead Online, and Red Dead Redemption 2: Story Mode.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-undead-nightmare-playstation-3', 'Red Dead Redemption: Undead Nightmare', 'Red Dead', '2010-11-23', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wrq.jpg', 'A port for the Switch and PS4 lacking multiplayer modes present in the original release.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-game-of-the-year-edition-playstation-3', 'Red Dead Redemption: Game of the Year Edition', 'Red Dead', '2011-10-11', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3cu9.jpg', 'Red Dead Redemption: Game of the Year Edition will include the full, original Red Dead Redemption game plus all free and paid downloadable content packs released to date, including the wildly popular Undead Nightmare single and multiplayer offerings, as well as all DLC originally released as pre-order content.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('remember-me-playstation-3', 'Remember Me', NULL, '2013-06-03', 'PlayStation 3', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/uwk5nzvqt6q9l2ogr3am.jpg', 'A psychological horror game and visual novel that will test your morality, your ability to adapt, and your willpower to remain sane under pressure...', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-playstation-3', 'Resident Evil 5', 'Resident Evil', '2009-03-13', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtgs.jpg', 'Resident Evil 5 is the seventh video game in the Resident Evil series. It features similar gameplay to Resident Evil 4 utilizing the same over the shoulder view, but this time the environment plays a significant role. The player is now dependent on his partner more than in older games. When the partner''s health bar drop down to 0, he will enter the dying stage where the health bar will flash red and gradually lower as he stays like this. Resident Evil 5 also features new types of enemies called Majini and mostly are of African descent.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-gold-edition-playstation-3', 'Resident Evil 5: Gold Edition', 'Resident Evil', '2010-03-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nxe.jpg', 'Resident Evil 5: Gold Edition includes "Lost in Nightmares" and another campaign-expansion episode, "Desperate Escape", where players control Josh Stone and Jill Valentine as they assist Chris and Sheva. The edition also includes the previously released Versus mode, four new costumes and an alternate Mercenaries mode with eight new playable characters, new items and maps.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-operation-raccoon-city-playstation-3', 'Resident Evil: Operation Raccoon City', 'Resident Evil', '2012-03-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20d0.jpg', 'Resident Evil: Operation Raccoon City is a third-person shooter and is a spin-off of the long-running Resident Evil series. Unlike the main games in the series, it is less of a survival horror game and more of an action-packed shooter. The game includes twelve playable characters, however the players can choose only four characters for the online modes. Each team member has their own special role and abilities.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-6-playstation-3', 'Resident Evil 6', 'Resident Evil', '2012-10-02', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pyq.jpg', 'Resident Evil 6 is the ninth video game installment in the Resident Evil series. It continues the struggle against zombies infected by the new highly virulent C-virus. The game uses the same over-the-shoulder view as Resident Evil 4 and Resident Evil 5, however with a new gameplay mechanic that allows players to slowly move while shoot. Players can select between three scenarios featuring multiple characters and intertwined storylines, and within these scenarios both stories and action cross paths. At key moments during the game, up to four players can join together online to tackle a specific situation, with some stages seeing the usual partnerships swapped to further increase the depth of gameplay.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-playstation-3', 'Resident Evil: Revelations', 'Resident Evil', '2013-05-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-2-playstation-3', 'Resident Evil: Revelations 2', 'Resident Evil', '2015-03-18', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92d9.jpg', 'Resident Evil: Revelations 2 is the retail version of the episodic survival horror series that was originally released as four downloadable episodes. This physical version combines the entire story along with some extras, but not all the available DLC. The PC version did not receive a retail release, but the same content was bundled on Steam. The game comprises four episodes, each of which feature two separate stories. This sequel bears a stronger tone to the concept of survival horror than titles such as Resident Evil 5 and Resident Evil 6. Elements of ammunition management as well as stealth or sneaking come into play in the gameplay.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resistance-fall-of-man-playstation-3', 'Resistance: Fall of Man', 'Resistance', '2006-11-14', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b4m.jpg', 'In an alternate 1951, Sgt. Nathan Hale is among a unit of US soldiers sent to aid the British military against the invading aliens, known as Chimera. When Hale''s unit is completely wiped out in a surprise attack, he struggles for survival...', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resistance-2-playstation-3', 'Resistance 2', 'Resistance', '2008-11-04', 'PlayStation 3', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co39vd.jpg', 'After a valiant struggle to stop the Chimera invasion in Europe, mankind must make its last stand on the shores of the United States.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resistance-3-playstation-3', 'Resistance 3', 'Resistance', '2011-09-06', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b3y.jpg', 'The third and currently final installment in the Resistance series. Resistance 3 portrays Capelli''s heroic survival inside the brutal Resistance world. Featuring new upgradeable weapons, the return of the weapon wheel, two-player online or split-screen campaign co-op and a progression-based multiplayer experience, Resistance 3 delivers a heroic-yet savage first-person shooter experience.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('retro-city-rampage-dx-playstation-3', 'Retro City Rampage DX', 'Retro City Rampage', '2012-10-09', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h4u.jpg', 'Open-world carjacking goes back to the ''80s in this 8-BIT nostalgic throwback.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-playstation-3', 'Shakedown: Hawaii', 'Retro City Rampage', '2020-08-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rune-factory-tides-of-destiny-playstation-3', 'Rune Factory: Tides of Destiny', 'Rune Factory', '2011-10-07', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h4x.jpg', 'Aden and Sonja, two lifelong friends, live a tranquil life on Fenith Island until they''re struck by a mysterious curse: they awaken to find both of their souls are now trapped in the same body! On top of this unusual calamity, the Fenith they knew is gone, replaced by a strange island populated with unfamiliar faces. Only by exploring this new world will they be able to solve the mystery of this curse and save their beloved Island. During the course of their journey, Aden and Sonja will be aided by a colorful cast of characters, as well as take command of the towering golem Ymir. Using their newfound giant friend, they''ll cross vast seas, discover hidden islands and dungeons packed with riches, and battle fearsome monsters of the deep!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-tennis-playstation-3', 'Sega Superstars Tennis', 'Sega All-Stars', '2008-03-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6p9b.jpg', 'Developed by Sumo Digital, this is the handheld port of Sega Superstars Tennis. While the core mechanics remain very similar, the game differs from the home console version in its presentation, depth, and certain elements of functionality.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-sega-all-stars-racing-playstation-3', 'Sonic & Sega All-Stars Racing', 'Sega All-Stars', '2010-02-23', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te6.jpg', 'Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-all-stars-racing-transformed-playstation-3', 'Sonic & All-Stars Racing Transformed', 'Sega All-Stars', '2012-11-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvw.jpg', 'Race as Sonic and a host of legendary All-Stars and prepare to transform! Speed across land, sea and air in a high velocity battle to the finish line, as your amazing transformable vehicle changes from car to boat to plane mid-race. Racing on mobile will never be the same again!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('silent-hill-hd-collection-playstation-3', 'Silent Hill HD Collection', 'Silent Hill', '2012-03-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co284k.jpg', 'Silent Hill HD Collection is a compilation of remastered ports of Silent Hill 2 and Silent Hill 3. The core play mechanics and story for all games remained mostly the same with some artistic changes in the remastered versions. Both games have had a graphics overhaul to allow them to support modern 720p resolution on consoles, as well as run at locked 30 frames per second. They also feature an alternate voice dub, as well as PlayStation Network Trophies and Xbox 360 Achievements. Players have the option to switch between the original voice acting and the alternate voice acting for Silent Hill 2, while the re-dub is mandatory for Silent Hill 3 because it lacks the original voice acting.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-skyheroes-playstation-3', 'MySims SkyHeroes', 'The Sims', '2010-09-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uk1.jpg', 'The DS port of the final game in the MySims series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-playstation-3', 'The Sims 3', 'The Sims', '2010-10-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nas.jpg', 'The Sims 3 is a console game developed by Electronic Arts for the Nintendo Wii.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-pets-playstation-3', 'The Sims 3: Pets', 'The Sims', '2011-10-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7jis.jpg', 'Bring excitement and surprise into your Sims'' lives with pets in The Sims 3: Pets, an expansion pack for The Sims 3! Create the perfect (or imperfect) pets for your Sims, from fierce guard dogs to destructive kittens to trusty horses and more as you determine not only how your Sims'' pets look but their personality traits as well. With a variety of new activities and social interactions, take direct control of your Sims'' pets and explore new ways to mess with their lives. Give your Sims a new member of their household and discover all-new ways to play with life!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-spyro-s-adventure-playstation-3', 'Skylanders: Spyro''s Adventure', 'Skylanders', '2011-10-16', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsc.jpg', 'Skylanders: Spyro''s Adventure is the first video game in the Skylanders series. It is a video game that is played along with toy figures that interact with it through a "Portal of Power", that reads their tag through NFC and features the voices of Josh Keaton, Dave Wittenberg, Darin De Paul, Joey Camen, Audrey Wasilewski, Keythe Farley and Kevin Michael Richardson.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-giants-playstation-3', 'Skylanders: Giants', 'Skylanders', '2012-10-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vlm.jpg', 'Skylanders: Giants is a 2012 video game in the Skylanders series, a direct sequel to the 2011 game Skylanders: Spyro''s Adventure and features the voices of Kevin Michael Richardson, Greg Ellis, Peter Lurie, Steve Blum, Dave Wittenberg, Carlos Alazraqui, Kevin Sorbo, Bobcat Goldthwait, Patrick Seitz and Julie Nathanson. It is the game before Skylanders: Swap Force. As the title suggests, it features larger Skylanders known as "Giants", along with other new gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-playstation-3', 'Skylanders: Swap Force', 'Skylanders', '2013-10-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-playstation-3', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-playstation-3', 'Skylanders: SuperChargers', 'Skylanders', '2015-09-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsk.jpg', 'Exclusive to the Wii U version of the game is a special figure of Donkey Kong and Bowser.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-playstation-3', 'Skylanders: Imaginators', 'Skylanders', '2016-10-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sly-collection-playstation-3', 'The Sly Collection', 'Sly Cooper', '2011-11-29', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g8d.jpg', 'The Sly Collection is a remastered compilation of the first three Sly Cooper games, developed by Sanzaru Games and published by Sony Computer Entertainment. Released in 2010 for PlayStation 3 and later for PlayStation Vita, it includes Sly Cooper and the Thievius Raccoonus, Sly 2: Band of Thieves, and Sly 3: Honor Among Thieves, all with enhanced HD graphics, Trophy support, and stereoscopic 3D compatibility on PS3. The collection preserves the original gameplay while offering visual and performance improvements.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sly-cooper-thieves-in-time-playstation-3', 'Sly Cooper: Thieves in Time', 'Sly Cooper', '2013-02-05', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rbv.jpg', 'Sly Cooper: Thieves in Time is a stealth platformer developed by Sanzaru Games and published by Sony Computer Entertainment. Released in 2013 for PlayStation 3 and PlayStation Vita, it is the fourth main entry in the Sly Cooper series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-playstation-3', 'Sonic the Hedgehog', 'Sonic the Hedgehog', '2007-01-30', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ubt.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-unleashed-playstation-3', 'Sonic Unleashed', 'Sonic the Hedgehog', '2008-12-09', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6p.jpg', 'Gameplay in Sonic Unleashed focuses on two modes of platforming play: fast-paced levels that take place during daytime, showcasing Sonic''s trademark speed as seen in previous games in the series, and slower, night-time levels, during which Sonic''s Werehog form emerges, and gameplay switches to an action-based, brawler style of play, in which Sonic battles Gaia enemies', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-s-ultimate-genesis-collection-playstation-3', 'Sonic''s Ultimate Genesis Collection', 'Sonic the Hedgehog', '2009-02-10', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1upp.jpg', 'The compilation features 48 Sega games (49 counting two versions of Altered Beast) which were previously released for the Mega Drive/Genesis (including most of the Sonic the Hedgehog titles released for the system), arcade and Sega Master System. It is similar to the Sega Genesis Collection released previously for the PlayStation 2 and PSP, however it contains 16 (in NTSC regions) more games (including unlockable extras).', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-generations-playstation-3', 'Sonic Generations', 'Sonic the Hedgehog', '2011-11-01', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zya.jpg', 'In the 3DS version of Sonic Generations, Modern Sonic''s gameplay is similar to that of Sonic Rush and the DS version of Sonic Colors. He has the Boost, the ability to slide under obstacles, jump off walls, and the Homing Attack. After the second era, Modern Sonic learns the Stomp. Modern Sonic''s levels use the 3D effect of depth on the 3DS version more actively as well as to giving a better view for when Modern Sonic jumps into the background, although the console versions are 3D-TV compatible. In the HD version, Modern Sonic is only able to wall jump off certain panels (similar to the DS version of Sonic Colors), but in the 3DS version, he is able to wall jump on any wall (much like Sonic Unleashed and the Wii version of Sonic Colors).', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sports-champions-playstation-3', 'Sports Champions', 'Sports Champions', '2010-09-17', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kcm.jpg', 'Sports Champions is a 2010 sports video game developed by San Diego Studio and Zindagi Games and published by Sony Computer Entertainment for PlayStation 3, which utilizes PlayStation Move. It was officially unveiled at the 2010 Game Developers Conference in San Francisco. The game is a collection of modern and medieval sports games published by Sony Computer Entertainment and is jointly developed by San Diego Studio and Zindagi Games as a launch game for the PlayStation Move which would be bundled with the controller in several regions.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sports-champions-2-playstation-3', 'Sports Champions 2', 'Sports Champions', '2012-10-30', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4a62.jpg', 'Using the PlayStation Move motion controller and PlayStation Eye, players become part of the event as they use their controllers to compete in a variety of new sporting challenges. Building upon the game mechanics of the first title, Zindagi Games and Sony’s Worldwide San Diego Studio make it easily accessible for players of all levels to jump right into the action. Each of the six events will have you energized as you improve your backswing, bowl a strike or perfect your left hook.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-dawn-of-the-dragon-playstation-3', 'The Legend of Spyro: Dawn of the Dragon', 'Spyro', '2008-10-21', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a8.jpg', NULL, 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-playstation-3', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-playstation-3', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-ii-playstation-3', 'Star Wars: The Force Unleashed II', 'Star Wars', '2010-10-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xw.jpg', 'The Star Wars Saga continues with Star Wars: The Force Unleashed II, the highly anticipated sequel to the fastest-selling Star Wars game ever created, which has sold more than seven million copies worldwide.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('starhawk-playstation-3', 'Starhawk', NULL, '2012-05-08', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v8o.jpg', 'Starhawk is a 1979 vector arcade game by Cinematronics. Starhawk is a shoot ''em up with a fixed environment. The game was unique at the time as it presented the graphics in a pseudo-three dimensional way. Essentially, the game is a simple video game version of the Star Wars: Episode IV trench run. The game was later ported to the Vectrex video game console in 1982. The game is remembered as having quite advanced graphics for the time and being the first video game based upon or to have noticeable references to Star Wars.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-graces-playstation-3', 'Tales of Graces', 'Tales', '2012-03-13', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ywb.jpg', 'Tales of Graces is an action role-playing game. You will follow Asbel Lhant int he world of Ephinea. In his childhood, Asbet became friends with an amnesiac girl and witnesses her death. However, seven years later, he is reunited with the girl who retains her amnesia...', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-xillia-playstation-3', 'Tales of Xillia', 'Tales', '2013-08-06', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6suf.jpg', 'A bundle released in Europe in 2016, containing Tales of Xillia and Tales of Xillia 2 on one Blu-ray disc.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-symphonia-chronicles-playstation-3', 'Tales of Symphonia Chronicles', 'Tales', '2014-02-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h0v.jpg', 'Tales of Symphonia Chronicles is a compilation release of Tales of Symphonia and Tales of Symphonia: Dawn of the New World HD remasters with additional content.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-xillia-2-playstation-3', 'Tales of Xillia 2', 'Tales', '2014-08-19', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25yo.jpg', 'The game takes place a year after Tales of Xillia. Elle Mel Marta is given specific instructions by her father to board a train and to find the Land of Canaan. Her train is hijacked before its departure and Ludger Will Kresnik boards it to save her. The train crashes and the two receive life saving treatment from Clanspia Inc. which puts Ludger in debt. Clanspia Inc. hires Ludger, intending to use his Kresnik powers to destroy alternative timelines because the spirit Origin can no longer sustain the abundance of souls in the worlds. While working off the debt, Ludger also searches for his brother, Julius Will Kresnik, who has been blamed for the train hijacking.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-zestiria-playstation-3', 'Tales of Zestiria', 'Tales', '2015-10-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rdq.jpg', 'Tales of Zestiria is a Japanese role-playing game. It is the fifteenth main entry in the Tales series. As with previous entries in the Tales series, the game uses a variation of the action-based Linear Motion Battle System, with additional elements including a navigable open world, and the ability for certain characters to fuse into a single entity in battle to deliver powerful attacks. The story follows Sorey, a young man blessed with powers by a mystical spirit race known as the Seraphim who act as a stabilizing force in the land, as he travels to free the land of Glenwood from the threat of the Hellion, creatures spawned by negative emotions.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-playstation-3', 'Terraria', NULL, '2013-03-26', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teslagrad-playstation-3', 'Teslagrad', NULL, '2015-04-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6eo7.jpg', 'Teslagrad 2 is the sequel to the original Teslagrad, developed by Rain Games and released in 2023. This 2D puzzle platformer builds upon the magnetic and electrical mechanics of its predecessor, with players once again using these abilities to solve puzzles and traverse complex environments. Set in a new region, the game introduces new powers, enemies, and challenges, while maintaining the visual storytelling and atmospheric design characteristic of the series.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thief-playstation-3', 'Thief', 'Thief', '2014-02-25', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rom.jpg', 'In the third instalment of the Thief series, master-thief Garrett is contacted by Keeper Artemus with a mission to steal two valuable artefacts. At the same time, Garrett learns about a prophecy: the coming of a Dark Age. He embarks upon a journey to unravel a mystery that threatens the existence of the order of Keepers. Is it possible that there is a traitor in their midst?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-playstation-3', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2007-03-30', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-trilogy-playstation-3', 'Tom Clancy''s Splinter Cell Trilogy', 'Tom Clancy''s Splinter Cell', '2011-09-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h03.jpg', 'Tom Clancy''s Splinter Cell Classic Trilogy HD is a remastered, high-definition collection of the first three games of the Tom Clancy''s Splinter Cell series for the PlayStation 3.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-blacklist-playstation-3', 'Tom Clancy''s Splinter Cell: Blacklist', 'Tom Clancy''s Splinter Cell', '2013-08-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ygp.jpg', 'Splinter Cell Blacklist builds on the stealth roots of the franchise, while exploring new directions to embrace the realms of action and adventure. Players can define their personal play styles and be rewarded for those choices.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-underworld-playstation-3', 'Tomb Raider: Underworld', 'Tomb Raider', '2008-11-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voc.jpg', 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of challenge and choice.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-tomb-raider-trilogy-playstation-3', 'The Tomb Raider Trilogy', 'Tomb Raider', '2011-03-22', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z3o.jpg', 'A HD re-release of Legend, Anniversary, and Underworld on the PS3.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-playstation-3', 'Tomb Raider', 'Tomb Raider', '2013-03-05', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-playstation-3', 'Turok', 'Turok', '2008-02-05', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2699.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-drake-s-fortune-playstation-3', 'Uncharted: Drake''s Fortune', 'Uncharted', '2007-11-20', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tp7.jpg', 'A 400-year-old clue in the coffin of Sir Francis Drake sets a modern-day fortune hunter on an exploration for the fabled treasure of El Dorado, leading to the discovery of a forgotten island in the middle of the Pacific Ocean.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-2-among-thieves-playstation-3', 'Uncharted 2: Among Thieves', 'Uncharted', '2009-10-13', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tnb.jpg', 'In the sequel to Drake''s Fortune, Nathan Drake comes across a map that showcases the location of Marco Polo''s missing ships. It takes him on a journey to find the infamous Cintamani Stone, and uncover the truth behind it.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-3-drake-s-deception-playstation-3', 'Uncharted 3: Drake''s Deception', 'Uncharted', '2011-11-01', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tp8.jpg', 'A search for the fabled "Atlantis of the Sands" propels fortune hunter Nathan Drake on a trek into the heart of the Arabian Desert. When the terrible secrets of this lost city are unearthed, Drake''s quest descends into a desperate bid for survival that strains the limits of his endurance and forces him to confront his deepest fears.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-game-of-the-year-edition-playstation-3', 'The Walking Dead: Game of the Year Edition', 'The Walking Dead', '2013-11-19', 'PlayStation 3', 0, 0, NULL, NULL, NULL, NULL, 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-season-two-playstation-3', 'The Walking Dead: Season Two', 'The Walking Dead', '2014-10-14', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k36.jpg', 'Similar to the previous season, The Walking Dead: Season Two is a point-and-click adventure game. The player, in control of Clementine, can direct the character around the environment, examine and interact with various scenery elements and collect and use objects to advance the story. The player can also initiate conversations with non-player characters via conversation trees. Certain replies from other characters may offer the player multiple choices to select from, including the option to stay silent, with a limited amount of time to make the selection; if the player does not select an option, the conversation will continue as if they had stayed quiet. Such choices can affect how the other characters will later react to Clementine which can influence later events in the story. Other scenes are more action-oriented, requiring the player to complete quick time events to avoid Clementine or her allies from getting killed. If the player fails these events, the game will restart at the start of such scenes. Such action scenes may also require the player to make a key decision within a limited time frame, such as which of two characters to save from attacking walkers.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('warhawk-playstation-3', 'Warhawk', 'Warhawk', '2007-08-28', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9j6j.jpg', 'Warhawk, released as AirAssault in Japan, is a futuristic arcade-style flight-combat game where the player flies a VTOL aircraft. The player maneuvers with 360 degrees of flight control through six levels. Weapons include fire-off lock-ons, rockets, multi-fire swarmers, and plasma cannons. The game has no multiplayer capabilities and does not feature DualShock or analog controller support.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-playstation-3', 'Watch Dogs', 'Watch Dogs', '2014-05-27', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j2m.jpg', 'Purchase the Watch Dogs and Watch Dogs 2 bundle and gain access to these award-winning titles at a great price. In Watch Dogs, become Aiden Pearce and hack your way around Chicago to take down ctOS. In Watch Dogs 2, join Marcus Holloway and the Dedsec hacker group to expose a new digital conspiracy.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-playstation-3', 'Wolfenstein', 'Wolfenstein', '2009-08-18', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-new-order-playstation-3', 'Wolfenstein: The New Order', 'Wolfenstein', '2014-05-20', 'PlayStation 3', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c0.jpg', 'Wolfenstein: The New Order is an action-adventure shooter game played from a first-person perspective. It is the semi-sequel to 2009''s Wolfenstein, however utilizes very little from the game and drops any direct references to veil or supernatural.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-hd-collection-playstation-3', 'Zone of the Enders HD Collection', 'Zone of the Enders', '2012-10-30', 'PlayStation 3', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4slq.jpg', 'Zone of the Enders HD Edition (Zone of the Enders HD Collection outside Japan) is a re-release of Zone of the Enders and Zone of the Enders: The 2nd Runner for the Playstation 3 and Xbox 360 consoles. The collection refines the textures and graphics and The 2nd Runner game comes with the Special Edition content that was released only in Japan and Europe, an import soundtrack featuring remixes of the music featured in the series, along with a demo of Metal Gear Rising: Revengeance. It also has a new Opening Movie, set to the Theme of Z.O.E. 2, Beyond the Bounds, animated by Sunrise. The collection was released in North America on October 30, 2012 and was released in Europe on November 30, 2012.', 'NA', 32);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-liberation-playstation-vita', 'Assassin''s Creed III: Liberation', 'Assassin''s Creed', '2012-10-30', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xim.jpg', 'Assassin''s Creed III: Liberation is a PlayStation Vita game released on October 30, 2012. Set in 1765 Louisiana, featuring Aveline de Grandpré, a mixed-race female Assassin. The game takes place during the lead-up to the American Revolution, with Aveline navigating the complex social and political landscape of New Orleans. She uses three distinct personas (Assassin, Lady, and Slave) to pursue her missions, fighting against Spanish forces and colonial powers.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-chronicles-playstation-vita', 'Assassin''s Creed Chronicles', 'Assassin''s Creed', '2016-04-05', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yvv.jpg', 'As the direct prequel of the critically acclaimed console title Assassin’s Creed, discover more of the story of Altaïr as he must find “the chalice,” an object of such power that whoever is in possession of it can end the Crusades.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-playstation-vita', 'Atari Flashback Classics', 'Atari Flashback Classics', '2018-12-19', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5byo.jpg', 'Each volume of Atari Flashback Classics packs hours of retro-gaming gaming goodness from the Atari 2600 Video Computer System (VCS) and arcade machines onto your gaming platform. Players can experience Atari’s greatest hits with the benefit of today’s technology, including full 1080p high-definition, global leaderboards, online multiplayer, and more!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-playstation-vita', 'Axiom Verge', 'Axiom Verge', '2016-04-19', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kml.jpg', 'After a lab accident, a scientist awakens in a mysterious, alien world. Is this a distant planet? The far future? Or a complex virtual-reality computer simulation?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bastion-playstation-vita', 'Bastion', NULL, '2015-12-05', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qlj.jpg', 'A hack-and-slash RPG featuring a reactive narrator, various unlockable weapons, weapon upgrades, practice mini-games and optional difficulty modifiers, set in an imaginary world in the aftermath of an uncertain apocalypse, in which the player embodies a teenager with a troubled past as he and the narrator work together to rebuild the world out of a persisting hub called the Bastion.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bit-trip-presents-runner2-future-legend-of-rhythm-alien-playstation-vita', 'Bit.Trip Presents... Runner2: Future Legend of Rhythm Alien', 'Bit.Trip', '2013-12-17', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86be.jpg', 'Runner2 is the sequel to the critically acclaimed and IGF award winning BIT.TRIP RUNNER.,In the style of the BIT.TRIP series, Runner2 is a rhythm-music platforming game.,Players will run through fantastic environments, using brand new moves, to brand new soundtracks as they run, jump, slide, kick, and soar toward the goal of tracking down the Timbletot and thwarting his evil plans to destroy not only our world, but every world there is.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-bit-trip-playstation-vita', 'The Bit.Trip', 'Bit.Trip', '2015-12-05', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86bs.jpg', 'A collection of the six original Bit.Trip games for the PS3, PS4, and Vita.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-curse-of-the-moon-playstation-vita', 'Bloodstained: Curse of the Moon', 'Bloodstained', '2018-05-24', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaas.jpg', '“Bloodstained: Curse of the Moon” is packed with the retro charm that made the legendary 2D action games of the 80s so enjoyable.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-2-playstation-vita', 'Borderlands 2', 'Borderlands', '2014-05-13', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ba3.jpg', 'A new era of shoot and loot is about to begin. Play as one of four new vault hunters facing off against a massive new world of creatures, psychos and the evil mastermind, Handsome Jack. Make new friends, arm them with a bazillion weapons and fight alongside them in 4 player co-op on a relentless quest for revenge and redemption across the undiscovered and unpredictable living planet.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('broken-age-playstation-vita', 'Broken Age', NULL, '2015-04-28', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vh9.jpg', 'Broken Age is a point-and-click adventure telling the stories of a young boy and girl leading parallel lives. Vella Tartine has been chosen by her village to be sacrificed to a terrible monster — but she decides to fight back. Meanwhile, Shay Volta is living a solitary life on a spaceship under the care of a motherly computer, but he wants to break free to lead adventures and do good in the world. Adventures ensue.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-origins-blackgate-playstation-vita', 'Batman: Arkham Origins Blackgate', 'DC', '2013-10-25', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4oie.jpg', 'Batman: Arkham Origins Blackgate - Deluxe Edition amplifies the 2.5-D game developed by Armature Studio with new maps, enemy encounters, difficulty levels, and batsuits, all with enhanced visuals.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-gods-among-us-playstation-vita', 'Injustice: Gods Among Us', 'DC', '2013-11-12', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8616.jpg', 'What if our greatest heroes became our greatest threat? Injustice: Gods Among Us introduces a bold new franchise to the fighting game genre from NetherRealm Studios, creators of the definitive fighting game Mortal Kombat. Featuring DC Comics icons such Batman, Cyborg, The Flash, Harley Quinn, Nightwing, Solomon Grundy, Superman and Wonder Woman, the latest title from the award-winning studio presents a deep original story. Heroes and villains will engage in epic battles on a massive scale in a world where the line between good and evil has been blurred.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wolf-among-us-playstation-vita', 'The Wolf Among Us', 'DC', '2014-11-04', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vdk.jpg', 'The fifth episode of The Wolf Among Us, a five-episode series based on Fables (DC Comics/Vertigo).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-playstation-vita', 'Disney Infinity 2.0', 'Disney Infinity', '2015-05-09', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-builders-playstation-vita', 'Dragon Quest Builders', 'Dragon Quest', '2016-10-11', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9mq.jpg', '"Dragon Quest Builders is a sandbox action RPG where your imagination is the limit! Everything plays out in real time and the world is made entirely of blocks (although it may not look that blocky) and you can use these blocks to build pretty much whatever you want. Building is easy and can be done in three steps:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-2-the-power-of-two-playstation-vita', 'Epic Mickey 2: The Power of Two', 'Epic Mickey', '2013-06-18', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nhy.jpg', 'Unleash the power of the brush in an all new co-op adventure. Join Mickey and Oswald in an epic battle to save the magical world of Wasteland and change it forever. Interact with your favorite characters like never before in the most heroic adventure yet.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-x-2-hd-remaster-playstation-vita', 'Final Fantasy X/X-2 HD Remaster', 'Final Fantasy', '2014-03-18', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zpl.jpg', 'Based on the international versions of the games that were previously only released in Japan and Europe, FINAL FANTASY X/X-2 HD Remaster brings these timeless classics forward to the current generation of fans, old and new alike.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-of-final-fantasy-playstation-vita', 'World of Final Fantasy', 'Final Fantasy', '2016-10-25', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24k0.jpg', 'World of Final Fantasy combines classic RPG gameplay mechanics with fresh and imaginative toy-like visuals. As a brand-new title in the Final Fantasy franchise, this game can be enjoyed by both fans and newcomers to the series. Players will lead a pair of twins through varied Final Fantasy worlds and encounter the adorably familiar monsters therein. Capture and raise such familiar beasts as cactuar, chocobo, and behemoth to discover alternate forms and learn new abilities.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-collection-playstation-vita', 'God of War Collection', 'God of War', '2014-05-06', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ene.jpg', 'God of War: Origins Collection (known as God of War Collection – Volume II in Europe and Australia) is a remastered port of the two PlayStation Portable instalments in the series—Chains of Olympus and Ghost of Sparta—for the PlayStation 3 on a single Blu-ray Disc.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gravity-rush-playstation-vita', 'Gravity Rush', 'Gravity Rush', '2012-06-12', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5tgy.jpg', 'Gain a new perspective as you take on the role of Kat, a strong-willed girl seeking the means to protect her future in a world that’s crumbling to pieces. Tilt and move the PlayStation Vita System, taking gravity into your own hands to deliver devastating attacks, uncover the secrets to your past and explore a mysterious world.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guacamelee-playstation-vita', 'Guacamelee!', 'Guacamelee!', '2013-04-09', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g6i.jpg', '"Guacamelee! is a Metroid-vania style action-platformer set in a magical Mexican inspired world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('home-playstation-vita', 'Home', NULL, '2014-11-04', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ed9.jpg', 'Help Hazel redesign client homes in this fun Hidden Objects game, "Home Designer: Home Sweet Home".', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hue-playstation-vita', 'Hue', NULL, '2016-11-29', 'PlayStation Vita', 1, 0, NULL, NULL, 'Hue² is a puzzle game, which brings calmness, peace, and a sense of harmony. You need to place the colored cubes in a harmonious way in the gradient. The locked cubes are not moveable and they will be your guide. It seems that it is a piece of cake, right? Well, the beginning levels are really easy to pass, but on the other hand, when the number of locked cubes and the number of colorful cubes increase, the game becomes more interesting and challenging. 377 levels will challenge your logic and sense of color.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iconoclasts-playstation-vita', 'Iconoclasts', NULL, '2018-01-23', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ug9.jpg', 'Join renegade mechanic Robin and uncover the secrets of a dying planet. Explore a huge, open world filled with intricate puzzles, oddball characters and menacing bosses in a beautiful platform adventure telling a personal story about faith, purpose and whether the world is really worth saving.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-collection-playstation-vita', 'Jak and Daxter Collection', 'Jak and Daxter', '2013-06-18', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ny0.jpg', 'The Jak and Daxter Collection is a compilation of the first three main instalments in the Jak and Daxter series (The Precursor Legacy, Jak II, and Jak 3) remastered in full 720p HD with support for 3D graphics and PlayStation Network trophies.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('touch-my-katamari-playstation-vita', 'Touch My Katamari', 'Katamari', '2012-02-22', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9s71.jpg', 'Roll up some fun with this portable entry in the beloved Katamari Damacy franchise. In Touch My Katamari, the ever-growing ball of bits and bobs is controlled by touching the screen or using both analog control sticks to roll it in any direction.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-mercenary-playstation-vita', 'Killzone: Mercenary', 'Killzone', '2013-09-10', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v41.jpg', 'Killzone: Mercenary is a first-person shooter video game and the second handheld game in the Killzone series. For the first time in a Killzone campaign, players can fight alongside Helghast forces as well as ISA specialists, carrying out missions that regular soldiers cannot. As a mercenary, players are free to decide which tactics and load outs they will use to fulfill their contract; employers will reward players with money if successfully completed. The game utilizes the PS Vita''s touchscreen and rear touch panel.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-playstation-vita', 'Lego Harry Potter: Years 5–7', 'Lego', '2012-03-06', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-playstation-vita', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-playstation-vita', 'Lego The Lord of the Rings', 'Lego', '2012-10-30', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-legends-of-chima-laval-s-journey-playstation-vita', 'Lego Legends of Chima: Laval''s Journey', 'Lego', '2013-06-25', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co615v.jpg', 'Get ready for an epic adventure as Laval races to unlock the secret of the legendary triple-Chi armour before Cragger can manipulate its awesome power to threaten the balance of Chima itself! Laval and his allies will explore Lion Temple, Eagle Spire, Gorilla Forrest, Rhino Quary, Croc Swamp and more as they harness the power of Chi to leap, swing, fly and fight through 15 levels of intense action! Can Laval discover the truth behind the legend of the triple-Chi before it’s too late?', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-universe-in-peril-playstation-vita', 'Lego Marvel Super Heroes: Universe in Peril', 'Lego', '2013-10-22', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co484t.jpg', 'A port of Lego Marvel Super Heroes, a 2013 Lego-themed action-adventure video based on Marvel comic book character.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-playstation-vita', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-playstation-vita', 'Lego The Hobbit', 'Lego', '2014-04-08', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-ninjago-nindroids-playstation-vita', 'Lego Ninjago: Nindroids', 'Lego', '2014-07-29', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co615t.jpg', 'The highly popular LEGO Ninjago videogame franchise is back with high-kicking action and adventure! LEGO Ninjago: Nindroids comes to the Nintendo 3DS and PlayStation Vita this summer. Based on the first five new episodes of the animated TV series, "LEGO Ninjago Rebooted,” players will battle and defend the New Ninjago City where the Ninjas face a technological threat by the evil Overlord and his robotic army of Nindroids. Using swift combo attacks, unique fighting moves, special weapons and new vehicles, the Ninjas must fight with all their might to save Ninjago.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-playstation-vita', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-ninjago-shadow-of-ronin-playstation-vita', 'Lego Ninjago: Shadow of Ronin', 'Lego', '2015-03-27', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3c83.jpg', 'There is a new threat in Ninjago, and he goes by the name of Ronin. With help from his army of dark samurai, Ronin steals the Ninjas'' memories using an ancient weapon called the Obsidian Glaive. In LEGO Ninjago: Shadow of Ronin, it is up to players to help the Ninjas regain their memories and reclaim their powers before Ronin completes his plan and releases an even greater evil on Ninjago.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-playstation-vita', 'Lego Jurassic World', 'Lego', '2015-06-12', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-playstation-vita', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-playstation-vita', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('little-deviants-playstation-vita', 'Little Deviants', NULL, '2012-02-15', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kxe.jpg', 'Join the Little Deviants in a series of madcap adventures that allow you to have fun discovering and experimenting with the new PS Vita System functions - including rear touch, front touch, six-axis motion senors, front and rear cameras and microphone.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-ps-vita-playstation-vita', 'LittleBigPlanet PS Vita', 'LittleBigPlanet', '2012-09-25', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tv7.jpg', 'In LittleBigPlanet for PlayStationVita, join Sackboy on a completely new adventure, filled with exploration and competition.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-marvel-vs-capcom-3-playstation-vita', 'Ultimate Marvel vs. Capcom 3', 'Marvel', '2012-02-22', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yej.jpg', 'Ultimate Marvel vs. Capcom 3 is a crossover fighting game developed by Capcom in collaboration with Eighting. It is an updated version of Marvel vs. Capcom 3: Fate of Two Worlds. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. The game was released in November 2011 for the PlayStation 3 and Xbox 360, and was featured as a launch title for the PlayStation Vita in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-playstation-vita', 'The Amazing Spider-Man', 'Marvel', '2013-11-19', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-hd-collection-playstation-vita', 'Metal Gear Solid HD Collection', 'Metal Gear', '2012-06-12', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gkj.jpg', 'From the critically acclaimed director, Hideo Kojima, Metal Gear Solid HD Collection offers a handful of the most popular Metal Gear Solid titles from the past in true HD for the first time ever. Featuring three complete games, Metal Gear Solid 2: Sons of Liberty, Metal Gear Solid: Snake Eater and Metal Gear Solid: Peace Walker, the HD Collection offers old and new fans a chance to experience the epic game play, design and storytelling of the MGS franchise. The "Metal Gear Solid (MGS)" series is the seminal work of Hideo Kojima, Japan''s master game creator, and the progenitor of the stealth action game genre. The series has become a global phenomenon, with over 27 million copies sold worldwide. The player controls a secret agent from an elite special forces unit who is sent on solo sneaking missions through enemy installations, vast jungles, and sometimes even the thick of battle. Alone and surrounded by the enemy, even a special forces agent will find it tough to come out alive. But that is the secret behind the series'' popularity-the cerebral challenge of figuring out how to avoid combat, and the thrill of sneaking through enemy territory undetected.The MGS series is also known for its storyline, which blends seamlessly with the gameplay. The scenarios are based on extensive research and incorporate the drama of actual developments in society. These elements have made MGS what it is today: a mature work of entertainment that transcends national borders and the confines of video games, and one of the leading products of the Japanese content business.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-sigma-plus-playstation-vita', 'Ninja Gaiden Sigma Plus', 'Ninja Gaiden', '2012-02-22', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h0h.jpg', 'Ninja Gaiden Sigma Plus is a port of Ninja Gaiden Sigma. Like Ninja Gaiden Black''s "Ninja Dog" mode, Sigma Plus features an easier difficulty called "Hero" mode, making it more accessible to casual gamers. It also takes advantage of the additional features that the Vita offers, including gyroscopic first-person aiming (by tilting the PlayStation Vita, the player can adjust the camera angle in first-person viewing modes), back touchpad controls (tapping symbols using the rear touchpad will allow Ryu to boost the power of his Ninpo), and touch screen controls (players can go into first-person mode by tapping the touch screen). In addition, Ninja Gaiden Sigma Plus offers new sets of accessories that Ryu and Rachel can equip.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-2-playstation-vita', 'Ninja Gaiden Σ2+', 'Ninja Gaiden', '2013-02-26', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ymx.jpg', 'Ninja Gaiden Sigma 2 is the “ultimate” Ninja Gaiden, featuring characters from the previous installments that have defined the franchise. It radiates a striking visual appeal in high resolution display, featuring character and environmental graphics whose quality exceeds the original Ninja Gaiden Sigma. Combining both melee and long-range battles against enemies, the game requires skillful and strategic playing to successfully journey through the missions.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('octodad-dadliest-catch-playstation-vita', 'Octodad: Dadliest Catch', NULL, '2015-05-26', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1szo.jpg', 'Octodad: Dadliest Catch is a game about destruction, deception, and fatherhood. The player controls Octodad, a dapper octopus masquerading as a human, as he goes about his life. Octodad''s existence is a constant struggle, as he must master mundane tasks with his unwieldy boneless tentacles while simultaneously keeping his cephalopodan nature a secret from his human family.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-stranger-s-wrath-hd-playstation-vita', 'Oddworld: Stranger''s Wrath HD', 'Oddworld', '2012-12-18', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yox.jpg', 'Oddworld: Stranger''s Wrath HD is a remaster of Oddworld: Stranger''s Wrath. The improvements include remastered dialogue, improved character textures and bonus material.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-munch-s-oddysee-playstation-vita', 'Oddworld: Munch''s Oddysee', 'Oddworld', '2014-12-16', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yni.jpg', 'Oddworld: Munch''s Oddysee is set in the fictional Oddworld universe and take place after those of Abe''s Exoddus. The player controls Munch as well as Abe, the hero of the previous Oddworld games. Abe''s abilities haven''t changed much since the last installment: as before, GameSpeak must be used to communicate with other creatures, leading them to safety. His fellow Mudokons can now be ordered to attack enemies. Abe can also grab and toss Mudokons or Munch to lead them to area they cannot access otherwise. Possessing enemies also comes into play, and is needed to solve many of the puzzles. Possession abilities can now be used to ignite quarrels between enemies and make them fight each other.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-new-n-tasty-playstation-vita', 'Oddworld: New ''n'' Tasty!', 'Oddworld', '2016-01-19', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n69.jpg', 'Oddworld: New ''n'' Tasty is a faithful remake of Oddworld: Abe''s Oddysee where the pre-rendered sceneries are recreated in real-time 3D without changing the original gameplay. It also replaces the single screens linked together of the original version into a true 2.5D side-scrolling game. While there are various enhancements and details to the character and the scenery, the basic gameplay is still largely similar in a side by side comparison. The GameSpeak system Abe uses to command and talk to other characters start with the same commands, but can later be expanded. This version of the game supports leaderboards for the completion time of each mode and the overall game. There are three difficulty levels and the game. It includes the original cooperative function of the original game when another player can take over when the first player dies, taking turns controlling Abe.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('papers-please-playstation-vita', 'Papers, Please', NULL, '2017-12-12', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vep.jpg', 'The communist state of Arstotzka has just ended a 6-year war with neighboring Kolechia and reclaimed its rightful half of the border town, Grestin. Your job as immigration inspector is to control the flow of people entering the Arstotzkan side of Grestin from Kolechia. Among the throngs of immigrants and visitors looking for work are hidden smugglers, spies, and terrorists. Using only the documents provided by travelers and the Ministry of Admission''s primitive inspect, search, and fingerprint systems you must decide who can enter Arstotzka and who will be turned away or arrested.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-golden-playstation-vita', 'Persona 4 Golden', 'Persona', '2012-11-20', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1x.jpg', 'An enhanced rerelease of Shin Megami Tensei: Persona 4 (2008) featuring quality-of-life improvements, gameplay enhancements, new locations, balance tweaks, online functionality, new difficulty options, an additional side character storyline and a changed endgame.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-dancing-all-night-playstation-vita', 'Persona 4: Dancing All Night', 'Persona', '2015-09-29', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hmn.jpg', 'Persona 4: Dancing All Night is a story-driven music game of the cult hit RPG Persona 4, developed by ATLUS. Replacing the RPG elements are dance battles that challenge players'' dexterity and accuracy, as they tap out re-mixes of fan-favorite themes and brand new music tracks. The storyline continues from after the events of Persona 4, when the teenage mega-idol, Rise Kujikawa, returns to the city to re-take her show biz career. During that time, a strange video appears on the internet and the unfortunate people who watched it have gone missing! Members of Kanamin Kitchen, Rise''s junior idol group, have disappeared and it''s up to the Investigation team to mount a rescue mission - only they discover the same monstrous Shadows from the Midnight Channel. To make matters even worse, their Persona abilities are rendered ineffective, and the Shadows in P4D can only be defeated by dance, so bust out powerful dance moves to save the day!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-all-stars-battle-royale-playstation-vita', 'PlayStation All-Stars Battle Royale', NULL, '2012-11-20', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ssv.jpg', 'Playstation All-Stars Battle Royal is a cross over fighting game featuring (mostly exclusive) iconic characters from various Playstation franchises. Each stage also feature prominent setting from other franchises.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('proteus-playstation-vita', 'Proteus', NULL, '2013-10-29', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ezb.jpg', 'Proteus is a game about exploration and immersion in a dream-like island world where the soundtrack to your play is created by your surroundings. Played in first-person, the primary means of interaction is simply your presence in the world and how you observe it. The procedurally generated islands are home to creatures natural and imagined, tranquil valleys and ruins with magical properties.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-collection-playstation-vita', 'Ratchet & Clank Collection', 'Ratchet & Clank', '2014-07-29', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230q.jpg', 'This trilogy of Ratchet & Clank classics contains Ratchet & Clank, Ratchet & Clank: Going Commando, and Ratchet & Clank: Up Your Arsenal – all remastered in 1080p with additional upgrades such as Trophy and 3D support.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-origins-playstation-vita', 'Rayman Origins', 'Rayman', '2012-02-15', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v7k.jpg', 'Bubble Dreamer, Rayman, his best friend Globox, and some Teensy friends are chilling out at the Bubble Dreamer''s resting grounds, the Snoring Tree. However, their snoring disturbs an old granny from the Land of the Livid Dead, who retaliates by sending an evil army of horrendous creatures and the Darktoons across the world, capturing the Electoons that inhabit the world, imprisoning Betilla the Nymph and her sisters, and plunging the Glade into chaos. As a result, the ensuing disaster causes the Bubble Dreamer to go crazy and have nightmares. Although they are captured, Rayman and his friends are able to escape the Darktoons. They are then tasked by the Magician to gather enough Electoons to cure the Bubble Dreamer and restore the Glade of Dreams. Their efforts to locate the Electoons allow them to gain access to the various lands of the Glade, rescuing the Nymphs along the way.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-playstation-vita', 'Rayman Legends', 'Rayman', '2013-09-03', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-2-playstation-vita', 'Resident Evil: Revelations 2', 'Resident Evil', '2015-08-18', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92d9.jpg', 'Resident Evil: Revelations 2 is the retail version of the episodic survival horror series that was originally released as four downloadable episodes. This physical version combines the entire story along with some extras, but not all the available DLC. The PC version did not receive a retail release, but the same content was bundled on Steam. The game comprises four episodes, each of which feature two separate stories. This sequel bears a stronger tone to the concept of survival horror than titles such as Resident Evil 5 and Resident Evil 6. Elements of ammunition management as well as stealth or sneaking come into play in the gameplay.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resistance-burning-skies-playstation-vita', 'Resistance: Burning Skies', 'Resistance', '2012-05-29', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b4c.jpg', 'Resistance: Burning Skies is a unique Resistance experience developed specifically for PS Vita that takes full advantage of the system''s dual analog sticks and features an all-new hero and story written by William C. Dietz, author of Resistance: The Gathering Storm and Resistance: A Hole in the Sky.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('retro-city-rampage-dx-playstation-vita', 'Retro City Rampage DX', 'Retro City Rampage', '2012-10-09', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h4u.jpg', 'Open-world carjacking goes back to the ''80s in this 8-BIT nostalgic throwback.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-playstation-vita', 'Shakedown: Hawaii', 'Retro City Rampage', '2019-05-07', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-all-stars-racing-transformed-playstation-vita', 'Sonic & All-Stars Racing Transformed', 'Sega All-Stars', '2012-12-18', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvw.jpg', 'Race as Sonic and a host of legendary All-Stars and prepare to transform! Speed across land, sea and air in a high velocity battle to the finish line, as your amazing transformable vehicle changes from car to boat to plane mid-race. Racing on mobile will never be the same again!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-half-genie-hero-playstation-vita', 'Shantae: Half-Genie Hero', 'Shantae', '2016-12-20', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ymj.jpg', 'Shantae embarks on her first full HD adventure! After three highly successful outings with Shantae, Shantae: Risky''s Revenge, and Shantae and the Pirate''s Curse, Shantae and her friends finally get a full HD console-based sequel! Boasting vivid, detailed high-definition graphics that retain the 2D hand-drawn sprites the series is known for, this newest entry in the Shantae series almost looks like a playable TV show! Presented as a stage-based 2.5D platformer with heavy exploration elements, Shantae uses her trademark Hair-Whip Attack to dispatch enemies, then takes advantage of her Belly Dance Magic to transform into 8 different forms that each have their own unique abilities and move sets. As new forms are mastered, old stages can be re-explored to unearth new items and secrets, ensuring there''s plenty of content on offer for novices and platforming gurus alike. Topple the villainous Baron behind each criminal caper afflicting Sequin Land, and prepare for the ultimate showdown against Shantae''s arch-nemesis: that bodacious buccaneer, Risky Boots!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-playstation-vita', 'Shovel Knight', 'Shovel Knight', '2016-11-09', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaa7.jpg', 'Shovel Knight is a sweeping classic action adventure game with awesome gameplay, memorable characters, and an 8-bit retro aesthetic. It''s a hot mashup of new and old! You play as the eponymous Shovel Knight, a small knight with a huge quest. Shovel Knight has come to this land with two goals: to defeat the evil Enchantress and quest for his lost beloved. He wields a Shovel Blade: a multipurpose weapon whose techniques have now been lost to the ages. Always honest and helpful, Shovel Knight is a shining example of the code of Shovelry: Slash Mercilessly and Dig Tirelessly!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sly-cooper-thieves-in-time-playstation-vita', 'Sly Cooper: Thieves in Time', 'Sly Cooper', '2013-02-05', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rbv.jpg', 'Sly Cooper: Thieves in Time is a stealth platformer developed by Sanzaru Games and published by Sony Computer Entertainment. Released in 2013 for PlayStation 3 and PlayStation Vita, it is the fourth main entry in the Sly Cooper series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sly-collection-playstation-vita', 'The Sly Collection', 'Sly Cooper', '2014-05-27', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g8d.jpg', 'The Sly Collection is a remastered compilation of the first three Sly Cooper games, developed by Sanzaru Games and published by Sony Computer Entertainment. Released in 2010 for PlayStation 3 and later for PlayStation Vita, it includes Sly Cooper and the Thievius Raccoonus, Sly 2: Band of Thieves, and Sly 3: Honor Among Thieves, all with enhanced HD graphics, Trophy support, and stereoscopic 3D compatibility on PS3. The collection preserves the original gameplay while offering visual and performance improvements.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spelunky-playstation-vita', 'Spelunky', NULL, '2013-08-27', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47m4.jpg', 'Spelunky (also known as Spelunky HD) is a remake of Spelunky (now known as Spelunky Classic), an open source indie platformer video game created by Derek Yu and originally released as freeware for Microsoft Windows. The player controls a spelunker who explores a series of caves while collecting treasure, saving damsels, fighting enemies and dodging traps. The caves are procedurally generated, making each run through the game unique. Spelunky is one of the first examples of a roguelike-like, borrowing concepts from the roguelike genre, and was the influence for many later roguelike-like games.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-meat-boy-playstation-vita', 'Super Meat Boy', 'Super Meat Boy', '2015-10-06', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5t36.jpg', 'Super Meat Boy Handheld! is Super Meat Boy for the iPhone... kinda.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-splitz-playstation-vita', 'Super Monkey Ball: Banana Splitz', 'Super Monkey Ball', '2012-10-23', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3s6e.jpg', 'Super Monkey Ball: Banana Splitz is a video game released exclusively for the PlayStation Vita by Sega. The game is the tenth release in the Super Monkey Ball series.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-swapper-playstation-vita', 'The Swapper', NULL, '2014-08-05', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coatev.jpg', 'The Swapper is a short puzzle platformer where you must complete every puzzle and collect 124 orbs, in groups of 3 and 9 later on, to complete the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-hearts-playstation-vita', 'Tales of Hearts', 'Tales', '2014-11-11', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21pi.jpg', 'In this point and click adventure, there is a secret world hidden at the bottom of the forest: the magical kingdom of Brie where tiny humans live in harmony with animals. When little Max is called home to help his estranged mother, he never imagined it would be the biggest journey he would have to make.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-space-mutant-blobs-attack-playstation-vita', 'Tales from Space: Mutant Blobs Attack', NULL, '2012-02-21', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rk0.jpg', 'Tales from Space: Mutant Blobs Attack is a sci-fi puzzle-platformer of cataclysmic proportions. You''re a Blob of alien origin with mutant powers and an insatiable appetite. To the great horror of your former captors (and all of humanity), you have escaped into the world.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tearaway-playstation-vita', 'Tearaway', 'Tearaway', '2013-11-22', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h0d.jpg', 'Explore a spectacular world held entirely in your hands.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-playstation-vita', 'Terraria', NULL, '2013-12-17', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teslagrad-playstation-vita', 'Teslagrad', NULL, '2015-11-24', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6eo7.jpg', 'Teslagrad 2 is the sequel to the original Teslagrad, developed by Rain Games and released in 2023. This 2D puzzle platformer builds upon the magnetic and electrical mechanics of its predecessor, with players once again using these abilities to solve puzzles and traverse complex environments. Set in a new region, the game introduces new powers, enemies, and challenges, while maintaining the visual storytelling and atmospheric design characteristic of the series.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-ultimate-playstation-vita', 'Tetris Ultimate', 'Tetris', '2015-06-02', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rkf.jpg', 'Tetris Ultimate has six exciting modes, fun new features, and unique visuals, the evolution of this iconic game is the ultimate must-have on next-gen consoles.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thomas-was-alone-playstation-vita', 'Thomas Was Alone', NULL, '2013-04-23', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ak5.jpg', 'Thomas Was Alone is an indie minimalist 2D platformer about friendship and jumping and floating and anti-gravity. Guide a group of rectangles through a series of obstacles, using their different skills together to get to the end of each environment.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-golden-abyss-playstation-vita', 'Uncharted: Golden Abyss', 'Uncharted', '2012-02-15', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1un0.jpg', 'Uncover the dark secret behind the 400-year-old massacre of a Spanish expedition as Nathan Drake tracks the murderous trail of an ancient and secret Spanish sect. Caught in the middle of a rivalry between Jason Dante - his old friend - and Marisa Chase - the granddaughter of an archeologist who has mysteriously vanished without a trace - Nathan Drake delves into the treacherous river basins, undiscovered temple ruins and karst caverns of Central America in search of a legendary lost city, only to find himself pushed to the edge of the Golden Abyss', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('undertale-playstation-vita', 'Undertale', NULL, '2017-08-15', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('volume-playstation-vita', 'Volume', NULL, '2016-01-06', 'PlayStation Vita', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobn3i.jpg', NULL, 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-complete-first-season-playstation-vita', 'The Walking Dead : The Complete First Season', 'The Walking Dead', '2013-08-22', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4wxx.jpg', 'The living will have to survive amongst the dead in this game based on The Walking Dead, the widely acclaimed comic book series and television series. Across five dark and emotional episodes of gameplay, every decision and action you take can result in the entire story of the game changing around you.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-season-two-playstation-vita', 'The Walking Dead: Season Two', 'The Walking Dead', '2014-11-04', 'PlayStation Vita', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k36.jpg', 'Similar to the previous season, The Walking Dead: Season Two is a point-and-click adventure game. The player, in control of Clementine, can direct the character around the environment, examine and interact with various scenery elements and collect and use objects to advance the story. The player can also initiate conversations with non-player characters via conversation trees. Certain replies from other characters may offer the player multiple choices to select from, including the option to stay silent, with a limited amount of time to make the selection; if the player does not select an option, the conversation will continue as if they had stayed quiet. Such choices can affect how the other characters will later react to Clementine which can influence later events in the story. Other scenes are more action-oriented, requiring the player to complete quick time events to avoid Clementine or her allies from getting killed. If the player fails these events, the game will restart at the start of such scenes. Such action scenes may also require the player to make a key decision within a limited time frame, such as which of two characters to save from attacking walkers.', 'NA', 33);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('abz-playstation-4', 'Abzû', NULL, '2017-01-31', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28sy.jpg', 'Abzu is an exploration game where you are a lone diver in a lush ocean world. The diver descends deeper and deeper into the depths, where she will encounter majestic creatures, discover ancient secrets, and search for her true purpose. Abzu roughly translates to "The Ocean of Wisdom" from ancient Sumerian.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('accounting-playstation-4', 'Accounting+', NULL, '2017-12-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9cp4.jpg', 'Real Escape Game.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alan-wake-remastered-playstation-4', 'Alan Wake Remastered', 'Alan Wake', '2021-10-05', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65aa.jpg', 'Alan Wake Remastered is an updated version of the original psychological horror action-adventure game developed by Remedy Entertainment. The game retains the core narrative, which follows bestselling thriller novelist Alan Wake as he struggles with writer''s block. He visits the small town of Bright Falls with his wife, Alice, in search of inspiration. Shortly after their arrival, Alice mysteriously disappears.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('among-us-crewmate-edition-playstation-4', 'Among Us: Crewmate Edition', 'Among Us', '2021-12-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wwy.jpg', 'Play online with 4-15 players as you attempt to hold your spaceship together and return back to civilization. But beware... as there may be an alien impostor aboard!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('apico-playstation-4', 'Apico', NULL, '2022-09-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48vu.jpg', 'Apico is a laid-back beekeeping sim game about breeding, collecting, & conserving bees! Set in a series of lush environments, Apico uniquely combines resource gathering, biology, and beekeeping minigames, taking ideas from a mix of real-life and fantasy apiculture & floriculture.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arcade-classics-anniversary-collection-playstation-4', 'Arcade Classics Anniversary Collection', NULL, '2019-04-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vaa.jpg', '8 Konami arcade classics of the 80s, from Nemesis to TwinBee. Including bonus eBook packed with new information never before revealed to the public.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arzette-the-jewel-of-faramore-playstation-4', 'Arzette: The Jewel of Faramore', NULL, '2024-02-14', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ryw.jpg', 'Arzette: The Jewel of Faramore is a new interactive animated adventure, where players must help Arzette save the Kingdom of Faramore from the evil demon king, Daimur. It is a spiritual successor to a pair of infamous fantasy adventure titles, being developed by Seedy Eye Software and both funded & published by Limited Run Games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iv-black-flag-playstation-4', 'Assassin''s Creed IV: Black Flag', 'Assassin''s Creed', '2013-11-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tx9.jpg', NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-unity-playstation-4', 'Assassin''s Creed Unity', 'Assassin''s Creed', '2014-11-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xiq.jpg', 'Assassin’s Creed Unity is an action-adventure game set in Paris during the French Revolution. The player controls Arno Dorian, an Assassin who seeks to uncover the forces behind the political unrest. The game introduces new weapons, including the Phantom Blade, a modified Hidden Blade with ranged capabilities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-syndicate-playstation-4', 'Assassin''s Creed Syndicate', 'Assassin''s Creed', '2015-10-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xis.jpg', 'London, 1868. The Industrial Revolution unleashes an incredible age of invention, transforming the lives of millions with technologies once thought impossible. Opportunities created during this period have people rushing to London to engage in this new world, a world no longer controlled by kings, emperors, politicians, or religion, but by a new common denominator: money.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-chronicles-playstation-4', 'Assassin''s Creed Chronicles', 'Assassin''s Creed', '2016-02-09', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yvv.jpg', 'As the direct prequel of the critically acclaimed console title Assassin’s Creed, discover more of the story of Altaïr as he must find “the chalice,” an object of such power that whoever is in possession of it can end the Crusades.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-the-ezio-collection-playstation-4', 'Assassin''s Creed: The Ezio Collection', 'Assassin''s Creed', '2016-11-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nrv.jpg', 'Make history as the legendary Master Assassin, Ezio Auditore da Firenze, in Assassin’s Creed The Ezio Collection, which includes the acclaimed single-player campaigns and single-player add-on content (no multiplayer content) from Assassin’s Creed II, Assassin’s Creed Brotherhood, and Assassin’s Creed Revelations with enhanced
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-origins-playstation-4', 'Assassin''s Creed Origins', 'Assassin''s Creed', '2017-10-27', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbe.jpg', 'Assassin’s Creed Origins is an action-adventure game set in ancient Egypt at the end of the Ptolemaic era. The story follows Bayek, a Medjay tasked with protecting the people, as personal tragedy draws him into a wider conflict that leads to the origins of the Assassin Brotherhood.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-rogue-remastered-playstation-4', 'Assassin''s Creed Rogue Remastered', 'Assassin''s Creed', '2018-03-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xit.jpg', 'In addition to running in 4K, Assassin''s Creed Rogue Remastered sports higher-resolution textures and shadows, improved environmental rendering, and new visual effects, making its sprawling wilderness, Arctic icescapes, and bustling version of New York City more striking than ever. The new edition also packs in all of the original''s downloadable content and expansions, including two bonus missions – The Armor of Sir Gunn and The Siege of Fort de Sable – as well as the weapons, outfits, and customization items in the Master Templar and Explorer packs. It also includes a new bonus: Bayek''s legacy outfit from Assassin''s Creed Origins.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-odyssey-playstation-4', 'Assassin''s Creed Odyssey', 'Assassin''s Creed', '2018-10-05', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ka7.jpg', 'A bundle including three Assassin''s Creed titles: Assassin''s Creed Valhalla, Assassin''s Creed Odyssey, and Assassin''s Creed Origins.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-remastered-playstation-4', 'Assassin''s Creed III Remastered', 'Assassin''s Creed', '2019-03-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjw.jpg', 'Relive the American Revolution or experience it for the first time in Assassin''s Creed III Remastered, with enhanced graphics and improved gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-valhalla-playstation-4', 'Assassin''s Creed Valhalla', 'Assassin''s Creed', '2020-11-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ed3.jpg', 'In Assassin''s Creed Valhalla, become Eivor, a legendary Viking raider on a quest for glory. Explore a dynamic and beautiful open world set against the brutal backdrop of England’s Dark Ages. Raid your enemies, grow your settlement, and build your political power in the quest to earn a place among the gods in Valhalla.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('astro-bot-rescue-mission-playstation-4', 'Astro Bot Rescue Mission', 'Astro Bot', '2018-10-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eao.jpg', 'Astro Bot: Rescue Mission is a brand new Platform game exclusive to PS VR. Take control of Astro the captain bot and go on an epic VR rescue mission to save your fellow Bots who are dispersed all over space."', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-1-playstation-4', 'Atari Flashback Classics: Vol.1', 'Atari Flashback Classics', '2016-10-12', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-2-playstation-4', 'Atari Flashback Classics: Vol.2', 'Atari Flashback Classics', '2016-10-12', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-3-playstation-4', 'Atari Flashback Classics: Vol.3', 'Atari Flashback Classics', '2018-12-13', 'PlayStation 4', 0, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-1-playstation-4', 'Atari Recharged Collection 1', 'Atari Recharged', '2023-11-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cnf.jpg', 'Atari Recharged Collection 1 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-2-playstation-4', 'Atari Recharged Collection 2', 'Atari Recharged', '2023-11-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cng.jpg', 'Atari Recharged Collection 2 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-3-playstation-4', 'Atari Recharged Collection 3', 'Atari Recharged', '2024-01-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaekx.jpg', 'The Atari Recharged Collection 3 includes Yars: Recharged and Caverns of Mars: Recharged.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-4-playstation-4', 'Atari Recharged Collection 4', 'Atari Recharged', '2024-01-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaenn.jpg', 'The Atari Recharged Collection 4 includes Missile Command: Recharged and Gravitar: Recharged.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-playstation-4', 'Axiom Verge', 'Axiom Verge', '2015-03-31', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kml.jpg', 'After a lab accident, a scientist awakens in a mysterious, alien world. Is this a distant planet? The far future? Or a complex virtual-reality computer simulation?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-2-playstation-4', 'Axiom Verge 2', 'Axiom Verge', '2021-08-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3k3x.jpg', 'You may have played Axiom Verge, or heard it referenced as a benchmark for indie “metroidvania” adventures. Axiom Verge 2 is part of the same story as Axiom Verge 1 but is a completely new game: new characters, new powers, new enemies, and a new world. You can play it before or after the original.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('axiom-verge-1-2-double-pack-playstation-4', 'Axiom Verge 1 & 2 Double Pack', 'Axiom Verge', '2021-08-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wha.jpg', 'Axiom Verge 1:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('balan-wonderworld-playstation-4', 'Balan Wonderworld', NULL, '2021-03-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xxs.jpg', 'Balan Wonderworld is a wondrous action-platformer game themed around a mysterious musical theatre.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baldur-s-gate-enhanced-edition-baldur-s-gate-ii-enhanced-edition-playstation-4', 'Baldur''s Gate: Enhanced Edition & Baldur''s Gate II: Enhanced Edition', 'Baldur''s Gate', '2019-10-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ndo.jpg', 'Kidnapped. Imprisoned. Tortured. The wizard Irenicus holds you captive in his stronghold, attempting to strip you of the powers that are your birthright.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bastion-playstation-4', 'Bastion', NULL, '2015-04-07', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qlj.jpg', 'A hack-and-slash RPG featuring a reactive narrator, various unlockable weapons, weapon upgrades, practice mini-games and optional difficulty modifiers, set in an imaginary world in the aftermath of an uncertain apocalypse, in which the player embodies a teenager with a troubled past as he and the narrator work together to rebuild the world out of a persisting hub called the Bastion.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('battlezone-playstation-4', 'Battlezone', 'Battlezone', '2016-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mws.jpg', 'Battlezone is an arcade game from Atari released in November 1980. It displays a wireframe view (using vector graphics rather than raster graphics) on a horizontal black and white (with green and red sectioned color overlay) vector monitor. Due to its novel gameplay and look, this game was very popular for many years. Throughout the 1980s, Battlezone was ported to several home computer systems (usually on the Atarisoft label), including the Apple II, the Commodore 64, the Sinclair ZX Spectrum, and the Atari XEGS. The Atari ST port contains large parts of the original 6502 code which is emulated in real time. An Atari 2600 port was also released, but has colored raster graphics due to limitations and the view is behind the tank rather than inside it.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-20th-anniversary-edition-playstation-4', 'Beyond Good & Evil - 20th Anniversary Edition', 'Beyond Good & Evil', '2024-06-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8eda.jpg', 'Swoop into the marvelous world of Hillys as action-reporter Jade to investigate the mysterious DomZ alien attacks alongside colorful characters, like her adoptive uncle Pey’j or the valiant Double H. Embark on this epic adventure in up to 4K, 60 fps with improved graphics, controls, and audio, along with brand-new autosave and cross-save features. Enjoy exclusive new rewards as you explore the planet and discover more about Jade’s past in a new treasure hunt throughout Hillys. Put your skills to the test thanks to the new speedrun mode and updated achievements, and learn more about the game’s development and secrets in the anniversary gallery! Armed with her daï-jo and faithful camera, Jade’s adventure will get you to freely explore Hillys, combat creatures large and small, infiltrate dangerous areas, solve enigmatic puzzles, play addictive mini-games, race the best hovercraft pilots, and take pictures of the whole experience.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-binding-of-isaac-afterbirth-playstation-4', 'The Binding of Isaac: Afterbirth+', 'The Binding of Isaac', '2017-06-30', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8p3u.jpg', 'The Binding of Isaac: Afterbirth+ is a dungeon-crawling shoot-''em-up that''s literally a different game each and every time you play it! The randomly generated maps are built with over 11,000 unique room configurations, each populated with a nearly endless variety of enemies, items, challenges and secrets!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-the-collection-playstation-4', 'BioShock: The Collection', 'BioShock', '2016-09-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uv1.jpg', 'BioShock: The Collection is a game bundle consisting of remastered 1080p editions of BioShock, BioShock 2 and BioShock Infinite along with their accompanying downloadable content.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-bit-trip-playstation-4', 'The Bit.Trip', 'Bit.Trip', '2015-12-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86bs.jpg', 'A collection of the six original Bit.Trip games for the PS3, PS4, and Vita.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bit-trip-presents-runner2-future-legend-of-rhythm-alien-playstation-4', 'Bit.Trip Presents... Runner2: Future Legend of Rhythm Alien', 'Bit.Trip', '2016-02-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86be.jpg', 'Runner2 is the sequel to the critically acclaimed and IGF award winning BIT.TRIP RUNNER.,In the style of the BIT.TRIP series, Runner2 is a rhythm-music platforming game.,Players will run through fantastic environments, using brand new moves, to brand new soundtracks as they run, jump, slide, kick, and soar toward the goal of tracking down the Timbletot and thwarting his evil plans to destroy not only our world, but every world there is.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-zero-playstation-4', 'Blaster Master Zero', 'Blaster Master', '2020-06-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-zero-2-playstation-4', 'Blaster Master Zero 2', 'Blaster Master', '2020-06-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blood-truth-playstation-4', 'Blood & Truth', NULL, '2019-05-28', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rh8.jpg', 'Put on your PlayStation VR headset and ready yourself for hard-hitting action in the gritty and glamorous London underworld. You are elite Special Forces soldier Ryan Marks, on a desperate mission to save his family from a ruthless criminal overlord.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodborne-playstation-4', 'Bloodborne', NULL, '2015-03-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob99l.jpg', 'An action RPG in which the player embodies a Hunter who, after being transfused with the mysterious blood local to the city of Yharnam, sets off into a "night of the Hunt", an extended night in which Hunters may phase in and out of dream and reality in order to thin the outbreak of abominable beasts that plague the land and, for the more resilient and insightful Hunters, uncover the answers to the Hunt''s many mysteries.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-curse-of-the-moon-playstation-4', 'Bloodstained: Curse of the Moon', 'Bloodstained', '2018-05-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaas.jpg', '“Bloodstained: Curse of the Moon” is packed with the retro charm that made the legendary 2D action games of the 80s so enjoyable.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-ritual-of-the-night-playstation-4', 'Bloodstained: Ritual of the Night', 'Bloodstained', '2019-06-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc4a.jpg', 'Bloodstained: Ritual of the Night is a gothic horror action side-scrolling RPG set in 19th century England. A paranormal force has summoned a demon-infested castle, revealing crystal shards infused with tremendous magical power.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-curse-of-the-moon-2-playstation-4', 'Bloodstained: Curse of the Moon 2', 'Bloodstained', '2020-07-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobax6.jpg', 'Curse of the Moon 2 brings classic 2D action and a dark, 8-bit aesthetic together with modern playability. The multiple-scenario structure of the previous title returns with an epic new story supervised by IGA (Koji Igarashi) himself.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-bomberman-r-playstation-4', 'Super Bomberman R', 'Bomberman', '2018-06-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x7j.jpg', 'A sequel to Super Bomberman R, featuring an expanded story mode, and a new "Castle" battle mode which has one group teaming up to build castle defenses while the other attempts to breach the castle and take the treasure.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-the-handsome-collection-playstation-4', 'Borderlands: The Handsome Collection', 'Borderlands', '2015-03-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229i.jpg', 'Borderlands: The Handsome Collection is a compilation of Borderlands 2 and Borderlands: The Pre-Sequel! for PlayStation 4 and Xbox One, along with all of their accompanying downloadable content, enhanced local multiplayer, and the ability to transfer save data from their respective PlayStation 3/Vita and Xbox 360 versions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-the-borderlands-playstation-4', 'Tales from the Borderlands', 'Borderlands', '2016-04-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tr.jpg', 'Tales from the Borderlands is a five part episodic game series. Set on the unforgiving world of Pandora after the events seen in Borderlands 2, this is a story full of Borderlands'' trademark humor, following two adventurers on their quest for greatness.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-game-of-the-year-edition-playstation-4', 'Borderlands: Game of the Year Edition', 'Borderlands', '2019-04-03', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229j.jpg', 'Lock, Load, & Face the Madness! Get ready for the mind-blowing insanity, as one of four trigger-happy mercenaries, taking out everything that stands in your way. With its addictive action, frantic first person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is the breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell bent on finding a legendary stockpile of powerful alien technology known as The Vault.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-3-playstation-4', 'Borderlands 3', 'Borderlands', '2019-09-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20r3.jpg', 'The original shooter-looter returns, packing bazillions of guns and a mayhem-fueled adventure! Blast through new worlds and enemies as one of four new Vault Hunters. Play solo or with friends to take on insane enemies, score loads of loot and save your home from the most ruthless cult leaders in the galaxy.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tiny-tina-s-wonderlands-playstation-4', 'Tiny Tina''s Wonderlands', 'Borderlands', '2022-03-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co390m.jpg', 'Embark on an epic adventure full of whimsy, wonder, and high-powered weaponry! Bullets, magic, and broadswords collide across this chaotic fantasy world brought to life by the unpredictable Tiny Tina.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-boy-and-his-blob-retro-collection-playstation-4', 'A Boy and His Blob Retro Collection', 'A Boy and His Blob', '2022-05-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tlv.jpg', 'The Blob is back in an exclusive collection with Limited Run Games. The Retro Collection includes the original NES A Boy and His Blob: Trouble on Blobolonia, and The Rescue of Princess Blobette, originally on Game Boy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-bridge-playstation-4', 'The Bridge', NULL, '2015-08-18', 'PlayStation 4', 1, 0, NULL, NULL, NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('broforce-playstation-4', 'Broforce', NULL, '2016-03-01', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28vv.jpg', 'When evil threatens the world, the world calls on Broforce - an under-funded, over-powered paramilitary organization dealing exclusively in excessive force. Brace your loins with up to four players to run ‘n’ gun as dozens of different bros and eliminate the opposing terrorist forces that threaten our way of life. Unleash scores of unique weapons and set off incredible chain reactions of fire, napalm, and limbs in the name of freedom.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('broken-age-playstation-4', 'Broken Age', NULL, '2015-04-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vh9.jpg', 'Broken Age is a point-and-click adventure telling the stories of a young boy and girl leading parallel lives. Vella Tartine has been chosen by her village to be sacrificed to a terrible monster — but she decides to fight back. Meanwhile, Shay Volta is living a solitary life on a spaceship under the care of a motherly computer, but he wants to break free to lead adventures and do good in the world. Adventures ensue.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('brothers-a-tale-of-two-sons-playstation-4', 'Brothers: A Tale of Two Sons', NULL, '2015-09-01', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rro.jpg', 'Brothers is presented from a third-person view overlooking the two brothers. The brothers are moved individually by two thumbsticks on the controller. The controller triggers also cause the respective brother to interact with the game world, such as talking to a non-player character or grabbing onto a ledge or object.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-the-woolies-strike-back-playstation-4', 'Bubsy: The Woolies Strike Back', 'Bubsy', '2017-10-31', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/fgwgl5gc00cg5syybti6.jpg', '"Bubsy the Woolies Strike Back! is an all new Bubsy adventure featuring Bubsy in a bevy of exotic locations as he travels the planet looking for the beloved Golden Fleece.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-paws-on-fire-playstation-4', 'Bubsy: Paws on Fire!', 'Bubsy', '2019-05-16', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3mma.jpg', 'From the developers of the BIT.TRIP series comes Bubsy: Paws on Fire!, the latest and greatest in bobcat-based gaming.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bug-fables-the-everlasting-sapling-playstation-4', 'Bug Fables: The Everlasting Sapling', 'Bug Fables', '2020-05-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6r8x.jpg', 'Bug Fables: The Everlasting Sapling is an adventure RPG following three heroes, Vi, Kabbu, and Leif, as they embark on an epic quest in Bugaria in search of treasure and immortality. The game combines flat objects with 3D physics as the player jumps and utilizes the heroes’ unique abilities to solve puzzles and stun enemies while exploring a variety of unique, colorful areas. Battles are turn-based and with timed button inputs that can enhance your abilities.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bugsnax-playstation-4', 'Bugsnax', NULL, '2020-11-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qjm.jpg', 'Bugsnax is a humorous action adventure game in which we explore an island full of creatures that are hybrids of worms and food. The game was developed and released by independent Young Horses studio.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('carrion-playstation-4', 'Carrion', NULL, '2021-10-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eau.jpg', 'Carrion is a reverse horror game in which you assume the role of an amorphous alien being. Use your unique otherworldly abilities to your advantage and hunt down your prey!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('carto-playstation-4', 'Carto', NULL, '2020-10-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kf2.jpg', 'Carto is a tile placement adventure game where you explore the lands you placed and discover the secrets while exploring. What will happen to the world and the characters when you rearrange the tiles of the map?', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-requiem-symphony-of-the-night-rondo-of-blood-playstation-4', 'Castlevania Requiem Symphony of the Night & Rondo of Blood', 'Castlevania', '2018-10-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49m1.jpg', 'Experience two of the greatest games from the famous Castlevania series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-anniversary-collection-playstation-4', 'Castlevania Anniversary Collection', 'Castlevania', '2019-05-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8kz.jpg', 'Konami''s Castlevania Anniversary Collection traces the origins of the historic vampire franchise. Included is a unique eBook with details provided by developers, artists and others inspired by the Castlevania legacy which sheds a fresh light into the world of Castlevania.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-advance-collection-playstation-4', 'Castlevania Advance Collection', 'Castlevania', '2021-09-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xj.jpg', 'Castlevania Advance Collection includes three legendary Castlevania games that were first released in the early 2000s: Circle of the Moon, Aria of Sorrow, and Harmony of Dissonance. In addition, this collection also includes Castlevania: Dracula X and some never-before-seen sketches and artwork from the games!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('celeste-playstation-4', 'Celeste', NULL, '2018-01-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9dh.jpg', 'Help Madeline survive her inner demons on her journey to the top of Celeste Mountain, in this super-tight platformer from the creators of TowerFall. Brave hundreds of hand-crafted challenges, uncover devious secrets, and piece together the mystery of the mountain.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('citizens-unite-earth-x-space-playstation-4', 'Citizens Unite!: Earth x Space', NULL, '2021-01-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pch.jpg', 'Citizens Unite!: Earth x Space includes both the Citizens of Earth and Citizens of Space games. This time the two adventures have united with brand-new elements. Recruit 88 Citizens with unique abilities to save the Earth in both time-periods! Time travel back-and-forth between Citizens of Earth and Citizens of Space, unlocking new content and revealing the true ending!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-vi-playstation-4', 'Sid Meier''s Civilization VI', 'Civilization', '2019-11-22', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaaqr.jpg', 'Civilization is a turn-based strategy game in which you attempt to build an empire to stand the test of time. Become Ruler of the World by establishing and leading a civilization from the Stone Age to the Information Age. Wage war, conduct diplomacy, advance your culture, and go head-to-head with history’s greatest leaders as you attempt to build the greatest civilization the world has ever known.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('concrete-genie-playstation-4', 'Concrete Genie', NULL, '2019-10-08', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3u25.jpg', 'Concrete Genie is a game about Ash, a young boy who is bullied but discovers a magical paint that might save his home town.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-anniversary-collection-playstation-4', 'Contra Anniversary Collection', 'Contra', '2019-06-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob230.jpg', 'The Contra Anniversary Collection brings this classic Run and Gun franchise back to modern platforms and a new generation of players. Grab power ups and blast your way through waves of menacing enemies and bosses that will put your reaction skills to the test. Also included is a digital Bonus Book with tons of concept documents and sketches, the official chronology of the franchise, an exclusive interview with the veteran producer of the series, and more! Alone or with a friend, Contra provides hours of nail biting action. In a pinch make sure you know the code!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-rogue-corps-playstation-4', 'Contra: Rogue Corps', 'Contra', '2019-09-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lzz.jpg', 'CONTRA: ROGUE CORPS is a twin stick, third-person action game drawing upon its roots in fast and focused combat developed for the Xbox One, PlayStation 4, Nintendo Switch, and PC (STEAM). From the director of CONTRA III: THE ALIEN WARS and CONTRA: HARD CORPS, Nobuya Nakazato instills more than 25 years of franchise pedigree into CONTRA: ROGUE CORPS with enormous crazed enemies, over-the-top violence, and a cast of diverse playable characters that add to the irreverent tone of the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-operation-galuga-playstation-4', 'Contra: Operation Galuga', 'Contra', '2024-03-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72z7.jpg', 'The legendary Contra series is back! Contra: Operation Galuga is a modern reimagining of the classic run-‘n’-gun action game from the ’80s, featuring modern graphics and sound. Encounter new stages, new play mechanics, an updated weapons system and explosive co-op combat for up to two players in Story Mode or four players in Arcade Mode.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-playstation-4', 'Control', 'Control', '2019-08-27', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob5pu.jpg', 'Explore a vast universe with pulse-pounding action, side-splitting humor, and hair-raising plot twists in these 2 classic space adventure games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-ultimate-edition-playstation-4', 'Control: Ultimate Edition', 'Control', '2020-09-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ewb.jpg', 'Control Ultimate Edition contains the main game and all previously released Expansions ("The Foundation" and "AWE") in one great value package. Winner of over 80 awards, Control is a visually stunning third-person action-adventure that will keep you on the edge of your seat.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('costume-quest-2-playstation-4', 'Costume Quest 2', 'Costume Quest', '2014-10-31', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72nf.jpg', 'In developer Double Fine’s triumphant return to Auburn Pines, our candy-crazed crusaders Wren and Reynold must once again protect Halloween from untold horrors, and grown-ups! Your favorite trick-or-treaters will come armed with a new batch of costumes they wear to transform into giant super powered fantasy Hallowarriors. Fans of the original can look forward to a sweet upgraded battle system and a story that is unmistakably Double Fine.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-n-sane-trilogy-playstation-4', 'Crash Bandicoot N. Sane Trilogy', 'Crash Bandicoot', '2017-06-30', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v62.jpg', 'Crash Bandicoot N. Sane Trilogy is a remastered version, of the original 3 games (Crash Bandicoot, Crash Bandicoot 2: Cortex Strikes Back, and Crash Bandicoot 3: Warped) with enhanced features applied to each game.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-racing-nitro-fueled-playstation-4', 'Crash Team Racing Nitro-Fueled', 'Crash Bandicoot', '2019-06-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2p89.jpg', 'This compilation contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-4-it-s-about-time-playstation-4', 'Crash Bandicoot 4: It''s About Time', 'Crash Bandicoot', '2020-10-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hp4.jpg', 'Crash Bandicoot 4: It''s About Time is the eighth Crash Bandicoot series game, though the fourth chronologically. The game retains the series'' core platforming gameplay and adds new elements through the use of the Quantum Masks, who can alter levels and provide means to traverse or overcome obstacles. It also includes additional game modes for replaying levels, and the ability to control five characters, three of whom – Cortex, Dingodile, and Tawna – have their own unique gameplay and levels.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-rumble-playstation-4', 'Crash Team Rumble', 'Crash Bandicoot', '2023-06-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lzv.jpg', 'Crash Team Rumble is a promotional tie-in game by McDonald''s made as a part of their Crash Team Rumble Happy Meal campaign.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crossing-souls-playstation-4', 'Crossing Souls', NULL, '2018-02-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45pi.jpg', 'A girl who is "one person in two bodies" challenging a mystery dungeon. Items that can be transmigrated to change their form as well as spirit weapons. The story of a soul that spans the ages. And... tasty bananas.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crypt-of-the-necrodancer-playstation-4', 'Crypt of the NecroDancer', 'Crypt of the NecroDancer', '2021-04-30', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co524p.jpg', 'Crypt of the NecroDancer: Synchrony is a massive new content pack for Crypt of the NecroDancer! It adds online multiplayer (co-op and vs), three new characters, full mod support (and built-in mod portal), new items, enemies, traps, and more!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-remastered-trilogy-playstation-4', 'Crysis Remastered Trilogy', 'Crysis', '2021-10-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wsr.jpg', 'The classic first person shooter from Crytek is back with the action-packed gameplay, sandbox world, and thrilling epic battles you loved the first time around – now with remastered graphics optimized for a new generation of hardware.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cuphead-playstation-4', 'Cuphead', NULL, '2020-07-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ao.jpg', 'Cuphead is a classic run and gun action game heavily focused on boss battles. Inspired by cartoons of the 1930s, the visuals and audio are painstakingly created with the same techniques of the era, i.e. traditional cel animation (hand drawn & hand inked!), watercolor backgrounds, and original jazz recordings. Play as Cuphead or Mugman (in single player or co-op) as you traverse strange worlds, acquire new weapons, learn powerful super moves, and discover hidden secrets. Cuphead is all action, all the time.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-scholar-of-the-first-sin-playstation-4', 'Dark Souls II: Scholar of the First Sin', 'Dark Souls', '2015-04-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb02.jpg', 'Dark Souls II: Scholar of the First Sin is an enhanced edition of Dark Souls II, released in April 2015 by FromSoftware and Bandai Namco Entertainment. This version includes updated graphics, improved performance, and all previously released DLC expansions (Crown of the Sunken King, Crown of the Old Iron King, and Crown of the Ivory King). It also features rebalanced gameplay, new enemy placements, additional NPCs, and expanded lore,', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-iii-playstation-4', 'Dark Souls III', 'Dark Souls', '2016-04-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9ed.jpg', 'Dark Souls III is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment. Released in March 2016, it is the fourth entry in the Souls series and the final instalment in the Dark Souls trilogy. Set in the decaying kingdom of Lothric, players take on the role of the "Ashen One," an undead warrior tasked with rekindling the First Flame to prevent the world from falling into darkness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-remastered-playstation-4', 'Dark Souls: Remastered', 'Dark Souls', '2018-05-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobazz.jpg', 'Dark Souls Remastered is a remastered version of the original game Dark Souls. The updated version of the game features graphical enhancements, an expanded online mode, and the Artorias of the Abyss DLC.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darkest-dungeon-ancestral-edition-playstation-4', 'Darkest Dungeon: Ancestral Edition', 'Darkest Dungeon', '2018-04-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28qk.jpg', 'The Ancestral Edition includes the Darkest Dungeon core game plus the following content packs: The Crimson Court, The Shieldbreaker and The Color of Madness.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-deathinitive-edition-playstation-4', 'Darksiders II: Deathinitive Edition', 'Darksiders', '2015-10-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qql.jpg', 'A remastered version of the 2012 release, Darksiders II.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-warmastered-edition-playstation-4', 'Darksiders: Warmastered Edition', 'Darksiders', '2016-11-22', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24hi.jpg', 'Deceived by the forces of evil into prematurely bringing about the end of the world, War – the first Horseman of the Apocalypse – stands accused of breaking the sacred law by inciting a war between Heaven and Hell. In the slaughter that ensued, the demonic forces defeated the heavenly hosts and laid claim to the Earth.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-iii-playstation-4', 'Darksiders III', 'Darksiders', '2018-11-27', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qqk.jpg', 'Return to an apocalyptic planet Earth in Darksiders III, a hack-n-slash action adventure where players take on the role of FURY in her quest to hunt down and dispose of the Seven Deadly Sins. The Charred Council calls upon Fury to battle from the heights of heaven down through the depths of hell in a quest to restore humanity and prove that she is the most powerful of the Horsemen. As a mage, FURY relies on her whip and magic to restore the balance between good and evil. The expansive, Darksiders III game world is presented as an open-ended, living, free-form planet Earth that is dilapidated by war and decay, and overrun by nature. FURY will move back and forth between environments to uncover secrets while advancing the Darksiders III story.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-genesis-playstation-4', 'Darksiders Genesis', 'Darksiders', '2020-02-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1f.jpg', 'In this Action RPG spin-off, the fourth Horseman of the Apocalypse Strife is called upon to save humankind from certain destruction at the hands of Lucifer. True to its roots, Darksiders Genesis will feature intense combat, exploration, puzzle-solving, epic boss battles and serpent holes from heaven to hell. The game marks the first, full-scale Darksiders adventure played from the top-down perspective.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('day-of-the-tentacle-remastered-playstation-4', 'Day of the Tentacle Remastered', 'Day of the Tentacle', '2016-03-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2865.jpg', 'Originally released by LucasArts in 1993 as a sequel to Ron Gilbert’s ground breaking Maniac Mansion, Day of the Tentacle is a mind-bending, time travel, cartoon puzzle adventure game in which three unlikely friends work together to prevent an evil mutated purple tentacle from taking over the world!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('days-gone-playstation-4', 'Days Gone', NULL, '2019-04-26', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94bn.jpg', 'Days Gone is an open-world action-adventure game developed by Bend Studio and published by Sony Interactive Entertainment. Released in April 2019 for PlayStation 4 and later for PC in May 2021, the game is set in a post-apocalyptic world where players control Deacon St. John, a drifter and bounty hunter navigating a landscape overrun by "Freakers," zombie-like creatures created by a global pandemic.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-gods-among-us-playstation-4', 'Injustice: Gods Among Us', 'DC', '2013-11-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8616.jpg', 'What if our greatest heroes became our greatest threat? Injustice: Gods Among Us introduces a bold new franchise to the fighting game genre from NetherRealm Studios, creators of the definitive fighting game Mortal Kombat. Featuring DC Comics icons such Batman, Cyborg, The Flash, Harley Quinn, Nightwing, Solomon Grundy, Superman and Wonder Woman, the latest title from the award-winning studio presents a deep original story. Heroes and villains will engage in epic battles on a massive scale in a world where the line between good and evil has been blurred.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wolf-among-us-playstation-4', 'The Wolf Among Us', 'DC', '2014-11-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vdk.jpg', 'The fifth episode of The Wolf Among Us, a five-episode series based on Fables (DC Comics/Vertigo).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-knight-playstation-4', 'Batman: Arkham Knight', 'DC', '2015-06-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fx3.jpg', 'This addon inlcudes a Batman costume inspired by the 2008 movie ‘The Dark Knight’.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-telltale-series-playstation-4', 'Batman: The Telltale Series', 'DC', '2016-08-02', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u65.jpg', 'Batman: The Telltale Series is an episodic graphic adventure game developed by Telltale Games, first released in 2016. The game offers a narrative-focused experience, where players control Bruce Wayne and his alter ego, Batman, making choices that shape the story and relationships with characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-vr-playstation-4', 'Batman: Arkham VR', 'DC', '2016-10-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22zo.jpg', 'Your quest to clean up Gotham has only just begun – and now it’s even more terrifying than it’s ever been. Exclusive to PlayStation VR, Batman: Arkham VR lets you become the Dark Knight in a virtual reality recreation of the DC’s hero’s more iconic locations.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-return-to-arkham-playstation-4', 'Batman: Return to Arkham', 'DC', '2016-10-18', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dhj.jpg', 'Batman: Return to Arkham sees the combination of two classic entries in the Batman: Arkham series make a return to modern consoles (PS4 and Xbox One) with improved graphics. Warner Bros. is remastering 2009’s Batman: Arkham Asylum and 2011’s Batman: Arkham City which will release in this collection package along with all of the associated DLC.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-2-playstation-4', 'Injustice 2', 'DC', '2017-05-16', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xym.jpg', 'Power up and build the ultimate version of your favorite DC legends in INJUSTICE 2. With a massive selection of DC Super Heroes and Super-Villains, INJUSTICE 2 allows you to equip every iconic character with unique and powerful gear earned throughout the game. Experience an unprecedented level of control over how your favorite characters look, how they fight, and how they develop across a huge variety of game modes. This is your super Hero. Your Journey. Your Injustice.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-enemy-within-playstation-4', 'Batman: The Enemy Within', 'DC', '2017-10-03', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co208l.jpg', 'In this latest chapter, both Bruce Wayne and Batman will be forced into precarious new roles. The Riddler has returned to terrorize Gotham City, but his gruesome puzzles merely foreshadow an even greater crisis. With the arrival of a ruthless federal agent and the return of a still nascent Joker, Batman must navigate uneasy alliances while Bruce Wayne undertakes a perilous series of deceptions. Which of Batman''s new allies will you choose to trust? And how deep into the darkness will you let Bruce descend?', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-cells-playstation-4', 'Dead Cells', 'Dead Cells', '2019-08-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3hi.jpg', 'A port of Dead Cells exclusive to Apple Arcade, with all the game’s main DLC expansions excluding the Everyone is Here! expansion.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-playstation-4', 'Dead Rising', 'Dead Rising', '2016-09-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzo.jpg', 'It’s the holiday season in Willamette, Colorado and a mysterious outbreak has overrun the Willamette Memorial Megaplex Mall and surrounding town with dangerous and deadly predators. Join Frank West as you explore a vast, open world sandbox filled with dangerous new zombies and a million ways to kill them as you seek to uncover the truth behind the outbreak – or die trying.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-playstation-4', 'Dead Rising 2', 'Dead Rising', '2016-09-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzw.jpg', 'As Chuck Greene, you have 72 hours to save your infected daughter, clear your name and survive the hordes of hungry zombies before the military comes in and nukes the city. To ensure your survival, you can combine everyday objects to create numerous deadly combo weapons and slaughter the ravenous zombies. Dead Rising 2, it’s where Creativity Kills.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-4-frank-s-big-package-playstation-4', 'Dead Rising 4: Frank''s Big Package', 'Dead Rising', '2017-12-05', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30i6.jpg', 'Just in time for the holidays, Dead Rising 4: Frank’s Big Package is a special delivery that will let players unwrap the Dead Rising 4 main game, in addition to all other previously released game content. The new bundle will also introduce a game mode called “Capcom Heroes,” an all-new way to experience the Dead Rising 4 story that lets Frank West wear over a dozen outfits and perform outrageous special attacks inspired by classic Capcom characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dear-esther-landmark-edition-playstation-4', 'Dear Esther Landmark Edition', NULL, '2016-09-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24vl.jpg', 'Dear Esther: Landmark Edition has been remade with the Unity engine, featuring a full audio remaster, and the addition of a brand-new Directors'' Commentary mode, allowing players to explore the island and learn what inspired the game and how it was crafted by The Chinese Room and Rob Briscoe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('death-stranding-playstation-4', 'Death Stranding', 'Death Stranding', '2019-11-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobksf.jpg', 'Death Stranding is an action game set in a post-apocalyptic United States.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-playstation-4', 'Destiny', 'Destiny', '2014-09-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-2-playstation-4', 'Destiny 2', 'Destiny', '2017-09-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('detroit-become-human-playstation-4', 'Detroit: Become Human', NULL, '2018-05-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6mzf.jpg', 'Detroit: Become Human is an interactive narrative adventure game developed by Quantic Dream and released in 2018. Set in a near-future Detroit where androids serve humans, the story follows three android protagonists—Kara, Connor, and Markus—who shape the city’s fate through their choices. Gameplay combines exploration, dialogue interactions, and quick-time events, with branching storylines and multiple endings. The narrative explores themes of artificial intelligence, freedom, and morality.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-mankind-divided-playstation-4', 'Deus Ex: Mankind Divided', 'Deus Ex', '2016-08-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25jt.jpg', 'Deus Ex: Mankind Divided directly follows the aftermath of the Aug Incident, a day when mechanically augmented citizens all over the world were stripped of control over their minds and bodies, resulting in the deaths of millions of innocents. The year is now 2029, and the golden era of augmentations is over. Mechanically augmented humans have been deemed outcasts and segregated from the rest of society. Crime and acts of terror serve as a thin veil to cover up an overarching conspiracy aimed at controlling the future of mankind…', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dmc-definitive-edition-playstation-4', 'DmC: Definitive Edition', 'Devil May Cry', '2015-03-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u6x.jpg', 'DmC: Devil May Cry - Definitive Edition includes all the stylish action gameplay from the original release, all previously released downloadable content, including the Vergil''s Downfall campaign plus brand new modes and additional content, making this the ultimate offering for Devil May Cry fans. Maximizing the potential of next-gen hardware, the game''s high quality production values will run at a stunning 1080p and smooth 60 fps across PlayStation 4 and Xbox One.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-hd-collection-playstation-4', 'Devil May Cry HD Collection', 'Devil May Cry', '2018-03-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n18.jpg', 'Devil May Cry HD Collection is a collection of high-definition remasters of the PS2 games of the first three games in the Devil May Cry franchise. In addition to the reworked graphics, it also contains trophies/achievements.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-5-playstation-4', 'Devil May Cry 5', 'Devil May Cry', '2019-03-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawk9.jpg', 'The ultimate Devil Hunter is back in style, in the game action fans have been waiting for. Includes Playable Character: Vergil content (also available separately).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-ultimate-evil-edition-playstation-4', 'Diablo III: Ultimate Evil Edition', 'Diablo', '2014-08-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3irp.jpg', 'Diablo III: Ultimate Evil Edition includes the expansion pack Reaper of Souls and features special four-player co-op features. With the wireless controller and a custom-designed console interface, players will be outfitted with touch pad functionality and new social features as they engage in pulse-pounding combat with hordes of monsters and acquire items of incredible power.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-eternal-collection-playstation-4', 'Diablo III: Eternal Collection', 'Diablo', '2018-06-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dha.jpg', 'Generations of gamers have battled the demonic hordes of Diablo, and now it’s your turn to take part in the action-RPG legacy. This Eternal Collection features Diablo III, the Reaper of Souls expansion set and the Rise of the Necromancer pack—all together in one definitive volume. Prepare yourself, mortal hero. The hellgates are opening.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disco-elysium-the-final-cut-playstation-4', 'Disco Elysium: The Final Cut', 'Disco Elysium', '2021-12-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ve1.jpg', 'Disco Elysium: The Final Cut is an enhanced edition of the original role-playing game developed and published by ZA/UM. It retains the core gameplay and narrative while adding full voice acting, new quests, additional endings, and other narrative revisions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-definitive-edition-playstation-4', 'Dishonored: Definitive Edition', 'Dishonored', '2015-08-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pcv.jpg', 'Arkane Studios’ 2012 Game of the Year, Dishonored, and all of its additional content - Dunwall City Trials, The Knife of Dunwall, The Brigmore Witches and Void Walker’s Arsenal – comes to PlayStation 4 and Xbox One in Dishonored: Definitive Edition! Experience Dishonored plus all of its additional content on the new console systems for the first time, complete with enhanced graphics that take full advantage of the powerful hardware of this generation.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-2-playstation-4', 'Dishonored 2', 'Dishonored', '2016-11-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9e29.jpg', 'Dishonored 2 is a first-person action video game and the sequel to Dishonored. It borrows many of the gameplay elements from the first opus: players define their own play style by blending action, assassination, stealth, mobility and combat. Combining tools at their disposal, players are allowed options to eliminate enemies, whether they choose to pursue them unseen or ruthlessly attack head on. Dishonored 2 features the same campaign style as its predecessor in which the protagonist must advance through a series of missions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-death-of-the-outsider-playstation-4', 'Dishonored: Death of the Outsider', 'Dishonored', '2017-09-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pd2.jpg', 'Dishonored: Death of the Outsider is a standalone expansion pack and a sequel to Dishonored 2. The game features all the series hallmarks, including brutal combat systems, unique level design and immersive storytelling that responds to your every choice. With compelling characters and exhilarating action, Death of the Outsider is the perfect entry point for those new to the Dishonored series, while delivering a significant expansion of the gameplay and world for longtime fans.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-playstation-4', 'Disney Infinity 2.0', 'Disney Infinity', '2014-09-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-3-0-playstation-4', 'Disney Infinity 3.0', 'Disney Infinity', '2015-08-30', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doki-doki-literature-club-plus-playstation-4', 'Doki Doki Literature Club Plus!', 'Doki Doki Literature Club', '2021-06-30', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawpa.jpg', 'Welcome to the club! Write poems for your crush and experience the terror of school romance in this critically-acclaimed psychological horror story.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('donut-county-playstation-4', 'Donut County', NULL, '2018-08-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qv8.jpg', 'Donut County is a story-based physics puzzle game where you play as an ever-growing hole in the ground. Meet cute characters, steal their trash, and throw them in a hole.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-playstation-4', 'Doom', 'Doom', '2016-05-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-vfr-playstation-4', 'Doom VFR', 'Doom', '2017-12-01', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xev.jpg', 'Taking place after the events of Doom, you take control of scientist who was killed during the initial demon invasion of Mars.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-the-classics-collection-playstation-4', 'Doom: The Classics Collection', 'Doom', '2019-07-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xvn.jpg', 'This includes three classic Doom games preserved on one disc - Doom, Doom II, and Doom 3! No game downloads required.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-64-playstation-4', 'Doom 64', 'Doom', '2020-03-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qmz.jpg', 'Fight against demons in your crusade to hunt down the Mother of Demons and stop Hell''s invasion. As the player battle through more than 30 action-packed levels, they have to be on the lookout for enhanced weapons and secrets to help them put an end to the demonic threat.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-eternal-playstation-4', 'Doom Eternal', 'Doom', '2020-03-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5n.jpg', 'Hell’s armies have invaded Earth. Become the Slayer in an epic single-player campaign to conquer demons across dimensions and stop the final destruction of humanity. The only thing they fear... is you.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-slayers-collection-playstation-4', 'Doom: Slayers Collection', 'Doom', '2020-08-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kdb.jpg', 'The Doom Slayers Collection takes players through more than two decades of demon slaying – from the classic games that popularized the first-person shooter to the fan favorite franchise reboot, wield an arsenal of powerful weapons as you battle demon hordes on Mars, on Earth, and across Hell in four critically acclaimed games: Doom, Doom II, Doom 3, and Doom (2016).', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3-vr-edition-playstation-4', 'DOOM 3: VR Edition', 'Doom', '2021-03-29', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('downwell-playstation-4', 'Downwell', NULL, '2016-05-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co284e.jpg', 'Downwell is a curious game about a young man with guns for boots venturing down a well in search of untold treasures. Make your way further and further down into a darkness filled with nasty creatures and mysterious secrets and collect the spectacular red gems scattered about the rocks. Step into an oddly placed shop to buy some helpful items or level up between caverns to battle well dwelling monsters and uncover hidden caves filled with riches and relics. No two trips down the well are ever the same!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-inquisition-playstation-4', 'Dragon Age: Inquisition', 'Dragon Age', '2014-11-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvy.jpg', 'Dragon Age: Inquisition is a role-playing game and the third main game in the Dragon Age series. It is set in the Thedas continent, the same fantasy world as the two previous games. It consist of two large countries: Ferelden (from Dragon Age: Origins) and Orlais, as well as the land inbetween.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-heroes-the-world-tree-s-woe-and-the-blight-below-playstation-4', 'Dragon Quest Heroes: The World Tree''s Woe and the Blight Below', 'Dragon Quest', '2015-10-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u5j.jpg', 'In Dragon Quest Heroes, the protagonists must rise up against insurmountable odds, challenging swarms of enemies and conquering gigantic monsters in an exhilarating action game. Filled with characters and monsters designed by world-renowned artist Akira Toriyama.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-builders-playstation-4', 'Dragon Quest Builders', 'Dragon Quest', '2016-10-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9mq.jpg', '"Dragon Quest Builders is a sandbox action RPG where your imagination is the limit! Everything plays out in real time and the world is made entirely of blocks (although it may not look that blocky) and you can use these blocks to build pretty much whatever you want. Building is easy and can be done in three steps:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-heroes-ii-playstation-4', 'Dragon Quest Heroes II', 'Dragon Quest', '2017-04-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u5h.jpg', '"DRAGON QUEST HEROES II is a hack-and-slash, field-roaming Action RPG that sends players on a new adventure to restore order in a once peaceful world filled with hordes of monsters and battles of epic proportions. Up to 4 players can band together in cooperative multiplayer to conquer swarms of enemies and defeat challenging boss monsters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-xi-echoes-of-an-elusive-age-playstation-4', 'Dragon Quest XI: Echoes of an Elusive Age', 'Dragon Quest', '2018-09-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x9d.jpg', 'Dragon Quest XI continues the gameplay of previous games in the series, in which players explore worlds and fight against various monsters, including the ability to explore high areas. Before entering battle, players can also toggle between the 3D and 2D graphical styles. The game features the series'' traditional turn-based battle system.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-builders-2-playstation-4', 'Dragon Quest Builders 2', 'Dragon Quest', '2019-07-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9ms.jpg', 'Dragon Quest Builders 2 is a block-building role-playing game with a charming campaign and a robust multiplayer building mode that supports up to four players online. Create your customized character, team-up with your fearless friend Malroth, gather the skills required to become a full-fledged builder, and combat the Children of Hargon, a vile cult that worships destruction! Then, take your builder online and join your friends to collaborate and create something truly magnificent. Don’t let the name fool you, despite the 2, this is a completely standalone experience featuring new characters, an expansive world, unlimited building combinations, and a storyline that’s sure to satisfy longtime fans and newcomers alike!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-xi-s-echoes-of-an-elusive-age-definitive-edition-playstation-4', 'Dragon Quest XI S: Echoes of an Elusive Age - Definitive Edition', 'Dragon Quest', '2020-12-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x9f.jpg', 'The Definitive Edition includes all the content from the original release of the acclaimed DRAGON QUEST XI, and adds extra character-specific scenarios, the choice of playing with the original soundtrack or a grand orchestral version of the music, the ability to switch between 2D and 3D graphic modes, a Japanese voice-acting option, and much more.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-trilogy-playstation-4', 'Dragon''s Lair Trilogy', 'Dragon''s Lair', '2017-12-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co249y.jpg', 'Dragon''s Lair Trilogy (includes Dragon''s Lair, Dragon''s Lair II: Time Warp, and Space Ace.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dreams-playstation-4', 'Dreams', NULL, '2020-02-14', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co528y.jpg', 'A fake dating sim version of the Yume Nikki fighting fangame Dream vs. Dream released on April Fools Day 2014.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('duck-game-playstation-4', 'Duck Game', NULL, '2017-08-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9t4w.jpg', 'Join the ducks on their cute journey for world domination.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('eagle-flight-playstation-4', 'Eagle Flight', NULL, '2016-11-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4gv4.jpg', '50 years after humans vanished from the face of the Earth, nature reclaimed the city of Paris, leaving a breathtaking playground. As an eagle, you soar past iconic landmarks, dive through narrow streets, and engage in heart-pounding aerial dog fights to protect your territory from opponents.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('elden-ring-playstation-4', 'Elden Ring', NULL, '2022-02-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95gk.jpg', 'Elden Ring: Nightreign is a standalone adventure within the ELDEN RING universe, crafted to offer players a new gaming experience by reimagining the game’s core design.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-online-tamriel-unlimited-playstation-4', 'The Elder Scrolls Online: Tamriel Unlimited', 'The Elder Scrolls', '2015-06-09', 'PlayStation 4', 0, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-online-gold-edition-playstation-4', 'The Elder Scrolls Online: Gold Edition', 'The Elder Scrolls', '2016-09-09', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fm8.jpg', 'The award-winning fantasy role-playing series, The Elder Scrolls, goes online. Experience the world of Tamriel on your own, or together with friends, guild mates, and thousands of other players.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-special-edition-playstation-4', 'The Elder Scrolls V: Skyrim – Special Edition', 'The Elder Scrolls', '2016-10-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vco.jpg', 'Skyrim special edition is a remaster of the classic from 2011. Now with upgraded visuals.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-vr-playstation-4', 'The Elder Scrolls V: Skyrim VR', 'The Elder Scrolls', '2017-11-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tci.jpg', 'A true, full-length open-world game for VR has arrived. Skyrim VR reimagines the complete epic fantasy masterpiece with an unparalleled sense of scale, depth, and immersion. From battling ancient dragons to exploring rugged mountains and more, Skyrim VR brings to life a complete open world for you to experience any way you choose. Skyrim VR includes the critically-acclaimed core game and official add-ons – Dawnguard, Hearthfire, and Dragonborn.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-end-is-nigh-playstation-4', 'The End Is Nigh', NULL, '2019-04-30', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n38.jpg', 'The End Is Nigh is a sprawling adventure platformer where the player takes control of Ash, one of few ''things'' that have ''survived'' the "end of the world."
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ender-lilies-quietus-of-the-knights-playstation-4', 'Ender Lilies: Quietus of the Knights', 'Ender', '2021-07-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9s9e.jpg', 'Ender Lilies is a dark fantasy 2D Action RPG about unraveling the mysteries of a nation destroyed by a cataclysmic event. The fallen Kingdom of End is a tragic and beautiful world featuring a majestic castle, submerged forests and forbidden underground areas.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enter-the-gungeon-playstation-4', 'Enter the Gungeon', NULL, '2016-04-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobl6c.jpg', 'Enter the Gungeon is a gunfight dungeon crawler following a band of regretful misfits seeking to shoot, loot, dodge roll and table-flip their way to personal absolution by reaching the legendary Gungeon’s ultimate treasure: the gun that can kill the past. Select a hero and battle your way to the bot¬tom of the Gungeon by surviving a challenging and evolving series of floors filled with the dangerously adorable Gundead and fearsome Gungeon bosses armed to the teeth. Gather precious loot, discover hidden secrets, and chat with opportunistic merchants and shopkeepers to purchase powerful items to gain an edge.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('etherborn-playstation-4', 'Etherborn', NULL, '2019-07-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jaf.jpg', 'Etherborn is an environmental puzzle platformer built on exploring and understanding gravity-shifting structures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-playstation-4', 'The Evil Within', 'The Evil Within', '2014-10-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgs.jpg', 'The Evil Within embodies the meaning of pure survival horror. Highly-crafted environments, horrifying anxiety, and an intricate story are combined to create an immersive world that will bring you to the height of tension. With limited resources at your disposal, you’ll fight for survival and experience profound fear in this perfect blend of horror and action.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-2-playstation-4', 'The Evil Within 2', 'The Evil Within', '2017-10-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgu.jpg', 'The Evil Within 2 is the latest evolution of survival horror. Detective Sebastian Castellanos has lost it all. But when given a chance to save his daughter, he must descend once more into the nightmarish world of STEM.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-4-playstation-4', 'Fallout 4', 'Fallout', '2015-11-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yc6.jpg', 'Bethesda Game Studios welcome you to the world of Fallout 4, their most ambitious game ever, and the next generation of open-world gaming. As the sole survivor of Vault 111, you enter a world destroyed by nuclear war. Every second is a fight for survival, and every choice is yours. Only you can rebuild and determine the fate of the Wasteland. Welcome home.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-4-playstation-4', 'Far Cry 4', 'Far Cry', '2014-11-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ke6.jpg', 'Dive into the savage universe of Far Cry with this double-pack edition featuring both Far Cry 4 and Far Cry: Primal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-primal-playstation-4', 'Far Cry Primal', 'Far Cry', '2016-02-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28ha.jpg', 'Gamers play as TAKKAR, a seasoned hunter and the last surviving member of his hunting group. Arriving in the majestic and savage land of Oros, players will pursue one single goal; survive in a world where humans are the prey. They will meet a cast of memorable characters who will help them push back and tame the dangers of the wild.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-5-playstation-4', 'Far Cry 5', 'Far Cry', '2018-03-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qsa.jpg', 'It''s time to defend Hope County with this bundle featuring both Far Cry 5 and Far Cry New Dawn
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-classic-edition-playstation-4', 'Far Cry 3 Classic Edition', 'Far Cry', '2018-06-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nkb.jpg', 'Far Cry 3 Classic Edition has been updated to run smoothly on modern platforms and allow fans and newcomers to experience the single-player Far Cry 3 campaign in stunning detail.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-new-dawn-playstation-4', 'Far Cry New Dawn', 'Far Cry', '2019-02-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpg.jpg', 'Dive into a transformed vibrant post-apocalyptic Hope County, Montana, 17 years after a global nuclear catastrophe. Lead the fight against the Highwaymen, as they seek to take over the last remaining resources.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-6-playstation-4', 'Far Cry 6', 'Far Cry', '2021-10-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2npg.jpg', 'Dive into the gritty world of a modern-day guerrilla revolution to liberate a nation from its oppressive dictators. Welcome to Yara, a tropical paradise frozen in time. Far Cry 6 thrusts players into a modern-day guerrilla revolution. As dictator of Yara, Anton Castillo is intent on restoring his nation back to its former glory by any means, with his son, Diego, following in his bloody footsteps. Become a guerrilla fighter and liberate Yara.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-blood-dragon-playstation-4', 'Far Cry 3: Blood Dragon', 'Far Cry', '2021-12-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpp.jpg', 'There’s only one force powerful enough to stop an army of rampaging killer cyborgs, mutated scientists, metal sharks and vicious Blood Dragons that shoot lasers from their eyes – that force is you. Your name is Sergeant Rex Power Colt, a Mark IV Cyber Commando. Lock and load as you and your seven favorite fully customizable killing implements tackle a bizarre open world island crawling with evil. Take down the enemy with ninja stars, guns or even just good old explosives. Your battle. Your way. Their tough luck.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('farpoint-playstation-4', 'Farpoint', NULL, '2017-05-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co237p.jpg', 'Farpoint is an unnerving VR space adventure set on a hostile alien planet. On a mission to pick up scientists studying an anomaly near Jupiter, a rupture from the anomaly transports the player and scientists to an unknown alien world.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiv-playstation-4', 'Final Fantasy XIV', 'Final Fantasy', '2014-04-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobl9m.jpg', 'Take part in an epic and ever-changing Final Fantasy as you adventure and explore with friends from around the world. Final Fantasy XIV Online is the 2013 relaunch of the massively multiplayer online role-playing game that takes the wonder of the FF legacy and expands it, allowing you to explore the realm of Eorzea like never before in a Final Fantasy game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-type-0-hd-playstation-4', 'Final Fantasy Type-0 HD', 'Final Fantasy', '2015-03-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9er5.jpg', 'Final Fantasy Type-0 HD is a high-definition remaster of the Japan-exclusive PlayStation Portable game Final Fantasy Type-0.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-x-2-hd-remaster-playstation-4', 'Final Fantasy X/X-2 HD Remaster', 'Final Fantasy', '2015-05-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zpl.jpg', 'Based on the international versions of the games that were previously only released in Japan and Europe, FINAL FANTASY X/X-2 HD Remaster brings these timeless classics forward to the current generation of fans, old and new alike.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-of-final-fantasy-playstation-4', 'World of Final Fantasy', 'Final Fantasy', '2016-10-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24k0.jpg', 'World of Final Fantasy combines classic RPG gameplay mechanics with fresh and imaginative toy-like visuals. As a brand-new title in the Final Fantasy franchise, this game can be enjoyed by both fans and newcomers to the series. Players will lead a pair of twins through varied Final Fantasy worlds and encounter the adorably familiar monsters therein. Capture and raise such familiar beasts as cactuar, chocobo, and behemoth to discover alternate forms and learn new abilities.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xv-playstation-4', 'Final Fantasy XV', 'Final Fantasy', '2016-11-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nz1.jpg', 'Play as Noctis, the Crown Prince of the Kingdom of Lucis, as you seek to reclaim your homeland from the imperial army. With your closest friends along for the ride, you’ll travel through the breath-taking world of Eos, encountering larger-than-life beasts and unforgiving enemies. Face thrilling combat as you learn to master your weaponry and magic skills by channeling the power of your ancestors.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xii-the-zodiac-age-playstation-4', 'Final Fantasy XII: The Zodiac Age', 'Final Fantasy', '2017-07-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g6o.jpg', '"FINAL FANTASY XII THE ZODIAC AGE improves upon the 2006 classic FINAL FANTASY XII, now more beautiful and easier to play than ever. The high-definition remaster introduces several modern advancements, including reconstructed battle design and a revamped job system. With newly implemented trophies and share functions, as well as stark visual and sound improvements in true HD for the first time, players both returning and new to the game will experience a grand adventure that spans the world of Ivalice in an entirely fresh and improved way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dissidia-final-fantasy-nt-playstation-4', 'Dissidia Final Fantasy NT', 'Final Fantasy', '2018-01-30', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jpy.jpg', 'Dissidia Final Fantasy NT: Free Edition is packed with iconic stages and music from the entire Final Fantasy series, a cast of over 25 beloved characters with unique fighting styles and abilities, legendary summons that wreak destruction on the arena and much more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-vii-remake-playstation-4', 'Final Fantasy VII Remake', 'Final Fantasy', '2020-04-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcwt.jpg', 'A modern reimagining of one of the most iconic games of all time, Final Fantasy VII Remake harnesses the very latest technology to recreate and expand Square Enix''s legendary RPG adventure for the current generation. Set in a post-industrial fantasy world that has fallen under the control of the shadowy Shinra Electric Power Company, take on the role of Cloud Strife - a mercenary and former member of Shinra''s elite Soldier unit - and team up with anti-Shinra organization Avalanche as they step-up their resistance.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-i-vi-collection-playstation-4', 'Final Fantasy I-VI Collection', 'Final Fantasy', '2024-10-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nzk.jpg', 'The Final Fantasy: Pixel Remaster series will comprise FINAL FANTASY I through FINAL FANTASY VI, with each game releasing individually. For long-term fans that will be hugely exciting news - a chance to revisit some of their most beloved RPGs of all time in a way that perfectly captures the spirit of those original game.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('firewatch-playstation-4', 'Firewatch', NULL, '2016-02-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1ts.jpg', 'Firewatch is a single-player first-person video game where you, as a man named Henry, explore the Wyoming wilderness after taking a summer job as a fire lookout. What is supposed to be a peaceful respite from your complicated life takes a turn when you start to question some of the things that are happening to you.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('five-nights-at-freddy-s-help-wanted-playstation-4', 'Five Nights at Freddy''s: Help Wanted', 'Five Nights at Freddy''s', '2019-05-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6975.jpg', 'This is the mobile version of Five Nights at Freddy’s: Help Wanted, a collection of classic and original mini-games set in the Five Nights universe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('five-nights-at-freddy-s-core-collection-playstation-4', 'Five Nights at Freddy''s: Core Collection', 'Five Nights at Freddy''s', '2021-01-12', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldz.jpg', 'Five Nights at Freddy''s: Core Collection is a physical bundle of several games in the Five Nights at Freddy''s franchise. The collection will consist of the Console Ports of Five Nights at Freddy''s 1 to 4 and Sister Location.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('freedom-planet-playstation-4', 'Freedom Planet', 'Freedom Planet', '2017-03-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qr7.jpg', 'Freedom Planet is a combat-based platform adventure that pits a spunky dragon girl and her friends against an alien attack force. There''s trouble around every turn, from insects to giant robots to sheer explosive destruction, but you''ll have a variety of special fighting abilities to blast your way through each stage.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-of-tsushima-playstation-4', 'Ghost of Tsushima', 'Ghost of Tsushima', '2020-07-17', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2crj.jpg', 'Uncover the hidden wonders of Tsushima in this open-world action adventure. Forge a new path and wage an unconventional war for the freedom of Tsushima. Challenge opponents with your katana, master the bow to eliminate distant threats, develop stealth tactics to ambush enemies in order to win over the mongols.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-of-tsushima-director-s-cut-playstation-4', 'Ghost of Tsushima Director''s Cut', 'Ghost of Tsushima', '2021-08-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5f.jpg', 'Ghost of Tsushima: Director''s Cut Includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('giana-sisters-twisted-dreams-director-s-cut-playstation-4', 'Giana Sisters: Twisted Dreams Director''s Cut', 'Giana Sisters', '2014-12-09', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rj3.jpg', 'Giana Sisters: Twisted Dreams is a platform game developed by Black Forest Games for Microsoft Windows. It is the successor to the 1987 Commodore 64 title The Great Giana Sisters and sequel to the 2009 re-imagining Giana Sisters DS. The game was funded through crowdfunding website Kickstarter, reaching its goal of $150,000.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-iii-remastered-playstation-4', 'God of War III Remastered', 'God of War', '2015-07-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3koh.jpg', 'Set in the realm of brutal Greek mythology, God of War III Remastered is the critically acclaimed single-player game that allows players to take on the fearless role of the ex-Spartan warrior, Kratos, as he rises from the darkest depths of Hades to scale the very heights of Mount Olympus to seek his bloody revenge. Armed with double-chained blades and an array of new weapons and magic, Kratos must take on mythology’s deadliest creatures while solving intricate puzzles throughout his merciless quest to destroy Olympus.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-playstation-4', 'God of War', 'God of War', '2018-04-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobkt6.jpg', 'God of War is the sequel to God of War III as well as a continuation of the canon God of War chronology. Unlike previous installments, this game focuses on Norse mythology and follows an older and more seasoned Kratos and his son Atreus in the years since the third game. It is in this harsh, unforgiving world that he must fight to survive… and teach his son to do the same.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-ragnar-k-playstation-4', 'God of War Ragnarök', 'God of War', '2022-11-09', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92vm.jpg', 'Start your journey in Midgard as either a fledgling Swordsman, an apprentice Mage, or a rookie Acolyte as you explore a fantasy world with thousands of other players. Level up your character and upgrade your skills through quests or by defeating monsters ranging from the cute to the menacing using the wide variety of skills at your disposal. Test your might and compete with other players in the PvP arena. Group up with other players to finish quests, gain levels, defeat powerful bosses and complete difficult dungeons.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gorogoa-playstation-4', 'Gorogoa', NULL, '2018-05-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kby.jpg', 'Gorogoa is a beautiful hand-drawn story suspended inside a completely unique puzzle. Arrange and combine lavishly illustrated panels, each one a separate interactive window into a living game world.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-playstation-4', 'Grand Theft Auto V', 'Grand Theft Auto', '2014-11-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-the-trilogy-playstation-4', 'Grand Theft Auto: The Trilogy', 'Grand Theft Auto', '2021-12-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ms5.jpg', 'A bundle that contains the original trilogy from one of the most popular and critically acclaimed franchises in entertainment history.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gravity-rush-remastered-playstation-4', 'Gravity Rush Remastered', 'Gravity Rush', '2016-02-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8583.jpg', 'Gravity Rush is an action-adventure video game developed by SIE Japan Studio and Project Siren, and published by Sony Computer Entertainment. Gravity Rush Remastered is the PS4 remaster of the original Gravity Rush game which is bundled with all the previously released downloadable content.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gravity-rush-2-playstation-4', 'Gravity Rush 2', 'Gravity Rush', '2017-01-20', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaxyt.jpg', 'Another mind-bending adventure awaits gravity queen Kat as a new danger emerges to threaten the fabric of the universe itself. Still searching for clues behind the mystery of her origin, and with the powerful Raven at her side, Kat must master three unique gravity attack styles as she takes on enemies and massive bosses.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grim-fandango-remastered-playstation-4', 'Grim Fandango Remastered', 'Grim Fandango', '2015-01-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27pj.jpg', 'Something''s rotten in the land of the dead, and you''re being played for a sucker. Meet Manny Calavera, travel agent at the Department of Death. He sells luxury packages to souls on their four-year journey to eternal rest. But there''s trouble in paradise. Help Manny untangle himself from a conspiracy that threatens his very salvation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gris-playstation-4', 'Gris', NULL, '2019-11-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qv5.jpg', 'Gris is a 2D platformer developed by Nomada Studio and published by Devolver Digital. It is a visually striking game that follows the journey of a young woman named Gris as she navigates a world of grief and loss. The game features no dialogue, relying on its hand-painted art style, evocative music, and environmental storytelling to convey its themes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guacamelee-super-turbo-championship-edition-playstation-4', 'Guacamelee! Super Turbo Championship Edition', 'Guacamelee!', '2014-07-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob233.jpg', 'Guacamelee! STCE is an enhanced version of Guacamelee! Gold Edition that adds in two huge new levels, an explosive new ‘Intenso’ power mode, 4-player local co-op support and more. You’ll need to use every bit of your skill and power to defeat STCE’s new challenges (including a scheming new boss- El Trio de la Muerte), in addition to everything the original game''s sprawling world has to throw at you.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guacamelee-one-two-punch-collection-playstation-4', 'Guacamelee! One-Two Punch Collection', 'Guacamelee!', '2019-02-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6031.jpg', 'Guacamelee! One-Two Punch Collection includes both Guacamelee! Super Turbo Championship Edition and Guacamelee! 2, an exclusive two-sided poster, a complete instruction manual, and download codes for two soundtracks.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hades-playstation-4', 'Hades', NULL, '2021-08-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4rs3.jpg', 'A South Korean-made first person shooter (potentially the first ever from that country).', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-light-of-hope-playstation-4', 'Harvest Moon: Light of Hope', 'Harvest Moon', '2018-05-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xlb.jpg', 'The third Harvest Moon game created by Natsume without the original developers of the series.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-mad-dash-playstation-4', 'Harvest Moon: Mad Dash', 'Harvest Moon', '2019-10-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gk7.jpg', 'Go solo or take a few friends along for the frenzy! Harvest, fish, milk, and more as you fullfil orders to complete each level! Things may start out easy, but you''ll hit the beach, the farm, and even the Underworld as you progress through the game! Have you ever tried to grow crops with molten lava falling on them?! That and other obstacles await you as you and your friends try to clear all the levels to restore the broken lighthouse!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('harvest-moon-one-world-playstation-4', 'Harvest Moon: One World', 'Harvest Moon', '2021-03-02', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xl3.jpg', 'Explore a world of new and familiar faces, unique villages and adventurous challenges, while managing your growing farm.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('haven-playstation-4', 'Haven', NULL, '2021-02-04', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co542m.jpg', 'A sandbox game set in an Iron Age world loosely inspired by Slavic and Germanic myth and legend.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('headlander-playstation-4', 'Headlander', NULL, '2016-07-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/uyhtdsepz3tsqi9j55m5.jpg', 'Launch into the ultimate head trip as you blast through psychotic robots in a retro 70''s sci-fi action adventure from Double Fine Productions. It is a world of automation, a utopia gone wrong in which all of humanity have transferred their minds into robotic imposter bodies and are ruled by a computer.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('heaven-s-vault-playstation-4', 'Heaven''s Vault', NULL, '2019-04-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2t94.jpg', 'Explore the lost ruins of the Nebula, read ancient inscriptions, and uncover a forgotten past in this narrative archaeological science-fiction adventure game from the creators of 80 Days.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-heavy-rain-beyond-two-souls-collection-playstation-4', 'The Heavy Rain & Beyond: Two Souls Collection', NULL, '2016-02-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mq1.jpg', 'This bundle contains two games from game development studio Quantic Dreams and designer David Cage: Heavy Rain and Beyond: Two Souls.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hellblade-senua-s-sacrifice-playstation-4', 'Hellblade: Senua''s Sacrifice', 'Hellblade', '2018-12-04', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l7l.jpg', 'From the makers of Heavenly Sword, Enslaved: Odyssey to the West, and DmC: Devil May Cry, comes a warrior’s brutal journey into myth and madness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hollow-knight-playstation-4', 'Hollow Knight', NULL, '2018-09-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaes9.jpg', 'Unofficial port of the hit game Hollow Knight for PlayStation Vita.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('home-playstation-4', 'Home', NULL, '2014-10-28', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ed9.jpg', 'Help Hazel redesign client homes in this fun Hidden Objects game, "Home Designer: Home Sweet Home".', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('horizon-zero-dawn-playstation-4', 'Horizon Zero Dawn', 'Horizon', '2017-02-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2una.jpg', 'Welcome to a vibrant world rich with the beauty of nature – but inhabited by awe-inspiring, highly advanced machines. As a young machine hunter named Aloy, you must unravel the mysteries of this world and find your own destiny.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('horizon-zero-dawn-complete-edition-playstation-4', 'Horizon Zero Dawn: Complete Edition', 'Horizon', '2017-12-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tem.jpg', 'In an era where machines roam the land and mankind is no longer the dominant species, a young hunter named Aloy embarks on a journey to discover her destiny. Explore a vibrant and lush world inhabited by mysterious mechanized creatures. Embark on a compelling, emotional journey and unravel mysteries of tribal societies, ancient artefacts and enhanced technologies that will determine the fate of this planet and of life itself.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('horizon-forbidden-west-playstation-4', 'Horizon Forbidden West', 'Horizon', '2022-02-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gvu.jpg', 'Horizon Forbidden West continues Aloy’s story as she moves west to a far-future America to brave a majestic, but dangerous frontier where she’ll face awe-inspiring machines and mysterious new threats.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hotline-miami-playstation-4', 'Hotline Miami', 'Hotline Miami', '2014-08-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vqp.jpg', 'A top-down slasher/shooter with unlockable gameplay-altering masks and weapons, featuring a neon-flavoured electronic aesthetic, in which a hitman receives anonymous calls ordering him to travel to certain residences and crime dens and massacre those within, as he stumbles through unreal visions and inconsistencies without any answers to how, why or who.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hotline-miami-2-wrong-number-playstation-4', 'Hotline Miami 2: Wrong Number', 'Hotline Miami', '2015-03-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wf6.jpg', 'Hotline Miami 2: Wrong Number is the brutal conclusion to the Hotline Miami saga, set against a backdrop of escalating violence and retribution over spilled blood in the original game. Follow the paths of several distinct factions – each with their own questionable methods and uncertain motivations – as unforeseen consequences intersect and reality once again slips back into a brilliant haze of neon and bloodshed.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hue-playstation-4', 'Hue', NULL, '2016-08-30', 'PlayStation 4', 1, 0, NULL, NULL, 'Hue² is a puzzle game, which brings calmness, peace, and a sense of harmony. You need to place the colored cubes in a harmonious way in the gradient. The locked cubes are not moveable and they will be your guide. It seems that it is a piece of cake, right? Well, the beginning levels are really easy to pass, but on the other hand, when the number of locked cubes and the number of colorful cubes increase, the game becomes more interesting and challenging. 377 levels will challenge your logic and sense of color.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hyper-light-drifter-playstation-4', 'Hyper Light Drifter', 'Hyper Light', '2016-07-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4dwx.jpg', 'The wait is over, the worldwide acclaimed game Hyper Light Drifter is finally here with this impressive Special Edition!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iconoclasts-playstation-4', 'Iconoclasts', NULL, '2018-01-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ug9.jpg', 'Join renegade mechanic Robin and uncover the secrets of a dying planet. Explore a huge, open world filled with intricate puzzles, oddball characters and menacing bosses in a beautiful platform adventure telling a personal story about faith, purpose and whether the world is really worth saving.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ikenfell-playstation-4', 'Ikenfell', NULL, '2020-10-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fsc.jpg', 'A turn-based tactical RPG about a group of troublesome magic students. Use timing mechanics to power your spells and block attacks, explore the twisted halls of a vast magic school, fight challenging monsters and bosses, and uncover dark secrets never meant to be found.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('immortals-fenyx-rising-playstation-4', 'Immortals Fenyx Rising', NULL, '2020-12-03', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kcb.jpg', 'From the creators of Assassin’s Creed Odyssey comes a storybook adventure about a forgotten hero on a quest to save the Greek gods.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('indigo-prophecy-playstation-4', 'Indigo Prophecy', NULL, '2016-08-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rhh.jpg', 'Indigo Prophecy is an action-adventure game that involves the player in making decisions to alter the narrative. The name change in North America was made to avoid confusion with Michael Moore''s Fahrenheit 9/11 documentary film, which was released in 2004. Indigo Prophecy introduced elements like ethical ambiguity, romance, the inability to perish, and interactive storytelling that would endure in Quantic Dream later games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('infamous-second-son-playstation-4', 'Infamous Second Son', 'Infamous', '2014-03-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1izy.jpg', 'Infamous: Second Son, a PlayStation 4 exclusive , brings you an action adventure game where surrounded by a society that fears them, superhumans are ruthlessly hunted down and caged by the Department of Unified Protection. Step into a locked-down Seattle as Delsin Rowe, who has recently discovered his superhuman power and is now capable of fighting back against the oppressive DUP. Enjoy your power as you choose how you will push your awesome abilities to the limit and witness the consequences of your actions as they affect the city and people around you.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('inside-playstation-4', 'Inside', NULL, '2016-08-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66n4.jpg', 'A short story about what sort of challenges everyday little things can be. Help the girl buy milk, be the first not to disappoint her.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('inside-limbo-playstation-4', 'Inside / Limbo', NULL, '2017-05-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co821u.jpg', 'A bundle containing two of Playdead''s critically acclaimed titles, Inside & Limbo.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('it-takes-two-playstation-4', 'It Takes Two', NULL, '2021-03-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob22v.jpg', 'Embark on the craziest journey of your life in It Takes Two, a genre-bending platform adventure created purely for co-op. Invite a friend to join for free with Friend’s Pass and work together across a huge variety of gleefully disruptive gameplay challenges. Play as the clashing couple Cody and May, two humans turned into dolls by a magic spell. Together, trapped in a fantastical world where the unpredictable hides around every corner, they are reluctantly challenged with saving their fractured relationship.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-jackbox-party-pack-playstation-4', 'The Jackbox Party Pack', NULL, '2015-11-03', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zel.jpg', 'The team behind "You Don''t Know Jack" presents five guffaw-inducing party games in one pack! You''re gonna need more than one party for this. Your phones or tablets are your controllers! For 1-100 players! Games include:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-and-daxter-the-precursor-legacy-playstation-4', 'Jak and Daxter: The Precursor Legacy', 'Jak and Daxter', '2017-08-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w7q.jpg', 'Jak and Daxter: The Precursor Legacy is a 2001 platform video game developed by Naughty Dog and published by Sony Computer Entertainment for the Sony PlayStation 2 on December 4, 2001, as the first game of the Jak and Daxter series. The game follows the protagonist, a young teenager named Jak, as he tries to help his friend Daxter after he is transformed into an "ottsel", a fictional hybrid of an otter and a weasel.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-ii-playstation-4', 'Jak II', 'Jak and Daxter', '2017-12-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2agi.jpg', 'Jak II is an open-world platform, third-person shooter, and an action-adventure video game. It is the second game of the Jak and Daxter series and a sequel to Jak and Daxter: The Precursor Legacy.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-3-playstation-4', 'Jak 3', 'Jak and Daxter', '2017-12-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6kks.jpg', 'Jak 3 is a platform game developed by Naughty Dog for Sony''s PlayStation 2 console. The game is the sequel to Jak II, and third in the series. The game features new weapons and devices, new playable areas, and a storyline that picks up after the events of the previous games. As in the other games in the series, the player takes on the dual role of recurring protagonists Jak and Daxter.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jak-x-combat-racing-playstation-4', 'Jak X: Combat Racing', 'Jak and Daxter', '2017-12-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27zt.jpg', 'After saving Haven City once again, Jak and Daxter find themselves poisoned forced into competition on the international car-racing circuit by the execution of Krew''s will.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('job-simulator-playstation-4', 'Job Simulator', NULL, '2016-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpsf.jpg', 'Be ready to get your hands really dirty. In this game you will have to do things that others find too disgusting. Sewage, excrements and blood are just a few examples of what awaits you. You need to be careful or else you will catch an infection. Staying in the hospital means the end of work.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('katamari-damacy-reroll-playstation-4', 'Katamari Damacy Reroll', 'Katamari', '2020-11-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25sm.jpg', 'When the King of All Cosmos accidentally destroys all the stars in the sky, he orders you, his pint-sized princely son, to put the twinkle back in the heavens above. Join the King and Prince of Cosmos on their wacky adventure to restore the stars at home or on the go – now in full HD!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kaze-and-the-wild-masks-playstation-4', 'Kaze and the Wild Masks', NULL, '2021-05-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t98.jpg', 'Go on a journey as Kaze in this 90’s classics inspired platformer. When the Crystal Islands get cursed, Kaze needs to save her friend Hogo while facing enraged living vegetables. Find the Wild Masks to unleash the powers of the legendary guardians and master land, sky and sea.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kena-bridge-of-spirits-playstation-4', 'Kena: Bridge of Spirits', NULL, '2021-09-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9hwy.jpg', 'Kena: Bridge of Spirits: a story-driven, action adventure combining exploration with fast-paced combat. Untangle the past as Kena, a young Spirit Guide in search of the sacred Mountain Shrine. Help free the spirits trapped in a forgotten village with the help of the Rot, Kena''s adorable (yet powerful) spirit companions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kentucky-route-zero-tv-edition-playstation-4', 'Kentucky Route Zero: TV Edition', 'Kentucky Route Zero', '2020-01-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xix.jpg', 'Kentucky Route Zero is a magical realist adventure game about a secret highway in the caves beneath Kentucky, and the mysterious folks who travel it. Gameplay is inspired by point-and-click adventure games (like the classic Monkey Island or King''s Quest series, or more recently Telltale''s Walking Dead series), but focused on characterization, atmosphere and storytelling rather than clever puzzles or challenges of skill.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kero-blaster-playstation-4', 'Kero Blaster', NULL, '2017-04-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4iej.jpg', 'Kero Blaster is a platform video game created by Daisuke "Pixel" Amaya. It was released in 2014 for PC and iOS and is the first major project of Pixel since Cave Story in 2004. The game lays a heavy emphasis on shooting and got positive reviews on both platforms. A short, free demo titled Pink Hour has been available since a month before the full game''s release.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('killzone-shadow-fall-playstation-4', 'Killzone: Shadow Fall', 'Killzone', '2013-11-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v40.jpg', 'Killzone Shadow Fall is the sixth game of the Killzone series. Gameplay in Shadow Fall is fairly similar to previous installments, though now with more improvements. The game is much more open-ended allowing for multiple ways to reach your target and complete objectives. The player is accompanied by a companion drone called the OWL which can help you in many different ways including deploying a zip-line or stunning the enemy. Using futuristic weapons and gear allows for new stealth gameplay. The online multiplayer mode allows for up to 24-players to battle at once on any of the games default 10 maps. The level system is now challenge-based where completing any of the games many challenges will upgrade your rank. Warzone returns as an online game mode along with Team Deathmatch and Beacon Retrieval (Capture the Flag). A new feature allows for the user to create Warzones with their own specific rules and share them with the community to download and play.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-hd-2-8-final-chapter-prologue-playstation-4', 'Kingdom Hearts HD 2.8 Final Chapter Prologue', 'Kingdom Hearts', '2017-01-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co312y.jpg', 'Kingdom Hearts HD 2.8 Final Chapter Prologue is a compilation that brings the popular Kingdom Hearts [Dream Drop Distance] to the PlayStation4 computer entertainment system platform remastered in high definition.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-hd-1-5-2-5-remix-playstation-4', 'Kingdom Hearts HD 1.5 + 2.5 Remix', 'Kingdom Hearts', '2017-03-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co312w.jpg', 'Kingdom Hearts HD 1.5 + 2.5 Remix is an HD remastered collection of 6 unforgettable Kingdom Hearts experiences. Kingdom Hearts HD 1.5 + 2.5 Remix is the perfect opportunity to start wielding your Keyblade to save the Disney worlds from darkness.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-iii-playstation-4', 'Kingdom Hearts III', 'Kingdom Hearts', '2019-01-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tpy.jpg', 'Kingdom Hearts III is the third main installment in the Kingdom Hearts series developed and published by Square Enix. It was initially released January 2019 for the PlayStation 4 and the Xbox One. An expansion, Kingdom Hearts III Re Mind was released in January 2020.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-melody-of-memory-playstation-4', 'Kingdom Hearts: Melody of Memory', 'Kingdom Hearts', '2020-11-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gk9.jpg', 'Kingdom Hearts: Melody of Memory is a rhythm action game developed and published by Square Enix for the PlayStation 4, Xbox One, and Nintendo Switch. It is the fourteenth installment in the Kingdom Hearts series. The game features over 140 songs from the series and the ability to play as over 20 characters. Additionally, Kairi''s story is continued from the end of the Kingdom Hearts III Re Mind downloadable content.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('knack-playstation-4', 'Knack', 'Knack', '2013-11-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4lea.jpg', 'From Mark Cerny, one of the greatest minds in video games today, Knack is a fun-filled adventure of colossal proportions that invites players to wield fantastic powers and discover a unique and vibrant world.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('knack-ii-playstation-4', 'Knack II', 'Knack', '2017-09-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4le9.jpg', 'Meet Knack, a little guy with surprising moves and the ability to transform from big to small and back again in this family-friendly adventure from the developers at PlayStation.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-playstation-4', 'L.A. Noire', 'L.A. Noire', '2017-11-14', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldn.jpg', 'L.A. Noire is a neo-noir detective action-adventure video game developed by Team Bondi and published by Rockstar Games. It was initially released for the PlayStation 3 and Xbox 360 platforms on 17 May 2011; a Microsoft Windows port was later released on 8 November 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-guardian-playstation-4', 'The Last Guardian', NULL, '2016-12-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa2ic.jpg', 'In The Last Guardian, players discover a fantastical beast named Trico, who acts as companion and protector as the two traverse a mysterious fantasy world. Now step inside the world to interact with Trico in a whole new way.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-of-us-remastered-playstation-4', 'The Last of Us Remastered', 'The Last of Us', '2014-07-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5zks.jpg', 'The Last of Us Remastered is an updated release of the PS3 game The Last of Us. It is identical to the PS3 version but runs at a 1080p resolution and incorporates character models with a higher resolution. There are also improved shadows and lighting, upgraded textures, 60 frames per second and other types of improvements. In addition to the base game, two map packs and the expansion The Last of Us: Left Behind are included.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-of-us-part-ii-playstation-4', 'The Last of Us Part II', 'The Last of Us', '2020-06-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ziw.jpg', 'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble nature of the player character introduces platforming elements, allowing the player to jump and climb to traverse environments and gain advantages during combat.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-tinker-city-of-colors-playstation-4', 'The Last Tinker: City of Colors', NULL, '2014-08-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co43wv.jpg', 'The Last Tinker is a joyous action adventure and definitely no platformer, as there is no jump button. Koru, a boy from the slums of Colortown, must rise and stand against the Bleakness, a dark force intent on wiping out joy. Koru must use color and emotion to restore life to Colortown!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-playstation-4', 'Lego Marvel Super Heroes', 'Lego', '2013-11-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-playstation-4', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-playstation-4', 'Lego The Hobbit', 'Lego', '2014-04-08', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-playstation-4', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-playstation-4', 'Lego Jurassic World', 'Lego', '2015-06-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dimensions-playstation-4', 'Lego Dimensions', 'Lego', '2015-09-27', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w4t.jpg', 'Help stop crime in the Lego Dimensions multiverse with Lego City’s Chase McCain. Build and place Chase on the Lego Toy Pad to bring him to life in the game. Use his Lego City Detective Scanner to track down bad guys and change his disguise to unlock more abilities. Become a Miner to break Silver Lego bricks or a Fireman to use your Water Beam to put out fires. Unlock the Lego City Adventure World to explore new areas like Blackwell’s moonbase and the Lego City Police Department, and the Battle Arena to compete with up to 4 of your friends. Build Chase’s Police Helicopter to fire off bolts, then rebuild it into the Police Hovercraft and Police Plane for additional in-game abilities.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-playstation-4', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-playstation-4', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-collection-playstation-4', 'Lego Harry Potter Collection', 'Lego', '2016-10-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8s8o.jpg', 'The LEGO Harry Potter: Collection is an action-adventure compilation that combines LEGO Harry Potter: Years 1–4 and LEGO Harry Potter: Years 5–7 into a single experience.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-worlds-playstation-4', 'Lego Worlds', 'Lego', '2017-03-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1j95.jpg', 'LEGO Worlds is an open environment of procedurally-generated Worlds made entirely of LEGO bricks which you can freely manipulate and dynamically populate with LEGO models. Create anything you can imagine one brick at a time, or use large-scale landscaping tools to create vast mountain ranges and dot your world with tropical islands. Drop in prefabricated structures to build and customize any world to your liking. Explore using helicopters, dragons, motorbikes or even gorillas and unlock treasures that enhance your gameplay. Watch your creations come to life through characters and creatures that interact with you and each other in unexpected ways. In LEGO Worlds, anything is possible!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-city-undercover-playstation-4', 'Lego City Undercover', 'Lego', '2017-04-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vx0.jpg', 'As Chase McCain, you''ll become an expert at hand-to-hand combat, fighting your foes and wrestling them to the ground until you can slap the cuffs on ''em. The best officers are also pros at free running, jumping, climbing, and traversing the city on special blue and white bricks. Do you have what it takes?', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-ninjago-movie-video-game-playstation-4', 'The Lego Ninjago Movie Video Game', 'Lego', '2017-09-22', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co253j.jpg', 'Find your inner ninja with the all-new LEGO Ninjago Movie Video Game! Play as your favorite ninjas, Lloyd, Jay, Kai, Cole, Zane, Nya and Master Wu to defend Ninjago City from the evil Lord Garmadon and his Shark Army. Master the art of Ninja-gility by wall-running, high-jumping and battling the foes of Ninjago to rank up and upgrade the ninja’s combat skills. Only in the LEGO Ninjago Movie Video Game will you experience the film across 8 action packed locations each with its own unique Challenge Dojo. And with the Battle Maps, play against friends and family in competitions for up to four players!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-2-playstation-4', 'Lego Marvel Super Heroes 2', 'Lego', '2017-11-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27zc.jpg', 'Get the Deluxe Edition now and gain access to the main game and season pass content! Join your favorite Super Heroes and Super Villains from different eras and realities as they go head-to-head with the time-traveling Kang the Conqueror in the all-new, original adventure, LEGO Marvel Super Heroes 2! Play as the Guardians of the Galaxy, Spider-Man, Thor, Hulk, Black Panther, Captain Marvel, Doctor Strange, Green Goblin and dozens of other Marvel Super Heroes and Villains in this cosmic battle across the time-tossed city of Chronopolis! Travel across lands -- from Ancient Egypt to The Old West, Sakaar and New York City in 2099 -- and transport objects or characters through the centuries! And, with new battle modes, friends and family can play against each other in a series of themed challenges and battle arenas!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-incredibles-playstation-4', 'Lego The Incredibles', 'Lego', '2018-06-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wkq.jpg', 'LEGO The Incredibles takes players on an adventure where they’ll control their favourite Incredibles characters and team up as a family to conquer crime and family life.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dc-super-villains-playstation-4', 'Lego DC Super-Villains', 'Lego', '2018-10-16', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26qa.jpg', 'Lego DC Super-Villains is a Lego-themed action-adventure platform video game developed by Traveller''s Tales. The fourth installment in the Lego Batman series of games, it is a spin-off that focuses entirely on villains of the DC Universe; it is the first in the series to do so since the villain levels from Lego Batman: The Videogame.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-2-videogame-playstation-4', 'The Lego Movie 2 Videogame', 'Lego', '2019-02-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dhg.jpg', 'The alien monster invaders have left Bricksburg in ruins. It is now up to Emmet and a host of heroic characters to go beyond their world and save their friends from the strange inhabitants of the Systar System. Players can journey into outer space, discover new worlds, and test their Master Building skills.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-playstation-4', 'Life is Strange', 'Life is Strange', '2016-01-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7p.jpg', 'The long awaited sequel to the award winning Life is Strange returns with a new 5-part narrative adventure from DONTNOD Entertainment.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-before-the-storm-playstation-4', 'Life is Strange: Before The Storm', 'Life is Strange', '2018-03-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1twj.jpg', 'Life is Strange: Before the Storm is a new three part standalone story adventure set three years before the events of the first game. This time play as Chloe Price, a rebel who forms an unlikely friendship with Rachel Amber in dramatic new story in the BAFTA award winning franchise.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-2-playstation-4', 'Life is Strange 2', 'Life is Strange', '2020-02-04', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7p.jpg', 'The long awaited sequel to the award winning Life is Strange returns with a new 5-part narrative adventure from DONTNOD Entertainment.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-true-colors-playstation-4', 'Life is Strange: True Colors', 'Life is Strange', '2021-09-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vpp.jpg', 'Life is Strange is a series of award-winning and critically-acclaimed narrative adventure games. Discover a universe where everyday heroes wield supernatural powers, while dealing with real challenges, real relationships, and real emotions. It''s our world... with a twist of the strange. No matter your choices, the experience will stay with you forever. Deep in the mountains of Colorado, you''ll find Haven Springs, a small mining town filled with beauty and mystery. As Alex, you''ll discover the shocking secrets behind your brother’s death in an emotional roller-coaster of an adventure, using your psychic power of Empathy to change fate and change lives.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-0-playstation-4', 'Yakuza 0', 'Like a Dragon', '2017-01-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co252x.jpg', 'Yakuza 0 is an action-adventure game developed by Ryu Ga Gotoku Studio and published by Sega. Serving as a prequel to the Yakuza series, it is set in 1988 Japan during the country''s economic bubble era. The game follows two protagonists: Kazuma Kiryu in Tokyo''s Kamurocho district and Goro Majima in Osaka''s Sotenbori district. Players alternate between their stories as they navigate the criminal underworld, engaging in street fights, managing businesses, and participating in various side activities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-kiwami-playstation-4', 'Yakuza Kiwami', 'Like a Dragon', '2017-08-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coazbq.jpg', 'A bundle including Yakuza Kiwami and Yakuza Kiwami 2.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-6-the-song-of-life-playstation-4', 'Yakuza 6: The Song of Life', 'Like a Dragon', '2018-04-17', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co492w.jpg', 'Step into Japan''s criminal underworld in this explosive action brawler starring legendary yakuza, Kazuma Kiryu, who is hellbent on unraveling the truth around his daughter''s tragic accident.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-kiwami-2-playstation-4', 'Yakuza Kiwami 2', 'Like a Dragon', '2018-08-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1qc.jpg', 'Yakuza Kiwami 2 is a remake of Yakuza 2, and is an action-adventure game set in an open world environment and played from a third-person perspective. Combat is based on that previously seen in Yakuza 6. A new "Majima Saga" story scenario features recurring series anti-hero Goro Majima as a playable character.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-3-remastered-playstation-4', 'Yakuza 3 Remastered', 'Like a Dragon', '2019-08-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26ar.jpg', 'Yakuza 3 Remastered is an updated version of Yakuza 3, developed by Ryu Ga Gotoku Studio and published by Sega. Released as part of The Yakuza Remastered Collection in 2019, the remaster features improved graphics, a higher frame rate, and restored content that was cut from the original Western release. The game follows protagonist Kazuma Kiryu as he manages an orphanage in Okinawa while being drawn back into conflicts with the yakuza.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-4-remastered-playstation-4', 'Yakuza 4 Remastered', 'Like a Dragon', '2019-10-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s10.jpg', 'The game from 2010 has been remastered for the PS4 with one of Yakuza 4''s main protagonists, Masayoshi Tanimura, being recast and getting a visual makeover.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-5-remastered-playstation-4', 'Yakuza 5 Remastered', 'Like a Dragon', '2020-02-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s11.jpg', 'Experience the fifth chapter of the Kazuma Kiryu saga in 1080p and 60fps. Get ready for a Yakuza experience of unprecedented scale. Follow five characters across five Japanese cities, each trying to achieve their dream. The connections between them bring them together, but the conflict that unfolds is nothing any of them could have predicted.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-like-a-dragon-playstation-4', 'Yakuza: Like a Dragon', 'Like a Dragon', '2020-11-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2em9.jpg', 'Yakuza: Like a Dragon is a role-playing game developed and published by Sega. Released in 2020, it is the eighth main entry in the Yakuza series. The game introduces a new protagonist, Ichiban Kasuga, and departs from the traditional action combat system, instead featuring turn-based combat with a party of characters. Set in the fictional city of Yokohama, the game follows Kasuga''s quest for revenge and his journey through Japan''s criminal underworld.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lost-judgment-playstation-4', 'Lost Judgment', 'Like a Dragon', '2021-09-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53ld.jpg', 'Lost Judgment is an action-adventure video game developed by Ryu Ga Gotoku Studio and published by Sega. A sequel to the 2018 game Judgment (a spin-off of the Like a Dragon series), the game focuses on private detective Takayuki Yagami as he investigates a criminal accused of both sexual harassment and murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('like-a-dragon-infinite-wealth-playstation-4', 'Like a Dragon: Infinite Wealth', 'Like a Dragon', '2024-01-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8356.jpg', 'Like a Dragon: Infinite Wealth is a turn-based role-playing game developed by Ryu Ga Gotoku Studio and published by Sega. It follows dual protagonists Ichiban Kasuga and Kazuma Kiryu, with the narrative set primarily in Japan and Hawaii. The game uses a party-based combat system that builds on previous Like a Dragon entries, incorporating positioning and environmental interactions. Players engage in main story missions alongside a wide range of optional activities and side content. The title combines narrative-driven progression with exploration, character development, and minigames typical of the series.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('littlebigplanet-3-playstation-4', 'LittleBigPlanet 3', 'LittleBigPlanet', '2014-11-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3t1c.jpg', 'In LittleBigPlanet 3, explore a world filled with creativity as you explore all corners of the Imagisphere, meet the inhabitants of the mysterious planet Bunkum and face the nefarious Newton. Discover endless surprises that the LittleBigPlanet Community have created and shared for you to enjoy, with new levels and games to play every day. Then if you''re feeling inspired, flex your creative muscles with the powerful and intuitive customization tools, to bring your own imagination to life in LittleBigPlanet 3.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sackboy-a-big-adventure-playstation-4', 'Sackboy: A Big Adventure', 'LittleBigPlanet', '2020-11-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4522.jpg', 'Iconic PlayStation hero, Sackboy returns in an all-new 3D adventure with a deeply immersive and expressive control scheme. Players can go on this epic platforming journey solo-style, or they can team up with friends for collaborative, chaotic multiplayer fun.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('secret-of-mana-playstation-4', 'Secret of Mana', 'Mana', '2018-02-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9a7h.jpg', '"The memorable adventure of Randi, Primm and Popoi is reborn as "Secret of Mana"!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('trials-of-mana-playstation-4', 'Trials of Mana', 'Mana', '2020-04-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lzw.jpg', 'Trials of Mana is a full high definition remake of the third entry in the Mana series, previously exclusively released in Japan in 1995 as Seiken Densetsu 3. Trials of Mana tells the story of six heroes as they battle against the monsters of destruction that threaten a world where Mana has been weakened. Players can customize their own party of three, selected from six unique characters, to experience different stories.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-playstation-4', 'The Amazing Spider-Man 2', 'Marvel', '2014-04-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deadpool-playstation-4', 'Deadpool', 'Marvel', '2015-11-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xsf.jpg', 'In Deadpool the player takes control of the loud-mouthed, foul-mouthed, merc-with-a-mouth Wade Wilson (a.k.a. Deadpool). While on out on a contract to kill a corrupt media mogul, Mister Sinister intervenes and kills him instead, drawing the ire of Deadpool who then vows revenge only to stumble upon a bigger plot which could spell the end of humanity.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-marvel-vs-capcom-3-playstation-4', 'Ultimate Marvel vs. Capcom 3', 'Marvel', '2016-12-03', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yej.jpg', 'Ultimate Marvel vs. Capcom 3 is a crossover fighting game developed by Capcom in collaboration with Eighting. It is an updated version of Marvel vs. Capcom 3: Fate of Two Worlds. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. The game was released in November 2011 for the PlayStation 3 and Xbox 360, and was featured as a launch title for the PlayStation Vita in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guardians-of-the-galaxy-the-telltale-series-playstation-4', 'Guardians of the Galaxy: The Telltale Series', 'Marvel', '2017-04-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27yt.jpg', 'Marvel''s Guardians of the Galaxy: The Telltale Series is a brand new story of the universe''s unlikeliest heroes: Star-Lord, Gamora, Drax, Rocket, and Groot. In the wake of an epic battle, the Guardians discover an artifact of unspeakable power. Each of them has a reason to desire this relic, as does a ruthless enemy who is the last of her kind, and who will stop at nothing to tear it from their hands.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-infinite-playstation-4', 'Marvel vs. Capcom: Infinite', 'Marvel', '2017-09-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wqa.jpg', 'Marvel vs. Capcom: Infinite will feature a variety of exciting and accessible single player modes and rich multi-player content for new players and longtime fans alike. In addition to single player Arcade, Training and Mission modes, a visually stunning and immersive cinematic Story Mode will put players at the center of both universes as they battle for survival against a sinister new threat. Marvel vs. Capcom: Infinite is being built to highlight a combination of iconic locations and fan favorite characters from both universes, including Captain Marvel and Iron Man from the Marvel side, and Ryu and Mega Man X from Capcom.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-spider-man-playstation-4', 'Marvel''s Spider-Man', 'Marvel', '2018-09-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w2p.jpg', 'After gaining control of equipment left in the wake of Sable International’s military occupation, Hammerhead and his gang have declared war against the other Dons of the Maggia crime family. Spider-Man and Captain of the Police Department of New York Yuri Watanabe must put an end to the violence before the entire city erupts in a turf war.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-iron-man-vr-playstation-4', 'Marvel''s Iron Man VR', 'Marvel', '2020-07-03', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-avengers-playstation-4', 'Marvel''s Avengers', 'Marvel', '2020-09-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fkb.jpg', 'Based on the Marvel Cinematic Universe film Marvel''s Ant-Man, this DLC adds a brand-new level and eleven characters to LEGO Marvel''s Avengers journey.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-spider-man-miles-morales-playstation-4', 'Marvel''s Spider-Man: Miles Morales', 'Marvel', '2020-11-12', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobg1j.jpg', 'The latest adventure in the Spider-Man universe will build on and expand ‘Marvel’s Spider-Man’ through an all-new story. Players will experience the rise of Miles Morales as he masters new powers to become his own Spider-Man.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-guardians-of-the-galaxy-playstation-4', 'Marvel''s Guardians of the Galaxy', 'Marvel', '2021-10-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yh5.jpg', 'A bundle including Marvel''s Guardians of the Galaxy and Marvel''s Avengers.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-andromeda-playstation-4', 'Mass Effect: Andromeda', 'Mass Effect', '2017-03-21', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co39vk.jpg', 'A new adventure awaits in the Mass Effect universe. With stunning visuals and a new galaxy to discover, BioWare delivers the next generation of space exploration.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-legendary-edition-playstation-4', 'Mass Effect Legendary Edition', 'Mass Effect', '2021-05-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k5h.jpg', 'One person is all that stands between humanity and the greatest threat it’s ever faced. Relive the legend of Commander Shepard in the highly acclaimed Mass Effect trilogy with the Mass Effect Legendary Edition. Includes single-player base content and over 40 DLCs from Mass Effect, Mass Effect 2, and Mass Effect 3 games, including promo weapons, armors and packs. Experience an amazingly rich and detailed universe where your decisions have profound consequences on the action and the outcome.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('medievil-playstation-4', 'MediEvil', 'MediEvil', '2019-10-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjk.jpg', 'MediEvil is an action-adventure game developed by SCE Cambridge Studio and published by Sony Computer Entertainment. Originally released in 1998 for the PlayStation, the game follows Sir Daniel Fortesque, a skeletal knight accidentally resurrected to battle the sorcerer Zarok and save the kingdom of Gallowmere.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-playstation-4', 'Mega Man Legacy Collection', 'Mega Man', '2015-08-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-2-playstation-4', 'Mega Man Legacy Collection 2', 'Mega Man', '2017-08-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-11-playstation-4', 'Mega Man 11', 'Mega Man', '2018-10-02', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qb8.jpg', 'A GameStop/EB Games exclusive edition of Mega Man 11 that was only released in North America.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-legacy-collection-1-2-playstation-4', 'Mega Man X Legacy Collection 1+2', 'Mega Man X', '2018-07-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2055.jpg', '"Mega Man X Legacy Collection includes the legendary 16-bit titles and the series’ exciting foray into 32-bits: Mega Man X, Mega Man X2, Mega Man X3, and Mega Man X4. The heroic robot grows stronger as he takes down Mavericks and steals their weapons, and also has the ability to dash and wall jump for thrilling, fast-paced combat. Mega Man X’s mysterious friend, Zero, also joins the fray as a playable character later in this collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-zx-legacy-collection-playstation-4', 'Mega Man Zero / ZX Legacy Collection', NULL, '2020-02-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204w.jpg', 'Mega Man Zero/ZX Legacy Collection brings together six classic titles in one game: Mega Man Zero 1, 2, 3 and 4, as well as Mega Man ZX and ZX Advent. The collection also features Z-Chaser, an exclusive new mode created just for this set of games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-messenger-playstation-4', 'The Messenger', 'The Messenger', '2019-03-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1th.jpg', 'As a demon army besieges his village, a young ninja ventures through a cursed world, to deliver a scroll paramount to his clan''s survival.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-ground-zeroes-playstation-4', 'Metal Gear Solid V: Ground Zeroes', 'Metal Gear', '2014-03-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v88.jpg', 'Metal Gear Solid V: Ground Zeroes is a prologue to Metal Gear Solid V: The Phantom Pain. It offers players new sneaking and traversal methods compared to its predecessors, as well as the choice in what order the story events take place by selecting missions by advance. The most important change for this title is the shift to an open world design with a real-time day and night cycle doing away with the linear mission approach of previous games. The game was originally developed as a mission for The Phantom Pain, but an extended development time resulted in director Hideo Kojima splitting the specific portion of the game as a stand-alone product so that players could get early access to Metal Gear Solid V.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-phantom-pain-playstation-4', 'Metal Gear Solid V: The Phantom Pain', 'Metal Gear', '2015-09-01', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v85.jpg', 'Metal Gear Solid V: The Phantom Pain is the sequel to Metal Gear Solid V: Ground Zeroes and a prequel to the original Metal Gear. The game has a complex story with long cut-scene sequences, but there are fewer and they are shorter compared to earlier Metal Gear Solid titles. Most of the gameplay mechanics introduced in Ground Zeroes are carried over: it is still an action game and stealth oriented but replaces the linear corridor design from most earlier titles with large open world environments that offer the player unrestricted freedom for the approach. The world has now a real-time day and night cycle and various weather effects that influence enemy behaviour, visibility and sound. Sabotaging or destroying certain structures can also influence other parts of the map.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-definitive-experience-playstation-4', 'Metal Gear Solid V: The Definitive Experience', 'Metal Gear', '2016-10-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ats.jpg', 'Metal Gear Solid V: The Definitive Experience is the ultimate collection of the Metal Gear Solid V story which includes Metal Gear Solid V: Ground Zeroes and Metal Gear Solid V: Tha Phantom Pain, the tactical multiplayer game as well as all their DLC content.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-survive-playstation-4', 'Metal Gear Survive', 'Metal Gear', '2018-02-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27m5.jpg', 'In a struggle to stay alive on this harsh terrain filled with deadly creatures, soldiers who were previously on Motherbase now must work cooperatively in order to survive.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-mordor-playstation-4', 'Middle-earth: Shadow of Mordor', 'Middle-earth', '2014-09-30', 'PlayStation 4', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20pd.jpg', 'Middle-earth: Shadow of Mordor is a open world third-person action role-playing video game developed by Monolith Productions and published by Warner Bros. Interactive Entertainment, which takes place in the world of J.R.R. Tolkien''s Legendarium.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-war-playstation-4', 'Middle-earth: Shadow of War', 'Middle-earth', '2017-10-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coalj6.jpg', 'Middle-earth: Shadow of War Mobile is a free-to-play real-time RPG continuing Talion’s journey through Mordor.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mighty-no-9-playstation-4', 'Mighty No. 9', NULL, '2016-06-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaquo.jpg', 'Well to celebrate Cirno day and for the ⑨Jam, i made this small little game about cirno.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mighty-switch-force-collection-playstation-4', 'Mighty Switch Force! Collection', 'Mighty Switch Force!', '2019-07-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8y4.jpg', 'Switch up the fun with four games in one with Mighty Switch Force! Collection! Take control of cybernetic peacekeeper Patricia Wagon and jump, shoot, and puzzle-solve your way through four fantastic games: Mighty Switch Force!, Mighty Switch Force! 2, Mighty Switch Force! Hyper Drive Edition, and Mighty Switch Force! Academy.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-playstation-4-edition-playstation-4', 'Minecraft: PlayStation 4 Edition', 'Minecraft', '2014-10-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co89e6.jpg', 'The critically acclaimed Minecraft comes to PlayStation 4. Create your very own game world and explore, build and conquer.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-playstation-4', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2016-10-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-season-two-playstation-4', 'Minecraft: Story Mode - Season Two', 'Minecraft', '2017-09-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vin.jpg', 'Minecraft: Story Mode - Season Two continues Jesse''s saga in a five-part, narrative-driven, episodic game series developed by Telltale in collaboration with Mojang and members of the Minecraft community. Though players'' choices from the first season will carry over into season two, this new season will be accessible to both returning fans and newcomers alike. This second season will also include Telltale''s unique multiplayer ''Crowd Play'' feature, which allows friends and family to engage with the adventure together by helping to decide the direction of the story from any mobile device with an online connection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-playstation-4', 'Minecraft', 'Minecraft', '2019-12-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fu7.jpg', 'Minecraft focuses on allowing the player to explore, interact with, and modify a dynamically-generated map made of one-cubic-meter-sized blocks. In addition to blocks, the environment features plants, mobs, and items. Some activities in the game include mining for ore, fighting hostile mobs, and crafting new blocks and tools by gathering various resources found in the game. The game''s open-ended model allows players to create structures, creations, and artwork on various multiplayer servers or their single-player maps. Other features include redstone circuits for logic computations and remote actions, minecarts and tracks, and a mysterious underworld called the Nether. A designated but completely optional goal of the game is to travel to a dimension called the End, and defeat the ender dragon.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-dungeons-hero-edition-playstation-4', 'Minecraft Dungeons Hero Edition', 'Minecraft', '2020-09-08', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co233s.jpg', 'Fight your way through an all-new action-adventure game, inspired by classic dungeon crawlers and set in the Minecraft universe! Up to four friends can play together, or you can brave the dungeons alone. Includes a Hero Cape, two player skins, and a chicken pet. It also includes two DLC packs, when they become available.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minit-playstation-4', 'Minit', NULL, '2018-04-03', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vcj.jpg', 'Minit is a peculiar little adventure played sixty seconds at a time.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mirror-s-edge-catalyst-playstation-4', 'Mirror''s Edge Catalyst', 'Mirror''s Edge', '2016-06-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28r2.jpg', 'Mirror''s Edge Catalyst is an action-adventure game and the reboot to Mirror''s Edge. The story in the game explores the past of the protagonist Faith. Like in the previous game, the main gameplay in Mirror''s Edge Catalyst involves traversing the city using parkour to reach certain objectives. Unlike the linear levels in Mirror''s Edge, Mirror''s Edge Catalyst features an open-world free-roaming environment. Combat has been overhauled and emphasized compared to the first game and Catalyst no longer allows the player to use weapons, instead focusing on melee attacks.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-world-playstation-4', 'Monster Hunter: World', 'Monster Hunter', '2018-01-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rst.jpg', 'Welcome to a new world! Take on the role of a hunter and slay ferocious monsters in a living, breathing ecosystem where you can use the landscape and its diverse inhabitants to get the upper hand. Hunt alone or in co-op with up to three other players, and use materials collected from fallen foes to craft new gear and take on even bigger, badder beasts!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-world-iceborne-master-edition-playstation-4', 'Monster Hunter World: Iceborne Master Edition', 'Monster Hunter', '2019-09-06', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24ch.jpg', 'Discover breathtaking environments and battle titanic creatures in this collection that includes Monster Hunter: World and its massive expansion, Iceborne. As a hunter, you''ll take on quests to track & slay monsters in a variety of living, breathing habitats. Take down these monsters and use their materials to forge even more powerful weapons and armor, then prepare for even tougher foes as the story unfolds. Each discovery adds new areas, creatures, and drama to the adventure! The Iceborne expansion adds new monsters, gear and abilities to Monster Hunter: World. Picking up right where the base game left off, the Research Commission and your hunter set off to a new polar region, kicking off a brand-new story set in Hoarfrost Reach. Conquer these missions alone, or play online with other hunters for epic multiplayer quests.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('moss-playstation-4', 'Moss', NULL, '2018-02-27', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpik.jpg', 'Play Moss Moss to moss the world and find secrets.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('murdered-soul-suspect-playstation-4', 'Murdered: Soul Suspect', NULL, '2014-06-03', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7a.jpg', 'Murdered: Soul Suspect is a supernatural detective thriller which challenges players to solve possibly the hardest case of all… their own murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('n-playstation-4', 'N++', NULL, '2015-07-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2535.jpg', 'N++ is a fast-paced, action-packed platformer set in the distant future. You play as a ninja, darting through obstacles, narrowly evading a slew of inadvertently homicidal enemy robots and collecting gold in a minimalist, sci-fi world. N++ is all about smooth physics, deftly controlling the speed and inertia of the character, and the awesome feeling of fluidly moving through each level.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neonwall-playstation-4', 'Neonwall', NULL, '2018-09-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tjr.jpg', 'Travel through a world of neon, overcoming obstacles and traps. This experience requires focus, concentration, and timing to let the ball rolling as fast as you can. Remember... in a world made of neons... you will need balls to survive.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ni-no-kuni-ii-revenant-kingdom-playstation-4', 'Ni no Kuni II: Revenant Kingdom', 'Ni no Kuni', '2018-03-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25ub.jpg', 'The sequel to Ni no Kuni being developed for Windows and PlayStation 4.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ni-no-kuni-wrath-of-the-white-witch-remastered-playstation-4', 'Ni no Kuni: Wrath of the White Witch Remastered', 'Ni no Kuni', '2019-09-20', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob235.jpg', 'Ni no Kuni: Wrath of the White Witch Remastered on PlayStation 4 and PC features brilliant new visual enhancements, letting PlayStation 4 players enjoy the game at 1080p resolution and with a super-smooth frame rate of 60 frames per second (fps). PlayStation 4 Pro users can also opt for true 4K resolution at 30 fps, or 1440p at 60fps.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nier-automata-playstation-4', 'Nier: Automata', 'Nier', '2017-03-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pcj.jpg', 'NieR: Automata tells the story of androids 2B, 9S and A2 and their battle to reclaim the machine-driven dystopia overrun by powerful machines.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nier-replicant-ver-1-22474487139-playstation-4', 'Nier Replicant ver.1.22474487139...', 'Nier', '2021-04-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5h0n.jpg', 'NieR Replicant ver.1.22474487139... is an updated version of NieR Replicant, previously only released in Japan. Discover the one-of-a-kind prequel to the critically-acclaimed masterpiece NieR: Automata. Now with a modern upgrade, experience masterfully revived visuals, a fascinating storyline and more!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('night-in-the-woods-playstation-4', 'Night in the Woods', NULL, '2017-02-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fc4.jpg', 'Gather round the campfire and trace the constellations in Longest Night!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-master-collection-playstation-4', 'Ninja Gaiden: Master Collection', 'Ninja Gaiden', '2021-06-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpt5.jpg', 'The “Ninja Gaiden” series is respected and beloved across the entire gaming world, and has sold 6.8 million units in total.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nioh-playstation-4', 'Nioh', 'Nioh', '2017-02-07', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20xg.jpg', 'In Nioh, players will traverse war-torn Japan as William, a blonde-haired swordsman whose background as a fierce warrior and seasoned knowledge of the blade allows him to survive in the demon-plagued land of the samurai. Known as Yokai, these demons inhabit a number of dangerous locations and lie in wait in the shadows to ambush unsuspecting victims. Players will also face off with other samurai in supernatural sword battles and intense, multi-target engagements offering a level of difficulty that will truly test even the most hardened samurai’s skills, patience, and strategy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nioh-2-playstation-4', 'Nioh 2', 'Nioh', '2020-03-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kh2.jpg', 'Battle hordes of yokai in this masocore Action RPG. Create your protagonist and embark on an adventure through a myriad of locales across Japan during the Sengoku period. Utilize the new Yokai Shift ability to defeat even the most ferocious yokai and be prepared to brave through Dark Realms created by your enemies.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-man-s-sky-playstation-4', 'No Man''s Sky', 'No Man''s Sky', '2016-08-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j4g.jpg', 'Update 5.0, WORLDS, transforms the universe into a richer, wilder, more varied and immersive place. Featuring huge leaps in water and cloud visuals, increased planetary diversity, new gameplay features, and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-man-s-sky-beyond-playstation-4', 'No Man’s Sky Beyond', 'No Man''s Sky', '2019-09-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ovn.jpg', 'Update 2.0, Beyond, massively expands the multiplayer experience introduced in NEXT, takes immersion to a whole new level with fully-fledged Virtual Reality, overhauls base building, NPCs, technology trees, and much, much more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('octodad-dadliest-catch-playstation-4', 'Octodad: Dadliest Catch', NULL, '2014-04-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1szo.jpg', 'Octodad: Dadliest Catch is a game about destruction, deception, and fatherhood. The player controls Octodad, a dapper octopus masquerading as a human, as he goes about his life. Octodad''s existence is a constant struggle, as he must master mundane tasks with his unwieldy boneless tentacles while simultaneously keeping his cephalopodan nature a secret from his human family.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-new-n-tasty-playstation-4', 'Oddworld: New ''n'' Tasty!', 'Oddworld', '2014-07-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n69.jpg', 'Oddworld: New ''n'' Tasty is a faithful remake of Oddworld: Abe''s Oddysee where the pre-rendered sceneries are recreated in real-time 3D without changing the original gameplay. It also replaces the single screens linked together of the original version into a true 2.5D side-scrolling game. While there are various enhancements and details to the character and the scenery, the basic gameplay is still largely similar in a side by side comparison. The GameSpeak system Abe uses to command and talk to other characters start with the same commands, but can later be expanded. This version of the game supports leaderboards for the completion time of each mode and the overall game. There are three difficulty levels and the game. It includes the original cooperative function of the original game when another player can take over when the first player dies, taking turns controlling Abe.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-soulstorm-playstation-4', 'Oddworld: Soulstorm', 'Oddworld', '2021-04-06', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ysw.jpg', 'Oddworld: Soulstorm is a modern re-imagining of the 1998 title Oddworld: Abe''s Exoddus. It serves as a direct sequel to Oddworld: New ''n'' Tasty. The player controls Abe, a reluctant hero who inadvertently sparked an uprising and now must lead his fellow Mudokons in their fight for freedom against the Magog Cartel and the planet’s ruling power.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-hd-playstation-4', 'Ōkami HD', 'Ōkami', '2017-12-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22s8.jpg', 'Experience the critically acclaimed masterpiece with its renowned Sumi-e ink art style in breathtaking high resolution. Take on the role of Amaterasu, the Japanese sun goddess who inhabits the form of a legendary white wolf, on a quest to defeat Orochi, an eight-headed demon and tyrannical monster responsible for turning the world of Nippon into a ruined wasteland.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('omori-playstation-4', 'Omori', NULL, '2022-06-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pgb.jpg', 'This is an Omori mod that was said to be AI generated to be appealing as possible to players.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('onimusha-warlords-playstation-4', 'Onimusha: Warlords', 'Onimusha', '2019-01-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4r13.jpg', 'This enhanced HD version of Onimusha: Warlords now supports 16:9 wide screen resolution as well as the old 4:3 ratio. Improved controls now allow players to move and fight with analog-stick precision. The Japanese voices have been re-recorded for this remaster, and the brand new soundtrack promises to be even more spectacular than the original.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-order-1886-playstation-4', 'The Order: 1886', NULL, '2015-02-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rn6.jpg', 'The Order: 1886 introduces players to a unique vision of Victorian-Era London where Man uses advanced technology to battle a powerful and ancient foe. As a member of an elite order of knights, join a centuries-old war that will determine the course of history forever.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('outer-wilds-playstation-4', 'Outer Wilds', 'Outer Wilds', '2019-10-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65ac.jpg', 'Outer Wilds is a critically-acclaimed and award-winning open world mystery about a solar system trapped in an endless time loop. The newest member of the space program in a small village on the planet Timber Hearth, the player navigates a space shuttle and travels across their solar system to get to the bottom of its mysteries by exploring the cosmos and gathering the knowledge hidden within each of the system''s planets, left behind by another civilization in the distant past.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-outer-worlds-playstation-4', 'The Outer Worlds', NULL, '2019-10-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eew.jpg', 'The Outer Worlds is a new single-player sci-fi RPG from Obsidian Entertainment and Private Division. As you explore the furthest reaches of space and encounter a host of factions all vying for power, who you decide to become will determine the fate of everyone in Halcyon. In the corporate equation for the colony, you are the unplanned variable.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-gourmet-edition-playstation-4', 'Overcooked! Gourmet Edition', 'Overcooked!', '2016-11-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x6s.jpg', 'The Overcooked Gourmet Edition stirs together the smash hit co-op cooking game and the Lost Morsel content pack into one delicious package that will test your culinary skills to the limit!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-2-playstation-4', 'Overcooked! 2', 'Overcooked!', '2018-08-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g3n.jpg', 'This bundle contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-overcooked-2-playstation-4', 'Overcooked! + Overcooked! 2', 'Overcooked!', '2019-11-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g3n.jpg', 'This bundle contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-all-you-can-eat-playstation-4', 'Overcooked! All You Can Eat', 'Overcooked!', '2021-03-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4969.jpg', 'Five new birthday themed levels, the new Tabby Cat chef, a recipe to make a cup of tea, and in-game Switcheroo mechanic where living playing cards stalk the levels transporting players across the kitchen, are all on the menu.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('owlboy-playstation-4', 'Owlboy', NULL, '2018-04-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaac.jpg', 'Owlboy is a platform/action-adventure video game created by Norwegian developer D-Pad Studio.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oxenfree-playstation-4', 'Oxenfree', NULL, '2016-05-31', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hlq.jpg', 'Oxenfree is a supernatural adventure game. Rites of passage and Senior year traditions set the stage for a group of friends sneaking off to Edwards Island, an old military outpost with no phone service. Players will take on the role of Alex as she brings her new stepbrother Jonas to an overnight party gone horribly wrong. Inspired by classic cult films like Stand by Me and Poltergeist, Oxenfree is an adventure that pulls from the past but looks to the present. “It’s a coming of age story where players control how their hero comes of age,” says Sean Krankel, co-founder of Night School. “We’re drawing on the fond and mortifying aspects of being in your late teens, and setting it against a dangerous and ghostly backdrop.”', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-championship-edition-2-arcade-game-series-playstation-4', 'Pac-Man Championship Edition 2 + Arcade Game Series', 'Pac-Man', '2016-11-01', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27xn.jpg', 'Bandai-Namco bundles its hit Pac-Man Championship Edition 2 on a disc with three Namco classics.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-playstation-4', 'Panzer Dragoon', 'Panzer Dragoon', '2020-09-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ixu.jpg', 'Panzer Dragoon II Zwei is an "on-rails" shoot ''em up game released exclusively for the Sega Saturn. It was the second Panzer Dragoon game released but it is a prequel of the series. It was developed by Team Andromeda, one of Sega''s internal development studios.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pixel-gear-playstation-4', 'Pixel Gear', 'Persona', '2016-10-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co79fi.jpg', 'Pixel Gear is a pixel style VR shoot-em-up with a variety of humorous cartoon monsters and ghosts as enemies. Utlize your skills and weapons to defeat them, gain energy, and apply your skills wisely to slow down time and load up infinite bullets. Observe the environment carefully. And keep on shooting in the pixel battlefield.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-playstation-4', 'Persona 5', 'Persona', '2017-04-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zoq.jpg', 'Persona 5 Strikers is a crossover between Koei Tecmo''s hack and slash Dynasty Warriors series and Atlus''s turn-based role-playing game Persona series. As a result, it features gameplay elements from both, such as the real-time action combat of the former with the turn-based Persona-battling aspect of the latter. The game is set six months after the events of Persona 5, and follows Joker and the rest of the Phantom Thieves of Hearts as they end up in a mysterious version of Tokyo filled with supernatural enemies.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-dancing-in-moonlight-playstation-4', 'Persona 3: Dancing in Moonlight', 'Persona', '2018-12-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ob9.jpg', 'Face-to-face with an enigmatic Velvet Room resident, the SEES are forced to perform at a mysterious dance party. Test your rhythm based gameplay skills and dominate the dance floor!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-dancing-in-starlight-playstation-4', 'Persona 5: Dancing in Starlight', 'Persona', '2018-12-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cbi.jpg', 'Dancing game featuring characters from Persona 5.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-royal-playstation-4', 'Persona 5 Royal', 'Persona', '2020-03-31', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8h07.jpg', 'The Launch Edition includes the game in a limited edition Steelbook case and a dynamic PS4 theme download.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-5-strikers-playstation-4', 'Persona 5 Strikers', 'Persona', '2021-02-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zoq.jpg', 'Persona 5 Strikers is a crossover between Koei Tecmo''s hack and slash Dynasty Warriors series and Atlus''s turn-based role-playing game Persona series. As a result, it features gameplay elements from both, such as the real-time action combat of the former with the turn-based Persona-battling aspect of the latter. The game is set six months after the events of Persona 5, and follows Joker and the rest of the Phantom Thieves of Hearts as they end up in a mysterious version of Tokyo filled with supernatural enemies.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-portable-playstation-4', 'Persona 3 Portable', 'Persona', '2023-01-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60ug.jpg', 'From the Midnight Channel to the Dark Hour, two iconic Persona titles return!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-golden-playstation-4', 'Persona 4 Golden', 'Persona', '2023-01-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1x.jpg', 'An enhanced rerelease of Shin Megami Tensei: Persona 4 (2008) featuring quality-of-life improvements, gameplay enhancements, new locations, balance tweaks, online functionality, new difficulty options, an additional side character storyline and a changed endgame.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-reload-playstation-4', 'Persona 3 Reload', 'Persona', '2024-02-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co78nt.jpg', 'Persona 3 Reload: Persona 5 Royal Persona Set 1 contains additional content that allows you to use Personas from Persona 5 Royal.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-playstation-4', 'Plants vs. Zombies: Garden Warfare', 'Plants vs. Zombies', '2014-08-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qyz.jpg', 'Plants vs. Zombies is digging into the trenches with an explosive new 3D experience. Blast zombies, plants, and new characters with inventive weapons across a mine-blowing PvZ world. Take on Co-Op and Multiplayer action with your friends and sow the seeds of victory!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-2-playstation-4', 'Plants vs. Zombies: Garden Warfare 2', 'Plants vs. Zombies', '2016-02-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3xur.jpg', 'The battle for suburbia grows to crazy new heights in Plants vs. Zombies Garden Warfare 2! In this hilarious, action-packed shooter, zombie leader Dr. Zomboss has strengthened his horde and rebuilt suburbia as a zombie utopia. But hope remains, because for the first time the plants are taking the offensive in an all-out attack to reclaim their turf. Play as the plants in the all-new 24-player Herbal Assault mode, or choose your side in 4-player co-op or Solo Play!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-battle-for-neighborville-playstation-4', 'Plants vs. Zombies: Battle for Neighborville', 'Plants vs. Zombies', '2019-10-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3isd.jpg', 'Similar to its predecessors, the game is a third-person shooter where players take control of the Plants or the Zombies in either a cooperative or competitive multiplayer environment. The game features 20 customizable gameplay classes, six of which are new to the franchise, and they are classified into three groups: attackers, defenders, or support. Each camp also has a new team play class that allows players of the same class to combine forms when they fight against enemies. Players can compete against each other in various competitive multiplayer modes, including the objective-based Turf War mode and the team deathmatch variant Team Vanquish. The game also features several player-versus-environment open zones which allowed players to explore, find collectibles, and complete quests. Split-screen local multiplayer is also available for all gameplay mode', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-vr-demo-disc-playstation-4', 'PlayStation VR Demo Disc', 'PlayStation VR Demo Disc', '2016-10-13', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-vr-demo-disc-2-playstation-4', 'PlayStation VR Demo Disc 2', 'PlayStation VR Demo Disc', '2017-11-07', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-vr-demo-disc-3-playstation-4', 'PlayStation VR Demo Disc 3', 'PlayStation VR Demo Disc', '2019-01-15', 'PlayStation 4', 1, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('playstation-vr-worlds-playstation-4', 'PlayStation VR Worlds', NULL, '2016-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cf3.jpg', 'Step into PlayStation VR Worlds and journey through five unique and exclusive PlayStationVR experiences.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bridge-constructor-portal-playstation-4', 'Bridge Constructor Portal', 'Portal', '2018-02-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230j.jpg', 'Enter the Aperture Science Enrichment Center and experience Bridge Constructor Portal – the unique merging of the classic Portal and Bridge Constructor games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prison-boss-vr-playstation-4', 'Prison Boss VR', NULL, '2018-12-04', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2790.jpg', 'Prison Boss VR is a crafting and trading game using room-scale to turn your VR space into a jail cell! Craft cigarettes, alcohol and cookies for other inmates! Customize your cell as your reputation grows! Earn cash until you can’t store it anymore and become the Prison Boss!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-biohazard-bundle-playstation-4', 'Prototype Biohazard Bundle', 'Prototype', '2015-07-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s88.jpg', 'This bundle contains Prototype and Prototype 2, now remastered to offer enhanced visuals and an improved frame rate.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-in-the-rhombus-of-ruin-playstation-4', 'Psychonauts in the Rhombus of Ruin', 'Psychonauts', '2017-02-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24us.jpg', 'Psychonauts in the Rhombus of Ruin is a first-person virtual reality puzzle platform video game. The game''s story is intended to bridge the events between Psychonauts and Psychonauts 2.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-playstation-4', 'Psychonauts', 'Psychonauts', '2019-06-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7ms.jpg', 'Psychonauts is a platform-adventure game developed by Double Fine Productions and released in 2005. It follows Razputin “Raz” Aquato, a young psychic who runs away from the circus to attend a summer camp for aspiring psychonauts. Players explore imaginative levels set inside the minds of different characters, each reflecting their mental states. Gameplay combines platforming, combat, and the use of psychic abilities such as telekinesis and levitation. The game was praised for its creativity, humor, and distinctive art style.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-2-playstation-4', 'Psychonauts 2', 'Psychonauts', '2021-08-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7mx.jpg', 'Psychonauts 2 is a platform-adventure game developed by Double Fine Productions and released in 2021. It continues the story of Razputin “Raz” Aquato, a young psychic who joins the international psychic espionage agency known as the Psychonauts.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-playstation-4', 'Puyo Puyo Tetris', 'Puyo Puyo Tetris', '2017-04-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3vws.jpg', '"Two puzzle game juggernauts collide as Tetris, one of the largest-selling and recognized brands in gaming history, and Puyo Puyo from SEGA have combined to create a fun-to-play, fast-paced, competitive party game like no other! The game has tons of different styles of gameplay – from the single-player Adventure and Challenge modes to the ferocious competition of the up-to-four player Arcade modes. There''s plenty of Tetris/Puyo variety, even an in-game Shop where players can unlock new characters, new skins for Puyos and Tetriminos, new backgrounds and more."', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-2-playstation-4', 'Puyo Puyo Tetris 2', 'Puyo Puyo Tetris', '2020-12-08', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3246.jpg', 'Stack, chain, and combo your way to victory in the ultimate matching of two puzzle game legends! Pre-order now and get ready to traverse dimensions and experience brand new worlds in time for the holidays, with the PC release fast-dropping onto Steam in early 2021.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('q-u-b-e-10th-anniversary-playstation-4', 'Q.U.B.E. 10th Anniversary', 'Q.U.B.E.', '2022-09-14', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ygb.jpg', 'Entirely rebuilt from the ground up, Q.U.B.E. 10th Anniversary is the ultimate celebration of the decade-old original, bringing refined visuals, completely redesigned and revised gameplay sections, and a whole new chapter to the award-winning, brain-twisting first-person puzzler.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-playstation-4', 'Quake', 'Quake', '2021-08-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-playstation-4', 'Quake II', 'Quake', '2023-08-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-quarry-playstation-4', 'The Quarry', NULL, '2022-06-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kl4.jpg', 'It''s late summer in the remote forests of upstate New York, and the teen counselors of Hackett''s Quarry have the camp to themselves for one final night. That means no kids, no adults, and no rules. In this thrilling cinematic tale, you control the fates of all nine camp counselors as their party plans unravel into an unpredictable night of horror. With life-or-death decisions around every turn, the choices you make will determine how the story unfolds.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-invasion-the-interactive-tv-show-playstation-4', 'Rabbids Invasion: The Interactive TV Show', 'Rabbids', '2014-11-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavxt.jpg', 'Rabbids Invasion, the kids hit animated TV show, is now an interactive game on PlayStation 4. With motion gameplay, kids can now play in their living room with a selection of episodes from the TV show. Through fun, silly challenges, players have an outrageous time with family and friends and experience the Rabbids Invasion TV show in a brand new way.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rain-world-playstation-4', 'Rain World', NULL, '2017-03-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24pm.jpg', 'Rain World is a survival platformer set in an abandoned industrial environment ravaged by a shattered ecosystem. Bone-crushingly intense rains pound the surface, making life as we know it almost impossible. The creatures in this world hibernate most of the time, but in the few brief dry periods they go out in search of food.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-playstation-4', 'Ratchet & Clank', 'Ratchet & Clank', '2016-04-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230q.jpg', 'This trilogy of Ratchet & Clank classics contains Ratchet & Clank, Ratchet & Clank: Going Commando, and Ratchet & Clank: Up Your Arsenal – all remastered in 1080p with additional upgrades such as Trophy and 3D support.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-playstation-4', 'Rayman Legends', 'Rayman', '2014-02-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-2-playstation-4', 'Red Dead Redemption 2', 'Red Dead', '2018-10-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1q1f.jpg', 'Red Dead Redemption 2 is the epic tale of outlaw Arthur Morgan and the infamous Van der Linde gang, on the run across America at the dawn of the modern age.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-2-playstation-4', 'Resident Evil: Revelations 2', 'Resident Evil', '2015-03-18', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92d9.jpg', 'Resident Evil: Revelations 2 is the retail version of the episodic survival horror series that was originally released as four downloadable episodes. This physical version combines the entire story along with some extras, but not all the available DLC. The PC version did not receive a retail release, but the same content was bundled on Steam. The game comprises four episodes, each of which feature two separate stories. This sequel bears a stronger tone to the concept of survival horror than titles such as Resident Evil 5 and Resident Evil 6. Elements of ammunition management as well as stealth or sneaking come into play in the gameplay.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-origins-collection-playstation-4', 'Resident Evil Origins Collection', 'Resident Evil', '2016-01-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnx.jpg', 'Experience the early days of the outbreak in Resident Evil Origins Collection, a compilation package of two with two Resident Evil origin stories: Resident Evil 0 and Resident Evil HD . Both terrifying games have been brought to new new levels of horror with new HD visuals, improved sound, widescreen support, an optional modernized control system and more.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-6-playstation-4', 'Resident Evil 6', 'Resident Evil', '2016-03-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pyq.jpg', 'Resident Evil 6 is the ninth video game installment in the Resident Evil series. It continues the struggle against zombies infected by the new highly virulent C-virus. The game uses the same over-the-shoulder view as Resident Evil 4 and Resident Evil 5, however with a new gameplay mechanic that allows players to slowly move while shoot. Players can select between three scenarios featuring multiple characters and intertwined storylines, and within these scenarios both stories and action cross paths. At key moments during the game, up to four players can join together online to tackle a specific situation, with some stages seeing the usual partnerships swapped to further increase the depth of gameplay.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-playstation-4', 'Resident Evil 5', 'Resident Evil', '2016-06-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtgs.jpg', 'Resident Evil 5 is the seventh video game in the Resident Evil series. It features similar gameplay to Resident Evil 4 utilizing the same over the shoulder view, but this time the environment plays a significant role. The player is now dependent on his partner more than in older games. When the partner''s health bar drop down to 0, he will enter the dying stage where the health bar will flash red and gradually lower as he stays like this. Resident Evil 5 also features new types of enemies called Majini and mostly are of African descent.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-playstation-4', 'Resident Evil 4', 'Resident Evil', '2016-08-30', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wn5.jpg', 'This pack includes Resident Evil 4 and Resident Evil CODE: Veronica X.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-7-biohazard-playstation-4', 'Resident Evil 7: Biohazard', 'Resident Evil', '2017-01-24', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtwh.jpg', 'Resident Evil 7: Biohazard is the first game of the Resident Evil series to switch from 3rd-person to fully 1st-person perspective. A complete refresh of gameplay systems simultaneously propels the survival horror experience to another level. It is as much horror as it is survival, boosting up scare elements and minimizing downright shooting action. The game allows use of Sony''s PSVR Headset to play in VR mode.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-playstation-4', 'Resident Evil: Revelations', 'Resident Evil', '2017-08-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-7-biohazard-gold-edition-playstation-4', 'Resident Evil 7: Biohazard Gold Edition', 'Resident Evil', '2017-12-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fad.jpg', 'Set in modern day rural America and taking place after the dramatic events of Resident Evil 6, players experience the terror directly from the first person perspective. Resident Evil 7 embodies the series'' signature gameplay elements of exploration and tense atmosphere that first coined "survival horror" some twenty years ago; meanwhile, a complete refresh of gameplay systems simultaneously propels the survival horror experience to the next level.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-playstation-4', 'Resident Evil 2', 'Resident Evil', '2019-01-25', 'PlayStation 4', 1, 0, NULL, NULL, NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-3-playstation-4', 'Resident Evil 3', 'Resident Evil', '2020-04-03', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22l7.jpg', 'Resident Evil 3 is a remake of the original Resident Evil 3: Nemesis released in 1999. It updates the story and gameplay for a modern audience. Like the Resident Evil 2 remake, the game uses over-the-shoulder third person point of view similar to Resident Evil 4 and later installments. Players will spend most of their time playing as Jill Valentine, although on some occasions they will assume the role of Carlos Oliveira, giving him more screen time as a deuteragonist.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-village-playstation-4', 'Resident Evil Village', 'Resident Evil', '2021-05-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyw.jpg', 'A bundle including the following content:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('retro-city-rampage-dx-playstation-4', 'Retro City Rampage DX', 'Retro City Rampage', '2014-11-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2h4u.jpg', 'Open-world carjacking goes back to the ''80s in this 8-BIT nostalgic throwback.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shakedown-hawaii-playstation-4', 'Shakedown: Hawaii', 'Retro City Rampage', '2019-05-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1kyl.jpg', 'Build a "legitimate" corporation via open world missions, shakedowns, sabotage and property acquisition.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-of-the-obra-dinn-playstation-4', 'Return of the Obra Dinn', NULL, '2019-10-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27j9.jpg', 'In this 1-bit first-person mystery game, a merchant ship called the Obra Dinn has appeared at a London harbor, years after being declared lost at sea. As an insurance adjuster, the player must examine the ship for clues.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('reus-playstation-4', 'Reus', NULL, '2016-10-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co701t.jpg', 'Shape humanity with the power of the gods in Reus 2. Choose your giants, combine natural elements, and manipulate fate to guide the path of civilization. The choices are yours, and so are the consequences.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rez-infinite-playstation-4', 'Rez Infinite', 'Rez', '2016-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7koc.jpg', 'The ultimate version of Sega''s psychodelic rail-shooter adventure Rez, fully remastered and evolved, including VR support and additional new content, all by members of the original development team', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rime-playstation-4', 'Rime', NULL, '2017-05-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co84t0.jpg', 'You stumble across an old book and get trapped within its world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('robinson-the-journey-playstation-4', 'Robinson: The Journey', NULL, '2016-11-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27wh.jpg', 'Go beyond boundaries in Robinson: The Journey, a brand new virtual reality game from Crytek. Harnessing the power of CRYENGINE, Robinson: The Journey will offer players an unparalleled sense of presence in a game world as they assume the role of a young boy who has crash-landed on a mysterious planet. With freedom to explore their surroundings in 360 degrees of detail, players will become pioneers by interacting with the rich ecosystem around them and unearthing incredible secrets at every turn.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rocket-knight-adventures-re-sparked-playstation-4', 'Rocket Knight Adventures: Re-Sparked', 'Rocket Knight', '2024-06-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7na9.jpg', 'The mightiest mammal to ever rocket to stardom is back in a three-game, Carbon Engine-powered collection that includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rogue-legacy-playstation-4', 'Rogue Legacy', NULL, '2014-07-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27fi.jpg', 'You control a family of characters one at a time, and when your character dies, you choose who his or her successor is, whether it is a barbarian son of yours who has OCD, your daughter who became a ninja even though she can''t see well, an assassin who is fighting for the gays, or a miner who wants to collect gold! Traits are randomized each time upon death, leading to multiple playthroughs with 35 traits, each character will be unique.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rollercoaster-tycoon-joyride-playstation-4', 'RollerCoaster Tycoon Joyride', 'RollerCoaster Tycoon', '2018-03-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9mv1.jpg', 'Soar through the sky with RollerCoaster Tycoon Joyride, a fully immersive coaster builder, and rider exclusively for PlayStation 4 and enhanced for PlayStation VR.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('roombo-first-blood-playstation-4', 'Roombo: First Blood', NULL, '2021-02-05', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50md.jpg', 'Roombo: First Blood is a comedic, top-down, stealth-action game about being a robot vacuum cleaner and fending off burglars that have broken into your home. A Samurai Punk Short.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('salt-and-sacrifice-playstation-4', 'Salt and Sacrifice', 'Salt', '2022-05-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwoi.jpg', 'Salt and Sacrifice is a 2D action role-playing game developed by Ska Studios and released in 2022. It serves as a follow-up to Salt and Sanctuary, introducing a more open, hunt-focused structure. Players take on the role of a Marked Inquisitor tasked with tracking and defeating powerful mages across interconnected regions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sayonara-wild-hearts-playstation-4', 'Sayonara Wild Hearts', NULL, '2019-09-19', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gx1.jpg', 'Sayonara Wild Hearts is a euphoric music video dream about being awesome, riding motorcycles, skateboarding, dance battling, shooting lasers, wielding swords, and breaking hearts at 200 mph.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-showdown-playstation-4', 'Scribblenauts Showdown', 'Scribblenauts', '2018-03-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co272u.jpg', 'It’s Scribblenauts, party-style! Use your imagination and go head-to-head in the ultimate multiplayer showdown! Enjoy a party-style Scribblenauts experience, conjuring from over 35,000 objects from the vast Scribblenauts dictionary to outsmart your opponent in over 25 mini-games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-mega-pack-playstation-4', 'Scribblenauts Mega Pack', 'Scribblenauts', '2018-09-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/du7bf613i5hyjwbto3rj.jpg', 'Get the best of Scribblenauts with Scribblenauts Mega Pack! Two classic games with ALL-NEW content to explore!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-genesis-classics-playstation-4', 'Sega Genesis Classics', NULL, '2018-05-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sm8.jpg', 'The collection has over 50 retro classics to experience across every genre; arcade action, shooters, beat’em ups, puzzlers, old favourites and hidden gems, with a raft of modern features. These include online multiplayer, achievements, mirror modes, rewind and save states meaning players old and new should find revisiting these great games an absolute Sonic 3D Blast.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sekiro-shadows-die-twice-playstation-4', 'Sekiro: Shadows Die Twice', NULL, '2019-03-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2a23.jpg', 'Carve your own clever path to vengeance as you come face-to-face with larger than life foes in FromSoftware''s dark and twisted adventure set in feudal Japan. Unleash an arsenal of deadly prosthetic tools and ninja abilities, while blending stealth, vertical traversal, and visceral combat. Survive a relentless and bloody confrontation on a quest to restore your honor and save the one you''re sworn to protect.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-of-the-colossus-playstation-4', 'Shadow of the Colossus', NULL, '2018-02-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ijk.jpg', 'In a desolate land where beasts as big as mountains roam free, a lone hero and his horse must ride into the unknown on a quest for ancient power. Shadow of the Colossus, an undisputed PlayStation 2 masterpiece, is about to be reborn with the power of PlayStation 3.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-risky-s-revenge-director-s-cut-playstation-4', 'Shantae: Risky''s Revenge - Director''s Cut', 'Shantae', '2015-06-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49xa.jpg', 'Shantae: Risky’s Revenge – Director’s Cut brings hair-whipping, belly-dancing to your PC! Play one of the most critically acclaimed handheld series of all time, now with brand new features!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-pirate-s-curse-playstation-4', 'Shantae and the Pirate''s Curse', 'Shantae', '2016-04-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b1u.jpg', 'Embark on a brand new adventure with Shantae, the hair-whipping belly dancing genie. When she loses her magic, Shantae must team up with her nemesis, the nefarious pirate Risky Boots in order to save Sequin Land from an evil curse. As a pirate, Shantae gains new weapons to advance her quest, slay monsters, battle epic bosses…and hopefully get her magic back in the bargain! But can she really trust her deadliest enemy?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-half-genie-hero-playstation-4', 'Shantae: Half-Genie Hero', 'Shantae', '2016-12-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ymj.jpg', 'Shantae embarks on her first full HD adventure! After three highly successful outings with Shantae, Shantae: Risky''s Revenge, and Shantae and the Pirate''s Curse, Shantae and her friends finally get a full HD console-based sequel! Boasting vivid, detailed high-definition graphics that retain the 2D hand-drawn sprites the series is known for, this newest entry in the Shantae series almost looks like a playable TV show! Presented as a stage-based 2.5D platformer with heavy exploration elements, Shantae uses her trademark Hair-Whip Attack to dispatch enemies, then takes advantage of her Belly Dance Magic to transform into 8 different forms that each have their own unique abilities and move sets. As new forms are mastered, old stages can be re-explored to unearth new items and secrets, ensuring there''s plenty of content on offer for novices and platforming gurus alike. Topple the villainous Baron behind each criminal caper afflicting Sequin Land, and prepare for the ultimate showdown against Shantae''s arch-nemesis: that bodacious buccaneer, Risky Boots!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-seven-sirens-playstation-4', 'Shantae and the Seven Sirens', 'Shantae', '2020-05-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7csj.jpg', 'Formerly referred to as Shantae 5, Shantae and the Seven Sirens sends the belly-dancing, hair-whipping, half-genie hero to a tropical island where Shantae and her friends encounter other Half-Genie allies, but they soon learn there’s trouble in paradise. As Shantae gets caught up in the island’s sinister secrets, she’ll use all-new dance abilities and instant-transformation Fusion Magic to explore the nonlinear, interconnected world where she’ll visit multiple towns, overcome treacherous labyrinths, and battle dastardly bosses. The game also features a new collectible card system that grants players the freedom to augment Shantae’s powers to suit their own style of play.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-playstation-4', 'Shantae', 'Shantae', '2022-08-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27l6.jpg', 'Genie-girl Shantae is the self-appointed guardian of a small fishing village, Scuttle Town. Living life in a lighthouse rather than a bottle, she''s constantly on the lookout for danger. When the nefarious lady-pirate, Risky Boots catches wind of the treasure that was recently unearthed in the village, she launches an attack. To get Scuttle out of trouble, it''s up to Shantae to prove that she''s the rightful ''Guardian Genie'' to the best of her dancing, buying and hair-whipping abilities. Now crack that whip!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-advance-risky-revolution-playstation-4', 'Shantae Advance: Risky Revolution', 'Shantae', '2025-08-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaboc.jpg', 'Shantae is back in an adventure 20 years in the making! The nefarious pirate Risky Boots has a “groundbreaking” new plan that will leave Sequin Land spinning — by rotating the continent, she can move any town right to the coast for easy plundering! As Shantae, turn the tectonic tables on Risky by taking control of the land itself: shift, twist, navigate, and explore by swapping between mix-and-match multilayered levels! Hair-whip and belly-dance your way through scrambled lands, misplaced towns, monster-filled crypts, and daunting labyrinths. Six creature transformations, fierce boss battles, and a 4-player versus mode await!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shenmue-iii-playstation-4', 'Shenmue III', 'Shenmue', '2019-11-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ftj.jpg', 'Shenmue III is an action-adventure video game and the sequel to the 2001 game Shenmue II. It follows teenage martial artist Ryo Hazuki in his quest to find his father''s killer in 1980s China. In 2015, Suzuki launched a Kickstarter crowdfunding campaign to help fund Shenmue III and the campaign met its initial target of $2 million USD in under eight hours. The campaign ended in July having raised over $6 million, becoming the most funded video game in Kickstarter history.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-playstation-4', 'Shovel Knight', 'Shovel Knight', '2015-11-03', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaa7.jpg', 'Shovel Knight is a sweeping classic action adventure game with awesome gameplay, memorable characters, and an 8-bit retro aesthetic. It''s a hot mashup of new and old! You play as the eponymous Shovel Knight, a small knight with a huge quest. Shovel Knight has come to this land with two goals: to defeat the evil Enchantress and quest for his lost beloved. He wields a Shovel Blade: a multipurpose weapon whose techniques have now been lost to the ages. Always honest and helpful, Shovel Knight is a shining example of the code of Shovelry: Slash Mercilessly and Dig Tirelessly!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-treasure-trove-playstation-4', 'Shovel Knight: Treasure Trove', 'Shovel Knight', '2019-12-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gsx.jpg', 'Shovel Knight: Treasure Trove is the full and complete edition of Shovel Knight, a sweeping classic action-adventure game series with awesome gameplay, memorable characters, and an 8-bit retro aesthetic! Run, jump, and battle as Shovel Knight, wielder of the Shovel Blade, in a quest for his lost beloved. Take down the nefarious knights of the Order of No Quarter and confront their menacing leader, The Enchantress.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('signalis-playstation-4', 'Signalis', NULL, '2022-10-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ig.jpg', 'Signalis is a classic survival horror experience with a unique aesthetic, full of melancholic mystery. Investigate a dark secret, solve puzzles, fight off nightmarish creatures and navigate dystopian, surreal retrotech worlds as Elster, a technician Replika searching for her lost dreams.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-4-playstation-4', 'The Sims 4', 'The Sims', '2017-11-17', 'PlayStation 4', 0, 0, NULL, NULL, NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-playstation-4', 'Skylanders: Swap Force', 'Skylanders', '2013-11-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-playstation-4', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-playstation-4', 'Skylanders: SuperChargers', 'Skylanders', '2015-09-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsk.jpg', 'Exclusive to the Wii U version of the game is a special figure of Donkey Kong and Bowser.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-playstation-4', 'Skylanders: Imaginators', 'Skylanders', '2016-10-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('slime-rancher-playstation-4', 'Slime Rancher', 'Slime Rancher', '2018-09-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co73i2.jpg', 'Slime Rancher is a charming, first-person, sandbox experience. Play as Beatrix LeBeau: a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ''Far, Far Range.'' Each day will present new challenges and risky opportunities as you attempt to amass a great fortune in the business of slime ranching. Collect colorful slimes, grow crops, harvest resources, and explore the untamed wilds through the mastery of your all-purpose vacpack.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('slime-rancher-deluxe-edition-playstation-4', 'Slime Rancher: Deluxe Edition', 'Slime Rancher', '2020-05-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ky.jpg', 'Slime Rancher is a charming, first-person, video game experience. Play as Beatrix LeBeau: a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ‘Far, Far Range’ to stake a claim and make her fortune wrangling slimes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('song-of-the-deep-playstation-4', 'Song of the Deep', NULL, '2016-07-12', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rck.jpg', 'A metroidvania-style action-adventure game following a young girl’s quest into the unknown to find her missing father.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-forces-playstation-4', 'Sonic Forces', 'Sonic the Hedgehog', '2017-11-07', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zr8.jpg', 'Fight through a world destroyed by Dr. Eggman and a powerful new villain in Sonic Forces, the new fast-paced action platformer from the team that brought you Sonic Colors and Sonic Generations. Sonic Forces lets you speed through rolling ruined landscapes as Modern Sonic, catapult past perilous platforms as Classic Sonic, and use powerful new gadgets as your own Custom Hero Character.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-plus-playstation-4', 'Sonic Mania Plus', 'Sonic the Hedgehog', '2018-07-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wqj.jpg', 'Experience Classic and Modern Sonic in two great games -- speed through rolling landscapes in all-new 2D adventures in Sonic Mania Plus, and create your own character to take back the world from the evil Dr. Eggman in the 3D adventure, Sonic Forces!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('team-sonic-racing-playstation-4', 'Team Sonic Racing', 'Sonic the Hedgehog', '2019-05-21', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1upm.jpg', 'Team Sonic Racing combines the best elements of arcade and fast-paced competitive style racing as you face-off with friends in intense multiplayer racing.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-playstation-4', 'Sonic Mania', 'Sonic the Hedgehog', '2019-11-05', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8uho.jpg', 'Sonic Mania and Sonic PLUS is a complete overhaul of Sonic Mania and its DLC:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-colors-ultimate-playstation-4', 'Sonic Colors: Ultimate', 'Sonic the Hedgehog', '2021-09-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31a0.jpg', 'Join Sonic in the high-speed adventure of a lifetime across a colorful interstellar amusement park. Color the Universe in Sonic Colors: Ultimate!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-frontiers-playstation-4', 'Sonic Frontiers', 'Sonic the Hedgehog', '2022-11-08', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p52.jpg', 'Worlds will collide in Sonic the Hedgehog’s newest adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-origins-plus-playstation-4', 'Sonic Origins Plus', 'Sonic the Hedgehog', '2023-06-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6oez.jpg', 'Sonic Origins Plus is an updated version of Sonic Origins that includes the Plus Expansion Pack. Unlike Sonic Mania Plus, Sonic Origins Plus can be bought digitally on PC as a single purchase like the console versions, while the base game continues to be available on it''s own. Digital versions of Sonic Origins on all platforms can be upgraded to Plus by purchasing the Plus Expansion Pack separately.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-superstars-playstation-4', 'Sonic Superstars', 'Sonic the Hedgehog', '2023-10-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbw4.jpg', 'Adventure through the mystical Northstar Islands in this all-new take on classic 2D Sonic high-speed action platforming. Play as Sonic, Tails, Knuckles, and Amy Rose and harness all-new Emerald powers to move and attack in dynamic new ways. Navigate gorgeous, never-before-seen environments solo or with up to 3 other players and stop Dr. Eggman, Fang, and a mysterious new adversary from converting the islands'' giant animals into Badniks before it''s too late!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-channel-5-vr-kinda-funky-news-flash-playstation-4', 'Space Channel 5 VR: Kinda Funky News Flash!', 'Space Channel 5', '2020-02-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co235e.jpg', 'Space Channel 5 is SEGA’s legendary Dreamcast rhythm game first released 19 years ago and now brand new stories, characters, stages and sounds… NEW station 5 is going to be on the air soon! Identical twin sisters, Rookie reporters - Lou & Kee assigned to cover a breaking dance news story as your avatars. Come and experience the return of Ulala for yourselves!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-forever-playstation-4', 'Space Invaders Forever', 'Space Invaders', '2020-12-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kx6.jpg', 'Back again - arcade legend and icon of gaming history! Lighting the fuse for a gaming revolution. Space Invaders is surely one of the most famous video games of all time and was the launching pad for the video gaming revolution. The game mechanics and its design make it a game that encompasses all the very best.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spelunky-playstation-4', 'Spelunky', NULL, '2014-10-07', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47m4.jpg', 'Spelunky (also known as Spelunky HD) is a remake of Spelunky (now known as Spelunky Classic), an open source indie platformer video game created by Derek Yu and originally released as freeware for Microsoft Windows. The player controls a spelunker who explores a series of caves while collecting treasure, saving damsels, fighting enemies and dodging traps. The caves are procedurally generated, making each run through the game unique. Spelunky is one of the first examples of a roguelike-like, borrowing concepts from the roguelike genre, and was the influence for many later roguelike-like games.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spiritfarer-playstation-4', 'Spiritfarer', NULL, '2020-08-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fe7.jpg', 'Spiritfarer is a cozy management game about dying. You play Stella, ferrymaster to the deceased, a Spiritfarer. Build a boat to explore the world, then befriend and care for spirits before finally releasing them into the afterlife. Farm, mine, fish, harvest, cook, and craft your way across mystical seas. Join the adventure as Daffodil the cat, in two-player cooperative play. Spend relaxing quality time with your spirit passengers, create lasting memories, and, ultimately, learn how to say goodbye to your cherished friends. What will you leave behind?', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-reignited-trilogy-playstation-4', 'Spyro Reignited Trilogy', 'Spyro', '2018-11-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaat.jpg', 'Spyro Reignited Trilogy is a collection of remasters of the first three games in the Spyro series: Spyro the Dragon (1998), Ripto''s Rage! (1999), and Year of the Dragon (2000).', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-playstation-4', 'Star Wars Battlefront', 'Star Wars', '2015-11-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2res.jpg', 'In 2004, the original Star Wars: Battlefront came onto the scene and took gamers – and Star Wars fans – by surprise. It was an ambitious action shooter that gave players the opportunity to step into the shoes of their favorite Star Wars characters, pilot quintessential Star Wars vehicles, and relive classic Star Wars battles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-racer-revenge-playstation-4', 'Star Wars Racer Revenge', 'Star Wars', '2016-01-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1o.jpg', 'Star Wars: Racer Revenge is a Star Wars video game that involves high speed racing. It is the sequel to Star Wars Episode I: Racer. The story takes place eight years after The Phantom Menace, Sebulba wants revenge on Anakin Skywalker. Unlike its predecessor, the player is unable to continue racing if they crash their pod.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-bounty-hunter-playstation-4', 'Star Wars: Bounty Hunter', 'Star Wars', '2016-01-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8f77.jpg', 'Experience the legendary Bounty Hunter fantasy set before the events of Star Wars: Episode II - Attack of the Clones. Face off against foes and maneuver through acrobatic battles in this adaption optimized for today''s consoles and hardware.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-ii-playstation-4', 'Star Wars Battlefront II', 'Star Wars', '2017-11-17', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1g4.jpg', 'Star Wars: Battlefront II is the sequel to Star Wars: Battlefront. It is a high-selling Star Wars video game following the many adventures of several characters. The two games are very similar, as both revolve around troopers from various factions fighting in different locales. Battlefront II, however, includes elements and missions from Star Wars: Episode III Revenge of the Sith, as well as enhanced aspects of gameplay including space combat and the ability to play as Jedi characters or other heroes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-ii-jedi-outcast-playstation-4', 'Star Wars Jedi Knight II: Jedi Outcast', 'Star Wars', '2019-09-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y67.jpg', 'In the tradition of the highly acclaimed Star Wars: Jedi Knight series, Star Wars: Jedi Knight 2, Jedi Outcast features rebel agent Kyle Katarn in exhilarating first-person action. Several years have passed since Kyle avenged his father''s death and saved the Valley of the Jedi from Jerec and his band of Dark Jedi. Allowing his Force powers to languish for fear of falling to the dark side, Kyle entrusted his lightsaber to Luke Skywalker, vowing never to use it again. But when a new and menacing threat to the galaxy emerges, Kyle knows he must reclaim his past in order to save his future.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-fallen-order-playstation-4', 'Star Wars Jedi: Fallen Order', 'Star Wars', '2019-11-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbi.jpg', 'Star Wars Jedi: Fallen Order is a narratively driven, single-player game puts you in the role of a Jedi Padawan who narrowly escaped the purge of Order 66 following the events of Episode III: Revenge of the Sith. On a quest to rebuild the Jedi Order, you must pick up the pieces of your shattered past to complete your training, develop new powerful Force abilities and master the art of the iconic lightsaber - all while staying one step ahead of the Empire and its deadly Inquisitors.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-jedi-academy-playstation-4', 'Star Wars Jedi Knight: Jedi Academy', 'Star Wars', '2020-03-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5c44.jpg', 'Star Wars: Jedi Knight: Jedi Academy, of the highly acclaimed Jedi Knight series, allows players to take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker. Interact with famous Star Wars characters in many classic Star Wars locations as you face the ultimate choice: fight for good and freedom on the light side, or follow the path of power and evil to the dark side.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-racer-playstation-4', 'Star Wars Episode I: Racer', 'Star Wars', '2020-06-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wj7.jpg', 'Star Wars: Episode 1 - Racer lets you participate in the famous pod race sequence that was the critical highlight of the film Star Wars: Episode I, The Phantom Menace back in 1999.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('vader-immortal-a-star-wars-vr-series-playstation-4', 'Vader Immortal: A Star Wars VR Series', 'Star Wars', '2020-08-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31db.jpg', 'Step inside a galaxy far, far away with Vader Immortal: A Star Wars VR Series. You are a smuggler operating near Mustafar, the fiery world Darth Vader calls home. When you are unexpectedly pulled out of hyperspace, you find yourself uncovering an ancient mystery at the behest of the Sith Lord himself.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-squadrons-playstation-4', 'Star Wars: Squadrons', 'Star Wars', '2020-10-02', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wlz.jpg', 'Master the art of starfighter combat in the authentic piloting experience STAR WARS: Squadrons. Buckle up, feel the adrenaline of first-person multiplayer space dogfights alongside your squadron, and learn what it means to be a pilot in a thrilling STAR WARS single-player campaign.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-republic-commando-playstation-4', 'Star Wars: Republic Commando', 'Star Wars', '2021-04-06', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2au4.jpg', 'Chaos has erupted throughout the galaxy. As a leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihalate the enemy. Your squad will follow your orders and your lead, working together as a team-instinctively, intelligently, instantly. You are their leader. They are your weapon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stardew-valley-playstation-4', 'Stardew Valley', NULL, '2016-12-13', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa93h.jpg', 'Stardew Valley is an open-ended country-life RPG! You’ve inherited your grandfather’s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home? It won’t be easy. Ever since Joja Corporation came to town, the old ways of life have all but disappeared. The community center, once the town’s most vibrant hub of activity, now lies in shambles. But the valley seems full of opportunity. With a little dedication, you might just be the one to restore Stardew Valley to greatness!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('starlink-battle-for-atlas-playstation-4', 'Starlink: Battle for Atlas', NULL, '2018-10-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pm8.jpg', 'Starlink: Battle for Atlas is an all-new action-adventure game developed by Ubisoft Toronto. This deep, open-world space saga features Smart Building Technology empowering players to assemble and customize real-world physical starships. Each part attached to the starship appears instantly in-game and players can experiment with different pilot abilities, weapon types, and status effects and unleash devastating combos upon their enemies.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stray-playstation-4', 'Stray', NULL, '2022-07-19', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaa4c.jpg', 'A fantasy tactical RPG where you command over 70 characters across grid-based battles. Customize skills, unleash flashy Spell Cards, and enjoy rich animations in a strategic, story-driven adventure set in the world of Touhou.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('subnautica-playstation-4', 'Subnautica', 'Subnautica', '2018-12-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x8n.jpg', 'Combining the award-winning game Subnautica with its unreleased sequel Subnautica Below Zero, this Nintendo Switch exclusive allows players to fully immerse themselves in the full mystery surrounding the water world of planet 4546B. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive in both hostile water zones and frozen terrains.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('subnautica-below-zero-playstation-4', 'Subnautica: Below Zero', 'Subnautica', '2021-05-14', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x8n.jpg', 'Combining the award-winning game Subnautica with its unreleased sequel Subnautica Below Zero, this Nintendo Switch exclusive allows players to fully immerse themselves in the full mystery surrounding the water world of planet 4546B. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive in both hostile water zones and frozen terrains.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('new-super-lucky-s-tale-playstation-4', 'New Super Lucky''s Tale', 'Super Lucky''s Tale', '2020-08-21', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ehd.jpg', 'Leap into a Playful Platforming Adventure for all ages!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-meat-boy-playstation-4', 'Super Meat Boy', 'Super Meat Boy', '2015-10-06', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5t36.jpg', 'Super Meat Boy Handheld! is Super Meat Boy for the iPhone... kinda.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-meat-boy-forever-playstation-4', 'Super Meat Boy Forever', 'Super Meat Boy', '2021-04-16', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qlr.jpg', 'Meat Boy and Bandage Girl have grown as a couple since 2010. It seems like only yesterday the two love birds were escaping from an exploding laboratory in the sky. Now it’s the current year, and they’ve welcomed their daughter Nugget into the world. Their peaceful days enjoying life as a family came to an abrupt end when Dr. Fetus beat the snot out of them with a rusty shovel, and kidnapped Nugget! Now it’s up to Meat Boy and Bandage Girl to rescue their daughter from a lunatic fetus in a jar that can only be described as an incel version of Tony Stark.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-blitz-hd-playstation-4', 'Super Monkey Ball: Banana Blitz HD ', 'Super Monkey Ball', '2019-10-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uh1.jpg', 'Hold onto your bananas, because Super Monkey Ball: Banana Blitz HD is rolling your way! Experience the magic of one of the most beloved titles in the series, now remastered in HD!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-mania-playstation-4', 'Super Monkey Ball Banana Mania', 'Super Monkey Ball', '2021-10-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaeop.jpg', 'Super Monkey Ball: Banana Mania is a "modern HD remaster" of Super Monkey Ball, Super Monkey Ball 2, and Super Monkey Ball Deluxe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-swapper-playstation-4', 'The Swapper', NULL, '2014-08-05', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coatev.jpg', 'The Swapper is a short puzzle platformer where you must complete every puzzle and collect 124 orbs, in groups of 3 and 9 later on, to complete the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tacoma-playstation-4', 'Tacoma', NULL, '2018-05-08', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tge.jpg', 'Tacoma is a sci-fi narrative adventure set aboard a high-tech space station in the year 2088. Explore every detail of how the station''s crew lived and worked, finding the clues that add up to a gripping story of trust, fear, and resolve in the face of disaster.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-zestiria-playstation-4', 'Tales of Zestiria', 'Tales', '2015-10-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rdq.jpg', 'Tales of Zestiria is a Japanese role-playing game. It is the fifteenth main entry in the Tales series. As with previous entries in the Tales series, the game uses a variation of the action-based Linear Motion Battle System, with additional elements including a navigable open world, and the ability for certain characters to fuse into a single entity in battle to deliver powerful attacks. The story follows Sorey, a young man blessed with powers by a mystical spirit race known as the Seraphim who act as a stabilizing force in the land, as he travels to free the land of Glenwood from the threat of the Hellion, creatures spawned by negative emotions.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-berseria-playstation-4', 'Tales of Berseria', 'Tales', '2017-01-24', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rk1.jpg', 'In Tales Of Berseria players embark on a journey as they assume the role of Velvet, a young woman whose once gentle nature has been replaced and overcome with a festering anger and hatred after a traumatic experience three years prior to the events within Tales Of Berseria imbued her left hand with a special ability. Along her journey, Velvet will meet a whole cast of characters, including a young boy named Laphicet. If Velvet is the embodiment of "darkness," then Laphicet is created in the image of "light" and will be an important ally to Velvet.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-vesperia-definitive-edition-playstation-4', 'Tales of Vesperia: Definitive Edition', 'Tales', '2019-01-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gb5.jpg', 'Tales of Vesperia: Definitive Edition is a remaster of the expanded Playstation 3 port of the original game, which was exclusive to Japan.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-arise-playstation-4', 'Tales of Arise', 'Tales', '2021-09-10', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ls2.jpg', 'On the planet Dahna, reverence has always been given to Rena--the planet in the sky--as a land of the righteous and divine. Stories handed down for generations became truth and masked reality for the people of Dahna. For 300 years, Rena has ruled over Dahna, pillaging the planet of its resources and stripping people of their dignity and freedom.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-talos-principle-deluxe-edition-playstation-4', 'The Talos Principle: Deluxe Edition', 'The Talos Principle', '2015-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9diw.jpg', 'The Talos Principle is a philosophical first-person puzzle game from Croteam, the creators of the Serious Sam series, and written by Tom Jubert (FTL, The Swapper) and Jonas Kyratzes (Infinite Ocean). Players are tasked with solving a series of increasingly difficult and complex puzzles woven into a metaphysical parable about intelligence and meaning in an inevitably doomed world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tearaway-unfolded-playstation-4', 'Tearaway Unfolded', 'Tearaway', '2015-09-08', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nfd.jpg', 'Journey through a vibrant, living papery world, with a plucky messenger who has a unique message to deliver - to you! Choose to guide either atoi or iota on this adventure, each a bold courier with an expressive personality and a unique message for you locked away inside their envelope head. In order to read it though, they''re going to need your help to deliver it!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('telling-lies-playstation-4', 'Telling Lies', NULL, '2020-04-28', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ryq.jpg', 'Four private lives. One big lie. Search through secretly recorded video conversations to discover the truth. The successor to the acclaimed Her Story.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-playstation-4', 'Terraria', NULL, '2014-11-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teslagrad-playstation-4', 'Teslagrad', NULL, '2015-04-14', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6eo7.jpg', 'Teslagrad 2 is the sequel to the original Teslagrad, developed by Rain Games and released in 2023. This 2D puzzle platformer builds upon the magnetic and electrical mechanics of its predecessor, with players once again using these abilities to solve puzzles and traverse complex environments. Set in a new region, the game introduces new powers, enemies, and challenges, while maintaining the visual storytelling and atmospheric design characteristic of the series.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-effect-playstation-4', 'Tetris Effect', 'Tetris', '2018-11-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kfy.jpg', 'Named after a real-world phenomenon where players'' brains are so engrossed that images of the iconic falling Tetrimino blocks linger in their vision, thoughts, and even dreams, Tetris Effect amplifies this magical feeling of total immersion by surrounding you with fantastic, fully three-dimensional worlds that react and evolve based on how you play. Music, backgrounds, sounds, special effects - everything, down to the Tetris pieces themselves, pulse, dance, shimmer, and explode in perfect sync with how you''re playing.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-effect-connected-playstation-4', 'Tetris Effect: Connected', 'Tetris', '2021-08-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7kus.jpg', 'Tetris Effect: Connected adds an all-new robust multiplayer expansion to the huge variety of addictive and innovative single-player modes that Tetris Effect is known for. Connect and play with or against each other in all-new modes like "Zone Battle," which shakes up traditional 1-on-1 Tetris gameplay via the time-stopping Zone mechanic, or try the innovative co-op of "Connected" mode, where up to three players can literally connect their Tetris playfields together and play as one, as they work together to take down a series of increasingly-challenging CPU-controlled bosses.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thief-playstation-4', 'Thief', 'Thief', '2014-02-25', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rom.jpg', 'In the third instalment of the Thief series, master-thief Garrett is contacted by Keeper Artemus with a mission to steal two valuable artefacts. At the same time, Garrett learns about a prophecy: the coming of a Dark Age. He embarks upon a journey to unravel a mystery that threatens the existence of the order of Keepers. Is it possible that there is a traitor in their midst?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thimbleweed-park-playstation-4', 'Thimbleweed Park', NULL, '2017-08-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wq3.jpg', 'Thimbleweed Park is the curious story of two washed up detectives investigating a dead body found in the river just outside of town. It''s a game where you switch between five playable characters while uncovering the dark, satirical and bizarre world of Thimbleweed Park.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thomas-was-alone-playstation-4', 'Thomas Was Alone', NULL, '2014-11-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ak5.jpg', 'Thomas Was Alone is an indie minimalist 2D platformer about friendship and jumping and floating and anti-gravity. Guide a group of rectangles through a series of obstacles, using their different skills together to get to the end of each environment.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thumper-playstation-4', 'Thumper', NULL, '2016-10-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4e.jpg', 'Thumper is a rhythm violence game. It combines classic rhythm-action with breakneck speed and brutal physicality.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('titanfall-2-playstation-4', 'Titanfall 2', 'Titanfall', '2016-10-28', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/fhbeilnghyhhmjqhinqa.jpg', 'Titanfall 2 will deliver a crafted experience that explores the unique bond between man and machine. Playable offline, the single player campaign in Titanfall 2 will let fans step out onto the Frontier as a Militia rifleman with aspirations of becoming an elite Pilot. Stranded behind enemy lines and facing overwhelming odds, players must team up with a veteran Titan to uphold a mission they were never meant to carry out.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('to-the-top-playstation-4', 'To the Top', NULL, '2017-05-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa2le.jpg', 'Top Gun: Firestorm was developed by Fluid Studios and published by Titus Interactive in 2001 for Game Boy Color, and the following year for Game Boy Advance. It is an Isometric flight action game with missions to complete.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toejam-earl-back-in-the-groove-playstation-4', 'ToeJam & Earl: Back in the Groove', 'ToeJam & Earl', '2019-03-01', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1i1e.jpg', 'ToeJam and Earl have crash-landed back on Earth in ToeJam and Earl: Back in the Groove!, a funky fresh rogue-like adventure infused with old skool hip-hop and jam packed with awesome throwbacks to the 1991 classic.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toki-tori-2-playstation-4', 'Toki Tori 2+', 'Toki Tori', '2016-02-23', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1of8.jpg', 'Toki Tori 2 is a puzzle adventure game in which you explore a lush forest island inhabited by strange creatures. Whistle and stomp to influence their behavior, and solve the puzzles. But what''s up with that black goo? It''s threatening your home world!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-definitive-edition-playstation-4', 'Tomb Raider: Definitive Edition', 'Tomb Raider', '2014-01-28', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co268v.jpg', 'Tomb Raider: Definitive Edition is a re-release of Tomb Raider, developed by Crystal Dynamics and published by Square-Enix for the Playstation 4 and the Xbox One. The game is optimized for next-gen consoles, with the help of outside developers including United Front Games and Nixxes Software.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rise-of-the-tomb-raider-playstation-4', 'Rise of the Tomb Raider', 'Tomb Raider', '2016-10-11', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rqa.jpg', 'Join Lara Croft on her first great tomb raiding expedition as she seeks to discover the secret of immortality. Featuring high-octane action set in the most beautiful and hostile environments on earth, Rise of the Tomb Raider delivers cinematic survival action-adventure.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-of-the-tomb-raider-playstation-4', 'Shadow of the Tomb Raider', 'Tomb Raider', '2018-09-14', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3hec.jpg', NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('transistor-playstation-4', 'Transistor', NULL, '2014-05-20', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob23o.jpg', 'An unconventional tactical action RPG in which after a powerful group called the Camerata cause measureless destruction through the ambiguous settlement of Cloudbank, Red, a famous singer in the city, goes on a journey along with her lover who is trapped inside the Transistor, a powerful machine with mysterious properties, to get to the bottom of the situation and get her lost voice back.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('trover-saves-the-universe-playstation-4', 'Trover Saves the Universe', NULL, '2019-05-31', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v3y.jpg', 'Wonderful. Your dogs have been dognapped by a beaked lunatic who stuffed them into his eye holes and is using their life essence to destroy the universe. Does that make any sense? You''ve partnered with Trover, a little purple eye hole monster to save them. Find power babies and plug them into his eye holes so that he can absorb their power, track down Glorkon, and save your dogs (and the Universe).', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tunic-playstation-4', 'Tunic', NULL, '2022-09-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/td1t8kb33gyo8mvhl2pc.jpg', 'Tunic is an action adventure about a tiny fox in a big world. Explore the wilderness, discover spooky ruins, and fight terrible creatures from long ago.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-playstation-4', 'Turok', 'Turok', '2021-02-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2699.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-2-seeds-of-evil-playstation-4', 'Turok 2: Seeds of Evil', 'Turok', '2021-02-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zcg.jpg', 'The Amaranthine Accordance is trying to bring a massive Dinosoid army to Earth from the Lost Land in an effort to restore dinosaurs to their rightful home.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-3-shadow-of-oblivion-playstation-4', 'Turok 3: Shadow of Oblivion', 'Turok', '2023-11-30', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7fpt.jpg', 'Turok 3: Shadow of Oblivion is a faithful restoration of the classic first-person shooter originally released in 2000 for the Nintendo 64, upgraded through Nightdive Studios’ proprietary KEX Engine for play on modern gaming devices with up to a 4K resolution at 120FPS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('typoman-revised-playstation-4', 'Typoman: Revised', NULL, '2017-02-21', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4i.jpg', 'Typoman is a 2D puzzle platformer. You slip into the role of a character made of letters, struggling to make your way through a dark and hostile world. Despite your small stature you have a powerful gift: You can use words to alter your environment. But choose your words wisely. They can either be a blessing... or a curse!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-the-nathan-drake-collection-playstation-4', 'Uncharted: The Nathan Drake Collection', 'Uncharted', '2015-10-09', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tps.jpg', 'Uncharted: The Nathan Drake Collection is a remastered compilation of the action-adventure shooter platform video games Drake''s Fortune, Among Thieves, and Drake''s Deception. Ported by Bluepoint Games, the collection was released exclusively for the PlayStation 4 on October 7, 2015 in Europe and October 9th, 2015 in North America.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-4-a-thief-s-end-playstation-4', 'Uncharted 4: A Thief''s End', 'Uncharted', '2016-05-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7h.jpg', 'Several years after his last adventure, retired fortune hunter, Nathan Drake, is forced back into the world of thieves. With the stakes much more personal, Drake embarks on a globe-trotting journey in pursuit of a historical conspiracy behind a fabled pirate treasure. His greatest adventure will test his physical limits, his resolve, and ultimately what he''s willing to sacrifice to save the ones he loves.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-the-lost-legacy-playstation-4', 'Uncharted: The Lost Legacy', 'Uncharted', '2017-08-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tp9.jpg', 'From the critically acclaimed developer, Naughty Dog, comes the first standalone adventure in the Uncharted series. Fan-favorite character, Chloe Frazer, must enlist the aid of renowned mercenary Nadine Ross from Uncharted 4: A Thief’s End in order to recover a fabled ancient Indian artifact and keep it out of the hands of a ruthless war profiteer. Together, they’ll venture deep into the mountains of India in search of the legendary artifact. Along the way, they’ll learn to work together to unearth the mystery of the artifact, fight their way through fierce opposition, and prevent the region from falling into chaos.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('undertale-playstation-4', 'Undertale', NULL, '2017-08-15', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unpacking-playstation-4', 'Unpacking', NULL, '2022-05-10', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2879.jpg', 'Unpacking is a job-simulator game about inspecting packages, deciding if they are accepted or denied depending on the rules of that day and doing different procedures for each package.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unsighted-playstation-4', 'Unsighted', NULL, '2021-09-30', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3bt4.jpg', 'Traverse Arcadia your way. Save your friends. Time is ticking.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('until-dawn-playstation-4', 'Until Dawn', 'Until Dawn', '2015-08-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1weo.jpg', 'In Dawn of War III you will have no choice but to face your foes when a catastrophic weapon is found on the mysterious world of Acheron.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('until-dawn-rush-of-blood-playstation-4', 'Until Dawn: Rush of Blood', 'Until Dawn', '2016-10-13', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2afs.jpg', 'Descend into madness
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-inpatient-playstation-4', 'The Inpatient', 'Until Dawn', '2018-01-23', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob521.jpg', 'A twisting tale of terror. Life and death decisions
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('untitled-goose-game-playstation-4', 'Untitled Goose Game', NULL, '2019-12-17', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vqc.jpg', 'It''s a lovely morning in the village and you are a horrible goose.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('vampyr-playstation-4', 'Vampyr', NULL, '2018-06-05', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8lrg.jpg', 'London, 1918. You are newly-turned Vampyr Dr. Jonathan Reid. As a doctor, you must find a cure to save the city’s flu-ravaged citizens. As a Vampyr, you are cursed to feed on those you vowed to heal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('volume-playstation-4', 'Volume', NULL, '2015-08-18', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobn3i.jpg', NULL, 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-complete-first-season-plus-400-days-playstation-4', 'The Walking Dead: The Complete First Season Plus 400 Days', 'The Walking Dead', '2014-10-14', 'PlayStation 4', 0, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-season-two-playstation-4', 'The Walking Dead: Season Two', 'The Walking Dead', '2014-10-21', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k36.jpg', 'Similar to the previous season, The Walking Dead: Season Two is a point-and-click adventure game. The player, in control of Clementine, can direct the character around the environment, examine and interact with various scenery elements and collect and use objects to advance the story. The player can also initiate conversations with non-player characters via conversation trees. Certain replies from other characters may offer the player multiple choices to select from, including the option to stay silent, with a limited amount of time to make the selection; if the player does not select an option, the conversation will continue as if they had stayed quiet. Such choices can affect how the other characters will later react to Clementine which can influence later events in the story. Other scenes are more action-oriented, requiring the player to complete quick time events to avoid Clementine or her allies from getting killed. If the player fails these events, the game will restart at the start of such scenes. Such action scenes may also require the player to make a key decision within a limited time frame, such as which of two characters to save from attacking walkers.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-telltale-series-a-new-frontier-playstation-4', 'The Walking Dead: The Telltale Series A New Frontier', 'The Walking Dead', '2017-02-07', 'PlayStation 4', 0, 0, NULL, NULL, NULL, NULL, 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-final-season-playstation-4', 'The Walking Dead: The Final Season', 'The Walking Dead', '2019-03-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v9y.jpg', 'After years on the road facing threats both living and dead, a secluded school might finally be Clementine and AJ''s chance for a home. But protecting it will mean sacrifice. In this gripping, emotional final season, your choices define your relationships, shape your world, and determine how Clementine''s story ends.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-telltale-definitive-series-playstation-4', 'The Walking Dead: The Telltale Definitive Series', 'The Walking Dead', '2019-09-10', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7axc.jpg', 'The Walking Dead: The Telltale Definitive Series contains all 4 Seasons and The Walking Dead: Michonne, which includes over 50 hours of gameplay across 23 unique episodes. With graphical enhancements, behind the scenes bonus features and faithful recreations of classic menus, this is the definitive way to experience Clementine''s journey and find out how her story ends.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wandersong-playstation-4', 'Wandersong', NULL, '2019-01-22', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1oey.jpg', 'Wandersong takes you on a whimsical, musical journey across the globe. Eons ago, the goddess Eya put the universe into motion with her music--now, as she does every epoch or so, she''s going to sing a new song and reset existence. You play as a lowly bard tasked with finding the pieces of a mysterious melody called the Earthsong, which is said to be able to preserve the planet. Use your singing to help characters, solve puzzles, and save the world!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-playstation-4', 'Watch Dogs', 'Watch Dogs', '2014-05-27', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j2m.jpg', 'Purchase the Watch Dogs and Watch Dogs 2 bundle and gain access to these award-winning titles at a great price. In Watch Dogs, become Aiden Pearce and hack your way around Chicago to take down ctOS. In Watch Dogs 2, join Marcus Holloway and the Dedsec hacker group to expose a new digital conspiracy.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-2-playstation-4', 'Watch Dogs 2', 'Watch Dogs', '2016-11-15', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2p3j.jpg', 'Explore a massive and dynamic open world offering an incredible variety of gameplay possibilities. Hack your way through traffic while you engage in dangerous car chases through the winding streets of San Francisco, traverse the rooftops of the colorful and vibrant neighborhoods of Oakland, and infiltrate the cutting-edge offices of Silicon Valley companies. There are many secrets to uncover in the birthplace of the tech revolution.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-legion-playstation-4', 'Watch Dogs: Legion', 'Watch Dogs', '2020-10-29', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyq.jpg', 'In Watch Dogs: Legion, near future London is facing its downfall... Unless you do something about it. Build a resistance, fight back, and give the city back to the people. It''s time to rise up.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wattam-playstation-4', 'Wattam', NULL, '2019-12-17', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2600.jpg', 'From the creator behind Noby Noby Boy and Katamari Damacy comes Wattam - Long ago, a huge explosion blasted the world of Wattam across the galaxy. Help the Mayor build stacks and chains with characters like Sushi, Flower, Cloud & Poop to create joyful, colorful explosions that will guide the diaspora of Wattam back home.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-way-out-playstation-4', 'A Way Out', NULL, '2018-03-23', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fc6.jpg', 'Milky Way Prince: The Vampire Star is a visual novel that explores themes of abuse, idealization, and intimacy within a romantic relationship. Players experience a summer of dysfunctional love through branching storylines, unexpected twists, and a unique mechanic that allows selection of sensory interactions with the protagonist’s boyfriend.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('what-remains-of-edith-finch-playstation-4', 'What Remains of Edith Finch', NULL, '2017-04-25', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbj.jpg', 'What Remains of Edith Finch is a collection of short stories about a cursed family in Washington State.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-new-order-playstation-4', 'Wolfenstein: The New Order', 'Wolfenstein', '2014-05-20', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c0.jpg', 'Wolfenstein: The New Order is an action-adventure shooter game played from a first-person perspective. It is the semi-sequel to 2009''s Wolfenstein, however utilizes very little from the game and drops any direct references to veil or supernatural.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-old-blood-playstation-4', 'Wolfenstein: The Old Blood', 'Wolfenstein', '2015-07-21', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21et.jpg', 'Wolfenstein: The Old Blood is a prequel to the critically acclaimed first-person action-adventure shooter, Wolfenstein: The New Order. The adventure, which spans eight chapters and two interconnected stories, features the hallmarks of MachineGames – thrilling action, immersive story and intense first-person combat. As war hero B.J. Blazkowicz, arm yourself with new weapons such as the bolt-action rifle and grenade-launching Kampfpistole as you attempt to thwart the advancing Nazi war machine, and take advantage of duel-wielding pipes that can be used for wall climbing – or for vicious take-downs of never-before-seen Nazi adversaries.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-ii-the-new-colossus-playstation-4', 'Wolfenstein II: The New Colossus', 'Wolfenstein', '2017-10-27', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-youngblood-playstation-4', 'Wolfenstein: Youngblood', 'Wolfenstein', '2019-07-26', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21by.jpg', 'Wolfenstein: Youngblood is a brand-new co-op experience from MachineGames, the award-winning studio that developed the critically acclaimed Wolfenstein II: The New Colossus.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-cyberpilot-playstation-4', 'Wolfenstein: Cyberpilot', 'Wolfenstein', '2019-07-26', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21er.jpg', 'Experience the world of Wolfenstein from a whole new perspective in Cyberpilot VR, a virtual reality gaming experience from MachineGames.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-the-dragon-s-trap-playstation-4', 'Wonder Boy: The Dragon''s Trap', 'Wonder Boy', '2017-04-18', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4q.jpg', 'A modern version of cult classic Wonder Boy: The Dragon''s Trap! A close collaboration between Lizardcube, DotEmu and legendary series creator Ryuichi Nishizawa, based on Westone Bit Entertainment''s original masterpiece.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-boy-and-the-cursed-kingdom-playstation-4', 'Monster Boy and the Cursed Kingdom', 'Wonder Boy', '2018-12-04', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27mg.jpg', 'A legendary game series returns with an all-new adventure! Monster Boy is a colourful side-scrolling action adventure created in cooperation with Ryuichi Nishizawa, the creator of the Wonder Boy Monster World series (Trademark of SEGA Corporation Japan).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wonderful-101-remastered-playstation-4', 'The Wonderful 101: Remastered', 'The Wonderful 101', '2020-05-19', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nnf.jpg', 'Get ready for a unique side-scrolling experience in the world of The Wonderful 101: Remastered! This free DLC lets you enjoy a brand new episode in which you experience Luka''s story!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neo-the-world-ends-with-you-playstation-4', 'Neo: The World Ends With You', 'The World Ends with You', '2021-07-27', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kzv.jpg', 'Explore a stylized recreation of Shibuya, as you take on the role of Rindo to battle for survival and unravel the mysteries of the deadly “Reaper’s Game” in this new Action RPG and follow-up to the classic RPG hit "The World Ends with You."', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-to-the-west-playstation-4', 'World to the West', NULL, '2017-03-16', 'PlayStation 4', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbrz.jpg', 'In the game Wild West World, you must build an economic empire during the Wild West. Buy farms and ranches and try and drive your competition out of business by whatever means possible.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoku-s-island-express-playstation-4', 'Yoku''s Island Express', NULL, '2018-05-29', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob89x.jpg', 'Yoku’s Island Express is an open world/metroidvania-style pinball adventure, Seamlessly blending platform navigation with pinball mechanics across a large open world. Yoku the dung beetle sets foot on the beach of Mokumana Island, ready to take on the duties as the new postman. But the ancient island God is trapped in a restless sleep and the islanders are plagued by quakes and storms brought forth by its nightmares. Yoku''s Island Express is a unique and quirky adventure with handcrafted visuals, where you''ll soar through the air, vacuum explosive snails, fight a Screetch, feed starving lemurs, discover the mystery of the Fruit Altar, wake an old god, and hopefully help tiny Yoku rebuild the island post-office.', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-playstation-4', 'Yooka-Laylee', 'Yooka-Laylee', '2017-04-11', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4v.jpg', 'Explore huge, beautiful worlds, meet (and beat) an unforgettable cast of characters and horde a vault-load of shiny collectibles as buddy-duo Yooka (the green one) and Laylee (the wisecracking bat with the big nose) embark on an epic adventure to thwart corporate creep Capital B and his devious scheme to absorb all the world’s books… and convert them into pure profit!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-and-the-impossible-lair-playstation-4', 'Yooka-Laylee and the Impossible Lair', 'Yooka-Laylee', '2019-10-08', 'PlayStation 4', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2z9b.jpg', 'Yooka and Laylee are back for a brand new adventure! Get ready for the ultimate challenge - the Impossible Lair!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-the-2nd-runner-m-rs-playstation-4', 'Zone of the Enders: The 2nd Runner M∀RS', 'Zone of the Enders', '2018-09-04', 'PlayStation 4', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3od1.jpg', 'Relive the experience Zone of The Enders: The 2nd Runner M∀RS as a full-length remaster of the classic fast-paced 3D robot action game, recreated in VR, native 4K and in full surround sound. Enter Jehuty’s cockpit and fly through martian skies!', 'NA', 34);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alan-wake-remastered-playstation-5', 'Alan Wake Remastered', 'Alan Wake', '2021-10-05', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65aa.jpg', 'Alan Wake Remastered is an updated version of the original psychological horror action-adventure game developed by Remedy Entertainment. The game retains the core narrative, which follows bestselling thriller novelist Alan Wake as he struggles with writer''s block. He visits the small town of Bright Falls with his wife, Alice, in search of inspiration. Shortly after their arrival, Alice mysteriously disappears.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('among-us-crewmate-edition-playstation-5', 'Among Us: Crewmate Edition', 'Among Us', '2021-12-21', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wwy.jpg', 'Play online with 4-15 players as you attempt to hold your spaceship together and return back to civilization. But beware... as there may be an alien impostor aboard!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('animal-well-playstation-5', 'Animal Well', NULL, '2024-05-09', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hdh.jpg', 'What lurks beneath the surface of this deceptively minimalistic adventure? In Animal Well there is more than what you see. Explore a dense interconnected labyrinth, and unravel its many secrets. Collect items to manipulate your environment in surprising and meaningful ways. Encounter creatures both beautiful and unsettling, and try to survive what lurks in the dark.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('another-crab-s-treasure-playstation-5', 'Another Crab''s Treasure', NULL, '2024-04-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coam1a.jpg', 'Take a peek at the very first build of Another Crab''s Treasure made back in Feb of 2021!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('apico-playstation-5', 'Apico', NULL, '2022-09-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48vu.jpg', 'Apico is a laid-back beekeeping sim game about breeding, collecting, & conserving bees! Set in a series of lush environments, Apico uniquely combines resource gathering, biology, and beekeeping minigames, taking ideas from a mix of real-life and fantasy apiculture & floriculture.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('armored-core-vi-fires-of-rubicon-playstation-5', 'Armored Core VI: Fires of Rubicon', 'Armored Core', '2023-08-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coan1v.jpg', 'By combining FromSoftware’s longstanding expertise in mech games and their signature robust gameplay, Armored Core VI: Fires of Rubicon will be a new action experience.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arzette-the-jewel-of-faramore-playstation-5', 'Arzette: The Jewel of Faramore', NULL, '2024-02-14', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ryw.jpg', 'Arzette: The Jewel of Faramore is a new interactive animated adventure, where players must help Arzette save the Kingdom of Faramore from the evil demon king, Daimur. It is a spiritual successor to a pair of infamous fantasy adventure titles, being developed by Seedy Eye Software and both funded & published by Limited Run Games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-valhalla-playstation-5', 'Assassin''s Creed Valhalla', 'Assassin''s Creed', '2020-11-12', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ed3.jpg', 'In Assassin''s Creed Valhalla, become Eivor, a legendary Viking raider on a quest for glory. Explore a dynamic and beautiful open world set against the brutal backdrop of England’s Dark Ages. Raid your enemies, grow your settlement, and build your political power in the quest to earn a place among the gods in Valhalla.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('astro-bot-playstation-5', 'Astro Bot', 'Astro Bot', '2024-09-06', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coba3k.jpg', 'Buckle up for some epic PlayStation camaraderie, join forces with your favourite PlayStation icons and show the universe that small is mighty in this fresh new Astro adventure, exclusive to PS5 consoles!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-1-playstation-5', 'Atari Recharged Collection 1', 'Atari Recharged', '2023-11-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cnf.jpg', 'Atari Recharged Collection 1 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-2-playstation-5', 'Atari Recharged Collection 2', 'Atari Recharged', '2023-11-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8cng.jpg', 'Atari Recharged Collection 2 is on a region-free physical cart for the PlayStation 5, Nintendo Switch and PlayStation 4.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-3-playstation-5', 'Atari Recharged Collection 3', 'Atari Recharged', '2024-01-07', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaekx.jpg', 'The Atari Recharged Collection 3 includes Yars: Recharged and Caverns of Mars: Recharged.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-recharged-collection-4-playstation-5', 'Atari Recharged Collection 4', 'Atari Recharged', '2024-01-07', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaenn.jpg', 'The Atari Recharged Collection 4 includes Missile Command: Recharged and Gravitar: Recharged.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('balan-wonderworld-playstation-5', 'Balan Wonderworld', NULL, '2021-03-26', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xxs.jpg', 'Balan Wonderworld is a wondrous action-platformer game themed around a mysterious musical theatre.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baldur-s-gate-3-playstation-5', 'Baldur''s Gate 3', 'Baldur''s Gate', '2023-09-06', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co670h.jpg', 'An ancient evil has returned to Baldur''s Gate, intent on devouring it from the inside out. The fate of Faerun lies in your hands. Alone, you may resist. But together, you can overcome.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baldur-s-gate-3-playstation-5-2', 'Baldur''s Gate 3', 'Baldur''s Gate', '2023-09-06', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co670h.jpg', 'An ancient evil has returned to Baldur''s Gate, intent on devouring it from the inside out. The fate of Faerun lies in your hands. Alone, you may resist. But together, you can overcome.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-20th-anniversary-edition-playstation-5', 'Beyond Good & Evil - 20th Anniversary Edition', 'Beyond Good & Evil', '2024-06-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8eda.jpg', 'Swoop into the marvelous world of Hillys as action-reporter Jade to investigate the mysterious DomZ alien attacks alongside colorful characters, like her adoptive uncle Pey’j or the valiant Double H. Embark on this epic adventure in up to 4K, 60 fps with improved graphics, controls, and audio, along with brand-new autosave and cross-save features. Enjoy exclusive new rewards as you explore the planet and discover more about Jade’s past in a new treasure hunt throughout Hillys. Put your skills to the test thanks to the new speedrun mode and updated achievements, and learn more about the game’s development and secrets in the anniversary gallery! Armed with her daï-jo and faithful camera, Jade’s adventure will get you to freely explore Hillys, combat creatures large and small, infiltrate dangerous areas, solve enigmatic puzzles, play addictive mini-games, race the best hovercraft pilots, and take pictures of the whole experience.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bit-trip-rerunner-playstation-5', 'Bit.Trip Rerunner', 'Bit.Trip', '2024-05-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co73ia.jpg', 'Rerunner defines rhythm gaming, combining nostalgia with innovative mechanics and a fresh art style, making it a must-play experience for gamers of all backgrounds.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blue-prince-playstation-5', 'Blue Prince', NULL, '2025-11-21', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9mzd.jpg', 'Welcome to Mt. Holly, where every dawn unveils a new mystery. Navigate through shifting corridors and ever-changing chambers in this genre-defying strategy puzzle adventure. But will the unpredictable path you create lead you to the rumored Room 46?', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tiny-tina-s-wonderlands-next-level-edition-playstation-5', 'Tiny Tina''s Wonderlands Next Level Edition', 'Borderlands', '2022-03-25', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co41e0.jpg', 'Embark on an adventure full of whimsy, wonder, and high-powered weaponry! Roll your own multiclass hero then shoot, loot, slash, and cast on a quest to stop the Dragon Lord.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-boy-and-his-blob-retro-collection-playstation-5', 'A Boy and His Blob Retro Collection', 'A Boy and His Blob', '2022-05-13', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tlv.jpg', 'The Blob is back in an exclusive collection with Limited Run Games. The Retro Collection includes the original NES A Boy and His Blob: Trouble on Blobolonia, and The Rescue of Princess Blobette, originally on Game Boy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bugsnax-playstation-5', 'Bugsnax', NULL, '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qjm.jpg', 'Bugsnax is a humorous action adventure game in which we explore an island full of creatures that are hybrids of worms and food. The game was developed and released by independent Young Horses studio.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-dominus-collection-playstation-5', 'Castlevania Dominus Collection', 'Castlevania', '2024-08-27', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xk.jpg', 'Three incredible action adventure games from the Castlevania series have finally returned, for the first time! But wait, there''s more! Haunted Castle Revisited, a redesigned version of the very first Castlevania arcade game, makes its debut!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('chicory-a-colorful-tale-playstation-5', 'Chicory: A Colorful Tale', NULL, '2021-06-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coayhk.jpg', 'Chicory: A Colorful Tale is an adventure game about a dog wielding a magic paintbrush! Use the power of art to explore, solve puzzles, help your animal friends and restore color to the world.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('clair-obscur-expedition-33-playstation-5', 'Clair Obscur: Expedition 33', NULL, '2025-04-24', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9gam.jpg', 'Lead the members of Expedition 33 on their quest to destroy the Paintress so that she can never paint death again. Explore a world of wonders inspired by Belle Époque France and battle unique enemies in this turn-based RPG with real-time mechanics.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cocoon-playstation-5', 'Cocoon', NULL, '2023-09-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa69e.jpg', 'Enter the world of Jade Cocoon: Story of the Tamamayu. As Levant. a Cocoon Master. you will engage powerful monsters in deadly one on one combat. As the magic and talon clashes of these battles turn to your favor you can call on the mystic cocoon powers and capture your fallen foe. Once captured these mighty creatures will be the key to unlocking the curse that has overcome your village.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('concord-playstation-5', 'Concord', NULL, '2024-08-23', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8aag.jpg', 'In Concord, you play as the crew of the Northstar—a group of guns-for-hire known in our galaxy as Freegunners. The Freegunners roam the stars taking high-stakes jobs on worlds across Wild space, where they face other fiercely competitive Freegunner crews. From match-to-match, you’ll form your team of Freegunners with other players and battle it out with rival crews to take home the reward across a variety of maps and modes.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-operation-galuga-playstation-5', 'Contra: Operation Galuga', 'Contra', '2024-03-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72z7.jpg', 'The legendary Contra series is back! Contra: Operation Galuga is a modern reimagining of the classic run-‘n’-gun action game from the ’80s, featuring modern graphics and sound. Encounter new stages, new play mechanics, an updated weapons system and explosive co-op combat for up to two players in Story Mode or four players in Arcade Mode.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-ultimate-edition-playstation-5', 'Control: Ultimate Edition', 'Control', '2021-02-02', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ewb.jpg', 'Control Ultimate Edition contains the main game and all previously released Expansions ("The Foundation" and "AWE") in one great value package. Winner of over 80 awards, Control is a visually stunning third-person action-adventure that will keep you on the edge of your seat.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('c-smash-vrs-playstation-5', 'C-Smash VRS', 'Cosmic Smash', '2023-06-23', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co75qb.jpg', 'SEGA’s futuristic sports classic is reimagined for VR and enters a New Dimension on PS5!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crow-country-playstation-5', 'Crow Country', NULL, '2024-05-09', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ab9.jpg', 'The year is 1990. Edward Crow has disappeared. The owner of ''Crow Country'', he has not been seen since he unexpectedly shut down his park two years ago. The silence is broken when a mysterious young woman named Mara Forest ventures into the heart of the abandoned theme park in order to find him.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('death-stranding-director-s-cut-playstation-5', 'Death Stranding Director''s Cut', 'Death Stranding', '2021-09-24', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobksg.jpg', 'Death Stranding is an action game set in a post-apocalyptic United States. Players control Sam Porter Bridges, a courier tasked with reconnecting isolated cities via a communication network while delivering essential cargo. The gameplay blends traversal, resource management, and narrative elements, with a focus on social connectivity through asynchronous multiplayer. It is known for its unique mechanics, atmospheric world, and philosophical themes. The Director''s Cut includes more character action, extended storylines through new missions and a unique Social Strand System to stay connected with other players around the globe.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('death-s-door-playstation-5', 'Death''s Door', NULL, '2021-11-23', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co45xc.jpg', 'Death''s Door is an action-adventure game developed by Acid Nerve and published by Devolver Digital. Released in 2021, it follows a crow reaper tasked with collecting souls in a mysterious, atmospheric world. The game features exploration, fast-paced combat, and puzzle-solving.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deathloop-playstation-5', 'Deathloop', NULL, '2021-09-14', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4nzt.jpg', 'Deathloop transports players to the lawless island of Blackreef in an eternal struggle between two extraordinary assassins. Explore stunning environments and meticulously designed levels in an immersive gameplay experience that lets you approach every situation any way you like. Hunt down targets all over the island in an effort to put an end to the cycle once and for all, and remember, if at first you don’t succeed… die, die again.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('demon-turf-playstation-5', 'Demon Turf', NULL, '2021-11-04', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob8xp.jpg', 'Demon Turf is back and better than ever! Join Beebz in this neon lit adventure where speedy platforming reigns supreme!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('demon-s-souls-playstation-5', 'Demon''s Souls', NULL, '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coamv6.jpg', 'Soul Demon Hunters is a 2D side-scrolling action game with pixel graphics, where you resolve supernatural phenomena across the world through combat.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-5-special-edition-playstation-5', 'Devil May Cry 5: Special Edition', 'Devil May Cry', '2020-11-12', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sdu.jpg', 'Devil May Cry 5: Special Edition features improved visuals and gameplay at up to 120 frames per second. Alongside all previously-released downloadable content, other additions include Vergil as a playable character, ray tracing graphics options, and two additional game modes: Legendary Dark Knight mode, which significantly increases the number of enemies in each level, and Turbo mode, which increases the game speed by 20%.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disco-elysium-the-final-cut-playstation-5', 'Disco Elysium: The Final Cut', 'Disco Elysium', '2021-12-09', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ve1.jpg', 'Disco Elysium: The Final Cut is an enhanced edition of the original role-playing game developed and published by ZA/UM. It retains the core gameplay and narrative while adding full voice acting, new quests, additional endings, and other narrative revisions.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doki-doki-literature-club-plus-playstation-5', 'Doki Doki Literature Club Plus!', 'Doki Doki Literature Club', '2021-06-30', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawpa.jpg', 'Welcome to the club! Write poems for your crush and experience the terror of school romance in this critically-acclaimed psychological horror story.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-doom-ii-playstation-5', 'Doom + Doom II', 'Doom', '2025-05-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6w0l.jpg', 'Doom II was included in Doom 3 Collector''s Edition for the Xbox, which was released in 2005. This port includes an exclusive level, "Betray". It featured multiplayer like the PC version, however not through Xbox Live. This port was programmed by Vicarious Visions. The Xbox version of Doom 3: Resurrection of Evil also contains this same port, as well as Master Levels for Doom II.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dustborn-playstation-5', 'Dustborn', NULL, '2024-08-20', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6zbx.jpg', 'Lead a band of misfits and outcasts on a perilous road trip across a Divided States of America, in a story-driven action-adventure about hope, friendship, love, robots — and the power of words.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('elden-ring-playstation-5', 'Elden Ring', NULL, '2022-02-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95gk.jpg', 'Elden Ring: Nightreign is a standalone adventure within the ELDEN RING universe, crafted to offer players a new gaming experience by reimagining the game’s core design.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ender-magnolia-bloom-in-the-mist-playstation-5', 'Ender Magnolia: Bloom in the Mist', 'Ender', '2025-01-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gk1.jpg', 'Decades after the Rain of Death, a new journey begins in the Land of Fumes, where mystical powers lie beneath the earth. The kingdom’s desire for conquest led to the creation of the Homunculi, machine-like artificial life forms prepared to execute the king’s will. A recent resource-harvesting mission gone awry caused toxic vapors to emerge from underground, driving both man and machine to feral madness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-6-playstation-5', 'Far Cry 6', 'Far Cry', '2021-10-07', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2npg.jpg', 'Dive into the gritty world of a modern-day guerrilla revolution to liberate a nation from its oppressive dictators. Welcome to Yara, a tropical paradise frozen in time. Far Cry 6 thrusts players into a modern-day guerrilla revolution. As dictator of Yara, Anton Castillo is intent on restoring his nation back to its former glory by any means, with his son, Diego, following in his bloody footsteps. Become a guerrilla fighter and liberate Yara.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-vii-remake-intergrade-playstation-5', 'Final Fantasy VII Remake Intergrade', 'Final Fantasy', '2021-06-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9hh.jpg', 'Final Fantasy VII Remake Intergrade is an enhanced and expanded version of Final Fantasy VII Remake that features a new episode starring Yuffie and introduces an exhilarating new story arc with numerous gameplay additions for players to enjoy.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stranger-of-paradise-final-fantasy-origin-playstation-5', 'Stranger of Paradise: Final Fantasy Origin', 'Final Fantasy', '2022-03-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kag.jpg', 'Jack and his allies, Ash and Jed, burn with resolve to defeat Chaos as they throw open the gates to the Chaos Shrine. Yet doubts remain—are they truly the Warriors of Light the prophecy foretold?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crisis-core-final-fantasy-vii-reunion-playstation-5', 'Crisis Core: Final Fantasy VII Reunion', 'Final Fantasy', '2022-12-13', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobjb3.jpg', 'Crisis Core: Final Fantasy VII - Reunion is an HD remaster of the smash hit prequel to Final Fantasy VII. In addition to all graphics being remastered in HD, fully voiced dialogue and new soundtrack arrangements make for a dynamic new retelling of a beloved classic.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xvi-playstation-5', 'Final Fantasy XVI', 'Final Fantasy', '2023-06-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobd9i.jpg', 'A single-player action RPG set in a high-fantasy world where warring nations and powerful summoned Eikons shape political intrigue and personal vengeance. Players control Clive, a former shield bearer whose life is upended by tragedy. Engage in fast-paced, tactical real-time combat that blends heavy weapons, Eikon-driven abilities, and cinematic set pieces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-vii-rebirth-playstation-5', 'Final Fantasy VII Rebirth', 'Final Fantasy', '2024-02-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9k6.jpg', 'Final Fantasy VII Rebirth is the second entry in the Final Fantasy VII remake project, which retells the story of the genre-redefining RPG across three distinct games. Iconic heroes Cloud, Barret, Tifa, Aerith and Red XIII have escaped from the dystopian city Midgar and are now in pursuit of Sephiroth, the vengeful swordsman from Cloud’s past who was thought to be dead.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-forgotten-city-playstation-5', 'The Forgotten City', NULL, '2021-07-28', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3muu.jpg', 'The Forgotten City is a mystery adventure game of exploration and deduction, and a re-imagining of the critically acclaimed mod of the same name. Combat is an option, but violence will only get you so far. Only by questioning an intertwined community of colorful characters, cleverly exploiting the time loop, and making difficult moral choices can you hope to solve this epic mystery. Here, your decisions matter. The fate of the city is in your hands.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('forspoken-playstation-5', 'Forspoken', NULL, '2023-01-24', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4u6r.jpg', 'Forspoken follows the journey of Frey, a young New Yorker transported to the beautiful and cruel land of Athia. In search of a way home, Frey must use her newfound magical abilities to traverse sprawling landscapes and battle monstrous creatures.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('freedom-planet-2-playstation-5', 'Freedom Planet 2', 'Freedom Planet', '2024-04-04', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6dk4.jpg', 'The sequel to the 16-bit platformer by GalaxyTrail. Lilac, Carol, and Milla must stop the water dragon Merga from resurrecting the ancient super-weapon Bakunawa. It is the second entry in the Freedom Planet franchise.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gex-trilogy-playstation-5', 'Gex Trilogy', 'Gex', '2025-06-16', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9d3l.jpg', 'Gex Trilogy is the definitive edition of the classic platforming series with Gexcessive attitude, complete with Gextras like rewind and save anywhere. Relive Gex''s snark-laced adventures through the warped lens of twentieth-century pop culture and use your Gexterity to survive an onslaught of television-themed challenges.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghost-of-tsushima-director-s-cut-playstation-5', 'Ghost of Tsushima Director''s Cut', 'Ghost of Tsushima', '2021-08-20', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5f.jpg', 'Ghost of Tsushima: Director''s Cut Includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghostwire-tokyo-playstation-5', 'Ghostwire: Tokyo', NULL, '2022-03-25', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55xn.jpg', 'After strange disappearances hit Tokyo''s population, it''s up to you to uncover the source and purge the city of a strange, new evil. Armed with your own mysterious spectral abilities, you will face down the occult, unravel conspiracy theories and experience urban legends like never before.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('glover-playstation-5', 'Glover', NULL, '2024-08-01', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar3y.jpg', 'The cult classic from the ''90s returns! Glover is a charming 3D platformer where you control a magical glove on a quest to restore balance to the kingdom. Roll, jump, and manipulate your magic ball to solve puzzles, overcome challenges, and defeat the evil glove threatening the world!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('god-of-war-ragnar-k-playstation-5', 'God of War Ragnarök', 'God of War', '2022-11-09', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92vm.jpg', 'Start your journey in Midgard as either a fledgling Swordsman, an apprentice Mage, or a rookie Acolyte as you explore a fantasy world with thousands of other players. Level up your character and upgrade your skills through quests or by defeating monsters ranging from the cute to the menacing using the wide variety of skills at your disposal. Test your might and compete with other players in the PvP arena. Group up with other players to finish quests, gain levels, defeat powerful bosses and complete difficult dungeons.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-making-of-karateka-playstation-5', 'The Making of Karateka', 'Gold Master', '2023-08-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qdy.jpg', 'Play the history. Go behind the scenes of Jordan Mechner''s landmark game Karateka in this interactive documentary from Digital Eclipse, with archival materials, video features, and more. Experience pixel-perfect versions of this legendary game, with all-new features.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('llamasoft-the-jeff-minter-story-playstation-5', 'Llamasoft: The Jeff Minter Story', 'Gold Master', '2024-03-13', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7gxd.jpg', '42 of the weirdest, trippiest, sheepiest games ever created. Enter the mind of Jeff Minter, the legendary creator of Attack of the Mutant Camels, Gridrunner, and Tempest 2000, in this interactive documentary from Digital Eclipse.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-forever-playstation-5', 'Tetris Forever', 'Gold Master', '2024-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbof.jpg', 'Tetris Forever celebrates the original, genre-inspiring puzzle game that escaped from behind the Iron Curtain, onto the world stage, and into our cultural consciousness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gradius-origins-playstation-5', 'Gradius Origins', 'Gradius', '2025-08-07', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9l0o.jpg', 'This collection features 18 versions across all 7 arcade titles in the series, including the first-ever appearance of Gradius III AM Show Version on home consoles.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gran-turismo-7-playstation-5', 'Gran Turismo 7', 'Gran Turismo', '2022-03-04', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g84.jpg', 'Gran Turismo 7 brings together the very best features of the Real Driving Simulator. Whether you’re a competitive or casual racer, collector, tuner, livery designer or photographer – find your line with a staggering collection of game modes including fan-favorites like GT Campaign, Arcade and Driving School. With the reintroduction of the legendary GT Simulation Mode, buy, tune, race and sell your way through a rewarding solo campaign as you unlock new cars and challenges. And if you love going head-to-head with others, hone your skills and compete in the GT Sport Mode.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-playstation-5', 'Grand Theft Auto V', 'Grand Theft Auto', '2022-03-15', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gris-playstation-5', 'Gris', NULL, '2022-12-13', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qv5.jpg', 'Gris is a 2D platformer developed by Nomada Studio and published by Devolver Digital. It is a visually striking game that follows the journey of a young woman named Gris as she navigates a world of grief and loss. The game features no dialogue, relying on its hand-painted art style, evocative music, and environmental storytelling to convey its themes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grounded-fully-yoked-edition-playstation-5', 'Grounded Fully Yoked Edition', 'Grounded', '2024-04-16', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co835s.jpg', 'The free 1.4 "Fully Yoked" content update for all players introduces royal Ant Queens, a New Game+ mode, full Japanese VO, and an exciting array of new weapons, armor, and more. Additional content includes new molars, infused bugs, the ability to upgrade gear past level 9, four new achievements, one new mutation, twelve Ant Queen-related buildings, new baby ant pets, and other gameplay additions. Beginning with this update, hosts can now load a save while in the middle of a multiplayer session and all connected players will seamlessly transition into the new game world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hades-playstation-5', 'Hades', NULL, '2021-08-13', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4rs3.jpg', 'A South Korean-made first person shooter (potentially the first ever from that country).', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('haven-playstation-5', 'Haven', NULL, '2020-12-03', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co542m.jpg', 'A sandbox game set in an Iron Age world loosely inspired by Slavic and Germanic myth and legend.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('horizon-forbidden-west-playstation-5', 'Horizon Forbidden West', 'Horizon', '2022-02-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gvu.jpg', 'Horizon Forbidden West continues Aloy’s story as she moves west to a far-future America to brave a majestic, but dangerous frontier where she’ll face awe-inspiring machines and mysterious new threats.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('horizon-forbidden-west-complete-edition-playstation-5', 'Horizon Forbidden West Complete Edition', 'Horizon', '2022-02-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7580.jpg', 'In this complete collection with Horizon Forbidden West and Horizon Forbidden West: Burning Shores DLC, take on more awe-inspiring machines, meet new tribes, and travel to the treacherous archipelago of Los Angeles!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-horizon-adventures-playstation-5', 'Lego Horizon Adventures', 'Horizon', '2024-11-14', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8juk.jpg', 'LEGO Horizon Adventures is an action-adventure game developed by Guerrilla Games and Studio Gobo, blending the Horizon series setting with LEGO-style visuals and humour.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('humanity-playstation-5', 'Humanity', NULL, '2023-05-16', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co58ju.jpg', 'Human Error: Episode One tells the story of a civil protection officer called Anders fighting Vortigaunts, Alien Grunts, and Alien Controllers using the Combine''s forces as his allies.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('immortals-fenyx-rising-playstation-5', 'Immortals Fenyx Rising', NULL, '2020-12-03', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kcb.jpg', 'From the creators of Assassin’s Creed Odyssey comes a storybook adventure about a forgotten hero on a quest to save the Greek gods.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('indika-playstation-5', 'Indika', NULL, '2024-05-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85mc.jpg', 'Play a third-person, story-driven game set in alternative Russia of the late XIX century where religious visions clash with harsh reality. INDIKA tells the story of a young nun who sets off on a journey of self-discovery with the most unusual companion by her side, the devil himself.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('inscryption-playstation-5', 'Inscryption', NULL, '2022-08-30', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co401c.jpg', 'Inscryption is an inky black card-based odyssey that blends the deckbuilding roguelike, escape-room style puzzles, and psychological horror into a blood-laced smoothie. Darker still are the secrets inscrybed upon the cards...', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kena-bridge-of-spirits-playstation-5', 'Kena: Bridge of Spirits', NULL, '2021-09-21', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9hwy.jpg', 'Kena: Bridge of Spirits: a story-driven, action adventure combining exploration with fast-paced combat. Untangle the past as Kena, a young Spirit Guide in search of the sacred Mountain Shrine. Help free the spirits trapped in a forgotten village with the help of the Rot, Kena''s adorable (yet powerful) spirit companions.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-of-us-part-i-playstation-5', 'The Last of Us Part I', 'The Last of Us', '2022-09-02', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1gq.jpg', 'Experience the emotional storytelling and unforgettable characters of Joel and Ellie in The Last of Us, winner of over 200 Game of the Year awards and now rebuilt for PlayStation 5.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-last-of-us-part-ii-playstation-5', 'The Last of Us Part II', 'The Last of Us', '2024-01-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ziw.jpg', 'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble nature of the player character introduces platforming elements, allowing the player to jump and climb to traverse environments and gain advantages during combat.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-true-colors-playstation-5', 'Life is Strange: True Colors', 'Life is Strange', '2021-09-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vpp.jpg', 'Life is Strange is a series of award-winning and critically-acclaimed narrative adventure games. Discover a universe where everyday heroes wield supernatural powers, while dealing with real challenges, real relationships, and real emotions. It''s our world... with a twist of the strange. No matter your choices, the experience will stay with you forever. Deep in the mountains of Colorado, you''ll find Haven Springs, a small mining town filled with beauty and mystery. As Alex, you''ll discover the shocking secrets behind your brother’s death in an emotional roller-coaster of an adventure, using your psychic power of Empathy to change fate and change lives.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-double-exposure-playstation-5', 'Life is Strange: Double Exposure', 'Life is Strange', '2024-10-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8bp9.jpg', 'Max Caulfield, photographer-in-residence at the prestigious Caledon University, discovers her closest new friend Safi dead in the snow. Murdered. To save her, Max tries to Rewind time – a power she’s not used in years… Instead, Max opens the way to a parallel timeline where Safi is still alive and still in danger! Max realizes the killer will soon strike again – in both versions of reality. Only Max can Shift between the two parallel timelines to solve and prevent the same murder.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('like-a-dragon-infinite-wealth-playstation-5', 'Like a Dragon: Infinite Wealth', 'Like a Dragon', '2024-01-26', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8356.jpg', 'Like a Dragon: Infinite Wealth is a turn-based role-playing game developed by Ryu Ga Gotoku Studio and published by Sega. It follows dual protagonists Ichiban Kasuga and Kazuma Kiryu, with the narrative set primarily in Japan and Hawaii. The game uses a party-based combat system that builds on previous Like a Dragon entries, incorporating positioning and environmental interactions. Players engage in main story missions alongside a wide range of optional activities and side content. The title combines narrative-driven progression with exploration, character development, and minigames typical of the series.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sackboy-a-big-adventure-playstation-5', 'Sackboy: A Big Adventure', 'LittleBigPlanet', '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4522.jpg', 'Iconic PlayStation hero, Sackboy returns in an all-new 3D adventure with a deeply immersive and expressive control scheme. Players can go on this epic platforming journey solo-style, or they can team up with friends for collaborative, chaotic multiplayer fun.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lost-records-bloom-rage-playstation-5', 'Lost Records: Bloom & Rage', NULL, '2025-08-07', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p3a.jpg', 'Lost Records: Bloom & Rage is a brand-new story-driven journey through time from the creative minds behind Life is Strange. The magical summer of 1995 is one of self-discovery and forging unbreakable bonds for high school friends Swann, Nora, Autumn, and Kat. 27 years of no contact later, fate reunites them to confront the long-buried secret that made them promise to never speak again.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('manifold-garden-playstation-5', 'Manifold Garden', NULL, '2021-05-20', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ws9.jpg', 'Manifold Garden is a game that reimagines physics and space.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('manifold-garden-playstation-5-2', 'Manifold Garden', NULL, '2021-05-20', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ws9.jpg', 'Manifold Garden is a game that reimagines physics and space.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-spider-man-miles-morales-playstation-5', 'Marvel''s Spider-Man: Miles Morales', 'Marvel', '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobg1j.jpg', 'The latest adventure in the Spider-Man universe will build on and expand ‘Marvel’s Spider-Man’ through an all-new story. Players will experience the rise of Miles Morales as he masters new powers to become his own Spider-Man.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-avengers-playstation-5', 'Marvel''s Avengers', 'Marvel', '2021-03-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fkb.jpg', 'Based on the Marvel Cinematic Universe film Marvel''s Ant-Man, this DLC adds a brand-new level and eleven characters to LEGO Marvel''s Avengers journey.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-guardians-of-the-galaxy-playstation-5', 'Marvel''s Guardians of the Galaxy', 'Marvel', '2021-10-26', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yh5.jpg', 'A bundle including Marvel''s Guardians of the Galaxy and Marvel''s Avengers.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-spider-man-2-playstation-5', 'Marvel''s Spider-Man 2', 'Marvel', '2023-10-20', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobg1k.jpg', 'Marvel''s Spider-Man 2 is an action-adventure game developed by Insomniac Games and published by Sony Interactive Entertainment. Released in October 2023 exclusively for the PlayStation 5, it is a direct sequel to Marvel''s Spider-Man (2018) and Marvel''s Spider-Man: Miles Morales (2020). The game continues the story of Peter Parker and Miles Morales as they face new challenges and threats in New York City.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-messenger-playstation-5', 'The Messenger', 'The Messenger', '2025-03-21', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1th.jpg', 'As a demon army besieges his village, a young ninja ventures through a cursed world, to deliver a scroll paramount to his clan''s survival.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-master-collection-vol-1-playstation-5', 'Metal Gear Solid: Master Collection Vol. 1', 'Metal Gear', '2023-10-24', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jaw.jpg', 'Metal Gear Solid Master Collection: Volume 1 compiles the early entries in the Metal Gear series into a single package, offering players the opportunity to experience the origins of stealth action gameplay. The collection includes the following titles: Metal Gear, Metal Gear 2: Solid Snake, Metal Gear Solid (with VR Missions/Special Missions), Metal Gear Solid 2: Sons of Liberty (HD Collection version), Metal Gear Solid 3: Snake Eater (HD Collection version), as well as the NES/Famicom version of Metal Gear and Snake’s Revenge. Regional versions of the titles are available as additional downloads.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-monkey-island-playstation-5', 'Return to Monkey Island', 'Monkey Island', '2022-11-08', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56kr.jpg', 'Return to Monkey Island, the long-awaited follow-up to the legendary Secret of Monkey Island and Monkey Island 2: LeChuck''s Revenge by Ron Gilbert''s Terrible Toybox in collaboration with Devolver Digital and Lucasfilm Games, coming 2022.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monument-valley-the-trilogy-playstation-5', 'Monument Valley: The Trilogy', 'Monument Valley', '2025-10-30', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaecb.jpg', 'Monument Valley: Trilogy is a puzzle game featuring geometric landscapes and optical illusion-based levels. Players navigate through surreal architectural environments, solving spatial puzzles by manipulating the game''s architectural structures. The series follows a silent protagonist through interconnected puzzle worlds, combining minimalist design with intricate spatial challenges.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neon-white-playstation-5', 'Neon White', NULL, '2022-12-13', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tgh.jpg', 'Neon White is a single-player speedrunning FPS where you can sacrifice your guns for godlike parkour moves.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('neva-playstation-5', 'Neva', NULL, '2024-10-15', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8x5c.jpg', 'Neva is an action-adventure game developed by Nomada Studio and published by Devolver Digital.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-nioh-collection-playstation-5', 'The Nioh Collection', 'Nioh', '2021-02-05', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kiz.jpg', 'The Nioh Collection is a package released by Team Ninja and Koei Tecmo in February 2021. This collection includes remastered versions of both Nioh games, optimized for next-gen consoles. Specifically, it features:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-soulstorm-playstation-5', 'Oddworld: Soulstorm', 'Oddworld', '2021-04-06', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ysw.jpg', 'Oddworld: Soulstorm is a modern re-imagining of the 1998 title Oddworld: Abe''s Exoddus. It serves as a direct sequel to Oddworld: New ''n'' Tasty. The player controls Abe, a reluctant hero who inadvertently sparked an uprising and now must lead his fellow Mudokons in their fight for freedom against the Magog Cartel and the planet’s ruling power.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('outer-wilds-archaeologist-edition-playstation-5', 'Outer Wilds: Archaeologist Edition', 'Outer Wilds', '2022-09-15', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3yjh.jpg', 'Outer Wilds: Archaeologist Edition contains Outer Wilds base game and Echoes of the Eye expansion.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-all-you-can-eat-playstation-5', 'Overcooked! All You Can Eat', 'Overcooked!', '2020-12-08', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4969.jpg', 'Five new birthday themed levels, the new Tabby Cat chef, a recipe to make a cup of tea, and in-game Switcheroo mechanic where living playing cards stalk the levels transporting players across the kitchen, are all on the menu.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-pathless-playstation-5', 'The Pathless', NULL, '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hm5.jpg', 'The Pathless is a mythic adventure where you play as the Hunter, a skilled archer who explores a mysterious cursed island with an eagle companion. Your goal is to lift an unnatural shroud of darkness that plagues the world. As you bound acrobatically through dense forests, you will hunt prey, discover ancient ruins, and form a deep bond with your eagle. But beware: dangerous spirits also lurk in the woods. If you aren''t careful, you may become the hunted yourself.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('penny-s-big-breakaway-playstation-5', 'Penny''s Big Breakaway', NULL, '2024-02-21', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nmg.jpg', 'Join Penny & Yo-Yo in a kinetic 3D-platformer bursting with innovative gameplay! Showcase your catalog of tricks and chain impressive combos to deliver Penny & Yo-Yo''s perfect breakout performance. Take the stage with this vibrant pair in Penny’s Big Breakaway.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pentiment-playstation-5', 'Pentiment', NULL, '2024-02-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v1e.jpg', 'A 16th-century narrative adventure set in Upper Bavaria, following Andreas Maler, a journeyman artist working in the bygone scriptorium of Kiersau Abbey during a time of great social unrest. While finishing his masterpiece, Andreas inadvertently becomes entangled in a series of murders that take place over 25 years. Peasants, thieves, craftsmen, monks, nuns, nobles, and even saints must be investigated and interrogated to expose the truth.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-reload-playstation-5', 'Persona 3 Reload', 'Persona', '2024-02-02', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co78nt.jpg', 'Persona 3 Reload: Persona 5 Royal Persona Set 1 contains additional content that allows you to use Personas from Persona 5 Royal.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-plucky-squire-playstation-5', 'The Plucky Squire', NULL, '2024-09-17', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6z44.jpg', 'Storybook characters discover a three-dimensional world outside the pages of their book and must jump between 2D & 3D realms to save their friends in this charming action-adventure.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-lost-crown-playstation-5', 'Prince of Persia: The Lost Crown', 'Prince of Persia', '2024-01-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coafpt.jpg', 'A Two Thrones Dark Prince–inspired skin for Sargon.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pumpkin-jack-playstation-5', 'Pumpkin Jack', NULL, '2021-10-27', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3r4x.jpg', 'Pumpkin Jack is a Spooky Scary 3D platformer in which you embody Jack, the Mythical Pumpkin Lord! Dive into an Epic Adventure through otherworldly landscapes and help the Evil annihilate the Good!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-2-playstation-5', 'Puyo Puyo Tetris 2', 'Puyo Puyo Tetris', '2020-12-08', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3246.jpg', 'Stack, chain, and combo your way to victory in the ultimate matching of two puzzle game legends! Pre-order now and get ready to traverse dimensions and experience brand new worlds in time for the holidays, with the PC release fast-dropping onto Steam in early 2021.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('q-u-b-e-10th-anniversary-playstation-5', 'Q.U.B.E. 10th Anniversary', 'Q.U.B.E.', '2022-09-14', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ygb.jpg', 'Entirely rebuilt from the ground up, Q.U.B.E. 10th Anniversary is the ultimate celebration of the decade-old original, bringing refined visuals, completely redesigned and revised gameplay sections, and a whole new chapter to the award-winning, brain-twisting first-person puzzler.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('q-u-b-e-2-ultimate-edition-playstation-5', 'Q.U.B.E. 2 Ultimate Edition', 'Q.U.B.E.', '2023-01-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6258.jpg', 'Includes ALL downloadable content for Q.U.B.E. 2: Classic Gloves, Lost Orbit, Aftermath. In Q.U.B.E. 2 you play as Amelia Cross, an archaeologist who has awoken among the ruins of an alien landscape. With the distant help of another survivor you must manipulate the structure of this mysterious world and find a way back home. As you explore and solve puzzles to progress, thought-provoking questions about your true purpose and the origins of the structure you are navigating will need to be considered, forcing you to come to terms with a devastating truth that will shake your world.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-playstation-5', 'Quake', 'Quake', '2021-10-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-playstation-5', 'Quake II', 'Quake', '2023-08-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-quarry-playstation-5', 'The Quarry', NULL, '2022-06-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kl4.jpg', 'It''s late summer in the remote forests of upstate New York, and the teen counselors of Hackett''s Quarry have the camp to themselves for one final night. That means no kids, no adults, and no rules. In this thrilling cinematic tale, you control the fates of all nine camp counselors as their party plans unravel into an unpredictable night of horror. With life-or-death decisions around every turn, the choices you make will determine how the story unfolds.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rain-world-playstation-5', 'Rain World', NULL, '2023-07-11', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24pm.jpg', 'Rain World is a survival platformer set in an abandoned industrial environment ravaged by a shattered ecosystem. Bone-crushingly intense rains pound the surface, making life as we know it almost impossible. The creatures in this world hibernate most of the time, but in the few brief dry periods they go out in search of food.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ratchet-clank-rift-apart-playstation-5', 'Ratchet & Clank: Rift Apart', 'Ratchet & Clank', '2021-06-11', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2str.jpg', 'Go dimension-hopping with Ratchet and Clank as they take on an evil emperor from another reality. Jump between action-packed worlds and beyond at mind-blowing speeds, complete with dazzling visuals and an insane arsenal.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-matter-playstation-5', 'Red Matter', 'Red Matter', '2023-05-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8caj.jpg', 'Red Matter is a story-driven VR puzzle adventure game set during a dystopian sci-fi Cold War. Take on the role of Agent Epsilon, an astronaut of the Atlantic Union dispatched to an abandoned Volgravian moon base on a frozen, faraway planet. Your mission: to investigate a shady top secret research project.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-matter-2-playstation-5', 'Red Matter 2', 'Red Matter', '2023-05-18', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ccv.jpg', 'Red Matter 2 is an immersive, puzzle-adventure game that will transport you to the far reaches of space. Step into the shoes of Sasha, an agent awakened in a lunar base by an undercover operative and tasked with uncovering the secrets of the mysterious Red Matter.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-village-playstation-5', 'Resident Evil Village', 'Resident Evil', '2021-05-07', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyw.jpg', 'A bundle including the following content:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-playstation-5', 'Resident Evil 4', 'Resident Evil', '2023-03-24', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wn5.jpg', 'This pack includes Resident Evil 4 and Resident Evil CODE: Veronica X.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('returnal-playstation-5', 'Returnal', NULL, '2021-04-30', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co73sj.jpg', '"Return or No Return" is a first-person horror survival game set in a mansion that traps travelers passing through the infamous shortcut- The Tenebris Tunnel. After a mysterious smoke sweeps through the car, your friends have disappeared, and you''re trapped! You must save them to escape death.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rocket-knight-adventures-re-sparked-playstation-5', 'Rocket Knight Adventures: Re-Sparked', 'Rocket Knight', '2024-06-11', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7na9.jpg', 'The mightiest mammal to ever rocket to stardom is back in a three-game, Carbon Engine-powered collection that includes:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rogue-legacy-2-playstation-5', 'Rogue Legacy 2', 'Rogue Legacy', '2023-06-20', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4p51.jpg', 'Rogue Legacy is back! But now it''s got a 2 on the end of it!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadows-of-the-damned-hella-remastered-playstation-5', 'Shadows of the Damned: Hella Remastered', 'Shadows of the Damned', '2024-10-28', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ygy.jpg', 'Shadows of the Damned, an action-adventure road trip through hell, has been remastered at last! Get ready for a story about rock, love, and just a little bit of demon slaying.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-risky-s-revenge-director-s-cut-playstation-5', 'Shantae: Risky''s Revenge - Director''s Cut', 'Shantae', '2021-10-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49xa.jpg', 'Shantae: Risky’s Revenge – Director’s Cut brings hair-whipping, belly-dancing to your PC! Play one of the most critically acclaimed handheld series of all time, now with brand new features!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-half-genie-hero-ultimate-edition-playstation-5', 'Shantae: Half-Genie Hero Ultimate Edition', 'Shantae', '2021-11-02', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rka.jpg', 'The ultimate edition of Shantae: Half-Genie Hero comes with all of the previously released DLC, Modes, and Costumes in one epic collection! Includes an exclusive Blue Bathing Suit for use in Beach Mode!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-seven-sirens-playstation-5', 'Shantae and the Seven Sirens', 'Shantae', '2022-03-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7csj.jpg', 'Formerly referred to as Shantae 5, Shantae and the Seven Sirens sends the belly-dancing, hair-whipping, half-genie hero to a tropical island where Shantae and her friends encounter other Half-Genie allies, but they soon learn there’s trouble in paradise. As Shantae gets caught up in the island’s sinister secrets, she’ll use all-new dance abilities and instant-transformation Fusion Magic to explore the nonlinear, interconnected world where she’ll visit multiple towns, overcome treacherous labyrinths, and battle dastardly bosses. The game also features a new collectible card system that grants players the freedom to augment Shantae’s powers to suit their own style of play.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-playstation-5', 'Shantae', 'Shantae', '2022-08-26', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27l6.jpg', 'Genie-girl Shantae is the self-appointed guardian of a small fishing village, Scuttle Town. Living life in a lighthouse rather than a bottle, she''s constantly on the lookout for danger. When the nefarious lady-pirate, Risky Boots catches wind of the treasure that was recently unearthed in the village, she launches an attack. To get Scuttle out of trouble, it''s up to Shantae to prove that she''s the rightful ''Guardian Genie'' to the best of her dancing, buying and hair-whipping abilities. Now crack that whip!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-and-the-pirate-s-curse-playstation-5', 'Shantae and the Pirate''s Curse', 'Shantae', '2022-09-27', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4b1u.jpg', 'Embark on a brand new adventure with Shantae, the hair-whipping belly dancing genie. When she loses her magic, Shantae must team up with her nemesis, the nefarious pirate Risky Boots in order to save Sequin Land from an evil curse. As a pirate, Shantae gains new weapons to advance her quest, slay monsters, battle epic bosses…and hopefully get her magic back in the bargain! But can she really trust her deadliest enemy?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-advance-risky-revolution-playstation-5', 'Shantae Advance: Risky Revolution', 'Shantae', '2025-08-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaboc.jpg', 'Shantae is back in an adventure 20 years in the making! The nefarious pirate Risky Boots has a “groundbreaking” new plan that will leave Sequin Land spinning — by rotating the continent, she can move any town right to the coast for easy plundering! As Shantae, turn the tectonic tables on Risky by taking control of the land itself: shift, twist, navigate, and explore by swapping between mix-and-match multilayered levels! Hair-whip and belly-dance your way through scrambled lands, misplaced towns, monster-filled crypts, and daunting labyrinths. Six creature transformations, fierce boss battles, and a 4-player versus mode await!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shinobi-art-of-vengeance-playstation-5', 'Shinobi: Art of Vengeance', 'Shinobi', '2025-08-29', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9e1j.jpg', 'Slay the enemies in the silence of the moment. Run through the world of Shinobi full of monsters and ninja actions. Grab Oborozuki, the legendary sword, and slay evil once more. Your clan and the world are counting on you.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-frontiers-playstation-5', 'Sonic Frontiers', 'Sonic the Hedgehog', '2022-11-08', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p52.jpg', 'Worlds will collide in Sonic the Hedgehog’s newest adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-origins-plus-playstation-5', 'Sonic Origins Plus', 'Sonic the Hedgehog', '2023-06-23', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6oez.jpg', 'Sonic Origins Plus is an updated version of Sonic Origins that includes the Plus Expansion Pack. Unlike Sonic Mania Plus, Sonic Origins Plus can be bought digitally on PC as a single purchase like the console versions, while the base game continues to be available on it''s own. Digital versions of Sonic Origins on all platforms can be upgraded to Plus by purchasing the Plus Expansion Pack separately.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-superstars-playstation-5', 'Sonic Superstars', 'Sonic the Hedgehog', '2023-10-17', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbw4.jpg', 'Adventure through the mystical Northstar Islands in this all-new take on classic 2D Sonic high-speed action platforming. Play as Sonic, Tails, Knuckles, and Amy Rose and harness all-new Emerald powers to move and attack in dynamic new ways. Navigate gorgeous, never-before-seen environments solo or with up to 3 other players and stop Dr. Eggman, Fang, and a mysterious new adversary from converting the islands'' giant animals into Badniks before it''s too late!', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-space-for-the-unbound-playstation-5', 'A Space for the Unbound', NULL, '2023-01-19', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62kn.jpg', 'A coming-of-age adventure where you follow two high school sweethearts on a journey of self-discovery at the end of their high school years while facing the end of the world. Explore 90s Indonesian town, uncover its secrets, use supernatural powers to dive into people''s hearts, and pet cats.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-stanley-parable-ultra-deluxe-playstation-5', 'The Stanley Parable: Ultra Deluxe', 'The Stanley Parable', '2022-04-27', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4p71.jpg', 'The Stanley Parable: Ultra Deluxe is an expanded re-imagining of 2013''s The Stanley Parable. You will play as Stanley, and you will not play as Stanley. You will make a choice, and you will become powerless. You are not here to win. The Stanley Parable is a game that plays you.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stray-playstation-5', 'Stray', NULL, '2022-07-19', 'PlayStation 5', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaa4c.jpg', 'A fantasy tactical RPG where you command over 70 characters across grid-based battles. Customize skills, unleash flashy Spell Cards, and enjoy rich animations in a strategic, story-driven adventure set in the world of Touhou.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-mania-playstation-5', 'Super Monkey Ball Banana Mania', 'Super Monkey Ball', '2021-10-05', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaeop.jpg', 'Super Monkey Ball: Banana Mania is a "modern HD remaster" of Super Monkey Ball, Super Monkey Ball 2, and Super Monkey Ball Deluxe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-arise-playstation-5', 'Tales of Arise', 'Tales', '2021-09-10', 'PlayStation 5', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ls2.jpg', 'On the planet Dahna, reverence has always been given to Rena--the planet in the sky--as a land of the righteous and divine. Stories handed down for generations became truth and masked reality for the people of Dahna. For 300 years, Rena has ruled over Dahna, pillaging the planet of its resources and stripping people of their dignity and freedom.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-talos-principle-2-playstation-5', 'The Talos Principle 2', 'The Talos Principle', '2023-11-02', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jbl.jpg', 'The Talos Principle II is a thought-provoking first-person puzzle experience that greatly expands on the first game''s philosophical themes and stunning environments with increasingly mind-bending challenges.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thumper-playstation-5', 'Thumper', NULL, '2023-02-22', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4e.jpg', 'Thumper is a rhythm violence game. It combines classic rhythm-action with breakneck speed and brutal physicality.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-i-iii-remastered-playstation-5', 'Tomb Raider I–III Remastered', 'Tomb Raider', '2024-02-14', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8xte.jpg', 'Tomb Raider I•II•III Remastered is a collection of the first three Tomb Raider games, originally released between 1996 and 1998, updated with enhanced visuals and modern controls.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomba-special-edition-playstation-5', 'Tomba! Special Edition', 'Tomba!', '2024-08-01', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92no.jpg', 'Our favourite pink-haired, high-jumping jungle boy is back!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('uncharted-legacy-of-thieves-collection-playstation-5', 'Uncharted: Legacy of Thieves Collection', 'Uncharted', '2022-01-28', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3swl.jpg', 'Uncharted: Legacy of Thieves Collection is a remastered collection of two games in the Uncharted saga: Uncharted 4: A Thief’s End and Uncharted: The Lost Legacy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('unpacking-playstation-5', 'Unpacking', NULL, '2022-05-10', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2879.jpg', 'Unpacking is a job-simulator game about inspecting packages, deciding if they are accepted or denied depending on the rules of that day and doing different procedures for each package.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-legion-playstation-5', 'Watch Dogs: Legion', 'Watch Dogs', '2020-11-12', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyq.jpg', 'In Watch Dogs: Legion, near future London is facing its downfall... Unless you do something about it. Build a resistance, fight back, and give the city back to the people. It''s time to rise up.', 'NA', 35);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-boy-and-the-cursed-kingdom-playstation-5', 'Monster Boy and the Cursed Kingdom', 'Wonder Boy', '2021-12-02', 'PlayStation 5', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27mg.jpg', 'A legendary game series returns with an all-new adventure! Monster Boy is a colourful side-scrolling action adventure created in cooperation with Ryuichi Nishizawa, the creator of the Wonder Boy Monster World series (Trademark of SEGA Corporation Japan).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('altered-beast-sega-master-system', 'Altered Beast', 'Altered Beast', '1989-06-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sqq.jpg', 'The Sega Genesis/Mega Drive has different enemy layouts and input mechanics from the original arcade version.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-flash-sega-master-system', 'The Flash', 'DC', '1991-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coauc0.jpg', 'Need an Action Fix? Get Sky High!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghouls-n-ghosts-sega-master-system', 'Ghouls ''n Ghosts', 'Ghosts ''n Goblins', '1990-03-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95yx.jpg', NULL, 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-sega-master-system', 'Golden Axe', 'Golden Axe', '1990-03-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25qt.jpg', 'Progress is made through the game by fighting through Death Adder''s henchmen, including men armed with clubs and maces, skeleton warriors, and knights. Players are able to attack using their weapon, jump and cast spells that hurt all enemies on the screen. The force of this magic depends on the number of "bars" of magic power currently available. The bars are filled by collecting blue ''magic potions'' attained by kicking little sprites who then drop the potions. These sprites appear during regular levels and during bonus stages in between levels. The male warrior Ax is able to cast earth spells. The dwarf Gilius, casts lightning spells and the female warrior Tyris casts fire magic. Each character has a different number of maximum magic bars and varying ranges of attack.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-warrior-sega-master-system', 'Golden Axe Warrior', 'Golden Axe', '1991-04-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b8f.jpg', 'World peace is at stake! Death Adder, a wicked giant, has stolen the nine crystals from the kingdom of Firewood and has hidden them in nine labyrinths that he has created. These nine magic crystals protected the people from evil – especially from Death Adder''s grasp. But now that the crystals are lost, the world is defenseless!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castle-of-illusion-starring-mickey-mouse-sega-master-system', 'Castle of Illusion Starring Mickey Mouse', 'Illusion', '1991-02-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6as3.jpg', 'To save his girlfriend Minnie from the wicked witch Mizrabel, Mickey must venture into the Castle of Illusion. Crossing six levels (including a magical forest, a toy land and a candy world), he must collect the gems of the rainbow in order to confront and defeat the witch.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-sega-master-system', 'Lemmings', 'Lemmings', '1992-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-sega-master-system', 'Marble Madness', NULL, '1992-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-vs-the-kingpin-sega-master-system', 'Spider-Man vs. The Kingpin', 'Marvel', '1991-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oo.jpg', 'Spider-Man vs. The Kingpin is a video game produced by Sega of America and developed by Technopop initially on the Mega Drive/Genesis. It was ported internally by Sega of America for the Master System and Game Gear consoles, the latter being published by Acclaim Entertainment through its Flying Edge division. An updated version was also released for the Sega CD under the name of The Amazing Spider-Man vs. The Kingpin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-return-of-the-sinister-six-sega-master-system', 'Spider-Man: Return of the Sinister Six', 'Marvel', '1992-10-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co987q.jpg', 'Spider-Man: Return of the Sinister Six is a side-scrolling game which puts you in the role of Spidey throughout six levels against Electro, Sandman, Mysterio, Vulture, Hobgoblin and Doctor Octopus respectively. Some puzzle solving (like finding a key) is necessary to beat some levels. Spidey can duck jump, climb walls, punch, shoot webs to swing (by pressing punch and jump together) and perform a jump kick (by pressing the punch button twice). Collecting web cartridges allows Spidey to shoot limited web projectiles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-sega-master-system', 'The Incredible Hulk', 'Marvel', '1994-07-01', 'Sega Master System', 0, 0, NULL, NULL, NULL, 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-sega-master-system', 'Prince of Persia', 'Prince of Persia', '1992-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-sega-master-system', 'Sonic the Hedgehog', 'Sonic the Hedgehog', '1991-10-25', 'Sega Master System', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ubt.jpg', NULL, 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-sega-master-system', 'Wonder Boy', 'Wonder Boy', '1987-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52cn.jpg', 'Wonder Boy was ported to the Sega Mark III/Master System video game console by Sega. The game is also known as Super Wonder Boy for its Sega Mark III release in Japan.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-in-monster-land-sega-master-system', 'Wonder Boy in Monster Land', 'Wonder Boy', '1988-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52d4.jpg', 'Wonder Boy: Monster Land is an action role-playing platform video game developed by Westone. It was released by Sega for the arcades in 1987 and for the Sega Master System in 1988 as a sequel to the 1986 game Wonder Boy, taking place eleven years after the events in the previous game.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-iii-the-dragon-s-trap-sega-master-system', 'Wonder Boy III: The Dragon''s Trap', 'Wonder Boy', '1989-01-01', 'Sega Master System', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52cw.jpg', 'A direct sequel to Wonder Boy in Monster Land, you wander through the lands using multiple forms that each have different abilities. Each defeated boss unlocks a new form that has to be used to advance to a new area, while shops give you access to new equipment for money.', 'NA', 36);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('altered-beast-sega-genesis', 'Altered Beast', 'Altered Beast', '1989-08-14', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sqq.jpg', 'The Sega Genesis/Mega Drive has different enemy layouts and input mechanics from the original arcade version.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blaster-master-2-sega-genesis', 'Blaster Master 2', 'Blaster Master', '1993-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1jx6.jpg', 'The side-scrolling/top-down hybrid action adventure gameplay returns with a brand new sequel to Blaster Master Zero!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-bomberman-sega-genesis', 'Mega Bomberman', 'Bomberman', '1995-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dch.jpg', 'Mega Bomberman is a top-down action game. Control your Bomberman through various levels defeating multiple enemies and plenty of bosses. Each level consist of blocks for exploding and some blocks that don''t explode. At times you will need the non-exploding blocks as shelter. The blocks that do explode reveal power-ups and eggs.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-in-claws-encounters-of-the-furred-kind-sega-genesis', 'Bubsy in Claws Encounters of the Furred Kind', 'Bubsy', '1993-07-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sls.jpg', 'Bubsy in Claws Encounters of the Furred Kind, known as Bubsy for short, is a platform video game released by Accolade in the early 1990s. It is the first game in the Bubsy series of video games. The game''s name is a play on words in reference to Close Encounters of the Third Kind, with the game revolving around Bubsy defending the planet''s supply of yarnballs from alien invaders. The game received a sequel, Bubsy 2, in 1994.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bubsy-2-sega-genesis', 'Bubsy 2', 'Bubsy', '1994-10-15', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h04.jpg', NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-bloodlines-sega-genesis', 'Castlevania: Bloodlines', 'Castlevania', '1994-03-17', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcm9.jpg', 'Time refuses to forget the Belmont family''s horrifying, bloody destiny. And in 1917 two of its descendants are summoned by fate into epic battle. Their enemy? The most evil incarnation of Castlevania legacy to ever rise from the grave, the vampiress Countess Bartley. This spine-tingling, 6-stage fear-fest overflows with graphic sights and sounds from your worst nightmares. As John Morris, the whip wielding vampire hunter, or Eric Lecarde, master lanceman, you''ll pursue the demonic Countess all across Europe before she resurrects Dracula for a final reign of global terror. Alas, her trail of doom is laden with zombies, hideous mutants, grotesque giants, ghouls and ghastly creatures. Taste the sweat dripping into your mouth as you try rescuing yourself from diabolical traps. Feel the torturous strain on every muscle as you wield again and again sacred weapon power-ups such as Holy Water, the Battle Axe, the Crystal Blade Boomerang and the Mirror of Truth. But in the end, make sure you''ve saved enough strength to scream!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-hard-corps-sega-genesis', 'Contra: Hard Corps', 'Contra', '1994-08-08', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n11.jpg', 'Kickin'' cyborg butt... That''s what it''s all about, dude. Jack into this game of genetic engineering gone bad. Real bad. It''s five years after the mother of all wars ended - and things still aren''t right. Your job is to fix it. The ever-popular Contra series makes its Sega Genesis debut with a pulse-pounding new storyline. At 16 megs, HARD CORPS pushes the technology to bring you over ten gut-wrenching levels with huge boss characters, great graphics and dynamic sound. Find high powered weapons such as the homing gun, crush gun, needle laser or mine setter. Do you think you can handle it? Trust me, you can''t. You still here? Okay, then get ready for the fight of your life. Pick one of the four heroes and begin your search across many dark levels of doom. The ending changes, depending on the paths you choose - but every pass crosses boss characters that will blow you away. Literally!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-sega-genesis', 'Batman', 'DC', '1991-06-27', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fx3.jpg', 'This addon inlcudes a Batman costume inspired by the 2008 movie ‘The Dark Knight’.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-return-of-the-joker-sega-genesis', 'Batman: Return of the Joker', 'DC', '1992-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pij.jpg', 'Batman: Return of the Joker was developed and published by Sunsoft as the second in their Batman series on the Nintendo Entertainment System. It departed from the original game by focusing on the comic-book version of Batman instead of the movie-inspired conception. The story itself was self-contained, and did not depict a pre-existing storyline. The game is a side-scrolling platformer with beat ''em up features.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-sega-genesis', 'Superman', 'DC', '1992-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b3i.jpg', 'Superman: The New Adventures, often referred to as Superman 64, is a 1999 adventure video game developed and published by Titus Software for the Nintendo 64 video game console. The game is based on the television series Superman: The Animated Series. Superman was first released in North America on May 31, 1999 and in Europe on July 23, 1999.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-returns-sega-genesis', 'Batman Returns', 'DC', '1992-10-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zck.jpg', 'Batman Returns is a beat-em-up side-scrolling game designed for the Sega consoles. It was published by Sega.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-death-and-return-of-superman-sega-genesis', 'The Death and Return of Superman', 'DC', '1995-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25nt.jpg', 'Brace yourself for a hard-hitting fight to the finish that lets you relive the classic DC comic book series! As Superman, fight for your life against mighty Doomsday, the vile distributor of death and destruction! Then, control the destiny of the four Supermen - each claiming to be the one, true Superman! Explode through 10 levels of super-powered battles and fly at furious speeds - until only the real Superman is left standing!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-task-force-sega-genesis', 'Justice League Task Force', 'DC', '1995-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wc7.jpg', 'Justice League Task Force is a fighting game produced by Sunsoft and distributed by Acclaim for the Super Nintendo Entertainment System and Genesis in 1995. The Super NES version was co-developed by Blizzard Entertainment and the Genesis version by Condor, Inc. (later known as Blizzard North).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-adventures-of-batman-robin-sega-genesis', 'The Adventures of Batman & Robin', 'DC', '1995-08-02', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6379.jpg', 'Robin & Commissioner Gordon have mysteriously disappeared, and Batman suspects kidnapping. Have our two comrades succumb to the deadly beauty of Poison Ivy? Does the Riddler know the answer? Or will The Joker have the last laugh?', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-sega-genesis', 'Batman Forever', 'DC', '1995-09-04', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gyn.jpg', 'The Game Boy version of Batman Forever', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quackshot-starring-donald-duck-sega-genesis', 'QuackShot Starring Donald Duck', 'Donald Duck', '1991-12-19', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y89.jpg', 'QuackShot starring Donald Duck is a steady Disney run-and-jump platformer, with a little puzzle-solving element. Characters are mostly based on Disney''s cartoon series Duck Tales.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-dolphin-sega-genesis', 'Ecco the Dolphin', 'Ecco the Dolphin', '1992-12-29', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co23oy.jpg', 'Life was an adventure for Ecco, the young dolphin. The ocean seemed endless with rolling breakers to race through! At high speed Ecco could burst through the waves leaping through the air – almost flying! Until one day, all of that changed. A freak whirlpool of air and water tore the life from Ecco’s home leaving Ecco all alone. Now he must fight to stay alive, while traversing the vast ocean in search of clues that will help him save his family and return them to the bay.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-tides-of-time-sega-genesis', 'Ecco: The Tides of Time', 'Ecco the Dolphin', '1994-09-28', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65a3.jpg', '8-bit port of Ecco: The Tides of Time.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-jr-sega-genesis', 'Ecco Jr.', 'Ecco the Dolphin', '1995-08-15', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co43ng.jpg', 'Somewhere there is a place called the Endless Sea. There lives a giant whale named Big Blue. To find Big Blue, you have to open the Crystal Doors called Glyphs. To open the Crystal Doors, you must satisfy their wish. Guide Ecco and his friends to swim through the ocean and find Big Blue.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ghouls-n-ghosts-sega-genesis', 'Ghouls ''n Ghosts', 'Ghosts ''n Goblins', '1989-09-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95yx.jpg', NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-sega-genesis', 'Golden Axe', 'Golden Axe', '1989-12-22', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25qt.jpg', 'Progress is made through the game by fighting through Death Adder''s henchmen, including men armed with clubs and maces, skeleton warriors, and knights. Players are able to attack using their weapon, jump and cast spells that hurt all enemies on the screen. The force of this magic depends on the number of "bars" of magic power currently available. The bars are filled by collecting blue ''magic potions'' attained by kicking little sprites who then drop the potions. These sprites appear during regular levels and during bonus stages in between levels. The male warrior Ax is able to cast earth spells. The dwarf Gilius, casts lightning spells and the female warrior Tyris casts fire magic. Each character has a different number of maximum magic bars and varying ranges of attack.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-ii-sega-genesis', 'Golden Axe II', 'Golden Axe', '1992-01-26', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qgu.jpg', 'The Lord of Darkness, Dark Guld, has arisen again. Wielding the famous Golden Axe, he has destroyed entire countries with his evil clan, forcing the world into chaos. Once again, three brave warriors stand up to face the oppressors, and won’t rest until the Golden Axe is returned to its rightful place.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castle-of-illusion-starring-mickey-mouse-sega-genesis', 'Castle of Illusion Starring Mickey Mouse', 'Illusion', '1990-12-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6as3.jpg', 'To save his girlfriend Minnie from the wicked witch Mizrabel, Mickey must venture into the Castle of Illusion. Crossing six levels (including a magical forest, a toy land and a candy world), he must collect the gems of the rainbow in order to confront and defeat the witch.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-of-illusion-starring-mickey-mouse-and-donald-duck-sega-genesis', 'World of Illusion Starring Mickey Mouse and Donald Duck', 'Illusion', '1993-03-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9777.jpg', 'Alakazam! Here''s classic Disney fun with your favorites, Mickey Mouse and Donald Duck! Transported into a world of wonder, Mickey and Donald must perform amazing feats of magic to defeat a crafty Sorcerer and find their way back home!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-sega-genesis', 'Lemmings', 'Lemmings', '1992-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-2-the-tribes-sega-genesis', 'Lemmings 2: The Tribes', 'Lemmings', '1994-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6dnq.jpg', 'This port is almost completely identical to the main release. However, the lack of game intro and the greatly reduced quality of sounds with a chiptune soundtrack due to the sound card makes this an overall inferior port.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-sega-genesis', 'Marble Madness', NULL, '1991-08-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-vs-the-kingpin-sega-genesis', 'Spider-Man vs. The Kingpin', 'Marvel', '1991-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oo.jpg', 'Spider-Man vs. The Kingpin is a video game produced by Sega of America and developed by Technopop initially on the Mega Drive/Genesis. It was ported internally by Sega of America for the Master System and Game Gear consoles, the latter being published by Acclaim Entertainment through its Flying Edge division. An updated version was also released for the Sega CD under the name of The Amazing Spider-Man vs. The Kingpin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-and-the-avengers-sega-genesis', 'Captain America and The Avengers', 'Marvel', '1992-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h0d.jpg', 'The Captain America and the Avengers for Game Boy.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-the-x-men-in-arcade-s-revenge-sega-genesis', 'Spider-Man and the X-Men in Arcade''s Revenge', 'Marvel', '1993-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal21.jpg', 'Spider-Man and members of the X-Men have teamed up in this side-scrolling action game to fight against Arcade, who has built a giant amusement park for the sole purpose of trapping and destroying the super-heroes. You first play as Spider-Man, who sees the X-Men get kidnapped by Arcade and follows them. Once you make it inside Arcade''s park you can choose to play as Spider-Man, Cyclops, Storm, Gambit, or Wolverine, each of whom are trapped in a different part of Arcade''s maze of deadly traps. You must navigate all five of them safely out, using their different skills and abilities while defeating baddies and bosses along the way.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-sega-genesis', 'X-Men', 'Marvel', '1993-03-08', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97ob.jpg', 'A handheld video game based on Marvel''s superheroes X-Men.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolverine-adamantium-rage-sega-genesis', 'Wolverine: Adamantium Rage', 'Marvel', '1994-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xqh.jpg', 'Released in 1994 for both the Super NES and the Sega Genesis, Wolverine: Adamantium Rage is a platform-action video game. Teeny Weeny Games developed the Genesis version, while the Super NES version was created by Bits Studios. Despite being developed independently, the two versions share a common opening storyline and gameplay, though they differ in certain key aspects. Notably, it is one of the pioneering video games to incorporate a recharging health system.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-sega-genesis', 'The Incredible Hulk', 'Marvel', '1994-07-01', 'Sega Genesis', 0, 0, NULL, NULL, NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-venom-maximum-carnage-sega-genesis', 'Spider-Man and Venom: Maximum Carnage', 'Marvel', '1994-09-16', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal24.jpg', 'Spider-Man and Venom: Maximum Carnage is a side-scrolling beat ''em up game for the Super NES and Sega Genesis/Mega Drive, developed by Software Creations and published by Acclaim Entertainment and it''s subsidiary LJN in 1994. The game, based on a sprawling comic book story arc of the same name, features numerous heroes, including Spider-Man, Venom, and their allies from the Marvel Comics fictional universe like Captain America, Black Cat, Iron Fist, Cloak and Dagger, Deathlok, Morbius and Firestar, all teaming up to battle an onslaught of villains led by Carnage, including Shriek, Doppelganger, Demogoblin and Carrion.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-punisher-sega-genesis', 'The Punisher', 'Marvel', '1994-11-15', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p2u.jpg', 'Crime is everywhere on the streets of New York City. As Frank "the Punisher" Castle, it is your job to clean them up. However, there seem to be bigger things at hand...', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-sega-genesis', 'Spider-Man', 'Marvel', '1995-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-2-clone-wars-sega-genesis', 'X-Men 2: Clone Wars', 'Marvel', '1995-05-15', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5klx.jpg', 'Released in 1995, X-Men 2: Clone Wars is a platform game created by Headgames and published by Sega of America for the Mega Drive/Genesis. Serving as a sequel to 1993''s X-Men, the game is inspired by the Marvel Comics superhero team, the X-Men.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('venom-spider-man-separation-anxiety-sega-genesis', 'Venom/Spider-Man: Separation Anxiety', 'Marvel', '1995-11-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal37.jpg', 'Separation Anxiety is a side scrolling beat''em up game, featuring characters and stories taken from the Spiderman comics. The story is loosely based on a mini series of comics about Venom. In this game, the player(s) gets to choose between controlling Spider-Man, or his on and off again foe Venom. As Spiderman you must stop the life foundation who have removed five symbiotes from Venom. They plan to bond them with their soldiers, creating a dangerous army. Venom recovering from his wounds also realises he must destroy them.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-the-wily-wars-sega-genesis', 'Mega Man: The Wily Wars', 'Mega Man', '2022-01-28', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55cy.jpg', 'In the last few years, a titanic struggle for control of the planet has raged. Each time it has pitted Mega Man, a cybernetic champion of justice against the villainous Dr. Wily and his renegade robots. And each time, Mega Man has emerged victorious! Now, in a desperate attempt to change the past, Dr. Wily has used a time machine to slip back to the time of his first battles with Mega Man. There he plans to make sure that this time, Mega Man will be history!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-sega-genesis', 'Ms. Pac-Man', 'Pac-Man', '1990-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sq9.jpg', NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-attack-sega-genesis', 'Pac-Attack', 'Pac-Man', '1993-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kty.jpg', 'Pac-Man makes a rare appearance outside of a maze environment in Pac-Attack, a fun and quirky puzzle game. This unique entry in the genre puts its own twist on established conventions and adds one of gaming''s most iconic characters to the mix. The goal is simple: Keep your screen clear of falling blocks and ghosts by lining up blocks horizontally, causing them to disappear.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-2-the-new-adventures-sega-genesis', 'Pac-Man 2: The New Adventures', 'Pac-Man', '1994-01-01', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sss.jpg', 'Pac-Man 2: The New Adventures, known in Japan as Hello! Pac-Man, is a side-scrolling adventure game "sequel" to Pac-Man. Instead of being a maze game like the majority of its predecessors, Pac-Man 2 incorporates light point-and-click adventure game elements. It was produced and published by Namco for the Super Nintendo Entertainment System (SNES) and Sega Mega Drive/Genesis systems, and was released on April 6, 1994 by Namco. The game borrows its structure and certain elements from Pac-Land, and also appears to contain certain elements from the animated series, such as Pac-Man''s family and a main villain commanding the ghosts. The Genesis version was not released in Japan or Europe.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-sega-genesis', 'Prince of Persia', 'Prince of Persia', '1993-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ristar-sega-genesis', 'Ristar', NULL, '1995-02-16', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p00.jpg', 'Ristar is a platform game developed and published by Sega for the Sega Genesis in 1995. A Sega Game Gear game, of the same name and genre, Ristar, was also released, which shared similar themes while possessing different level design and gameplay mechanics. The game stars an anthropomorphic cartoon star who uses his hands and long, stretchable arms to both move and combat enemies. Reception for the game has been generally positive, but the game''s initial release was overshadowed due to the imminent ending of the Genesis''s lifecycle and the succession of the Sega Saturn and other fifth generation video game consoles. While never receiving any sequels, Sega has re-released the game a number of times digitally and on Sega-themed compilations, and has occasionally given Ristar himself cameos in other Sega properties.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('flicky-sega-genesis', 'Flicky', 'Sonic the Hedgehog', '1991-04-01', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7c8r.jpg', 'Join the adventures of Flicky, a fun-loving, little blue bird who drives cats everywhere crazy! As a heroic bird, find all of the missing Chirps and guide them to the “Exit” where they’ll be safe from those mischievous felines and other ferocious domesticated animals in the house.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-sega-genesis', 'Sonic the Hedgehog', 'Sonic the Hedgehog', '1991-06-23', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ubt.jpg', NULL, 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-2-sega-genesis', 'Sonic the Hedgehog 2', 'Sonic the Hedgehog', '1992-11-24', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwqd.jpg', 'Sonic the Hedgehog 2 is an LCD game created by Tiger Electronics in 1993. The background image used in the game is Oil Ocean Zone, from the 16-bit version of Sonic the Hedgehog 2.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-spinball-sega-genesis', 'Sonic the Hedgehog Spinball', 'Sonic the Hedgehog', '1993-11-23', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sca.jpg', 'Sonic Spinball is an LCD game created by Tiger Electronics in 1994. It is the first Tiger-based LCD game to use the rectangular-shaped 3rd generation casing. The game features two flipper buttons (with the left one doubling as a ball launcher) and looks to have been a standard pinball game. It also contains four function buttons on the center of the console that turn off the system, toggle sound effects, displays the high score, and turns on the system and starts the game. The background of the game features a level similar to the Machine in its 16-bit counterpart.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dr-robotnik-s-mean-bean-machine-sega-genesis', 'Dr. Robotnik''s Mean Bean Machine', 'Sonic the Hedgehog', '1993-11-26', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v8c.jpg', 'Dr. Robotnik is changing the jolly folk of Beanville into devious little robots that will help rid Planet Mobius of music and fun forever. Group the beans together to help them escape, and compete against Robotnik’s wily henchbots!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-3-sega-genesis', 'Sonic the Hedgehog 3', 'Sonic the Hedgehog', '1994-02-02', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar2r.jpg', 'Sonic the Hedgehog 3 is a special promotional cartridge created for the Sega Genesis by Paramount Pictures to promote the then-upcoming Sonic the Hedgehog 3 film.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-knuckles-sega-genesis', 'Sonic & Knuckles', 'Sonic the Hedgehog', '1994-10-18', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ups.jpg', 'Sonic and Knuckles join forces to defeat rotten Dr. Robotnik''s Death Egg invasion! Play Sonic & Knuckles by itself or Lock-on with other Sonic games. This game''s revolutionary Lock-on technology adds all new features to your other Sonic games for ultimate replays! Play as Sonic and let loose on Robotnik with amazing new powers. Play as Knuckles and tackle Robotnik and Metal Sonic with bare-fisted attacks, high-speed glides and wall-climbing power! Lock-on with Sonic 3 and transform Floating Island into a huge 34 meg Sonic-epic loaded with new secrets! Play as Sonic, Knuckles, and even Tails - with Game Save! Lock-on with Sonic 2 and play as Knuckles with all his signature moves!', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-3d-blast-sega-genesis', 'Sonic 3D Blast', 'Sonic the Hedgehog', '1996-11-07', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v74.jpg', 'Sonic 3D Blast is a 1996 platform video game developed by Traveller''s Tales and Sonic Team, and published by Sega for the Genesis, Saturn, and Windows. Part of the Sonic the Hedgehog series, the game abandons previous Sonic games'' side-scrolling style in favor of isometric gameplay, making use of some pre-rendered 3D models converted into sprites. The game features creatures known as Flickies, which first appeared in the 1984 arcade game Flicky. Controlling only Sonic himself, the player''s goal is to collect Flickies and carry them to safety, periodically sparring with the series antagonist Dr. Robotnik, who is imprisoning them within robots.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-classics-sega-genesis', 'Sonic Classics', 'Sonic the Hedgehog', '1997-08-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v7z.jpg', 'Sonic Classics compiles three games from the Sonic The Hedgehog series onto one cartridge. They are: Sonic the Hedgehog, Sonic the Hedgehog 2, Dr. Robotnik''s Mean Bean Machine
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-invaders-91-sega-genesis', 'Space Invaders ''91', 'Space Invaders', '1991-01-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9i9o.jpg', 'Space Invaders ''91 is a port of the the coin-op Space Invaders ''91, just like Super Space Invaders for other platforms, but still different from those. This version differs from Super Space Invaders in that there are no cutscenes, there is only one mode of play as opposed to SSI''s two, and there is no stage select.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toejam-earl-sega-genesis', 'ToeJam & Earl', 'ToeJam & Earl', '1991-10-15', 'Sega Genesis', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7u7r.jpg', 'The alien duo is back in an all-new adventure. In ToeJam & Earl III: Mission to Earth, ToeJam, Big Earl, and their new friend, Latisha, embark on a mission to retrieve the 12 sacred Albums of Funk, stolen by the inhabitantats of Earth. Across expansive environments, you must guide this group toward a showdown with the evil Anti-Funk. You''ll collect a wide variety of power-ups, take on dangerous side quests, and double-team the clueless Earthlings in style.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toejam-earl-in-panic-on-funkotron-sega-genesis', 'ToeJam & Earl in Panic on Funkotron', 'ToeJam & Earl', '1993-12-01', 'Sega Genesis', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rpc.jpg', 'ToeJam & Earl in Panic on Funkotron is a platform video game, developed by Johnson Voorsanger Productions and published by Sega originally in 1993.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-in-monster-world-sega-genesis', 'Wonder Boy in Monster World', 'Wonder Boy', '1992-02-01', 'Sega Genesis', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52cu.jpg', 'Monsters have taken over the land, and every day the citizens fear for their lives, hoping that a hero will step forth and bring peace to the embattled country.', 'NA', 37);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-returns-game-gear', 'Batman Returns', 'DC', '1992-09-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zck.jpg', 'Batman Returns is a beat-em-up side-scrolling game designed for the Sega consoles. It was published by Sega.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-adventures-of-batman-robin-game-gear', 'The Adventures of Batman & Robin', 'DC', '1995-06-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6379.jpg', 'Robin & Commissioner Gordon have mysteriously disappeared, and Batman suspects kidnapping. Have our two comrades succumb to the deadly beauty of Poison Ivy? Does the Riddler know the answer? Or will The Joker have the last laugh?', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-game-gear', 'Batman Forever', 'DC', '1995-09-04', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gyn.jpg', 'The Game Boy version of Batman Forever', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lucky-dime-caper-starring-donald-duck-game-gear', 'The Lucky Dime Caper starring Donald Duck', 'Donald Duck', '1991-10-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7tyb.jpg', 'Sorceress Magica De Spell and her rotten ravens have kidnapped Huey, Dewey and Louie! Worse yet, she''s snatched Uncle Scrooge''s Lucky Dime! Join Donald Duck in his quest to prove that Magica is no match for him.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deep-duck-trouble-starring-donald-duck-game-gear', 'Deep Duck Trouble Starring Donald Duck', 'Donald Duck', '1993-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2b8d.jpg', 'Uncle Scrooge found a magical necklace on a mysterious island, but the necklace put a curse on him. Now Uncle Scrooge is doomed to float around in the air forever! (Of course Donald always said Scrooge was full of hot air anyway!) To take the curse off Uncle Scrooge, Donald has to take the necklace back to the island. But there''s plenty of danger awaiting Donald there. How about lending him a hand?', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-dolphin-game-gear', 'Ecco the Dolphin', 'Ecco the Dolphin', '1993-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co23oy.jpg', 'Life was an adventure for Ecco, the young dolphin. The ocean seemed endless with rolling breakers to race through! At high speed Ecco could burst through the waves leaping through the air – almost flying! Until one day, all of that changed. A freak whirlpool of air and water tore the life from Ecco’s home leaving Ecco all alone. Now he must fight to stay alive, while traversing the vast ocean in search of clues that will help him save his family and return them to the bay.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-tides-of-time-game-gear', 'Ecco: The Tides of Time', 'Ecco the Dolphin', '1994-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65a3.jpg', '8-bit port of Ecco: The Tides of Time.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ax-battler-a-legend-of-golden-axe-game-gear', 'Ax Battler: A Legend of Golden Axe', 'Golden Axe', '1992-03-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47yt.jpg', 'Use your wits and your razor sharp sword to recapture the Golden Axe from the diabolical Death Adder. Defeat skeletons and giant bats in dark, deep chasms and caves. And summon Earth, Thunder and Fire Magic to fight gargoyles that come to life before your eyes!', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castle-of-illusion-starring-mickey-mouse-game-gear', 'Castle of Illusion Starring Mickey Mouse', 'Illusion', '1991-06-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6as3.jpg', 'To save his girlfriend Minnie from the wicked witch Mizrabel, Mickey must venture into the Castle of Illusion. Crossing six levels (including a magical forest, a toy land and a candy world), he must collect the gems of the rainbow in order to confront and defeat the witch.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('land-of-illusion-starring-mickey-mouse-game-gear', 'Land of Illusion Starring Mickey Mouse', 'Illusion', '1993-05-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zmt.jpg', 'Mickey finds himself in a fairy tale land where an evil Phantom-in-the-Clouds has stolen a special gem which brought peace and prosperity to a tiny village. It''s up to you to help him save the day - and earn a place in Minnie''s heart!', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('legend-of-illusion-starring-mickey-mouse-game-gear', 'Legend of Illusion Starring Mickey Mouse', 'Illusion', '1995-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6fbb.jpg', 'Mickey is tricked into a perilous quest when the kingdom is threatened by an evil cloud of darkness. As temporary king, Mickey must solve riddles, find maps and avoid trickery across 5 magical lands to save the Tree of Life from the cowardly King Pete.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-game-gear', 'Lemmings', 'Lemmings', '1994-12-06', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marble-madness-game-gear', 'Marble Madness', NULL, '1992-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ffw.jpg', 'Marble Madness is a tense and exciting pinball card building game. Using pinball collision as the main gameplay, supplemented by card construction, each game has a different experience, so experience the exhilaration of each collision.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-vs-the-kingpin-game-gear', 'Spider-Man vs. The Kingpin', 'Marvel', '1992-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oo.jpg', 'Spider-Man vs. The Kingpin is a video game produced by Sega of America and developed by Technopop initially on the Mega Drive/Genesis. It was ported internally by Sega of America for the Master System and Game Gear consoles, the latter being published by Acclaim Entertainment through its Flying Edge division. An updated version was also released for the Sega CD under the name of The Amazing Spider-Man vs. The Kingpin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-and-the-avengers-game-gear', 'Captain America and The Avengers', 'Marvel', '1993-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9h0d.jpg', 'The Captain America and the Avengers for Game Boy.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-return-of-the-sinister-six-game-gear', 'Spider-Man: Return of the Sinister Six', 'Marvel', '1993-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co987q.jpg', 'Spider-Man: Return of the Sinister Six is a side-scrolling game which puts you in the role of Spidey throughout six levels against Electro, Sandman, Mysterio, Vulture, Hobgoblin and Doctor Octopus respectively. Some puzzle solving (like finding a key) is necessary to beat some levels. Spidey can duck jump, climb walls, punch, shoot webs to swing (by pressing punch and jump together) and perform a jump kick (by pressing the punch button twice). Collecting web cartridges allows Spidey to shoot limited web projectiles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-game-gear', 'X-Men', 'Marvel', '1994-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97ob.jpg', 'A handheld video game based on Marvel''s superheroes X-Men.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-and-the-x-men-in-arcade-s-revenge-game-gear', 'Spider-Man and the X-Men in Arcade''s Revenge', 'Marvel', '1994-03-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coal21.jpg', 'Spider-Man and members of the X-Men have teamed up in this side-scrolling action game to fight against Arcade, who has built a giant amusement park for the sole purpose of trapping and destroying the super-heroes. You first play as Spider-Man, who sees the X-Men get kidnapped by Arcade and follows them. Once you make it inside Arcade''s park you can choose to play as Spider-Man, Cyclops, Storm, Gambit, or Wolverine, each of whom are trapped in a different part of Arcade''s maze of deadly traps. You must navigate all five of them safely out, using their different skills and abilities while defeating baddies and bosses along the way.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-game-gear', 'The Incredible Hulk', 'Marvel', '1994-07-01', 'Game Gear', 0, 0, NULL, NULL, NULL, 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-gamesmaster-s-legacy-game-gear', 'X-Men: Gamesmaster''s Legacy', 'Marvel', '1995-02-16', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ivv.jpg', 'X-Men: Gamesmaster''s Legacy is an action game released in 1995 on the Game Gear. The game starts off with Cyclops and Storm as playable X-Men, although Wolverine, Gambit, Rogue, Bishop, Jean Grey, and Cable can be later unlocked. It is loosely based on the "Upstarts" and "X-Cutioner''s Song" storylines that took place in the comics. It is the sequel to the original X-Men Game Gear game.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-and-x-o-manowar-in-heavy-metal-game-gear', 'Iron Man and X-O Manowar in Heavy Metal', 'Marvel', '1996-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co80mh.jpg', 'The Game Boy port of Iron Man and X-O Manowar in Heavy Metal.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-mojo-world-game-gear', 'X-Men: Mojo World', 'Marvel', '1996-09-27', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4eb5.jpg', 'X-Men: Mojo World, a video game released in 1996 for the Game Gear system, features Wolverine and Rogue as the initial playable X-Men, with Gambit, Cyclops, Havok, and Shard unlockable later on. The game utilizes the same engine as its predecessor, X-Men: Gamesmaster''s Legacy, and was also launched for the Master System in Brazil by Tec Toy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-game-gear', 'Mega Man', 'Mega Man', '1995-10-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3z14.jpg', 'A box set decorated with Mega Man 30th Anniversary art containing 19 Mega Man games and the voice acting script used for Mega Man 11.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-game-gear', 'Ninja Gaiden', 'Ninja Gaiden', '1991-12-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ip6.jpg', 'A handheld electronic port of Ninja Gaiden, released in 1989.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-game-gear', 'Pac-Man', 'Pac-Man', '1991-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mw3.jpg', 'Pac-Man 256 is inspired by the glitched 256th level of Pac-Man. In the game, the player must continuously navigate an endless maze while avoiding ghosts and using power-ups and power pellets to combat them. Fruits grant a temporary multiplier, and as Pac-Man eats dots, it is up to the player to try to top their high score.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-attack-game-gear', 'Pac-Attack', 'Pac-Man', '1994-06-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8kty.jpg', 'Pac-Man makes a rare appearance outside of a maze environment in Pac-Attack, a fun and quirky puzzle game. This unique entry in the genre puts its own twist on established conventions and adds one of gaming''s most iconic characters to the mix. The goal is simple: Keep your screen clear of falling blocks and ghosts by lining up blocks horizontally, causing them to disappear.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-game-gear', 'Prince of Persia', 'Prince of Persia', '1992-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ristar-game-gear', 'Ristar', NULL, '1995-02-16', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9p00.jpg', 'Ristar is a platform game developed and published by Sega for the Sega Genesis in 1995. A Sega Game Gear game, of the same name and genre, Ristar, was also released, which shared similar themes while possessing different level design and gameplay mechanics. The game stars an anthropomorphic cartoon star who uses his hands and long, stretchable arms to both move and combat enemies. Reception for the game has been generally positive, but the game''s initial release was overshadowed due to the imminent ending of the Genesis''s lifecycle and the succession of the Sega Saturn and other fifth generation video game consoles. While never receiving any sequels, Sega has re-released the game a number of times digitally and on Sega-themed compilations, and has occasionally given Ristar himself cameos in other Sega properties.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-game-gear', 'Sonic the Hedgehog', 'Sonic the Hedgehog', '1991-12-28', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ubt.jpg', NULL, 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-2-game-gear', 'Sonic the Hedgehog 2', 'Sonic the Hedgehog', '1992-11-17', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobwqd.jpg', 'Sonic the Hedgehog 2 is an LCD game created by Tiger Electronics in 1993. The background image used in the game is Oil Ocean Zone, from the 16-bit version of Sonic the Hedgehog 2.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-chaos-game-gear', 'Sonic Chaos', 'Sonic the Hedgehog', '1993-11-23', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30yz.jpg', 'Sonic Chaos is a fan game and re-imagining of the 1993 Sega Game Gear and Master System platform game of the same name. Based on the current style of 2D classic Sonic games inspired by Sonic Mania, Sonic Chaos updates the 8 bit visuals of the original and adapts a play style more closely resembling the classic 16-bit games.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dr-robotnik-s-mean-bean-machine-game-gear', 'Dr. Robotnik''s Mean Bean Machine', 'Sonic the Hedgehog', '1993-12-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v8c.jpg', 'Dr. Robotnik is changing the jolly folk of Beanville into devious little robots that will help rid Planet Mobius of music and fun forever. Group the beans together to help them escape, and compete against Robotnik’s wily henchbots!', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-spinball-game-gear', 'Sonic the Hedgehog Spinball', 'Sonic the Hedgehog', '1994-09-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sca.jpg', 'Sonic Spinball is an LCD game created by Tiger Electronics in 1994. It is the first Tiger-based LCD game to use the rectangular-shaped 3rd generation casing. The game features two flipper buttons (with the left one doubling as a ball launcher) and looks to have been a standard pinball game. It also contains four function buttons on the center of the console that turn off the system, toggle sound effects, displays the high score, and turns on the system and starts the game. The background of the game features a level similar to the Machine in its 16-bit counterpart.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-triple-trouble-game-gear', 'Sonic Triple Trouble', 'Sonic the Hedgehog', '1994-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5md2.jpg', 'Sonic Triple Trouble SMS is a fan-made Master System port of the original Sonic Triple Trouble, which was only released for the Game Gear and never got a Master System version. This port has been created by modifying the original Sonic the Hedgehog for the Sega Master System.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tails-adventure-game-gear', 'Tails Adventure', 'Sonic the Hedgehog', '1995-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ztg.jpg', 'Tails must stop the Battle Fortress bird army from taking control of Tails Island to rule over the animals.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-labyrinth-game-gear', 'Sonic Labyrinth', 'Sonic the Hedgehog', '1995-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobcxn.jpg', 'Port of the Game Gear title to the Sega Master System, honestly not the best way to play the game, the extra screen is actually garbage data, making it a bit confusing to play, unless you wanna play this on real hardware or using a Master System only emulator I recommend playing the GG version instead as this version does not give you any extra viewpoint.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-drift-2-game-gear', 'Sonic Drift 2', 'Sonic the Hedgehog', '1995-11-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ztt.jpg', 'Start your engines and prepare for the race of your life! Choose from 7 of your favorite characters including Sonic, Knuckles and Robotnik, each with his own special powers. Plug in your Gear to Gear connector and take on a friend through over 17 courses in the ultimate Chaos Grand Prix!', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-blast-game-gear', 'Sonic Blast', 'Sonic the Hedgehog', '1996-11-14', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ppf.jpg', 'Sonic Robo Blast is an early Sonic fan game from 1998, created by Sonikku, real name Johnny Wallbank, of Sonic Team Junior. It is one of the earliest Sonic fangames to exist and led to the founding of Sonic Team Junior as well as the eventual creation of it''s sequel, Sonic Robo Blast 2.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-game-gear', 'Star Wars', 'Star Wars', '1993-01-01', 'Game Gear', 0, 0, NULL, NULL, NULL, 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-star-wars-return-of-the-jedi-game-gear', 'Super Star Wars: Return of the Jedi', 'Star Wars', '1995-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xp.jpg', 'All the Adventure and Excitement of the 16-bit Game -- are you ready to challenge the dark side?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tempo-jr-game-gear', 'Tempo Jr.', 'Tempo', '1995-04-01', 'Game Gear', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9cyi.jpg', 'Music can be fun! Tempo, the hip-hoppin'' grasshopper lives in the musical world of planet Rhythmia. It''s up to Tempo to save the rhythm and give King Dirge the blues! Tempo boogies, spins, snaps his fingers and slings notes to zap King Dirge''s tune-swiping ants.', 'NA', 38);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('revenge-of-drancon-game-gear', 'Revenge of Drancon', 'Wonder Boy', '1991-01-01', 'Game Gear', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52cs.jpg', 'Your girlfriend... She''s gone! Kidnapped by the notorious King Drancon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-returns-sega-cd', 'Batman Returns', 'DC', '1993-05-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zck.jpg', 'Batman Returns is a beat-em-up side-scrolling game designed for the Sega consoles. It was published by Sega.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-adventures-of-batman-robin-sega-cd', 'The Adventures of Batman & Robin', 'DC', '1995-01-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6379.jpg', 'Robin & Commissioner Gordon have mysteriously disappeared, and Batman suspects kidnapping. Have our two comrades succumb to the deadly beauty of Poison Ivy? Does the Riddler know the answer? Or will The Joker have the last laugh?', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-sega-cd', 'Dragon''s Lair', 'Dragon''s Lair', '1993-01-01', 'Sega CD', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co790b.jpg', 'Dragon''s Lair is a side-scrolling platform game based on the laserdisc game of the same name released for the Nintendo Entertainment System and developed by the MotiveTime group. Plotwise, the game is identical to the original.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-dolphin-sega-cd', 'Ecco the Dolphin', 'Ecco the Dolphin', '1993-06-23', 'Sega CD', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co23oy.jpg', 'Life was an adventure for Ecco, the young dolphin. The ocean seemed endless with rolling breakers to race through! At high speed Ecco could burst through the waves leaping through the air – almost flying! Until one day, all of that changed. A freak whirlpool of air and water tore the life from Ecco’s home leaving Ecco all alone. Now he must fight to stay alive, while traversing the vast ocean in search of clues that will help him save his family and return them to the bay.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-tides-of-time-sega-cd', 'Ecco: The Tides of Time', 'Ecco the Dolphin', '1994-11-01', 'Sega CD', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65a3.jpg', '8-bit port of Ecco: The Tides of Time.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-vs-the-kingpin-sega-cd', 'Spider-Man vs. The Kingpin', 'Marvel', '1993-01-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co85oo.jpg', 'Spider-Man vs. The Kingpin is a video game produced by Sega of America and developed by Technopop initially on the Mega Drive/Genesis. It was ported internally by Sega of America for the Master System and Game Gear consoles, the latter being published by Acclaim Entertainment through its Flying Edge division. An updated version was also released for the Sega CD under the name of The Amazing Spider-Man vs. The Kingpin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-sega-cd', 'Prince of Persia', 'Prince of Persia', '1992-01-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-cd-sega-cd', 'Sonic CD', 'Sonic the Hedgehog', '1993-11-19', 'Sega CD', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6o6t.jpg', 'Sonic CD (also known as Sonic CD 2011) is a remaster of the original game, adding many new features like widescreen support, improved controls, access to both American and Japanese soundtracks and Tails as an unlockable playable character.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-rebel-assault-sega-cd', 'Star Wars: Rebel Assault', 'Star Wars', '1993-11-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2c0i.jpg', 'A bundle containing Star Wars: Rebel Assault and Star Wars: Rebel Assault II - The Hidden Empire.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-chess-sega-cd', 'Star Wars Chess', 'Star Wars', '1994-01-01', 'Sega CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e9v.jpg', 'Star Wars Chess is a chess game where the pieces are characters from the Star Wars universe. When pieces are taken, an animated battle is shown, much like in Battle Chess.', 'NA', 39);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-jr-and-the-great-ocean-treasure-hunt-sega-pico', 'Ecco Jr. and the Great Ocean Treasure Hunt', 'Ecco the Dolphin', '1995-01-01', 'Sega Pico', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/ji4rbiqesfjlwaj3si9m.jpg', 'An educational game for the Pico featuring Ecco Jr.', 'NA', 40);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tails-and-the-music-maker-sega-pico', 'Tails and the Music Maker', 'Sonic the Hedgehog', '1994-09-01', 'Sega Pico', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4vtg.jpg', 'Tails and the Music Maker is game that feature Tails "Miles" Prower as the main character. It debuted on the Sega Pico.', 'NA', 40);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-s-gameworld-sega-pico', 'Sonic the Hedgehog''s Gameworld', 'Sonic the Hedgehog', '1994-11-01', 'Sega Pico', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zve.jpg', 'Sonic the Hedgehog''s Gameworld is a game developed by Aspect Co. Ltd for the Sega Pico. It was released in Japan in August 1994. It was not released in North America until two years later, in November 1996, and was never released in Europe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-sega-32x', 'Doom', 'Doom', '1994-11-21', 'Sega 32X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-web-of-fire-sega-32x', 'The Amazing Spider-Man: Web of Fire', 'Marvel', '1996-03-01', 'Sega 32X', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4t7l.jpg', 'A massive electrical plasma grid has shrouded New York City in a blanket of hysteria and destruction. Skyscrapers are crumbling. Civilians are frying. It''s only a matter of time before The Big Apple becomes the Baked Apple.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('knuckles-chaotix-sega-32x', 'Knuckles'' Chaotix', 'Sonic the Hedgehog', '1995-04-20', 'Sega 32X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yio.jpg', 'A mysterious island rose from the sea shortly after the events of Sonic & Knuckles. Dr. Robotnik discovered the island, and found a mysterious ring inscribed with descriptions of the Chaos Rings, ancient Rings infused with Chaos Emerald energy. In order to find these Rings, Robotnik built his base, the Newtrogic High Zone, on the island. Mighty the Armadillo, Espio the Chameleon, Vector the Crocodile, and Charmy Bee also arrived at the island, and ended up being captured by Robotnik and Metal Sonic, and placed in Robotnik''s Combi Catcher machine. Knuckles, curious about the strange island, goes there as well, and manages to rescue Espio. The two then go on to stop Robotnik from getting the Chaos Rings.', 'NA', 41);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-arcade-sega-32x', 'Star Wars Arcade', 'Star Wars', '1994-11-21', 'Sega 32X', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xet.jpg', 'Launch your X-wing fighter for the final Death Star assault! The Force is with you as you pursue Darth Vader through an exploding galaxy! You are the last hope for the Rebel Alliance!', 'NA', 41);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tempo-sega-32x', 'Tempo', 'Tempo', '1995-01-01', 'Sega 32X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4hjz.jpg', 'Tempo is a rhythm platforming game, but instead of staying on the beat... You make the beat!', 'NA', 41);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('saturn-bomberman-sega-saturn', 'Saturn Bomberman', 'Bomberman', '1997-08-22', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2su8.jpg', 'Saturn Bomberman is an action game by Hudson Soft for the Sega Saturn. The twelfth installment in the Bomberman series, it was first released in Japan on July 19, 1996, in Europe in May 1, 1997, and in North America in September 4, 1997. It is best known for its multiplayer functionality for up to ten players using multitaps. It received praise for its gameplay and multiplayer, but criticism for not advancing the Bomberman series enough.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-sega-saturn', 'Sid Meier''s Civilization', 'Civilization', '1997-05-02', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hgf.jpg', 'An expansion pack to Sid Meier''s compelling strategy game Civilization II, the rare Scenario Disk Conflicts in Civilization includes 20 bonus scenarios, including eight "Best of the Net" scenarios created by fans of the series.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-legacy-of-war-sega-saturn', 'Contra: Legacy of War', 'Contra', '1997-05-21', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gfb.jpg', 'Contra: Legacy of War is a 3D action game produced by Konami and developed by Appaloosa Interactive that was originally released in 1996 for the PlayStation and Sega Saturn. It was the first of two Contra games that were externally developed by Appaloosa, followed by C: The Contra Adventure in 1998. The game marks the series'' jump to three-dimensional graphics and controversial changes in gameplay. Legacy of War was released packaged with a pair of 3D anaglyph glasses, which the game supported. Legacy of War bears the distinction for being the first console game in the series to retain both the Contra title and human characters during its release in Europe and Australia (where the console series has been known as Probotector from the first NES game and up until Contra: Hard Corps). The game was scheduled to be released in Japan as well, but was canceled.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('croc-legend-of-the-gobbos-sega-saturn', 'Croc: Legend of the Gobbos', 'Croc', '1997-01-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dmk.jpg', 'All is not well in Croc''s world. His friends, the Gobbos, have been captured by the evil Baron Dante. It is your mission in this 3D platformer to search through 42 different levels to save all of your friends before it''s too late.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-forever-the-arcade-game-sega-saturn', 'Batman Forever: The Arcade Game', 'DC', '1996-11-21', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yd0.jpg', 'A Final-Fight/Double-Dragon style game which features the Caped Crusader and his sidekick Robin in a traditional beat-em-up. Based on the Batman Forever movie, this side-scrolling beat-em-up features the plot, several memorable characters, and quotes from its movie counterpart.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-sega-saturn', 'Doom', 'Doom', '1997-03-31', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-the-duel-sega-saturn', 'Golden Axe: The Duel', 'Golden Axe', '1996-06-27', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co47yo.jpg', 'Many years have passed since the last war with Death Adder. But, as memories of those dark times begin to fade, another war is beginning. Out of the mists of time, a magical axe is discovered. The legend of the axe is well known throughout the land, for it is told that this axe is the very one which Gillius Thunderhead used to slay Death Adder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-3d-sega-saturn', 'Lemmings 3D', 'Lemmings', '1996-01-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co67te.jpg', 'Lemmings 3D is a puzzle video game released in 1995, developed by Clockwork Games and published by Psygnosis. The gameplay, like the original Lemmings game, requires the player to lead all the lemmings to their exit by giving them the appropriate "skills". It was the first Lemmings game to be rendered in 3D. It was released for DOS, PlayStation, and Sega Saturn, with all three releases being almost identical minus some performance differences.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-children-of-the-atom-sega-saturn', 'X-Men: Children of the Atom', 'Marvel', '1995-01-05', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wez.jpg', 'X-Men: Children of the Atom is an arcade game featuring characters licensed from Marvel Comics. Timed with the popularity of the mid-1990s X-Men animated series, the game incorporates voice actors from the show reprising their respective roles. The gameplay involves one-on-one fighting matches, where players face off against different characters in the game. The ultimate challenge comes in the form of battles against Juggernaut and Magneto.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-and-x-o-manowar-in-heavy-metal-sega-saturn', 'Iron Man and X-O Manowar in Heavy Metal', 'Marvel', '1996-01-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co80mh.jpg', 'The Game Boy port of Iron Man and X-O Manowar in Heavy Metal.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-the-pantheon-saga-sega-saturn', 'The Incredible Hulk: The Pantheon Saga', 'Marvel', '1997-04-10', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52sl.jpg', 'True to the comic books, the Hulk relies on no other weapons than his massive muscles to punch, kick and crush his enemies. When he has accumulated enough gamma energy, he may use powerful special moves like a Vortex Spin or the Floor Hammer. Rare bonus items also allow the Hulk to summon one of the four Pantheon team members Atalanta, Ulysses, Ajax and Hector to assist in the thick of battle.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-heroes-sega-saturn', 'Marvel Super Heroes', 'Marvel', '1997-10-02', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8sbu.jpg', 'Educational arcade-style games with Spider-Man, Wolverine, Iron Man and She-Hulk. Learn addiction, subtraction, multiplication, division, fractions, geometry and more. Exciting animation, sound and interactivity. Ages 8-12.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-8-sega-saturn', 'Mega Man 8', 'Mega Man', '1997-01-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55c7.jpg', 'A gigantic space explosion sends two strange meteors crashing to Earth. The call goes out and Mega Man speeds to the site. There he sees his arch-rival, Dr. Wiley, fleeing the scene, clutching one of the mysterious metallic meteors. Now Mega Man must uncover the secret of the second meteor in a race to stay one step ahead of Dr. Wiley and his new deadly breed of super-powered robots.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x4-sega-saturn', 'Mega Man X4', 'Mega Man X', '1997-09-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coar91.jpg', 'Battle armies of Maverick Reploid Robots while mastering all-new strategic moves like the Air Hover and Zero''s Saber Tactic system. Discover a myriad of power-ups, secret rooms, extra weapons and invincible vehicles to take on 8 all new X-Hunter Bosses. And for the first time, play as Mega Man X or battle with his mighty partner Zero in 2 separate adventures. Mega Man X4 - now you can be a hero, or a Zero!', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nights-into-dreams-sega-saturn', 'Nights into Dreams', 'Nights', '1996-08-20', 'Sega Saturn', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52xf.jpg', 'Cotton: Fantastic Night Dreams is a scrolling shooter arcade game, released on Sega''s Sega System 16B Arcade system board in 1989. It is the first in the Cotton series of videogames.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-sega-saturn', 'Panzer Dragoon', 'Panzer Dragoon', '1995-05-11', 'Sega Saturn', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ixu.jpg', 'Panzer Dragoon II Zwei is an "on-rails" shoot ''em up game released exclusively for the Sega Saturn. It was the second Panzer Dragoon game released but it is a prequel of the series. It was developed by Team Andromeda, one of Sega''s internal development studios.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-ii-zwei-sega-saturn', 'Panzer Dragoon II Zwei', 'Panzer Dragoon', '1996-05-10', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ixu.jpg', 'Panzer Dragoon II Zwei is an "on-rails" shoot ''em up game released exclusively for the Sega Saturn. It was the second Panzer Dragoon game released but it is a prequel of the series. It was developed by Team Andromeda, one of Sega''s internal development studios.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-saga-sega-saturn', 'Panzer Dragoon Saga', 'Panzer Dragoon', '1998-04-30', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobalf.jpg', 'Enter the world of Panzer Dragoon Saga and experience a game like no other: a fusion of classic Panzer action with the most technologically advanced RPG to come to Saturn. Board your morphing dragon and behold as the mysteries of the Panzer world unfurl across four massive CDs. The new "rail free" 3D engine lets you soar deeper into role-playing adventure than you ever before imagined. Your destiny awaits.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-sega-saturn', 'Quake', 'Quake', '1997-10-31', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-sega-saturn', 'Rayman', 'Rayman', '1995-11-01', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jo7.jpg', 'English with Rayman is an educational 2D platform game, based on the original Rayman. It was designed to teach young children the basics of the English language. It is not to be confused with Rayman Junior, which is an entirely different game. English with Rayman blends the Glade of Dreams with the real world in a way which makes little sense in the context of the series, making numerous references to real-world locations such as Ireland and Scotland. English with Rayman was adapted to teach various other languages under such names as French with Rayman.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-sega-saturn', 'Resident Evil', 'Resident Evil', '1997-08-31', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20cp.jpg', 'Resident Evil Archives: Resident Evil is the port of the remake Resident Evil for the Wii console system.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-3d-blast-sega-saturn', 'Sonic 3D Blast', 'Sonic the Hedgehog', '1996-11-07', 'Sega Saturn', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v74.jpg', 'Sonic 3D Blast is a 1996 platform video game developed by Traveller''s Tales and Sonic Team, and published by Sega for the Genesis, Saturn, and Windows. Part of the Sonic the Hedgehog series, the game abandons previous Sonic games'' side-scrolling style in favor of isometric gameplay, making use of some pre-rendered 3D models converted into sprites. The game features creatures known as Flickies, which first appeared in the 1984 arcade game Flicky. Controlling only Sonic himself, the player''s goal is to collect Flickies and carry them to safety, periodically sparring with the series antagonist Dr. Robotnik, who is imprisoning them within robots.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-jam-sega-saturn', 'Sonic Jam', 'Sonic the Hedgehog', '1997-08-22', 'Sega Saturn', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jb0.jpg', 'Sonic Jam 6 is a version of Super Mario Bros. 2 (the bootleg version) featuring Sonic instead of Mario. This version replaces the title screen with ported version of Sonic Jam''s and includes a screenshot of the Sega Mega Drive version of Sonic 3D Blast''s intro to overlap Mario''s face on the level intro/status screen. However, his face wasn''t removed in the bonus areas.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-r-sega-saturn', 'Sonic R', 'Sonic the Hedgehog', '1997-10-31', 'Sega Saturn', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sfd.jpg', 'Originally released for the Sega Saturn, Sonic R is a racing game featuring characters from the Sonic the Hedgehog series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-plus-sega-saturn', 'Tetris Plus', 'Tetris', '1996-10-18', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9idl.jpg', NULL, 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-sega-saturn', 'Tomb Raider', 'Tomb Raider', '1996-11-14', 'Sega Saturn', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 42);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-online-dreamcast', 'Bomberman Online', 'Bomberman', '2001-10-30', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co30fo.jpg', 'Just when you thought Bomberman had planted his last explosive, the prolific video game hero returns for a modern update on his classic series. With addictive battles, frantic new modes, and brand new stages, Bomberman Online offers explosive action for all. Fans of the older multiplayer versions of the franchise will rejoice at the inclusion of four online modes Battle Royal, Hyper Bomber, Panel Attack, and Submarine Attack each designed to accommodate up to 10 players. The game''s lone single-player mode boasts five awesome levels, and the graphics are rendered in 3D this time around.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ecco-the-dolphin-defender-of-the-future-dreamcast', 'Ecco the Dolphin: Defender of the Future', 'Ecco the Dolphin', '2000-09-10', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53la.jpg', 'At the dawn of the 30th Century, dolphins and humans had been together in a cross-species society for 500 years. Together, they had set out to explore space, offering peace and friendship to all who would welcome it. But space had its dangers; a violent species known as the Foe decided to conquer Earth. However, the dolphins and humans drove them to the brink of defeat, and so the Foe sought vengeance on Earth. The few caretaker dolphins who had been left behind on Earth were not entirely defenseless; they were protected by their creation called the Guardian—a gigantic, sentient being made of a crystalline substance which projected a forcefield over the entire planet. Undeterred, the Foe made suicide attacks on the field, searching for a weak point.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-2-dreamcast', 'Grand Theft Auto 2', 'Grand Theft Auto', '2000-05-01', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4s1j.jpg', 'The PSX port of Grand Theft Auto 2 is an open world action-adventure video game. It is the sequel to Grand Theft Auto, part of the Grand Theft Auto series. The open world design lets players freely roam Anywhere City, the setting of the game.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jet-grind-radio-dreamcast', 'Jet Grind Radio', 'Jet Set Radio', '2000-10-31', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rje.jpg', 'Jet Grind Radio (released as Jet Set Radio in Europe) is a video game for the Game Boy Advance system, which is based on the Dreamcast title of the same name. The game was developed by Vicarious Visions and published by THQ.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-clash-of-super-heroes-dreamcast', 'Marvel vs. Capcom: Clash of Super Heroes', 'Marvel', '1999-09-30', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9eql.jpg', 'This PlayStation port differs from the arcade version, in that players are unable to switch characters on-the-fly, reducing the secondary character to an assist role only.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-2-new-age-of-heroes-dreamcast', 'Marvel vs. Capcom 2: New Age of Heroes', 'Marvel', '2000-06-29', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95z7.jpg', 'The iOS port of Marvel vs. Capcom 2 introduces a new feature called Variable System that allows the player to tag in other team members at any time.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-dreamcast', 'Spider-Man', 'Marvel', '2001-04-19', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-dreamcast', 'Namco Museum', 'Namco Museum', '2000-06-25', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhd.jpg', 'Popular Namco games collected on Nintendo Switch.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ms-pac-man-maze-madness-dreamcast', 'Ms. Pac-Man Maze Madness', 'Pac-Man', '2000-11-13', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co66r6.jpg', 'Game Boy Advance port of Ms. Pac-Man: Maze Madness.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-3d-dreamcast', 'Prince of Persia 3D', 'Prince of Persia', '2000-11-21', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qzv.jpg', 'Prince of Persia 3D is an Action Adventure game, developed and published by Red Orb Entertainment, which was released in 1999. It is the third installment in the Prince of Persia franchise, and technically the first of many reboots the franchise has got. Even though the game follows plenty of concepts from the original duology of games, it has a completely unconnected story from them. Despite that, since the release of Prince of Persia: Sands of Time marks the second reboot and the start of the "modern era" of the franchise, this game is often considered a part of "original trilogy/classic trilogy" including the original duology.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-iii-arena-dreamcast', 'Quake III Arena', 'Quake', '2000-10-23', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ybj.jpg', 'Welcome to the Arena, where high-ranking warriors are transformed into spineless mush. Abandoning every ounce of common sense and any trace of doubt, you lunge onto a stage of harrowing landscapes and veiled abysses. Your new environment rejects you with lava pits and atmospheric hazards as legions of foes surround you, testing the gut reaction that brought you here in the first place. Your new mantra: Fight or be finished.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-2-the-great-escape-dreamcast', 'Rayman 2: The Great Escape', 'Rayman', '2000-03-21', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54kj.jpg', 'The PC version of Rayman 2: The Great Escape retains the same level structure from the Nintendo 64 version with higher resolution graphics and a higher frame rate.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-code-veronica-dreamcast', 'Resident Evil – Code: Veronica', 'Resident Evil', '2000-02-29', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vzn.jpg', 'Resident Evil Code: Veronica is the fourth video game in Capcom''s Resident Evil survival horror series. The game continues the survival horror gameplay of its predecessors: the protagonist explores the surroundings, fighting monsters and solving puzzles. However, it is the first game in the series to do away with pre-rendered backgrounds using a fully polygonal 3D engine instead, which allows for features such as real-time lighting and camera movement. Still, such movements are only used sparingly, and the use of perspective is mostly unchanged from earlier installments: the camera automatically switches to different static angles showing protagonists, monsters and rooms from different spooky viewpoints.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-3-nemesis-dreamcast', 'Resident Evil 3: Nemesis', 'Resident Evil', '2000-11-17', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobv12.jpg', 'Resident Evil 3: Nemesis remastered to be fully playable on modern PCs by Capcom and GOG. Join Jill Valentine, the survivor of the notorious disaster, as her nightmare continues. After resigning from S.T.A.R.S. Jill now prepares to head out of Raccoon City… but caught in a town crawling with zombies, more than ever she must rely on brute force and cunning to find a way to escape alive.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-dreamcast', 'Resident Evil 2', 'Resident Evil', '2000-12-06', 'Dreamcast', 0, 0, NULL, NULL, NULL, 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('seaman-dreamcast', 'Seaman', NULL, '2000-08-09', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9q1c.jpg', 'Seaman is a virtual pet video game for the Sega Dreamcast. It is one of the few Dreamcast games to take advantage of the microphone attachment. The narration is voiced by Toshiyuki Hosokawa in the original Japanese-language version and by Leonard Nimoy in the English-language version and the face of Seaman is actually that of the game''s producer, Yoot Saito.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-adventure-dreamcast', 'Sonic Adventure', 'Sonic the Hedgehog', '1999-09-09', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4iln.jpg', 'DLC for the PlayStation Network and Xbox Live Arcade versions of Sonic Adventure. It restores the ability to play as Metal Sonic and the Mission Mode from Sonic Adventure DX: Director''s Cut.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-shuffle-dreamcast', 'Sonic Shuffle', 'Sonic the Hedgehog', '2000-11-13', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ztr.jpg', 'Sonic Shuffle is a party game developed by Sonic Team and Hudson Soft and published by Sega for the Dreamcast video game console. The game is based on the prospect of advancing characters around a board game while playing mini-games in between turns, much in the same vein as Nintendo''s Mario Party.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-adventure-2-dreamcast', 'Sonic Adventure 2', 'Sonic the Hedgehog', '2001-06-23', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5agh.jpg', 'Sonic Adventure 2, even though it has the same name, it is actually a remaster for the original Sonic Adventure 2, with updated graphics and the assets from Sonic Adventure 2: Battle.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('space-channel-5-dreamcast', 'Space Channel 5', 'Space Channel 5', '2000-06-04', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w09.jpg', 'When the Morolians invade, ace reporter Ulala scoops the story for Space Channel 5. The hip-hopping aliens zap citizens into a hypnotic dance trance, but beat girl Ulala is their ultimate match. She busts out her grooviest attacks to free the captives and make headlines. Get down with Sega''s supernova star as she struts through the space station in style.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-racer-dreamcast', 'Star Wars Episode I: Racer', 'Star Wars', '2000-04-04', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wj7.jpg', 'Star Wars: Episode 1 - Racer lets you participate in the famous pod race sequence that was the critical highlight of the film Star Wars: Episode I, The Phantom Menace back in 1999.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-i-jedi-power-battles-dreamcast', 'Star Wars Episode I: Jedi Power Battles', 'Star Wars', '2000-10-18', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav0d.jpg', 'The game follows the plot of Star Wars Episode I: The Phantom Menace. Players can choose from one of five prequel-era Jedi and run, jump, slash, and use the Force through the game''s ten levels, starting on the Trade Federation Battleship and ending with the battle against Darth Maul on Naboo.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-demolition-dreamcast', 'Star Wars: Demolition', 'Star Wars', '2000-11-19', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ca.jpg', 'Experience Star Wars: Demolition originally released on the PlayStation console, enhanced with up-rendering, rewind, quick save, and custom video filters.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-next-tetris-dreamcast', 'The Next Tetris', 'Tetris', '2000-01-01', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fum.jpg', 'If you think you''ve mastered Tetris then think again! Now there''s The Next Tetris, a revolutionary twist on the classic puzzle game. More features, more challenging, and more addictive than ever. The Next Tetris - it''ll blow your mind!', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-tetris-dreamcast', 'Sega Tetris', 'Tetris', '2000-11-23', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v4u.jpg', NULL, 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-the-last-revelation-dreamcast', 'Tomb Raider: The Last Revelation', 'Tomb Raider', '2000-03-25', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3hbt.jpg', 'Tomb Raider IV: The Last Revelation is the fourth game of the Tomb Raider games series, it plays very similar to the previous games in the series but some new things have been added to the game. The biggest addition is that now rather large parts of the game consist of several interconnected levels sometimes explored in any order, with puzzles in one level often requiring that some actions are done in other levels. The new additions to Lara''s arsenal are a revolver and a bow with several sets of arrows including exploding and poisonous ones.', 'NA', 43);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-chronicles-dreamcast', 'Tomb Raider Chronicles', 'Tomb Raider', '2000-11-28', 'Dreamcast', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fnm.jpg', 'A remaster of the original Tomb Raider: Chronicles and the ability to toggle between original and remastered graphics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-typing-of-the-dead-dreamcast', 'The Typing of the Dead', NULL, '2001-01-23', 'Dreamcast', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tq7.jpg', 'The Typing of the Dead is an arcade game that was developed by WOW Entertainment and published by Sega for the NAOMI hardware. The game was released in Japanese arcades in 1999 and was ported to the Sega Dreamcast in 2001 by Smilebit. A Windows version was released in 2000 and a PlayStation 2 port followed in 2004.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-jam-game-com', 'Sonic Jam', 'Sonic the Hedgehog', '1998-07-10', 'Game.com', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3jb0.jpg', 'Sonic Jam 6 is a version of Super Mario Bros. 2 (the bootleg version) featuring Sonic instead of Mario. This version replaces the title screen with ported version of Sonic Jam''s and includes a screenshot of the Sega Mega Drive version of Sonic 3D Blast''s intro to overlap Mario''s face on the level intro/status screen. However, his face wasn''t removed in the bonus areas.', 'NA', 44);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-turbografx-16', 'Bomberman', 'Bomberman', '1991-01-01', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q1m.jpg', 'Bomberman Jetters is an action RPG that could be considered the spiritual successor to Bomberman Tournament.', 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-93-turbografx-16', 'Bomberman ''93', 'Bomberman', '1993-01-01', 'TurboGrafx-16', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co685w.jpg', 'Tension, strategy, action, excitement - Bomberman''s back!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bonk-s-adventure-turbografx-16', 'Bonk''s Adventure', 'Bonk', '1990-04-01', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ek3.jpg', NULL, 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bonk-s-revenge-turbografx-16', 'Bonk''s Revenge', 'Bonk', '1991-08-01', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5v5r.jpg', 'One day soon after arriving on the moon, Bonk hears an incredible explosion. Oh, no! The Earth has split into two! The sinister King Drool has struck again. This is bad. Real bad. Bonk must return to the Earth immediately!', 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('air-zonk-turbografx-16', 'Air Zonk', 'Bonk', '1992-10-01', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7hkq.jpg', 'The powered-up Zonk gathers his friends to form Team Cool, and they set out to stop King Drool’s plan to conquer the world. Choose from 3 levels of difficulty and 3 types of Friend Modes. Shoot King Drool''s cyber robots and avoid their attacks while collecting the Air Bones to unleash a variety of attacks. Enjoy unique moves such as combining with a friend to create an invincible hybrid form or blasting enemies with a charged attack. Air “Zonk” is filled with humor, like its wacky theme song that plays when you post a huge score or when your game is over.', 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('keith-courage-in-alpha-zones-turbografx-16', 'Keith Courage in Alpha Zones', NULL, '1989-08-29', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6msv.jpg', 'Now the Battle is in Your Hands.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-land-turbografx-16', 'Pac-Land', 'Pac-Man', '1990-01-01', 'TurboGrafx-16', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coad9l.jpg', 'Pac-Land is a side-scrolling action game released by Namco in 1984. The title follows Pac-Man on a quest to bring lost fairies home to Fairyland. What strange events will Pac-Man encounter as he leaves town, then passes through the mountains and forests? Pac-Man''s charming adventures begin here!', 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hatris-turbografx-16', 'Hatris', 'Tetris', '1991-05-24', 'TurboGrafx-16', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7198.jpg', NULL, 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-curse-turbografx-16', 'Dragon''s Curse', 'Wonder Boy', '1990-12-31', 'TurboGrafx-16', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6xeb.jpg', 'A port of Wonder Boy III: The Dragon''s Trap developed by Hudson Soft for the PC-Engine. It was released in Japan under the title of Adventure Island, shouldn''t be confused with the Adventure Island series, also by Hudson Soft.', 'NA', 45);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-turbografx-cd', 'Bomberman', 'Bomberman', '1992-01-01', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6q1m.jpg', 'Bomberman Jetters is an action RPG that could be considered the spiritual successor to Bomberman Tournament.', 'NA', 46);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-slayer-the-legend-of-heroes-turbografx-cd', 'Dragon Slayer: The Legend of Heroes', 'Dragon Slayer', '1992-12-01', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2faq.jpg', 'In this epic role-playing game, you must guide Prince Logan all accross the beautiful and dngerious world of Isrenasa in the quest to regain his throne. This game features a huge world to explore and many companions to join you on your journey. This game features one of the largest quests and most advanced interface of any role-playing game for the TurboDuo system.', 'NA', 46);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lemmings-turbografx-cd', 'Lemmings', 'Lemmings', '1992-11-27', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bjm.jpg', 'This port saw the same enhanced graphics and UI upgrade from their respective standalone ports return, as well as the higher quality music. However, an intro is absent.', 'NA', 46);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-turbografx-cd', 'Prince of Persia', 'Prince of Persia', '1992-10-01', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 46);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wonder-boy-iii-monster-lair-turbografx-cd', 'Wonder Boy III: Monster Lair', 'Wonder Boy', '1990-08-01', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52cx.jpg', 'The monsters are attacking the quiet town of Xenobia. Guide Leo and Priscilla to wipe out the monsters using the Legendary Weapons.', 'NA', 46);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-dynastic-hero-turbografx-cd', 'The Dynastic Hero', 'Wonder Boy', '1993-01-01', 'TurboGrafx-CD', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50af.jpg', 'The land of Tarron is under siege and you must save it from the wicked Drillkor Empire. A beautiful guide will help you along the way as only you, The Dynastic Hero, can deliver the goods!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-xbox', 'Beyond Good & Evil', 'Beyond Good & Evil', '2003-12-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n6b.jpg', 'Beyond Good & Evil is an action-adventure game with elements of puzzle-solving and stealth-based games. The player controls the protagonist, Jade, from a third-person perspective. Jade can run, move stealthily, jump over obstacles and pits, climb ladders, push or bash doors and objects, and flatten herself against walls. As Jade, the player investigates a number of installations in search of the truth about a war with an alien threat.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blinx-the-time-sweeper-xbox', 'Blinx: The Time Sweeper', 'Blinx', '2002-10-07', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xqi.jpg', 'Blinx: The Time Sweeper is a platform game developed by Artoon and published by Microsoft Game Studios. It was released for the Xbox on October 7, 2002. A sequel, Blinx 2: Masters of Time and Space, was released for the Xbox in 2004.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blinx-2-masters-of-time-and-space-xbox', 'Blinx 2: Masters of Time and Space', 'Blinx', '2004-11-16', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ip4.jpg', 'Blinx 2: Masters of Time & Space continues the adventures of Blinx, a heroic cat with the ability to make time slow, fast-forward, rewind, or stop. In this sequel, Blinx and his squad of tough, agile cats use their time-control powers to battle menacing time monsters, outmaneuver the criminal pig gang, and discover why time is disappearing. You can play as Blinx or his rivals--the sneaky pigs--who are equipped with the ability to morph and control space.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-finest-hour-xbox', 'Call of Duty: Finest Hour', 'Call of Duty', '2004-11-16', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b6a.jpg', '"Call of Duty: Finest Hour" is an immersive first-person shooter set against the dramatic backdrop of World War II. Developed by Spark Unlimited and published by Activision, this installment transports players to the heart of historic battles across multiple fronts. Experience the intensity of warfare through the eyes of American, British, and Soviet soldiers, each with unique missions and storylines.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-2-big-red-one-xbox', 'Call of Duty 2: Big Red One', 'Call of Duty', '2005-11-01', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b67.jpg', '"Call of Duty 2: Big Red One" is a first-person shooter developed by Treyarch and published by Activision, tailored specifically for console gamers. Released in 2005, the game focuses on the experiences of the U.S. Army''s 1st Infantry Division, famously known as the "Big Red One," during World War II.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('capcom-classics-collection-xbox', 'Capcom Classics Collection', 'Capcom Classics Collection', '2005-09-27', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaskp.jpg', 'Capcom serves up a collection of classic games in Capcom Classics Collection. You can relive more than 20 classic titles including 1942, Final Fight, Ghosts ''n Goblins, and Commando. The games can be played in either one- or two-player mode. Capcom Classics Collection also includes bonus material, such as remixed soundtracks, game tips, and original artwork.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('capcom-classics-collection-vol-2-xbox', 'Capcom Classics Collection Vol. 2', 'Capcom Classics Collection', '2006-11-14', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5tsl.jpg', 'Capcom Classics Collection Vol. 2 reacquaints players with the revolutionary games of their time while providing countless rounds of quarter-free entertainment. Each treasured favourite contains bountiful bonus features including remixed soundtracks, original art and history that will leave everyone wanting for more. Homes will turn into virtual arcade halls as this 20-in-1 compilation will have players flashing back to the good old days and introduce to a new generation the titles that helped define Capcom''s legacy as a leading worldwide developer and publisher.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-curse-of-darkness-xbox', 'Castlevania: Curse of Darkness', 'Castlevania', '2005-11-01', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1otg.jpg', 'Castlevania: Curse of Darkness is a direct sequel to Castlevania III: Dracula''s Curse. The game differs from its predecessor in a number of ways, including a more complex, action-adventure style of gameplay featuring character growth based on accumulated experience points. Master the unique new skills of Devil Forgery to develop and enhance Innocent Devils - allies that will help to conquer enemies, evade traps and solve challenging puzzles.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('conker-live-reloaded-xbox', 'Conker: Live & Reloaded', 'Conker', '2005-06-21', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2w7f.jpg', 'Conker, gaming’s notoriously naughty squirrel, arrives on the Xbox with a bang in an all-new Xbox Live-enabled team-based shooter, Conker: Live and Reloaded.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-the-wrath-of-cortex-xbox', 'Crash Bandicoot: The Wrath of Cortex', 'Crash Bandicoot', '2002-04-16', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55ex.jpg', 'Crash Bandicoot: The Wrath of Cortex is the fourth mainline series game and the first to feature Crash Bandicoot on the PlayStation 2. It was later ported to the GameCube and Xbox, making it his first multiplatform appearance. The player controls Crash and his younger sister Coco who must gather 25 crystals and defeat the main antagonists of the story, Doctor Neo Cortex and his new super weapon Crunch Bandicoot. Much of the game takes place in a Virtual Reality Hub System created by Coco to help Crash gather the crystals. The gameplay is similar to the older games of the series.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-nitro-kart-xbox', 'Crash Nitro Kart', 'Crash Bandicoot', '2003-11-11', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pya.jpg', 'Crash Bandicoot returns to the karting scene with a host of other characters from the adventure series, and this time they have both Neo Cortex and Emperor Velo to worry about. Velo has taken the crew to a remote planet, forced to race for their lives against Neo Cortex and his many evil doers.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-twinsanity-xbox', 'Crash Twinsanity', 'Crash Bandicoot', '2004-09-28', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co55if.jpg', 'Crash Twinsanity is the fifth mainline series game of the Crash Bandicoot series where Crash and the villain Cortex are forced into partnership. Each character occupies the same screen but they run along on different planes. Crash''s gameplay is mostly the same as before, he can still do his trademark spin attack, double jump and body slam moves. The originality comes in his duo with Dr. Cortex, as he can throw him to places he can''t reach himself or use him as a hammer to slap enemies. The consistent conflict between both heroes causes many funny situations.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-tag-team-racing-xbox', 'Crash Tag Team Racing', 'Crash Bandicoot', '2005-10-19', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7occ.jpg', 'Crash Bandicoot returns for high adrenaline racing, bending the rules of the track in Ebeneezer Von Clutch''s condemned arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-vengeance-xbox', 'Batman: Vengeance', 'DC', '2001-12-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h0x.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-the-man-of-steel-xbox', 'Superman: The Man of Steel', 'DC', '2002-11-19', 'Xbox', 0, 0, NULL, NULL, 'Superman: Man of Steel was the last known working title of an open world action game Factor 5 were working on for Brash Entertainment, which was being based around the legendary DC comics superhero license, Superman. It was planned to be made for the PS3, Xbox 360, and Nintendo Wii. Its initial codename was ‘Blue Steel’.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-dark-tomorrow-xbox', 'Batman: Dark Tomorrow', 'DC', '2003-03-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dys.jpg', 'Batman: Dark Tomorrow is an action-adventure video game developed by HotGen and published by Kemco for the Nintendo GameCube and Microsoft Xbox consoles. The Xbox version is not compatible with the Xbox 360. It is based on the DC Comics'' character Batman and his iteration from the DC Universe source material, unlike most other Batman games which are adaptations of the character in film or television appearances.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('aquaman-battle-for-atlantis-xbox', 'Aquaman: Battle for Atlantis', 'DC', '2003-07-30', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4sn0.jpg', 'Aquaman: Battle for Atlantis is an action-adventure video game for the Xbox and GameCube systems. Developed by Lucky Chicken Games and published by TDK, it is based on Peter David''s interpretation of the DC Comics character Aquaman.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-rise-of-sin-tzu-xbox', 'Batman: Rise of Sin Tzu', 'DC', '2003-10-16', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc6.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('catwoman-xbox', 'Catwoman', 'DC', '2004-07-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2d3t.jpg', 'Catwoman is an action-adventure video game based on the 2004 film of the same name based on the fictional character. It features the likeness of the film''s lead actress Halle Berry, while the character''s voice is provided by actress Jennifer Hale.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('constantine-xbox', 'Constantine', 'DC', '2005-02-14', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qyl.jpg', 'Indie MMORPG game, Constantine! Do Adventure And be strong! The Constantine is a world that exists inside Nathan''s tree. After spring, summer, autumn and winter, the world goes to sleep.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-begins-xbox', 'Batman Begins', 'DC', '2005-06-14', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xux.jpg', 'Game Boy Advance port of Batman Begins.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('teen-titans-xbox', 'Teen Titans', 'DC', '2006-05-24', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ubh.jpg', 'A game based on the "Teen Titans Go!" animated series. It follows the main character, Robin, as he seeks to be the best figure fighter in Jump City, a fictional city in the DC Universe.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-returns-xbox', 'Superman Returns', 'DC', '2006-11-22', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2des.jpg', 'Inspired by the Warner Bros. Pictures feature film and more than 60 years of DC Comics'' lore. As the Man of Steel, you’ll hone your unworldly super powers such as Flight, X-Ray Vision, Heat Vision, Super Hearing, Super Strength, Super Speed, and Super Breath to fight villains that only Superman can defeat.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('justice-league-heroes-xbox', 'Justice League Heroes', 'DC', '2006-11-22', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxy.jpg', 'The PlayStation Portable version of Justice League Heroes.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-invisible-war-xbox', 'Deus Ex: Invisible War', 'Deus Ex', '2003-12-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coboyb.jpg', 'Several religious and political factions see an opportunity to re-shape a worldwide government to their agendas. In this techno-nightmare, take part in the dark struggle to raise the world from its own ashes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3-xbox', 'Doom 3', 'Doom', '2005-04-03', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9dgk.jpg', 'A gameplay-altering mod that changes the slow pacing of the base game, to a more fast-paced action-horror shooter. The mod attempts to completely overhaul the entire game with new monsters, rebalanced weapons, rebalanced monster stats, better graphics, new gameplay features, and much more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3-resurrection-of-evil-xbox', 'Doom 3: Resurrection of Evil', 'Doom', '2005-10-05', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kwk.jpg', 'Doom 3: Resurrection of Evil (commonly abbreviated to as RoE) is an expansion pack for Doom 3 developed by Nerve Software and id Software included on BFG Edition that features enhanced graphics, better audio with more horror effects, a checkpoint save system, and support for 3D displays and HMDs.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-s-lair-3d-return-to-the-lair-xbox', 'Dragon''s Lair 3D: Return to the Lair', 'Dragon''s Lair', '2002-11-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22p7.jpg', 'Dragon''s Lair 3D: Return to the Lair is an action-adventure video game released in 2002 by Dragonstone Software. The game is based on Cinematronics'' 1983 laserdisc arcade game Dragon''s Lair, and follows a similar story; the hero, Dirk the Daring, must enter the evil wizard Mordroc''s castle to rescue Princess Daphne from Singe the dragon. Many of the characters and locations from the 1983 original make appearances in the game, along with new puzzles, rooms and enemies. Animator and director Don Bluth, who produced the cartoon animation for the arcade original, also produced two new animated sequences for the opening and ending of the game. The game uses cel shading to mimic the distinctive style of the original.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iii-morrowind-xbox', 'The Elder Scrolls III: Morrowind', 'The Elder Scrolls', '2002-06-06', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2knd.jpg', 'First-person WRPG and third mainline entry in the Elder Scrolls franchise in which the player arrives in the island of Vvardenfell, an exotic land plagued by disease-carrying storms and ruled by a godly Tribunal, in the Morrowind province of Tamriel, and takes part in the prophecy foretelling the second coming of Nerevar, who will supposedly save Morrowind from malicious clans both within and outside Vvardenfell.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iii-morrowind-game-of-the-year-edition-xbox', 'The Elder Scrolls III: Morrowind Game of the Year Edition', 'The Elder Scrolls', '2003-10-31', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ycf.jpg', 'An epic, open-ended single-player RPG, Morrowind allows you to create and play any kind of character imaginable. You can choose to follow the main storyline and find the source of the evil blight that plagues the land, or set off on your own to explore strange locations and develop your character based on their actions throughout the game. Featuring stunning 3D graphics, open-ended gameplay, and an incredible level of detail and interactivity, Morrowind offers a gameplay experience like no other.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-xbox', 'Fable', 'Fable', '2004-09-14', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc6d.jpg', 'Become the Hero you want to be in an immersive open-world action-RPG where each choice shapes your journey, reputation is everything, and fairytale endings are never guaranteed.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-the-lost-chapters-xbox', 'Fable: The Lost Chapters', 'Fable', '2005-10-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24mu.jpg', 'Fable was expanded and rereleased as Fable: The Lost Chapters for Xbox and Windows PC platforms in September 2005. The game was later ported to Mac OS X by Robosoft Technologies and published by Feral Interactive on 31 March 2008.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-brotherhood-of-steel-xbox', 'Fallout: Brotherhood of Steel', 'Fallout', '2004-01-14', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ybr.jpg', 'This is a Tactical Squad-Based Combat comes to the Fallout Universe. You are the wretched refuse. You may be born from dirt, but we will forge you into steel. You will learn to bend; if not you, will you break. In these dark times, the Brotherhood - your Brotherhood - is all that stands between the rekindled flame of civilization and the howling, radiated wasteland.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-instincts-xbox', 'Far Cry Instincts', 'Far Cry', '2005-09-27', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xeg.jpg', 'The game follows the story of a man named Jack Carver. Carver is a former service member of the United States Navy, who was dishonorably discharged following a number of illegal actions. Afterwards, he sets up a shop in Manhattan and begins supplying illegal arms to anyone and everyone, until a gang performs a hit using weapons supplied by Jack against a Mafia heir. Consequently, a price is put on his head by the Mob, and he was forced to flee the United States and settle in Micronesia.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-instincts-evolution-xbox', 'Far Cry Instincts Evolution', 'Far Cry', '2006-03-28', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ful.jpg', 'A sequel to Far Cry: Instincts with a different campaign.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grabbed-by-the-ghoulies-xbox', 'Grabbed by the Ghoulies', NULL, '2003-10-21', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co94o8.jpg', 'When Grabbed By The Ghoulies was featured in Rare Replay, it was the only one of the games in the collection that got itself remastered to run natively on the Xbox One.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-iii-xbox', 'Grand Theft Auto III', 'Grand Theft Auto', '2003-10-31', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb8.jpg', 'Featuring a fully 3-D living city, a combination of narrative driven and non-linear gameplay and a completely open environment, Grand Theft Auto III represents a huge leap forward in interactive entertainment. For the first time, players are put at the heart of their very own gangster movie, and let loose in a fully-realised 3 dimensional city, in which anything can happen and probably will.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-vice-city-xbox', 'Grand Theft Auto: Vice City', 'Grand Theft Auto', '2003-10-31', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co565f.jpg', 'In the year 1986, Tommy Vercetti is heavily indebted to his mafia superiors after a drug deal gone awry, but his dreams of taking over Vice City (based on Miami) push him down a different path. Featuring a wide variety of vehicles and weapons, radio stations playing hit songs from the era and an intense atmosphere, GTA: Vice City is an open-world sandbox satire of ''80''s Miami.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-san-andreas-xbox', 'Grand Theft Auto: San Andreas', 'Grand Theft Auto', '2005-06-07', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb9.jpg', 'Returning after his mother''s murder to the semi-fictional city of Los Santos (based on Los Angeles), Carl Johnson, a former gang banger, must take back the streets for his family and friends by gaining respect and once again gaining control over the streets. However, a story filled with crime, lies and corruption will lead him to trudge the entire state of San Andreas (based on California and Nevada) to rebuild his life.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('half-life-2-xbox', 'Half-Life 2', 'Half-Life', '2005-11-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co779u.jpg', 'This mod is to run Half-Life 2: Update (itself a mod for the original Half-Life 2) under MMod.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-combat-evolved-xbox', 'Halo: Combat Evolved', 'Halo', '2001-11-15', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2r2r.jpg', 'Bent on Humankind''s extermination, a powerful fellowship of alien races known as the Covenant is wiping out Earth''s fledgling interstellar empire. Climb into the boots of Master Chief, a biologically altered super-soldier, as you and the other surviving defenders of a devastated colony-world make a desperate attempt to lure the alien fleet away from earth. Shot down and marooned on the ancient ring-world Halo, you begin a guerilla-war against the Covenant. Fight for humanity against an alien onslaught as you race to uncover the mysteries of Halo.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-2-xbox', 'Halo 2', 'Halo', '2004-11-09', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x77.jpg', 'Halo 2 is the sequel to the highly successful and critically acclaimed Halo: Combat Evolved. In Halo 2, the saga continues as Master Chief—a genetically enhanced super-soldier—is the only thing standing between the relentless Covenant and the destruction of all humankind.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('indigo-prophecy-xbox', 'Indigo Prophecy', NULL, '2005-09-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3rhh.jpg', 'Indigo Prophecy is an action-adventure game that involves the player in making decisions to alter the narrative. The name change in North America was made to avoid confusion with Michael Moore''s Fahrenheit 9/11 documentary film, which was released in 2004. Indigo Prophecy introduced elements like ethical ambiguity, romance, the inability to perish, and interactive storytelling that would endure in Quantic Dream later games.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('jet-set-radio-future-xbox', 'Jet Set Radio Future', 'Jet Set Radio', '2002-02-25', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co87hw.jpg', 'Jet Set Radio Future is a video game developed by Smilebit and is the sequel to Jet Set Radio. Similar to the original, it depicts a future Tokyo where freedom of expression is outlawed. The user plays a character in the GG''s, a gang of in-line skating graffiti artists who skate around Tokyo covering up rival gangs'' graffiti, knocking over Rokkaku police, and dancing to the electric soundtrack. The game uses a cel-shaded style of animation, and has been widely acclaimed for its unique music style, detailed art, and gameplay. Though the game is set in the future, its style and content incorporates many aspects of 1980''s old school hip hop culture, as well as 1990''s J-pop culture.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-xbox', 'Bionicle', 'Lego', '2003-10-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3den.jpg', 'LEGO Bionicle is an action-adventure platformer in an isometric perspective. The player controls Takua, a villager on the island of Mata Nui through a series of linear levels that take place in the 6 different biomes across the island. This is the only canon handheld Bionicle game, and seems to serve as a prelude to the Mata Nui Online Game and Mata Nui Online Game II.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-video-game-xbox', 'Lego Star Wars: The Video Game', 'Lego', '2005-04-05', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5xvm.jpg', 'Take LEGO Star Wars mobile with the official port for the Game Boy Advance. Experience Star Wars in LEGO form while platforming through The Phantom Menace, Attack of the Clones and Revenge of the Sith.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-xbox', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mad-dash-racing-xbox', 'Mad Dash Racing', NULL, '2001-11-15', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4qm0.jpg', 'Mad Dash Racing combines high-speed combat and 3D adventure action with a crew of motley characters for an insane multiplayer competition for up to four. Players select from nine different characters, each with their own unique personality and abilities, and compete in a race for survival against the evil Hex, his dirty minions and your unforgiving friends. Glide across rivers of hot, steaming lava, slip through underwater pipes, bash through mammoth boulders, and slide down icy glaciers to beat the other racers and escape Hex''s wicked wrath.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-xbox', 'Spider-Man', 'Marvel', '2002-04-16', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97qp.jpg', 'A compilation of two Spider-Man games on the Game Boy Advance.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('blade-ii-xbox', 'Blade II', 'Marvel', '2002-09-03', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ot7.jpg', 'For countless generations there was very little to stand between vampires and their human prey--until now. In Blade II, you are a vampire hunter who possesses all the strengths of a vampire, and none of its weaknesses. Skilled in martial arts, guns, and swordplay, you must protect humans from the hungering darkness. Keep the evil forces at bay with your 360-degree combat system and unstoppable rage powers. High-tech weaponry, destructive rage abilities, and over-the-top finishing moves turn every enemy encounter into an action-packed bloodbath.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-next-dimension-xbox', 'X-Men: Next Dimension', 'Marvel', '2002-10-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzm.jpg', 'X-Men: Next Dimension is a fighting game and the third game in the X-Men: Mutant Academy game series. Next Dimension expands upon the concept of the first two games by adding several new characters, 3-D maps, and a story mode, which allows the player to fight a series of battles in between short movies that move the plot along. The plot of the story mode is loosely based on the comic story "Operation: Zero Tolerance".', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-2-new-age-of-heroes-xbox', 'Marvel vs. Capcom 2: New Age of Heroes', 'Marvel', '2003-03-27', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95z7.jpg', 'The iOS port of Marvel vs. Capcom 2 introduces a new feature called Variable System that allows the player to tag in other team members at any time.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x2-wolverine-s-revenge-xbox', 'X2: Wolverine''s Revenge', 'Marvel', '2003-04-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gx1.jpg', 'Logan was surgically implanted with the virtually unbreakable adamantium skeleton that made him into Wolverine, one of the world''s most famous X-Men. Now, more than 30 years later, Wolverine has discovered that he was also implanted with something else: a viral time-bomb that will render him lifeless in 48 hours. The clock is ticking. The antidote needs to be found quickly.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hulk-xbox', 'Hulk', 'Marvel', '2003-05-28', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ovx.jpg', 'Based after the events of the blockbuster movie (starring Eric Bana), you play Dr. Bruce Banner and his alter ego, green giant The Hulk. After fighting his way through the first year of his new identity, Bruce and The Hulk must now face a new enemy, The Leader, who wants to use the same gamma technology that created The Hulk in Bruce to develop an army of giants.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-2-xbox', 'Spider-Man 2', 'Marvel', '2004-06-28', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc6.jpg', 'In the console version of "Spider-Man 2", Manhattan becomes a gamer''s playground as you take the role of Spider-Man in a battle against the nefarious Doc Ock. Based on the plot of the movie Spider-Man 2 and the heroes and villains created by Marvel, the game allows players to encounter unique and dangerous villains as they patrol the streets and rooftops of the biggest city created in any Super Hero game to date.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-xbox', 'X-Men Legends', 'Marvel', '2004-09-21', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6b64.jpg', 'The N-Gage port of X-Men Legends.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-punisher-xbox', 'The Punisher', 'Marvel', '2005-01-16', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p2u.jpg', 'Crime is everywhere on the streets of New York City. As Frank "the Punisher" Castle, it is your job to clean them up. However, there seem to be bigger things at hand...', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-xbox', 'Fantastic Four', 'Marvel', '2005-06-27', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nah.jpg', 'The Fantastic Four video game, released in 1997 for the PlayStation, is a beat ''em-up action game based on the Marvel Comics superhero team. Developed by Probe Entertainment and published by Acclaim Entertainment, the game features playable characters Mr. Fantastic, The Invisible Woman, The Human Torch, The Thing, and She-Hulk, each with unique abilities. A version for the Sega Saturn was planned but ultimately cancelled. Players engage in combat, solve puzzles, and navigate obstacles across various levels, drawing from the rich lore of the Fantastic Four comics.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-ultimate-destruction-xbox', 'The Incredible Hulk: Ultimate Destruction', 'Marvel', '2005-08-23', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dzh.jpg', 'The Incredible Hulk: Ultimate Destruction, released in 2005, is an action-adventure video game developed by Radical Entertainment and published by Vivendi Universal Games (VU Games). The game centres around the Marvel Comics superhero, the Hulk, and features an open world with destructible environments. The storyline depicts the Hulk being unconsciously guided by his human alter-ego, Bruce Banner, and his psychotherapist, Leonard Samson. They influence him to construct a device aimed at healing Banner''s psyche and preventing the emergence of a darker personality. In addition to progressing through the main narrative, players can undertake side missions and acquire new abilities for the Hulk.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-nemesis-rise-of-the-imperfects-xbox', 'Marvel Nemesis: Rise of the Imperfects', 'Marvel', '2005-09-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1jr.jpg', 'Marvel Nemesis: Rise of the Imperfects pits fierce Marvel superheroes against each other in a 3D fighting game. You can assume control of heroes such as the Punisher, Spider-Man, and Captain America, and duel with them in interactive and destructible environments. A new team of superheroes called the Imperfects joins the mayhem. You can play in single-player story mode to unlock collectible awards, or you can play against other gamers in multiplayer modes.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-legends-ii-rise-of-apocalypse-xbox', 'X-Men Legends II: Rise of Apocalypse', 'Marvel', '2005-09-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pf0.jpg', 'X-Men Legends II: Rise of Apocalypse is an action role-playing game and a sequel to X-Men Legends. The player controls a party of four characters, though only one at a time can be controlled directly. Besides switching the characters for combat purposes, the player is often obliged to do so, because some of the tasks in the game require the specific abilities of a certain mutant. For example, Iceman can put out the fire, Magneto can generate a metal bridge across a gap, etc. Most of the time, however, is spent in combat, collecting loot and acquiring experience points. Unlike the first game, items dropped by enemies are random. The character will level up, become stronger, and learn new skills. The player can opt to allocate all the experience and skill points manually.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-spider-man-xbox', 'Ultimate Spider-Man', 'Marvel', '2005-09-22', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/lsjknidfrlnz2cintrkr.jpg', 'Help Spider-Man save Harry Osborn from the Venom symbiote.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-xbox', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-xbox', 'Marvel: Ultimate Alliance', 'Marvel', '2006-10-24', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-anniversary-collection-xbox', 'Mega Man Anniversary Collection', 'Mega Man', '2005-03-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7154.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-2-substance-xbox', 'Metal Gear Solid 2: Substance', 'Metal Gear', '2002-11-04', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5eg1.jpg', 'Metal Gear Solid 2: Substance is a re-vamped and revised edition of the original Metal Gear Solid 2: Sons of Liberty, in which Solid Snake must recover the stolen Metal Gear Ray from a group of terrorists bent on using its power for unthinkable reasons. Along with the original espionage shooter comes a collection of 200 VR missions. Missions range from killing certain targets and using particular weapons, as well as seeing the world of Solid Snake from different perspectives and styles, with first-person target modes and a variety mode including crazy characters of different shapes and sizes. Also included are various alternative missions, ranging from the protagonist sneaking around and snapping photos of targets to bomb disposal, all out destruction, and more.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-fellowship-of-the-ring-xbox', 'The Lord of the Rings: The Fellowship of the Ring', 'Middle-earth', '2002-09-24', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lum.jpg', 'J.R.R. Tolkien''s Middle-earth is a land of beauty, magic, and darkness. In The Lord of the Rings: The Fellowship of the Ring, you follow Tolkien''s narrative from the Shire to the halls of Moria, and finally to the banks of the River Anduin. Gameplay alternates between melee, archery, sorcery, and stealth as you control Frodo, Gandalf, and Aragorn. Join this band of heroes in their quest to destroy the One Ring, which contains all the power of the dark lord Sauron.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-two-towers-xbox', 'The Lord of the Rings: The Two Towers', 'Middle-earth', '2002-12-30', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gxb.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-return-of-the-king-xbox', 'The Lord of the Rings: The Return of the King', 'Middle-earth', '2003-11-05', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8hd8.jpg', 'An unlicensed Lord of the Rings Game using the engine from Pocky and Rocky with Becky. Despite the name, the game is vaguely based on the first Lord of the Rings movie, The Fellowship of the Ring. Each level starts off with a screenshot from the movie, though the actual levels and bosses have little resemblance', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-hobbit-xbox', 'The Hobbit', 'Middle-earth', '2003-11-11', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa3li.jpg', 'Step into the hairy hobbits'' feet of Bilbo Baggins in Vivendi Universal Games'' take on Tolkien''s prequel to the massive Lord of the Rings trilogy.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-third-age-xbox', 'The Lord of the Rings: The Third Age', 'Middle-earth', '2004-11-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20oi.jpg', 'The Lord of the Rings: The Third Age for Game Boy Advance is a turn-based tactics game released in 2004. The game consists of 2 campaigns (Good and Evil). In each campaign the player chooses a commander. As the player completes missions and progresses through the campaign, they are able to use experience points to purchase skills and equipment upgrades in order to enhance the performance of their primary and secondary heroes.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-xbox', 'Namco Museum', 'Namco Museum', '2002-10-09', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zhd.jpg', 'Popular Namco games collected on Nintendo Switch.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-50th-anniversary-xbox', 'Namco Museum 50th Anniversary', 'Namco Museum', '2005-08-30', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dz6.jpg', 'Includes 14 Classic Arcade Hits
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-xbox', 'Ninja Gaiden', 'Ninja Gaiden', '2004-03-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ip6.jpg', 'A handheld electronic port of Ninja Gaiden, released in 1989.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-black-xbox', 'Ninja Gaiden Black', 'Ninja Gaiden', '2005-09-20', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9b3s.jpg', 'Using Unreal Engine 5 to significantly enhance graphic expression, this is the definitive version of "NINJA GAIDEN 2," featuring additional playable characters and enhanced battle support functions.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-munch-s-oddysee-xbox', 'Oddworld: Munch''s Oddysee', 'Oddworld', '2001-11-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yni.jpg', 'Oddworld: Munch''s Oddysee is set in the fictional Oddworld universe and take place after those of Abe''s Exoddus. The player controls Munch as well as Abe, the hero of the previous Oddworld games. Abe''s abilities haven''t changed much since the last installment: as before, GameSpeak must be used to communicate with other creatures, leading them to safety. His fellow Mudokons can now be ordered to attack enemies. Abe can also grab and toss Mudokons or Munch to lead them to area they cannot access otherwise. Possessing enemies also comes into play, and is needed to solve many of the puzzles. Possession abilities can now be used to ignite quarrels between enemies and make them fight each other.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('oddworld-stranger-s-wrath-xbox', 'Oddworld: Stranger''s Wrath', 'Oddworld', '2005-01-25', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gu1.jpg', 'Oddworld: Stranger''s Wrath is set in the fictional Oddworld universe, differing in many ways from the preceding installment. The game incorporates two basic genres: third-person platforming action and first-person shooter. The player can switch between the modes at any time by using a melee or a ranged weapon, respectively. The goal of the game, for the most part, is to bag the outlaws and bring them in, collecting "moolah" (the game''s currency) in the process. The Stranger can stun or knock down enemies, as well as use a stealthy approach, e.g. hiding in long grass to surprise the enemy.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-2-xbox', 'Pac-Man World 2', 'Pac-Man', '2002-10-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa8l2.jpg', 'PAC-MAN WORLD 2 Re-PAC modernizes, updates, and enhances the fan favorite 3D Platforming adventure in nearly every way! Venture across PAC-LAND to reclaim the golden fruit and put a stop to the ghosts and their dastardly boss, Spooky!', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-world-3-xbox', 'Pac-Man World 3', 'Pac-Man', '2005-11-17', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bc8.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('panzer-dragoon-orta-xbox', 'Panzer Dragoon Orta', 'Panzer Dragoon', '2003-01-12', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co68yo.jpg', 'The fourth installment of the Panzer Dragoon series has you playing Orta, a young girl who has been imprisoned by the Empire. Under a wave of attack, the prison camp is broken through by a mysterious dragon, and Orta takes it upon herself to ride the dragon, and destroy the Empire once and for all. Along the way, she will also discover her own destiny, and the mystery surrounding her new friend.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-sands-of-time-xbox', 'Prince of Persia: The Sands of Time', 'Prince of Persia', '2003-11-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4t8l.jpg', 'Deceived by the treacherous Vizier, I was led to unleash the Sands of Time curse upon the Sultan''s kingdom. With little but an ancient dagger and a devious princess to aid me, I must undo my fatal mistake. Mine is a fight for survival… not glory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-warrior-within-xbox', 'Prince of Persia: Warrior Within', 'Prince of Persia', '2004-12-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52j9.jpg', 'Prince of Persia: Warrior Within is the mobile J2ME port of the PC/console game of the same title.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-two-thrones-xbox', 'Prince of Persia: The Two Thrones', 'Prince of Persia', '2005-12-01', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coav9r.jpg', 'In the mobile version of the last game in the trilogy, the Prince returns to Babylon after the events of the previous game, only to find out that a vizier has taken his throne. This new ruler has captured the Babylonian women. You need to set them free and defeat the vizier at the same time. Exposure to the sands of time, however, has awakened an evil presence inside the Prince, which manifests itself as the Dark Prince. During the game, you will often morph into the other presence, whose only goal it to reclaim the throne, the populace be damned.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-xbox', 'Psychonauts', 'Psychonauts', '2005-04-19', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7ms.jpg', 'Psychonauts is a platform-adventure game developed by Double Fine Productions and released in 2005. It follows Razputin “Raz” Aquato, a young psychic who runs away from the circus to attend a summer camp for aspiring psychonauts. Players explore imaginative levels set inside the minds of different characters, each reflecting their mental states. Gameplay combines platforming, combat, and the use of psychic abilities such as telekinesis and levitation. The game was praised for its creativity, humor, and distinctive art style.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-m-xbox', 'Rayman M', 'Rayman', '2002-09-24', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctf.jpg', 'Developed by Ubisoft Montpellier and Pastagames, Rayman Mini follows Rayman on a legendary journey as he has been reduced to the size of ant! To undo this spell, Rayman will travel through a macro-photographic world, encountering friendly allies and defeating epic bosses along the way.', NULL, 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-3-hoodlum-havoc-xbox', 'Rayman 3: Hoodlum Havoc', 'Rayman', '2003-03-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jnb.jpg', 'This port of Rayman 3 released for the DigiBlast handheld console is based on the Game Boy Advance port of the game, but has less stages and no multiplayer. Every pseudo-3D stage were removed.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-revolver-xbox', 'Red Dead Revolver', 'Red Dead', '2004-05-04', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lcn.jpg', 'Red Dead Revolver is a 2004 action-adventure game developed by Rockstar San Diego and published by Rockstar Games. It is the first entry in the Red Dead series and was released for the PlayStation 2 and Xbox in May 2004.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rollercoaster-tycoon-xbox', 'RollerCoaster Tycoon', 'RollerCoaster Tycoon', '2003-03-25', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2r6q.jpg', 'The premise of the game is to complete a series of preset scenarios by successfully building and maintaining amusement parks through business ownership as a theme park entrepreneur. The key to any park is building a large amount and diverse range of rides for the visitors. Players can choose from dozens of roller coaster types and can also build log flumes, carousels, bumper cars, haunted houses, go karts, ferris wheels, and swinging ships, among other rides. The intensity and type of rides must be balanced, as visitors'' preferences vary significantly from person to person. For example, some guests prefer exciting rides and have high nausea tolerance levels, while other guests are just the opposite.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-xbox', 'The Sims', 'The Sims', '2003-03-25', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5sap.jpg', 'The Everyday Sims Bundle will transform how your Sims live day to day, from teaching life lessons to child Sims to doing their laundry!', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-bustin-out-xbox', 'The Sims Bustin'' Out', 'The Sims', '2003-12-16', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5w.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-urbz-sims-in-the-city-xbox', 'The Urbz: Sims in the City', 'The Sims', '2004-11-09', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6a5s.jpg', 'Starting out as a humble window washer in the city of Miniopolis, the player is quickly embroiled in a devious plot by the greedy tycoon Daddy Bigbucks to take over the city.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-2-xbox', 'The Sims 2', 'The Sims', '2005-10-24', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4ja7.jpg', 'The Sims 2 for Nintendo DS is the first DS game of The Sims 2. Like the many of the console games it takes place in Strangetown with some of the same faces.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-heroes-xbox', 'Sonic Heroes', 'Sonic the Hedgehog', '2004-01-27', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9olx.jpg', 'Sonic Heroes is an adventure and multiplatform video game in the Sonic The Hedgehog series, developed by Sonic Team and published by SEGA for the Nintendo GameCube, Sony PlayStation 2, Microsoft Xbox and Microsoft Windows PCs.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mega-collection-plus-xbox', 'Sonic Mega Collection Plus', 'Sonic the Hedgehog', '2004-11-02', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2uz8.jpg', 'Sonic Mega Collection Plus is an update of Sonic Mega Collection for the PlayStation 2 and Xbox consoles. A Microsoft Windows version was also released in Europe and North America. This edition includes all of the games in Sonic Mega Collection, including the two Genesis games that were included in the Japanese version of Sonic Mega Collection, plus the addition of six Game Gear games.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-the-hedgehog-xbox', 'Shadow the Hedgehog', 'Sonic the Hedgehog', '2005-11-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4s0m.jpg', 'Shadow the Hedgehog in Sonic the Hedgehog brings the Ultimate Lifeform to South Island to put a stop to Dr. Robotnik''s Evil Plans!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-riders-xbox', 'Sonic Riders', 'Sonic the Hedgehog', '2006-02-21', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coam3h.jpg', '"Sonic Riders Plus" is a mod of the original Sonic Riders for the Gamecube that focuses on enhancing the competitive potential of the game while still remaining true to the game''s nature.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-a-hero-s-tail-xbox', 'Spyro: A Hero''s Tail', 'Spyro', '2004-11-09', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48ew.jpg', 'Spyro: A Hero''s Tail is the fifth console game in the original Spyro series and the ninth game in the series in all. Developed by Eurocom, it was the first game in the series for the Xbox, as well as the second game in the series for the PlayStation 2 and GameCube (with the former console release being the only one of the three to support widescreen). It is also the final installment in the original Spyro continuity for home consoles. This is also the first and only Spyro game to be completely produced in Europe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-a-new-beginning-xbox', 'The Legend of Spyro: A New Beginning', 'Spyro', '2006-10-10', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86aa.jpg', NULL, 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-starfighter-special-edition-xbox', 'Star Wars: Starfighter: Special Edition', 'Star Wars', '2001-11-26', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6bcy.jpg', 'The Special Edition of Star Wars Starfighter for Xbox features high-quality air and space combat, with added missions, a two-player mode, expanded racing and capture-the-flag play, and improved graphics. Set in the Star Wars universe and inspired by The Phantom Menace, players must save Naboo from the Trade Federation''s invasion. Players choose from three pilots, each with a unique ship: Rhys, a Naboo pilot-in-training with the N-1 starfighter; Vana, a Naboo expatriate with an ultra-fast, stealthy ship; and Nym, an alien pirate with a powerful, heavily armed starship.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-obi-wan-xbox', 'Star Wars: Obi-Wan', 'Star Wars', '2001-12-19', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2485.jpg', 'Join the legendary Jedi Knight Obi-Wan Kenobi as he takes on the worst scum and villainy the galaxy has to offer in level after level of fast-paced action. In Star Wars: Obi-Wan, you''ll call upon the Force and your powerful lightsaber as you face a mysterious new enemy, an assassin droid project and a devious plot that could dramatically shift the balance of power in the universe. Fight your way through an underworld trail of munitions dealers and crime lords-from the lowest depths of Coruscant and dusty Tatooine to the lush city of Theed. The Force is in your hands.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-starfighter-xbox', 'Star Wars: Jedi Starfighter', 'Star Wars', '2002-05-13', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1n.jpg', 'The game features two immediately playable craft: Nym''s starfighter, "The Havoc", which features heavy armament as a bomber, and Adi''s fighter, which features force powers such as lightning and force shield.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-ii-jedi-outcast-xbox', 'Star Wars Jedi Knight II: Jedi Outcast', 'Star Wars', '2002-11-19', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y67.jpg', 'In the tradition of the highly acclaimed Star Wars: Jedi Knight series, Star Wars: Jedi Knight 2, Jedi Outcast features rebel agent Kyle Katarn in exhilarating first-person action. Several years have passed since Kyle avenged his father''s death and saved the Valley of the Jedi from Jerec and his band of Dark Jedi. Allowing his Force powers to languish for fear of falling to the dark side, Kyle entrusted his lightsaber to Luke Skywalker, vowing never to use it again. But when a new and menacing threat to the galaxy emerges, Kyle knows he must reclaim his past in order to save his future.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-xbox', 'Star Wars: The Clone Wars', 'Star Wars', '2003-04-22', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p1l.jpg', 'The Clone Wars has you deep inside the battles of the Old Republic through 16 missions, piloting a range of vehicles including speeder bikes, Republic Gunships and fighter tanks as well as the weapon of the Jedi, your lightsabre, for close combat. Whereas the Rogue Squadron series concentrated on aerial battles, The Clone Wars contains almost all ground battles. You must fight as Anakin Skywalker, Obi Wan Kenobi, Mace Windu, and others throughout the game to prevent the Confederacy from gaining a deadly weapon. Multiplayer options are also included for up to four players with game types including deathmatch, conquest, and a co-op ground and vehicle survival mode.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-knights-of-the-old-republic-xbox', 'Star Wars: Knights of the Old Republic', 'Star Wars', '2003-07-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tmz.jpg', 'Choose Your Path! Set 4,000 years before the Galactic Empire, you are the last hope for the Jedi Order and the Republic - can you master the ways of the Force to become their savior? Or will you fall to the dark side and achieve ultimate power? Hero, villain, peacekeeper, or chaos-bringer... you and your party will determine the fate of the galaxy!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-knight-jedi-academy-xbox', 'Star Wars Jedi Knight: Jedi Academy', 'Star Wars', '2003-11-18', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5c44.jpg', 'Star Wars: Jedi Knight: Jedi Academy, of the highly acclaimed Jedi Knight series, allows players to take on the role of a new student eager to learn the ways of the Force from Jedi Master Luke Skywalker. Interact with famous Star Wars characters in many classic Star Wars locations as you face the ultimate choice: fight for good and freedom on the light side, or follow the path of power and evil to the dark side.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-xbox', 'Star Wars: Battlefront', 'Star Wars', '2004-09-21', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2res.jpg', 'In 2004, the original Star Wars: Battlefront came onto the scene and took gamers – and Star Wars fans – by surprise. It was an ambitious action shooter that gave players the opportunity to step into the shoes of their favorite Star Wars characters, pilot quintessential Star Wars vehicles, and relive classic Star Wars battles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-knights-of-the-old-republic-ii-the-sith-lords-xbox', 'Star Wars Knights of the Old Republic II: The Sith Lords', 'Star Wars', '2004-12-06', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrj.jpg', 'Star Wars Knights of the Old Republic II: The Sith Lords is a sequel to the blockbuster RPG Star Wars Knights of the Old Republic. Players continue to enjoy the title''s emotionally compelling and story-driven theme, additions to features such as new characters, classes, locations and force powers as well as a deeper look into the founding lore.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-republic-commando-xbox', 'Star Wars: Republic Commando', 'Star Wars', '2005-02-28', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2au4.jpg', 'Chaos has erupted throughout the galaxy. As a leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihalate the enemy. Your squad will follow your orders and your lead, working together as a team-instinctively, intelligently, instantly. You are their leader. They are your weapon.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-episode-iii-revenge-of-the-sith-xbox', 'Star Wars: Episode III – Revenge of the Sith', 'Star Wars', '2005-05-04', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3sjo.jpg', 'The Clone Wars continue to rage between the Republic and the Separatists. Supreme Chancellor Palpatine has been taken hostage, and Obi-Wan, together with Anakin, must rescue him! The Star Wars Episode III: Revenge of the Sith games for the Game Boy Advance and Nintendo DS systems allow players to experience the stunning Jedi action of the movie. Developed by Ubisoft''s Montreal studio, each version leverages the strengths of its handheld platform to produce the ultimate Jedi action experience. The control of multiple heroes, devastating Force powers, and never-before-seen locations are just a few of the elements in store!', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-ii-xbox', 'Star Wars: Battlefront II', 'Star Wars', '2005-11-01', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1g4.jpg', 'Star Wars: Battlefront II is the sequel to Star Wars: Battlefront. It is a high-selling Star Wars video game following the many adventures of several characters. The two games are very similar, as both revolve around troopers from various factions fighting in different locales. Battlefront II, however, includes elements and missions from Star Wars: Episode III Revenge of the Sith, as well as enhanced aspects of gameplay including space combat and the ability to play as Jedi characters or other heroes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-deluxe-xbox', 'Super Monkey Ball Deluxe', 'Super Monkey Ball', '2005-03-15', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rhe.jpg', 'This game is basically a fusion of Super Monkey Ball 1 and 2 for the PS2 and XBox. All of the levels from those two games are available in this collection, and all of the minigames are already unlocked and included. Formerly only available to GameCube players, the Super Monkey Ball series has made it to the PS2 and Xbox after a wait of almost 3 and a half years.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thief-deadly-shadows-xbox', 'Thief: Deadly Shadows', 'Thief', '2004-05-25', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rom.jpg', 'In the third instalment of the Thief series, master-thief Garrett is contacted by Keeper Artemus with a mission to steal two valuable artefacts. At the same time, Garrett learns about a prophecy: the coming of a Dark Age. He embarks upon a journey to unravel a mystery that threatens the existence of the order of Keepers. Is it possible that there is a traitor in their midst?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('toejam-earl-iii-mission-to-earth-xbox', 'ToeJam & Earl III: Mission to Earth', 'ToeJam & Earl', '2002-10-23', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7u7r.jpg', 'The alien duo is back in an all-new adventure. In ToeJam & Earl III: Mission to Earth, ToeJam, Big Earl, and their new friend, Latisha, embark on a mission to retrieve the 12 sacred Albums of Funk, stolen by the inhabitantats of Earth. Across expansive environments, you must guide this group toward a showdown with the evil Anti-Funk. You''ll collect a wide variety of power-ups, take on dangerous side quests, and double-team the clueless Earthlings in style.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-xbox', 'Tom Clancy''s Splinter Cell', 'Tom Clancy''s Splinter Cell', '2002-11-17', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r1.jpg', '2D versions of the game were released for the Game Boy Advance and N-Gage (the latter as Tom Clancy''s Splinter Cell: Team Stealth Action), as well as the mobile phones version developed by Gameloft. A remastered high definition version of Tom Clancy''s Splinter Cell was released on the PlayStation 3 in September 2011. The success of the game series spawned a series of novels written under the pseudonym David Michaels.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-pandora-tomorrow-xbox', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow', 'Tom Clancy''s Splinter Cell', '2004-03-23', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tce.jpg', 'Tom Clancy''s Splinter Cell: Pandora Tomorrow is a stealth video game developed and published by Ubisoft Shanghai and Ubisoft Milan, while Ubisoft Montreal, developer of the original Splinter Cell, was working on Chaos Theory. Pandora Tomorrow is the second game in the Splinter Cell series endorsed by writer Tom Clancy. The game follows the covert activities of Sam Fisher, an agent working for a black-ops branch of the National Security Agency (NSA) called "Third Echelon". Sam Fisher is voiced by Michael Ironside. Dennis Haysbert voices the character Irving Lambert, Fisher''s boss, making this the only time he is not voiced by Don Jordan. Lalo Schifrin provides the theme music for the game. A remastered high-definition version of Tom Clancy''s Splinter Cell: Pandora Tomorrow was announced for the PlayStation Network for the PlayStation 3 on December 20, 2010.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-chaos-theory-xbox', 'Tom Clancy''s Splinter Cell: Chaos Theory', 'Tom Clancy''s Splinter Cell', '2005-03-28', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95rb.jpg', 'Tom Clancy''s Splinter Cell: Chaos Theory is the mobile version of the console game of the same name and the fourth mobile game in the series. Like the previous games in the series it is a stealth based platform game played from a side view perspective and has similar gameplay. The player once again controls Sam Fisher who has to prevent terrorists from crashing the global stock markets and overthrow the world''s governments.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-xbox', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2006-10-24', 'Xbox', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-xbox', 'Tomb Raider: Legend', 'Tomb Raider', '2006-04-11', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-evolution-xbox', 'Turok: Evolution', 'Turok', '2002-09-01', 'Xbox', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1p3p.jpg', 'Get locked and loaded in an exciting prequel to the Turok series. Turok: Evolution is an epic adventure set against the backdrop of living jungles, mysterious temples, and deadly dinosaurs. Battle over 32 types of dinosaurs as Tal''Set, a warrior caught in the midst of a brutal war in the Lost Land. Use your arsenal of all-new weapons including Variable Payload Cruise Missiles, Gravity Disruptor beams, and the Swarm Bore. Soar through the skies on a winged Quetzalcoatlus, or set out on foot on of the lush interactive environments. Experience an adventure before time.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-castle-wolfenstein-xbox', 'Return to Castle Wolfenstein', 'Wolfenstein', '2003-05-06', 'Xbox', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xzr.jpg', 'Return to Castle Wolfenstein is a first-person shooter and a reboot of Wolfenstein 3D. The player''s arsenal includes among others a Luger, MP 40 submachine gun, Mauser rifle with sniper scope, flamethrower, dynamite and grenades. The game also features a multiplayer component in which players are split into Axis and Allies sides with each a set of objectives to complete.', 'NA', 47);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alan-wake-xbox-360', 'Alan Wake', 'Alan Wake', '2010-05-18', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jar.jpg', 'Alan Wake 2 marks Remedy Entertainment’s first foray into the survival horror genre. Ritualistic murders in a small town. A writer trapped in a nightmare. An FBI agent looking for answers. Two realities. Two hero characters. One horror story that wants them dead.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-xbox-360', 'Assassin''s Creed', 'Assassin''s Creed', '2007-11-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ka7.jpg', 'A bundle including three Assassin''s Creed titles: Assassin''s Creed Valhalla, Assassin''s Creed Odyssey, and Assassin''s Creed Origins.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-ii-xbox-360', 'Assassin''s Creed II', 'Assassin''s Creed', '2009-11-17', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rcf.jpg', 'Discover an intriguing and epic story of power, revenge and conspiracy set during a pivotal moment in history: the Italian Renaissance.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-brotherhood-xbox-360', 'Assassin''s Creed: Brotherhood', 'Assassin''s Creed', '2010-11-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5j8z.jpg', 'A remaster of Assassin''s Creed Brotherhood included with Assassin''s Creed: The Ezio Collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-revelations-xbox-360', 'Assassin''s Creed: Revelations', 'Assassin''s Creed', '2011-11-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xih.jpg', 'Assassin''s Creed Revelations presents the most immersive experience available in the series to date and the culmination of Ezio''s adventure. In Assassin''s Creed Revelations, master assassin Ezio Auditore walks in the footsteps of his legendary mentor, Altair, on a journey of discovery and revelation. It is a perilous path - one that will take Ezio to Constantinople, the heart of the Ottoman Empire, where a growing army of Templars threatens to destabilize the region.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-xbox-360', 'Assassin''s Creed III', 'Assassin''s Creed', '2012-10-30', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xii.jpg', 'The American Colonies, 1775. A brave young warrior fights to save his homeland. But what begins as a struggle over territory turns into an extraordinary journey that will transform him into a Master Assassin—and will forever change the destiny of a nation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-ezio-trilogy-xbox-360', 'Assassin''s Creed: Ezio Trilogy', 'Assassin''s Creed', '2012-11-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49hd.jpg', 'Assassin''s Creed: Ezio Trilogy is a collection of the three main series Assassin''s Creed games that feature Ezio Auditore da Firenze: Assassin''s Creed II, Assassin''s Creed: Brotherhood, and Assassin''s Creed: Revelations. The Bonfire of the Vanities, the Battle of Forlì, and the exclusive black ''Bonus Skin''. DLC for Assassin''s Creed II is only available with the PS3 version; The xbox 360 version only includes the original games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iv-black-flag-xbox-360', 'Assassin''s Creed IV: Black Flag', 'Assassin''s Creed', '2013-10-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tx9.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-the-americas-collection-xbox-360', 'Assassin''s Creed: The Americas Collection', 'Assassin''s Creed', '2014-10-28', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co49pi.jpg', 'Assassin''s Creed: The Americas Collection is a compilation consisting of three games in the Assassin''s Creed series. The Americas Collection includes Assassin''s Creed III, Assassin''s Creed: Liberation HD and Assassin''s Creed IV: Black Flag.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-rogue-xbox-360', 'Assassin''s Creed Rogue', 'Assassin''s Creed', '2014-11-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xir.jpg', 'Assassin''s Creed Rogue is a 2014 action-adventure video game developed by Ubisoft Sofia and published by Ubisoft. It is the seventh major installment in the Assassin''s Creed series, and is set between 2012''s Assassin''s Creed III and 2013''s Assassin''s Creed IV: Black Flag. It also has ties to Assassin''s Creed Unity, which was released on the same day as Rogue. It is the last Assassin''s Creed game to be developed for the seventh generation of consoles, being released for PlayStation 3 and Xbox 360 in November 2014 and for Windows in March 2015.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('banjo-kazooie-nuts-bolts-xbox-360', 'Banjo-Kazooie: Nuts & Bolts', 'Banjo-Kazooie', '2008-11-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2feg.jpg', 'Banjo and Kazooie are facing their greatest adventure yet, battling long-time nemesis Gruntilda for rightful ownership of Spiral Mountain. Use your wits and imagination to invent wild and wonderful contraptions so Banjo and Kazooie can crush this wicked witch. Rule the road, sky, and water in the land of Banjo-Kazooie: Nuts & Bolts!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bayonetta-xbox-360', 'Bayonetta', 'Bayonetta', '2010-01-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamt.jpg', 'This is a European bundle that includes Bayonetta 1 and Bayonetta 2 both in each own disc and case for the WiiU.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bejeweled-3-xbox-360', 'Bejeweled 3', 'Bejeweled', '2011-11-15', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zso.jpg', 'The biggest, brightest Bejeweled ever! Discover all-new ways to play the world''s #1 puzzle game. Find your perfect match with 8 breathtaking game modes that meet all your moods ease into Classic Bejeweled for cascades of fun, journey through 40 challenging Quest puzzles, charge into the electrifying Lightning for non-stop action, and tailor your experience in Zen for a revolutionary new way to relax.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-xbox-360', 'BioShock', 'BioShock', '2007-08-21', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3aet.jpg', 'The year is 1960 and the player character, Jack, is on board a plane crossing the Atlantic ocean. Things go wrong though and the plane crashes. Jack is lucky though and finds himself outside a lighthouse. This is no ordinary lighthouse however. It leads to Rapture, an Utopian underwater city built by the tycoon Andrew Ryan. It''s not long until Jack is contacted by a man called Atlas who offers Jack his support.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-2-xbox-360', 'BioShock 2', 'BioShock', '2010-02-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mlj.jpg', 'BioShock 2 is the second game of the BioShock series and the sequel to BioShock. It continues the grand storyline of the underwater metropolis Rapture. BioShock 2 capitalizes and improves upon the high-quality effects, unique gameplay elements, and immersive atmosphere that defined the first game. It explores more brutal gameplay than its predecessor, with new enemies, weapons, Plasmids, and Gene Tonics.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-ultimate-rapture-edition-xbox-360', 'BioShock: Ultimate Rapture Edition', 'BioShock', '2013-01-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co54yf.jpg', 'This edition includes the original BioShock, BioShock 2 and add-on content for both games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-infinite-xbox-360', 'BioShock Infinite', 'BioShock', '2013-03-26', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n12.jpg', 'BioShock Infinite is the third game in the BioShock series. It is not a direct sequel/prequel to any of the previous BioShock games but takes place in an entirely different setting, although it shares similar features, gameplay and concepts with the previous games. BioShock Infinite features a range of environments that force the player to adapt, with different weapons and strategies for each situation. Interior spaces feature close combat with enemies, but unlike previous games set in Rapture, the setting of Infinite contains open spaces with emphasis on sniping and ranged combat against as many as fifteen enemies at once.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-infinite-the-complete-edition-xbox-360', 'BioShock Infinite: The Complete Edition', 'BioShock', '2014-11-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50k0.jpg', 'BioShock Infinite: The Complete Edition is a re-release of BioShock Infinite including all its downloadable content.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bomberman-act-zero-xbox-360', 'Bomberman: Act Zero', 'Bomberman', '2006-08-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uml.jpg', 'Bomberman: Act Zero is an action video game developed by Hudson Soft and published by Konami for the Xbox 360 in 2006. It is noteworthy for its departure from standard titles in the Bomberman series; it features more realistic graphics and a dark, dystopian future setting.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-xbox-360', 'Borderlands', 'Borderlands', '2009-10-20', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tx.jpg', 'With its addictive action, frantic first-person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is a breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell-bent on finding a legendary stockpile of powerful alien technology known as The Vault.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-game-of-the-year-edition-xbox-360', 'Borderlands: Game of the Year Edition', 'Borderlands', '2010-10-12', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229j.jpg', 'Lock, Load, & Face the Madness! Get ready for the mind-blowing insanity, as one of four trigger-happy mercenaries, taking out everything that stands in your way. With its addictive action, frantic first person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is the breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell bent on finding a legendary stockpile of powerful alien technology known as The Vault.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-2-xbox-360', 'Borderlands 2', 'Borderlands', '2012-09-18', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ba3.jpg', 'A new era of shoot and loot is about to begin. Play as one of four new vault hunters facing off against a massive new world of creatures, psychos and the evil mastermind, Handsome Jack. Make new friends, arm them with a bazillion weapons and fight alongside them in 4 player co-op on a relentless quest for revenge and redemption across the undiscovered and unpredictable living planet.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-2-game-of-the-year-edition-xbox-360', 'Borderlands 2: Game of the Year Edition', 'Borderlands', '2013-10-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k8e.jpg', 'Borderlands 2 furthers the distinct blending of First Person Shooter and Role Playing genres to create the true evolution of the Role Playing Shooter. Team up with up to three other players for four-player online goodness or go old-school with two-player split-screen couch sharing mayhem as you spend hours leveling up your character and equipping them with one of the millions of badass weapons. Borderlands 2 features a new visually stunning array of procedurally generated guns, shields, grenades, artifacts, enemies and more. Choose one of the four new character classes to be taken through a carefully crafted and connected story to all new and surprising environments across the living planet of Pandora. Make new friends, arm them to the teeth and fight alongside them on your relentless quest for revenge and redemption.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-the-pre-sequel-xbox-360', 'Borderlands: The Pre-Sequel', 'Borderlands', '2014-10-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tq.jpg', 'Shoot ''n'' loot your way through a brand new adventure that rockets you onto Pandora''s moon in Borderlands: The Pre-Sequel. Discover the story behind Borderlands 2’s villain, Handsome Jack, and his rise to power in this brand new game in the Borderlands series. Taking place between the original Borderlands and Borderlands 2, the Pre-Sequel gives you a whole lotta new gameplay featuring the genre fusion of shooter and RPG gameplay that players can’t get enough of.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-the-borderlands-xbox-360', 'Tales from the Borderlands', 'Borderlands', '2016-04-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tr.jpg', 'Tales from the Borderlands is a five part episodic game series. Set on the unforgiving world of Pandora after the events seen in Borderlands 2, this is a story full of Borderlands'' trademark humor, following two adventurers on their quest for greatness.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('br-tal-legend-xbox-360', 'Brütal Legend', NULL, '2009-10-13', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27c8.jpg', 'Brütal Legend is an action-adventure that marries visceral action combat with open-world freedom. Set in a universe somewhere between Lord of the Rings and Spinal Tap, it’s a fresh take on the action/driving genre, which in this case is full of imitation cover bands, demons intent on enslaving humanity and Heavy metal tunes. Featuring the talents of comedian, actor and musician, Jack Black as super roadie Eddie Riggs, as well as cameos by some of the biggest names in metal music it''s a wild ride in the belly of the beast that is not to be missed by gamers and Metalheads alike.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-2-xbox-360', 'Call of Duty 2', 'Call of Duty', '2005-11-22', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co804s.jpg', 'The mobile version of "Call of Duty 2" brings the intense World War II action of the acclaimed series to handheld devices. Developed to capture the essence of its console counterpart, this version offers players a chance to experience iconic battles on the go.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-3-xbox-360', 'Call of Duty 3', 'Call of Duty', '2006-11-07', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wku.jpg', '"Call of Duty 3" is a first-person shooter developed by Treyarch and published by Activision, released in 2006. This installment in the acclaimed series focuses on the Normandy breakout, one of the most pivotal moments of World War II, and follows the Allied forces'' push to liberate Paris from Nazi occupation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-4-modern-warfare-xbox-360', 'Call of Duty 4: Modern Warfare', 'Call of Duty', '2007-11-05', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2adb.jpg', 'Call of Duty 4: Modern Warfare is a game in the Call of Duty series franchise, developed specifically for the Nintendo DS. It was released on November 5, 2007. Like Call of Duty 4: Modern Warfare for traditional consoles, the Nintendo DS version takes place in modern day and offers players modern weapons. The game features many elements of gameplay typical to the series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-world-at-war-xbox-360', 'Call of Duty: World at War', 'Call of Duty', '2008-11-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wl8.jpg', 'Call of Duty: World at War immerses players into the most gritty and chaotic WWII combat ever experienced. Players band together to survive the most harrowing and climactic battles that led to the demise of the Axis powers on the European and Pacific fronts.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-modern-warfare-2-xbox-360', 'Call of Duty: Modern Warfare 2', 'Call of Duty', '2009-11-10', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3cwt.jpg', 'Call of Duty: Modern Warfare 2 is a first-person shooter video game developed by Infinity Ward and published by Activision for the Xbox 360 and PlayStation 3 video game consoles and the Microsoft Windows operating system. Officially announced on February 11, 2009, the game was released worldwide on November 10, 2009. It is the sixth installment of the Call of Duty series and the direct sequel to Call of Duty 4: Modern Warfare, continuing the same storyline, with Call of Duty: Modern Warfare 3 set to end the storyline.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-xbox-360', 'Call of Duty: Black Ops', 'Call of Duty', '2010-11-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wkl.jpg', 'Call of Duty: Black Ops is the seventh main Call of Duty game and the sequel to Call of Duty: World at War. The game differs from most previous installments, which would involve a usual three-country campaign, while Call of Duty: Black Ops features two playable countries (Russia and the USA) but only has an American campaign. Several new features are also introduced, such as dive-to-prone and the available use of a flashlight on certain weapons. Furthermore, the campaign''s playable characters now speak while being controlled by the player.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-modern-warfare-3-xbox-360', 'Call of Duty: Modern Warfare 3', 'Call of Duty', '2011-11-08', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctx.jpg', 'The game brings "open combat, " offering players more choices in approaching the single-player missions. Makarov returns as the chief villain of the new campaign.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-ii-xbox-360', 'Call of Duty: Black Ops II', 'Call of Duty', '2012-11-13', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wkv.jpg', 'Pushing the boundaries of what fans have come to expect from the record-setting entertainment franchise, Call of Duty: Black Ops II propels players into a near future, 21st Century Cold War, where technology and weapons have converged to create a new generation of warfare between old and new foes. In this conflict, the mechanized creations of men reign supreme, facing off against each other as their creators stay safe and unconflicted, and in the process grow ever softer. In this scenario an important question will be asked: What happens when an enemy steals the keys to your war? To understand such a possible future, you must understand where you have been.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lords-of-shadow-xbox-360', 'Castlevania: Lords of Shadow', 'Castlevania', '2010-10-05', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pnz.jpg', 'Castlevania: Lords of Shadow 2 is an action-adventure game and a sequel to the 2010 game, Castlevania: Lords of Shadow, and the 35th installment on the Castlevania franchise. The game was developed by MercurySteam and published by Konami. This is MercurySteam''s last contribution to the franchise. The story is set in both medieval and modern worlds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-lords-of-shadow-2-xbox-360', 'Castlevania: Lords of Shadow 2', 'Castlevania', '2014-02-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pnz.jpg', 'Castlevania: Lords of Shadow 2 is an action-adventure game and a sequel to the 2010 game, Castlevania: Lords of Shadow, and the 35th installment on the Castlevania franchise. The game was developed by MercurySteam and published by Konami. This is MercurySteam''s last contribution to the franchise. The story is set in both medieval and modern worlds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('civilization-revolution-xbox-360', 'Civilization Revolution', 'Civilization', '2008-07-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95wx.jpg', 'Build. Discover. Conquer. Rule the World!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crackdown-xbox-360', 'Crackdown', 'Crackdown', '2007-02-20', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1w65.jpg', 'Crackdown is an open world, third-person shooter video game for the Xbox 360. Set in the fictional Pacific City, the player controls a biologically enhanced Agent, tasked with defeating three crime lords and their organized crime syndicates. The Agent''s abilities improve by defeating both crime lords and their supporters, as well as by completing optional activities, such as street races and scavenger hunts. The gameplay is nonlinear: instead of following a rigid mission sequence, players are free to select the approach to completing their missions and activities. The game features a two-player cooperative play mode via Xbox Live.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crackdown-2-xbox-360', 'Crackdown 2', 'Crackdown', '2010-07-06', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7g2s.jpg', 'Crackdown 2 is a sandbox-style third-person shooter video game developed by Ruffian Games and published by Microsoft Game Studios. It was released on Xbox 360 in July 2010 and is a direct sequel to the 2007 video game Crackdown.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-of-the-titans-xbox-360', 'Crash of the Titans', 'Crash Bandicoot', '2007-10-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5cv8.jpg', 'Crash of the Titans is the sixth Crash Bandicoot series game. The gameplay has the player explore levels, picking up power-ups to use against enemies as well as for the first time, use fighting combos such as punches and kicks against enemies. When Crash defeats an enemy or destroys an object, a magical substance known as Mojo is released. If the player collects enough Mojo, he will earn either an ability upgrade or a new move.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-mind-over-mutant-xbox-360', 'Crash: Mind over Mutant', 'Crash Bandicoot', '2008-10-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3n2m.jpg', 'Crash: Mind Over Mutant is the sequel to Crash of the Titans and the seventh Crash Bandicoot series game. The game uses many of the same mechanics as its predecessor with a few changes. Rather than having twenty linear platforming levels to complete in sequence, Mind Over Mutant features eight distinct locations for Crash to explore and travel between as the story progresses. The player can complete missions given by non-playable characters and discover collectibles through the levels.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-2-xbox-360', 'Crysis 2', 'Crysis', '2011-03-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2on2.jpg', 'Sequel to one of the greatest PC shooters ever, Crysis 2 offers console players their first taste of Crytek''s unique shooter gameplay. Featuring futuristic war, gorgeous destruction and the chance to kick alien butt on the grandest stage of all, New York City, Crysis 2 is destined at the least to equal its predecessor, if not surpass it. Additional features include: challenging AI enemies in the single player campaign, 12-player support online, new and improved upgradable Nanosuit 2 technology and more.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-3-xbox-360', 'Crysis 3', 'Crysis', '2013-02-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2on3.jpg', 'The award-winning developer Crytek is back with Crysis 3, the first blockbuster shooter of 2013! Crysis 3 is the ultimate sandbox shooter, realized in the stunning visuals only Crytek and the latest version of CryENGINE can deliver. Available now on Xbox 360, PlayStation 3, and PC.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-xbox-360', 'Dark Souls', 'Dark Souls', '2011-10-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x78.jpg', 'Dark Souls is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment. Released in September 2011 as a spiritual sequel to Demon''s Souls, it is set in a dark, medieval fantasy world. It is renowned for its challenging gameplay, intricate level design, and deep lore. Players control a customizable character known as the Chosen Undead, embarking on a perilous journey to uncover the secrets of the cursed land of Lordran.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-xbox-360', 'Dark Souls II', 'Dark Souls', '2014-03-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eoo.jpg', 'Dark Souls II is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment, released in March 2014. Set in the kingdom of Drangleic, players control the Bearer of the Curse, seeking to cure their undead curse. The game features challenging combat, deep lore, and a dark, atmospheric world. It introduces new mechanics like dual-wielding and a flexible character progression system, with improved multiplayer options for cooperative and PvP play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-scholar-of-the-first-sin-xbox-360', 'Dark Souls II: Scholar of the First Sin', 'Dark Souls', '2015-04-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb02.jpg', 'Dark Souls II: Scholar of the First Sin is an enhanced edition of Dark Souls II, released in April 2015 by FromSoftware and Bandai Namco Entertainment. This version includes updated graphics, improved performance, and all previously released DLC expansions (Crown of the Sunken King, Crown of the Old Iron King, and Crown of the Ivory King). It also features rebalanced gameplay, new enemy placements, additional NPCs, and expanded lore,', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-xbox-360', 'Darksiders', 'Darksiders', '2010-01-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pao.jpg', 'In The Darkside Detective: A Fumble in the Dark - Tales of the Darkside you''ll join the fan favorite side characters to solve the mysteries of Twin Lake! Will the Bloodwolves, the Brightside Division, and Rexa each solve their cases and save Twin Lake', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-xbox-360', 'Darksiders II', 'Darksiders', '2012-08-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wi5.jpg', 'Become Death - The most feared of the legendary Four Horseman.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('superman-returns-xbox-360', 'Superman Returns', 'DC', '2006-11-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2des.jpg', 'Inspired by the Warner Bros. Pictures feature film and more than 60 years of DC Comics'' lore. As the Man of Steel, you’ll hone your unworldly super powers such as Flight, X-Ray Vision, Heat Vision, Super Hearing, Super Strength, Super Speed, and Super Breath to fight villains that only Superman can defeat.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mortal-kombat-vs-dc-universe-xbox-360', 'Mortal Kombat vs. DC Universe', 'DC', '2008-11-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y13.jpg', 'In this arcade-style fighting game, both DC and Mortal Kombat universes are represented by 10 champions each, and one "boss" character, for a total of 22 fighters. Play is similar to the 2D Mortal Kombat games (with some 3D elements), focusing more on the special move aspect than the complex combos found in the previous three games (Deadly Alliance, Deception, Armageddon).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watchmen-the-end-is-nigh-xbox-360', 'Watchmen: The End Is Nigh', 'DC', '2009-07-21', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fv5.jpg', 'Watchmen: The End Is Nigh is an episodic video game series that serves as a prequel to the film adaptation of the DC Comics limited series Watchmen.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-asylum-xbox-360', 'Batman: Arkham Asylum', 'DC', '2009-08-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voj.jpg', 'Batman: Arkham Asylum is an action-adventure game developed by Rocksteady Studios and published by Warner Bros. Interactive Entertainment. Released in 2009, it follows Batman as he battles the Joker, who seizes control of Arkham Asylum and frees its inmates. The game features stealth, combat, and detective elements, with players using Batman''s gadgets and skills to subdue enemies and solve puzzles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('green-lantern-rise-of-the-manhunters-xbox-360', 'Green Lantern: Rise of the Manhunters', 'DC', '2011-06-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ky.jpg', 'Green Lantern: Rise of the Manhunters is an action video game, the first based on DC Comics'' Green Lantern (Hal Jordan). The game is a tie-in/sequel to the film Green Lantern, which opened in theatres on June 17, 2011. The game features 3D visuals on the PlayStation 3 and Xbox 360, providing TriOviz Inficolor 3D for standard televisions and stereoscopic 3D for dedicated 3DTVs.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-city-xbox-360', 'Batman: Arkham City', 'DC', '2011-10-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voh.jpg', 'Batman: Arkham City builds upon the intense, atmospheric foundation of Batman: Arkham Asylum, sending players soaring into Arkham City, the new maximum security "home" for all of Gotham City''s thugs, gangsters and insane criminal masterminds.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-gods-among-us-xbox-360', 'Injustice: Gods Among Us', 'DC', '2013-04-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8616.jpg', 'What if our greatest heroes became our greatest threat? Injustice: Gods Among Us introduces a bold new franchise to the fighting game genre from NetherRealm Studios, creators of the definitive fighting game Mortal Kombat. Featuring DC Comics icons such Batman, Cyborg, The Flash, Harley Quinn, Nightwing, Solomon Grundy, Superman and Wonder Woman, the latest title from the award-winning studio presents a deep original story. Heroes and villains will engage in epic battles on a massive scale in a world where the line between good and evil has been blurred.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-origins-xbox-360', 'Batman: Arkham Origins', 'DC', '2013-10-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3zg8.jpg', 'A free-to-play fighting video game for mobile that follows the same premise as the main versions of Arkham Origins.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('young-justice-legacy-xbox-360', 'Young Justice: Legacy', 'DC', '2013-11-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7mda.jpg', 'Young Justice: Legacy is a multiplayer action RPG based on the Young Justice TV series.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wolf-among-us-xbox-360', 'The Wolf Among Us', 'DC', '2014-11-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vdk.jpg', 'The fifth episode of The Wolf Among Us, a five-episode series based on Fables (DC Comics/Vertigo).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-telltale-series-xbox-360', 'Batman: The Telltale Series', 'DC', '2016-09-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u65.jpg', 'Batman: The Telltale Series is an episodic graphic adventure game developed by Telltale Games, first released in 2016. The game offers a narrative-focused experience, where players control Bruce Wayne and his alter ego, Batman, making choices that shape the story and relationships with characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-xbox-360', 'Dead Rising', 'Dead Rising', '2006-08-08', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzo.jpg', 'It’s the holiday season in Willamette, Colorado and a mysterious outbreak has overrun the Willamette Memorial Megaplex Mall and surrounding town with dangerous and deadly predators. Join Frank West as you explore a vast, open world sandbox filled with dangerous new zombies and a million ways to kill them as you seek to uncover the truth behind the outbreak – or die trying.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-xbox-360', 'Dead Rising 2', 'Dead Rising', '2010-09-28', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzw.jpg', 'As Chuck Greene, you have 72 hours to save your infected daughter, clear your name and survive the hordes of hungry zombies before the military comes in and nukes the city. To ensure your survival, you can combine everyday objects to create numerous deadly combo weapons and slaughter the ravenous zombies. Dead Rising 2, it’s where Creativity Kills.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-off-the-record-xbox-360', 'Dead Rising 2: Off the Record', 'Dead Rising', '2011-10-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t1w.jpg', 'The new "Off the Record" storyline means an all new Dead Rising 2 experience. Frank will face off against more twisted enemies, build more outrageous combo weapons, follow his own unique mission structure and explore brand new areas of Fortune City to get his biggest scoop yet. Join Frank as he indulges in the insanity of "Uranus Zone," Fortune City’s very own theme park. Full of deadly rides and crazy attractions, the sci-fi themed Uranus Zone is a true zombie-killing paradise.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-xbox-360', 'Dead Space', 'Dead Space', '2008-10-13', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5th8.jpg', 'A 2011 science-fiction survival horror mobile game developed by Australian company IronMonkey Studios and published by Electronic Arts for iOS, BlackBerry Tablet OS, Xperia Play, Android and BlackBerry 10 devices.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-2-xbox-360', 'Dead Space 2', 'Dead Space', '2011-01-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co715m.jpg', 'Cancelled Nintendo Wii port of Dead Space 2.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-space-3-xbox-360', 'Dead Space 3', 'Dead Space', '2013-02-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2int.jpg', 'Dead Space 3 is a 2013 survival horror action video game developed by Visceral Games and published by Electronic Arts for PlayStation 3, Windows, and Xbox 360. It is the third and final main entry in the Dead Space series. The game supports online cooperative multiplayer sessions in which a second player takes the role of new character John Carver.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-xbox-360', 'Destiny', 'Destiny', '2014-09-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-human-revolution-xbox-360', 'Deus Ex: Human Revolution', 'Deus Ex', '2011-08-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rd2.jpg', 'In Deus Ex: Human Revolution you play Adam Jensen, a security specialist, handpicked to oversee the defense of one of America''s most experimental biotechnology firms. But when a black ops team breaks in and kills the scientists you were hired to protect, everything you thought you knew about your job changes. At a time when scientific advancements are routinely turning athletes, soldiers and spies into super-enhanced beings, someone is working very hard to ensure mankind''s evolution follows a particular path. You need to discover why - because the decisions you take and the choices you make will be the only things that can determine mankind''s future.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-4-xbox-360', 'Devil May Cry 4', 'Devil May Cry', '2008-02-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7uh1.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-hd-collection-xbox-360', 'Devil May Cry HD Collection', 'Devil May Cry', '2012-03-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n18.jpg', 'Devil May Cry HD Collection is a collection of high-definition remasters of the PS2 games of the first three games in the Devil May Cry franchise. In addition to the reworked graphics, it also contains trophies/achievements.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dmc-devil-may-cry-xbox-360', 'DmC: Devil May Cry', 'Devil May Cry', '2013-01-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u77.jpg', 'DmC: Devil May Cry is the fifth game in the hack-and-slash third-person action series and the first not largely developed by Capcom. This title is a reimagining of the series, with the same protagonist Dante, but set in an alternate universe. The Dante in this game is very different from before, doing away with the trademark white hair and altering the main character as well as the game''s tone with a much more Western influence. The gameplay is still largely identical as Dante engages many opponents with a fast fighting style, stringing together combos and hits in quick succession.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-xbox-360', 'Diablo III', 'Diablo', '2013-09-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gfx.jpg', 'Diablo III is an action role-playing game that takes place throughout the dark fantasy world of Sanctuary.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-ultimate-evil-edition-xbox-360', 'Diablo III: Ultimate Evil Edition', 'Diablo', '2014-08-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3irp.jpg', 'Diablo III: Ultimate Evil Edition includes the expansion pack Reaper of Souls and features special four-player co-op features. With the wireless controller and a custom-designed console interface, players will be outfitted with touch pad functionality and new social features as they engage in pulse-pounding combat with hordes of monsters and acquire items of incredible power.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-xbox-360', 'Dishonored', 'Dishonored', '2012-10-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coabgu.jpg', 'Dishonored is an immersive first-person action game that casts you as a supernatural assassin driven by revenge. With Dishonored’s flexible combat system, creatively eliminate your targets as you combine the supernatural abilities, weapons and unusual gadgets at your disposal. Pursue your enemies under the cover of darkness or ruthlessly attack them head on with weapons drawn. The outcome of each mission plays out based on the choices you make.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-game-of-the-year-edition-xbox-360', 'Dishonored Game Of The Year Edition', 'Dishonored', '2013-10-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa4rb.jpg', 'While this shares the name of the Definitive Edition remaster on PS4 and Xbox One, the PC version did not receive any graphical improvements, and just saw it''s Game of the Year Edition renamed to "Definitive Edition".
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-xbox-360', 'Disney Infinity', 'Disney Infinity', '2013-08-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-xbox-360', 'Disney Infinity 2.0', 'Disney Infinity', '2014-09-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-3-0-xbox-360', 'Disney Infinity 3.0', 'Disney Infinity', '2015-08-30', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-3-bfg-edition-xbox-360', 'Doom 3: BFG Edition', 'Doom', '2012-10-16', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ovt.jpg', 'The BFG Edition features enhanced graphics, better audio with more horror effects, a checkpoint save system, and support for 3D displays and HMDs. The game also includes the previous expansion Resurrection of Evil and a new single-player expansion pack called The Lost Mission. Additionally, it includes copies of the original Doom (the Ultimate Doom edition with the add-on fourth episode, "Thy Flesh Consumed"), and Doom II with the expansion No Rest for the Living, previously available for the Xbox 360. The BFG Edition also features the ability to use the flashlight while holding a weapon, in the form of the so-called armor-mounted flashlight.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-origins-xbox-360', 'Dragon Age: Origins', 'Dragon Age', '2009-11-03', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvs.jpg', 'Dragon Age: Origins is a third-person role-playing game described as a spiritual successor to Baldur''s Gate and Neverwinter Nights franchises. Players create their own character by customizing gender and appearance as well as choosing a race and class. Combat is in real time with the ability to pause at any moment: tactical options include an editor which allows the player to give the AI detailed instructions on how to behave in every possible situation. Although the main storyline is the same for every character created, the game features six unique prologues, two for each race. Dragon Age: Origins received critical acclaim upon release, with praise mostly directed at its story, setting, characters, music and combat system.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-origins-ultimate-edition-xbox-360', 'Dragon Age: Origins Ultimate Edition', 'Dragon Age', '2010-10-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co868g.jpg', 'Dragon Age: Origins - Ultimate Edition includes Dragon Age: Origins, Dragon Age: Origins - Awakening and all nine content packs.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-ii-xbox-360', 'Dragon Age II', 'Dragon Age', '2011-03-08', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mw1.jpg', 'Dragon Age II is the sequel to Dragon Age: Origins and the second major game in the series. Like its predecessor, players can explore and engage in combat from a third-person perspective and will also encounter various companions who play major roles in the plot and gameplay. Depending on players'' decisions and dialogue, a companion will either recognize the main character Hawke as a friend or a rival. The game adopts the wheel-based dialogue system, meaning short responses that reflect different tones and attitudes the player wishes to choose for Hawke. The combat system is quite similar to the one used in the previous Dragon Age game, though it has been noticeably sped up.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-inquisition-xbox-360', 'Dragon Age: Inquisition', 'Dragon Age', '2014-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvy.jpg', 'Dragon Age: Inquisition is a role-playing game and the third main game in the Dragon Age series. It is set in the Thedas continent, the same fantasy world as the two previous games. It consist of two large countries: Ferelden (from Dragon Age: Origins) and Orlais, as well as the land inbetween.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dreamcast-collection-xbox-360', 'Dreamcast Collection', NULL, '2011-02-22', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wmh.jpg', 'Dreamcast fans rejoice! All of our Dreamcast games on Steam are now available in one neat bundle! Put some Ulala in your life and save big on 7 titles from Sonic to Jet Set Radio. There’s something for everyone!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ducktales-remastered-xbox-360', 'DuckTales: Remastered', 'DuckTales', '2013-11-12', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zsa.jpg', 'DuckTales Remastered takes the classic Disney platforming adventure to a whole new level. All of the visuals from the 8-bit game have been beautifully re-created as hand-drawn and animated sprites, across a backdrop of luscious, re-envisioned level backgrounds. Furthermore, original Disney Character Voices talent, including some from the cartoon TV series, bring in-game characters to life with charm and wit, while the classic melodies of the original soundtrack are given a modern twist. The game also features an all new tutorial level where players can get familiar with the iconic pogo jump and cane swing, while Scrooge McDuck''s Museum allows players to track all their stats and compare their progress with others via global leaderboards.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-oblivion-xbox-360', 'The Elder Scrolls IV: Oblivion', 'The Elder Scrolls', '2006-03-20', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fpz.jpg', 'The Elder Scrolls IV: Oblivion, the fourth game in the Elder Scrolls story, is set within the province of Cyrodiil, the heartland and Imperial capital of Tamriel. Emperor Uriel Septim VII is assassinated in flight from his own palace, but just before he dies he passes on to you the mystic Amulet of Kings. The adventure proper begins with the quest to find Uriel''s lost and illegitimate son who is the only heir to the throne. In a world where the forces of darkness seek their ultimate dominion over the ranks of man and mer alike, you alone stand between the future of Tamriel and the gates of Oblivion.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-shivering-isles-xbox-360', 'The Elder Scrolls IV: Shivering Isles', 'The Elder Scrolls', '2007-03-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j90.jpg', 'In the Shivering Isles expansion, see a world created in Sheogorath''s own image, one divided between Mania and Dementia and unlike anything you''ve experienced in Oblivion.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-iv-oblivion-game-of-the-year-edition-xbox-360', 'The Elder Scrolls IV: Oblivion Game of the Year Edition', 'The Elder Scrolls', '2007-09-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ycb.jpg', 'The Elder Scrolls IV: Oblivion Game of the Year Edition presents one of the best RPGs of all time like never before. Step inside the most richly detailed and vibrant game-world ever created. With a powerful combination of freeform gameplay and unprecedented graphics, you can unravel the main quest at your own pace or explore the vast world and find your own challenges. Also included in the Game of the Year edition are Knights of the Nine and the Shivering Isles expansion, adding new and unique quests and content to the already massive world of Oblivion. See why critics called Oblivion the Best Game of 2006.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-xbox-360', 'The Elder Scrolls V: Skyrim', 'The Elder Scrolls', '2011-11-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tnw.jpg', 'Skyrim reimagines and revolutionizes the open-world fantasy epic, bringing to life a complete virtual world open for you to explore any way you choose. Play any type of character you can imagine, and do whatever you want; the legendary freedom of choice, storytelling, and adventure of The Elder Scrolls is realized like never before.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-legendary-edition-xbox-360', 'The Elder Scrolls V: Skyrim – Legendary Edition', 'The Elder Scrolls', '2013-06-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dcm.jpg', 'Live Another Life, In Another World: Play any type of character you can imagine, and do whatever you want; the freedom of choice, storytelling, and adventure of The Elder Scrolls comes to life in one legendary experience from all three official add-ons.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enslaved-odyssey-to-the-west-xbox-360', 'Enslaved: Odyssey to the West', NULL, '2010-10-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gko.jpg', 'Follow a gripping, surprise-filled journey as two dissimilar characters form an uneasy partnership in order to survive through a perilous, post-apocalyptic America. 150 years in the future, war and destruction have left the world in ruins with few humans remaining and nature having reclaimed the world.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('epic-mickey-2-the-power-of-two-xbox-360', 'Epic Mickey 2: The Power of Two', 'Epic Mickey', '2012-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7nhy.jpg', 'Unleash the power of the brush in an all new co-op adventure. Join Mickey and Oswald in an epic battle to save the magical world of Wasteland and change it forever. Interact with your favorite characters like never before in the most heroic adventure yet.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-xbox-360', 'The Evil Within', 'The Evil Within', '2014-10-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgs.jpg', 'The Evil Within embodies the meaning of pure survival horror. Highly-crafted environments, horrifying anxiety, and an intricate story are combined to create an immersive world that will bring you to the height of tension. With limited resources at your disposal, you’ll fight for survival and experience profound fear in this perfect blend of horror and action.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-ii-xbox-360', 'Fable II', 'Fable', '2008-10-21', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1y2h.jpg', 'Fable 2 is the second game in the fable series by Lionhead Studios, it is an open world role-playing game. It has a simple story line where the hero needs to save Albion from the evil Lord Lucian by collecting together the other three heroes to defeat him. Interactive cut-scenes are a large part of the game however the main character never speaks and all dialogue is uncontrolled.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-iii-xbox-360', 'Fable III', 'Fable', '2010-10-26', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co231s.jpg', 'Set 50 years after the events of Fable II, the continent of Albion (where the Fable series is set) is under the control of Logan, a tyrant king and the Hero''s older brother[1]. The player''s character, the "Hero", is forced into a quest to become a revolutionary leader to defeat Logan after he reveals his true personality to the Hero. Over the course of the first half of the game, the Hero will overthrow Logan and become ruler of Albion themselves. During the second half of the game, a strange force from Aurora, called The Darkness will threaten Albion and the player has to decide how to react to it.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-the-journey-xbox-360', 'Fable: The Journey', 'Fable', '2012-10-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21ly.jpg', 'Fable: The Journey offers a whole new way to experience the deep storyline and picturesque world of Albion that fans have come to know and love. Set 50 years after the events of Fable III, this new version asks you to come to the aid of the mysterious Theresa, who thrusts you into an action-packed adventure full of dangerous enemies, hair-raising chases and humorous characters. Built from the ground up for Kinect, Fable: The Journey gives you the power to wield magic as a deadly weapon, defend yourself in combat and solve puzzles on your journey to becoming a hero.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fable-anniversary-xbox-360', 'Fable Anniversary', 'Fable', '2014-02-04', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22lr.jpg', 'Fully re-mastered with HD visuals and audio, Fable Anniversary is a stunning rendition of the original game that will delight faithful fans and new players alike! The all new Heroic difficulty setting will test the mettle of even the most hardcore Fable fan. With no Resurrection Phials and even more lethal enemies to contend with, will you be able to survive? Forge a hero based on your actions: age and evolve a hero or villain through the actions you choose and the path you follow-be it for good, evil, or in-between. Build your living legend: Through deeds and actions, build a name for yourself across the land. Recruit allies and followers. Gain glory or notoriety. Who will you be? With an entirely new lighting system, slick new interface, all new textures, models and gameplay, Fable Anniversary is the full HD, definitive Fable experience.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-3-xbox-360', 'Fallout 3', 'Fallout', '2008-10-28', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7yj5.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-new-vegas-xbox-360', 'Fallout: New Vegas', 'Fallout', '2010-10-19', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u60.jpg', 'In this first-person Western RPG, the player takes on the role of Courier 6, barely surviving after being robbed of their cargo, shot and put into a shallow grave by a New Vegas mob boss. The Courier sets out to track down their robbers and retrieve their cargo, and winds up getting tangled in the complex ideological and socioeconomic web of the many factions and settlements of post-nuclear Nevada.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-instincts-predator-xbox-360', 'Far Cry Instincts Predator', 'Far Cry', '2006-03-28', 'Xbox 360', 0, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nly.jpg', 'Far Cry Instincts: Predator, a Xbox 360 title, was released March 27, 2006. Predator is a graphically enhanced version of both Far Cry Instincts and Far Cry Instincts: Evolution.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-2-xbox-360', 'Far Cry 2', 'Far Cry', '2008-10-21', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpo.jpg', 'A civil war has swept through the country and you''re caught in the middle of it. Track down the person at the forefront of the fighting, a ruthless arms dealer known only as "The Jackal". As you undertake deadly missions and form fragile alliances with conflicting rebel groups, one thing becomes clear - the Jackal is hunting you too.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-xbox-360', 'Far Cry 3', 'Far Cry', '2012-12-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpd.jpg', 'Explore an island playground as stunningly beautiful as it is diverse – from mountain ranges to swampy grasslands and white sandy beaches. Fight your way through the island’s towns, temples, river ports and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-compilation-xbox-360', 'Far Cry Compilation', 'Far Cry', '2014-01-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62si.jpg', 'Far Cry Compilation is a collection of Far Cry games that includes Far Cry 2, Far Cry 3 and Far Cry 3: Blood Dragon. The compilation was created to celebrate the tenth anniversary of the Far Cry series and released only in North America.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-4-xbox-360', 'Far Cry 4', 'Far Cry', '2014-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ke6.jpg', 'Dive into the savage universe of Far Cry with this double-pack edition featuring both Far Cry 4 and Far Cry: Primal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xi-xbox-360', 'Final Fantasy XI', 'Final Fantasy', '2006-04-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2tpl.jpg', 'Final Fantasy XI R was a remake of the 2002 MMORPG Final Fantasy XI for mobile devices.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiii-xbox-360', 'Final Fantasy XIII', 'Final Fantasy', '2010-03-09', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coboys.jpg', 'As a deepening crisis threatens to plunge the floating world of Cocoon into chaos, a band of unsuspecting strangers find themselves branded enemies of the state. With the panicking population baying for their blood, and the military all too happy to oblige, they have no choice but to run for their lives. Join them on a desperate quest to challenge the forces controlling their fate, and prevent untold destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xiii-2-xbox-360', 'Final Fantasy XIII-2', 'Final Fantasy', '2012-01-31', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tr9.jpg', 'FINAL FANTASY XIII-2 is created with the aim of surpassing the quality of its predecessor in every way, featuring new gameplay systems and cutting-edge visuals and audio. In this game the player has the freedom to choose from a range of possibilities and paths; where their choices affect not only the immediate environment, but even shape time and space!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lightning-returns-final-fantasy-xiii-xbox-360', 'Lightning Returns: Final Fantasy XIII', 'Final Fantasy', '2014-02-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coblfq.jpg', 'As Lightning, it is your mission to save souls so they may be brought to a new world. However, with only thirteen days remaining, not everyone can be saved. Armed with all-new weapons, player customization and battle abilities, you are in a race against time to fully understand your destiny. It all ends here.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-xbox-360', 'Gears of War', 'Gears of War', '2006-11-07', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8wct.jpg', 'This expanded version for Windows added a new story Act, as well as new multiplayer maps.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-2-xbox-360', 'Gears of War 2', 'Gears of War', '2008-11-07', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28gg.jpg', 'In Gears of War 2, The COG continues its fight against the Locust horde, who are attempting to sink all of the cities on the planet Sera by using a big riftworm to eat the ground beneath them. Sergeant Marcus Fenix leads Delta Squad into the depths of the planet to try to stop the worm from eating but instead they discover the true intent of the Locust actions.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-3-xbox-360', 'Gears of War 3', 'Gears of War', '2011-09-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2a21.jpg', 'Gears of War 3 is the spectacular conclusion to one of the most memorable and celebrated sagas in videogames. Gears of War 3 plunges players into a harrowing tale of hope, survival and brotherhood. In Gears of War 3, players fight on as Marcus Fenix, the grizzled war hero and leader of Delta Squad. Eighteen months after the fall of the last human city, the war against the Locust rages on. Meanwhile, deep beneath the surface, a fearsome new threat is infecting the planet from within. With survivors scattered and civilization in ruins, time is running out for Marcus and his comrades as they fight to save the human race.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-judgment-xbox-360', 'Gears of War: Judgment', 'Gears of War', '2013-03-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y2a.jpg', '"Gears of War: Judgment" takes you back before events of the original "Gears of War" trilogy to the immediate aftermath of Emergence Day - the defining event of the "Gears of War" universe. Follow Kilo Squad, led by Damon Baird and Augustus "The Cole Train" Cole, as they fight to save the city of Halvo Bay from an unstoppable enemy in the most intense ''Gears'' game yet.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('golden-axe-beast-rider-xbox-360', 'Golden Axe: Beast Rider', 'Golden Axe', '2008-10-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5x8e.jpg', 'Beast Rider is the first Golden Axe game in 3D as opposed to side scrolling hack and slash. While this is a major shift in game style from the previous games, Beast Rider maintains many of the elements from the originals such as magic and riding beasts, as well as sending the player on a quest to defeat Death Adder.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-iv-xbox-360', 'Grand Theft Auto IV', 'Grand Theft Auto', '2008-04-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbv.jpg', 'Grand Theft Auto IV is an action-adventure video game developed by Rockstar North and published by Rockstar Games. It is the eleventh title in the Grand Theft Auto series, and the first main entry since 2004''s Grand Theft Auto: San Andreas.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-episodes-from-liberty-city-xbox-360', 'Grand Theft Auto: Episodes from Liberty City', 'Grand Theft Auto', '2009-10-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lbe.jpg', 'Episodes from Liberty City is a standalone compilation of the episodes: Grand Theft Auto IV: Ballad of Gay Tony and Grand Theft Auto IV: The Lost and Damned', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-xbox-360', 'Grand Theft Auto V', 'Grand Theft Auto', '2013-09-17', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-3-xbox-360', 'Halo 3', 'Halo', '2007-09-25', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xhh.jpg', 'New Mombasa is in ruins, yet the fight is far from over. Halo 3: ODST drops players onto the streets of the besieged city in this first-person shooter. Assume the role of “The Rookie”, an Orbital Drop Shock Trooper, and discover the truth behind the Covenant invasion. Engage in intense online multiplayer battles with the complete collection of Halo 3 multiplayer maps – including three all-new battlefields – and join your teammates in Firefight, a new cooperative mode that pits you against waves of Covenant invaders.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-wars-xbox-360', 'Halo Wars', 'Halo', '2009-03-03', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wc0.jpg', 'The Covenant has declared war on humanity, and Harvest is the first battleground. Set 21 years before the events of Halo: Combat Evolved, Halo Wars is an exciting real-time strategy game set in the legendary Halo universe. In this unique installment in the Halo franchise, players experience the epic battles that marked the beginning of the Covenant War. With the UNSC Spirit of Fire at their disposal, players fight in the intense and enormous conflicts that would define humanity''s relentless heroism in its darkest hour.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-3-odst-xbox-360', 'Halo 3: ODST', 'Halo', '2009-09-22', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xhh.jpg', 'New Mombasa is in ruins, yet the fight is far from over. Halo 3: ODST drops players onto the streets of the besieged city in this first-person shooter. Assume the role of “The Rookie”, an Orbital Drop Shock Trooper, and discover the truth behind the Covenant invasion. Engage in intense online multiplayer battles with the complete collection of Halo 3 multiplayer maps – including three all-new battlefields – and join your teammates in Firefight, a new cooperative mode that pits you against waves of Covenant invaders.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-reach-xbox-360', 'Halo: Reach', 'Halo', '2010-09-14', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xha.jpg', 'Experience the story before the events of Halo: Combat Evolved as you fight to defend the planet Reach from a harrowing Covenant invasion. In this first-person shooter you can customize your own Spartan with armor and accessories to experience both a pulse-pounding campaign and addictive multiplayer mode. Reach will fall, but it won''t go down without a fight.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-combat-evolved-anniversary-xbox-360', 'Halo: Combat Evolved Anniversary', 'Halo', '2011-11-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xhb.jpg', 'Halo: Combat Evolved Anniversary is a spectacular remastered version of the original game, created to celebrate the 10th anniversary of one of the most beloved first-person shooters in gaming history. Bundled with seven of the most popular multiplayer maps in Halo history ready for Xbox Live, Halo: Anniversary includes a bounty of new features including cooperative play over Xbox Live, Achievements, new challenges, and new fiction to uncover.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-4-xbox-360', 'Halo 4', 'Halo', '2012-11-06', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xhf.jpg', 'Halo 4 marks the start of an epic new saga within the award-winning Halo universe. The Master Chief returns in this award-winning first-person shooter developed by 343 Industries. Shipwrecked on a mysterious world, faced with new enemies and deadly technology, the Chief returns to battle against an ancient evil bent on vengeance and annihilation...the universe will never be the same.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-jackbox-party-pack-xbox-360', 'The Jackbox Party Pack', NULL, '2015-11-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zel.jpg', 'The team behind "You Don''t Know Jack" presents five guffaw-inducing party games in one pack! You''re gonna need more than one party for this. Your phones or tablets are your controllers! For 1-100 players! Games include:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kameo-elements-of-power-xbox-360', 'Kameo: Elements of Power', NULL, '2005-11-22', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v8t.jpg', 'Kameo: Elements of Power is a third person platformer that tells the story a young elf Kameo, who must regain her Elemental Powers, defeat her corrupted sister Kalus and her accomplice evil Troll King Thorn.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beautiful-katamari-xbox-360', 'Beautiful Katamari', 'Katamari', '2007-10-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co48qa.jpg', 'Experience the new high-definition, next generation sights and sounds of Beautiful Katamari as the Prince takes on a new high-rolling adventure, with his famous cousins in tow, to save the Katamari universe once again after the King of All Cosmos has a very un-royal and unfortunate accident. As usual, the King of All Cosmos demands the service of his son, the Prince, to roll anything and everything up into massive clumps and set things right, bringing harmony once again to the Katamari Cosmos. To keep his son inspired, the King of All Cosmos will provide another fresh and memorable soundtrack that will have players moving and grooving to the beat as they roll through the absurd, yet wonderful world of Beautiful Katamari.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-adventures-xbox-360', 'Kinect Adventures!', NULL, '2010-11-04', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22p6.jpg', 'Kinect Adventures! is a sports video game released by Microsoft Game Studios for the Xbox 360. Released in 2010, it is a collection of five adventure and sports minigames and was developed by Good Science Studio, a subsidiary of Microsoft Game Studios. The game utilizes the Kinect motion camera and was offered as a pack-in game with the console. It was officially unveiled at the 2010 Electronic Entertainment Expo in Los Angeles and went on to become the best selling game on the Xbox 360, selling 24 million units worldwide.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-sports-xbox-360', 'Kinect Sports', 'Kinect Sports', '2010-11-04', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22rp.jpg', 'Kinect Sports is a sports video game developed by Rare and published by Microsoft Game Studios for the Xbox 360. The game utilizes the Kinect motion-sensing peripheral.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-sports-season-two-xbox-360', 'Kinect Sports: Season Two', 'Kinect Sports', '2011-10-25', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22rx.jpg', 'Kinect Sports Season Two is a sequel to Rare''s 2010 multi-million seller Kinect Sports, with 6 new events, full-body tracking & in-game voice control.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-sports-ultimate-collection-xbox-360', 'Kinect Sports Ultimate Collection', 'Kinect Sports', '2012-09-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co489z.jpg', 'Finally, you don''t have to choose! This ultimate collection hast two best-selling Kinect games wrapped into one - putting 13 great sporting games at your fingertips. So grab your friends and compete for a personal best or jump in and out of the action in team Party Mode! Anyone can play in these controller-free, full-body sports games. With your body as the controller, nothing comes between you and the action!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-xbox-360', 'L.A. Noire', 'L.A. Noire', '2011-05-17', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldn.jpg', 'L.A. Noire is a neo-noir detective action-adventure video game developed by Team Bondi and published by Rockstar Games. It was initially released for the PlayStation 3 and Xbox 360 platforms on 17 May 2011; a Microsoft Windows port was later released on 8 November 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-the-complete-edition-xbox-360', 'L.A. Noire: The Complete Edition', 'L.A. Noire', '2011-10-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldm.jpg', 'L.A. Noire is set in Los Angeles in 1947 and challenges the player, controlling a Los Angeles Police Department (LAPD) officer, to solve a range of cases across five divisions. Players must investigate crime scenes for clues, follow up leads, and interrogate suspects, and the player''s success at these activities will impact how much of each case''s story is revealed.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-ii-the-original-trilogy-xbox-360', 'Lego Star Wars II: The Original Trilogy', 'Lego', '2006-09-12', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ipr.jpg', 'Experience LEGO Star Wars II: The Original Trilogy originally released on the PSP (PlayStationPortable) system, enhanced with up-rendering, rewind, quick save, and custom video filters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bionicle-heroes-xbox-360', 'Bionicle Heroes', 'Lego', '2006-11-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co525j.jpg', 'Bionicle Heroes DS is a classic first-person shooter. As a nameless Matoran, you''ll travel across 25 themed levels (including jungles, lava-worlds, ancient underground temples) discovering new weapons and new robotic foes to blast apart. Along the way, you''ll use the masks'' powers to survive the hostile environments as well as collect gears and robot parts to solve simple puzzles by assembling LEGO-style ramps, bridges, and doorways.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-complete-saga-xbox-360', 'Lego Star Wars: The Complete Saga', 'Lego', '2007-11-06', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrr.jpg', 'Play through a fun Star Wars galaxy that combines the endless customization of LEGO with the epic story from all six episodes of Star Wars. This is the definitive LEGO Star Wars comprising the first two games and expanding them with new characters, enhanced visuals, and more bonus levels than you can shake a lightsaber at.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-the-original-adventures-xbox-360', 'Lego Indiana Jones: The Original Adventures', 'Lego', '2008-06-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4w36.jpg', 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO. Explore and Discover - Battle enemies, solve puzzles, and seek out the world''s greatest treasures.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-the-videogame-xbox-360', 'Lego Batman: The Videogame', 'Lego', '2008-09-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qrn.jpg', 'The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame. Play as Batman and his sidekick Robin as you build, drive, swing and fight your way through Gotham City capturing escaped villains including The Joker, Penguin, Scarecrow and more. Then, jump into the story from the other side and play as Batman''s foes! Enjoy the power you wield and battle Batman while spreading chaos throughout the city. There is no rest for the good (or evil!).', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-rock-band-xbox-360', 'Lego Rock Band', 'Lego', '2009-11-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wpb.jpg', 'LEGO Rock Band is a blending of Rock Band and LEGO series. Players get to start a band and hire band members who will play with them. Just like with real Lego, players can mix and match bodies, torsos, legs and heads to create a character any way they want. The main game has players touring around the world at various locations, like the original Rock Band games. Unlike Rock Band however, LEGO Rock Band also has special levels where you must perform outrageous tasks such as fighting an octopus or demolishing a building using your rock concert. As players make their way through the song lists, they earn "Studs", the game''s currency. Studs can be used to purchase Lego items to decorate your Rock Den, hire new staff, buy new clothes or instruments.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-indiana-jones-2-the-adventure-continues-xbox-360', 'Lego Indiana Jones 2: The Adventure Continues', 'Lego', '2009-11-17', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6up6.jpg', 'LEGO Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO fashion, get creative and build your own levels to play with friends!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-1-4-xbox-360', 'Lego Harry Potter: Years 1–4', 'Lego', '2010-06-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65lz.jpg', 'LEGO Harry Potter: Years 1-4 will give gamers the chance to experience the magic and adventure of Harry Potter in a uniquely LEGO way. Playing as Harry Potter, Ron Weasley and Hermione Granger, as well as more than 100 other favorite characters, gamers will have the opportunity to attend lessons, cast spells, mix potions, fly on broomsticks and complete tasks to earn rewards. Throughout the game, players will also have the freedom to explore iconic settings from the wizarding world including Hogwarts castle, Diagon Alley, the Forbidden Forest and the village of Hogsmeade.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-iii-the-clone-wars-xbox-360', 'Lego Star Wars III: The Clone Wars', 'Lego', '2011-03-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk2.jpg', 'The Saga continues. Build, battle and laugh your way across the Star Wars universe like never before! Play as Anakin Skywalker and Obi-Wan Kenobi through a story spanning the entire Clone Wars era. LEGO Star Wars III: The Clone Wars combines epic space battles, challenging puzzles and of course, the imaginative gameplay of LEGO.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-pirates-of-the-caribbean-the-video-game-xbox-360', 'Lego Pirates of the Caribbean: The Video Game', 'Lego', '2011-05-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg', 'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-years-5-7-xbox-360', 'Lego Harry Potter: Years 5–7', 'Lego', '2011-11-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qro.jpg', 'The game will whisk you away to familiar locations from books 5-7 Order of the Phoenix, Half-Blood Prince and The Deathly Hallows, including Grimmauld Place, the Ministry of Magic and Godric''s Hollow.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-2-dc-super-heroes-xbox-360', 'Lego Batman 2: DC Super Heroes', 'Lego', '2012-06-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0q.jpg', 'The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-lord-of-the-rings-xbox-360', 'Lego The Lord of the Rings', 'Lego', '2012-11-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7z02.jpg', 'Based on The Lord of the Rings motion picture trilogy, LEGO The Lord of the Rings follows the original storylines of The Lord of the Rings: The Fellowship of the Ring, The Lord of the Rings: The Two Towers, and The Lord of the Rings: The Return of the King, taking players through the epic story events reimagined with the humor and endless variety of LEGO play.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-xbox-360', 'Lego Marvel Super Heroes', 'Lego', '2013-10-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-xbox-360', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-xbox-360', 'Lego The Hobbit', 'Lego', '2014-04-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-xbox-360', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-xbox-360', 'Lego Jurassic World', 'Lego', '2015-06-12', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dimensions-xbox-360', 'Lego Dimensions', 'Lego', '2015-09-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w4t.jpg', 'Help stop crime in the Lego Dimensions multiverse with Lego City’s Chase McCain. Build and place Chase on the Lego Toy Pad to bring him to life in the game. Use his Lego City Detective Scanner to track down bad guys and change his disguise to unlock more abilities. Become a Miner to break Silver Lego bricks or a Fireman to use your Water Beam to put out fires. Unlock the Lego City Adventure World to explore new areas like Blackwell’s moonbase and the Lego City Police Department, and the Battle Arena to compete with up to 4 of your friends. Build Chase’s Police Helicopter to fire off bolts, then rebuild it into the Police Hovercraft and Police Plane for additional in-game abilities.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-xbox-360', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-xbox-360', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-the-official-game-xbox-360', 'X-Men: The Official Game', 'Marvel', '2006-05-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6gzh.jpg', 'X-Men: The Official Game (also known as X3: The Official Game) is Activision''s tie-in video game to the 2006 film X-Men: The Last Stand. The game covers the events of the films X2: X-Men United and X-Men: The Last Stand, specifically following the characters of Wolverine, Iceman, and Nightcrawler. It also bridges the gap between the two films, explaining why Nightcrawler is not present for The Last Stand and also introduces new foes to the X-Men film canon, such as HYDRA, who FOX didn''t own the film rights.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-xbox-360', 'Marvel: Ultimate Alliance', 'Marvel', '2006-10-24', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-3-xbox-360', 'Spider-Man 3', 'Marvel', '2007-05-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nc4.jpg', 'The next-gen version of Spider-Man 3, a videogame based on the 2007 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fantastic-four-rise-of-the-silver-surfer-xbox-360', 'Fantastic Four: Rise of the Silver Surfer', 'Marvel', '2007-06-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x77.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-friend-or-foe-xbox-360', 'Spider-Man: Friend or Foe', 'Marvel', '2007-10-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h33.jpg', 'Defeat Spider-Man’s most famous enemies, like Venom, Green Goblin, and Doc Ock to add them to your epic array of playable sidekicks in this movie trilogy inspired adventure. Experience ground-breaking Co-operative Multiplayer, as Spider-Man or a sidekick, in exotic spots around the globe, including Tokyo, Egypt and Nepal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-xbox-360', 'Iron Man', 'Marvel', '2008-05-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co97rg.jpg', 'In Marvel''s Iron Man VR the player, who plays as the genius inventor Tony Stark, confronts ghosts from his past—powerful forces who seek to ruin him and everything he stands for. By fully embracing the magic of PlayStation VR, players will come face-to-face with iconic allies and Super Villains as they jet around the globe on a heroic mission to save not only Stark Industries, but the world itself.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-incredible-hulk-xbox-360', 'The Incredible Hulk', 'Marvel', '2008-06-05', 'Xbox 360', 0, 0, NULL, NULL, NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-web-of-shadows-xbox-360', 'Spider-Man: Web of Shadows', 'Marvel', '2008-10-21', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ujz.jpg', 'Spider-Man: Web of Shadows is a video game title encompassing three versions: a full-3D action game for Microsoft Windows, PlayStation 3, Wii, and Xbox 360; a 2.5D sidescrolling beat em up action game for the PlayStation Portable and PlayStation 2 (called Amazing Allies Edition), and a 2.5D side-scrolling brawler/platformer for the Nintendo DS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-origins-wolverine-xbox-360', 'X-Men Origins: Wolverine', 'Marvel', '2009-05-01', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2426.jpg', 'A port of X-Men Origins: Wolverine, a hack-and-slash action-adventure game loosely based on the film of the same name.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-ultimate-alliance-2-xbox-360', 'Marvel: Ultimate Alliance 2', 'Marvel', '2009-09-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjz.jpg', 'Marvel: Ultimate Alliance 2 is the second game in the Marvel: Ultimate Alliance series, and is loosely based on the events of the Civil War comic book story line. It brings with it a larger roster of heroes and villains to play as, as well as more ways to utilize your team in battle.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('iron-man-2-xbox-360', 'Iron Man 2', 'Marvel', '2010-05-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sxm.jpg', 'This is the Wii version of Iron Man 2, an action-adventure video game loosely based on the 2010 movie of the same name.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-shattered-dimensions-xbox-360', 'Spider-Man: Shattered Dimensions', 'Marvel', '2010-09-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zpp.jpg', 'Spider-Man: Shattered Dimensions is a thrilling action-packed adventure set in four dramatically different universes from legendary Spider-Man lore, each with a distinct Spider-Man armed with unique skills and strengths, in one original storyline. Players will be transported to new locations never before seen in a Spider-Man game, from lush jungles and dusty deserts to various urban terrains. Acclaimed comic book writer Dan Slott takes players on a mission to contain the magical energy of the Tablet of Order and Chaos, which has been shattered and sent hurtling across parallel universes, and battle fan-favorite villains in a quest to restore the fabric of reality.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-the-infinity-gauntlet-xbox-360', 'Marvel Super Hero Squad: The Infinity Gauntlet', 'Marvel', '2010-11-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2di9.jpg', 'Marvel Super Hero Squad: The Infinity Gauntlet is a continuation of the video game Marvel Super Hero Squad and it was released on November 16, 2010. Similar to the first game, it features cartoonish Super-deformed versions of the Marvel Comics characters, as seen in the Marvel Super Hero Squad toy line, as well as the television show.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-3-fate-of-two-worlds-xbox-360', 'Marvel vs. Capcom 3: Fate of Two Worlds', 'Marvel', '2011-02-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ye3.jpg', 'Marvel vs. Capcom 3: Fate of Two Worlds is a crossover fighting game developed by Capcom in collaboration with Eighting. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. It was released for the PlayStation 3 and Xbox 360 consoles in February 2011. It is the fifth installment of the Marvel vs. Capcom franchise and the first to use three-dimensional character models instead of sprites.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thor-god-of-thunder-xbox-360', 'Thor: God of Thunder', 'Marvel', '2011-05-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co531w.jpg', 'Thor: God of Thunder is an action-adventure game developed by Liquid Entertainment and published by Sega in 2011. It serves as a tie-in to the Thor film from the Marvel Cinematic Universe. Players control Thor as he wields Mjolnir to battle enemies across the Nine Realms, facing iconic foes such as Surtur and Ulik while protecting Asgard from destruction.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('captain-america-super-soldier-xbox-360', 'Captain America: Super Soldier', 'Marvel', '2011-07-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ovp.jpg', 'The Nintendo 3DS port of Captain America: Super Soldier.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('x-men-destiny-xbox-360', 'X-Men: Destiny', 'Marvel', '2011-09-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2cnk.jpg', 'X-Men: Destiny is an action role-playing video game based on the X-Men comic book series. It was developed by Silicon Knights. Written by Mike Carey, the writer of the X-Men: Legacy comic book series, it was first published and released by Activision for the Nintendo DS, PlayStation 3, Xbox 360 and Wii consoles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spider-man-edge-of-time-xbox-360', 'Spider-Man: Edge of Time', 'Marvel', '2011-10-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6h30.jpg', 'The fate of one Webslinger hangs on the webs of another in this game where two Spider-Man worlds collide with the death - yes, the death - of Peter Parker. Play as the Amazing Spider-Man and Spider-Man 2099 in a storyline that weaves together two timelines. The two heroes battle in separate worlds with a shared destiny, working to prevent an event that has dire consequences for Parker and the fate of the worlds he protects. Your actions in one timeline could cause ripple effects in the other. Picture-in-picture visuals let you watch your actions change the future - or rewrite the past - for better or for worse.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-super-hero-squad-comic-combat-xbox-360', 'Marvel Super Hero Squad: Comic Combat', 'Marvel', '2011-11-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co485l.jpg', 'Marvel Super Hero Squad: Comic Combat is a video game that uses the uDraw GameTablet, developed by Griptonite Games, and published by THQ and Vivendi Games. The game is the third in the Marvel Super Hero Squad franchise, acting as the sequel to two video games Marvel Super Hero Squad and Marvel Super Hero Squad: The Infinity Gauntlet. It was released on November 15, 2011 for the uDraw GameTablet, PlayStation 3, Xbox 360, and Nintendo Wii game systems.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-marvel-vs-capcom-3-xbox-360', 'Ultimate Marvel vs. Capcom 3', 'Marvel', '2011-11-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yej.jpg', 'Ultimate Marvel vs. Capcom 3 is a crossover fighting game developed by Capcom in collaboration with Eighting. It is an updated version of Marvel vs. Capcom 3: Fate of Two Worlds. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. The game was released in November 2011 for the PlayStation 3 and Xbox 360, and was featured as a launch title for the PlayStation Vita in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mib-alien-crisis-xbox-360', 'MIB: Alien Crisis', 'Marvel', '2012-05-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9cbu.jpg', 'Become the next top agent of the Men In Black. Arm yourself with a full arsenal of iconic MIB weapons to investigate and stop an evil alien plot to snatch up an ancient artifact that is the key to seizing control of the universe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-xbox-360', 'The Amazing Spider-Man', 'Marvel', '2012-06-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1s.jpg', 'The Amazing Spider-Man is an action-adventure video game released in 2012, developed by Beenox and published by Activision. The game serves as a tie-in to the 2012 film of the same name, though it features its original storyline that continues after the movie''s events. Players control Spider-Man as he swings through an open-world version of New York City, battling criminals and iconic villains like the Lizard and Rhino while facing Oscorp''s mutated creatures.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-avengers-battle-for-earth-xbox-360', 'Marvel Avengers: Battle for Earth', 'Marvel', '2012-10-30', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22so.jpg', 'The Skrulls have landed and now it is up to you to embody your favorite Marvel super heroes and defeat epic enemies during the Secret Invasion. Unleash your inner superhero in Marvel Avengers Battle For Earth!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deadpool-xbox-360', 'Deadpool', 'Marvel', '2013-06-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xsf.jpg', 'In Deadpool the player takes control of the loud-mouthed, foul-mouthed, merc-with-a-mouth Wade Wilson (a.k.a. Deadpool). While on out on a contract to kill a corrupt media mogul, Mister Sinister intervenes and kills him instead, drawing the ire of Deadpool who then vows revenge only to stumble upon a bigger plot which could spell the end of humanity.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-xbox-360', 'The Amazing Spider-Man 2', 'Marvel', '2014-04-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-xbox-360', 'Mass Effect', 'Mass Effect', '2007-11-20', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7c1f.jpg', 'The heavily anticipated continuation of the Mass Effect series.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-2-xbox-360', 'Mass Effect 2', 'Mass Effect', '2010-01-26', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9jdu.jpg', 'Firewalker Pack is a DLC pack for Mass Effect 2.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-3-xbox-360', 'Mass Effect 3', 'Mass Effect', '2012-03-06', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5rwt.jpg', 'The N7 Digital Deluxe Edition contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-hd-collection-xbox-360', 'Metal Gear Solid HD Collection', 'Metal Gear', '2011-11-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gkj.jpg', 'From the critically acclaimed director, Hideo Kojima, Metal Gear Solid HD Collection offers a handful of the most popular Metal Gear Solid titles from the past in true HD for the first time ever. Featuring three complete games, Metal Gear Solid 2: Sons of Liberty, Metal Gear Solid: Snake Eater and Metal Gear Solid: Peace Walker, the HD Collection offers old and new fans a chance to experience the epic game play, design and storytelling of the MGS franchise. The "Metal Gear Solid (MGS)" series is the seminal work of Hideo Kojima, Japan''s master game creator, and the progenitor of the stealth action game genre. The series has become a global phenomenon, with over 27 million copies sold worldwide. The player controls a secret agent from an elite special forces unit who is sent on solo sneaking missions through enemy installations, vast jungles, and sometimes even the thick of battle. Alone and surrounded by the enemy, even a special forces agent will find it tough to come out alive. But that is the secret behind the series'' popularity-the cerebral challenge of figuring out how to avoid combat, and the thrill of sneaking through enemy territory undetected.The MGS series is also known for its storyline, which blends seamlessly with the gameplay. The scenarios are based on extensive research and incorporate the drama of actual developments in society. These elements have made MGS what it is today: a mature work of entertainment that transcends national borders and the confines of video games, and one of the leading products of the Japanese content business.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-rising-revengeance-xbox-360', 'Metal Gear Rising: Revengeance', 'Metal Gear', '2013-02-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l1t.jpg', 'Developed by Kojima Productions and PlatinumGames, Metal Gear Rising: Revengeance takes the renowned Metal Gear franchise into exciting new territory with an all-new action experience. The game seamlessly melds pure action and epic story-telling that surrounds Raiden – a child soldier transformed into a half-human, half-cyborg ninja who uses his High Frequency katana blade to cut through any thing that stands in his vengeful path!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-ground-zeroes-xbox-360', 'Metal Gear Solid V: Ground Zeroes', 'Metal Gear', '2014-03-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v88.jpg', 'Metal Gear Solid V: Ground Zeroes is a prologue to Metal Gear Solid V: The Phantom Pain. It offers players new sneaking and traversal methods compared to its predecessors, as well as the choice in what order the story events take place by selecting missions by advance. The most important change for this title is the shift to an open world design with a real-time day and night cycle doing away with the linear mission approach of previous games. The game was originally developed as a mission for The Phantom Pain, but an extended development time resulted in director Hideo Kojima splitting the specific portion of the game as a stand-alone product so that players could get early access to Metal Gear Solid V.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-phantom-pain-xbox-360', 'Metal Gear Solid V: The Phantom Pain', 'Metal Gear', '2015-09-01', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v85.jpg', 'Metal Gear Solid V: The Phantom Pain is the sequel to Metal Gear Solid V: Ground Zeroes and a prequel to the original Metal Gear. The game has a complex story with long cut-scene sequences, but there are fewer and they are shorter compared to earlier Metal Gear Solid titles. Most of the gameplay mechanics introduced in Ground Zeroes are carried over: it is still an action game and stealth oriented but replaces the linear corridor design from most earlier titles with large open world environments that offer the player unrestricted freedom for the approach. The world has now a real-time day and night cycle and various weather effects that influence enemy behaviour, visibility and sound. Sabotaging or destroying certain structures can also influence other parts of the map.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-the-battle-for-middle-earth-ii-xbox-360', 'The Lord of the Rings: The Battle for Middle-earth II', 'Middle-earth', '2006-07-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20oh.jpg', 'Wage war in the North and assume command of the most storied civilizations in all of Middle-earth history - the Elven and Dwarven armies - or fight on the side of Evil with heroes and creatures that have never been seen in The Lord of the Rings films. Defend or overtake never before seen lands such as Dol Guldur, The Misty Mountains, and Mirkwood as you unleash powerful new weapons and abilities, such as summoning dragons.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-conquest-xbox-360', 'The Lord of the Rings: Conquest', 'Middle-earth', '2009-01-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lup.jpg', 'Play as Evil characters in a brand new, ''Evil'' campaign. Battle through scenarios after Frodo failed to destroy the One Ring; it''s good to be bad! Battle online, in a co-op campaign or offline in split-screen.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lord-of-the-rings-war-in-the-north-xbox-360', 'The Lord of the Rings: War in the North', 'Middle-earth', '2011-11-01', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20p9.jpg', 'The Lord of the Rings: War in the North is a co-op Action RPG that immerses you and your friends in a brutal new chapter in the War of the Ring. Snowblind Studios is in the unique position of drawing inspiration from both the literary and film rights to world of Middle-earth, allowing players to bloody their axes on a wide range of deadly enemies and traverse both established and never-before-seen locations. The result is a journey that is both epic and intimate, familiar yet unexpected.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-mordor-xbox-360', 'Middle-earth: Shadow of Mordor', 'Middle-earth', '2014-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20pd.jpg', 'Middle-earth: Shadow of Mordor is a open world third-person action role-playing video game developed by Monolith Productions and published by Warner Bros. Interactive Entertainment, which takes place in the world of J.R.R. Tolkien''s Legendarium.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-xbox-360-edition-xbox-360', 'Minecraft: Xbox 360 Edition', 'Minecraft', '2013-06-04', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobh6x.jpg', 'Imagine it, build it! Minecraft: Xbox 360 Edition lets you create worlds from the comfort of your sofa. Play alone or play with your friends. Explore, build and conquer! At night monsters come out, so make sure to build a shelter before that happens. After that, your world is your imagination. Turn your hours into minutes with Minecraft!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-xbox-360', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2016-10-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-season-two-xbox-360', 'Minecraft: Story Mode - Season Two', 'Minecraft', '2017-10-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vin.jpg', 'Minecraft: Story Mode - Season Two continues Jesse''s saga in a five-part, narrative-driven, episodic game series developed by Telltale in collaboration with Mojang and members of the Minecraft community. Though players'' choices from the first season will carry over into season two, this new season will be accessible to both returning fans and newcomers alike. This second season will also include Telltale''s unique multiplayer ''Crowd Play'' feature, which allows friends and family to engage with the adventure together by helping to decide the direction of the story from any mobile device with an online connection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mirror-s-edge-xbox-360', 'Mirror''s Edge', 'Mirror''s Edge', '2008-11-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sf5.jpg', 'Mirror''s Edge is a side-scrolling platform game developed by IronMonkey Studios and published by Electronic Arts. It was released for the iPod on September 2, 2009, for iPad and iPhone on April 1, 2010, and later for Windows Phone on July 13, 2012. The game is a prequel to the original Mirror''s Edge, setting the scene about Runners and the city''s shady corporations.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('murdered-soul-suspect-xbox-360', 'Murdered: Soul Suspect', NULL, '2014-06-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7a.jpg', 'Murdered: Soul Suspect is a supernatural detective thriller which challenges players to solve possibly the hardest case of all… their own murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('namco-museum-virtual-arcade-xbox-360', 'Namco Museum Virtual Arcade', 'Namco Museum', '2008-11-04', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7zpp.jpg', 'Go back in time with Namco Museum: Virtual Arcade and relive classic Namco arcade favorites including Tower of Druaga, Galaga, Grobda, Mappy, Metro-Cross, Ms. Pac-Man, New Rally-X, Pac-Man Arrangement, Pole Position 2, Sky Kid, and Xevious, just to name a few. Namco Museum: Virtual Arcade also features Pac-Man Championship Edition which was voted the best downloadable game of 2007 by numerous video game publications. Galaga Legions continues Pac-Man Championship Edition''s legacy with a smart re-tooling of the franchise that stays true to the series'' roots.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nier-xbox-360', 'Nier', 'Nier', '2010-04-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coapbf.jpg', 'Nothing is as it seems in Square Enix''s latest action adventure game, set in a crumbling world plagued by disease and dark, unrecognizable creatures. Players assume the role of the unyielding protagonist, NIER, resolute in his quest to discover a cure for his daughter, who is infected with the Black Scrawl virus. With powerful allies and a mysterious book, NIER encounters things that will confound even the mightiest of warriors. With NIER, experience seamless in-battle cinematics and explore hauntingly familiar lands, intense action-packed battles, and storytelling like only Square Enix can do', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-ii-xbox-360', 'Ninja Gaiden II', 'Ninja Gaiden', '2008-06-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2stg.jpg', 'Ninja Gaiden II is an action-adventure video game developed by Team Ninja and published by Microsoft Corporation. It is the sequel to the 2004 title Ninja Gaiden and was released worldwide for the Xbox 360 in June 2008.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-3-xbox-360', 'Ninja Gaiden 3', 'Ninja Gaiden', '2012-03-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ryd.jpg', 'Ninja Gaiden 3 is the first main entry in the modern Ninja Gaiden series not to be directed by former Team Ninja head Tomonobu Itagaki. NG3 features new game mechanics, a focus on consequence and 8-player online modes.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-3-razor-s-edge-xbox-360', 'Ninja Gaiden 3: Razor''s Edge', 'Ninja Gaiden', '2013-04-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1ty.jpg', 'Ninja Gaiden 3: Razor''s Edge is an enhanced port of Ninja Gaiden 3 that includes all downloadable content from the original title, as well as additional enhancements made to improve the game. The game can be considered an equivalent to the Ninja Gaiden Sigma games, as it enhances the original title.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yaiba-ninja-gaiden-z-xbox-360', 'Yaiba: Ninja Gaiden Z', 'Ninja Gaiden', '2014-03-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ygu.jpg', 'Step into a living comic book in this new take on the Ninja Gaiden series. Brandishing his ninja sword and the mecha weapons in his cyber arm, Yaiba slaughters zombies with brutal, over-the-top abandon. Will you slice enemies to pieces, crush them with Yaiba''s cyborg arm or just rip off a zombie’s arms to use as nunchucks?', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-orange-box-xbox-360', 'The Orange Box', NULL, '2007-10-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2yez.jpg', 'The Orange Box is a bundle that includes five titles from Valve: Half-Life 2; Half-Life 2:Episode 1; Half-Life 2: Episode Two; Team Fortress 2, the sequel to the game that put class-based, multiplayer team warfare on the map; and Portal, the game that blends puzzles, first person action, and adventure gaming to produce an experience like no other.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-xbox-360', 'Pac-Man and the Ghostly Adventures', 'Pac-Man', '2013-10-29', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-and-the-ghostly-adventures-2-xbox-360', 'Pac-Man and the Ghostly Adventures 2', 'Pac-Man', '2014-10-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnj.jpg', 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('perfect-dark-zero-xbox-360', 'Perfect Dark Zero', 'Perfect Dark', '2005-11-22', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ecm.jpg', 'What was originally intended to be a launch title for the GameCube, but Microsoft buyout of Rare resulted in the game’s development being moved to the Xbox, but in the end it became a launch title for the Xbox 360.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-arena-xbox-360', 'Persona 4 Arena', 'Persona', '2012-08-07', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25v5.jpg', 'Persona 4 Arena is a fighting video game developed for Japanese arcades and later ported to home consoles. Based on Atlus'' Persona role-playing game series, Arena serves as a direct sequel to Persona 4 and features characters from its predecessor, Persona 3. Atlus wrote the story to the game while Arc System Works handled the gameplay.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-arena-ultimax-xbox-360', 'Persona 4 Arena Ultimax', 'Persona', '2014-09-30', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5k1y.jpg', 'Persona 4 Arena Ultimax is a fighting video game developed by Arc System Works and Atlus. It is the direct sequel to Persona 4 Arena, which is itself a follow-up to the role-playing game Persona 4. The game was originally released in Japanese arcades on November 28, 2013, and later ported to home consoles. Unlike the previous game, it is not region locked.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-xbox-360', 'Plants vs. Zombies', 'Plants vs. Zombies', '2010-09-08', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co69id.jpg', 'Zombies are invading your home, and the only defense is your arsenal of plants! Plants vs. Zombies is a tower defense video game developed and published by PopCap Games. As a horde of zombies approaches along several parallel lanes, players must defend their homes by placing plants, which fire projectiles at the zombies or otherwise detrimentally affect them.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-xbox-360', 'Plants vs. Zombies: Garden Warfare', 'Plants vs. Zombies', '2014-02-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qyz.jpg', 'Plants vs. Zombies is digging into the trenches with an explosive new 3D experience. Blast zombies, plants, and new characters with inventive weapons across a mine-blowing PvZ world. Take on Co-Op and Multiplayer action with your friends and sow the seeds of victory!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('popcap-arcade-vol-1-xbox-360', 'PopCap Arcade Vol. 1', 'PopCap Arcade', '2007-11-15', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/ffdpnqbibbagdvvhls1o.jpg', 'Four of PopCap''s classics on Xbox 360.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('popcap-arcade-vol-2-xbox-360', 'PopCap Arcade Vol. 2', 'PopCap Arcade', '2009-03-31', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/emmsgkxf9r4p60nwifbb.jpg', 'PopCap''s second disc of their arcade hits. Includes Peggle, Feeding Frenzy 2, and Heavy Weapon.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('portal-2-xbox-360', 'Portal 2', 'Portal', '2011-04-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaanx.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-xbox-360', 'Prince of Persia', 'Prince of Persia', '2008-12-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3gts.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prince-of-persia-the-forgotten-sands-xbox-360', 'Prince of Persia: The Forgotten Sands', 'Prince of Persia', '2010-05-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8z2j.jpg', 'Prince of Persia: The Forgotten Sands is a promotional browser flash game created to promote the Prince of Persia: The Forgotten Sands. Playing the game unlocked a costume in the main game, though that feature no longer works. The game is still playable on explosivebarrel.net
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-xbox-360', 'Prototype', 'Prototype', '2009-06-09', 'Xbox 360', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5fpf.jpg', 'PtAP have chosen you to be the new test prototype! What does it mean, you wonder? We will force you to fight against robots and other Prototypes like you, with Power-ups and Paintballs.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-2-xbox-360', 'Prototype 2', 'Prototype', '2012-04-24', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20jt.jpg', 'Prototype 2 is an open-world action game published by Activision and developed by Radical Entertainment. It''s a direct sequel to Prototype and was announced at the 2010 Spike Video Game Awards.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-4-xbox-360', 'Quake 4', 'Quake', '2005-11-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1o1t.jpg', 'Quake 4 is a action shooter game which serves as the another chapter in the Quake series.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('enemy-territory-quake-wars-xbox-360', 'Enemy Territory: Quake Wars', 'Quake', '2008-05-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2o4l.jpg', 'Enemy Territory: Quake Wars is a first-person shooter video game developed by Splash Damage and published by Activision for Microsoft Windows, Linux, Mac OS X, PlayStation 3 and Xbox 360. The prequel to Quake II, Quake Wars is set in the same science fiction universe as Quake II and Quake 4, with a minimal back-story serving as a prequel to Quake II. It is the second multiplayer-focused game in the Quake series after Quake III Arena.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-4-re-release-xbox-360', 'Quake 4 (re-release)', 'Quake', '2012-06-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1o1t.jpg', 'Quake 4 is a action shooter game which serves as the another chapter in the Quake series.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-raving-rabbids-xbox-360', 'Rayman Raving Rabbids', 'Rabbids', '2007-04-24', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6pj8.jpg', 'Rayman Raving Rabbids was originally developed as a 3D platform game, under the working title Rayman 4. It was announced by Ubisoft on the 11th of April, 2006, shortly after the cancellation of Phoenix Studio''s unrelated Rayman 4 project. Under development by Ubisoft Montpellier, the game was to be a free-roaming action platforming game, in which the player would control Rayman as he battled against an invading army of Rabbids. The game was announced for the PlayStation 3, Xbox 360, Windows, and the Nintendo Wii, which was then codenamed the ''Revolution''.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('raving-rabbids-alive-kicking-xbox-360', 'Raving Rabbids: Alive & Kicking', 'Rabbids', '2011-11-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22ts.jpg', 'Raving Rabbids: Alive & Kicking, known as Rabbids: Fuori di schermo in Italy, is a video game which was released by publisher and developer Ubisoft (Ubisoft Paris and Ubisoft Milan) on November 3, 2011 in Australia, November 4, 2011 in Europe and November 8, 2011 in North America for the Xbox 360 video game platform. This is the sixth game from the Raving Rabbids games franchise and it is the only Rabbids game not released on a Nintendo platform. The game was exclusively developed for the Kinect and consists of mini-games with up to 4 players. It was presented at the 15th E3 in Los Angeles, California, United States.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-invasion-the-interactive-tv-show-xbox-360', 'Rabbids Invasion: The Interactive TV Show', 'Rabbids', '2014-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavxt.jpg', 'Rabbids Invasion, the kids hit animated TV show, is now an interactive game on PlayStation 4. With motion gameplay, kids can now play in their living room with a selection of episodes from the TV show. Through fun, silly challenges, players have an outrageous time with family and friends and experience the Rabbids Invasion TV show in a brand new way.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-origins-xbox-360', 'Rayman Origins', 'Rayman', '2011-11-15', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v7k.jpg', 'Bubble Dreamer, Rayman, his best friend Globox, and some Teensy friends are chilling out at the Bubble Dreamer''s resting grounds, the Snoring Tree. However, their snoring disturbs an old granny from the Land of the Livid Dead, who retaliates by sending an evil army of horrendous creatures and the Darktoons across the world, capturing the Electoons that inhabit the world, imprisoning Betilla the Nymph and her sisters, and plunging the Glade into chaos. As a result, the ensuing disaster causes the Bubble Dreamer to go crazy and have nightmares. Although they are captured, Rayman and his friends are able to escape the Darktoons. They are then tasked by the Magician to gather enough Electoons to cure the Bubble Dreamer and restore the Glade of Dreams. Their efforts to locate the Electoons allow them to gain access to the various lands of the Glade, rescuing the Nymphs along the way.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-xbox-360', 'Rayman Legends', 'Rayman', '2013-09-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-xbox-360', 'Red Dead Redemption', 'Red Dead', '2010-05-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6zwq.jpg', 'This bundle includes Red Dead Redemption, Red Dead Redemption: Undead Nightmare, Red Dead Online, and Red Dead Redemption 2: Story Mode.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-undead-nightmare-xbox-360', 'Red Dead Redemption: Undead Nightmare', 'Red Dead', '2010-11-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wrq.jpg', 'A port for the Switch and PS4 lacking multiplayer modes present in the original release.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-game-of-the-year-edition-xbox-360', 'Red Dead Redemption: Game of the Year Edition', 'Red Dead', '2011-10-11', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3cu9.jpg', 'Red Dead Redemption: Game of the Year Edition will include the full, original Red Dead Redemption game plus all free and paid downloadable content packs released to date, including the wildly popular Undead Nightmare single and multiplayer offerings, as well as all DLC originally released as pre-order content.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('remember-me-xbox-360', 'Remember Me', NULL, '2013-06-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/uwk5nzvqt6q9l2ogr3am.jpg', 'A psychological horror game and visual novel that will test your morality, your ability to adapt, and your willpower to remain sane under pressure...', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-xbox-360', 'Resident Evil 5', 'Resident Evil', '2009-03-13', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtgs.jpg', 'Resident Evil 5 is the seventh video game in the Resident Evil series. It features similar gameplay to Resident Evil 4 utilizing the same over the shoulder view, but this time the environment plays a significant role. The player is now dependent on his partner more than in older games. When the partner''s health bar drop down to 0, he will enter the dying stage where the health bar will flash red and gradually lower as he stays like this. Resident Evil 5 also features new types of enemies called Majini and mostly are of African descent.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-gold-edition-xbox-360', 'Resident Evil 5: Gold Edition', 'Resident Evil', '2010-03-09', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nxe.jpg', 'Resident Evil 5: Gold Edition includes "Lost in Nightmares" and another campaign-expansion episode, "Desperate Escape", where players control Josh Stone and Jill Valentine as they assist Chris and Sheva. The edition also includes the previously released Versus mode, four new costumes and an alternate Mercenaries mode with eight new playable characters, new items and maps.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-operation-raccoon-city-xbox-360', 'Resident Evil: Operation Raccoon City', 'Resident Evil', '2012-03-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20d0.jpg', 'Resident Evil: Operation Raccoon City is a third-person shooter and is a spin-off of the long-running Resident Evil series. Unlike the main games in the series, it is less of a survival horror game and more of an action-packed shooter. The game includes twelve playable characters, however the players can choose only four characters for the online modes. Each team member has their own special role and abilities.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-6-xbox-360', 'Resident Evil 6', 'Resident Evil', '2012-10-02', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pyq.jpg', 'Resident Evil 6 is the ninth video game installment in the Resident Evil series. It continues the struggle against zombies infected by the new highly virulent C-virus. The game uses the same over-the-shoulder view as Resident Evil 4 and Resident Evil 5, however with a new gameplay mechanic that allows players to slowly move while shoot. Players can select between three scenarios featuring multiple characters and intertwined storylines, and within these scenarios both stories and action cross paths. At key moments during the game, up to four players can join together online to tackle a specific situation, with some stages seeing the usual partnerships swapped to further increase the depth of gameplay.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-xbox-360', 'Resident Evil: Revelations', 'Resident Evil', '2013-05-21', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-2-xbox-360', 'Resident Evil: Revelations 2', 'Resident Evil', '2015-03-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92d9.jpg', 'Resident Evil: Revelations 2 is the retail version of the episodic survival horror series that was originally released as four downloadable episodes. This physical version combines the entire story along with some extras, but not all the available DLC. The PC version did not receive a retail release, but the same content was bundled on Steam. The game comprises four episodes, each of which feature two separate stories. This sequel bears a stronger tone to the concept of survival horror than titles such as Resident Evil 5 and Resident Evil 6. Elements of ammunition management as well as stealth or sneaking come into play in the gameplay.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-superstars-tennis-xbox-360', 'Sega Superstars Tennis', 'Sega All-Stars', '2008-03-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6p9b.jpg', 'Developed by Sumo Digital, this is the handheld port of Sega Superstars Tennis. While the core mechanics remain very similar, the game differs from the home console version in its presentation, depth, and certain elements of functionality.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-sega-all-stars-racing-xbox-360', 'Sonic & Sega All-Stars Racing', 'Sega All-Stars', '2010-02-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1te6.jpg', 'Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle under lush rain forest canopies and tear through bustling city scapes in a frantic race to the finish line. Jostle against a selection of 20 challengers including Super Monkey Ball’s Ai Ai, Amigo from Samba and the evil Dr. Eggman in your unique character vehicle. Stay ahead of the pack by dodging traps and launching outrageous character moves such as the invincible Super Sonic, Banana Blitz assault of monkey balls or Tails wild Tornado - set to throw any vehicle clean in the air! But if you’ve been battered, beaten and broken, it’s not over yet! Super-charge your vehicle with power-ups to get back in the race and be sure to stay alert for the secret short-cuts that will give you the edge to victory.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-all-stars-racing-transformed-xbox-360', 'Sonic & All-Stars Racing Transformed', 'Sega All-Stars', '2012-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvw.jpg', 'Race as Sonic and a host of legendary All-Stars and prepare to transform! Speed across land, sea and air in a high velocity battle to the finish line, as your amazing transformable vehicle changes from car to boat to plane mid-race. Racing on mobile will never be the same again!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mysims-skyheroes-xbox-360', 'MySims SkyHeroes', 'The Sims', '2010-09-28', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uk1.jpg', 'The DS port of the final game in the MySims series.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-xbox-360', 'The Sims 3', 'The Sims', '2010-10-26', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nas.jpg', 'The Sims 3 is a console game developed by Electronic Arts for the Nintendo Wii.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-3-pets-xbox-360', 'The Sims 3: Pets', 'The Sims', '2011-10-18', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7jis.jpg', 'Bring excitement and surprise into your Sims'' lives with pets in The Sims 3: Pets, an expansion pack for The Sims 3! Create the perfect (or imperfect) pets for your Sims, from fierce guard dogs to destructive kittens to trusty horses and more as you determine not only how your Sims'' pets look but their personality traits as well. With a variety of new activities and social interactions, take direct control of your Sims'' pets and explore new ways to mess with their lives. Give your Sims a new member of their household and discover all-new ways to play with life!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-spyro-s-adventure-xbox-360', 'Skylanders: Spyro''s Adventure', 'Skylanders', '2011-10-16', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsc.jpg', 'Skylanders: Spyro''s Adventure is the first video game in the Skylanders series. It is a video game that is played along with toy figures that interact with it through a "Portal of Power", that reads their tag through NFC and features the voices of Josh Keaton, Dave Wittenberg, Darin De Paul, Joey Camen, Audrey Wasilewski, Keythe Farley and Kevin Michael Richardson.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-giants-xbox-360', 'Skylanders: Giants', 'Skylanders', '2012-10-21', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6vlm.jpg', 'Skylanders: Giants is a 2012 video game in the Skylanders series, a direct sequel to the 2011 game Skylanders: Spyro''s Adventure and features the voices of Kevin Michael Richardson, Greg Ellis, Peter Lurie, Steve Blum, Dave Wittenberg, Carlos Alazraqui, Kevin Sorbo, Bobcat Goldthwait, Patrick Seitz and Julie Nathanson. It is the game before Skylanders: Swap Force. As the title suggests, it features larger Skylanders known as "Giants", along with other new gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-xbox-360', 'Skylanders: Swap Force', 'Skylanders', '2013-10-13', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-xbox-360', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-xbox-360', 'Skylanders: SuperChargers', 'Skylanders', '2015-09-20', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsk.jpg', 'Exclusive to the Wii U version of the game is a special figure of Donkey Kong and Bowser.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-xbox-360', 'Skylanders: Imaginators', 'Skylanders', '2016-10-16', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-the-hedgehog-xbox-360', 'Sonic the Hedgehog', 'Sonic the Hedgehog', '2006-11-14', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8ubt.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-unleashed-xbox-360', 'Sonic Unleashed', 'Sonic the Hedgehog', '2008-11-18', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2v6p.jpg', 'Gameplay in Sonic Unleashed focuses on two modes of platforming play: fast-paced levels that take place during daytime, showcasing Sonic''s trademark speed as seen in previous games in the series, and slower, night-time levels, during which Sonic''s Werehog form emerges, and gameplay switches to an action-based, brawler style of play, in which Sonic battles Gaia enemies', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-s-ultimate-genesis-collection-xbox-360', 'Sonic''s Ultimate Genesis Collection', 'Sonic the Hedgehog', '2009-02-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1upp.jpg', 'The compilation features 48 Sega games (49 counting two versions of Altered Beast) which were previously released for the Mega Drive/Genesis (including most of the Sonic the Hedgehog titles released for the system), arcade and Sega Master System. It is similar to the Sega Genesis Collection released previously for the PlayStation 2 and PSP, however it contains 16 (in NTSC regions) more games (including unlockable extras).', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-free-riders-xbox-360', 'Sonic Free Riders', 'Sonic the Hedgehog', '2010-11-04', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zvt.jpg', 'Jump into the race! Become your favorite Sonic character and use your whole body to twist, turn and jump in this hi-octane game exclusive to Kinect. Crouch and jump to pull huge airs! Ride boards, bikes, jet skis, and even a mine cart! Take out competitors with crazy weapons!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-generations-xbox-360', 'Sonic Generations', 'Sonic the Hedgehog', '2011-11-01', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zya.jpg', 'In the 3DS version of Sonic Generations, Modern Sonic''s gameplay is similar to that of Sonic Rush and the DS version of Sonic Colors. He has the Boost, the ability to slide under obstacles, jump off walls, and the Homing Attack. After the second era, Modern Sonic learns the Stomp. Modern Sonic''s levels use the 3D effect of depth on the 3DS version more actively as well as to giving a better view for when Modern Sonic jumps into the background, although the console versions are 3D-TV compatible. In the HD version, Modern Sonic is only able to wall jump off certain panels (similar to the DS version of Sonic Colors), but in the 3DS version, he is able to wall jump on any wall (much like Sonic Unleashed and the Wii version of Sonic Colors).', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spec-ops-the-line-xbox-360', 'Spec Ops: The Line', 'Spec Ops', '2012-06-26', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2acb.jpg', 'A third-person shooter in which three American soldiers led by Capt. Walker are sent to Dubai in order to recover whoever remains of an infantry unit, the 33rd Battalion, until they decide to take action against the militants situated in the city. As they progress, however, the logistical and ethical complexity of their objective deepens, and their perception of themselves, and their enemy, is put into question.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-legend-of-spyro-dawn-of-the-dragon-xbox-360', 'The Legend of Spyro: Dawn of the Dragon', 'Spyro', '2008-10-21', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co86a8.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-xbox-360', 'Star Wars: The Force Unleashed', 'Star Wars', '2008-09-16', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xx.jpg', 'Star Wars: The Force Unleashed is a Star Wars video game that takes place between the films Star Wars: Episode III Revenge of the Sith and Star Wars: Episode IV A New Hope. It is the centerpiece of the Star Wars: The Force Unleashed multimedia project,
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-clone-wars-republic-heroes-xbox-360', 'Star Wars: The Clone Wars – Republic Heroes', 'Star Wars', '2009-10-06', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5nrd.jpg', 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and clone troopers from the preeminent animated television series – from familiar faces like Anakin Skywalker to new heroes like Clone Captain Rex.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-the-force-unleashed-ii-xbox-360', 'Star Wars: The Force Unleashed II', 'Star Wars', '2010-10-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25xw.jpg', 'The Star Wars Saga continues with Star Wars: The Force Unleashed II, the highly anticipated sequel to the fastest-selling Star Wars game ever created, which has sold more than seven million copies worldwide.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-star-wars-xbox-360', 'Kinect Star Wars', 'Star Wars', '2012-04-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22ry.jpg', '"Kinect Star Wars" brings Star Wars to life like never before. Harnessing the controller-free power of Kinect for Xbox 360, "Kinect Star Wars" allows fans to physically hone their Jedi skills, wield the power of the Force in their hands, pilot iconic starships and vehicles, rampage as a vicious rancor monster or even dance with iconic Star Wars characters. Using full body motions, players can live out the ultimate Star Wars fantasy to use the Force, battle with a lightsaber and more -- no controller required.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-vesperia-xbox-360', 'Tales of Vesperia', 'Tales', '2008-08-26', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gb1.jpg', 'The Japan-exclusive PlayStation 3 version of Tales of Vesperia features full-voice acting, nearly doubling the size of the script of the original Xbox 360 version. New songs, towns, and dungeons have been added. Other major changes include new quests, bosses, skits, and story elements. New gameplay additions are introduced, such as higher Overlimit levels, more artes, mystic artes, equipment, and character costumes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-xbox-360', 'Terraria', NULL, '2013-03-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-the-grand-master-ace-xbox-360', 'Tetris: The Grand Master Ace', 'Tetris', '2005-12-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3a6y.jpg', NULL, 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-evolution-xbox-360', 'Tetris Evolution', 'Tetris', '2007-03-19', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3a78.jpg', 'In Tetris Evolution, players enjoy not only traditional Tetris gameplay but numerous new modes including "Go Low" and "Eraser" for both single and multiplayer. The multiplayer mode not only allows for up to four players on a single console, but players can now compete with up to four players via the Xbox Live online entertainment service.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thief-xbox-360', 'Thief', 'Thief', '2014-02-25', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rom.jpg', 'In the third instalment of the Thief series, master-thief Garrett is contacted by Keeper Artemus with a mission to steal two valuable artefacts. At the same time, Garrett learns about a prophecy: the coming of a Dark Age. He embarks upon a journey to unravel a mystery that threatens the existence of the order of Keepers. Is it possible that there is a traitor in their midst?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('titanfall-xbox-360', 'Titanfall', 'Titanfall', '2014-04-08', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wo1.jpg', 'In Titanfall, players fight on a war-torn planet in six-on-six online multiplayer-only matches as mech-style Titans and their pilots. The game''s action is fast-paced: as pilots, players can run along walls and link jumps together parkour-style, use a variety of futuristic military weapons, and employ one of three special abilities: cloaking, stimming (increasing speed and health regeneration) and radar pinging; as Titans, players are equipped with more destructive armaments and special protective shields, with no limit to their abilities besides cooldown and reloading.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-double-agent-xbox-360', 'Tom Clancy''s Splinter Cell: Double Agent', 'Tom Clancy''s Splinter Cell', '2006-10-17', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95r2.jpg', 'In the highly anticipated sequel, Tom Clancy''s Splinter Cell: Double Agent, play as a double agent spy for the first time ever. Take on dual roles of covert operative and ruthless terrorist, where your choices of whom to betray and whom to protect actually affect the outcome of your game. This is the Ubisoft Montreal version, which plays more like the classic Splinter Cell games. The games share the same general plot but feature different storylines, plot twists, and levels. They do however, share the same background music, a few cut scenes and all voice actors.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-conviction-xbox-360', 'Tom Clancy''s Splinter Cell: Conviction', 'Tom Clancy''s Splinter Cell', '2010-04-13', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ypl.jpg', 'Experience an unparalleled level of action as you navigate the world of Sam Fisher. Go online or split screen in four co-op modes. Play the prologue to the single player storyline in co-op.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tom-clancy-s-splinter-cell-blacklist-xbox-360', 'Tom Clancy''s Splinter Cell: Blacklist', 'Tom Clancy''s Splinter Cell', '2013-08-20', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ygp.jpg', 'Splinter Cell Blacklist builds on the stealth roots of the franchise, while exploring new directions to embrace the realms of action and adventure. Players can define their personal play styles and be rewarded for those choices.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-legend-xbox-360', 'Tomb Raider: Legend', 'Tomb Raider', '2006-04-11', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nnv.jpg', 'Tomb Raider: Legend is the seventh major game in the Tomb Raider series, now for the first time developed by Crystal Dynamics, along with the original character designer of the game''s protagonist, Lara Croft. It serves as a reboot of the franchise, with a new incarnation of Lara Croft. The typical third-person action-adventure exploring is still present, and Lara can move more freely because specific jumps no longer limit her. As players travel through rough environments, they will need to run, dive, swim, climb on poles, ladders, and roofs, use zip lines, shimmy, and vault, with acrobatic actions such as somersaults and flips. Players need to cross difficult terrain, solve puzzles to advance or open up new areas, and engage in combat.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-anniversary-xbox-360', 'Tomb Raider: Anniversary', 'Tomb Raider', '2007-10-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8mz7.jpg', 'The Wii port of Tomb Raider: Anniversary carries over the levels and general gameplay of the other versions while incorporating motion controls. Wii-exclusive first-person puzzles include breaking through walls with a pickaxe, using a flashlight in dark areas, assembling mechanisms from pieces found around the environment, manipulating symbol-based locks and using paper and charcoal to take rubbings of puzzle-related symbols, all utilizing the Wii Remote.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-underworld-xbox-360', 'Tomb Raider: Underworld', 'Tomb Raider', '2008-11-18', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1voc.jpg', 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of challenge and choice.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-xbox-360', 'Tomb Raider', 'Tomb Raider', '2013-03-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3lq1.jpg', 'Tomb Raider: The Angel of Darkness is the sixth game in the Tomb Raider series, and is the sequel to Tomb Raider: Chronicles. Angel of Darkness introduces new stealth and close-combat moves - ducking, sneaking and hug-the-walls walking. Lara must build her skills by performing action sequences. You''ll have her running, dodging, performing flying leaps and platform jumps, shimming along walls and cables, as well as moving boxes and other obstacles around. Advancements are achieved with strategically placed power-ups. Collect weapons and ammunition, artifacts and money.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rise-of-the-tomb-raider-xbox-360', 'Rise of the Tomb Raider', 'Tomb Raider', '2015-11-10', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rqa.jpg', 'Join Lara Croft on her first great tomb raiding expedition as she seeks to discover the secret of immortality. Featuring high-octane action set in the most beautiful and hostile environments on earth, Rise of the Tomb Raider delivers cinematic survival action-adventure.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-xbox-360', 'Turok', 'Turok', '2008-02-05', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2699.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viva-pi-ata-xbox-360', 'Viva Piñata', 'Viva Piñata', '2006-11-09', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mv6.jpg', 'In Viva Pinata: Pocket Paradise, players will inherit a neglected garden on Pinata Island and turn it into a pinata paradise by tending to all aspects of cleaning the garden, growing and maintaining vegetation, caring for and breeding pinatas, as well as attracting new pinata species. The game features seven all-new pinata species, each with new requirements, houses and unique cut scenes. Viva Pinata: Pocket Paradise also includes twelve full motion video clips that serve as tutorial levels within the game. The videos feature the stars of the Fox 4Kids Viva Pinata TV series, including Hudson Horstashio, Fergy Fudgehog and Paulie Pretztail. The brand-new Playground mode allows players to create a lush garden full of exciting and exotic pinatas in a very short amount of time. In addition, certain rare pinatas can only be acquired by using the Nintendo DS local wireless connection, where players can transfer items from their garden to a friend''s garden.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viva-pi-ata-party-animals-xbox-360', 'Viva Piñata: Party Animals', 'Viva Piñata', '2007-10-30', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50pm.jpg', 'A multiplayer game expanding the Viva Pinata experience. Compete in a variety of zany battles and races in the social party game Viva Piñata: Party Animals. Control the fame, fortune, and destiny of all your favorite characters from Viva Piñata: Fergy Fudgehog, Paulie Pretztail, Franklin Fizzlybear, and Hudson Horstachio. It''s party time!', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('viva-pi-ata-trouble-in-paradise-xbox-360', 'Viva Piñata: Trouble in Paradise', 'Viva Piñata', '2008-09-02', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2z8o.jpg', 'The original Rare Ltd. team behind Viva Piñata has reunited to bring gamers Viva Piñata: Trouble in Paradise, the newest and most fun piñata adventure to date. Available exclusively on Xbox 360, Viva Piñata: Trouble in Paradise reinvigorates a colorful and engaging gaming experience on the Xbox 360 platform. Now with full cooperative and online gameplay modes, the Viva Piñata franchise opens its doors even wider with a new game that provides hours of fun for gamers of all ages, fans of the animated series and animal lovers alike.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-game-of-the-year-edition-xbox-360', 'The Walking Dead: Game of the Year Edition', 'The Walking Dead', '2013-11-19', 'Xbox 360', 0, 0, NULL, NULL, NULL, NULL, 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-season-two-xbox-360', 'The Walking Dead: Season Two', 'The Walking Dead', '2014-10-14', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k36.jpg', 'Similar to the previous season, The Walking Dead: Season Two is a point-and-click adventure game. The player, in control of Clementine, can direct the character around the environment, examine and interact with various scenery elements and collect and use objects to advance the story. The player can also initiate conversations with non-player characters via conversation trees. Certain replies from other characters may offer the player multiple choices to select from, including the option to stay silent, with a limited amount of time to make the selection; if the player does not select an option, the conversation will continue as if they had stayed quiet. Such choices can affect how the other characters will later react to Clementine which can influence later events in the story. Other scenes are more action-oriented, requiring the player to complete quick time events to avoid Clementine or her allies from getting killed. If the player fails these events, the game will restart at the start of such scenes. Such action scenes may also require the player to make a key decision within a limited time frame, such as which of two characters to save from attacking walkers.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-xbox-360', 'Watch Dogs', 'Watch Dogs', '2014-05-27', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j2m.jpg', 'Purchase the Watch Dogs and Watch Dogs 2 bundle and gain access to these award-winning titles at a great price. In Watch Dogs, become Aiden Pearce and hack your way around Chicago to take down ctOS. In Watch Dogs 2, join Marcus Holloway and the Dedsec hacker group to expose a new digital conspiracy.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-xbox-360', 'Wolfenstein', 'Wolfenstein', '2009-08-18', 'Xbox 360', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-new-order-xbox-360', 'Wolfenstein: The New Order', 'Wolfenstein', '2014-05-20', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c0.jpg', 'Wolfenstein: The New Order is an action-adventure shooter game played from a first-person perspective. It is the semi-sequel to 2009''s Wolfenstein, however utilizes very little from the game and drops any direct references to veil or supernatural.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xbox-live-arcade-unplugged-vol-1-xbox-360', 'Xbox Live Arcade Unplugged Vol. 1', 'Xbox Live Arcade', '2006-09-05', 'Xbox 360', 0, 0, NULL, NULL, NULL, NULL, 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xbox-live-arcade-compilation-disc-xbox-360', 'Xbox Live Arcade Compilation Disc', 'Xbox Live Arcade', '2007-10-23', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6djh.jpg', 'Xbox Live Arcade Compilation Disc is a package of five Arcade games and seven demos, typically bundled alongside Xbox 360 consoles. When inserted, all games and demos will appear in the Xbox at once, On occasion, this would be bundled alongside Sega Superstars Tennis.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xbox-live-arcade-game-pack-xbox-360', 'Xbox Live Arcade Game Pack', 'Xbox Live Arcade', '2009-11-03', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/xlgly1dtujqgi9odfuqi.jpg', 'Xbox Live Arcade Game Pack is a package of three Xbox Live Arcade games. The compilation was packaged with a black wireless controller. The disc works by inserting it into the system just like any other game. However, rather than directly launching any of the titles, it adds three items to the Xbox Live Arcade menu with a small disc icon next to each name.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xbox-360-triple-pack-xbox-360', 'Xbox 360 Triple Pack', 'Xbox Live Arcade', '2011-04-19', 'Xbox 360', 0, 0, NULL, NULL, NULL, NULL, 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zone-of-the-enders-hd-collection-xbox-360', 'Zone of the Enders HD Collection', 'Zone of the Enders', '2012-10-30', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4slq.jpg', 'Zone of the Enders HD Edition (Zone of the Enders HD Collection outside Japan) is a re-release of Zone of the Enders and Zone of the Enders: The 2nd Runner for the Playstation 3 and Xbox 360 consoles. The collection refines the textures and graphics and The 2nd Runner game comes with the Special Edition content that was released only in Japan and Europe, an import soundtrack featuring remixes of the music featured in the series, along with a demo of Metal Gear Rising: Revengeance. It also has a new Opening Movie, set to the Theme of Z.O.E. 2, Beyond the Bounds, animated by Sunrise. The collection was released in North America on October 30, 2012 and was released in Europe on November 30, 2012.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoo-tycoon-xbox-360', 'Zoo Tycoon', 'Zoo Tycoon', '2013-11-22', 'Xbox 360', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22u7.jpg', 'Zoo Tycoon is a business simulation developed by Blue Fang Games and released by Microsoft Game Studios. It is a tycoon game in which the player must run a zoo and try to make a profit. Although first released for Microsoft Windows and Macintosh in 2001, it was ported to the Nintendo DS in 2005. It was followed by two expansion packs, Zoo Tycoon: Dinosaur Digs and Zoo Tycoon: Marine Mania, which were released in 2002, as well as a sequel, Zoo Tycoon 2, released in 2004.', 'NA', 48);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('abz-xbox-one', 'Abzû', NULL, '2017-01-31', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28sy.jpg', 'Abzu is an exploration game where you are a lone diver in a lush ocean world. The diver descends deeper and deeper into the depths, where she will encounter majestic creatures, discover ancient secrets, and search for her true purpose. Abzu roughly translates to "The Ocean of Wisdom" from ancient Sumerian.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alan-wake-remastered-xbox-one', 'Alan Wake Remastered', 'Alan Wake', '2021-10-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co65aa.jpg', 'Alan Wake Remastered is an updated version of the original psychological horror action-adventure game developed by Remedy Entertainment. The game retains the core narrative, which follows bestselling thriller novelist Alan Wake as he struggles with writer''s block. He visits the small town of Bright Falls with his wife, Alice, in search of inspiration. Shortly after their arrival, Alice mysteriously disappears.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('among-us-crewmate-edition-xbox-one', 'Among Us: Crewmate Edition', 'Among Us', '2021-12-21', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wwy.jpg', 'Play online with 4-15 players as you attempt to hold your spaceship together and return back to civilization. But beware... as there may be an alien impostor aboard!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iv-black-flag-xbox-one', 'Assassin''s Creed IV: Black Flag', 'Assassin''s Creed', '2013-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tx9.jpg', NULL, 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-unity-xbox-one', 'Assassin''s Creed Unity', 'Assassin''s Creed', '2014-11-11', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xiq.jpg', 'Assassin’s Creed Unity is an action-adventure game set in Paris during the French Revolution. The player controls Arno Dorian, an Assassin who seeks to uncover the forces behind the political unrest. The game introduces new weapons, including the Phantom Blade, a modified Hidden Blade with ranged capabilities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-syndicate-xbox-one', 'Assassin''s Creed Syndicate', 'Assassin''s Creed', '2015-10-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xis.jpg', 'London, 1868. The Industrial Revolution unleashes an incredible age of invention, transforming the lives of millions with technologies once thought impossible. Opportunities created during this period have people rushing to London to engage in this new world, a world no longer controlled by kings, emperors, politicians, or religion, but by a new common denominator: money.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-chronicles-xbox-one', 'Assassin''s Creed Chronicles', 'Assassin''s Creed', '2016-02-09', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8yvv.jpg', 'As the direct prequel of the critically acclaimed console title Assassin’s Creed, discover more of the story of Altaïr as he must find “the chalice,” an object of such power that whoever is in possession of it can end the Crusades.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-the-ezio-collection-xbox-one', 'Assassin''s Creed: The Ezio Collection', 'Assassin''s Creed', '2016-11-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nrv.jpg', 'Make history as the legendary Master Assassin, Ezio Auditore da Firenze, in Assassin’s Creed The Ezio Collection, which includes the acclaimed single-player campaigns and single-player add-on content (no multiplayer content) from Assassin’s Creed II, Assassin’s Creed Brotherhood, and Assassin’s Creed Revelations with enhanced
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-origins-xbox-one', 'Assassin''s Creed Origins', 'Assassin''s Creed', '2017-10-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbe.jpg', 'Assassin’s Creed Origins is an action-adventure game set in ancient Egypt at the end of the Ptolemaic era. The story follows Bayek, a Medjay tasked with protecting the people, as personal tragedy draws him into a wider conflict that leads to the origins of the Assassin Brotherhood.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-rogue-remastered-xbox-one', 'Assassin''s Creed Rogue Remastered', 'Assassin''s Creed', '2018-03-20', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xit.jpg', 'In addition to running in 4K, Assassin''s Creed Rogue Remastered sports higher-resolution textures and shadows, improved environmental rendering, and new visual effects, making its sprawling wilderness, Arctic icescapes, and bustling version of New York City more striking than ever. The new edition also packs in all of the original''s downloadable content and expansions, including two bonus missions – The Armor of Sir Gunn and The Siege of Fort de Sable – as well as the weapons, outfits, and customization items in the Master Templar and Explorer packs. It also includes a new bonus: Bayek''s legacy outfit from Assassin''s Creed Origins.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-odyssey-xbox-one', 'Assassin''s Creed Odyssey', 'Assassin''s Creed', '2018-10-05', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ka7.jpg', 'A bundle including three Assassin''s Creed titles: Assassin''s Creed Valhalla, Assassin''s Creed Odyssey, and Assassin''s Creed Origins.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-iii-remastered-xbox-one', 'Assassin''s Creed III Remastered', 'Assassin''s Creed', '2019-03-29', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gjw.jpg', 'Relive the American Revolution or experience it for the first time in Assassin''s Creed III Remastered, with enhanced graphics and improved gameplay mechanics.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('assassin-s-creed-valhalla-xbox-one', 'Assassin''s Creed Valhalla', 'Assassin''s Creed', '2020-11-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ed3.jpg', 'In Assassin''s Creed Valhalla, become Eivor, a legendary Viking raider on a quest for glory. Explore a dynamic and beautiful open world set against the brutal backdrop of England’s Dark Ages. Raid your enemies, grow your settlement, and build your political power in the quest to earn a place among the gods in Valhalla.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-1-xbox-one', 'Atari Flashback Classics: Vol.1', 'Atari Flashback Classics', '2016-11-01', 'Xbox One', 1, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-2-xbox-one', 'Atari Flashback Classics: Vol.2', 'Atari Flashback Classics', '2016-11-01', 'Xbox One', 1, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('atari-flashback-classics-vol-3-xbox-one', 'Atari Flashback Classics: Vol.3', 'Atari Flashback Classics', '2018-12-13', 'Xbox One', 0, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('balan-wonderworld-xbox-one', 'Balan Wonderworld', NULL, '2021-03-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2xxs.jpg', 'Balan Wonderworld is a wondrous action-platformer game themed around a mysterious musical theatre.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baldur-s-gate-enhanced-edition-baldur-s-gate-ii-enhanced-edition-xbox-one', 'Baldur''s Gate: Enhanced Edition & Baldur''s Gate II: Enhanced Edition', 'Baldur''s Gate', '2019-10-15', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ndo.jpg', 'Kidnapped. Imprisoned. Tortured. The wizard Irenicus holds you captive in his stronghold, attempting to strip you of the powers that are your birthright.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bioshock-the-collection-xbox-one', 'BioShock: The Collection', 'BioShock', '2016-09-13', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uv1.jpg', 'BioShock: The Collection is a game bundle consisting of remastered 1080p editions of BioShock, BioShock 2 and BioShock Infinite along with their accompanying downloadable content.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bloodstained-ritual-of-the-night-xbox-one', 'Bloodstained: Ritual of the Night', 'Bloodstained', '2019-06-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobc4a.jpg', 'Bloodstained: Ritual of the Night is a gothic horror action side-scrolling RPG set in 19th century England. A paranormal force has summoned a demon-infested castle, revealing crystal shards infused with tremendous magical power.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-bomberman-r-xbox-one', 'Super Bomberman R', 'Bomberman', '2018-06-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4x7j.jpg', 'A sequel to Super Bomberman R, featuring an expanded story mode, and a new "Castle" battle mode which has one group teaming up to build castle defenses while the other attempts to breach the castle and take the treasure.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-the-handsome-collection-xbox-one', 'Borderlands: The Handsome Collection', 'Borderlands', '2015-03-24', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229i.jpg', 'Borderlands: The Handsome Collection is a compilation of Borderlands 2 and Borderlands: The Pre-Sequel! for PlayStation 4 and Xbox One, along with all of their accompanying downloadable content, enhanced local multiplayer, and the ability to transfer save data from their respective PlayStation 3/Vita and Xbox 360 versions.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-from-the-borderlands-xbox-one', 'Tales from the Borderlands', 'Borderlands', '2016-04-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20tr.jpg', 'Tales from the Borderlands is a five part episodic game series. Set on the unforgiving world of Pandora after the events seen in Borderlands 2, this is a story full of Borderlands'' trademark humor, following two adventurers on their quest for greatness.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-game-of-the-year-edition-xbox-one', 'Borderlands: Game of the Year Edition', 'Borderlands', '2019-04-03', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co229j.jpg', 'Lock, Load, & Face the Madness! Get ready for the mind-blowing insanity, as one of four trigger-happy mercenaries, taking out everything that stands in your way. With its addictive action, frantic first person shooter combat, massive arsenal of weaponry, RPG elements and four-player co-op, Borderlands is the breakthrough experience that challenges all the conventions of modern shooters. Borderlands places you in the role of a mercenary on the lawless and desolate planet of Pandora, hell bent on finding a legendary stockpile of powerful alien technology known as The Vault.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('borderlands-3-xbox-one', 'Borderlands 3', 'Borderlands', '2019-09-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20r3.jpg', 'The original shooter-looter returns, packing bazillions of guns and a mayhem-fueled adventure! Blast through new worlds and enemies as one of four new Vault Hunters. Play solo or with friends to take on insane enemies, score loads of loot and save your home from the most ruthless cult leaders in the galaxy.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tiny-tina-s-wonderlands-xbox-one', 'Tiny Tina''s Wonderlands', 'Borderlands', '2022-03-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co390m.jpg', 'Embark on an epic adventure full of whimsy, wonder, and high-powered weaponry! Bullets, magic, and broadswords collide across this chaotic fantasy world brought to life by the unpredictable Tiny Tina.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('brothers-a-tale-of-two-sons-xbox-one', 'Brothers: A Tale of Two Sons', NULL, '2015-09-01', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rro.jpg', 'Brothers is presented from a third-person view overlooking the two brothers. The brothers are moved individually by two thumbsticks on the controller. The controller triggers also cause the respective brother to interact with the game world, such as talking to a non-player character or grabbing onto a ledge or object.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-ghosts-xbox-one', 'Call of Duty: Ghosts', 'Call of Duty', '2013-11-22', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3b15.jpg', 'Call of Duty: Ghosts takes place following a catastrophic event that changed the global balance of powers in the world. As a result, the United States is no longer recognized as a superpower. Ten years after the event, an unseen enemy emerges as a threat, but the remnants of US special forces from every branch came together to create an elite group of soldiers known as the "Ghosts", who are determined to eradicate all threats to protect the weak and the remains of America.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-advanced-warfare-xbox-one', 'Call of Duty: Advanced Warfare', 'Call of Duty', '2014-11-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wky.jpg', 'Call of Duty: Advanced Warfare envisions the powerful battlegrounds of the future, where both technology and tactic have evolved to usher in a new era of combat for the franchise. Delivering a stunning performance, Academy Award winning actor Kevin Spacey stars as Jonathan Irons – one of the most powerful men in the world – shaping this chilling vision of the future of war.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-iii-xbox-one', 'Call of Duty: Black Ops III', 'Call of Duty', '2015-11-06', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60bm.jpg', 'The PlayStation 3 and Xbox 360 versions of Call of Duty: Black Ops III were developed by Beenox and Mercenary Technology while the PlayStation 4, Xbox One, PC versions of the game were developed by Treyarch. Due to the last generation consoles'' inferior hardware, significant changes had to be made.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-infinite-warfare-xbox-one', 'Call of Duty: Infinite Warfare', 'Call of Duty', '2016-11-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wkp.jpg', 'Call of Duty: Infinite Warfare delivers three unique game modes: Campaign, Multiplayer, and Zombies. Campaign is a return to the gritty, military roots of the franchise, while boldly looking ahead, delivering a rich and engaging narrative that is unlike anything to date in a Call of Duty game. The player will embark on a classically-styled story about grand scale warfare, set in a future where human conflict has spread throughout our solar system.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-wwii-xbox-one', 'Call of Duty: WWII', 'Call of Duty', '2017-11-03', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rdj.jpg', 'Call of Duty: WWII creates the definitive World War II next generation experience across three different game modes: Campaign, Multiplayer, and Co-Operative. Featuring stunning visuals, the Campaign transports players to the European theater as they engage in an all-new Call of Duty story set in iconic World War II battles. Multiplayer marks a return to original, boots-on-the ground Call of Duty gameplay. Authentic weapons and traditional run-and-gun action immerse you in a vast array of World War II-themed locations. The Co-Operative mode unleashes a new and original story in a standalone game experience full of unexpected, adrenaline-pumping moments.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-4-xbox-one', 'Call of Duty: Black Ops 4', 'Call of Duty', '2018-10-12', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wkf.jpg', 'Black Ops is back! Featuring gritty, grounded, fluid Multiplayer combat, the biggest Zombies offering ever with three full undead adventures at launch, and Blackout, where the universe of Black Ops comes to life in one massive battle royale experience featuring the largest map in Call of Duty history, signature Black Ops combat, characters, locations and weapons from the entire Black Ops series.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-modern-warfare-xbox-one', 'Call of Duty: Modern Warfare', 'Call of Duty', '2019-10-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctx.jpg', 'The game brings "open combat, " offering players more choices in approaching the single-player missions. Makarov returns as the chief villain of the new campaign.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-cold-war-xbox-one', 'Call of Duty: Black Ops Cold War', 'Call of Duty', '2020-11-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n6j.jpg', 'The iconic Black Ops series is back with Call of Duty: Black Ops Cold War - the direct sequel to the original and fan-favorite Call of Duty: Black Ops. Black Ops Cold War will drop fans into the depths of the Cold War’s volatile geopolitical battle of the early 1980s. Nothing is ever as it seems in a gripping single-player Campaign, where players will come face-to-face with historical figures and hard truths, as they battle around the globe through iconic locales like East Berlin, Vietnam, Turkey, Soviet KGB headquarters and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-vanguard-xbox-one', 'Call of Duty: Vanguard', 'Call of Duty', '2021-11-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kq8.jpg', 'This is WWII combat like never before. Witness the origins of Special Forces as you play a pivotal role and change the face of history, forming Task Force One in a gripping Campaign across four major theaters of war. Become an original Special Forces Operator in an online Multiplayer rich in innovation with 20 maps available at launch. Prepare for a franchise-first, universe-expanding Zombies crossover. Immerse yourself in a fully integrated Call of Duty: Warzone experience featuring a new and massive map. This is the most connected Call of Duty ever, all powered by the next generation Call of Duty engine introduced in Modern Warfare.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-modern-warfare-ii-xbox-one', 'Call of Duty: Modern Warfare II', 'Call of Duty', '2022-10-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3cwt.jpg', 'Call of Duty: Modern Warfare 2 is a first-person shooter video game developed by Infinity Ward and published by Activision for the Xbox 360 and PlayStation 3 video game consoles and the Microsoft Windows operating system. Officially announced on February 11, 2009, the game was released worldwide on November 10, 2009. It is the sixth installment of the Call of Duty series and the direct sequel to Call of Duty 4: Modern Warfare, continuing the same storyline, with Call of Duty: Modern Warfare 3 set to end the storyline.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-modern-warfare-iii-xbox-one', 'Call of Duty: Modern Warfare III', 'Call of Duty', '2023-11-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7ctx.jpg', 'The game brings "open combat, " offering players more choices in approaching the single-player missions. Makarov returns as the chief villain of the new campaign.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('call-of-duty-black-ops-6-xbox-one', 'Call of Duty: Black Ops 6', 'Call of Duty', '2024-10-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zis.jpg', 'Developed by Treyarch and Raven, Black Ops 6 is a spy action thriller set in the early 90s, a period of transition and upheaval in global politics, characterized by the end of the Cold War and the rise of the United States as a single superpower. With a mind-bending narrative, and unbound by the rules of engagement, this is signature Black Ops.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-advance-collection-xbox-one', 'Castlevania Advance Collection', 'Castlevania', '2021-09-23', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xj.jpg', 'Castlevania Advance Collection includes three legendary Castlevania games that were first released in the early 2000s: Circle of the Moon, Aria of Sorrow, and Harmony of Dissonance. In addition, this collection also includes Castlevania: Dracula X and some never-before-seen sketches and artwork from the games!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sid-meier-s-civilization-vi-xbox-one', 'Sid Meier''s Civilization VI', 'Civilization', '2019-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaaqr.jpg', 'Civilization is a turn-based strategy game in which you attempt to build an empire to stand the test of time. Become Ruler of the World by establishing and leading a civilization from the Stone Age to the Information Age. Wage war, conduct diplomacy, advance your culture, and go head-to-head with history’s greatest leaders as you attempt to build the greatest civilization the world has ever known.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-rogue-corps-xbox-one', 'Contra: Rogue Corps', 'Contra', '2019-09-24', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lzz.jpg', 'CONTRA: ROGUE CORPS is a twin stick, third-person action game drawing upon its roots in fast and focused combat developed for the Xbox One, PlayStation 4, Nintendo Switch, and PC (STEAM). From the director of CONTRA III: THE ALIEN WARS and CONTRA: HARD CORPS, Nobuya Nakazato instills more than 25 years of franchise pedigree into CONTRA: ROGUE CORPS with enormous crazed enemies, over-the-top violence, and a cast of diverse playable characters that add to the irreverent tone of the game.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('contra-operation-galuga-xbox-one', 'Contra: Operation Galuga', 'Contra', '2024-03-12', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co72z7.jpg', 'The legendary Contra series is back! Contra: Operation Galuga is a modern reimagining of the classic run-‘n’-gun action game from the ’80s, featuring modern graphics and sound. Encounter new stages, new play mechanics, an updated weapons system and explosive co-op combat for up to two players in Story Mode or four players in Arcade Mode.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-xbox-one', 'Control', 'Control', '2019-08-27', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob5pu.jpg', 'Explore a vast universe with pulse-pounding action, side-splitting humor, and hair-raising plot twists in these 2 classic space adventure games.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-ultimate-edition-xbox-one', 'Control: Ultimate Edition', 'Control', '2020-09-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ewb.jpg', 'Control Ultimate Edition contains the main game and all previously released Expansions ("The Foundation" and "AWE") in one great value package. Winner of over 80 awards, Control is a visually stunning third-person action-adventure that will keep you on the edge of your seat.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crackdown-3-xbox-one', 'Crackdown 3', 'Crackdown', '2019-02-15', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2388.jpg', 'Stop crime as a super-powered Agent of justice in Crackdown 3''s hyper-powered sandbox of mayhem and destruction. Explore the heights of a futuristic city, race through the streets in a transforming vehicle, and use your powerful abilities to stop a ruthless criminal empire. Developed by original creator Dave Jones, Crackdown 3 delivers cooperative mayhem and an all-new multiplayer mode where destruction is your ultimate weapon.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-n-sane-trilogy-xbox-one', 'Crash Bandicoot N. Sane Trilogy', 'Crash Bandicoot', '2018-06-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v62.jpg', 'Crash Bandicoot N. Sane Trilogy is a remastered version, of the original 3 games (Crash Bandicoot, Crash Bandicoot 2: Cortex Strikes Back, and Crash Bandicoot 3: Warped) with enhanced features applied to each game.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-racing-nitro-fueled-xbox-one', 'Crash Team Racing Nitro-Fueled', 'Crash Bandicoot', '2019-06-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2p89.jpg', 'This compilation contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-bandicoot-4-it-s-about-time-xbox-one', 'Crash Bandicoot 4: It''s About Time', 'Crash Bandicoot', '2020-10-02', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hp4.jpg', 'Crash Bandicoot 4: It''s About Time is the eighth Crash Bandicoot series game, though the fourth chronologically. The game retains the series'' core platforming gameplay and adds new elements through the use of the Quantum Masks, who can alter levels and provide means to traverse or overcome obstacles. It also includes additional game modes for replaying levels, and the ability to control five characters, three of whom – Cortex, Dingodile, and Tawna – have their own unique gameplay and levels.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crash-team-rumble-xbox-one', 'Crash Team Rumble', 'Crash Bandicoot', '2023-06-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7lzv.jpg', 'Crash Team Rumble is a promotional tie-in game by McDonald''s made as a part of their Crash Team Rumble Happy Meal campaign.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('crysis-remastered-trilogy-xbox-one', 'Crysis Remastered Trilogy', 'Crysis', '2021-10-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wsr.jpg', 'The classic first person shooter from Crytek is back with the action-packed gameplay, sandbox world, and thrilling epic battles you loved the first time around – now with remastered graphics optimized for a new generation of hardware.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('cuphead-xbox-one', 'Cuphead', NULL, '2017-09-29', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co62ao.jpg', 'Cuphead is a classic run and gun action game heavily focused on boss battles. Inspired by cartoons of the 1930s, the visuals and audio are painstakingly created with the same techniques of the era, i.e. traditional cel animation (hand drawn & hand inked!), watercolor backgrounds, and original jazz recordings. Play as Cuphead or Mugman (in single player or co-op) as you traverse strange worlds, acquire new weapons, learn powerful super moves, and discover hidden secrets. Cuphead is all action, all the time.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-ii-scholar-of-the-first-sin-xbox-one', 'Dark Souls II: Scholar of the First Sin', 'Dark Souls', '2015-04-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobb02.jpg', 'Dark Souls II: Scholar of the First Sin is an enhanced edition of Dark Souls II, released in April 2015 by FromSoftware and Bandai Namco Entertainment. This version includes updated graphics, improved performance, and all previously released DLC expansions (Crown of the Sunken King, Crown of the Old Iron King, and Crown of the Ivory King). It also features rebalanced gameplay, new enemy placements, additional NPCs, and expanded lore,', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-iii-xbox-one', 'Dark Souls III', 'Dark Souls', '2016-04-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9ed.jpg', 'Dark Souls III is an action role-playing game developed by FromSoftware and published by Bandai Namco Entertainment. Released in March 2016, it is the fourth entry in the Souls series and the final instalment in the Dark Souls trilogy. Set in the decaying kingdom of Lothric, players take on the role of the "Ashen One," an undead warrior tasked with rekindling the First Flame to prevent the world from falling into darkness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dark-souls-remastered-xbox-one', 'Dark Souls: Remastered', 'Dark Souls', '2018-05-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobazz.jpg', 'Dark Souls Remastered is a remastered version of the original game Dark Souls. The updated version of the game features graphical enhancements, an expanded online mode, and the Artorias of the Abyss DLC.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-ii-deathinitive-edition-xbox-one', 'Darksiders II: Deathinitive Edition', 'Darksiders', '2015-10-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qql.jpg', 'A remastered version of the 2012 release, Darksiders II.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-warmastered-edition-xbox-one', 'Darksiders: Warmastered Edition', 'Darksiders', '2016-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24hi.jpg', 'Deceived by the forces of evil into prematurely bringing about the end of the world, War – the first Horseman of the Apocalypse – stands accused of breaking the sacred law by inciting a war between Heaven and Hell. In the slaughter that ensued, the demonic forces defeated the heavenly hosts and laid claim to the Earth.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-iii-xbox-one', 'Darksiders III', 'Darksiders', '2018-11-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1qqk.jpg', 'Return to an apocalyptic planet Earth in Darksiders III, a hack-n-slash action adventure where players take on the role of FURY in her quest to hunt down and dispose of the Seven Deadly Sins. The Charred Council calls upon Fury to battle from the heights of heaven down through the depths of hell in a quest to restore humanity and prove that she is the most powerful of the Horsemen. As a mage, FURY relies on her whip and magic to restore the balance between good and evil. The expansive, Darksiders III game world is presented as an open-ended, living, free-form planet Earth that is dilapidated by war and decay, and overrun by nature. FURY will move back and forth between environments to uncover secrets while advancing the Darksiders III story.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('darksiders-genesis-xbox-one', 'Darksiders Genesis', 'Darksiders', '2020-02-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1f.jpg', 'In this Action RPG spin-off, the fourth Horseman of the Apocalypse Strife is called upon to save humankind from certain destruction at the hands of Lucifer. True to its roots, Darksiders Genesis will feature intense combat, exploration, puzzle-solving, epic boss battles and serpent holes from heaven to hell. The game marks the first, full-scale Darksiders adventure played from the top-down perspective.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('day-of-the-tentacle-remastered-xbox-one', 'Day of the Tentacle Remastered', 'Day of the Tentacle', '2020-10-29', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2865.jpg', 'Originally released by LucasArts in 1993 as a sequel to Ron Gilbert’s ground breaking Maniac Mansion, Day of the Tentacle is a mind-bending, time travel, cartoon puzzle adventure game in which three unlikely friends work together to prevent an evil mutated purple tentacle from taking over the world!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-wolf-among-us-xbox-one', 'The Wolf Among Us', 'DC', '2014-11-04', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vdk.jpg', 'The fifth episode of The Wolf Among Us, a five-episode series based on Fables (DC Comics/Vertigo).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-arkham-knight-xbox-one', 'Batman: Arkham Knight', 'DC', '2015-06-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fx3.jpg', 'This addon inlcudes a Batman costume inspired by the 2008 movie ‘The Dark Knight’.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-telltale-series-xbox-one', 'Batman: The Telltale Series', 'DC', '2016-08-02', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u65.jpg', 'Batman: The Telltale Series is an episodic graphic adventure game developed by Telltale Games, first released in 2016. The game offers a narrative-focused experience, where players control Bruce Wayne and his alter ego, Batman, making choices that shape the story and relationships with characters.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-return-to-arkham-xbox-one', 'Batman: Return to Arkham', 'DC', '2016-10-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dhj.jpg', 'Batman: Return to Arkham sees the combination of two classic entries in the Batman: Arkham series make a return to modern consoles (PS4 and Xbox One) with improved graphics. Warner Bros. is remastering 2009’s Batman: Arkham Asylum and 2011’s Batman: Arkham City which will release in this collection package along with all of the associated DLC.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('injustice-2-xbox-one', 'Injustice 2', 'DC', '2017-05-16', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xym.jpg', 'Power up and build the ultimate version of your favorite DC legends in INJUSTICE 2. With a massive selection of DC Super Heroes and Super-Villains, INJUSTICE 2 allows you to equip every iconic character with unique and powerful gear earned throughout the game. Experience an unprecedented level of control over how your favorite characters look, how they fight, and how they develop across a huge variety of game modes. This is your super Hero. Your Journey. Your Injustice.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('batman-the-enemy-within-xbox-one', 'Batman: The Enemy Within', 'DC', '2017-08-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co208l.jpg', 'In this latest chapter, both Bruce Wayne and Batman will be forced into precarious new roles. The Riddler has returned to terrorize Gotham City, but his gruesome puzzles merely foreshadow an even greater crisis. With the arrival of a ruthless federal agent and the return of a still nascent Joker, Batman must navigate uneasy alliances while Bruce Wayne undertakes a perilous series of deceptions. Which of Batman''s new allies will you choose to trust? And how deep into the darkness will you let Bruce descend?', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-3-xbox-one', 'Dead Rising 3', 'Dead Rising', '2013-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2pvc.jpg', 'Available exclusively for Xbox One and Windows, Dead Rising 3 marks the return of one of the most popular zombie video game franchises. Set 10 years after the events of Fortune City in Dead Rising 2, players are introduced to Nick Ramos, a young mechanic with a strange tattoo and a mysterious past, who must find a way to escape a city full of zombies before an impending military strike wipes the city of Los Perdidos, California, and everyone in it, off the map. Nick can’t do it alone – he must join up with other survivors to stay alive. They must fight their way out before it’s too late.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-xbox-one', 'Dead Rising', 'Dead Rising', '2016-09-13', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzo.jpg', 'It’s the holiday season in Willamette, Colorado and a mysterious outbreak has overrun the Willamette Memorial Megaplex Mall and surrounding town with dangerous and deadly predators. Join Frank West as you explore a vast, open world sandbox filled with dangerous new zombies and a million ways to kill them as you seek to uncover the truth behind the outbreak – or die trying.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-2-xbox-one', 'Dead Rising 2', 'Dead Rising', '2016-09-13', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzw.jpg', 'As Chuck Greene, you have 72 hours to save your infected daughter, clear your name and survive the hordes of hungry zombies before the military comes in and nukes the city. To ensure your survival, you can combine everyday objects to create numerous deadly combo weapons and slaughter the ravenous zombies. Dead Rising 2, it’s where Creativity Kills.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dead-rising-4-xbox-one', 'Dead Rising 4', 'Dead Rising', '2016-12-06', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gzo.jpg', 'It’s the holiday season in Willamette, Colorado and a mysterious outbreak has overrun the Willamette Memorial Megaplex Mall and surrounding town with dangerous and deadly predators. Join Frank West as you explore a vast, open world sandbox filled with dangerous new zombies and a million ways to kill them as you seek to uncover the truth behind the outbreak – or die trying.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-xbox-one', 'Destiny', 'Destiny', '2014-09-09', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('destiny-2-xbox-one', 'Destiny 2', 'Destiny', '2017-09-06', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9v5i.jpg', 'Heroes both old and new must battle against a foe threatening to upend life as they know it. The sequel to Fire Emblem: Bound Destiny takes the series in a bold new direction, featuring tighter and more responsive gameplay. Now more than ever, the lives of the party are in your hands.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deus-ex-mankind-divided-xbox-one', 'Deus Ex: Mankind Divided', 'Deus Ex', '2016-08-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25jt.jpg', 'Deus Ex: Mankind Divided directly follows the aftermath of the Aug Incident, a day when mechanically augmented citizens all over the world were stripped of control over their minds and bodies, resulting in the deaths of millions of innocents. The year is now 2029, and the golden era of augmentations is over. Mechanically augmented humans have been deemed outcasts and segregated from the rest of society. Crime and acts of terror serve as a thin veil to cover up an overarching conspiracy aimed at controlling the future of mankind…', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dmc-definitive-edition-xbox-one', 'DmC: Definitive Edition', 'Devil May Cry', '2015-03-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1u6x.jpg', 'DmC: Devil May Cry - Definitive Edition includes all the stylish action gameplay from the original release, all previously released downloadable content, including the Vergil''s Downfall campaign plus brand new modes and additional content, making this the ultimate offering for Devil May Cry fans. Maximizing the potential of next-gen hardware, the game''s high quality production values will run at a stunning 1080p and smooth 60 fps across PlayStation 4 and Xbox One.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-hd-collection-xbox-one', 'Devil May Cry HD Collection', 'Devil May Cry', '2018-03-13', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n18.jpg', 'Devil May Cry HD Collection is a collection of high-definition remasters of the PS2 games of the first three games in the Devil May Cry franchise. In addition to the reworked graphics, it also contains trophies/achievements.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-5-xbox-one', 'Devil May Cry 5', 'Devil May Cry', '2019-03-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coawk9.jpg', 'The ultimate Devil Hunter is back in style, in the game action fans have been waiting for. Includes Playable Character: Vergil content (also available separately).
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-ultimate-evil-edition-xbox-one', 'Diablo III: Ultimate Evil Edition', 'Diablo', '2014-08-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3irp.jpg', 'Diablo III: Ultimate Evil Edition includes the expansion pack Reaper of Souls and features special four-player co-op features. With the wireless controller and a custom-designed console interface, players will be outfitted with touch pad functionality and new social features as they engage in pulse-pounding combat with hordes of monsters and acquire items of incredible power.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('diablo-iii-eternal-collection-xbox-one', 'Diablo III: Eternal Collection', 'Diablo', '2018-06-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dha.jpg', 'Generations of gamers have battled the demonic hordes of Diablo, and now it’s your turn to take part in the action-RPG legacy. This Eternal Collection features Diablo III, the Reaper of Souls expansion set and the Rise of the Necromancer pack—all together in one definitive volume. Prepare yourself, mortal hero. The hellgates are opening.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disco-elysium-the-final-cut-xbox-one', 'Disco Elysium: The Final Cut', 'Disco Elysium', '2021-12-09', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ve1.jpg', 'Disco Elysium: The Final Cut is an enhanced edition of the original role-playing game developed and published by ZA/UM. It retains the core gameplay and narrative while adding full voice acting, new quests, additional endings, and other narrative revisions.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-definitive-edition-xbox-one', 'Dishonored: Definitive Edition', 'Dishonored', '2015-08-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pcv.jpg', 'Arkane Studios’ 2012 Game of the Year, Dishonored, and all of its additional content - Dunwall City Trials, The Knife of Dunwall, The Brigmore Witches and Void Walker’s Arsenal – comes to PlayStation 4 and Xbox One in Dishonored: Definitive Edition! Experience Dishonored plus all of its additional content on the new console systems for the first time, complete with enhanced graphics that take full advantage of the powerful hardware of this generation.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-2-xbox-one', 'Dishonored 2', 'Dishonored', '2016-11-11', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9e29.jpg', 'Dishonored 2 is a first-person action video game and the sequel to Dishonored. It borrows many of the gameplay elements from the first opus: players define their own play style by blending action, assassination, stealth, mobility and combat. Combining tools at their disposal, players are allowed options to eliminate enemies, whether they choose to pursue them unseen or ruthlessly attack head on. Dishonored 2 features the same campaign style as its predecessor in which the protagonist must advance through a series of missions.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dishonored-death-of-the-outsider-xbox-one', 'Dishonored: Death of the Outsider', 'Dishonored', '2017-09-15', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pd2.jpg', 'Dishonored: Death of the Outsider is a standalone expansion pack and a sequel to Dishonored 2. The game features all the series hallmarks, including brutal combat systems, unique level design and immersive storytelling that responds to your every choice. With compelling characters and exhilarating action, Death of the Outsider is the perfect entry point for those new to the Dishonored series, while delivering a significant expansion of the gameplay and world for longtime fans.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-2-0-xbox-one', 'Disney Infinity 2.0', 'Disney Infinity', '2014-09-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rxo.jpg', 'In Disney Infinity (2.0 Edition) you have the freedom and endless opportunity to create stories and play experiences starring some of your favorite Marvel Super Heroes and Disney characters. Save the World or Create your Own!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('disney-infinity-3-0-xbox-one', 'Disney Infinity 3.0', 'Disney Infinity', '2015-08-30', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2sbu.jpg', 'Disney Infinity 3.0 Edition now welcomes Star Wars to the ever-growing collection of Marvel, Disney and Disney•Pixar characters, stories and worlds. Together new heroes can join forces with characters from previous editions and embark on adventures as big as your imagination in the 3.0 Toy Box!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-xbox-one', 'Doom', 'Doom', '2016-05-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6wn4.jpg', 'Celebrate Doom''s 25th anniversary with the re-release of Doom II. This beloved sequel to the groundbreaking Doom (1993) gave players the brutal Super Shotgun to bear against deadlier demons, and the infamous boss, the Icon of Sin.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-eternal-xbox-one', 'Doom Eternal', 'Doom', '2020-03-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3p5n.jpg', 'Hell’s armies have invaded Earth. Become the Slayer in an epic single-player campaign to conquer demons across dimensions and stop the final destruction of humanity. The only thing they fear... is you.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-64-xbox-one', 'Doom 64', 'Doom', '2020-03-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qmz.jpg', 'Fight against demons in your crusade to hunt down the Mother of Demons and stop Hell''s invasion. As the player battle through more than 30 action-packed levels, they have to be on the lookout for enhanced weapons and secrets to help them put an end to the demonic threat.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-slayers-collection-xbox-one', 'Doom: Slayers Collection', 'Doom', '2020-08-04', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2kdb.jpg', 'The Doom Slayers Collection takes players through more than two decades of demon slaying – from the classic games that popularized the first-person shooter to the fan favorite franchise reboot, wield an arsenal of powerful weapons as you battle demon hordes on Mars, on Earth, and across Hell in four critically acclaimed games: Doom, Doom II, Doom 3, and Doom (2016).', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('doom-doom-ii-xbox-one', 'Doom + Doom II', 'Doom', '2025-05-18', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6w0l.jpg', 'Doom II was included in Doom 3 Collector''s Edition for the Xbox, which was released in 2005. This port includes an exclusive level, "Betray". It featured multiplayer like the PC version, however not through Xbox Live. This port was programmed by Vicarious Visions. The Xbox version of Doom 3: Resurrection of Evil also contains this same port, as well as Master Levels for Doom II.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-inquisition-xbox-one', 'Dragon Age: Inquisition', 'Dragon Age', '2014-11-18', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2mvy.jpg', 'Dragon Age: Inquisition is a role-playing game and the third main game in the Dragon Age series. It is set in the Thedas continent, the same fantasy world as the two previous games. It consist of two large countries: Ferelden (from Dragon Age: Origins) and Orlais, as well as the land inbetween.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-quest-xi-s-echoes-of-an-elusive-age-definitive-edition-xbox-one', 'Dragon Quest XI S: Echoes of an Elusive Age - Definitive Edition', 'Dragon Quest', '2020-12-04', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1x9f.jpg', 'The Definitive Edition includes all the content from the original release of the acclaimed DRAGON QUEST XI, and adds extra character-specific scenarios, the choice of playing with the original soundtrack or a grand orchestral version of the music, the ability to switch between 2D and 3D graphic modes, a Japanese voice-acting option, and much more.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('elden-ring-xbox-one', 'Elden Ring', NULL, '2022-02-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co95gk.jpg', 'Elden Ring: Nightreign is a standalone adventure within the ELDEN RING universe, crafted to offer players a new gaming experience by reimagining the game’s core design.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-online-tamriel-unlimited-xbox-one', 'The Elder Scrolls Online: Tamriel Unlimited', 'The Elder Scrolls', '2015-06-09', 'Xbox One', 1, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-online-gold-edition-xbox-one', 'The Elder Scrolls Online: Gold Edition', 'The Elder Scrolls', '2016-09-09', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fm8.jpg', 'The award-winning fantasy role-playing series, The Elder Scrolls, goes online. Experience the world of Tamriel on your own, or together with friends, guild mates, and thousands of other players.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-elder-scrolls-v-skyrim-special-edition-xbox-one', 'The Elder Scrolls V: Skyrim – Special Edition', 'The Elder Scrolls', '2016-10-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vco.jpg', 'Skyrim special edition is a remaster of the classic from 2011. Now with upgraded visuals.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-xbox-one', 'The Evil Within', 'The Evil Within', '2014-10-14', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgs.jpg', 'The Evil Within embodies the meaning of pure survival horror. Highly-crafted environments, horrifying anxiety, and an intricate story are combined to create an immersive world that will bring you to the height of tension. With limited resources at your disposal, you’ll fight for survival and experience profound fear in this perfect blend of horror and action.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-evil-within-2-xbox-one', 'The Evil Within 2', 'The Evil Within', '2017-10-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgu.jpg', 'The Evil Within 2 is the latest evolution of survival horror. Detective Sebastian Castellanos has lost it all. But when given a chance to save his daughter, he must descend once more into the nightmarish world of STEM.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-4-xbox-one', 'Fallout 4', 'Fallout', '2015-11-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yc6.jpg', 'Bethesda Game Studios welcome you to the world of Fallout 4, their most ambitious game ever, and the next generation of open-world gaming. As the sole survivor of Vault 111, you enter a world destroyed by nuclear war. Every second is a fight for survival, and every choice is yours. Only you can rebuild and determine the fate of the Wasteland. Welcome home.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('fallout-76-xbox-one', 'Fallout 76', 'Fallout', '2018-11-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yc4.jpg', 'Bethesda Game Studios welcome you to Fallout 76. Twenty-five years after the bombs fall you and your fellow Vault Dwellers, chosen from the nation’s best and brightest, emerge into post-nuclear America on Reclamation Day, 2102. Play solo or join together as you explore, quest, build, and triumph against the wasteland’s greatest threats. Explore a vast wasteland, devastated by nuclear war, in this open-world multiplayer addition to the Fallout story. Experience the largest, most dynamic world ever created in the legendary Fallout universe.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-4-xbox-one', 'Far Cry 4', 'Far Cry', '2014-11-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ke6.jpg', 'Dive into the savage universe of Far Cry with this double-pack edition featuring both Far Cry 4 and Far Cry: Primal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-primal-xbox-one', 'Far Cry Primal', 'Far Cry', '2016-02-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28ha.jpg', 'Gamers play as TAKKAR, a seasoned hunter and the last surviving member of his hunting group. Arriving in the majestic and savage land of Oros, players will pursue one single goal; survive in a world where humans are the prey. They will meet a cast of memorable characters who will help them push back and tame the dangers of the wild.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-5-xbox-one', 'Far Cry 5', 'Far Cry', '2018-03-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6qsa.jpg', 'It''s time to defend Hope County with this bundle featuring both Far Cry 5 and Far Cry New Dawn
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-classic-edition-xbox-one', 'Far Cry 3 Classic Edition', 'Far Cry', '2018-06-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2nkb.jpg', 'Far Cry 3 Classic Edition has been updated to run smoothly on modern platforms and allow fans and newcomers to experience the single-player Far Cry 3 campaign in stunning detail.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-new-dawn-xbox-one', 'Far Cry New Dawn', 'Far Cry', '2019-02-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpg.jpg', 'Dive into a transformed vibrant post-apocalyptic Hope County, Montana, 17 years after a global nuclear catastrophe. Lead the fight against the Highwaymen, as they seek to take over the last remaining resources.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-6-xbox-one', 'Far Cry 6', 'Far Cry', '2021-10-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2npg.jpg', 'Dive into the gritty world of a modern-day guerrilla revolution to liberate a nation from its oppressive dictators. Welcome to Yara, a tropical paradise frozen in time. Far Cry 6 thrusts players into a modern-day guerrilla revolution. As dictator of Yara, Anton Castillo is intent on restoring his nation back to its former glory by any means, with his son, Diego, following in his bloody footsteps. Become a guerrilla fighter and liberate Yara.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('far-cry-3-blood-dragon-xbox-one', 'Far Cry 3: Blood Dragon', 'Far Cry', '2021-12-16', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vpp.jpg', 'There’s only one force powerful enough to stop an army of rampaging killer cyborgs, mutated scientists, metal sharks and vicious Blood Dragons that shoot lasers from their eyes – that force is you. Your name is Sergeant Rex Power Colt, a Mark IV Cyber Commando. Lock and load as you and your seven favorite fully customizable killing implements tackle a bizarre open world island crawling with evil. Take down the enemy with ninja stars, guns or even just good old explosives. Your battle. Your way. Their tough luck.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-type-0-hd-xbox-one', 'Final Fantasy Type-0 HD', 'Final Fantasy', '2015-03-17', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9er5.jpg', 'Final Fantasy Type-0 HD is a high-definition remaster of the Japan-exclusive PlayStation Portable game Final Fantasy Type-0.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xv-xbox-one', 'Final Fantasy XV', 'Final Fantasy', '2016-11-29', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nz1.jpg', 'Play as Noctis, the Crown Prince of the Kingdom of Lucis, as you seek to reclaim your homeland from the imperial army. With your closest friends along for the ride, you’ll travel through the breath-taking world of Eos, encountering larger-than-life beasts and unforgiving enemies. Face thrilling combat as you learn to master your weaponry and magic skills by channeling the power of your ancestors.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-of-final-fantasy-xbox-one', 'World of Final Fantasy', 'Final Fantasy', '2018-11-06', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24k0.jpg', 'World of Final Fantasy combines classic RPG gameplay mechanics with fresh and imaginative toy-like visuals. As a brand-new title in the Final Fantasy franchise, this game can be enjoyed by both fans and newcomers to the series. Players will lead a pair of twins through varied Final Fantasy worlds and encounter the adorably familiar monsters therein. Capture and raise such familiar beasts as cactuar, chocobo, and behemoth to discover alternate forms and learn new abilities.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-x-x-2-hd-remaster-xbox-one', 'Final Fantasy X/X-2 HD Remaster', 'Final Fantasy', '2019-04-16', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zpl.jpg', 'Based on the international versions of the games that were previously only released in Japan and Europe, FINAL FANTASY X/X-2 HD Remaster brings these timeless classics forward to the current generation of fans, old and new alike.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('final-fantasy-xii-the-zodiac-age-xbox-one', 'Final Fantasy XII: The Zodiac Age', 'Final Fantasy', '2019-04-30', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g6o.jpg', '"FINAL FANTASY XII THE ZODIAC AGE improves upon the 2006 classic FINAL FANTASY XII, now more beautiful and easier to play than ever. The high-definition remaster introduces several modern advancements, including reconstructed battle design and a revamped job system. With newly implemented trophies and share functions, as well as stark visual and sound improvements in true HD for the first time, players both returning and new to the game will experience a grand adventure that spans the world of Ivalice in an entirely fresh and improved way.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('five-nights-at-freddy-s-core-collection-xbox-one', 'Five Nights at Freddy''s: Core Collection', 'Five Nights at Freddy''s', '2021-01-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldz.jpg', 'Five Nights at Freddy''s: Core Collection is a physical bundle of several games in the Five Nights at Freddy''s franchise. The collection will consist of the Console Ports of Five Nights at Freddy''s 1 to 4 and Sister Location.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-forgotten-city-xbox-one', 'The Forgotten City', NULL, '2021-07-28', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3muu.jpg', 'The Forgotten City is a mystery adventure game of exploration and deduction, and a re-imagining of the critically acclaimed mod of the same name. Combat is an option, but violence will only get you so far. Only by questioning an intertwined community of colorful characters, cleverly exploiting the time loop, and making difficult moral choices can you hope to solve this epic mystery. Here, your decisions matter. The fate of the city is in your hands.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-ultimate-edition-xbox-one', 'Gears of War: Ultimate Edition', 'Gears of War', '2015-08-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co246i.jpg', 'Gears of War: Ultimate Edition is a remaster of the original Gears of War game developed by The Coalition and Splash Damage and published by Microsoft Studios for Microsoft''s Xbox One console and Windows 10 operating system.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-of-war-4-xbox-one', 'Gears of War 4', 'Gears of War', '2016-10-11', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2y29.jpg', 'A new saga begins for one of the most acclaimed video game franchises in history. After narrowly escaping an attack on their village, JD Fenix and his friends, Kait and Del, must rescue the ones they love and discover the source of a monstrous new enemy.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-5-xbox-one', 'Gears 5', 'Gears of War', '2019-09-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oz5.jpg', 'From one of gaming’s most acclaimed sagas, Gears is bigger than ever, with five thrilling modes and the deepest campaign yet. With all-out war descending, Kait Diaz breaks away to uncover her connection to the enemy and discovers the true danger to Sera – herself.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gears-tactics-xbox-one', 'Gears Tactics', 'Gears of War', '2020-11-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uzk.jpg', 'Gears Tactics is the fast-paced, turn-based strategy game from one of the most-acclaimed video game franchises – Gears of War. Outnumbered and fighting for survival, recruit and command your squad to hunt down an evil mastermind who makes monsters.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-xbox-one', 'Grand Theft Auto V', 'Grand Theft Auto', '2014-11-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-the-trilogy-xbox-one', 'Grand Theft Auto: The Trilogy', 'Grand Theft Auto', '2021-12-20', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ms5.jpg', 'A bundle that contains the original trilogy from one of the most popular and critically acclaimed franchises in entertainment history.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grand-theft-auto-v-xbox-one-2', 'Grand Theft Auto V', 'Grand Theft Auto', '2022-03-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9751.jpg', 'This bundle contains the original version of Grand Theft Auto V, the standalone game Grand Theft Auto Online and the story mode add-on of Grand Theft Auto V.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grim-fandango-remastered-xbox-one', 'Grim Fandango Remastered', 'Grim Fandango', '2020-10-29', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27pj.jpg', 'Something''s rotten in the land of the dead, and you''re being played for a sucker. Meet Manny Calavera, travel agent at the Department of Death. He sells luxury packages to souls on their four-year journey to eternal rest. But there''s trouble in paradise. Help Manny untangle himself from a conspiracy that threatens his very salvation.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('grounded-fully-yoked-edition-xbox-one', 'Grounded Fully Yoked Edition', 'Grounded', '2022-09-27', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co835s.jpg', 'The free 1.4 "Fully Yoked" content update for all players introduces royal Ant Queens, a New Game+ mode, full Japanese VO, and an exciting array of new weapons, armor, and more. Additional content includes new molars, infused bugs, the ability to upgrade gear past level 9, four new achievements, one new mutation, twelve Ant Queen-related buildings, new baby ant pets, and other gameplay additions. Beginning with this update, hosts can now load a save while in the middle of a multiplayer session and all connected players will seamlessly transition into the new game world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hades-xbox-one', 'Hades', NULL, '2021-08-13', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4rs3.jpg', 'A South Korean-made first person shooter (potentially the first ever from that country).', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-the-master-chief-collection-xbox-one', 'Halo: The Master Chief Collection', 'Halo', '2014-11-11', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t95.jpg', 'The improved and enhanced Halo: The Master Chief Collection features visual enhancements with up to 4K UHD resolution, improved matchmaking, offline LAN, customizable installation options, and faster load times, it’s the definitive way to experience the ultimate Halo saga. Includes the extensive suite of campaign, multiplayer and additional features from Halo: Combat Evolved Anniversary, Halo 2: Anniversary, Halo 3, and Halo 4 - all updated to run at 60FPS.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-5-guardians-xbox-one', 'Halo 5: Guardians', 'Halo', '2015-10-27', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1xhg.jpg', 'Halo 5: Guardians delivers epic multiplayer experiences that span multiple modes, full-featured level building tools, and another chapter in the Master Chief saga. The Master Chief saga continues, with solo and up to 4-player cooperative experience that spans three worlds. A mysterious and unstoppable force threatens the galaxy. The Spartans of Fireteam Osiris and Blue Team must embark on a journey that will change the course of history and the future of mankind.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-wars-2-xbox-one', 'Halo Wars 2', 'Halo', '2017-02-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2807.jpg', 'After decades adrift and declared “lost with all hands,” the brave crew of the UNSC Spirit of Fire are mysteriously awoken above an ancient Forerunner haven known as the Ark. In Halo Wars 2, Captain Cutter and his crew will face one of humanity’s most formidable threats yet: The Banished – a fierce and powerful Brute faction led by a cunning and lethal warrior known as Atriox.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('halo-infinite-xbox-one', 'Halo Infinite', 'Halo', '2021-12-08', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dto.jpg', 'The Master Chief returns in Halo Infinite – the next chapter of the legendary franchise. When all hope is lost and humanity’s fate hangs in the balance, the Master Chief is ready to confront the most ruthless foe he’s ever faced. Step inside the armor of humanity’s greatest hero to experience an epic adventure and explore the massive scale of the Halo ring.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('hellblade-senua-s-sacrifice-xbox-one', 'Hellblade: Senua''s Sacrifice', 'Hellblade', '2018-12-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2l7l.jpg', 'From the makers of Heavenly Sword, Enslaved: Odyssey to the West, and DmC: Devil May Cry, comes a warrior’s brutal journey into myth and madness.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('humanity-xbox-one', 'Humanity', NULL, '2024-05-30', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co58ju.jpg', 'Human Error: Episode One tells the story of a civil protection officer called Anders fighting Vortigaunts, Alien Grunts, and Alien Controllers using the Combine''s forces as his allies.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('immortals-fenyx-rising-xbox-one', 'Immortals Fenyx Rising', NULL, '2020-12-03', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9kcb.jpg', 'From the creators of Assassin’s Creed Odyssey comes a storybook adventure about a forgotten hero on a quest to save the Greek gods.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('inside-limbo-xbox-one', 'Inside / Limbo', NULL, '2017-05-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co821u.jpg', 'A bundle containing two of Playdead''s critically acclaimed titles, Inside & Limbo.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('it-takes-two-xbox-one', 'It Takes Two', NULL, '2021-03-26', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob22v.jpg', 'Embark on the craziest journey of your life in It Takes Two, a genre-bending platform adventure created purely for co-op. Invite a friend to join for free with Friend’s Pass and work together across a huge variety of gleefully disruptive gameplay challenges. Play as the clashing couple Cody and May, two humans turned into dolls by a magic spell. Together, trapped in a fantastical world where the unpredictable hides around every corner, they are reluctantly challenged with saving their fractured relationship.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-jackbox-party-pack-xbox-one', 'The Jackbox Party Pack', NULL, '2015-11-03', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4zel.jpg', 'The team behind "You Don''t Know Jack" presents five guffaw-inducing party games in one pack! You''re gonna need more than one party for this. Your phones or tablets are your controllers! For 1-100 players! Games include:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('journey-to-the-savage-planet-xbox-one', 'Journey to the Savage Planet', NULL, '2020-01-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1pkf.jpg', 'Onward To Adventure
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('katamari-damacy-reroll-xbox-one', 'Katamari Damacy Reroll', 'Katamari', '2020-11-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co25sm.jpg', 'When the King of All Cosmos accidentally destroys all the stars in the sky, he orders you, his pint-sized princely son, to put the twinkle back in the heavens above. Join the King and Prince of Cosmos on their wacky adventure to restore the stars at home or on the go – now in full HD!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kaze-and-the-wild-masks-xbox-one', 'Kaze and the Wild Masks', NULL, '2021-05-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1t98.jpg', 'Go on a journey as Kaze in this 90’s classics inspired platformer. When the Crystal Islands get cursed, Kaze needs to save her friend Hogo while facing enraged living vegetables. Find the Wild Masks to unleash the powers of the legendary guardians and master land, sky and sea.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kinect-sports-rivals-xbox-one', 'Kinect Sports Rivals', 'Kinect Sports', '2014-04-08', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22rt.jpg', 'Kinect Sports Rivals is the next generation of the best-selling Kinect franchise, Kinect Sports, that brings your favorite sports back in re-imagined ways, and delivers new sports and events made possible with Xbox One’s revolutionary technology. Kinect Sports Rivals puts you in the game like never before, tracks your movements and expressions with incredible accuracy, and offers never-ending competition with your friends and rivals.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-iii-xbox-one', 'Kingdom Hearts III', 'Kingdom Hearts', '2019-01-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1tpy.jpg', 'Kingdom Hearts III is the third main installment in the Kingdom Hearts series developed and published by Square Enix. It was initially released January 2019 for the PlayStation 4 and the Xbox One. An expansion, Kingdom Hearts III Re Mind was released in January 2020.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kingdom-hearts-melody-of-memory-xbox-one', 'Kingdom Hearts: Melody of Memory', 'Kingdom Hearts', '2020-11-13', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gk9.jpg', 'Kingdom Hearts: Melody of Memory is a rhythm action game developed and published by Square Enix for the PlayStation 4, Xbox One, and Nintendo Switch. It is the fourteenth installment in the Kingdom Hearts series. The game features over 140 songs from the series and the ability to play as over 20 characters. Additionally, Kairi''s story is continued from the end of the Kingdom Hearts III Re Mind downloadable content.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('l-a-noire-xbox-one', 'L.A. Noire', 'L.A. Noire', '2017-11-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ldn.jpg', 'L.A. Noire is a neo-noir detective action-adventure video game developed by Team Bondi and published by Rockstar Games. It was initially released for the PlayStation 3 and Xbox 360 platforms on 17 May 2011; a Microsoft Windows port was later released on 8 November 2011.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-xbox-one', 'Lego Marvel Super Heroes', 'Lego', '2013-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5bze.jpg', 'Lego Marvel Super Heroes is a 2013 Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. The game features gameplay similar to other Lego titles, alternating between various action-adventure sequences and puzzle-solving scenarios.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-videogame-xbox-one', 'The Lego Movie Videogame', 'Lego', '2014-02-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kpj.jpg', 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business'' evil plans - a mission that Emmet is hopelessly and hilariously unprepared for. It''s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare, Cleopatra and more.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-hobbit-xbox-one', 'Lego The Hobbit', 'Lego', '2014-04-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20po.jpg', 'Reclaim the Lost Kingdom brick by brick! Join Bilbo Baggins, Gandalf, Thorin and his company of Dwarves in an epic adventure across Middle-earth to recapture the Lonely Mountain in the most expansive LEGO game to date. Battle ravenous Trolls, dangerous Orcs and many more. Combine the Dwarves'' unique abilities to solve puzzles - often with hilarious results! Explore iconic locations in Middle-earth, from the Shire to Goblin-town and beyond.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-batman-3-beyond-gotham-xbox-one', 'Lego Batman 3: Beyond Gotham', 'Lego', '2014-11-11', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9wob.jpg', 'The portable Lego Batman 3 adventure feature freeflow combat new to the seires and bite sized levels.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-jurassic-world-xbox-one', 'Lego Jurassic World', 'Lego', '2015-06-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1mws.jpg', 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as Jurassic World, LEGO Jurassic World is the first videogame where players will be able to relive and experience all four Jurassic films.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dimensions-xbox-one', 'Lego Dimensions', 'Lego', '2015-09-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3w4t.jpg', 'Help stop crime in the Lego Dimensions multiverse with Lego City’s Chase McCain. Build and place Chase on the Lego Toy Pad to bring him to life in the game. Use his Lego City Detective Scanner to track down bad guys and change his disguise to unlock more abilities. Become a Miner to break Silver Lego bricks or a Fireman to use your Water Beam to put out fires. Unlock the Lego City Adventure World to explore new areas like Blackwell’s moonbase and the Lego City Police Department, and the Battle Arena to compete with up to 4 of your friends. Build Chase’s Police Helicopter to fire off bolts, then rebuild it into the Police Hovercraft and Police Plane for additional in-game abilities.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-s-avengers-xbox-one', 'Lego Marvel''s Avengers', 'Lego', '2016-01-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2bvz.jpg', 'Lego Marvel''s Avengers is a Lego-themed action-adventure video game developed by Traveller''s Tales and published by Warner Bros. Interactive Entertainment. It is the spin-off to Lego Marvel Super Heroes and the second instalment of the Lego Marvel franchise. The game is based on the Marvel Cinematic Universe.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-star-wars-the-force-awakens-xbox-one', 'Lego Star Wars: The Force Awakens', 'Lego', '2016-06-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wnc.jpg', 'LEGO Star Wars: The Force Awakens takes players deeper into the new film than any other game with all of the heroic characters from the movie, including Rey, Finn, Poe Dameron, Han Solo, Chewbacca, C-3PO, and BB-8, as well as Kylo Ren, General Hux and Captain Phasma, while also exploring iconic Star Wars locales, such as Jakku and Starkiller Base.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-worlds-xbox-one', 'Lego Worlds', 'Lego', '2017-03-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1j95.jpg', 'LEGO Worlds is an open environment of procedurally-generated Worlds made entirely of LEGO bricks which you can freely manipulate and dynamically populate with LEGO models. Create anything you can imagine one brick at a time, or use large-scale landscaping tools to create vast mountain ranges and dot your world with tropical islands. Drop in prefabricated structures to build and customize any world to your liking. Explore using helicopters, dragons, motorbikes or even gorillas and unlock treasures that enhance your gameplay. Watch your creations come to life through characters and creatures that interact with you and each other in unexpected ways. In LEGO Worlds, anything is possible!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-city-undercover-xbox-one', 'Lego City Undercover', 'Lego', '2017-04-04', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5vx0.jpg', 'As Chase McCain, you''ll become an expert at hand-to-hand combat, fighting your foes and wrestling them to the ground until you can slap the cuffs on ''em. The best officers are also pros at free running, jumping, climbing, and traversing the city on special blue and white bricks. Do you have what it takes?', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-ninjago-movie-video-game-xbox-one', 'The Lego Ninjago Movie Video Game', 'Lego', '2017-09-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co253j.jpg', 'Find your inner ninja with the all-new LEGO Ninjago Movie Video Game! Play as your favorite ninjas, Lloyd, Jay, Kai, Cole, Zane, Nya and Master Wu to defend Ninjago City from the evil Lord Garmadon and his Shark Army. Master the art of Ninja-gility by wall-running, high-jumping and battling the foes of Ninjago to rank up and upgrade the ninja’s combat skills. Only in the LEGO Ninjago Movie Video Game will you experience the film across 8 action packed locations each with its own unique Challenge Dojo. And with the Battle Maps, play against friends and family in competitions for up to four players!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-marvel-super-heroes-2-xbox-one', 'Lego Marvel Super Heroes 2', 'Lego', '2017-11-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27zc.jpg', 'Get the Deluxe Edition now and gain access to the main game and season pass content! Join your favorite Super Heroes and Super Villains from different eras and realities as they go head-to-head with the time-traveling Kang the Conqueror in the all-new, original adventure, LEGO Marvel Super Heroes 2! Play as the Guardians of the Galaxy, Spider-Man, Thor, Hulk, Black Panther, Captain Marvel, Doctor Strange, Green Goblin and dozens of other Marvel Super Heroes and Villains in this cosmic battle across the time-tossed city of Chronopolis! Travel across lands -- from Ancient Egypt to The Old West, Sakaar and New York City in 2099 -- and transport objects or characters through the centuries! And, with new battle modes, friends and family can play against each other in a series of themed challenges and battle arenas!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-the-incredibles-xbox-one', 'Lego The Incredibles', 'Lego', '2018-06-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wkq.jpg', 'LEGO The Incredibles takes players on an adventure where they’ll control their favourite Incredibles characters and team up as a family to conquer crime and family life.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-dc-super-villains-xbox-one', 'Lego DC Super-Villains', 'Lego', '2018-10-16', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26qa.jpg', 'Lego DC Super-Villains is a Lego-themed action-adventure platform video game developed by Traveller''s Tales. The fourth installment in the Lego Batman series of games, it is a spin-off that focuses entirely on villains of the DC Universe; it is the first in the series to do so since the villain levels from Lego Batman: The Videogame.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lego-harry-potter-collection-xbox-one', 'Lego Harry Potter Collection', 'Lego', '2018-10-30', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8s8o.jpg', 'The LEGO Harry Potter: Collection is an action-adventure compilation that combines LEGO Harry Potter: Years 1–4 and LEGO Harry Potter: Years 5–7 into a single experience.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-lego-movie-2-videogame-xbox-one', 'The Lego Movie 2 Videogame', 'Lego', '2019-02-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dhg.jpg', 'The alien monster invaders have left Bricksburg in ruins. It is now up to Emmet and a host of heroic characters to go beyond their world and save their friends from the strange inhabitants of the Systar System. Players can journey into outer space, discover new worlds, and test their Master Building skills.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-xbox-one', 'Life is Strange', 'Life is Strange', '2016-01-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7p.jpg', 'The long awaited sequel to the award winning Life is Strange returns with a new 5-part narrative adventure from DONTNOD Entertainment.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-before-the-storm-xbox-one', 'Life is Strange: Before The Storm', 'Life is Strange', '2018-03-06', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1twj.jpg', 'Life is Strange: Before the Storm is a new three part standalone story adventure set three years before the events of the first game. This time play as Chloe Price, a rebel who forms an unlikely friendship with Rachel Amber in dramatic new story in the BAFTA award winning franchise.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-2-xbox-one', 'Life is Strange 2', 'Life is Strange', '2020-02-04', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7p.jpg', 'The long awaited sequel to the award winning Life is Strange returns with a new 5-part narrative adventure from DONTNOD Entertainment.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('life-is-strange-true-colors-xbox-one', 'Life is Strange: True Colors', 'Life is Strange', '2021-09-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vpp.jpg', 'Life is Strange is a series of award-winning and critically-acclaimed narrative adventure games. Discover a universe where everyday heroes wield supernatural powers, while dealing with real challenges, real relationships, and real emotions. It''s our world... with a twist of the strange. No matter your choices, the experience will stay with you forever. Deep in the mountains of Colorado, you''ll find Haven Springs, a small mining town filled with beauty and mystery. As Alex, you''ll discover the shocking secrets behind your brother’s death in an emotional roller-coaster of an adventure, using your psychic power of Empathy to change fate and change lives.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-0-xbox-one', 'Yakuza 0', 'Like a Dragon', '2020-02-26', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co252x.jpg', 'Yakuza 0 is an action-adventure game developed by Ryu Ga Gotoku Studio and published by Sega. Serving as a prequel to the Yakuza series, it is set in 1988 Japan during the country''s economic bubble era. The game follows two protagonists: Kazuma Kiryu in Tokyo''s Kamurocho district and Goro Majima in Osaka''s Sotenbori district. Players alternate between their stories as they navigate the criminal underworld, engaging in street fights, managing businesses, and participating in various side activities.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-kiwami-xbox-one', 'Yakuza Kiwami', 'Like a Dragon', '2020-04-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coazbq.jpg', 'A bundle including Yakuza Kiwami and Yakuza Kiwami 2.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-kiwami-2-xbox-one', 'Yakuza Kiwami 2', 'Like a Dragon', '2020-07-30', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1qc.jpg', 'Yakuza Kiwami 2 is a remake of Yakuza 2, and is an action-adventure game set in an open world environment and played from a third-person perspective. Combat is based on that previously seen in Yakuza 6. A new "Majima Saga" story scenario features recurring series anti-hero Goro Majima as a playable character.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-like-a-dragon-xbox-one', 'Yakuza: Like a Dragon', 'Like a Dragon', '2020-11-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2em9.jpg', 'Yakuza: Like a Dragon is a role-playing game developed and published by Sega. Released in 2020, it is the eighth main entry in the Yakuza series. The game introduces a new protagonist, Ichiban Kasuga, and departs from the traditional action combat system, instead featuring turn-based combat with a party of characters. Set in the fictional city of Yokohama, the game follows Kasuga''s quest for revenge and his journey through Japan''s criminal underworld.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-3-remastered-xbox-one', 'Yakuza 3 Remastered', 'Like a Dragon', '2021-01-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co26ar.jpg', 'Yakuza 3 Remastered is an updated version of Yakuza 3, developed by Ryu Ga Gotoku Studio and published by Sega. Released as part of The Yakuza Remastered Collection in 2019, the remaster features improved graphics, a higher frame rate, and restored content that was cut from the original Western release. The game follows protagonist Kazuma Kiryu as he manages an orphanage in Okinawa while being drawn back into conflicts with the yakuza.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-4-remastered-xbox-one', 'Yakuza 4 Remastered', 'Like a Dragon', '2021-01-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s10.jpg', 'The game from 2010 has been remastered for the PS4 with one of Yakuza 4''s main protagonists, Masayoshi Tanimura, being recast and getting a visual makeover.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-5-remastered-xbox-one', 'Yakuza 5 Remastered', 'Like a Dragon', '2021-01-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s11.jpg', 'Experience the fifth chapter of the Kazuma Kiryu saga in 1080p and 60fps. Get ready for a Yakuza experience of unprecedented scale. Follow five characters across five Japanese cities, each trying to achieve their dream. The connections between them bring them together, but the conflict that unfolds is nothing any of them could have predicted.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yakuza-6-the-song-of-life-xbox-one', 'Yakuza 6: The Song of Life', 'Like a Dragon', '2021-03-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co492w.jpg', 'Step into Japan''s criminal underworld in this explosive action brawler starring legendary yakuza, Kazuma Kiryu, who is hellbent on unraveling the truth around his daughter''s tragic accident.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('lost-judgment-xbox-one', 'Lost Judgment', 'Like a Dragon', '2021-09-24', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co53ld.jpg', 'Lost Judgment is an action-adventure video game developed by Ryu Ga Gotoku Studio and published by Sega. A sequel to the 2018 game Judgment (a spin-off of the Like a Dragon series), the game focuses on private detective Takayuki Yagami as he investigates a criminal accused of both sexual harassment and murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-amazing-spider-man-2-xbox-one', 'The Amazing Spider-Man 2', 'Marvel', '2014-05-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7h9v.jpg', 'The Android and iOS port of The Amazing Spider-Man 2.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deadpool-xbox-one', 'Deadpool', 'Marvel', '2015-11-17', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4xsf.jpg', 'In Deadpool the player takes control of the loud-mouthed, foul-mouthed, merc-with-a-mouth Wade Wilson (a.k.a. Deadpool). While on out on a contract to kill a corrupt media mogul, Mister Sinister intervenes and kills him instead, drawing the ire of Deadpool who then vows revenge only to stumble upon a bigger plot which could spell the end of humanity.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ultimate-marvel-vs-capcom-3-xbox-one', 'Ultimate Marvel vs. Capcom 3', 'Marvel', '2017-03-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yej.jpg', 'Ultimate Marvel vs. Capcom 3 is a crossover fighting game developed by Capcom in collaboration with Eighting. It is an updated version of Marvel vs. Capcom 3: Fate of Two Worlds. The game features characters from both Capcom''s video game franchises and comic book series published by Marvel Comics. The game was released in November 2011 for the PlayStation 3 and Xbox 360, and was featured as a launch title for the PlayStation Vita in 2012.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('guardians-of-the-galaxy-the-telltale-series-xbox-one', 'Guardians of the Galaxy: The Telltale Series', 'Marvel', '2017-04-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27yt.jpg', 'Marvel''s Guardians of the Galaxy: The Telltale Series is a brand new story of the universe''s unlikeliest heroes: Star-Lord, Gamora, Drax, Rocket, and Groot. In the wake of an epic battle, the Guardians discover an artifact of unspeakable power. Each of them has a reason to desire this relic, as does a ruthless enemy who is the last of her kind, and who will stop at nothing to tear it from their hands.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-vs-capcom-infinite-xbox-one', 'Marvel vs. Capcom: Infinite', 'Marvel', '2017-09-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wqa.jpg', 'Marvel vs. Capcom: Infinite will feature a variety of exciting and accessible single player modes and rich multi-player content for new players and longtime fans alike. In addition to single player Arcade, Training and Mission modes, a visually stunning and immersive cinematic Story Mode will put players at the center of both universes as they battle for survival against a sinister new threat. Marvel vs. Capcom: Infinite is being built to highlight a combination of iconic locations and fan favorite characters from both universes, including Captain Marvel and Iron Man from the Marvel side, and Ryu and Mega Man X from Capcom.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-avengers-xbox-one', 'Marvel''s Avengers', 'Marvel', '2020-09-04', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fkb.jpg', 'Based on the Marvel Cinematic Universe film Marvel''s Ant-Man, this DLC adds a brand-new level and eleven characters to LEGO Marvel''s Avengers journey.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('marvel-s-guardians-of-the-galaxy-xbox-one', 'Marvel''s Guardians of the Galaxy', 'Marvel', '2021-10-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4yh5.jpg', 'A bundle including Marvel''s Guardians of the Galaxy and Marvel''s Avengers.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-andromeda-xbox-one', 'Mass Effect: Andromeda', 'Mass Effect', '2017-03-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co39vk.jpg', 'A new adventure awaits in the Mass Effect universe. With stunning visuals and a new galaxy to discover, BioWare delivers the next generation of space exploration.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mass-effect-legendary-edition-xbox-one', 'Mass Effect Legendary Edition', 'Mass Effect', '2021-05-14', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k5h.jpg', 'One person is all that stands between humanity and the greatest threat it’s ever faced. Relive the legend of Commander Shepard in the highly acclaimed Mass Effect trilogy with the Mass Effect Legendary Edition. Includes single-player base content and over 40 DLCs from Mass Effect, Mass Effect 2, and Mass Effect 3 games, including promo weapons, armors and packs. Experience an amazingly rich and detailed universe where your decisions have profound consequences on the action and the outcome.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-xbox-one', 'Mega Man Legacy Collection', 'Mega Man', '2015-08-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-legacy-collection-2-xbox-one', 'Mega Man Legacy Collection 2', 'Mega Man', '2017-08-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2054.jpg', 'Jump into 10 classic Mega Man games, coming to Nintendo Switch! Play the blue bomber''s six original 8-bit quests in Mega Man Legacy Collection, which Includes Mega Man 1, 2, 3, 4, 5, & 6. Mega Man Legacy Collection 2 continues the adventures with the series'' evolution and retro revolution across Mega Man 7, 8, 9, & 10. These collections are bursting with additional content, from time trials and remix challenges to a music player and an extensive gallery of rare illustrations. A new "rewind" feature makes the 6 challenging 8-bit titles in Mega Man Legacy Collection more accessible for newcomers, with the option to rewind time and enjoy a swift recovery from blunders. Unlock additional challenges with the Mega Man amiibo figure!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-11-xbox-one', 'Mega Man 11', 'Mega Man', '2018-10-02', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5qb8.jpg', 'A GameStop/EB Games exclusive edition of Mega Man 11 that was only released in North America.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-x-legacy-collection-1-2-xbox-one', 'Mega Man X Legacy Collection 1+2', 'Mega Man X', '2018-07-24', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2055.jpg', '"Mega Man X Legacy Collection includes the legendary 16-bit titles and the series’ exciting foray into 32-bits: Mega Man X, Mega Man X2, Mega Man X3, and Mega Man X4. The heroic robot grows stronger as he takes down Mavericks and steals their weapons, and also has the ability to dash and wall jump for thrilling, fast-paced combat. Mega Man X’s mysterious friend, Zero, also joins the fray as a playable character later in this collection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mega-man-zero-zx-legacy-collection-xbox-one', 'Mega Man Zero / ZX Legacy Collection', NULL, '2020-02-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co204w.jpg', 'Mega Man Zero/ZX Legacy Collection brings together six classic titles in one game: Mega Man Zero 1, 2, 3 and 4, as well as Mega Man ZX and ZX Advent. The collection also features Z-Chaser, an exclusive new mode created just for this set of games.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-ground-zeroes-xbox-one', 'Metal Gear Solid V: Ground Zeroes', 'Metal Gear', '2014-03-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v88.jpg', 'Metal Gear Solid V: Ground Zeroes is a prologue to Metal Gear Solid V: The Phantom Pain. It offers players new sneaking and traversal methods compared to its predecessors, as well as the choice in what order the story events take place by selecting missions by advance. The most important change for this title is the shift to an open world design with a real-time day and night cycle doing away with the linear mission approach of previous games. The game was originally developed as a mission for The Phantom Pain, but an extended development time resulted in director Hideo Kojima splitting the specific portion of the game as a stand-alone product so that players could get early access to Metal Gear Solid V.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-phantom-pain-xbox-one', 'Metal Gear Solid V: The Phantom Pain', 'Metal Gear', '2015-09-01', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v85.jpg', 'Metal Gear Solid V: The Phantom Pain is the sequel to Metal Gear Solid V: Ground Zeroes and a prequel to the original Metal Gear. The game has a complex story with long cut-scene sequences, but there are fewer and they are shorter compared to earlier Metal Gear Solid titles. Most of the gameplay mechanics introduced in Ground Zeroes are carried over: it is still an action game and stealth oriented but replaces the linear corridor design from most earlier titles with large open world environments that offer the player unrestricted freedom for the approach. The world has now a real-time day and night cycle and various weather effects that influence enemy behaviour, visibility and sound. Sabotaging or destroying certain structures can also influence other parts of the map.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-solid-v-the-definitive-experience-xbox-one', 'Metal Gear Solid V: The Definitive Experience', 'Metal Gear', '2016-10-11', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ats.jpg', 'Metal Gear Solid V: The Definitive Experience is the ultimate collection of the Metal Gear Solid V story which includes Metal Gear Solid V: Ground Zeroes and Metal Gear Solid V: Tha Phantom Pain, the tactical multiplayer game as well as all their DLC content.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('metal-gear-survive-xbox-one', 'Metal Gear Survive', 'Metal Gear', '2018-02-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27m5.jpg', 'In a struggle to stay alive on this harsh terrain filled with deadly creatures, soldiers who were previously on Motherbase now must work cooperatively in order to survive.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-mordor-xbox-one', 'Middle-earth: Shadow of Mordor', 'Middle-earth', '2014-09-30', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20pd.jpg', 'Middle-earth: Shadow of Mordor is a open world third-person action role-playing video game developed by Monolith Productions and published by Warner Bros. Interactive Entertainment, which takes place in the world of J.R.R. Tolkien''s Legendarium.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('middle-earth-shadow-of-war-xbox-one', 'Middle-earth: Shadow of War', 'Middle-earth', '2017-10-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coalj6.jpg', 'Middle-earth: Shadow of War Mobile is a free-to-play real-time RPG continuing Talion’s journey through Mordor.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mighty-no-9-xbox-one', 'Mighty No. 9', NULL, '2016-06-21', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaquo.jpg', 'Well to celebrate Cirno day and for the ⑨Jam, i made this small little game about cirno.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-xbox-one-edition-xbox-one', 'Minecraft: Xbox One Edition', 'Minecraft', '2014-11-18', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2f9d.jpg', 'Build with your imagination! Minecraft, the best-selling game on Xbox 360, is now available on Xbox One. Create and explore your very own world where the only limit is what you can imagine - just be sure to build a shelter before night comes to keep yourself safe from monsters. Play on your own, or with up to 4 players split screen, or 8 players online.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-the-complete-adventure-xbox-one', 'Minecraft: Story Mode - The Complete Adventure', 'Minecraft', '2016-10-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ya.jpg', 'Embark on a perilous quest across the Overworld, to the End, and beyond. This version includes all five episodes of Season One and all three episodes of the Adventure Pass.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-story-mode-season-two-xbox-one', 'Minecraft: Story Mode - Season Two', 'Minecraft', '2017-09-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1vin.jpg', 'Minecraft: Story Mode - Season Two continues Jesse''s saga in a five-part, narrative-driven, episodic game series developed by Telltale in collaboration with Mojang and members of the Minecraft community. Though players'' choices from the first season will carry over into season two, this new season will be accessible to both returning fans and newcomers alike. This second season will also include Telltale''s unique multiplayer ''Crowd Play'' feature, which allows friends and family to engage with the adventure together by helping to decide the direction of the story from any mobile device with an online connection.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-xbox-one', 'Minecraft', 'Minecraft', '2018-10-09', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8fu7.jpg', 'Minecraft focuses on allowing the player to explore, interact with, and modify a dynamically-generated map made of one-cubic-meter-sized blocks. In addition to blocks, the environment features plants, mobs, and items. Some activities in the game include mining for ore, fighting hostile mobs, and crafting new blocks and tools by gathering various resources found in the game. The game''s open-ended model allows players to create structures, creations, and artwork on various multiplayer servers or their single-player maps. Other features include redstone circuits for logic computations and remote actions, minecarts and tracks, and a mysterious underworld called the Nether. A designated but completely optional goal of the game is to travel to a dimension called the End, and defeat the ender dragon.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('minecraft-dungeons-hero-edition-xbox-one', 'Minecraft Dungeons Hero Edition', 'Minecraft', '2020-09-08', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co233s.jpg', 'Fight your way through an all-new action-adventure game, inspired by classic dungeon crawlers and set in the Minecraft universe! Up to four friends can play together, or you can brave the dungeons alone. Includes a Hero Cape, two player skins, and a chicken pet. It also includes two DLC packs, when they become available.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mirror-s-edge-catalyst-xbox-one', 'Mirror''s Edge Catalyst', 'Mirror''s Edge', '2016-06-07', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co28r2.jpg', 'Mirror''s Edge Catalyst is an action-adventure game and the reboot to Mirror''s Edge. The story in the game explores the past of the protagonist Faith. Like in the previous game, the main gameplay in Mirror''s Edge Catalyst involves traversing the city using parkour to reach certain objectives. Unlike the linear levels in Mirror''s Edge, Mirror''s Edge Catalyst features an open-world free-roaming environment. Combat has been overhauled and emphasized compared to the first game and Catalyst no longer allows the player to use weapons, instead focusing on melee attacks.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-world-xbox-one', 'Monster Hunter: World', 'Monster Hunter', '2018-01-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rst.jpg', 'Welcome to a new world! Take on the role of a hunter and slay ferocious monsters in a living, breathing ecosystem where you can use the landscape and its diverse inhabitants to get the upper hand. Hunt alone or in co-op with up to three other players, and use materials collected from fallen foes to craft new gear and take on even bigger, badder beasts!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('monster-hunter-world-iceborne-master-edition-xbox-one', 'Monster Hunter World: Iceborne Master Edition', 'Monster Hunter', '2019-09-06', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co24ch.jpg', 'Discover breathtaking environments and battle titanic creatures in this collection that includes Monster Hunter: World and its massive expansion, Iceborne. As a hunter, you''ll take on quests to track & slay monsters in a variety of living, breathing habitats. Take down these monsters and use their materials to forge even more powerful weapons and armor, then prepare for even tougher foes as the story unfolds. Each discovery adds new areas, creatures, and drama to the adventure! The Iceborne expansion adds new monsters, gear and abilities to Monster Hunter: World. Picking up right where the base game left off, the Research Commission and your hunter set off to a new polar region, kicking off a brand-new story set in Hoarfrost Reach. Conquer these missions alone, or play online with other hunters for epic multiplayer quests.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('mortal-kombat-legacy-kollection-xbox-one', 'Mortal Kombat: Legacy Kollection', 'Mortal Kombat', '2025-10-30', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9x1h.jpg', 'Step into the arena and choose your fighter! Mortal Kombat: Legacy Kollection includes all the essential games from Mortal Kombat''s early years. Experience the legendary origins of the franchise with the iconic arcade classics that started it all—alongside a curated selection of most-loved home versions for the Super NES and Sega Genesis. Dive deeper with rare and fan-favorite releases across the Game Boy, Game Gear, Sega 32X, Game Boy Advance, and more—a celebration of the franchise’s groundbreaking legacy.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('murdered-soul-suspect-xbox-one', 'Murdered: Soul Suspect', NULL, '2014-06-03', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1r7a.jpg', 'Murdered: Soul Suspect is a supernatural detective thriller which challenges players to solve possibly the hardest case of all… their own murder.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('nier-replicant-ver-1-22474487139-xbox-one', 'Nier Replicant ver.1.22474487139...', 'Nier', '2021-04-23', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5h0n.jpg', 'NieR Replicant ver.1.22474487139... is an updated version of NieR Replicant, previously only released in Japan. Discover the one-of-a-kind prequel to the critically-acclaimed masterpiece NieR: Automata. Now with a modern upgrade, experience masterfully revived visuals, a fascinating storyline and more!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ninja-gaiden-master-collection-xbox-one', 'Ninja Gaiden: Master Collection', 'Ninja Gaiden', '2021-06-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobpt5.jpg', 'The “Ninja Gaiden” series is respected and beloved across the entire gaming world, and has sold 6.8 million units in total.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('no-man-s-sky-xbox-one', 'No Man''s Sky', 'No Man''s Sky', '2018-07-24', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8j4g.jpg', 'Update 5.0, WORLDS, transforms the universe into a richer, wilder, more varied and immersive place. Featuring huge leaps in water and cloud visuals, increased planetary diversity, new gameplay features, and more.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('kami-hd-xbox-one', 'Ōkami HD', 'Ōkami', '2017-12-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22s8.jpg', 'Experience the critically acclaimed masterpiece with its renowned Sumi-e ink art style in breathtaking high resolution. Take on the role of Amaterasu, the Japanese sun goddess who inhabits the form of a legendary white wolf, on a quest to defeat Orochi, an eight-headed demon and tyrannical monster responsible for turning the world of Nippon into a ruined wasteland.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ori-and-the-blind-forest-xbox-one', 'Ori and the Blind Forest', 'Ori', '2015-03-11', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2s0m.jpg', 'The forest of Nibel is dying. After a powerful storm sets a series of devastating events in motion, Ori must journey to find courage and confront a dark nemesis to save the forest of Nibel. “Ori and the Blind Forest” tells the tale of a young orphan destined for heroics, through a visually stunning Action-Platformer crafted by Moon Studios. Featuring hand-painted artwork, meticulously animated character performance, a fully orchestrated score and dozens of new features in the Definitive Edition, “Ori and the Blind Forest” explores a deeply emotional story about love and sacrifice, and the hope that exists in us all.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ori-and-the-will-of-the-wisps-xbox-one', 'Ori and the Will of the Wisps', 'Ori', '2020-03-11', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e1l.jpg', 'Ori and the Will of the Wisps is a platform-adventure game that combines exploration, traversal, and combat within an interconnected world. Designed in a Metroidvania style, it focuses on navigating varied environments, uncovering hidden areas, and acquiring abilities that expand movement and progression options.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-outer-worlds-xbox-one', 'The Outer Worlds', NULL, '2019-10-25', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2eew.jpg', 'The Outer Worlds is a new single-player sci-fi RPG from Obsidian Entertainment and Private Division. As you explore the furthest reaches of space and encounter a host of factions all vying for power, who you decide to become will determine the fate of everyone in Halcyon. In the corporate equation for the colony, you are the unplanned variable.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-gourmet-edition-xbox-one', 'Overcooked! Gourmet Edition', 'Overcooked!', '2016-11-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x6s.jpg', 'The Overcooked Gourmet Edition stirs together the smash hit co-op cooking game and the Lost Morsel content pack into one delicious package that will test your culinary skills to the limit!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-2-xbox-one', 'Overcooked! 2', 'Overcooked!', '2018-08-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g3n.jpg', 'This bundle contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-overcooked-2-xbox-one', 'Overcooked! + Overcooked! 2', 'Overcooked!', '2019-11-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g3n.jpg', 'This bundle contains:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pac-man-championship-edition-2-arcade-game-series-xbox-one', 'Pac-Man Championship Edition 2 + Arcade Game Series', 'Pac-Man', '2016-11-01', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27xn.jpg', 'Bandai-Namco bundles its hit Pac-Man Championship Edition 2 on a disc with three Namco classics.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pentiment-xbox-one', 'Pentiment', NULL, '2022-11-15', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4v1e.jpg', 'A 16th-century narrative adventure set in Upper Bavaria, following Andreas Maler, a journeyman artist working in the bygone scriptorium of Kiersau Abbey during a time of great social unrest. While finishing his masterpiece, Andreas inadvertently becomes entangled in a series of murders that take place over 25 years. Peasants, thieves, craftsmen, monks, nuns, nobles, and even saints must be investigated and interrogated to expose the truth.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-3-portable-xbox-one', 'Persona 3 Portable', 'Persona', '2023-01-19', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co60ug.jpg', 'From the Midnight Channel to the Dark Hour, two iconic Persona titles return!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('persona-4-golden-xbox-one', 'Persona 4 Golden', 'Persona', '2023-01-19', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1n1x.jpg', 'An enhanced rerelease of Shin Megami Tensei: Persona 4 (2008) featuring quality-of-life improvements, gameplay enhancements, new locations, balance tweaks, online functionality, new difficulty options, an additional side character storyline and a changed endgame.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pillars-of-eternity-complete-edition-xbox-one', 'Pillars of Eternity: Complete Edition', 'Pillars of Eternity', '2017-08-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z3j.jpg', 'Pillars of Eternity, the ultimate role-playing experience on PC, comes to Xbox One and PlayStation 4, this fall! Created by and for role-playing fans by Obsidian Entertainment, masters of the RPG genre, Pillars started as a Kickstarter project, where it shattered all funding goals and pulled in more than 75,000 backers. From there, it released to broad critical acclaim, won dozens of awards, and has been a fan favorite on the PC. Now, Paradox Arctic, in partnership with 505 Games, is bringing Pillars'' fantastical world, tactical combat, and unforgettable story to fans on a whole new platform. Pillars of Eternity: Complete Edition includes all previously released additional content from the PC version, including all DLC and expansions in a single package.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('pillars-of-eternity-ii-deadfire-ultimate-edition-xbox-one', 'Pillars of Eternity II: Deadfire - Ultimate Edition', 'Pillars of Eternity', '2020-01-27', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x57.jpg', 'Obsidian Entertainment proudly presents the sequel to our crowdfunded and critically-acclaimed role-playing game, Pillars of Eternity. Welcome to Pillars of Eternity II: Deadfire. With Pillars II, we are revisiting the rich narrative, beautiful environments, and tactical combat that made Pillars of Eternity one of the highest-rated PC games of all time.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-xbox-one', 'Plants vs. Zombies: Garden Warfare', 'Plants vs. Zombies', '2014-02-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qyz.jpg', 'Plants vs. Zombies is digging into the trenches with an explosive new 3D experience. Blast zombies, plants, and new characters with inventive weapons across a mine-blowing PvZ world. Take on Co-Op and Multiplayer action with your friends and sow the seeds of victory!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-garden-warfare-2-xbox-one', 'Plants vs. Zombies: Garden Warfare 2', 'Plants vs. Zombies', '2016-02-23', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3xur.jpg', 'The battle for suburbia grows to crazy new heights in Plants vs. Zombies Garden Warfare 2! In this hilarious, action-packed shooter, zombie leader Dr. Zomboss has strengthened his horde and rebuilt suburbia as a zombie utopia. But hope remains, because for the first time the plants are taking the offensive in an all-out attack to reclaim their turf. Play as the plants in the all-new 24-player Herbal Assault mode, or choose your side in 4-player co-op or Solo Play!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('plants-vs-zombies-battle-for-neighborville-xbox-one', 'Plants vs. Zombies: Battle for Neighborville', 'Plants vs. Zombies', '2019-10-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3isd.jpg', 'Similar to its predecessors, the game is a third-person shooter where players take control of the Plants or the Zombies in either a cooperative or competitive multiplayer environment. The game features 20 customizable gameplay classes, six of which are new to the franchise, and they are classified into three groups: attackers, defenders, or support. Each camp also has a new team play class that allows players of the same class to combine forms when they fight against enemies. Players can compete against each other in various competitive multiplayer modes, including the objective-based Turf War mode and the team deathmatch variant Team Vanquish. The game also features several player-versus-environment open zones which allowed players to explore, find collectibles, and complete quests. Split-screen local multiplayer is also available for all gameplay mode', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('bridge-constructor-portal-xbox-one', 'Bridge Constructor Portal', 'Portal', '2018-02-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co230j.jpg', 'Enter the Aperture Science Enrichment Center and experience Bridge Constructor Portal – the unique merging of the classic Portal and Bridge Constructor games.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prey-xbox-one', 'Prey', NULL, '2017-05-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9aoh.jpg', 'In Prey, you awaken aboard Talos I, a space station orbiting the moon in the year 2032. You are the key subject of an experiment meant to alter humanity forever – but things have gone terribly wrong. The space station has been overrun by hostile aliens and you are now being hunted. As you dig into the dark secrets of Talos I and your own past, you must survive using the tools found on the station, your wits, weapons, and mind-bending abilities.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('project-spark-starter-pack-xbox-one', 'Project Spark Starter Pack', 'Project Spark', '2014-10-07', 'Xbox One', 1, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('prototype-biohazard-bundle-xbox-one', 'Prototype Biohazard Bundle', 'Prototype', '2015-07-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6s88.jpg', 'This bundle contains Prototype and Prototype 2, now remastered to offer enhanced visuals and an improved frame rate.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('psychonauts-2-xbox-one', 'Psychonauts 2', 'Psychonauts', '2021-08-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob7mx.jpg', 'Psychonauts 2 is a platform-adventure game developed by Double Fine Productions and released in 2021. It continues the story of Razputin “Raz” Aquato, a young psychic who joins the international psychic espionage agency known as the Psychonauts.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('puyo-puyo-tetris-2-xbox-one', 'Puyo Puyo Tetris 2', 'Puyo Puyo Tetris', '2020-12-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3246.jpg', 'Stack, chain, and combo your way to victory in the ultimate matching of two puzzle game legends! Pre-order now and get ready to traverse dimensions and experience brand new worlds in time for the holidays, with the PC release fast-dropping onto Steam in early 2021.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-xbox-one', 'Quake', 'Quake', '2021-08-19', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4n28.jpg', 'Coffee Quake is one of the largest Community map packs featuring 74 small levels across four episodes following the classic Quake themes. Each map was made within two hours and has an average playtime of 3-5 minutes - well-suited for the occasional coffee break. The pack comes with a start map and a remix/remake of the original end map as well as a music track and some demos. The map sources are included.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quake-ii-xbox-one', 'Quake II', 'Quake', '2023-08-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9bg8.jpg', 'Quake II is a first-person shooter video game developed by id Software and published by Activision. It is not a direct sequel to Quake, id decided to revert to an existing trademark when they were unable to agree on a new name that did not violate another company''s trademark.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('quantum-break-xbox-one', 'Quantum Break', NULL, '2016-04-05', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gsr.jpg', 'Fix Time Before It Destroys Everything!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-quarry-xbox-one', 'The Quarry', NULL, '2022-06-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4kl4.jpg', 'It''s late summer in the remote forests of upstate New York, and the teen counselors of Hackett''s Quarry have the camp to themselves for one final night. That means no kids, no adults, and no rules. In this thrilling cinematic tale, you control the fates of all nine camp counselors as their party plans unravel into an unpredictable night of horror. With life-or-death decisions around every turn, the choices you make will determine how the story unfolds.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rabbids-invasion-the-interactive-tv-show-xbox-one', 'Rabbids Invasion: The Interactive TV Show', 'Rabbids', '2014-11-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coavxt.jpg', 'Rabbids Invasion, the kids hit animated TV show, is now an interactive game on PlayStation 4. With motion gameplay, kids can now play in their living room with a selection of episodes from the TV show. Through fun, silly challenges, players have an outrageous time with family and friends and experience the Rabbids Invasion TV show in a brand new way.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rare-replay-xbox-one', 'Rare Replay', NULL, '2015-08-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co50mg.jpg', 'Rare Replay is a 2015 compilation of 30 video games previously developed by Rare and its predecessor, Ultimate Play the Game, in their 30-year combined history. The emulated games span multiple genres and consoles - from the ZX Spectrum to the Xbox 360 - and retain the features and errors of their original releases with minimal edits. The compilation adds cheats to make the older games easier and a Snapshots mode of specific challenges culled from parts of the games. Player progress is rewarded with behind-the-scenes footage and interviews about Rare''s major and unreleased games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rayman-legends-xbox-one', 'Rayman Legends', 'Rayman', '2014-02-18', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3ma8.jpg', 'The Glade of Dreams is in trouble once again! The nightmares multiplied and spread, creating new monsters even more terrifying than before!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('recore-xbox-one', 'ReCore', NULL, '2016-09-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dqn.jpg', 'Presenting ReCore a game from the legendary creator Keiji Inafune and the makers of Metroid Prime. As one of the last remaining humans, forge friendships with courageous robot companions and lead them on an epic adventure through a mysterious, dynamic world.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('red-dead-redemption-2-xbox-one', 'Red Dead Redemption 2', 'Red Dead', '2018-10-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1q1f.jpg', 'Red Dead Redemption 2 is the epic tale of outlaw Arthur Morgan and the infamous Van der Linde gang, on the run across America at the dawn of the modern age.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-2-xbox-one', 'Resident Evil: Revelations 2', 'Resident Evil', '2015-03-20', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co92d9.jpg', 'Resident Evil: Revelations 2 is the retail version of the episodic survival horror series that was originally released as four downloadable episodes. This physical version combines the entire story along with some extras, but not all the available DLC. The PC version did not receive a retail release, but the same content was bundled on Steam. The game comprises four episodes, each of which feature two separate stories. This sequel bears a stronger tone to the concept of survival horror than titles such as Resident Evil 5 and Resident Evil 6. Elements of ammunition management as well as stealth or sneaking come into play in the gameplay.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-origins-collection-xbox-one', 'Resident Evil Origins Collection', 'Resident Evil', '2016-01-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3dnx.jpg', 'Experience the early days of the outbreak in Resident Evil Origins Collection, a compilation package of two with two Resident Evil origin stories: Resident Evil 0 and Resident Evil HD . Both terrifying games have been brought to new new levels of horror with new HD visuals, improved sound, widescreen support, an optional modernized control system and more.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-6-xbox-one', 'Resident Evil 6', 'Resident Evil', '2016-03-29', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3pyq.jpg', 'Resident Evil 6 is the ninth video game installment in the Resident Evil series. It continues the struggle against zombies infected by the new highly virulent C-virus. The game uses the same over-the-shoulder view as Resident Evil 4 and Resident Evil 5, however with a new gameplay mechanic that allows players to slowly move while shoot. Players can select between three scenarios featuring multiple characters and intertwined storylines, and within these scenarios both stories and action cross paths. At key moments during the game, up to four players can join together online to tackle a specific situation, with some stages seeing the usual partnerships swapped to further increase the depth of gameplay.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-5-xbox-one', 'Resident Evil 5', 'Resident Evil', '2016-06-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtgs.jpg', 'Resident Evil 5 is the seventh video game in the Resident Evil series. It features similar gameplay to Resident Evil 4 utilizing the same over the shoulder view, but this time the environment plays a significant role. The player is now dependent on his partner more than in older games. When the partner''s health bar drop down to 0, he will enter the dying stage where the health bar will flash red and gradually lower as he stays like this. Resident Evil 5 also features new types of enemies called Majini and mostly are of African descent.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-4-xbox-one', 'Resident Evil 4', 'Resident Evil', '2016-08-30', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wn5.jpg', 'This pack includes Resident Evil 4 and Resident Evil CODE: Veronica X.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-7-biohazard-xbox-one', 'Resident Evil 7: Biohazard', 'Resident Evil', '2017-01-24', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobtwh.jpg', 'Resident Evil 7: Biohazard is the first game of the Resident Evil series to switch from 3rd-person to fully 1st-person perspective. A complete refresh of gameplay systems simultaneously propels the survival horror experience to another level. It is as much horror as it is survival, boosting up scare elements and minimizing downright shooting action. The game allows use of Sony''s PSVR Headset to play in VR mode.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-revelations-xbox-one', 'Resident Evil: Revelations', 'Resident Evil', '2017-08-29', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8zvu.jpg', 'Resident Evil: Revelations is a remaster of the 3DS game with high quality HD visuals, enhanced lighting effects and an immersive sound experience.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-7-biohazard-gold-edition-xbox-one', 'Resident Evil 7: Biohazard Gold Edition', 'Resident Evil', '2017-12-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fad.jpg', 'Set in modern day rural America and taking place after the dramatic events of Resident Evil 6, players experience the terror directly from the first person perspective. Resident Evil 7 embodies the series'' signature gameplay elements of exploration and tense atmosphere that first coined "survival horror" some twenty years ago; meanwhile, a complete refresh of gameplay systems simultaneously propels the survival horror experience to the next level.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-2-xbox-one', 'Resident Evil 2', 'Resident Evil', '2019-01-25', 'Xbox One', 0, 0, NULL, NULL, NULL, 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-3-xbox-one', 'Resident Evil 3', 'Resident Evil', '2020-04-03', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22l7.jpg', 'Resident Evil 3 is a remake of the original Resident Evil 3: Nemesis released in 1999. It updates the story and gameplay for a modern audience. Like the Resident Evil 2 remake, the game uses over-the-shoulder third person point of view similar to Resident Evil 4 and later installments. Players will spend most of their time playing as Jill Valentine, although on some occasions they will assume the role of Carlos Oliveira, giving him more screen time as a deuteragonist.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('resident-evil-village-xbox-one', 'Resident Evil Village', 'Resident Evil', '2021-05-07', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyw.jpg', 'A bundle including the following content:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rime-xbox-one', 'Rime', NULL, '2017-05-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co84t0.jpg', 'You stumble across an old book and get trapped within its world.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('ryse-son-of-rome-xbox-one', 'Ryse: Son of Rome', NULL, '2013-11-22', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2r7y.jpg', 'Ryse: Son of Rome is a stunning action-adventure that follows Marius Titus on a heroic quest to avenge the death of his family, and preserve the honor of Rome, at all costs.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-showdown-xbox-one', 'Scribblenauts Showdown', 'Scribblenauts', '2018-03-06', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co272u.jpg', 'It’s Scribblenauts, party-style! Use your imagination and go head-to-head in the ultimate multiplayer showdown! Enjoy a party-style Scribblenauts experience, conjuring from over 35,000 objects from the vast Scribblenauts dictionary to outsmart your opponent in over 25 mini-games.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('scribblenauts-mega-pack-xbox-one', 'Scribblenauts Mega Pack', 'Scribblenauts', '2018-09-18', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/du7bf613i5hyjwbto3rj.jpg', 'Get the best of Scribblenauts with Scribblenauts Mega Pack! Two classic games with ALL-NEW content to explore!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sea-of-thieves-xbox-one', 'Sea of Thieves', 'Sea of Thieves', '2018-03-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2558.jpg', 'Sea of Thieves offers the essential pirate experience, from sailing and fighting to exploring and looting – everything you need to live the pirate life and become a legend in your own right. With no set roles, you have complete freedom to approach the world, and other players, however you choose.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sea-of-thieves-anniversary-edition-xbox-one', 'Sea of Thieves: Anniversary Edition', 'Sea of Thieves', '2019-04-25', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1lfg.jpg', NULL, 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sega-genesis-classics-xbox-one', 'Sega Genesis Classics', NULL, '2018-05-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6sm8.jpg', 'The collection has over 50 retro classics to experience across every genre; arcade action, shooters, beat’em ups, puzzlers, old favourites and hidden gems, with a raft of modern features. These include online multiplayer, achievements, mirror modes, rewind and save states meaning players old and new should find revisiting these great games an absolute Sonic 3D Blast.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sekiro-shadows-die-twice-xbox-one', 'Sekiro: Shadows Die Twice', NULL, '2019-03-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2a23.jpg', 'Carve your own clever path to vengeance as you come face-to-face with larger than life foes in FromSoftware''s dark and twisted adventure set in feudal Japan. Unleash an arsenal of deadly prosthetic tools and ninja abilities, while blending stealth, vertical traversal, and visceral combat. Survive a relentless and bloody confrontation on a quest to restore your honor and save the one you''re sworn to protect.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shantae-advance-risky-revolution-xbox-one', 'Shantae Advance: Risky Revolution', 'Shantae', '2025-08-19', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaboc.jpg', 'Shantae is back in an adventure 20 years in the making! The nefarious pirate Risky Boots has a “groundbreaking” new plan that will leave Sequin Land spinning — by rotating the continent, she can move any town right to the coast for easy plundering! As Shantae, turn the tectonic tables on Risky by taking control of the land itself: shift, twist, navigate, and explore by swapping between mix-and-match multilayered levels! Hair-whip and belly-dance your way through scrambled lands, misplaced towns, monster-filled crypts, and daunting labyrinths. Six creature transformations, fierce boss battles, and a 4-player versus mode await!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shenmue-i-ii-xbox-one', 'Shenmue I & II', 'Shenmue', '2018-08-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2e3q.jpg', '"Originally released for the Dreamcast in 2000 and 2001, Shenmue I & II is an open world action adventure combining jujitsu combat, investigative sleuthing, RPG elements, and memorable mini-games. It pioneered many aspects of modern gaming, including open world city exploration, and was the game that coined the Quick Time Event (QTE). It was one of the first games with a persistent open world, where day cycles to night, weather changes, shops open and close and NPCs go about their business all on their own schedules. Its engrossing epic story and living world created a generation of passionate fans, and the game consistently makes the list of “greatest games of all time”."', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shovel-knight-treasure-trove-xbox-one', 'Shovel Knight: Treasure Trove', 'Shovel Knight', '2019-12-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2gsx.jpg', 'Shovel Knight: Treasure Trove is the full and complete edition of Shovel Knight, a sweeping classic action-adventure game series with awesome gameplay, memorable characters, and an 8-bit retro aesthetic! Run, jump, and battle as Shovel Knight, wielder of the Shovel Blade, in a quest for his lost beloved. Take down the nefarious knights of the Order of No Quarter and confront their menacing leader, The Enchantress.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-sims-4-xbox-one', 'The Sims 4', 'The Sims', '2017-11-17', 'Xbox One', 1, 0, NULL, NULL, NULL, 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-swap-force-xbox-one', 'Skylanders: Swap Force', 'Skylanders', '2013-11-22', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9fsw.jpg', 'Skylanders: Swap Force is a platformer video game developed by Vicarious Visions and published by Activision. It is the third main game in the Skylanders video game and toy franchise, following 2012''s Skylanders: Giants, which was a direct sequel to 2011''s Skylanders: Spyro''s Adventure (the spin-off of The Legend of Spyro series). It is the game before Skylanders: Trap Team and features the voices of John DiMaggio, Jess Harnell, Audrey Wasilewski, Richard Tatum, David Sobolov, Josh Keaton, Keythe Farley, Dave Wittenberg, Joey Camen, Gregg Berger, Troy Baker and Robin Atkin Downes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-trap-team-xbox-one', 'Skylanders: Trap Team', 'Skylanders', '2014-10-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9ft0.jpg', 'In Skylanders Trap Team, Kaos continues his ongoing quest to rule over Skylands. He has discovered the location of the legendary Cloudcracker Prison -- a fortress built entirely out of the magical substance Traptanium and home to Skylands’ most nefarious baddies. In an attempt to build his own army of foes, Kaos blows up the prison, releasing the most wanted villains and blasting shards of Traptanium to Earth in the form of Traps. Now it’s up to Portal Masters to recapture all of the escaped villains using powerful Traptanium Traps and defeat Kaos before it’s too late!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-superchargers-xbox-one', 'Skylanders: SuperChargers', 'Skylanders', '2015-09-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsk.jpg', 'Exclusive to the Wii U version of the game is a special figure of Donkey Kong and Bowser.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('skylanders-imaginators-xbox-one', 'Skylanders: Imaginators', 'Skylanders', '2016-10-16', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8tsm.jpg', 'Exclusive to the Wii U and Nintendo Switch versions of the game is a special figure of Donkey Kong and Bowser.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('slime-rancher-xbox-one', 'Slime Rancher', 'Slime Rancher', '2018-09-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co73i2.jpg', 'Slime Rancher is a charming, first-person, sandbox experience. Play as Beatrix LeBeau: a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ''Far, Far Range.'' Each day will present new challenges and risky opportunities as you attempt to amass a great fortune in the business of slime ranching. Collect colorful slimes, grow crops, harvest resources, and explore the untamed wilds through the mastery of your all-purpose vacpack.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('slime-rancher-deluxe-edition-xbox-one', 'Slime Rancher: Deluxe Edition', 'Slime Rancher', '2020-05-26', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co27ky.jpg', 'Slime Rancher is a charming, first-person, video game experience. Play as Beatrix LeBeau: a plucky, young rancher who sets out for a life a thousand light years away from Earth on the ‘Far, Far Range’ to stake a claim and make her fortune wrangling slimes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('song-of-the-deep-xbox-one', 'Song of the Deep', NULL, '2016-07-12', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rck.jpg', 'A metroidvania-style action-adventure game following a young girl’s quest into the unknown to find her missing father.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-forces-xbox-one', 'Sonic Forces', 'Sonic the Hedgehog', '2017-11-07', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1zr8.jpg', 'Fight through a world destroyed by Dr. Eggman and a powerful new villain in Sonic Forces, the new fast-paced action platformer from the team that brought you Sonic Colors and Sonic Generations. Sonic Forces lets you speed through rolling ruined landscapes as Modern Sonic, catapult past perilous platforms as Classic Sonic, and use powerful new gadgets as your own Custom Hero Character.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-plus-xbox-one', 'Sonic Mania Plus', 'Sonic the Hedgehog', '2018-07-17', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2wqj.jpg', 'Experience Classic and Modern Sonic in two great games -- speed through rolling landscapes in all-new 2D adventures in Sonic Mania Plus, and create your own character to take back the world from the evil Dr. Eggman in the 3D adventure, Sonic Forces!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('team-sonic-racing-xbox-one', 'Team Sonic Racing', 'Sonic the Hedgehog', '2019-05-21', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1upm.jpg', 'Team Sonic Racing combines the best elements of arcade and fast-paced competitive style racing as you face-off with friends in intense multiplayer racing.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-mania-xbox-one', 'Sonic Mania', 'Sonic the Hedgehog', '2019-11-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8uho.jpg', 'Sonic Mania and Sonic PLUS is a complete overhaul of Sonic Mania and its DLC:
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-colors-ultimate-xbox-one', 'Sonic Colors: Ultimate', 'Sonic the Hedgehog', '2021-09-07', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co31a0.jpg', 'Join Sonic in the high-speed adventure of a lifetime across a colorful interstellar amusement park. Color the Universe in Sonic Colors: Ultimate!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-frontiers-xbox-one', 'Sonic Frontiers', 'Sonic the Hedgehog', '2022-11-08', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5p52.jpg', 'Worlds will collide in Sonic the Hedgehog’s newest adventure.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-origins-plus-xbox-one', 'Sonic Origins Plus', 'Sonic the Hedgehog', '2023-06-23', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6oez.jpg', 'Sonic Origins Plus is an updated version of Sonic Origins that includes the Plus Expansion Pack. Unlike Sonic Mania Plus, Sonic Origins Plus can be bought digitally on PC as a single purchase like the console versions, while the base game continues to be available on it''s own. Digital versions of Sonic Origins on all platforms can be upgraded to Plus by purchasing the Plus Expansion Pack separately.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-superstars-xbox-one', 'Sonic Superstars', 'Sonic the Hedgehog', '2023-10-17', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbw4.jpg', 'Adventure through the mystical Northstar Islands in this all-new take on classic 2D Sonic high-speed action platforming. Play as Sonic, Tails, Knuckles, and Amy Rose and harness all-new Emerald powers to move and attack in dynamic new ways. Navigate gorgeous, never-before-seen environments solo or with up to 3 other players and stop Dr. Eggman, Fang, and a mysterious new adversary from converting the islands'' giant animals into Badniks before it''s too late!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sonic-x-shadow-generations-xbox-one', 'Sonic X Shadow Generations', 'Sonic the Hedgehog', '2024-10-22', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaq3d.jpg', 'A legacy skin for Classic Sonic inspired by his look in Sonic Jam.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('spyro-reignited-trilogy-xbox-one', 'Spyro Reignited Trilogy', 'Spyro', '2018-11-13', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobaat.jpg', 'Spyro Reignited Trilogy is a collection of remasters of the first three games in the Spyro series: Spyro the Dragon (1998), Ripto''s Rage! (1999), and Year of the Dragon (2000).', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-xbox-one', 'Star Wars Battlefront', 'Star Wars', '2015-11-17', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2res.jpg', 'In 2004, the original Star Wars: Battlefront came onto the scene and took gamers – and Star Wars fans – by surprise. It was an ambitious action shooter that gave players the opportunity to step into the shoes of their favorite Star Wars characters, pilot quintessential Star Wars vehicles, and relive classic Star Wars battles.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-battlefront-ii-xbox-one', 'Star Wars Battlefront II', 'Star Wars', '2017-11-17', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1g4.jpg', 'Star Wars: Battlefront II is the sequel to Star Wars: Battlefront. It is a high-selling Star Wars video game following the many adventures of several characters. The two games are very similar, as both revolve around troopers from various factions fighting in different locales. Battlefront II, however, includes elements and missions from Star Wars: Episode III Revenge of the Sith, as well as enhanced aspects of gameplay including space combat and the ability to play as Jedi characters or other heroes.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-fallen-order-xbox-one', 'Star Wars Jedi: Fallen Order', 'Star Wars', '2019-11-15', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rbi.jpg', 'Star Wars Jedi: Fallen Order is a narratively driven, single-player game puts you in the role of a Jedi Padawan who narrowly escaped the purge of Order 66 following the events of Episode III: Revenge of the Sith. On a quest to rebuild the Jedi Order, you must pick up the pieces of your shattered past to complete your training, develop new powerful Force abilities and master the art of the iconic lightsaber - all while staying one step ahead of the Empire and its deadly Inquisitors.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-squadrons-xbox-one', 'Star Wars: Squadrons', 'Star Wars', '2020-10-02', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wlz.jpg', 'Master the art of starfighter combat in the authentic piloting experience STAR WARS: Squadrons. Buckle up, feel the adrenaline of first-person multiplayer space dogfights alongside your squadron, and learn what it means to be a pilot in a thrilling STAR WARS single-player campaign.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('stardew-valley-xbox-one', 'Stardew Valley', NULL, '2016-12-14', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coa93h.jpg', 'Stardew Valley is an open-ended country-life RPG! You’ve inherited your grandfather’s old farm plot in Stardew Valley. Armed with hand-me-down tools and a few coins, you set out to begin your new life. Can you learn to live off the land and turn these overgrown fields into a thriving home? It won’t be easy. Ever since Joja Corporation came to town, the old ways of life have all but disappeared. The community center, once the town’s most vibrant hub of activity, now lies in shambles. But the valley seems full of opportunity. With a little dedication, you might just be the one to restore Stardew Valley to greatness!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('starlink-battle-for-atlas-xbox-one', 'Starlink: Battle for Atlas', NULL, '2018-10-16', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7pm8.jpg', 'Starlink: Battle for Atlas is an all-new action-adventure game developed by Ubisoft Toronto. This deep, open-world space saga features Smart Building Technology empowering players to assemble and customize real-world physical starships. Each part attached to the starship appears instantly in-game and players can experiment with different pilot abilities, weapon types, and status effects and unleash devastating combos upon their enemies.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('subnautica-xbox-one', 'Subnautica', 'Subnautica', '2018-12-04', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x8n.jpg', 'Combining the award-winning game Subnautica with its unreleased sequel Subnautica Below Zero, this Nintendo Switch exclusive allows players to fully immerse themselves in the full mystery surrounding the water world of planet 4546B. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive in both hostile water zones and frozen terrains.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('subnautica-below-zero-xbox-one', 'Subnautica: Below Zero', 'Subnautica', '2021-05-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2x8n.jpg', 'Combining the award-winning game Subnautica with its unreleased sequel Subnautica Below Zero, this Nintendo Switch exclusive allows players to fully immerse themselves in the full mystery surrounding the water world of planet 4546B. Craft equipment, pilot submarines and out-smart wildlife to explore lush coral reefs, volcanoes, cave systems, and more - all while trying to survive in both hostile water zones and frozen terrains.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('sunset-overdrive-xbox-one', 'Sunset Overdrive', NULL, '2014-10-28', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co20td.jpg', 'The city’s overrun with mutants. Problem? Not for you. Sunset Overdrive is an open-world playground of post-apocalyptic possibilities. Vault, grind & wall-run while using a deadly & unconventional arsenal. With hyper-agility, unique weapons, & customizable abilities, it rewrites the rules of shooters while delivering an irreverent adventure.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-lucky-s-tale-xbox-one', 'Super Lucky''s Tale', 'Super Lucky''s Tale', '2017-11-07', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22o8.jpg', 'Super Lucky’s Tale is a delightful, playground platformer for all ages that follows Lucky, the ever-optimistic and lovable hero, on his quest to find his inner strength and help his beloved sister rescue the Book of Ages from the nefarious Jinx. Head back to the era of classic platformers with challenges players of all skill levels and all ages can enjoy.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-blitz-hd-xbox-one', 'Super Monkey Ball: Banana Blitz HD ', 'Super Monkey Ball', '2019-10-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1uh1.jpg', 'Hold onto your bananas, because Super Monkey Ball: Banana Blitz HD is rolling your way! Experience the magic of one of the most beloved titles in the series, now remastered in HD!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('super-monkey-ball-banana-mania-xbox-one', 'Super Monkey Ball Banana Mania', 'Super Monkey Ball', '2021-10-05', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaeop.jpg', 'Super Monkey Ball: Banana Mania is a "modern HD remaster" of Super Monkey Ball, Super Monkey Ball 2, and Super Monkey Ball Deluxe.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-vesperia-definitive-edition-xbox-one', 'Tales of Vesperia: Definitive Edition', 'Tales', '2019-01-11', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5gb5.jpg', 'Tales of Vesperia: Definitive Edition is a remaster of the expanded Playstation 3 port of the original game, which was exclusive to Japan.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tales-of-arise-xbox-one', 'Tales of Arise', 'Tales', '2021-09-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ls2.jpg', 'On the planet Dahna, reverence has always been given to Rena--the planet in the sky--as a land of the righteous and divine. Stories handed down for generations became truth and masked reality for the people of Dahna. For 300 years, Rena has ruled over Dahna, pillaging the planet of its resources and stripping people of their dignity and freedom.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('terraria-xbox-one', 'Terraria', NULL, '2014-11-14', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/coaamg.jpg', 'Dig, Fight, Explore, Build: The very world is at your fingertips as you fight for survival, fortune, and glory. Will you delve deep into cavernous expanses in search of treasure and raw materials with which to craft ever-evolving gear, machinery, and aesthetics? Perhaps you will choose instead to seek out ever-greater foes to test your mettle in combat? Maybe you will decide to construct your own city to house the host of mysterious allies you may encounter along your travels? In the World of Terraria, the choice is yours!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tetris-effect-connected-xbox-one', 'Tetris Effect: Connected', 'Tetris', '2020-11-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7kus.jpg', 'Tetris Effect: Connected adds an all-new robust multiplayer expansion to the huge variety of addictive and innovative single-player modes that Tetris Effect is known for. Connect and play with or against each other in all-new modes like "Zone Battle," which shakes up traditional 1-on-1 Tetris gameplay via the time-stopping Zone mechanic, or try the innovative co-op of "Connected" mode, where up to three players can literally connect their Tetris playfields together and play as one, as they work together to take down a series of increasingly-challenging CPU-controlled bosses.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('thief-xbox-one', 'Thief', 'Thief', '2014-02-25', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2rom.jpg', 'In the third instalment of the Thief series, master-thief Garrett is contacted by Keeper Artemus with a mission to steal two valuable artefacts. At the same time, Garrett learns about a prophecy: the coming of a Dark Age. He embarks upon a journey to unravel a mystery that threatens the existence of the order of Keepers. Is it possible that there is a traitor in their midst?
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('titanfall-xbox-one', 'Titanfall', 'Titanfall', '2014-03-11', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3wo1.jpg', 'In Titanfall, players fight on a war-torn planet in six-on-six online multiplayer-only matches as mech-style Titans and their pilots. The game''s action is fast-paced: as pilots, players can run along walls and link jumps together parkour-style, use a variety of futuristic military weapons, and employ one of three special abilities: cloaking, stimming (increasing speed and health regeneration) and radar pinging; as Titans, players are equipped with more destructive armaments and special protective shields, with no limit to their abilities besides cooldown and reloading.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('titanfall-2-xbox-one', 'Titanfall 2', 'Titanfall', '2016-10-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/fhbeilnghyhhmjqhinqa.jpg', 'Titanfall 2 will deliver a crafted experience that explores the unique bond between man and machine. Playable offline, the single player campaign in Titanfall 2 will let fans step out onto the Frontier as a Militia rifleman with aspirations of becoming an elite Pilot. Stranded behind enemy lines and facing overwhelming odds, players must team up with a veteran Titan to uphold a mission they were never meant to carry out.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tomb-raider-definitive-edition-xbox-one', 'Tomb Raider: Definitive Edition', 'Tomb Raider', '2014-01-28', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co268v.jpg', 'Tomb Raider: Definitive Edition is a re-release of Tomb Raider, developed by Crystal Dynamics and published by Square-Enix for the Playstation 4 and the Xbox One. The game is optimized for next-gen consoles, with the help of outside developers including United Front Games and Nixxes Software.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('rise-of-the-tomb-raider-xbox-one', 'Rise of the Tomb Raider', 'Tomb Raider', '2015-11-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1rqa.jpg', 'Join Lara Croft on her first great tomb raiding expedition as she seeks to discover the secret of immortality. Featuring high-octane action set in the most beautiful and hostile environments on earth, Rise of the Tomb Raider delivers cinematic survival action-adventure.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shadow-of-the-tomb-raider-xbox-one', 'Shadow of the Tomb Raider', 'Tomb Raider', '2018-09-14', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co3hec.jpg', NULL, 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('tunic-xbox-one', 'Tunic', NULL, '2022-03-16', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/td1t8kb33gyo8mvhl2pc.jpg', 'Tunic is an action adventure about a tiny fox in a big world. Explore the wilderness, discover spooky ruins, and fight terrible creatures from long ago.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-xbox-one', 'Turok', 'Turok', '2018-03-02', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2699.jpg', 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-2-seeds-of-evil-xbox-one', 'Turok 2: Seeds of Evil', 'Turok', '2018-03-02', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2zcg.jpg', 'The Amaranthine Accordance is trying to bring a massive Dinosoid army to Earth from the Lost Land in an effort to restore dinosaurs to their rightful home.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('turok-3-shadow-of-oblivion-xbox-one', 'Turok 3: Shadow of Oblivion', 'Turok', '2023-11-30', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7fpt.jpg', 'Turok 3: Shadow of Oblivion is a faithful restoration of the classic first-person shooter originally released in 2000 for the Nintendo 64, upgraded through Nightdive Studios’ proprietary KEX Engine for play on modern gaming devices with up to a 4K resolution at 120FPS.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('undertale-xbox-one', 'Undertale', NULL, '2021-03-16', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('undertale-xbox-one-2', 'Undertale', NULL, '2021-03-16', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob1t2.jpg', 'A small child falls into the Underground, where monsters have long been banished by humans and are hunting every human that they find. The player controls the child as they try to make it back to the Surface through hostile environments, all the while engaging with a turn-based combat system with puzzle-solving and bullet hell elements, as well as other unconventional game mechanics.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('vampyr-xbox-one', 'Vampyr', NULL, '2018-06-05', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8lrg.jpg', 'London, 1918. You are newly-turned Vampyr Dr. Jonathan Reid. As a doctor, you must find a cure to save the city’s flu-ravaged citizens. As a Vampyr, you are cursed to feed on those you vowed to heal.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-complete-first-season-plus-400-days-xbox-one', 'The Walking Dead: The Complete First Season Plus 400 Days', 'The Walking Dead', '2014-10-14', 'Xbox One', 0, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-season-two-xbox-one', 'The Walking Dead: Season Two', 'The Walking Dead', '2014-10-21', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2k36.jpg', 'Similar to the previous season, The Walking Dead: Season Two is a point-and-click adventure game. The player, in control of Clementine, can direct the character around the environment, examine and interact with various scenery elements and collect and use objects to advance the story. The player can also initiate conversations with non-player characters via conversation trees. Certain replies from other characters may offer the player multiple choices to select from, including the option to stay silent, with a limited amount of time to make the selection; if the player does not select an option, the conversation will continue as if they had stayed quiet. Such choices can affect how the other characters will later react to Clementine which can influence later events in the story. Other scenes are more action-oriented, requiring the player to complete quick time events to avoid Clementine or her allies from getting killed. If the player fails these events, the game will restart at the start of such scenes. Such action scenes may also require the player to make a key decision within a limited time frame, such as which of two characters to save from attacking walkers.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-telltale-series-a-new-frontier-xbox-one', 'The Walking Dead: The Telltale Series A New Frontier', 'The Walking Dead', '2017-02-07', 'Xbox One', 0, 0, NULL, NULL, NULL, NULL, 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-final-season-xbox-one', 'The Walking Dead: The Final Season', 'The Walking Dead', '2019-03-26', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1v9y.jpg', 'After years on the road facing threats both living and dead, a secluded school might finally be Clementine and AJ''s chance for a home. But protecting it will mean sacrifice. In this gripping, emotional final season, your choices define your relationships, shape your world, and determine how Clementine''s story ends.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('the-walking-dead-the-telltale-definitive-series-xbox-one', 'The Walking Dead: The Telltale Definitive Series', 'The Walking Dead', '2019-09-10', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co7axc.jpg', 'The Walking Dead: The Telltale Definitive Series contains all 4 Seasons and The Walking Dead: Michonne, which includes over 50 hours of gameplay across 23 unique episodes. With graphical enhancements, behind the scenes bonus features and faithful recreations of classic menus, this is the definitive way to experience Clementine''s journey and find out how her story ends.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-xbox-one', 'Watch Dogs', 'Watch Dogs', '2014-05-27', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j2m.jpg', 'Purchase the Watch Dogs and Watch Dogs 2 bundle and gain access to these award-winning titles at a great price. In Watch Dogs, become Aiden Pearce and hack your way around Chicago to take down ctOS. In Watch Dogs 2, join Marcus Holloway and the Dedsec hacker group to expose a new digital conspiracy.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-2-xbox-one', 'Watch Dogs 2', 'Watch Dogs', '2016-11-15', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2p3j.jpg', 'Explore a massive and dynamic open world offering an incredible variety of gameplay possibilities. Hack your way through traffic while you engage in dangerous car chases through the winding streets of San Francisco, traverse the rooftops of the colorful and vibrant neighborhoods of Oakland, and infiltrate the cutting-edge offices of Silicon Valley companies. There are many secrets to uncover in the birthplace of the tech revolution.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('watch-dogs-legion-xbox-one', 'Watch Dogs: Legion', 'Watch Dogs', '2020-10-29', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2oyq.jpg', 'In Watch Dogs: Legion, near future London is facing its downfall... Unless you do something about it. Build a resistance, fight back, and give the city back to the people. It''s time to rise up.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('a-way-out-xbox-one', 'A Way Out', NULL, '2018-03-23', 'Xbox One', 1, 1, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2fc6.jpg', 'Milky Way Prince: The Vampire Star is a visual novel that explores themes of abuse, idealization, and intimacy within a romantic relationship. Players experience a summer of dysfunctional love through branching storylines, unexpected twists, and a unique mechanic that allows selection of sensory interactions with the protagonist’s boyfriend.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('we-happy-few-xbox-one', 'We Happy Few', NULL, '2018-08-10', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9grj.jpg', 'The people of Happy Happy Land aren''t happy, they can''t seem to work things out. Maybe all they need is a little bit of creative thinking.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-new-order-xbox-one', 'Wolfenstein: The New Order', 'Wolfenstein', '2014-05-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c0.jpg', 'Wolfenstein: The New Order is an action-adventure shooter game played from a first-person perspective. It is the semi-sequel to 2009''s Wolfenstein, however utilizes very little from the game and drops any direct references to veil or supernatural.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-the-old-blood-xbox-one', 'Wolfenstein: The Old Blood', 'Wolfenstein', '2015-07-21', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21et.jpg', 'Wolfenstein: The Old Blood is a prequel to the critically acclaimed first-person action-adventure shooter, Wolfenstein: The New Order. The adventure, which spans eight chapters and two interconnected stories, features the hallmarks of MachineGames – thrilling action, immersive story and intense first-person combat. As war hero B.J. Blazkowicz, arm yourself with new weapons such as the bolt-action rifle and grenade-launching Kampfpistole as you attempt to thwart the advancing Nazi war machine, and take advantage of duel-wielding pipes that can be used for wall climbing – or for vicious take-downs of never-before-seen Nazi adversaries.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-ii-the-new-colossus-xbox-one', 'Wolfenstein II: The New Colossus', 'Wolfenstein', '2017-10-27', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21c5.jpg', 'Wolfenstein II: The New Colossus is the eleventh installment of the Wolfenstein series and a sequel to the 2014''s Wolfenstein: The New Order. The game follows the main protagonist, William Joseph "B.J." Blazkowicz, in his efforts to ignite a Second American Revolution.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('wolfenstein-youngblood-xbox-one', 'Wolfenstein: Youngblood', 'Wolfenstein', '2019-07-26', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co21by.jpg', 'Wolfenstein: Youngblood is a brand-new co-op experience from MachineGames, the award-winning studio that developed the critically acclaimed Wolfenstein II: The New Colossus.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('world-to-the-west-xbox-one', 'World to the West', NULL, '2017-07-19', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cobbrz.jpg', 'In the game Wild West World, you must build an economic empire during the Wild West. Buy farms and ranches and try and drive your competition out of business by whatever means possible.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('xcom-2-xbox-one', 'XCOM 2', 'XCOM', '2016-09-27', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g41.jpg', 'The XCOM 2 Collection includes the award-winning strategy game XCOM 2, the War of the Chosen expansion, and four DLC packs (Resistance Warrior Pack, Anarchy’s Children, Alien Hunters, Shen’s Last Gift, Tactical Legacy Pack) for a bundled discount.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yoku-s-island-express-xbox-one', 'Yoku''s Island Express', NULL, '2018-05-29', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob89x.jpg', 'Yoku’s Island Express is an open world/metroidvania-style pinball adventure, Seamlessly blending platform navigation with pinball mechanics across a large open world. Yoku the dung beetle sets foot on the beach of Mokumana Island, ready to take on the duties as the new postman. But the ancient island God is trapped in a restless sleep and the islanders are plagued by quakes and storms brought forth by its nightmares. Yoku''s Island Express is a unique and quirky adventure with handcrafted visuals, where you''ll soar through the air, vacuum explosive snails, fight a Screetch, feed starving lemurs, discover the mystery of the Fruit Altar, wake an old god, and hopefully help tiny Yoku rebuild the island post-office.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-xbox-one', 'Yooka-Laylee', 'Yooka-Laylee', '2017-04-11', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co1z4v.jpg', 'Explore huge, beautiful worlds, meet (and beat) an unforgettable cast of characters and horde a vault-load of shiny collectibles as buddy-duo Yooka (the green one) and Laylee (the wisecracking bat with the big nose) embark on an epic adventure to thwart corporate creep Capital B and his devious scheme to absorb all the world’s books… and convert them into pure profit!', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('yooka-laylee-and-the-impossible-lair-xbox-one', 'Yooka-Laylee and the Impossible Lair', 'Yooka-Laylee', '2019-10-08', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2z9b.jpg', 'Yooka and Laylee are back for a brand new adventure! Get ready for the ultimate challenge - the Impossible Lair!
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoo-tycoon-xbox-one', 'Zoo Tycoon', 'Zoo Tycoon', '2013-11-22', 'Xbox One', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22u7.jpg', 'Zoo Tycoon is a business simulation developed by Blue Fang Games and released by Microsoft Game Studios. It is a tycoon game in which the player must run a zoo and try to make a profit. Although first released for Microsoft Windows and Macintosh in 2001, it was ported to the Nintendo DS in 2005. It was followed by two expansion packs, Zoo Tycoon: Dinosaur Digs and Zoo Tycoon: Marine Mania, which were released in 2002, as well as a sequel, Zoo Tycoon 2, released in 2004.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('zoo-tycoon-ultimate-animal-collection-xbox-one', 'Zoo Tycoon: Ultimate Animal Collection', 'Zoo Tycoon', '2017-08-20', 'Xbox One', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co22qo.jpg', 'Zoo Tycoon: Ultimate Animal Collection adds animals from Australia and South America in 4K Ultra HD to Xbox One and PC.', 'NA', 49);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('alan-wake-2-deluxe-edition-xbox-series-x', 'Alan Wake 2 Deluxe Edition', 'Alan Wake', '2023-10-27', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jht.jpg', 'Alan Wake II: Deluxe Edition is a special edition of Alan Wake II.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('arzette-the-jewel-of-faramore-xbox-series-x', 'Arzette: The Jewel of Faramore', NULL, '2024-02-14', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6ryw.jpg', 'Arzette: The Jewel of Faramore is a new interactive animated adventure, where players must help Arzette save the Kingdom of Faramore from the evil demon king, Daimur. It is a spiritual successor to a pair of infamous fantasy adventure titles, being developed by Seedy Eye Software and both funded & published by Limited Run Games.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('baldur-s-gate-3-xbox-series-x', 'Baldur''s Gate 3', 'Baldur''s Gate', '2023-12-07', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co670h.jpg', 'An ancient evil has returned to Baldur''s Gate, intent on devouring it from the inside out. The fate of Faerun lies in your hands. Alone, you may resist. But together, you can overcome.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('beyond-good-evil-20th-anniversary-edition-xbox-series-x', 'Beyond Good & Evil - 20th Anniversary Edition', 'Beyond Good & Evil', '2024-06-25', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8eda.jpg', 'Swoop into the marvelous world of Hillys as action-reporter Jade to investigate the mysterious DomZ alien attacks alongside colorful characters, like her adoptive uncle Pey’j or the valiant Double H. Embark on this epic adventure in up to 4K, 60 fps with improved graphics, controls, and audio, along with brand-new autosave and cross-save features. Enjoy exclusive new rewards as you explore the planet and discover more about Jade’s past in a new treasure hunt throughout Hillys. Put your skills to the test thanks to the new speedrun mode and updated achievements, and learn more about the game’s development and secrets in the anniversary gallery! Armed with her daï-jo and faithful camera, Jade’s adventure will get you to freely explore Hillys, combat creatures large and small, infiltrate dangerous areas, solve enigmatic puzzles, play addictive mini-games, race the best hovercraft pilots, and take pictures of the whole experience.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('castlevania-dominus-collection-xbox-series-x', 'Castlevania Dominus Collection', 'Castlevania', '2024-08-27', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/cob9xk.jpg', 'Three incredible action adventure games from the Castlevania series have finally returned, for the first time! But wait, there''s more! Haunted Castle Revisited, a redesigned version of the very first Castlevania arcade game, makes its debut!', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('control-ultimate-edition-xbox-series-x', 'Control: Ultimate Edition', 'Control', '2021-02-02', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co2ewb.jpg', 'Control Ultimate Edition contains the main game and all previously released Expansions ("The Foundation" and "AWE") in one great value package. Winner of over 80 awards, Control is a visually stunning third-person action-adventure that will keep you on the edge of your seat.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('deathloop-xbox-series-x', 'Deathloop', NULL, '2022-09-20', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4nzt.jpg', 'Deathloop transports players to the lawless island of Blackreef in an eternal struggle between two extraordinary assassins. Explore stunning environments and meticulously designed levels in an immersive gameplay experience that lets you approach every situation any way you like. Hunt down targets all over the island in an effort to put an end to the cycle once and for all, and remember, if at first you don’t succeed… die, die again.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('devil-may-cry-5-special-edition-xbox-series-x', 'Devil May Cry 5: Special Edition', 'Devil May Cry', '2020-11-10', 'Xbox Series X', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9sdu.jpg', 'Devil May Cry 5: Special Edition features improved visuals and gameplay at up to 120 frames per second. Alongside all previously-released downloadable content, other additions include Vergil as a playable character, ray tracing graphics options, and two additional game modes: Legendary Dark Knight mode, which significantly increases the number of enemies in each level, and Turbo mode, which increases the game speed by 20%.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('dragon-age-the-veilguard-xbox-series-x', 'Dragon Age: The Veilguard', 'Dragon Age', '2024-10-31', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gj5.jpg', 'Select from different races and combat classes, customize your appearance, choose your character’s backstory and begin your journey as Rook, Dragon Age’s newest hero.
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gex-trilogy-xbox-series-x', 'Gex Trilogy', 'Gex', '2025-06-16', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9d3l.jpg', 'Gex Trilogy is the definitive edition of the classic platforming series with Gexcessive attitude, complete with Gextras like rewind and save anywhere. Relive Gex''s snark-laced adventures through the warped lens of twentieth-century pop culture and use your Gexterity to survive an onslaught of television-themed challenges.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('gradius-origins-xbox-series-x', 'Gradius Origins', 'Gradius', '2025-08-07', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9l0o.jpg', 'This collection features 18 versions across all 7 arcade titles in the series, including the first-ever appearance of Gradius III AM Show Version on home consoles.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('microsoft-flight-simulator-xbox-series-x', 'Microsoft Flight Simulator', 'Microsoft Flight Simulator', '2021-07-27', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co8gfq.jpg', 'The fifth take on the Flight Simulator series. This version added SVGA graphics, textures in certain areas, sound card support, and two new flight areas, Paris and Munich. This was the final DOS-only release.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('return-to-monkey-island-xbox-series-x', 'Return to Monkey Island', 'Monkey Island', '2022-11-08', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co56kr.jpg', 'Return to Monkey Island, the long-awaited follow-up to the legendary Secret of Monkey Island and Monkey Island 2: LeChuck''s Revenge by Ron Gilbert''s Terrible Toybox in collaboration with Devolver Digital and Lucasfilm Games, coming 2022.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('overcooked-all-you-can-eat-xbox-series-x', 'Overcooked! All You Can Eat', 'Overcooked!', '2020-12-08', 'Xbox Series X', 0, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co4969.jpg', 'Five new birthday themed levels, the new Tabby Cat chef, a recipe to make a cup of tea, and in-game Switcheroo mechanic where living playing cards stalk the levels transporting players across the kitchen, are all on the menu.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('penny-s-big-breakaway-xbox-series-x', 'Penny''s Big Breakaway', NULL, '2024-02-21', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co6nmg.jpg', 'Join Penny & Yo-Yo in a kinetic 3D-platformer bursting with innovative gameplay! Showcase your catalog of tricks and chain impressive combos to deliver Penny & Yo-Yo''s perfect breakout performance. Take the stage with this vibrant pair in Penny’s Big Breakaway.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('redfall-xbox-series-x', 'Redfall', NULL, '2023-05-02', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co52ds.jpg', 'Redfall is an open-world, co-op FPS from Arkane Austin, the award-winning team behind Prey and Dishonored. Continuing Arkane’s legacy of carefully crafted worlds and immersive sims, Redfall brings the studio’s signature gameplay to this story-driven action shooter.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('shinobi-art-of-vengeance-xbox-series-x', 'Shinobi: Art of Vengeance', 'Shinobi', '2025-08-29', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co9e1j.jpg', 'Slay the enemies in the silence of the moment. Run through the world of Shinobi full of monsters and ninja actions. Grab Oborozuki, the legendary sword, and slay evil once more. Your clan and the world are counting on you.', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('star-wars-jedi-survivor-xbox-series-x', 'Star Wars Jedi: Survivor', 'Star Wars', '2023-04-28', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co5uzk.jpg', 'The story of Cal Kestis continues in Star Wars Jedi: Survivor, a third-person, galaxy-spanning, action-adventure game from Respawn Entertainment, developed in collaboration with Lucasfilm Games. This narratively driven, single-player title picks up five years after the events of Star Wars Jedi: Fallen Order and follows Cal’s increasingly desperate fight as the galaxy descends further into darkness. Pushed to the edges of the galaxy by the Empire, Cal will find himself surrounded by threats new and familiar. As one of the last surviving Jedi Knights, Cal is driven to make a stand during the galaxy’s darkest times — but how far is he willing to go to protect himself, his crew, and the legacy of the Jedi Order?', 'NA', 50);
INSERT INTO games (id, title, series, release_date, platform, owned, queued, sort_index, image_url, summary, region, platform_id) VALUES ('starfield-xbox-series-x', 'Starfield', NULL, '2023-09-06', 'Xbox Series X', 1, 0, NULL, 'https://images.igdb.com/igdb/image/upload/t_cover_big/co39vv.jpg', 'In this next generation role-playing game set amongst the stars, create any character you want and explore with unparalleled freedom as you embark on an epic journey to answer humanity’s greatest mystery.', 'NA', 50);
