INSERT INTO platforms (id, name, igdb_id, display_name, parent_platform_id, brand, launch_date, image_url, description) VALUES (48, 'Xbox 360', NULL, 'Xbox 360', NULL, 'Xbox', '2005-11-22', NULL, 'Xbox 360 brings you a total games and entertainment experience. The largest library of games, including titles that get you right into the thick of it with Kinect. Plus, your whole family can watch HD movies, TV shows, live events, music, sports and more—across all your devices. Xbox 360 is the center of your games and entertainment universe.');
INSERT INTO platforms (id, name, igdb_id, display_name, parent_platform_id, brand, launch_date, image_url, description) VALUES (49, 'Xbox One', NULL, 'Xbox One', NULL, 'Xbox', '2013-11-22', NULL, 'Welcome to a new generation of games and entertainment. Where games push the boundaries of realism. And television obeys your every command. Where listening to music while playing a game is a snap. And you can jump from TV to movies to music to a game in an instant. Where your experience is custom tailored to you. And the entertainment you love is all in one place. Welcome to the all-in-one, Xbox One');
